static void lan78xx_disconnect(struct usb_interface* intf) {
  struct lan78xx_net* dev;
  struct usb_device* udev;
  struct net_device* net;
  struct phy_device* phydev;
  dev = usb_get_intfdata(intf);
  usb_set_intfdata(intf, NULL);
  if (!dev) return;
  set_bit(EVENT_DEV_DISCONNECT, &dev->flags);
  netif_napi_del(&dev->napi);
  udev = interface_to_usbdev(intf);
  net = dev->net;
  unregister_netdev(net);
  cancel_delayed_work_sync(&dev->wq);
  phydev = net->phydev;
  phy_unregister_fixup_for_uid(PHY_KSZ9031RNX, 0xfffffff0);
  phy_unregister_fixup_for_uid(PHY_LAN8835, 0xfffffff0);
  phy_disconnect(net->phydev);
  if (phy_is_pseudo_fixed_link(phydev)) fixed_phy_unregister(phydev);
  usb_scuttle_anchored_urbs(&dev->deferred);
  if (timer_pending(&dev->stat_monitor)) del_timer_sync(&dev->stat_monitor);
  lan78xx_unbind(dev, intf);
  lan78xx_free_tx_resources(dev);
  lan78xx_free_rx_resources(dev);
  usb_kill_urb(dev->urb_intr);
  usb_free_urb(dev->urb_intr);
  free_netdev(net);
  usb_put_dev(udev);
}

static void make_response(struct xen_blkif_ring* ring, u64 id,
                          unsigned short op, int st) {
  struct blkif_response resp;
  unsigned long flags;
  union blkif_back_rings* blk_rings;
  int notify;
  resp.id = id;
  resp.operation = op;
  resp.status = st;
  spin_lock_irqsave(&ring->blk_ring_lock, flags);
  blk_rings = &ring->blk_rings;
  switch (ring->blkif->blk_protocol) {
    case BLKIF_PROTOCOL_NATIVE:
      memcpy(
          RING_GET_RESPONSE(&blk_rings->native, blk_rings->native.rsp_prod_pvt),
          &resp, sizeof(resp));
      break;
    case BLKIF_PROTOCOL_X86_32:
      memcpy(
          RING_GET_RESPONSE(&blk_rings->x86_32, blk_rings->x86_32.rsp_prod_pvt),
          &resp, sizeof(resp));
      break;
    case BLKIF_PROTOCOL_X86_64:
      memcpy(
          RING_GET_RESPONSE(&blk_rings->x86_64, blk_rings->x86_64.rsp_prod_pvt),
          &resp, sizeof(resp));
      break;
    default:
      BUG();
  }
  blk_rings->common.rsp_prod_pvt++;
  RING_PUSH_RESPONSES_AND_CHECK_NOTIFY(&blk_rings->common, notify);
  spin_unlock_irqrestore(&ring->blk_ring_lock, flags);
  if (notify) notify_remote_via_irq(ring->irq);
}

static int decode_tree_entry(struct tree_desc* desc, const char* buf,
                             unsigned long size, struct strbuf* err) {
  const char* path;
  unsigned int mode, len;
  if (size < 23 || buf[size - 21]) {
    strbuf_addstr(err, _("too-short tree object"));
    return -1;
  }
  path = get_mode(buf, &mode);
  if (!path) {
    strbuf_addstr(err, _("malformed mode in tree entry"));
    return -1;
  }
  if (!*path) {
    strbuf_addstr(err, _("empty filename in tree entry"));
    return -1;
  }
  len = strlen(path) + 1;
  desc->entry.path = path;
  desc->entry.mode = canon_mode(mode);
  desc->entry.oid = (const struct object_id*)(path + len);
  return 0;
}

sg_common_write(Sg_fd* sfp, Sg_request* srp, unsigned char* cmnd, int timeout,
                int blocking) {
  int k, at_head;
  Sg_device* sdp = sfp->parentdp;
  sg_io_hdr_t* hp = &srp->header;
  srp->data.cmd_opcode = cmnd[0];
  hp->status = 0;
  hp->masked_status = 0;
  hp->msg_status = 0;
  hp->info = 0;
  hp->host_status = 0;
  hp->driver_status = 0;
  hp->resid = 0;
  SCSI_LOG_TIMEOUT(
      4, sg_printk(KERN_INFO, sfp->parentdp,
                   "sg_common_write:  scsi opcode=0x%02x, cmd_size=%d\n",
                   (int)cmnd[0], (int)hp->cmd_len));
  k = sg_start_req(srp, cmnd);
  if (k) {
    SCSI_LOG_TIMEOUT(1, sg_printk(KERN_INFO, sfp->parentdp,
                                  "sg_common_write: start_req err=%d\n", k));
    sg_finish_rem_req(srp);
    return k;
  }
  if (atomic_read(&sdp->detaching)) {
    if (srp->bio) blk_end_request_all(srp->rq, -EIO);
    sg_finish_rem_req(srp);
    return -ENODEV;
  }
  hp->duration = jiffies_to_msecs(jiffies);
  if (hp->interface_id != '\0' && (SG_FLAG_Q_AT_TAIL & hp->flags))
    at_head = 0;
  else
    at_head = 1;
  srp->rq->timeout = timeout;
  kref_get(&sfp->f_ref);
  blk_execute_rq_nowait(sdp->device->request_queue, sdp->disk, srp->rq, at_head,
                        sg_rq_end_io);
  return 0;
}

exif_data_load_data_thumbnail(ExifData* data, const unsigned char* d,
                              unsigned int ds, ExifLong o, ExifLong s) {
  if ((o + s < o) || (o + s < s) || (o + s > ds) || (o > ds)) {
    exif_log(data->priv->log, EXIF_LOG_CODE_DEBUG, "ExifData",
             "Bogus thumbnail offset (%u) or size (%u).", o, s);
    return;
  }
  if (data->data) exif_mem_free(data->priv->mem, data->data);
  if (!(data->data = exif_data_alloc(data, s))) {
    EXIF_LOG_NO_MEMORY(data->priv->log, "ExifData", s);
    data->size = 0;
    return;
  }
  data->size = s;
  memcpy(data->data, d + o, s);
}

static int sco_sock_recvmsg(struct kiocb* iocb, struct socket* sock,
                            struct msghdr* msg, size_t len, int flags) {
  struct sock* sk = sock->sk;
  struct sco_pinfo* pi = sco_pi(sk);
  lock_sock(sk);
  if (sk->sk_state == BT_CONNECT2 &&
      test_bit(BT_SK_DEFER_SETUP, &bt_sk(sk)->flags)) {
    hci_conn_accept(pi->conn->hcon, 0);
    sk->sk_state = BT_CONFIG;
    release_sock(sk);
    return 0;
  }
  release_sock(sk);
  return bt_sock_recvmsg(iocb, sock, msg, len, flags);
}

bool read(ReadonlyBytes buffer) {
  auto fields_size = sizeof(LocalFileHeader) - (sizeof(u8*) * 3);
  if (buffer.size() < fields_size) return false;
  if (memcmp(buffer.data(), local_file_header_signature,
             sizeof(local_file_header_signature)) != 0)
    return false;
  memcpy(reinterpret_cast<void*>(&minimum_version),
         buffer.data() + sizeof(local_file_header_signature), fields_size);
  name = buffer.data() + sizeof(local_file_header_signature) + fields_size;
  extra_data = name + name_length;
  compressed_data = extra_data + extra_data_length;
  return true;
}

void AverageEvalQuantizedUint8(TfLiteContext* context, TfLiteNode* node,
                               TfLitePoolParams* params, OpData* data,
                               const TfLiteTensor* input,
                               TfLiteTensor* output) {
  int32_t activation_min;
  int32_t activation_max;
  (void)CalculateActivationRangeQuantized(context, params->activation, output,
                                          &activation_min, &activation_max);
#define TF_LITE_AVERAGE_POOL(type)                                         \
  tflite::PoolParams op_params;                                            \
  op_params.stride_height = params->stride_height;                         \
  op_params.stride_width = params->stride_width;                           \
  op_params.filter_height = params->filter_height;                         \
  op_params.filter_width = params->filter_width;                           \
  op_params.padding_values.height = data->padding.height;                  \
  op_params.padding_values.width = data->padding.width;                    \
  op_params.quantized_activation_min = activation_min;                     \
  op_params.quantized_activation_max = activation_max;                     \
  type::AveragePool(op_params, GetTensorShape(input),                      \
                    GetTensorData<uint8_t>(input), GetTensorShape(output), \
                    GetTensorData<uint8_t>(output))
  if (kernel_type == kReference) {
    TF_LITE_AVERAGE_POOL(reference_ops);
  } else {
    TF_LITE_AVERAGE_POOL(optimized_ops);
  }
#undef TF_LITE_AVERAGE_POOL
}

static cJSON* get_object_item(const cJSON* const object, const char* const name,
                              const cJSON_bool case_sensitive) {
  cJSON* current_element = NULL;
  if ((object == NULL) || (name == NULL)) {
    return NULL;
  }
  current_element = object->child;
  if (case_sensitive) {
    while ((current_element != NULL) &&
           (strcmp(name, current_element->string) != 0)) {
      current_element = current_element->next;
    }
  } else {
    while ((current_element != NULL) &&
           (case_insensitive_strcmp(
                (const unsigned char*)name,
                (const unsigned char*)(current_element->string)) != 0)) {
      current_element = current_element->next;
    }
  }
  return current_element;
}

static void outbound_phy_packet_callback(struct fw_packet* packet,
                                         struct fw_card* card, int status) {
  struct outbound_phy_packet_event* e =
      container_of(packet, struct outbound_phy_packet_event, p);
  switch (status) {
    case ACK_COMPLETE:
      e->phy_packet.rcode = RCODE_COMPLETE;
      break;
    case ACK_PENDING:
      e->phy_packet.rcode = RCODE_COMPLETE;
      break;
    case ACK_BUSY_X:
    case ACK_BUSY_A:
    case ACK_BUSY_B:
      e->phy_packet.rcode = RCODE_BUSY;
      break;
    case ACK_DATA_ERROR:
      e->phy_packet.rcode = RCODE_DATA_ERROR;
      break;
    case ACK_TYPE_ERROR:
      e->phy_packet.rcode = RCODE_TYPE_ERROR;
      break;
    default:
      e->phy_packet.rcode = status;
      break;
  }
  e->phy_packet.data[0] = packet->timestamp;
  queue_event(e->client, &e->event, &e->phy_packet,
              sizeof(e->phy_packet) + e->phy_packet.length, NULL, 0);
  client_put(e->client);
}

LogFilePrep(const char* fname, const char* backup, const char* idstring) {
  char* logFileName = NULL;
  if (asprintf(&logFileName, fname, idstring) == -1)
    FatalError("Cannot allocate space for the log file name\n");
  if (backup && *backup) {
    struct stat buf;
    if (!stat(logFileName, &buf) && S_ISREG(buf.st_mode)) {
      char* suffix;
      char* oldLog;
      if ((asprintf(&suffix, backup, idstring) == -1) ||
          (asprintf(&oldLog, "%s%s", logFileName, suffix) == -1)) {
        FatalError("Cannot allocate space for the log file name\n");
      }
      free(suffix);
      if (rename(logFileName, oldLog) == -1) {
        FatalError("Cannot move old log file \"%s\" to \"%s\"\n", logFileName,
                   oldLog);
      }
      free(oldLog);
    }
  } else {
    if (remove(logFileName) != 0 && errno != ENOENT) {
      FatalError("Cannot remove old log file \"%s\": %s\n", logFileName,
                 strerror(errno));
    }
  }
  return logFileName;
}

lyd_new_output(struct lyd_node* parent, const struct lys_module* module,
               const char* name) {
  const struct lys_node *snode = NULL, *siblings;
  if ((!parent && !module) || !name) {
    LOGARG;
    return NULL;
  }
  siblings = lyd_new_find_schema(parent, module, 1);
  if (!siblings) {
    LOGARG;
    return NULL;
  }
  if (lys_getnext_data(
          module, lys_parent(siblings), name, strlen(name),
          LYS_CONTAINER | LYS_LIST | LYS_NOTIF | LYS_RPC | LYS_ACTION,
          &snode) ||
      !snode) {
    LOGERR(siblings->module->ctx, LY_EINVAL,
           "Failed to find \"%s\" as a sibling to \"%s:%s\".", name,
           lys_node_module(siblings)->name, siblings->name);
    return NULL;
  }
  return _lyd_new(parent, snode, 0);
}

address_space_translate_for_iotlb(CPUState* cpu, int asidx, hwaddr addr,
                                  hwaddr* xlat, hwaddr* plen, MemTxAttrs attrs,
                                  int* prot) {
  MemoryRegionSection* section;
  IOMMUMemoryRegion* iommu_mr;
  IOMMUMemoryRegionClass* imrc;
  IOMMUTLBEntry iotlb;
  int iommu_idx;
  AddressSpaceDispatch* d =
      qatomic_rcu_read(&cpu->cpu_ases[asidx].memory_dispatch);
  for (;;) {
    section = address_space_translate_internal(d, addr, &addr, plen, false);
    iommu_mr = memory_region_get_iommu(section->mr);
    if (!iommu_mr) {
      break;
    }
    imrc = memory_region_get_iommu_class_nocheck(iommu_mr);
    iommu_idx = imrc->attrs_to_index(iommu_mr, attrs);
    tcg_register_iommu_notifier(cpu, iommu_mr, iommu_idx);
    iotlb = imrc->translate(iommu_mr, addr, IOMMU_NONE, iommu_idx);
    addr =
        ((iotlb.translated_addr & ~iotlb.addr_mask) | (addr & iotlb.addr_mask));
    if (!(iotlb.perm & IOMMU_RO)) {
      *prot &= ~(PAGE_READ | PAGE_EXEC);
    }
    if (!(iotlb.perm & IOMMU_WO)) {
      *prot &= ~PAGE_WRITE;
    }
    if (!*prot) {
      goto translate_fail;
    }
    d = flatview_to_dispatch(address_space_to_flatview(iotlb.target_as));
  }
  assert(!memory_region_is_iommu(section->mr));
  *xlat = addr;
  return section;
translate_fail:
  return &d->map.sections[PHYS_SECTION_UNASSIGNED];
}

