avp_find(struct l2tp_avp* avp, const u_char* pkt, int pktlen,
         uint16_t vendor_id, uint16_t attr_type, int fill_data) {
  int avpsz;
  while (pktlen >= 6 && (avpsz = avp_enum(avp, pkt, pktlen, fill_data)) > 0) {
    if (avp->vendor_id != vendor_id || avp->attr_type != attr_type) {
      if (avpsz < 6) return NULL;
      pkt += avpsz;
      pktlen -= avpsz;
      continue;
    }
    return avp;
  }
  return NULL;
}

build_unc_path_to_root(const struct smb_vol* vol,
                       const struct cifs_sb_info* cifs_sb) {
  char *full_path, *pos;
  unsigned int pplen = vol->prepath ? strlen(vol->prepath) + 1 : 0;
  unsigned int unc_len = strnlen(vol->UNC, MAX_TREE_SIZE + 1);
  full_path = kmalloc(unc_len + pplen + 1, GFP_KERNEL);
  if (full_path == NULL) return ERR_PTR(-ENOMEM);
  strncpy(full_path, vol->UNC, unc_len);
  pos = full_path + unc_len;
  if (pplen) {
    *pos++ = CIFS_DIR_SEP(cifs_sb);
    strncpy(pos, vol->prepath, pplen);
    pos += pplen;
  }
  *pos = '\0';
  convert_delimiter(full_path, CIFS_DIR_SEP(cifs_sb));
  cifs_dbg(FYI, "%s: full_path=%s\n", __func__, full_path);
  return full_path;
}

int btrfs_get_dev_stats(struct btrfs_fs_info* fs_info,
                        struct btrfs_ioctl_get_dev_stats* stats) {
  struct btrfs_device* dev;
  struct btrfs_fs_devices* fs_devices = fs_info->fs_devices;
  int i;
  mutex_lock(&fs_devices->device_list_mutex);
  dev = btrfs_find_device(fs_info->fs_devices, stats->devid, NULL, NULL);
  mutex_unlock(&fs_devices->device_list_mutex);
  if (!dev) {
    btrfs_warn(fs_info, "get dev_stats failed, device not found");
    return -ENODEV;
  } else if (!dev->dev_stats_valid) {
    btrfs_warn(fs_info, "get dev_stats failed, not yet valid");
    return -ENODEV;
  } else if (stats->flags & BTRFS_DEV_STATS_RESET) {
    for (i = 0; i < BTRFS_DEV_STAT_VALUES_MAX; i++) {
      if (stats->nr_items > i)
        stats->values[i] = btrfs_dev_stat_read_and_reset(dev, i);
      else
        btrfs_dev_stat_reset(dev, i);
    }
  } else {
    for (i = 0; i < BTRFS_DEV_STAT_VALUES_MAX; i++)
      if (stats->nr_items > i) stats->values[i] = btrfs_dev_stat_read(dev, i);
  }
  if (stats->nr_items > BTRFS_DEV_STAT_VALUES_MAX)
    stats->nr_items = BTRFS_DEV_STAT_VALUES_MAX;
  return 0;
}

static int parse_video_info(AVIOContext* pb, AVStream* st) {
  uint16_t size_asf;
  uint32_t size_bmp;
  unsigned int tag;
  st->codecpar->width = avio_rl32(pb);
  st->codecpar->height = avio_rl32(pb);
  avio_skip(pb, 1);
  size_asf = avio_rl16(pb);
  tag = ff_get_bmp_header(pb, st, &size_bmp);
  st->codecpar->codec_tag = tag;
  st->codecpar->codec_id = ff_codec_get_id(ff_codec_bmp_tags, tag);
  size_bmp = FFMAX(size_asf, size_bmp);
  if (size_bmp > BMP_HEADER_SIZE) {
    int ret;
    st->codecpar->extradata_size = size_bmp - BMP_HEADER_SIZE;
    if (!(st->codecpar->extradata = av_malloc(st->codecpar->extradata_size +
                                              AV_INPUT_BUFFER_PADDING_SIZE))) {
      st->codecpar->extradata_size = 0;
      return AVERROR(ENOMEM);
    }
    memset(st->codecpar->extradata + st->codecpar->extradata_size, 0,
           AV_INPUT_BUFFER_PADDING_SIZE);
    if ((ret = avio_read(pb, st->codecpar->extradata,
                         st->codecpar->extradata_size)) < 0)
      return ret;
  }
  return 0;
}

size_t _process_request_next_key(mcp_parser_t* pr) {
  const char* cur = pr->request + pr->parsed;
  int remain = pr->reqlen - pr->parsed - 2;
  while (remain) {
    if (*cur == ' ') {
      remain--;
      cur++;
      pr->parsed++;
    } else {
      break;
    }
  }
  const char* s = memchr(cur, ' ', remain);
  if (s != NULL) {
    pr->klen = s - cur;
    pr->parsed += s - cur;
  } else {
    pr->klen = remain;
    pr->parsed += remain;
  }
  return cur - pr->request;
}

process_request_identities(SocketEntry* e) {
  Identity* id;
  struct sshbuf *msg, *keys;
  int r;
  u_int nentries = 0;
  debug2_f("entering");
  if ((msg = sshbuf_new()) == NULL || (keys = sshbuf_new()) == NULL)
    fatal_f("sshbuf_new failed");
  TAILQ_FOREACH(id, &idtab->idlist, next) {
    if (identity_permitted(id, e, NULL, NULL, NULL) != 0) continue;
    if ((r = sshkey_puts_opts(id->key, keys, SSHKEY_SERIALIZE_INFO)) != 0 ||
        (r = sshbuf_put_cstring(keys, id->comment)) != 0) {
      error_fr(r, "compose key/comment");
      continue;
    }
    nentries++;
  }
  debug2_f("replying with %u allowed of %u available keys", nentries,
           idtab->nentries);
  if ((r = sshbuf_put_u8(msg, SSH2_AGENT_IDENTITIES_ANSWER)) != 0 ||
      (r = sshbuf_put_u32(msg, nentries)) != 0 ||
      (r = sshbuf_putb(msg, keys)) != 0)
    fatal_fr(r, "compose");
  if ((r = sshbuf_put_stringb(e->output, msg)) != 0) fatal_fr(r, "enqueue");
  sshbuf_free(msg);
  sshbuf_free(keys);
}

static void add_bytes_l2_c(uint8_t* dst, uint8_t* src1, uint8_t* src2, int w) {
  long i;
  for (i = 0; i <= w - sizeof(long); i += sizeof(long)) {
    long a = *(long*)(src1 + i);
    long b = *(long*)(src2 + i);
    *(long*)(dst + i) = ((a & pb_7f) + (b & pb_7f)) ^ ((a ^ b) & pb_80);
  }
  for (; i < w; i++) dst[i] = src1[i] + src2[i];
}

static int crypto_rng_report(struct sk_buff* skb, struct crypto_alg* alg) {
  struct crypto_report_rng rrng;
  snprintf(rrng.type, CRYPTO_MAX_ALG_NAME, "%s", "rng");
  rrng.seedsize = alg->cra_rng.seedsize;
  if (nla_put(skb, CRYPTOCFGA_REPORT_RNG, sizeof(struct crypto_report_rng),
              &rrng))
    goto nla_put_failure;
  return 0;
nla_put_failure:
  return -EMSGSIZE;
}

static void zend_throw_or_error(int fetch_type, zend_class_entry* exception_ce,
                                const char* format, ...) {
  va_list va;
  char* message = NULL;
  va_start(va, format);
  zend_vspprintf(&message, 0, format, va);
  if (fetch_type & ZEND_FETCH_CLASS_EXCEPTION) {
    zend_throw_error(exception_ce, message);
  } else {
    zend_error(E_ERROR, "%s", message);
  }
  efree(message);
  va_end(va);
}

static TEE_Result do_allocate_publickey(struct rsa_public_key* key,
                                        size_t size_bits) {
  RSA_TRACE("Allocate Public Key of %zu bits", size_bits);
  memset(key, 0, sizeof(*key));
  key->e = crypto_bignum_allocate(MAX_BITS_EXP_E);
  if (!key->e) goto err_alloc_publickey;
  key->n = crypto_bignum_allocate(size_bits);
  if (!key->n) goto err_alloc_publickey;
  return TEE_SUCCESS;
err_alloc_publickey:
  RSA_TRACE("Allocation error");
  crypto_bignum_free(key->e);
  crypto_bignum_free(key->n);
  return TEE_ERROR_OUT_OF_MEMORY;
}

bool chopOff(string& domain) {
  if (domain.empty()) return false;
  string::size_type fdot = domain.find('.');
  if (fdot == string::npos)
    domain = "";
  else {
    string::size_type remain = domain.length() - (fdot + 1);
    char tmp[remain];
    memcpy(tmp, domain.c_str() + fdot + 1, remain);
    domain.assign(tmp, remain);
  }
  return true;
}

juniper_atm2_print(netdissect_options* ndo, const struct pcap_pkthdr* h,
                   register const u_char* p) {
  int llc_hdrlen;
  struct juniper_l2info_t l2info;
  l2info.pictype = DLT_JUNIPER_ATM2;
  if (juniper_parse_header(ndo, p, h, &l2info) == 0) return l2info.header_len;
  p += l2info.header_len;
  if (l2info.cookie[7] & ATM2_PKT_TYPE_MASK) {
    oam_print(ndo, p, l2info.length, ATM_OAM_NOHEC);
    return l2info.header_len;
  }
  if (EXTRACT_24BITS(p) == 0xfefe03 || EXTRACT_24BITS(p) == 0xaaaa03) {
    llc_hdrlen = llc_print(ndo, p, l2info.length, l2info.caplen, NULL, NULL);
    if (llc_hdrlen > 0) return l2info.header_len;
  }
  if (l2info.direction != JUNIPER_BPF_PKT_IN &&
      (EXTRACT_32BITS(l2info.cookie) & ATM2_GAP_COUNT_MASK)) {
    ether_print(ndo, p, l2info.length, l2info.caplen, NULL, NULL);
    return l2info.header_len;
  }
  if (p[0] == 0x03) {
    isoclns_print(ndo, p + 1, l2info.length - 1, l2info.caplen - 1);
    return l2info.header_len;
  }
  if (juniper_ppp_heuristic_guess(ndo, p, l2info.length) != 0)
    return l2info.header_len;
  if (ip_heuristic_guess(ndo, p, l2info.length) != 0) return l2info.header_len;
  return l2info.header_len;
}

daemon_AuthUserPwd(char* username, char* password, char* errbuf) {
#ifdef _WIN32
  HANDLE Token;
  if (LogonUser(username, ".", password, LOGON32_LOGON_NETWORK,
                LOGON32_PROVIDER_DEFAULT, &Token) == 0) {
    pcap_fmt_errmsg_for_win32_err(errbuf, PCAP_ERRBUF_SIZE, GetLastError(),
                                  "LogonUser() failed");
    return -1;
  }
  if (ImpersonateLoggedOnUser(Token) == 0) {
    pcap_fmt_errmsg_for_win32_err(errbuf, PCAP_ERRBUF_SIZE, GetLastError(),
                                  "ImpersonateLoggedOnUser() failed");
    CloseHandle(Token);
    return -1;
  }
  CloseHandle(Token);
  return 0;
#else
  struct passwd* user;
  char* user_password;
#ifdef HAVE_GETSPNAM
  struct spwd* usersp;
#endif
  char* crypt_password;
  if ((user = getpwnam(username)) == NULL) {
    pcap_snprintf(errbuf, PCAP_ERRBUF_SIZE,
                  "Authentication failed: user name or password incorrect");
    return -1;
  }
#ifdef HAVE_GETSPNAM
  if ((usersp = getspnam(username)) == NULL) {
    pcap_snprintf(errbuf, PCAP_ERRBUF_SIZE,
                  "Authentication failed: user name or password incorrect");
    return -1;
  }
  user_password = usersp->sp_pwdp;
#else
  user_password = user->pw_passwd;
#endif
  crypt_password = crypt(password, user_password);
  if (crypt_password == NULL) {
    pcap_snprintf(errbuf, PCAP_ERRBUF_SIZE, "Authentication failed");
    return -1;
  }
  if (strcmp(user_password, crypt_password) != 0) {
    pcap_snprintf(errbuf, PCAP_ERRBUF_SIZE,
                  "Authentication failed: user name or password incorrect");
    return -1;
  }
  if (setuid(user->pw_uid)) {
    pcap_fmt_errmsg_for_errno(errbuf, PCAP_ERRBUF_SIZE, errno, "setuid");
    return -1;
  }
  return 0;
#endif
}

zzip_disk_entry_fopen(ZZIP_DISK* disk, ZZIP_DISK_ENTRY* entry) {
  struct zzip_file_header* header = zzip_disk_entry_to_file_header(disk, entry);
  if (!header) return 0;
  ___ ZZIP_DISK_FILE* file = malloc(sizeof(ZZIP_DISK_FILE));
  if (!file) return 0;
  file->buffer = disk->buffer;
  file->endbuf = disk->endbuf;
  file->avail = zzip_file_header_usize(header);
  if (!file->avail || zzip_file_header_data_stored(header)) {
    file->stored = zzip_file_header_to_data(header);
    DBG2("stored size %i", (int)file->avail);
    if (file->stored + file->avail >= disk->endbuf) goto error;
    return file;
  }
  file->stored = 0;
  file->zlib.opaque = 0;
  file->zlib.zalloc = Z_NULL;
  file->zlib.zfree = Z_NULL;
  file->zlib.avail_in = zzip_file_header_csize(header);
  file->zlib.next_in = zzip_file_header_to_data(header);
  DBG2("compressed size %i", (int)file->zlib.avail_in);
  if (file->zlib.next_in + file->zlib.avail_in >= disk->endbuf) goto error;
  if (!zzip_file_header_data_deflated(header)) goto error;
  if (inflateInit2(&file->zlib, -MAX_WBITS) != Z_OK) goto error;
  return file;
error:
  free(file);
  errno = EBADMSG;
  return 0;
  ____;
}

cid_parse_font_matrix(CID_Face face, CID_Parser* parser) {
  CID_FaceDict dict;
  FT_Face root = (FT_Face)&face->root;
  FT_Fixed temp[6];
  FT_Fixed temp_scale;
  if (parser->num_dict >= 0 && parser->num_dict < face->cid.num_dicts) {
    FT_Matrix* matrix;
    FT_Vector* offset;
    dict = face->cid.font_dicts + parser->num_dict;
    matrix = &dict->font_matrix;
    offset = &dict->font_offset;
    (void)cid_parser_to_fixed_array(parser, 6, temp, 3);
    temp_scale = FT_ABS(temp[3]);
    temp[5] = FT_DivFix(temp[5], temp_scale);
    temp[3] = 0x10000L;
  }
  matrix->xx = temp[0];
  matrix->yx = temp[1];
