  temp[5] = FT_DivFix(temp[5], temp_scale);
  temp[3] = 0x10000L;
}

GetCode_(gdIOCtx* fd, CODE_STATIC_DATA* scd, int code_size, int flag,
         int* ZeroDataBlockP) {
  int i, j, ret;
  unsigned char count;
  if (flag) {
    scd->curbit = 0;
    scd->lastbit = 0;
    scd->last_byte = 0;
    scd->done = FALSE;
    return 0;
  }
  if ((scd->curbit + code_size) >= scd->lastbit) {
    if (scd->done) {
      if (scd->curbit >= scd->lastbit) {
      }
      return -1;
    }
    scd->buf[0] = scd->buf[scd->last_byte - 2];
    scd->buf[1] = scd->buf[scd->last_byte - 1];
    if ((count = GetDataBlock(fd, &scd->buf[2], ZeroDataBlockP)) <= 0)
      scd->done = TRUE;
    scd->last_byte = 2 + count;
    scd->curbit = (scd->curbit - scd->lastbit) + 16;
    scd->lastbit = (2 + count) * 8;
  }
  if ((scd->curbit + code_size - 1) >= (CSD_BUF_SIZE * 8)) {
    ret = -1;
  } else {
    ret = 0;
    for (i = scd->curbit, j = 0; j < code_size; ++i, ++j) {
      ret |= ((scd->buf[i / 8] & (1 << (i % 8))) != 0) << j;
    }
  }
  scd->curbit += code_size;
  return ret;
}

RunTerminationHelper(HANDLE console_token, DWORD pid) {
  WCHAR module_path[MAX_PATH];
  GetModuleFileNameW(NULL, module_path, _countof(module_path));
  std::wstring command{module_path};
  command += L" --terminate " + std::to_wstring(pid);
  STARTUPINFOW startup_info = {};
  startup_info.cb = sizeof(startup_info);
  startup_info.lpDesktop = (LPWSTR)L"winsta0\\default";
  PROCESS_INFORMATION process_info;
  if (!CreateProcessAsUserW(console_token, NULL, (LPWSTR)command.c_str(), NULL,
                            NULL, FALSE,
                            CREATE_UNICODE_ENVIRONMENT | DETACHED_PROCESS, NULL,
                            NULL, &startup_info, &process_info)) {
    return false;
  }
  WaitForSingleObject(process_info.hProcess, INFINITE);
  DWORD exit_code;
  GetExitCodeProcess(process_info.hProcess, &exit_code);
  CloseHandle(process_info.hProcess);
  CloseHandle(process_info.hThread);
  return exit_code == 0;
}

static int crypto_report(struct sk_buff* in_skb, struct nlmsghdr* in_nlh,
                         struct nlattr** attrs) {
  struct net* net = sock_net(in_skb->sk);
  struct crypto_user_alg* p = nlmsg_data(in_nlh);
  struct crypto_alg* alg;
  struct sk_buff* skb;
  struct crypto_dump_info info;
  int err;
  if (!null_terminated(p->cru_name) || !null_terminated(p->cru_driver_name))
    return -EINVAL;
  alg = crypto_alg_match(p, 0);
  if (!alg) return -ENOENT;
  err = -ENOMEM;
  skb = nlmsg_new(NLMSG_DEFAULT_SIZE, GFP_KERNEL);
  if (!skb) goto drop_alg;
  info.in_skb = in_skb;
  info.out_skb = skb;
  info.nlmsg_seq = in_nlh->nlmsg_seq;
  info.nlmsg_flags = 0;
  err = crypto_report_alg(alg, &info);
drop_alg:
  crypto_mod_put(alg);
  if (err) return err;
  return nlmsg_unicast(net->crypto_nlsk, skb, NETLINK_CB(in_skb).portid);
}

