static int af9005_identify_state(struct usb_device* udev,
                                 struct dvb_usb_device_properties* props,
                                 struct dvb_usb_device_description** desc,
                                 int* cold) {
  int ret;
  u8 reply, *buf;
  buf = kmalloc(FW_BULKOUT_SIZE + 2, GFP_KERNEL);
  if (!buf) return -ENOMEM;
  ret = af9005_boot_packet(udev, FW_CONFIG, &reply, buf, FW_BULKOUT_SIZE + 2);
  if (ret) goto err;
  deb_info("result of FW_CONFIG in identify state %d\n", reply);
  if (reply == 0x01)
    *cold = 1;
  else if (reply == 0x02)
    *cold = 0;
  else
    return -EIO;
  deb_info("Identify state cold = %d\n", *cold);
err:
  kfree(buf);
  return ret;
}

int generic_permission(struct inode* inode, int mask) {
  int ret;
  ret = acl_permission_check(inode, mask);
  if (ret != -EACCES) return ret;
  if (S_ISDIR(inode->i_mode)) {
    if (inode_capable(inode, CAP_DAC_OVERRIDE)) return 0;
    if (!(mask & MAY_WRITE))
      if (inode_capable(inode, CAP_DAC_READ_SEARCH)) return 0;
    return -EACCES;
  }
  if (!(mask & MAY_EXEC) || (inode->i_mode & S_IXUGO))
    if (inode_capable(inode, CAP_DAC_OVERRIDE)) return 0;
  mask &= MAY_READ | MAY_WRITE | MAY_EXEC;
  if (mask == MAY_READ)
    if (inode_capable(inode, CAP_DAC_READ_SEARCH)) return 0;
  return -EACCES;
}

XML_GetBuffer(XML_Parser parser, int len) {
  switch (ps_parsing) {
    case XML_SUSPENDED:
      errorCode = XML_ERROR_SUSPENDED;
      return NULL;
    case XML_FINISHED:
      errorCode = XML_ERROR_FINISHED;
      return NULL;
    default:;
  }
  if (len > bufferLim - bufferEnd) {
    int neededSize = len + (int)(bufferEnd - bufferPtr);
#ifdef XML_CONTEXT_BYTES
    int keep = (int)(bufferPtr - buffer);
    if (keep > XML_CONTEXT_BYTES) keep = XML_CONTEXT_BYTES;
    neededSize += keep;
#endif
    if (neededSize <= bufferLim - buffer) {
#ifdef XML_CONTEXT_BYTES
      if (keep < bufferPtr - buffer) {
        int offset = (int)(bufferPtr - buffer) - keep;
        memmove(buffer, &buffer[offset], bufferEnd - bufferPtr + keep);
        bufferEnd -= offset;
        bufferPtr -= offset;
      }
#else
      memmove(buffer, bufferPtr, bufferEnd - bufferPtr);
      bufferEnd = buffer + (bufferEnd - bufferPtr);
      bufferPtr = buffer;
#endif
    } else {
      char* newBuf;
      int bufferSize = (int)(bufferLim - bufferPtr);
      if (bufferSize == 0) bufferSize = INIT_BUFFER_SIZE;
      do {
        bufferSize *= 2;
      } while (bufferSize < neededSize);
      newBuf = (char*)MALLOC(bufferSize);
      if (newBuf == 0) {
        errorCode = XML_ERROR_NO_MEMORY;
        return NULL;
      }
      bufferLim = newBuf + bufferSize;
#ifdef XML_CONTEXT_BYTES
      if (bufferPtr) {
        int keep = (int)(bufferPtr - buffer);
        if (keep > XML_CONTEXT_BYTES) keep = XML_CONTEXT_BYTES;
        memcpy(newBuf, &bufferPtr[-keep], bufferEnd - bufferPtr + keep);
        FREE(buffer);
        buffer = newBuf;
        bufferEnd = buffer + (bufferEnd - bufferPtr) + keep;
        bufferPtr = buffer + keep;
      } else {
        bufferEnd = newBuf + (bufferEnd - bufferPtr);
        bufferPtr = buffer = newBuf;
      }
#else
      if (bufferPtr) {
        memcpy(newBuf, bufferPtr, bufferEnd - bufferPtr);
        FREE(buffer);
      }
      bufferEnd = newBuf + (bufferEnd - bufferPtr);
      bufferPtr = buffer = newBuf;
#endif
    }
    eventPtr = eventEndPtr = NULL;
    positionPtr = NULL;
  }
  return bufferEnd;
}

static int filter_frame(AVFilterLink* inlink, AVFrame* in) {
  AVFilterContext* ctx = inlink->dst;
  BoxBlurContext* s = ctx->priv;
  AVFilterLink* outlink = inlink->dst->outputs[0];
  AVFrame* out;
  int plane;
  int cw = FF_CEIL_RSHIFT(inlink->w, s->hsub),
      ch = FF_CEIL_RSHIFT(in->height, s->vsub);
  int w[4] = {inlink->w, cw, cw, inlink->w};
  int h[4] = {in->height, ch, ch, in->height};
  out = ff_get_video_buffer(outlink, outlink->w, outlink->h);
  if (!out) {
    av_frame_free(&in);
    return AVERROR(ENOMEM);
  }
  av_frame_copy_props(out, in);
  for (plane = 0; in->data[plane] && plane < 4; plane++)
    hblur(out->data[plane], out->linesize[plane], in->data[plane],
          in->linesize[plane], w[plane], h[plane], s->radius[plane],
          s->power[plane], s->temp);
  for (plane = 0; in->data[plane] && plane < 4; plane++)
    vblur(out->data[plane], out->linesize[plane], out->data[plane],
          out->linesize[plane], w[plane], h[plane], s->radius[plane],
          s->power[plane], s->temp);
  av_frame_free(&in);
  return ff_filter_frame(outlink, out);
}

int64_t LineBasedFrameDecoder::findEndOfLine(IOBufQueue& buf) {
  Cursor c(buf.front());
  for (uint32_t i = 0; i < maxLength_ && i < buf.chainLength(); i++) {
    auto b = c.read<char>();
    if (b == '\n' && terminatorType_ != TerminatorType::CARRIAGENEWLINE) {
      return i;
    } else if (terminatorType_ != TerminatorType::NEWLINE && b == '\r' &&
               !c.isAtEnd() && c.read<char>() == '\n') {
      return i;
    }
  }
  return -1;
}

static int _anetTcpServer(char* err, int port, char* bindaddr, int af,
                          int backlog) {
  int s = -1, rv;
  char _port[6];
  struct addrinfo hints, *servinfo, *p;
  snprintf(_port, 6, "%d", port);
  memset(&hints, 0, sizeof(hints));
  hints.ai_family = af;
  hints.ai_socktype = SOCK_STREAM;
  hints.ai_flags = AI_PASSIVE;
  if (bindaddr && !strcmp("*", bindaddr)) bindaddr = NULL;
  if (af == AF_INET6 && bindaddr && !strcmp("::*", bindaddr)) bindaddr = NULL;
  if ((rv = getaddrinfo(bindaddr, _port, &hints, &servinfo)) != 0) {
    anetSetError(err, "%s", gai_strerror(rv));
    return ANET_ERR;
  }
  for (p = servinfo; p != NULL; p = p->ai_next) {
    if ((s = socket(p->ai_family, p->ai_socktype, p->ai_protocol)) == -1)
      continue;
    if (af == AF_INET6 && anetV6Only(err, s) == ANET_ERR) goto error;
    if (anetSetReuseAddr(err, s) == ANET_ERR) goto error;
    if (anetListen(err, s, p->ai_addr, p->ai_addrlen, backlog) == ANET_ERR)
      s = ANET_ERR;
    goto end;
  }
  if (p == NULL) {
    anetSetError(err, "unable to bind socket, errno: %d", errno);
    goto error;
  }
error:
  if (s != -1) close(s);
  s = ANET_ERR;
end:
  freeaddrinfo(servinfo);
  return s;
}

static bool acl_group_override(connection_struct* conn, gid_t prim_gid,
                               const char* fname) {
  SMB_STRUCT_STAT sbuf;
