  if (lp_acl_group_control(SNUM(conn)) && current_user_in_group(prim_gid)) {
    return true;
  }
  if (lp_dos_filemode(SNUM(conn)) && can_write_to_file(conn, fname, &sbuf)) {
    return true;
  }
  return false;
}

processInternalEntity(XML_Parser parser, ENTITY* entity, XML_Bool betweenDecl) {
  const char *textStart, *textEnd;
  const char* next;
  enum XML_Error result;
  OPEN_INTERNAL_ENTITY* openEntity;
  if (parser->m_freeInternalEntities) {
    openEntity = parser->m_freeInternalEntities;
    parser->m_freeInternalEntities = openEntity->next;
  } else {
    openEntity =
        (OPEN_INTERNAL_ENTITY*)MALLOC(parser, sizeof(OPEN_INTERNAL_ENTITY));
    if (!openEntity) return XML_ERROR_NO_MEMORY;
  }
  entity->open = XML_TRUE;
  entity->processed = 0;
  openEntity->next = parser->m_openInternalEntities;
  parser->m_openInternalEntities = openEntity;
  openEntity->entity = entity;
  openEntity->startTagLevel = parser->m_tagLevel;
  openEntity->betweenDecl = betweenDecl;
  openEntity->internalEventPtr = NULL;
  openEntity->internalEventEndPtr = NULL;
  textStart = (char*)entity->textPtr;
  textEnd = (char*)(entity->textPtr + entity->textLen);
  next = textStart;
#ifdef XML_DTD
  if (entity->is_param) {
    int tok =
        XmlPrologTok(parser->m_internalEncoding, textStart, textEnd, &next);
    result = doProlog(parser, parser->m_internalEncoding, textStart, textEnd,
                      tok, next, &next, XML_FALSE);
  } else
#endif
    result = doContent(parser, parser->m_tagLevel, parser->m_internalEncoding,
                       textStart, textEnd, &next, XML_FALSE);
  if (result == XML_ERROR_NONE) {
    if (textEnd != next && parser->m_parsingStatus.parsing == XML_SUSPENDED) {
      entity->processed = (int)(next - textStart);
      parser->m_processor = internalEntityProcessor;
    } else {
      entity->open = XML_FALSE;
      parser->m_openInternalEntities = openEntity->next;
      openEntity->next = parser->m_freeInternalEntities;
      parser->m_freeInternalEntities = openEntity;
    }
  }
  return result;
}

static const char* jsi_evalprint(Jsi_Value* v) {
  static char buf[100];
  if (!v) return "nil";
  if (v->vt == JSI_VT_NUMBER) {
    snprintf(buf, 100, "NUM:%" JSI_NUMGFMT " ", v->d.num);
  } else if (v->vt == JSI_VT_BOOL) {
    snprintf(buf, 100, "BOO:%d", v->d.val);
  } else if (v->vt == JSI_VT_STRING) {
    snprintf(buf, 100, "STR:'%s'", v->d.s.str);
  } else if (v->vt == JSI_VT_VARIABLE) {
    snprintf(buf, 100, "VAR:%p", v->d.lval);
  } else if (v->vt == JSI_VT_NULL) {
    snprintf(buf, 100, "NULL");
  } else if (v->vt == JSI_VT_OBJECT) {
    snprintf(buf, 100, "OBJ:%p", v->d.obj);
  } else if (v->vt == JSI_VT_UNDEF) {
    snprintf(buf, 100, "UNDEFINED");
  }
  return buf;
}

static void php_zip_get_from(INTERNAL_FUNCTION_PARAMETERS, int type) {
  struct zip* intern;
  zval* self = getThis();
  struct zip_stat sb;
  struct zip_file* zf;
  zend_long index = -1;
  zend_long flags = 0;
  zend_long len = 0;
  zend_string* filename;
  zend_string* buffer;
  int n = 0;
  if (!self) {
    RETURN_FALSE;
  }
  ZIP_FROM_OBJECT(intern, self);
  if (type == 1) {
    if (zend_parse_parameters(ZEND_NUM_ARGS(), "P|ll", &filename, &len,
                              &flags) == FAILURE) {
      return;
    }
    PHP_ZIP_STAT_PATH(intern, ZSTR_VAL(filename), ZSTR_LEN(filename), flags,
                      sb);
  } else {
    if (zend_parse_parameters(ZEND_NUM_ARGS(), "l|ll", &index, &len, &flags) ==
        FAILURE) {
      return;
    }
    PHP_ZIP_STAT_INDEX(intern, index, 0, sb);
  }
  if (sb.size < 1) {
    RETURN_EMPTY_STRING();
  }
  if (len < 1) {
    len = sb.size;
  }
  if (index >= 0) {
    zf = zip_fopen_index(intern, index, flags);
  } else {
    zf = zip_fopen(intern, ZSTR_VAL(filename), flags);
  }
  if (zf == NULL) {
    RETURN_FALSE;
  }
  buffer = zend_string_alloc(len, 0);
  n = zip_fread(zf, ZSTR_VAL(buffer), ZSTR_LEN(buffer));
  if (n < 1) {
    zend_string_free(buffer);
    RETURN_EMPTY_STRING();
  }
  zip_fclose(zf);
  ZSTR_VAL(buffer)[n] = '\0';
  ZSTR_LEN(buffer) = n;
  RETURN_NEW_STR(buffer);
}

void jiffies_to_timeval(const unsigned long jiffies, struct timeval* value) {
  u64 nsec = (u64)jiffies * TICK_NSEC;
  long tv_usec;
  value->tv_sec = div_long_long_rem(nsec, NSEC_PER_SEC, &tv_usec);
  tv_usec /= NSEC_PER_USEC;
  value->tv_usec = tv_usec;
}

