GF_Err Q_DecCoordOnUnitSphere(GF_BifsDecoder* codec, GF_BitStream* bs,
                              u32 NbBits, u32 NbComp, Fixed* m_ft) {
  u32 i, orient, sign;
  s32 value;
  Fixed tang[4], delta;
  s32 dir;
  if (NbComp != 2 && NbComp != 3) return GF_BAD_PARAM;
  dir = 1;
  if (NbComp == 2) dir -= 2 * gf_bs_read_int(bs, 1);
  orient = gf_bs_read_int(bs, 2);
  if ((orient == 3) && (NbComp == 2)) return GF_NON_COMPLIANT_BITSTREAM;
  for (i = 0; i < NbComp; i++) {
    value = gf_bs_read_int(bs, NbBits) - (1 << (NbBits - 1));
    sign = (value >= 0) ? 1 : -1;
    m_ft[i] = sign * Q_InverseQuantize(0, 1, NbBits - 1, sign * value);
  }
  delta = 1;
  for (i = 0; i < NbComp; i++) {
    tang[i] = gf_tan(gf_mulfix(GF_PI / 4, m_ft[i]));
    delta += gf_mulfix(tang[i], tang[i]);
  }
  delta = gf_divfix(INT2FIX(dir), gf_sqrt(delta));
  m_ft[orient] = delta;
  for (i = 0; i < NbComp; i++) {
    m_ft[(orient + i + 1) % (NbComp + 1)] = gf_mulfix(tang[i], delta);
  }
  return GF_OK;
}

mptctl_eventreport(unsigned long arg) {
  struct mpt_ioctl_eventreport __user* uarg = (void __user*)arg;
  struct mpt_ioctl_eventreport karg;
  MPT_ADAPTER* ioc;
  int iocnum;
  int numBytes, maxEvents, max;
  if (copy_from_user(&karg, uarg, sizeof(struct mpt_ioctl_eventreport))) {
    printk(KERN_ERR MYNAM
           "%s@%d::mptctl_eventreport - "
           "Unable to read in mpt_ioctl_eventreport struct @ %p\n",
           __FILE__, __LINE__, uarg);
    return -EFAULT;
  }
  if (((iocnum = mpt_verify_adapter(karg.hdr.iocnum, &ioc)) < 0) ||
      (ioc == NULL)) {
    printk(KERN_DEBUG MYNAM "%s::mptctl_eventreport() @%d - ioc%d not found!\n",
           __FILE__, __LINE__, iocnum);
    return -ENODEV;
  }
  dctlprintk(
      ioc, printk(MYIOC_s_DEBUG_FMT "mptctl_eventreport called.\n", ioc->name));
  numBytes = karg.hdr.maxDataSize - sizeof(mpt_ioctl_header);
  maxEvents = numBytes / sizeof(MPT_IOCTL_EVENTS);
  max = MPTCTL_EVENT_LOG_SIZE < maxEvents ? MPTCTL_EVENT_LOG_SIZE : maxEvents;
  if ((max < 1) || !ioc->events) return -ENODATA;
  ioc->aen_event_read_flag = 0;
  numBytes = max * sizeof(MPT_IOCTL_EVENTS);
  if (copy_to_user(uarg->eventData, ioc->events, numBytes)) {
    printk(MYIOC_s_ERR_FMT
           "%s@%d::mptctl_eventreport - "
           "Unable to write out mpt_ioctl_eventreport struct @ %p\n",
           ioc->name, __FILE__, __LINE__, ioc->events);
    return -EFAULT;
  }
  return 0;
}

void Huff_offsetReceive(node_t* node, int* ch, byte* fin, int* offset) {
  bloc = *offset;
  while (node && node->symbol == INTERNAL_NODE) {
    if (get_bit(fin)) {
      node = node->right;
    } else {
      node = node->left;
    }
  }
  if (!node) {
    *ch = 0;
    return;
  }
  *ch = node->symbol;
  *offset = bloc;
}

static int mb86a20s_read_status(struct dvb_frontend* fe,
                                enum fe_status* status) {
  struct mb86a20s_state* state = fe->demodulator_priv;
  int val;
  *status = 0;
  val = mb86a20s_readreg(state, 0x0a) & 0xf;
  if (val < 0) return val;
  if (val >= 2) *status |= FE_HAS_SIGNAL;
  if (val >= 4) *status |= FE_HAS_CARRIER;
  if (val >= 5) *status |= FE_HAS_VITERBI;
  if (val >= 7) *status |= FE_HAS_SYNC;
  if (val >= 8) *status |= FE_HAS_LOCK;
  dev_dbg(&state->i2c->dev, "%s: Status = 0x%02x (state = %d)\n", __func__,
          *status, val);
  return val;
}

void Compute(OpKernelContext* ctx) override {
  const auto splits = ctx->input(0).flat<int64>();
  const auto values = ctx->input(1).flat<Tidx>();
  const Tensor& size_t = ctx->input(2);
  const auto weights = ctx->input(3).flat<T>();
  const int64 weights_size = weights.size();
  Tidx size = size_t.scalar<Tidx>()();
  OP_REQUIRES(
      ctx, size >= 0,
      errors::InvalidArgument("size (", size, ") must be non-negative"));
  int num_rows = splits.size() - 1;
  int num_values = values.size();
  int batch_idx = 0;
  Tensor* out_t;
  OP_REQUIRES_OK(
      ctx, ctx->allocate_output(0, TensorShape({num_rows, size}), &out_t));
  functor::SetZeroFunctor<Device, T> fill;
  fill(ctx->eigen_device<Device>(), out_t->flat<T>());
  const auto out = out_t->matrix<T>();
  for (int idx = 0; idx < num_values; ++idx) {
    while (idx >= splits(batch_idx)) {
      batch_idx++;
    }
    Tidx bin = values(idx);
    OP_REQUIRES(ctx, bin >= 0,
                errors::InvalidArgument("Input must be non-negative"));
    if (bin < size) {
      if (binary_output_) {
        out(batch_idx - 1, bin) = T(1);
      } else {
        T value = (weights_size > 0) ? weights(idx) : T(1);
        out(batch_idx - 1, bin) += value;
      }
    }
  }
}

status_t AudioFlinger::EffectModule::command(uint32_t cmdCode, uint32_t cmdSize,
                                             void* pCmdData,
                                             uint32_t* replySize,
                                             void* pReplyData) {
  Mutex::Autolock _l(mLock);
  ALOGVV("command(), cmdCode: %d, mEffectInterface: %p", cmdCode,
         mEffectInterface);
  if (mState == DESTROYED || mEffectInterface == NULL) {
    return NO_INIT;
  }
  if (mStatus != NO_ERROR) {
    return mStatus;
  }
  if (cmdCode == EFFECT_CMD_GET_PARAM &&
      (*replySize < sizeof(effect_param_t) ||
       ((effect_param_t*)pCmdData)->psize >
           *replySize - sizeof(effect_param_t))) {
    android_errorWriteLog(0x534e4554, "29251553");
    return -EINVAL;
  }
  status_t status = (*mEffectInterface)
                        ->command(mEffectInterface, cmdCode, cmdSize, pCmdData,
                                  replySize, pReplyData);
  if (cmdCode != EFFECT_CMD_GET_PARAM && status == NO_ERROR) {
    uint32_t size = (replySize == NULL) ? 0 : *replySize;
    for (size_t i = 1; i < mHandles.size(); i++) {
      EffectHandle* h = mHandles[i];
      if (h != NULL && !h->destroyed_l()) {
        h->commandExecuted(cmdCode, cmdSize, pCmdData, size, pReplyData);
      }
    }
  }
  return status;
}

bool PlatformFontSkia::InitDefaultFont() {
  if (g_default_font.Get()) return true;
  bool success = false;
  std::string family = kFallbackFontFamilyName;
  int size_pixels = 12;
  int style = Font::NORMAL;
  Font::Weight weight = Font::Weight::NORMAL;
  FontRenderParams params;
  const SkiaFontDelegate* delegate = SkiaFontDelegate::instance();
  if (delegate) {
    delegate->GetDefaultFontDescription(&family, &size_pixels, &style, &weight,
                                        &params);
  } else if (default_font_description_) {
#if defined(OS_CHROMEOS)
    FontRenderParamsQuery query;
    CHECK(FontList::ParseDescription(*default_font_description_,
                                     &query.families, &query.style,
                                     &query.pixel_size, &query.weight))
        << "Failed to parse font description " << *default_font_description_;
    params = gfx::GetFontRenderParams(query, &family);
    size_pixels = query.pixel_size;
    style = query.style;
    weight = query.weight;
#else
    NOTREACHED();
#endif
  }
  sk_sp<SkTypeface> typeface =
      CreateSkTypeface(style & Font::ITALIC, weight, &family, &success);
  if (!success) return false;
  g_default_font.Get() = new PlatformFontSkia(
      std::move(typeface), family, size_pixels, style, weight, params);
  return true;
}

static bool do_write_pids(pid_t tpid, const char* contrl, const char* cg,
                          const char* file, const char* buf) {
  int sock[2] = {-1, -1};
  pid_t qpid, cpid = -1;
  FILE* pids_file = NULL;
  bool answer = false, fail = false;
  pids_file = open_pids_file(contrl, cg);
  if (!pids_file) return false;
  if (socketpair(AF_UNIX, SOCK_DGRAM, 0, sock) < 0) {
    perror("socketpair");
    goto out;
  }
  cpid = fork();
  if (cpid == -1) goto out;
  if (!cpid) {
    fclose(pids_file);
    pid_from_ns_wrapper(sock[1], tpid);
  }
  const char* ptr = buf;
  while (sscanf(ptr, "%d", &qpid) == 1) {
    struct ucred cred;
    char v;
    if (write(sock[0], &qpid, sizeof(qpid)) != sizeof(qpid)) {
      fprintf(stderr, "%s: error writing pid to child: %s\n", __func__,
              strerror(errno));
      goto out;
    }
    if (recv_creds(sock[0], &cred, &v)) {
      if (v == '0') {
        if (fprintf(pids_file, "%d", (int)cred.pid) < 0) fail = true;
      }
    }
    ptr = strchr(ptr, '\n');
    if (!ptr) break;
    ptr++;
  }
  qpid = -1;
  if (write(sock[0], &qpid, sizeof(qpid)) != sizeof(qpid))
    fprintf(stderr, "Warning: failed to ask child to exit\n");
  if (!fail) answer = true;
out:
  if (cpid != -1) wait_for_pid(cpid);
  if (sock[0] != -1) {
    close(sock[0]);
    close(sock[1]);
  }
  if (pids_file) {
    if (fclose(pids_file) != 0) answer = false;
  }
  return answer;
}

static XMLSharedNodeList* find_impl(xmlXPathContext* ctxt,
                                    const string& xpath) {
  xmlXPathObject* result = xmlXPathEval((const xmlChar*)xpath.c_str(), ctxt);
  if (!result) {
    xmlXPathFreeContext(ctxt);
    xmlFreeDoc(ctxt->doc);
    throw XMLException("Invalid XPath: " + xpath);
  }
  if (result->type != XPATH_NODESET) {
    xmlXPathFreeObject(result);
    xmlXPathFreeContext(ctxt);
    xmlFreeDoc(ctxt->doc);
    throw XMLException("Only nodeset result types are supported.");
  }
  xmlNodeSet* nodeset = result->nodesetval;
  XMLSharedNodeList* nodes = new XMLSharedNodeList();
  if (nodeset) {
    for (int i = 0; i < nodeset->nodeNr; ++i) {
      XMLNode* node = readnode(nodeset->nodeTab[i]);
      nodes->push_back(boost::shared_ptr<XMLNode>(node));
    }
  } else {
  }
  xmlXPathFreeObject(result);
  return nodes;
}

int ovl_setattr(struct dentry* dentry, struct iattr* attr) {
  int err;
  struct dentry* upperdentry;
  err = ovl_want_write(dentry);
  if (err) goto out;
  upperdentry = ovl_dentry_upper(dentry);
  if (upperdentry) {
    mutex_lock(&upperdentry->d_inode->i_mutex);
    err = notify_change(upperdentry, attr, NULL);
    mutex_unlock(&upperdentry->d_inode->i_mutex);
  } else {
    err = ovl_copy_up_last(dentry, attr, false);
  }
  ovl_drop_write(dentry);
out:
  return err;
}

isofs_export_encode_fh(struct inode* inode, __u32* fh32, int* max_len,
                       struct inode* parent) {
  struct iso_inode_info* ei = ISOFS_I(inode);
  int len = *max_len;
  int type = 1;
  __u16* fh16 = (__u16*)fh32;
  if (parent && (len < 5)) {
    *max_len = 5;
    return 255;
  } else if (len < 3) {
    *max_len = 3;
    return 255;
  }
  len = 3;
  fh32[0] = ei->i_iget5_block;
  fh16[2] = (__u16)ei->i_iget5_offset;
  fh32[2] = inode->i_generation;
  if (parent) {
    struct iso_inode_info* eparent;
    eparent = ISOFS_I(parent);
    fh32[3] = eparent->i_iget5_block;
    fh16[3] = (__u16)eparent->i_iget5_offset;
    fh32[4] = parent->i_generation;
    len = 5;
    type = 2;
  }
  *max_len = len;
  return type;
}

Status RangeSize(const Tensor* start_t, const Tensor* limit_t,
                 const Tensor* delta_t, InferenceContext* const c) {
  T start = start_t->scalar<T>()();
  T limit = limit_t->scalar<T>()();
  T delta = delta_t->scalar<T>()();
  if (start > limit && delta > T(0)) {
    return errors::InvalidArgument(
        "Requires start <= limit when delta > 0: ", start, "/", limit);
  }
  if (start < limit && delta < T(0)) {
    return errors::InvalidArgument(
        "Requires start >= limit when delta < 0: ", start, "/", limit);
  }
  if (delta == T(0)) {
    return errors::InvalidArgument("Requires delta != 0");
  }
  auto size = (std::is_integral<T>::value
                   ? ((Eigen::numext::abs(limit - start) +
                       Eigen::numext::abs(delta) - T(1)) /
                      Eigen::numext::abs(delta))
                   : (Eigen::numext::ceil(
                         Eigen::numext::abs((limit - start) / delta))));
  if (size > std::numeric_limits<int64_t>::max()) {
    return errors::InvalidArgument("Requires ((limit - start) / delta) <= ",
                                   std::numeric_limits<int64_t>::max());
  }
  c->set_output(0, c->Vector(static_cast<int64_t>(size)));
  return Status::OK();
}

static void process_request(struct connection* conn) {
  num_requests++;
  if (!parse_request(conn)) {
    default_reply(conn, 400, "Bad Request",
                  "You sent a request that the server couldn't understand.");
  } else if (is_https_redirect(conn)) {
    redirect_https(conn);
  } else if (auth_key != NULL && (conn->authorization == NULL ||
                                  strcmp(conn->authorization, auth_key))) {
    default_reply(conn, 401, "Unauthorized",
                  "Access denied due to invalid credentials.");
  } else if (strcmp(conn->method, "GET") == 0) {
    process_get(conn);
  } else if (strcmp(conn->method, "HEAD") == 0) {
    process_get(conn);
    conn->header_only = 1;
  } else {
    default_reply(conn, 501, "Not Implemented",
                  "The method you specified is not implemented.");
  }
  conn->state = SEND_HEADER;
  free(conn->request);
  conn->request = NULL;
}

void blk_cleanup_queue(struct request_queue* q) {
  mutex_lock(&q->sysfs_lock);
  blk_set_queue_dying(q);
  blk_queue_flag_set(QUEUE_FLAG_NOMERGES, q);
  blk_queue_flag_set(QUEUE_FLAG_NOXMERGES, q);
  blk_queue_flag_set(QUEUE_FLAG_DYING, q);
  mutex_unlock(&q->sysfs_lock);
  blk_freeze_queue(q);
  rq_qos_exit(q);
  blk_queue_flag_set(QUEUE_FLAG_DEAD, q);
  blk_flush_integrity();
  del_timer_sync(&q->backing_dev_info->laptop_mode_wb_timer);
  blk_sync_queue(q);
  if (queue_is_mq(q)) blk_mq_exit_queue(q);
  percpu_ref_exit(&q->q_usage_counter);
  blk_put_queue(q);
}

void Location::SetLocation(const String& url, LocalDOMWindow* current_window,
                           LocalDOMWindow* entered_window,
                           ExceptionState* exception_state,
                           SetLocationPolicy set_location_policy) {
  if (!IsAttached()) return;
  if (!current_window->GetFrame()) return;
  Document* entered_document = entered_window->document();
  if (!entered_document) return;
  KURL completed_url = entered_document->CompleteURL(url);
  if (completed_url.IsNull()) return;
  if (!current_window->GetFrame()->CanNavigate(*dom_window_->GetFrame(),
                                               completed_url)) {
    if (exception_state) {
      exception_state->ThrowSecurityError(
          "The current window does not have permission to navigate the target "
          "frame to '" +
          url + "'.");
    }
    return;
  }
  if (exception_state && !completed_url.IsValid()) {
    exception_state->ThrowDOMException(DOMExceptionCode::kSyntaxError,
                                       "'" + url + "' is not a valid URL.");
    return;
  }
  if (dom_window_->IsInsecureScriptAccess(*current_window, completed_url))
    return;
  V8DOMActivityLogger* activity_logger =
      V8DOMActivityLogger::CurrentActivityLoggerIfIsolatedWorld();
  if (activity_logger) {
    Vector<String> argv;
    argv.push_back("LocalDOMWindow");
    argv.push_back("url");
    argv.push_back(entered_document->Url());
    argv.push_back(completed_url);
    activity_logger->LogEvent("blinkSetAttribute", argv.size(), argv.data());
  }
  WebFrameLoadType frame_load_type = WebFrameLoadType::kStandard;
  if (set_location_policy == SetLocationPolicy::kReplaceThisFrame)
    frame_load_type = WebFrameLoadType::kReplaceCurrentItem;
  dom_window_->GetFrame()->ScheduleNavigation(*current_window->document(),
                                              completed_url, frame_load_type,
                                              UserGestureStatus::kNone);
}

int ConnectionImpl::saveHeader(const nghttp2_frame* frame, HeaderString&& name,
                               HeaderString&& value) {
  StreamImpl* stream = getStream(frame->hd.stream_id);
  if (!stream) {
    stats_.headers_cb_no_stream_.inc();
    return 0;
  }
  stream->saveHeader(std::move(name), std::move(value));
  if (stream->headers_->byteSize() > max_request_headers_kb_ * 1024) {
    stats_.header_overflow_.inc();
    return NGHTTP2_ERR_TEMPORAL_CALLBACK_FAILURE;
  } else {
    return 0;
  }
}

void ssl_update_cache(SSL_CONNECTION* s, int mode) {
  int i;
  if (s->session->session_id_length == 0) return;
  if (s->server && s->session->sid_ctx_length == 0 &&
      (s->verify_mode & SSL_VERIFY_PEER) != 0)
    return;
  i = s->session_ctx->session_cache_mode;
  if ((i & mode) != 0 && (!s->hit || SSL_CONNECTION_IS_TLS13(s))) {
    if ((i & SSL_SESS_CACHE_NO_INTERNAL_STORE) == 0 &&
        (!SSL_CONNECTION_IS_TLS13(s) || !s->server ||
         (s->max_early_data > 0 && (s->options & SSL_OP_NO_ANTI_REPLAY) == 0) ||
         s->session_ctx->remove_session_cb != NULL ||
         (s->options & SSL_OP_NO_TICKET) != 0))
      SSL_CTX_add_session(s->session_ctx, s->session);
    if (s->session_ctx->new_session_cb != NULL) {
      SSL_SESSION_up_ref(s->session);
      if (!s->session_ctx->new_session_cb(SSL_CONNECTION_GET_SSL(s),
                                          s->session))
        SSL_SESSION_free(s->session);
    }
  }
  if ((!(i & SSL_SESS_CACHE_NO_AUTO_CLEAR)) && ((i & mode) == mode)) {
    TSAN_QUALIFIER int* stat;
    if (mode & SSL_SESS_CACHE_CLIENT)
      stat = &s->session_ctx->stats.sess_connect_good;
    else
      stat = &s->session_ctx->stats.sess_accept_good;
    if ((ssl_tsan_load(s->session_ctx, stat) & 0xff) == 0xff)
      SSL_CTX_flush_sessions(s->session_ctx, (unsigned long)time(NULL));
  }
}

static inline int check_entry_size_and_hooks(struct arpt_entry* e,
                                             struct xt_table_info* newinfo,
                                             const unsigned char* base,
                                             const unsigned char* limit,
                                             const unsigned int* hook_entries,
                                             const unsigned int* underflows,
                                             unsigned int valid_hooks) {
  unsigned int h;
  int err;
  if ((unsigned long)e % __alignof__(struct arpt_entry) != 0 ||
      (unsigned char*)e + sizeof(struct arpt_entry) >= limit ||
      (unsigned char*)e + e->next_offset > limit) {
    duprintf("Bad offset %p\n", e);
    return -EINVAL;
  }
  if (e->next_offset <
      sizeof(struct arpt_entry) + sizeof(struct xt_entry_target)) {
    duprintf("checking: element %p size %u\n", e, e->next_offset);
    return -EINVAL;
  }
  if (!arp_checkentry(&e->arp)) return -EINVAL;
  err = xt_check_entry_offsets(e, e->target_offset, e->next_offset);
  if (err) return err;
  for (h = 0; h < NF_ARP_NUMHOOKS; h++) {
    if (!(valid_hooks & (1 << h))) continue;
    if ((unsigned char*)e - base == hook_entries[h])
      newinfo->hook_entry[h] = hook_entries[h];
    if ((unsigned char*)e - base == underflows[h]) {
      if (!check_underflow(e)) {
        pr_debug(
            "Underflows must be unconditional and "
            "use the STANDARD target with "
            "ACCEPT/DROP\n");
        return -EINVAL;
      }
      newinfo->underflow[h] = underflows[h];
    }
  }
  e->counters = ((struct xt_counters){0, 0});
  e->comefrom = 0;
  return 0;
}

ZEND_API void zend_objects_store_del_ref_by_handle_ex(
    zend_object_handle handle, const zend_object_handlers* handlers TSRMLS_DC) {
  struct _store_object* obj;
  int failure = 0;
  if (!EG(objects_store).object_buckets) {
    return;
  }
  obj = &EG(objects_store).object_buckets[handle].bucket.obj;
  if (EG(objects_store).object_buckets[handle].valid) {
    if (obj->refcount == 1) {
      if (!EG(objects_store).object_buckets[handle].destructor_called) {
        EG(objects_store).object_buckets[handle].destructor_called = 1;
        if (obj->dtor) {
          if (handlers && !obj->handlers) {
            obj->handlers = handlers;
          }
          zend_try { obj->dtor(obj->object, handle TSRMLS_CC); }
          zend_catch { failure = 1; }
          zend_end_try();
        }
      }
      obj = &EG(objects_store).object_buckets[handle].bucket.obj;
      if (obj->refcount == 1) {
        GC_REMOVE_ZOBJ_FROM_BUFFER(obj);
        if (obj->free_storage) {
          zend_try { obj->free_storage(obj->object TSRMLS_CC); }
          zend_catch { failure = 1; }
          zend_end_try();
        }
        ZEND_OBJECTS_STORE_ADD_TO_FREE_LIST();
      }
    }
  }
  obj->refcount--;
#if ZEND_DEBUG_OBJECTS
  if (obj->refcount == 0) {
    fprintf(stderr, "Deallocated object id #%d\n", handle);
  } else {
    fprintf(stderr, "Decreased refcount of object id #%d\n", handle);
  }
#endif
  if (failure) {
    zend_bailout();
  }
}

