static int mwifiex_pcie_init_evt_ring(struct mwifiex_adapter* adapter) {
  struct pcie_service_card* card = adapter->card;
  struct mwifiex_evt_buf_desc* desc;
  struct sk_buff* skb;
  dma_addr_t buf_pa;
  int i;
  for (i = 0; i < MWIFIEX_MAX_EVT_BD; i++) {
    skb = dev_alloc_skb(MAX_EVENT_SIZE);
    if (!skb) {
      mwifiex_dbg(adapter, ERROR, "Unable to allocate skb for EVENT buf.\n");
      kfree(card->evtbd_ring_vbase);
      return -ENOMEM;
    }
    skb_put(skb, MAX_EVENT_SIZE);
    if (mwifiex_map_pci_memory(adapter, skb, MAX_EVENT_SIZE,
                               PCI_DMA_FROMDEVICE))
      return -1;
    buf_pa = MWIFIEX_SKB_DMA_ADDR(skb);
    mwifiex_dbg(adapter, EVENT,
                "info: EVT ring: skb=%p len=%d data=%p buf_pa=%#x:%x\n", skb,
                skb->len, skb->data, (u32)buf_pa, (u32)((u64)buf_pa >> 32));
    card->evt_buf_list[i] = skb;
    card->evtbd_ring[i] = (void*)(card->evtbd_ring_vbase + (sizeof(*desc) * i));
    desc = card->evtbd_ring[i];
    desc->paddr = buf_pa;
    desc->len = (u16)skb->len;
    desc->flags = 0;
  }
  return 0;
}

int32_t PPB_Flash_MessageLoop_Impl::InternalRun(
    const RunFromHostProxyCallback& callback) {
  if (state_->run_called()) {
    if (!callback.is_null()) callback.Run(PP_ERROR_FAILED);
    return PP_ERROR_FAILED;
  }
  state_->set_run_called();
  state_->set_run_callback(callback);
  scoped_refptr<State> state_protector(state_);
  {
    base::MessageLoop::ScopedNestableTaskAllower allow(
        base::MessageLoop::current());
    base::MessageLoop::current()->Run();
  }
  return state_protector->result();
}

void oz_hcd_get_desc_cnf(void* hport, u8 req_id, int status, const u8* desc,
                         int length, int offset, int total_size) {
  struct oz_port* port = hport;
  struct urb* urb;
  int err = 0;
  oz_dbg(ON, "oz_hcd_get_desc_cnf length = %d offs = %d tot_size = %d\n",
         length, offset, total_size);
  urb = oz_find_urb_by_id(port, 0, req_id);
  if (!urb) return;
  if (status == 0) {
    int copy_len;
    int required_size = urb->transfer_buffer_length;
    if (required_size > total_size) required_size = total_size;
    copy_len = required_size - offset;
    if (length <= copy_len) copy_len = length;
    memcpy(urb->transfer_buffer + offset, desc, copy_len);
    offset += copy_len;
    if (offset < required_size) {
      struct usb_ctrlrequest* setup =
          (struct usb_ctrlrequest*)urb->setup_packet;
      unsigned wvalue = le16_to_cpu(setup->wValue);
      if (oz_enqueue_ep_urb(port, 0, 0, urb, req_id))
        err = -ENOMEM;
      else if (oz_usb_get_desc_req(port->hpd, req_id, setup->bRequestType,
                                   (u8)(wvalue >> 8), (u8)wvalue, setup->wIndex,
                                   offset, required_size - offset)) {
        oz_dequeue_ep_urb(port, 0, 0, urb);
        err = -ENOMEM;
      }
      if (err == 0) return;
    }
  }
  urb->actual_length = total_size;
  oz_complete_urb(port->ozhcd->hcd, urb, 0);
}

static bigint* sig_verify(BI_CTX* ctx, const uint8_t* sig, int sig_len,
                          bigint* modulus, bigint* pub_exp) {
  int i, size;
  bigint *decrypted_bi, *dat_bi;
  bigint* bir = NULL;
  uint8_t* block = (uint8_t*)malloc(sig_len);
  dat_bi = bi_import(ctx, sig, sig_len);
  ctx->mod_offset = BIGINT_M_OFFSET;
  decrypted_bi = bi_mod_power2(ctx, dat_bi, modulus, pub_exp);
  bi_export(ctx, decrypted_bi, block, sig_len);
  ctx->mod_offset = BIGINT_M_OFFSET;
  i = 10;
  while (block[i++] && i < sig_len);
  size = sig_len - i;
  if (size > 0) {
    int len;
    const uint8_t* sig_ptr = get_signature(&block[i], &len);
    if (sig_ptr) {
      bir = bi_import(ctx, sig_ptr, len);
    }
  }
  free(block);
  bi_clear_cache(ctx);
  return bir;
}

int prepare_binprm(struct linux_binprm* bprm) {
  struct inode* inode = file_inode(bprm->file);
  umode_t mode = inode->i_mode;
  int retval;
  bprm->cred->euid = current_euid();
  bprm->cred->egid = current_egid();
  if (!(bprm->file->f_path.mnt->mnt_flags & MNT_NOSUID) &&
      !task_no_new_privs(current) &&
      kuid_has_mapping(bprm->cred->user_ns, inode->i_uid) &&
      kgid_has_mapping(bprm->cred->user_ns, inode->i_gid)) {
    if (mode & S_ISUID) {
      bprm->per_clear |= PER_CLEAR_ON_SETID;
      bprm->cred->euid = inode->i_uid;
    }
    if ((mode & (S_ISGID | S_IXGRP)) == (S_ISGID | S_IXGRP)) {
      bprm->per_clear |= PER_CLEAR_ON_SETID;
      bprm->cred->egid = inode->i_gid;
    }
  }
  retval = security_bprm_set_creds(bprm);
  if (retval) return retval;
  bprm->cred_prepared = 1;
  memset(bprm->buf, 0, BINPRM_BUF_SIZE);
  return kernel_read(bprm->file, 0, bprm->buf, BINPRM_BUF_SIZE);
}

static int nla_validate_array(const struct nlattr* head, int len, int maxtype,
                              const struct nla_policy* policy,
                              struct netlink_ext_ack* extack,
                              unsigned int validate) {
  const struct nlattr* entry;
  int rem;
  nla_for_each_attr(entry, head, len, rem) {
    int ret;
    if (nla_len(entry) == 0) continue;
    if (nla_len(entry) < NLA_HDRLEN) {
      NL_SET_ERR_MSG_ATTR(extack, entry, "Array element too short");
      return -ERANGE;
    }
    ret = __nla_validate(nla_data(entry), nla_len(entry), maxtype, policy,
                         validate, extack);
    if (ret < 0) return ret;
  }
  return 0;
}

bool PDFiumEngine::HandleEvent(const pp::InputEvent& event) {
  DCHECK(!defer_page_unload_);
  defer_page_unload_ = true;
  bool rv = false;
  switch (event.GetType()) {
    case PP_INPUTEVENT_TYPE_MOUSEDOWN:
      rv = OnMouseDown(pp::MouseInputEvent(event));
      break;
    case PP_INPUTEVENT_TYPE_MOUSEUP:
      rv = OnMouseUp(pp::MouseInputEvent(event));
      break;
    case PP_INPUTEVENT_TYPE_MOUSEMOVE:
      rv = OnMouseMove(pp::MouseInputEvent(event));
      break;
    case PP_INPUTEVENT_TYPE_KEYDOWN:
      rv = OnKeyDown(pp::KeyboardInputEvent(event));
      break;
    case PP_INPUTEVENT_TYPE_KEYUP:
      rv = OnKeyUp(pp::KeyboardInputEvent(event));
      break;
    case PP_INPUTEVENT_TYPE_CHAR:
      rv = OnChar(pp::KeyboardInputEvent(event));
      break;
    case PP_INPUTEVENT_TYPE_TOUCHSTART: {
      KillTouchTimer(next_touch_timer_id_);
      pp::TouchInputEvent touch_event(event);
      if (touch_event.GetTouchCount(PP_TOUCHLIST_TYPE_TARGETTOUCHES) == 1)
        ScheduleTouchTimer(touch_event);
      break;
    }
    case PP_INPUTEVENT_TYPE_TOUCHEND:
      KillTouchTimer(next_touch_timer_id_);
      break;
    case PP_INPUTEVENT_TYPE_TOUCHMOVE:
      KillTouchTimer(next_touch_timer_id_);
    default:
      break;
  }
  DCHECK(defer_page_unload_);
  defer_page_unload_ = false;
  for (int page_index : deferred_page_unloads_) pages_[page_index]->Unload();
  deferred_page_unloads_.clear();
  return rv;
}

void HTPStateFree(void* state) {
  SCEnter();
  HtpState* s = (HtpState*)state;
  if (s == NULL) {
    SCReturn;
  }
  if (s->connp != NULL) {
    SCLogDebug("freeing HTP state");
    uint64_t tx_id;
    uint64_t total_txs = HTPStateGetTxCnt(state);
    if (s->conn != NULL) {
      for (tx_id = 0; tx_id < total_txs; tx_id++) {
        htp_tx_t* tx = HTPStateGetTx(s, tx_id);
        if (tx != NULL) {
          HtpTxUserData* htud = (HtpTxUserData*)htp_tx_get_user_data(tx);
          HtpTxUserDataFree(s, htud);
          htp_tx_set_user_data(tx, NULL);
        }
      }
    }
    htp_connp_destroy_all(s->connp);
  }
  HTPFree(s, sizeof(HtpState));
#ifdef DEBUG
  SCMutexLock(&htp_state_mem_lock);
  htp_state_memcnt--;
  htp_state_memuse -= sizeof(HtpState);
  SCLogDebug("htp memory %" PRIu64 " (%" PRIu64 ")", htp_state_memuse,
             htp_state_memcnt);
  SCMutexUnlock(&htp_state_mem_lock);
#endif
  SCReturn;
}

