asmlinkage void __sched schedule(void) {
  struct task_struct *prev, *next;
  unsigned long* switch_count;
  struct rq* rq;
  int cpu;
need_resched:
  preempt_disable();
  cpu = smp_processor_id();
  rq = cpu_rq(cpu);
  rcu_note_context_switch(cpu);
  prev = rq->curr;
  release_kernel_lock(prev);
need_resched_nonpreemptible:
  schedule_debug(prev);
  if (sched_feat(HRTICK)) hrtick_clear(rq);
  raw_spin_lock_irq(&rq->lock);
  clear_tsk_need_resched(prev);
  switch_count = &prev->nivcsw;
  if (prev->state && !(preempt_count() & PREEMPT_ACTIVE)) {
    if (unlikely(signal_pending_state(prev->state, prev))) {
      prev->state = TASK_RUNNING;
    } else {
      if (prev->flags & PF_WQ_WORKER) {
        struct task_struct* to_wakeup;
        to_wakeup = wq_worker_sleeping(prev, cpu);
        if (to_wakeup) try_to_wake_up_local(to_wakeup);
      }
      deactivate_task(rq, prev, DEQUEUE_SLEEP);
    }
    switch_count = &prev->nvcsw;
  }
  pre_schedule(rq, prev);
  if (unlikely(!rq->nr_running)) idle_balance(cpu, rq);
  put_prev_task(rq, prev);
  next = pick_next_task(rq);
  if (likely(prev != next)) {
    sched_info_switch(prev, next);
    perf_event_task_sched_out(prev, next);
    rq->nr_switches++;
    rq->curr = next;
    ++*switch_count;
    context_switch(rq, prev, next);
    cpu = smp_processor_id();
    rq = cpu_rq(cpu);
  } else
    raw_spin_unlock_irq(&rq->lock);
  post_schedule(rq);
  if (unlikely(reacquire_kernel_lock(prev))) goto need_resched_nonpreemptible;
  preempt_enable_no_resched();
  if (need_resched()) goto need_resched;
}

do_bid_note(struct magic_set* ms, unsigned char* nbuf, uint32_t type,
            int swap __attribute__((__unused__)), uint32_t namesz,
            uint32_t descsz, size_t noff, size_t doff, int* flags) {
  if (namesz == 4 && strcmp((char*)&nbuf[noff], "GNU") == 0 &&
      type == NT_GNU_BUILD_ID && (descsz >= 4 || descsz <= 20)) {
    uint8_t desc[20];
    const char* btype;
    uint32_t i;
    *flags |= FLAGS_DID_BUILD_ID;
    switch (descsz) {
      case 8:
        btype = "xxHash";
        break;
      case 16:
        btype = "md5/uuid";
        break;
      case 20:
        btype = "sha1";
        break;
      default:
        btype = "unknown";
        break;
    }
    if (file_printf(ms, ", BuildID[%s]=", btype) == -1) return 1;
    (void)memcpy(desc, &nbuf[doff], descsz);
    for (i = 0; i < descsz; i++)
      if (file_printf(ms, "%02x", desc[i]) == -1) return 1;
    return 1;
  }
  return 0;
}

static enum hrtimer_restart posix_timer_fn(struct hrtimer* timer) {
  struct k_itimer* timr;
  unsigned long flags;
  int si_private = 0;
  enum hrtimer_restart ret = HRTIMER_NORESTART;
  timr = container_of(timer, struct k_itimer, it.real.timer);
  spin_lock_irqsave(&timr->it_lock, flags);
  timr->it_active = 0;
  if (timr->it_interval != 0) si_private = ++timr->it_requeue_pending;
  if (posix_timer_event(timr, si_private)) {
    if (timr->it_interval != 0) {
      ktime_t now = hrtimer_cb_get_time(timer);
#ifdef CONFIG_HIGH_RES_TIMERS
      {
        ktime_t kj = NSEC_PER_SEC / HZ;
        if (timr->it_interval < kj) now = ktime_add(now, kj);
      }
#endif
      timr->it_overrun +=
          (unsigned int)hrtimer_forward(timer, now, timr->it_interval);
      ret = HRTIMER_RESTART;
      ++timr->it_requeue_pending;
      timr->it_active = 1;
    }
  }
  unlock_timer(timr, flags);
  return ret;
}

static int ttusb_dec_send_command(struct ttusb_dec* dec, const u8 command,
                                  int param_length, const u8 params[],
                                  int* result_length, u8 cmd_result[]) {
  int result, actual_len;
  u8* b;
  dprintk("%s\n", __func__);
  b = kmalloc(COMMAND_PACKET_SIZE + 4, GFP_KERNEL);
  if (!b) return -ENOMEM;
  if ((result = mutex_lock_interruptible(&dec->usb_mutex))) {
    kfree(b);
    printk("%s: Failed to lock usb mutex.\n", __func__);
    return result;
  }
  b[0] = 0xaa;
  b[1] = ++dec->trans_count;
  b[2] = command;
  b[3] = param_length;
  if (params) memcpy(&b[4], params, param_length);
  if (debug) {
    printk(KERN_DEBUG "%s: command: %*ph\n", __func__, param_length, b);
  }
  result = usb_bulk_msg(dec->udev, dec->command_pipe, b,
                        COMMAND_PACKET_SIZE + 4, &actual_len, 1000);
  if (result) {
    printk("%s: command bulk message failed: error %d\n", __func__, result);
    mutex_unlock(&dec->usb_mutex);
    kfree(b);
    return result;
  }
  result = usb_bulk_msg(dec->udev, dec->result_pipe, b, COMMAND_PACKET_SIZE + 4,
                        &actual_len, 1000);
  if (result) {
    printk("%s: result bulk message failed: error %d\n", __func__, result);
    mutex_unlock(&dec->usb_mutex);
    kfree(b);
    return result;
  } else {
    if (debug) {
      printk(KERN_DEBUG "%s: result: %*ph\n", __func__, actual_len, b);
    }
    if (result_length) *result_length = b[3];
    if (cmd_result && b[3] > 0) memcpy(cmd_result, &b[4], b[3]);
    mutex_unlock(&dec->usb_mutex);
    kfree(b);
    return 0;
  }
}

void* hashtable_get(hashtable_t* hashtable, const char* key) {
  pair_t* pair;
  size_t hash;
  bucket_t* bucket;
  hash = hash_str(key);
  bucket = &hashtable->buckets[hash % num_buckets(hashtable)];
  pair = hashtable_find_pair(hashtable, bucket, key, hash);
  if (!pair) return NULL;
  return pair->value;
}

