void ath_tx_aggr_sleep(struct ieee80211_sta* sta, struct ath_softc* sc,
                       struct ath_node* an) {
  struct ath_atx_tid* tid;
  struct ath_atx_ac* ac;
  struct ath_txq* txq;
  bool buffered;
  int tidno;
  for (tidno = 0, tid = &an->tid[tidno]; tidno < IEEE80211_NUM_TIDS;
       tidno++, tid++) {
    if (!tid->sched) continue;
    ac = tid->ac;
    txq = ac->txq;
    ath_txq_lock(sc, txq);
    buffered = ath_tid_has_buffered(tid);
    tid->sched = false;
    list_del(&tid->list);
    if (ac->sched) {
      ac->sched = false;
      list_del(&ac->list);
    }
    ath_txq_unlock(sc, txq);
    ieee80211_sta_set_buffered(sta, tidno, buffered);
  }
}

static inline void find_entity_for_char(unsigned int k,
                                        enum entity_charset charset,
                                        const entity_stage1_row* table,
                                        const unsigned char** entity,
                                        size_t* entity_len, unsigned char* old,
                                        size_t oldlen, size_t* cursor) {
  unsigned stage1_idx = ENT_STAGE1_INDEX(k);
  const entity_stage3_row* c;
  if (stage1_idx > 0x1D) {
    *entity = NULL;
    *entity_len = 0;
    return;
  }
  c = &table[stage1_idx][ENT_STAGE2_INDEX(k)][ENT_STAGE3_INDEX(k)];
  if (!c->ambiguous) {
    *entity = (const unsigned char*)c->data.ent.entity;
    *entity_len = c->data.ent.entity_len;
  } else {
    size_t cursor_before = *cursor;
    int status = SUCCESS;
    unsigned next_char;
    if (!(*cursor < oldlen)) goto no_suitable_2nd;
    next_char = get_next_char(charset, old, oldlen, cursor, &status);
    if (status == FAILURE) goto no_suitable_2nd;
    {
      const entity_multicodepoint_row *s, *e;
      s = &c->data.multicodepoint_table[1];
      e = s - 1 + c->data.multicodepoint_table[0].leading_entry.size;
      for (; s <= e; s++) {
        if (s->normal_entry.second_cp == next_char) {
          *entity = s->normal_entry.entity;
          *entity_len = s->normal_entry.entity_len;
          return;
        }
      }
    }
  no_suitable_2nd:
    *cursor = cursor_before;
    *entity = (const unsigned char*)c->data.multicodepoint_table[0]
                  .leading_entry.default_entity;
    *entity_len =
        c->data.multicodepoint_table[0].leading_entry.default_entity_len;
  }
}

static Fixed lsr_translate_scale(GF_LASeRCodec* lsr, u32 val) {
  if (val >> (lsr->coord_bits - 1)) {
    s32 v = val - (1 << lsr->coord_bits);
    return INT2FIX(v) / 256;
  } else {
    return INT2FIX(val) / 256;
  }
}

token_continue(i_ctx_t* i_ctx_p, scanner_state* pstate, bool save) {
  os_ptr op = osp;
  int code;
  ref token;
  pop(1);
again:
  gs_scanner_error_object(i_ctx_p, pstate, &i_ctx_p->error_object);
  break;
  case scan_BOS:
    code = 0;
  case 0:
    push(2);
    ref_assign(op - 1, &token);
    make_true(op);
    break;
  case scan_EOF:
    push(1);
    make_false(op);
    code = 0;
    break;
  case scan_Refill:
    code = gs_scan_handle_refill(i_ctx_p, pstate, save, ztoken_continue);
    switch (code) {
      case 0:
        goto again;
      case o_push_estack:
        return code;
    }
    break;
}

void TightDecoder::FilterGradient(const rdr::U8* inbuf, const PixelFormat& pf,
                                  PIXEL_T* outbuf, int stride, const Rect& r) {
  int x, y, c;
  static rdr::U8 prevRow[TIGHT_MAX_WIDTH * 3];
  static rdr::U8 thisRow[TIGHT_MAX_WIDTH * 3];
  rdr::U8 pix[3];
  int est[3];
  memset(prevRow, 0, sizeof(prevRow));
  int rectHeight = r.height();
  int rectWidth = r.width();
  for (y = 0; y < rectHeight; y++) {
    pf.rgbFromBuffer(pix, &inbuf[y * rectWidth], 1);
    for (c = 0; c < 3; c++) pix[c] += prevRow[c];
    memcpy(thisRow, pix, sizeof(pix));
    pf.bufferFromRGB((rdr::U8*)&outbuf[y * stride], pix, 1);
    for (x = 1; x < rectWidth; x++) {
      for (c = 0; c < 3; c++) {
        est[c] = prevRow[x * 3 + c] + pix[c] - prevRow[(x - 1) * 3 + c];
        if (est[c] > 255) {
          est[c] = 255;
        } else if (est[c] < 0) {
          est[c] = 0;
        }
      }
      pf.rgbFromBuffer(pix, &inbuf[y * rectWidth + x], 1);
      for (c = 0; c < 3; c++) pix[c] += est[c];
      memcpy(&thisRow[x * 3], pix, sizeof(pix));
      pf.bufferFromRGB((rdr::U8*)&outbuf[y * stride + x], pix, 1);
    }
    memcpy(prevRow, thisRow, sizeof(prevRow));
  }
}

vips_tracked_malloc(size_t size) {
  void* buf;
  vips_tracked_init();
  size += 16;
  if (!(buf = g_try_malloc(size))) {
#ifdef DEBUG
    g_assert_not_reached();
#endif
    vips_error("vips_tracked", _("out of memory --- size == %dMB"),
               (int)(size / (1024.0 * 1024.0)));
    g_warning(_("out of memory --- size == %dMB"),
              (int)(size / (1024.0 * 1024.0)));
    return (NULL);
  }
  g_mutex_lock(vips_tracked_mutex);
  *((size_t*)buf) = size;
  buf = (void*)((char*)buf + 16);
  vips_tracked_mem += size;
  if (vips_tracked_mem > vips_tracked_mem_highwater)
    vips_tracked_mem_highwater = vips_tracked_mem;
  vips_tracked_allocs += 1;
#ifdef DEBUG_VERBOSE
  printf("vips_tracked_malloc: %p, %zd bytes\n", buf, size);
#endif
  g_mutex_unlock(vips_tracked_mutex);
  VIPS_GATE_MALLOC(size);
  return (buf);
}

static int net_ctl_permissions(struct ctl_table_header* head,
                               struct ctl_table* table) {
  struct net* net = container_of(head->set, struct net, sysctls);
  kuid_t root_uid = make_kuid(net->user_ns, 0);
  kgid_t root_gid = make_kgid(net->user_ns, 0);
  if (ns_capable(net->user_ns, CAP_NET_ADMIN) ||
      uid_eq(root_uid, current_uid())) {
    int mode = (table->mode >> 6) & 7;
    return (mode << 6) | (mode << 3) | mode;
  }
  if (gid_eq(root_gid, current_gid())) {
    int mode = (table->mode >> 3) & 7;
    return (mode << 3) | mode;
  }
  return table->mode;
}

void UnbufferedAsioTlsStream::BeforeHandshake(handshake_type type) {
  namespace ssl = boost::asio::ssl;
  if (!m_Hostname.IsEmpty()) {
    X509_VERIFY_PARAM_set1_host(SSL_get0_param(native_handle()),
                                m_Hostname.CStr(), m_Hostname.GetLength());
  }
  set_verify_mode(ssl::verify_peer | ssl::verify_client_once);
  set_verify_callback([this](bool preverified, ssl::verify_context& ctx) {
    if (!preverified) {
      m_VerifyOK = false;
      std::ostringstream msgbuf;
      int err = X509_STORE_CTX_get_error(ctx.native_handle());
      msgbuf << "code " << err << ": " << X509_verify_cert_error_string(err);
      m_VerifyError = msgbuf.str();
    }
    return true;
  });
#ifdef SSL_CTRL_SET_TLSEXT_HOSTNAME
  if (type == client && !m_Hostname.IsEmpty()) {
    String environmentName = Application::GetAppEnvironment();
    String serverName = m_Hostname;
    if (!environmentName.IsEmpty()) serverName += ":" + environmentName;
    SSL_set_tlsext_host_name(native_handle(), serverName.CStr());
  }
#endif
}

