      [REPLY_OSTATR - REPLY_ACK] = "OSTATR",
      [REPLY_RSTATR - REPLY_ACK] = "RSTATR",
      [REPLY_RAW - REPLY_ACK] = "RAW",
      [REPLY_FMT - REPLY_ACK] = "FMT",
      [REPLY_KEYPPAD - REPLY_ACK] = "KEYPPAD",
      [REPLY_COM - REPLY_ACK] = "COM",
      [REPLY_BIOREADR - REPLY_ACK] = "BIOREADR",
