aiff_read_chanmap(SF_PRIVATE* psf, unsigned dword) {
  const AIFF_CAF_CHANNEL_MAP* map_info;
  unsigned channel_bitmap, channel_decriptions, bytesread;
  int layout_tag;
  bytesread = psf_binheader_readf(psf, "444", &layout_tag, &channel_bitmap,
                                  &channel_decriptions);
  if ((map_info = aiff_caf_of_channel_layout_tag(layout_tag)) == NULL) return 0;
  psf_log_printf(psf, "  Tag    : %x\n", layout_tag);
  if (map_info) psf_log_printf(psf, "  Layout : %s\n", map_info->name);
  if (bytesread < dword) psf_binheader_readf(psf, "j", dword - bytesread);
  if (map_info->channel_map != NULL) {
    size_t chanmap_size = psf->sf.channels * sizeof(psf->channel_map[0]);
    free(psf->channel_map);
    if ((psf->channel_map = malloc(chanmap_size)) == NULL)
      return SFE_MALLOC_FAILED;
    memcpy(psf->channel_map, map_info->channel_map, chanmap_size);
  };
  return 0;
}

_warc_read(struct archive_read* a, const void** buf, size_t* bsz,
           int64_t* off) {
  struct warc_s* w = a->format->data;
  const char* rab;
  ssize_t nrd;
  if (w->cntoff >= w->cntlen) {
  eof:
    *buf = NULL;
    *bsz = 0U;
    *off = w->cntoff + 4U;
    w->unconsumed = 0U;
    return (ARCHIVE_EOF);
  }
  rab = __archive_read_ahead(a, 1U, &nrd);
  if (nrd < 0) {
    *bsz = 0U;
    return (int)nrd;
  } else if (nrd == 0) {
    goto eof;
  } else if ((size_t)nrd > w->cntlen - w->cntoff) {
    nrd = w->cntlen - w->cntoff;
  }
  *off = w->cntoff;
  *bsz = nrd;
  *buf = rab;
  w->cntoff += nrd;
  w->unconsumed = (size_t)nrd;
  return (ARCHIVE_OK);
}

TfLiteStatus EvalHashtableSize(TfLiteContext* context, TfLiteNode* node) {
  const TfLiteTensor* input_resource_id_tensor =
      GetInput(context, node, kInputResourceIdTensor);
  int resource_id = input_resource_id_tensor->data.i32[0];
  TfLiteTensor* output_tensor = GetOutput(context, node, kOutputTensor);
  auto* output_data = GetTensorData<std::int64_t>(output_tensor);
  Subgraph* subgraph = reinterpret_cast<Subgraph*>(context->impl_);
  auto& resources = subgraph->resources();
  auto* lookup = resource::GetHashtableResource(&resources, resource_id);
  TF_LITE_ENSURE(context, lookup != nullptr);
  output_data[0] = lookup->Size();
  return kTfLiteOk;
}

