setv4key_principal_2_svc(setv4key_arg* arg, struct svc_req* rqstp) {
  static generic_ret ret;
  char* prime_arg;
  gss_buffer_desc client_name, service_name;
  OM_uint32 minor_stat;
  kadm5_server_handle_t handle;
  const char* errmsg = NULL;
  xdr_free(xdr_generic_ret, &ret);
  if ((ret.code = new_server_handle(arg->api_version, rqstp, &handle)))
    goto exit_func;
  if ((ret.code = check_handle((void*)handle))) goto exit_func;
  ret.api_version = handle->api_version;
  if (setup_gss_names(rqstp, &client_name, &service_name) < 0) {
    ret.code = KADM5_FAILURE;
    goto exit_func;
  }
  if (krb5_unparse_name(handle->context, arg->princ, &prime_arg)) {
    ret.code = KADM5_BAD_PRINCIPAL;
    goto exit_func;
  }
  if (!(CHANGEPW_SERVICE(rqstp)) &&
      kadm5int_acl_check(handle->context, rqst2name(rqstp), ACL_SETKEY,
                         arg->princ, NULL)) {
    ret.code =
        kadm5_setv4key_principal((void*)handle, arg->princ, arg->keyblock);
  } else {
    log_unauth("kadm5_setv4key_principal", prime_arg, &client_name,
               &service_name, rqstp);
    ret.code = KADM5_AUTH_SETKEY;
  }
  if (ret.code != KADM5_AUTH_SETKEY) {
    if (ret.code != 0)
      errmsg = krb5_get_error_message(handle->context, ret.code);
    log_done("kadm5_setv4key_principal", prime_arg, errmsg, &client_name,
             &service_name, rqstp);
    if (errmsg != NULL) krb5_free_error_message(handle->context, errmsg);
  }
  free(prime_arg);
  gss_release_buffer(&minor_stat, &client_name);
  gss_release_buffer(&minor_stat, &service_name);
exit_func:
  free_server_handle(handle);
  return &ret;
}

Jsi_Value* jsi_ValueObjKeyAssign(Jsi_Interp* interp, Jsi_Value* target,
                                 Jsi_Value* keyval, Jsi_Value* value,
                                 int flag) {
  int arrayindex = -1;
  if (keyval->vt == JSI_VT_NUMBER && Jsi_NumberIsInteger(keyval->d.num) &&
      keyval->d.num >= 0) {
    arrayindex = (int)keyval->d.num;
  }
  if (arrayindex >= 0 && arrayindex < MAX_ARRAY_LIST &&
      target->vt == JSI_VT_OBJECT && target->d.obj->arr) {
    return jsi_ObjArraySetDup(interp, target->d.obj, value, arrayindex);
  }
  const char* kstr = Jsi_ValueToString(interp, keyval, NULL);
#if (defined(JSI_HAS___PROTO__) && JSI_HAS___PROTO__ == 2)
  if (Jsi_Strcmp(kstr, "__proto__") == 0) {
    Jsi_Obj* obj = target->d.obj;
    obj->__proto__ = Jsi_ValueDup(interp, value);
    return obj->__proto__;
  }
#endif
  Jsi_Value* v = Jsi_ValueNew1(interp);
  if (value) Jsi_ValueCopy(interp, v, value);
  jsi_ValueObjSet(interp, target, kstr, v, flag,
                  (Jsi_ValueIsStringKey(interp, keyval) ? JSI_OM_ISSTRKEY : 0));
  Jsi_DecrRefCount(interp, v);
  return v;
}

PyImaging_MapBuffer(PyObject* self, PyObject* args) {
  Py_ssize_t y, size;
  Imaging im;
  PyObject* target;
  Py_buffer view;
  char* mode;
  char* codec;
  PyObject* bbox;
  Py_ssize_t offset;
  int xsize, ysize;
  int stride;
  int ystep;
  if (!PyArg_ParseTuple(args, "O(ii)sOn(sii)", &target, &xsize, &ysize, &codec,
                        &bbox, &offset, &mode, &stride, &ystep))
    return NULL;
  if (!PyImaging_CheckBuffer(target)) {
    PyErr_SetString(PyExc_TypeError, "expected string or buffer");
    return NULL;
  }
  if (stride <= 0) {
    if (!strcmp(mode, "L") || !strcmp(mode, "P"))
      stride = xsize;
    else if (!strncmp(mode, "I;16", 4))
      stride = xsize * 2;
    else
      stride = xsize * 4;
  }
  size = (Py_ssize_t)ysize * stride;
  if (PyImaging_GetBuffer(target, &view) < 0) return NULL;
  if (view.len < 0) {
    PyErr_SetString(PyExc_ValueError, "buffer has negative size");
    return NULL;
  }
  if (offset + size > view.len) {
    PyErr_SetString(PyExc_ValueError, "buffer is not large enough");
    return NULL;
  }
  im = ImagingNewPrologueSubtype(mode, xsize, ysize,
                                 sizeof(ImagingBufferInstance));
  if (!im) return NULL;
  if (ystep > 0)
    for (y = 0; y < ysize; y++)
      im->image[y] = (char*)view.buf + offset + y * stride;
  else
    for (y = 0; y < ysize; y++)
      im->image[ysize - y - 1] = (char*)view.buf + offset + y * stride;
  im->destroy = mapping_destroy_buffer;
  Py_INCREF(target);
  ((ImagingBufferInstance*)im)->target = target;
  ((ImagingBufferInstance*)im)->view = view;
  if (!ImagingNewEpilogue(im)) return NULL;
  return PyImagingNew(im);
}

int vp9_alloc_context_buffers(VP9_COMMON* cm, int width, int height) {
  int new_mi_size;
  vp9_set_mb_mi(cm, width, height);
  new_mi_size = cm->mi_stride * calc_mi_size(cm->mi_rows);
  if (cm->mi_alloc_size < new_mi_size) {
    cm->free_mi(cm);
    if (cm->alloc_mi(cm, new_mi_size)) goto fail;
  }
  if (cm->seg_map_alloc_size < cm->mi_rows * cm->mi_cols) {
    free_seg_map(cm);
    if (alloc_seg_map(cm, cm->mi_rows * cm->mi_cols)) goto fail;
  }
  if (cm->above_context_alloc_cols < cm->mi_cols) {
    vpx_free(cm->above_context);
    cm->above_context = (ENTROPY_CONTEXT*)vpx_calloc(
        2 * mi_cols_aligned_to_sb(cm->mi_cols) * MAX_MB_PLANE,
        sizeof(*cm->above_context));
    if (!cm->above_context) goto fail;
    vpx_free(cm->above_seg_context);
    cm->above_seg_context = (PARTITION_CONTEXT*)vpx_calloc(
        mi_cols_aligned_to_sb(cm->mi_cols), sizeof(*cm->above_seg_context));
    if (!cm->above_seg_context) goto fail;
    cm->above_context_alloc_cols = cm->mi_cols;
  }
  return 0;
fail:
  vp9_free_context_buffers(cm);
  return 1;
}

rpa_read_buffer(pool_t pool, const unsigned char** data,
                const unsigned char* end, unsigned char** buffer) {
  const unsigned char* p = *data;
  unsigned int len;
  if (p > end) return 0;
  len = *p++;
  if (p + len > end) return 0;
  *buffer = p_malloc(pool, len);
  memcpy(*buffer, p, len);
  *data += 1 + len;
  return len;
}

cmnd_matches_all(const struct sudoers_parse_tree* parse_tree,
                 const struct member* m, const char* runchroot,
                 struct cmnd_info* info) {
  const bool negated = m->negated;
  struct sudo_command* c;
  int matched = UNSPEC;
  struct alias* a;
  debug_decl(cmnd_matches_all, SUDOERS_DEBUG_MATCH);
  switch (m->type) {
    case ALL:
      c = (struct sudo_command*)m->name;
      if (command_matches(parse_tree->ctx, c->cmnd, c->args, runchroot, info,
                          &c->digests))
        matched = negated ? DENY : ALLOW;
      break;
    case ALIAS:
      a = alias_get(parse_tree, m->name, CMNDALIAS);
      if (a != NULL) {
        TAILQ_FOREACH_REVERSE(m, &a->members, member_list, entries) {
          matched = cmnd_matches_all(parse_tree, m, runchroot, info);
          if (matched != UNSPEC) {
            if (negated) matched = matched == ALLOW ? DENY : ALLOW;
            break;
          }
        }
        alias_put(a);
      }
      break;
  }
  debug_return_int(matched);
}

static TEE_Result do_allocate_keypair(struct ecc_keypair* key,
                                      uint32_t type __unused,
                                      size_t size_bits) {
  ECC_TRACE("Allocate Keypair of %zu bits", size_bits);
  memset(key, 0, sizeof(*key));
  key->d = crypto_bignum_allocate(size_bits);
  if (!key->d) goto err;
  key->x = crypto_bignum_allocate(size_bits);
  if (!key->x) goto err;
  key->y = crypto_bignum_allocate(size_bits);
  if (!key->y) goto err;
  return TEE_SUCCESS;
err:
  ECC_TRACE("Allocation error");
  crypto_bignum_free(key->d);
  crypto_bignum_free(key->x);
  return TEE_ERROR_OUT_OF_MEMORY;
}

void buffer_slow_realign(struct buffer* buf) {
  if (buf->i) {
    int block1 = buf->i;
    int block2 = 0;
    if (buf->p + buf->i > buf->data + buf->size) {
      block1 = buf->data + buf->size - buf->p;
      block2 = buf->p + buf->i - (buf->data + buf->size);
    }
    if (block2) memcpy(swap_buffer, buf->data, block2);
    memmove(buf->data, buf->p, block1);
    if (block2) memcpy(buf->data + block1, swap_buffer, block2);
  }
  buf->p = buf->data;
}

static unsigned long randomize_stack_top(unsigned long stack_top) {
  unsigned int random_variable = 0;
  if ((current->flags & PF_RANDOMIZE) &&
      !(current->personality & ADDR_NO_RANDOMIZE)) {
    random_variable = get_random_int() & STACK_RND_MASK;
    random_variable <<= PAGE_SHIFT;
  }
#ifdef CONFIG_STACK_GROWSUP
  return PAGE_ALIGN(stack_top) + random_variable;
#else
  return PAGE_ALIGN(stack_top) - random_variable;
#endif
}

