static int filter_frame(AVFilterLink* inlink, AVFrame* in) {
  GradFunContext* s = inlink->dst->priv;
  AVFilterLink* outlink = inlink->dst->outputs[0];
  AVFrame* out;
  int p, direct;
  if (av_frame_is_writable(in)) {
    direct = 1;
    out = in;
  } else {
    direct = 0;
    out = ff_get_video_buffer(outlink, outlink->w, outlink->h);
    if (!out) {
      av_frame_free(&in);
      return AVERROR(ENOMEM);
    }
    av_frame_copy_props(out, in);
  }
  for (p = 0; p < 4 && in->data[p]; p++) {
    int w = inlink->w;
    int h = inlink->h;
    int r = s->radius;
    if (p) {
      w = s->chroma_w;
      h = s->chroma_h;
      r = s->chroma_r;
    }
    if (FFMIN(w, h) > 2 * r)
      filter(s, out->data[p], in->data[p], w, h, out->linesize[p],
             in->linesize[p], r);
    else if (out->data[p] != in->data[p])
      av_image_copy_plane(out->data[p], out->linesize[p], in->data[p],
                          in->linesize[p], w, h);
  }
  if (!direct) av_frame_free(&in);
  return ff_filter_frame(outlink, out);
}

void poly_frommsg(poly* r, const uint8_t msg[KYBER_INDCPA_MSGBYTES]) {
  unsigned int i, j;
  int16_t mask;
#if (KYBER_INDCPA_MSGBYTES != KYBER_N / 8)
#error "KYBER_INDCPA_MSGBYTES must be equal to KYBER_N/8 bytes!"
#endif
  for (i = 0; i < KYBER_N / 8; i++) {
    for (j = 0; j < 8; j++) {
      mask = -(int16_t)((msg[i] >> j) & 1);
      r->coeffs[8 * i + j] = mask & ((KYBER_Q + 1) / 2);
    }
  }
}

TfLiteStatus GatherNd(const TfLiteEvalTensor* params,
                      const TfLiteEvalTensor* indices,
                      TfLiteEvalTensor* output) {
  const int indices_dims = indices->dims->size;
  const int indices_nd = indices->dims->data[indices_dims - 1];
  const int params_dims = params->dims->size;
  const IndicesT* index_data = tflite::micro::GetTensorData<IndicesT>(indices);
  const ParamsT* param_data = tflite::micro::GetTensorData<ParamsT>(params);
  ParamsT* output_data = tflite::micro::GetTensorData<ParamsT>(output);
  int n_slices = 1;
  for (int i = 0; i < indices_dims - 1; ++i) {
    n_slices *= indices->dims->data[i];
  }
  int slice_size = 1;
  for (int i = indices_nd; i < params_dims; ++i) {
    slice_size *= params->dims->data[i];
  }
  int remain_flat_size = ElementCount(*params->dims);
  int dims_to_count[MAX_INDICES_ND];
  for (int i = 0; i < indices_nd; ++i) {
    dims_to_count[i] = remain_flat_size / params->dims->data[i];
    remain_flat_size = dims_to_count[i];
  }
  for (int i = 0; i < n_slices; ++i) {
    int from_pos = 0;
    for (int j = 0; j < indices_nd; ++j) {
      int offset = i * indices_nd + j;
      IndicesT index = index_data[offset];
      from_pos += index * dims_to_count[j];
    }
    std::memcpy(output_data + i * slice_size, param_data + from_pos,
                sizeof(ParamsT) * slice_size);
  }
  return kTfLiteOk;
}

static int semctl_setval(struct ipc_namespace* ns, int semid, int semnum,
                         unsigned long arg) {
  struct sem_undo* un;
  struct sem_array* sma;
  struct sem* curr;
  int err;
  int nsems;
  struct list_head tasks;
  int val;
#if defined(CONFIG_64BIT) && defined(__BIG_ENDIAN)
  val = arg >> 32;
#else
  val = arg;
#endif
  sma = sem_lock_check(ns, semid);
  if (IS_ERR(sma)) return PTR_ERR(sma);
  INIT_LIST_HEAD(&tasks);
  nsems = sma->sem_nsems;
  err = -EACCES;
  if (ipcperms(ns, &sma->sem_perm, S_IWUGO)) goto out_unlock;
  err = security_sem_semctl(sma, SETVAL);
  if (err) goto out_unlock;
  err = -EINVAL;
  if (semnum < 0 || semnum >= nsems) goto out_unlock;
  curr = &sma->sem_base[semnum];
  err = -ERANGE;
  if (val > SEMVMX || val < 0) goto out_unlock;
  assert_spin_locked(&sma->sem_perm.lock);
  list_for_each_entry(un, &sma->list_id, list_id) un->semadj[semnum] = 0;
  curr->semval = val;
  curr->sempid = task_tgid_vnr(current);
  sma->sem_ctime = get_seconds();
  do_smart_update(sma, NULL, 0, 0, &tasks);
  err = 0;
out_unlock:
  sem_unlock(sma);
  wake_up_sem_queue_do(&tasks);
  return err;
}

escapes(cp, tp) const char* cp;
char* tp;
{
  while (*cp) {
    int cval = 0, meta = 0;
    if (*cp == '\\' && cp[1] && index("mM", cp[1]) && cp[2]) {
      meta = 1;
      cp += 2;
    }
    if (*cp == '\\' && cp[1] && index("0123456789xXoO", cp[1]) && cp[2]) {
      NEARDATA const char hex[] = "00112233445566778899aAbBcCdDeEfF";
      const char* dp;
      int dcount = 0;
      cp++;
      if (*cp == 'x' || *cp == 'X')
        for (++cp; *cp && (dp = index(hex, *cp)) && (dcount++ < 2); cp++)
          cval = (cval * 16) + ((int)(dp - hex) / 2);
      else if (*cp == 'o' || *cp == 'O')
        for (++cp; *cp && (index("01234567", *cp)) && (dcount++ < 3); cp++)
          cval = (cval * 8) + (*cp - '0');
      else
        for (; *cp && (index("0123456789", *cp)) && (dcount++ < 3); cp++)
          cval = (cval * 10) + (*cp - '0');
    } else if (*cp == '\\' && cp[1]) {
      switch (*++cp) {
        case '\\':
          cval = '\\';
          break;
        case 'n':
          cval = '\n';
          break;
        case 't':
          cval = '\t';
          break;
        case 'b':
          cval = '\b';
          break;
        case 'r':
          cval = '\r';
          break;
        default:
          cval = *cp;
      }
      cp++;
    } else if (*cp == '^' && cp[1]) {
      cval = (*++cp & 0x1f);
      cp++;
    } else
      cval = *cp++;
    if (meta) cval |= 0x80;
    *tp++ = cval;
  }
  *tp = '\0';
}

void oz_hcd_get_desc_cnf(void* hport, u8 req_id, int status, const u8* desc,
                         int length, int offset, int total_size) {
  struct oz_port* port = hport;
  struct urb* urb;
  int err = 0;
  oz_dbg(ON, "oz_hcd_get_desc_cnf length = %d offs = %d tot_size = %d\n",
         length, offset, total_size);
  urb = oz_find_urb_by_id(port, 0, req_id);
  if (!urb) return;
  if (status == 0) {
    int copy_len;
    int required_size = urb->transfer_buffer_length;
    if (required_size > total_size) required_size = total_size;
    copy_len = required_size - offset;
    if (length <= copy_len) copy_len = length;
    memcpy(urb->transfer_buffer + offset, desc, copy_len);
    offset += copy_len;
    if (offset < required_size) {
      struct usb_ctrlrequest* setup =
          (struct usb_ctrlrequest*)urb->setup_packet;
      unsigned wvalue = le16_to_cpu(setup->wValue);
      if (oz_enqueue_ep_urb(port, 0, 0, urb, req_id))
        err = -ENOMEM;
      else if (oz_usb_get_desc_req(port->hpd, req_id, setup->bRequestType,
                                   (u8)(wvalue >> 8), (u8)wvalue, setup->wIndex,
                                   offset, required_size - offset)) {
        oz_dequeue_ep_urb(port, 0, 0, urb);
        err = -ENOMEM;
      }
      if (err == 0) return;
    }
  }
  urb->actual_length = total_size;
  oz_complete_urb(port->ozhcd->hcd, urb, 0);
}

TfLiteStatus SimpleStatefulOp::Invoke(TfLiteContext* context,
                                      TfLiteNode* node) {
  OpData* data = reinterpret_cast<OpData*>(node->user_data);
  *data->invoke_count += 1;
  const TfLiteTensor* input = GetInput(context, node, kInputTensor);
  const uint8_t* input_data = GetTensorData<uint8_t>(input);
  int size = NumElements(input->dims);
  uint8_t* sorting_buffer = reinterpret_cast<uint8_t*>(
      context->GetScratchBuffer(context, data->sorting_buffer));
  for (int i = 0; i < size; i++) {
    sorting_buffer[i] = input_data[i];
  }
  for (int i = 1; i < size; i++) {
    for (int j = i; j > 0 && sorting_buffer[j] < sorting_buffer[j - 1]; j--) {
      std::swap(sorting_buffer[j], sorting_buffer[j - 1]);
    }
  }
  TfLiteTensor* median = GetOutput(context, node, kMedianTensor);
  uint8_t* median_data = GetTensorData<uint8_t>(median);
  TfLiteTensor* invoke_count = GetOutput(context, node, kInvokeCount);
  int32_t* invoke_count_data = GetTensorData<int32_t>(invoke_count);
  median_data[0] = sorting_buffer[size / 2];
  invoke_count_data[0] = *data->invoke_count;
  return kTfLiteOk;
}

static void uv__process_child_init(const uv_process_options_t* options,
                                   int stdio_count, int (*pipes)[2],
                                   int error_fd) {
  int close_fd;
  int use_fd;
  int fd;
  if (options->flags & UV_PROCESS_DETACHED) setsid();
  for (fd = 0; fd < stdio_count; fd++) {
    close_fd = pipes[fd][0];
    use_fd = pipes[fd][1];
    if (use_fd < 0) {
      if (fd >= 3)
        continue;
      else {
        use_fd = open("/dev/null", fd == 0 ? O_RDONLY : O_RDWR);
        close_fd = use_fd;
        if (use_fd == -1) {
          uv__write_int(error_fd, -errno);
          perror("failed to open stdio");
          _exit(127);
        }
      }
    }
    if (fd == use_fd)
      uv__cloexec(use_fd, 0);
    else
      dup2(use_fd, fd);
    if (fd <= 2) uv__nonblock(fd, 0);
    if (close_fd != -1) uv__close(close_fd);
  }
  for (fd = 0; fd < stdio_count; fd++) {
    use_fd = pipes[fd][1];
    if (use_fd >= 0 && fd != use_fd) close(use_fd);
  }
  if (options->cwd != NULL && chdir(options->cwd)) {
    uv__write_int(error_fd, -errno);
    perror("chdir()");
    _exit(127);
  }
  if ((options->flags & UV_PROCESS_SETGID) && setgid(options->gid)) {
    uv__write_int(error_fd, -errno);
    perror("setgid()");
    _exit(127);
  }
  if ((options->flags & UV_PROCESS_SETUID) && setuid(options->uid)) {
    uv__write_int(error_fd, -errno);
    perror("setuid()");
    _exit(127);
  }
  if (options->env != NULL) {
    environ = options->env;
  }
  execvp(options->file, options->args);
  uv__write_int(error_fd, -errno);
  perror("execvp()");
  _exit(127);
}

ext2_xattr_cache_find(struct inode* inode, struct ext2_xattr_header* header) {
  __u32 hash = le32_to_cpu(header->h_hash);
  struct mb_cache_entry* ce;
  if (!header->h_hash) return NULL;
  ea_idebug(inode, "looking for cached blocks [%x]", (int)hash);
again:
  ce = mb_cache_entry_find_first(ext2_xattr_cache, inode->i_sb->s_bdev, hash);
  while (ce) {
    struct buffer_head* bh;
    if (IS_ERR(ce)) {
      if (PTR_ERR(ce) == -EAGAIN) goto again;
      break;
    }
    bh = sb_bread(inode->i_sb, ce->e_block);
    if (!bh) {
      ext2_error(inode->i_sb, "ext2_xattr_cache_find",
                 "inode %ld: block %ld read error", inode->i_ino,
                 (unsigned long)ce->e_block);
    } else {
      lock_buffer(bh);
      if (le32_to_cpu(HDR(bh)->h_refcount) > EXT2_XATTR_REFCOUNT_MAX) {
        ea_idebug(inode, "block %ld refcount %d>%d", (unsigned long)ce->e_block,
                  le32_to_cpu(HDR(bh)->h_refcount), EXT2_XATTR_REFCOUNT_MAX);
      } else if (!ext2_xattr_cmp(header, HDR(bh))) {
        ea_bdebug(bh, "b_count=%d", atomic_read(&(bh->b_count)));
        mb_cache_entry_release(ce);
        return bh;
      }
      unlock_buffer(bh);
      brelse(bh);
    }
    ce = mb_cache_entry_find_next(ce, inode->i_sb->s_bdev, hash);
  }
  return NULL;
}

