  }
}

vips_foreign_load_gif_scan_image(VipsForeignLoadGif* gif) {
  VipsObjectClass* class = VIPS_OBJECT_GET_CLASS(gif);
  GifFileType* file = gif->file;
  ColorMapObject* map =
      file->Image.ColorMap ? file->Image.ColorMap : file->SColorMap;
  GifByteType* extension;
  if (DGifGetImageDesc(gif->file) == GIF_ERROR) {
    vips_foreign_load_gif_error(gif);
    return (-1);
  }
  if (file->Image.Left < 0 || file->Image.Width < 1 ||
      file->Image.Width > 10000 ||
      file->Image.Left + file->Image.Width > file->SWidth ||
      file->Image.Top < 0 || file->Image.Height < 1 ||
      file->Image.Height > 10000 ||
      file->Image.Top + file->Image.Height > file->SHeight) {
    vips_error(class->nickname, "%s", _("bad frame size"));
    return (-1);
  }
  if (!gif->has_colour && map) {
    int i;
    for (i = 0; i < map->ColorCount; i++)
      if (map->Colors[i].Red != map->Colors[i].Green ||
          map->Colors[i].Green != map->Colors[i].Blue) {
        gif->has_colour = TRUE;
        break;
      }
  }
  do {
    if (vips_foreign_load_gif_code_next(gif, &extension)) return (-1);
  } while (extension != NULL);
  return (0);
}

static int em_fxrstor(struct x86_emulate_ctxt* ctxt) {
  struct fxregs_state fx_state;
  int rc;
  rc = check_fxsr(ctxt);
  if (rc != X86EMUL_CONTINUE) return rc;
  rc = segmented_read(ctxt, ctxt->memop.addr.mem, &fx_state, 512);
  if (rc != X86EMUL_CONTINUE) return rc;
  if (fx_state.mxcsr >> 16) return emulate_gp(ctxt, 0);
  ctxt->ops->get_fpu(ctxt);
  if (ctxt->mode < X86EMUL_MODE_PROT64) rc = fxrstor_fixup(ctxt, &fx_state);
  if (rc == X86EMUL_CONTINUE)
    rc = asm_safe("fxrstor %[fx]", : [fx] "m"(fx_state));
  ctxt->ops->put_fpu(ctxt);
  return rc;
}

int blk_init_allocated_queue(struct request_queue* q) {
  WARN_ON_ONCE(q->mq_ops);
  q->fq = blk_alloc_flush_queue(q, NUMA_NO_NODE, q->cmd_size);
  if (!q->fq) return -ENOMEM;
  if (q->init_rq_fn && q->init_rq_fn(q, q->fq->flush_rq, GFP_KERNEL))
    goto out_free_flush_queue;
  if (blk_init_rl(&q->root_rl, q, GFP_KERNEL)) goto out_exit_flush_rq;
  INIT_WORK(&q->timeout_work, blk_timeout_work);
  q->queue_flags |= QUEUE_FLAG_DEFAULT;
  blk_queue_make_request(q, blk_queue_bio);
  q->sg_reserved_size = INT_MAX;
  if (elevator_init(q)) goto out_exit_flush_rq;
  return 0;
out_exit_flush_rq:
  if (q->exit_rq_fn) q->exit_rq_fn(q, q->fq->flush_rq);
out_free_flush_queue:
  blk_free_flush_queue(q->fq);
  return -ENOMEM;
}

static Bigint* Balloc(int k) {
  int x;
  Bigint* rv;
  _THREAD_PRIVATE_MUTEX_LOCK(dtoa_mutex);
  if ((rv = freelist[k])) {
    freelist[k] = rv->next;
  } else {
    x = 1 << k;
    rv = (Bigint*)MALLOC(sizeof(Bigint) + (x - 1) * sizeof(Long));
    rv->k = k;
    rv->maxwds = x;
  }
  _THREAD_PRIVATE_MUTEX_UNLOCK(dtoa_mutex);
  rv->sign = rv->wds = 0;
  return rv;
}

static __be32 nfsd3_proc_setacl(struct svc_rqst* rqstp,
                                struct nfsd3_setaclargs* argp,
                                struct nfsd3_attrstat* resp) {
  struct inode* inode;
  svc_fh* fh;
  __be32 nfserr = 0;
  int error;
  fh = fh_copy(&resp->fh, &argp->fh);
  nfserr = fh_verify(rqstp, &resp->fh, 0, NFSD_MAY_SATTR);
  if (nfserr) goto out;
  inode = d_inode(fh->fh_dentry);
  if (!IS_POSIXACL(inode) || !inode->i_op->set_acl) {
    error = -EOPNOTSUPP;
    goto out_errno;
  }
  error = fh_want_write(fh);
  if (error) goto out_errno;
  error = inode->i_op->set_acl(inode, argp->acl_access, ACL_TYPE_ACCESS);
  if (error) goto out_drop_write;
  error = inode->i_op->set_acl(inode, argp->acl_default, ACL_TYPE_DEFAULT);
out_drop_write:
  fh_drop_write(fh);
out_errno:
  nfserr = nfserrno(error);
out:
  posix_acl_release(argp->acl_access);
  posix_acl_release(argp->acl_default);
  RETURN_STATUS(nfserr);
}

