rpl_daoack_print(netdissect_options* ndo, const u_char* bp, u_int length) {
  const struct nd_rpl_daoack* daoack = (const struct nd_rpl_daoack*)bp;
  const char* dagid_str = "<elided>";
  ND_TCHECK2(*daoack, ND_RPL_DAOACK_MIN_LEN);
  if (length < ND_RPL_DAOACK_MIN_LEN) goto tooshort;
  bp += ND_RPL_DAOACK_MIN_LEN;
  length -= ND_RPL_DAOACK_MIN_LEN;
  if (RPL_DAOACK_D(daoack->rpl_flags)) {
    ND_TCHECK2(daoack->rpl_dagid, DAGID_LEN);
    if (length < DAGID_LEN) goto tooshort;
    dagid_str = ip6addr_string(ndo, daoack->rpl_dagid);
    bp += DAGID_LEN;
    length -= DAGID_LEN;
  }
  ND_PRINT((ndo, " [dagid:%s,seq:%u,instance:%u,status:%u]", dagid_str,
            daoack->rpl_daoseq, daoack->rpl_instanceid, daoack->rpl_status));
  if (ndo->ndo_vflag > 1) {
    const struct rpl_dio_genoption* opt = (const struct rpl_dio_genoption*)bp;
    rpl_dio_printopt(ndo, opt, length);
  }
  return;
trunc:
  ND_PRINT((ndo, " [|dao-truncated]"));
  return;
tooshort:
  ND_PRINT((ndo, " [|dao-length too short]"));
  return;
}

static int openssl_static_locks_install(void) {
  int result;
  if (openssl_locks != NULL) {
    LogInfo("Locks already initialized");
    result = MU_FAILURE;
  } else {
    openssl_locks = malloc(CRYPTO_num_locks() * sizeof(LOCK_HANDLE));
    if (openssl_locks == NULL) {
      LogError("Failed to allocate locks");
      result = MU_FAILURE;
    } else {
      int i;
      for (i = 0; i < CRYPTO_num_locks(); i++) {
        openssl_locks[i] = Lock_Init();
        if (openssl_locks[i] == NULL) {
          LogError("Failed to allocate lock %d", i);
          break;
        }
      }
      if (i != CRYPTO_num_locks()) {
        int j;
        for (j = 0; j < i; j++) {
          Lock_Deinit(openssl_locks[j]);
        }
        result = MU_FAILURE;
      } else {
        CRYPTO_set_locking_callback(openssl_static_locks_lock_unlock_cb);
        result = 0;
      }
    }
  }
  return result;
}

static int cuse_channel_release(struct inode* inode, struct file* file) {
  struct fuse_dev* fud = file->private_data;
  struct cuse_conn* cc = fc_to_cc(fud->fc);
  int rc;
  mutex_lock(&cuse_lock);
  list_del_init(&cc->list);
  mutex_unlock(&cuse_lock);
  if (cc->dev) device_unregister(cc->dev);
  if (cc->cdev) {
    unregister_chrdev_region(cc->cdev->dev, 1);
    cdev_del(cc->cdev);
  }
  rc = fuse_dev_release(inode, file);
  return rc;
}

get_number(int* numptr, int low, const char* names[], int ch, FILE* file,
           const char* terms) {
  char temp[MAX_TEMPSTR], *pc;
  int len, i;
  pc = temp;
  len = 0;
  while (isdigit((unsigned char)ch)) {
    if (++len >= MAX_TEMPSTR) goto bad;
    *pc++ = ch;
    ch = get_char(file);
  }
  *pc = '\0';
  if (len != 0) {
    if (!strchr(terms, ch)) goto bad;
    *numptr = atoi(temp);
    return (ch);
  }
  if (names) {
    while (isalpha((unsigned char)ch)) {
      if (++len >= MAX_TEMPSTR) goto bad;
      *pc++ = ch;
      ch = get_char(file);
    }
    *pc = '\0';
    if (len != 0 && strchr(terms, ch)) {
      for (i = 0; names[i] != NULL; i++) {
        Debug(DPARS | DEXT, ("get_num, compare(%s,%s)\n", names[i],
                             temp)) if (!strcasecmp(names[i], temp)) {
          *numptr = i + low;
          return (ch);
        }
      }
    }
  }
bad:
  unget_char(ch, file);
  return (EOF);
}

snmp_ber_decode_unsigned_integer(unsigned char* buf, uint32_t* buff_len,
                                 uint8_t expected_type, uint32_t* num) {
  uint8_t i, len, type;
  buf = snmp_ber_decode_type(buf, buff_len, &type);
  if (buf == NULL || type != expected_type) {
    return NULL;
  }
  buf = snmp_ber_decode_length(buf, buff_len, &len);
  if (buf == NULL || len > 4) {
    return NULL;
  }
  if (*buff_len < len) {
    return NULL;
  }
  *num = (uint32_t)(*buf++ & 0xFF);
  (*buff_len)--;
  for (i = 1; i < len; ++i) {
    *num <<= 8;
    *num |= (uint8_t)(*buf++ & 0xFF);
    (*buff_len)--;
  }
  return buf;
}

char* _single_string_alloc_and_copy(LPCWSTR in) {
  char* chr;
  int len = 0;
  if (!in) {
    return in;
  }
  while (in[len] != 0) {
    len++;
  }
  chr = malloc(len + 1);
  len = 0;
  while (in[len] != 0) {
    chr[len] = 0xFF & in[len];
    len++;
  }
  chr[len++] = '\0';
  return chr;
}

