static inline struct sem_array* sem_obtain_lock(struct ipc_namespace* ns,
                                                int id) {
  struct kern_ipc_perm* ipcp;
  struct sem_array* sma;
  rcu_read_lock();
  ipcp = ipc_obtain_object(&sem_ids(ns), id);
  if (IS_ERR(ipcp)) {
    sma = ERR_CAST(ipcp);
    goto err;
  }
  spin_lock(&ipcp->lock);
  if (!ipcp->deleted) return container_of(ipcp, struct sem_array, sem_perm);
  spin_unlock(&ipcp->lock);
  sma = ERR_PTR(-EINVAL);
err:
  rcu_read_unlock();
  return sma;
}

COMPAT_SYSCALL_DEFINE3(set_mempolicy, int, mode, compat_ulong_t __user*, nmask,
                       compat_ulong_t, maxnode) {
  long err = 0;
  unsigned long __user* nm = NULL;
  unsigned long nr_bits, alloc_size;
  DECLARE_BITMAP(bm, MAX_NUMNODES);
  nr_bits = min_t(unsigned long, maxnode - 1, MAX_NUMNODES);
  alloc_size = ALIGN(nr_bits, BITS_PER_LONG) / 8;
  if (nmask) {
    err = compat_get_bitmap(bm, nmask, nr_bits);
    nm = compat_alloc_user_space(alloc_size);
    err |= copy_to_user(nm, bm, alloc_size);
  }
  if (err) return -EFAULT;
  return sys_set_mempolicy(mode, nm, nr_bits + 1);
}

check_entry_size_and_hooks(struct ip6t_entry* e, struct xt_table_info* newinfo,
                           const unsigned char* base,
                           const unsigned char* limit,
                           const unsigned int* hook_entries,
                           const unsigned int* underflows,
                           unsigned int valid_hooks) {
  unsigned int h;
  int err;
  if ((unsigned long)e % __alignof__(struct ip6t_entry) != 0 ||
      (unsigned char*)e + sizeof(struct ip6t_entry) >= limit) {
    duprintf("Bad offset %p\n", e);
    return -EINVAL;
  }
  if (e->next_offset <
      sizeof(struct ip6t_entry) + sizeof(struct xt_entry_target)) {
    duprintf("checking: element %p size %u\n", e, e->next_offset);
    return -EINVAL;
  }
  err = check_entry(e);
  if (err) return err;
  for (h = 0; h < NF_INET_NUMHOOKS; h++) {
    if (!(valid_hooks & (1 << h))) continue;
    if ((unsigned char*)e - base == hook_entries[h])
      newinfo->hook_entry[h] = hook_entries[h];
    if ((unsigned char*)e - base == underflows[h]) {
      if (!check_underflow(e)) {
        pr_err(
            "Underflows must be unconditional and "
            "use the STANDARD target with "
            "ACCEPT/DROP\n");
        return -EINVAL;
      }
      newinfo->underflow[h] = underflows[h];
    }
  }
  e->counters = ((struct xt_counters){0, 0});
  e->comefrom = 0;
  return 0;
}

RCMS* r_pkcs7_parse_cms(const ut8* buffer, ut32 length) {
  RASN1Object* object;
  RCMS* container;
  if (!buffer || !length) {
    return NULL;
  }
  container = R_NEW0(RCMS);
  if (!container) {
    return NULL;
  }
  object = r_asn1_create_object(buffer, length);
  if (!object || object->list.length != 2 || !object->list.objects[0] ||
      object->list.objects[1]->list.length != 1) {
    r_asn1_free_object(object);
    free(container);
    return NULL;
  }
  container->contentType = r_asn1_stringify_oid(
      object->list.objects[0]->sector, object->list.objects[0]->length);
  r_pkcs7_parse_signeddata(&container->signedData,
                           object->list.objects[1]->list.objects[0]);
  r_asn1_free_object(object);
  return container;
}

static int rm_read_multi(AVFormatContext* s, AVIOContext* pb, AVStream* st,
                         char* mime) {
  int number_of_streams = avio_rb16(pb);
  int number_of_mdpr;
  int i, ret;
  unsigned size2;
  for (i = 0; i < number_of_streams; i++) avio_rb16(pb);
  number_of_mdpr = avio_rb16(pb);
  if (number_of_mdpr != 1) {
    avpriv_request_sample(s, "MLTI with multiple (%d) MDPR", number_of_mdpr);
  }
  for (i = 0; i < number_of_mdpr; i++) {
    AVStream* st2;
    if (i > 0) {
      st2 = avformat_new_stream(s, NULL);
      if (!st2) {
        ret = AVERROR(ENOMEM);
        return ret;
      }
      st2->id = st->id + (i << 16);
      st2->codecpar->bit_rate = st->codecpar->bit_rate;
      st2->start_time = st->start_time;
      st2->duration = st->duration;
      st2->codecpar->codec_type = AVMEDIA_TYPE_DATA;
      st2->priv_data = ff_rm_alloc_rmstream();
      if (!st2->priv_data) return AVERROR(ENOMEM);
    } else
      st2 = st;
    size2 = avio_rb32(pb);
    ret = ff_rm_read_mdpr_codecdata(s, s->pb, st2, st2->priv_data, size2, mime);
    if (ret < 0) return ret;
  }
  return 0;
}

static CPINLINE zend_class_entry* swoole_try_get_ce(zend_string* class_name) {
  zend_class_entry* ce = zend_lookup_class(class_name);
  if (ce) {
    return ce;
  }
  zval user_func, args[1], retval;
  if ((PG(unserialize_callback_func) == NULL) ||
      (PG(unserialize_callback_func)[0] == '\0')) {
    zend_throw_exception_ex(NULL, 0, "can not find class %s",
                            class_name->val TSRMLS_CC);
    return NULL;
  }
  zend_string* fname =
      swoole_string_init(ZEND_STRL(PG(unserialize_callback_func)));
  Z_STR(user_func) = fname;
  Z_TYPE_INFO(user_func) = IS_STRING_EX;
  ZVAL_STR(&args[0], class_name);
  call_user_function_ex(CG(function_table), NULL, &user_func, &retval, 1, args,
                        0, NULL);
  swoole_string_release(fname);
  ce = zend_lookup_class(class_name);
  if (!ce) {
    zend_throw_exception_ex(NULL, 0, "can not find class %s",
                            class_name->val TSRMLS_CC);
    return NULL;
  } else {
    return ce;
  }
}

int fpm_unix_resolve_socket_premissions(struct fpm_worker_pool_s* wp) {
  struct fpm_worker_pool_config_s* c = wp->config;
  wp->socket_uid = -1;
  wp->socket_gid = -1;
  wp->socket_mode = 0666;
  if (!c) {
    return 0;
  }
  if (c->listen_owner && *c->listen_owner) {
    struct passwd* pwd;
    pwd = getpwnam(c->listen_owner);
    if (!pwd) {
      zlog(ZLOG_SYSERROR, "[pool %s] cannot get uid for user '%s'",
           wp->config->name, c->listen_owner);
      return -1;
    }
    wp->socket_uid = pwd->pw_uid;
    wp->socket_gid = pwd->pw_gid;
  }
  if (c->listen_group && *c->listen_group) {
    struct group* grp;
    grp = getgrnam(c->listen_group);
    if (!grp) {
      zlog(ZLOG_SYSERROR, "[pool %s] cannot get gid for group '%s'",
           wp->config->name, c->listen_group);
      return -1;
    }
    wp->socket_gid = grp->gr_gid;
  }
  if (c->listen_mode && *c->listen_mode) {
    wp->socket_mode = strtoul(c->listen_mode, 0, 8);
  }
  return 0;
}

service_info* FindServiceEventURLPath(service_table* table,
                                      const char* eventURLPath) {
  service_info* finger = NULL;
  uri_type parsed_url;
  uri_type parsed_url_in;
  if (table && parse_uri(eventURLPath, strlen(eventURLPath), &parsed_url_in) ==
                   HTTP_SUCCESS) {
    finger = table->serviceList;
    while (finger) {
      if (finger->eventURL) {
        if (parse_uri(finger->eventURL, strlen(finger->eventURL),
                      &parsed_url) == HTTP_SUCCESS) {
          if (!token_cmp(&parsed_url.pathquery, &parsed_url_in.pathquery)) {
            return finger;
          }
        }
      }
      finger = finger->next;
    }
  }
  return NULL;
}

