static void addECSOption(char* packet, const size_t& packetSize, uint16_t* len,
                         const ComboAddress& remote, int stamp) {
  string EDNSRR;
  struct dnsheader* dh = (struct dnsheader*)packet;
  EDNSSubnetOpts eso;
  if (stamp < 0)
    eso.source = Netmask(remote);
  else {
    ComboAddress stamped(remote);
    *((char*)&stamped.sin4.sin_addr.s_addr) = stamp;
    eso.source = Netmask(stamped);
  }
  string optRData = makeEDNSSubnetOptsString(eso);
  string record;
  generateEDNSOption(EDNSOptionCode::ECS, optRData, record);
  generateOptRR(record, EDNSRR);
  uint16_t arcount = ntohs(dh->arcount);
  if (packetSize - *len > EDNSRR.size()) {
    arcount++;
    dh->arcount = htons(arcount);
    memcpy(packet + *len, EDNSRR.c_str(), EDNSRR.size());
    *len += EDNSRR.size();
  }
}

static char* rfc2047_decode_word(const char* s, size_t len,
                                 enum ContentEncoding enc) {
  const char* it = s;
  const char* end = s + len;
  if (enc == ENCQUOTEDPRINTABLE) {
    struct Buffer buf = {0};
    for (; it < end; ++it) {
      if (*it == '_') {
        mutt_buffer_addch(&buf, ' ');
      } else if ((*it == '=') && (!(it[1] & ~127) && hexval(it[1]) != -1) &&
                 (!(it[2] & ~127) && hexval(it[2]) != -1)) {
        mutt_buffer_addch(&buf, (hexval(it[1]) << 4) | hexval(it[2]));
        it += 2;
      } else {
        mutt_buffer_addch(&buf, *it);
      }
    }
    mutt_buffer_addch(&buf, '\0');
    return buf.data;
  } else if (enc == ENCBASE64) {
    char* out = mutt_mem_malloc(3 * len / 4 + 1);
    int dlen = mutt_b64_decode(out, it);
    if (dlen == -1) {
      FREE(&out);
      return NULL;
    }
    out[dlen] = '\0';
    return out;
  }
  assert(0);
  return NULL;
}

static Status ParseEquation(const string& equation, OperandLabels* input_labels,
                            Labels* output_labels,
                            std::vector<DimensionType>* label_types,
                            OperandLabelCounts* input_label_counts,
                            LabelCounts* output_label_counts,
                            gtl::InlinedVector<bool, 2>* input_has_ellipsis,
                            bool* output_has_ellipsis) {
  gtl::InlinedVector<string, 2> input_str;
  string output_str;
  TF_RETURN_IF_ERROR(ParseEinsumEquation(equation, &input_str, &output_str));
  absl::flat_hash_map<char, int> label_mapping;
  int num_inputs = input_str.size();
  input_labels->resize(num_inputs);
  for (int i = 0; i < num_inputs; ++i) {
    MapToLabels(input_str[i], &input_labels->at(i), &label_mapping);
  }
  MapToLabels(output_str, output_labels, &label_mapping);
  int num_labels = label_mapping.size();
  input_label_counts->resize(num_inputs);
  input_has_ellipsis->resize(num_inputs);
  for (int i = 0; i < num_inputs; ++i) {
    input_label_counts->at(i).resize(num_labels);
    for (const int label : input_labels->at(i)) {
      if (label != kEllipsisLabel)
        input_label_counts->at(i)[label] += 1;
      else
        input_has_ellipsis->at(i) = true;
    }
  }
  output_label_counts->resize(num_labels);
  for (const int label : *output_labels) {
    if (label != kEllipsisLabel)
      output_label_counts->at(label) += 1;
    else
      *output_has_ellipsis = true;
  }
  label_types->resize(num_labels);
  for (int label = 0; label < num_labels; ++label) {
    if (label == kEllipsisLabel) continue;
    bool removed = (*output_label_counts)[label] == 0;
    bool unique = num_inputs == 1 || (*input_label_counts)[0][label] == 0 ||
                  (*input_label_counts)[1][label] == 0;
    (*label_types)[label] = GetDimensionType(removed, unique);
  }
  return Status::OK();
}

static int xar_hash_check(int hash, const void* result, const void* expected) {
  int len;
  if (!result || !expected) return 1;
  switch (hash) {
    case XAR_CKSUM_SHA1:
      len = SHA1_HASH_SIZE;
      break;
    case XAR_CKSUM_MD5:
      len = CLI_HASH_MD5;
      break;
    case XAR_CKSUM_OTHER:
    case XAR_CKSUM_NONE:
    default:
      return 1;
  }
  return memcmp(result, expected, len);
}

