  }
}

kdc_process_s4u_x509_user(krb5_context context, krb5_kdc_req* request,
                          krb5_pa_data* pa_data, krb5_keyblock* tgs_subkey,
                          krb5_keyblock* tgs_session,
                          krb5_pa_s4u_x509_user** s4u_x509_user,
                          const char** status) {
  krb5_error_code code;
  krb5_data req_data;
  req_data.length = pa_data->length;
  req_data.data = (char*)pa_data->contents;
  code = decode_krb5_pa_s4u_x509_user(&req_data, s4u_x509_user);
  if (code) return code;
  code = verify_s4u_x509_user_checksum(
      context, tgs_subkey ? tgs_subkey : tgs_session, &req_data, request->nonce,
      *s4u_x509_user);
  if (code) {
    *status = "INVALID_S4U2SELF_CHECKSUM";
    krb5_free_pa_s4u_x509_user(context, *s4u_x509_user);
    *s4u_x509_user = NULL;
    return code;
  }
  if (krb5_princ_size(context, (*s4u_x509_user)->user_id.user) == 0 ||
      (*s4u_x509_user)->user_id.subject_cert.length != 0) {
    *status = "INVALID_S4U2SELF_REQUEST";
    krb5_free_pa_s4u_x509_user(context, *s4u_x509_user);
    *s4u_x509_user = NULL;
    return KRB5KDC_ERR_C_PRINCIPAL_UNKNOWN;
  }
  return 0;
}

fb_mmap(struct file* file, struct vm_area_struct* vma) {
  struct fb_info* info = file_fb_info(file);
  struct fb_ops* fb;
  unsigned long off;
  unsigned long start;
  u32 len;
  if (!info) return -ENODEV;
  if (vma->vm_pgoff > (~0UL >> PAGE_SHIFT)) return -EINVAL;
  off = vma->vm_pgoff << PAGE_SHIFT;
  fb = info->fbops;
  if (!fb) return -ENODEV;
  mutex_lock(&info->mm_lock);
  if (fb->fb_mmap) {
    int res;
    res = fb->fb_mmap(info, vma);
    mutex_unlock(&info->mm_lock);
    return res;
  }
  start = info->fix.smem_start;
  len = PAGE_ALIGN((start & ~PAGE_MASK) + info->fix.smem_len);
  if (off >= len) {
    off -= len;
    if (info->var.accel_flags) {
      mutex_unlock(&info->mm_lock);
      return -EINVAL;
    }
    start = info->fix.mmio_start;
    len = PAGE_ALIGN((start & ~PAGE_MASK) + info->fix.mmio_len);
  }
  mutex_unlock(&info->mm_lock);
  start &= PAGE_MASK;
  if ((vma->vm_end - vma->vm_start + off) > len) return -EINVAL;
  off += start;
  vma->vm_pgoff = off >> PAGE_SHIFT;
  vma->vm_page_prot = vm_get_page_prot(vma->vm_flags);
  fb_pgprotect(file, vma, off);
  if (io_remap_pfn_range(vma, vma->vm_start, off >> PAGE_SHIFT,
                         vma->vm_end - vma->vm_start, vma->vm_page_prot))
    return -EAGAIN;
  return 0;
}

static void tm_reclaim_thread(struct thread_struct* thr, struct thread_info* ti,
                              uint8_t cause) {
  unsigned long msr_diff = 0;
  if (test_ti_thread_flag(ti, TIF_RESTORE_TM)) {
    msr_diff = thr->ckpt_regs.msr & ~thr->regs->msr;
    if (msr_diff & MSR_FP)
      memcpy(&thr->transact_fp, &thr->fp_state, sizeof(struct thread_fp_state));
    if (msr_diff & MSR_VEC)
      memcpy(&thr->transact_vr, &thr->vr_state, sizeof(struct thread_vr_state));
    clear_ti_thread_flag(ti, TIF_RESTORE_TM);
    msr_diff &= MSR_FP | MSR_VEC | MSR_VSX | MSR_FE0 | MSR_FE1;
  }
  tm_reclaim(thr, thr->regs->msr, cause);
  thr->regs->msr |= msr_diff;
}

