static unsigned long randomize_stack_top(unsigned long stack_top) {
  unsigned int random_variable = 0;
  if ((current->flags & PF_RANDOMIZE) &&
      !(current->personality & ADDR_NO_RANDOMIZE)) {
    random_variable = get_random_int() & STACK_RND_MASK;
    random_variable <<= PAGE_SHIFT;
  }
#ifdef CONFIG_STACK_GROWSUP
  return PAGE_ALIGN(stack_top) + random_variable;
#else
  return PAGE_ALIGN(stack_top) - random_variable;
#endif
}

snmp_engine(unsigned char* buff, uint32_t buff_len, unsigned char* out,
            uint32_t* out_len) {
  static snmp_header_t header;
  static snmp_varbind_t varbinds[SNMP_MAX_NR_VALUES];
  static uint32_t varbind_length = SNMP_MAX_NR_VALUES;
  buff =
      snmp_message_decode(buff, buff_len, &header, varbinds, &varbind_length);
  if (buff == NULL) {
    return NULL;
  }
  if (header.version != SNMP_VERSION_1) {
    if (strncmp(header.community.community, SNMP_COMMUNITY,
                header.community.length)) {
      LOG_ERR("Request with invalid community\n");
      return NULL;
    }
  }
  switch (header.pdu_type) {
    case SNMP_DATA_TYPE_PDU_GET_REQUEST:
      if (snmp_engine_get(&header, varbinds, varbind_length) == -1) {
        return NULL;
      }
      break;
    case SNMP_DATA_TYPE_PDU_GET_NEXT_REQUEST:
      if (snmp_engine_get_next(&header, varbinds, varbind_length) == -1) {
        return NULL;
      }
      break;
    case SNMP_DATA_TYPE_PDU_GET_BULK:
      if (snmp_engine_get_bulk(&header, varbinds, &varbind_length) == -1) {
        return NULL;
      }
      break;
    default:
      LOG_ERR("Invalid request type");
      return NULL;
  }
  header.pdu_type = SNMP_DATA_TYPE_PDU_GET_RESPONSE;
  out = snmp_message_encode(out, out_len, &header, varbinds, varbind_length);
  return ++out;
}

build_config(char* prefix, struct server* server) {
  char* path = NULL;
  int path_size = strlen(prefix) + strlen(server->port) + 20;
  path = ss_malloc(path_size);
  snprintf(path, path_size, "%s/.shadowsocks_%s.conf", prefix, server->port);
  FILE* f = fopen(path, "w+");
  if (f == NULL) {
    if (verbose) {
      LOGE("unable to open config file");
    }
    ss_free(path);
    return;
  }
  fprintf(f, "{\n");
  fprintf(f, "\"server_port\":%d,\n", atoi(server->port));
  fprintf(f, "\"password\":\"%s\"", server->password);
  if (server->fast_open[0])
    fprintf(f, ",\n\"fast_open\": %s", server->fast_open);
  if (server->mode) fprintf(f, ",\n\"mode\":\"%s\"", server->mode);
  if (server->method) fprintf(f, ",\n\"method\":\"%s\"", server->method);
  if (server->plugin) fprintf(f, ",\n\"plugin\":\"%s\"", server->plugin);
  if (server->plugin_opts)
    fprintf(f, ",\n\"plugin_opts\":\"%s\"", server->plugin_opts);
  fprintf(f, "\n}\n");
  fclose(f);
  ss_free(path);
}

