BGD_DECLARE(void) gdImageWebpCtx(gdImagePtr im, gdIOCtx* outfile, int quality) {
  uint8_t* argb;
  int x, y;
  uint8_t* p;
  uint8_t* out;
  size_t out_size;
  if (im == NULL) {
    return;
  }
  if (!gdImageTrueColor(im)) {
    gd_error("Paletter image not supported by webp");
    return;
  }
  if (quality == -1) {
    quality = 80;
  }
  argb = (uint8_t*)gdMalloc(gdImageSX(im) * 4 * gdImageSY(im));
  if (!argb) {
    return;
  }
  p = argb;
  for (y = 0; y < gdImageSY(im); y++) {
    for (x = 0; x < gdImageSX(im); x++) {
      register int c;
      register char a;
      c = im->tpixels[y][x];
      a = gdTrueColorGetAlpha(c);
      if (a == 127) {
        a = 0;
      } else {
        a = 255 - ((a << 1) + (a >> 6));
      }
      *(p++) = gdTrueColorGetRed(c);
      *(p++) = gdTrueColorGetGreen(c);
      *(p++) = gdTrueColorGetBlue(c);
      *(p++) = a;
    }
  }
  out_size = WebPEncodeRGBA(argb, gdImageSX(im), gdImageSY(im),
                            gdImageSX(im) * 4, quality, &out);
  if (out_size == 0) {
    gd_error("gd-webp encoding failed");
    goto freeargb;
  }
  gdPutBuf(out, out_size, outfile);
  free(out);
freeargb:
  gdFree(argb);
}

static long ec_device_ioctl_xcmd(struct cros_ec_dev* ec, void __user* arg) {
  long ret;
  struct cros_ec_command u_cmd;
  struct cros_ec_command* s_cmd;
  if (copy_from_user(&u_cmd, arg, sizeof(u_cmd))) return -EFAULT;
  if ((u_cmd.outsize > EC_MAX_MSG_BYTES) || (u_cmd.insize > EC_MAX_MSG_BYTES))
    return -EINVAL;
  s_cmd =
      kmalloc(sizeof(*s_cmd) + max(u_cmd.outsize, u_cmd.insize), GFP_KERNEL);
  if (!s_cmd) return -ENOMEM;
  if (copy_from_user(s_cmd, arg, sizeof(*s_cmd) + u_cmd.outsize)) {
    ret = -EFAULT;
    goto exit;
  }
  s_cmd->command += ec->cmd_offset;
  ret = cros_ec_cmd_xfer(ec->ec_dev, s_cmd);
  if (ret < 0) goto exit;
  if (copy_to_user(arg, s_cmd, sizeof(*s_cmd) + u_cmd.insize)) ret = -EFAULT;
exit:
  kfree(s_cmd);
  return ret;
}

static void add_password(AUTH_HDR* request, unsigned char type,
                         CONST char* password, char* secret) {
  MD5_CTX md5_secret, my_md5;
  unsigned char misc[AUTH_VECTOR_LEN];
  int i;
  int length = strlen(password);
  unsigned char hashed[256 + AUTH_PASS_LEN];
  unsigned char* vector;
  attribute_t* attr;
  if (length > MAXPASS) {
    length = MAXPASS;
  }
  if (length == 0) {
    length = AUTH_PASS_LEN;
  }
  if ((length & (AUTH_PASS_LEN - 1)) != 0) {
    length += (AUTH_PASS_LEN - 1);
    length &= ~(AUTH_PASS_LEN - 1);
  }
  memset(hashed, 0, length);
  memcpy(hashed, password, strlen(password));
  attr = find_attribute(request, PW_PASSWORD);
  if (type == PW_PASSWORD) {
    vector = request->vector;
  } else {
    vector = attr->data;
  }
  MD5Init(&md5_secret);
  MD5Update(&md5_secret, (unsigned char*)secret, strlen(secret));
  my_md5 = md5_secret;
  MD5Update(&my_md5, vector, AUTH_VECTOR_LEN);
  MD5Final(misc, &my_md5);
  xor(hashed, misc, AUTH_PASS_LEN);
  for (i = 1; i < (length >> 4); i++) {
    my_md5 = md5_secret;
    MD5Update(&my_md5, &hashed[(i - 1) * AUTH_PASS_LEN], AUTH_PASS_LEN);
    MD5Final(misc, &my_md5);
    xor(&hashed[i * AUTH_PASS_LEN], misc, AUTH_PASS_LEN);
  }
  if (type == PW_OLD_PASSWORD) {
    attr = find_attribute(request, PW_OLD_PASSWORD);
  }
  if (!attr) {
    add_attribute(request, type, hashed, length);
  } else {
    memcpy(attr->data, hashed, length);
  }
}

static void iriap_getvaluebyclass_indication(struct iriap_cb* self,
                                             struct sk_buff* skb) {
  struct ias_object* obj;
  struct ias_attrib* attrib;
  int name_len;
  int attr_len;
  char name[IAS_MAX_CLASSNAME + 1];
  char attr[IAS_MAX_ATTRIBNAME + 1];
  __u8* fp;
  int n;
  IRDA_DEBUG(4, "%s()\n", __func__);
  IRDA_ASSERT(self != NULL, return;);
  IRDA_ASSERT(self->magic == IAS_MAGIC, return;);
  IRDA_ASSERT(skb != NULL, return;);
  fp = skb->data;
  n = 1;
  name_len = fp[n++];
  memcpy(name, fp + n, name_len);
  n += name_len;
  name[name_len] = '\0';
  attr_len = fp[n++];
  memcpy(attr, fp + n, attr_len);
  n += attr_len;
  attr[attr_len] = '\0';
  IRDA_DEBUG(4, "LM-IAS: Looking up %s: %s\n", name, attr);
  obj = irias_find_object(name);
  if (obj == NULL) {
    IRDA_DEBUG(2, "LM-IAS: Object %s not found\n", name);
    iriap_getvaluebyclass_response(self, 0x1235, IAS_CLASS_UNKNOWN,
                                   &irias_missing);
    return;
  }
  IRDA_DEBUG(4, "LM-IAS: found %s, id=%d\n", obj->name, obj->id);
  attrib = irias_find_attrib(obj, attr);
  if (attrib == NULL) {
    IRDA_DEBUG(2, "LM-IAS: Attribute %s not found\n", attr);
    iriap_getvaluebyclass_response(self, obj->id, IAS_ATTRIB_UNKNOWN,
                                   &irias_missing);
    return;
  }
  iriap_getvaluebyclass_response(self, obj->id, IAS_SUCCESS, attrib->value);
}

static ssize_t drop_sync(QIOChannel* ioc, size_t size) {
  ssize_t ret = 0;
  char small[1024];
  char* buffer;
  buffer = sizeof(small) < size ? small : g_malloc(MIN(65536, size));
  while (size > 0) {
    ssize_t count = read_sync(ioc, buffer, MIN(65536, size));
    if (count <= 0) {
      goto cleanup;
    }
    assert(count <= size);
    size -= count;
    ret += count;
  }
cleanup:
  if (buffer != small) {
    g_free(buffer);
  }
  return ret;
}

bool DefaultCertValidator::matchSubjectAltName(
    X509* cert,
    const std::vector<
        Matchers::StringMatcherImpl<envoy::type::matcher::v3::StringMatcher>>&
        subject_alt_name_matchers) {
  bssl::UniquePtr<GENERAL_NAMES> san_names(static_cast<GENERAL_NAMES*>(
      X509_get_ext_d2i(cert, NID_subject_alt_name, nullptr, nullptr)));
  if (san_names == nullptr) {
    return false;
  }
  for (const GENERAL_NAME* general_name : san_names.get()) {
    const std::string san = Utility::generalNameAsString(general_name);
    for (auto& config_san_matcher : subject_alt_name_matchers) {
      if (general_name->type == GEN_DNS &&
                  config_san_matcher.matcher().match_pattern_case() ==
                      envoy::type::matcher::v3::StringMatcher::
                          MatchPatternCase::kExact
              ? Utility::dnsNameMatch(config_san_matcher.matcher().exact(),
                                      absl::string_view(san))
              : config_san_matcher.match(san)) {
        return true;
      }
    }
  }
  return false;
}

fill_threshhold_buffer(byte* dest_strip, byte* src_strip, int src_width,
                       int left_offset, int left_width, int num_tiles,
                       int right_width) {
  byte* ptr_out_temp = dest_strip;
  int ii;
  memcpy(dest_strip, src_strip + left_offset, left_width);
  ptr_out_temp += left_width;
  for (ii = 0; ii < num_tiles; ii++) {
    memcpy(ptr_out_temp, src_strip, src_width);
    ptr_out_temp += src_width;
  }
  memcpy(ptr_out_temp, src_strip, right_width);
#ifdef PACIFY_VALGRIND
  ptr_out_temp += right_width;
  ii = (dest_strip - ptr_out_temp) % (LAND_BITS - 1);
  if (ii > 0) memset(ptr_out_temp, 0, ii);
#endif
}

