nfsd4_set_nfs4_acl(struct svc_rqst* rqstp, struct svc_fh* fhp,
                   struct nfs4_acl* acl) {
  __be32 error;
  int host_error;
  struct dentry* dentry;
  struct inode* inode;
  struct posix_acl *pacl = NULL, *dpacl = NULL;
  unsigned int flags = 0;
  error = fh_verify(rqstp, fhp, 0, NFSD_MAY_SATTR);
  if (error) return error;
  dentry = fhp->fh_dentry;
  inode = d_inode(dentry);
  if (!inode->i_op->set_acl || !IS_POSIXACL(inode)) return nfserr_attrnotsupp;
  if (S_ISDIR(inode->i_mode)) flags = NFS4_ACL_DIR;
  host_error = nfs4_acl_nfsv4_to_posix(acl, &pacl, &dpacl, flags);
  if (host_error == -EINVAL) return nfserr_attrnotsupp;
  if (host_error < 0) goto out_nfserr;
  host_error = inode->i_op->set_acl(inode, pacl, ACL_TYPE_ACCESS);
  if (host_error < 0) goto out_release;
  if (S_ISDIR(inode->i_mode)) {
    host_error = inode->i_op->set_acl(inode, dpacl, ACL_TYPE_DEFAULT);
  }
out_release:
  posix_acl_release(pacl);
  posix_acl_release(dpacl);
out_nfserr:
  if (host_error == -EOPNOTSUPP)
    return nfserr_attrnotsupp;
  else
    return nfserrno(host_error);
}

bool IsConstantFoldable(
    const Node* n,
    const std::unordered_map<string, std::vector<PartialTensorShape>>*
        shape_map,
    const std::function<bool(const Node*)>& consider,
    int64_t max_constant_size_in_bytes,
    std::unordered_map<const Node*, std::vector<Tensor>>*
        shape_replacement_map) {
  if (n->IsConstant()) {
    return true;
  }
  if (MaybeReplaceShapeOp(n, shape_map, shape_replacement_map)) {
    return true;
  }
  if (n->op_def().is_stateful()) {
    return false;
  }
  if (consider && !consider(n)) {
    return false;
  }
  if (shape_map != nullptr) {
    auto shape_it = shape_map->find(n->name());
    if (shape_it != shape_map->end()) {
      for (int64_t i = 0; i < shape_it->second.size(); ++i) {
        const auto& out_shape = shape_it->second[i];
        if (out_shape.IsFullyDefined() &&
            out_shape.num_elements() * DataTypeSize(n->output_type(i)) >
                max_constant_size_in_bytes) {
          return false;
        }
      }
    }
  }
  if (n->IsControlFlow() || n->IsSend() || n->IsRecv()) {
    return false;
  }
  if (n->IsGetSessionHandle() || n->IsGetSessionTensor() ||
      n->IsDeleteSessionTensor()) {
    return false;
  }
  if (n->IsSource()) {
    return false;
  }
  if (n->IsSink()) {
    return false;
  }
  if (n->IsFakeParam()) {
    return false;
  }
  if (!KernelDefAvailable(DeviceType(DEVICE_CPU), n->def())) {
    return false;
  }
  if (n->attrs().Find(kScopedAllocatorAttrName) != nullptr) {
    VLOG(2) << "Skip node [" << n->DebugString()
            << "] for constant folding due to scoped allocator";
    return false;
  }
  return true;
}

int BN_GF2m_poly2arr(const BIGNUM* a, int p[], int max) {
  int i, j, k = 0;
  BN_ULONG mask;
  if (BN_is_zero(a)) return 0;
  for (i = a->top - 1; i >= 0; i--) {
    if (!a->d[i]) continue;
    mask = BN_TBIT;
    for (j = BN_BITS2 - 1; j >= 0; j--) {
      if (a->d[i] & mask) {
        if (k < max) p[k] = BN_BITS2 * i + j;
        k++;
      }
      mask >>= 1;
    }
  }
  if (k < max) {
    p[k] = -1;
    k++;
  }
  return k;
}

static int kvm_ioctl_create_device(struct kvm* kvm,
                                   struct kvm_create_device* cd) {
  struct kvm_device_ops* ops = NULL;
  struct kvm_device* dev;
  bool test = cd->flags & KVM_CREATE_DEVICE_TEST;
  int ret;
  if (cd->type >= ARRAY_SIZE(kvm_device_ops_table)) return -ENODEV;
  ops = kvm_device_ops_table[cd->type];
  if (ops == NULL) return -ENODEV;
  if (test) return 0;
  dev = kzalloc(sizeof(*dev), GFP_KERNEL);
  if (!dev) return -ENOMEM;
  dev->ops = ops;
  dev->kvm = kvm;
  mutex_lock(&kvm->lock);
  ret = ops->create(dev, cd->type);
  if (ret < 0) {
    mutex_unlock(&kvm->lock);
    kfree(dev);
    return ret;
  }
  list_add(&dev->vm_node, &kvm->devices);
  mutex_unlock(&kvm->lock);
  if (ops->init) ops->init(dev);
  ret = anon_inode_getfd(ops->name, &kvm_device_fops, dev, O_RDWR | O_CLOEXEC);
  if (ret < 0) {
    ops->destroy(dev);
    mutex_lock(&kvm->lock);
    list_del(&dev->vm_node);
    mutex_unlock(&kvm->lock);
    return ret;
  }
  kvm_get_kvm(kvm);
  cd->fd = ret;
  return 0;
}

void handle_debug_usb_rx(const void* msg, size_t len) {
  if (msg_tiny_flag) {
    uint8_t buf[64];
    memcpy(buf, msg, sizeof(buf));
    uint16_t msgId = buf[4] | ((uint16_t)buf[3]) << 8;
    uint32_t msgSize = buf[8] | ((uint32_t)buf[7]) << 8 |
                       ((uint32_t)buf[6]) << 16 | ((uint32_t)buf[5]) << 24;
    if (msgSize > 64 - 9) {
      (*msg_failure)(FailureType_Failure_UnexpectedMessage,
                     "Malformed tiny packet");
      return;
    }
    const MessagesMap_t* entry = message_map_entry(DEBUG_MSG, msgId, IN_MSG);
    if (!entry) {
      (*msg_failure)(FailureType_Failure_UnexpectedMessage, "Unknown message");
      return;
    }
    tiny_dispatch(entry, buf + 9, msgSize);
  } else {
    usb_rx_helper(msg, len, DEBUG_MSG);
  }
}

Java_org_tensorflow_lite_InterpreterTest_getNativeHandleForDelegate(
