  static TfLiteRegistration registration = {
      .init = nullptr,
      .free = nullptr,
      .prepare =
          [](TfLiteContext* context, TfLiteNode* node) {
            const TfLiteTensor* input = tflite::GetInput(context, node, 0);
            TfLiteTensor* output = tflite::GetOutput(context, node, 0);
            TfLiteIntArray* output_dims = TfLiteIntArrayCopy(input->dims);
            output->type = kTfLiteFloat32;
            return context->ResizeTensor(context, output, output_dims);
          },
      .invoke =
          [](TfLiteContext* context, TfLiteNode* node) {
            TfLiteTensor* output = tflite::GetOutput(context, node, 0);
            std::fill(output->data.f,
                      output->data.f + tflite::NumElements(output), 7.0f);
            return kTfLiteOk;
          },
      .profiling_string = nullptr,
      .builtin_code = 0,
      .custom_name = "",
      .version = 1,
  };
  static TfLiteDelegate delegate = {
      .data_ = nullptr,
      .Prepare = [](TfLiteContext* context,
                    TfLiteDelegate* delegate) -> TfLiteStatus {
        TfLiteIntArray* execution_plan;
        TF_LITE_ENSURE_STATUS(
            context->GetExecutionPlan(context, &execution_plan));
        context->ReplaceNodeSubsetsWithDelegateKernels(
            context, registration, execution_plan, delegate);
        for (size_t i = 0; i < context->tensors_size; ++i) {
          context->tensors[i].delegate = delegate;
          context->tensors[i].buffer_handle = static_cast<int>(i);
        }
        return kTfLiteOk;
      },
      .CopyFromBufferHandle = nullptr,
      .CopyToBufferHandle = nullptr,
      .FreeBufferHandle = nullptr,
      .flags = kTfLiteDelegateFlagsAllowDynamicTensors,
  };
  return reinterpret_cast<jlong>(&delegate);
}

static bool blk_kick_flush(struct request_queue* q,
                           struct blk_flush_queue* fq) {
  struct list_head* pending = &fq->flush_queue[fq->flush_pending_idx];
  struct request* first_rq =
      list_first_entry(pending, struct request, flush.list);
  struct request* flush_rq = fq->flush_rq;
  if (fq->flush_pending_idx != fq->flush_running_idx || list_empty(pending))
    return false;
  if (!list_empty(&fq->flush_data_in_flight) &&
      time_before(jiffies, fq->flush_pending_since + FLUSH_PENDING_TIMEOUT))
    return false;
  fq->flush_pending_idx ^= 1;
  blk_rq_init(q, flush_rq);
  if (q->mq_ops) {
    flush_rq->mq_ctx = first_rq->mq_ctx;
    flush_rq->tag = first_rq->tag;
  }
  flush_rq->cmd_type = REQ_TYPE_FS;
  flush_rq->cmd_flags = WRITE_FLUSH | REQ_FLUSH_SEQ;
  flush_rq->rq_disk = first_rq->rq_disk;
  flush_rq->end_io = flush_end_io;
  return blk_flush_queue_rq(flush_rq, false);
}

escape_xml(const char* text) {
  static char* escaped;
  static size_t escaped_size;
  char* out;
  size_t len;
  if (!strlen(text)) return "empty string";
  for (out = escaped, len = 0; *text; ++len, ++out, ++text) {
    if ((len + 8) > escaped_size) {
      char* bigger_escaped;
      escaped_size += 128;
      bigger_escaped = realloc(escaped, escaped_size);
      if (!bigger_escaped) {
        free(escaped);
        escaped = NULL;
        escaped_size = 0;
        return ">>> out of memory <<<";
      }
      out = bigger_escaped + len;
      escaped = bigger_escaped;
    }
    switch (*text) {
      case '&':
        strcpy(out, "&amp;");
        len += strlen(out) - 1;
        out = escaped + len;
        break;
      case '<':
        strcpy(out, "&lt;");
        len += strlen(out) - 1;
        out = escaped + len;
        break;
      case '>':
        strcpy(out, "&gt;");
        len += strlen(out) - 1;
        out = escaped + len;
        break;
      default:
        *out = *text;
        break;
    }
  }
  *out = '\x0';
  return escaped;
}

int Jsi_ObjArraySizer(Jsi_Interp* interp, Jsi_Obj* obj, uint len) {
  int nsiz = len + 1, mod = ALLOC_MOD_SIZE;
  assert(obj->isarrlist);
  if (mod > 1) nsiz = nsiz + ((mod - 1) - (nsiz + mod - 1) % mod);
  if (nsiz > MAX_ARRAY_LIST) {
    Jsi_LogError("array size too large");
    return 0;
  }
  if (len >= obj->arrMaxSize) {
    int oldsz = (nsiz - obj->arrMaxSize);
    obj->arr = (Jsi_Value**)Jsi_Realloc(obj->arr, nsiz * sizeof(Jsi_Value*));
    memset(obj->arr + obj->arrMaxSize, 0, oldsz * sizeof(Jsi_Value*));
    obj->arrMaxSize = nsiz;
  }
  if (len > obj->arrCnt) obj->arrCnt = len;
  return nsiz;
}

std::string controller::bookmark(const std::string& url,
                                 const std::string& title,
                                 const std::string& description,
                                 const std::string& feed_title) {
  std::string bookmark_cmd = cfg.get_configvalue("bookmark-cmd");
  bool is_interactive = cfg.get_configvalue_as_bool("bookmark-interactive");
  if (bookmark_cmd.length() > 0) {
    std::string cmdline = strprintf::fmt(
        "%s '%s' %s %s %s", bookmark_cmd, utils::replace_all(url, "'", "%27"),
        quote_empty(stfl::quote(title)), quote_empty(stfl::quote(description)),
        quote_empty(stfl::quote(feed_title)));
    LOG(level::DEBUG, "controller::bookmark: cmd = %s", cmdline);
    if (is_interactive) {
      v->push_empty_formaction();
      stfl::reset();
      utils::run_interactively(cmdline, "controller::bookmark");
      v->pop_current_formaction();
      return "";
    } else {
      char* my_argv[4];
      my_argv[0] = const_cast<char*>("/bin/sh");
      my_argv[1] = const_cast<char*>("-c");
      my_argv[2] = const_cast<char*>(cmdline.c_str());
      my_argv[3] = nullptr;
      return utils::run_program(my_argv, "");
    }
  } else {
    return _(
        "bookmarking support is not configured. Please set the configuration "
        "variable `bookmark-cmd' accordingly.");
  }
}

