static int faultin_page(struct task_struct* tsk, struct vm_area_struct* vma,
                        unsigned long address, unsigned int* flags,
                        int* nonblocking) {
  unsigned int fault_flags = 0;
  int ret;
  if ((*flags & (FOLL_POPULATE | FOLL_MLOCK)) == FOLL_MLOCK) return -ENOENT;
  if ((*flags & FOLL_POPULATE) &&
      (stack_guard_page_start(vma, address) ||
       stack_guard_page_end(vma, address + PAGE_SIZE)))
    return -ENOENT;
  if (*flags & FOLL_WRITE) fault_flags |= FAULT_FLAG_WRITE;
  if (*flags & FOLL_REMOTE) fault_flags |= FAULT_FLAG_REMOTE;
  if (nonblocking) fault_flags |= FAULT_FLAG_ALLOW_RETRY;
  if (*flags & FOLL_NOWAIT)
    fault_flags |= FAULT_FLAG_ALLOW_RETRY | FAULT_FLAG_RETRY_NOWAIT;
  if (*flags & FOLL_TRIED) {
    VM_WARN_ON_ONCE(fault_flags & FAULT_FLAG_ALLOW_RETRY);
    fault_flags |= FAULT_FLAG_TRIED;
  }
  ret = handle_mm_fault(vma, address, fault_flags);
  if (ret & VM_FAULT_ERROR) {
    if (ret & VM_FAULT_OOM) return -ENOMEM;
    if (ret & (VM_FAULT_HWPOISON | VM_FAULT_HWPOISON_LARGE))
      return *flags & FOLL_HWPOISON ? -EHWPOISON : -EFAULT;
    if (ret & (VM_FAULT_SIGBUS | VM_FAULT_SIGSEGV)) return -EFAULT;
    BUG();
  }
  if (tsk) {
    if (ret & VM_FAULT_MAJOR)
      tsk->maj_flt++;
    else
      tsk->min_flt++;
  }
  if (ret & VM_FAULT_RETRY) {
    if (nonblocking) *nonblocking = 0;
    return -EBUSY;
  }
  if ((ret & VM_FAULT_WRITE) && !(vma->vm_flags & VM_WRITE))
    *flags &= ~FOLL_WRITE;
  return 0;
}

TightDecoder::FilterGradient24(const rdr::U8* inbuf, const PixelFormat& pf,
                               PIXEL_T* outbuf, int stride, const Rect& r) {
  int x, y, c;
  rdr::U8 prevRow[TIGHT_MAX_WIDTH * 3];
  rdr::U8 thisRow[TIGHT_MAX_WIDTH * 3];
  rdr::U8 pix[3];
  int est[3];
  memset(prevRow, 0, sizeof(prevRow));
  int rectHeight = r.height();
  int rectWidth = r.width();
  for (y = 0; y < rectHeight; y++) {
    for (c = 0; c < 3; c++) {
      pix[c] = inbuf[y * rectWidth * 3 + c] + prevRow[c];
      thisRow[c] = pix[c];
    }
    pf.bufferFromRGB((rdr::U8*)&outbuf[y * stride], pix, 1);
    for (x = 1; x < rectWidth; x++) {
      for (c = 0; c < 3; c++) {
        est[c] = prevRow[x * 3 + c] + pix[c] - prevRow[(x - 1) * 3 + c];
        if (est[c] > 0xff) {
          est[c] = 0xff;
        } else if (est[c] < 0) {
          est[c] = 0;
        }
        pix[c] = inbuf[(y * rectWidth + x) * 3 + c] + est[c];
        thisRow[x * 3 + c] = pix[c];
      }
      pf.bufferFromRGB((rdr::U8*)&outbuf[y * stride + x], pix, 1);
    }
    memcpy(prevRow, thisRow, sizeof(prevRow));
  }
}

static int ocfs2_prepare_page_for_write(struct inode* inode, u64* p_blkno,
                                        struct ocfs2_write_ctxt* wc,
                                        struct page* page, u32 cpos,
                                        loff_t user_pos, unsigned user_len,
                                        int new) {
  int ret;
  unsigned int map_from = 0, map_to = 0;
  unsigned int cluster_start, cluster_end;
  unsigned int user_data_from = 0, user_data_to = 0;
  ocfs2_figure_cluster_boundaries(OCFS2_SB(inode->i_sb), cpos, &cluster_start,
                                  &cluster_end);
  if (page == wc->w_target_page) {
    map_from = user_pos & (PAGE_CACHE_SIZE - 1);
    map_to = map_from + user_len;
    if (new)
      ret = ocfs2_map_page_blocks(page, p_blkno, inode, cluster_start,
                                  cluster_end, new);
    else
      ret = ocfs2_map_page_blocks(page, p_blkno, inode, map_from, map_to, new);
    if (ret) {
      mlog_errno(ret);
      goto out;
    }
    user_data_from = map_from;
    user_data_to = map_to;
    if (new) {
      map_from = cluster_start;
      map_to = cluster_end;
    }
  } else {
    BUG_ON(!new);
    map_from = cluster_start;
    map_to = cluster_end;
    ret = ocfs2_map_page_blocks(page, p_blkno, inode, cluster_start,
                                cluster_end, new);
    if (ret) {
      mlog_errno(ret);
      goto out;
    }
  }
  if (new && !PageUptodate(page))
    ocfs2_clear_page_regions(page, OCFS2_SB(inode->i_sb), cpos, user_data_from,
                             user_data_to);
  flush_dcache_page(page);
out:
  return ret;
}

SYSCALL_DEFINE6(recvfrom, int, fd, void __user*, ubuf, size_t, size,
                unsigned int, flags, struct sockaddr __user*, addr, int __user*,
                addr_len) {
  struct socket* sock;
  struct iovec iov;
  struct msghdr msg;
  struct sockaddr_storage address;
  int err, err2;
  int fput_needed;
  if (size > INT_MAX) size = INT_MAX;
  sock = sockfd_lookup_light(fd, &err, &fput_needed);
  if (!sock) goto out;
  msg.msg_control = NULL;
  msg.msg_controllen = 0;
  msg.msg_iovlen = 1;
  msg.msg_iov = &iov;
  iov.iov_len = size;
  iov.iov_base = ubuf;
  msg.msg_name = (struct sockaddr*)&address;
  msg.msg_namelen = sizeof(address);
  if (sock->file->f_flags & O_NONBLOCK) flags |= MSG_DONTWAIT;
  err = sock_recvmsg(sock, &msg, size, flags);
  if (err >= 0 && addr != NULL) {
    err2 = move_addr_to_user(&address, msg.msg_namelen, addr, addr_len);
    if (err2 < 0) err = err2;
  }
  fput_light(sock->file, fput_needed);
out:
  return err;
}

