}

psh_glyph_find_strong_points(PSH_Glyph glyph, FT_Int dimension) {
  PSH_Hint_Table table = &glyph->hint_tables[dimension];
  PS_Mask mask = table->hint_masks->masks;
  FT_UInt num_masks = table->hint_masks->num_masks;
  FT_UInt first = 0;
  FT_Int major_dir = dimension == 0 ? PSH_DIR_VERTICAL : PSH_DIR_HORIZONTAL;
  PSH_Dimension dim = &glyph->globals->dimension[dimension];
  FT_Fixed scale = dim->scale_mult;
  FT_Int threshold;
  threshold = (FT_Int)FT_DivFix(PSH_STRONG_THRESHOLD, scale);
  if (threshold > PSH_STRONG_THRESHOLD_MAXIMUM)
    threshold = PSH_STRONG_THRESHOLD_MAXIMUM;
  if (num_masks > 1 && glyph->num_points > 0) {
    first = mask->end_point;
    mask++;
    for (; num_masks > 1; num_masks--, mask++) {
      next = mask->end_point;
      FT_Int count;
      next = mask->end_point;
      count = next - first;
      if (count > 0) {
                                             threshold, major_dir );
      }
      first = next;
    }
  }
  if (num_masks == 1) {
    FT_UInt count = glyph->num_points;
    PSH_Point point = glyph->points;
    psh_hint_table_activate_mask(table, table->hint_masks->masks);
    psh_hint_table_find_strong_points(table, point, count, threshold,
                                      major_dir);
  }
  {
    FT_UInt count = glyph->num_points;
    PSH_Point point = glyph->points;
    for (; count > 0; count--, point++)
      if (point->hint && !psh_point_is_strong(point))
        psh_point_set_strong(point);
  }
}

BOOL CEAnsi::ReportString(LPCWSTR asRet) {
  if (!asRet || !*asRet) return FALSE;
  INPUT_RECORD ir[16] = {};
  const size_t nLen = wcslen(asRet);
  if (nLen > std::numeric_limits<DWORD>::max()) return false;
  INPUT_RECORD* pir =
      (nLen <= static_cast<int>(countof(ir)))
          ? ir
          : static_cast<INPUT_RECORD*>(calloc(nLen, sizeof(INPUT_RECORD)));
  if (!pir) return FALSE;
  INPUT_RECORD* p = pir;
  LPCWSTR pc = asRet;
  for (size_t i = 0; i < nLen; i++, p++, pc++) {
    const char ch = *pc >= 0x20 ? *pc : L' ';
    p->EventType = KEY_EVENT;
    p->Event.KeyEvent.bKeyDown = TRUE;
    p->Event.KeyEvent.wRepeatCount = 1;
    p->Event.KeyEvent.uChar.UnicodeChar = ch;
  }
  DumpKnownEscape(asRet, nLen, de_Report);
  DWORD nWritten = 0;
  HANDLE hIn = GetStdHandle(STD_INPUT_HANDLE);
  const BOOL bSuccess =
      WriteConsoleInput(hIn, pir, static_cast<DWORD>(nLen), &nWritten) &&
      (nWritten == nLen);
  if (pir != ir) free(pir);
  return bSuccess;
}

lyd_new_leaf(struct lyd_node* parent, const struct lys_module* module,
             const char* name, const char* val_str) {
  const struct lys_node *snode = NULL, *siblings;
  if ((!parent && !module) || !name) {
    LOGARG;
    return NULL;
  }
  siblings = lyd_new_find_schema(parent, module, 0);
  if (!siblings) {
    LOGARG;
    return NULL;
  }
  if (lys_getnext_data(module, lys_parent(siblings), name, strlen(name),
                       LYS_LEAFLIST | LYS_LEAF, &snode) ||
      !snode) {
    LOGERR(siblings->module->ctx, LY_EINVAL,
           "Failed to find \"%s\" as a sibling to \"%s:%s\".", name,
           lys_node_module(siblings)->name, siblings->name);
    return NULL;
  }
  return _lyd_new_leaf(parent, snode, val_str, 0, 0);
}

sf_open_virtual(SF_VIRTUAL_IO* sfvirtual, int mode, SF_INFO* sfinfo,
                void* user_data) {
  SF_PRIVATE* psf;
  if (sfvirtual->get_filelen == NULL || sfvirtual->seek == NULL ||
      sfvirtual->tell == NULL) {
    sf_errno = SFE_BAD_VIRTUAL_IO;
    snprintf(
        sf_parselog, sizeof(sf_parselog),
        "Bad vio_get_filelen / vio_seek / vio_tell in SF_VIRTUAL_IO struct.\n");
    return NULL;
  };
  if ((mode == SFM_READ || mode == SFM_RDWR) && sfvirtual->read == NULL) {
    sf_errno = SFE_BAD_VIRTUAL_IO;
    snprintf(sf_parselog, sizeof(sf_parselog),
             "Bad vio_read in SF_VIRTUAL_IO struct.\n");
    return NULL;
  };
  if ((mode == SFM_WRITE || mode == SFM_RDWR) && sfvirtual->write == NULL) {
    sf_errno = SFE_BAD_VIRTUAL_IO;
    snprintf(sf_parselog, sizeof(sf_parselog),
             "Bad vio_write in SF_VIRTUAL_IO struct.\n");
    return NULL;
  };
  if ((psf = calloc(1, sizeof(SF_PRIVATE))) == NULL) {
    sf_errno = SFE_MALLOC_FAILED;
    return NULL;
  };
  psf_init_files(psf);
  psf->virtual_io = SF_TRUE;
  psf->vio = *sfvirtual;
  psf->vio_user_data = user_data;
  psf->file.mode = mode;
  return psf_open_file(psf, sfinfo);
}

static int read_file_dentry_set(struct exfat_de_iter* iter,
                                struct exfat_inode** new_node,
                                int* skip_dentries) {
  struct exfat_dentry *file_de, *stream_de, *dentry;
  struct exfat_inode* node = NULL;
  int i, ret;
  ret = exfat_de_iter_get(iter, 0, &file_de);
  if (ret || file_de->type != EXFAT_FILE) {
    exfat_debug("failed to get file dentry\n");
    return -EINVAL;
  }
  ret = exfat_de_iter_get(iter, 1, &stream_de);
  if (ret || stream_de->type != EXFAT_STREAM) {
    exfat_debug("failed to get stream dentry\n");
    *skip_dentries = 2;
    goto skip_dset;
  }
  *new_node = NULL;
  node = exfat_alloc_inode(le16_to_cpu(file_de->file_attr));
  if (!node) return -ENOMEM;
  for (i = 2; i <= file_de->file_num_ext; i++) {
    ret = exfat_de_iter_get(iter, i, &dentry);
    if (ret || dentry->type != EXFAT_NAME) break;
    memcpy(node->name + (i - 2) * ENTRY_NAME_MAX, dentry->name_unicode,
           sizeof(dentry->name_unicode));
  }
  node->first_clus = le32_to_cpu(stream_de->stream_start_clu);
  node->is_contiguous = ((stream_de->stream_flags & EXFAT_SF_CONTIGUOUS) != 0);
  node->size = le64_to_cpu(stream_de->stream_size);
  *skip_dentries = i;
  *new_node = node;
  return 0;
skip_dset:
  *new_node = NULL;
  exfat_free_inode(node);
  return -EINVAL;
}

static int crypto_report_cipher(struct sk_buff* skb, struct crypto_alg* alg) {
  struct crypto_report_cipher rcipher;
  snprintf(rcipher.type, CRYPTO_MAX_ALG_NAME, "%s", "cipher");
  rcipher.blocksize = alg->cra_blocksize;
  rcipher.min_keysize = alg->cra_cipher.cia_min_keysize;
  rcipher.max_keysize = alg->cra_cipher.cia_max_keysize;
  if (nla_put(skb, CRYPTOCFGA_REPORT_CIPHER,
              sizeof(struct crypto_report_cipher), &rcipher))
    goto nla_put_failure;
  return 0;
nla_put_failure:
  return -EMSGSIZE;
}

struct vfsmount* clone_private_mount(const struct path* path) {
  struct mount* old_mnt = real_mount(path->mnt);
  struct mount* new_mnt;
  if (IS_MNT_UNBINDABLE(old_mnt)) return ERR_PTR(-EINVAL);
  new_mnt = clone_mnt(old_mnt, path->dentry, CL_PRIVATE);
  if (IS_ERR(new_mnt)) return ERR_CAST(new_mnt);
  new_mnt->mnt_ns = MNT_NS_INTERNAL;
  return &new_mnt->mnt;
}

static int intel_vgpu_mmap(struct mdev_device* mdev,
                           struct vm_area_struct* vma) {
  unsigned int index;
  u64 virtaddr;
  unsigned long req_size, pgoff = 0;
  pgprot_t pg_prot;
  struct intel_vgpu* vgpu = mdev_get_drvdata(mdev);
  index = vma->vm_pgoff >> (VFIO_PCI_OFFSET_SHIFT - PAGE_SHIFT);
  if (index >= VFIO_PCI_ROM_REGION_INDEX) return -EINVAL;
  if (vma->vm_end < vma->vm_start) return -EINVAL;
  if ((vma->vm_flags & VM_SHARED) == 0) return -EINVAL;
  if (index != VFIO_PCI_BAR2_REGION_INDEX) return -EINVAL;
  pg_prot = vma->vm_page_prot;
  virtaddr = vma->vm_start;
  req_size = vma->vm_end - vma->vm_start;
  pgoff = vgpu_aperture_pa_base(vgpu) >> PAGE_SHIFT;
  return remap_pfn_range(vma, virtaddr, pgoff, req_size, pg_prot);
}

njs_promise_resolve(njs_vm_t* vm, njs_value_t* constructor, njs_value_t* x) {
  njs_int_t ret;
  njs_value_t value;
  njs_object_t* object;
  njs_promise_capability_t* capability;
  static const njs_value_t string_constructor = njs_string("constructor");
  if (njs_is_object(x)) {
    object = njs_object_proto_lookup(njs_object(x), NJS_PROMISE, njs_object_t);
    if (object != NULL) {
      ret =
          njs_value_property(vm, x, njs_value_arg(&string_constructor), &value);
      if (njs_slow_path(ret == NJS_ERROR)) {
        return NULL;
      }
      if (njs_values_same(&value, constructor)) {
        return njs_promise(x);
      }
    }
  }
  capability = njs_promise_new_capability(vm, constructor);
  if (njs_slow_path(capability == NULL)) {
    return NULL;
  }
  ret = njs_function_call(vm, njs_function(&capability->resolve),
                          &njs_value_undefined, x, 1, &value);
  if (njs_slow_path(ret != NJS_OK)) {
    return NULL;
  }
  return njs_promise(&capability->promise);
}

static void scsi_dma_restart_bh(void* opaque) {
  SCSIDiskState* s = opaque;
  SCSIRequest* req;
  SCSIDiskReq* r;
  qemu_bh_delete(s->bh);
  s->bh = NULL;
  QTAILQ_FOREACH(req, &s->qdev.requests, next) {
    r = DO_UPCAST(SCSIDiskReq, req, req);
    if (r->status & SCSI_REQ_STATUS_RETRY) {
      int status = r->status;
      int ret;
      r->status &= ~(SCSI_REQ_STATUS_RETRY | SCSI_REQ_STATUS_RETRY_TYPE_MASK);
      switch (status & SCSI_REQ_STATUS_RETRY_TYPE_MASK) {
        case SCSI_REQ_STATUS_RETRY_READ:
          scsi_read_data(&r->req);
          break;
        case SCSI_REQ_STATUS_RETRY_WRITE:
          scsi_write_data(&r->req);
          break;
        case SCSI_REQ_STATUS_RETRY_FLUSH:
          ret = scsi_disk_emulate_command(r, r->iov.iov_base);
          if (ret == 0) {
            scsi_req_complete(&r->req, GOOD);
          }
      }
    }
  }
}

void ip4_datagram_release_cb(struct sock* sk) {
  const struct inet_sock* inet = inet_sk(sk);
  const struct ip_options_rcu* inet_opt;
  __be32 daddr = inet->inet_daddr;
  struct flowi4 fl4;
  struct rtable* rt;
  if (!__sk_dst_get(sk) || __sk_dst_check(sk, 0)) return;
  rcu_read_lock();
  inet_opt = rcu_dereference(inet->inet_opt);
  if (inet_opt && inet_opt->opt.srr) daddr = inet_opt->opt.faddr;
  rt =
      ip_route_output_ports(sock_net(sk), &fl4, sk, daddr, inet->inet_saddr,
                            inet->inet_dport, inet->inet_sport, sk->sk_protocol,
                            RT_CONN_FLAGS(sk), sk->sk_bound_dev_if);
  if (!IS_ERR(rt)) __sk_dst_set(sk, &rt->dst);
  rcu_read_unlock();
}

struct tcp_sock_t* tcp_open(uint16_t port) {
  struct tcp_sock_t* this = calloc(1, sizeof *this);
  if (this == NULL) {
    ERR("callocing this failed");
    goto error;
  }
  this->sd = -1;
  this->sd = socket(AF_INET6, SOCK_STREAM, 0);
  if (this->sd < 0) {
    ERR("sockect open failed");
    goto error;
  }
  struct sockaddr_in6 addr;
  memset(&addr, 0, sizeof addr);
  addr.sin6_family = AF_INET6;
  addr.sin6_port = htons(port);
  addr.sin6_addr = in6addr_any;
  if (bind(this->sd, (struct sockaddr*)&addr, sizeof addr) < 0) {
    if (g_options.only_desired_port == 1)
      ERR("Bind on port failed. "
          "Requested port may be taken or require root permissions.");
    goto error;
  }
  if (listen(this->sd, HTTP_MAX_PENDING_CONNS) < 0) {
    ERR("listen failed on socket");
    goto error;
  }
  return this;
error:
  if (this != NULL) {
    if (this->sd != -1) {
      close(this->sd);
    }
    free(this);
  }
  return NULL;
}

AP_CORE_DECLARE(void) ap_parse_uri(request_rec* r, const char* uri) {
  int status = HTTP_OK;
  r->unparsed_uri = apr_pstrdup(r->pool, uri);
  while ((uri[0] == '/') && (uri[1] == '/')) {
    ++uri;
  }
  if (r->method_number == M_CONNECT) {
    status = apr_uri_parse_hostinfo(r->pool, uri, &r->parsed_uri);
  } else {
    status = apr_uri_parse(r->pool, uri, &r->parsed_uri);
  }
  if (status == APR_SUCCESS) {
    if (r->parsed_uri.scheme &&
        !ap_cstr_casecmp(r->parsed_uri.scheme, ap_http_scheme(r))) {
      r->hostname = r->parsed_uri.hostname;
    } else if (r->method_number == M_CONNECT) {
      r->hostname = r->parsed_uri.hostname;
    }
    r->args = r->parsed_uri.query;
    r->uri =
        r->parsed_uri.path ? r->parsed_uri.path : apr_pstrdup(r->pool, "/");
#if defined(OS2) || defined(WIN32)
    {
      char* x;
      for (x = r->uri; (x = strchr(x, '\\')) != NULL;) *x = '/';
    }
#endif
  } else {
    r->args = NULL;
    r->hostname = NULL;
    r->status = HTTP_BAD_REQUEST;
    r->uri = apr_pstrdup(r->pool, uri);
  }
}

