getprivs_ret* get_privs_2_svc(krb5_ui_4* arg, struct svc_req* rqstp) {
  static getprivs_ret ret;
  gss_buffer_desc client_name, service_name;
  OM_uint32 minor_stat;
  kadm5_server_handle_t handle;
  const char* errmsg = NULL;
  xdr_free(xdr_getprivs_ret, &ret);
  if ((ret.code = new_server_handle(*arg, rqstp, &handle))) goto exit_func;
  if ((ret.code = check_handle((void*)handle))) goto exit_func;
  ret.api_version = handle->api_version;
  if (setup_gss_names(rqstp, &client_name, &service_name) < 0) {
    ret.code = KADM5_FAILURE;
    goto exit_func;
  }
  ret.code = kadm5_get_privs((void*)handle, &ret.privs);
  if (ret.code != 0) errmsg = krb5_get_error_message(handle->context, ret.code);
  log_done("kadm5_get_privs", client_name.value, errmsg, &client_name,
           &service_name, rqstp);
  if (errmsg != NULL) krb5_free_error_message(handle->context, errmsg);
  gss_release_buffer(&minor_stat, &client_name);
  gss_release_buffer(&minor_stat, &service_name);
exit_func:
  free_server_handle(handle);
  return &ret;
}

int copy_creds(struct task_struct* p, unsigned long clone_flags) {
#ifdef CONFIG_KEYS
  struct thread_group_cred* tgcred;
#endif
  struct cred* new;
  int ret;
  if (
#ifdef CONFIG_KEYS
      !p->cred->thread_keyring &&
#endif
      clone_flags & CLONE_THREAD) {
    p->real_cred = get_cred(p->cred);
    get_cred(p->cred);
    alter_cred_subscribers(p->cred, 2);
    kdebug("share_creds(%p{%d,%d})", p->cred, atomic_read(&p->cred->usage),
           read_cred_subscribers(p->cred));
    atomic_inc(&p->cred->user->processes);
    return 0;
  }
  new = prepare_creds();
  if (!new) return -ENOMEM;
  if (clone_flags & CLONE_NEWUSER) {
    ret = create_user_ns(new);
    if (ret < 0) goto error_put;
  }
  new->user_ns = new->user->user_ns;
#ifdef CONFIG_KEYS
  if (new->thread_keyring) {
    key_put(new->thread_keyring);
    new->thread_keyring = NULL;
    if (clone_flags & CLONE_THREAD) install_thread_keyring_to_cred(new);
  }
  if (!(clone_flags & CLONE_THREAD)) {
    tgcred = kmalloc(sizeof(*tgcred), GFP_KERNEL);
    if (!tgcred) {
      ret = -ENOMEM;
      goto error_put;
    }
    atomic_set(&tgcred->usage, 1);
    spin_lock_init(&tgcred->lock);
    tgcred->process_keyring = NULL;
    tgcred->session_keyring = key_get(new->tgcred->session_keyring);
    release_tgcred(new);
    new->tgcred = tgcred;
  }
#endif
  atomic_inc(&new->user->processes);
  p->cred = p->real_cred = get_cred(new);
  alter_cred_subscribers(new, 2);
  validate_creds(new);
  return 0;
error_put:
  put_cred(new);
  return ret;
}

ssh_packet_set_postauth(struct ssh* ssh) {
  struct sshcomp* comp;
  int r, mode;
  debug("%s: called", __func__);
  ssh->state->after_authentication = 1;
  ssh->state->rekeying = 0;
  for (mode = 0; mode < MODE_MAX; mode++) {
    if (ssh->state->newkeys[mode] == NULL) continue;
    comp = &ssh->state->newkeys[mode]->comp;
    if (comp && comp->enabled && (r = ssh_packet_init_compression(ssh)) != 0)
      return r;
  }
  return 0;
}

static int cp2112_gpio_direction_output(struct gpio_chip* chip, unsigned offset,
                                        int value) {
  struct cp2112_device* dev = gpiochip_get_data(chip);
  struct hid_device* hdev = dev->hdev;
  u8* buf = dev->in_out_buffer;
  unsigned long flags;
  int ret;
  spin_lock_irqsave(&dev->lock, flags);
  ret = hid_hw_raw_request(hdev, CP2112_GPIO_CONFIG, buf,
                           CP2112_GPIO_CONFIG_LENGTH, HID_FEATURE_REPORT,
                           HID_REQ_GET_REPORT);
  if (ret != CP2112_GPIO_CONFIG_LENGTH) {
    hid_err(hdev, "error requesting GPIO config: %d\n", ret);
    goto fail;
  }
  buf[1] |= 1 << offset;
  buf[2] = gpio_push_pull;
  ret = hid_hw_raw_request(hdev, CP2112_GPIO_CONFIG, buf,
                           CP2112_GPIO_CONFIG_LENGTH, HID_FEATURE_REPORT,
                           HID_REQ_SET_REPORT);
  if (ret < 0) {
    hid_err(hdev, "error setting GPIO config: %d\n", ret);
    goto fail;
  }
  spin_unlock_irqrestore(&dev->lock, flags);
  cp2112_gpio_set(chip, offset, value);
  return 0;
fail:
  spin_unlock_irqrestore(&dev->lock, flags);
  return ret < 0 ? ret : -EIO;
}

static void jsiSqlFunc(sqlite3_context* context, int argc,
                       sqlite3_value** argv) {
  SqlFunc* p = (SqlFunc*)sqlite3_user_data(context);
  int i;
  int rc;
  Jsi_Interp* interp = p->interp;
  Jsi_Value *vpargs, *itemsStatic[100], **items = itemsStatic, *ret;
  if (argc > 100) items = (Jsi_Value**)Jsi_Calloc(argc, sizeof(Jsi_Value*));
  for (i = 0; i < argc; i++) {
    items[i] = dbGetValueGet(interp, argv[i]);
  }
  vpargs = Jsi_ValueMakeObject(interp, NULL,
                               Jsi_ObjNewArray(interp, items, argc, 0));
  Jsi_IncrRefCount(interp, vpargs);
  ret = Jsi_ValueNew1(interp);
  rc = Jsi_FunctionInvoke(interp, p->tocall, vpargs, &ret, NULL);
  Jsi_DecrRefCount(interp, vpargs);
  if (items != itemsStatic) Jsi_Free(items);
  bool b;
  if (rc != JSI_OK) {
    char buf[250];
    snprintf(buf, sizeof(buf), "error in function: %.200s", p->zName);
    sqlite3_result_error(context, buf, -1);
  } else if (Jsi_ValueIsBoolean(interp, ret)) {
    Jsi_GetBoolFromValue(interp, ret, &b);
    sqlite3_result_int(context, b);
  } else if (Jsi_ValueIsNumber(interp, ret)) {
    Jsi_Number d;
    Jsi_GetNumberFromValue(interp, ret, &d);
    sqlite3_result_double(context, (double)d);
  } else {
    const char* data;
    if (!(data = Jsi_ValueGetStringLen(interp, ret, &i))) {
      data = Jsi_ValueToString(interp, ret, NULL);
      i = Jsi_Strlen(data);
    }
    sqlite3_result_text(context, (char*)data, i, SQLITE_TRANSIENT);
  }
  Jsi_DecrRefCount(interp, ret);
}

