int tipc_nl_publ_dump(struct sk_buff* skb, struct netlink_callback* cb) {
  int err;
  u32 tsk_portid = cb->args[0];
  u32 last_publ = cb->args[1];
  u32 done = cb->args[2];
  struct net* net = sock_net(skb->sk);
  struct tipc_sock* tsk;
  if (!tsk_portid) {
    struct nlattr** attrs;
    struct nlattr* sock[TIPC_NLA_SOCK_MAX + 1];
    err = tipc_nlmsg_parse(cb->nlh, &attrs);
    if (err) return err;
    err = nla_parse_nested(sock, TIPC_NLA_SOCK_MAX, attrs[TIPC_NLA_SOCK],
                           tipc_nl_sock_policy);
    if (err) return err;
    if (!sock[TIPC_NLA_SOCK_REF]) return -EINVAL;
    tsk_portid = nla_get_u32(sock[TIPC_NLA_SOCK_REF]);
  }
  if (done) return 0;
  tsk = tipc_sk_lookup(net, tsk_portid);
  if (!tsk) return -EINVAL;
  lock_sock(&tsk->sk);
  err = __tipc_nl_list_sk_publ(skb, cb, tsk, &last_publ);
  if (!err) done = 1;
  release_sock(&tsk->sk);
  sock_put(&tsk->sk);
  cb->args[0] = tsk_portid;
  cb->args[1] = last_publ;
  cb->args[2] = done;
  return skb->len;
}

static int putreg(struct task_struct* child, unsigned long regno,
                  unsigned long value) {
  unsigned long tmp;
  if (test_tsk_thread_flag(child, TIF_IA32)) value &= 0xffffffff;
  switch (regno) {
    case offsetof(struct user_regs_struct, fs):
      if (value && (value & 3) != 3) return -EIO;
      child->thread.fsindex = value & 0xffff;
      return 0;
    case offsetof(struct user_regs_struct, gs):
      if (value && (value & 3) != 3) return -EIO;
      child->thread.gsindex = value & 0xffff;
      return 0;
    case offsetof(struct user_regs_struct, ds):
      if (value && (value & 3) != 3) return -EIO;
      child->thread.ds = value & 0xffff;
      return 0;
    case offsetof(struct user_regs_struct, es):
      if (value && (value & 3) != 3) return -EIO;
      child->thread.es = value & 0xffff;
      return 0;
    case offsetof(struct user_regs_struct, ss):
      if ((value & 3) != 3) return -EIO;
      value &= 0xffff;
      return 0;
    case offsetof(struct user_regs_struct, fs_base):
      if (value >= TASK_SIZE_OF(child)) return -EIO;
      child->thread.fs = value;
      return 0;
    case offsetof(struct user_regs_struct, gs_base):
      if (value >= TASK_SIZE_OF(child)) return -EIO;
      child->thread.gs = value;
      return 0;
    case offsetof(struct user_regs_struct, eflags):
      value &= FLAG_MASK;
      tmp = get_stack_long(child, EFL_OFFSET);
      tmp &= ~FLAG_MASK;
      value |= tmp;
      break;
    case offsetof(struct user_regs_struct, cs):
      if ((value & 3) != 3) return -EIO;
      value &= 0xffff;
      break;
  }
  put_stack_long(child, regno - sizeof(struct pt_regs), value);
  return 0;
}

static int __init ipgre_init(void) {
  int err;
  printk(KERN_INFO "GRE over IPv4 tunneling driver\n");
  if (inet_add_protocol(&ipgre_protocol, IPPROTO_GRE) < 0) {
    printk(KERN_INFO "ipgre init: can't add protocol\n");
    return -EAGAIN;
  }
  err = register_pernet_device(&ipgre_net_ops);
  if (err < 0) goto gen_device_failed;
  err = rtnl_link_register(&ipgre_link_ops);
  if (err < 0) goto rtnl_link_failed;
  err = rtnl_link_register(&ipgre_tap_ops);
  if (err < 0) goto tap_ops_failed;
out:
  return err;
tap_ops_failed:
  rtnl_link_unregister(&ipgre_link_ops);
rtnl_link_failed:
  unregister_pernet_device(&ipgre_net_ops);
gen_device_failed:
  inet_del_protocol(&ipgre_protocol, IPPROTO_GRE);
  goto out;
}

static pfn_t kvm_pin_pages(struct kvm_memory_slot* slot, gfn_t gfn,
                           unsigned long size) {
  gfn_t end_gfn;
  pfn_t pfn;
  pfn = gfn_to_pfn_memslot(slot, gfn);
  end_gfn = gfn + (size >> PAGE_SHIFT);
  gfn += 1;
  if (is_error_noslot_pfn(pfn)) return pfn;
  while (gfn < end_gfn) gfn_to_pfn_memslot(slot, gfn++);
  return pfn;
}

static RSA_PSS_PARAMS* rsa_pss_decode(const X509_ALGOR* alg,
                                      X509_ALGOR** pmaskHash) {
  const unsigned char* p;
  int plen;
  RSA_PSS_PARAMS* pss;
  *pmaskHash = NULL;
  if (!alg->parameter || alg->parameter->type != V_ASN1_SEQUENCE) return NULL;
  p = alg->parameter->value.sequence->data;
  plen = alg->parameter->value.sequence->length;
  pss = d2i_RSA_PSS_PARAMS(NULL, &p, plen);
  if (!pss) return NULL;
  if (pss->maskGenAlgorithm) {
    ASN1_TYPE* param = pss->maskGenAlgorithm->parameter;
    if (OBJ_obj2nid(pss->maskGenAlgorithm->algorithm) == NID_mgf1 &&
        param->type == V_ASN1_SEQUENCE) {
      p = param->value.sequence->data;
      plen = param->value.sequence->length;
      *pmaskHash = d2i_X509_ALGOR(NULL, &p, plen);
    }
  }
  return pss;
}

