    return -EINVAL;
  }
  exec2_list = kmalloc(sizeof(*exec2_list) * args->buffer_count,
                       GFP_KERNEL | __GFP_NOWARN | __GFP_NORETRY);
  if (exec2_list == NULL)
    exec2_list = drm_malloc_ab(sizeof(*exec2_list), args->buffer_count);
  if (exec2_list == NULL) {
    DRM_DEBUG("Failed to allocate exec list for %d buffers\n",
              args->buffer_count);
    return -ENOMEM;
  }
  ret = copy_from_user(
      exec2_list,
      (struct drm_i915_relocation_entry __user*)(uintptr_t)args->buffers_ptr,
      sizeof(*exec2_list) * args->buffer_count);
  if (ret != 0) {
    DRM_DEBUG("copy %d exec entries failed %d\n", args->buffer_count, ret);
    drm_free_large(exec2_list);
    return -EFAULT;
  }
  ret = i915_gem_do_execbuffer(dev, data, file, args, exec2_list);
  if (!ret) {
    ret = copy_to_user(
        (struct drm_i915_relocation_entry __user*)(uintptr_t)args->buffers_ptr,
        exec2_list, sizeof(*exec2_list) * args->buffer_count);
    if (ret) {
      ret = -EFAULT;
      DRM_DEBUG(
          "failed to copy %d exec entries "
          "back to user (%d)\n",
          args->buffer_count, ret);
    }
  }
  drm_free_large(exec2_list);
  return ret;
}

static int handle_to_path(int mountdirfd, struct file_handle __user* ufh,
                          struct path* path) {
  int retval = 0;
  struct file_handle f_handle;
  struct file_handle* handle = NULL;
  if (!capable(CAP_DAC_READ_SEARCH)) {
    retval = -EPERM;
    goto out_err;
  }
  if (copy_from_user(&f_handle, ufh, sizeof(struct file_handle))) {
    retval = -EFAULT;
    goto out_err;
  }
  if ((f_handle.handle_bytes > MAX_HANDLE_SZ) || (f_handle.handle_bytes == 0)) {
    retval = -EINVAL;
    goto out_err;
  }
  handle =
      kmalloc(sizeof(struct file_handle) + f_handle.handle_bytes, GFP_KERNEL);
  if (!handle) {
    retval = -ENOMEM;
    goto out_err;
  }
  if (copy_from_user(handle, ufh,
                     sizeof(struct file_handle) + f_handle.handle_bytes)) {
    retval = -EFAULT;
    goto out_handle;
  }
  retval = do_handle_to_path(mountdirfd, handle, path);
out_handle:
  kfree(handle);
out_err:
  return retval;
}

validate_event(struct pmu_hw_events* hw_events, struct perf_event* event) {
  struct arm_pmu* armpmu = to_arm_pmu(event->pmu);
  struct pmu* leader_pmu = event->group_leader->pmu;
  if (event->pmu != leader_pmu || event->state < PERF_EVENT_STATE_OFF) return 1;
  if (event->state == PERF_EVENT_STATE_OFF && !event->attr.enable_on_exec)
    return 1;
  return armpmu->get_event_idx(hw_events, event) >= 0;
}

static void _cmd_window_show_opt(const char* data, int right) {
