static int ldb_lock_backend_callback(struct ldb_request* req,
                                     struct ldb_reply* ares) {
  struct ldb_db_lock_context* lock_context;
  int ret;
  lock_context = talloc_get_type(req->context, struct ldb_db_lock_context);
  if (!ares) {
    return ldb_module_done(lock_context->req, NULL, NULL,
                           LDB_ERR_OPERATIONS_ERROR);
  }
  if (ares->error != LDB_SUCCESS || ares->type == LDB_REPLY_DONE) {
    ret = ldb_module_done(lock_context->req, ares->controls, ares->response,
                          ares->error);
    talloc_free(lock_context);
    return ret;
  }
  switch (ares->type) {
    case LDB_REPLY_ENTRY:
      return ldb_module_send_entry(lock_context->req, ares->message,
                                   ares->controls);
    case LDB_REPLY_REFERRAL:
      return ldb_module_send_referral(lock_context->req, ares->referral);
    default:
      return LDB_ERR_OPERATIONS_ERROR;
  }
}

long ParseElementHeader(IMkvReader* pReader, long long& pos, long long stop,
                        long long& id, long long& size) {
  if (stop >= 0 && pos >= stop) return E_FILE_FORMAT_INVALID;
  long len;
  id = ReadID(pReader, pos, len);
  if (id < 0) return E_FILE_FORMAT_INVALID;
  pos += len;
  if (stop >= 0 && pos >= stop) return E_FILE_FORMAT_INVALID;
  size = ReadUInt(pReader, pos, len);
  if (size < 0 || len < 1 || len > 8) {
    return E_FILE_FORMAT_INVALID;
  }
  const unsigned long long rollover_check =
      static_cast<unsigned long long>(pos) + len;
  if (rollover_check > LONG_LONG_MAX) return E_FILE_FORMAT_INVALID;
  pos += len;
  if (stop >= 0 && pos >= stop) return E_FILE_FORMAT_INVALID;
  return 0;
}

CbrDetectorRemote::Result CbrDetectorRemote::Decrypt(
    cricket::MediaType media_type, const std::vector<uint32_t>& csrcs,
    rtc::ArrayView<const uint8_t> additional_data,
    rtc::ArrayView<const uint8_t> encrypted_frame,
    rtc::ArrayView<uint8_t> frame) {
  const uint8_t* src = encrypted_frame.data();
  uint8_t* dst = frame.data();
  uint32_t data_len = encrypted_frame.size();
  if (media_type == cricket::MEDIA_TYPE_AUDIO) {
    if (data_len == frame_size && frame_size >= 40) {
      frame_count++;
      if (frame_count > 200 && !detected) {
        info("CBR detector: remote cbr detected\n");
        detected = true;
      }
    } else {
      frame_count = 0;
      frame_size = data_len;
      if (detected) {
        info("CBR detector: remote cbr detected disabled\n");
        detected = false;
      }
    }
  }
  memcpy(dst, src, data_len);
out:
  return CbrDetectorRemote::Result(CbrDetectorRemote::Status::kOk, data_len);
}

