static int ptrace_check_attach(struct task_struct* child, bool ignore_state) {
  int ret = -ESRCH;
  read_lock(&tasklist_lock);
  if ((child->ptrace & PT_PTRACED) && child->parent == current) {
    spin_lock_irq(&child->sighand->siglock);
    WARN_ON_ONCE(task_is_stopped(child));
    if (ignore_state ||
        (task_is_traced(child) && !(child->jobctl & JOBCTL_LISTENING)))
      ret = 0;
    spin_unlock_irq(&child->sighand->siglock);
  }
  read_unlock(&tasklist_lock);
  if (!ret && !ignore_state)
    ret = wait_task_inactive(child, TASK_TRACED) ? 0 : -ESRCH;
  return ret;
}

spa_base64_to_bits(char* out, int outlength, const char* in) {
  int len = 0;
  register uschar digit1, digit2, digit3, digit4;
  if (in[0] == '+' && in[1] == ' ') in += 2;
  if (*in == '\r') return (0);
  do {
    if (len >= outlength) return (-1);
    digit1 = in[0];
    if (DECODE64(digit1) == BAD) return (-1);
    digit2 = in[1];
    if (DECODE64(digit2) == BAD) return (-1);
    digit3 = in[2];
    if (digit3 != '=' && DECODE64(digit3) == BAD) return (-1);
    digit4 = in[3];
    if (digit4 != '=' && DECODE64(digit4) == BAD) return (-1);
    in += 4;
    *out++ = (DECODE64(digit1) << 2) | (DECODE64(digit2) >> 4);
    ++len;
    if (digit3 != '=') {
      if (len >= outlength) return (-1);
      *out++ = ((DECODE64(digit2) << 4) & 0xf0) | (DECODE64(digit3) >> 2);
      ++len;
      if (digit4 != '=') {
        if (len >= outlength) return (-1);
        *out++ = ((DECODE64(digit3) << 6) & 0xc0) | DECODE64(digit4);
        ++len;
      }
    }
  } while (*in && *in != '\r' && digit4 != '=');
  return (len);
}

inline bool loadModule(const char* filename, IR::Module& outModule) {
  std::vector<U8> fileBytes;
  if (!loadFile(filename, fileBytes)) {
    return false;
  }
  if (*(U32*)fileBytes.data() == 0x6d736100) {
    return loadBinaryModule(fileBytes.data(), fileBytes.size(), outModule);
  } else {
    fileBytes.push_back(0);
    std::vector<WAST::Error> parseErrors;
    if (!WAST::parseModule((const char*)fileBytes.data(), fileBytes.size(),
                           outModule, parseErrors)) {
      Log::printf(Log::error, "Error parsing WebAssembly text file:\n");
      reportParseErrors(filename, parseErrors);
      return false;
    }
    return true;
  }
}

bool IsPadOpSupported(const TfLiteRegistration* registration,
                      const TfLiteNode* node, TfLiteContext* context) {
  const TfLiteTensor* padding = GetInput(context, node, 1);
  if (!IsConstantTensor(padding)) {
    TF_LITE_KERNEL_LOG(context,
                       "%s: Only constant padding is supported for PAD.",
                       padding->name);
    return false;
  }
  if (padding->dims->data[0] != 4 || padding->dims->data[1] != 2) {
    TF_LITE_KERNEL_LOG(context, "%s: Only 4D inputs are supported for PAD.",
                       padding->name);
    return false;
  }
  const int32_t* padding_data = GetTensorData<int32_t>(padding);
  if (!(padding_data[0] == 0 && padding_data[1] == 0)) {
    TF_LITE_KERNEL_LOG(
        context, "%s: Padding for batch dimension is not supported in PAD.",
        padding->name);
    return false;
  }
  if (!(padding_data[6] == 0 && padding_data[7] == 0)) {
    TF_LITE_KERNEL_LOG(
        context, "%s: Padding for channel dimension is not supported in PAD.",
        padding->name);
    return false;
  }
  return true;
}

void SmallVectorBase::grow_pod(void* FirstEl, size_t MinCapacity,
                               size_t TSize) {
  if (MinCapacity > UINT32_MAX)
    report_bad_alloc_error("SmallVector capacity overflow during allocation");
  size_t NewCapacity = 2 * capacity() + 1;
  NewCapacity =
      std::min(std::max(NewCapacity, MinCapacity), size_t(UINT32_MAX));
  void* NewElts;
  if (BeginX == FirstEl) {
    NewElts = safe_malloc(NewCapacity * TSize);
    memcpy(NewElts, this->BeginX, size() * TSize);
  } else {
    NewElts = safe_realloc(this->BeginX, NewCapacity * TSize);
  }
  this->BeginX = NewElts;
  this->Capacity = NewCapacity;
}

static int http_open(URLContext* h, const char* uri, int flags,
                     AVDictionary** options) {
  HTTPContext* s = h->priv_data;
  int ret;
  if (s->seekable == 1)
    h->is_streamed = 0;
  else
    h->is_streamed = 1;
  s->filesize = -1;
  s->location = av_strdup(uri);
  if (!s->location) return AVERROR(ENOMEM);
  if (options) av_dict_copy(&s->chained_options, *options, 0);
  if (s->headers) {
    int len = strlen(s->headers);
    if (len < 2 || strcmp("\r\n", s->headers + len - 2)) {
      av_log(h, AV_LOG_WARNING, "No trailing CRLF found in HTTP header.\n");
      ret = av_reallocp(&s->headers, len + 3);
      if (ret < 0) return ret;
      s->headers[len] = '\r';
      s->headers[len + 1] = '\n';
      s->headers[len + 2] = '\0';
    }
  }
  if (s->listen) {
    return http_listen(h, uri, flags, options);
  }
  ret = http_open_cnx(h, options);
  if (ret < 0) av_dict_free(&s->chained_options);
  return ret;
}

xbstream_open(ds_ctxt_t* ctxt, const char* path, MY_STAT* mystat) {
  ds_file_t* file;
  ds_stream_file_t* stream_file;
  ds_stream_ctxt_t* stream_ctxt;
  ds_ctxt_t* dest_ctxt;
  xb_wstream_t* xbstream;
  xb_wstream_file_t* xbstream_file;
  xb_ad(ctxt->pipe_ctxt != NULL);
  dest_ctxt = ctxt->pipe_ctxt;
  stream_ctxt = (ds_stream_ctxt_t*)ctxt->ptr;
  pthread_mutex_lock(&stream_ctxt->mutex);
  if (stream_ctxt->dest_file == NULL) {
    stream_ctxt->dest_file = ds_open(dest_ctxt, path, mystat);
    if (stream_ctxt->dest_file == NULL) {
      return NULL;
    }
  }
  pthread_mutex_unlock(&stream_ctxt->mutex);
  file = (ds_file_t*)my_malloc(sizeof(ds_file_t) + sizeof(ds_stream_file_t),
                               MYF(MY_FAE));
  stream_file = (ds_stream_file_t*)(file + 1);
  xbstream = stream_ctxt->xbstream;
  xbstream_file = xb_stream_write_open(xbstream, path, mystat, stream_ctxt,
                                       my_xbstream_write_callback);
  if (xbstream_file == NULL) {
    msg("xb_stream_write_open() failed.");
    goto err;
  }
  stream_file->xbstream_file = xbstream_file;
  stream_file->stream_ctxt = stream_ctxt;
  file->ptr = stream_file;
  file->path = stream_ctxt->dest_file->path;
  return file;
err:
  if (stream_ctxt->dest_file) {
    ds_close(stream_ctxt->dest_file);
    stream_ctxt->dest_file = NULL;
  }
  my_free(file);
  return NULL;
}

x86_reg X86_insn_reg_intel(unsigned int id, enum cs_ac_type* access) {
  unsigned int first = 0;
  unsigned int last = ARR_SIZE(insn_regs_intel) - 1;
  unsigned int mid = ARR_SIZE(insn_regs_intel) / 2;
  if (!intel_regs_sorted) {
    memcpy(insn_regs_intel_sorted, insn_regs_intel,
           sizeof(insn_regs_intel_sorted));
    qsort(insn_regs_intel_sorted, ARR_SIZE(insn_regs_intel_sorted),
          sizeof(struct insn_reg), regs_cmp);
    intel_regs_sorted = true;
  }
  while (first <= last) {
    if (insn_regs_intel_sorted[mid].insn < id) {
      first = mid + 1;
    } else if (insn_regs_intel_sorted[mid].insn == id) {
      if (access) {
        *access = insn_regs_intel_sorted[mid].access;
      }
      return insn_regs_intel_sorted[mid].reg;
    } else {
      if (mid == 0) break;
      last = mid - 1;
    }
    mid = (first + last) / 2;
  }
  return 0;
}

