xmlDocPtr soap_xmlParseMemory(const void* buf, size_t buf_size) {
  xmlParserCtxtPtr ctxt = NULL;
  xmlDocPtr ret;
  ctxt = xmlCreateMemoryParserCtxt(buf, buf_size);
  if (ctxt) {
    ctxt->options -= XML_PARSE_DTDLOAD;
    ctxt->sax->ignorableWhitespace = soap_ignorableWhitespace;
    ctxt->sax->comment = soap_Comment;
    ctxt->sax->warning = NULL;
    ctxt->sax->error = NULL;
#if LIBXML_VERSION >= 20703
    ctxt->options |= XML_PARSE_HUGE;
#endif
    xmlParseDocument(ctxt);
    if (ctxt->wellFormed) {
      ret = ctxt->myDoc;
      if (ret->URL == NULL && ctxt->directory != NULL) {
        ret->URL = xmlCharStrdup(ctxt->directory);
      }
    } else {
      ret = NULL;
      xmlFreeDoc(ctxt->myDoc);
      ctxt->myDoc = NULL;
    }
    xmlFreeParserCtxt(ctxt);
  } else {
    ret = NULL;
  }
  return ret;
}

static bool ntlmssp_check_buffer(const struct ntlmssp_buffer* buffer,
                                 size_t data_size, const char** error) {
  uint32_t offset = read_le32(&buffer->offset);
  uint16_t length = read_le16(&buffer->length);
  uint16_t space = read_le16(&buffer->space);
  if (length == 0 && space == 0) return TRUE;
  if (offset >= data_size) {
    *error = "buffer offset out of bounds";
    return FALSE;
  }
  if (offset + space > data_size) {
    *error = "buffer end out of bounds";
    return FALSE;
  }
  return TRUE;
}

static int sctp_v6_xmit(struct sk_buff* skb, struct sctp_transport* transport) {
  struct sock* sk = skb->sk;
  struct ipv6_pinfo* np = inet6_sk(sk);
  struct flowi6 fl6;
  memset(&fl6, 0, sizeof(fl6));
  fl6.flowi6_proto = sk->sk_protocol;
  fl6.daddr = transport->ipaddr.v6.sin6_addr;
  fl6.saddr = transport->saddr.v6.sin6_addr;
  fl6.flowlabel = np->flow_label;
  IP6_ECN_flow_xmit(sk, fl6.flowlabel);
  if (ipv6_addr_type(&fl6.saddr) & IPV6_ADDR_LINKLOCAL)
    fl6.flowi6_oif = transport->saddr.v6.sin6_scope_id;
  else
    fl6.flowi6_oif = sk->sk_bound_dev_if;
  if (np->opt && np->opt->srcrt) {
    struct rt0_hdr* rt0 = (struct rt0_hdr*)np->opt->srcrt;
    fl6.daddr = *rt0->addr;
  }
  pr_debug("%s: skb:%p, len:%d, src:%pI6 dst:%pI6\n", __func__, skb, skb->len,
           &fl6.saddr, &fl6.daddr);
  SCTP_INC_STATS(sock_net(sk), SCTP_MIB_OUTSCTPPACKS);
  if (!(transport->param_flags & SPP_PMTUD_ENABLE)) skb->local_df = 1;
  return ip6_xmit(sk, skb, &fl6, np->opt, np->tclass);
}

void MakeDataset(OpKernelContext* ctx, DatasetBase** output) override {
  const Tensor* indices;
  OP_REQUIRES_OK(ctx, ctx->input("indices", &indices));
  const Tensor* values;
  OP_REQUIRES_OK(ctx, ctx->input("values", &values));
  const Tensor* dense_shape;
  OP_REQUIRES_OK(ctx, ctx->input("dense_shape", &dense_shape));
  OP_REQUIRES(ctx, TensorShapeUtils::IsMatrix(indices->shape()),
              errors::InvalidArgument(
                  "Input indices should be a matrix but received shape ",
                  indices->shape().DebugString()));
  const auto num_indices = indices->NumElements();
  const auto num_values = values->NumElements();
  if (num_indices == 0 || num_values == 0) {
    OP_REQUIRES(ctx, num_indices == num_values,
                errors::InvalidArgument(
                    "If indices or values are empty, the other one must also "
                    "be. Got indices of shape ",
                    indices->shape().DebugString(), " and values of shape ",
                    values->shape().DebugString()));
  }
  OP_REQUIRES(ctx, TensorShapeUtils::IsVector(values->shape()),
              errors::InvalidArgument(
                  "Input values should be a vector but received shape ",
                  indices->shape().DebugString()));
  OP_REQUIRES(ctx, TensorShapeUtils::IsVector(dense_shape->shape()),
              errors::InvalidArgument(
                  "Input shape should be a vector but received shape ",
                  dense_shape->shape().DebugString()));
  int64_t previous_batch_index = -1;
  for (int64_t i = 0; i < indices->dim_size(0); ++i) {
    int64_t next_batch_index = indices->matrix<int64_t>()(i, 0);
    OP_REQUIRES(
        ctx, next_batch_index >= previous_batch_index,
        errors::Unimplemented("The SparseTensor must be ordered in the batch "
                              "dimension; handling arbitrarily ordered input "
                              "is not currently supported."));
    previous_batch_index = next_batch_index;
  }
  gtl::InlinedVector<int64_t, 8> std_order(dense_shape->NumElements(), 0);
  sparse::SparseTensor tensor;
  OP_REQUIRES_OK(
      ctx, sparse::SparseTensor::Create(
               *indices, *values, TensorShape(dense_shape->vec<int64_t>()),
               std_order, &tensor));
  *output = new Dataset<T>(ctx, std::move(tensor));
}

QueueHandle_t xQueueGenericCreate(const UBaseType_t uxQueueLength,
                                  const UBaseType_t uxItemSize,
                                  const uint8_t ucQueueType) {
  Queue_t* pxNewQueue;
  size_t xQueueSizeInBytes;
  uint8_t* pucQueueStorage;
  configASSERT(uxQueueLength > (UBaseType_t)0);
  xQueueSizeInBytes = (size_t)(uxQueueLength * uxItemSize);
  configASSERT((uxItemSize == 0) ||
               (uxQueueLength == (xQueueSizeInBytes / uxItemSize)));
  pxNewQueue = (Queue_t*)pvPortMalloc(sizeof(Queue_t) + xQueueSizeInBytes);
  if (pxNewQueue != NULL) {
    pucQueueStorage = (uint8_t*)pxNewQueue;
    pucQueueStorage += sizeof(Queue_t);
#if (configSUPPORT_STATIC_ALLOCATION == 1)
    {
      pxNewQueue->ucStaticallyAllocated = pdFALSE;
    }
#endif
    prvInitialiseNewQueue(uxQueueLength, uxItemSize, pucQueueStorage,
                          ucQueueType, pxNewQueue);
  } else {
    traceQUEUE_CREATE_FAILED(ucQueueType);
    mtCOVERAGE_TEST_MARKER();
  }
  return pxNewQueue;
}

atm_if_print(netdissect_options* ndo, const struct pcap_pkthdr* h,
             const u_char* p) {
  u_int caplen = h->caplen;
  u_int length = h->len;
  uint32_t llchdr;
  u_int hdrlen = 0;
  if (caplen < 1 || length < 1) {
    ND_PRINT((ndo, "%s", tstr));
    return (caplen);
  }
  if (*p == LLC_UI) {
    if (ndo->ndo_eflag) ND_PRINT((ndo, "CNLPID "));
    isoclns_print(ndo, p + 1, length - 1, caplen - 1);
    return hdrlen;
  }
  if (caplen < 3 || length < 3) {
    ND_PRINT((ndo, "%s", tstr));
    return (caplen);
  }
  llchdr = EXTRACT_24BITS(p);
  if (llchdr != LLC_UI_HDR(LLCSAP_SNAP) && llchdr != LLC_UI_HDR(LLCSAP_ISONS) &&
      llchdr != LLC_UI_HDR(LLCSAP_IP)) {
    if (caplen < 20 || length < 20) {
      ND_PRINT((ndo, "%s", tstr));
      return (caplen);
    }
    if (ndo->ndo_eflag)
      ND_PRINT((ndo, "%08x%08x %08x%08x ", EXTRACT_32BITS(p),
                EXTRACT_32BITS(p + 4), EXTRACT_32BITS(p + 8),
                EXTRACT_32BITS(p + 12)));
    p += 20;
    length -= 20;
    caplen -= 20;
    hdrlen += 20;
  }
  hdrlen += atm_llc_print(ndo, p, length, caplen);
  return (hdrlen);
}

static zend_bool add_post_var(zval* arr, post_var_data_t* var,
                              zend_bool eof TSRMLS_DC) {
  char *ksep, *vsep, *val;
  size_t klen, vlen;
  unsigned int new_vlen;
  if (var->ptr >= var->end) {
    return 0;
  }
  vsep = memchr(var->ptr, '&', var->end - var->ptr);
  if (!vsep) {
    if (!eof) {
      return 0;
    } else {
      vsep = var->end;
    }
  }
  ksep = memchr(var->ptr, '=', vsep - var->ptr);
  if (ksep) {
    *ksep = '\0';
    klen = ksep - var->ptr;
    vlen = vsep - ++ksep;
  } else {
    ksep = "";
    klen = vsep - var->ptr;
    vlen = 0;
  }
  php_url_decode(var->ptr, klen);
  val = estrndup(ksep, vlen);
  if (vlen) {
    vlen = php_url_decode(val, vlen);
  }
  if (sapi_module.input_filter(PARSE_POST, var->ptr, &val, vlen,
                               &new_vlen TSRMLS_CC)) {
    php_register_variable_safe(var->ptr, val, new_vlen, arr TSRMLS_CC);
  }
  efree(val);
  var->ptr = vsep + (vsep != var->end);
  return 1;
}

