update_bar_address(struct vmctx* ctx, struct pci_vdev* dev, uint64_t addr,
                   int idx, int type, bool ignore_reg_unreg) {
  bool decode = false;
  uint64_t orig_addr = dev->bar[idx].addr;
  if (!ignore_reg_unreg) {
    if (dev->bar[idx].type == PCIBAR_IO)
      decode = porten(dev);
    else
      decode = memen(dev);
  }
  if (decode) unregister_bar(dev, idx);
  switch (type) {
    case PCIBAR_IO:
    case PCIBAR_MEM32:
      dev->bar[idx].addr = addr;
      break;
    case PCIBAR_MEM64:
      dev->bar[idx].addr &= ~0xffffffffUL;
      dev->bar[idx].addr |= addr;
      break;
    case PCIBAR_MEMHI64:
      dev->bar[idx].addr &= 0xffffffff;
      dev->bar[idx].addr |= addr;
      break;
    default:
      assert(0);
  }
  if (decode) register_bar(dev, idx);
  if (dev->dev_ops->vdev_update_bar_map && decode)
    dev->dev_ops->vdev_update_bar_map(ctx, dev, idx, orig_addr);
}

long ZEXPORT inflateMark(strm)
z_streamp strm;
{
  struct inflate_state FAR* state;
  if (strm == Z_NULL || strm->state == Z_NULL) return -1L << 16;
  state = (struct inflate_state FAR*)strm->state;
  return ((long)(state->back) << 16) +
         (state->mode == COPY
              ? state->length
              : (state->mode == MATCH ? state->was - state->length : 0));
}

Integer InvertibleRWFunction::CalculateInverse(RandomNumberGenerator& rng,
                                               const Integer& x) const {
  DoQuickSanityCheck();
  ModularArithmetic modn(m_n);
  Integer r, rInv;
  do {
    r.Randomize(rng, Integer::One(), m_n - Integer::One());
    rInv = modn.MultiplicativeInverse(r);
  } while (rInv.IsZero());
  Integer re = modn.Square(r);
  re = modn.Multiply(re, x);
  Integer cp = re % m_p, cq = re % m_q;
  if (Jacobi(cp, m_p) * Jacobi(cq, m_q) != 1) {
    cp = cp.IsOdd() ? (cp + m_p) >> 1 : cp >> 1;
    cq = cq.IsOdd() ? (cq + m_q) >> 1 : cq >> 1;
  }
#pragma omp parallel
#pragma omp sections
  {
#pragma omp section
    cp = ModularSquareRoot(cp, m_p);
#pragma omp section
    cq = ModularSquareRoot(cq, m_q);
  }
  Integer y = CRT(cq, m_q, cp, m_p, m_u);
  y = modn.Multiply(y, rInv);
  y = STDMIN(y, m_n - y);
  if (ApplyFunction(y) != x)
    throw Exception(Exception::OTHER_ERROR,
                    "InvertibleRWFunction: computational error during private "
                    "key operation");
  return y;
}

static int snd_compr_allocate_buffer(struct snd_compr_stream* stream,
                                     struct snd_compr_params* params) {
  unsigned int buffer_size;
  void* buffer;
  buffer_size = params->buffer.fragment_size * params->buffer.fragments;
  if (stream->ops->copy) {
    buffer = NULL;
  } else {
    buffer = kmalloc(buffer_size, GFP_KERNEL);
    if (!buffer) return -ENOMEM;
  }
  stream->runtime->fragment_size = params->buffer.fragment_size;
  stream->runtime->fragments = params->buffer.fragments;
  stream->runtime->buffer = buffer;
  stream->runtime->buffer_size = buffer_size;
  return 0;
}

