  if (check_user_password(new_user_password, data)) {
    result = true;
    user_password = new_user_password;
  }
  return result;
}

void Ogg::XiphComment::parse(const ByteVector& data) {
  int pos = 0;
  int vendorLength = data.mid(0, 4).toUInt(false);
  pos += 4;
  d->vendorID = String(data.mid(pos, vendorLength), String::UTF8);
  pos += vendorLength;
  int commentFields = data.mid(pos, 4).toUInt(false);
  pos += 4;
  for (int i = 0; i < commentFields; i++) {
    int commentLength = data.mid(pos, 4).toUInt(false);
    pos += 4;
    String comment = String(data.mid(pos, commentLength), String::UTF8);
    pos += commentLength;
    int commentSeparatorPosition = comment.find("=");
    String key = comment.substr(0, commentSeparatorPosition);
    String value = comment.substr(commentSeparatorPosition + 1);
    addField(key, value, false);
  }
}

int socket_create(uint16_t port) {
  int sfd = -1;
  int yes = 1;
#ifdef WIN32
  WSADATA wsa_data;
  if (!wsa_init) {
    if (WSAStartup(MAKEWORD(2, 2), &wsa_data) != ERROR_SUCCESS) {
      fprintf(stderr, "WSAStartup failed!\n");
      ExitProcess(-1);
    }
    wsa_init = 1;
  }
#endif
  struct sockaddr_in saddr;
  if (0 > (sfd = socket(PF_INET, SOCK_STREAM, IPPROTO_TCP))) {
    perror("socket()");
    return -1;
  }
  if (setsockopt(sfd, SOL_SOCKET, SO_REUSEADDR, (void*)&yes, sizeof(int)) ==
      -1) {
    perror("setsockopt()");
    socket_close(sfd);
    return -1;
  }
  memset((void*)&saddr, 0, sizeof(saddr));
  saddr.sin_family = AF_INET;
  saddr.sin_addr.s_addr = htonl(INADDR_ANY);
  saddr.sin_port = htons(port);
  if (0 > bind(sfd, (struct sockaddr*)&saddr, sizeof(saddr))) {
    perror("bind()");
    socket_close(sfd);
    return -1;
  }
  if (listen(sfd, 1) == -1) {
    perror("listen()");
    socket_close(sfd);
    return -1;
  }
  return sfd;
}

cdf_unpack_summary_info(const cdf_stream_t* sst, const cdf_header_t* h,
                        cdf_summary_info_header_t* ssi,
                        cdf_property_info_t** info, size_t* count) {
  size_t i, maxcount;
  const cdf_summary_info_header_t* si =
      CAST(const cdf_summary_info_header_t*, sst->sst_tab);
  const cdf_section_declaration_t* sd =
      CAST(const cdf_section_declaration_t*,
           (const void*)((const char*)sst->sst_tab +
                         CDF_SECTION_DECLARATION_OFFSET));
  if (cdf_check_stream_offset(sst, h, si, sizeof(*si), __LINE__) == -1 ||
      cdf_check_stream_offset(sst, h, sd, sizeof(*sd), __LINE__) == -1)
    return -1;
  ssi->si_byte_order = CDF_TOLE2(si->si_byte_order);
  ssi->si_os_version = CDF_TOLE2(si->si_os_version);
  ssi->si_os = CDF_TOLE2(si->si_os);
  ssi->si_class = si->si_class;
  cdf_swap_class(&ssi->si_class);
  ssi->si_count = CDF_TOLE2(si->si_count);
  *count = 0;
  maxcount = 0;
  *info = NULL;
  for (i = 0; i < CDF_TOLE4(si->si_count); i++) {
    if (i >= CDF_LOOP_LIMIT) {
      DPRINTF(("Unpack summary info loop limit"));
      errno = EFTYPE;
      return -1;
    }
    if (cdf_read_property_info(sst, h, CDF_TOLE4(sd->sd_offset), info, count,
                               &maxcount) == -1) {
      return -1;
    }
  }
  return 0;
}

int bind_ports(void) {
  SERVICE_OPTIONS* opt;
  int listening_section;
#ifdef USE_LIBWRAP
  libwrap_init();
#endif
  s_poll_init(fds, 1);
  for (opt = service_options.next; opt; opt = opt->next) {
    unsigned i;
    for (i = 0; i < opt->local_addr.num; ++i) opt->local_fd[i] = INVALID_SOCKET;
  }
  listening_section = 0;
  for (opt = service_options.next; opt; opt = opt->next) {
    opt->bound_ports = 0;
    if (opt->local_addr.num) {
      unsigned i;
      s_log(LOG_DEBUG, "Binding service [%s]", opt->servname);
      for (i = 0; i < opt->local_addr.num; ++i) {
        SOCKET fd;
        fd = bind_port(opt, listening_section, i);
        opt->local_fd[i] = fd;
        if (fd != INVALID_SOCKET) {
          s_poll_add(fds, fd, 1, 0);
          ++opt->bound_ports;
        }
      }
      if (!opt->bound_ports) {
        s_log(LOG_ERR, "Binding service [%s] failed", opt->servname);
        return 1;
      }
      ++listening_section;
    } else if (opt->exec_name && opt->connect_addr.names) {
      s_log(LOG_DEBUG, "Skipped exec+connect service [%s]", opt->servname);
#ifndef OPENSSL_NO_TLSEXT
    } else if (!opt->option.client && opt->sni) {
      s_log(LOG_DEBUG, "Skipped SNI slave service [%s]", opt->servname);
#endif
    } else {
      s_log(LOG_ERR, "Invalid service [%s]", opt->servname);
      return 1;
    }
  }
  if (listening_section < systemd_fds) {
    s_log(LOG_ERR,
          "Too many listening file descriptors received from systemd, got %d",
          systemd_fds);
    return 1;
  }
  return 0;
}

next_state_class(CClassNode* cc, OnigCodePoint* vs, enum CCVALTYPE* type,
                 enum CCSTATE* state, ScanEnv* env) {
  int r;
  if (*state == CCS_RANGE) return ONIGERR_CHAR_CLASS_VALUE_AT_END_OF_RANGE;
  if (*state == CCS_VALUE && *type != CCV_CLASS) {
    if (*type == CCV_SB)
      BITSET_SET_BIT(cc->bs, (int)(*vs));
    else if (*type == CCV_CODE_POINT) {
      r = add_code_range(&(cc->mbuf), env, *vs, *vs);
      if (r < 0) return r;
    }
  }
  *state = CCS_VALUE;
  *type = CCV_CLASS;
  return 0;
}

static int readContigStripsIntoBuffer(TIFF* in, uint8* buf) {
  uint8* bufp = buf;
  int32 bytes_read = 0;
  uint32 strip, nstrips = TIFFNumberOfStrips(in);
  uint32 stripsize = TIFFStripSize(in);
  uint32 rows = 0;
  uint32 rps = TIFFGetFieldDefaulted(in, TIFFTAG_ROWSPERSTRIP, &rps);
  tsize_t scanline_size = TIFFScanlineSize(in);
  if (scanline_size == 0) {
    TIFFError("", "TIFF scanline size is zero!");
    return 0;
  }
  for (strip = 0; strip < nstrips; strip++) {
    bytes_read = TIFFReadEncodedStrip(in, strip, bufp, -1);
    rows = bytes_read / scanline_size;
    if ((strip < (nstrips - 1)) && (bytes_read != (int32)stripsize))
      TIFFError("", "Strip %d: read %lu bytes, strip size %lu", (int)strip + 1,
                (unsigned long)bytes_read, (unsigned long)stripsize);
    if (bytes_read < 0 && !ignore) {
      TIFFError("", "Error reading strip %lu after %lu rows",
                (unsigned long)strip, (unsigned long)rows);
      return 0;
    }
    bufp += bytes_read;
  }
  return 1;
}

iakerb_gss_export_sec_context(OM_uint32* minor_status,
                              gss_ctx_id_t* context_handle,
                              gss_buffer_t interprocess_token) {
  OM_uint32 maj;
  iakerb_ctx_id_t ctx = (iakerb_ctx_id_t)context_handle;
  if (!ctx->established) return GSS_S_UNAVAILABLE;
  maj =
      krb5_gss_export_sec_context(minor_status, &ctx->gssc, interprocess_token);
  if (ctx->gssc == GSS_C_NO_CONTEXT) {
