static ssize_t acpi_table_aml_write(struct config_item* cfg, const void* data,
                                    size_t size) {
  const struct acpi_table_header* header = data;
  struct acpi_table* table;
  int ret;
  table = container_of(cfg, struct acpi_table, cfg);
  if (table->header) {
    pr_err("table already loaded\n");
    return -EBUSY;
  }
  if (header->length != size) {
    pr_err("invalid table length\n");
    return -EINVAL;
  }
  if (memcmp(header->signature, ACPI_SIG_SSDT, 4)) {
    pr_err("invalid table signature\n");
    return -EINVAL;
  }
  table = container_of(cfg, struct acpi_table, cfg);
  table->header = kmemdup(header, header->length, GFP_KERNEL);
  if (!table->header) return -ENOMEM;
  ret = acpi_load_table(table->header, &table->index);
  if (ret) {
    kfree(table->header);
    table->header = NULL;
  }
  return ret;
}

Status DoCompute(OpKernelContext* ctx) {
  tensorflow::ResourceTagger tag(kTFDataResourceTag,
                                 ctx->op_kernel().type_string());
  tstring filename;
  TF_RETURN_IF_ERROR(ParseScalarArgument<tstring>(ctx, "filename", &filename));
  tstring compression_type;
  TF_RETURN_IF_ERROR(
      ParseScalarArgument<tstring>(ctx, "compression_type", &compression_type));
  std::unique_ptr<WritableFile> file;
  TF_RETURN_IF_ERROR(ctx->env()->NewWritableFile(filename, &file));
  auto writer = absl::make_unique<io::RecordWriter>(
      file.get(),
      io::RecordWriterOptions::CreateRecordWriterOptions(compression_type));
  DatasetBase* dataset;
  TF_RETURN_IF_ERROR(GetDatasetFromVariantTensor(ctx->input(0), &dataset));
  IteratorContext::Params params(ctx);
  FunctionHandleCache function_handle_cache(params.flr);
  params.function_handle_cache = &function_handle_cache;
  ResourceMgr resource_mgr;
  params.resource_mgr = &resource_mgr;
  CancellationManager cancellation_manager(ctx->cancellation_manager());
  params.cancellation_manager = &cancellation_manager;
  IteratorContext iter_ctx(std::move(params));
  DatasetBase* finalized_dataset;
  TF_RETURN_IF_ERROR(FinalizeDataset(ctx, dataset, &finalized_dataset));
  std::unique_ptr<IteratorBase> iterator;
  TF_RETURN_IF_ERROR(finalized_dataset->MakeIterator(
      &iter_ctx, nullptr, "ToTFRecordOpIterator", &iterator));
  std::vector<Tensor> components;
  components.reserve(finalized_dataset->output_dtypes().size());
  bool end_of_sequence;
  do {
    TF_RETURN_IF_ERROR(
        iterator->GetNext(&iter_ctx, &components, &end_of_sequence));
    if (!end_of_sequence) {
      TF_RETURN_IF_ERROR(
          writer->WriteRecord(components[0].scalar<tstring>()()));
    }
    components.clear();
  } while (!end_of_sequence);
  return Status::OK();
}

void gf_isom_check_position(GF_Box* s, GF_Box* child, u32* pos) {
  if (!s || !s->child_boxes || !child || !pos) return;
  if (s->internal_flags & GF_ISOM_ORDER_FREEZE) return;
  s32 cur_pos = gf_list_find(s->child_boxes, child);
  if (cur_pos < 0) return;
  if (cur_pos != (s32)*pos) {
    gf_list_del_item(s->child_boxes, child);
    gf_list_insert(s->child_boxes, child, *pos);
  }
  (*pos)++;

bool SQClass::NewSlot(SQSharedState* ss, const SQObjectPtr& key,
                      const SQObjectPtr& val, bool bstatic) {
  SQObjectPtr temp;
  bool belongs_to_static_table =
      sq_type(val) == OT_CLOSURE || sq_type(val) == OT_NATIVECLOSURE || bstatic;
  if (_locked && !belongs_to_static_table) return false;
  if (_members->Get(key, temp) && _isfield(temp)) {
    _defaultvalues[_member_idx(temp)].val = val;
    return true;
  }
  if (belongs_to_static_table) {
    SQInteger mmidx;
    if ((sq_type(val) == OT_CLOSURE || sq_type(val) == OT_NATIVECLOSURE) &&
        (mmidx = ss->GetMetaMethodIdxByName(key)) != -1) {
      _metamethods[mmidx] = val;
    } else {
      SQObjectPtr theval = val;
      if (_base && sq_type(val) == OT_CLOSURE) {
        theval = _closure(val)->Clone();
        _closure(theval)->_base = _base;
        __ObjAddRef(_base);
      }
      if (sq_type(temp) == OT_NULL) {
        bool isconstructor;
        SQVM::IsEqual(ss->_constructoridx, key, isconstructor);
        if (isconstructor) {
          _constructoridx = (SQInteger)_methods.size();
        }
        SQClassMember m;
        m.val = theval;
        _members->NewSlot(key, SQObjectPtr(_make_method_idx(_methods.size())));
        _methods.push_back(m);
      } else {
        _methods[_member_idx(temp)].val = theval;
      }
    }
    return true;
  }
  SQClassMember m;
  m.val = val;
  _members->NewSlot(key, SQObjectPtr(_make_field_idx(_defaultvalues.size())));
  _defaultvalues.push_back(m);
  return true;
}

pdf_t* pdf_new(const char* name) {
  const char* n;
  pdf_t* pdf;
  pdf = calloc(1, sizeof(pdf_t));
  if (name) {
    if ((n = strrchr(name, '/')))
      ++n;
    else
      n = name;
    pdf->name = malloc(strlen(n) + 1);
    strcpy(pdf->name, n);
  } else {
    pdf->name = malloc(strlen("Unknown") + 1);
    strcpy(pdf->name, "Unknown");
  }
  return pdf;
}

static void parse_content_range(URLContext* h, const char* p) {
  HTTPContext* s = h->priv_data;
  const char* slash;
  if (!strncmp(p, "bytes ", 6)) {
    p += 6;
    s->off = strtoll(p, NULL, 10);
    if ((slash = strchr(p, '/')) && strlen(slash) > 0)
      s->filesize = strtoll(slash + 1, NULL, 10);
  }
  if (s->seekable == -1 && (!s->is_akamai || s->filesize != 2147483647))
    h->is_streamed = 0;
}

