}

choose_windows(s) const char* s;
{
  register int i;
  for (i = 0; winchoices[i].procs; i++) {
    if ('+' == winchoices[i].procs->name[0]) continue;
    if ('-' == winchoices[i].procs->name[0]) continue;
    if (!strcmpi(s, winchoices[i].procs->name)) {
      windowprocs = *winchoices[i].procs;
      if (last_winchoice && last_winchoice->ini_routine)
        (*last_winchoice->ini_routine)(WININIT_UNDO);
      if (winchoices[i].ini_routine) (*winchoices[i].ini_routine)(WININIT);
      last_winchoice = &winchoices[i];
      return;
    }
  }
  if (!windowprocs.win_raw_print) windowprocs.win_raw_print = def_raw_print;
  if (!windowprocs.win_wait_synch) windowprocs.win_wait_synch = def_wait_synch;
  if (!winchoices[0].procs) {
    raw_printf("No window types?");
    nh_terminate(EXIT_FAILURE);
  }
  if (!winchoices[1].procs) {
    config_error_add("Window type %s not recognized.  The only choice is: %s",
                     s, winchoices[0].procs->name);
  } else {
    char buf[BUFSZ];
    boolean first = TRUE;
    buf[0] = '\0';
    for (i = 0; winchoices[i].procs; i++) {
      if ('+' == winchoices[i].procs->name[0]) continue;
      if ('-' == winchoices[i].procs->name[0]) continue;
      Sprintf(eos(buf), "%s%s", first ? "" : ", ", winchoices[i].procs->name);
      first = FALSE;
    }
    config_error_add("Window type %s not recognized.  Choices are:  %s", s,
                     buf);
  }
  if (windowprocs.win_raw_print == def_raw_print || WINDOWPORT("safe-startup"))
    nh_terminate(EXIT_SUCCESS);
}

_g_file_remove_directory(GFile* directory, GCancellable* cancellable,
                         GError** error) {
  GFileEnumerator* enumerator;
  GFileInfo* info;
  gboolean error_occurred = FALSE;
  if (directory == NULL) return TRUE;
  enumerator = g_file_enumerate_children(directory,
                                         G_FILE_ATTRIBUTE_STANDARD_NAME
                                         "," G_FILE_ATTRIBUTE_STANDARD_TYPE,
                                         0, cancellable, error);
  while (!error_occurred && (info = g_file_enumerator_next_file(
                                 enumerator, cancellable, error)) != NULL) {
    GFile* child;
    child = g_file_get_child(directory, g_file_info_get_name(info));
    switch (g_file_info_get_file_type(info)) {
      case G_FILE_TYPE_DIRECTORY:
        if (!_g_file_remove_directory(child, cancellable, error))
          error_occurred = TRUE;
        break;
      default:
        if (!g_file_delete(child, cancellable, error)) error_occurred = TRUE;
        break;
    }
    g_object_unref(child);
    g_object_unref(info);
  }
  if (!error_occurred && !g_file_delete(directory, cancellable, error))
    error_occurred = TRUE;
  g_object_unref(enumerator);
  return !error_occurred;
}

pktap_if_print(netdissect_options* ndo, const struct pcap_pkthdr* h,
               const u_char* p) {
  uint32_t dlt, hdrlen, rectype;
  u_int caplen = h->caplen;
  u_int length = h->len;
  if_printer printer;
  const pktap_header_t* hdr;
  if (caplen < sizeof(pktap_header_t) || length < sizeof(pktap_header_t)) {
    ND_PRINT((ndo, "[|pktap]"));
    return (0);
  }
  hdr = (const pktap_header_t*)p;
  dlt = EXTRACT_LE_32BITS(&hdr->pkt_dlt);
  hdrlen = EXTRACT_LE_32BITS(&hdr->pkt_len);
  if (hdrlen < sizeof(pktap_header_t)) {
    ND_PRINT((ndo, "[|pktap]"));
    return (0);
  }
  if (caplen < hdrlen || length < hdrlen) {
    ND_PRINT((ndo, "[|pktap]"));
    return (hdrlen);
  }
  if (ndo->ndo_eflag) pktap_header_print(ndo, p, length);
  length -= hdrlen;
  caplen -= hdrlen;
  p += hdrlen;
  rectype = EXTRACT_LE_32BITS(&hdr->pkt_rectype);
  switch (rectype) {
    case PKT_REC_NONE:
      ND_PRINT((ndo, "no data"));
      break;
    case PKT_REC_PACKET:
      if ((printer = lookup_printer(dlt)) != NULL) {
        hdrlen += printer(ndo, h, p);
      } else {
        if (!ndo->ndo_eflag)
          pktap_header_print(ndo, (const u_char*)hdr, length + hdrlen);
        if (!ndo->ndo_suppress_default_print) ND_DEFAULTPRINT(p, caplen);
      }
      break;
  }
  return (hdrlen);
}

