static MemTxResult address_space_write_continue(AddressSpace* as, hwaddr addr,
                                                MemTxAttrs attrs,
                                                const uint8_t* buf, int len,
                                                hwaddr addr1, hwaddr l,
                                                MemoryRegion* mr) {
  uint8_t* ptr;
  uint64_t val;
  MemTxResult result = MEMTX_OK;
  bool release_lock = false;
  for (;;) {
    if (!memory_access_is_direct(mr, true)) {
      release_lock |= prepare_mmio_access(mr);
      l = memory_access_size(mr, l, addr1);
      switch (l) {
        case 8:
          val = ldq_p(buf);
          result |= memory_region_dispatch_write(mr, addr1, val, 8, attrs);
          break;
        case 4:
          val = (uint32_t)ldl_p(buf);
          result |= memory_region_dispatch_write(mr, addr1, val, 4, attrs);
          break;
        case 2:
          val = lduw_p(buf);
          result |= memory_region_dispatch_write(mr, addr1, val, 2, attrs);
          break;
        case 1:
          val = ldub_p(buf);
          result |= memory_region_dispatch_write(mr, addr1, val, 1, attrs);
          break;
        default:
          abort();
      }
    } else {
      ptr = qemu_map_ram_ptr(mr->ram_block, addr1);
      memcpy(ptr, buf, l);
      invalidate_and_set_dirty(mr, addr1, l);
    }
    if (release_lock) {
      qemu_mutex_unlock_iothread();
      release_lock = false;
    }
    len -= l;
    buf += l;
    addr += l;
    if (!len) {
      break;
    }
    l = len;
    mr = address_space_translate(as, addr, &addr1, &l, true);
  }
  return result;
}

void PdfTranslator::setSource(const std::string& source) {
  int dbg(0);
  std::cerr << ++dbg << std::endl;
  if (checkIsPDF(source)) {
    multiSource.push_back(source);
  } else {
    ifstream in(source.c_str(), ifstream::in);
    if (!in.good())
      throw runtime_error("setSource() failed to open input file");
    char* filenameBuffer = new char[1000];
    do {
      in.getline(filenameBuffer, 1000);
      std::string ts(filenameBuffer, in.gcount());
      if (ts.size() > 4) {
        multiSource.push_back(ts);
        std::cerr << "Appending " << ts << " to source" << endl;
      }
    } while (!in.eof());
    in.close();
    delete[] filenameBuffer;
  }
  std::cerr << ++dbg << std::endl;
  for (std::vector<std::string>::const_iterator ms = multiSource.begin();
       ms != multiSource.end(); ++ms) {
    if (ms == multiSource.begin()) {
      try {
        sourceDoc = new PdfMemDocument((*ms).c_str());
      } catch (PdfError& e) {
        std::cerr << "Unable to create Document: "
                  << PdfError::ErrorMessage(e.GetError()) << std::endl;
        return;
      }
    } else {
      PdfMemDocument mdoc((*ms).c_str());
      sourceDoc->InsertPages(mdoc, 0, mdoc.GetPageCount());
    }
  }
  pcount = sourceDoc->GetPageCount();
  if (pcount > 0) {
    PoDoFo::PdfRect rect(sourceDoc->GetPage(0)->GetMediaBox());
    sourceWidth = rect.GetWidth() - rect.GetLeft();
    sourceHeight = rect.GetHeight() - rect.GetBottom();
  }
}

auth_password(Authctxt* authctxt, const char* password) {
  struct passwd* pw = authctxt->pw;
  int result, ok = authctxt->valid;
#if defined(USE_SHADOW) && defined(HAS_SHADOW_EXPIRE)
  static int expire_checked = 0;
#endif
#ifndef HAVE_CYGWIN
  if (pw->pw_uid == 0 && options.permit_root_login != PERMIT_YES) ok = 0;
#endif
  if (*password == '\0' && options.permit_empty_passwd == 0) return 0;
#ifdef KRB5
  if (options.kerberos_authentication == 1) {
    int ret = auth_krb5_password(authctxt, password);
    if (ret == 1 || ret == 0) return ret && ok;
  }
#endif
#ifdef HAVE_CYGWIN
  {
    HANDLE hToken = cygwin_logon_user(pw, password);
    if (hToken == INVALID_HANDLE_VALUE) return 0;
    cygwin_set_impersonation_token(hToken);
    return ok;
  }
#endif
#ifdef USE_PAM
  if (options.use_pam) return (sshpam_auth_passwd(authctxt, password) && ok);
#endif
#if defined(USE_SHADOW) && defined(HAS_SHADOW_EXPIRE)
  if (!expire_checked) {
    expire_checked = 1;
    if (auth_shadow_pwexpired(authctxt)) authctxt->force_pwchange = 1;
  }
#endif
  result = sys_auth_passwd(authctxt, password);
  if (authctxt->force_pwchange) disable_forwarding();
  return (result && ok);
}

MONGO_EXPORT bson_type bson_iterator_next(bson_iterator* i) {
  int ds;
  if (i->first) {
    i->first = 0;
    return (bson_type)(*i->cur);
  }
  switch (bson_iterator_type(i)) {
    case BSON_EOO:
      return BSON_EOO;
    case BSON_UNDEFINED:
    case BSON_NULL:
      ds = 0;
      break;
    case BSON_BOOL:
      ds = 1;
      break;
    case BSON_INT:
      ds = 4;
      break;
    case BSON_LONG:
    case BSON_DOUBLE:
    case BSON_TIMESTAMP:
    case BSON_DATE:
      ds = 8;
      break;
    case BSON_OID:
      ds = 12;
      break;
    case BSON_STRING:
    case BSON_SYMBOL:
    case BSON_CODE:
      ds = 4 + bson_iterator_int_raw(i);
      break;
    case BSON_BINDATA:
      ds = 5 + bson_iterator_int_raw(i);
      break;
    case BSON_OBJECT:
    case BSON_ARRAY:
    case BSON_CODEWSCOPE:
      ds = bson_iterator_int_raw(i);
      break;
    case BSON_DBREF:
      ds = 4 + 12 + bson_iterator_int_raw(i);
      break;
    case BSON_REGEX: {
      const char* s = bson_iterator_value(i);
      const char* p = s;
      p += strlen(p) + 1;
      p += strlen(p) + 1;
      ds = p - s;
      break;
    }
    default: {
      char msg[] = "unknown type: 000000000000";
      bson_numstr(msg + 14, (unsigned)(i->cur[0]));
      bson_fatal_msg(0, msg);
      return 0;
    }
  }
  i->cur += 1 + strlen(i->cur + 1) + 1 + ds;
  return (bson_type)(*i->cur);
}

static int ebt_size_mwt(struct compat_ebt_entry_mwt* match32,
                        unsigned int size_left, enum compat_mwt type,
                        struct ebt_entries_buf_state* state, const void* base) {
  int growth = 0;
  char* buf;
  if (size_left == 0) return 0;
  buf = (char*)match32;
  while (size_left >= sizeof(*match32)) {
    struct ebt_entry_match* match_kern;
    int ret;
    match_kern = (struct ebt_entry_match*)state->buf_kern_start;
    if (match_kern) {
      char* tmp;
      tmp = state->buf_kern_start + state->buf_kern_offset;
      match_kern = (struct ebt_entry_match*)tmp;
    }
    ret = ebt_buf_add(state, buf, sizeof(*match32));
    if (ret < 0) return ret;
    size_left -= sizeof(*match32);
    ret = ebt_buf_add_pad(state, ebt_compat_entry_padsize());
    if (ret < 0) return ret;
    if (match32->match_size > size_left) return -EINVAL;
    size_left -= match32->match_size;
    ret = compat_mtw_from_user(match32, type, state, base);
    if (ret < 0) return ret;
    if (WARN_ON(ret < match32->match_size)) return -EINVAL;
    growth += ret - match32->match_size;
    growth += ebt_compat_entry_padsize();
    buf += sizeof(*match32);
    buf += match32->match_size;
    if (match_kern) match_kern->match_size = ret;
    WARN_ON(type == EBT_COMPAT_TARGET && size_left);
    match32 = (struct compat_ebt_entry_mwt*)buf;
  }
  return growth;
}

int ipmi_si_port_setup(struct si_sm_io* io) {
  unsigned int addr = io->addr_data;
  int idx;
  if (!addr) return -ENODEV;
  io->io_cleanup = port_cleanup;
  switch (io->regsize) {
    case 1:
      io->inputb = port_inb;
      io->outputb = port_outb;
      break;
    case 2:
      io->inputb = port_inw;
      io->outputb = port_outw;
      break;
    case 4:
      io->inputb = port_inl;
      io->outputb = port_outl;
      break;
    default:
      dev_warn(io->dev, "Invalid register size: %d\n", io->regsize);
      return -EINVAL;
  }
  for (idx = 0; idx < io->io_size; idx++) {
    if (request_region(addr + idx * io->regspacing, io->regsize, DEVICE_NAME) ==
        NULL) {
      while (idx--) release_region(addr + idx * io->regspacing, io->regsize);
      return -EIO;
    }
  }
  return 0;
}

