static int ReadHuffmanCode(int alphabet_size, VP8LDecoder* const dec,
                           int* const code_lengths, HuffmanCode* const table) {
  int ok = 0;
  int size = 0;
  VP8LBitReader* const br = &dec->br_;
  const int simple_code = VP8LReadBits(br, 1);
  memset(code_lengths, 0, alphabet_size * sizeof(*code_lengths));
  if (simple_code) {
    const int num_symbols = VP8LReadBits(br, 1) + 1;
    const int first_symbol_len_code = VP8LReadBits(br, 1);
    int symbol = VP8LReadBits(br, (first_symbol_len_code == 0) ? 1 : 8);
    code_lengths[symbol] = 1;
    if (num_symbols == 2) {
      symbol = VP8LReadBits(br, 8);
      code_lengths[symbol] = 1;
    }
    ok = 1;
  } else {
    int i;
    int code_length_code_lengths[NUM_CODE_LENGTH_CODES] = {0};
    const int num_codes = VP8LReadBits(br, 4) + 4;
    assert(num_codes <= NUM_CODE_LENGTH_CODES);
    for (i = 0; i < num_codes; ++i) {
      code_length_code_lengths[kCodeLengthCodeOrder[i]] = VP8LReadBits(br, 3);
    }
    ok = ReadHuffmanCodeLengths(dec, code_length_code_lengths, alphabet_size,
                                code_lengths);
  }
  ok = ok && !br->eos_;
  if (ok) {
    size = VP8LBuildHuffmanTable(table, HUFFMAN_TABLE_BITS, code_lengths,
                                 alphabet_size);
  }
  if (!ok || size == 0) {
    return VP8LSetError(dec, VP8_STATUS_BITSTREAM_ERROR);
  }
  return size;
}

get_chainname_rulenum(const struct ip6t_entry* s, const struct ip6t_entry* e,
                      const char* hookname, const char** chainname,
                      const char** comment, unsigned int* rulenum) {
  const struct xt_standard_target* t = (void*)ip6t_get_target_c(s);
  if (strcmp(t->target.u.kernel.target->name, XT_ERROR_TARGET) == 0) {
    *chainname = t->target.data;
    (*rulenum) = 0;
  } else if (s == e) {
    (*rulenum)++;
    if (s->target_offset == sizeof(struct ip6t_entry) &&
        strcmp(t->target.u.kernel.target->name, XT_STANDARD_TARGET) == 0 &&
        t->verdict < 0 && unconditional(&s->ipv6)) {
      *comment = *chainname == hookname ? comments[NF_IP6_TRACE_COMMENT_POLICY]
                                        : comments[NF_IP6_TRACE_COMMENT_RETURN];
    }
    return 1;
  } else
    (*rulenum)++;
  return 0;
}

static bool anal_fcn_data(RCore* core, const char* input) {
  RAnalFunction* fcn = r_anal_get_fcn_in(core->anal, core->offset, -1);
  ut32 fcn_size = r_anal_function_size_from_entry(fcn);
  if (fcn) {
    int i;
    bool gap = false;
    ut64 gap_addr = UT64_MAX;
    char* bitmap = calloc(1, fcn_size);
    if (bitmap) {
      RAnalBlock* b;
      RListIter* iter;
      r_list_foreach(fcn->bbs, iter, b) {
        int f = b->addr - fcn->addr;
        int t = R_MIN(f + b->size, fcn_size);
        if (f >= 0) {
          while (f < t) {
            bitmap[f++] = 1;
          }
        }
      }
    }
    for (i = 0; i < fcn_size; i++) {
      ut64 here = fcn->addr + i;
      if (bitmap && bitmap[i]) {
        if (gap) {
          r_cons_printf("Cd %d @ 0x%08" PFMT64x "\n", here - gap_addr,
                        gap_addr);
          gap = false;
        }
        gap_addr = UT64_MAX;
      } else {
        if (!gap) {
          gap = true;
          gap_addr = here;
        }
      }
    }
    if (gap) {
      r_cons_printf("Cd %d @ 0x%08" PFMT64x "\n",
                    fcn->addr + fcn_size - gap_addr, gap_addr);
    }
    free(bitmap);
    return true;
  }
  return false;
}

valid_length(uint8_t option, int dl, int* type) {
  const struct dhcp_opt* opt;
  ssize_t sz;
  if (dl == 0) return -1;
  for (opt = dhcp_opts; opt->option; opt++) {
    if (opt->option != option) continue;
    if (type) *type = opt->type;
    if (opt->type == 0 || opt->type & (STRING | RFC3442 | RFC5969)) return 0;
    sz = 0;
    if (opt->type & (UINT32 | IPV4)) sz = sizeof(uint32_t);
    if (opt->type & UINT16) sz = sizeof(uint16_t);
    if (opt->type & UINT8) sz = sizeof(uint8_t);
    if (opt->type & (IPV4 | ARRAY)) return dl % sz;
    return (dl == sz ? 0 : -1);
  }
  return 0;
}

static unsigned int help(struct sk_buff* skb, enum ip_conntrack_info ctinfo,
                         unsigned int protoff, unsigned int matchoff,
                         unsigned int matchlen,
                         struct nf_conntrack_expect* exp) {
  char buffer[sizeof("4294967296 65635")];
  u_int16_t port;
  unsigned int ret;
  exp->saved_proto.tcp.port = exp->tuple.dst.u.tcp.port;
  exp->dir = IP_CT_DIR_REPLY;
  exp->expectfn = nf_nat_follow_master;
  for (port = ntohs(exp->saved_proto.tcp.port); port != 0; port++) {
    int ret;
    exp->tuple.dst.u.tcp.port = htons(port);
    ret = nf_ct_expect_related(exp);
    if (ret == 0)
      break;
    else if (ret != -EBUSY) {
      port = 0;
      break;
    }
  }
  if (port == 0) {
    nf_ct_helper_log(skb, exp->master, "all ports in use");
    return NF_DROP;
  }
  ret = nf_nat_mangle_tcp_packet(skb, exp->master, ctinfo, protoff, matchoff,
                                 matchlen, buffer, strlen(buffer));
  if (ret != NF_ACCEPT) {
    nf_ct_helper_log(skb, exp->master, "cannot mangle packet");
    nf_ct_unexpect_related(exp);
  }
  return ret;
}

check_mime_type(const gchar* uri, GError** error) {
  GError* err = NULL;
  const gchar* mimeFromFile;
  mimeFromFile = ev_file_get_mime_type(uri, FALSE, &err);
  if (mimeFromFile) {
    const gchar* mimetypes[] = {"application/epub+zip",
                                "application/x-booki+zip", NULL};
    guint i;
    for (i = 0; i < g_strv_length(mimetypes); i++) {
      if (strcmp(mimeFromFile, mimetypes[i]) == 0) return TRUE;
    }
    if (strcmp(mimeFromFile, "application/zip") == 0) {
      mimeFromFile = ev_file_get_mime_type(uri, TRUE, &err);
      if (mimeFromFile) {
        for (i = 0; i < g_strv_length(mimetypes); i++) {
          if (g_strcmp0(mimeFromFile, mimetypes[i]) == 0) return TRUE;
        }
        g_set_error_literal(error, EV_DOCUMENT_ERROR, EV_DOCUMENT_ERROR_INVALID,
                            _("Not an ePub document"));
        return FALSE;
      }
    }
  }
  if (err)
    g_propagate_error(error, err);
  else
    g_set_error_literal(error, EV_DOCUMENT_ERROR, EV_DOCUMENT_ERROR_INVALID,
                        _("Unknown MIME Type"));
  return FALSE;
}

void Node::RunForwardTypeInference() {
  VLOG(4) << "Forward type inference: " << props_->node_def.DebugString();
  if (props_->fwd_type_fn == nullptr) {
    return;
  }
  std::vector<Node*> input_nodes(props_->input_types.size(), nullptr);
  std::vector<int> input_idx(props_->input_types.size(), 0);
  for (const auto& edge : in_edges_) {
    if (edge->IsControlEdge()) {
      continue;
    }
    DCHECK(edge->dst_input() < input_nodes.size()) << DebugString();
    int i = edge->dst_input();
    input_nodes.at(i) = edge->src();
    input_idx.at(i) = edge->src_output();
  }
  for (const auto* node : input_nodes) {
    if (node == nullptr) {
      ClearTypeInfo();
      return;
    }
  }
  static FullTypeDef* no_type = new FullTypeDef();
  std::vector<std::reference_wrapper<const FullTypeDef>> input_types;
  for (int i = 0; i < input_nodes.size(); i++) {
    const auto* node = input_nodes[i];
    if (node->def().has_experimental_type()) {
      const auto& node_t = node->def().experimental_type();
      if (node_t.type_id() != TFT_UNSET) {
        int ix = input_idx[i];
        DCHECK(ix < node_t.args_size())
            << "input " << i << " should have an output " << ix
            << " but instead only has " << node_t.args_size()
            << " outputs: " << node_t.DebugString();
        input_types.emplace_back(node_t.args(ix));
      } else {
        input_types.emplace_back(*no_type);
      }
    } else {
      ClearTypeInfo();
      return;
    }
  }
  const auto infer_type = props_->fwd_type_fn(input_types);
  const FullTypeDef infer_typedef = infer_type.ValueOrDie();
  if (infer_typedef.type_id() != TFT_UNSET) {
    MaybeCopyOnWrite();
    *(props_->node_def.mutable_experimental_type()) = infer_typedef;
  }
}

static int sh_op(RAnal* anal, RAnalOp* op, ut64 addr, const ut8* data,
                 int len) {
  ut8 op_MSB, op_LSB;
  int ret;
  if (!data) return 0;
  memset(op, '\0', sizeof(RAnalOp));
  op->addr = addr;
  op->type = R_ANAL_OP_TYPE_UNK;
  op->jump = op->fail = -1;
  op->ptr = op->val = -1;
  op->size = 2;
  op_MSB = anal->big_endian ? data[0] : data[1];
  op_LSB = anal->big_endian ? data[1] : data[0];
  ret = first_nibble_decode[(op_MSB >> 4) & 0x0F](anal, op,
                                                  (ut16)(op_MSB << 8 | op_LSB));
  return ret;
}

static MagickBooleanType ConcatenateImages(int argc, char** argv,
                                           ExceptionInfo* exception) {
  FILE *input, *output;
  int c;
  register ssize_t i;
  if (ExpandFilenames(&argc, &argv) == MagickFalse)
    ThrowFileException(exception, ResourceLimitError, "MemoryAllocationFailed",
                       GetExceptionMessage(errno));
  output = fopen_utf8(argv[argc - 1], "wb");
  if (output == (FILE*)NULL) {
    ThrowFileException(exception, FileOpenError, "UnableToOpenFile",
                       argv[argc - 1]);
    return (MagickFalse);
  }
  for (i = 2; i < (ssize_t)(argc - 1); i++) {
#if 0
    fprintf(stderr, "DEBUG: Concatenate Image: \"%s\"\n", argv[i]);
#endif
    input = fopen_utf8(argv[i], "rb");
    if (input == (FILE*)NULL) {
      ThrowFileException(exception, FileOpenError, "UnableToOpenFile", argv[i]);
      continue;
    }
    for (c = fgetc(input); c != EOF; c = fgetc(input))
      (void)fputc((char)c, output);
    (void)fclose(input);
    (void)remove_utf8(argv[i]);
  }
  (void)fclose(output);
  return (MagickTrue);
}

