NAN_METHOD(DetectCharacterEncoding) {
  Nan::HandleScope scope;
  v8::Local<v8::Object> inputBuffer = info[0]->ToObject();
  UCharsetDetector* charsetDetector;
  const UCharsetMatch* charsetMatch;
  UErrorCode errorCode = U_ZERO_ERROR;
  charsetDetector = ucsdet_open(&errorCode);
  if (U_FAILURE(errorCode)) {
    Nan::ThrowError("Failed to open ICU charset detector.");
    return;
  }
  ucsdet_setText(charsetDetector, node::Buffer::Data(inputBuffer),
                 node::Buffer::Length(inputBuffer), &errorCode);
  if (U_FAILURE(errorCode)) {
    Nan::ThrowError("Failed to set ICU charset detector’s text.");
    ucsdet_close(charsetDetector);
    return;
  }
  charsetMatch = ucsdet_detect(charsetDetector, &errorCode);
  if (U_FAILURE(errorCode)) {
    Nan::ThrowError("Failed to detect charset.");
    ucsdet_close(charsetDetector);
    return;
  }
  const char* charsetName = ucsdet_getName(charsetMatch, &errorCode);
  if (U_FAILURE(errorCode)) {
    Nan::ThrowError("Failed to get name from charset match.");
    ucsdet_close(charsetDetector);
    return;
  }
  int32_t confidence = ucsdet_getConfidence(charsetMatch, &errorCode);
  if (U_FAILURE(errorCode)) {
    Nan::ThrowError("Failed to get confidence from charset match.");
    ucsdet_close(charsetDetector);
    return;
  }
  v8::Local<v8::Object> obj = Nan::New<v8::Object>();
  obj->Set(Nan::New<v8::String>("encoding").ToLocalChecked(),
           Nan::New<v8::String>(charsetName).ToLocalChecked());
  obj->Set(Nan::New<v8::String>("confidence").ToLocalChecked(),
           Nan::New<v8::Number>(confidence));
  info.GetReturnValue().Set(obj);
  ucsdet_close(charsetDetector);
}

void ApplyBlockElementCommand::formatSelection(
    const VisiblePosition& startOfSelection,
    const VisiblePosition& endOfSelection) {
  Position start = startOfSelection.deepEquivalent().downstream();
  if (isAtUnsplittableElement(start)) {
    RefPtr<Element> blockquote = createBlockElement();
    insertNodeAt(blockquote, start);
    RefPtr<Element> placeholder = createBreakElement(document());
    appendNode(placeholder, blockquote);
    setEndingSelection(VisibleSelection(positionBeforeNode(placeholder.get()),
                                        DOWNSTREAM,
                                        endingSelection().isDirectional()));
    return;
  }
  RefPtr<Element> blockquoteForNextIndent;
  VisiblePosition endOfCurrentParagraph = endOfParagraph(startOfSelection);
  VisiblePosition endAfterSelection =
      endOfParagraph(endOfParagraph(endOfSelection).next());
  m_endOfLastParagraph = endOfParagraph(endOfSelection).deepEquivalent();
  bool atEnd = false;
  Position end;
  while (endOfCurrentParagraph != endAfterSelection && !atEnd) {
    if (endOfCurrentParagraph.deepEquivalent() == m_endOfLastParagraph)
      atEnd = true;
    rangeForParagraphSplittingTextNodesIfNeeded(endOfCurrentParagraph, start,
                                                end);
    endOfCurrentParagraph = end;
    Position afterEnd = end.next();
    Node* enclosingCell = enclosingNodeOfType(start, &isTableCell);
    VisiblePosition endOfNextParagraph =
        endOfNextParagrahSplittingTextNodesIfNeeded(endOfCurrentParagraph,
                                                    start, end);
    formatRange(start, end, m_endOfLastParagraph, blockquoteForNextIndent);
    if (enclosingCell &&
        enclosingCell != enclosingNodeOfType(
                             endOfNextParagraph.deepEquivalent(), &isTableCell))
      blockquoteForNextIndent = 0;
    if (endAfterSelection.isNotNull() &&
        !endAfterSelection.deepEquivalent().inDocument())
      break;
    if (endOfNextParagraph.isNotNull() &&
        !endOfNextParagraph.deepEquivalent().inDocument()) {
      ASSERT_NOT_REACHED();
      return;
    }
    endOfCurrentParagraph = endOfNextParagraph;
  }
}

static void io_async_task_func(struct callback_head* cb) {
  struct io_kiocb* req = container_of(cb, struct io_kiocb, task_work);
  struct async_poll* apoll = req->apoll;
  struct io_ring_ctx* ctx = req->ctx;
  trace_io_uring_task_run(req->ctx, req->opcode, req->user_data);
  if (io_poll_rewait(req, &apoll->poll)) {
    spin_unlock_irq(&ctx->completion_lock);
    return;
  }
  if (hash_hashed(&req->hash_node)) hash_del(&req->hash_node);
  io_poll_remove_double(req, apoll->double_poll);
  spin_unlock_irq(&ctx->completion_lock);
  if (!READ_ONCE(apoll->poll.canceled))
    __io_req_task_submit(req);
  else
    __io_req_task_cancel(req, -ECANCELED);
  kfree(apoll->double_poll);
  kfree(apoll);
}

ds_fgetstr(FILE* f, dynamic_string* s, char eos) {
  int insize;
  int strsize;
  int next_ch;
  insize = 0;
  strsize = s->ds_length;
  next_ch = getc(f);
  while (next_ch != eos && next_ch != EOF) {
    if (insize >= strsize - 1) {
      ds_resize(s, strsize * 2 + 2);
      strsize = s->ds_length;
    }
    s->ds_string[insize++] = next_ch;
    next_ch = getc(f);
  }
  s->ds_string[insize++] = '\0';
  if (insize == 1 && next_ch == EOF)
    return NULL;
  else
    return s->ds_string;
}

static inline void add_sdb_addrline(Sdb* s, ut64 addr, const char* file,
                                    ut64 line, int mode, PrintfCallback print) {
  const char* p;
  char* fileline;
  char offset[SDB_NUM_BUFSZ];
  char* offset_ptr;
  if (!s || !file) {
    return;
  }
  p = r_str_rchr(file, NULL, '/');
  if (p) {
    p++;
  } else {
    p = file;
  }
  switch (mode) {
    case 1:
    case 'r':
    case '*':
      print("CL %s:%d 0x%08" PFMT64x "\n", p, (int)line, addr);
      break;
  }
#if 0
	if (r_file_exists (file)) {
		p = file;
	}
#else
  p = file;
#endif
  fileline = r_str_newf("%s|%" PFMT64d, p, line);
  offset_ptr = sdb_itoa(addr, 16, offset, sizeof(offset));
  sdb_add(s, offset_ptr, fileline, 0);
  sdb_add(s, fileline, offset_ptr, 0);
  free(fileline);
}

static void cmd_parse_lsub(struct ImapData* idata, char* s) {
  char buf[STRING];
  char errstr[STRING];
  struct Buffer err, token;
  struct Url url;
  struct ImapList list;
  if (idata->cmddata && idata->cmdtype == IMAP_CT_LIST) {
    cmd_parse_list(idata, s);
    return;
  }
  if (!ImapCheckSubscribed) return;
  idata->cmdtype = IMAP_CT_LIST;
  idata->cmddata = &list;
  cmd_parse_list(idata, s);
  idata->cmddata = NULL;
  if (!list.name || list.noselect) return;
  mutt_debug(3, "Subscribing to %s\n", list.name);
  mutt_str_strfcpy(buf, "mailboxes \"", sizeof(buf));
  mutt_account_tourl(&idata->conn->account, &url);
  imap_quote_string(errstr, sizeof(errstr), list.name);
  url.path = errstr + 1;
  url.path[strlen(url.path) - 1] = '\0';
  if (mutt_str_strcmp(url.user, ImapUser) == 0) url.user = NULL;
  url_tostring(&url, buf + 11, sizeof(buf) - 11, 0);
  mutt_str_strcat(buf, sizeof(buf), "\"");
  mutt_buffer_init(&token);
  mutt_buffer_init(&err);
  err.data = errstr;
  err.dsize = sizeof(errstr);
  if (mutt_parse_rc_line(buf, &token, &err))
    mutt_debug(1, "Error adding subscribed mailbox: %s\n", errstr);
  FREE(&token.data);
}

PGTYPESinterval_from_asc(char* str, char** endptr) {
  interval* result = NULL;
  fsec_t fsec;
  struct tm tt, *tm = &tt;
  int dtype;
  int nf;
  char* field[MAXDATEFIELDS];
  int ftype[MAXDATEFIELDS];
  char lowstr[MAXDATELEN + MAXDATEFIELDS];
  char* realptr;
  char** ptr = (endptr != NULL) ? endptr : &realptr;
  tm->tm_year = 0;
  tm->tm_mon = 0;
  tm->tm_mday = 0;
  tm->tm_hour = 0;
  tm->tm_min = 0;
  tm->tm_sec = 0;
  fsec = 0;
  if (strlen(str) >= sizeof(lowstr)) {
    errno = PGTYPES_INTVL_BAD_INTERVAL;
    return NULL;
  }
  if (ParseDateTime(str, lowstr, field, ftype, &nf, ptr) != 0 ||
      (DecodeInterval(field, ftype, nf, &dtype, tm, &fsec) != 0 &&
       DecodeISO8601Interval(str, &dtype, tm, &fsec) != 0)) {
    errno = PGTYPES_INTVL_BAD_INTERVAL;
    return NULL;
  }
  result = (interval*)pgtypes_alloc(sizeof(interval));
  if (!result) return NULL;
  if (dtype != DTK_DELTA) {
    errno = PGTYPES_INTVL_BAD_INTERVAL;
    free(result);
    return NULL;
  }
  if (tm2interval(tm, fsec, result) != 0) {
    errno = PGTYPES_INTVL_BAD_INTERVAL;
    free(result);
    return NULL;
  }
  errno = 0;
  return result;
}

