}

build_ycc_rgb_table(j_decompress_ptr cinfo) {
  my_upsample_ptr upsample = (my_upsample_ptr)cinfo->upsample;
  int i;
  JLONG x;
  SHIFT_TEMPS
  upsample->Cr_r_tab = (int*)(*cinfo->mem->alloc_small)(
      (j_common_ptr)cinfo, JPOOL_IMAGE, (MAXJSAMPLE + 1) * sizeof(int));
  upsample->Cb_b_tab = (int*)(*cinfo->mem->alloc_small)(
      (j_common_ptr)cinfo, JPOOL_IMAGE, (MAXJSAMPLE + 1) * sizeof(int));
  upsample->Cr_g_tab = (JLONG*)(*cinfo->mem->alloc_small)(
      (j_common_ptr)cinfo, JPOOL_IMAGE, (MAXJSAMPLE + 1) * sizeof(JLONG));
  upsample->Cb_g_tab = (JLONG*)(*cinfo->mem->alloc_small)(
      (j_common_ptr)cinfo, JPOOL_IMAGE, (MAXJSAMPLE + 1) * sizeof(JLONG));
  for (i = 0, x = -CENTERJSAMPLE; i <= MAXJSAMPLE; i++, x++) {
    upsample->Cr_r_tab[i] =
        (int)RIGHT_SHIFT(FIX(1.40200) * x + ONE_HALF, SCALEBITS);
    upsample->Cb_b_tab[i] =
        (int)RIGHT_SHIFT(FIX(1.77200) * x + ONE_HALF, SCALEBITS);
    upsample->Cr_g_tab[i] = (-FIX(0.71414)) * x;
    upsample->Cb_g_tab[i] = (-FIX(0.34414)) * x + ONE_HALF;
  }
}

void Magick::Image::read(MagickCore::Image* image,
                         MagickCore::ExceptionInfo* exceptionInfo) {
  if (image != (MagickCore::Image*)NULL &&
      image->next != (MagickCore::Image*)NULL) {
    MagickCore::Image* next;
    next = image->next;
    image->next = (MagickCore::Image*)NULL;
    next->previous = (MagickCore::Image*)NULL;
    DestroyImageList(next);
  }
  replaceImage(image);
  if (exceptionInfo->severity == MagickCore::UndefinedException &&
      image == (MagickCore::Image*)NULL) {
    (void)MagickCore::DestroyExceptionInfo(exceptionInfo);
    if (!quiet())
      throwExceptionExplicit(MagickCore::ImageWarning, "No image was loaded.");
  }
  ThrowImageException;
}

gen_values(codegen_scope* s, node* t, int val, int limit) {
  int n = 0;
  int first = 1;
  int slimit = GEN_VAL_STACK_MAX;
  if (limit == 0) limit = GEN_LIT_ARY_MAX;
  if (cursp() >= slimit) slimit = INT16_MAX;
  if (!val) {
    while (t) {
      codegen(s, t->car, NOVAL);
      n++;
      t = t->cdr;
    }
    return n;
  }
  while (t) {
    int is_splat = nint(t->car->car) == NODE_SPLAT;
    if (is_splat || n > limit || cursp() >= slimit) {
      pop_n(n);
      if (first) {
        if (n == 0) {
          genop_1(s, OP_LOADNIL, cursp());
        } else {
          genop_2(s, OP_ARRAY, cursp(), n);
        }
        push();
        first = 0;
        limit = GEN_LIT_ARY_MAX;
      } else if (n > 0) {
        pop();
        genop_2(s, OP_ARYPUSH, cursp(), n);
        push();
      }
      n = 0;
    }
    codegen(s, t->car, val);
    if (is_splat) {
      pop();
      pop();
      genop_1(s, OP_ARYCAT, cursp());
      push();
    } else {
      n++;
    }
    t = t->cdr;
  }
  if (!first) {
    pop();
    if (n > 0) {
      pop_n(n);
      genop_2(s, OP_ARYPUSH, cursp(), n);
    }
    return -1;
  }
  return n;
}

GC_INNER void* GC_generic_malloc_ignore_off_page(size_t lb, int k) {
  void* result;
  size_t lg;
  size_t lb_rounded;
  word n_blocks;
  GC_bool init;
  DCL_LOCK_STATE;
  if (SMALL_OBJ(lb)) return (GC_generic_malloc((word)lb, k));
  lg = ROUNDED_UP_GRANULES(lb);
  lb_rounded = GRANULES_TO_BYTES(lg);
  n_blocks = OBJ_SZ_TO_BLOCKS(lb_rounded);
  init = GC_obj_kinds[k].ok_init;
  if (EXPECT(GC_have_errors, FALSE)) GC_print_all_errors();
  GC_INVOKE_FINALIZERS();
  LOCK();
  result = (ptr_t)GC_alloc_large(ADD_SLOP(lb), k, IGNORE_OFF_PAGE);
  if (0 != result) {
    if (GC_debugging_started) {
      BZERO(result, n_blocks * HBLKSIZE);
    } else {
#ifdef THREADS
      ((word*)result)[0] = 0;
      ((word*)result)[1] = 0;
      ((word*)result)[GRANULES_TO_WORDS(lg) - 1] = 0;
      ((word*)result)[GRANULES_TO_WORDS(lg) - 2] = 0;
#endif
    }
  }
  GC_bytes_allocd += lb_rounded;
  if (0 == result) {
    GC_oom_func oom_fn = GC_oom_fn;
    UNLOCK();
    return ((*oom_fn)(lb));
  } else {
    UNLOCK();
    if (init && !GC_debugging_started) {
      BZERO(result, n_blocks * HBLKSIZE);
    }
    return (result);
  }
}

static unsigned char* AcquireCompactPixels(const Image* image,
                                           ExceptionInfo* exception) {
  size_t packet_size;
  unsigned char* compact_pixels;
  packet_size = image->depth > 8UL ? 2UL : 1UL;
  compact_pixels = (unsigned char*)AcquireQuantumMemory(
      (9 * image->columns) + 1, packet_size * sizeof(*compact_pixels));
  if (compact_pixels == (unsigned char*)NULL) {
    (void)ThrowMagickException(exception, GetMagickModule(), ResourceLimitError,
                               "MemoryAllocationFailed", "`%s'",
                               image->filename);
  }
  return (compact_pixels);
}

