static int kvm_ioctl_create_device(struct kvm* kvm,
                                   struct kvm_create_device* cd) {
  struct kvm_device_ops* ops = NULL;
  struct kvm_device* dev;
  bool test = cd->flags & KVM_CREATE_DEVICE_TEST;
  int ret;
  if (cd->type >= ARRAY_SIZE(kvm_device_ops_table)) return -ENODEV;
  ops = kvm_device_ops_table[cd->type];
  if (ops == NULL) return -ENODEV;
  if (test) return 0;
  dev = kzalloc(sizeof(*dev), GFP_KERNEL);
  if (!dev) return -ENOMEM;
  dev->ops = ops;
  dev->kvm = kvm;
  mutex_lock(&kvm->lock);
  ret = ops->create(dev, cd->type);
  if (ret < 0) {
    mutex_unlock(&kvm->lock);
    kfree(dev);
    return ret;
  }
  list_add(&dev->vm_node, &kvm->devices);
  mutex_unlock(&kvm->lock);
  if (ops->init) ops->init(dev);
  ret = anon_inode_getfd(ops->name, &kvm_device_fops, dev, O_RDWR | O_CLOEXEC);
  if (ret < 0) {
    mutex_lock(&kvm->lock);
    list_del(&dev->vm_node);
    mutex_unlock(&kvm->lock);
    ops->destroy(dev);
    return ret;
  }
  kvm_get_kvm(kvm);
  cd->fd = ret;
  return 0;
}

vm_fault_t gru_fault(struct vm_fault* vmf) {
  struct vm_area_struct* vma = vmf->vma;
  struct gru_thread_state* gts;
  unsigned long paddr, vaddr;
  unsigned long expires;
  vaddr = vmf->address;
  gru_dbg(grudev, "vma %p, vaddr 0x%lx (0x%lx)\n", vma, vaddr,
          GSEG_BASE(vaddr));
  STAT(nopfn);
  gts = gru_find_thread_state(vma, TSID(vaddr, vma));
  if (!gts) return VM_FAULT_SIGBUS;
again:
  mutex_lock(&gts->ts_ctxlock);
  preempt_disable();
  gru_check_context_placement(gts);
  if (!gts->ts_gru) {
    STAT(load_user_context);
    if (!gru_assign_gru_context(gts)) {
      preempt_enable();
      mutex_unlock(&gts->ts_ctxlock);
      set_current_state(TASK_INTERRUPTIBLE);
      schedule_timeout(GRU_ASSIGN_DELAY);
      expires = gts->ts_steal_jiffies + GRU_STEAL_DELAY;
      if (time_before(expires, jiffies)) gru_steal_context(gts);
      goto again;
    }
    gru_load_context(gts);
    paddr = gseg_physical_address(gts->ts_gru, gts->ts_ctxnum);
    remap_pfn_range(vma, vaddr & ~(GRU_GSEG_PAGESIZE - 1), paddr >> PAGE_SHIFT,
                    GRU_GSEG_PAGESIZE, vma->vm_page_prot);
  }
  preempt_enable();
  mutex_unlock(&gts->ts_ctxlock);
  return VM_FAULT_NOPAGE;
}

tar_directory_for_file(GsfInfileTar* dir, const char* name, gboolean last) {
  const char* s = name;
  while (1) {
    const char* s0 = s;
    char* dirname;
    while (1) {
      if (*s == 0) {
        if (last && s != s0)
          break;
        else
          return dir;
      }
      if (*s == '/') break;
      s++;
    }
    dirname = g_strndup(s0, s - s0);
    while (*s == '/') s++;
    if (strcmp(dirname, ".") != 0) {
      GsfInput* subdir = gsf_infile_child_by_name(GSF_INFILE(dir), dirname);
      if (subdir) {
        g_object_unref(subdir);
        dir = GSF_INFILE_TAR(subdir);
      } else
        dir = tar_create_dir(dir, dirname);
    }
    g_free(dirname);
  }
}

struct crypto_alg* crypto_larval_lookup(const char* name, u32 type, u32 mask) {
  struct crypto_alg* alg;
  if (!name) return ERR_PTR(-ENOENT);
  mask &= ~(CRYPTO_ALG_LARVAL | CRYPTO_ALG_DEAD);
  type &= mask;
  alg = crypto_alg_lookup(name, type, mask);
  if (!alg) {
    request_module("%s", name);
    if (!((type ^ CRYPTO_ALG_NEED_FALLBACK) & mask & CRYPTO_ALG_NEED_FALLBACK))
      request_module("%s-all", name);
    alg = crypto_alg_lookup(name, type, mask);
  }
  if (alg) return crypto_is_larval(alg) ? crypto_larval_wait(alg) : alg;
  return crypto_larval_add(name, type, mask);
}

static int f2fs_set_data_page_dirty(struct page* page) {
  struct address_space* mapping = page->mapping;
  struct inode* inode = mapping->host;
  trace_f2fs_set_page_dirty(page, DATA);
  if (!PageUptodate(page)) SetPageUptodate(page);
  if (f2fs_is_atomic_file(inode) && !f2fs_is_commit_atomic_write(inode)) {
    if (!IS_ATOMIC_WRITTEN_PAGE(page)) {
      f2fs_register_inmem_page(inode, page);
      return 1;
    }
    return 0;
  }
  if (!PageDirty(page)) {
    __set_page_dirty_nobuffers(page);
    f2fs_update_dirty_page(inode, page);
    return 1;
  }
  return 0;
}

