static ssize_t stellaris_enet_receive(NetClientState* nc, const uint8_t* buf,
                                      size_t size) {
  stellaris_enet_state* s = qemu_get_nic_opaque(nc);
  int n;
  uint8_t* p;
  uint32_t crc;
  if ((s->rctl & SE_RCTL_RXEN) == 0) return -1;
  if (s->np >= 31) {
    return 0;
  }
  DPRINTF("Received packet len=%zu\n", size);
  n = s->next_packet + s->np;
  if (n >= 31) n -= 31;
  s->np++;
  s->rx[n].len = size + 6;
  p = s->rx[n].data;
  *(p++) = (size + 6);
  *(p++) = (size + 6) >> 8;
  memcpy(p, buf, size);
  p += size;
  crc = crc32(~0, buf, size);
  *(p++) = crc;
  *(p++) = crc >> 8;
  *(p++) = crc >> 16;
  *(p++) = crc >> 24;
  if ((size & 3) != 2) {
    memset(p, 0, (6 - size) & 3);
  }
  s->ris |= SE_INT_RX;
  stellaris_enet_update(s);
  return size;
}

table_regex_match(const char* string, const char* pattern) {
  regex_t preg;
  int cflags = REG_EXTENDED | REG_NOSUB;
  if (strncmp(pattern, "(?i)", 4) == 0) {
    cflags |= REG_ICASE;
    pattern += 4;
  }
  if (regcomp(&preg, pattern, cflags) != 0) return (0);
  if (regexec(&preg, string, 0, NULL, 0) != 0) return (0);
  return (1);
}

