}

purgekeys_2_svc(purgekeys_arg* arg, struct svc_req* rqstp) {
  static generic_ret ret;
  char *prime_arg, *funcname;
  gss_buffer_desc client_name, service_name;
  OM_uint32 minor_stat;
  kadm5_server_handle_t handle;
  const char* errmsg = NULL;
  xdr_free(xdr_generic_ret, &ret);
  if ((ret.code = new_server_handle(arg->api_version, rqstp, &handle)))
    goto exit_func;
  if ((ret.code = check_handle((void*)handle))) goto exit_func;
  ret.api_version = handle->api_version;
  funcname = "kadm5_purgekeys";
  if (setup_gss_names(rqstp, &client_name, &service_name) < 0) {
    ret.code = KADM5_FAILURE;
    goto exit_func;
  }
  if (krb5_unparse_name(handle->context, arg->princ, &prime_arg)) {
    ret.code = KADM5_BAD_PRINCIPAL;
    goto exit_func;
  }
  if (!cmp_gss_krb5_name(handle, rqst2name(rqstp), arg->princ) &&
      (CHANGEPW_SERVICE(rqstp) ||
       !kadm5int_acl_check(handle->context, rqst2name(rqstp), ACL_MODIFY,
                           arg->princ, NULL))) {
    ret.code = KADM5_AUTH_MODIFY;
    log_unauth(funcname, prime_arg, &client_name, &service_name, rqstp);
  } else {
    ret.code = kadm5_purgekeys((void*)handle, arg->princ, arg->keepkvno);
    if (ret.code != 0)
      errmsg = krb5_get_error_message(handle->context, ret.code);
    log_done(funcname, prime_arg, errmsg, &client_name, &service_name, rqstp);
    if (errmsg != NULL) krb5_free_error_message(handle->context, errmsg);
  }
  free(prime_arg);
  gss_release_buffer(&minor_stat, &client_name);
  gss_release_buffer(&minor_stat, &service_name);
exit_func:
  free_server_handle(handle);
  return &ret;
}

decode_string(CBORDecoderObject* self, uint8_t subtype) {
  uint64_t length = 0;
  bool indefinite = true;
  PyObject* ret;
  char length_hex[17];
  if (decode_length(self, subtype, &length, &indefinite) == -1) return NULL;
  if (length > (uint64_t)PY_SSIZE_T_MAX - (uint64_t)PyBytesObject_SIZE) {
    sprintf(length_hex, "%llX", length);
    PyErr_Format(_CBOR2_CBORDecodeValueError, "excessive string size 0x%s",
                 length_hex);
    return NULL;
  }
  if (indefinite)
    ret = decode_indefinite_strings(self);
  else
    ret = decode_definite_string(self, (Py_ssize_t)length);
  set_shareable(self, ret);
  return ret;
}

bool ExtensionService::IsDownloadFromGallery(const GURL& download_url,
                                             const GURL& referrer_url) {
  if (IsDownloadFromMiniGallery(download_url) &&
      StartsWithASCII(referrer_url.spec(),
                      extension_urls::kMiniGalleryBrowsePrefix, false)) {
    return true;
  }
  const Extension* download_extension = GetExtensionByWebExtent(download_url);
  const Extension* referrer_extension = GetExtensionByWebExtent(referrer_url);
  const Extension* webstore_app = GetWebStoreApp();
  bool referrer_valid = (referrer_extension == webstore_app);
  bool download_valid = (download_extension == webstore_app);
  GURL store_url = GURL(CommandLine::ForCurrentProcess()->GetSwitchValueASCII(
      switches::kAppsGalleryURL));
  if (!store_url.is_empty()) {
    std::string store_tld =
        net::RegistryControlledDomainService::GetDomainAndRegistry(store_url);
    if (!referrer_valid) {
      std::string referrer_tld =
          net::RegistryControlledDomainService::GetDomainAndRegistry(
              referrer_url);
      referrer_valid = referrer_url.is_empty() || (referrer_tld == store_tld);
    }
    if (!download_valid) {
      std::string download_tld =
          net::RegistryControlledDomainService::GetDomainAndRegistry(
              download_url);
      download_valid = (download_tld == store_tld);
    }
  }
  return (referrer_valid && download_valid);
}

