static void oz_usb_handle_ep_data(struct oz_usb_ctx* usb_ctx,
                                  struct oz_usb_hdr* usb_hdr, int len) {
  struct oz_data* data_hdr = (struct oz_data*)usb_hdr;
  switch (data_hdr->format) {
    case OZ_DATA_F_MULTIPLE_FIXED: {
      struct oz_multiple_fixed* body = (struct oz_multiple_fixed*)data_hdr;
      u8* data = body->data;
      int n;
      if (!body->unit_size) break;
      n = (len - sizeof(struct oz_multiple_fixed) + 1) / body->unit_size;
      while (n--) {
        oz_hcd_data_ind(usb_ctx->hport, body->endpoint, data, body->unit_size);
        data += body->unit_size;
      }
    } break;
    case OZ_DATA_F_ISOC_FIXED: {
      struct oz_isoc_fixed* body = (struct oz_isoc_fixed*)data_hdr;
      int data_len = len - sizeof(struct oz_isoc_fixed) + 1;
      int unit_size = body->unit_size;
      u8* data = body->data;
      int count;
      int i;
      if (!unit_size) break;
      count = data_len / unit_size;
      for (i = 0; i < count; i++) {
        oz_hcd_data_ind(usb_ctx->hport, body->endpoint, data, unit_size);
        data += unit_size;
      }
    } break;
  }
}

int kvm_arch_vcpu_ioctl_run(struct kvm_vcpu* vcpu, struct kvm_run* run) {
  int ret;
  sigset_t sigsaved;
  if (unlikely(vcpu->arch.target < 0)) return -ENOEXEC;
  ret = kvm_vcpu_first_run_init(vcpu);
  if (ret) return ret;
  if (run->exit_reason == KVM_EXIT_MMIO) {
    ret = kvm_handle_mmio_return(vcpu, vcpu->run);
    if (ret) return ret;
  }
  if (vcpu->sigset_active) sigprocmask(SIG_SETMASK, &vcpu->sigset, &sigsaved);
  ret = 1;
  run->exit_reason = KVM_EXIT_UNKNOWN;
  while (ret > 0) {
    cond_resched();
    update_vttbr(vcpu->kvm);
    if (vcpu->arch.pause) vcpu_pause(vcpu);
    kvm_vgic_flush_hwstate(vcpu);
    kvm_timer_flush_hwstate(vcpu);
    local_irq_disable();
    if (signal_pending(current)) {
      ret = -EINTR;
      run->exit_reason = KVM_EXIT_INTR;
    }
    if (ret <= 0 || need_new_vmid_gen(vcpu->kvm)) {
      local_irq_enable();
      kvm_timer_sync_hwstate(vcpu);
      kvm_vgic_sync_hwstate(vcpu);
      continue;
    }
    trace_kvm_entry(*vcpu_pc(vcpu));
    kvm_guest_enter();
    vcpu->mode = IN_GUEST_MODE;
    ret = kvm_call_hyp(__kvm_vcpu_run, vcpu);
    vcpu->mode = OUTSIDE_GUEST_MODE;
    vcpu->arch.last_pcpu = smp_processor_id();
    kvm_guest_exit();
    trace_kvm_exit(*vcpu_pc(vcpu));
    local_irq_enable();
    kvm_timer_sync_hwstate(vcpu);
    kvm_vgic_sync_hwstate(vcpu);
    ret = handle_exit(vcpu, run, ret);
  }
  if (vcpu->sigset_active) sigprocmask(SIG_SETMASK, &sigsaved, NULL);
  return ret;
}

void Compute(OpKernelContext* ctx) override {
  const Tensor& values_tensor = ctx->input(0);
  const Tensor& value_range_tensor = ctx->input(1);
  const Tensor& nbins_tensor = ctx->input(2);
  OP_REQUIRES(ctx, TensorShapeUtils::IsVector(value_range_tensor.shape()),
              errors::InvalidArgument("value_range should be a vector."));
  OP_REQUIRES(
      ctx, (value_range_tensor.shape().num_elements() == 2),
      errors::InvalidArgument("value_range should be a vector of 2 elements."));
  OP_REQUIRES(ctx, TensorShapeUtils::IsScalar(nbins_tensor.shape()),
              errors::InvalidArgument("nbins should be a scalar."));
  const auto values = values_tensor.flat<T>();
  const auto value_range = value_range_tensor.flat<T>();
  const auto nbins = nbins_tensor.scalar<int32>()();
  OP_REQUIRES(
      ctx, (value_range(0) < value_range(1)),
      errors::InvalidArgument("value_range should satisfy value_range[0] < "
                              "value_range[1], but got '[",
                              value_range(0), ", ", value_range(1), "]'"));
  OP_REQUIRES(ctx, (nbins > 0),
              errors::InvalidArgument(
                  "nbins should be a positive number, but got '", nbins, "'"));
  Tensor* out_tensor;
  OP_REQUIRES_OK(ctx,
                 ctx->allocate_output(0, TensorShape({nbins}), &out_tensor));
  auto out = out_tensor->flat<Tout>();
  OP_REQUIRES_OK(ctx,
                 functor::HistogramFixedWidthFunctor<Device, T, Tout>::Compute(
                     ctx, values, value_range, nbins, out));
}

std::string get_wml_location(const std::string& filename,
                             const std::string& current_dir) {
  DBG_FS << "Looking for '" << filename << "'.\n";
  std::string result;
  if (filename.empty()) {
    LOG_FS << "  invalid filename\n";
    return result;
  }
  if (filename.find("..") != std::string::npos) {
    ERR_FS << "Illegal path '" << filename << "' (\"..\" not allowed).\n";
    return result;
  }
  bool already_found = false;
  if (filename[0] == '~') {
    result = get_user_data_dir() + "/data/" + filename.substr(1);
    DBG_FS << "  trying '" << result << "'\n";
    already_found = file_exists(result) || is_directory(result);
  } else if (filename.size() >= 2 && filename[0] == '.' && filename[1] == '/') {
    result = current_dir + filename.substr(2);
  } else if (!game_config::path.empty())
    result = game_config::path + "/data/" + filename;
  DBG_FS << "  trying '" << result << "'\n";
  if (result.empty() ||
      (!already_found && !file_exists(result) && !is_directory(result))) {
    DBG_FS << "  not found\n";
    result.clear();
  } else
    DBG_FS << "  found: '" << result << "'\n";
  return result;
}

int usb_cypress_load_firmware(struct usb_device* udev,
                              const struct firmware* fw, int type) {
  struct hexline* hx;
  u8 reset;
  int ret, pos = 0;
  hx = kmalloc(sizeof(*hx), GFP_KERNEL);
  if (!hx) return -ENOMEM;
  reset = 1;
  if ((ret = usb_cypress_writemem(udev, cypress[type].cpu_cs_register, &reset,
                                  1)) != 1)
    err("could not stop the USB controller CPU.");
  while ((ret = dvb_usb_get_hexline(fw, hx, &pos)) > 0) {
    deb_fw("writing to address 0x%04x (buffer: 0x%02x %02x)\n", hx->addr,
           hx->len, hx->chk);
    ret = usb_cypress_writemem(udev, hx->addr, hx->data, hx->len);
    if (ret != hx->len) {
      err("error while transferring firmware (transferred size: %d, block "
          "size: %d)",
          ret, hx->len);
      ret = -EINVAL;
      break;
    }
  }
  if (ret < 0) {
    err("firmware download failed at %d with %d", pos, ret);
    kfree(hx);
    return ret;
  }
  if (ret == 0) {
    reset = 0;
    if (ret || usb_cypress_writemem(udev, cypress[type].cpu_cs_register, &reset,
                                    1) != 1) {
      err("could not restart the USB controller CPU.");
      ret = -EINVAL;
    }
  } else
    ret = -EIO;
  kfree(hx);
  return ret;
}

