static int input_default_setkeycode(struct input_dev* dev,
                                    const struct input_keymap_entry* ke,
                                    unsigned int* old_keycode) {
  unsigned int index;
  int error;
  int i;
  if (!dev->keycodesize) return -EINVAL;
  if (ke->flags & INPUT_KEYMAP_BY_INDEX) {
    index = ke->index;
  } else {
    error = input_scancode_to_scalar(ke, &index);
    if (error) return error;
  }
  if (index >= dev->keycodemax) return -EINVAL;
  if (dev->keycodesize < sizeof(ke->keycode) &&
      (ke->keycode >> (dev->keycodesize * 8)))
    return -EINVAL;
  switch (dev->keycodesize) {
    case 1: {
      u8* k = (u8*)dev->keycode;
      *old_keycode = k[index];
      k[index] = ke->keycode;
      break;
    }
    case 2: {
      u16* k = (u16*)dev->keycode;
      *old_keycode = k[index];
      k[index] = ke->keycode;
      break;
    }
    default: {
      u32* k = (u32*)dev->keycode;
      *old_keycode = k[index];
      k[index] = ke->keycode;
      break;
    }
  }
  __clear_bit(*old_keycode, dev->keybit);
  __set_bit(ke->keycode, dev->keybit);
  for (i = 0; i < dev->keycodemax; i++) {
    if (input_fetch_keycode(dev, i) == *old_keycode) {
      __set_bit(*old_keycode, dev->keybit);
      break;
    }
  }
  return 0;
}

sanitize_filename(const char* file_name) {
  size_t prefix_len;
  char const* p;
  if (file_name == NULL) return NULL;
  prefix_len = 0;
  for (p = file_name; *p;) {
    if (ISDOT(p[0]) && ISDOT(p[1]) && (ISSLASH(p[2]) || !p[2]))
      prefix_len = p + 2 - file_name;
    do {
      char c = *p++;
      if (ISSLASH(c)) break;
    } while (*p);
  }
  p = file_name + prefix_len;
  while (ISSLASH(*p)) p++;
  return p;
}

static int io_add_buffers(struct io_provide_buf* pbuf,
                          struct io_buffer** head) {
  struct io_buffer* buf;
  u64 addr = pbuf->addr;
  int i, bid = pbuf->bid;
  for (i = 0; i < pbuf->nbufs; i++) {
    buf = kmalloc(sizeof(*buf), GFP_KERNEL);
    if (!buf) break;
    buf->addr = addr;
    buf->len = pbuf->len;
    buf->bid = bid;
    addr += pbuf->len;
    bid++;
    if (!*head) {
      INIT_LIST_HEAD(&buf->list);
      *head = buf;
    } else {
      list_add_tail(&buf->list, &(*head)->list);
    }
  }
  return i ? i : -ENOMEM;
}

vips_foreign_load_gif_scan_image(VipsForeignLoadGif* gif) {
  VipsObjectClass* class = VIPS_OBJECT_GET_CLASS(gif);
  GifFileType* file = gif->file;
  ColorMapObject* map =
      file->Image.ColorMap ? file->Image.ColorMap : file->SColorMap;
  GifByteType* extension;
  if (DGifGetImageDesc(gif->file) == GIF_ERROR) {
    vips_foreign_load_gif_error(gif);
    return (-1);
  }
  if (file->Image.Left < 0 || file->Image.Width < 1 ||
      file->Image.Width > 10000 ||
      file->Image.Left + file->Image.Width > file->SWidth ||
      file->Image.Top < 0 || file->Image.Height < 1 ||
      file->Image.Height > 10000 ||
      file->Image.Top + file->Image.Height > file->SHeight) {
    vips_error(class->nickname, "%s", _("bad frame size"));
    return (-1);
  }
  if (!gif->has_colour && map) {
    int i;
    for (i = 0; i < map->ColorCount; i++)
      if (map->Colors[i].Red != map->Colors[i].Green ||
          map->Colors[i].Green != map->Colors[i].Blue) {
        gif->has_colour = TRUE;
        break;
      }
  }
  do {
    if (vips_foreign_load_gif_code_next(gif, &extension)) return (-1);
  } while (extension != NULL);
  return (0);
}

