static bool tipc_crypto_key_rcv(struct tipc_crypto* rx, struct tipc_msg* hdr) {
  struct tipc_crypto* tx = tipc_net(rx->net)->crypto_tx;
  struct tipc_aead_key* skey = NULL;
  u16 key_gen = msg_key_gen(hdr);
  u16 size = msg_data_sz(hdr);
  u8* data = msg_data(hdr);
  spin_lock(&rx->lock);
  if (unlikely(rx->skey || (key_gen == rx->key_gen && rx->key.keys))) {
    pr_err("%s: key existed <%p>, gen %d vs %d\n", rx->name, rx->skey, key_gen,
           rx->key_gen);
    goto exit;
  }
  skey = kmalloc(size, GFP_ATOMIC);
  if (unlikely(!skey)) {
    pr_err("%s: unable to allocate memory for skey\n", rx->name);
    goto exit;
  }
  skey->keylen = ntohl(*((__be32*)(data + TIPC_AEAD_ALG_NAME)));
  memcpy(skey->alg_name, data, TIPC_AEAD_ALG_NAME);
  memcpy(skey->key, data + TIPC_AEAD_ALG_NAME + sizeof(__be32), skey->keylen);
  if (unlikely(size != tipc_aead_key_size(skey))) {
    kfree(skey);
    skey = NULL;
    goto exit;
  }
  rx->key_gen = key_gen;
  rx->skey_mode = msg_key_mode(hdr);
  rx->skey = skey;
  rx->nokey = 0;
  mb();
exit:
  spin_unlock(&rx->lock);
  if (likely(skey && queue_delayed_work(tx->wq, &rx->work, 0))) return true;
  return false;
}

LUA_API void lua_upvaluejoin(lua_State* L, int fidx1, int n1, int fidx2,
                             int n2) {
  LClosure* f1;
  UpVal** up1 = getupvalref(L, fidx1, n1, &f1);
  UpVal** up2 = getupvalref(L, fidx2, n2, NULL);
  luaC_upvdeccount(L, *up1);
  *up1 = *up2;
  (*up1)->refcount++;
  if (upisopen(*up1)) (*up1)->u.open.touched = 1;
  luaC_upvalbarrier(L, *up1);
}

void ValidateOpDimensionsFromInputs(const int n, const int h, const int w,
                                    const int c, const int kx, const int ky,
                                    const int sx, const int sy,
                                    const string& data_format,
                                    const string& padding) {
  OpContext op_context;
  int ho;
  int wo;
  if (data_format == "NHWC") {
    op_context = DescribePoolingOp("MaxPool", {n, h, w, c}, {1, kx, ky, 1},
                                   {1, sx, sy, 1}, "NHWC", padding);
    ho = op_context.op_info.outputs(0).shape().dim(1).size();
    wo = op_context.op_info.outputs(0).shape().dim(2).size();
  } else {
    op_context = DescribePoolingOp("MaxPool", {n, c, h, w}, {1, 1, kx, ky},
                                   {1, 1, sx, sy}, "NCHW", padding);
    ho = op_context.op_info.outputs(0).shape().dim(2).size();
    wo = op_context.op_info.outputs(0).shape().dim(3).size();
  }
  bool found_unknown_shapes;
  auto dims = OpLevelCostEstimator::OpDimensionsFromInputs(
      op_context.op_info.inputs(0).shape(), op_context.op_info,
      &found_unknown_shapes);
  Padding padding_enum;
  if (padding == "VALID") {
    padding_enum = Padding::VALID;
  } else {
    padding_enum = Padding::SAME;
  }
  EXPECT_EQ(n, dims.batch);
  EXPECT_EQ(h, dims.ix);
  EXPECT_EQ(w, dims.iy);
  EXPECT_EQ(c, dims.iz);
  EXPECT_EQ(kx, dims.kx);
  EXPECT_EQ(ky, dims.ky);
  EXPECT_EQ(sx, dims.sx);
  EXPECT_EQ(sy, dims.sy);
  EXPECT_EQ(ho, dims.ox);
  EXPECT_EQ(wo, dims.oy);
  EXPECT_EQ(c, dims.oz);
  EXPECT_EQ(padding_enum, dims.padding);
}

dotraplinkage void notrace do_int3(struct pt_regs* regs, long error_code) {
#ifdef CONFIG_DYNAMIC_FTRACE
  if (unlikely(atomic_read(&modifying_ftrace_code)) &&
      ftrace_int3_handler(regs))
    return;
#endif
  if (poke_int3_handler(regs)) return;
  ist_enter(regs);
  RCU_LOCKDEP_WARN(!rcu_is_watching(), "entry code didn't wake RCU");
#ifdef CONFIG_KGDB_LOW_LEVEL_TRAP
  if (kgdb_ll_trap(DIE_INT3, "int3", regs, error_code, X86_TRAP_BP, SIGTRAP) ==
      NOTIFY_STOP)
    goto exit;
#endif
#ifdef CONFIG_KPROBES
  if (kprobe_int3_handler(regs)) goto exit;
#endif
  if (notify_die(DIE_INT3, "int3", regs, error_code, X86_TRAP_BP, SIGTRAP) ==
      NOTIFY_STOP)
    goto exit;
  debug_stack_usage_inc();
  cond_local_irq_enable(regs);
  do_trap(X86_TRAP_BP, SIGTRAP, "int3", regs, error_code, NULL);
  cond_local_irq_disable(regs);
  debug_stack_usage_dec();
exit:
  ist_exit(regs);
}

void CConfig::Write(CFile& File, unsigned int iIndentation) {
  CString sIndentation = CString(iIndentation, '\t');
  for (const auto& it : m_ConfigEntries) {
    for (const CString& sValue : it.second) {
      File.Write(sIndentation + it.first + " = " + sValue + "\n");
    }
  }
  for (const auto& it : m_SubConfigs) {
    for (const auto& it2 : it.second) {
      File.Write("\n");
      File.Write(sIndentation + "<" + it.first + " " + it2.first + ">\n");
      it2.second.m_pSubConfig->Write(File, iIndentation + 1);
      File.Write(sIndentation + "</" + it.first + ">\n");
    }
  }
}

internalEntityProcessor(XML_Parser parser, const char* s, const char* end,
                        const char** nextPtr) {
  ENTITY* entity;
  const char *textStart, *textEnd;
  const char* next;
  enum XML_Error result;
  OPEN_INTERNAL_ENTITY* openEntity = parser->m_openInternalEntities;
  if (!openEntity) return XML_ERROR_UNEXPECTED_STATE;
  entity = openEntity->entity;
  textStart = ((char*)entity->textPtr) + entity->processed;
  textEnd = (char*)(entity->textPtr + entity->textLen);
  next = textStart;
#ifdef XML_DTD
  if (entity->is_param) {
    int tok =
        XmlPrologTok(parser->m_internalEncoding, textStart, textEnd, &next);
    result = doProlog(parser, parser->m_internalEncoding, textStart, textEnd,
                      tok, next, &next, XML_FALSE);
  } else
#endif
    result =
        doContent(parser, openEntity->startTagLevel, parser->m_internalEncoding,
                  textStart, textEnd, &next, XML_FALSE);
  if (result != XML_ERROR_NONE)
    return result;
  else if (textEnd != next &&
           parser->m_parsingStatus.parsing == XML_SUSPENDED) {
    entity->processed = (int)(next - (char*)entity->textPtr);
    return result;
  } else {
    entity->open = XML_FALSE;
    parser->m_openInternalEntities = openEntity->next;
    openEntity->next = parser->m_freeInternalEntities;
    parser->m_freeInternalEntities = openEntity;
  }
#ifdef XML_DTD
  if (entity->is_param) {
    int tok;
    parser->m_processor = prologProcessor;
    tok = XmlPrologTok(parser->m_encoding, s, end, &next);
    return doProlog(parser, parser->m_encoding, s, end, tok, next, nextPtr,
                    (XML_Bool)!parser->m_parsingStatus.finalBuffer);
  } else
#endif
  {
    parser->m_processor = contentProcessor;
    return doContent(parser, parser->m_parentParser ? 1 : 0, parser->m_encoding,
                     s, end, nextPtr,
                     (XML_Bool)!parser->m_parsingStatus.finalBuffer);
  }
}

static int stimer_set_config(struct kvm_vcpu_hv_stimer* stimer, u64 config,
                             bool host) {
  union hv_stimer_config new_config = {.as_uint64 = config},
                         old_config = {.as_uint64 = stimer->config.as_uint64};
  struct kvm_vcpu* vcpu = hv_stimer_to_vcpu(stimer);
  struct kvm_vcpu_hv* hv_vcpu = to_hv_vcpu(vcpu);
  struct kvm_vcpu_hv_synic* synic = to_hv_synic(vcpu);
  if (!synic->active && !host) return 1;
  if (unlikely(!host && hv_vcpu->enforce_cpuid && new_config.direct_mode &&
               !(hv_vcpu->cpuid_cache.features_edx &
                 HV_STIMER_DIRECT_MODE_AVAILABLE)))
    return 1;
  trace_kvm_hv_stimer_set_config(hv_stimer_to_vcpu(stimer)->vcpu_id,
                                 stimer->index, config, host);
  stimer_cleanup(stimer);
  if (old_config.enable && !new_config.direct_mode && new_config.sintx == 0)
    new_config.enable = 0;
  stimer->config.as_uint64 = new_config.as_uint64;
  if (stimer->config.enable) stimer_mark_pending(stimer, false);
  return 0;
}

void* pvPortMalloc(size_t xWantedSize) {
  BlockLink_t *pxBlock, *pxPreviousBlock, *pxNewBlockLink;
  static BaseType_t xHeapHasBeenInitialised = pdFALSE;
  void* pvReturn = NULL;
  vTaskSuspendAll();
  {
    if (xHeapHasBeenInitialised == pdFALSE) {
      prvHeapInit();
      xHeapHasBeenInitialised = pdTRUE;
    }
    if (xWantedSize > 0) {
      xWantedSize += heapSTRUCT_SIZE;
      if ((xWantedSize & portBYTE_ALIGNMENT_MASK) != 0) {
        xWantedSize +=
            (portBYTE_ALIGNMENT - (xWantedSize & portBYTE_ALIGNMENT_MASK));
      }
    }
    if ((xWantedSize > 0) && (xWantedSize < configADJUSTED_HEAP_SIZE)) {
      pxPreviousBlock = &xStart;
      pxBlock = xStart.pxNextFreeBlock;
      while ((pxBlock->xBlockSize < xWantedSize) &&
             (pxBlock->pxNextFreeBlock != NULL)) {
        pxPreviousBlock = pxBlock;
        pxBlock = pxBlock->pxNextFreeBlock;
      }
      if (pxBlock != &xEnd) {
        pvReturn = (void*)(((uint8_t*)pxPreviousBlock->pxNextFreeBlock) +
                           heapSTRUCT_SIZE);
        pxPreviousBlock->pxNextFreeBlock = pxBlock->pxNextFreeBlock;
        if ((pxBlock->xBlockSize - xWantedSize) > heapMINIMUM_BLOCK_SIZE) {
          pxNewBlockLink = (void*)(((uint8_t*)pxBlock) + xWantedSize);
          pxNewBlockLink->xBlockSize = pxBlock->xBlockSize - xWantedSize;
          pxBlock->xBlockSize = xWantedSize;
          prvInsertBlockIntoFreeList((pxNewBlockLink));
        }
        xFreeBytesRemaining -= pxBlock->xBlockSize;
      }
    }
    traceMALLOC(pvReturn, xWantedSize);
  }
  (void)xTaskResumeAll();
#if (configUSE_MALLOC_FAILED_HOOK == 1)
  {
    if (pvReturn == NULL) {
      extern void vApplicationMallocFailedHook(void);
      vApplicationMallocFailedHook();
    }
  }
#endif
  return pvReturn;
}

rfbSendRectEncodingRaw(rfbClientPtr cl, int x, int y, int w, int h) {
  rfbFramebufferUpdateRectHeader rect;
  int nlines;
  int bytesPerLine = w * (cl->format.bitsPerPixel / 8);
  char* fbptr = (cl->scaledScreen->frameBuffer +
                 (cl->scaledScreen->paddedWidthInBytes * y) +
                 (x * (cl->scaledScreen->bitsPerPixel / 8)));
  if (cl->ublen > 0) {
    if (!rfbSendUpdateBuf(cl)) return FALSE;
  }
  rect.r.x = Swap16IfLE(x);
  rect.r.y = Swap16IfLE(y);
  rect.r.w = Swap16IfLE(w);
  rect.r.h = Swap16IfLE(h);
  rect.encoding = Swap32IfLE(rfbEncodingRaw);
  memcpy(&cl->updateBuf[cl->ublen], (char*)&rect,
         sz_rfbFramebufferUpdateRectHeader);
  cl->ublen += sz_rfbFramebufferUpdateRectHeader;
  rfbStatRecordEncodingSent(
      cl, rfbEncodingRaw, sz_rfbFramebufferUpdateRectHeader + bytesPerLine * h,
      sz_rfbFramebufferUpdateRectHeader + bytesPerLine * h);
  nlines = (UPDATE_BUF_SIZE - cl->ublen) / bytesPerLine;
  while (TRUE) {
    if (nlines > h) nlines = h;
    (*cl->translateFn)(cl->translateLookupTable, &(cl->screen->serverFormat),
                       &cl->format, fbptr, &cl->updateBuf[cl->ublen],
                       cl->scaledScreen->paddedWidthInBytes, w, nlines);
    cl->ublen += nlines * bytesPerLine;
    h -= nlines;
    if (h == 0) return TRUE;
    if (!rfbSendUpdateBuf(cl)) return FALSE;
    fbptr += (cl->scaledScreen->paddedWidthInBytes * nlines);
    nlines = (UPDATE_BUF_SIZE - cl->ublen) / bytesPerLine;
    if (nlines == 0) {
      rfbErr(
          "rfbSendRectEncodingRaw: send buffer too small for %d "
          "bytes per line\n",
          bytesPerLine);
      rfbCloseClient(cl);
      return FALSE;
    }
  }
}

static int ng_pkt(git_pkt** out, const char* line, size_t len) {
  git_pkt_ng* pkt;
  const char* ptr;
  size_t alloclen;
  pkt = git__malloc(sizeof(*pkt));
  GITERR_CHECK_ALLOC(pkt);
  pkt->ref = NULL;
  pkt->type = GIT_PKT_NG;
  line += 3;
  if (!(ptr = strchr(line, ' '))) goto out_err;
  len = ptr - line;
  GITERR_CHECK_ALLOC_ADD(&alloclen, len, 1);
  pkt->ref = git__malloc(alloclen);
  GITERR_CHECK_ALLOC(pkt->ref);
  memcpy(pkt->ref, line, len);
  pkt->ref[len] = '\0';
  line = ptr + 1;
  if (!(ptr = strchr(line, '\n'))) goto out_err;
  len = ptr - line;
  GITERR_CHECK_ALLOC_ADD(&alloclen, len, 1);
  pkt->msg = git__malloc(alloclen);
  GITERR_CHECK_ALLOC(pkt->msg);
  memcpy(pkt->msg, line, len);
  pkt->msg[len] = '\0';
  *out = (git_pkt*)pkt;
  return 0;
out_err:
  giterr_set(GITERR_NET, "invalid packet line");
  git__free(pkt->ref);
  git__free(pkt);
  return -1;
}

AP_DECLARE(void) ap_update_vhost_from_headers(request_rec* r) {
  core_server_config* conf =
      ap_get_core_module_config(r->server->module_config);
  const char* host_header = apr_table_get(r->headers_in, "Host");
  int is_v6literal = 0;
  int have_hostname_from_url = 0;
  if (r->hostname) {
    have_hostname_from_url = 1;
    is_v6literal = fix_hostname(r, NULL, conf->http_conformance);
  } else if (host_header != NULL) {
    is_v6literal = fix_hostname(r, host_header, conf->http_conformance);
  }
  if (r->status != HTTP_OK) return;
  if (conf->http_conformance != AP_HTTP_CONFORMANCE_UNSAFE) {
    if (have_hostname_from_url && host_header != NULL) {
      const char* repl = construct_host_header(r, is_v6literal);
      apr_table_setn(r->headers_in, "Host", repl);
      ap_log_rerror(APLOG_MARK, APLOG_DEBUG, 0, r, APLOGNO(02417)
                          "Replacing host header '%s' with host '%s' given "
                          "in the request uri", host_header, repl);
    }
  }
  if (r->connection->vhost_lookup_data) {
    if (r->hostname)
      check_hostalias(r);
    else
      check_serverpath(r);
  }
}

static int ScaKwdTab(GmfMshSct* msh) {
  int KwdCod, c;
  int64_t NexPos, EndPos, LstPos;
  char str[GmfStrSiz];
  if (msh->typ & Asc) {
    while (fscanf(msh->hdl, "%s", str) != EOF) {
      if (isalpha(str[0])) {
        for (KwdCod = 1; KwdCod <= GmfMaxKwd; KwdCod++)
          if (!strcmp(str, GmfKwdFmt[KwdCod][0])) {
            ScaKwdHdr(msh, KwdCod);
            break;
          }
      } else if (str[0] == '#')
        while ((c = fgetc(msh->hdl)) != '\n' && c != EOF);
    }
  } else {
    EndPos = GetFilSiz(msh);
    LstPos = -1;
    do {
      ScaWrd(msh, (char*)&KwdCod);
      NexPos = GetPos(msh);
      if (NexPos > EndPos) longjmp(msh->err, -24);
      if (NexPos && (NexPos <= LstPos)) longjmp(msh->err, -30);
      LstPos = NexPos;
      if ((KwdCod >= 1) && (KwdCod <= GmfMaxKwd)) ScaKwdHdr(msh, KwdCod);
      if (NexPos && !(SetFilPos(msh, NexPos))) longjmp(msh->err, -25);
    } while (NexPos && (KwdCod != GmfEnd));
  }
  return (1);
}

static noinline void key_gc_unused_keys(struct list_head* keys) {
  while (!list_empty(keys)) {
    struct key* key = list_entry(keys->next, struct key, graveyard_link);
    list_del(&key->graveyard_link);
    kdebug("- %u", key->serial);
    key_check(key);
    security_key_free(key);
    if (test_bit(KEY_FLAG_IN_QUOTA, &key->flags)) {
      spin_lock(&key->user->lock);
      key->user->qnkeys--;
      key->user->qnbytes -= key->quotalen;
      spin_unlock(&key->user->lock);
    }
    atomic_dec(&key->user->nkeys);
    if (test_bit(KEY_FLAG_INSTANTIATED, &key->flags))
      atomic_dec(&key->user->nikeys);
    key_user_put(key->user);
    if (key->type->destroy) key->type->destroy(key);
    kfree(key->description);
#ifdef KEY_DEBUGGING
    key->magic = KEY_DEBUG_MAGIC_X;
#endif
    kmem_cache_free(key_jar, key);
  }
}

void HeaderMapImpl::insertByKey(HeaderString&& key, HeaderString&& value) {
  EntryCb cb =
      ConstSingleton<StaticLookupTable>::get().find(key.getStringView());
  if (cb) {
    key.clear();
    StaticLookupResponse ref_lookup_response = cb(*this);
    if (*ref_lookup_response.entry_ == nullptr) {
      maybeCreateInline(ref_lookup_response.entry_, *ref_lookup_response.key_,
                        std::move(value));
    } else {
      appendToHeader((*ref_lookup_response.entry_)->value(),
                     value.getStringView());
      value.clear();
    }
  } else {
    std::list<HeaderEntryImpl>::iterator i =
        headers_.insert(std::move(key), std::move(value));
    i->entry_ = i;
  }
}

int __gfs2_set_acl(struct inode* inode, struct posix_acl* acl, int type) {
  int error;
  int len;
  char* data;
  const char* name = gfs2_acl_name(type);
  if (acl && acl->a_count > GFS2_ACL_MAX_ENTRIES(GFS2_SB(inode))) return -E2BIG;
  if (type == ACL_TYPE_ACCESS) {
    umode_t mode = inode->i_mode;
    error = posix_acl_equiv_mode(acl, &mode);
    if (error < 0) return error;
    if (error == 0) acl = NULL;
    if (mode != inode->i_mode) {
      inode->i_mode = mode;
      mark_inode_dirty(inode);
    }
  }
  if (acl) {
    len = posix_acl_to_xattr(&init_user_ns, acl, NULL, 0);
    if (len == 0) return 0;
    data = kmalloc(len, GFP_NOFS);
    if (data == NULL) return -ENOMEM;
    error = posix_acl_to_xattr(&init_user_ns, acl, data, len);
    if (error < 0) goto out;
  } else {
    data = NULL;
    len = 0;
  }
  error = __gfs2_xattr_set(inode, name, data, len, 0, GFS2_EATYPE_SYS);
  if (error) goto out;
  set_cached_acl(inode, type, acl);
out:
  kfree(data);
  return error;
}

static void perf_callchain_user_64(struct perf_callchain_entry* entry,
                                   struct pt_regs* regs) {
  unsigned long sp, next_sp;
  unsigned long next_ip;
  unsigned long lr;
  long level = 0;
  struct signal_frame_64 __user* sigframe;
  unsigned long __user *fp, *uregs;
  next_ip = perf_instruction_pointer(regs);
  lr = regs->link;
  sp = regs->gpr[1];
  perf_callchain_store(entry, next_ip);
  for (;;) {
    fp = (unsigned long __user*)sp;
    if (!valid_user_sp(sp, 1) || read_user_stack_64(fp, &next_sp)) return;
    if (level > 0 && read_user_stack_64(&fp[2], &next_ip)) return;
    if (next_sp - sp >= sizeof(struct signal_frame_64) &&
        (is_sigreturn_64_address(next_ip, sp) ||
         (level <= 1 && is_sigreturn_64_address(lr, sp))) &&
        sane_signal_64_frame(sp)) {
      sigframe = (struct signal_frame_64 __user*)sp;
      uregs = sigframe->uc.uc_mcontext.gp_regs;
      if (read_user_stack_64(&uregs[PT_NIP], &next_ip) ||
          read_user_stack_64(&uregs[PT_LNK], &lr) ||
          read_user_stack_64(&uregs[PT_R1], &sp))
        return;
      level = 0;
      perf_callchain_store(entry, PERF_CONTEXT_USER);
      perf_callchain_store(entry, next_ip);
      continue;
    }
    if (level == 0) next_ip = lr;
    perf_callchain_store(entry, next_ip);
    ++level;
    sp = next_sp;
  }
}

header_put_le_int(SF_PRIVATE* psf, int x) {
  if (psf->headindex < SIGNED_SIZEOF(psf->header) - 4) {
    psf->header[psf->headindex++] = x;
    psf->header[psf->headindex++] = (x >> 8);
    psf->header[psf->headindex++] = (x >> 16);
    psf->header[psf->headindex++] = (x >> 24);
  };
}

CBORTag_hash(CBORTagObject* self) {
  if (!_CBOR2_thread_locals && _CBOR2_init_thread_locals() == -1) return -1;
  Py_hash_t ret = -1;
  PyObject* running_hashes = NULL;
  PyObject* tmp = NULL;
  PyObject* self_id = PyLong_FromVoidPtr(self);
  if (!self_id) goto exit;
  running_hashes =
      PyObject_GetAttrString(_CBOR2_thread_locals, "running_hashes");
  if (!running_hashes) {
    PyErr_Clear();
    running_hashes = PySet_New(NULL);
    if (PyObject_SetAttrString(_CBOR2_thread_locals, "running_hashes",
                               running_hashes) == -1)
      goto exit;
  } else {
    switch (PySet_Contains(running_hashes, self_id)) {
      case -1:
        goto exit;
      case 1:
        PyErr_SetString(PyExc_RuntimeError,
                        "This CBORTag is not hashable because it contains a "
                        "reference to itself");
        goto exit;
    }
  }
  if (PySet_Add(running_hashes, self_id) == -1) goto exit;
  tmp = Py_BuildValue("(KO)", self->tag, self->value);
  if (!tmp) goto exit;
  ret = PyObject_Hash(tmp);
  if (PySet_Discard(running_hashes, self_id) == -1) {
    ret = -1;
    goto exit;
  }
  Py_ssize_t length = PySequence_Length(running_hashes);
  if (length == 1) {
    ret = -1;
    goto exit;
  }
  if (length == 0 &&
      PyObject_DelAttrString(_CBOR2_thread_locals, "running_hashes") == -1) {
    ret = -1;
    goto exit;
  }
exit:
  Py_CLEAR(self_id);
  Py_CLEAR(running_hashes);
  Py_CLEAR(tmp);
  return ret;
}

static bool anal_fcn_data(RCore* core, const char* input) {
  RAnalFunction* fcn = r_anal_get_fcn_in(core->anal, core->offset, -1);
  ut32 fcn_size = r_anal_function_size_from_entry(fcn);
  if (fcn) {
    int i;
    bool gap = false;
    ut64 gap_addr = UT64_MAX;
    char* bitmap = calloc(1, fcn_size);
    if (bitmap) {
      RAnalBlock* b;
      RListIter* iter;
      r_list_foreach(fcn->bbs, iter, b) {
        int f = b->addr - fcn->addr;
        int t = R_MIN(f + b->size, fcn_size);
        if (f >= 0) {
          while (f < t) {
            bitmap[f++] = 1;
          }
        }
      }
    }
    for (i = 0; i < fcn_size; i++) {
      ut64 here = fcn->addr + i;
      if (bitmap && bitmap[i]) {
        if (gap) {
          r_cons_printf("Cd %d @ 0x%08" PFMT64x "\n", here - gap_addr,
                        gap_addr);
          gap = false;
        }
        gap_addr = UT64_MAX;
      } else {
        if (!gap) {
          gap = true;
          gap_addr = here;
        }
      }
    }
    if (gap) {
      r_cons_printf("Cd %d @ 0x%08" PFMT64x "\n",
                    fcn->addr + fcn_size - gap_addr, gap_addr);
    }
    free(bitmap);
    return true;
  }
  return false;
}

static void youngcollection(lua_State* L, global_State* g) {
  GCObject** psurvival;
  lua_assert(g->gcstate == GCSpropagate);
  markold(g, g->survival, g->reallyold);
  markold(g, g->finobj, g->finobjrold);
  atomic(L);
  psurvival = sweepgen(L, g, &g->allgc, g->survival);
  sweepgen(L, g, psurvival, g->reallyold);
  g->reallyold = g->old;
  g->old = *psurvival;
  g->survival = g->allgc;
  psurvival = sweepgen(L, g, &g->finobj, g->finobjsur);
  sweepgen(L, g, psurvival, g->finobjrold);
  g->finobjrold = g->finobjold;
  g->finobjold = *psurvival;
  g->finobjsur = g->finobj;
  sweepgen(L, g, &g->tobefnz, NULL);
  finishgencycle(L, g);
}

lyd_new_output_anydata(struct lyd_node* parent, const struct lys_module* module,
                       const char* name, void* value,
                       LYD_ANYDATA_VALUETYPE value_type) {
  const struct lys_node *siblings, *snode;
  if ((!parent && !module) || !name) {
    LOGARG;
    return NULL;
  }
  siblings = lyd_new_find_schema(parent, module, 1);
  if (!siblings) {
    LOGARG;
    return NULL;
  }
  if (lys_getnext_data(module, lys_parent(siblings), name, strlen(name),
                       LYS_ANYDATA, &snode) ||
      !snode) {
    LOGERR(siblings->module->ctx, LY_EINVAL,
           "Failed to find \"%s\" as a sibling to \"%s:%s\".", name,
           lys_node_module(siblings)->name, siblings->name);
    return NULL;
  }
  return lyd_create_anydata(parent, snode, value, value_type);
}

static bool dccp_new(struct nf_conn* ct, const struct sk_buff* skb,
                     unsigned int dataoff, unsigned int* timeouts) {
  struct net* net = nf_ct_net(ct);
  struct dccp_net* dn;
  struct dccp_hdr _dh, *dh;
  const char* msg;
  u_int8_t state;
  dh = skb_header_pointer(skb, dataoff, sizeof(_dh), &dh);
  BUG_ON(dh == NULL);
  state = dccp_state_table[CT_DCCP_ROLE_CLIENT][dh->dccph_type][CT_DCCP_NONE];
  switch (state) {
    default:
      dn = dccp_pernet(net);
      if (dn->dccp_loose == 0) {
        msg = "nf_ct_dccp: not picking up existing connection ";
        goto out_invalid;
      }
    case CT_DCCP_REQUEST:
      break;
    case CT_DCCP_INVALID:
      msg = "nf_ct_dccp: invalid state transition ";
      goto out_invalid;
  }
  ct->proto.dccp.role[IP_CT_DIR_ORIGINAL] = CT_DCCP_ROLE_CLIENT;
  ct->proto.dccp.role[IP_CT_DIR_REPLY] = CT_DCCP_ROLE_SERVER;
  ct->proto.dccp.state = CT_DCCP_NONE;
  ct->proto.dccp.last_pkt = DCCP_PKT_REQUEST;
  ct->proto.dccp.last_dir = IP_CT_DIR_ORIGINAL;
  ct->proto.dccp.handshake_seq = 0;
  return true;
out_invalid:
  if (LOG_INVALID(net, IPPROTO_DCCP))
    nf_log_packet(net, nf_ct_l3num(ct), 0, skb, NULL, NULL, NULL, "%s", msg);
  return false;
}

static int dnxhd_init_vlc(DNXHDContext* ctx, uint32_t cid, int bitdepth) {
  if (cid != ctx->cid) {
    const CIDEntry* cid_table = ff_dnxhd_get_cid_table(cid);
    if (!cid_table) {
      av_log(ctx->avctx, AV_LOG_ERROR, "unsupported cid %" PRIu32 "\n", cid);
      return AVERROR(ENOSYS);
    }
    if (cid_table->bit_depth != bitdepth &&
        cid_table->bit_depth != DNXHD_VARIABLE) {
      av_log(ctx->avctx, AV_LOG_ERROR, "bit depth mismatches %d %d\n",
             cid_table->bit_depth, bitdepth);
      return AVERROR_INVALIDDATA;
    }
    ctx->cid_table = cid_table;
    av_log(ctx->avctx, AV_LOG_VERBOSE, "Profile cid %" PRIu32 ".\n", cid);
    ff_free_vlc(&ctx->ac_vlc);
    ff_free_vlc(&ctx->dc_vlc);
    ff_free_vlc(&ctx->run_vlc);
    init_vlc(&ctx->ac_vlc, DNXHD_VLC_BITS, 257, ctx->cid_table->ac_bits, 1, 1,
             ctx->cid_table->ac_codes, 2, 2, 0);
    init_vlc(&ctx->dc_vlc, DNXHD_DC_VLC_BITS, bitdepth > 8 ? 14 : 12,
             ctx->cid_table->dc_bits, 1, 1, ctx->cid_table->dc_codes, 1, 1, 0);
    init_vlc(&ctx->run_vlc, DNXHD_VLC_BITS, 62, ctx->cid_table->run_bits, 1, 1,
             ctx->cid_table->run_codes, 2, 2, 0);
    ctx->cid = cid;
  }
  return 0;
}

size_t util_path_encode(char* s, size_t len) {
  char t[(len * 3) + 1];
  size_t i, j;
  for (i = 0, j = 0; s[i] != '\0'; i++) {
    if (s[i] == '/') {
      memcpy(&t[j], "\\x2f", 4);
      j += 4;
    } else if (s[i] == '\\') {
      memcpy(&t[j], "\\x5c", 4);
      j += 4;
    } else {
      t[j] = s[i];
      j++;
    }
  }
  if (len == 0) return j;
  i = (j < len - 1) ? j : len - 1;
  memcpy(s, t, i);
  s[i] = '\0';
  return j;
}

