BGD_DECLARE(gdImagePtr) gdImageCreate(int sx, int sy) {
  int i;
  gdImagePtr im;
  if (overflow2(sizeof(unsigned char*), sy)) {
    gdFree(im);
    return NULL;
  }
  im = (gdImage*)gdMalloc(sizeof(gdImage));
  if (!im) {
    return NULL;
  }
  memset(im, 0, sizeof(gdImage));
  im->pixels = (unsigned char**)gdMalloc(sizeof(unsigned char*) * sy);
  if (!im->pixels) {
    gdFree(im);
    return NULL;
  }
  im->polyInts = 0;
  im->polyAllocated = 0;
  im->brush = 0;
  im->tile = 0;
  im->style = 0;
  for (i = 0; (i < sy); i++) {
    im->pixels[i] = (unsigned char*)gdCalloc(sx, sizeof(unsigned char));
    if (!im->pixels[i]) {
      for (--i; i >= 0; i--) {
        gdFree(im->pixels[i]);
      }
      gdFree(im);
      return NULL;
    }
  }
  im->sx = sx;
  im->sy = sy;
  im->colorsTotal = 0;
  im->transparent = (-1);
  im->interlace = 0;
  im->thick = 1;
  im->AA = 0;
  for (i = 0; (i < gdMaxColors); i++) {
    im->open[i] = 1;
    im->red[i] = 0;
    im->green[i] = 0;
    im->blue[i] = 0;
  };
  im->trueColor = 0;
  im->tpixels = 0;
  im->cx1 = 0;
  im->cy1 = 0;
  im->cx2 = im->sx - 1;
  im->cy2 = im->sy - 1;
  return im;
}

rdpdr_process(STREAM s) {
  uint32 handle;
  uint16 vmin;
  uint16 component;
  uint16 pakid;
  logger(Protocol, Debug, "rdpdr_process()");
  in_uint16(s, component);
  in_uint16(s, pakid);
  if (component == RDPDR_CTYP_CORE) {
    switch (pakid) {
      case PAKID_CORE_DEVICE_IOREQUEST:
        rdpdr_process_irp(s);
        break;
      case PAKID_CORE_SERVER_ANNOUNCE:
        in_uint8s(s, 2);
        in_uint16_le(s, vmin);
        in_uint32_le(s, g_client_id);
        if (vmin < 0x000c) g_client_id = 0x815ed39d;
        g_epoch++;
#if WITH_SCARD
        scard_release_all_contexts();
#endif
        rdpdr_send_client_announce_reply();
        rdpdr_send_client_name_request();
        break;
      case PAKID_CORE_CLIENTID_CONFIRM:
        rdpdr_send_client_device_list_announce();
        break;
      case PAKID_CORE_DEVICE_REPLY:
        in_uint32(s, handle);
        logger(Protocol, Debug,
               "rdpdr_process(), server connected to resource %d", handle);
        break;
      case PAKID_CORE_SERVER_CAPABILITY:
        rdpdr_send_client_capability_response();
        break;
      default:
        logger(Protocol, Debug, "rdpdr_process(), pakid 0x%x of component 0x%x",
               pakid, component);
        break;
    }
  } else if (component == RDPDR_CTYP_PRN) {
    if (pakid == PAKID_PRN_CACHE_DATA) printercache_process(s);
  } else
    logger(Protocol, Warning, "rdpdr_process(), unhandled component 0x%x",
           component);
}

int pipe_resize_ring(struct pipe_inode_info* pipe, unsigned int nr_slots) {
  struct pipe_buffer* bufs;
  unsigned int head, tail, mask, n;
  mask = pipe->ring_size - 1;
  head = pipe->head;
  tail = pipe->tail;
  n = pipe_occupancy(pipe->head, pipe->tail);
  if (nr_slots < n) return -EBUSY;
  bufs = kcalloc(nr_slots, sizeof(*bufs), GFP_KERNEL_ACCOUNT | __GFP_NOWARN);
  if (unlikely(!bufs)) return -ENOMEM;
  if (n > 0) {
    unsigned int h = head & mask;
    unsigned int t = tail & mask;
    if (h > t) {
      memcpy(bufs, pipe->bufs + t, n * sizeof(struct pipe_buffer));
    } else {
      unsigned int tsize = pipe->ring_size - t;
      if (h > 0)
        memcpy(bufs + tsize, pipe->bufs, h * sizeof(struct pipe_buffer));
      memcpy(bufs, pipe->bufs + t, tsize * sizeof(struct pipe_buffer));
    }
  }
  head = n;
  tail = 0;
  kfree(pipe->bufs);
  pipe->bufs = bufs;
  pipe->ring_size = nr_slots;
  if (pipe->max_usage > nr_slots) pipe->max_usage = nr_slots;
  pipe->tail = tail;
  pipe->head = head;
  wake_up_interruptible(&pipe->wr_wait);
  return 0;
}

int ossl_dsa_check_pairwise(const DSA* dsa) {
  int ret = 0;
  BN_CTX* ctx = NULL;
  BIGNUM* pub_key = NULL;
  if (dsa->params.p == NULL || dsa->params.g == NULL || dsa->priv_key == NULL ||
      dsa->pub_key == NULL)
    return 0;
  ctx = BN_CTX_new_ex(dsa->libctx);
  if (ctx == NULL) goto err;
  pub_key = BN_new();
  if (pub_key == NULL) goto err;
  if (!ossl_dsa_generate_public_key(ctx, dsa, dsa->priv_key, pub_key)) goto err;
  ret = BN_cmp(pub_key, dsa->pub_key) == 0;
err:
  BN_free(pub_key);
  BN_CTX_free(ctx);
  return ret;
}

CallResult<PseudoHandle<>> GeneratorInnerFunction::callInnerFunction(
    Handle<GeneratorInnerFunction> selfHandle, Runtime& runtime, Handle<> arg,
    Action action) {
  auto self = Handle<GeneratorInnerFunction>::vmcast(selfHandle);
  SmallHermesValue shv =
      SmallHermesValue::encodeHermesValue(arg.getHermesValue(), runtime);
  self->result_.set(shv, runtime.getHeap());
  self->action_ = action;
  auto ctx = runtime.makeMutableHandle(selfHandle->savedContext_);
  const uint32_t argCount = self->argCount_;
  HermesValue newTarget = HermesValue::encodeUndefinedValue();
  ScopedNativeCallFrame frame{runtime, argCount, selfHandle.getHermesValue(),
                              newTarget, ctx->at(0)};
  if (LLVM_UNLIKELY(frame.overflowed()))
    return runtime.raiseStackOverflow(Runtime::StackOverflowKind::NativeStack);
  for (ArrayStorage::size_type i = 0, e = argCount; i < e; ++i) {
    frame->getArgRef(i) = ctx->at(i + 1);
  }
  if (LLVM_UNLIKELY(selfHandle->getCodeBlock(runtime)->isLazy())) {
    selfHandle->getCodeBlock(runtime)->lazyCompile(runtime);
    if (LLVM_UNLIKELY(ArrayStorage::resize(
                          ctx, runtime,
                          getContextSize(selfHandle->getCodeBlock(runtime),
                                         selfHandle->argCount_)) ==
                      ExecutionStatus::EXCEPTION)) {
      return ExecutionStatus::EXCEPTION;
    }
    selfHandle->savedContext_.set(runtime, ctx.get(), runtime.getHeap());
  }
  return JSFunction::_callImpl(selfHandle, runtime);
}

int verify_compat_iovec(struct msghdr* kern_msg, struct iovec* kern_iov,
                        struct sockaddr_storage* kern_address, int mode) {
  int tot_len;
  if (kern_msg->msg_namelen) {
    if (mode == VERIFY_READ) {
      int err = move_addr_to_kernel(kern_msg->msg_name, kern_msg->msg_namelen,
                                    kern_address);
      if (err < 0) return err;
    }
    kern_msg->msg_name = kern_address;
  } else
    kern_msg->msg_name = NULL;
  tot_len = iov_from_user_compat_to_kern(
      kern_iov, (struct compat_iovec __user*)kern_msg->msg_iov,
      kern_msg->msg_iovlen);
  if (tot_len >= 0) kern_msg->msg_iov = kern_iov;
  return tot_len;
}

BGD_DECLARE(void) gdImageWebpCtx(gdImagePtr im, gdIOCtx* outfile, int quality) {
  uint8_t* argb;
  int x, y;
  uint8_t* p;
  uint8_t* out;
  size_t out_size;
  if (im == NULL) {
    return;
  }
  if (!gdImageTrueColor(im)) {
    gd_error("Paletter image not supported by webp");
    return;
  }
  if (quality == -1) {
    quality = 80;
  }
  if (overflow2(gdImageSX(im), 4)) {
    return;
  }
  if (overflow2(gdImageSX(im) * 4, gdImageSY(im))) {
    return;
  }
  argb = (uint8_t*)gdMalloc(gdImageSX(im) * 4 * gdImageSY(im));
  if (!argb) {
    return;
  }
  p = argb;
  for (y = 0; y < gdImageSY(im); y++) {
    for (x = 0; x < gdImageSX(im); x++) {
      register int c;
      register char a;
      c = im->tpixels[y][x];
      a = gdTrueColorGetAlpha(c);
      if (a == 127) {
        a = 0;
      } else {
        a = 255 - ((a << 1) + (a >> 6));
      }
      *(p++) = gdTrueColorGetRed(c);
      *(p++) = gdTrueColorGetGreen(c);
      *(p++) = gdTrueColorGetBlue(c);
      *(p++) = a;
    }
  }
  out_size = WebPEncodeRGBA(argb, gdImageSX(im), gdImageSY(im),
                            gdImageSX(im) * 4, quality, &out);
  if (out_size == 0) {
    gd_error("gd-webp encoding failed");
    goto freeargb;
  }
  gdPutBuf(out, out_size, outfile);
  free(out);
freeargb:
  gdFree(argb);
}

