}

Pl_AES_PDF::flush(bool strip_padding) {
  assert(this->offset == this->buf_size);
  if (first) {
    first = false;
    bool return_after_init = false;
    if (this->cbc_mode) {
      if (encrypt) {
        initializeVector();
        if (!(this->use_zero_iv || this->use_specified_iv)) {
          getNext()->write(this->cbc_block, this->buf_size);
        }
      } else if (this->use_zero_iv || this->use_specified_iv) {
        initializeVector();
      } else {
        memcpy(this->cbc_block, this->inbuf, this->buf_size);
        this->offset = 0;
        return_after_init = true;
      }
    }
    this->crypto->rijndael_init(encrypt, this->key.get(), key_bytes,
                                this->cbc_mode, this->cbc_block);
    if (return_after_init) {
      return;
    }
  }
  if (this->encrypt) {
    this->crypto->rijndael_process(this->inbuf, this->outbuf);
  } else {
    this->crypto->rijndael_process(this->inbuf, this->outbuf);
  }
  unsigned int bytes = this->buf_size;
  if (strip_padding) {
    unsigned char last = this->outbuf[this->buf_size - 1];
    if (last <= this->buf_size) {
      bool strip = true;
      for (unsigned int i = 1; i <= last; ++i) {
        if (this->outbuf[this->buf_size - i] != last) {
          strip = false;
          break;
        }
      }
      if (strip) {
        bytes -= last;
      }
    }
  }
  getNext()->write(this->outbuf, bytes);
  this->offset = 0;
}

static const char* jvp_literal_number_literal(jv n) {
  assert(JVP_HAS_FLAGS(n, JVP_FLAGS_NUMBER_LITERAL));
  decNumber* pdec = jvp_dec_number_ptr(n);
  jvp_literal_number* plit = jvp_literal_number_ptr(n);
  if (decNumberIsNaN(pdec)) {
    return "null";
  }
  if (decNumberIsInfinite(pdec)) {
    return NULL;
  }
  if (plit->literal_data == NULL) {
    int len = jvp_dec_number_ptr(n)->digits + 14;
    plit->literal_data = jv_mem_alloc(len);
    decNumberToString(pdec, plit->literal_data);
  }
  return plit->literal_data;
}

struct sctp_chunk* sctp_make_strreset_req(const struct sctp_association* asoc,
                                          __u16 stream_num, __be16* stream_list,
                                          bool out, bool in) {
  __u16 stream_len = stream_num * sizeof(__u16);
  struct sctp_strreset_outreq outreq;
  struct sctp_strreset_inreq inreq;
  struct sctp_chunk* retval;
  __u16 outlen, inlen;
  outlen = (sizeof(outreq) + stream_len) * out;
  inlen = (sizeof(inreq) + stream_len) * in;
  retval = sctp_make_reconf(asoc, outlen + inlen);
  if (!retval) return NULL;
  if (outlen) {
    outreq.param_hdr.type = SCTP_PARAM_RESET_OUT_REQUEST;
    outreq.param_hdr.length = htons(outlen);
    outreq.request_seq = htonl(asoc->strreset_outseq);
    outreq.response_seq = htonl(asoc->strreset_inseq - 1);
    outreq.send_reset_at_tsn = htonl(asoc->next_tsn - 1);
    sctp_addto_chunk(retval, sizeof(outreq), &outreq);
    if (stream_len) sctp_addto_chunk(retval, stream_len, stream_list);
  }
  if (inlen) {
    inreq.param_hdr.type = SCTP_PARAM_RESET_IN_REQUEST;
    inreq.param_hdr.length = htons(inlen);
    inreq.request_seq = htonl(asoc->strreset_outseq + out);
    sctp_addto_chunk(retval, sizeof(inreq), &inreq);
    if (stream_len) sctp_addto_chunk(retval, stream_len, stream_list);
  }
  return retval;
}

static ssize_t inotify_read(struct file* file, char __user* buf, size_t count,
                            loff_t* pos) {
  size_t event_size = sizeof(struct inotify_event);
  struct inotify_device* dev;
  char __user* start;
  int ret;
  DEFINE_WAIT(wait);
  start = buf;
  dev = file->private_data;
  while (1) {
    prepare_to_wait(&dev->wq, &wait, TASK_INTERRUPTIBLE);
    mutex_lock(&dev->ev_mutex);
    if (!list_empty(&dev->events)) {
      ret = 0;
      break;
    }
    mutex_unlock(&dev->ev_mutex);
    if (file->f_flags & O_NONBLOCK) {
      ret = -EAGAIN;
      break;
    }
    if (signal_pending(current)) {
      ret = -EINTR;
      break;
    }
    schedule();
  }
  finish_wait(&dev->wq, &wait);
  if (ret) return ret;
  while (1) {
    struct inotify_kernel_event* kevent;
    ret = buf - start;
    if (list_empty(&dev->events)) break;
    kevent = inotify_dev_get_event(dev);
    if (event_size + kevent->event.len > count) {
      if (ret == 0 && count > 0) {
        ret = -EINVAL;
      }
      break;
    }
    remove_kevent(dev, kevent);
    mutex_unlock(&dev->ev_mutex);
    if (copy_to_user(buf, &kevent->event, event_size)) {
      ret = -EFAULT;
      break;
    }
    buf += event_size;
    count -= event_size;
    if (kevent->name) {
      if (copy_to_user(buf, kevent->name, kevent->event.len)) {
        ret = -EFAULT;
        break;
      }
      buf += kevent->event.len;
      count -= kevent->event.len;
    }
    free_kevent(kevent);
    mutex_lock(&dev->ev_mutex);
  }
  mutex_unlock(&dev->ev_mutex);
  return ret;
}

static void parse_rtcp_bye(pjmedia_rtcp_session* sess, const void* pkt,
                           pj_size_t size) {
  pj_str_t reason = {"-", 1};
  if (size > 8) {
    reason.slen =
        PJ_MIN(sizeof(sess->stat.peer_sdes_buf_), *((pj_uint8_t*)pkt + 8));
    pj_memcpy(sess->stat.peer_sdes_buf_, ((pj_uint8_t*)pkt + 9), reason.slen);
    reason.ptr = sess->stat.peer_sdes_buf_;
  }
  PJ_LOG(5, (sess->name, "Received RTCP BYE, reason: %.*s", reason.slen,
             reason.ptr));
}

format_nstime_as_iso8601(gchar* buf, size_t buflen, const nstime_t* ns,
                         char* decimal_point, gboolean local, int precision) {
  struct tm tm, *tmp;
  gchar* ptr;
  size_t buf_remaining;
  int num_chars;
  if (local)
    tmp = ws_localtime_r(&ns->secs, &tm);
  else
    tmp = ws_gmtime_r(&ns->secs, &tm);
  if (tmp == NULL) {
    snprintf(buf, buflen, "Not representable");
    return;
  }
  ptr = buf;
  buf_remaining = buflen;
  num_chars = snprintf(ptr, buf_remaining, "%04d-%02d-%02d %02d:%02d:%02d",
                       tmp->tm_year + 1900, tmp->tm_mon + 1, tmp->tm_mday,
                       tmp->tm_hour, tmp->tm_min, tmp->tm_sec);
  if (num_chars < 0) {
    snprintf(buf, buflen, "snprintf() failed");
    return;
  }
  if ((unsigned int)num_chars >= buf_remaining) {
    return;
  }
  ptr += num_chars;
  buf_remaining -= num_chars;
  if (precision == 0) {
    return;
  }
  format_fractional_part_nsecs(ptr, buf_remaining, (guint32)ns->nsecs,
                               decimal_point, precision);
}

static bool __oom_reap_task_mm(struct task_struct* tsk, struct mm_struct* mm) {
  struct mmu_gather tlb;
  struct vm_area_struct* vma;
  bool ret = true;
  mutex_lock(&oom_lock);
  if (!down_read_trylock(&mm->mmap_sem)) {
    ret = false;
    trace_skip_task_reaping(tsk->pid);
    goto unlock_oom;
  }
  if (mm_has_notifiers(mm)) {
    up_read(&mm->mmap_sem);
    schedule_timeout_idle(HZ);
    goto unlock_oom;
  }
  if (test_bit(MMF_OOM_SKIP, &mm->flags)) {
    up_read(&mm->mmap_sem);
    trace_skip_task_reaping(tsk->pid);
    goto unlock_oom;
  }
  trace_start_task_reaping(tsk->pid);
  set_bit(MMF_UNSTABLE, &mm->flags);
  tlb_gather_mmu(&tlb, mm, 0, -1);
  for (vma = mm->mmap; vma; vma = vma->vm_next) {
    if (!can_madv_dontneed_vma(vma)) continue;
    if (vma_is_anonymous(vma) || !(vma->vm_flags & VM_SHARED))
      unmap_page_range(&tlb, vma, vma->vm_start, vma->vm_end, NULL);
  }
  tlb_finish_mmu(&tlb, 0, -1);
  pr_info(
      "oom_reaper: reaped process %d (%s), now anon-rss:%lukB, file-rss:%lukB, "
      "shmem-rss:%lukB\n",
      task_pid_nr(tsk), tsk->comm, K(get_mm_counter(mm, MM_ANONPAGES)),
      K(get_mm_counter(mm, MM_FILEPAGES)),
      K(get_mm_counter(mm, MM_SHMEMPAGES)));
  up_read(&mm->mmap_sem);
  trace_finish_task_reaping(tsk->pid);
unlock_oom:
  mutex_unlock(&oom_lock);
  return ret;
}

MOBI_RET mobi_trie_insert_infl(MOBITrie** root, const MOBIIndx* indx,
                               size_t i) {
  MOBIIndexEntry e = indx->entries[i];
  char* inflected = e.label;
  for (size_t j = 0; j < e.tags_count; j++) {
    MOBIIndexTag t = e.tags[j];
    if (t.tagid == INDX_TAGARR_INFL_PARTS_V1) {
      for (size_t k = 0; k < t.tagvalues_count - 1; k += 2) {
        uint32_t len = t.tagvalues[k];
        uint32_t offset = t.tagvalues[k + 1];
        char* base = mobi_get_cncx_string_flat(indx->cncx_record, offset, len);
        if (base == NULL) {
          return MOBI_MALLOC_FAILED;
        }
        MOBI_RET ret = mobi_trie_insert_reversed(root, base, inflected);
        free(base);
        if (ret != MOBI_SUCCESS) {
          return ret;
        }
      }
    }
  }
  return MOBI_SUCCESS;
}

static inline void mcryptd_check_internal(struct rtattr** tb, u32* type,
                                          u32* mask) {
