static size_t consume_init_expr(ut8* buf, ut8* max, ut8 eoc, void* out,
                                ut32* offset) {
  ut32 i = 0;
  while (buf + i < max && buf[i] != eoc) {
    i += 1;
  }
  if (buf[i] != eoc) {
    return 0;
  }
  if (offset) {
    *offset += i + 1;
  }
  return i + 1;
}

njs_function_frame_save(njs_vm_t* vm, njs_frame_t* frame, u_char* pc) {
  size_t value_count, n;
  njs_value_t *start, *end, *p, **new, *value, **local;
  njs_function_t* function;
  njs_native_frame_t *active, *native;
  *frame = *vm->active_frame;
  frame->previous_active_frame = NULL;
  native = &frame->native;
  active = &vm->active_frame->native;
  value_count = njs_function_frame_value_count(active);
  function = active->function;
  new = (njs_value_t**)((u_char*)native + NJS_FRAME_SIZE);
  value = (njs_value_t*)(new + value_count + function->u.lambda->temp);
  native->arguments = value;
  native->arguments_offset = value + (function->args_offset - 1);
  native->local = new + njs_function_frame_args_count(active);
  native->temp = new + value_count;
  native->pc = pc;
  start = njs_function_frame_values(active, &end);
  p = native->arguments;
  while (start < end) {
    *p = *start++;
    *new ++= p++;
  }
  p = native->arguments;
  local = native->local + function->args_offset;
  for (n = 0; n < function->args_count; n++) {
    if (!njs_is_valid(p)) {
      njs_set_undefined(p);
    }
    *local++ = p++;
  }
  return NJS_OK;
}

static int newque(struct ipc_namespace* ns, struct ipc_params* params) {
  struct msg_queue* msq;
  int id, retval;
  key_t key = params->key;
  int msgflg = params->flg;
  msq = ipc_rcu_alloc(sizeof(*msq));
  if (!msq) return -ENOMEM;
  msq->q_perm.mode = msgflg & S_IRWXUGO;
  msq->q_perm.key = key;
  msq->q_perm.security = NULL;
  retval = security_msg_queue_alloc(msq);
  if (retval) {
    ipc_rcu_putref(msq, ipc_rcu_free);
    return retval;
  }
  id = ipc_addid(&msg_ids(ns), &msq->q_perm, ns->msg_ctlmni);
  if (id < 0) {
    ipc_rcu_putref(msq, msg_rcu_free);
    return id;
  }
  msq->q_stime = msq->q_rtime = 0;
  msq->q_ctime = get_seconds();
  msq->q_cbytes = msq->q_qnum = 0;
  msq->q_qbytes = ns->msg_ctlmnb;
  msq->q_lspid = msq->q_lrpid = 0;
  INIT_LIST_HEAD(&msq->q_messages);
  INIT_LIST_HEAD(&msq->q_receivers);
  INIT_LIST_HEAD(&msq->q_senders);
  ipc_unlock_object(&msq->q_perm);
  rcu_read_unlock();
  return msq->q_perm.id;
}

static void tcp_mtu_probing(struct inet_connection_sock* icsk,
                            struct sock* sk) {
  const struct net* net = sock_net(sk);
  int mss;
  if (!net->ipv4.sysctl_tcp_mtu_probing) return;
  if (!icsk->icsk_mtup.enabled) {
    icsk->icsk_mtup.enabled = 1;
    icsk->icsk_mtup.probe_timestamp = tcp_jiffies32;
  } else {
    mss = tcp_mtu_to_mss(sk, icsk->icsk_mtup.search_low) >> 1;
    mss = min(net->ipv4.sysctl_tcp_base_mss, mss);
    mss = max(mss, 68 - tcp_sk(sk)->tcp_header_len);
    icsk->icsk_mtup.search_low = tcp_mss_to_mtu(sk, mss);
  }
  tcp_sync_mss(sk, icsk->icsk_pmtu_cookie);
}

Map1to1(SDL_Palette* src, SDL_Palette* dst, int* identical) {
  Uint8* map;
  int i;
  if (identical) {
    if (src->ncolors <= dst->ncolors) {
      if (src == dst || (SDL_memcmp(src->colors, dst->colors,
                                    src->ncolors * sizeof(SDL_Color)) == 0)) {
        *identical = 1;
        return (NULL);
      }
    }
    *identical = 0;
  }
  map = (Uint8*)SDL_malloc(src->ncolors);
  if (map == NULL) {
    SDL_OutOfMemory();
    return (NULL);
  }
  for (i = 0; i < src->ncolors; ++i) {
    map[i] = SDL_FindColor(dst, src->colors[i].r, src->colors[i].g,
                           src->colors[i].b, src->colors[i].a);
  }
  return (map);
}

Status BuildXlaCompilationCache(DeviceBase* device, FunctionLibraryRuntime* flr,
                                const XlaPlatformInfo& platform_info,
                                XlaCompilationCache** cache) {
  if (platform_info.xla_device_metadata()) {
    *cache = new XlaCompilationCache(
        platform_info.xla_device_metadata()->client(),
        platform_info.xla_device_metadata()->jit_device_type());
    return Status::OK();
  }
  auto platform =
      se::MultiPlatformManager::PlatformWithId(platform_info.platform_id());
  if (!platform.ok()) {
    return platform.status();
  }
  StatusOr<xla::Compiler*> compiler_for_platform =
      xla::Compiler::GetForPlatform(platform.ValueOrDie());
  if (!compiler_for_platform.ok()) {
    const Status& status = compiler_for_platform.status();
    if (status.code() == error::NOT_FOUND) {
      return errors::Unimplemented("Could not find compiler for platform ",
                                   platform.ValueOrDie()->Name(), ": ",
                                   status.ToString());
    }
  }
  xla::LocalClientOptions client_options;
  client_options.set_platform(platform.ValueOrDie());
  client_options.set_intra_op_parallelism_threads(
      device->tensorflow_cpu_worker_threads()->num_threads);
  string allowed_gpus =
      flr->config_proto()->gpu_options().visible_device_list();
  TF_ASSIGN_OR_RETURN(absl::optional<std::set<int>> gpu_ids,
                      ParseVisibleDeviceList(allowed_gpus));
  client_options.set_allowed_devices(gpu_ids);
  auto client = xla::ClientLibrary::GetOrCreateLocalClient(client_options);
  if (!client.ok()) {
    return client.status();
  }
  const XlaOpRegistry::DeviceRegistration* registration;
  if (!XlaOpRegistry::GetCompilationDevice(platform_info.device_type().type(),
                                           &registration)) {
    return errors::InvalidArgument("No JIT device registered for ",
                                   platform_info.device_type().type());
  }
  *cache = new XlaCompilationCache(
      client.ValueOrDie(), DeviceType(registration->compilation_device_name));
  return Status::OK();
}

messageAddArgument(message* m, const char* arg) {
  int offset;
  char* p;
  assert(m != NULL);
  if (arg == NULL) return;
  while (isspace(*arg)) arg++;
  if (*arg == '\0') return;
  cli_dbgmsg("messageAddArgument, arg='%s'\n", arg);
  if (!usefulArg(arg)) return;
  for (offset = 0; offset < m->numberOfArguments; offset++)
    if (m->mimeArguments[offset] == NULL)
      break;
    else if (strcasecmp(arg, m->mimeArguments[offset]) == 0)
      return;
  if (offset == m->numberOfArguments) {
    char** q;
    m->numberOfArguments++;
    q = (char**)cli_realloc(m->mimeArguments,
                            m->numberOfArguments * sizeof(char*));
    if (q == NULL) {
      m->numberOfArguments--;
      return;
    }
    m->mimeArguments = q;
  }
  p = m->mimeArguments[offset] = rfc2231(arg);
  if (!p) {
    cli_dbgmsg("messageAddArgument, error from rfc2231()\n");
    return;
  }
  if (strchr(p, '=') == NULL) {
    if (strncmp(p, "filename", 8) == 0) {
      cli_dbgmsg("Possible data corruption fixed\n");
      p[8] = '=';
    } else {
      if (*p) cli_dbgmsg("messageAddArgument, '%s' contains no '='\n", p);
      free(m->mimeArguments[offset]);
      m->mimeArguments[offset] = NULL;
      return;
    }
  }
  if ((strncasecmp(p, "filename=", 9) == 0) ||
      (strncasecmp(p, "name=", 5) == 0))
    if (messageGetMimeType(m) == NOMIME) {
      cli_dbgmsg("Force mime encoding to application\n");
      messageSetMimeType(m, "application");
    }
}

void luaD_call(lua_State* L, StkId func, int nresults) {
  lua_CFunction f;
retry:
  switch (ttypetag(s2v(func))) {
    case LUA_VCCL:
      f = clCvalue(s2v(func))->f;
      goto Cfunc;
    case LUA_VLCF:
      f = fvalue(s2v(func));
    Cfunc: {
      int n;
      CallInfo* ci = next_ci(L);
      checkstackp(L, LUA_MINSTACK, func);
      ci->nresults = nresults;
      ci->callstatus = CIST_C;
      ci->top = L->top + LUA_MINSTACK;
      ci->func = func;
      L->ci = ci;
      lua_assert(ci->top <= L->stack_last);
      if (L->hookmask & LUA_MASKCALL) {
        int narg = cast_int(L->top - func) - 1;
        luaD_hook(L, LUA_HOOKCALL, -1, 1, narg);
      }
      lua_unlock(L);
      n = (*f)(L);
      lua_lock(L);
      api_checknelems(L, n);
      luaD_poscall(L, ci, n);
      break;
    }
    case LUA_VLCL: {
      CallInfo* ci = next_ci(L);
      Proto* p = clLvalue(s2v(func))->p;
      int narg = cast_int(L->top - func) - 1;
      int nfixparams = p->numparams;
      int fsize = p->maxstacksize;
      checkstackp(L, fsize, func);
      ci->nresults = nresults;
      ci->u.l.savedpc = p->code;
      ci->callstatus = 0;
      ci->top = func + 1 + fsize;
      ci->func = func;
      L->ci = ci;
      for (; narg < nfixparams; narg++) setnilvalue(s2v(L->top++));
      lua_assert(ci->top <= L->stack_last);
      luaV_execute(L, ci);
      break;
    }
    default: {
      checkstackp(L, 1, func);
      luaD_tryfuncTM(L, func);
      goto retry;
    }
  }
}

static int override_release(char __user* release, int len) {
  int ret = 0;
  char buf[65];
  if (current->personality & UNAME26) {
    char* rest = UTS_RELEASE;
    int ndots = 0;
    unsigned v;
    while (*rest) {
      if (*rest == '.' && ++ndots >= 3) break;
      if (!isdigit(*rest) && *rest != '.') break;
      rest++;
    }
    v = ((LINUX_VERSION_CODE >> 8) & 0xff) + 40;
    snprintf(buf, len, "2.6.%u%s", v, rest);
    ret = copy_to_user(release, buf, len);
  }
  return ret;
}

static long madvise_willneed(struct vm_area_struct* vma,
                             struct vm_area_struct** prev, unsigned long start,
                             unsigned long end) {
  struct file* file = vma->vm_file;
#ifdef CONFIG_SWAP
  if (!file) {
    *prev = vma;
    force_swapin_readahead(vma, start, end);
    return 0;
  }
  if (shmem_mapping(file->f_mapping)) {
    *prev = vma;
    force_shm_swapin_readahead(vma, start, end, file->f_mapping);
    return 0;
  }
#else
  if (!file) return -EBADF;
#endif
  if (IS_DAX(file_inode(file))) {
    return 0;
  }
  *prev = vma;
  start = ((start - vma->vm_start) >> PAGE_SHIFT) + vma->vm_pgoff;
  if (end > vma->vm_end) end = vma->vm_end;
  end = ((end - vma->vm_start) >> PAGE_SHIFT) + vma->vm_pgoff;
  force_page_cache_readahead(file->f_mapping, file, start, end - start);
  return 0;
}

