_pdfioTokenGet(_pdfio_token_t* tb, char* buffer, size_t bufsize) {
  if (tb->num_tokens > 0) {
    tb->num_tokens--;
    strncpy(buffer, tb->tokens[tb->num_tokens], bufsize - 1);
    buffer[bufsize - 1] = '\0';
    PDFIO_DEBUG(
        "_pdfioTokenGet(tb=%p, buffer=%p, bufsize=%u): Popping '%s' from "
        "stack.\n",
        tb, buffer, (unsigned)bufsize, buffer);
    free(tb->tokens[tb->num_tokens]);
    tb->tokens[tb->num_tokens] = NULL;
    return (true);
  }
  return (_pdfioTokenRead(tb, buffer, bufsize));
}

status_t HevcParameterSets::addNalUnit(const uint8_t* data, size_t size) {
  uint8_t nalUnitType = (data[0] >> 1) & 0x3f;
  status_t err = OK;
  switch (nalUnitType) {
    case 32:
      err = parseVps(data + 2, size - 2);
      break;
    case 33:
      err = parseSps(data + 2, size - 2);
      break;
    case 34:
      err = parsePps(data + 2, size - 2);
      break;
    case 39:
    case 40:
      break;
    default:
      ALOGE("Unrecognized NAL unit type.");
      return ERROR_MALFORMED;
  }
  if (err != OK) {
    return err;
  }
  sp<ABuffer> buffer = ABuffer::CreateAsCopy(data, size);
  buffer->setInt32Data(nalUnitType);
  mNalUnits.push(buffer);
  return OK;
}

gdImagePtr gdImageCrop(gdImagePtr src, const gdRectPtr crop) {
  gdImagePtr dst;
  if (src->trueColor) {
    dst = gdImageCreateTrueColor(crop->width, crop->height);
    gdImageSaveAlpha(dst, 1);
  } else {
    dst = gdImageCreate(crop->width, crop->height);
    gdImagePaletteCopy(dst, src);
  }
  dst->transparent = src->transparent;
  if (src->sx < (crop->x + crop->width - 1)) {
    crop->width = src->sx - crop->x + 1;
  }
  if (src->sy < (crop->y + crop->height - 1)) {
    crop->height = src->sy - crop->y + 1;
  }
#if 0
printf("rect->x: %i\nrect->y: %i\nrect->width: %i\nrect->height: %i\n", crop->x, crop->y, crop->width, crop->height);
#endif
  if (dst == NULL) {
    return NULL;
  } else {
    int y = crop->y;
    if (src->trueColor) {
      unsigned int dst_y = 0;
      while (y < (crop->y + (crop->height - 1))) {
        memcpy(dst->tpixels[dst_y++], src->tpixels[y++] + crop->x,
               crop->width * 4);
      }
    } else {
      int x;
      for (y = crop->y; y < (crop->y + (crop->height - 1)); y++) {
        for (x = crop->x; x < (crop->x + (crop->width - 1)); x++) {
          dst->pixels[y - crop->y][x - crop->x] = src->pixels[y][x];
        }
      }
    }
    return dst;
  }
}

void prefetch_table(const void* tab, size_t len) {
  const volatile byte* vtab = tab;
  size_t i;
  for (i = 0; i < len; i += 8 * 32) {
    (void)vtab[i + 0 * 32];
    (void)vtab[i + 1 * 32];
    (void)vtab[i + 2 * 32];
    (void)vtab[i + 3 * 32];
    (void)vtab[i + 4 * 32];
    (void)vtab[i + 5 * 32];
    (void)vtab[i + 6 * 32];
    (void)vtab[i + 7 * 32];
  }
  (void)vtab[len - 1];
}

LayoutUnit RenderBox::availableLogicalHeightUsing(const Length& h) const {
  if (h.isFixed()) return computeContentBoxLogicalHeight(h.value());
  if (isRenderView())
    return isHorizontalWritingMode()
               ? toRenderView(this)->frameView()->visibleHeight()
               : toRenderView(this)->frameView()->visibleWidth();
  if (isTableCell() && (h.isAuto() || h.isPercent()))
    return overrideHeight() - borderAndPaddingLogicalWidth();
  if (h.isPercent())
    return computeContentBoxLogicalHeight(
        h.calcValue(containingBlock()->availableLogicalHeight()));
  if (isRenderBlock() && isPositioned() && style()->height().isAuto() &&
      !(style()->top().isAuto() || style()->bottom().isAuto())) {
    RenderBlock* block = const_cast<RenderBlock*>(toRenderBlock(this));
    LayoutUnit oldHeight = block->logicalHeight();
    block->computeLogicalHeight();
    LayoutUnit newHeight =
        block->computeContentBoxLogicalHeight(block->contentLogicalHeight());
    block->setLogicalHeight(oldHeight);
    return computeContentBoxLogicalHeight(newHeight);
  }
  return containingBlock()->availableLogicalHeight();
}

R_API st64 r_buf_fread_at(RBuffer* b, ut64 addr, ut8* buf, const char* fmt,
                          int n) {
  r_return_val_if_fail(b && buf && fmt, -1);
  st64 o_addr = r_buf_seek(b, 0, R_BUF_CUR);
  st64 r = r_buf_seek(b, addr, R_BUF_SET);
  if (r < 0) {
    return r;
  }
  r = r_buf_fread(b, buf, fmt, n);
  r_buf_seek(b, o_addr, R_BUF_SET);
  return r;
}

fribidi_cap_rtl_to_unicode(const char* s, FriBidiStrIndex len,
                           FriBidiChar* us) {
  FriBidiStrIndex i, j;
  if (!caprtl_to_unicode) init_cap_rtl();
  j = 0;
  for (i = 0; i < len; i++) {
    char ch;
    ch = s[i];
    if (ch == '_') {
      switch (ch = s[++i]) {
        case '>':
          us[j++] = FRIBIDI_CHAR_LRM;
          break;
        case '<':
          us[j++] = FRIBIDI_CHAR_RLM;
          break;
        case 'l':
          us[j++] = FRIBIDI_CHAR_LRE;
          break;
        case 'r':
          us[j++] = FRIBIDI_CHAR_RLE;
          break;
        case 'o':
          us[j++] = FRIBIDI_CHAR_PDF;
          break;
        case 'L':
          us[j++] = FRIBIDI_CHAR_LRO;
          break;
        case 'R':
          us[j++] = FRIBIDI_CHAR_RLO;
          break;
        case 'i':
          us[j++] = FRIBIDI_CHAR_LRI;
          break;
        case 'y':
          us[j++] = FRIBIDI_CHAR_RLI;
          break;
        case 'f':
          us[j++] = FRIBIDI_CHAR_FSI;
          break;
        case 'I':
          us[j++] = FRIBIDI_CHAR_PDI;
          break;
        case '_':
          us[j++] = '_';
          break;
        default:
          us[j++] = '_';
          i--;
          break;
      }
    } else
      us[j++] = caprtl_to_unicode[(int)s[i]];
  }
  return j;
}

static bool ParseSampler(Sampler* sampler, std::string* err, const json& o,
                         bool store_original_json_for_extras_and_extensions) {
  ParseStringProperty(&sampler->name, err, o, "name", false);
  int minFilter = -1;
  int magFilter = -1;
  int wrapS = TINYGLTF_TEXTURE_WRAP_REPEAT;
  int wrapT = TINYGLTF_TEXTURE_WRAP_REPEAT;
  ParseIntegerProperty(&minFilter, err, o, "minFilter", false);
  ParseIntegerProperty(&magFilter, err, o, "magFilter", false);
  ParseIntegerProperty(&wrapS, err, o, "wrapS", false);
  ParseIntegerProperty(&wrapT, err, o, "wrapT", false);
  sampler->minFilter = minFilter;
  sampler->magFilter = magFilter;
  sampler->wrapS = wrapS;
  sampler->wrapT = wrapT;
  ParseExtensionsProperty(&(sampler->extensions), err, o);
  ParseExtrasProperty(&(sampler->extras), o);
  if (store_original_json_for_extras_and_extensions) {
    {
      json_const_iterator it;
      if (FindMember(o, "extensions", it)) {
        sampler->extensions_json_string = JsonToString(GetValue(it));
      }
    }
    {
      json_const_iterator it;
      if (FindMember(o, "extras", it)) {
        sampler->extras_json_string = JsonToString(GetValue(it));
      }
    }
  }
  return true;
}

SRP_user_pwd* SRP_VBASE_get_by_user(SRP_VBASE* vb, char* username) {
  int i;
  SRP_user_pwd* user;
  unsigned char digv[SHA_DIGEST_LENGTH];
  unsigned char digs[SHA_DIGEST_LENGTH];
  EVP_MD_CTX* ctxt = NULL;
  if (vb == NULL) return NULL;
  for (i = 0; i < sk_SRP_user_pwd_num(vb->users_pwd); i++) {
    user = sk_SRP_user_pwd_value(vb->users_pwd, i);
    if (strcmp(user->id, username) == 0) return user;
  }
  if ((vb->seed_key == NULL) || (vb->default_g == NULL) ||
      (vb->default_N == NULL))
    return NULL;
  if ((user = SRP_user_pwd_new()) == NULL) return NULL;
  SRP_user_pwd_set_gN(user, vb->default_g, vb->default_N);
  if (!SRP_user_pwd_set_ids(user, username, NULL)) goto err;
  if (RAND_bytes(digv, SHA_DIGEST_LENGTH) <= 0) goto err;
  ctxt = EVP_MD_CTX_new();
  EVP_DigestInit_ex(ctxt, EVP_sha1(), NULL);
  EVP_DigestUpdate(ctxt, vb->seed_key, strlen(vb->seed_key));
  EVP_DigestUpdate(ctxt, username, strlen(username));
  EVP_DigestFinal_ex(ctxt, digs, NULL);
  EVP_MD_CTX_free(ctxt);
  ctxt = NULL;
  if (SRP_user_pwd_set_sv_BN(user, BN_bin2bn(digs, SHA_DIGEST_LENGTH, NULL),
                             BN_bin2bn(digv, SHA_DIGEST_LENGTH, NULL)))
    return user;
err:
  EVP_MD_CTX_free(ctxt);
  SRP_user_pwd_free(user);
  return NULL;
}

static bool access_pmu_evcntr(struct kvm_vcpu* vcpu, struct sys_reg_params* p,
                              const struct sys_reg_desc* r) {
  u64 idx;
  if (!kvm_arm_pmu_v3_ready(vcpu)) return trap_raz_wi(vcpu, p, r);
  if (r->CRn == 9 && r->CRm == 13) {
    if (r->Op2 == 2) {
      if (pmu_access_event_counter_el0_disabled(vcpu)) return false;
      idx = vcpu_sys_reg(vcpu, PMSELR_EL0) & ARMV8_PMU_COUNTER_MASK;
    } else if (r->Op2 == 0) {
      if (pmu_access_cycle_counter_el0_disabled(vcpu)) return false;
      idx = ARMV8_PMU_CYCLE_IDX;
    } else {
      BUG();
    }
  } else if (r->CRn == 14 && (r->CRm & 12) == 8) {
    if (pmu_access_event_counter_el0_disabled(vcpu)) return false;
    idx = ((r->CRm & 3) << 3) | (r->Op2 & 7);
  } else {
    BUG();
  }
  if (!pmu_counter_idx_valid(vcpu, idx)) return false;
  if (p->is_write) {
    if (pmu_access_el0_disabled(vcpu)) return false;
    kvm_pmu_set_counter_value(vcpu, idx, p->regval);
  } else {
    p->regval = kvm_pmu_get_counter_value(vcpu, idx);
  }
  return true;
}

convert_to_decimal(mpn_t a, size_t extra_zeroes) {
  mp_limb_t* a_ptr = a.limbs;
  size_t a_len = a.nlimbs;
  size_t c_len = 9 * ((size_t)(a_len * (GMP_LIMB_BITS * 0.03345f)) + 1);
  char* c_ptr = (char*)malloc(xsum(c_len, extra_zeroes));
  if (c_ptr != NULL) {
    char* d_ptr = c_ptr;
    for (; extra_zeroes > 0; extra_zeroes--) *d_ptr++ = '0';
    while (a_len > 0) {
      mp_limb_t remainder = 0;
      mp_limb_t* ptr = a_ptr + a_len;
      size_t count;
      for (count = a_len; count > 0; count--) {
        mp_twolimb_t num = ((mp_twolimb_t)remainder << GMP_LIMB_BITS) | *--ptr;
        *ptr = num / 1000000000;
        remainder = num % 1000000000;
      }
      for (count = 9; count > 0; count--) {
        *d_ptr++ = '0' + (remainder % 10);
        remainder = remainder / 10;
      }
      if (a_ptr[a_len - 1] == 0) a_len--;
    }
    while (d_ptr > c_ptr && d_ptr[-1] == '0') d_ptr--;
    if (d_ptr == c_ptr) *d_ptr++ = '0';
    *d_ptr = '\0';
  }
  return c_ptr;
}

xfs_attr_shortform_addname(xfs_da_args_t* args) {
  int newsize, forkoff, retval;
  trace_xfs_attr_sf_addname(args);
  retval = xfs_attr_shortform_lookup(args);
  if ((args->flags & ATTR_REPLACE) && (retval == -ENOATTR)) {
    return retval;
  } else if (retval == -EEXIST) {
    if (args->flags & ATTR_CREATE) return retval;
    retval = xfs_attr_shortform_remove(args);
    ASSERT(retval == 0);
  }
  if (args->namelen >= XFS_ATTR_SF_ENTSIZE_MAX ||
      args->valuelen >= XFS_ATTR_SF_ENTSIZE_MAX)
    return -ENOSPC;
  newsize = XFS_ATTR_SF_TOTSIZE(args->dp);
  newsize += XFS_ATTR_SF_ENTSIZE_BYNAME(args->namelen, args->valuelen);
  forkoff = xfs_attr_shortform_bytesfit(args->dp, newsize);
  if (!forkoff) return -ENOSPC;
  xfs_attr_shortform_add(args, forkoff);
  return 0;
}

static char* getPreferredTag(const char* gf_tag) {
  char* result = NULL;
  int grOffset = 0;
  grOffset = findOffset(LOC_GRANDFATHERED, gf_tag);
  if (grOffset < 0) {
    return NULL;
  }
  if (grOffset < LOC_PREFERRED_GRANDFATHERED_LEN) {
    result = estrdup(LOC_PREFERRED_GRANDFATHERED[grOffset]);
  } else {
    result = estrdup(LOC_GRANDFATHERED[grOffset]);
  }
  return result;
}

static int ssl_parse_supported_elliptic_curves(ssl_context* ssl,
                                               const unsigned char* buf,
                                               size_t len) {
  size_t list_size, our_size;
  const unsigned char* p;
  const ecp_curve_info *curve_info, **curves;
  list_size = ((buf[0] << 8) | (buf[1]));
  if (list_size + 2 != len || list_size % 2 != 0) {
    SSL_DEBUG_MSG(1, ("bad client hello message"));
    return (POLARSSL_ERR_SSL_BAD_HS_CLIENT_HELLO);
  }
  our_size = list_size / 2 + 1;
  if (our_size > POLARSSL_ECP_DP_MAX) our_size = POLARSSL_ECP_DP_MAX;
  if ((curves = polarssl_malloc(our_size * sizeof(*curves))) == NULL)
    return (POLARSSL_ERR_SSL_MALLOC_FAILED);
  memset((void*)curves, 0, our_size * sizeof(*curves));
  ssl->handshake->curves = curves;
  p = buf + 2;
  while (list_size > 0 && our_size > 1) {
    curve_info = ecp_curve_info_from_tls_id((p[0] << 8) | p[1]);
    if (curve_info != NULL) {
      *curves++ = curve_info;
      our_size--;
    }
    list_size -= 2;
    p += 2;
  }
  return (0);
}

static inline void encode_openhdr(struct xdr_stream* xdr,
                                  const struct nfs_openargs* arg) {
  __be32* p;
  RESERVE_SPACE(8);
  WRITE32(OP_OPEN);
  WRITE32(arg->seqid->sequence->counter);
  encode_share_access(xdr, arg->open_flags);
  RESERVE_SPACE(28);
  WRITE64(arg->clientid);
  WRITE32(16);
  WRITEMEM("open id:", 8);
  WRITE64(arg->id);
}

int HttpFileImpl::save(const std::string& path) const {
  assert(!path.empty());
  if (fileName_.empty()) return -1;
  filesystem::path fsPath(utils::toNativePath(path));
  if (!fsPath.is_absolute() &&
      (!fsPath.has_parent_path() ||
       (fsPath.begin()->string() != "." && fsPath.begin()->string() != ".."))) {
    filesystem::path fsUploadPath(
        utils::toNativePath(HttpAppFrameworkImpl::instance().getUploadPath()));
    fsPath = fsUploadPath / fsPath;
  }
  filesystem::path fsFileName(utils::toNativePath(fileName_));
  if (!filesystem::exists(fsPath)) {
    LOG_TRACE << "create path:" << fsPath;
    drogon::error_code err;
    filesystem::create_directories(fsPath, err);
    if (err) {
      LOG_SYSERR;
      return -1;
    }
  }
  return saveTo(fsPath / fsFileName);
}

static int l2tp_ip_recvmsg(struct kiocb* iocb, struct sock* sk,
                           struct msghdr* msg, size_t len, int noblock,
                           int flags, int* addr_len) {
  struct inet_sock* inet = inet_sk(sk);
  size_t copied = 0;
  int err = -EOPNOTSUPP;
  struct sockaddr_in* sin = (struct sockaddr_in*)msg->msg_name;
  struct sk_buff* skb;
  if (flags & MSG_OOB) goto out;
  if (addr_len) *addr_len = sizeof(*sin);
  skb = skb_recv_datagram(sk, flags, noblock, &err);
  if (!skb) goto out;
  copied = skb->len;
  if (len < copied) {
    msg->msg_flags |= MSG_TRUNC;
    copied = len;
  }
  err = skb_copy_datagram_iovec(skb, 0, msg->msg_iov, copied);
  if (err) goto done;
  sock_recv_timestamp(msg, sk, skb);
  if (sin) {
    sin->sin_family = AF_INET;
    sin->sin_addr.s_addr = ip_hdr(skb)->saddr;
    sin->sin_port = 0;
    memset(&sin->sin_zero, 0, sizeof(sin->sin_zero));
  }
  if (inet->cmsg_flags) ip_cmsg_recv(msg, skb);
  if (flags & MSG_TRUNC) copied = skb->len;
done:
  skb_free_datagram(sk, skb);
out:
  return err ? err : copied;
}

NOEXPORT int verify_callback(int preverify_ok, X509_STORE_CTX* callback_ctx) {
  SSL* ssl;
  CLI* c;
  ssl = X509_STORE_CTX_get_ex_data(callback_ctx,
                                   SSL_get_ex_data_X509_STORE_CTX_idx());
  c = SSL_get_ex_data(ssl, index_ssl_cli);
  if (!c->opt->option.verify_chain && !c->opt->option.verify_peer) {
    s_log(LOG_INFO, "Certificate verification disabled");
    return 1;
  }
  if (verify_checks(c, preverify_ok, callback_ctx)) {
    SSL_SESSION* sess = SSL_get1_session(c->ssl);
    if (sess) {
      int ok = SSL_SESSION_set_ex_data(sess, index_session_authenticated,
                                       (void*)(-1));
      SSL_SESSION_free(sess);
      if (!ok) {
        sslerror("SSL_SESSION_set_ex_data");
        return 0;
      }
    }
    return 1;
  }
  if (c->opt->option.client || c->opt->protocol) return 0;
  if (c->opt->redirect_addr.names) return 1;
  return 0;
}

