static int virtio_gpu_object_shmem_init(struct virtio_gpu_device* vgdev,
                                        struct virtio_gpu_object* bo,
                                        struct virtio_gpu_mem_entry** ents,
                                        unsigned int* nents) {
  bool use_dma_api = !virtio_has_dma_quirk(vgdev->vdev);
  struct virtio_gpu_object_shmem* shmem = to_virtio_gpu_shmem(bo);
  struct scatterlist* sg;
  int si, ret;
  ret = drm_gem_shmem_pin(&bo->base);
  if (ret < 0) return -EINVAL;
  shmem->pages = drm_gem_shmem_get_sg_table(&bo->base);
  if (!shmem->pages) {
    drm_gem_shmem_unpin(&bo->base);
    return -EINVAL;
  }
  if (use_dma_api) {
    ret = dma_map_sgtable(vgdev->vdev->dev.parent, shmem->pages, DMA_TO_DEVICE,
                          0);
    if (ret) return ret;
    *nents = shmem->mapped = shmem->pages->nents;
  } else {
    *nents = shmem->pages->orig_nents;
  }
  *ents =
      kvmalloc_array(*nents, sizeof(struct virtio_gpu_mem_entry), GFP_KERNEL);
  if (!(*ents)) {
    DRM_ERROR("failed to allocate ent list\n");
    return -ENOMEM;
  }
  if (use_dma_api) {
    for_each_sgtable_dma_sg(shmem->pages, sg, si) {
      (*ents)[si].addr = cpu_to_le64(sg_dma_address(sg));
      (*ents)[si].length = cpu_to_le32(sg_dma_len(sg));
      (*ents)[si].padding = 0;
    }
  } else {
    for_each_sgtable_sg(shmem->pages, sg, si) {
      (*ents)[si].addr = cpu_to_le64(sg_phys(sg));
      (*ents)[si].length = cpu_to_le32(sg->length);
      (*ents)[si].padding = 0;
    }
  }
  return 0;
}

B44Compressor::B44Compressor(const Header& hdr, size_t maxScanLineSize,
                             size_t numScanLines, bool optFlatFields)
    : Compressor(hdr),
      _maxScanLineSize(maxScanLineSize),
      _optFlatFields(optFlatFields),
      _format(XDR),
      _numScanLines(numScanLines),
      _tmpBuffer(0),
      _outBuffer(0),
      _numChans(0),
      _channels(hdr.channels()),
      _channelData(0) {
  (void)_maxScanLineSize;
  _tmpBuffer = new unsigned short[checkArraySize(
      uiMult(maxScanLineSize, numScanLines), sizeof(unsigned short))];
  const ChannelList& channels = header().channels();
  int numHalfChans = 0;
  for (ChannelList::ConstIterator c = channels.begin(); c != channels.end();
       ++c) {
    assert(pixelTypeSize(c.channel().type) % pixelTypeSize(HALF) == 0);
    ++_numChans;
    if (c.channel().type == HALF) ++numHalfChans;
  }
  size_t padding = 12 * numHalfChans * (numScanLines + 3) / 4;
  _outBuffer = new char[uiAdd(uiMult(maxScanLineSize, numScanLines), padding)];
  _channelData = new ChannelData[_numChans];
  int i = 0;
  for (ChannelList::ConstIterator c = channels.begin(); c != channels.end();
       ++c, ++i) {
    _channelData[i].ys = c.channel().ySampling;
    _channelData[i].type = c.channel().type;
    _channelData[i].pLinear = c.channel().pLinear;
    _channelData[i].size =
        pixelTypeSize(c.channel().type) / pixelTypeSize(HALF);
  }
  const Box2i& dataWindow = hdr.dataWindow();
  _minX = dataWindow.min.x;
  _maxX = dataWindow.max.x;
  _maxY = dataWindow.max.y;
  assert(sizeof(unsigned short) == pixelTypeSize(HALF));
  if (_numChans == numHalfChans) _format = NATIVE;
}

nft_meta_get_eval_time(enum nft_meta_keys key, u32* dest) {
