static void ipmr_destroy_unres(struct mfc_cache* c) {
  struct sk_buff* skb;
  atomic_dec(&cache_resolve_queue_len);
  while ((skb = skb_dequeue(&c->mfc_un.unres.unresolved))) {
    if (skb->nh.iph->version == 0) {
      struct nlmsghdr* nlh =
          (struct nlmsghdr*)skb_pull(skb, sizeof(struct iphdr));
      nlh->nlmsg_type = NLMSG_ERROR;
      nlh->nlmsg_len = NLMSG_LENGTH(sizeof(struct nlmsgerr));
      skb_trim(skb, nlh->nlmsg_len);
      ((struct nlmsgerr*)NLMSG_DATA(nlh))->error = -ETIMEDOUT;
      netlink_unicast(rtnl, skb, NETLINK_CB(skb).dst_pid, MSG_DONTWAIT);
    } else
      kfree_skb(skb);
  }
  kmem_cache_free(mrt_cachep, c);
}

MONGO_EXPORT int bson_append_regex(bson* b, const char* name,
                                   const char* pattern, const char* opts) {
  const int plen = strlen(pattern) + 1;
  const int olen = strlen(opts) + 1;
  if (bson_append_estart(b, BSON_REGEX, name, plen + olen) == BSON_ERROR)
    return BSON_ERROR;
  if (bson_check_string(b, pattern, plen - 1) == BSON_ERROR) return BSON_ERROR;
  bson_append(b, pattern, plen);
  bson_append(b, opts, olen);
  return BSON_OK;
}

static void setup_private_mount(const char* snap_name) {
  uid_t uid = getuid();
  gid_t gid = getgid();
  char tmpdir[MAX_BUF] = {0};
  sc_must_snprintf(tmpdir, sizeof(tmpdir), "/tmp/snap.%s_XXXXXX", snap_name);
  if (mkdtemp(tmpdir) == NULL) {
    die("cannot create temporary directory essential for private /tmp");
  }
  mode_t old_mask = umask(0);
  char* d = sc_strdup(tmpdir);
  sc_must_snprintf(tmpdir, sizeof(tmpdir), "%s/tmp", d);
  free(d);
  if (mkdir(tmpdir, 01777) != 0) {
    die("cannot create temporary directory for private /tmp");
  }
  umask(old_mask);
  char* pwd = get_current_dir_name();
  if (pwd == NULL) die("cannot get current working directory");
  if (chdir("/") != 0) die("cannot change directory to '/'");
  sc_do_mount(tmpdir, "/tmp", NULL, MS_BIND, NULL);
  sc_do_mount("none", "/tmp", NULL, MS_PRIVATE, NULL);
  if (chown("/tmp/", uid, gid) < 0) {
    die("cannot change ownership of /tmp");
  }
  if (chdir(pwd) != 0)
    die("cannot change current working directory to the original directory");
  free(pwd);
}

void GHASH::key_schedule(std::span<const uint8_t> key) {
  m_H.assign(key.begin(), key.end());
  m_H_ad.resize(GCM_BS);
  m_ad_len = 0;
  m_text_len = 0;
  uint64_t H0 = load_be<uint64_t>(m_H.data(), 0);
  uint64_t H1 = load_be<uint64_t>(m_H.data(), 1);
  const uint64_t R = 0xE100000000000000;
  m_HM.resize(256);
  for (size_t i = 0; i != 2; ++i) {
    for (size_t j = 0; j != 64; ++j) {
      m_HM[4 * j + 2 * i] = H0;
      m_HM[4 * j + 2 * i + 1] = H1;
      const uint64_t carry = R * (H1 & 1);
      H1 = (H1 >> 1) | (H0 << 63);
      H0 = (H0 >> 1) ^ carry;
    }
  }
#if defined(BOTAN_HAS_GHASH_CLMUL_CPU)
  if (CPUID::has_carryless_multiply()) {
    m_H_pow.resize(8);
    ghash_precompute_cpu(m_H.data(), m_H_pow.data());
  }
#endif
}

base_sock_create(struct net* net, struct socket* sock, int protocol, int kern) {
  struct sock* sk;
  if (sock->type != SOCK_RAW) return -ESOCKTNOSUPPORT;
  sk = sk_alloc(net, PF_ISDN, GFP_KERNEL, &mISDN_proto, kern);
  if (!sk) return -ENOMEM;
  sock_init_data(sock, sk);
  sock->ops = &base_sock_ops;
  sock->state = SS_UNCONNECTED;
  sock_reset_flag(sk, SOCK_ZAPPED);
  sk->sk_protocol = protocol;
  sk->sk_state = MISDN_OPEN;
  mISDN_sock_link(&base_sockets, sk);
  return 0;
}

htmlParsePubidLiteral(htmlParserCtxtPtr ctxt) {
  const xmlChar* q;
  xmlChar* ret = NULL;
  if (CUR == '"') {
    NEXT;
    q = CUR_PTR;
    while (IS_PUBIDCHAR_CH(CUR)) NEXT;
    if (CUR != '"') {
      htmlParseErr(ctxt, XML_ERR_LITERAL_NOT_FINISHED,
                   "Unfinished PubidLiteral\n", NULL, NULL);
    } else {
      ret = xmlStrndup(q, CUR_PTR - q);
      NEXT;
    }
  } else if (CUR == '\'') {
    NEXT;
    q = CUR_PTR;
    while ((IS_PUBIDCHAR_CH(CUR)) && (CUR != '\'')) NEXT;
    if (CUR != '\'') {
      htmlParseErr(ctxt, XML_ERR_LITERAL_NOT_FINISHED,
                   "Unfinished PubidLiteral\n", NULL, NULL);
    } else {
      ret = xmlStrndup(q, CUR_PTR - q);
      NEXT;
    }
  } else {
    htmlParseErr(ctxt, XML_ERR_LITERAL_NOT_STARTED,
                 "PubidLiteral \" or ' expected\n", NULL, NULL);
  }
  return (ret);
}

static void mdbEvalSetColumn(MyDbEvalContext* p, int iCol, Jsi_DString* dStr) {
  char nbuf[200];
  MysqlPrep* prep = p->prep;
  SqlFieldResults* field = prep->fieldResult + iCol;
  Jsi_Interp* interp = p->jdb->interp;
  if (field->isnull) return;
  switch (field->jsiTypeMap) {
    case JSI_OPTION_STRING: {
      int bytes = field->len;
      const char* zBlob = field->buffer.vstring;
      if (!zBlob) {
        const char* nv = p->jdb->optPtr->nullvalue;
        Jsi_DSAppend(dStr, nv ? nv : "null", NULL);
        return;
      }
      Jsi_DSAppendLen(dStr, zBlob, bytes);
      return;
    }
    case JSI_OPTION_BOOL: {
      snprintf(nbuf, sizeof(nbuf), "%s",
               field->buffer.vchar ? "true" : "false");
      Jsi_DSAppend(dStr, nbuf, NULL);
      return;
    }
    case JSI_OPTION_INT64: {
      snprintf(nbuf, sizeof(nbuf), "%lld", field->buffer.vlonglong);
      Jsi_DSAppend(dStr, nbuf, NULL);
      return;
    }
    case JSI_OPTION_TIME_D:
    case JSI_OPTION_TIME_W: {
      Jsi_Number jtime = mdbMyTimeToJS(&field->buffer.timestamp);
      Jsi_NumberToString(interp, jtime, nbuf, sizeof(nbuf));
      Jsi_DSAppend(dStr, nbuf, NULL);
      return;
    }
    case JSI_OPTION_DOUBLE: {
      Jsi_NumberToString(interp, field->buffer.vdouble, nbuf, sizeof(nbuf));
      Jsi_DSAppend(dStr, nbuf, NULL);
      return;
    }
    default:
      Jsi_LogWarn("unknown type: %d", field->jsiTypeMap);
  }
}

allocate_trace_buffer(struct trace_array* tr, struct trace_buffer* buf,
                      int size) {
  enum ring_buffer_flags rb_flags;
  rb_flags = tr->trace_flags & TRACE_ITER_OVERWRITE ? RB_FL_OVERWRITE : 0;
  buf->tr = tr;
  buf->buffer = ring_buffer_alloc(size, rb_flags);
  if (!buf->buffer) return -ENOMEM;
  buf->data = alloc_percpu(struct trace_array_cpu);
  if (!buf->data) {
    ring_buffer_free(buf->buffer);
    return -ENOMEM;
  }
  set_buffer_entries(&tr->trace_buffer,
                     ring_buffer_size(tr->trace_buffer.buffer, 0));
  return 0;
}

lldp_mgmt_addr_tlv_print(netdissect_options* ndo, const u_char* pptr,
                         u_int len) {
  uint8_t mgmt_addr_len, intf_num_subtype, oid_len;
  const u_char* tptr;
  u_int tlen;
  char* mgmt_addr;
  tlen = len;
  tptr = pptr;
  if (tlen < 1) {
    return 0;
  }
  mgmt_addr_len = *tptr++;
  tlen--;
  if (tlen < mgmt_addr_len) {
    return 0;
  }
  mgmt_addr = lldp_network_addr_print(ndo, tptr, mgmt_addr_len);
  if (mgmt_addr == NULL) {
    return 0;
  }
  ND_PRINT((ndo, "\n\t  Management Address length %u, %s", mgmt_addr_len,
            mgmt_addr));
  tptr += mgmt_addr_len;
  tlen -= mgmt_addr_len;
  if (tlen < LLDP_INTF_NUM_LEN) {
    return 0;
  }
  intf_num_subtype = *tptr;
  ND_PRINT((ndo, "\n\t  %s Interface Numbering (%u): %u",
            tok2str(lldp_intf_numb_subtype_values, "Unknown", intf_num_subtype),
            intf_num_subtype, EXTRACT_32BITS(tptr + 1)));
  tptr += LLDP_INTF_NUM_LEN;
  tlen -= LLDP_INTF_NUM_LEN;
  if (tlen) {
    oid_len = *tptr;
    if (tlen < oid_len) {
      return 0;
    }
    if (oid_len) {
      ND_PRINT((ndo, "\n\t  OID length %u", oid_len));
      safeputs(ndo, tptr + 1, oid_len);
    }
  }
  return 1;
}

compat_cipher_proposal(struct ssh* ssh, char* cipher_prop) {
  if (!(ssh->compat & SSH_BUG_BIGENDIANAES)) return cipher_prop;
  debug2_f("original cipher proposal: %s", cipher_prop);
  if ((cipher_prop = match_filter_denylist(cipher_prop, "aes*")) == NULL)
    fatal("match_filter_denylist failed");
  debug2_f("compat cipher proposal: %s", cipher_prop);
  if (*cipher_prop == '\0') fatal("No supported ciphers found");
  return cipher_prop;
}

static bool TryParse(const char* inp, int length, TypedValue* buf, Variant& out,
                     JSONContainerType container_type, bool is_tsimplejson) {
  SimpleParser parser(inp, length, buf, container_type, is_tsimplejson);
  bool ok = parser.parseValue();
  parser.skipSpace();
  if (!ok || parser.p != inp + length) {
    tvDecRefRange(buf, parser.top);
    return false;
  }
  out = Variant::attach(*--parser.top);
  return true;
}

vhost_scsi_make_tpg(struct se_wwn* wwn, struct config_group* group,
                    const char* name) {
  struct vhost_scsi_tport* tport =
      container_of(wwn, struct vhost_scsi_tport, tport_wwn);
  struct vhost_scsi_tpg* tpg;
  unsigned long tpgt;
  int ret;
  if (strstr(name, "tpgt_") != name) return ERR_PTR(-EINVAL);
  if (kstrtoul(name + 5, 10, &tpgt) || tpgt > UINT_MAX) return ERR_PTR(-EINVAL);
  tpg = kzalloc(sizeof(struct vhost_scsi_tpg), GFP_KERNEL);
  if (!tpg) {
    pr_err("Unable to allocate struct vhost_scsi_tpg");
    return ERR_PTR(-ENOMEM);
  }
  mutex_init(&tpg->tv_tpg_mutex);
  INIT_LIST_HEAD(&tpg->tv_tpg_list);
  tpg->tport = tport;
  tpg->tport_tpgt = tpgt;
  ret = core_tpg_register(&vhost_scsi_fabric_configfs->tf_ops, wwn,
                          &tpg->se_tpg, tpg, TRANSPORT_TPG_TYPE_NORMAL);
  if (ret < 0) {
    kfree(tpg);
    return NULL;
  }
  mutex_lock(&vhost_scsi_mutex);
  list_add_tail(&tpg->tv_tpg_list, &vhost_scsi_list);
  mutex_unlock(&vhost_scsi_mutex);
  return &tpg->se_tpg;
}

static bool __oom_reap_task_mm(struct task_struct* tsk, struct mm_struct* mm) {
  struct mmu_gather tlb;
  struct vm_area_struct* vma;
  bool ret = true;
  mutex_lock(&oom_lock);
  if (!down_read_trylock(&mm->mmap_sem)) {
    ret = false;
    trace_skip_task_reaping(tsk->pid);
    goto unlock_oom;
  }
  if (mm_has_notifiers(mm)) {
    up_read(&mm->mmap_sem);
    schedule_timeout_idle(HZ);
    goto unlock_oom;
  }
  if (test_bit(MMF_OOM_SKIP, &mm->flags)) {
    up_read(&mm->mmap_sem);
    trace_skip_task_reaping(tsk->pid);
    goto unlock_oom;
  }
  trace_start_task_reaping(tsk->pid);
  set_bit(MMF_UNSTABLE, &mm->flags);
  tlb_gather_mmu(&tlb, mm, 0, -1);
  for (vma = mm->mmap; vma; vma = vma->vm_next) {
    if (!can_madv_dontneed_vma(vma)) continue;
    if (vma_is_anonymous(vma) || !(vma->vm_flags & VM_SHARED))
      unmap_page_range(&tlb, vma, vma->vm_start, vma->vm_end, NULL);
  }
  tlb_finish_mmu(&tlb, 0, -1);
  pr_info(
      "oom_reaper: reaped process %d (%s), now anon-rss:%lukB, file-rss:%lukB, "
      "shmem-rss:%lukB\n",
      task_pid_nr(tsk), tsk->comm, K(get_mm_counter(mm, MM_ANONPAGES)),
      K(get_mm_counter(mm, MM_FILEPAGES)),
      K(get_mm_counter(mm, MM_SHMEMPAGES)));
  up_read(&mm->mmap_sem);
  trace_finish_task_reaping(tsk->pid);
unlock_oom:
  mutex_unlock(&oom_lock);
  return ret;
}

ChildProcessTerminationInfo ChildProcessLauncherHelper::GetTerminationInfo(
    const ChildProcessLauncherHelper::Process& process, bool known_dead) {
  ChildProcessTerminationInfo info;
  if (!java_peer_avaiable_on_client_thread_) return info;
  Java_ChildProcessLauncherHelperImpl_getTerminationInfo(
      AttachCurrentThread(), java_peer_, reinterpret_cast<intptr_t>(&info));
  base::android::ApplicationState app_state =
      base::android::ApplicationStatusListener::GetState();
  bool app_foreground =
      app_state == base::android::APPLICATION_STATE_HAS_RUNNING_ACTIVITIES ||
      app_state == base::android::APPLICATION_STATE_HAS_PAUSED_ACTIVITIES;
  if (app_foreground &&
      (info.binding_state == base::android::ChildBindingState::MODERATE ||
       info.binding_state == base::android::ChildBindingState::STRONG)) {
    info.status = base::TERMINATION_STATUS_OOM_PROTECTED;
  } else {
    info.status = base::TERMINATION_STATUS_NORMAL_TERMINATION;
  }
  return info;
}

writefile(const char* name, struct string* s) {
  FILE* f;
  int ret;
  f = fopen(name, "w");
  if (!f) {
    warn("open %s:", name);
    return -1;
  }
  ret = 0;
  if (fwrite(s->s, 1, s->n, f) != s->n || fflush(f) != 0) {
    warn("write %s:", name);
    ret = -1;
  }
  fclose(f);
  return ret;
}

rsock_init_unixsock(VALUE sock, VALUE path, int server) {
  struct sockaddr_un sockaddr;
  socklen_t sockaddrlen;
  int fd, status;
  rb_io_t* fptr;
  FilePathValue(path);
  INIT_SOCKADDR_UN(&sockaddr, sizeof(struct sockaddr_un));
  if (sizeof(sockaddr.sun_path) < (size_t)RSTRING_LEN(path)) {
    rb_raise(rb_eArgError,
             "too long unix socket path (%ldbytes given but %dbytes max)",
             RSTRING_LEN(path), (int)sizeof(sockaddr.sun_path));
  }
  memcpy(sockaddr.sun_path, RSTRING_PTR(path), RSTRING_LEN(path));
  sockaddrlen = rsock_unix_sockaddr_len(path);
  fd = rsock_socket(AF_UNIX, SOCK_STREAM, 0);
  if (fd < 0) {
    rsock_sys_fail_path("socket(2)", path);
  }
  if (server) {
    status = bind(fd, (struct sockaddr*)&sockaddr, sockaddrlen);
  } else {
    int prot;
    struct unixsock_arg arg;
    arg.sockaddr = &sockaddr;
    arg.sockaddrlen = sockaddrlen;
    arg.fd = fd;
    status = (int)rb_protect(unixsock_connect_internal, (VALUE)&arg, &prot);
    if (prot) {
      close(fd);
      rb_jump_tag(prot);
    }
  }
  if (status < 0) {
    int e = errno;
    close(fd);
    rsock_syserr_fail_path(e, "connect(2)", path);
  }
  if (server) {
    if (listen(fd, SOMAXCONN) < 0) {
      int e = errno;
      close(fd);
      rsock_syserr_fail_path(e, "listen(2)", path);
    }
  }
  rsock_init_sock(sock, fd);
  if (server) {
    GetOpenFile(sock, fptr);
    fptr->pathv = rb_str_new_frozen(path);
  }
  return sock;
}

void Con_Dump_f(void) {
  int l, x, i;
  short* line;
  fileHandle_t f;
  int bufferlen;
  char* buffer;
  char filename[MAX_QPATH];
  if (Cmd_Argc() != 2) {
    Com_Printf("usage: condump <filename>\n");
    return;
  }
  Q_strncpyz(filename, Cmd_Argv(1), sizeof(filename));
  COM_DefaultExtension(filename, sizeof(filename), ".txt");
  f = FS_FOpenFileWrite(filename);
  if (!f) {
    Com_Printf("ERROR: couldn't open %s.\n", filename);
    return;
  }
  Com_Printf("Dumped console text to %s.\n", filename);
  for (l = con.current - con.totallines + 1; l <= con.current; l++) {
    line = con.text + (l % con.totallines) * con.linewidth;
    for (x = 0; x < con.linewidth; x++)
      if ((line[x] & 0xff) != ' ') break;
    if (x != con.linewidth) break;
  }
#ifdef _WIN32
  bufferlen = con.linewidth + 3 * sizeof(char);
#else
  bufferlen = con.linewidth + 2 * sizeof(char);
#endif
  buffer = Hunk_AllocateTempMemory(bufferlen);
  buffer[bufferlen - 1] = 0;
  for (; l <= con.current; l++) {
    line = con.text + (l % con.totallines) * con.linewidth;
    for (i = 0; i < con.linewidth; i++) buffer[i] = line[i] & 0xff;
    for (x = con.linewidth - 1; x >= 0; x--) {
      if (buffer[x] == ' ')
        buffer[x] = 0;
      else
        break;
    }
#ifdef _WIN32
    Q_strcat(buffer, bufferlen, "\r\n");
#else
    Q_strcat(buffer, bufferlen, "\n");
#endif
    FS_Write(buffer, strlen(buffer), f);
  }
  Hunk_FreeTempMemory(buffer);
  FS_FCloseFile(f);
}

static int tc_fill_tclass(struct sk_buff* skb, struct Qdisc* q,
                          unsigned long cl, u32 pid, u32 seq, u16 flags,
                          int event) {
  struct tcmsg* tcm;
  struct nlmsghdr* nlh;
  unsigned char* b = skb_tail_pointer(skb);
  struct gnet_dump d;
  const struct Qdisc_class_ops* cl_ops = q->ops->cl_ops;
  nlh = NLMSG_NEW(skb, pid, seq, event, sizeof(*tcm), flags);
  tcm = NLMSG_DATA(nlh);
  tcm->tcm_family = AF_UNSPEC;
  tcm->tcm_ifindex = qdisc_dev(q)->ifindex;
  tcm->tcm_parent = q->handle;
  tcm->tcm_handle = q->handle;
  tcm->tcm_info = 0;
  NLA_PUT_STRING(skb, TCA_KIND, q->ops->id);
  if (cl_ops->dump && cl_ops->dump(q, cl, skb, tcm) < 0) goto nla_put_failure;
  if (gnet_stats_start_copy_compat(skb, TCA_STATS2, TCA_STATS, TCA_XSTATS,
                                   qdisc_root_sleeping_lock(q), &d) < 0)
    goto nla_put_failure;
  if (cl_ops->dump_stats && cl_ops->dump_stats(q, cl, &d) < 0)
    goto nla_put_failure;
  if (gnet_stats_finish_copy(&d) < 0) goto nla_put_failure;
  nlh->nlmsg_len = skb_tail_pointer(skb) - b;
  return skb->len;
nlmsg_failure:
nla_put_failure:
  nlmsg_trim(skb, b);
  return -1;
}

ikev1_attrmap_print(netdissect_options* ndo, const u_char* p, const u_char* ep,
                    const struct attrmap* map, size_t nmap) {
  int totlen;
  uint32_t t, v;
  if (p[0] & 0x80)
    totlen = 4;
  else
    totlen = 4 + EXTRACT_16BITS(&p[2]);
  if (ep < p + totlen) {
    ND_PRINT((ndo, "[|attr]"));
    return ep + 1;
  }
  ND_PRINT((ndo, "("));
  t = EXTRACT_16BITS(&p[0]) & 0x7fff;
  if (map && t < nmap && map[t].type)
    ND_PRINT((ndo, "type=%s ", map[t].type));
  else
    ND_PRINT((ndo, "type=#%d ", t));
  if (p[0] & 0x80) {
    ND_PRINT((ndo, "value="));
    v = EXTRACT_16BITS(&p[2]);
    if (map && t < nmap && v < map[t].nvalue && map[t].value[v])
      ND_PRINT((ndo, "%s", map[t].value[v]));
    else
      rawprint(ndo, (const uint8_t*)&p[2], 2);
  } else {
    ND_PRINT((ndo, "len=%d value=", EXTRACT_16BITS(&p[2])));
    rawprint(ndo, (const uint8_t*)&p[4], EXTRACT_16BITS(&p[2]));
  }
  ND_PRINT((ndo, ")"));
  return p + totlen;
}

nfsd4_set_nfs4_acl(struct svc_rqst* rqstp, struct svc_fh* fhp,
                   struct nfs4_acl* acl) {
  __be32 error;
  int host_error;
  struct dentry* dentry;
  struct inode* inode;
  struct posix_acl *pacl = NULL, *dpacl = NULL;
  unsigned int flags = 0;
  error = fh_verify(rqstp, fhp, 0, NFSD_MAY_SATTR);
  if (error) return error;
  dentry = fhp->fh_dentry;
  inode = d_inode(dentry);
  if (!inode->i_op->set_acl || !IS_POSIXACL(inode)) return nfserr_attrnotsupp;
  if (S_ISDIR(inode->i_mode)) flags = NFS4_ACL_DIR;
  host_error = nfs4_acl_nfsv4_to_posix(acl, &pacl, &dpacl, flags);
  if (host_error == -EINVAL) return nfserr_attrnotsupp;
  if (host_error < 0) goto out_nfserr;
  host_error = inode->i_op->set_acl(inode, pacl, ACL_TYPE_ACCESS);
  if (host_error < 0) goto out_release;
  if (S_ISDIR(inode->i_mode)) {
    host_error = inode->i_op->set_acl(inode, dpacl, ACL_TYPE_DEFAULT);
  }
out_release:
  posix_acl_release(pacl);
  posix_acl_release(dpacl);
out_nfserr:
  if (host_error == -EOPNOTSUPP)
    return nfserr_attrnotsupp;
  else
    return nfserrno(host_error);
}

