status_t ESDS::parseESDescriptor(size_t offset, size_t size) {
  if (size < 3) {
    return ERROR_MALFORMED;
  }
  offset += 2;
  size -= 2;
  unsigned streamDependenceFlag = mData[offset] & 0x80;
  unsigned URL_Flag = mData[offset] & 0x40;
  unsigned OCRstreamFlag = mData[offset] & 0x20;
  ++offset;
  --size;
  if (streamDependenceFlag) {
    offset += 2;
    size -= 2;
  }
  if (URL_Flag) {
    if (offset >= size) {
      return ERROR_MALFORMED;
    }
    unsigned URLlength = mData[offset];
    offset += URLlength + 1;
    size -= URLlength + 1;
  }
  if (OCRstreamFlag) {
    offset += 2;
    size -= 2;
    if ((offset >= size || mData[offset] != kTag_DecoderConfigDescriptor) &&
        offset - 2 < size &&
        mData[offset - 2] == kTag_DecoderConfigDescriptor) {
      offset -= 2;
      size += 2;
      ALOGW("Found malformed 'esds' atom, ignoring missing OCR_ES_Id.");
    }
  }
  if (offset >= size) {
    return ERROR_MALFORMED;
  }
  uint8_t tag;
  size_t sub_offset, sub_size;
  status_t err =
      skipDescriptorHeader(offset, size, &tag, &sub_offset, &sub_size);
  if (err != OK) {
    return err;
  }
  if (tag != kTag_DecoderConfigDescriptor) {
    return ERROR_MALFORMED;
  }
  err = parseDecoderConfigDescriptor(sub_offset, sub_size);
  return err;
}

static bool cgm_bind_dir(const char* root, const char* dirname) {
  nih_local char* cgpath = NULL;
  cgpath = NIH_MUST(nih_strdup(NULL, root));
  NIH_MUST(nih_strcat(&cgpath, NULL, "/sys/fs/cgroup"));
  if (!dir_exists(cgpath)) {
    ERROR("%s does not exist", cgpath);
    return false;
  }
  if (mount("cgroup", cgpath, "tmpfs", 0, "size=10000,mode=755")) {
    SYSERROR("Failed to mount tmpfs at %s", cgpath);
    return false;
  }
  NIH_MUST(nih_strcat(&cgpath, NULL, "/cgmanager"));
  if (mkdir(cgpath, 0755) < 0) {
    SYSERROR("Failed to create %s", cgpath);
    return false;
  }
  if (mount(dirname, cgpath, "none", MS_BIND, 0)) {
    SYSERROR("Failed to bind mount %s to %s", dirname, cgpath);
    return false;
  }
  return true;
}

INST_HANDLER(sbrx) {
  int b = buf[0] & 0x7;
  int r = ((buf[0] >> 4) & 0xf) | ((buf[1] & 0x01) << 4);
  RAnalOp next_op;
  avr_op_analyze(anal, &next_op, op->addr + op->size, buf + op->size,
                 len - op->size, cpu);
  r_strbuf_fini(&next_op.esil);
  op->jump = op->addr + next_op.size + 2;
  op->cycles = 1;
  ESIL_A("%d,1,<<,r%d,&,", b, r);
  ESIL_A((buf[1] & 0xe) == 0xc ? "!," : "!,!,");
  ESIL_A("?{,%" PFMT64d ",pc,=,},", op->jump);
}

void Compute(OpKernelContext* context) override {
  const Tensor& input = context->input(0);
  const float min_input = context->input(1).flat<float>()(0);
  const float max_input = context->input(2).flat<float>()(0);
  Tensor* output = nullptr;
  OP_REQUIRES_OK(context, context->allocate_output(0, input.shape(), &output));
  const T min_as_quantized = FloatToQuantized<T>(0.0f, min_input, max_input);
  if (meta::IsSupportedAndEnabled() && std::is_same<T, quint8>()) {
    auto input_ui8_array = input.flat<quint8>();
    meta::Clamp(context, input_ui8_array.data(), input_ui8_array.size(),
                min_as_quantized, 255, output->flat<quint8>().data());
  } else {
    output->flat<T>().device(context->eigen_cpu_device()) =
        input.flat<T>().cwiseMax(min_as_quantized).template cast<T>();
  }
  Tensor* output_min = nullptr;
  OP_REQUIRES_OK(context, context->allocate_output(1, {}, &output_min));
  output_min->flat<float>()(0) = min_input;
  Tensor* output_max = nullptr;
  OP_REQUIRES_OK(context, context->allocate_output(2, {}, &output_max));
  output_max->flat<float>()(0) = max_input;
}

add_link_ref(struct link_ref** references, const uint8_t* name,
             size_t name_size) {
  struct link_ref* ref = calloc(1, sizeof(struct link_ref));
  if (!ref) return NULL;
  ref->id = hash_link_ref(name, name_size);
  ref->next = references[ref->id % REF_TABLE_SIZE];
  references[ref->id % REF_TABLE_SIZE] = ref;
  return ref;
}

static int raw_cmd_copyin(int cmd, void __user* param,
                          struct floppy_raw_cmd** rcmd) {
  struct floppy_raw_cmd* ptr;
  int ret;
  int i;
  *rcmd = NULL;
loop:
  ptr = kmalloc(sizeof(struct floppy_raw_cmd), GFP_USER);
  if (!ptr) return -ENOMEM;
  *rcmd = ptr;
  ret = copy_from_user(ptr, param, sizeof(*ptr));
  if (ret) return -EFAULT;
  ptr->next = NULL;
  ptr->buffer_length = 0;
  param += sizeof(struct floppy_raw_cmd);
  if (ptr->cmd_count > 33) return -EINVAL;
  for (i = 0; i < 16; i++) ptr->reply[i] = 0;
  ptr->resultcode = 0;
  ptr->kernel_data = NULL;
  if (ptr->flags & (FD_RAW_READ | FD_RAW_WRITE)) {
    if (ptr->length <= 0) return -EINVAL;
    ptr->kernel_data = (char*)fd_dma_mem_alloc(ptr->length);
    fallback_on_nodma_alloc(&ptr->kernel_data, ptr->length);
    if (!ptr->kernel_data) return -ENOMEM;
    ptr->buffer_length = ptr->length;
  }
  if (ptr->flags & FD_RAW_WRITE) {
    ret = fd_copyin(ptr->data, ptr->kernel_data, ptr->length);
    if (ret) return ret;
  }
  if (ptr->flags & FD_RAW_MORE) {
    rcmd = &(ptr->next);
    ptr->rate &= 0x43;
    goto loop;
  }
  return 0;
}

static int cbs_av1_read_uvlc(CodedBitstreamContext* ctx, GetBitContext* gbc,
                             const char* name, uint32_t* write_to,
                             uint32_t range_min, uint32_t range_max) {
  uint32_t value;
  int position, zeroes, i, j;
  char bits[65];
  if (ctx->trace_enable) position = get_bits_count(gbc);
  zeroes = i = 0;
  while (1) {
    if (get_bits_left(gbc) < zeroes + 1) {
      av_log(ctx->log_ctx, AV_LOG_ERROR,
             "Invalid uvlc code at "
             "%s: bitstream ended.\n",
             name);
      return AVERROR_INVALIDDATA;
    }
    if (get_bits1(gbc)) {
      bits[i++] = '1';
      break;
    } else {
      bits[i++] = '0';
      ++zeroes;
    }
  }
  if (zeroes >= 32) {
    value = MAX_UINT_BITS(32);
  } else {
    value = get_bits_long(gbc, zeroes);
    for (j = 0; j < zeroes; j++)
      bits[i++] = (value >> (zeroes - j - 1) & 1) ? '1' : '0';
    value += (1 << zeroes) - 1;
  }
  if (ctx->trace_enable) {
    bits[i] = 0;
    ff_cbs_trace_syntax_element(ctx, position, name, NULL, bits, value);
  }
  if (value < range_min || value > range_max) {
    av_log(ctx->log_ctx, AV_LOG_ERROR,
           "%s out of range: "
           "%" PRIu32 ", but must be in [%" PRIu32 ",%" PRIu32 "].\n",
           name, value, range_min, range_max);
    return AVERROR_INVALIDDATA;
  }
  *write_to = value;
  return 0;
}

static bool dccp_new(struct nf_conn* ct, const struct sk_buff* skb,
                     unsigned int dataoff, unsigned int* timeouts) {
  struct net* net = nf_ct_net(ct);
  struct dccp_net* dn;
  struct dccp_hdr _dh, *dh;
  const char* msg;
  u_int8_t state;
  dh = skb_header_pointer(skb, dataoff, sizeof(_dh), &dh);
  BUG_ON(dh == NULL);
  state = dccp_state_table[CT_DCCP_ROLE_CLIENT][dh->dccph_type][CT_DCCP_NONE];
  switch (state) {
    default:
      dn = dccp_pernet(net);
      if (dn->dccp_loose == 0) {
        msg = "nf_ct_dccp: not picking up existing connection ";
        goto out_invalid;
      }
    case CT_DCCP_REQUEST:
      break;
    case CT_DCCP_INVALID:
      msg = "nf_ct_dccp: invalid state transition ";
      goto out_invalid;
  }
  ct->proto.dccp.role[IP_CT_DIR_ORIGINAL] = CT_DCCP_ROLE_CLIENT;
  ct->proto.dccp.role[IP_CT_DIR_REPLY] = CT_DCCP_ROLE_SERVER;
  ct->proto.dccp.state = CT_DCCP_NONE;
  ct->proto.dccp.last_pkt = DCCP_PKT_REQUEST;
  ct->proto.dccp.last_dir = IP_CT_DIR_ORIGINAL;
  ct->proto.dccp.handshake_seq = 0;
  return true;
out_invalid:
  if (LOG_INVALID(net, IPPROTO_DCCP))
    nf_log_packet(net, nf_ct_l3num(ct), 0, skb, NULL, NULL, NULL, "%s", msg);
  return false;
}

void ScriptLoader::executeScript(const ScriptSourceCode& sourceCode) {
  ASSERT(m_alreadyStarted);
  if (sourceCode.isEmpty()) return;
  RefPtr<Document> elementDocument(m_element->document());
  RefPtr<Document> contextDocument = elementDocument->contextDocument().get();
  if (!contextDocument) return;
  LocalFrame* frame = contextDocument->frame();
  bool shouldBypassMainWorldContentSecurityPolicy =
      (frame && frame->script().shouldBypassMainWorldContentSecurityPolicy()) ||
      elementDocument->contentSecurityPolicy()->allowScriptNonce(
          m_element->fastGetAttribute(HTMLNames::nonceAttr)) ||
      elementDocument->contentSecurityPolicy()->allowScriptHash(
          sourceCode.source());
  if (!m_isExternalScript &&
      (!shouldBypassMainWorldContentSecurityPolicy &&
       !elementDocument->contentSecurityPolicy()->allowInlineScript(
           elementDocument->url(), m_startLineNumber)))
    return;
  if (m_isExternalScript && m_resource &&
      !m_resource->mimeTypeAllowedByNosniff()) {
    contextDocument->addConsoleMessage(
        SecurityMessageSource, ErrorMessageLevel,
        "Refused to execute script from '" + m_resource->url().elidedString() +
            "' because its MIME type ('" + m_resource->mimeType() +
            "') is not executable, and strict MIME type checking is enabled.");
    return;
  }
  if (frame) {
    const bool isImportedScript = contextDocument != elementDocument;
    IgnoreDestructiveWriteCountIncrementer
        ignoreDestructiveWriteCountIncrementer(
            m_isExternalScript || isImportedScript ? contextDocument.get() : 0);
    if (isHTMLScriptLoader(m_element))
      contextDocument->pushCurrentScript(toHTMLScriptElement(m_element));
    AccessControlStatus corsCheck = NotSharableCrossOrigin;
    if (sourceCode.resource() &&
        sourceCode.resource()->passesAccessControlCheck(
            m_element->document().securityOrigin()))
      corsCheck = SharableCrossOrigin;
    frame->script().executeScriptInMainWorld(sourceCode, corsCheck);
    if (isHTMLScriptLoader(m_element)) {
      ASSERT(contextDocument->currentScript() == m_element);
      contextDocument->popCurrentScript();
    }
  }
}

