local block_state deflate_huff(s, flush)
deflate_state* s;
int flush;
{
  int bflush;
  for (;;) {
    if (s->lookahead == 0) {
      fill_window(s);
      if (s->lookahead == 0) {
        if (flush == Z_NO_FLUSH) return need_more;
        break;
      }
    }
    s->match_length = 0;
    Tracevv((stderr, "%c", s->window[s->strstart]));
    _tr_tally_lit(s, s->window[s->strstart], bflush);
    s->lookahead--;
    s->strstart++;
    if (bflush) FLUSH_BLOCK(s, 0);
  }
  s->insert = 0;
  if (flush == Z_FINISH) {
    FLUSH_BLOCK(s, 1);
    return finish_done;
  }
  if (s->last_lit) FLUSH_BLOCK(s, 0);
  return block_done;
}

snmp_ber_decode_integer(unsigned char* buf, uint32_t* buff_len, uint32_t* num) {
  uint8_t i, len, type;
  buf = snmp_ber_decode_type(buf, buff_len, &type);
  if (buf == NULL || type != BER_DATA_TYPE_INTEGER) {
    return NULL;
  }
  buf = snmp_ber_decode_length(buf, buff_len, &len);
  if (buf == NULL || len > 4) {
    return NULL;
  }
  if (*buff_len < len) {
    return NULL;
  }
  *num = (uint32_t)(*buf++ & 0xFF);
  (*buff_len)--;
  for (i = 1; i < len; ++i) {
    *num <<= 8;
    *num |= (uint8_t)(*buf++ & 0xFF);
    (*buff_len)--;
  }
  return buf;
}

MmkvHostObject::MmkvHostObject(const std::string& instanceId, std::string path,
                               std::string cryptKey) {
  __android_log_print(
      ANDROID_LOG_INFO, "RNMMKV",
      "Creating MMKV instance \"%s\"... (Path: %s, Encryption-Key: %s)",
      instanceId.c_str(), path.c_str(), cryptKey.c_str());
  std::string* pathPtr = path.size() > 0 ? &path : nullptr;
  std::string* cryptKeyPtr = cryptKey.size() > 0 ? &cryptKey : nullptr;
  instance = MMKV::mmkvWithID(instanceId, mmkv::DEFAULT_MMAP_SIZE,
                              MMKV_SINGLE_PROCESS, cryptKeyPtr, pathPtr);
  if (instance == nullptr) {
    if (instanceId.empty()) {
      throw std::runtime_error(
          "Failed to create MMKV instance! `id` cannot be empty!");
    }
    if (cryptKey.size() > 16) {
      throw std::runtime_error(
          "Failed to create MMKV instance! `encryptionKey` cannot be longer "
          "than 16 bytes!");
    }
    throw std::runtime_error("Failed to create MMKV instance!");
  }
}

