int gg_change_status_descr(struct gg_session* sess, int status,
                           const char* descr) {
  struct gg_new_status80 p;
  char* gen_descr = NULL;
  int descr_len = 0;
  int res;
  gg_debug_session(sess, GG_DEBUG_FUNCTION,
                   "** gg_change_status_descr(%p, %d, \"%s\");\n", sess, status,
                   descr);
  if (!sess) {
    errno = EFAULT;
    return -1;
  }
  if (sess->state != GG_STATE_CONNECTED) {
    errno = ENOTCONN;
    return -1;
  }
  sess->status = status;
  if (descr != NULL && sess->encoding != GG_ENCODING_UTF8) {
    descr = gen_descr = gg_encoding_convert(descr, GG_ENCODING_CP1250,
                                            GG_ENCODING_UTF8, -1, -1);
    if (!gen_descr) return -1;
  }
  if (descr) {
    descr_len = strlen(descr);
    if (descr_len > GG_STATUS_DESCR_MAXSIZE)
      descr_len = GG_STATUS_DESCR_MAXSIZE;
  } else {
    descr = "";
  }
  p.status = gg_fix32(status);
  p.flags = gg_fix32(sess->status_flags);
  p.description_size = gg_fix32(descr_len);
  if (sess->protocol_version >= GG_PROTOCOL_110) {
    p.flags = gg_fix32(0x00000014);
    descr_len++;
  }
  res = gg_send_packet(sess, GG_NEW_STATUS80, &p, sizeof(p), descr, descr_len,
                       NULL);
  free(gen_descr);
  if (GG_S_NA(status)) {
    sess->state = GG_STATE_DISCONNECTING;
    sess->timeout = GG_TIMEOUT_DISCONNECT;
  }
  return res;
}

int LibRaw::subtract_black() {
  CHECK_ORDER_LOW(LIBRAW_PROGRESS_RAW2_IMAGE);
  try {
    if (!is_phaseone_compressed() &&
        (C.cblack[0] || C.cblack[1] || C.cblack[2] || C.cblack[3])) {
#define BAYERC(row, col, c) \
  imgdata.image[((row) >> IO.shrink) * S.iwidth + ((col) >> IO.shrink)][c]
      int cblk[4], i;
      for (i = 0; i < 4; i++) cblk[i] = C.cblack[i];
      int size = S.iheight * S.iwidth;
#define MIN(a, b) ((a) < (b) ? (a) : (b))
#define MAX(a, b) ((a) > (b) ? (a) : (b))
#define LIM(x, min, max) MAX(min, MIN(x, max))
#define CLIP(x) LIM(x, 0, 65535)
      for (i = 0; i < size * 4; i++) {
        int val = imgdata.image[0][i];
        val -= cblk[i & 3];
        imgdata.image[0][i] = CLIP(val);
        if (C.data_maximum < val) C.data_maximum = val;
      }
#undef MIN
#undef MAX
#undef LIM
#undef CLIP
      C.maximum -= C.black;
      ZERO(C.cblack);
      C.black = 0;
#undef BAYERC
    } else {
      int idx;
      ushort* p = (ushort*)imgdata.image;
      C.data_maximum = 0;
      for (idx = 0; idx < S.iheight * S.iwidth * 4; idx++)
        if (C.data_maximum < p[idx]) C.data_maximum = p[idx];
    }
    return 0;
  } catch (LibRaw_exceptions err) {
    EXCEPTION_HANDLER(err);
  }
}

Sfdouble_t sh_strnum(Shell_t* shp, const char* str, char** ptr, int mode) {
  Sfdouble_t d;
  char* last;
  if (*str == 0) {
    if (ptr) *ptr = (char*)str;
    return 0;
  }
  errno = 0;
  d = number(str, &last, shp->inarith ? 0 : 10, NULL);
  if (*last) {
    if (*last != '.' || last[1] != '.') {
      d = strval(shp, str, &last, arith, mode);
      Varsubscript = true;
    }
    if (!ptr && *last && mode > 0)
      errormsg(SH_DICT, ERROR_exit(1), e_lexbadchar, *last, str);
  } else if (!d && *str == '-') {
    d = -0.0;
  }
  if (ptr) *ptr = last;
  return d;
}

