static u64 __skb_get_nlattr_nest(u64 ctx, u64 A, u64 X, u64 r4, u64 r5) {
  struct sk_buff* skb = (struct sk_buff*)(long)ctx;
  struct nlattr* nla;
  if (skb_is_nonlinear(skb)) return 0;
  if (A > skb->len - sizeof(struct nlattr)) return 0;
  nla = (struct nlattr*)&skb->data[A];
  if (nla->nla_len > A - skb->len) return 0;
  nla = nla_find_nested(nla, X);
  if (nla) return (void*)nla - (void*)skb->data;
  return 0;
}

static void bump_cpu_timer(struct k_itimer* timer, u64 now) {
  int i;
  u64 delta, incr;
  if (timer->it.cpu.incr == 0) return;
  if (now < timer->it.cpu.expires) return;
  incr = timer->it.cpu.incr;
  delta = now + incr - timer->it.cpu.expires;
  for (i = 0; incr < delta - incr; i++) incr = incr << 1;
  for (; i >= 0; incr >>= 1, i--) {
    if (delta < incr) continue;
    timer->it.cpu.expires += incr;
    timer->it_overrun += 1 << i;
    delta -= incr;
  }
}

