static void parse_media(pj_scanner* scanner, pjmedia_sdp_media* med,
                        volatile parse_context* ctx) {
  pj_str_t str;
  ctx->last_error = PJMEDIA_SDP_EINMEDIA;
  if (*(scanner->curptr + 1) != '=') {
    on_scanner_error(scanner);
    return;
  }
  pj_scan_advance_n(scanner, 2, SKIP_WS);
  pj_scan_get_until_ch(scanner, ' ', &med->desc.media);
  pj_scan_get_char(scanner);
  pj_scan_get(scanner, &cs_token, &str);
  med->desc.port = (unsigned short)pj_strtoul(&str);
  if (*scanner->curptr == '/') {
    pj_scan_get_char(scanner);
    pj_scan_get(scanner, &cs_token, &str);
    med->desc.port_count = pj_strtoul(&str);
  } else {
    med->desc.port_count = 0;
  }
  if (pj_scan_get_char(scanner) != ' ') {
    PJ_THROW(SYNTAX_ERROR);
  }
  pj_scan_get_until_chr(scanner, " \t\r\n", &med->desc.transport);
  med->desc.fmt_count = 0;
  while (*scanner->curptr == ' ') {
    pj_str_t fmt;
    pj_scan_get_char(scanner);
    if ((*scanner->curptr == '\r') || (*scanner->curptr == '\n')) break;
    pj_scan_get(scanner, &cs_token, &fmt);
    if (med->desc.fmt_count < PJMEDIA_MAX_SDP_FMT)
      med->desc.fmt[med->desc.fmt_count++] = fmt;
    else
      PJ_PERROR(2, (THIS_FILE, PJ_ETOOMANY,
                    "Error adding SDP media format %.*s, "
                    "format is ignored",
                    (int)fmt.slen, fmt.ptr));
  }
  pj_scan_skip_line(scanner);
}

static bool MR_primality_test(UnsignedBigInteger n,
                              const Vector<UnsignedBigInteger, 256>& tests) {
  ASSERT(!(n < 4));
  auto predecessor = n.minus({1});
  auto d = predecessor;
  size_t r = 0;
  {
    auto div_result = d.divided_by(2);
    while (div_result.remainder == 0) {
      d = div_result.quotient;
      div_result = d.divided_by(2);
      ++r;
    }
  }
  if (r == 0) {
    return n == 2;
  }
  for (auto a : tests) {
    ASSERT(a < n);
    auto x = ModularPower(a, d, n);
    if (x == 1 || x == predecessor) continue;
    bool skip_this_witness = false;
    for (size_t i = 0; i < r - 1; ++i) {
      x = ModularPower(x, 2, n);
      if (x == predecessor) {
        skip_this_witness = true;
        break;
      }
    }
    if (skip_this_witness) continue;
    return false;
  }
  return true;
}

void TestGatherNd(int* param_dims, const ParamType* param_data, int* index_dims,
                  const IndexType* index_data, int* output_dims,
                  ParamType* output_data,
                  const ParamType* expected_output_data) {
  TfLiteIntArray* pdims = IntArrayFromInts(param_dims);
  TfLiteIntArray* idims = IntArrayFromInts(index_dims);
  TfLiteIntArray* odims = IntArrayFromInts(output_dims);
  constexpr int inputs_size = 2;
  constexpr int outputs_size = 1;
  constexpr int tensors_size = inputs_size + outputs_size;
  TfLiteTensor tensors[tensors_size] = {
      CreateTensor(param_data, pdims),
      CreateTensor(index_data, idims),
      CreateTensor(output_data, odims),
  };
  int inputs_array_data[] = {2, 0, 1};
  TfLiteIntArray* inputs_array = IntArrayFromInts(inputs_array_data);
  int outputs_array_data[] = {1, 2};
  TfLiteIntArray* outputs_array = IntArrayFromInts(outputs_array_data);
  const TfLiteRegistration registration = Register_GATHER_ND();
  micro::KernelRunner runner(registration, tensors, tensors_size, inputs_array,
                             outputs_array, nullptr);
  TF_LITE_MICRO_EXPECT_EQ(kTfLiteOk, runner.InitAndPrepare());
  TF_LITE_MICRO_EXPECT_EQ(kTfLiteOk, runner.Invoke());
  TfLiteTensor* actual_output_tensor = &tensors[2];
  TfLiteIntArray* actual_output_dims = actual_output_tensor->dims;
  const int output_size = ElementCount(*actual_output_dims);
  for (int i = 0; i < output_size; ++i) {
    TF_LITE_MICRO_EXPECT_EQ(expected_output_data[i], output_data[i]);
  }
}

_gdata_service_build_session(void) {
