int crxFreeImageData(CrxImage* img) {
  CrxTile* tile = img->tiles;
  int nTiles = img->tileRows * img->tileCols;
  if (img->tiles) {
    for (int32_t curTile = 0; curTile < nTiles; curTile++, tile++)
      if (tile[curTile].comps)
        for (int32_t curPlane = 0; curPlane < img->nPlanes; curPlane++)
          crxFreeSubbandData(img, tile[curTile].comps + curPlane);
    free(img->tiles);
    img->tiles = 0;
  }
  if (img->planeBuf) {
    free(img->planeBuf);
    img->planeBuf = 0;
  }
  return 0;
}

int vp9_alloc_context_buffers(VP9_COMMON* cm, int width, int height) {
  int new_mi_size;
  vp9_set_mb_mi(cm, width, height);
  new_mi_size = cm->mi_stride * calc_mi_size(cm->mi_rows);
  if (cm->mi_alloc_size < new_mi_size) {
    cm->free_mi(cm);
    if (cm->alloc_mi(cm, new_mi_size)) goto fail;
  }
  if (cm->seg_map_alloc_size < cm->mi_rows * cm->mi_cols) {
    free_seg_map(cm);
    if (alloc_seg_map(cm, cm->mi_rows * cm->mi_cols)) goto fail;
  }
  if (cm->above_context_alloc_cols < cm->mi_cols) {
    vpx_free(cm->above_context);
    cm->above_context = (ENTROPY_CONTEXT*)vpx_calloc(
        2 * mi_cols_aligned_to_sb(cm->mi_cols) * MAX_MB_PLANE,
        sizeof(*cm->above_context));
    if (!cm->above_context) goto fail;
    vpx_free(cm->above_seg_context);
    cm->above_seg_context = (PARTITION_CONTEXT*)vpx_calloc(
        mi_cols_aligned_to_sb(cm->mi_cols), sizeof(*cm->above_seg_context));
    if (!cm->above_seg_context) goto fail;
    cm->above_context_alloc_cols = cm->mi_cols;
  }
  if (vp9_alloc_loop_filter(cm)) goto fail;
  return 0;
fail:
  vp9_set_mb_mi(cm, 0, 0);
  vp9_free_context_buffers(cm);
  return 1;
}

BOOL update_write_cache_brush_order(wStream* s,
                                    const CACHE_BRUSH_ORDER* cache_brush,
                                    UINT16* flags) {
  int i;
  BYTE iBitmapFormat;
  BOOL compressed = FALSE;
  if (!Stream_EnsureRemainingCapacity(
          s, update_approximate_cache_brush_order(cache_brush, flags)))
    return FALSE;
  iBitmapFormat = BPP_BMF[cache_brush->bpp];
  Stream_Write_UINT8(s, cache_brush->index);
  Stream_Write_UINT8(s, iBitmapFormat);
  Stream_Write_UINT8(s, cache_brush->cx);
  Stream_Write_UINT8(s, cache_brush->cy);
  Stream_Write_UINT8(s, cache_brush->style);
  Stream_Write_UINT8(s, cache_brush->length);
  if ((cache_brush->cx == 8) && (cache_brush->cy == 8)) {
    if (cache_brush->bpp == 1) {
      if (cache_brush->length != 8) {
        WLog_ERR(TAG, "incompatible 1bpp brush of length:%" PRIu32 "",
                 cache_brush->length);
        return FALSE;
      }
      for (i = 7; i >= 0; i--) {
        Stream_Write_UINT8(s, cache_brush->data[i]);
      }
    } else {
      if ((iBitmapFormat == BMF_8BPP) && (cache_brush->length == 20))
        compressed = TRUE;
      else if ((iBitmapFormat == BMF_16BPP) && (cache_brush->length == 24))
        compressed = TRUE;
      else if ((iBitmapFormat == BMF_32BPP) && (cache_brush->length == 32))
        compressed = TRUE;
      if (compressed != FALSE) {
        if (!update_compress_brush(s, cache_brush->data, cache_brush->bpp))
          return FALSE;
      } else {
        int scanline = (cache_brush->bpp / 8) * 8;
        for (i = 7; i >= 0; i--) {
          Stream_Write(s, &cache_brush->data[i * scanline], scanline);
        }
      }
    }
  }
  return TRUE;
}

get_uncompressed_data(struct archive_read* a, const void** buff, size_t size,
                      size_t minimum) {
  struct _7zip* zip = (struct _7zip*)a->format->data;
  ssize_t bytes_avail;
  if (zip->codec == _7Z_COPY && zip->codec2 == (unsigned long)-1) {
    *buff = __archive_read_ahead(a, 1, &bytes_avail);
    if (bytes_avail <= 0) {
      archive_set_error(&a->archive, ARCHIVE_ERRNO_FILE_FORMAT,
                        "Truncated 7-Zip file data");
      return (ARCHIVE_FATAL);
    }
    if ((size_t)bytes_avail > zip->uncompressed_buffer_bytes_remaining)
      bytes_avail = (ssize_t)zip->uncompressed_buffer_bytes_remaining;
    if ((size_t)bytes_avail > size) bytes_avail = (ssize_t)size;
    zip->pack_stream_bytes_unconsumed = bytes_avail;
  } else if (zip->uncompressed_buffer_pointer == NULL) {
    archive_set_error(&(a->archive), ARCHIVE_ERRNO_MISC,
                      "Damaged 7-Zip archive");
    return (ARCHIVE_FATAL);
  } else {
    if (minimum > zip->uncompressed_buffer_bytes_remaining) {
      if (extract_pack_stream(a, minimum) < 0) return (ARCHIVE_FATAL);
    }
    if (size > zip->uncompressed_buffer_bytes_remaining)
      bytes_avail = (ssize_t)zip->uncompressed_buffer_bytes_remaining;
    else
      bytes_avail = (ssize_t)size;
    *buff = zip->uncompressed_buffer_pointer;
    zip->uncompressed_buffer_pointer += bytes_avail;
  }
  zip->uncompressed_buffer_bytes_remaining -= bytes_avail;
  return (bytes_avail);
}

