static void Sp_search(js_State* J) {
  js_Regexp* re;
  const char* text;
  Resub m;
  text = checkstring(J, 0);
  if (js_isregexp(J, 1))
    js_copy(J, 1);
  else if (js_isundefined(J, 1))
    js_newregexp(J, "", 0);
  else
    js_newregexp(J, js_tostring(J, 1), 0);
  re = js_toregexp(J, -1);
  if (!js_regexec(re->prog, text, &m, 0))
    js_pushnumber(J, js_utfptrtoidx(text, m.sub[0].sp));
  else
    js_pushnumber(J, -1);
}

wchar* ConvertPath(const wchar* SrcPath, wchar* DestPath, size_t DestSize) {
  const wchar* DestPtr = SrcPath;
  for (const wchar* s = DestPtr; *s != 0; s++)
    if (IsPathDiv(s[0]) && s[1] == '.' && s[2] == '.' && IsPathDiv(s[3]))
      DestPtr = s + 4;
  while (*DestPtr != 0) {
    const wchar* s = DestPtr;
    if (s[0] != 0 && IsDriveDiv(s[1])) s += 2;
    if (s[0] == '\\' && s[1] == '\\') {
      const wchar* Slash = wcschr(s + 2, '\\');
      if (Slash != NULL && (Slash = wcschr(Slash + 1, '\\')) != NULL)
        s = Slash + 1;
    }
    for (const wchar* t = s; *t != 0; t++)
      if (IsPathDiv(*t))
        s = t + 1;
      else if (*t != '.')
        break;
    if (s == DestPtr) break;
    DestPtr = s;
  }
  if (DestPtr[0] == '.' && DestPtr[1] == '.' && DestPtr[2] == 0) DestPtr += 2;
  if (DestPath != NULL) {
    wchar TmpStr[NM];
    wcsncpyz(TmpStr, DestPtr, ASIZE(TmpStr));
    wcsncpyz(DestPath, TmpStr, DestSize);
  }
  return (wchar*)DestPtr;
}

tt_sbit_decoder_init(TT_SBitDecoder decoder, TT_Face face,
                     FT_ULong strike_index, TT_SBit_MetricsRec* metrics) {
  FT_Error error;
  FT_Stream stream = face->root.stream;
  FT_ULong ebdt_size;
  error = face->goto_table(face, TTAG_CBDT, stream, &ebdt_size);
  if (error) error = face->goto_table(face, TTAG_EBDT, stream, &ebdt_size);
  if (error) error = face->goto_table(face, TTAG_bdat, stream, &ebdt_size);
  if (error) goto Exit;
  decoder->face = face;
  decoder->stream = stream;
  decoder->bitmap = &face->root.glyph->bitmap;
  decoder->metrics = metrics;
  decoder->metrics_loaded = 0;
  decoder->bitmap_allocated = 0;
  decoder->ebdt_start = FT_STREAM_POS();
  decoder->ebdt_size = ebdt_size;
  decoder->eblc_base = face->sbit_table;
  decoder->eblc_limit = face->sbit_table + face->sbit_table_size;
  {
    FT_Byte* p;
    if (8 + 48 * strike_index + 3 * 4 + 34 + 1 > face->sbit_table_size) {
      error = FT_THROW(Invalid_File_Format);
      goto Exit;
    }
    p = decoder->eblc_base + 8 + 48 * strike_index;
    decoder->strike_index_array = FT_NEXT_ULONG(p);
    p += 4;
    decoder->strike_index_count = FT_NEXT_ULONG(p);
    p += 34;
    decoder->bit_depth = *p;
    if (decoder->strike_index_array > face->sbit_table_size ||
        decoder->strike_index_array + 8 * decoder->strike_index_count >
            face->sbit_table_size)
      error = FT_THROW(Invalid_File_Format);
  }
}

static struct ip_options* tcp_v4_save_options(struct sock* sk,
                                              struct sk_buff* skb) {
  struct ip_options* opt = &(IPCB(skb)->opt);
  struct ip_options* dopt = NULL;
  if (opt && opt->optlen) {
    int opt_size = optlength(opt);
    dopt = kmalloc(opt_size, GFP_ATOMIC);
    if (dopt) {
      if (ip_options_echo(dopt, skb)) {
        kfree(dopt);
        dopt = NULL;
      }
    }
  }
  return dopt;
}

TfLiteStatus ResizeOutputTensor(TfLiteContext* context,
                                SpaceToBatchNDContext* op_context) {
  TfLiteIntArray* input_size = op_context->input->dims;
  const int32* block_shape = GetTensorData<int32>(op_context->block_shape);
  const int32* paddings_data = GetTensorData<int32>(op_context->paddings);
  int spatial_dims_num = input_size->size - 2;
  TF_LITE_ENSURE_EQ(context, NumDimensions(op_context->block_shape), 1);
  TF_LITE_ENSURE_EQ(context, op_context->block_shape->dims->data[0],
                    spatial_dims_num);
  TF_LITE_ENSURE_EQ(context, NumDimensions(op_context->paddings), 2);
  TF_LITE_ENSURE_EQ(context, op_context->paddings->dims->data[0],
                    spatial_dims_num);
  TF_LITE_ENSURE_EQ(context, op_context->paddings->dims->data[1], 2);
  TfLiteIntArray* output_size = TfLiteIntArrayCopy(input_size);
  int output_batch_size = input_size->data[0];
  for (int dim = 0; dim < spatial_dims_num; ++dim) {
    int final_dim_size = (input_size->data[dim + 1] + paddings_data[dim * 2] +
                          paddings_data[dim * 2 + 1]);
    TF_LITE_ENSURE_EQ(context, final_dim_size % block_shape[dim], 0);
    output_size->data[dim + 1] = final_dim_size / block_shape[dim];
    output_batch_size *= block_shape[dim];
  }
  output_size->data[0] = output_batch_size;
  output_size->data[input_size->size - 1] =
      input_size->data[input_size->size - 1];
  return context->ResizeTensor(context, op_context->output, output_size);
}

static int nfs4_intent_set_file(struct nameidata* nd, struct path* path,
                                struct nfs4_state* state) {
  struct file* filp;
  int ret;
  if (nd->intent.open.flags & FMODE_EXEC) {
    ret = nfs_may_open(state->inode, state->owner->so_cred,
                       nd->intent.open.flags);
    if (ret < 0) goto out_close;
  }
  filp = lookup_instantiate_filp(nd, path->dentry, NULL);
  if (!IS_ERR(filp)) {
    struct nfs_open_context* ctx;
    ctx = nfs_file_open_context(filp);
    ctx->state = state;
    return 0;
  }
  ret = PTR_ERR(filp);
out_close:
  nfs4_close_sync(path, state, nd->intent.open.flags);
  return ret;
}

err_t verify_signed_hash(const struct RSA_public_key* k, u_char* s,
                         unsigned int s_max_octets, u_char** psig,
                         size_t hash_len, const u_char* sig_val,
                         size_t sig_len) {
  unsigned int padlen;
  {
    chunk_t temp_s;
    MP_INT c;
    n_to_mpz(&c, sig_val, sig_len);
    oswcrypto.mod_exp(&c, &c, &k->e, &k->n);
    temp_s = mpz_to_n(&c, sig_len);
    if (s_max_octets < sig_len) {
      return "2"
             "exponentiation failed; too many octets";
    }
    memcpy(s, temp_s.ptr, sig_len);
    pfree(temp_s.ptr);
    mpz_clear(&c);
  }
  padlen = sig_len - 3 - hash_len;
  DBG(DBG_CRYPT, DBG_dump("verify_sh decrypted SIG1:", s, sig_len));
  DBG(DBG_CRYPT,
      DBG_log("pad_len calculated: %d hash_len: %d", padlen, (int)hash_len));
  if (s[0] != 0x00 || s[1] != 0x01 || s[padlen + 2] != 0x00) {
    return "3"
           "SIG padding does not check out";
  }
  s += padlen + 3;
  (*psig) = s;
  return NULL;
}

check_entry_size_and_hooks(struct ipt_entry* e, struct xt_table_info* newinfo,
                           const unsigned char* base,
                           const unsigned char* limit,
                           const unsigned int* hook_entries,
                           const unsigned int* underflows,
                           unsigned int valid_hooks) {
  unsigned int h;
  int err;
  if ((unsigned long)e % __alignof__(struct ipt_entry) != 0 ||
      (unsigned char*)e + sizeof(struct ipt_entry) >= limit ||
      (unsigned char*)e + e->next_offset > limit) {
    duprintf("Bad offset %p\n", e);
    return -EINVAL;
  }
  if (e->next_offset <
      sizeof(struct ipt_entry) + sizeof(struct xt_entry_target)) {
    duprintf("checking: element %p size %u\n", e, e->next_offset);
    return -EINVAL;
  }
  if (!ip_checkentry(&e->ip)) return -EINVAL;
  err = xt_check_entry_offsets(e, e->target_offset, e->next_offset);
  if (err) return err;
  for (h = 0; h < NF_INET_NUMHOOKS; h++) {
    if (!(valid_hooks & (1 << h))) continue;
    if ((unsigned char*)e - base == hook_entries[h])
      newinfo->hook_entry[h] = hook_entries[h];
    if ((unsigned char*)e - base == underflows[h]) {
      if (!check_underflow(e)) {
        pr_debug(
            "Underflows must be unconditional and "
            "use the STANDARD target with "
            "ACCEPT/DROP\n");
        return -EINVAL;
      }
      newinfo->underflow[h] = underflows[h];
    }
  }
  e->counters = ((struct xt_counters){0, 0});
  e->comefrom = 0;
  return 0;
}

