static int check_passwd(unsigned char* passwd, size_t length) {
  struct digest* d = NULL;
  unsigned char* passwd1_sum;
  unsigned char* passwd2_sum;
  int ret = 0;
  int hash_len;
  if (IS_ENABLED(CONFIG_PASSWD_CRYPTO_PBKDF2)) {
    hash_len = PBKDF2_LENGTH;
  } else {
    d = digest_alloc(PASSWD_SUM);
    if (!d) {
      pr_err("No such digest: %s\n", PASSWD_SUM ? PASSWD_SUM : "NULL");
      return -ENOENT;
    }
    hash_len = digest_length(d);
  }
  passwd1_sum = calloc(hash_len * 2, sizeof(unsigned char));
  if (!passwd1_sum) return -ENOMEM;
  passwd2_sum = passwd1_sum + hash_len;
  if (is_passwd_env_enable())
    ret = read_env_passwd(passwd2_sum, hash_len);
  else if (is_passwd_default_enable())
    ret = read_default_passwd(passwd2_sum, hash_len);
  else
    ret = -EINVAL;
  if (ret < 0) goto err;
  if (IS_ENABLED(CONFIG_PASSWD_CRYPTO_PBKDF2)) {
    char* key = passwd2_sum + PBKDF2_SALT_LEN;
    char* salt = passwd2_sum;
    int keylen = PBKDF2_LENGTH - PBKDF2_SALT_LEN;
    ret = pkcs5_pbkdf2_hmac_sha1(passwd, length, salt, PBKDF2_SALT_LEN,
                                 PBKDF2_COUNT, keylen, passwd1_sum);
    if (ret) goto err;
    if (strncmp(passwd1_sum, key, keylen) == 0) ret = 1;
  } else {
    ret = digest_digest(d, passwd, length, passwd1_sum);
    if (ret) goto err;
    if (strncmp(passwd1_sum, passwd2_sum, hash_len) == 0) ret = 1;
  }
err:
  free(passwd1_sum);
  digest_free(d);
  return ret;
}

int au1100fb_fb_mmap(struct fb_info* fbi, struct vm_area_struct* vma) {
  struct au1100fb_device* fbdev;
  unsigned int len;
  unsigned long start = 0, off;
  fbdev = to_au1100fb_device(fbi);
  if (vma->vm_pgoff > (~0UL >> PAGE_SHIFT)) {
    return -EINVAL;
  }
  start = fbdev->fb_phys & PAGE_MASK;
  len = PAGE_ALIGN((start & ~PAGE_MASK) + fbdev->fb_len);
  off = vma->vm_pgoff << PAGE_SHIFT;
  if ((vma->vm_end - vma->vm_start + off) > len) {
    return -EINVAL;
  }
  off += start;
  vma->vm_pgoff = off >> PAGE_SHIFT;
  vma->vm_page_prot = pgprot_noncached(vma->vm_page_prot);
  pgprot_val(vma->vm_page_prot) |= (6 << 9);
  if (io_remap_pfn_range(vma, vma->vm_start, off >> PAGE_SHIFT,
                         vma->vm_end - vma->vm_start, vma->vm_page_prot)) {
    return -EAGAIN;
  }
  return 0;
}

int db__message_store_find(struct mosquitto* context, uint16_t mid,
                           struct mosquitto_msg_store** stored) {
  struct mosquitto_client_msg* tail;
  if (!context) return MOSQ_ERR_INVAL;
  *stored = NULL;
  DL_FOREACH(context->msgs_in.inflight, tail) {
    if (tail->store->source_mid == mid) {
      *stored = tail->store;
      return MOSQ_ERR_SUCCESS;
    }
  }
  DL_FOREACH(context->msgs_in.queued, tail) {
    if (tail->store->source_mid == mid) {
      *stored = tail->store;
      return MOSQ_ERR_SUCCESS;
    }
  }
  return 1;
}

int hsr_dev_finalize(struct net_device* hsr_dev, struct net_device* slave[2],
                     unsigned char multicast_spec, u8 protocol_version) {
  struct hsr_priv* hsr;
  struct hsr_port* port;
  int res;
  hsr = netdev_priv(hsr_dev);
  INIT_LIST_HEAD(&hsr->ports);
  INIT_LIST_HEAD(&hsr->node_db);
  INIT_LIST_HEAD(&hsr->self_node_db);
  ether_addr_copy(hsr_dev->dev_addr, slave[0]->dev_addr);
  res = hsr_create_self_node(&hsr->self_node_db, hsr_dev->dev_addr,
                             slave[1]->dev_addr);
  if (res < 0) return res;
  spin_lock_init(&hsr->seqnr_lock);
  hsr->sequence_nr = HSR_SEQNR_START;
  hsr->sup_sequence_nr = HSR_SUP_SEQNR_START;
  timer_setup(&hsr->announce_timer, hsr_announce, 0);
  timer_setup(&hsr->prune_timer, hsr_prune_nodes, 0);
  ether_addr_copy(hsr->sup_multicast_addr, def_multicast_addr);
  hsr->sup_multicast_addr[ETH_ALEN - 1] = multicast_spec;
  hsr->protVersion = protocol_version;
  netif_carrier_off(hsr_dev);
  res = hsr_add_port(hsr, hsr_dev, HSR_PT_MASTER);
  if (res) return res;
  res = register_netdevice(hsr_dev);
  if (res) goto fail;
  res = hsr_add_port(hsr, slave[0], HSR_PT_SLAVE_A);
  if (res) goto fail;
  res = hsr_add_port(hsr, slave[1], HSR_PT_SLAVE_B);
  if (res) goto fail;
  mod_timer(&hsr->prune_timer, jiffies + msecs_to_jiffies(PRUNE_PERIOD));
  return 0;
fail:
  hsr_for_each_port(hsr, port) hsr_del_port(port);
  return res;
}

int CommandData::IsProcessFile(FileHeader& FileHead, bool* ExactMatch,
                               int MatchType, wchar* MatchedArg,
                               uint MatchedArgSize) {
  if (MatchedArg != NULL && MatchedArgSize > 0) *MatchedArg = 0;
  if (wcslen(FileHead.FileName) >= NM) return 0;
  bool Dir = FileHead.Dir;
  if (ExclCheck(FileHead.FileName, Dir, false, true)) return 0;
#ifndef SFX_MODULE
  if (TimeCheck(FileHead.mtime)) return 0;
  if ((FileHead.FileAttr & ExclFileAttr) != 0 ||
      InclAttrSet && (FileHead.FileAttr & InclFileAttr) == 0)
    return 0;
  if (!Dir && SizeCheck(FileHead.UnpSize)) return 0;
#endif
  wchar* ArgName;
  FileArgs.Rewind();
  for (int StringCount = 1; (ArgName = FileArgs.GetString()) != NULL;
       StringCount++)
    if (CmpName(ArgName, FileHead.FileName, MatchType)) {
      if (ExactMatch != NULL)
        *ExactMatch = wcsicompc(ArgName, FileHead.FileName) == 0;
      if (MatchedArg != NULL) wcsncpyz(MatchedArg, ArgName, MatchedArgSize);
      return StringCount;
    }
  return 0;
}

write(Protocol_* iprot, const StructInfo& structInfo, const void* object) {
  DCHECK(object);
  size_t written = iprot->writeStructBegin(structInfo.name);
  if (UNLIKELY(structInfo.unionExt != nullptr)) {
    const FieldInfo* end = structInfo.fieldInfos + structInfo.numFields;
    const auto& unionId =
        activeUnionMemberId(object, structInfo.unionExt->unionTypeOffset);
    const FieldInfo* found = std::lower_bound(
        structInfo.fieldInfos, end, unionId,
        [](const FieldInfo& lhs, FieldID rhs) { return lhs.id < rhs; });
    if (found < end && found->id == unionId) {
      const OptionalThriftValue value = getValue(*found->typeInfo, object);
      if (value.hasValue()) {
        written += writeField(iprot, *found, value.value());
      } else if (found->typeInfo->type == protocol::TType::T_STRUCT) {
        written += iprot->writeFieldBegin(found->name, found->typeInfo->type,
                                          found->id);
        written += iprot->writeStructBegin(found->name);
        written += iprot->writeStructEnd();
        written += iprot->writeFieldStop();
        written += iprot->writeFieldEnd();
      }
    }
  } else {
    for (std::int16_t index = 0; index < structInfo.numFields; index++) {
      const auto& fieldInfo = structInfo.fieldInfos[index];
      if (fieldInfo.isUnqualified || fieldInfo.issetOffset == 0 ||
          fieldIsSet(object, fieldInfo.issetOffset)) {
        const OptionalThriftValue value =
            getValue(*fieldInfo.typeInfo, getMember(fieldInfo, object));
        if (value.hasValue()) {
          written += writeField(iprot, fieldInfo, value.value());
        }
      }
    }
  }
  written += iprot->writeFieldStop();
  written += iprot->writeStructEnd();
  return written;
}

ex_copy(linenr_T line1, linenr_T line2, linenr_T n) {
  linenr_T count;
  char_u* p;
  count = line2 - line1 + 1;
  if ((cmdmod.cmod_flags & CMOD_LOCKMARKS) == 0) {
    curbuf->b_op_start.lnum = n + 1;
    curbuf->b_op_end.lnum = n + count;
    curbuf->b_op_start.col = curbuf->b_op_end.col = 0;
  }
  if (u_save(n, n + 1) == FAIL) return;
  curwin->w_cursor.lnum = n;
  while (line1 <= line2) {
    p = vim_strsave(ml_get(line1));
    if (p != NULL) {
      ml_append(curwin->w_cursor.lnum, p, (colnr_T)0, FALSE);
      vim_free(p);
    }
    if (line1 == n) line1 = curwin->w_cursor.lnum;
    ++line1;
    if (curwin->w_cursor.lnum < line1) ++line1;
    if (curwin->w_cursor.lnum < line2) ++line2;
    ++curwin->w_cursor.lnum;
  }
  appended_lines_mark(n, count);
  msgmore((long)count);
}

