int infra_ip_ratelimit_inc(struct infra_cache* infra,
                           struct sockaddr_storage* addr, socklen_t addrlen,
                           time_t timenow, int has_cookie, int backoff,
                           struct sldns_buffer* buffer) {
  int max;
  struct lruhash_entry* entry;
  if (!infra_ip_ratelimit) {
    return 1;
  }
  entry = infra_find_ip_ratedata(infra, addr, addrlen, 1);
  if (entry) {
    int premax = infra_rate_max(entry->data, timenow, backoff);
    int* cur = infra_rate_give_second(entry->data, timenow);
    (*cur)++;
    max = infra_rate_max(entry->data, timenow, backoff);
    lock_rw_unlock(&entry->lock);
    return check_ip_ratelimit(addr, addrlen, buffer, premax, max, has_cookie);
  }
  infra_ip_create_ratedata(infra, addr, addrlen, timenow);
  return 1;
}

BOOL glyph_cache_put(rdpGlyphCache* glyphCache, UINT32 id, UINT32 index,
                     rdpGlyph* glyph) {
  rdpGlyph* prevGlyph;
  if (id > 9) {
    WLog_ERR(TAG, "invalid glyph cache id: %" PRIu32 "", id);
    return FALSE;
  }
  if (index > glyphCache->glyphCache[id].number) {
    WLog_ERR(TAG,
             "invalid glyph cache index: %" PRIu32 " in cache id: %" PRIu32 "",
             index, id);
    return FALSE;
  }
  WLog_Print(glyphCache->log, WLOG_DEBUG,
             "GlyphCachePut: id: %" PRIu32 " index: %" PRIu32 "", id, index);
  prevGlyph = glyphCache->glyphCache[id].entries[index];
