}

vq_endchains(struct virtio_vq_info* vq, int used_all_avail) {
  struct virtio_base* base;
  uint16_t event_idx, new_idx, old_idx;
  int intr;
  atomic_thread_fence();
  base = vq->base;
  old_idx = vq->save_used;
  vq->save_used = new_idx = vq->used->idx;
  if (used_all_avail &&
      (base->negotiated_caps & (1 << VIRTIO_F_NOTIFY_ON_EMPTY)))
    intr = 1;
  else if (base->negotiated_caps & (1 << VIRTIO_RING_F_EVENT_IDX)) {
    event_idx = VQ_USED_EVENT_IDX(vq);
    intr = (uint16_t)(new_idx - event_idx - 1) < (uint16_t)(new_idx - old_idx);
  } else {
    intr =
        new_idx != old_idx && !(vq->avail->flags & VRING_AVAIL_F_NO_INTERRUPT);
  }
  if (intr) vq_interrupt(base, vq);
}

String string_chunk_split(const char* src, int srclen, const char* end,
                          int endlen, int chunklen) {
  int chunks = srclen / chunklen;
  int restlen = srclen - chunks * chunklen;
  int out_len = (chunks + 1) * endlen + srclen;
  String ret(out_len, ReserveString);
  char* dest = ret.bufferSlice().ptr;
  const char* p;
  char* q;
  const char* pMax = src + srclen - chunklen + 1;
  for (p = src, q = dest; p < pMax;) {
    memcpy(q, p, chunklen);
    q += chunklen;
    memcpy(q, end, endlen);
    q += endlen;
    p += chunklen;
  }
  if (restlen) {
    memcpy(q, p, restlen);
    q += restlen;
    memcpy(q, end, endlen);
    q += endlen;
  }
  ret.setSize(q - dest);
  return ret;
}

static avifBool avifParseImageGridBox(avifImageGrid* grid, const uint8_t* raw,
                                      size_t rawLen) {
  BEGIN_STREAM(s, raw, rawLen);
  uint8_t version, flags;
  CHECK(avifROStreamRead(&s, &version, 1));
  if (version != 0) {
    return AVIF_FALSE;
  }
  CHECK(avifROStreamRead(&s, &flags, 1));
  CHECK(avifROStreamRead(&s, &grid->rows, 1));
  CHECK(avifROStreamRead(&s, &grid->columns, 1));
  ++grid->rows;
  ++grid->columns;
  uint32_t fieldLength = ((flags & 1) + 1) * 16;
  if (fieldLength == 16) {
    uint16_t outputWidth16, outputHeight16;
    CHECK(avifROStreamReadU16(&s, &outputWidth16));
    CHECK(avifROStreamReadU16(&s, &outputHeight16));
    grid->outputWidth = outputWidth16;
    grid->outputHeight = outputHeight16;
  } else {
    if (fieldLength != 32) {
      return AVIF_FALSE;
    }
    CHECK(avifROStreamReadU32(&s, &grid->outputWidth));
    CHECK(avifROStreamReadU32(&s, &grid->outputHeight));
  }
  return AVIF_TRUE;
}

u32 secure_ipv4_port_ephemeral(__be32 saddr, __be32 daddr, __be16 dport) {
  struct keydata* keyptr = get_keyptr();
  u32 hash[4];
  hash[0] = (__force u32)saddr;
  hash[1] = (__force u32)daddr;
  hash[2] = (__force u32)dport ^ keyptr->secret[10];
  hash[3] = keyptr->secret[11];
  return half_md4_transform(hash, keyptr->secret);
}

bit_write_MC(Bit_Chain* dat, BITCODE_MC val) {
  int i, j;
  int negative = 0;
  unsigned char byte[5];
  BITCODE_UMC mask = 0x0000007f;
  BITCODE_UMC value = (BITCODE_UMC)val;
  if (val < 0) {
    negative = 1;
    value = (BITCODE_UMC)-val;
  }
  for (i = 4, j = 0; i >= 0; i--, j += 7) {
    byte[i] = (unsigned char)((value & mask) >> j);
    byte[i] |= 0x80;
    mask = mask << 7;
  }
  for (i = 0; i < 4; i++)
    if (byte[i] & 0x7f) break;
  if (byte[i] & 0x40) i--;
  byte[i] &= 0x7f;
  if (negative) byte[i] |= 0x40;
  for (j = 4; j >= i; j--) bit_write_RC(dat, byte[j]);
}

static void Rp_test(js_State* J) {
  js_Regexp* re;
  const char* text;
  int opts;
  Resub m;
  re = js_toregexp(J, 0);
  text = js_tostring(J, 1);
  opts = 0;
  if (re->flags & JS_REGEXP_G) {
    if (re->last > strlen(text)) {
      re->last = 0;
      js_pushboolean(J, 0);
      return;
    }
    if (re->last > 0) {
      text += re->last;
      opts |= REG_NOTBOL;
    }
  }
  if (!js_regexec(re->prog, text, &m, opts)) {
    if (re->flags & JS_REGEXP_G) re->last = re->last + (m.sub[0].ep - text);
    js_pushboolean(J, 1);
    return;
  }
  if (re->flags & JS_REGEXP_G) re->last = 0;
  js_pushboolean(J, 0);
}

