bool DNP3_Base::AddToBuffer(Endpoint* endp, int target_len, const u_char** data,
                            int* len) {
  if (!target_len) return true;
  int to_copy = min(*len, target_len - endp->buffer_len);
  memcpy(endp->buffer + endp->buffer_len, *data, to_copy);
  *data += to_copy;
  *len -= to_copy;
  endp->buffer_len += to_copy;
  return endp->buffer_len == target_len;
}

void Compute(OpKernelContext* ctx) override {
  const Tensor& input = ctx->input(0);
  const float input_min_float = ctx->input(1).flat<float>()(0);
  const float input_max_float = ctx->input(2).flat<float>()(0);
  Tensor* output_min = nullptr;
  OP_REQUIRES_OK(ctx, ctx->allocate_output(0, TensorShape({}), &output_min));
  Tensor* output_max = nullptr;
  OP_REQUIRES_OK(ctx, ctx->allocate_output(1, TensorShape({}), &output_max));
  qint32 used_min_quantized;
  qint32 used_max_quantized;
  CalculateUsedRange(input, &used_min_quantized, &used_max_quantized);
  const float used_min_float = std::min(
      0.0f,
      QuantizedToFloat(used_min_quantized, input_min_float, input_max_float));
  const float used_max_float =
      QuantizedToFloat(used_max_quantized, input_min_float, input_max_float);
  output_min->flat<float>().setConstant(used_min_float);
  output_max->flat<float>().setConstant(used_max_float);
}

gst_mpegts_section_new(guint16 pid, guint8* data, gsize data_size) {
  GstMpegtsSection* res = NULL;
  guint8 tmp;
  guint8 table_id;
  guint16 section_length;
  section_length = GST_READ_UINT16_BE(data + 1) & 0x0FFF;
  if (G_UNLIKELY(data_size < section_length + 3)) goto short_packet;
  table_id = *data;
  res = _gst_mpegts_section_init(pid, table_id);
  res->data = data;
  data++;
  res->short_section = (*data & 0x80) == 0x00;
  res->section_length = section_length + 3;
  if (!res->short_section) {
    res->crc = GST_READ_UINT32_BE(res->data + res->section_length - 4);
    data += 2;
    res->subtable_extension = GST_READ_UINT16_BE(data);
    data += 2;
    tmp = *data++;
    res->version_number = tmp >> 1 & 0x1f;
    res->current_next_indicator = tmp & 0x01;
    res->section_number = *data++;
    res->last_section_number = *data;
  }
  return res;
short_packet: {
  GST_WARNING(
      "PID 0x%04x section extends past provided data (got:%" G_GSIZE_FORMAT
      ", need:%d)",
      pid, data_size, section_length + 3);
  g_free(data);
  return NULL;
}
}

static void coroutine_fn v9fs_wstat(void* opaque) {
  int32_t fid;
  int err = 0;
  int16_t unused;
  V9fsStat v9stat;
  size_t offset = 7;
  struct stat stbuf;
  V9fsFidState* fidp;
  V9fsPDU* pdu = opaque;
  v9fs_stat_init(&v9stat);
