static bool pb_release_union_field(pb_istream_t* stream,
                                   pb_field_iter_t* field) {
  pb_field_iter_t old_field = *field;
  pb_size_t old_tag = *(pb_size_t*)field->pSize;
  pb_size_t new_tag = field->tag;
  if (old_tag == 0) return true;
  if (old_tag == new_tag) return true;
  if (!pb_field_iter_find(&old_field, old_tag))
    PB_RETURN_ERROR(stream, "invalid union tag");
  pb_release_single_field(&old_field);
  return true;
}

static void coroutine_fn v9fs_xattrcreate(void* opaque) {
  int flags;
  int32_t fid;
  int64_t size;
  ssize_t err = 0;
  V9fsString name;
  size_t offset = 7;
  V9fsFidState* file_fidp;
  V9fsFidState* xattr_fidp;
  V9fsPDU* pdu = opaque;
  v9fs_string_init(&name);
  err = pdu_unmarshal(pdu, offset, "dsqd", &fid, &name, &size, &flags);
  if (err < 0) {
    goto out_nofid;
  }
  trace_v9fs_xattrcreate(pdu->tag, pdu->id, fid, name.data, size, flags);
  file_fidp = get_fid(pdu, fid);
  if (file_fidp == NULL) {
    err = -EINVAL;
    goto out_nofid;
  }
  xattr_fidp = file_fidp;
  xattr_fidp->fid_type = P9_FID_XATTR;
  xattr_fidp->fs.xattr.copied_len = 0;
  xattr_fidp->fs.xattr.len = size;
  xattr_fidp->fs.xattr.flags = flags;
  v9fs_string_init(&xattr_fidp->fs.xattr.name);
  v9fs_string_copy(&xattr_fidp->fs.xattr.name, &name);
  xattr_fidp->fs.xattr.value = g_malloc(size);
  err = offset;
  put_fid(pdu, file_fidp);
out_nofid:
  pdu_complete(pdu, err);
  v9fs_string_free(&name);
}

ut64 MACH0_(get_main)(struct MACH0_(obj_t) * bin) {
  ut64 addr = 0LL;
  struct symbol_t* symbols;
  int i;
  if (!(symbols = MACH0_(get_symbols)(bin))) {
    return 0;
  }
  for (i = 0; !symbols[i].last; i++) {
    if (!strcmp(symbols[i].name, "_main")) {
      addr = symbols[i].addr;
      break;
    }
  }
  free(symbols);
  if (!addr && bin->main_cmd.cmd == LC_MAIN) {
    addr = bin->entry + bin->baddr;
  }
  if (!addr) {
    ut8 b[128];
    ut64 entry = addr_to_offset(bin, bin->entry);
    if (entry > bin->size || entry + sizeof(b) > bin->size) return 0;
    i = r_buf_read_at(bin->b, entry, b, sizeof(b));
    if (i < 1) {
      return 0;
    }
    for (i = 0; i < 64; i++) {
      if (b[i] == 0xe8 && !b[i + 3] && !b[i + 4]) {
        int delta =
            b[i + 1] | (b[i + 2] << 8) | (b[i + 3] << 16) | (b[i + 4] << 24);
        return bin->entry + i + 5 + delta;
      }
    }
  }
  return addr;
}

absl::Status IsSupported(const TfLiteContext* context,
                         const TfLiteNode* tflite_node,
                         const TfLiteRegistration* registration) final {
  if (mirror_pad_) {
    const TfLiteMirrorPaddingParams* tf_options;
    RETURN_IF_ERROR(RetrieveBuiltinData(tflite_node, &tf_options));
    if (tf_options->mode !=
        TfLiteMirrorPaddingMode::kTfLiteMirrorPaddingReflect) {
      return absl::InvalidArgumentError(
          "Only Reflective padding is supported for Mirror Pad operation.");
    }
  }
  RETURN_IF_ERROR(CheckMaxSupportedOpVersion(registration, 2));
  RETURN_IF_ERROR(CheckInputsOutputs(context, tflite_node, 1, 1));
  RETURN_IF_ERROR(CheckTensorIsAvailable(context, tflite_node, 1));
  auto pad_tensor = tflite::GetInput(context, tflite_node, 1);
  if (pad_tensor->dims->size != 2) {
    return absl::InvalidArgumentError(
        absl::StrCat("Invalid paddings tensor dimension: expected 2 dim, got ",
                     pad_tensor->dims->size, " dim"));
  }
  bool supported =
      pad_tensor->dims->data[0] == 3 || pad_tensor->dims->data[0] == 4;
  if (!supported || pad_tensor->dims->data[1] != 2) {
    return absl::InvalidArgumentError(absl::StrCat(
        "Invalid paddings tensor shape: expected 4x2 or 3x2, got ",
        pad_tensor->dims->data[0], "x", pad_tensor->dims->data[1]));
  }
  return absl::OkStatus();
}

mptctl_eventenable(unsigned long arg) {
  struct mpt_ioctl_eventenable __user* uarg = (void __user*)arg;
  struct mpt_ioctl_eventenable karg;
  MPT_ADAPTER* ioc;
  int iocnum;
  if (copy_from_user(&karg, uarg, sizeof(struct mpt_ioctl_eventenable))) {
    printk(KERN_ERR MYNAM
           "%s@%d::mptctl_eventenable - "
           "Unable to read in mpt_ioctl_eventenable struct @ %p\n",
           __FILE__, __LINE__, uarg);
    return -EFAULT;
  }
  if (((iocnum = mpt_verify_adapter(karg.hdr.iocnum, &ioc)) < 0) ||
      (ioc == NULL)) {
    printk(KERN_DEBUG MYNAM "%s::mptctl_eventenable() @%d - ioc%d not found!\n",
           __FILE__, __LINE__, iocnum);
    return -ENODEV;
  }
  dctlprintk(
      ioc, printk(MYIOC_s_DEBUG_FMT "mptctl_eventenable called.\n", ioc->name));
  if (ioc->events == NULL) {
    int sz = MPTCTL_EVENT_LOG_SIZE * sizeof(MPT_IOCTL_EVENTS);
    ioc->events = kzalloc(sz, GFP_KERNEL);
    if (!ioc->events) {
      printk(MYIOC_s_ERR_FMT ": ERROR - Insufficient memory to add adapter!\n",
             ioc->name);
      return -ENOMEM;
    }
    ioc->alloc_total += sz;
    ioc->eventContext = 0;
  }
  ioc->eventTypes = karg.eventTypes;
  return 0;
}

static int __dwc3_gadget_kick_transfer(struct dwc3_ep* dep) {
  struct dwc3_gadget_ep_cmd_params params;
  struct dwc3_request* req;
  int starting;
  int ret;
  u32 cmd;
  if (!dwc3_calc_trbs_left(dep)) return 0;
  starting = !(dep->flags & DWC3_EP_BUSY);
  dwc3_prepare_trbs(dep);
  req = next_request(&dep->started_list);
  if (!req) {
    dep->flags |= DWC3_EP_PENDING_REQUEST;
    return 0;
  }
  memset(&params, 0, sizeof(params));
  if (starting) {
    params.param0 = upper_32_bits(req->trb_dma);
    params.param1 = lower_32_bits(req->trb_dma);
    cmd = DWC3_DEPCMD_STARTTRANSFER;
    if (usb_endpoint_xfer_isoc(dep->endpoint.desc))
      cmd |= DWC3_DEPCMD_PARAM(dep->frame_number);
  } else {
    cmd = DWC3_DEPCMD_UPDATETRANSFER | DWC3_DEPCMD_PARAM(dep->resource_index);
  }
  ret = dwc3_send_gadget_ep_cmd(dep, cmd, &params);
  if (ret < 0) {
    if (req->trb) memset(req->trb, 0, sizeof(struct dwc3_trb));
    dep->queued_requests--;
    dwc3_gadget_giveback(dep, req, ret);
    return ret;
  }
  dep->flags |= DWC3_EP_BUSY;
  if (starting) {
    dep->resource_index = dwc3_gadget_ep_get_transfer_index(dep);
    WARN_ON_ONCE(!dep->resource_index);
  }
  return 0;
}

void* UntrustedCacheMalloc::GetBuffer() {
  void** buffers = nullptr;
  void* buffer;
  bool is_pool_empty;
  {
    LockGuard spin_lock(&lock_);
    is_pool_empty = buffer_pool_.empty();
    if (is_pool_empty) {
      buffers =
          primitives::AllocateUntrustedBuffers(kPoolIncrement, kPoolEntrySize);
      for (int i = 0; i < kPoolIncrement; i++) {
        if (!buffers[i] ||
            !TrustedPrimitives::IsOutsideEnclave(buffers[i], kPoolEntrySize)) {
          abort();
        }
        buffer_pool_.push(buffers[i]);
      }
    }
    buffer = buffer_pool_.top();
    buffer_pool_.pop();
    busy_buffers_.insert(buffer);
  }
  if (is_pool_empty) {
    Free(buffers);
  }
  return buffer;
}

bool IsConvolutionOpSupported(const TfLiteRegistration* registration,
                              const TfLiteNode* node, TfLiteContext* context) {
  if (node->builtin_data == nullptr) return false;
  TfLiteFusedActivation activation;
  if (registration->builtin_code == kTfLiteBuiltinConv2d) {
    const auto* conv_params =
        reinterpret_cast<const TfLiteConvParams*>(node->builtin_data);
    activation = conv_params->activation;
  } else if (registration->builtin_code == kTfLiteBuiltinDepthwiseConv2d) {
    const auto* depthwise_conv_params =
        reinterpret_cast<const TfLiteDepthwiseConvParams*>(node->builtin_data);
    activation = depthwise_conv_params->activation;
  } else if (registration->builtin_code == kTfLiteBuiltinTransposeConv) {
    activation = kTfLiteActNone;
  } else {
    TF_LITE_KERNEL_LOG(
        context,
        "Invalid op: op must be Conv2D, DepthwiseConv2D or TransposeConv.");
    return false;
  }
  if (activation == kTfLiteActSignBit) {
    return false;
  }
  const int kOutputShapeTensor = 0;
  const int kWeightTensor = 1;
  const int kBiasTensor = 2;
  const TfLiteTensor* weights = GetInput(context, node, kWeightTensor);
  const int max_kernel_size = 16384;
  if (!IsConstantTensor(weights)) {
    return false;
  }
  if (weights->dims->data[1] > max_kernel_size ||
      weights->dims->data[2] > max_kernel_size) {
    return false;
  }
  if (registration->builtin_code == kTfLiteBuiltinTransposeConv) {
    if (!IsConstantTensor(GetInput(context, node, kOutputShapeTensor))) {
      return false;
    }
  } else {
    if (node->inputs->size >= kBiasTensor &&
        !IsConstantTensor(GetInput(context, node, kBiasTensor))) {
      return false;
    }
  }
  return true;
}

struct r_bin_dyldcache_obj_t* r_bin_dyldcache_from_bytes_new(const ut8* buf,
                                                             ut64 size) {
  struct r_bin_dyldcache_obj_t* bin;
  if (!(bin = malloc(sizeof(struct r_bin_dyldcache_obj_t)))) {
    return NULL;
  }
  memset(bin, 0, sizeof(struct r_bin_dyldcache_obj_t));
  if (!buf) {
    return r_bin_dyldcache_free(bin);
  }
  bin->b = r_buf_new();
  if (!r_buf_set_bytes(bin->b, buf, size)) {
    return r_bin_dyldcache_free(bin);
  }
  if (!r_bin_dyldcache_init(bin)) {
    return r_bin_dyldcache_free(bin);
  }
  bin->size = size;
  return bin;
}

