p11_rpc_buffer_get_byte_array(p11_buffer* buf, size_t* offset,
                              const unsigned char** data, size_t* length) {
  size_t off = *offset;
  uint32_t len;
  if (!p11_rpc_buffer_get_uint32(buf, &off, &len)) return false;
  if (len == 0xffffffff) {
    *offset = off;
    if (data) *data = NULL;
    if (length) *length = 0;
    return true;
  } else if (len >= 0x7fffffff) {
    p11_buffer_fail(buf);
    return false;
  }
  if (buf->len < len || *offset > buf->len - len) {
    p11_buffer_fail(buf);
    return false;
  }
  if (data) *data = (unsigned char*)buf->data + off;
  if (length) *length = len;
  *offset = off + len;
  return true;
}

soup_ntlm_parse_challenge(const char* challenge, char** nonce,
                          char** default_domain, gboolean* ntlmv2_session) {
  gsize clen;
  NTLMString domain;
  guchar* chall;
  guint32 flags;
  chall = g_base64_decode(challenge, &clen);
  if (clen < NTLM_CHALLENGE_DOMAIN_STRING_OFFSET ||
      clen < NTLM_CHALLENGE_NONCE_OFFSET + NTLM_CHALLENGE_NONCE_LENGTH) {
    g_free(chall);
    return FALSE;
  }
  memcpy(&flags, chall + NTLM_CHALLENGE_FLAGS_OFFSET, sizeof(flags));
  flags = GUINT_FROM_LE(flags);
  *ntlmv2_session = (flags & NTLM_FLAGS_NEGOTIATE_NTLMV2) ? TRUE : FALSE;
  if (default_domain) {
    memcpy(&domain, chall + NTLM_CHALLENGE_DOMAIN_STRING_OFFSET,
           sizeof(domain));
    domain.length = GUINT16_FROM_LE(domain.length);
    domain.offset = GUINT16_FROM_LE(domain.offset);
    if (clen < domain.length + domain.offset) {
      g_free(chall);
      return FALSE;
    }
    *default_domain = g_convert((char*)chall + domain.offset, domain.length,
                                "UTF-8", "UCS-2LE", NULL, NULL, NULL);
  }
  if (nonce) {
    *nonce = g_memdup(chall + NTLM_CHALLENGE_NONCE_OFFSET,
                      NTLM_CHALLENGE_NONCE_LENGTH);
  }
  g_free(chall);
  return TRUE;
}

static inline void* host_from_stream_offset(QEMUFile* f, ram_addr_t offset,
                                            int flags) {
  static RAMBlock* block = NULL;
  char id[256];
  uint8_t len;
  if (flags & RAM_SAVE_FLAG_CONTINUE) {
    if (!block) {
      error_report("Ack, bad migration stream!");
      return NULL;
    }
    return memory_region_get_ram_ptr(block->mr) + offset;
  }
  len = qemu_get_byte(f);
  qemu_get_buffer(f, (uint8_t*)id, len);
  id[len] = 0;
  QTAILQ_FOREACH(block, &ram_list.blocks, next) {
    if (!strncmp(id, block->idstr, sizeof(id)))
      return memory_region_get_ram_ptr(block->mr) + offset;
  }
  error_report("Can't find block %s!", id);
  return NULL;
}

expand_dynamic_string_token(struct link_map* l, const char* s) {
  size_t cnt;
  size_t total;
  char* result;
  cnt = DL_DST_COUNT(s, 1);
  if (cnt == 0) return local_strdup(s);
  total = DL_DST_REQUIRED(l, s, strlen(s), cnt);
  result = (char*)malloc(total + 1);
  if (result == NULL) return NULL;
  return DL_DST_SUBSTITUTE(l, s, result, 1);
}

sp<IMemory> MetadataRetrieverClient::getFrameAtTime(int64_t timeUs,
                                                    int option) {
  ALOGV("getFrameAtTime: time(%lld us) option(%d)", timeUs, option);
  Mutex::Autolock lock(mLock);
  Mutex::Autolock glock(sLock);
  mThumbnail.clear();
  if (mRetriever == NULL) {
    ALOGE("retriever is not initialized");
    return NULL;
  }
  VideoFrame* frame = mRetriever->getFrameAtTime(timeUs, option);
  if (frame == NULL) {
    ALOGE("failed to capture a video frame");
    return NULL;
  }
  size_t size = sizeof(VideoFrame) + frame->mSize;
  sp<MemoryHeapBase> heap =
      new MemoryHeapBase(size, 0, "MetadataRetrieverClient");
  if (heap == NULL) {
    ALOGE("failed to create MemoryDealer");
    delete frame;
    return NULL;
  }
  mThumbnail = new MemoryBase(heap, 0, size);
  if (mThumbnail == NULL) {
    ALOGE("not enough memory for VideoFrame size=%u", size);
    delete frame;
    return NULL;
  }
  VideoFrame* frameCopy = static_cast<VideoFrame*>(mThumbnail->pointer());
  frameCopy->mWidth = frame->mWidth;
  frameCopy->mHeight = frame->mHeight;
  frameCopy->mDisplayWidth = frame->mDisplayWidth;
  frameCopy->mDisplayHeight = frame->mDisplayHeight;
  frameCopy->mSize = frame->mSize;
  frameCopy->mRotationAngle = frame->mRotationAngle;
  ALOGV("rotation: %d", frameCopy->mRotationAngle);
  frameCopy->mData = (uint8_t*)frameCopy + sizeof(VideoFrame);
  memcpy(frameCopy->mData, frame->mData, frame->mSize);
  delete frame;
  return mThumbnail;
}

int bson_ensure_space(bson* b, const int bytesNeeded) {
  int pos = b->cur - b->data;
  char* orig = b->data;
  int new_size;
  if (pos + bytesNeeded <= b->dataSize) return BSON_OK;
  new_size = 1.5 * (b->dataSize + bytesNeeded);
  if (new_size < b->dataSize) {
    if ((b->dataSize + bytesNeeded) < INT_MAX)
      new_size = INT_MAX;
    else {
      b->err = BSON_SIZE_OVERFLOW;
      return BSON_ERROR;
    }
  }
  b->data = bson_realloc(b->data, new_size);
  if (!b->data) bson_fatal_msg(!!b->data, "realloc() failed");
  b->dataSize = new_size;
  b->cur += b->data - orig;
  return BSON_OK;
}

static int samldb_spn_uniqueness_check(struct samldb_ctx* ac,
                                       struct ldb_message_element* spn_el) {
  struct ldb_context* ldb = ldb_module_get_ctx(ac->module);
  int ret;
  const char* spn = NULL;
  size_t i;
  TALLOC_CTX* tmp_ctx = talloc_new(ac->msg);
  if (tmp_ctx == NULL) {
    return ldb_oom(ldb);
  }
  for (i = 0; i < spn_el->num_values; i++) {
    int n_components;
    spn = (char*)spn_el->values[i].data;
    n_components = count_spn_components(spn_el->values[i]);
    if (n_components > 3 || n_components < 2) {
      ldb_asprintf_errstring(ldb, "samldb: spn[%s] invalid with %u components",
                             spn, n_components);
      talloc_free(tmp_ctx);
      return LDB_ERR_CONSTRAINT_VIOLATION;
    }
    ret = check_spn_direct_collision(ldb, tmp_ctx, spn, ac->msg->dn);
    if (ret == LDB_ERR_COMPARE_TRUE) {
      DBG_INFO("SPN %s re-added to the same object\n", spn);
      talloc_free(tmp_ctx);
      return LDB_SUCCESS;
    }
    if (ret != LDB_SUCCESS) {
      DBG_ERR("SPN %s failed direct uniqueness check\n", spn);
      talloc_free(tmp_ctx);
      return ret;
    }
    ret = check_spn_alias_collision(ldb, tmp_ctx, spn, ac->msg->dn);
    if (ret == LDB_ERR_NO_SUCH_OBJECT) {
      break;
    }
    if (ret != LDB_SUCCESS) {
      DBG_ERR("SPN %s failed alias uniqueness check\n", spn);
      talloc_free(tmp_ctx);
      return ret;
    }
    DBG_INFO("SPN %s seems to be unique\n", spn);
  }
  talloc_free(tmp_ctx);
  return LDB_SUCCESS;
}

ext4_xattr_block_list(struct dentry* dentry, char* buffer, size_t buffer_size) {
  struct inode* inode = d_inode(dentry);
  struct buffer_head* bh = NULL;
  int error;
  struct mb_cache* ext4_mb_cache = EXT4_GET_MB_CACHE(inode);
  ea_idebug(inode, "buffer=%p, buffer_size=%ld", buffer, (long)buffer_size);
  error = 0;
  if (!EXT4_I(inode)->i_file_acl) goto cleanup;
  ea_idebug(inode, "reading block %llu",
            (unsigned long long)EXT4_I(inode)->i_file_acl);
  bh = sb_bread(inode->i_sb, EXT4_I(inode)->i_file_acl);
  error = -EIO;
  if (!bh) goto cleanup;
  ea_bdebug(bh, "b_count=%d, refcount=%d", atomic_read(&(bh->b_count)),
            le32_to_cpu(BHDR(bh)->h_refcount));
  if (ext4_xattr_check_block(inode, bh)) {
    EXT4_ERROR_INODE(inode, "bad block %llu", EXT4_I(inode)->i_file_acl);
    error = -EFSCORRUPTED;
    goto cleanup;
  }
  ext4_xattr_cache_insert(ext4_mb_cache, bh);
  error = ext4_xattr_list_entries(dentry, BFIRST(bh), buffer, buffer_size);
cleanup:
  brelse(bh);
  return error;
}

decode_sequence(const uint8_t* asn1, size_t len, const struct seq_info* seq,
                void* val) {
  krb5_error_code ret;
  const uint8_t* contents;
  size_t i, j, clen;
  taginfo t;
  assert(seq->n_fields > 0);
  for (i = 0; i < seq->n_fields; i++) {
    if (len == 0) break;
    ret = get_tag(asn1, len, &t, &contents, &clen, &asn1, &len);
    if (ret) goto error;
    for (; i < seq->n_fields; i++) {
      if (check_atype_tag(seq->fields[i], &t)) break;
      ret = omit_atype(seq->fields[i], val);
      if (ret) goto error;
    }
    if (i == seq->n_fields) break;
    ret = decode_atype(&t, contents, clen, seq->fields[i], val);
    if (ret) goto error;
  }
  for (; i < seq->n_fields; i++) {
    ret = omit_atype(seq->fields[i], val);
    if (ret) goto error;
  }
  return 0;
error:
  for (j = 0; j < i; j++) free_atype(seq->fields[j], val);
  for (j = 0; j < i; j++) free_atype_ptr(seq->fields[j], val);
  return ret;
}

void LanLinkProvider::addLink(
    const QString& deviceId, QSslSocket* socket, NetworkPacket* receivedPacket,
    LanDeviceLink::ConnectionStarted connectionOrigin) {
  disconnect(socket, &QAbstractSocket::disconnected, socket,
             &QObject::deleteLater);
  LanDeviceLink* deviceLink;
  QMap<QString, LanDeviceLink*>::iterator linkIterator = m_links.find(deviceId);
  if (linkIterator != m_links.end()) {
    deviceLink = linkIterator.value();
    deviceLink->reset(socket, connectionOrigin);
  } else {
    deviceLink = new LanDeviceLink(deviceId, this, socket, connectionOrigin);
    connect(deviceLink, &QObject::destroyed, this,
            &LanLinkProvider::deviceLinkDestroyed);
    m_links[deviceId] = deviceLink;
    if (m_pairingHandlers.contains(deviceId)) {
      Q_ASSERT(m_pairingHandlers.contains(deviceId));
      m_pairingHandlers[deviceId]->setDeviceLink(deviceLink);
    }
  }
  Q_EMIT onConnectionReceived(*receivedPacket, deviceLink);
}

int snmp_helper(void* context, size_t hdrlen, unsigned char tag,
                const void* data, size_t datalen) {
  struct snmp_ctx* ctx = (struct snmp_ctx*)context;
  __be32* pdata = (__be32*)data;
  if (*pdata == ctx->from) {
    pr_debug("%s: %pI4 to %pI4\n", __func__, (void*)&ctx->from,
             (void*)&ctx->to);
    if (*ctx->check) fast_csum(ctx, (unsigned char*)data - ctx->begin);
    *pdata = ctx->to;
  }
  return 1;
}

static void early_init_amd(struct cpuinfo_x86* c) {
  early_init_amd_mc(c);
  if (c->x86_power & (1 << 8)) {
    set_cpu_cap(c, X86_FEATURE_CONSTANT_TSC);
    set_cpu_cap(c, X86_FEATURE_NONSTOP_TSC);
    if (!check_tsc_unstable()) sched_clock_stable = 1;
  }
#ifdef CONFIG_X86_64
  set_cpu_cap(c, X86_FEATURE_SYSCALL32);
#else
  if (c->x86 == 5)
    if (c->x86_model == 13 || c->x86_model == 9 ||
        (c->x86_model == 8 && c->x86_mask >= 8))
      set_cpu_cap(c, X86_FEATURE_K6_MTRR);
#endif
#if defined(CONFIG_X86_LOCAL_APIC) && defined(CONFIG_PCI)
  if (cpu_has_apic && c->x86 >= 0xf) {
    unsigned int val;
    val = read_pci_config(0, 24, 0, 0x68);
    if ((val & ((1 << 17) | (1 << 18))) == ((1 << 17) | (1 << 18)))
      set_cpu_cap(c, X86_FEATURE_EXTD_APICID);
  }
#endif
}

static GF_Err BM_ParseGlobalQuantizer(GF_BifsDecoder* codec, GF_BitStream* bs,
                                      GF_List* com_list) {
  GF_Node* node;
  GF_Command* com;
  GF_CommandField* inf;
  node = gf_bifs_dec_node(codec, bs, NDT_SFWorldNode);
  if (!node) return GF_NON_COMPLIANT_BITSTREAM;
  if (codec->scenegraph->global_qp) {
    gf_node_unregister(codec->scenegraph->global_qp, NULL);
  }
  codec->ActiveQP = NULL;
  codec->scenegraph->global_qp = NULL;
  if (gf_node_get_tag(node) != TAG_MPEG4_QuantizationParameter) {
    gf_node_unregister(node, NULL);
    return GF_NON_COMPLIANT_BITSTREAM;
  }
  codec->ActiveQP = (M_QuantizationParameter*)node;
  codec->ActiveQP->isLocal = 0;
  codec->scenegraph->global_qp = node;
  node->sgprivate->num_instances = 2;
  com = gf_sg_command_new(codec->current_graph, GF_SG_GLOBAL_QUANTIZER);
  inf = gf_sg_command_field_new(com);
  inf->new_node = node;
  inf->field_ptr = &inf->new_node;
  inf->fieldType = GF_SG_VRML_SFNODE;
  gf_list_add(com_list, com);
  return GF_OK;
}

int nfc_dep_link_down(struct nfc_dev* dev) {
  int rc = 0;
  pr_debug("dev_name=%s\n", dev_name(&dev->dev));
  if (!dev->ops->dep_link_down) return -EOPNOTSUPP;
  device_lock(&dev->dev);
  if (!device_is_registered(&dev->dev)) {
    rc = -ENODEV;
    goto error;
  }
  if (dev->dep_link_up == false) {
    rc = -EALREADY;
    goto error;
  }
  rc = dev->ops->dep_link_down(dev);
  if (!rc) {
    dev->dep_link_up = false;
    dev->active_target = NULL;
    dev->rf_mode = NFC_RF_NONE;
    nfc_llcp_mac_is_down(dev);
    nfc_genl_dep_link_down_event(dev);
  }
error:
  device_unlock(&dev->dev);
  return rc;
}

SslSocket::SslSocket(Envoy::Ssl::ContextSharedPtr ctx, InitialState state,
                     const Network::TransportSocketOptionsConstSharedPtr&
                         transport_socket_options,
                     Ssl::HandshakerFactoryCb handshaker_factory_cb)
    : transport_socket_options_(transport_socket_options),
      ctx_(std::dynamic_pointer_cast<ContextImpl>(ctx)),
      info_(std::dynamic_pointer_cast<SslHandshakerImpl>(
