}

static int mincore_pte_range(pmd_t* pmd, unsigned long addr, unsigned long end,
                             struct mm_walk* walk) {
  spinlock_t* ptl;
  struct vm_area_struct* vma = walk->vma;
  pte_t* ptep;
  unsigned char* vec = walk->private;
  int nr = (end - addr) >> PAGE_SHIFT;
  ptl = pmd_trans_huge_lock(pmd, vma);
  if (ptl) {
    memset(vec, 1, nr);
    spin_unlock(ptl);
    goto out;
  }
  if (pmd_trans_unstable(pmd)) {
    __mincore_unmapped_range(addr, end, vma, vec);
    goto out;
  }
  ptep = pte_offset_map_lock(walk->mm, pmd, addr, &ptl);
  for (; addr != end; ptep++, addr += PAGE_SIZE) {
    pte_t pte = *ptep;
    if (pte_none(pte))
      __mincore_unmapped_range(addr, addr + PAGE_SIZE, vma, vec);
    else if (pte_present(pte))
      *vec = 1;
    else {
      swp_entry_t entry = pte_to_swp_entry(pte);
      if (non_swap_entry(entry)) {
        *vec = 1;
      } else {
#ifdef CONFIG_SWAP
        *vec = mincore_page(swap_address_space(entry), swp_offset(entry));
#else
        WARN_ON(1);
        *vec = 1;
#endif
      }
    }
    vec++;
  }
  pte_unmap_unlock(ptep - 1, ptl);
out:
  walk->private += nr;
  cond_resched();
  return 0;
}

TfLiteStatus ResizeOutput(TfLiteContext* context, const TfLiteTensor* input,
                          const TfLiteTensor* axis, TfLiteTensor* output) {
  int axis_value;
  if (axis->type == kTfLiteInt64) {
    axis_value = static_cast<int>(*GetTensorData<int64_t>(axis));
  } else {
    axis_value = *GetTensorData<int>(axis);
  }
  if (axis_value < 0) {
    axis_value += NumDimensions(input);
  }
  TfLiteIntArray* output_dims = TfLiteIntArrayCreate(NumDimensions(input) - 1);
  int j = 0;
  for (int i = 0; i < NumDimensions(input); ++i) {
    if (i != axis_value) {
      output_dims->data[j] = SizeOfDimension(input, i);
      ++j;
    }
  }
  return context->ResizeTensor(context, output, output_dims);
}

TfLiteStatus Eval(TfLiteContext* context, TfLiteNode* node) {
  OpContext op_context(context, node);
  switch (op_context.output->type) {
    case kTfLiteFloat32:
      TFLiteOperation<kernel_type, float, OpType>(context, node, op_context);
      break;
    case kTfLiteUInt8:
      TFLiteOperation<kernel_type, uint8_t, OpType>(context, node, op_context);
      break;
    case kTfLiteInt8:
      TFLiteOperation<kernel_type, int8_t, OpType>(context, node, op_context);
      break;
    case kTfLiteInt32:
      TFLiteOperation<kernel_type, int32_t, OpType>(context, node, op_context);
      break;
    case kTfLiteInt64:
      TFLiteOperation<kernel_type, int64_t, OpType>(context, node, op_context);
      break;
    case kTfLiteInt16:
      TFLiteOperation<kernel_type, int16_t, OpType>(context, node, op_context);
      break;
    default:
      context->ReportError(context,
                           "Type %d is currently not supported by Maximum.",
                           op_context.output->type);
      return kTfLiteError;
  }
  return kTfLiteOk;
}

LIBOPENMPT_MODPLUG_API unsigned int ModPlug_InstrumentName(ModPlugFile* file,
                                                           unsigned int qual,
                                                           char* buff) {
  const char* str;
  unsigned int retval;
  size_t tmpretval;
  if (!file) return 0;
  str = openmpt_module_get_instrument_name(file->mod, qual - 1);
  if (!str) {
    if (buff) {
      *buff = '\0';
    }
    return 0;
  }
  tmpretval = strlen(str);
  if (tmpretval >= INT_MAX) {
    tmpretval = INT_MAX - 1;
  }
  retval = (int)tmpretval;
  if (buff) {
    memcpy(buff, str, retval + 1);
    buff[retval] = '\0';
  }
  openmpt_free_string(str);
  return retval;
}

wb_prep(netdissect_options* ndo, const struct pkt_prep* prep, u_int len) {
  int n;
  const struct pgstate* ps;
  const u_char* ep = ndo->ndo_snapend;
  ND_PRINT((ndo, " wb-prep:"));
  if (len < sizeof(*prep)) {
    return (-1);
  }
  n = EXTRACT_32BITS(&prep->pp_n);
  ps = (const struct pgstate*)(prep + 1);
  while (--n >= 0 && !ND_TTEST(*ps)) {
    const struct id_off *io, *ie;
    char c = '<';
    ND_PRINT((ndo, " %u/%s:%u", EXTRACT_32BITS(&ps->slot),
              ipaddr_string(ndo, &ps->page.p_sid),
              EXTRACT_32BITS(&ps->page.p_uid)));
    io = (struct id_off*)(ps + 1);
    for (ie = io + ps->nid; io < ie && !ND_TTEST(*io); ++io) {
      ND_PRINT((ndo, "%c%s:%u", c, ipaddr_string(ndo, &io->id),
                EXTRACT_32BITS(&io->off)));
      c = ',';
    }
    ND_PRINT((ndo, ">"));
    ps = (struct pgstate*)io;
  }
  return ((u_char*)ps <= ep ? 0 : -1);
}

print_attr_string(netdissect_options* ndo, register const u_char* data,
                  u_int length, u_short attr_code) {
  register u_int i;
  ND_TCHECK2(data[0], length);
  switch (attr_code) {
    case TUNNEL_PASS:
      if (length < 3) {
        ND_PRINT((ndo, "%s", tstr));
        return;
      }
      if (*data && (*data <= 0x1F))
        ND_PRINT((ndo, "Tag[%u] ", *data));
      else
        ND_PRINT((ndo, "Tag[Unused] "));
      data++;
      length--;
      ND_PRINT((ndo, "Salt %u ", EXTRACT_16BITS(data)));
      data += 2;
      length -= 2;
      break;
    case TUNNEL_CLIENT_END:
    case TUNNEL_SERVER_END:
    case TUNNEL_PRIV_GROUP:
    case TUNNEL_ASSIGN_ID:
    case TUNNEL_CLIENT_AUTH:
    case TUNNEL_SERVER_AUTH:
      if (*data <= 0x1F) {
        if (length < 1) {
          ND_PRINT((ndo, "%s", tstr));
          return;
        }
        if (*data)
          ND_PRINT((ndo, "Tag[%u] ", *data));
        else
          ND_PRINT((ndo, "Tag[Unused] "));
        data++;
        length--;
      }
      break;
    case EGRESS_VLAN_NAME:
      ND_PRINT((ndo, "%s (0x%02x) ",
                tok2str(rfc4675_tagged, "Unknown tag", *data), *data));
      data++;
      length--;
      break;
  }
  for (i = 0; *data && i < length; i++, data++)
    ND_PRINT((ndo, "%c", (*data < 32 || *data > 126) ? '.' : *data));
  return;
trunc:
  ND_PRINT((ndo, "%s", tstr));
}

static int iscsi_add_notunderstood_response(
    char* key, char* value, struct iscsi_param_list* param_list) {
  struct iscsi_extra_response* extra_response;
  if (strlen(value) > VALUE_MAXLEN) {
    pr_err(
        "Value for notunderstood key \"%s\" exceeds %d,"
        " protocol error.\n",
        key, VALUE_MAXLEN);
    return -1;
  }
  extra_response = kzalloc(sizeof(struct iscsi_extra_response), GFP_KERNEL);
  if (!extra_response) {
    pr_err(
        "Unable to allocate memory for"
        " struct iscsi_extra_response.\n");
    return -1;
  }
  INIT_LIST_HEAD(&extra_response->er_list);
  strncpy(extra_response->key, key, strlen(key) + 1);
  strncpy(extra_response->value, NOTUNDERSTOOD, strlen(NOTUNDERSTOOD) + 1);
  list_add_tail(&extra_response->er_list, &param_list->extra_response_list);
  return 0;
}

