void HTMLFormElement::scheduleFormSubmission(FormSubmission* submission) {
  DCHECK(submission->method() == FormSubmission::PostMethod ||
         submission->method() == FormSubmission::GetMethod);
  DCHECK(submission->data());
  DCHECK(submission->form());
  if (submission->action().isEmpty()) return;
  if (document().isSandboxed(SandboxForms)) {
    document().addConsoleMessage(ConsoleMessage::create(
        SecurityMessageSource, ErrorMessageLevel,
        "Blocked form submission to '" + submission->action().elidedString() +
            "' because the form's frame is sandboxed and the 'allow-forms' "
            "permission is not set."));
    return;
  }
  if (protocolIsJavaScript(submission->action())) {
    if (!document().contentSecurityPolicy()->allowFormAction(
            submission->action()))
      return;
    document().frame()->script().executeScriptIfJavaScriptURL(
        submission->action(), this);
    return;
  }
  Frame* targetFrame = document().frame()->findFrameForNavigation(
      submission->target(), *document().frame());
  if (!targetFrame) {
    if (!LocalDOMWindow::allowPopUp(*document().frame()) &&
        !UserGestureIndicator::utilizeUserGesture())
      return;
    targetFrame = document().frame();
  } else {
    submission->clearTarget();
  }
  if (!targetFrame->host()) return;
  UseCounter::count(document(), UseCounter::FormsSubmitted);
  if (MixedContentChecker::isMixedFormAction(document().frame(),
                                             submission->action()))
    UseCounter::count(document().frame(),
                      UseCounter::MixedContentFormsSubmitted);
  if (targetFrame->isLocalFrame()) {
    toLocalFrame(targetFrame)
        ->navigationScheduler()
        .scheduleFormSubmission(&document(), submission);
  } else {
    FrameLoadRequest frameLoadRequest =
        submission->createFrameLoadRequest(&document());
    toRemoteFrame(targetFrame)->navigate(frameLoadRequest);
  }
}

static void encode_share_access(struct xdr_stream* xdr, int open_flags) {
  __be32* p;
  RESERVE_SPACE(8);
  switch (open_flags & (FMODE_READ | FMODE_WRITE)) {
    case FMODE_READ:
      WRITE32(NFS4_SHARE_ACCESS_READ);
      break;
    case FMODE_WRITE:
      WRITE32(NFS4_SHARE_ACCESS_WRITE);
      break;
    case FMODE_READ | FMODE_WRITE:
      WRITE32(NFS4_SHARE_ACCESS_BOTH);
      break;
    default:
      BUG();
  }
  WRITE32(0);
}

static int __init pcd_init(void) {
  struct pcd_unit* cd;
  int unit;
  if (disable) return -EINVAL;
  pcd_init_units();
  if (pcd_detect()) return -ENODEV;
  pcd_probe_capabilities();
  if (register_blkdev(major, name)) {
    for (unit = 0, cd = pcd; unit < PCD_UNITS; unit++, cd++) put_disk(cd->disk);
    return -EBUSY;
  }
  for (unit = 0, cd = pcd; unit < PCD_UNITS; unit++, cd++) {
    if (cd->present) {
      register_cdrom(&cd->info);
      cd->disk->private_data = cd;
      add_disk(cd->disk);
    }
  }
  return 0;
}

static struct socket* get_raw_socket(int fd) {
  struct {
    struct sockaddr_ll sa;
    char buf[MAX_ADDR_LEN];
  } uaddr;
  int r;
  struct socket* sock = sockfd_lookup(fd, &r);
  if (!sock) return ERR_PTR(-ENOTSOCK);
  if (sock->sk->sk_type != SOCK_RAW) {
    r = -ESOCKTNOSUPPORT;
    goto err;
  }
  r = sock->ops->getname(sock, (struct sockaddr*)&uaddr.sa, 0);
  if (r < 0) goto err;
  if (uaddr.sa.sll_family != AF_PACKET) {
    r = -EPFNOSUPPORT;
    goto err;
  }
  return sock;
err:
  sockfd_put(sock);
  return ERR_PTR(r);
}

Status OpLevelCostEstimator::PredictMaxPoolGrad(const OpContext& op_context,
                                                NodeCosts* node_costs) const {
  bool found_unknown_shapes = false;
  const auto& op_info = op_context.op_info;
  if (op_info.inputs_size() < 3) {
    return errors::InvalidArgument("MaxPoolGrad op has invalid inputs: ",
                                   op_info.ShortDebugString());
  }
  ConvolutionDimensions dims = OpDimensionsFromInputs(
      op_info.inputs(0).shape(), op_info, &found_unknown_shapes);
  int64_t ops = 0;
  if (dims.kx == 1 && dims.ky == 1) {
    ops = dims.batch * dims.ix * dims.iy * dims.iz;
  } else if (dims.kx <= dims.sx && dims.ky <= dims.sy) {
    ops = dims.batch * dims.iz *
          (dims.ox * dims.oy * (dims.kx * dims.ky - 1) + dims.ix * dims.iy);
  } else {
    ops = dims.batch * dims.iz *
          (dims.ox * dims.oy * (dims.kx * dims.ky - 1) + dims.ix * dims.iy * 2);
  }
  node_costs->num_compute_ops = ops;
  const int64_t input0_size =
      CalculateTensorSize(op_info.inputs(0), &found_unknown_shapes);
  const int64_t input2_size =
      CalculateTensorSize(op_info.inputs(2), &found_unknown_shapes);
  node_costs->num_input_bytes_accessed = {input0_size, 0, input2_size};
  const int64_t output_size =
      CalculateTensorSize(op_info.inputs(0), &found_unknown_shapes);
  node_costs->num_output_bytes_accessed = {output_size};
  node_costs->max_memory = output_size;
  if (found_unknown_shapes) {
    node_costs->inaccurate = true;
    node_costs->num_nodes_with_unknown_shapes = 1;
  }
  return Status::OK();
}

AudioSource::AudioSource(audio_source_t inputSource,
                         const String16& opPackageName, uint32_t sampleRate,
                         uint32_t channelCount, uint32_t outSampleRate)
    : mStarted(false),
      mSampleRate(sampleRate),
      mOutSampleRate(outSampleRate > 0 ? outSampleRate : sampleRate),
      mPrevSampleTimeUs(0),
      mFirstSampleTimeUs(-1ll),
      mNumFramesReceived(0),
      mNumClientOwnedBuffers(0) {
  ALOGV("sampleRate: %u, outSampleRate: %u, channelCount: %u", sampleRate,
        outSampleRate, channelCount);
  CHECK(channelCount == 1 || channelCount == 2);
  CHECK(sampleRate > 0);
  size_t minFrameCount;
  status_t status = AudioRecord::getMinFrameCount(
      &minFrameCount, sampleRate, AUDIO_FORMAT_PCM_16_BIT,
      audio_channel_in_mask_from_count(channelCount));
  if (status == OK) {
    uint32_t frameCount = kMaxBufferSize / sizeof(int16_t) / channelCount;
    size_t bufCount = 2;
    while ((bufCount * frameCount) < minFrameCount) {
      bufCount++;
    }
    mRecord = new AudioRecord(inputSource, sampleRate, AUDIO_FORMAT_PCM_16_BIT,
                              audio_channel_in_mask_from_count(channelCount),
                              opPackageName, (size_t)(bufCount * frameCount),
                              AudioRecordCallbackFunction, this, frameCount);
    mInitCheck = mRecord->initCheck();
    if (mInitCheck != OK) {
      mRecord.clear();
    }
  } else {
    mInitCheck = status;
  }
}

TfLiteStatus EvalHashtableImport(TfLiteContext* context, TfLiteNode* node) {
  const TfLiteTensor* input_resource_id_tensor =
      GetInput(context, node, kInputResourceIdTensor);
  const int resource_id = input_resource_id_tensor->data.i32[0];
  const TfLiteTensor* key_tensor = GetInput(context, node, kKeyTensor);
  const TfLiteTensor* value_tensor = GetInput(context, node, kValueTensor);
  Subgraph* subgraph = reinterpret_cast<Subgraph*>(context->impl_);
  auto& resources = subgraph->resources();
  auto* lookup = resource::GetHashtableResource(&resources, resource_id);
  TF_LITE_ENSURE(context, lookup != nullptr);
  TF_LITE_ENSURE_STATUS(
      lookup->CheckKeyAndValueTypes(context, key_tensor, value_tensor));
  auto result = lookup->Import(context, key_tensor, value_tensor);
  return result;
}

file_check_mem(struct magic_set* ms, unsigned int level) {
  size_t len;
  if (level >= ms->c.len) {
    len = (ms->c.len += 20) * sizeof(*ms->c.li);
    ms->c.li = CAST(struct level_info*,
                    (ms->c.li == NULL) ? malloc(len) : realloc(ms->c.li, len));
    if (ms->c.li == NULL) {
      file_oomem(ms, len);
      return -1;
    }
  }
  ms->c.li[level].got_match = 0;
#ifdef ENABLE_CONDITIONALS
  ms->c.li[level].last_match = 0;
  ms->c.li[level].last_cond = COND_NONE;
#endif
  return 0;
}

is_link_trusted(NautilusFile* file, gboolean is_launcher) {
