static void __munlock_pagevec(struct pagevec* pvec, struct zone* zone) {
  int i;
  int nr = pagevec_count(pvec);
  int delta_munlocked;
  struct pagevec pvec_putback;
  int pgrescued = 0;
  pagevec_init(&pvec_putback, 0);
  spin_lock_irq(zone_lru_lock(zone));
  for (i = 0; i < nr; i++) {
    struct page* page = pvec->pages[i];
    if (TestClearPageMlocked(page)) {
      if (__munlock_isolate_lru_page(page, false))
        continue;
      else
        __munlock_isolation_failed(page);
    }
    pagevec_add(&pvec_putback, pvec->pages[i]);
    pvec->pages[i] = NULL;
  }
  delta_munlocked = -nr + pagevec_count(&pvec_putback);
  __mod_zone_page_state(zone, NR_MLOCK, delta_munlocked);
  spin_unlock_irq(zone_lru_lock(zone));
  pagevec_release(&pvec_putback);
  for (i = 0; i < nr; i++) {
    struct page* page = pvec->pages[i];
    if (page) {
      lock_page(page);
      if (!__putback_lru_fast_prepare(page, &pvec_putback, &pgrescued)) {
        get_page(page);
        __munlock_isolated_page(page);
        unlock_page(page);
        put_page(page);
      }
    }
  }
  if (pagevec_count(&pvec_putback))
    __putback_lru_fast(&pvec_putback, pgrescued);
}

PS_SERIALIZER_DECODE_FUNC(php_binary) {
  const char* p;
  char* name;
  const char* endptr = val + vallen;
  zval* current;
  int namelen;
  int has_value;
  php_unserialize_data_t var_hash;
  PHP_VAR_UNSERIALIZE_INIT(var_hash);
  for (p = val; p < endptr;) {
    zval** tmp;
    namelen = ((unsigned char)(*p)) & (~PS_BIN_UNDEF);
    if (namelen < 0 || namelen > PS_BIN_MAX || (p + namelen) >= endptr) {
      return FAILURE;
    }
    name = estrndup(p + 1, namelen);
    p += namelen + 1;
    if (zend_hash_find(&EG(symbol_table), name, namelen + 1, (void**)&tmp) ==
        SUCCESS) {
      if ((Z_TYPE_PP(tmp) == IS_ARRAY &&
           Z_ARRVAL_PP(tmp) == &EG(symbol_table)) ||
          *tmp == PS(http_session_vars)) {
        efree(name);
        continue;
      }
    }
    if (has_value) {
      ALLOC_INIT_ZVAL(current);
      if (php_var_unserialize(&current, (const unsigned char**)&p,
                              (const unsigned char*)endptr,
                              &var_hash TSRMLS_CC)) {
        php_set_session_var(name, namelen, current, &var_hash TSRMLS_CC);
      } else {
        PHP_VAR_UNSERIALIZE_DESTROY(var_hash);
        return FAILURE;
      }
      var_push_dtor_no_addref(&var_hash, &current);
    }
    PS_ADD_VARL(name, namelen);
    efree(name);
  }
  PHP_VAR_UNSERIALIZE_DESTROY(var_hash);
  return SUCCESS;
}

static struct nlattr* reserve_sfa_size(struct sw_flow_actions** sfa,
                                       int attr_len, bool log) {
  struct sw_flow_actions* acts;
  int new_acts_size;
  size_t req_size = NLA_ALIGN(attr_len);
  int next_offset =
      offsetof(struct sw_flow_actions, actions) + (*sfa)->actions_len;
  if (req_size <= (ksize(*sfa) - next_offset)) goto out;
  new_acts_size = max(next_offset + req_size, ksize(*sfa) * 2);
  if (new_acts_size > MAX_ACTIONS_BUFSIZE) {
    if ((MAX_ACTIONS_BUFSIZE - next_offset) < req_size) {
      OVS_NLERR(log, "Flow action size exceeds max %u", MAX_ACTIONS_BUFSIZE);
      return ERR_PTR(-EMSGSIZE);
    }
    new_acts_size = MAX_ACTIONS_BUFSIZE;
  }
  acts = nla_alloc_flow_actions(new_acts_size);
  if (IS_ERR(acts)) return (void*)acts;
  memcpy(acts->actions, (*sfa)->actions, (*sfa)->actions_len);
  acts->actions_len = (*sfa)->actions_len;
  acts->orig_len = (*sfa)->orig_len;
  kfree(*sfa);
  *sfa = acts;
out:
  (*sfa)->actions_len += req_size;
  return (struct nlattr*)((unsigned char*)(*sfa) + next_offset);
}

isakmp_rfc3948_print(netdissect_options* ndo, const u_char* bp, u_int length,
                     const u_char* bp2) {
  if (length == 1 && bp[0] == 0xff) {
    ND_PRINT((ndo, "isakmp-nat-keep-alive"));
    return;
  }
  if (length < 4) {
    goto trunc;
  }
  if (bp[0] == 0 && bp[1] == 0 && bp[2] == 0 && bp[3] == 0) {
    ND_PRINT((ndo, "NONESP-encap: "));
    isakmp_print(ndo, bp + 4, length - 4, bp2);
    return;
  }
  {
    int nh, enh, padlen;
    int advance;
    ND_PRINT((ndo, "UDP-encap: "));
    advance = esp_print(ndo, bp, length, bp2, &enh, &padlen);
    if (advance <= 0) return;
    bp += advance;
    length -= advance + padlen;
    nh = enh & 0xff;
    ip_print_inner(ndo, bp, length, nh, bp2);
    return;
  }
trunc:
  ND_PRINT((ndo, "[|isakmp]"));
  return;
}

static void gsm_cleanup_mux(struct gsm_mux* gsm, bool disc) {
  int i;
  struct gsm_dlci* dlci = gsm->dlci[0];
  struct gsm_msg *txq, *ntxq;
  gsm->dead = true;
  mutex_lock(&gsm->mutex);
  if (dlci) {
    if (disc && dlci->state != DLCI_CLOSED) {
      gsm_dlci_begin_close(dlci);
      wait_event(gsm->event, dlci->state == DLCI_CLOSED);
    }
    dlci->dead = true;
  }
  del_timer_sync(&gsm->kick_timer);
  del_timer_sync(&gsm->t2_timer);
  del_timer_sync(&gsm->ka_timer);
  flush_work(&gsm->tx_work);
  if (gsm->has_devices) {
    gsm_unregister_devices(gsm_tty_driver, gsm->num);
    gsm->has_devices = false;
  }
  for (i = NUM_DLCI - 1; i >= 0; i--)
    if (gsm->dlci[i]) {
      gsm_dlci_release(gsm->dlci[i]);
      gsm->dlci[i] = NULL;
    }
  mutex_unlock(&gsm->mutex);
  tty_ldisc_flush(gsm->tty);
  list_for_each_entry_safe(txq, ntxq, &gsm->tx_ctrl_list, list) kfree(txq);
  INIT_LIST_HEAD(&gsm->tx_ctrl_list);
  list_for_each_entry_safe(txq, ntxq, &gsm->tx_data_list, list) kfree(txq);
  INIT_LIST_HEAD(&gsm->tx_data_list);
}

static char* handle_new_problem(GVariant* problem_info, uid_t caller_uid,
                                char** error) {
  problem_data_t* pd = problem_data_new();
  GVariantIter* iter;
  g_variant_get(problem_info, "a{ss}", &iter);
  gchar *key, *value;
  while (g_variant_iter_loop(iter, "{ss}", &key, &value)) {
    problem_data_add_text_editable(pd, key, value);
  }
  if (caller_uid != 0 ||
      problem_data_get_content_or_NULL(pd, FILENAME_UID) == NULL) {
    log_info("Adding UID %d to problem data", caller_uid);
    char buf[sizeof(uid_t) * 3 + 2];
    snprintf(buf, sizeof(buf), "%d", caller_uid);
    problem_data_add_text_noteditable(pd, FILENAME_UID, buf);
  }
  problem_data_add_basics(pd);
  char* problem_id = problem_data_save(pd);
  if (problem_id)
    notify_new_path(problem_id);
  else if (error)
    *error = xasprintf("Cannot create a new problem");
  problem_data_free(pd);
  return problem_id;
}

int read_escaped_char(yyscan_t yyscanner, uint8_t* escaped_char) {
  char text[4] = {0, 0, 0, 0};
  text[0] = '\\';
  text[1] = RE_YY_INPUT(yyscanner);
  if (text[1] == EOF) return 0;
  if (text[1] == 'x') {
    text[2] = RE_YY_INPUT(yyscanner);
    if (text[2] == EOF) return 0;
    text[3] = RE_YY_INPUT(yyscanner);
    if (text[3] == EOF) return 0;
  }
  *escaped_char = escaped_char_value(text);
  return 1;
}

static void* socketio_CloneOption(const char* name, const void* value) {
  void* result;
  if (name != NULL) {
    result = NULL;
    if (strcmp(name, OPTION_NET_INT_MAC_ADDRESS) == 0) {
      if (value == NULL) {
        LogError("Failed cloning option %s (value is NULL)", name);
      } else {
        if ((result = malloc(sizeof(char) * (strlen((char*)value) + 1))) ==
            NULL) {
          LogError("Failed cloning option %s (malloc failed)", name);
        } else {
          strcpy((char*)result, (char*)value);
        }
      }
    } else {
      LogError("Cannot clone option %s (not suppported)", name);
    }
  } else {
    result = NULL;
  }
  return result;
}

char* dexOptGenerateCacheFileName(const char* fileName,
                                  const char* subFileName) {
  char nameBuf[512];
  char absoluteFile[sizeof(nameBuf)];
  const size_t kBufLen = sizeof(nameBuf) - 1;
  const char* dataRoot;
  char* cp;
  absoluteFile[0] = '\0';
  if (fileName[0] != '/') {
    if (getcwd(absoluteFile, kBufLen) == NULL) {
      ALOGE("Can't get CWD while opening jar file");
      return NULL;
    }
    strncat(absoluteFile, "/", kBufLen);
  }
  strncat(absoluteFile, fileName, kBufLen);
  if (subFileName != NULL) {
    strncat(absoluteFile, "/", kBufLen);
    strncat(absoluteFile, subFileName, kBufLen);
  }
  cp = absoluteFile + 1;
  while (*cp != '\0') {
    if (*cp == '/') {
      *cp = '@';
    }
    cp++;
  }
  dataRoot = getenv("ANDROID_DATA");
  if (dataRoot == NULL) dataRoot = "/data";
  snprintf(nameBuf, kBufLen, "%s/%s", dataRoot, kCacheDirectoryName);
  if (strcmp(dataRoot, "/data") != 0) {
    int result = dexOptMkdir(nameBuf, 0700);
    if (result != 0 && errno != EEXIST) {
      ALOGE("Failed to create dalvik-cache directory %s: %s", nameBuf,
            strerror(errno));
      return NULL;
    }
  }
  snprintf(nameBuf, kBufLen, "%s/%s/%s", dataRoot, kCacheDirectoryName,
           kInstructionSet);
  if (strcmp(dataRoot, "/data") != 0) {
    int result = dexOptMkdir(nameBuf, 0700);
    if (result != 0 && errno != EEXIST) {
      ALOGE("Failed to create dalvik-cache directory %s: %s", nameBuf,
            strerror(errno));
      return NULL;
    }
  }
  strncat(nameBuf, absoluteFile, kBufLen);
  ALOGV("Cache file for '%s' '%s' is '%s'", fileName, subFileName, nameBuf);
  return strdup(nameBuf);
}

int DCTStream::getChars(int nChars, unsigned char* buffer) {
  for (int i = 0; i < nChars;) {
    if (current == limit) {
      if (!readLine()) return i;
    }
    int left = limit - current;
    if (nChars < left) left = nChars;
    memcpy(buffer + i, current, left);
    current += left;
    i += left;
  }
  return nChars;
}

static int __get_data_block(struct inode* inode, sector_t iblock,
                            struct buffer_head* bh, int create, int flag,
                            pgoff_t* next_pgofs) {
  struct f2fs_map_blocks map;
  int err;
  map.m_lblk = iblock;
  map.m_len = bh->b_size >> inode->i_blkbits;
  map.m_next_pgofs = next_pgofs;
  err = f2fs_map_blocks(inode, &map, create, flag);
  if (!err) {
    map_bh(bh, inode->i_sb, map.m_pblk);
    bh->b_state = (bh->b_state & ~F2FS_MAP_FLAGS) | map.m_flags;
    bh->b_size = map.m_len << inode->i_blkbits;
  }
  return err;
}

Agraph_t* agroot(void* obj) {
  switch (AGTYPE(obj)) {
    case AGINEDGE:
    case AGOUTEDGE:
      return ((Agedge_t*)obj)->node->root;
    case AGNODE:
      return ((Agnode_t*)obj)->root;
    case AGRAPH:
      return ((Agraph_t*)obj)->root;
    default:
      agerr(AGERR, "agroot of a bad object");
      return NILgraph;
  }
}

get_princs_2_svc(gprincs_arg* arg, struct svc_req* rqstp) {
  static gprincs_ret ret;
  char* prime_arg;
  gss_buffer_desc client_name, service_name;
  OM_uint32 minor_stat;
  kadm5_server_handle_t handle;
  const char* errmsg = NULL;
  xdr_free(xdr_gprincs_ret, &ret);
  if ((ret.code = new_server_handle(arg->api_version, rqstp, &handle)))
    goto exit_func;
  if ((ret.code = check_handle((void*)handle))) goto exit_func;
  ret.api_version = handle->api_version;
  if (setup_gss_names(rqstp, &client_name, &service_name) < 0) {
    ret.code = KADM5_FAILURE;
    goto exit_func;
  }
  prime_arg = arg->exp;
  if (prime_arg == NULL) prime_arg = "*";
  if (CHANGEPW_SERVICE(rqstp) ||
      !kadm5int_acl_check(handle->context, rqst2name(rqstp), ACL_LIST, NULL,
                          NULL)) {
    ret.code = KADM5_AUTH_LIST;
    log_unauth("kadm5_get_principals", prime_arg, &client_name, &service_name,
               rqstp);
  } else {
    ret.code =
        kadm5_get_principals((void*)handle, arg->exp, &ret.princs, &ret.count);
    if (ret.code != 0)
      errmsg = krb5_get_error_message(handle->context, ret.code);
    log_done("kadm5_get_principals", prime_arg, errmsg, &client_name,
             &service_name, rqstp);
    if (errmsg != NULL) krb5_free_error_message(handle->context, errmsg);
  }
  gss_release_buffer(&minor_stat, &client_name);
  gss_release_buffer(&minor_stat, &service_name);
exit_func:
  free_server_handle(handle);
  return &ret;
}

char* suhosin_encrypt_single_cookie(char* name, int name_len, char* value,
                                    int value_len, char* key TSRMLS_DC) {
  char buffer[4096];
  char buffer2[4096];
  char *buf = buffer, *buf2 = buffer2, *d, *d_url;
  int l;
  if (name_len > sizeof(buffer) - 2) {
    buf = estrndup(name, name_len);
  } else {
    memcpy(buf, name, name_len);
    buf[name_len] = 0;
  }
  name_len = php_url_decode(buf, name_len);
  normalize_varname(buf);
  name_len = strlen(buf);
  if (SUHOSIN_G(cookie_plainlist)) {
    if (zend_hash_exists(SUHOSIN_G(cookie_plainlist), buf, name_len + 1)) {
    encrypt_return_plain:
      if (buf != buffer) {
        efree(buf);
      }
      return estrndup(value, value_len);
    }
  } else if (SUHOSIN_G(cookie_cryptlist)) {
    if (!zend_hash_exists(SUHOSIN_G(cookie_cryptlist), buf, name_len + 1)) {
      goto encrypt_return_plain;
    }
  }
  if (strlen(value) <= sizeof(buffer2) - 2) {
    memcpy(buf2, value, value_len);
    buf2[value_len] = 0;
  } else {
    buf2 = estrndup(value, value_len);
  }
  value_len = php_url_decode(buf2, value_len);
  d = suhosin_encrypt_string(buf2, value_len, buf, name_len, key TSRMLS_CC);
  d_url = php_url_encode(d, strlen(d), &l);
  efree(d);
  if (buf != buffer) {
    efree(buf);
  }
  if (buf2 != buffer2) {
    efree(buf2);
  }
  return d_url;
}

