parse_user_name(char* user_input, char** ret_username) {
  register char* ptr;
  register int index = 0;
  char username[PAM_MAX_RESP_SIZE];
  *ret_username = NULL;
  bzero((void*)username, PAM_MAX_RESP_SIZE);
  ptr = user_input;
  while ((*ptr == ' ') || (*ptr == '\t')) ptr++;
  if (*ptr == '\0') {
    return (PAM_BUF_ERR);
  }
  while (*ptr != '\0') {
    if ((*ptr == ' ') || (*ptr == '\t'))
      break;
    else {
      username[index] = *ptr;
      index++;
      ptr++;
    }
  }
  if ((*ret_username = malloc(index + 1)) == NULL) return (PAM_BUF_ERR);
  (void)strcpy(*ret_username, username);
  return (PAM_SUCCESS);
}

openscript(char_u* name, int directly) {
  if (curscript + 1 == NSCRIPT) {
    emsg(_(e_nesting));
    return;
  }
#ifdef FEAT_EVAL
  if (ignore_script) return;
#endif
  if (scriptin[curscript] != NULL) ++curscript;
  expand_env(name, NameBuff, MAXPATHL);
  if ((scriptin[curscript] = mch_fopen((char*)NameBuff, READBIN)) == NULL) {
    semsg(_(e_notopen), name);
    if (curscript) --curscript;
    return;
  }
  if (save_typebuf() == FAIL) return;
  if (directly) {
    oparg_T oa;
    int oldcurscript;
    int save_State = State;
    int save_restart_edit = restart_edit;
    int save_insertmode = p_im;
    int save_finish_op = finish_op;
    int save_msg_scroll = msg_scroll;
    State = NORMAL;
    msg_scroll = FALSE;
    restart_edit = 0;
    p_im = FALSE;
    clear_oparg(&oa);
    finish_op = FALSE;
    oldcurscript = curscript;
    do {
      update_topline_cursor();
      normal_cmd(&oa, FALSE);
      vpeekc();
    } while (scriptin[oldcurscript] != NULL);
    State = save_State;
    msg_scroll = save_msg_scroll;
    restart_edit = save_restart_edit;
    p_im = save_insertmode;
    finish_op = save_finish_op;
  }
}

TRIO_PRIVATE void TrioWriteString TRIO_ARGS5(
    (self, string, flags, width, precision), trio_class_t* self,
    TRIO_CONST char* string, trio_flags_t flags, int width, int precision) {
  int length;
  int ch;
  assert(VALID(self));
  assert(VALID(self->OutStream));
  if (string == NULL) {
    string = internalNullString;
    length = sizeof(internalNullString) - 1;
#if TRIO_FEATURE_QUOTE
    flags &= (~FLAGS_QUOTE);
#endif
    width = 0;
  } else {
    if (precision == 0) {
      length = trio_length(string);
    } else {
      length = trio_length_max(string, precision);
    }
  }
  if ((NO_PRECISION != precision) && (precision < length)) {
    length = precision;
  }
  width -= length;
#if TRIO_FEATURE_QUOTE
  if (flags & FLAGS_QUOTE) self->OutStream(self, CHAR_QUOTE);
#endif
  if (!(flags & FLAGS_LEFTADJUST)) {
    while (width-- > 0) self->OutStream(self, CHAR_ADJUST);
  }
  while (length-- > 0) {
    ch = (int)((unsigned char)(*string++));
    TrioWriteStringCharacter(self, ch, flags);
  }
  if (flags & FLAGS_LEFTADJUST) {
    while (width-- > 0) self->OutStream(self, CHAR_ADJUST);
  }
#if TRIO_FEATURE_QUOTE
  if (flags & FLAGS_QUOTE) self->OutStream(self, CHAR_QUOTE);
#endif
}

