static int smtp_command_parse_parameters(struct smtp_command_parser* parser) {
  const unsigned char *p, *mp;
  uoff_t max_size =
      (parser->auth_response ? parser->limits.max_auth_size
                             : parser->limits.max_parameters_size);
  p = parser->cur + parser->state.poff;
  while (p < parser->end) {
    unichar_t ch;
    int nch = 1;
    if (parser->auth_response)
      ch = *p;
    else {
      nch = uni_utf8_get_char_n(p, (size_t)(p - parser->end), &ch);
    }
    if (nch < 0) {
      smtp_command_parser_error(
          parser, SMTP_COMMAND_PARSE_ERROR_BAD_COMMAND,
          "Invalid UTF-8 character in command parameters");
      return -1;
    }
    if ((parser->auth_response || (ch & 0x80) == 0x00) &&
        !smtp_char_is_textstr((unsigned char)ch))
      break;
    p += nch;
  }
  if (max_size > 0 && (uoff_t)(p - parser->cur) > max_size) {
    smtp_command_parser_error(
        parser, SMTP_COMMAND_PARSE_ERROR_LINE_TOO_LONG, "%s line is too long",
        (parser->auth_response ? "AUTH response" : "Command"));
    return -1;
  }
  parser->state.poff = p - parser->cur;
  if (p == parser->end) return 0;
  mp = p;
  if (mp > parser->cur) {
    while (mp > parser->cur && (*(mp - 1) == ' ' || *(mp - 1) == '\t')) mp--;
  }
  if (!parser->auth_response && mp > parser->cur && *parser->cur == ' ') {
    smtp_command_parser_error(parser, SMTP_COMMAND_PARSE_ERROR_BAD_COMMAND,
                              "Duplicate space after command name");
    return -1;
  }
  parser->state.cmd_params = i_strdup_until(parser->cur, mp);
  parser->cur = p;
  parser->state.poff = 0;
  return 1;
}

ecryptfs_decode_from_filename(unsigned char* dst, size_t* dst_size,
                              const unsigned char* src, size_t src_size) {
  u8 current_bit_offset = 0;
  size_t src_byte_offset = 0;
  size_t dst_byte_offset = 0;
  if (dst == NULL) {
    (*dst_size) = ecryptfs_max_decoded_size(src_size);
    goto out;
  }
  while (src_byte_offset < src_size) {
    unsigned char src_byte = filename_rev_map[(int)src[src_byte_offset]];
    switch (current_bit_offset) {
      case 0:
        dst[dst_byte_offset] = (src_byte << 2);
        current_bit_offset = 6;
        break;
      case 6:
        dst[dst_byte_offset++] |= (src_byte >> 4);
        dst[dst_byte_offset] = ((src_byte & 0xF) << 4);
        current_bit_offset = 4;
        break;
      case 4:
        dst[dst_byte_offset++] |= (src_byte >> 2);
        dst[dst_byte_offset] = (src_byte << 6);
        current_bit_offset = 2;
        break;
      case 2:
        dst[dst_byte_offset++] |= (src_byte);
        dst[dst_byte_offset] = 0;
        current_bit_offset = 0;
        break;
    }
    src_byte_offset++;
  }
  (*dst_size) = dst_byte_offset;
out:
  return;
}

static long cec_adap_g_log_addrs(struct cec_adapter* adap,
                                 struct cec_log_addrs __user* parg) {
  struct cec_log_addrs log_addrs;
