static int dccp_setsockopt_change(struct sock* sk, int type,
                                  struct dccp_so_feat __user* optval) {
  struct dccp_so_feat opt;
  u8* val;
  int rc;
  if (copy_from_user(&opt, optval, sizeof(opt))) return -EFAULT;
  val = kmalloc(opt.dccpsf_len, GFP_KERNEL);
  if (!val) return -ENOMEM;
  if (copy_from_user(val, opt.dccpsf_val, opt.dccpsf_len)) {
    rc = -EFAULT;
    goto out_free_val;
  }
  rc = dccp_feat_change(dccp_msk(sk), type, opt.dccpsf_feat, val,
                        opt.dccpsf_len, GFP_KERNEL);
  if (rc) goto out_free_val;
out:
  return rc;
out_free_val:
  kfree(val);
  goto out;
}

gnutls_session_get_data(gnutls_session_t session, void* session_data,
                        size_t* session_data_size) {
  gnutls_datum_t psession;
  int ret;
  if (session->internals.resumable == RESUME_FALSE)
    return GNUTLS_E_INVALID_SESSION;
  psession.data = session_data;
  ret = _gnutls_session_pack(session, &psession);
  if (ret < 0) {
    gnutls_assert();
    return ret;
  }
  *session_data_size = psession.size;
  if (psession.size > *session_data_size) {
    ret = GNUTLS_E_SHORT_MEMORY_BUFFER;
    goto error;
  }
  if (session_data != NULL) memcpy(session_data, psession.data, psession.size);
  ret = 0;
error:
  _gnutls_free_datum(&psession);
  return ret;
}

void SparseFillEmptyRowsOpImpl(OpKernelContext* context,
                               AsyncOpKernel::DoneCallback done = nullptr) {
  if (!done) {
    done = [] {};
  }
  const int kIndicesInput = 0;
  const int kValuesInput = 1;
  const int kDenseShapeInput = 2;
  const int kDefaultValueInput = 3;
  const Tensor& indices_t = context->input(kIndicesInput);
  const Tensor& values_t = context->input(kValuesInput);
  const Tensor& dense_shape_t = context->input(kDenseShapeInput);
  const Tensor& default_value_t = context->input(kDefaultValueInput);
  OP_REQUIRES_ASYNC(
      context, TensorShapeUtils::IsVector(dense_shape_t.shape()),
      errors::InvalidArgument("dense_shape must be a vector, saw: ",
                              dense_shape_t.shape().DebugString()),
      done);
  OP_REQUIRES_ASYNC(context, TensorShapeUtils::IsMatrix(indices_t.shape()),
                    errors::InvalidArgument("indices must be a matrix, saw: ",
                                            indices_t.shape().DebugString()),
                    done);
  OP_REQUIRES_ASYNC(context, TensorShapeUtils::IsVector(values_t.shape()),
                    errors::InvalidArgument("values must be a vector, saw: ",
                                            values_t.shape().DebugString()),
                    done);
  OP_REQUIRES_ASYNC(
      context, TensorShapeUtils::IsScalar(default_value_t.shape()),
      errors::InvalidArgument("default_value must be a scalar, saw: ",
                              default_value_t.shape().DebugString()),
      done);
  OP_REQUIRES_ASYNC(context, dense_shape_t.NumElements() != 0,
                    errors::InvalidArgument("Dense shape cannot be empty."),
                    done);
  using FunctorType = functor::SparseFillEmptyRows<Device, T, Tindex>;
  OP_REQUIRES_OK_ASYNC(context,
                       FunctorType()(context, default_value_t, indices_t,
                                     values_t, dense_shape_t, done),
                       done);
}

static int sclp_ctl_ioctl_sccb(void __user* user_area) {
  struct sclp_ctl_sccb ctl_sccb;
  struct sccb_header* sccb;
  int rc;
  if (copy_from_user(&ctl_sccb, user_area, sizeof(ctl_sccb))) return -EFAULT;
  if (!sclp_ctl_cmdw_supported(ctl_sccb.cmdw)) return -EOPNOTSUPP;
  sccb = (void*)get_zeroed_page(GFP_KERNEL | GFP_DMA);
  if (!sccb) return -ENOMEM;
  if (copy_from_user(sccb, u64_to_uptr(ctl_sccb.sccb), sizeof(*sccb))) {
    rc = -EFAULT;
    goto out_free;
  }
  if (sccb->length > PAGE_SIZE || sccb->length < 8) return -EINVAL;
  if (copy_from_user(sccb, u64_to_uptr(ctl_sccb.sccb), sccb->length)) {
    rc = -EFAULT;
    goto out_free;
  }
  rc = sclp_sync_request(ctl_sccb.cmdw, sccb);
  if (rc) goto out_free;
  if (copy_to_user(u64_to_uptr(ctl_sccb.sccb), sccb, sccb->length))
    rc = -EFAULT;
out_free:
  free_page((unsigned long)sccb);
  return rc;
}

int nfc_dev_down(struct nfc_dev* dev) {
  int rc = 0;
  pr_debug("dev_name=%s\n", dev_name(&dev->dev));
  device_lock(&dev->dev);
  if (!device_is_registered(&dev->dev)) {
    rc = -ENODEV;
    goto error;
  }
  if (!dev->dev_up) {
    rc = -EALREADY;
    goto error;
  }
  if (dev->polling || dev->active_target) {
    rc = -EBUSY;
    goto error;
  }
  if (dev->ops->dev_down) dev->ops->dev_down(dev);
  dev->dev_up = false;
error:
  device_unlock(&dev->dev);
  return rc;
}

void Compute(OpKernelContext* ctx) override {
  const Tensor& val = ctx->input(0);
  int64 id = ctx->session_state()->GetNewId();
  TensorStore::TensorAndKey tk{val, id, requested_device()};
  OP_REQUIRES_OK(ctx, ctx->tensor_store()->AddTensor(name(), tk));
  Tensor* handle = nullptr;
  OP_REQUIRES_OK(ctx, ctx->allocate_output(0, TensorShape({}), &handle));
  if (ctx->expected_output_dtype(0) == DT_RESOURCE) {
    ResourceHandle resource_handle = MakeResourceHandle<Tensor>(
        ctx, SessionState::kTensorHandleResourceTypeName, tk.GetHandle(name()));
    resource_handle.set_maybe_type_name(
        SessionState::kTensorHandleResourceTypeName);
    handle->scalar<ResourceHandle>()() = resource_handle;
  } else {
    handle->flat<tstring>().setConstant(tk.GetHandle(name()));
  }
}

static void nfs4_close_prepare(struct rpc_task* task, void* data) {
  struct nfs4_closedata* calldata = data;
  struct nfs4_state* state = calldata->state;
  int clear_rd, clear_wr, clear_rdwr;
  if (nfs_wait_on_sequence(calldata->arg.seqid, task) != 0) return;
  clear_rd = clear_wr = clear_rdwr = 0;
  spin_lock(&state->owner->so_lock);
  if (state->n_rdwr == 0) {
    if (state->n_rdonly == 0) {
      clear_rd |= test_and_clear_bit(NFS_O_RDONLY_STATE, &state->flags);
      clear_rdwr |= test_and_clear_bit(NFS_O_RDWR_STATE, &state->flags);
    }
    if (state->n_wronly == 0) {
      clear_wr |= test_and_clear_bit(NFS_O_WRONLY_STATE, &state->flags);
      clear_rdwr |= test_and_clear_bit(NFS_O_RDWR_STATE, &state->flags);
    }
  }
  spin_unlock(&state->owner->so_lock);
  if (!clear_rd && !clear_wr && !clear_rdwr) {
    task->tk_action = NULL;
    return;
  }
  nfs_fattr_init(calldata->res.fattr);
  if (test_bit(NFS_O_RDONLY_STATE, &state->flags) != 0) {
    task->tk_msg.rpc_proc = &nfs4_procedures[NFSPROC4_CLNT_OPEN_DOWNGRADE];
    calldata->arg.open_flags = FMODE_READ;
  } else if (test_bit(NFS_O_WRONLY_STATE, &state->flags) != 0) {
    task->tk_msg.rpc_proc = &nfs4_procedures[NFSPROC4_CLNT_OPEN_DOWNGRADE];
    calldata->arg.open_flags = FMODE_WRITE;
  }
  calldata->timestamp = jiffies;
  rpc_call_start(task);
}

static int decode_zbuf(AVBPrint* bp, const uint8_t* data,
                       const uint8_t* data_end) {
  z_stream zstream;
  unsigned char* buf;
  unsigned buf_size;
  int ret;
  zstream.zalloc = ff_png_zalloc;
  zstream.zfree = ff_png_zfree;
  zstream.opaque = NULL;
  if (inflateInit(&zstream) != Z_OK) return AVERROR_EXTERNAL;
  zstream.next_in = (unsigned char*)data;
  zstream.avail_in = data_end - data;
  av_bprint_init(bp, 0, -1);
  while (zstream.avail_in > 0) {
    av_bprint_get_buffer(bp, 1, &buf, &buf_size);
    if (!buf_size) {
      ret = AVERROR(ENOMEM);
      goto fail;
    }
    zstream.next_out = buf;
    zstream.avail_out = buf_size;
    ret = inflate(&zstream, Z_PARTIAL_FLUSH);
    if (ret != Z_OK && ret != Z_STREAM_END) {
      ret = AVERROR_EXTERNAL;
      goto fail;
    }
    bp->len += zstream.next_out - buf;
    if (ret == Z_STREAM_END) break;
  }
  inflateEnd(&zstream);
  bp->str[bp->len] = 0;
  return 0;
fail:
  inflateEnd(&zstream);
  av_bprint_finalize(bp, NULL);
  return ret;
}

static void br_multicast_del_pg(struct net_bridge* br,
                                struct net_bridge_port_group* pg) {
  struct net_bridge_mdb_htable* mdb;
  struct net_bridge_mdb_entry* mp;
  struct net_bridge_port_group* p;
  struct net_bridge_port_group __rcu** pp;
  mdb = mlock_dereference(br->mdb, br);
  mp = br_mdb_ip_get(mdb, &pg->addr);
  if (WARN_ON(!mp)) return;
  for (pp = &mp->ports; (p = mlock_dereference(*pp, br)) != NULL;
       pp = &p->next) {
    if (p != pg) continue;
    rcu_assign_pointer(*pp, p->next);
    hlist_del_init(&p->mglist);
    del_timer(&p->timer);
    call_rcu_bh(&p->rcu, br_multicast_free_pg);
    if (!mp->ports && !mp->mglist && netif_running(br->dev))
      mod_timer(&mp->timer, jiffies);
    return;
  }
  WARN_ON(1);
}

bool extract_sockaddr(char* url, char** sockaddr_url, char** sockaddr_port) {
  char *url_begin, *url_end, *ipv6_begin, *ipv6_end, *port_start = NULL;
  char url_address[256], port[6];
  int url_len, port_len = 0;
  *sockaddr_url = url;
        url_begin = strstr(url, "
	if (!url_begin)
		url_begin = url;
	else
		url_begin += 2;
	ipv6_begin = strstr(url_begin, "[");
	ipv6_end = strstr(url_begin, "]");
	if (ipv6_begin && ipv6_end && ipv6_end > ipv6_begin)
		url_end = strstr(ipv6_end, ":");
	else
		url_end = strstr(url_begin, ":");
	if (url_end) {
    url_len = url_end - url_begin;
    port_len = strlen(url_begin) - url_len - 1;
    if (port_len < 1) return false;
    port_start = url_end + 1;
	} else
		url_len = strlen(url_begin);
	if (url_len < 1)
		return false;
	sprintf(url_address, "%.*s", url_len, url_begin);
	if (port_len) {
    char* slash;
    snprintf(port, 6, "%.*s", port_len, port_start);
    slash = strchr(port, '/');
    if (slash) *slash = '\0';
	} else
		strcpy(port, "80");
	*sockaddr_port = strdup(port);
	*sockaddr_url = strdup(url_address);
	return true;
}

GetCode_(gdIOCtx* fd, CODE_STATIC_DATA* scd, int code_size, int flag,
         int* ZeroDataBlockP) {
  int i, j, ret;
  unsigned char count;
  if (flag) {
    scd->curbit = 0;
    scd->lastbit = 0;
    scd->last_byte = 2;
    scd->done = FALSE;
    return 0;
  }
  if ((scd->curbit + code_size) >= scd->lastbit) {
    if (scd->done) {
      if (scd->curbit >= scd->lastbit) {
      }
      return -1;
    }
    scd->buf[0] = scd->buf[scd->last_byte - 2];
    scd->buf[1] = scd->buf[scd->last_byte - 1];
    if ((count = GetDataBlock(fd, &scd->buf[2], ZeroDataBlockP)) <= 0) {
      scd->done = TRUE;
    }
    scd->last_byte = 2 + count;
    scd->curbit = (scd->curbit - scd->lastbit) + 16;
    scd->lastbit = (2 + count) * 8;
  }
  if ((scd->curbit + code_size - 1) >= (CSD_BUF_SIZE * 8)) {
    ret = -1;
  } else {
    ret = 0;
    for (i = scd->curbit, j = 0; j < code_size; ++i, ++j) {
      ret |= ((scd->buf[i / 8] & (1 << (i % 8))) != 0) << j;
    }
  }
  scd->curbit += code_size;
  return ret;
}

RoleName RoleName::parseFromBSON(const BSONElement& elem) {
  auto obj = elem.embeddedObjectUserCheck();
  std::array<BSONElement, 2> fields;
  obj.getFields({AuthorizationManager::ROLE_NAME_FIELD_NAME,
                 AuthorizationManager::ROLE_DB_FIELD_NAME},
                &fields);
  const auto& nameField = fields[0];
  uassert(ErrorCodes::BadValue,
          str::stream() << "user name must contain a string field named: "
                        << AuthorizationManager::ROLE_NAME_FIELD_NAME,
          nameField.type() == String);
  const auto& dbField = fields[1];
  uassert(ErrorCodes::BadValue,
          str::stream() << "role name must contain a string field named: "
                        << AuthorizationManager::ROLE_DB_FIELD_NAME,
          nameField.type() == String);
  return RoleName(nameField.valueStringData(), dbField.valueStringData());
}

yank_copy_line(struct block_def* bd, long y_idx, int exclude_trailing_space) {
  char_u* pnew;
  if (exclude_trailing_space) bd->endspaces = 0;
  if ((pnew = alloc(bd->startspaces + bd->endspaces + bd->textlen + 1)) == NULL)
    return FAIL;
  y_current->y_array[y_idx] = pnew;
  vim_memset(pnew, ' ', (size_t)bd->startspaces);
  pnew += bd->startspaces;
  mch_memmove(pnew, bd->textstart, (size_t)bd->textlen);
  pnew += bd->textlen;
  vim_memset(pnew, ' ', (size_t)bd->endspaces);
  pnew += bd->endspaces;
  if (exclude_trailing_space) {
    int s = bd->textlen + bd->endspaces;
    while (VIM_ISWHITE(*(bd->textstart + s - 1)) && s > 0) {
      s = s - (*mb_head_off)(bd->textstart, bd->textstart + s - 1) - 1;
      pnew--;
    }
  }
  *pnew = NUL;
  return OK;
}

static void wait_for_child_to_die(void* ctx) {
  REQUEST* request = ctx;
  rad_assert(request->magic == REQUEST_MAGIC);
  if ((request->child_state == REQUEST_QUEUED) ||
      ((request->child_state == REQUEST_RUNNING) &&
       (pthread_equal(request->child_pid, NO_SUCH_CHILD_PID) == 0))) {
    if (request->delay < (USEC * 60 * 5)) {
      request->delay += (request->delay >> 1);
      radlog(L_INFO,
             "WARNING: Child is hung for request %u in component %s module %s.",
             request->number, request->component, request->module);
    } else {
      RDEBUG2("Child is still stuck for request %u", request->number);
    }
    tv_add(&request->when, request->delay);
    INSERT_EVENT(wait_for_child_to_die, request);
    return;
  }
  RDEBUG2("Child is finally responsive for request %u", request->number);
  remove_from_request_hash(request);
#ifdef WITH_PROXY
  if (request->proxy) {
    wait_for_proxy_id_to_expire(request);
    return;
  }
#endif
  ev_request_free(&request);
}

QPDF::resolve(int objid, int generation) {
  QPDFObjGen og(objid, generation);
  if (!this->obj_cache.count(og)) {
    if (!this->xref_table.count(og)) {
      return new QPDF_Null;
    }
    QPDFXRefEntry const& entry = this->xref_table[og];
    switch (entry.getType()) {
      case 1: {
        qpdf_offset_t offset = entry.getOffset();
        int aobjid;
        int ageneration;
        QPDFObjectHandle oh = readObjectAtOffset(
            true, offset, "", objid, generation, aobjid, ageneration);
      } break;
      case 2:
        resolveObjectsInStream(entry.getObjStreamNumber());
        break;
      default:
        throw QPDFExc(qpdf_e_damaged_pdf, this->file->getName(), "", 0,
                      "object " + QUtil::int_to_string(objid) + "/" +
                          QUtil::int_to_string(generation) +
                          " has unexpected xref entry type");
    }
  }
  return this->obj_cache[og].object;
}

