static AVFrame* get_video_buffer(AVFilterLink* inlink, int w, int h) {
  PadContext* s = inlink->dst->priv;
  AVFrame* frame = ff_get_video_buffer(
      inlink->dst->outputs[0], w + (s->w - s->in_w), h + (s->h - s->in_h));
  int plane;
  if (!frame) return NULL;
  frame->width = w;
  frame->height = h;
  for (plane = 0; plane < 4 && frame->data[plane]; plane++) {
    int hsub = s->draw.hsub[plane];
    int vsub = s->draw.vsub[plane];
    frame->data[plane] += (s->x >> hsub) * s->draw.pixelstep[plane] +
                          (s->y >> vsub) * frame->linesize[plane];
  }
  return frame;
}

file_add_mapi_attrs(File* file, MAPI_Attr** attrs) {
  int i;
  for (i = 0; attrs[i]; i++) {
    MAPI_Attr* a = attrs[i];
    if (a->num_values) {
      switch (a->name) {
        case MAPI_ATTACH_LONG_FILENAME:
          if (file->name) XFREE(file->name);
          file->name = strdup((char*)a->values[0].data.buf);
          break;
        case MAPI_ATTACH_DATA_OBJ:
          file->len = a->values[0].len;
          if (file->data) XFREE(file->data);
          file->data = CHECKED_XMALLOC(unsigned char, file->len);
          memmove(file->data, a->values[0].data.buf, file->len);
          break;
        case MAPI_ATTACH_MIME_TAG:
          if (file->mime_type) XFREE(file->mime_type);
          file->mime_type = CHECKED_XMALLOC(char, a->values[0].len);
          memmove(file->mime_type, a->values[0].data.buf, a->values[0].len);
          break;
        case MAPI_ATTACH_CONTENT_ID:
          if (file->content_id) XFREE(file->content_id);
          file->content_id = CHECKED_XMALLOC(char, a->values[0].len);
          memmove(file->content_id, a->values[0].data.buf, a->values[0].len);
          break;
        default:
          break;
      }
    }
  }
}

static void cirrus_invalidate_region(CirrusVGAState* s, int off_begin,
                                     int off_pitch, int bytesperline,
                                     int lines) {
  int y;
  int off_cur;
  int off_cur_end;
  for (y = 0; y < lines; y++) {
    off_cur = off_begin;
    off_cur_end = (off_cur + bytesperline) & s->cirrus_addr_mask;
    memory_region_set_dirty(&s->vga.vram, off_cur, off_cur_end - off_cur);
    off_begin += off_pitch;
  }
  uint8_t* dst;
  dst = s->vga.vram_ptr + (s->cirrus_blt_dstaddr & s->cirrus_addr_mask);
  if (blit_is_unsafe(s, false)) return 0;
  (*s->cirrus_rop)(s, dst, src, s->cirrus_blt_dstpitch, 0, s->cirrus_blt_width,
                   s->cirrus_blt_height);
  cirrus_invalidate_region(s, s->cirrus_blt_dstaddr, s->cirrus_blt_dstpitch,
                           s->cirrus_blt_width, s->cirrus_blt_height);
  return 1;
}

R_API RBinJavaAttrInfo* r_bin_java_rtv_annotations_attr_new(RBinJavaObj* bin,
                                                            ut8* buffer,
                                                            ut64 sz,
                                                            ut64 buf_offset) {
  ut32 i = 0;
  ut64 offset = 0;
  if (buf_offset + 8 > sz) {
    return NULL;
  }
  RBinJavaAttrInfo* attr =
      r_bin_java_default_attr_new(bin, buffer, sz, buf_offset);
  offset += 6;
  if (attr) {
    attr->type = R_BIN_JAVA_ATTR_TYPE_RUNTIME_VISIBLE_ANNOTATION_ATTR;
    attr->info.annotation_array.num_annotations =
        R_BIN_JAVA_USHORT(buffer, offset);
    offset += 2;
    attr->info.annotation_array.annotations =
        r_list_newf(r_bin_java_annotation_free);
    for (i = 0; i < attr->info.annotation_array.num_annotations; i++) {
      if (offset >= sz) {
        break;
      }
      RBinJavaAnnotation* annotation = r_bin_java_annotation_new(
          buffer + offset, sz - offset, buf_offset + offset);
      if (annotation) {
        offset += annotation->size;
        r_list_append(attr->info.annotation_array.annotations,
                      (void*)annotation);
      }
    }
    attr->size = offset;
  }
  return attr;
}

int mutt_seqset_iterator_next(SEQSET_ITERATOR* iter, unsigned int* next) {
  char* range_sep;
  if (!iter || !next) return -1;
  if (iter->in_range) {
    if ((iter->down && iter->range_cur == (iter->range_end - 1)) ||
        (!iter->down && iter->range_cur == (iter->range_end + 1)))
      iter->in_range = 0;
  }
  if (!iter->in_range) {
    iter->substr_cur = iter->substr_end;
    if (iter->substr_cur == iter->eostr) return 1;
    while (!*(iter->substr_cur)) iter->substr_cur++;
    iter->substr_end = strchr(iter->substr_cur, ',');
    if (!iter->substr_end)
      iter->substr_end = iter->eostr;
    else
      *(iter->substr_end) = '\0';
    range_sep = strchr(iter->substr_cur, ':');
    if (range_sep) *range_sep++ = '\0';
    if (mutt_atoui(iter->substr_cur, &iter->range_cur)) return -1;
    if (range_sep) {
      if (mutt_atoui(range_sep, &iter->range_end)) return -1;
    } else
      iter->range_end = iter->range_cur;
    iter->down = (iter->range_end < iter->range_cur);
    iter->in_range = 1;
  }
  *next = iter->range_cur;
  if (iter->down)
    iter->range_cur--;
  else
    iter->range_cur++;
  return 0;
}

Status TensorSliceReader::GetTensor(
    const string& name, std::unique_ptr<tensorflow::Tensor>* out_tensor) const {
  DataType type;
  TensorShape shape;
  TensorSlice slice;
  {
    mutex_lock l(mu_);
    const TensorSliceSet* tss = gtl::FindPtrOrNull(tensors_, name);
    if (tss == nullptr) {
      return errors::NotFound(name, " not found in checkpoint file");
    }
    if (tss->Slices().size() > 1) {
      return errors::Unimplemented("Sliced checkpoints are not supported");
    }
    type = tss->type();
    shape = tss->shape();
    slice = tss->Slices().begin()->second.slice;
  }
  std::unique_ptr<tensorflow::Tensor> t(new tensorflow::Tensor(type, shape));
  bool success = false;
#define READER_COPY(dt)                                                  \
  case dt:                                                               \
    success = CopySliceData(name, slice,                                 \
                            t->flat<EnumToDataType<dt>::Type>().data()); \
    break;
  switch (type) {
    READER_COPY(DT_FLOAT);
    READER_COPY(DT_DOUBLE);
    READER_COPY(DT_INT32);
    READER_COPY(DT_UINT8);
    READER_COPY(DT_INT16);
    READER_COPY(DT_INT8);
    READER_COPY(DT_INT64);
    READER_COPY(DT_STRING);
    default:
      return errors::Unimplemented("Data type not supported");
  }
#undef READER_COPY
  if (!success) {
    return errors::NotFound(name, " not found in checkpoint file");
  }
  std::swap(*out_tensor, t);
  return Status::OK();
}

static int ext4_fill_flex_info(struct super_block* sb) {
  struct ext4_sb_info* sbi = EXT4_SB(sb);
  struct ext4_group_desc* gdp = NULL;
  ext4_group_t flex_group_count;
  ext4_group_t flex_group;
  int groups_per_flex = 0;
  size_t size;
  int i;
  sbi->s_log_groups_per_flex = sbi->s_es->s_log_groups_per_flex;
  groups_per_flex = 1 << sbi->s_log_groups_per_flex;
  if (groups_per_flex < 2) {
    sbi->s_log_groups_per_flex = 0;
    return 1;
  }
  flex_group_count = ((sbi->s_groups_count + groups_per_flex - 1) +
                      ((le16_to_cpu(sbi->s_es->s_reserved_gdt_blocks) + 1)
                       << EXT4_DESC_PER_BLOCK_BITS(sb))) /
                     groups_per_flex;
  size = flex_group_count * sizeof(struct flex_groups);
  sbi->s_flex_groups = ext4_kvzalloc(size, GFP_KERNEL);
  if (sbi->s_flex_groups == NULL) {
    ext4_msg(sb, KERN_ERR, "not enough memory for %u flex groups",
             flex_group_count);
    goto failed;
  }
  for (i = 0; i < sbi->s_groups_count; i++) {
    gdp = ext4_get_group_desc(sb, i, NULL);
    flex_group = ext4_flex_group(sbi, i);
    atomic_add(ext4_free_inodes_count(sb, gdp),
               &sbi->s_flex_groups[flex_group].free_inodes);
    atomic_add(ext4_free_group_clusters(sb, gdp),
               &sbi->s_flex_groups[flex_group].free_clusters);
    atomic_add(ext4_used_dirs_count(sb, gdp),
               &sbi->s_flex_groups[flex_group].used_dirs);
  }
  return 1;
failed:
  return 0;
}

void Compute(OpKernelContext* context) override {
  const Tensor& data = context->input(0);
  const Tensor& segment_ids = context->input(1);
  const Tensor& num_segments = context->input(2);
  if (!UnsortedSegmentReductionDoValidation(this, context, data, segment_ids,
                                            num_segments)) {
    return;
  }
  const auto segment_flat = segment_ids.flat<Index>();
  const Index output_rows = internal::SubtleMustCopy(static_cast<Index>(
      num_segments.dtype() == DT_INT32 ? num_segments.scalar<int32>()()
                                       : num_segments.scalar<int64>()()));
  OP_REQUIRES(context, output_rows >= 0,
              errors::InvalidArgument("Input num_segments == ", output_rows,
                                      " must not be negative."));
  TensorShape output_shape;
  output_shape.AddDim(output_rows);
  for (int i = segment_ids.dims(); i < data.dims(); i++) {
    output_shape.AddDim(data.dim_size(i));
  }
  Tensor* output = nullptr;
  OP_REQUIRES_OK(context, context->allocate_output(0, output_shape, &output));
  auto output_flat = output->flat_outer_dims<T>();
  auto data_ptr = data.template flat<T>().data();
  reduction_functor_(context, output_rows, segment_ids.shape(), segment_flat,
                     data.NumElements(), data_ptr, output_flat);
}

unsigned int oom_badness(struct task_struct* p, struct mem_cgroup* mem,
                         const nodemask_t* nodemask, unsigned long totalpages) {
  int points;
  if (oom_unkillable_task(p, mem, nodemask)) return 0;
  p = find_lock_task_mm(p);
  if (!p) return 0;
  if (atomic_read(&p->mm->oom_disable_count)) {
    task_unlock(p);
    return 0;
  }
  if (!totalpages) totalpages = 1;
  points = get_mm_rss(p->mm) + p->mm->nr_ptes;
  points += get_mm_counter(p->mm, MM_SWAPENTS);
  points *= 1000;
  points /= totalpages;
  task_unlock(p);
  if (has_capability_noaudit(p, CAP_SYS_ADMIN)) points -= 30;
  points += p->signal->oom_score_adj;
  if (points <= 0) return 1;
  return (points < 1000) ? points : 1000;
}

int __fsnotify_parent(const struct path* path, struct dentry* dentry,
                      __u32 mask) {
  struct dentry* parent;
  struct inode* p_inode;
  int ret = 0;
  if (!dentry) dentry = path->dentry;
  if (!(dentry->d_flags & DCACHE_FSNOTIFY_PARENT_WATCHED)) return 0;
  parent = dget_parent(dentry);
  p_inode = parent->d_inode;
  if (unlikely(!fsnotify_inode_watches_children(p_inode)))
    __fsnotify_update_child_dentry_flags(p_inode);
  else if (p_inode->i_fsnotify_mask & mask) {
    mask |= FS_EVENT_ON_CHILD;
    if (path)
      ret = fsnotify(p_inode, mask, path, FSNOTIFY_EVENT_PATH,
                     dentry->d_name.name, 0);
    else
      ret = fsnotify(p_inode, mask, dentry->d_inode, FSNOTIFY_EVENT_INODE,
                     dentry->d_name.name, 0);
  }
  dput(parent);
  return ret;
}

