static int append_ia5(STACK_OF(OPENSSL_STRING) * *sk,
                      const ASN1_IA5STRING* email) {
  char* emtmp;
  if (email->type != V_ASN1_IA5STRING) return 1;
  if (!email->data || !email->length) return 1;
  if (*sk == NULL) *sk = sk_OPENSSL_STRING_new(sk_strcmp);
  if (*sk == NULL) return 0;
  if (sk_OPENSSL_STRING_find(*sk, (char*)email->data) != -1) return 1;
  emtmp = OPENSSL_strdup((char*)email->data);
  if (emtmp == NULL || !sk_OPENSSL_STRING_push(*sk, emtmp)) {
    OPENSSL_free(emtmp);
    X509_email_free(*sk);
    *sk = NULL;
    return 0;
  }
  return 1;
}

static void xgmac_enet_send(XgmacState* s) {
  struct desc bd;
  int frame_size;
  int len;
  uint8_t frame[8192];
  uint8_t* ptr;
  ptr = frame;
  frame_size = 0;
  while (1) {
    xgmac_read_desc(s, &bd, 0);
    if ((bd.ctl_stat & 0x80000000) == 0) {
      break;
    }
    len = (bd.buffer1_size & 0xfff) + (bd.buffer2_size & 0xfff);
    if ((bd.buffer1_size & 0xfff) > 2048) {
      DEBUGF_BRK(
          "qemu:%s:ERROR...ERROR...ERROR... -- "
          "xgmac buffer 1 len on send > 2048 (0x%x)\n",
          __func__, bd.buffer1_size & 0xfff);
    }
    if ((bd.buffer2_size & 0xfff) != 0) {
      DEBUGF_BRK(
          "qemu:%s:ERROR...ERROR...ERROR... -- "
          "xgmac buffer 2 len on send != 0 (0x%x)\n",
          __func__, bd.buffer2_size & 0xfff);
    }
    if (len >= sizeof(frame)) {
      DEBUGF_BRK(
          "qemu:%s: buffer overflow %d read into %zu "
          "buffer\n",
          __func__, len, sizeof(frame));
      DEBUGF_BRK("qemu:%s: buffer1.size=%d; buffer2.size=%d\n", __func__,
                 bd.buffer1_size, bd.buffer2_size);
    }
    cpu_physical_memory_read(bd.buffer1_addr, ptr, len);
    ptr += len;
    frame_size += len;
    if (bd.ctl_stat & 0x20000000) {
      qemu_send_packet(qemu_get_queue(s->nic), frame, len);
      ptr = frame;
      frame_size = 0;
      s->regs[DMA_STATUS] |= DMA_STATUS_TI | DMA_STATUS_NIS;
    }
    bd.ctl_stat &= ~0x80000000;
    xgmac_write_desc(s, &bd, 0);
  }
}

int ff_amf_get_field_value(const uint8_t* data, const uint8_t* data_end,
                           const uint8_t* name, uint8_t* dst, int dst_size) {
  int namelen = strlen(name);
  int len;
  while (*data != AMF_DATA_TYPE_OBJECT && data < data_end) {
    len = ff_amf_tag_size(data, data_end);
    if (len < 0) len = data_end - data;
    data += len;
  }
  if (data_end - data < 3) return -1;
  data++;
  for (;;) {
    int size = bytestream_get_be16(&data);
    if (!size) break;
    if (size < 0 || size >= data_end - data) return -1;
    data += size;
    if (size == namelen && !memcmp(data - size, name, namelen)) {
      switch (*data++) {
        case AMF_DATA_TYPE_NUMBER:
          snprintf(dst, dst_size, "%g", av_int2double(AV_RB64(data)));
          break;
        case AMF_DATA_TYPE_BOOL:
          snprintf(dst, dst_size, "%s", *data ? "true" : "false");
          break;
        case AMF_DATA_TYPE_STRING:
          len = bytestream_get_be16(&data);
          av_strlcpy(dst, data, FFMIN(len + 1, dst_size));
          break;
        default:
          return -1;
      }
      return 0;
    }
    len = ff_amf_tag_size(data, data_end);
    if (len < 0 || len >= data_end - data) return -1;
    data += len;
  }
  return -1;
}

void FrameFactory::rebuildAggregateFrames(ID3v2::Tag* tag) const {
  if (tag->header()->majorVersion() < 4 && tag->frameList("TDRC").size() == 1 &&
      tag->frameList("TDAT").size() == 1) {
    TextIdentificationFrame* tdrc =
        static_cast<TextIdentificationFrame*>(tag->frameList("TDRC").front());
    UnknownFrame* tdat =
        static_cast<UnknownFrame*>(tag->frameList("TDAT").front());
    if (tdrc->fieldList().size() == 1 &&
        tdrc->fieldList().front().size() == 4 && tdat->data().size() >= 5) {
      String date(tdat->data().mid(1), String::Type(tdat->data()[0]));
      if (date.length() == 4) {
        tdrc->setText(tdrc->toString() + '-' + date.substr(2, 2) + '-' +
                      date.substr(0, 2));
        if (tag->frameList("TIME").size() == 1) {
          UnknownFrame* timeframe =
              static_cast<UnknownFrame*>(tag->frameList("TIME").front());
          if (timeframe->data().size() >= 5) {
            String time(timeframe->data().mid(1),
                        String::Type(timeframe->data()[0]));
            if (time.length() == 4) {
              tdrc->setText(tdrc->toString() + 'T' + time.substr(0, 2) + ':' +
                            time.substr(2, 2));
            }
          }
        }
      }
    }
  }
}

struct l2tp_packet_t* l2tp_packet_alloc(int ver, int msg_type,
                                        const struct sockaddr_in* addr, int H,
                                        const char* secret, size_t secret_len) {
  struct l2tp_packet_t* pack = mempool_alloc(pack_pool);
  if (!pack) return NULL;
  memset(pack, 0, sizeof(*pack));
  INIT_LIST_HEAD(&pack->attrs);
  pack->hdr.ver = ver;
  pack->hdr.T = 1;
  pack->hdr.L = 1;
  pack->hdr.S = 1;
  memcpy(&pack->addr, addr, sizeof(*addr));
  pack->hide_avps = H;
  pack->secret = secret;
  pack->secret_len = secret_len;
  if (msg_type) {
    if (l2tp_packet_add_int16(pack, Message_Type, msg_type, 1)) {
      mempool_free(pack);
      return NULL;
    }
  }
  return pack;
}

int http_parse_cont_len_header(struct ist* value, unsigned long long* body_len,
                               int not_first) {
  char *e, *n;
  unsigned long long cl;
  struct ist word;
  int check_prev = not_first;
  word.ptr = value->ptr - 1;
  e = value->ptr + value->len;
  while (++word.ptr < e) {
    if (unlikely(HTTP_IS_LWS(*word.ptr))) continue;
    for (cl = 0, n = word.ptr; n < e; n++) {
      unsigned int c = *n - '0';
      if (unlikely(c > 9)) {
        if (unlikely(n == word.ptr)) goto fail;
        break;
      }
      if (unlikely(cl > ULLONG_MAX / 10ULL)) goto fail;
      cl = cl * 10ULL;
      if (unlikely(cl + c < cl)) goto fail;
      cl = cl + c;
    }
    word.len = n - word.ptr;
    for (; n < e; n++) {
      if (!HTTP_IS_LWS(*n)) {
        if (unlikely(*n != ',')) goto fail;
        break;
      }
    }
    if (check_prev && cl != *body_len) goto fail;
    *body_len = cl;
    *value = word;
    word.ptr = n;
    check_prev = 1;
  }
  return !not_first;
fail:
  return -1;
}

