void main_cleanup() {
#ifdef USE_OS_THREADS
  CLI* c;
  unsigned i, threads;
  THREAD_ID* thread_list;
  CRYPTO_THREAD_write_lock(stunnel_locks[LOCK_THREAD_LIST]);
  threads = 0;
  for (c = thread_head; c; c = c->thread_next) threads++;
  thread_list = str_alloc((threads + 1) * sizeof(THREAD_ID));
  i = 0;
  for (c = thread_head; c; c = c->thread_next) {
    thread_list[i++] = c->thread_id;
    s_log(LOG_DEBUG, "Terminating a thread for [%s]", c->opt->servname);
  }
  if (cron_thread_id) {
    thread_list[threads++] = cron_thread_id;
    s_log(LOG_DEBUG, "Terminating the cron thread");
  }
  CRYPTO_THREAD_unlock(stunnel_locks[LOCK_THREAD_LIST]);
  if (threads) {
    s_log(LOG_NOTICE, "Terminating %u service thread(s)", threads);
    writesocket(terminate_pipe[1], "", 1);
    for (i = 0; i < threads; ++i) {
#ifdef USE_PTHREAD
      if (pthread_join(thread_list[i], NULL))
        s_log(LOG_ERR, "pthread_join() failed");
#endif
#ifdef USE_WIN32
      if (WaitForSingleObject(thread_list[i], INFINITE) == WAIT_FAILED)
        ioerror("WaitForSingleObject");
      if (!CloseHandle(thread_list[i])) ioerror("CloseHandle");
#endif
    }
    s_log(LOG_NOTICE, "Service threads terminated");
  }
  str_free(thread_list);
#endif
  unbind_ports();
  s_poll_free(fds);
  fds = NULL;
#if 0
    str_stats();
#endif
  log_flush(LOG_MODE_ERROR);
  log_close(SINK_SYSLOG | SINK_OUTFILE);
}

cib_connect(gboolean full) {
  int rc = pcmk_ok;
  static gboolean need_pass = TRUE;
  CRM_CHECK(cib != NULL, return -EINVAL);
  if (getenv("CIB_passwd") != NULL) {
    need_pass = FALSE;
  }
  if (watch_fencing && st == NULL) {
    st = stonith_api_new();
  }
  if (watch_fencing && st->state == stonith_disconnected) {
    crm_trace("Connecting to stonith");
    rc = st->cmds->connect(st, crm_system_name, NULL);
    if (rc == pcmk_ok) {
      crm_trace("Setting up stonith callbacks");
      st->cmds->register_notification(st, T_STONITH_NOTIFY_FENCE,
                                      mon_st_callback);
    }
  }
  if (cib->state != cib_connected_query &&
      cib->state != cib_connected_command) {
    crm_trace("Connecting to the CIB");
    if (as_console && need_pass && cib->variant == cib_remote) {
      need_pass = FALSE;
      print_as("Password:");
    }
    rc = cib->cmds->signon(cib, crm_system_name, cib_query);
    if (rc != pcmk_ok) {
      return rc;
    }
    current_cib = get_cib_copy(cib);
    mon_refresh_display(NULL);
    if (full) {
      if (rc == pcmk_ok) {
        rc = cib->cmds->set_connection_dnotify(cib, mon_cib_connection_destroy);
        if (rc == -EPROTONOSUPPORT) {
          print_as(
              "Notification setup failed, won't be able to reconnect after "
              "failure");
          if (as_console) {
            sleep(2);
          }
          rc = pcmk_ok;
        }
      }
      if (rc == pcmk_ok) {
        cib->cmds->del_notify_callback(cib, T_CIB_DIFF_NOTIFY, crm_diff_update);
        rc = cib->cmds->add_notify_callback(cib, T_CIB_DIFF_NOTIFY,
                                            crm_diff_update);
      }
      if (rc != pcmk_ok) {
        print_as("Notification setup failed, could not monitor CIB actions");
        if (as_console) {
          sleep(2);
        }
        clean_up(-rc);
      }
    }
  }
  return rc;
}

static void imap_parser_save_arg(struct imap_parser* parser,
                                 const unsigned char* data, size_t size) {
  struct imap_arg* arg;
  char* str;
  arg = imap_arg_create(parser);
  switch (parser->cur_type) {
    case ARG_PARSE_ATOM:
    case ARG_PARSE_TEXT:
      if (size == 3 && i_memcasecmp(data, "NIL", 3) == 0) {
        arg->type = IMAP_ARG_NIL;
      } else {
        arg->type = IMAP_ARG_ATOM;
      }
      arg->_data.str = imap_parser_strdup(parser, data, size);
      arg->str_len = size;
      break;
    case ARG_PARSE_STRING:
      i_assert(size > 0);
      arg->type = IMAP_ARG_STRING;
      str = p_strndup(parser->pool, data + 1, size - 1);
      if (parser->str_first_escape >= 0 &&
          (parser->flags & IMAP_PARSE_FLAG_NO_UNESCAPE) == 0) {
        (void)str_unescape(str + parser->str_first_escape - 1);
      }
      arg->_data.str = str;
      arg->str_len = strlen(str);
      break;
    case ARG_PARSE_LITERAL_DATA:
      if ((parser->flags & IMAP_PARSE_FLAG_LITERAL_SIZE) != 0) {
        arg->type = parser->literal_nonsync ? IMAP_ARG_LITERAL_SIZE_NONSYNC
                                            : IMAP_ARG_LITERAL_SIZE;
        arg->_data.literal_size = parser->literal_size;
        arg->literal8 = parser->literal8;
        break;
      }
    case ARG_PARSE_LITERAL_DATA_FORCED:
      if ((parser->flags & IMAP_PARSE_FLAG_LITERAL_TYPE) != 0)
        arg->type = IMAP_ARG_LITERAL;
      else
        arg->type = IMAP_ARG_STRING;
      arg->_data.str = imap_parser_strdup(parser, data, size);
      arg->literal8 = parser->literal8;
      arg->str_len = size;
      break;
    default:
      i_unreached();
  }
  parser->cur_type = ARG_PARSE_NONE;
}

ppm_load_read_header(FILE* fp, pnm_struct* img) {
  gchar* ptr;
  gchar header[MAX_CHARS_IN_ROW];
  gint maxval;
  fgets(header, MAX_CHARS_IN_ROW, fp);
  if (header[0] != ASCII_P ||
      (header[1] != PIXMAP_ASCII && header[1] != PIXMAP_RAW)) {
    g_warning("Image is not a portable pixmap");
    return FALSE;
  }
  img->type = header[1];
  fgets(header, MAX_CHARS_IN_ROW, fp);
  while (header[0] == '#') {
    fgets(header, MAX_CHARS_IN_ROW, fp);
  }
  img->width = strtol(header, &ptr, 0);
  img->height = atoi(ptr);
  fgets(header, MAX_CHARS_IN_ROW, fp);
  maxval = strtol(header, &ptr, 0);
  if ((maxval != 255) && (maxval != 65535)) {
    g_warning("Image is not an 8-bit or 16-bit portable pixmap");
    return FALSE;
  }
  switch (maxval) {
    case 255:
      img->bpc = sizeof(guchar);
      break;
    case 65535:
      img->bpc = sizeof(gushort);
      break;
    default:
      g_warning("%s: Programmer stupidity error", G_STRLOC);
  }
  if (!img->width || !img->height ||
      G_MAXSIZE / img->width / img->height / CHANNEL_COUNT < img->bpc) {
    g_warning("Illegal width/height: %ld/%ld", img->width, img->height);
    return FALSE;
  }
  img->numsamples = img->width * img->height * CHANNEL_COUNT;
  return TRUE;
}

std::string Backtrace::GetFunctionName(uintptr_t pc, uintptr_t* offset) {
  std::string func_name = GetFunctionNameRaw(pc, offset);
  if (!func_name.empty()) {
#if defined(__APPLE__)
    if (func_name[0] != '_') {
      return func_name;
    }
#endif
    char* name = __cxa_demangle(func_name.c_str(), 0, 0, 0);
    if (name) {
      func_name = name;
      free(name);
    }
  }
  return func_name;
}

unsigned long X509_issuer_and_serial_hash(X509* a) {
  unsigned long ret = 0;
  EVP_MD_CTX* ctx = EVP_MD_CTX_new();
  unsigned char md[16];
  char* f;
  if (ctx == NULL) goto err;
  f = X509_NAME_oneline(a->cert_info.issuer, NULL, 0);
  if (!EVP_DigestInit_ex(ctx, EVP_md5(), NULL)) goto err;
  if (!EVP_DigestUpdate(ctx, (unsigned char*)f, strlen(f))) goto err;
  OPENSSL_free(f);
  if (!EVP_DigestUpdate(ctx, (unsigned char*)a->cert_info.serialNumber.data,
                        (unsigned long)a->cert_info.serialNumber.length))
    goto err;
  if (!EVP_DigestFinal_ex(ctx, &(md[0]), NULL)) goto err;
  ret = (((unsigned long)md[0]) | ((unsigned long)md[1] << 8L) |
         ((unsigned long)md[2] << 16L) | ((unsigned long)md[3] << 24L)) &
        0xffffffffL;
err:
  EVP_MD_CTX_free(ctx);
  return ret;
}

void EventBindings::AttachFilteredEvent(
    const v8::FunctionCallbackInfo<v8::Value>& args) {
  CHECK_EQ(2, args.Length());
  CHECK(args[0]->IsString());
  CHECK(args[1]->IsObject());
  std::string event_name = *v8::String::Utf8Value(args[0]);
  if (!context()->HasAccessOrThrowError(event_name)) return;
  std::unique_ptr<base::DictionaryValue> filter;
  {
    std::unique_ptr<content::V8ValueConverter> converter(
        content::V8ValueConverter::create());
    std::unique_ptr<base::Value> filter_value(converter->FromV8Value(
        v8::Local<v8::Object>::Cast(args[1]), context()->v8_context()));
    if (!filter_value || !filter_value->IsType(base::Value::TYPE_DICTIONARY)) {
      args.GetReturnValue().Set(static_cast<int32_t>(-1));
      return;
    }
    filter = base::DictionaryValue::From(std::move(filter_value));
  }
  base::DictionaryValue* filter_weak = filter.get();
  int id = g_event_filter.Get().AddEventMatcher(
      event_name, ParseEventMatcher(std::move(filter)));
  attached_matcher_ids_.insert(id);
  std::string extension_id = context()->GetExtensionID();
  if (AddFilter(event_name, extension_id, *filter_weak)) {
    bool lazy = ExtensionFrameHelper::IsContextForEventPage(context());
    content::RenderThread::Get()->Send(new ExtensionHostMsg_AddFilteredListener(
        extension_id, event_name, *filter_weak, lazy));
  }
  args.GetReturnValue().Set(static_cast<int32_t>(id));
}

ArgParser::parseServerArgs(ServerArgs& args, int argc,
                           const char* const* argv) {
  setArgsBase(args);
  updateCommonArgs(argv);
  for (int i = 1; i < argc; ++i) {
    if (parsePlatformArg(args, argc, argv, i)) {
      continue;
    } else if (parseGenericArgs(argc, argv, i)) {
      continue;
    } else if (parseDeprecatedArgs(argc, argv, i)) {
      continue;
    } else if (isArg(i, argc, argv, "-a", "--address", 1)) {
      args.m_barrierAddress = argv[++i];
    } else if (isArg(i, argc, argv, "-c", "--config", 1)) {
      args.m_configFile = argv[++i];
    } else if (isArg(i, argc, argv, NULL, "--screen-change-script", 1)) {
      args.m_screenChangeScript = argv[++i];
    } else {
      LOG((CLOG_PRINT "%s: unrecognized option `%s'" BYE,
           args.m_exename.c_str(), argv[i], args.m_exename.c_str()));
      return false;
    }
  }
  if (checkUnexpectedArgs()) {
    return false;
  }
  return true;
}

struct ipv6_txoptions* ipv6_update_options(struct sock* sk,
                                           struct ipv6_txoptions* opt) {
  if (inet_sk(sk)->is_icsk) {
    if (opt && !((1 << sk->sk_state) & (TCPF_LISTEN | TCPF_CLOSE)) &&
        inet_sk(sk)->inet_daddr != LOOPBACK4_IPV6) {
      struct inet_connection_sock* icsk = inet_csk(sk);
      icsk->icsk_ext_hdr_len = opt->opt_flen + opt->opt_nflen;
      icsk->icsk_sync_mss(sk, icsk->icsk_pmtu_cookie);
    }
  }
  opt = xchg(&inet6_sk(sk)->opt, opt);
  sk_dst_reset(sk);
  return opt;
}

static __inline__ int scm_check_creds(struct ucred* creds) {
  const struct cred* cred = current_cred();
  kuid_t uid = make_kuid(cred->user_ns, creds->uid);
  kgid_t gid = make_kgid(cred->user_ns, creds->gid);
  if (!uid_valid(uid) || !gid_valid(gid)) return -EINVAL;
  if ((creds->pid == task_tgid_vnr(current) ||
       ns_capable(current->nsproxy->pid_ns->user_ns, CAP_SYS_ADMIN)) &&
      ((uid_eq(uid, cred->uid) || uid_eq(uid, cred->euid) ||
        uid_eq(uid, cred->suid)) ||
       nsown_capable(CAP_SETUID)) &&
      ((gid_eq(gid, cred->gid) || gid_eq(gid, cred->egid) ||
        gid_eq(gid, cred->sgid)) ||
       nsown_capable(CAP_SETGID))) {
    return 0;
  }
  return -EPERM;
}

static int binder_thread_release(struct binder_proc* proc,
                                 struct binder_thread* thread) {
  struct binder_transaction* t;
  struct binder_transaction* send_reply = NULL;
  int active_transactions = 0;
  struct binder_transaction* last_t = NULL;
  binder_inner_proc_lock(thread->proc);
  proc->tmp_ref++;
  atomic_inc(&thread->tmp_ref);
  rb_erase(&thread->rb_node, &proc->threads);
  t = thread->transaction_stack;
  if (t) {
    spin_lock(&t->lock);
    if (t->to_thread == thread) send_reply = t;
  }
  thread->is_dead = true;
  while (t) {
    last_t = t;
    active_transactions++;
    binder_debug(BINDER_DEBUG_DEAD_TRANSACTION,
                 "release %d:%d transaction %d %s, still active\n", proc->pid,
                 thread->pid, t->debug_id,
                 (t->to_thread == thread) ? "in" : "out");
    if (t->to_thread == thread) {
      t->to_proc = NULL;
      t->to_thread = NULL;
      if (t->buffer) {
        t->buffer->transaction = NULL;
        t->buffer = NULL;
      }
      t = t->to_parent;
    } else if (t->from == thread) {
      t->from = NULL;
      t = t->from_parent;
    } else
      BUG();
    spin_unlock(&last_t->lock);
    if (t) spin_lock(&t->lock);
  }
  if ((thread->looper & BINDER_LOOPER_STATE_POLL) &&
      waitqueue_active(&thread->wait)) {
    wake_up_poll(&thread->wait, EPOLLHUP | POLLFREE);
  }
  binder_inner_proc_unlock(thread->proc);
  if (send_reply) binder_send_failed_reply(send_reply, BR_DEAD_REPLY);
  binder_release_work(proc, &thread->todo);
  binder_thread_dec_tmpref(thread);
  return active_transactions;
}

mlx5_fw_fatal_reporter_dump(struct devlink_health_reporter* reporter,
                            struct devlink_fmsg* fmsg, void* priv_ctx) {
  struct mlx5_core_dev* dev = devlink_health_reporter_priv(reporter);
  u32 crdump_size = dev->priv.health.crdump_size;
  u32* cr_data;
  u32 data_size;
  u32 offset;
  int err;
  if (!mlx5_core_is_pf(dev)) return -EPERM;
  cr_data = kvmalloc(crdump_size, GFP_KERNEL);
  if (!cr_data) return -ENOMEM;
  err = mlx5_crdump_collect(dev, cr_data);
  if (err) return err;
  if (priv_ctx) {
    struct mlx5_fw_reporter_ctx* fw_reporter_ctx = priv_ctx;
    err = mlx5_fw_reporter_ctx_pairs_put(fmsg, fw_reporter_ctx);
    if (err) goto free_data;
  }
  err = devlink_fmsg_arr_pair_nest_start(fmsg, "crdump_data");
  if (err) goto free_data;
  for (offset = 0; offset < crdump_size; offset += data_size) {
    if (crdump_size - offset < MLX5_CR_DUMP_CHUNK_SIZE)
      data_size = crdump_size - offset;
    else
      data_size = MLX5_CR_DUMP_CHUNK_SIZE;
    err = devlink_fmsg_binary_put(fmsg, (char*)cr_data + offset, data_size);
    if (err) goto free_data;
  }
  err = devlink_fmsg_arr_pair_nest_end(fmsg);
free_data:
  kvfree(cr_data);
  return err;
}

NOEXPORT void tray_update(const int num) {
  NOTIFYICONDATA nid;
  static ICON_TYPE previous_icon = ICON_NONE;
  ICON_TYPE current_icon;
  LPTSTR tip;
  if (!global_options.option.taskbar) {
    tray_delete();
    return;
  }
  if (!tray_menu_handle)
    tray_menu_handle = LoadMenu(ghInst, MAKEINTRESOURCE(IDM_TRAYMENU));
  if (!tray_menu_handle) {
    ioerror("LoadMenu");
    return;
  }
  if (cmdline.service)
    EnableMenuItem(tray_menu_handle, IDM_EDIT_CONFIG, MF_GRAYED);
  ZeroMemory(&nid, sizeof nid);
  nid.cbSize = sizeof nid;
  nid.uID = 1;
  nid.uFlags = NIF_MESSAGE | NIF_TIP;
  nid.uCallbackMessage = WM_SYSTRAY;
  nid.hWnd = hwnd;
  if (num < 0) {
    tip = str_tprintf(TEXT("Server is down"));
    current_icon = ICON_ERROR;
  } else if (num > 0) {
    tip = str_tprintf(TEXT("%d active session(s)"), num);
    current_icon = ICON_ACTIVE;
  } else {
    tip = str_tprintf(TEXT("Server is idle"));
    current_icon = ICON_IDLE;
  }
  _tcsncpy(nid.szTip, tip, 63);
  nid.szTip[63] = TEXT('\0');
  str_free(tip);
  nid.hIcon = global_options.icon[current_icon];
  if (current_icon != previous_icon) {
    nid.uFlags |= NIF_ICON;
    previous_icon = current_icon;
  }
  if (Shell_NotifyIcon(NIM_MODIFY, &nid)) return;
  nid.uFlags |= NIF_ICON;
  Shell_NotifyIcon(NIM_ADD, &nid);
}

StatusOr<FullTypeDef> SpecializeType(const AttrSlice& attrs,
                                     const OpDef& op_def) {
  FullTypeDef ft;
  ft.set_type_id(TFT_PRODUCT);
  for (int i = 0; i < op_def.output_arg_size(); i++) {
    auto* t = ft.add_args();
    *t = op_def.output_arg(i).experimental_full_type();
    for (int j = 0; j < t->args_size(); j++) {
      auto* arg = t->mutable_args(i);
      if (arg->type_id() == TFT_VAR) {
        const auto* attr = attrs.Find(arg->s());
        if (attr == nullptr) {
          return Status(
              error::INVALID_ARGUMENT,
              absl::StrCat("Could not find an attribute for key ", arg->s()));
        }
        if (attr->value_case() == AttrValue::kList) {
          const auto& attr_list = attr->list();
          arg->set_type_id(TFT_PRODUCT);
          for (int i = 0; i < attr_list.type_size(); i++) {
            map_dtype_to_tensor(attr_list.type(i), arg->add_args());
          }
        } else if (attr->value_case() == AttrValue::kType) {
          map_dtype_to_tensor(attr->type(), arg);
        } else {
          return Status(error::UNIMPLEMENTED,
                        absl::StrCat("unknown attribute type",
                                     attrs.DebugString(), " key=", arg->s()));
        }
        arg->clear_s();
      }
    }
  }
  return ft;
}

