static struct scatterlist* alloc_sgtable(int size) {
  int alloc_size, nents, i;
  struct page* new_page;
  struct scatterlist* iter;
  struct scatterlist* table;
  nents = DIV_ROUND_UP(size, PAGE_SIZE);
  table = kcalloc(nents, sizeof(*table), GFP_KERNEL);
  if (!table) return NULL;
  sg_init_table(table, nents);
  iter = table;
  for_each_sg(table, iter, sg_nents(table), i) {
    new_page = alloc_page(GFP_KERNEL);
    if (!new_page) {
      iter = table;
      for_each_sg(table, iter, sg_nents(table), i) {
        new_page = sg_page(iter);
        if (new_page) __free_page(new_page);
      }
      return NULL;
    }
    alloc_size = min_t(int, size, PAGE_SIZE);
    size -= PAGE_SIZE;
    sg_set_page(iter, new_page, alloc_size, 0);
  }
  return table;
}

int NETSCAPE_SPKI_print(BIO* out, NETSCAPE_SPKI* spki) {
  EVP_PKEY* pkey;
  ASN1_IA5STRING* chal;
  ASN1_OBJECT* spkioid;
  int i, n;
  char* s;
  BIO_printf(out, "Netscape SPKI:\n");
  X509_PUBKEY_get0_param(&spkioid, NULL, NULL, NULL, spki->spkac->pubkey);
  i = OBJ_obj2nid(spkioid);
  BIO_printf(out, "  Public Key Algorithm: %s\n",
             (i == NID_undef) ? "UNKNOWN" : OBJ_nid2ln(i));
  pkey = X509_PUBKEY_get(spki->spkac->pubkey);
  if (!pkey)
    BIO_printf(out, "  Unable to load public key\n");
  else {
    EVP_PKEY_print_public(out, pkey, 4, NULL);
    EVP_PKEY_free(pkey);
  }
  chal = spki->spkac->challenge;
  if (chal->length) BIO_printf(out, "  Challenge String: %s\n", chal->data);
  i = OBJ_obj2nid(spki->sig_algor.algorithm);
  BIO_printf(out, "  Signature Algorithm: %s",
             (i == NID_undef) ? "UNKNOWN" : OBJ_nid2ln(i));
  n = spki->signature->length;
  s = (char*)spki->signature->data;
  for (i = 0; i < n; i++) {
    if ((i % 18) == 0) BIO_write(out, "\n      ", 7);
    BIO_printf(out, "%02x%s", (unsigned char)s[i], ((i + 1) == n) ? "" : ":");
  }
  BIO_write(out, "\n", 1);
  return 1;
}

static MagickBooleanType ReadPSDChannelPixels(Image* image, const ssize_t row,
                                              const PixelChannel channel,
                                              const unsigned char* pixels,
                                              ExceptionInfo* exception) {
  Quantum pixel;
  const unsigned char* p;
  Quantum* q;
  ssize_t x;
  size_t packet_size;
  p = pixels;
  q = GetAuthenticPixels(image, 0, row, image->columns, 1, exception);
  if (q == (Quantum*)NULL) return MagickFalse;
  packet_size = GetPSDPacketSize(image);
  for (x = 0; x < (ssize_t)image->columns; x++) {
    if (packet_size == 1)
      pixel = ScaleCharToQuantum(*p++);
    else if (packet_size == 2) {
      unsigned short nibble;
      p = PushShortPixel(MSBEndian, p, &nibble);
      pixel = ScaleShortToQuantum(nibble);
    } else {
      MagickFloatType nibble;
      p = PushFloatPixel(MSBEndian, p, &nibble);
      pixel = ClampToQuantum(((MagickRealType)QuantumRange) * nibble);
    }
    if (image->depth > 1) {
      SetPSDPixel(image, channel, packet_size, pixel, q, exception);
      q += GetPixelChannels(image);
    } else {
      ssize_t bit, number_bits;
      number_bits = (ssize_t)image->columns - x;
      if (number_bits > 8) number_bits = 8;
      for (bit = 0; bit < (ssize_t)number_bits; bit++) {
        SetPSDPixel(image, channel, packet_size,
                    (((unsigned char)pixel) & (0x01 << (7 - bit))) != 0
                        ? 0
                        : QuantumRange,
                    q, exception);
        q += GetPixelChannels(image);
        x++;
      }
      if (x != (ssize_t)image->columns) x--;
      continue;
    }
  }
  return (SyncAuthenticPixels(image, exception));
}

int verify_iovec(struct msghdr* m, struct iovec* iov,
                 struct sockaddr_storage* address, int mode) {
  int size, ct, err;
  if (m->msg_namelen) {
    if (mode == VERIFY_READ) {
      void __user* namep;
      namep = (void __user __force*)m->msg_name;
      err = move_addr_to_kernel(namep, m->msg_namelen, address);
      if (err < 0) return err;
    }
    m->msg_name = address;
  } else {
    m->msg_name = NULL;
  }
  size = m->msg_iovlen * sizeof(struct iovec);
  if (copy_from_user(iov, (void __user __force*)m->msg_iov, size))
    return -EFAULT;
  m->msg_iov = iov;
  err = 0;
  for (ct = 0; ct < m->msg_iovlen; ct++) {
    size_t len = iov[ct].iov_len;
    if (len > INT_MAX - err) {
      len = INT_MAX - err;
      iov[ct].iov_len = len;
    }
    err += len;
  }
  return err;
}

DRIVE_FILE* drive_file_new(const WCHAR* base_path, const WCHAR* path,
                           UINT32 PathLength, UINT32 id, UINT32 DesiredAccess,
                           UINT32 CreateDisposition, UINT32 CreateOptions,
                           UINT32 FileAttributes, UINT32 SharedAccess) {
  DRIVE_FILE* file;
  if (!base_path || (!path && (PathLength > 0))) return NULL;
  file = (DRIVE_FILE*)calloc(1, sizeof(DRIVE_FILE));
  if (!file) {
