grub_ext4_find_leaf(struct grub_ext2_data* data, char* buf,
                    struct grub_ext4_extent_header* ext_block,
                    grub_uint32_t fileblock) {
  struct grub_ext4_extent_idx* index;
  while (1) {
    int i;
    grub_disk_addr_t block;
    index = (struct grub_ext4_extent_idx*)(ext_block + 1);
    if (grub_le_to_cpu16(ext_block->magic) != EXT4_EXT_MAGIC) return 0;
    if (ext_block->depth == 0) return ext_block;
    for (i = 0; i < grub_le_to_cpu16(ext_block->entries); i++) {
      if (fileblock < grub_le_to_cpu32(index[i].block)) break;
    }
    if (--i < 0) return 0;
    block = grub_le_to_cpu16(index[i].leaf_hi);
    block = (block << 32) + grub_le_to_cpu32(index[i].leaf);
    if (grub_disk_read(data->disk, block << LOG2_EXT2_BLOCK_SIZE(data), 0,
                       EXT2_BLOCK_SIZE(data), buf))
      return 0;
    ext_block = (struct grub_ext4_extent_header*)buf;
  }
}

static int mpeg4video_probe(AVProbeData* probe_packet) {
  uint32_t temp_buffer = -1;
  int VO = 0, VOL = 0, VOP = 0, VISO = 0, res = 0;
  int i;
  for (i = 0; i < probe_packet->buf_size; i++) {
    temp_buffer = (temp_buffer << 8) + probe_packet->buf[i];
    if ((temp_buffer & 0xffffff00) != 0x100) continue;
    if (temp_buffer == VOP_START_CODE)
      VOP++;
    else if (temp_buffer == VISUAL_OBJECT_START_CODE)
      VISO++;
    else if (temp_buffer < 0x120)
      VO++;
    else if (temp_buffer < 0x130)
      VOL++;
    else if (!(0x1AF < temp_buffer && temp_buffer < 0x1B7) &&
             !(0x1B9 < temp_buffer && temp_buffer < 0x1C4))
      res++;
  }
  if (VOP >= VISO && VOP >= VOL && VO >= VOL && VOL > 0 && res == 0)
    return AVPROBE_SCORE_EXTENSION;
  return 0;
}

xmlDocPtr soap_xmlParseFile(const char* filename TSRMLS_DC) {
