struct dns_https_param* dns_get_HTTPS_svcparm_start(struct dns_rrs* rrs,
                                                    char* domain, int maxsize,
                                                    int* ttl, int* priority,
                                                    char* target,
                                                    int target_size) {
  int qtype = 0;
  unsigned char* data = NULL;
  int rr_len = 0;
  data = dns_get_rr_nested_start(rrs, domain, maxsize, &qtype, ttl, &rr_len);
  if (data == NULL) {
    return NULL;
  }
  if (qtype != DNS_T_HTTPS) {
    return NULL;
  }
  if (rr_len < 2) {
    return NULL;
  }
  *priority = _dns_read_short(&data);
  rr_len -= 2;
  if (rr_len <= 0) {
    return NULL;
  }
  int len = strnlen((char*)data, rr_len);
  safe_strncpy(target, (char*)data, target_size);
  data += len + 1;
  rr_len -= len + 1;
  if (rr_len <= 0) {
    return NULL;
  }
  return (struct dns_https_param*)data;
}

int socket_create(uint16_t port) {
  int sfd = -1;
  int yes = 1;
#ifdef WIN32
  WSADATA wsa_data;
  if (!wsa_init) {
    if (WSAStartup(MAKEWORD(2, 2), &wsa_data) != ERROR_SUCCESS) {
      fprintf(stderr, "WSAStartup failed!\n");
      ExitProcess(-1);
    }
    wsa_init = 1;
  }
#endif
  struct sockaddr_in saddr;
  if (0 > (sfd = socket(PF_INET, SOCK_STREAM, IPPROTO_TCP))) {
    perror("socket()");
    return -1;
  }
  if (setsockopt(sfd, SOL_SOCKET, SO_REUSEADDR, (void*)&yes, sizeof(int)) ==
      -1) {
    perror("setsockopt()");
    socket_close(sfd);
    return -1;
  }
  memset((void*)&saddr, 0, sizeof(saddr));
  saddr.sin_family = AF_INET;
  saddr.sin_addr.s_addr = htonl(INADDR_ANY);
  saddr.sin_port = htons(port);
  if (0 > bind(sfd, (struct sockaddr*)&saddr, sizeof(saddr))) {
    perror("bind()");
    socket_close(sfd);
    return -1;
  }
  if (listen(sfd, 1) == -1) {
    perror("listen()");
    socket_close(sfd);
    return -1;
  }
  return sfd;
}

static void atusb_disconnect(struct usb_interface* interface) {
