  usb_put_dev(atusb->usb_dev);
  pr_debug("%s done\n", __func__);
}

static char* ptr_to_id(char* buf, char* end, void* ptr,
                       struct printf_spec spec) {
  unsigned long hashval;
  if (unlikely(!have_filled_random_ptr_key)) {
    spec.field_width = 2 * sizeof(ptr);
    return string(buf, end, "(ptrval)", spec);
  }
#ifdef CONFIG_64BIT
  hashval = (unsigned long)siphash_1u64((u64)ptr, &ptr_key);
  hashval = hashval & 0xffffffff;
#else
  hashval = (unsigned long)siphash_1u32((u32)ptr, &ptr_key);
#endif
  return pointer_string(buf, end, (const void*)hashval, spec);
}

GF_Err gf_isom_set_extraction_slc(GF_ISOFile* the_file, u32 trackNumber,
                                  u32 StreamDescriptionIndex,
                                  const GF_SLConfig* slConfig) {
  GF_TrackBox* trak;
  GF_SampleEntryBox* entry;
  GF_Err e;
  GF_SLConfig** slc;
  trak = gf_isom_get_track_from_file(the_file, trackNumber);
  if (!trak) return GF_BAD_PARAM;
  e = Media_GetSampleDesc(trak->Media, StreamDescriptionIndex, &entry, NULL);
