  switch (entry->type) {
    case GF_ISOM_BOX_TYPE_MP4S:
      if (((GF_MPEGSampleEntryBox*)entry)->esd->desc->slConfig->predefined !=
          SLPredef_MP4)
        return GF_BAD_PARAM;
      slc = &((GF_MPEGSampleEntryBox*)entry)->slc;
      break;
    case GF_ISOM_BOX_TYPE_MP4A:
      if (((GF_MPEGAudioSampleEntryBox*)entry)
              ->esd->desc->slConfig->predefined != SLPredef_MP4)
        return GF_BAD_PARAM;
      slc = &((GF_MPEGAudioSampleEntryBox*)entry)->slc;
      break;
    case GF_ISOM_BOX_TYPE_MP4V:
      if (((GF_MPEGVisualSampleEntryBox*)entry)
              ->esd->desc->slConfig->predefined != SLPredef_MP4)
        return GF_BAD_PARAM;
      slc = &((GF_MPEGVisualSampleEntryBox*)entry)->slc;
      break;
    default:
      return GF_BAD_PARAM;
  }
  if (*slc) {
    gf_odf_desc_del((GF_Descriptor*)*slc);
    *slc = NULL;
  }
  if (!slConfig) return GF_OK;
  return gf_odf_desc_copy((GF_Descriptor*)slConfig, (GF_Descriptor**)slc);
}

bsg_write(struct file* file, const char __user* buf, size_t count,
          loff_t* ppos) {
  struct bsg_device* bd = file->private_data;
  ssize_t bytes_written;
  int ret;
  dprintk("%s: write %Zd bytes\n", bd->name, count);
  bsg_set_block(bd, file);
  bytes_written = 0;
  ret = __bsg_write(bd, buf, count, &bytes_written, file->f_mode & FMODE_WRITE);
  *ppos = bytes_written;
  if (!bytes_written || err_block_err(ret)) bytes_written = ret;
  dprintk("%s: returning %Zd\n", bd->name, bytes_written);
  return bytes_written;
}

BGD_DECLARE(void) gdImageWBMPCtx(gdImagePtr image, int fg, gdIOCtx* out) {
  int x, y, pos;
  Wbmp* wbmp;
  if ((wbmp = createwbmp(gdImageSX(image), gdImageSY(image), WBMP_WHITE)) ==
      NULL) {
    gd_error("Could not create WBMP\n");
    return;
  }
  pos = 0;
  for (y = 0; y < gdImageSY(image); y++) {
    for (x = 0; x < gdImageSX(image); x++) {
      if (gdImageGetPixel(image, x, y) == fg) {
        wbmp->bitmap[pos] = WBMP_BLACK;
      }
      pos++;
    }
  }
  if (writewbmp(wbmp, &gd_putout, out)) {
    gd_error("Could not save WBMP\n");
  }
  freewbmp(wbmp);
}

int AVI_read_frame(avi_t* AVI, u8* vidbuf, int* keyframe) {
  int n;
  if (AVI->mode == AVI_MODE_WRITE) {
    AVI_errno = AVI_ERR_NOT_PERM;
    return -1;
  }
  if (!AVI->video_index) {
    AVI_errno = AVI_ERR_NO_IDX;
    return -1;
  }
  if (AVI->video_pos < 0 || AVI->video_pos >= AVI->video_frames) return -1;
  n = (u32)AVI->video_index[AVI->video_pos].len;
  *keyframe = (AVI->video_index[AVI->video_pos].key == 0x10) ? 1 : 0;
  if (vidbuf == NULL) {
    AVI->video_pos++;
    return n;
  }
  gf_fseek(AVI->fdes, AVI->video_index[AVI->video_pos].pos, SEEK_SET);
  if (avi_read(AVI->fdes, vidbuf, n) != (u32)n) {
    AVI_errno = AVI_ERR_READ;
    return -1;
  }
  AVI->video_pos++;
  return n;
}

static Jsi_RC jsi_ArrayIndexSubCmd(Jsi_Interp* interp, Jsi_Value* args,
                                   Jsi_Value* _this, Jsi_Value** ret,
                                   Jsi_Func* funcPtr, int op) {
  int istart = 0, n, i = 0, dir = 1, idx = -1;
  Jsi_Value *seq = Jsi_ValueArrayIndex(interp, args, 0),
            *start = Jsi_ValueArrayIndex(interp, args, 1);
  Jsi_Obj* obj = _this->d.obj;
  if (_this->vt != JSI_VT_OBJECT || !Jsi_ObjIsArray(interp, _this->d.obj))
    return Jsi_LogError("expected array object");
  if (!seq) {
    goto bail;
  }
  n = Jsi_ObjGetLength(interp, obj);
  if (n == 0) {
    goto bail;
  }
  Jsi_Number nstart;
  if (op == 2) {
    istart = n - 1;
  }
  if (start && Jsi_GetNumberFromValue(interp, start, &nstart) == JSI_OK) {
    istart = (int)nstart;
    if (istart > n) goto bail;
    if (istart < 0) istart = (n + istart);
    if (istart < 0) goto bail;
  }
  if (op == 2) {
    istart = n - 1;
    dir = -1;
  }
  Jsi_ObjListifyArray(interp, obj);
  for (i = istart;; i += dir) {
    if ((dir > 0 && i >= n) || (dir < 0 && i < 0) || i >= (int)obj->arrCnt)
      break;
    if (obj->arr[i] &&
        Jsi_ValueCmp(interp, obj->arr[i], seq, JSI_CMP_EXACT) == 0) {
      idx = i;
      break;
    }
  }
bail:
  if (op == 3)
    Jsi_ValueMakeBool(interp, ret, (idx != -1));
  else
    Jsi_ValueMakeNumber(interp, ret, idx);
  return JSI_OK;
}

xfs_file_splice_write(struct pipe_inode_info* pipe, struct file* outfilp,
                      loff_t* ppos, size_t count, unsigned int flags) {
  struct inode* inode = outfilp->f_mapping->host;
  struct xfs_inode* ip = XFS_I(inode);
  int ioflags = 0;
  ssize_t ret;
  XFS_STATS_INC(xs_write_calls);
  if (outfilp->f_mode & FMODE_NOCMTIME) ioflags |= IO_INVIS;
  if (XFS_FORCED_SHUTDOWN(ip->i_mount)) return -EIO;
  xfs_ilock(ip, XFS_IOLOCK_EXCL);
  trace_xfs_file_splice_write(ip, count, *ppos, ioflags);
  ret = generic_file_splice_write(pipe, outfilp, ppos, count, flags);
  if (ret > 0) XFS_STATS_ADD(xs_write_bytes, ret);
  xfs_iunlock(ip, XFS_IOLOCK_EXCL);
  return ret;
}

int cli_hm_scan(const unsigned char* digest, uint32_t size,
                const char** virname, const struct cli_matcher* root,
                enum CLI_HASH_TYPE type) {
  const struct cli_htu32_element* item;
  unsigned int keylen;
  struct cli_sz_hash* szh;
  size_t l, r;
  if (!digest || !size || size == 0xffffffff || !root ||
      !root->hm.sizehashes[type].capacity)
    return CL_CLEAN;
  item = cli_htu32_find(&root->hm.sizehashes[type], size);
  if (!item) return CL_CLEAN;
  szh = (struct cli_sz_hash*)item->data.as_ptr;
  keylen = hashlen[type];
  l = 0;
  r = szh->items;
  while (l <= r) {
    size_t c = (l + r) / 2;
    int res = hm_cmp(digest, &szh->hash_array[keylen * c], keylen);
    if (res < 0) {
      if (!c) break;
      r = c - 1;
    } else if (res > 0)
      l = c + 1;
    else {
      if (virname) *virname = szh->virusnames[c];
      return CL_VIRUS;
    }
  }
  return CL_CLEAN;
}

static wStream* rdg_receive_packet(rdpRdg* rdg) {
  wStream* s;
  const size_t header = sizeof(RdgPacketHeader);
  size_t packetLength;
  assert(header <= INT_MAX);
  s = Stream_New(NULL, 1024);
  if (!s) return NULL;
  if (!rdg_read_all(rdg->tlsOut, Stream_Buffer(s), header)) {
    Stream_Free(s, TRUE);
    return NULL;
  }
  Stream_Seek(s, 4);
  Stream_Read_UINT32(s, packetLength);
  if ((packetLength > INT_MAX) || !Stream_EnsureCapacity(s, packetLength)) {
    Stream_Free(s, TRUE);
    return NULL;
  }
  if (!rdg_read_all(rdg->tlsOut, Stream_Buffer(s) + header,
                    (int)packetLength - (int)header)) {
    Stream_Free(s, TRUE);
    return NULL;
  }
  Stream_SetLength(s, packetLength);
  return s;
}

static size_t write_cb(void* contents, size_t size, size_t nmemb, void* data) {
  size_t realsize = 0;
  connection_t* conn = NULL;
  char* ptr = NULL;
  conn = data;
  ogs_assert(conn);
  realsize = size * nmemb;
  ptr = ogs_realloc(conn->memory, conn->size + realsize + 1);
  if (!ptr) {
    ogs_fatal("not enough memory (realloc returned NULL)");
    ogs_assert_if_reached();
    return 0;
  }
  conn->memory = ptr;
  memcpy(&(conn->memory[conn->size]), contents, realsize);
  conn->size += realsize;
  conn->memory[conn->size] = 0;
  return realsize;
}

bool Monitor::ms_verify_authorizer(Connection* con, int peer_type, int protocol,
                                   bufferlist& authorizer_data,
                                   bufferlist& authorizer_reply, bool& isvalid,
                                   CryptoKey& session_key) {
  dout(10) << "ms_verify_authorizer " << con->get_peer_addr() << " "
           << ceph_entity_type_name(peer_type) << " protocol " << protocol
           << dendl;
  if (is_shutdown()) return false;
  if (peer_type == CEPH_ENTITY_TYPE_MON &&
      auth_cluster_required.is_supported_auth(CEPH_AUTH_CEPHX)) {
    isvalid = false;
    if (protocol == CEPH_AUTH_CEPHX) {
      bufferlist::iterator iter = authorizer_data.begin();
      CephXServiceTicketInfo auth_ticket_info;
      if (authorizer_data.length()) {
        bool ret = cephx_verify_authorizer(g_ceph_context, &keyring, iter,
                                           auth_ticket_info, authorizer_reply);
        if (ret) {
          session_key = auth_ticket_info.session_key;
          isvalid = true;
        } else {
          dout(0) << "ms_verify_authorizer bad authorizer from mon "
                  << con->get_peer_addr() << dendl;
        }
      }
    } else {
      dout(0) << "ms_verify_authorizer cephx enabled, but no authorizer "
                 "(required for mon)"
              << dendl;
    }
  } else {
    isvalid = true;
  }
  return true;
}

fp_read(CBORDecoderObject* self, char* buf, const Py_ssize_t size) {
  PyObject *obj, *size_obj;
  char* data;
  int ret = -1;
  size_obj = PyLong_FromSsize_t(size);
  if (size_obj) {
    obj = PyObject_CallFunctionObjArgs(self->read, size_obj, NULL);
    if (obj) {
      assert(PyBytes_CheckExact(obj));
      if (PyBytes_GET_SIZE(obj) == (Py_ssize_t)size) {
        data = PyBytes_AS_STRING(obj);
        memcpy(buf, data, size);
        ret = 0;
      } else {
        PyErr_Format(_CBOR2_CBORDecodeEOF,
                     "premature end of stream (expected to read %zd bytes, "
                     "got %zd instead)",
                     size, PyBytes_GET_SIZE(obj));
      }
      Py_DECREF(obj);
    }
    Py_DECREF(size_obj);
  }
  return ret;
}

dissect_spoolss_keybuffer(tvbuff_t* tvb, int offset, packet_info* pinfo,
                          proto_tree* tree, dcerpc_info* di, guint8* drep) {
  guint32 size;
  int end_offset;
  if (di->conformant_run) return offset;
  offset = dissect_ndr_uint32(tvb, offset, pinfo, tree, di, drep,
                              hf_keybuffer_size, &size);
  end_offset = offset + (size * 2);
  if (end_offset < offset) {
    end_offset = tvb_reported_length_remaining(tvb, offset) + 1;
  }
  while (offset < end_offset)
    offset = dissect_spoolss_uint16uni(tvb, offset, pinfo, tree, drep, NULL,
                                       hf_keybuffer);
  return offset;
}

static int r_cmd_java_call(void* user, const char* input) {
  RCore* core = (RCore*)user;
  int res = false;
  ut32 i = 0;
  if (strncmp(input, "java", 4)) {
    return false;
  }
  if (input[4] != ' ') {
    return r_cmd_java_handle_help(core, input);
  }
  for (; i < END_CMDS; i++) {
    IFDBG r_cons_printf(
        "Checking cmd: %s %d\n", JAVA_CMDS[i].name,
        strncmp(input + 5, JAVA_CMDS[i].name, JAVA_CMDS[i].name_len));
    if (!strncmp(input + 5, JAVA_CMDS[i].name, JAVA_CMDS[i].name_len)) {
      const char* cmd = input + 5 + JAVA_CMDS[i].name_len;
      if (*cmd && *cmd == ' ') {
        cmd++;
      }
      res = JAVA_CMDS[i].handler(core, cmd);
      break;
    }
  }
  if (!res) {
    return r_cmd_java_handle_help(core, input);
  }
  return true;
}

krb5_gss_process_context_token(minor_status, context_handle,
                               token_buffer) OM_uint32* minor_status;
gss_ctx_id_t context_handle;
gss_buffer_t token_buffer;
{
  krb5_gss_ctx_id_rec* ctx;
  OM_uint32 majerr;
  ctx = (krb5_gss_ctx_id_t)context_handle;
  if (!ctx->established) {
    *minor_status = KG_CTX_INCOMPLETE;
    return (GSS_S_NO_CONTEXT);
  }
  if (GSS_ERROR(majerr =
                    kg_unseal(minor_status, context_handle, token_buffer,
                              GSS_C_NO_BUFFER, NULL, NULL, KG_TOK_DEL_CTX)))
    return (majerr);
  return (krb5_gss_delete_sec_context(minor_status, &context_handle,
                                      GSS_C_NO_BUFFER));
}

static plist_t parse_dict_node(struct bplist_data* bplist, const char** bnode,
                               uint64_t size) {
  uint64_t j;
  uint64_t str_i = 0, str_j = 0;
  uint64_t index1, index2;
  plist_data_t data = plist_new_plist_data();
  const char* const end_data = bplist->data + bplist->size;
  const char* index1_ptr = NULL;
  const char* index2_ptr = NULL;
  data->type = PLIST_DICT;
  data->length = size;
  plist_t node = node_create(NULL, data);
  for (j = 0; j < data->length; j++) {
    str_i = j * bplist->dict_size;
    str_j = (j + size) * bplist->dict_size;
    index1_ptr = (*bnode) + str_i;
    index2_ptr = (*bnode) + str_j;
    if ((index1_ptr < bplist->data ||
         index1_ptr + bplist->dict_size >= end_data) ||
        (index2_ptr < bplist->data ||
         index2_ptr + bplist->dict_size >= end_data)) {
      plist_free(node);
      return NULL;
    }
    index1 = UINT_TO_HOST(index1_ptr, bplist->dict_size);
    index2 = UINT_TO_HOST(index2_ptr, bplist->dict_size);
    if (index1 >= bplist->num_objects) {
      plist_free(node);
      return NULL;
    }
    if (index2 >= bplist->num_objects) {
      plist_free(node);
      return NULL;
    }
    plist_t key = parse_bin_node_at_index(bplist, index1);
    if (!key) {
      plist_free(node);
      return NULL;
    }
    plist_get_data(key)->type = PLIST_KEY;
    if (!plist_get_data(key)->strval) {
      fprintf(stderr,
              "ERROR: Malformed binary plist dict, invalid key node "
              "encountered!\n");
      plist_free(key);
      plist_free(node);
      return NULL;
    }
    plist_t val = parse_bin_node_at_index(bplist, index2);
    if (!val) {
      plist_free(key);
      plist_free(node);
      return NULL;
    }
    node_attach(node, key);
    node_attach(node, val);
  }
  return node;
}

static int perf_trace_event_perm(struct ftrace_event_call* tp_event,
                                 struct perf_event* p_event) {
  if (ftrace_event_is_function(tp_event) && perf_paranoid_kernel() &&
      !capable(CAP_SYS_ADMIN))
    return -EPERM;
  if (!(p_event->attr.sample_type & PERF_SAMPLE_RAW)) return 0;
  if (p_event->attach_state == PERF_ATTACH_TASK) {
    if (tp_event->flags & TRACE_EVENT_FL_CAP_ANY) return 0;
  }
  if (perf_paranoid_tracepoint_raw() && !capable(CAP_SYS_ADMIN)) return -EPERM;
  return 0;
}

static bool MR_primality_test(UnsignedBigInteger n,
                              const Vector<UnsignedBigInteger, 256>& tests) {
  ASSERT(!(n < 4));
  auto predecessor = n.minus({1});
  auto d = predecessor;
  size_t r = 0;
  {
    auto div_result = d.divided_by(2);
    while (div_result.remainder == 0) {
      d = div_result.quotient;
      div_result = d.divided_by(2);
      ++r;
    }
  }
  if (r == 0) {
    return n == 2;
  }
  for (auto a : tests) {
    ASSERT(a < n);
    auto x = ModularPower(a, d, n);
    if (x == 1 || x == predecessor) continue;
    bool skip_this_witness = false;
    for (size_t i = 0; i < r - 1; ++i) {
      x = ModularPower(x, 2, n);
      if (x == predecessor) {
        skip_this_witness = true;
        break;
      }
    }
    if (skip_this_witness) continue;
    return false;
  }
  return true;
}

