static int rndis_query_response(USBNetState* s, rndis_query_msg_type* buf,
                                unsigned int length) {
  rndis_query_cmplt_type* resp;
  uint8_t infobuf[sizeof(oid_supported_list)];
  uint32_t bufoffs, buflen;
  int infobuflen;
  unsigned int resplen;
  bufoffs = le32_to_cpu(buf->InformationBufferOffset) + 8;
  buflen = le32_to_cpu(buf->InformationBufferLength);
  if (bufoffs + buflen > length) return USB_RET_STALL;
     infobuflen = ndis_query(s, le32_to_cpu(buf->OID),
                             bufoffs + (uint8_t *) buf, buflen, infobuf,
    resplen = sizeof(rndis_query_cmplt_type) +
            ((infobuflen < 0) ? 0 : infobuflen);
    resp = rndis_queue_response(s, resplen);
    if (!resp)
        return USB_RET_STALL;
    resp->MessageType = cpu_to_le32(RNDIS_QUERY_CMPLT);
    resp->RequestID = buf->RequestID; 
    resp->MessageLength = cpu_to_le32(resplen);
    if (infobuflen < 0) {
    resp->Status = cpu_to_le32(RNDIS_STATUS_NOT_SUPPORTED);
    resp->InformationBufferLength = cpu_to_le32(0);
    resp->InformationBufferOffset = cpu_to_le32(0);
    return 0;
    }
    resp->Status = cpu_to_le32(RNDIS_STATUS_SUCCESS);
    resp->InformationBufferOffset =
            cpu_to_le32(infobuflen ? sizeof(rndis_query_cmplt_type) - 8 : 0);
    resp->InformationBufferLength = cpu_to_le32(infobuflen);
    memcpy(resp + 1, infobuf, infobuflen);
    return 0;
}

mark_op_resolved(FlatpakTransactionOperation* op, const char* commit,
                 GFile* sideload_path, GBytes* metadata, GBytes* old_metadata) {
  g_debug("marking op %s:%s resolved to %s", kind_to_str(op->kind),
          flatpak_decomposed_get_ref(op->ref), commit ? commit : "-");
  g_assert(op != NULL);
  g_assert(commit != NULL);
  op->resolved = TRUE;
  if (op->resolved_commit != commit) {
    g_free(op->resolved_commit);
    op->resolved_commit = g_strdup(commit);
  }
  if (sideload_path) op->resolved_sideload_path = g_object_ref(sideload_path);
  if (metadata) {
    g_autoptr(GKeyFile) metakey = g_key_file_new();
    if (g_key_file_load_from_bytes(metakey, metadata, G_KEY_FILE_NONE, NULL)) {
      op->resolved_metadata = g_bytes_ref(metadata);
      op->resolved_metakey = g_steal_pointer(&metakey);
    } else
      g_message("Warning: Failed to parse metadata for %s\n",
                flatpak_decomposed_get_ref(op->ref));
  }
  if (old_metadata) {
    g_autoptr(GKeyFile) metakey = g_key_file_new();
    if (g_key_file_load_from_bytes(metakey, old_metadata, G_KEY_FILE_NONE,
                                   NULL)) {
      op->resolved_old_metadata = g_bytes_ref(old_metadata);
      op->resolved_old_metakey = g_steal_pointer(&metakey);
    } else
      g_message("Warning: Failed to parse old metadata for %s\n",
                flatpak_decomposed_get_ref(op->ref));
  }
}

static void k_ascii(struct vc_data* vc, unsigned char value, char up_flag) {
  int base;
  if (up_flag) return;
  if (value < 10) {
    base = 10;
  } else {
    value -= 10;
    base = 16;
  }
  if (npadch == -1)
    npadch = value;
  else
    npadch = npadch * base + value;
}

absl::Span<const std::string> ConnectionInfoImplBase::ipSansPeerCertificate()
    const {
  if (!cached_ip_san_peer_certificate_.empty()) {
    return cached_ip_san_peer_certificate_;
  }
  bssl::UniquePtr<X509> cert(SSL_get_peer_certificate(ssl()));
  if (!cert) {
    ASSERT(cached_ip_san_peer_certificate_.empty());
    return cached_ip_san_peer_certificate_;
  }
  cached_ip_san_peer_certificate_ =
      Utility::getSubjectAltNames(*cert, GEN_IPADD);
  return cached_ip_san_peer_certificate_;
}

dhcpv6_print(netdissect_options* ndo, const u_char* cp, u_int length,
             int indent) {
  u_int i, t;
  const u_char *tlv, *value;
  uint16_t type, optlen;
  i = 0;
  while (i < length) {
    tlv = cp + i;
    type = EXTRACT_16BITS(tlv);
    optlen = EXTRACT_16BITS(tlv + 2);
    value = tlv + 4;
    ND_PRINT((ndo, "\n"));
    for (t = indent; t > 0; t--) ND_PRINT((ndo, "\t"));
    ND_PRINT((ndo, "%s", tok2str(dh6opt_str, "Unknown", type)));
    ND_PRINT((ndo, " (%u)", optlen + 4));
    switch (type) {
      case DH6OPT_DNS_SERVERS:
      case DH6OPT_SNTP_SERVERS: {
        if (optlen % 16 != 0) {
          ND_PRINT((ndo, " %s", istr));
          return -1;
        }
        for (t = 0; t < optlen; t += 16)
          ND_PRINT((ndo, " %s", ip6addr_string(ndo, value + t)));
      } break;
      case DH6OPT_DOMAIN_LIST: {
        const u_char* tp = value;
        while (tp < value + optlen) {
          ND_PRINT((ndo, " "));
          if ((tp = ns_nprint(ndo, tp, value + optlen)) == NULL) return -1;
        }
      } break;
    }
    i += 4 + optlen;
  }
  return 0;
}

static __u8* ch_report_fixup(struct hid_device* hdev, __u8* rdesc,
                             unsigned int* rsize) {
  if (*rsize >= 17 && rdesc[11] == 0x3c && rdesc[12] == 0x02) {
    hid_info(hdev, "fixing up Cherry Cymotion report descriptor\n");
    rdesc[11] = rdesc[16] = 0xff;
    rdesc[12] = rdesc[17] = 0x03;
  }
  return rdesc;
}

void CoreUserInputHandler::putPrivmsg(const QByteArray& target,
                                      const QByteArray& message,
                                      Cipher* cipher) {
  static const char* cmd = "PRIVMSG";
  static const char* splitter = " .,-!?";
  int maxSplitPos = message.count();
  int splitPos = maxSplitPos;
  forever {
    QByteArray crypted = message.left(splitPos);
    bool isEncrypted = false;
#ifdef HAVE_QCA2
    if (cipher && !cipher->key().isEmpty() && !message.isEmpty()) {
      isEncrypted = cipher->encrypt(crypted);
    }
#endif
    int overrun =
        lastParamOverrun(cmd, QList<QByteArray>() << target << crypted);
    if (overrun) {
      if (!isEncrypted) maxSplitPos = message.count() - overrun;
      splitPos = -1;
      for (const char* splitChar = splitter; *splitChar != 0; splitChar++) {
        splitPos =
            qMax(splitPos, message.lastIndexOf(*splitChar, maxSplitPos) + 1);
      }
      if (splitPos <= 0 || splitPos > maxSplitPos) splitPos = maxSplitPos;
      maxSplitPos = splitPos - 1;
      if (maxSplitPos <= 0) {
        qWarning() << tr("[Error] Could not encrypt your message: %1")
                          .arg(message.data());
        return;
      }
      continue;
    }
    putCmd(cmd, QList<QByteArray>() << target << crypted);
    if (splitPos < message.count())
      putPrivmsg(target, message.mid(splitPos), cipher);
    return;
  }
}

static int sof_set_get_large_ctrl_data(struct snd_sof_dev* sdev,
                                       struct sof_ipc_ctrl_data* cdata,
                                       struct sof_ipc_ctrl_data_params* sparams,
                                       bool send) {
  struct sof_ipc_ctrl_data* partdata;
  size_t send_bytes;
  size_t offset = 0;
  size_t msg_bytes;
  size_t pl_size;
  int err;
  int i;
  partdata = kzalloc(SOF_IPC_MSG_MAX_SIZE, GFP_KERNEL);
  if (!partdata) return -ENOMEM;
  if (send)
    err = sof_get_ctrl_copy_params(cdata->type, cdata, partdata, sparams);
  else
    err = sof_get_ctrl_copy_params(cdata->type, partdata, cdata, sparams);
  if (err < 0) return err;
  msg_bytes = sparams->msg_bytes;
  pl_size = sparams->pl_size;
  memcpy(partdata, cdata, sparams->hdr_bytes);
  mutex_lock(&sdev->ipc->tx_mutex);
  for (i = 0; i < sparams->num_msg; i++) {
    send_bytes = min(msg_bytes, pl_size);
    partdata->num_elems = send_bytes;
    partdata->rhdr.hdr.size = sparams->hdr_bytes + send_bytes;
    partdata->msg_index = i;
    msg_bytes -= send_bytes;
    partdata->elems_remaining = msg_bytes;
    if (send) memcpy(sparams->dst, sparams->src + offset, send_bytes);
    err = sof_ipc_tx_message_unlocked(sdev->ipc, partdata->rhdr.hdr.cmd,
                                      partdata, partdata->rhdr.hdr.size,
                                      partdata, partdata->rhdr.hdr.size);
    if (err < 0) break;
    if (!send) memcpy(sparams->dst + offset, sparams->src, send_bytes);
    offset += pl_size;
  }
  mutex_unlock(&sdev->ipc->tx_mutex);
  kfree(partdata);
  return err;
}

int tcp_read_sock(struct sock* sk, read_descriptor_t* desc,
                  sk_read_actor_t recv_actor) {
  struct sk_buff* skb;
  struct tcp_sock* tp = tcp_sk(sk);
  u32 seq = tp->copied_seq;
  u32 offset;
  int copied = 0;
  if (sk->sk_state == TCP_LISTEN) return -ENOTCONN;
  while ((skb = tcp_recv_skb(sk, seq, &offset)) != NULL) {
    if (offset < skb->len) {
      int used;
      size_t len;
      len = skb->len - offset;
      if (tp->urg_data) {
        u32 urg_offset = tp->urg_seq - seq;
        if (urg_offset < len) len = urg_offset;
        if (!len) break;
      }
      used = recv_actor(desc, skb, offset, len);
      if (used < 0) {
        if (!copied) copied = used;
        break;
      } else if (used <= len) {
        seq += used;
        copied += used;
        offset += used;
      }
      skb = tcp_recv_skb(sk, seq - 1, &offset);
      if (!skb || (offset + 1 != skb->len)) break;
    }
    if (tcp_hdr(skb)->fin) {
      sk_eat_skb(sk, skb, 0);
      ++seq;
      break;
    }
    sk_eat_skb(sk, skb, 0);
    if (!desc->count) break;
  }
  tp->copied_seq = seq;
  tcp_rcv_space_adjust(sk);
  if (copied > 0) tcp_cleanup_rbuf(sk, copied);
  return copied;
}

static __u8* mr_report_fixup(struct hid_device* hdev, __u8* rdesc,
