static int ep_loop_check_proc(void* priv, void* cookie, int call_nests) {
  int error = 0;
  struct file* file = priv;
  struct eventpoll* ep = file->private_data;
  struct eventpoll* ep_tovisit;
  struct rb_node* rbp;
  struct epitem* epi;
  mutex_lock_nested(&ep->mtx, call_nests + 1);
  ep->visited = 1;
  list_add(&ep->visited_list_link, &visited_list);
  for (rbp = rb_first_cached(&ep->rbr); rbp; rbp = rb_next(rbp)) {
    epi = rb_entry(rbp, struct epitem, rbn);
    if (unlikely(is_file_epoll(epi->ffd.file))) {
      ep_tovisit = epi->ffd.file->private_data;
      if (ep_tovisit->visited) continue;
      error = ep_call_nested(&poll_loop_ncalls, ep_loop_check_proc,
                             epi->ffd.file, ep_tovisit, current);
      if (error != 0) break;
    } else {
      if (list_empty(&epi->ffd.file->f_tfile_llink)) {
        get_file(epi->ffd.file);
        list_add(&epi->ffd.file->f_tfile_llink, &tfile_check_list);
      }
    }
  }
  mutex_unlock(&ep->mtx);
  return error;
}

void ip6_input(struct mbuf* m) {
  struct ip6* ip6;
  Slirp* slirp = m->slirp;
  if (!slirp->in6_enabled) {
    goto bad;
  }
  DEBUG_CALL("ip6_input");
  DEBUG_ARG("m = %p", m);
  DEBUG_ARG("m_len = %d", m->m_len);
  if (m->m_len < sizeof(struct ip6)) {
    goto bad;
  }
  ip6 = mtod(m, struct ip6*);
  if (ip6->ip_v != IP6VERSION) {
    goto bad;
  }
  if (ntohs(ip6->ip_pl) > slirp->if_mtu) {
    icmp6_send_error(m, ICMP6_TOOBIG, 0);
    goto bad;
  }
  if (ip6->ip_hl == 0) {
    icmp6_send_error(m, ICMP6_TIMXCEED, ICMP6_TIMXCEED_INTRANS);
    goto bad;
  }
  switch (ip6->ip_nh) {
    case IPPROTO_TCP:
      NTOHS(ip6->ip_pl);
      tcp_input(m, sizeof(struct ip6), (struct socket*)NULL, AF_INET6);
      break;
    case IPPROTO_UDP:
      udp6_input(m);
      break;
    case IPPROTO_ICMPV6:
      icmp6_input(m);
      break;
    default:
      m_free(m);
  }
  return;
bad:
  m_free(m);
}

