static void jsiDumpInstr(Jsi_Interp* interp, jsi_Pstate* ps, Jsi_Value* _this,
                         jsi_TryList* trylist, jsi_OpCode* ip,
                         Jsi_OpCodes* opcodes) {
  int i;
  char buf[200];
  jsi_code_decode(interp, ip, ip - opcodes->codes, buf, sizeof(buf));
  Jsi_Printf(interp, jsi_Stderr, "%p: %-30.200s : THIS=%s, STACK=[", ip, buf,
             jsi_evalprint(_this));
  for (i = 0; i < interp->framePtr->Sp; ++i) {
    Jsi_Printf(interp, jsi_Stderr, "%s%s", (i > 0 ? ", " : ""),
               jsi_evalprint(_jsi_STACKIDX(i)));
  }
  Jsi_Printf(interp, jsi_Stderr, "]");
  if (ip->fname) {
    const char *fn = ip->fname, *cp = Jsi_Strrchr(fn, '/');
    if (cp) fn = cp + 1;
    Jsi_Printf(interp, jsi_Stderr, ", %s:%d", fn, ip->Line);
  }
  Jsi_Printf(interp, jsi_Stderr, "\n");
  jsi_TryList* tlt = trylist;
  for (i = 0; tlt; tlt = tlt->next) i++;
  if (ps->last_exception)
    Jsi_Printf(interp, jsi_Stderr, "TL: %d, excpt: %s\n", i,
               jsi_evalprint(ps->last_exception));
}

static void sdp_copy_raw_data(tCONN_CB* p_ccb, bool offset) {
  unsigned int cpy_len, rem_len;
  uint32_t list_len;
  uint8_t* p;
  uint8_t type;
#if (SDP_DEBUG_RAW == TRUE)
  uint8_t num_array[SDP_MAX_LIST_BYTE_COUNT];
  uint32_t i;
  for (i = 0; i < p_ccb->list_len; i++) {
    snprintf((char*)&num_array[i * 2], sizeof(num_array) - i * 2, "%02X",
             (uint8_t)(p_ccb->rsp_list[i]));
  }
  SDP_TRACE_WARNING("result :%s", num_array);
#endif
  if (p_ccb->p_db->raw_data) {
    cpy_len = p_ccb->p_db->raw_size - p_ccb->p_db->raw_used;
    list_len = p_ccb->list_len;
    p = &p_ccb->rsp_list[0];
    if (offset) {
      type = *p++;
      p = sdpu_get_len_from_type(p, type, &list_len);
    }
    if (list_len < cpy_len) {
      cpy_len = list_len;
    }
    rem_len = SDP_MAX_LIST_BYTE_COUNT - (unsigned int)(p - &p_ccb->rsp_list[0]);
    if (cpy_len > rem_len) {
      SDP_TRACE_WARNING("rem_len :%d less than cpy_len:%d", rem_len, cpy_len);
      cpy_len = rem_len;
    }
    SDP_TRACE_WARNING(
        "%s: list_len:%d cpy_len:%d p:%p p_ccb:%p p_db:%p raw_size:%d "
        "raw_used:%d raw_data:%p",
        __func__, list_len, cpy_len, p, p_ccb, p_ccb->p_db,
        p_ccb->p_db->raw_size, p_ccb->p_db->raw_used, p_ccb->p_db->raw_data);
    memcpy(&p_ccb->p_db->raw_data[p_ccb->p_db->raw_used], p, cpy_len);
    p_ccb->p_db->raw_used += cpy_len;
  }
}

long jpc_bitstream_getbits(jpc_bitstream_t* bitstream, int n) {
  long v;
  int u;
  assert(n >= 0 && n < 32);
  v = 0;
  while (--n >= 0) {
    if ((u = jpc_bitstream_getbit(bitstream)) < 0) {
      return -1;
    }
    v = (v << 1) | u;
  }
  return v;
}

MakeFilename(char* buffer, char* orig_name, int cnt, int max_chars) {
  char* filename = malloc(PATH_MAX + 1);
  if (filename == NULL) error("%s: malloc", __func__);
  if (Gflag != 0) {
    struct tm* local_tm;
    if ((local_tm = localtime(&Gflag_time)) == NULL) {
      error("%s: localtime", __func__);
    }
    strftime(filename, PATH_MAX, orig_name, local_tm);
  } else {
    strncpy(filename, orig_name, PATH_MAX);
  }
  if (cnt == 0 && max_chars == 0)
    strncpy(buffer, filename, PATH_MAX + 1);
  else if (snprintf(buffer, PATH_MAX + 1, "%s%0*d", filename, max_chars, cnt) >
           PATH_MAX)
    error("too many output files or filename is too long (> %d)", PATH_MAX);
  free(filename);
}

