void Compute(OpKernelContext* context) override {
  const Tensor& rhs = context->input(1);
  context->forward_ref_input_to_ref_output(0, 0);
  AllocatorAttributes attr;
  if (!relax_constraints_) {
    attr.set_gpu_compatible(true);
    attr.set_nic_compatible(true);
  }
  {
    mutex_lock l(*context->input_ref_mutex(0));
    const Tensor& old_lhs = context->mutable_input(0, true);
    const bool same_shape = old_lhs.shape().IsSameSize(rhs.shape());
    if (validate_shape_) {
      OP_REQUIRES(context, same_shape,
                  errors::InvalidArgument(
                      "Assign requires shapes of both tensors to match. "
                      "lhs shape= ",
                      old_lhs.shape().DebugString(),
                      " rhs shape= ", rhs.shape().DebugString()));
    }
    if (old_lhs.IsInitialized() &&
        old_lhs.shape().num_elements() == rhs.shape().num_elements()) {
      Tensor reshaped_old_lhs;
      if (same_shape) {
        reshaped_old_lhs = old_lhs;
      } else {
        CHECK(reshaped_old_lhs.CopyFrom(old_lhs, rhs.shape()));
        context->replace_ref_input(0, reshaped_old_lhs, true);
      }
      if (use_exclusive_lock_) {
        Copy(context, &reshaped_old_lhs, rhs);
        return;
      }
    } else {
      std::unique_ptr<Tensor> input_alias =
          context->forward_input(1, OpKernelContext::Params::kNoReservation,
                                 rhs.dtype(), rhs.shape(), DEVICE_MEMORY, attr);
      if (input_alias != nullptr) {
        context->replace_ref_input(0, *input_alias, true);
        return;
      }
      Tensor copy_tensor;
      OP_REQUIRES_OK(context,
                     context->allocate_temp(old_lhs.dtype(), rhs.shape(),
                                            &copy_tensor, attr));
      context->clear_recorded_memory();
      context->replace_ref_input(0, copy_tensor, true);
      if (use_exclusive_lock_) {
        Copy(context, &copy_tensor, rhs);
        return;
      }
    }
  }
  Tensor old_unlocked_lhs = context->mutable_input(0, false);
  Copy(context, &old_unlocked_lhs, rhs);
}

static int parse_import_ptr(struct MACH0_(obj_t) * bin, struct reloc_t* reloc,
                            int idx) {
  int i, j, sym, wordsize;
  ut32 stype;
  wordsize = MACH0_(get_bits)(bin) / 8;
  if (idx < 0 || idx >= bin->nsymtab) {
    return 0;
  }
  if ((bin->symtab[idx].n_desc & REFERENCE_TYPE) ==
      REFERENCE_FLAG_UNDEFINED_LAZY) {
    stype = S_LAZY_SYMBOL_POINTERS;
  } else {
    stype = S_NON_LAZY_SYMBOL_POINTERS;
  }
  reloc->offset = 0;
  reloc->addr = 0;
  reloc->addend = 0;
#define CASE(T)                    \
  case (T / 8):                    \
    reloc->type = R_BIN_RELOC_##T; \
    break
  switch (wordsize) {
    CASE(8);
    CASE(16);
    CASE(32);
    CASE(64);
    default:
      return false;
  }
#undef CASE
  for (i = 0; i < bin->nsects; i++) {
    if ((bin->sects[i].flags & SECTION_TYPE) == stype) {
      for (j = 0, sym = -1; bin->sects[i].reserved1 + j < bin->nindirectsyms;
           j++)
        if (idx == bin->indirectsyms[bin->sects[i].reserved1 + j]) {
          sym = j;
          break;
        }
      reloc->offset = sym == -1 ? 0 : bin->sects[i].offset + sym * wordsize;
      reloc->addr = sym == -1 ? 0 : bin->sects[i].addr + sym * wordsize;
      return true;
    }
  }
  return false;
}

static inline LineContribType* _gdContributionsAlloc(
    unsigned int line_length, unsigned int windows_size) {
  unsigned int u = 0;
  LineContribType* res;
  int overflow_error = 0;
  res = (LineContribType*)gdMalloc(sizeof(LineContribType));
  if (!res) {
    return NULL;
  }
  res->WindowSize = windows_size;
  res->LineLength = line_length;
  if (overflow2(line_length, sizeof(ContributionType))) {
    gdFree(res);
    return NULL;
  }
  res->ContribRow =
      (ContributionType*)gdMalloc(line_length * sizeof(ContributionType));
  if (res->ContribRow == NULL) {
    gdFree(res);
    return NULL;
  }
  for (u = 0; u < line_length; u++) {
    if (overflow2(windows_size, sizeof(double))) {
      overflow_error = 1;
    } else {
      res->ContribRow[u].Weights =
          (double*)gdMalloc(windows_size * sizeof(double));
    }
    if (overflow_error == 1 || res->ContribRow[u].Weights == NULL) {
      unsigned int i;
      u--;
      for (i = 0; i <= u; i++) {
        gdFree(res->ContribRow[i].Weights);
      }
      gdFree(res->ContribRow);
      gdFree(res);
      return NULL;
    }
  }
  return res;
}

struct snd_seq_client_port* snd_seq_create_port(struct snd_seq_client* client,
                                                int port) {
  unsigned long flags;
  struct snd_seq_client_port *new_port, *p;
  int num = -1;
  if (snd_BUG_ON(!client)) return NULL;
  if (client->num_ports >= SNDRV_SEQ_MAX_PORTS) {
    pr_warn("ALSA: seq: too many ports for client %d\n", client->number);
    return NULL;
  }
  new_port = kzalloc(sizeof(*new_port), GFP_KERNEL);
  if (!new_port) return NULL;
  new_port->addr.client = client->number;
  new_port->addr.port = -1;
  new_port->owner = THIS_MODULE;
  sprintf(new_port->name, "port-%d", num);
  snd_use_lock_init(&new_port->use_lock);
  port_subs_info_init(&new_port->c_src);
  port_subs_info_init(&new_port->c_dest);
  num = port >= 0 ? port : 0;
  mutex_lock(&client->ports_mutex);
  write_lock_irqsave(&client->ports_lock, flags);
  list_for_each_entry(p, &client->ports_list_head, list) {
    if (p->addr.port > num) break;
    if (port < 0) num = p->addr.port + 1;
  }
  list_add_tail(&new_port->list, &p->list);
  client->num_ports++;
  new_port->addr.port = num;
  write_unlock_irqrestore(&client->ports_lock, flags);
  mutex_unlock(&client->ports_mutex);
  sprintf(new_port->name, "port-%d", num);
  return new_port;
}

pci_lintr_assert(struct pci_vdev* dev) {
  assert(dev->lintr.pin > 0);
  pthread_mutex_lock(&dev->lintr.lock);
  if (dev->lintr.state == IDLE) {
    if (pci_lintr_permitted(dev)) {
      dev->lintr.state = ASSERTED;
      pci_irq_assert(dev);
    } else
      dev->lintr.state = PENDING;
  }
  pthread_mutex_unlock(&dev->lintr.lock);
}

