CallResult<HermesValue> Runtime::interpretFunctionImpl(
    CodeBlock* newCodeBlock) {
  newCodeBlock->lazyCompile(*this);
#if defined(HERMES_MEMORY_INSTRUMENTATION) || !defined(NDEBUG)
  const inst::Inst* ip = getCurrentIP();
  (void)ip;
#endif
#ifdef HERMES_MEMORY_INSTRUMENTATION
  if (ip) {
    const CodeBlock* codeBlock;
    std::tie(codeBlock, ip) = getCurrentInterpreterLocation(ip);
    if (codeBlock) {
      pushCallStack(codeBlock, ip);
    } else {
      pushCallStack(newCodeBlock, (const Inst*)newCodeBlock->begin());
    }
  } else {
    pushCallStack(newCodeBlock, (const Inst*)newCodeBlock->begin());
  }
#endif
  InterpreterState state{newCodeBlock, 0};
  if (HERMESVM_CRASH_TRACE &&
      (getVMExperimentFlags() & experiments::CrashTrace)) {
    return Interpreter::interpretFunction<false, true>(*this, state);
  } else {
    return Interpreter::interpretFunction<false, false>(*this, state);
  }
}

BOOL rdp_read_share_control_header(wStream* s, UINT16* length, UINT16* type,
                                   UINT16* channel_id) {
  if (Stream_GetRemainingLength(s) < 2) return FALSE;
  Stream_Read_UINT16(s, *length);
  if (*length == 0x8000) {
    rdp_read_flow_control_pdu(s, type);
    *channel_id = 0;
    *length = 8;
    return TRUE;
  }
  if (((size_t)*length - 2) > Stream_GetRemainingLength(s)) return FALSE;
  Stream_Read_UINT16(s, *type);
  *type &= 0x0F;
  if (*length > 4)
    Stream_Read_UINT16(s, *channel_id);
  else
    *channel_id = 0;
  return TRUE;
}

krb5_gss_context_time(minor_status, context_handle,
                      time_rec) OM_uint32* minor_status;
gss_ctx_id_t context_handle;
OM_uint32* time_rec;
{
  krb5_error_code code;
  krb5_gss_ctx_id_rec* ctx;
  krb5_timestamp now;
  krb5_deltat lifetime;
  ctx = (krb5_gss_ctx_id_rec*)context_handle;
  if (!ctx->established) {
    *minor_status = KG_CTX_INCOMPLETE;
    return (GSS_S_NO_CONTEXT);
  }
  if ((code = krb5_timeofday(ctx->k5_context, &now))) {
    *minor_status = code;
    save_error_info(*minor_status, ctx->k5_context);
    return (GSS_S_FAILURE);
  }
  if ((lifetime = ctx->krb_times.endtime - now) <= 0) {
    *time_rec = 0;
    *minor_status = 0;
    return (GSS_S_CONTEXT_EXPIRED);
  } else {
    *time_rec = lifetime;
    *minor_status = 0;
    return (GSS_S_COMPLETE);
  }
}

int user_update(struct key* key, struct key_preparsed_payload* prep) {
  struct user_key_payload *upayload, *zap;
  size_t datalen = prep->datalen;
  int ret;
  ret = -EINVAL;
  if (datalen <= 0 || datalen > 32767 || !prep->data) goto error;
  ret = -ENOMEM;
  upayload = kmalloc(sizeof(*upayload) + datalen, GFP_KERNEL);
  if (!upayload) goto error;
  upayload->datalen = datalen;
  memcpy(upayload->data, prep->data, datalen);
  zap = upayload;
  ret = key_payload_reserve(key, datalen);
  if (ret == 0) {
    zap = key->payload.data[0];
    rcu_assign_keypointer(key, upayload);
    key->expiry = 0;
  }
  if (zap) kfree_rcu(zap, rcu);
error:
  return ret;
}

static UINT ExtractRunLengthRegularFgBg(const BYTE* pbOrderHdr,
                                        const BYTE* pbEnd, UINT32* advance) {
  UINT runLength = 0;
  WINPR_ASSERT(pbOrderHdr);
  WINPR_ASSERT(pbEnd);
  WINPR_ASSERT(advance);
  runLength = (*pbOrderHdr) & g_MaskRegularRunLength;
  if (runLength == 0) {
    if (!buffer_within_range(pbOrderHdr, 1, pbEnd)) {
      *advance = 0;
      return 0;
    }
    runLength = *(pbOrderHdr + 1) + 1;
    (*advance)++;
  } else
    runLength = runLength * 8;
  return runLength;
}

int Bind(const Node& node, int max_retry) override {
  receiver_ = zmq_socket(context_, ZMQ_ROUTER);
  CHECK(receiver_ != NULL) << "create receiver socket failed: "
                           << zmq_strerror(errno);
  int local = GetEnv("DMLC_LOCAL", 0);
  std::string addr = local ? "ipc:
                             int port = node.port;
  unsigned seed = static_cast<unsigned>(time(NULL) + port);
  for (int i = 0; i < max_retry + 1; ++i) {
    auto address = addr + std::to_string(port);
    if (zmq_bind(receiver_, address.c_str()) == 0) break;
    if (i == max_retry) {
      port = -1;
    } else {
      port = 10000 + rand_r(&seed) % 40000;
    }
  }
  return port;
}

onig_new_deluxe(regex_t** reg, const UChar* pattern, const UChar* pattern_end,
                OnigCompileInfo* ci, OnigErrorInfo* einfo) {
  int r;
  UChar *cpat, *cpat_end;
  if (IS_NOT_NULL(einfo)) einfo->par = (UChar*)NULL;
  if (ci->pattern_enc != ci->target_enc) {
    r = conv_encoding(ci->pattern_enc, ci->target_enc, pattern, pattern_end,
                      &cpat, &cpat_end);
    if (r != 0) return r;
  } else {
    cpat = (UChar*)pattern;
    cpat_end = (UChar*)pattern_end;
  }
  *reg = (regex_t*)xmalloc(sizeof(regex_t));
  if (IS_NULL(*reg)) {
    r = ONIGERR_MEMORY;
    goto err2;
  }
  r = onig_reg_init(*reg, ci->option, ci->case_fold_flag, ci->target_enc,
                    ci->syntax);
  if (r != 0) goto err;
  r = onig_compile(*reg, cpat, cpat_end, einfo);
  if (r != 0) {
  err:
    onig_free(*reg);
    *reg = NULL;
  }
err2:
  if (cpat != pattern) xfree(cpat);
  return r;
}

