ncp_read_kernel(struct ncp_server* server, const char* file_id, __u32 offset,
                __u16 to_read, char* target, int* bytes_read) {
  const char* source;
  int result;
  ncp_init_request(server);
  ncp_add_byte(server, 0);
  ncp_add_mem(server, file_id, 6);
  ncp_add_be32(server, offset);
  ncp_add_be16(server, to_read);
  if ((result = ncp_request(server, 72)) != 0) {
    goto out;
  }
  *bytes_read = ncp_reply_be16(server, 0);
  source = ncp_reply_data(server, 2 + (offset & 1));
  memcpy(target, source, *bytes_read);
out:
  ncp_unlock_server(server);
  return result;
}

static long ec_device_ioctl_xcmd(struct cros_ec_dev* ec, void __user* arg) {
  long ret;
  struct cros_ec_command u_cmd;
  struct cros_ec_command* s_cmd;
  if (copy_from_user(&u_cmd, arg, sizeof(u_cmd))) return -EFAULT;
  if ((u_cmd.outsize > EC_MAX_MSG_BYTES) || (u_cmd.insize > EC_MAX_MSG_BYTES))
    return -EINVAL;
  s_cmd =
      kmalloc(sizeof(*s_cmd) + max(u_cmd.outsize, u_cmd.insize), GFP_KERNEL);
  if (!s_cmd) return -ENOMEM;
  if (copy_from_user(s_cmd, arg, sizeof(*s_cmd) + u_cmd.outsize)) {
    ret = -EFAULT;
    goto exit;
  }
  s_cmd->command += ec->cmd_offset;
  ret = cros_ec_cmd_xfer(ec->ec_dev, s_cmd);
  if (ret < 0) goto exit;
  if (copy_to_user(arg, s_cmd, sizeof(*s_cmd) + u_cmd.insize)) ret = -EFAULT;
exit:
  kfree(s_cmd);
  return ret;
}

void ConnectionImpl::onHeaderValue(const char* data, size_t length) {
  if (header_parsing_state_ == HeaderParsingState::Done) {
    return;
  }
  const absl::string_view header_value = absl::string_view(data, length);
  if (strict_header_validation_) {
    if (!Http::HeaderUtility::headerIsValid(header_value)) {
      ENVOY_CONN_LOG(debug, "invalid header value: {}", connection_,
                     header_value);
      error_code_ = Http::Code::BadRequest;
      sendProtocolError();
      throw CodecProtocolException(
          "http/1.1 protocol error: header value contains invalid chars");
    }
  } else if (header_value.find('\0') != absl::string_view::npos) {
    throw CodecProtocolException(
        "http/1.1 protocol error: header value contains NUL");
  }
  header_parsing_state_ = HeaderParsingState::Value;
  current_header_value_.append(data, length);
  const uint32_t total = current_header_field_.size() +
                         current_header_value_.size() +
                         current_header_map_->byteSize();
  if (total > (max_request_headers_kb_ * 1024)) {
    error_code_ = Http::Code::RequestHeaderFieldsTooLarge;
    sendProtocolError();
    throw CodecProtocolException("headers size exceeds limit");
  }
}

int __ext4_journal_stop(const char* where, unsigned int line,
                        handle_t* handle) {
  struct super_block* sb;
  int err;
  int rc;
  if (!ext4_handle_valid(handle)) {
    ext4_put_nojournal(handle);
    return 0;
  }
  if (!handle->h_transaction) {
    err = jbd2_journal_stop(handle);
    return handle->h_err ? handle->h_err : err;
  }
  sb = handle->h_transaction->t_journal->j_private;
  err = handle->h_err;
  rc = jbd2_journal_stop(handle);
  if (!err) err = rc;
  if (err) __ext4_std_error(sb, where, line, err);
  return err;
}

void Compute(OpKernelContext* context) override {
  const Tensor& tensor_in = context->input(0);
  PoolParameters params{context, ksize_,      stride_,          padding_,
                        {},      FORMAT_NHWC, tensor_in.shape()};
  if (!context->status().ok()) {
    return;
  }
  const float min_input = context->input(1).flat<float>()(0);
  const float max_input = context->input(2).flat<float>()(0);
  OP_REQUIRES(context, params.depth_window == 1,
              errors::Unimplemented("Non-spatial pooling is not "
                                    "yet supported. Volunteers? :)"));
  OP_REQUIRES(context, tensor_in.dims() == 4,
              errors::InvalidArgument("tensor_in must be 4-dimensional"));
  Tensor* output = nullptr;
  OP_REQUIRES_OK(context, context->allocate_output(
                              0, params.forward_output_shape(), &output));
  const int32_t highest = static_cast<int32>(Eigen::NumTraits<T>::highest());
  const int32_t lowest = static_cast<int32>(Eigen::NumTraits<T>::lowest());
  Tensor int32_output(DT_INT32, params.forward_output_shape());
  Tensor int32_input(DT_INT32, tensor_in.shape());
  int32_input.flat<int32>() = tensor_in.flat<T>().template cast<int32>();
  SpatialAvgPool<Device, int32>(context, &int32_output, int32_input, params,
                                padding_);
  output->flat<T>() = int32_output.flat<int32>()
                          .cwiseMax(lowest)
                          .cwiseMin(highest)
                          .template cast<T>();
  Tensor* output_min = nullptr;
  OP_REQUIRES_OK(context, context->allocate_output(1, {}, &output_min));
  output_min->flat<float>()(0) = min_input;
  Tensor* output_max = nullptr;
  OP_REQUIRES_OK(context, context->allocate_output(2, {}, &output_max));
  output_max->flat<float>()(0) = max_input;
}

x509_verify_ctx_add_chain(struct x509_verify_ctx* ctx,
                          struct x509_verify_chain* chain, char* name) {
  size_t depth;
  X509* last = x509_verify_chain_last(chain);
  X509* leaf = x509_verify_chain_leaf(chain);
  depth = sk_X509_num(chain->certs);
  if (depth > 0) depth--;
  if (ctx->chains_count >= ctx->max_chains)
    return x509_verify_cert_error(ctx, last, depth,
                                  X509_V_ERR_CERT_CHAIN_TOO_LONG, 0);
  if (chain->cert_errors[depth] == X509_V_ERR_UNABLE_TO_GET_ISSUER_CERT_LOCALLY)
    chain->cert_errors[depth] = X509_V_OK;
  if (!x509_verify_ctx_validate_legacy_chain(ctx, chain, depth)) return 0;
  if ((ctx->chains[ctx->chains_count] = x509_verify_chain_dup(chain)) == NULL) {
    return x509_verify_cert_error(ctx, last, depth, X509_V_ERR_OUT_OF_MEM, 0);
  }
  if (!x509_verify_cert_valid(ctx, leaf, NULL)) return 0;
  if (!x509_verify_cert_hostname(ctx, leaf, name)) return 0;
  ctx->chains_count++;
  ctx->error = X509_V_OK;
  ctx->error_depth = depth;
  return 1;
}

R_API RSocket* r_socket_accept_timeout(RSocket* s, unsigned int timeout) {
  fd_set read_fds;
  fd_set except_fds;
  FD_ZERO(&read_fds);
  FD_SET(s->fd, &read_fds);
  FD_ZERO(&except_fds);
  FD_SET(s->fd, &except_fds);
  struct timeval t;
  t.tv_sec = timeout;
  t.tv_usec = 0;
  int r = select(s->fd + 1, &read_fds, NULL, &except_fds, &t);
  if (r < 0) {
    perror("select");
  } else if (r > 0 && FD_ISSET(s->fd, &read_fds)) {
    return r_socket_accept(s);
  }
  return NULL;
}

ble_hs_conn_timer(void) {
#if MYNEWT_VAL(BLE_L2CAP_RX_FRAG_TIMEOUT) == 0 && \
    BLE_HS_ATT_SVR_QUEUED_WRITE_TMO == 0
  return BLE_HS_FOREVER;
#endif
  struct ble_hs_conn* conn;
  ble_npl_time_t now;
  int32_t next_exp_in;
  int32_t time_diff;
  uint16_t conn_handle;
  for (;;) {
    conn_handle = BLE_HS_CONN_HANDLE_NONE;
    next_exp_in = BLE_HS_FOREVER;
    now = ble_npl_time_get();
    ble_hs_lock();
    SLIST_FOREACH(conn, &ble_hs_conns, bhc_next) {
      if (!(conn->bhc_flags & BLE_HS_CONN_F_TERMINATING)) {
#if MYNEWT_VAL(BLE_L2CAP_RX_FRAG_TIMEOUT) != 0
        if (conn->bhc_rx_chan != NULL) {
          time_diff = conn->bhc_rx_timeout - now;
          if (time_diff <= 0) {
            conn_handle = conn->bhc_handle;
            break;
          }
          if (time_diff < next_exp_in) {
            next_exp_in = time_diff;
          }
        }
#endif
#if BLE_HS_ATT_SVR_QUEUED_WRITE_TMO
        time_diff = ble_att_svr_ticks_until_tmo(&conn->bhc_att_svr, now);
        if (time_diff <= 0) {
          conn_handle = conn->bhc_handle;
          break;
        }
        if (time_diff < next_exp_in) {
          next_exp_in = time_diff;
        }
#endif
      }
    }
    ble_hs_unlock();
    if (conn_handle != BLE_HS_CONN_HANDLE_NONE) {
      ble_gap_terminate(conn_handle, BLE_ERR_REM_USER_CONN_TERM);
      continue;
    }
    return next_exp_in;
  }
}

R_API RBinJavaAttrInfo* r_bin_java_read_next_attr_from_buffer(ut8* buffer,
                                                              st64 sz,
                                                              st64 buf_offset) {
  RBinJavaAttrInfo* attr = NULL;
  char* name = NULL;
  ut64 offset = 0;
  ut16 name_idx;
  st64 nsz;
  RBinJavaAttrMetas* type_info = NULL;
  if (!buffer || ((int)sz) < 4 || buf_offset < 0) {
    eprintf("r_bin_Java_read_next_attr_from_buffer: invalid buffer size %d\n",
            (int)sz);
    return NULL;
  }
  name_idx = R_BIN_JAVA_USHORT(buffer, offset);
  offset += 2;
  nsz = R_BIN_JAVA_UINT(buffer, offset);
  offset += 4;
  name = r_bin_java_get_utf8_from_bin_cp_list(R_BIN_JAVA_GLOBAL_BIN, name_idx);
  if (!name) {
    name = strdup("unknown");
  }
  IFDBG eprintf("r_bin_java_read_next_attr: name_idx = %d is %s\n", name_idx,
                name);
  type_info = r_bin_java_get_attr_type_by_name(name);
  if (type_info) {
    IFDBG eprintf("Typeinfo: %s, was %s\n", type_info->name, name);
    if (nsz > sz) {
      free(name);
      return NULL;
    }
    if ((attr = type_info->allocs->new_obj(buffer, nsz, buf_offset))) {
      attr->metas->ord = (R_BIN_JAVA_GLOBAL_BIN->attr_idx++);
    }
  } else {
    eprintf(
        "r_bin_java_read_next_attr_from_buffer: Cannot find type_info for %s\n",
        name);
  }
  free(name);
  return attr;
}

juniper_mlfr_print(netdissect_options* ndo, const struct pcap_pkthdr* h,
                   register const u_char* p) {
  struct juniper_l2info_t l2info;
  l2info.pictype = DLT_JUNIPER_MLFR;
  if (juniper_parse_header(ndo, p, h, &l2info) == 0) return l2info.header_len;
  p += l2info.header_len;
  if (ndo->ndo_eflag && EXTRACT_32BITS(l2info.cookie) != 1)
    ND_PRINT((ndo, "Bundle-ID %u, ", l2info.bundle));
  switch (l2info.proto) {
    case (LLC_UI):
    case (LLC_UI << 8):
      isoclns_print(ndo, p, l2info.length, l2info.caplen);
      break;
    case (LLC_UI << 8 | NLPID_Q933):
    case (LLC_UI << 8 | NLPID_IP):
    case (LLC_UI << 8 | NLPID_IP6):
      isoclns_print(ndo, p - 1, l2info.length + 1, l2info.caplen + 1);
      break;
    default:
      ND_PRINT((ndo, "unknown protocol 0x%04x, length %u", l2info.proto,
                l2info.length));
  }
  return l2info.header_len;
}

static void mdbEvalSetColumnJSON(MyDbEvalContext* p, int iCol,
                                 Jsi_DString* dStr) {
  Jsi_Interp* interp = p->jdb->interp;
  char nbuf[200];
  MysqlPrep* prep = p->prep;
  SqlFieldResults* field = prep->fieldResult + iCol;
  if (field->isnull) {
    Jsi_DSAppend(dStr, "null", NULL);
    return;
  }
  const char* zBlob = "";
  int bytes = 0;
  switch (field->jsiTypeMap) {
    case JSI_OPTION_BOOL: {
      snprintf(nbuf, sizeof(nbuf), "%s",
               field->buffer.vchar ? "true" : "false");
      Jsi_DSAppend(dStr, nbuf, NULL);
      return;
    }
    case JSI_OPTION_INT64: {
      snprintf(nbuf, sizeof(nbuf), "%lld", field->buffer.vlonglong);
      Jsi_DSAppend(dStr, nbuf, NULL);
      return;
    }
    case JSI_OPTION_DOUBLE: {
      Jsi_NumberToString(interp, field->buffer.vdouble, nbuf, sizeof(nbuf));
      Jsi_DSAppend(dStr, nbuf, NULL);
      return;
    }
    case JSI_OPTION_TIME_D:
    case JSI_OPTION_TIME_W: {
      Jsi_Number jtime = mdbMyTimeToJS(&field->buffer.timestamp);
      Jsi_NumberToString(interp, jtime, nbuf, sizeof(nbuf));
      Jsi_DSAppend(dStr, nbuf, NULL);
      return;
    }
    case JSI_OPTION_STRING:
      zBlob = field->buffer.vstring;
    default: {
      if (!zBlob) {
        Jsi_DSAppend(dStr, "null", NULL);
        return;
      }
      Jsi_JSONQuote(interp, zBlob, bytes, dStr);
      return;
    }
  }
}

get_pols_2_svc(gpols_arg* arg, struct svc_req* rqstp) {
  static gpols_ret ret;
  char* prime_arg;
  gss_buffer_desc client_name, service_name;
  OM_uint32 minor_stat;
  kadm5_server_handle_t handle;
  const char* errmsg = NULL;
  xdr_free(xdr_gpols_ret, &ret);
  if ((ret.code = new_server_handle(arg->api_version, rqstp, &handle)))
    goto exit_func;
  if ((ret.code = check_handle((void*)handle))) goto exit_func;
  ret.api_version = handle->api_version;
  if (setup_gss_names(rqstp, &client_name, &service_name) < 0) {
    ret.code = KADM5_FAILURE;
    goto exit_func;
  }
  prime_arg = arg->exp;
  if (prime_arg == NULL) prime_arg = "*";
  if (CHANGEPW_SERVICE(rqstp) ||
      !kadm5int_acl_check(handle->context, rqst2name(rqstp), ACL_LIST, NULL,
                          NULL)) {
    ret.code = KADM5_AUTH_LIST;
    log_unauth("kadm5_get_policies", prime_arg, &client_name, &service_name,
               rqstp);
  } else {
    ret.code =
        kadm5_get_policies((void*)handle, arg->exp, &ret.pols, &ret.count);
    if (ret.code != 0)
      errmsg = krb5_get_error_message(handle->context, ret.code);
    log_done("kadm5_get_policies", prime_arg, errmsg, &client_name,
             &service_name, rqstp);
    if (errmsg != NULL) krb5_free_error_message(handle->context, errmsg);
  }
  gss_release_buffer(&minor_stat, &client_name);
  gss_release_buffer(&minor_stat, &service_name);
exit_func:
  free_server_handle(handle);
  return &ret;
}

int32_t* enc_untrusted_create_wait_queue() {
  MessageWriter input;
  MessageReader output;
  input.Push<uint64_t>(sizeof(int32_t));
  const auto status = NonSystemCallDispatcher(
      ::asylo::host_call::kLocalLifetimeAllocHandler, &input, &output);
  CheckStatusAndParamCount(status, output, "enc_untrusted_create_wait_queue",
                           2);
  int32_t* queue = reinterpret_cast<int32_t*>(output.next<uintptr_t>());
  int klinux_errno = output.next<int>();
  if (queue == nullptr) {
    errno = FromkLinuxErrorNumber(klinux_errno);
  }
  enc_untrusted_disable_waiting(queue);
  return queue;
}

init_ctx_new(OM_uint32* minor_status, spnego_gss_cred_id_t spcred,
             gss_ctx_id_t* ctx, send_token_flag* tokflag) {
  OM_uint32 ret;
  spnego_gss_ctx_id_t sc = NULL;
  sc = create_spnego_ctx();
  if (sc == NULL) return GSS_S_FAILURE;
  ret =
      get_negotiable_mechs(minor_status, spcred, GSS_C_INITIATE, &sc->mech_set);
  if (ret != GSS_S_COMPLETE) goto cleanup;
  sc->internal_mech = &sc->mech_set->elements[0];
  if (put_mech_set(sc->mech_set, &sc->DER_mechTypes) < 0) {
    ret = GSS_S_FAILURE;
    goto cleanup;
  }
  sc->ctx_handle = GSS_C_NO_CONTEXT;
  *ctx = (gss_ctx_id_t)sc;
  sc = NULL;
  *tokflag = INIT_TOKEN_SEND;
  ret = GSS_S_CONTINUE_NEEDED;
cleanup:
  release_spnego_ctx(&sc);
  return ret;
}

copy_ciphersuites(gnutls_session_t session, gnutls_buffer_st* cdata,
                  int add_scsv) {
  int ret;
  uint8_t cipher_suites[MAX_CIPHERSUITE_SIZE + 2];
  int cipher_suites_size;
  size_t init_length = cdata->length;
  ret = _gnutls_supported_ciphersuites(session, cipher_suites,
                                       sizeof(cipher_suites) - 2);
  if (ret < 0) return gnutls_assert_val(ret);
  ret = _gnutls_remove_unwanted_ciphersuites(session, cipher_suites, ret, NULL,
                                             0);
  if (ret < 0) return gnutls_assert_val(ret);
  if (ret == 0) return gnutls_assert_val(GNUTLS_E_INSUFFICIENT_CREDENTIALS);
  cipher_suites_size = ret;
  if (add_scsv) {
    cipher_suites[cipher_suites_size] = 0x00;
    cipher_suites[cipher_suites_size + 1] = 0xff;
    cipher_suites_size += 2;
    ret = _gnutls_ext_sr_send_cs(session);
    if (ret < 0) return gnutls_assert_val(ret);
  }
  ret = _gnutls_buffer_append_data_prefix(cdata, 16, cipher_suites,
                                          cipher_suites_size);
  if (ret < 0) return gnutls_assert_val(ret);
  ret = cdata->length - init_length;
  return ret;
}

static void __init mp_override_legacy_irq(u8 bus_irq, u8 polarity, u8 trigger,
                                          u32 gsi) {
  int ioapic;
  int pin;
  struct mpc_intsrc mp_irq;
  ioapic = mp_find_ioapic(gsi);
  if (ioapic < 0) return;
  pin = mp_find_ioapic_pin(ioapic, gsi);
  if ((bus_irq == 0) && (trigger == 3)) trigger = 1;
  mp_irq.type = MP_INTSRC;
  mp_irq.irqtype = mp_INT;
  mp_irq.irqflag = (trigger << 2) | polarity;
  mp_irq.srcbus = MP_ISA_BUS;
  mp_irq.srcbusirq = bus_irq;
  mp_irq.dstapic = mpc_ioapic_id(ioapic);
  mp_irq.dstirq = pin;
  mp_save_irq(&mp_irq);
  if (gsi < nr_legacy_irqs() && isa_irq_to_gsi[gsi] == gsi)
    isa_irq_to_gsi[gsi] = ACPI_INVALID_GSI;
  isa_irq_to_gsi[bus_irq] = gsi;
}

int xfrm_migrate(const struct xfrm_selector* sel, u8 dir, u8 type,
                 struct xfrm_migrate* m, int num_migrate,
                 struct xfrm_kmaddress* k, struct net* net,
                 struct xfrm_encap_tmpl* encap) {
  int i, err, nx_cur = 0, nx_new = 0;
  struct xfrm_policy* pol = NULL;
  struct xfrm_state *x, *xc;
  struct xfrm_state* x_cur[XFRM_MAX_DEPTH];
  struct xfrm_state* x_new[XFRM_MAX_DEPTH];
  struct xfrm_migrate* mp;
  if ((err = xfrm_migrate_check(m, num_migrate)) < 0) goto out;
  if ((pol = xfrm_migrate_policy_find(sel, dir, type, net)) == NULL) {
    err = -ENOENT;
    goto out;
  }
  for (i = 0, mp = m; i < num_migrate; i++, mp++) {
    if ((x = xfrm_migrate_state_find(mp, net))) {
      x_cur[nx_cur] = x;
      nx_cur++;
      xc = xfrm_state_migrate(x, mp, encap);
      if (xc) {
        x_new[nx_new] = xc;
        nx_new++;
      } else {
        err = -ENODATA;
        goto restore_state;
      }
    }
  }
  if ((err = xfrm_policy_migrate(pol, m, num_migrate)) < 0) goto restore_state;
  if (nx_cur) {
    xfrm_states_put(x_cur, nx_cur);
    xfrm_states_delete(x_cur, nx_cur);
  }
  km_migrate(sel, dir, type, m, num_migrate, k, encap);
  xfrm_pol_put(pol);
  return 0;
out:
  return err;
restore_state:
  if (pol) xfrm_pol_put(pol);
  if (nx_cur) xfrm_states_put(x_cur, nx_cur);
  if (nx_new) xfrm_states_delete(x_new, nx_new);
  return err;
}

char* ldb_dn_escape_value(TALLOC_CTX* mem_ctx, struct ldb_val value) {
  char* dst;
  if (!value.length) return NULL;
  dst = talloc_array(mem_ctx, char, value.length * 3 + 1);
  if (!dst) {
    talloc_free(dst);
    return NULL;
  }
  ldb_dn_escape_internal(dst, (const char*)value.data, value.length);
  dst = talloc_realloc(mem_ctx, dst, char, strlen(dst) + 1);
  return dst;
}

convert(Imaging imOut, Imaging imIn, const char* mode, ImagingPalette palette,
        int dither) {
  ImagingSectionCookie cookie;
  ImagingShuffler convert;
  int y;
  if (!imIn) {
    return (Imaging)ImagingError_ModeError();
  }
  if (!mode) {
    if (!imIn->palette) {
      return (Imaging)ImagingError_ModeError();
    }
    mode = imIn->palette->mode;
  } else {
    if (!strcmp(imIn->mode, mode)) {
      return ImagingCopy2(imOut, imIn);
    }
  }
  if (strcmp(imIn->mode, "P") == 0 || strcmp(imIn->mode, "PA") == 0) {
    return frompalette(imOut, imIn, mode);
  }
  if (strcmp(mode, "P") == 0 || strcmp(mode, "PA") == 0) {
    return topalette(imOut, imIn, mode, palette, dither);
  }
  if (dither && strcmp(mode, "1") == 0) {
    return tobilevel(imOut, imIn, dither);
  }
  convert = NULL;
  for (y = 0; converters[y].from; y++) {
    if (!strcmp(imIn->mode, converters[y].from) &&
        !strcmp(mode, converters[y].to)) {
      convert = converters[y].convert;
      break;
    }
  }
  if (!convert) {
#ifdef notdef
    return (Imaging)ImagingError_ValueError("conversion not supported");
#else
    static char buf[100];
    sprintf(buf, "conversion from %.10s to %.10s not supported", imIn->mode,
            mode);
    return (Imaging)ImagingError_ValueError(buf);
#endif
  }
  imOut = ImagingNew2Dirty(mode, imOut, imIn);
  if (!imOut) {
    return NULL;
  }
  ImagingSectionEnter(&cookie);
  for (y = 0; y < imIn->ysize; y++) {
    (*convert)((UINT8*)imOut->image[y], (UINT8*)imIn->image[y], imIn->xsize);
  }
  ImagingSectionLeave(&cookie);
  return imOut;
}

static int tc_fill_qdisc(struct sk_buff* skb, struct Qdisc* q, u32 clid,
                         u32 pid, u32 seq, u16 flags, int event) {
  struct tcmsg* tcm;
  struct nlmsghdr* nlh;
  unsigned char* b = skb->tail;
  struct gnet_dump d;
  nlh = NLMSG_NEW(skb, pid, seq, event, sizeof(*tcm), flags);
  tcm = NLMSG_DATA(nlh);
  tcm->tcm_family = AF_UNSPEC;
  tcm->tcm_ifindex = q->dev->ifindex;
  tcm->tcm_parent = clid;
  tcm->tcm_handle = q->handle;
  tcm->tcm_info = atomic_read(&q->refcnt);
  RTA_PUT(skb, TCA_KIND, IFNAMSIZ, q->ops->id);
  if (q->ops->dump && q->ops->dump(q, skb) < 0) goto rtattr_failure;
  q->qstats.qlen = q->q.qlen;
  if (gnet_stats_start_copy_compat(skb, TCA_STATS2, TCA_STATS, TCA_XSTATS,
                                   q->stats_lock, &d) < 0)
    goto rtattr_failure;
  if (q->ops->dump_stats && q->ops->dump_stats(q, &d) < 0) goto rtattr_failure;
  if (gnet_stats_copy_basic(&d, &q->bstats) < 0 ||
#ifdef CONFIG_NET_ESTIMATOR
      gnet_stats_copy_rate_est(&d, &q->rate_est) < 0 ||
#endif
      gnet_stats_copy_queue(&d, &q->qstats) < 0)
    goto rtattr_failure;
  if (gnet_stats_finish_copy(&d) < 0) goto rtattr_failure;
  nlh->nlmsg_len = skb->tail - b;
  return skb->len;
nlmsg_failure:
rtattr_failure:
  skb_trim(skb, b - skb->data);
  return -1;
}

