void ModifiablePixelBuffer::fillRect(const Rect& r, const void* pix) {
  int stride;
  U8* buf;
  int w, h, b;
  w = r.width();
  h = r.height();
  b = format.bpp / 8;
  if (h == 0) return;
  buf = getBufferRW(r, &stride);
  if (b == 1) {
    while (h--) {
      memset(buf, *(const U8*)pix, w);
      buf += stride * b;
    }
  } else {
    U8* start;
    int w1;
    start = buf;
    w1 = w;
    while (w1--) {
      memcpy(buf, pix, b);
      buf += b;
    }
    buf += (stride - w) * b;
    h--;
    while (h--) {
      memcpy(buf, start, w * b);
      buf += stride * b;
    }
  }
  commitBufferRW(r);
}

switchGroup(uid_t uid, const struct passwd* userInfo, gid_t gid) {
  if (userInfo != NULL) {
    bool setgroupsCalled = false;
#if defined(__linux__) || defined(__APPLE__) || defined(__FreeBSD__)
#ifdef __APPLE__
    int groups[1024];
    int ngroups = sizeof(groups) / sizeof(int);
#else
    gid_t groups[1024];
    int ngroups = sizeof(groups) / sizeof(gid_t);
#endif
    boost::scoped_array<gid_t> gidset;
    int ret = getgrouplist(userInfo->pw_name, gid, groups, &ngroups);
    if (ret == -1) {
      int e = errno;
      fprintf(stderr, "ERROR: getgrouplist(%s, %d) failed: %s (errno=%d)\n",
              userInfo->pw_name, (int)gid, strerror(e), e);
      exit(1);
    }
    if (ngroups <= NGROUPS_MAX) {
      setgroupsCalled = true;
      gidset.reset(new gid_t[ngroups]);
      if (setgroups(ngroups, gidset.get()) == -1) {
        int e = errno;
        fprintf(stderr, "ERROR: setgroups(%d, ...) failed: %s (errno=%d)\n",
                ngroups, strerror(e), e);
        exit(1);
      }
    }
#endif
    if (!setgroupsCalled && initgroups(userInfo->pw_name, gid) == -1) {
      int e = errno;
      fprintf(stderr, "ERROR: initgroups(%s, %d) failed: %s (errno=%d)\n",
              userInfo->pw_name, (int)gid, strerror(e), e);
      exit(1);
    }
  }
  if (setgid(gid) == -1) {
    int e = errno;
    fprintf(stderr, "ERROR: setgid(%d) failed: %s (errno=%d)\n", (int)gid,
            strerror(e), e);
    exit(1);
  }
}

