String StringUtil::Implode(const Variant& items, const String& delim,
                           const bool checkIsContainer) {
  if (checkIsContainer && !isContainer(items)) {
    throw_param_is_not_container();
  }
  int size = getContainerSize(items);
  if (size == 0) return empty_string();
  req::vector<String> sitems;
  sitems.reserve(size);
  int len = 0;
  int lenDelim = delim.size();
  for (ArrayIter iter(items); iter; ++iter) {
    sitems.emplace_back(iter.second().toString());
    len += sitems.back().size() + lenDelim;
  }
  len -= lenDelim;
  assert(sitems.size() == size);
  String s = String(len, ReserveString);
  char* buffer = s.mutableData();
  const char* sdelim = delim.data();
  char* p = buffer;
  String& init_str = sitems[0];
  int init_len = init_str.size();
  memcpy(p, init_str.data(), init_len);
  p += init_len;
  for (int i = 1; i < size; i++) {
    String& item = sitems[i];
    memcpy(p, sdelim, lenDelim);
    p += lenDelim;
    int lenItem = item.size();
    memcpy(p, item.data(), lenItem);
    p += lenItem;
  }
  assert(p - buffer == len);
  s.setSize(len);
  return s;
}

int init_aliases(void) {
  FILE* fp;
  char alias[MAXALIASLEN + 1U];
  char dir[PATH_MAX + 1U];
  if ((fp = fopen(ALIASES_FILE, "r")) == NULL) {
    return 0;
  }
  while (fgets(alias, sizeof alias, fp) != NULL) {
    if (*alias == '#' || *alias == '\n' || *alias == 0) {
      continue;
    }
    {
      char* const z = alias + strlen(alias) - 1U;
      if (*z != '\n') {
        goto bad;
      }
      *z = 0;
    }
    do {
      if (fgets(dir, sizeof dir, fp) == NULL || *dir == 0) {
        goto bad;
      }
      {
        char* const z = dir + strlen(dir) - 1U;
        if (*z == '\n') {
          *z = 0;
        }
      }
    } while (*dir == '#' || *dir == 0);
    if (head == NULL) {
      if ((head = tail = malloc(sizeof *head)) == NULL ||
          (tail->alias = strdup(alias)) == NULL ||
          (tail->dir = strdup(dir)) == NULL) {
        die_mem();
      }
      tail->next = NULL;
    } else {
      DirAlias* curr;
      if ((curr = malloc(sizeof *curr)) == NULL ||
          (curr->alias = strdup(alias)) == NULL ||
          (curr->dir = strdup(dir)) == NULL) {
        die_mem();
      }
      tail->next = curr;
      tail = curr;
    }
  }
  fclose(fp);
  aliases_up++;
  return 0;
bad:
  fclose(fp);
  logfile(LOG_ERR, MSG_ALIASES_BROKEN_FILE " [" ALIASES_FILE "]");
  return -1;
}

decode_bytestring(CBORDecoderObject* self, uint8_t subtype) {
  uint64_t length = 0;
  bool indefinite = true;
  PyObject* ret;
  char length_hex[17];
  if (decode_length(self, subtype, &length, &indefinite) == -1) return NULL;
  if (length > (uint64_t)PY_SSIZE_T_MAX - (uint64_t)PyBytesObject_SIZE) {
    sprintf(length_hex, "%llX", length);
    PyErr_Format(_CBOR2_CBORDecodeValueError, "excessive bytestring size 0x%s",
                 length_hex);
    return NULL;
  }
  if (indefinite)
    ret = decode_indefinite_bytestrings(self);
  else
    ret = decode_definite_bytestring(self, (Py_ssize_t)length);
  set_shareable(self, ret);
  return ret;
}

int dsOpen(void) {
  struct stat sb;
  int retval;
  char* path = server.diskstore_path;
  if ((retval = stat(path, &sb) == -1) && errno != ENOENT) {
    redisLog(REDIS_WARNING, "Error opening disk store at %s: %s", path,
             strerror(errno));
    return REDIS_ERR;
  }
  if (retval == 0 && S_ISDIR(sb.st_mode)) return REDIS_OK;
  if (retval == 0 && !S_ISDIR(sb.st_mode)) {
    redisLog(REDIS_WARNING, "Disk store at %s is not a directory", path);
    return REDIS_ERR;
  }
  if (mkdir(path) == -1) {
    redisLog(REDIS_WARNING, "Disk store init failed creating dir %s: %s", path,
             strerror(errno));
    return REDIS_ERR;
  }
  return REDIS_OK;
}

