static void pipe_advance(struct iov_iter* i, size_t size) {
  struct pipe_inode_info* pipe = i->pipe;
  struct pipe_buffer* buf;
  int idx = i->idx;
  size_t off = i->iov_offset, orig_sz;
  if (unlikely(i->count < size)) size = i->count;
  orig_sz = size;
  if (size) {
    if (off) size += off - pipe->bufs[idx].offset;
    while (1) {
      buf = &pipe->bufs[idx];
      if (size <= buf->len) break;
      size -= buf->len;
      idx = next_idx(idx, pipe);
    }
    buf->len = size;
    i->idx = idx;
    off = i->iov_offset = buf->offset + size;
  }
  if (off) idx = next_idx(idx, pipe);
  if (pipe->nrbufs) {
    int unused = (pipe->curbuf + pipe->nrbufs) & (pipe->buffers - 1);
    while (idx != unused) {
      pipe_buf_release(pipe, &pipe->bufs[idx]);
      idx = next_idx(idx, pipe);
      pipe->nrbufs--;
    }
  }
  i->count -= orig_sz;
}

NOEXPORT int init_section(int eof, SERVICE_OPTIONS** section_ptr) {
  char* errstr;
#ifndef USE_WIN32
  (*section_ptr)->option.log_stderr = new_global_options.option.log_stderr;
#endif
  if (*section_ptr == &new_service_options) {
    errstr = parse_global_option(CMD_INITIALIZE, NULL, NULL);
    if (errstr) {
      s_log(LOG_ERR, "Global options: %s", errstr);
      return 1;
    }
  }
  if (*section_ptr != &new_service_options || eof) {
    if (*section_ptr == &new_service_options)
      s_log(LOG_INFO, "Initializing inetd mode configuration");
    else
      s_log(LOG_INFO, "Initializing service [%s]", (*section_ptr)->servname);
    errstr = parse_service_option(CMD_INITIALIZE, section_ptr, NULL, NULL);
    if (errstr) {
      if (*section_ptr == &new_service_options)
        s_log(LOG_ERR, "Inetd mode: %s", errstr);
      else
        s_log(LOG_ERR, "Service [%s]: %s", (*section_ptr)->servname, errstr);
      return 1;
    }
  }
  return 0;
}

static void start_auth_request(PgSocket* client, const char* username) {
  int res;
  PktBuf* buf;
  client->auth_user = client->db->auth_user;
  client->pool = get_pool(client->db, client->db->auth_user);
  if (!find_server(client)) {
    client->wait_for_user_conn = true;
    return;
  }
  slog_noise(client, "Doing auth_conn query");
  client->wait_for_user_conn = false;
  client->wait_for_user = true;
  if (!sbuf_pause(&client->sbuf)) {
    release_server(client->link);
    disconnect_client(client, true, "pause failed");
    return;
  }
  client->link->ready = 0;
  res = 0;
  buf = pktbuf_dynamic(512);
  if (buf) {
    pktbuf_write_ExtQuery(buf, cf_auth_query, 1, username);
    res = pktbuf_send_immediate(buf, client->link);
    pktbuf_free(buf);
  }
  if (!res)
    disconnect_server(client->link, false, "unable to send login query");
}

static inline int pmd_none_or_trans_huge_or_clear_bad(pmd_t* pmd) {
  pmd_t pmdval = pmd_read_atomic(pmd);
#ifdef CONFIG_TRANSPARENT_HUGEPAGE
  barrier();
#endif
  if (pmd_none(pmdval)) return 1;
  if (unlikely(pmd_bad(pmdval))) {
    if (!pmd_trans_huge(pmdval)) pmd_clear_bad(pmd);
    return 1;
  }
  return 0;
}

addMultirowsForm(Buffer* buf, AnchorList* al) {
  int i, j, k, col, ecol, pos;
  Anchor a_form, *a;
  Line *l, *ls;
  if (al == NULL || al->nanchor == 0) return;
  for (i = 0; i < al->nanchor; i++) {
    a_form = al->anchors[i];
    al->anchors[i].rows = 1;
    if (a_form.hseq < 0 || a_form.rows <= 1) continue;
    for (l = buf->firstLine; l != NULL; l = l->next) {
      if (l->linenumber == a_form.y) break;
    }
    if (!l) continue;
    if (a_form.y == a_form.start.line)
      ls = l;
    else {
      for (ls = l; ls != NULL;
           ls = (a_form.y < a_form.start.line) ? ls->next : ls->prev) {
        if (ls->linenumber == a_form.start.line) break;
      }
      if (!ls) continue;
    }
    col = COLPOS(ls, a_form.start.pos);
    ecol = COLPOS(ls, a_form.end.pos);
    for (j = 0; l && j < a_form.rows; l = l->next, j++) {
      pos = columnPos(l, col);
      if (j == 0) {
        buf->hmarklist->marks[a_form.hseq].line = l->linenumber;
        buf->hmarklist->marks[a_form.hseq].pos = pos;
      }
      if (a_form.start.line == l->linenumber) continue;
      buf->formitem = putAnchor(buf->formitem, a_form.url, a_form.target, &a,
                                NULL, NULL, '\0', l->linenumber, pos);
      a->hseq = a_form.hseq;
      a->y = a_form.y;
      a->end.pos = pos + ecol - col;
      l->lineBuf[pos - 1] = '[';
      l->lineBuf[a->end.pos] = ']';
      for (k = pos; k < a->end.pos; k++) l->propBuf[k] |= PE_FORM;
    }
  }
}

void ssl_update_cache(SSL* s, int mode) {
  int i;
  if (s->session->session_id_length == 0) return;
  if (s->server && s->session->sid_ctx_length == 0 &&
      (s->verify_mode & SSL_VERIFY_PEER) != 0)
    return;
  i = s->session_ctx->session_cache_mode;
  if ((i & mode) != 0 && (!s->hit || SSL_IS_TLS13(s))) {
    if ((i & SSL_SESS_CACHE_NO_INTERNAL_STORE) == 0 &&
        (!SSL_IS_TLS13(s) || !s->server ||
         (s->max_early_data > 0 && (s->options & SSL_OP_NO_ANTI_REPLAY) == 0) ||
         s->session_ctx->remove_session_cb != NULL ||
         (s->options & SSL_OP_NO_TICKET) != 0))
      SSL_CTX_add_session(s->session_ctx, s->session);
    if (s->session_ctx->new_session_cb != NULL) {
      SSL_SESSION_up_ref(s->session);
      if (!s->session_ctx->new_session_cb(s, s->session))
        SSL_SESSION_free(s->session);
    }
  }
  if ((!(i & SSL_SESS_CACHE_NO_AUTO_CLEAR)) && ((i & mode) == mode)) {
    TSAN_QUALIFIER int* stat;
    if (mode & SSL_SESS_CACHE_CLIENT)
      stat = &s->session_ctx->stats.sess_connect_good;
    else
      stat = &s->session_ctx->stats.sess_accept_good;
    if ((ssl_tsan_load(s->session_ctx, stat) & 0xff) == 0xff)
      SSL_CTX_flush_sessions(s->session_ctx, (unsigned long)time(NULL));
  }
}

static void ip6_append_data_mtu(int* mtu, int* maxfraglen,
                                unsigned int fragheaderlen, struct sk_buff* skb,
                                struct rt6_info* rt) {
  if (!(rt->dst.flags & DST_XFRM_TUNNEL)) {
    if (skb == NULL) {
      *mtu = *mtu - rt->dst.header_len;
    } else {
      *mtu = dst_mtu(rt->dst.path);
    }
    *maxfraglen =
        ((*mtu - fragheaderlen) & ~7) + fragheaderlen - sizeof(struct frag_hdr);
  }
}

