static pfunc check_literal(struct jv_parser* p) {
  if (p->tokenpos == 0) return 0;
  const char* pattern = 0;
  int plen;
  jv v;
  switch (p->tokenbuf[0]) {
    case 't':
      pattern = "true";
      plen = 4;
      v = jv_true();
      break;
    case 'f':
      pattern = "false";
      plen = 5;
      v = jv_false();
      break;
    case 'n':
      pattern = "null";
      plen = 4;
      v = jv_null();
      break;
  }
  if (pattern) {
    if (p->tokenpos != plen) return "Invalid literal";
    for (int i = 0; i < plen; i++)
      if (p->tokenbuf[i] != pattern[i]) return "Invalid literal";
    TRY(value(p, v));
  } else {
    p->tokenbuf[p->tokenpos] = 0;
    char* end = 0;
    double d = jvp_strtod(&p->dtoa, p->tokenbuf, &end);
    if (end == 0 || *end != 0) return "Invalid numeric literal";
    TRY(value(p, jv_number(d)));
  }
  p->tokenpos = 0;
  return 0;
}

Pl_AES_PDF::flush(bool strip_padding) {
  assert(this->offset == this->buf_size);
  if (first) {
    first = false;
    bool return_after_init = false;
    if (this->cbc_mode) {
      if (encrypt) {
        initializeVector();
        if (!(this->use_zero_iv || this->use_specified_iv)) {
          getNext()->write(this->cbc_block, this->buf_size);
        }
      } else if (this->use_zero_iv || this->use_specified_iv) {
        initializeVector();
      } else {
        memcpy(this->cbc_block, this->inbuf, this->buf_size);
        this->offset = 0;
        return_after_init = true;
      }
    }
    this->crypto->rijndael_init(encrypt, this->key.get(), key_bytes,
                                this->cbc_mode, this->cbc_block);
    if (return_after_init) {
      return;
    }
  }
  if (this->encrypt) {
    this->crypto->rijndael_process(this->inbuf, this->outbuf);
  } else {
    this->crypto->rijndael_process(this->inbuf, this->outbuf);
  }
  unsigned int bytes = this->buf_size;
  if (strip_padding) {
    unsigned char last = this->outbuf[this->buf_size - 1];
    if (last <= this->buf_size) {
      bool strip = true;
      for (unsigned int i = 1; i <= last; ++i) {
        if (this->outbuf[this->buf_size - i] != last) {
          strip = false;
          break;
        }
      }
      if (strip) {
        bytes -= last;
      }
    }
  }
  getNext()->write(this->outbuf, bytes);
  this->offset = 0;
}

