UnicodeString::doAppend(const UChar* srcChars, int32_t srcStart,
                        int32_t srcLength) {
  if (!isWritable() || srcLength == 0 || srcChars == NULL) {
    return *this;
  }
  srcChars += srcStart;
  if (srcLength < 0) {
    if ((srcLength = u_strlen(srcChars)) == 0) {
      return *this;
    }
  }
  int32_t oldLength = length();
  int32_t newLength = oldLength + srcLength;
  const UChar* oldArray = getArrayStart();
  if (isBufferWritable() && oldArray < srcChars + srcLength &&
      srcChars < oldArray + oldLength) {
    UnicodeString copy(srcChars, srcLength);
    if (copy.isBogus()) {
      setToBogus();
      return *this;
    }
    return doAppend(copy.getArrayStart(), 0, srcLength);
  }
  if ((newLength <= getCapacity() && isBufferWritable()) ||
      cloneArrayIfNeeded(newLength, getGrowCapacity(newLength))) {
    UChar* newArray = getArrayStart();
    if (srcChars != newArray + oldLength) {
      us_arrayCopy(srcChars, 0, newArray, oldLength, srcLength);
    }
    setLength(newLength);
  }
  return *this;
}

runas_grouplist_matches(const struct sudoers_parse_tree* parse_tree,
                        const struct member_list* group_list,
                        struct member** matching_group) {
  const struct sudoers_context* ctx = parse_tree->ctx;
  int group_matched = UNSPEC;
  struct member* m;
  struct alias* a;
  debug_decl(runas_grouplist_matches, SUDOERS_DEBUG_MATCH);
  if (group_list != NULL) {
    TAILQ_FOREACH_REVERSE(m, group_list, member_list, entries) {
      switch (m->type) {
        case ALL:
          group_matched = m->negated ? DENY : ALLOW;
          break;
        case ALIAS:
          a = alias_get(parse_tree, m->name, RUNASALIAS);
          if (a != NULL) {
            const int rc = runas_grouplist_matches(parse_tree, &a->members,
                                                   matching_group);
            if (rc != UNSPEC) {
              if (m->negated) {
                group_matched = rc == ALLOW ? DENY : ALLOW;
              } else {
                group_matched = rc;
              }
            }
            alias_put(a);
            break;
          }
          FALLTHROUGH;
        case WORD:
          if (group_matches(m->name, ctx->runas.gr))
            group_matched = m->negated ? DENY : ALLOW;
          break;
      }
      if (group_matched != UNSPEC) {
        if (matching_group != NULL && m->type != ALIAS) *matching_group = m;
        break;
      }
    }
  }
  if (group_matched == UNSPEC) {
    struct gid_list* runas_groups;
    if (ctx->runas.pw->pw_gid == ctx->runas.gr->gr_gid) {
      group_matched = ALLOW;
    } else if ((runas_groups = runas_getgroups(ctx)) != NULL) {
      int i;
      for (i = 0; i < runas_groups->ngids; i++) {
        if (runas_groups->gids[i] == ctx->runas.gr->gr_gid) {
          group_matched = ALLOW;
          break;
        }
      }
      sudo_gidlist_delref(runas_groups);
    }
  }
  debug_return_int(group_matched);
}

static inline void get_conn_text(const conn* c, const int af, char* addr,
                                 struct sockaddr* sock_addr) {
  char addr_text[MAXPATHLEN];
  addr_text[0] = '\0';
  const char* protoname = "?";
  unsigned short port = 0;
  switch (af) {
    case AF_INET:
      (void)inet_ntop(af, &((struct sockaddr_in*)sock_addr)->sin_addr,
                      addr_text, sizeof(addr_text) - 1);
      port = ntohs(((struct sockaddr_in*)sock_addr)->sin_port);
      protoname = IS_UDP(c->transport) ? "udp" : "tcp";
      break;
    case AF_INET6:
      addr_text[0] = '[';
      addr_text[1] = '\0';
      if (inet_ntop(af, &((struct sockaddr_in6*)sock_addr)->sin6_addr,
                    addr_text + 1, sizeof(addr_text) - 2)) {
        strcat(addr_text, "]");
      }
      port = ntohs(((struct sockaddr_in6*)sock_addr)->sin6_port);
      protoname = IS_UDP(c->transport) ? "udp6" : "tcp6";
      break;
    case AF_UNIX:
      strncpy(addr_text, ((struct sockaddr_un*)sock_addr)->sun_path,
              sizeof(addr_text) - 1);
      addr_text[sizeof(addr_text) - 1] = '\0';
      protoname = "unix";
      break;
  }
  if (strlen(addr_text) < 2) {
    sprintf(addr_text, "<AF %d>", af);
  }
  if (port) {
    sprintf(addr, "%s:%s:%u", protoname, addr_text, port);
  } else {
    sprintf(addr, "%s:%s", protoname, addr_text);
  }
}

int pipe_resize_ring(struct pipe_inode_info* pipe, unsigned int nr_slots) {
  struct pipe_buffer* bufs;
  unsigned int head, tail, mask, n;
  mask = pipe->ring_size - 1;
  head = pipe->head;
  tail = pipe->tail;
  n = pipe_occupancy(pipe->head, pipe->tail);
  if (nr_slots < n) return -EBUSY;
  bufs = kcalloc(nr_slots, sizeof(*bufs), GFP_KERNEL_ACCOUNT | __GFP_NOWARN);
  if (unlikely(!bufs)) return -ENOMEM;
  if (n > 0) {
    unsigned int h = head & mask;
    unsigned int t = tail & mask;
    if (h > t) {
      memcpy(bufs, pipe->bufs + t, n * sizeof(struct pipe_buffer));
    } else {
      unsigned int tsize = pipe->ring_size - t;
      if (h > 0)
        memcpy(bufs + tsize, pipe->bufs, h * sizeof(struct pipe_buffer));
      memcpy(bufs, pipe->bufs + t, tsize * sizeof(struct pipe_buffer));
    }
  }
  head = n;
  tail = 0;
  kfree(pipe->bufs);
  pipe->bufs = bufs;
  pipe->ring_size = nr_slots;
  if (pipe->max_usage > nr_slots) pipe->max_usage = nr_slots;
  pipe->tail = tail;
  pipe->head = head;
  wake_up_interruptible(&pipe->wr_wait);
  return 0;
}

static int filter_frame(AVFilterLink* inlink, AVFrame* in) {
  DelogoContext* s = inlink->dst->priv;
  AVFilterLink* outlink = inlink->dst->outputs[0];
  const AVPixFmtDescriptor* desc = av_pix_fmt_desc_get(inlink->format);
  AVFrame* out;
  int hsub0 = desc->log2_chroma_w;
  int vsub0 = desc->log2_chroma_h;
  int direct = 0;
  int plane;
  AVRational sar;
  if (av_frame_is_writable(in)) {
    direct = 1;
    out = in;
  } else {
    out = ff_get_video_buffer(outlink, outlink->w, outlink->h);
    if (!out) {
      av_frame_free(&in);
      return AVERROR(ENOMEM);
    }
    av_frame_copy_props(out, in);
  }
  sar = in->sample_aspect_ratio;
  if (!sar.num) sar.num = sar.den = 1;
  for (plane = 0; plane < 4 && in->data[plane]; plane++) {
    int hsub = plane == 1 || plane == 2 ? hsub0 : 0;
    int vsub = plane == 1 || plane == 2 ? vsub0 : 0;
    apply_delogo(out->data[plane], out->linesize[plane], in->data[plane],
                 in->linesize[plane], FF_CEIL_RSHIFT(inlink->w, hsub),
                 FF_CEIL_RSHIFT(inlink->h, vsub), sar, s->x >> hsub,
                 s->y >> vsub,
                 FF_CEIL_RSHIFT(s->w + (s->x & ((1 << hsub) - 1)), hsub),
                 FF_CEIL_RSHIFT(s->h + (s->y & ((1 << vsub) - 1)), vsub),
                 s->band >> FFMIN(hsub, vsub), s->show, direct);
  }
  if (!direct) av_frame_free(&in);
  return ff_filter_frame(outlink, out);
}

