  };
}

static bool access_pmu_evcntr(struct kvm_vcpu* vcpu, struct sys_reg_params* p,
                              const struct sys_reg_desc* r) {
  u64 idx;
  if (!kvm_arm_pmu_v3_ready(vcpu)) return trap_raz_wi(vcpu, p, r);
  if (r->CRn == 9 && r->CRm == 13) {
    if (r->Op2 == 2) {
      if (pmu_access_event_counter_el0_disabled(vcpu)) return false;
      idx = vcpu_sys_reg(vcpu, PMSELR_EL0) & ARMV8_PMU_COUNTER_MASK;
    } else if (r->Op2 == 0) {
      if (pmu_access_cycle_counter_el0_disabled(vcpu)) return false;
      idx = ARMV8_PMU_CYCLE_IDX;
    } else {
      BUG();
    }
  } else if (r->CRn == 14 && (r->CRm & 12) == 8) {
    if (pmu_access_event_counter_el0_disabled(vcpu)) return false;
    idx = ((r->CRm & 3) << 3) | (r->Op2 & 7);
  } else {
    BUG();
  }
  if (!pmu_counter_idx_valid(vcpu, idx)) return false;
  if (p->is_write) {
    if (pmu_access_el0_disabled(vcpu)) return false;
    kvm_pmu_set_counter_value(vcpu, idx, p->regval);
  } else {
    p->regval = kvm_pmu_get_counter_value(vcpu, idx);
  }
  return true;
}

static void bfq_idle_slice_timer_body(struct bfq_queue* bfqq) {
  struct bfq_data* bfqd = bfqq->bfqd;
  enum bfqq_expiration reason;
  unsigned long flags;
  spin_lock_irqsave(&bfqd->lock, flags);
  bfq_clear_bfqq_wait_request(bfqq);
  if (bfqq != bfqd->in_service_queue) {
    spin_unlock_irqrestore(&bfqd->lock, flags);
    return;
  }
  if (bfq_bfqq_budget_timeout(bfqq))
    reason = BFQQE_BUDGET_TIMEOUT;
  else if (bfqq->queued[0] == 0 && bfqq->queued[1] == 0)
    reason = BFQQE_TOO_IDLE;
  else
    goto schedule_dispatch;
  bfq_bfqq_expire(bfqd, bfqq, true, reason);
schedule_dispatch:
  spin_unlock_irqrestore(&bfqd->lock, flags);
  bfq_schedule_dispatch(bfqd);

int main(int argc, char** argv) {
  test_cmp_parameters inParam;
  FILE *fbase = NULL, *ftest = NULL;
  int same = 0;
  char lbase[256];
  char strbase[256];
  char ltest[256];
  char strtest[256];
  if (parse_cmdline_cmp(argc, argv, &inParam) == 1) {
    compare_dump_files_help_display();
    goto cleanup;
  }
  printf("******Parameters********* \n");
  printf(
      " base_filename = %s\n"
      " test_filename = %s\n",
      inParam.base_filename, inParam.test_filename);
  printf("************************* \n");
  printf("Try to open: %s for reading ... ", inParam.base_filename);
  if ((fbase = fopen(inParam.base_filename, "rb")) == NULL) {
    goto cleanup;
  }
  printf("Ok.\n");
  printf("Try to open: %s for reading ... ", inParam.test_filename);
  if ((ftest = fopen(inParam.test_filename, "rb")) == NULL) {
    goto cleanup;
  }
  printf("Ok.\n");
  while (fgets(lbase, sizeof(lbase), fbase) &&
         fgets(ltest, sizeof(ltest), ftest)) {
    int nbase = sscanf(lbase, "%255[^\r\n]", strbase);
    int ntest = sscanf(ltest, "%255[^\r\n]", strtest);
    assert(nbase != 255 && ntest != 255);
    if (nbase != 1 || ntest != 1) {
      fprintf(stderr, "could not parse line from files\n");
