id3_skip(SF_PRIVATE* psf) {
  unsigned char buf[10];
  memset(buf, 0, sizeof(buf));
  psf_binheader_readf(psf, "pb", 0, buf, 10);
  if (buf[0] == 'I' && buf[1] == 'D' && buf[2] == '3') {
    int offset = buf[6] & 0x7f;
    offset = (offset << 7) | (buf[7] & 0x7f);
    offset = (offset << 7) | (buf[8] & 0x7f);
    offset = (offset << 7) | (buf[9] & 0x7f);
    psf_log_printf(psf, "ID3 length : %d\n--------------------\n", offset);
    if (offset < 0) return 0;
    psf->fileoffset += offset + 10;
    psf_binheader_readf(psf, "p", psf->fileoffset);
    return 1;
  };
  return 0;
}

static int bson_append_estart(bson* b, int type, const char* name,
                              const int dataSize) {
  const int len = strlen(name) + 1;
  if (b->finished) {
    b->err |= BSON_ALREADY_FINISHED;
    return BSON_ERROR;
  }
  if (bson_ensure_space(b, 1 + len + dataSize) == BSON_ERROR) {
    return BSON_ERROR;
  }
  if (bson_check_field_name(b, (const char*)name, len - 1) == BSON_ERROR) {
    bson_builder_error(b);
    return BSON_ERROR;
  }
  bson_append_byte(b, (char)type);
  bson_append(b, name, len);
  return BSON_OK;
}

static void sgi_timer_get(struct k_itimer* timr,
                          struct itimerspec* cur_setting) {
  if (timr->it.mmtimer.clock == TIMER_OFF) {
    cur_setting->it_interval.tv_nsec = 0;
    cur_setting->it_interval.tv_sec = 0;
    cur_setting->it_value.tv_nsec = 0;
    cur_setting->it_value.tv_sec = 0;
    return;
  }
  ns_to_timespec(cur_setting->it_interval,
                 timr->it.mmtimer.incr * sgi_clock_period);
  ns_to_timespec(cur_setting->it_value,
                 (timr->it.mmtimer.expires - rtc_time()) * sgi_clock_period);
  return;
}

void ComparisonQuantized(const TfLiteTensor* input1, const TfLiteTensor* input2,
                         TfLiteTensor* output, bool requires_broadcast) {
  if (input1->type == kTfLiteUInt8 || input1->type == kTfLiteInt8) {
    auto input1_offset = -input1->params.zero_point;
    auto input2_offset = -input2->params.zero_point;
    const int left_shift = 8;
    int32 input1_multiplier;
    int input1_shift;
    QuantizeMultiplierSmallerThanOneExp(input1->params.scale,
                                        &input1_multiplier, &input1_shift);
    int32 input2_multiplier;
    int input2_shift;
    QuantizeMultiplierSmallerThanOneExp(input2->params.scale,
                                        &input2_multiplier, &input2_shift);
    ComparisonParams op_params;
    op_params.left_shift = left_shift;
    op_params.input1_offset = input1_offset;
    op_params.input1_multiplier = input1_multiplier;
    op_params.input1_shift = input1_shift;
    op_params.input2_offset = input2_offset;
    op_params.input2_multiplier = input2_multiplier;
    op_params.input2_shift = input2_shift;
    if (requires_broadcast) {
      reference_ops::BroadcastComparison4DSlowWithScaling<input_dtype, opname>(
          op_params, GetTensorShape(input1), GetTensorData<input_dtype>(input1),
          GetTensorShape(input2), GetTensorData<input_dtype>(input2),
          GetTensorShape(output), GetTensorData<bool>(output));
    } else {
      reference_ops::ComparisonWithScaling<input_dtype, opname>(
          op_params, GetTensorShape(input1), GetTensorData<input_dtype>(input1),
          GetTensorShape(input2), GetTensorData<input_dtype>(input2),
          GetTensorShape(output), GetTensorData<bool>(output));
    }
  }
}

static enum led_brightness k90_backlight_get(struct led_classdev* led_cdev) {
  int ret;
  struct k90_led* led = container_of(led_cdev, struct k90_led, cdev);
  struct device* dev = led->cdev.dev->parent;
  struct usb_interface* usbif = to_usb_interface(dev->parent);
  struct usb_device* usbdev = interface_to_usbdev(usbif);
  int brightness;
  char data[8];
  ret = usb_control_msg(usbdev, usb_rcvctrlpipe(usbdev, 0), K90_REQUEST_STATUS,
                        USB_DIR_IN | USB_TYPE_VENDOR | USB_RECIP_DEVICE, 0, 0,
                        data, 8, USB_CTRL_SET_TIMEOUT);
  if (ret < 0) {
    dev_warn(dev, "Failed to get K90 initial state (error %d).\n", ret);
    return -EIO;
  }
  brightness = data[4];
  if (brightness < 0 || brightness > 3) {
    dev_warn(dev, "Read invalid backlight brightness: %02hhx.\n", data[4]);
    return -EIO;
  }
  return brightness;
}

static inline int r_sys_mkdirp(char* dir) {
  int ret = 1;
  const char slash = DIRSEP;
  char* path = dir;
  char* ptr = path;
  if (*ptr == slash) {
    ptr++;
  }
#if __SDB_WINDOWS__
  char* p = strstr(ptr, ":\\");
  if (p) {
    ptr = p + 2;
  }
#endif
  while ((ptr = strchr(ptr, slash))) {
    *ptr = 0;
    if (!r_sys_mkdir(path) && r_sys_mkdir_failed()) {
      eprintf("r_sys_mkdirp: fail '%s' of '%s'\n", path, dir);
      *ptr = slash;
      return 0;
    }
    *ptr = slash;
    ptr++;
  }
  return ret;
}

bool DSClientEvent::event() {
  bool restart = false;
  ParticipantProxyData* part_proxy_data;
  eprosima::shared_lock<eprosima::shared_mutex> lock(
      mp_PDP->mp_builtin->getDiscoveryMutex());
  for (auto server : mp_PDP->remote_server_attributes()) {
    std::unique_lock<std::recursive_mutex> pdp_lock(*mp_PDP->getMutex());
    part_proxy_data = mp_PDP->get_participant_proxy_data(server.guidPrefix);
    if (nullptr != part_proxy_data) {
      if (!mp_EDP->areRemoteEndpointsMatched(part_proxy_data)) {
        mp_EDP->assignRemoteEndpoints(*(part_proxy_data));
      }
    } else {
      restart = true;
    }
  }
  if (restart) {
    mp_PDP->_serverPing = true;
    mp_PDP->announceParticipantState(false);
    EPROSIMA_LOG_INFO(CLIENT_PDP_THREAD,
                      "Client " << mp_PDP->getRTPSParticipant()->getGuid()
                                << " PDP announcement");
  }
  return restart;
}

IOBasicTypes::LongBufferSizeType ObjectByteWriterWithPosition::Write(
    const IOBasicTypes::Byte* inBuffer,
    IOBasicTypes::LongBufferSizeType inBufferSize) {
  CREATE_ISOLATE_CONTEXT;
  CREATE_ESCAPABLE_SCOPE;
  Local<Object> anArray = NEW_ARRAY((int)inBufferSize);
  for (int i = 0; i < (int)inBufferSize; ++i)
    anArray->Set(GET_CURRENT_CONTEXT, NEW_NUMBER(i), NEW_NUMBER(inBuffer[i]));
  Local<Value> value = OBJECT_FROM_PERSISTENT(mObject)
                           ->Get(GET_CURRENT_CONTEXT, NEW_STRING("write"))
                           .ToLocalChecked();
  if (value->IsUndefined() || !value->IsFunction()) {
    THROW_EXCEPTION("write is not a function, it should be you know...");
    return 0;
  }
  Local<Function> func = Local<Function>::Cast(value);
  Local<Value> args[1];
  args[0] = anArray;
  Local<Value> result =
      func->Call(GET_CURRENT_CONTEXT, OBJECT_FROM_PERSISTENT(mObject), 1, args)
          .ToLocalChecked();
  if (result.IsEmpty()) {
    THROW_EXCEPTION(
        "wrong return value. it's empty. return the number of written "
        "characters");
    return 0;
  } else if (result->IsNumber()) {
    return TO_UINT32(result)->Value();
  } else {
    THROW_EXCEPTION(
        "wrong return value. write should return the number of written "
        "characters");
    return 0;
  }
}

