PHPAPI zend_string* php_escape_shell_arg(char* str) {
  int x, y = 0, l = (int)strlen(str);
  zend_string* cmd;
  size_t estimate = (4 * l) + 3;
  cmd = zend_string_alloc(4 * l + 2, 0);
#ifdef PHP_WIN32
  ZSTR_VAL(cmd)[y++] = '"';
#else
  ZSTR_VAL(cmd)[y++] = '\'';
#endif
  for (x = 0; x < l; x++) {
    int mb_len = php_mblen(str + x, (l - x));
    if (mb_len < 0) {
      continue;
    } else if (mb_len > 1) {
      memcpy(ZSTR_VAL(cmd) + y, str + x, mb_len);
      y += mb_len;
      x += mb_len - 1;
      continue;
    }
    switch (str[x]) {
#ifdef PHP_WIN32
      case '"':
      case '%':
      case '!':
        ZSTR_VAL(cmd)[y++] = ' ';
        break;
#else
      case '\'':
        ZSTR_VAL(cmd)[y++] = '\'';
        ZSTR_VAL(cmd)[y++] = '\\';
        ZSTR_VAL(cmd)[y++] = '\'';
#endif
      default:
        ZSTR_VAL(cmd)[y++] = str[x];
    }
  }
#ifdef PHP_WIN32
  if (y > 0 && '\\' == ZSTR_VAL(cmd)[y - 1]) {
    int k = 0, n = y - 1;
    for (; n >= 0 && '\\' == ZSTR_VAL(cmd)[n]; n--, k++);
    if (k % 2) {
      ZSTR_VAL(cmd)[y++] = '\\';
    }
  }
  ZSTR_VAL(cmd)[y++] = '"';
#else
  ZSTR_VAL(cmd)[y++] = '\'';
#endif
  ZSTR_VAL(cmd)[y] = '\0';
  if ((estimate - y) > 4096) {
    cmd = zend_string_truncate(cmd, y, 0);
  }
  ZSTR_LEN(cmd) = y;
  return cmd;
}

static int sof_set_get_large_ctrl_data(struct snd_sof_dev* sdev,
                                       struct sof_ipc_ctrl_data* cdata,
                                       struct sof_ipc_ctrl_data_params* sparams,
                                       bool send) {
  struct sof_ipc_ctrl_data* partdata;
  size_t send_bytes;
  size_t offset = 0;
  size_t msg_bytes;
  size_t pl_size;
  int err;
  int i;
  partdata = kzalloc(SOF_IPC_MSG_MAX_SIZE, GFP_KERNEL);
  if (!partdata) return -ENOMEM;
  if (send)
    err = sof_get_ctrl_copy_params(cdata->type, cdata, partdata, sparams);
  else
    err = sof_get_ctrl_copy_params(cdata->type, partdata, cdata, sparams);
  if (err < 0) return err;
  msg_bytes = sparams->msg_bytes;
  pl_size = sparams->pl_size;
  memcpy(partdata, cdata, sparams->hdr_bytes);
  mutex_lock(&sdev->ipc->tx_mutex);
  for (i = 0; i < sparams->num_msg; i++) {
    send_bytes = min(msg_bytes, pl_size);
    partdata->num_elems = send_bytes;
    partdata->rhdr.hdr.size = sparams->hdr_bytes + send_bytes;
    partdata->msg_index = i;
    msg_bytes -= send_bytes;
    partdata->elems_remaining = msg_bytes;
    if (send) memcpy(sparams->dst, sparams->src + offset, send_bytes);
    err = sof_ipc_tx_message_unlocked(sdev->ipc, partdata->rhdr.hdr.cmd,
                                      partdata, partdata->rhdr.hdr.size,
                                      partdata, partdata->rhdr.hdr.size);
    if (err < 0) break;
    if (!send) memcpy(sparams->dst + offset, sparams->src, send_bytes);
    offset += pl_size;
  }
  mutex_unlock(&sdev->ipc->tx_mutex);
  kfree(partdata);
  return err;
}

static int get_gate_page(struct mm_struct* mm, unsigned long address,
                         unsigned int gup_flags, struct vm_area_struct** vma,
                         struct page** page) {
  pgd_t* pgd;
  p4d_t* p4d;
  pud_t* pud;
  pmd_t* pmd;
  pte_t* pte;
  int ret = -EFAULT;
  if (gup_flags & FOLL_WRITE) return -EFAULT;
  if (address > TASK_SIZE)
    pgd = pgd_offset_k(address);
  else
    pgd = pgd_offset_gate(mm, address);
  BUG_ON(pgd_none(*pgd));
  p4d = p4d_offset(pgd, address);
  BUG_ON(p4d_none(*p4d));
  pud = pud_offset(p4d, address);
  BUG_ON(pud_none(*pud));
  pmd = pmd_offset(pud, address);
  if (!pmd_present(*pmd)) return -EFAULT;
  VM_BUG_ON(pmd_trans_huge(*pmd));
  pte = pte_offset_map(pmd, address);
  if (pte_none(*pte)) goto unmap;
  *vma = get_gate_vma(mm);
  if (!page) goto out;
  *page = vm_normal_page(*vma, address, *pte);
  if (!*page) {
    if ((gup_flags & FOLL_DUMP) || !is_zero_pfn(pte_pfn(*pte))) goto unmap;
    *page = pte_page(*pte);
    if (is_device_public_page(*page)) goto unmap;
  }
  get_page(*page);
out:
  ret = 0;
unmap:
  pte_unmap(pte);
  return ret;
}

equal_h(const struct ecc_modulo* p, const mp_limb_t* x1, const mp_limb_t* z1,
        const mp_limb_t* x2, const mp_limb_t* z2, mp_limb_t* scratch) {
#define t0 scratch
#define t1 (scratch + p->size)
  ecc_mod_mul(p, t0, x1, z2, t0);
  if (mpn_cmp(t0, p->m, p->size) >= 0) mpn_sub_n(t0, t0, p->m, p->size);
  ecc_mod_mul(p, t1, x2, z1, t1);
  if (mpn_cmp(t1, p->m, p->size) >= 0) mpn_sub_n(t1, t1, p->m, p->size);
  return mpn_cmp(t0, t1, p->size) == 0;
#undef t0
#undef t1
}

cstrchr(char_u* s, int c) {
  char_u* p;
  int cc;
  if (!rex.reg_ic || (!enc_utf8 && mb_char2len(c) > 1)) return vim_strchr(s, c);
  if (enc_utf8 && c > 0x80)
    cc = utf_fold(c);
  else if (MB_ISUPPER(c))
    cc = MB_TOLOWER(c);
  else if (MB_ISLOWER(c))
    cc = MB_TOUPPER(c);
  else
    return vim_strchr(s, c);
  if (has_mbyte) {
    for (p = s; *p != NUL; p += (*mb_ptr2len)(p)) {
      if (enc_utf8 && c > 0x80) {
        if (utf_fold(utf_ptr2char(p)) == cc) return p;
      } else if (*p == c || *p == cc)
        return p;
    }
  } else
    for (p = s; *p != NUL; ++p)
      if (*p == c || *p == cc) return p;
  return NULL;
}

