static MagickBooleanType IsWEBPImageLossless(const unsigned char* stream,
                                             const size_t length) {
#define VP8_CHUNK_INDEX 15
#define LOSSLESS_FLAG 'L'
#define EXTENDED_HEADER 'X'
#define VP8_CHUNK_HEADER "VP8"
#define VP8_CHUNK_HEADER_SIZE 3
#define RIFF_HEADER_SIZE 12
#define VP8X_CHUNK_SIZE 10
#define TAG_SIZE 4
#define CHUNK_SIZE_BYTES 4
#define CHUNK_HEADER_SIZE 8
#define MAX_CHUNK_PAYLOAD (~0U - CHUNK_HEADER_SIZE - 1)
  ssize_t offset;
  if (stream[VP8_CHUNK_INDEX] != EXTENDED_HEADER)
    return (stream[VP8_CHUNK_INDEX] == LOSSLESS_FLAG ? MagickTrue
                                                     : MagickFalse);
  offset = RIFF_HEADER_SIZE + TAG_SIZE + CHUNK_SIZE_BYTES + VP8X_CHUNK_SIZE;
  while (offset <= (ssize_t)(length - TAG_SIZE)) {
    uint32_t chunk_size, chunk_size_pad;
    chunk_size = ReadWebPLSBWord(stream + offset + TAG_SIZE);
    if (chunk_size > MAX_CHUNK_PAYLOAD) break;
    chunk_size_pad = (CHUNK_HEADER_SIZE + chunk_size + 1) & ~1;
    if (memcmp(stream + offset, VP8_CHUNK_HEADER, VP8_CHUNK_HEADER_SIZE) == 0)
      return (*(stream + offset + VP8_CHUNK_HEADER_SIZE) == LOSSLESS_FLAG
                  ? MagickTrue
                  : MagickFalse);
    offset += chunk_size_pad;
  }
  return (MagickFalse);
}

int fscrypt_get_encryption_info(struct inode* inode) {
  struct fscrypt_info* ci = inode->i_crypt_info;
  if (!ci || (ci->ci_keyring_key &&
              (ci->ci_keyring_key->flags &
               ((1 << KEY_FLAG_INVALIDATED) | (1 << KEY_FLAG_REVOKED) |
                (1 << KEY_FLAG_DEAD)))))
    return fscrypt_get_crypt_info(inode);
  return 0;
}

public
char* shell_quoten(constant char* s, size_t slen) {
  constant char* p;
  char* np;
  char* newstr;
  size_t len;
  constant char* esc = get_meta_escape();
  size_t esclen = strlen(esc);
  lbool use_quotes = FALSE;
  lbool have_quotes = FALSE;
  len = 1;
  for (p = s; p < s + slen; p++) {
    len++;
    if (*p == openquote || *p == closequote) have_quotes = TRUE;
    if (metachar(*p)) {
      if (esclen == 0) {
        use_quotes = TRUE;
      } else {
        len += esclen;
      }
    }
  }
  if (use_quotes) {
    if (have_quotes) return (NULL);
    len = slen + 3;
  }
  newstr = np = (char*)ecalloc(len, sizeof(char));
  if (use_quotes) {
    SNPRINTF4(newstr, len, "%c%.*s%c", openquote, (int)slen, s, closequote);
  } else {
    constant char* es = s + slen;
    while (s < es) {
      if (metachar(*s)) {
        strcpy(np, esc);
        np += esclen;
      }
      *np++ = *s++;
    }
    *np = '\0';
  }
  return (newstr);
}

void recalc_intercepts(struct vcpu_svm* svm) {
  struct vmcb_control_area *c, *h, *g;
  unsigned int i;
  vmcb_mark_dirty(svm->vmcb, VMCB_INTERCEPTS);
  if (!is_guest_mode(&svm->vcpu)) return;
  c = &svm->vmcb->control;
  h = &svm->vmcb01.ptr->control;
  g = &svm->nested.ctl;
  for (i = 0; i < MAX_INTERCEPT; i++) c->intercepts[i] = h->intercepts[i];
  if (g->int_ctl & V_INTR_MASKING_MASK) {
    vmcb_clr_intercept(c, INTERCEPT_CR8_READ);
    vmcb_clr_intercept(c, INTERCEPT_CR8_WRITE);
    vmcb_clr_intercept(c, INTERCEPT_VINTR);
  }
  vmcb_clr_intercept(c, INTERCEPT_VMMCALL);
  for (i = 0; i < MAX_INTERCEPT; i++) c->intercepts[i] |= g->intercepts[i];
  if (!intercept_smi) vmcb_clr_intercept(c, INTERCEPT_SMI);
}

fname_match(regmatch_T* rmp, char_u* name, int ignore_case) {
