int av_hwframe_ctx_init(AVBufferRef* ref) {
  AVHWFramesContext* ctx = (AVHWFramesContext*)ref->data;
  const enum AVPixelFormat* pix_fmt;
  int ret;
  if (ctx->internal->source_frames) {
    return 0;
  }
  for (pix_fmt = ctx->internal->hw_type->pix_fmts; *pix_fmt != AV_PIX_FMT_NONE;
       pix_fmt++) {
    if (*pix_fmt == ctx->format) break;
  }
  if (*pix_fmt == AV_PIX_FMT_NONE) {
    av_log(ctx, AV_LOG_ERROR,
           "The hardware pixel format '%s' is not supported by the device type "
           "'%s'\n",
           av_get_pix_fmt_name(ctx->format), ctx->internal->hw_type->name);
    return AVERROR(ENOSYS);
  }
  ret = av_image_check_size(ctx->width, ctx->height, 0, ctx);
  if (ret < 0) return ret;
  if (ctx->internal->hw_type->frames_init) {
    ret = ctx->internal->hw_type->frames_init(ctx);
    if (ret < 0) goto fail;
  }
  if (ctx->internal->pool_internal && !ctx->pool)
    ctx->pool = ctx->internal->pool_internal;
  if (ctx->initial_pool_size > 0) {
    ret = hwframe_pool_prealloc(ref);
    if (ret < 0) goto fail;
  }
  return 0;
fail:
  if (ctx->internal->hw_type->frames_uninit)
    ctx->internal->hw_type->frames_uninit(ctx);
  return ret;
}

archive_string_append_from_wcs(struct archive_string* as, const wchar_t* w,
                               size_t len) {
  int n, ret_val = 0;
  char* p;
  char* end;
#if HAVE_WCRTOMB
  mbstate_t shift_state;
  memset(&shift_state, 0, sizeof(shift_state));
#else
  wctomb(NULL, L'\0');
#endif
  if (archive_string_ensure(as, as->length + len + 1) == NULL) return (-1);
  p = as->s + as->length;
  end = as->s + as->buffer_length - MB_CUR_MAX - 1;
  while (*w != L'\0' && len > 0) {
    if (p >= end) {
      as->length = p - as->s;
      as->s[as->length] = '\0';
      if (archive_string_ensure(as, as->length + len * 2 + 1) == NULL)
        return (-1);
      p = as->s + as->length;
      end = as->s + as->buffer_length - MB_CUR_MAX - 1;
    }
#if HAVE_WCRTOMB
    n = wcrtomb(p, *w++, &shift_state);
#else
    n = wctomb(p, *w++);
#endif
    if (n == -1) {
      if (errno == EILSEQ) {
        *p++ = '?';
        ret_val = -1;
      } else {
        ret_val = -1;
        break;
      }
    } else
      p += n;
    len--;
  }
  as->length = p - as->s;
  as->s[as->length] = '\0';
  return (ret_val);
}

static __u8* pl_report_fixup(struct hid_device* hdev, __u8* rdesc,
                             unsigned int* rsize) {
  if (*rsize >= 60 && rdesc[39] == 0x2a && rdesc[40] == 0xf5 &&
      rdesc[41] == 0x00 && rdesc[59] == 0x26 && rdesc[60] == 0xf9 &&
      rdesc[61] == 0x00) {
    hid_info(hdev, "fixing up Petalynx Maxter Remote report descriptor\n");
    rdesc[60] = 0xfa;
    rdesc[40] = 0xfa;
  }
  return rdesc;
}

_clone_pdu_header(netsnmp_pdu* pdu) {
  netsnmp_pdu* newpdu;
  struct snmp_secmod_def* sptr;
  int ret;
  if (!pdu) return NULL;
  newpdu = (netsnmp_pdu*)malloc(sizeof(netsnmp_pdu));
  if (!newpdu) return NULL;
  memmove(newpdu, pdu, sizeof(netsnmp_pdu));
  newpdu->variables = NULL;
  newpdu->enterprise = NULL;
  newpdu->community = NULL;
  newpdu->securityEngineID = NULL;
  newpdu->securityName = NULL;
  newpdu->contextEngineID = NULL;
  newpdu->contextName = NULL;
  newpdu->transport_data = NULL;
  if (snmp_clone_mem((void**)&newpdu->enterprise, pdu->enterprise,
                     sizeof(oid) * pdu->enterprise_length) ||
      snmp_clone_mem((void**)&newpdu->community, pdu->community,
                     pdu->community_len) ||
      snmp_clone_mem((void**)&newpdu->contextEngineID, pdu->contextEngineID,
                     pdu->contextEngineIDLen) ||
      snmp_clone_mem((void**)&newpdu->securityEngineID, pdu->securityEngineID,
                     pdu->securityEngineIDLen) ||
      snmp_clone_mem((void**)&newpdu->contextName, pdu->contextName,
                     pdu->contextNameLen) ||
      snmp_clone_mem((void**)&newpdu->securityName, pdu->securityName,
                     pdu->securityNameLen) ||
      snmp_clone_mem((void**)&newpdu->transport_data, pdu->transport_data,
                     pdu->transport_data_length)) {
    snmp_free_pdu(newpdu);
    return NULL;
  }
  if (pdu->securityStateRef && pdu->command == SNMP_MSG_TRAP2) {
    netsnmp_assert(pdu->securityModel == SNMP_DEFAULT_SECMODEL);
    ret = usm_clone_usmStateReference(
        (struct usmStateReference*)pdu->securityStateRef,
        (struct usmStateReference**)&newpdu->securityStateRef);
    if (ret) {
      snmp_free_pdu(newpdu);
      return NULL;
    }
  }
  if ((sptr = find_sec_mod(newpdu->securityModel)) != NULL &&
      sptr->pdu_clone != NULL) {
    (*sptr->pdu_clone)(pdu, newpdu);
  }
  return newpdu;
}

int socket_accept(int fd, uint16_t port) {
#ifdef WIN32
  int addr_len;
#else
  socklen_t addr_len;
#endif
  int result;
  struct sockaddr_in addr;
  memset(&addr, 0, sizeof(addr));
  addr.sin_family = AF_INET;
  addr.sin_addr.s_addr = htonl(INADDR_ANY);
  addr.sin_port = htons(port);
  addr_len = sizeof(addr);
  result = accept(fd, (struct sockaddr*)&addr, &addr_len);
  return result;
}

flush_signal_handlers(struct task_struct* t, int force_default) {
  int i;
  struct k_sigaction* ka = &t->sighand->action[0];
  for (i = _NSIG; i != 0; i--) {
    if (force_default || ka->sa.sa_handler != SIG_IGN)
      ka->sa.sa_handler = SIG_DFL;
    ka->sa.sa_flags = 0;
    sigemptyset(&ka->sa.sa_mask);
    ka++;
  }
}

static int checkout_verify_paths(git_repository* repo, int action,
                                 git_diff_delta* delta) {
  unsigned int flags = GIT_PATH_REJECT_WORKDIR_DEFAULTS;
  if (action & CHECKOUT_ACTION__REMOVE) {
    if (!git_path_isvalid(repo, delta->old_file.path, delta->old_file.mode,
                          flags)) {
      git_error_set(GIT_ERROR_CHECKOUT, "cannot remove invalid path '%s'",
                    delta->old_file.path);
      return -1;
    }
  }
  if (action & ~CHECKOUT_ACTION__REMOVE) {
    if (!git_path_isvalid(repo, delta->new_file.path, delta->new_file.mode,
                          flags)) {
      git_error_set(GIT_ERROR_CHECKOUT, "cannot checkout to invalid path '%s'",
                    delta->new_file.path);
      return -1;
    }
  }
  return 0;
}

bool AffiliationFetcher::ParseResponse(
    AffiliationFetcherDelegate::Result* result) const {
  std::string serialized_response;
  if (!fetcher_->GetResponseAsString(&serialized_response)) {
    NOTREACHED();
  }
  affiliation_pb::LookupAffiliationResponse response;
  if (!response.ParseFromString(serialized_response)) return false;
  result->reserve(requested_facet_uris_.size());
  std::map<FacetURI, size_t> facet_uri_to_class_index;
  for (int i = 0; i < response.affiliation_size(); ++i) {
    const affiliation_pb::Affiliation& equivalence_class(
        response.affiliation(i));
    AffiliatedFacets affiliated_uris;
    for (int j = 0; j < equivalence_class.facet_size(); ++j) {
      const std::string& uri_spec(equivalence_class.facet(j));
      FacetURI uri = FacetURI::FromPotentiallyInvalidSpec(uri_spec);
      if (!uri.is_valid()) continue;
      affiliated_uris.push_back(uri);
    }
    if (affiliated_uris.empty()) continue;
    for (const FacetURI& uri : affiliated_uris) {
      if (!facet_uri_to_class_index.count(uri))
        facet_uri_to_class_index[uri] = result->size();
      if (facet_uri_to_class_index[uri] !=
          facet_uri_to_class_index[affiliated_uris[0]]) {
        return false;
      }
    }
    if (facet_uri_to_class_index[affiliated_uris[0]] == result->size())
      result->push_back(affiliated_uris);
  }
  for (const FacetURI& uri : requested_facet_uris_) {
    if (!facet_uri_to_class_index.count(uri))
      result->push_back(AffiliatedFacets(1, uri));
  }
  return true;
}

