rpl_dao_print(netdissect_options* ndo, const u_char* bp, u_int length) {
  const struct nd_rpl_dao* dao = (const struct nd_rpl_dao*)bp;
  const char* dagid_str = "<elided>";
  ND_TCHECK(*dao);
  if (length < ND_RPL_DAO_MIN_LEN) goto tooshort;
  bp += ND_RPL_DAO_MIN_LEN;
  length -= ND_RPL_DAO_MIN_LEN;
  if (RPL_DAO_D(dao->rpl_flags)) {
    ND_TCHECK2(dao->rpl_dagid, DAGID_LEN);
    if (length < DAGID_LEN) goto tooshort;
    dagid_str = ip6addr_string(ndo, dao->rpl_dagid);
    bp += DAGID_LEN;
    length -= DAGID_LEN;
  }
  ND_PRINT((ndo, " [dagid:%s,seq:%u,instance:%u%s%s,%02x]", dagid_str,
            dao->rpl_daoseq, dao->rpl_instanceid,
            RPL_DAO_K(dao->rpl_flags) ? ",acK" : "",
            RPL_DAO_D(dao->rpl_flags) ? ",Dagid" : "", dao->rpl_flags));
  if (ndo->ndo_vflag > 1) {
    const struct rpl_dio_genoption* opt = (const struct rpl_dio_genoption*)bp;
    rpl_dio_printopt(ndo, opt, length);
  }
  return;
trunc:
  ND_PRINT((ndo, " [|truncated]"));
  return;
tooshort:
  ND_PRINT((ndo, " [|length too short]"));
  return;
}

mem_log_init(const char* prog_name, const char* banner) {
  size_t log_name_len;
  char* log_name;
  if (__test_bit(LOG_CONSOLE_BIT, &debug)) {
    log_op = stderr;
    return;
  }
  if (log_op) fclose(log_op);
  log_name_len = 5 + strlen(prog_name) + 5 + 7 + 4 + 1;
  log_name = malloc(log_name_len);
  if (!log_name) {
    log_message(LOG_INFO, "Unable to malloc log file name");
    log_op = stderr;
    return;
  }
  snprintf(log_name, log_name_len, "/tmp/%s_mem.%d.log", prog_name, getpid());
  log_op = fopen(log_name, "a");
  if (log_op == NULL) {
    log_message(LOG_INFO, "Unable to open %s for appending", log_name);
    log_op = stderr;
  } else {
    int fd = fileno(log_op);
    fcntl(fd, F_SETFD, fcntl(fd, F_GETFD) | FD_CLOEXEC);
    setlinebuf(log_op);
    fprintf(log_op, "\n");
  }
  free(log_name);
  terminate_banner = banner;
}

void ip_options_build(struct sk_buff* skb, struct ip_options* opt, __be32 daddr,
                      struct rtable* rt, int is_frag) {
  unsigned char* iph = skb_network_header(skb);
  memcpy(&(IPCB(skb)->opt), opt, sizeof(struct ip_options));
  memcpy(iph + sizeof(struct iphdr), opt->__data, opt->optlen);
  opt = &(IPCB(skb)->opt);
  if (opt->srr) memcpy(iph + opt->srr + iph[opt->srr + 1] - 4, &daddr, 4);
  if (!is_frag) {
    if (opt->rr_needaddr)
      ip_rt_get_source(iph + opt->rr + iph[opt->rr + 2] - 5, rt);
    if (opt->ts_needaddr)
      ip_rt_get_source(iph + opt->ts + iph[opt->ts + 2] - 9, rt);
    if (opt->ts_needtime) {
      struct timespec tv;
      __be32 midtime;
      getnstimeofday(&tv);
      midtime = htonl((tv.tv_sec % 86400) * MSEC_PER_SEC +
                      tv.tv_nsec / NSEC_PER_MSEC);
      memcpy(iph + opt->ts + iph[opt->ts + 2] - 5, &midtime, 4);
    }
    return;
  }
  if (opt->rr) {
    memset(iph + opt->rr, IPOPT_NOP, iph[opt->rr + 1]);
    opt->rr = 0;
    opt->rr_needaddr = 0;
  }
  if (opt->ts) {
    memset(iph + opt->ts, IPOPT_NOP, iph[opt->ts + 1]);
    opt->ts = 0;
    opt->ts_needaddr = opt->ts_needtime = 0;
  }
}

bool CWallet::CommitTransaction(CWalletTx& wtxNew, CReserveKey& reservekey) {
  {
    LOCK2(cs_main, cs_wallet);
    printf("CommitTransaction:\n%s", wtxNew.ToString().c_str());
    {
      CWalletDB* pwalletdb =
          fFileBacked ? new CWalletDB(strWalletFile, "r") : NULL;
      reservekey.KeepKey();
      AddToWallet(wtxNew);
      set<CWalletTx*> setCoins;
      BOOST_FOREACH (const CTxIn& txin, wtxNew.vin) {
        CWalletTx& coin = mapWallet[txin.prevout.hash];
        coin.BindWallet(this);
        coin.MarkSpent(txin.prevout.n);
        coin.WriteToDisk();
        NotifyTransactionChanged(this, coin.GetHash(), CT_UPDATED);
      }
      if (fFileBacked) delete pwalletdb;
    }
    mapRequestCount[wtxNew.GetHash()] = 0;
    if (!wtxNew.AcceptToMemoryPool()) {
      printf("CommitTransaction() : Error: Transaction not valid");
      return false;
    }
    wtxNew.RelayWalletTransaction();
  }
  return true;
}

