eval_lambda(char_u** arg, typval_T* rettv, evalarg_T* evalarg, int verbose) {
  int evaluate = evalarg != NULL && (evalarg->eval_flags & EVAL_EVALUATE);
  typval_T base = *rettv;
  int ret;
  rettv->v_type = VAR_UNKNOWN;
  if (**arg == '{') {
    ret = get_lambda_tv(arg, rettv, FALSE, evalarg);
  } else {
    ++*arg;
    ret = eval1(arg, rettv, evalarg);
    *arg = skipwhite_and_linebreak(*arg, evalarg);
    if (**arg != ')') {
      emsg(_(e_missing_closing_paren));
      ret = FAIL;
    }
    ++*arg;
  }
  if (ret != OK)
    return FAIL;
  else if (**arg != '(') {
    if (verbose) {
      if (*skipwhite(*arg) == '(')
        emsg(_(e_nowhitespace));
      else
        semsg(_(e_missing_parenthesis_str), "lambda");
    }
    clear_tv(rettv);
    ret = FAIL;
  } else
    ret = call_func_rettv(arg, evalarg, rettv, evaluate, NULL, &base);
  if (evaluate) clear_tv(&base);
  return ret;
}

static int hash_accept(struct socket* sock, struct socket* newsock, int flags) {
  struct sock* sk = sock->sk;
  struct alg_sock* ask = alg_sk(sk);
  struct hash_ctx* ctx = ask->private;
  struct ahash_request* req = &ctx->req;
  char state[crypto_ahash_statesize(crypto_ahash_reqtfm(req))];
  struct sock* sk2;
  struct alg_sock* ask2;
  struct hash_ctx* ctx2;
  int err;
  err = crypto_ahash_export(req, state);
  if (err) return err;
  err = af_alg_accept(ask->parent, newsock);
  if (err) return err;
  sk2 = newsock->sk;
  ask2 = alg_sk(sk2);
  ctx2 = ask2->private;
  ctx2->more = 1;
  err = crypto_ahash_import(&ctx2->req, state);
  if (err) {
    sock_orphan(sk2);
    sock_put(sk2);
  }
  return err;
}

static inline void kvm_memslot_delete(struct kvm_memslots* slots,
                                      struct kvm_memory_slot* memslot) {
  struct kvm_memory_slot* mslots = slots->memslots;
  int i;
  if (WARN_ON(slots->id_to_index[memslot->id] == -1)) return;
  slots->used_slots--;
  for (i = slots->id_to_index[memslot->id]; i < slots->used_slots; i++) {
    mslots[i] = mslots[i + 1];
    slots->id_to_index[mslots[i].id] = i;
  }
  mslots[i] = *memslot;
  slots->id_to_index[memslot->id] = -1;
}

static int decode_bit_string(const u8* inbuf, size_t inlen, void* outbuf,
                             size_t outlen, int invert) {
  const u8* in = inbuf;
  u8* out = (u8*)outbuf;
  int zero_bits = *in & 0x07;
  size_t octets_left = inlen - 1;
  int i, count = 0;
  memset(outbuf, 0, outlen);
  in++;
  if (outlen < octets_left) return SC_ERROR_BUFFER_TOO_SMALL;
  if (inlen < 1) return SC_ERROR_INVALID_ASN1_OBJECT;
  while (octets_left) {
    int bits_to_go;
    *out = 0;
    if (octets_left == 1)
      bits_to_go = 8 - zero_bits;
    else
      bits_to_go = 8;
    if (invert)
      for (i = 0; i < bits_to_go; i++) {
        *out |= ((*in >> (7 - i)) & 1) << i;
      }
    else {
      *out = *in;
    }
    out++;
    in++;
    octets_left--;
    count++;
  }
  return (count * 8) - zero_bits;
}

bool AES_GCM_EncryptContext::Encrypt(const void* pPlaintextData,
                                     size_t cbPlaintextData, const void* pIV,
