}

static int nut_read_header(AVFormatContext* s) {
  NUTContext* nut = s->priv_data;
  AVIOContext* bc = s->pb;
  int64_t pos;
  int initialized_stream_count;
  nut->avf = s;
  pos = 0;
  do {
    pos = find_startcode(bc, MAIN_STARTCODE, pos) + 1;
    if (pos < 0 + 1) {
      av_log(s, AV_LOG_ERROR, "No main startcode found.\n");
      return AVERROR_INVALIDDATA;
    }
  } while (decode_main_header(nut) < 0);
  pos = 0;
  for (initialized_stream_count = 0;
       initialized_stream_count < s->nb_streams;) {
    pos = find_startcode(bc, STREAM_STARTCODE, pos) + 1;
    if (pos < 0 + 1) {
      av_log(s, AV_LOG_ERROR, "Not all stream headers found.\n");
      return AVERROR_INVALIDDATA;
    }
    if (decode_stream_header(nut) >= 0) initialized_stream_count++;
  }
  pos = 0;
  for (;;) {
    uint64_t startcode = find_any_startcode(bc, pos);
    pos = avio_tell(bc);
    if (startcode == 0) {
      av_log(s, AV_LOG_ERROR, "EOF before video frames\n");
      return AVERROR_INVALIDDATA;
    } else if (startcode == SYNCPOINT_STARTCODE) {
      nut->next_startcode = startcode;
      break;
    } else if (startcode != INFO_STARTCODE) {
      continue;
    }
    decode_info_header(nut);
  }
  ffformatcontext(s)->data_offset = pos - 8;
  if (bc->seekable & AVIO_SEEKABLE_NORMAL) {
    int64_t orig_pos = avio_tell(bc);
    find_and_decode_index(nut);
    avio_seek(bc, orig_pos, SEEK_SET);
  }
  av_assert0(nut->next_startcode == SYNCPOINT_STARTCODE);
  ff_metadata_conv_ctx(s, NULL, ff_nut_metadata_conv);
  return 0;
}

static int snd_ctl_elem_read(struct snd_card* card,
                             struct snd_ctl_elem_value* control) {
  struct snd_kcontrol* kctl;
  struct snd_kcontrol_volatile* vd;
  unsigned int index_offset;
  struct snd_ctl_elem_info info;
  const u32 pattern = 0xdeadbeef;
  int ret;
  kctl = snd_ctl_find_id(card, &control->id);
  if (kctl == NULL) return -ENOENT;
  index_offset = snd_ctl_get_ioff(kctl, &control->id);
  vd = &kctl->vd[index_offset];
  if (!(vd->access & SNDRV_CTL_ELEM_ACCESS_READ) || kctl->get == NULL)
    return -EPERM;
  snd_ctl_build_ioff(&control->id, kctl, index_offset);
#ifdef CONFIG_SND_CTL_DEBUG
  memset(&info, 0, sizeof(info));
  info.id = control->id;
  ret = __snd_ctl_elem_info(card, kctl, &info, NULL);
  if (ret < 0) return ret;
#endif
  if (!snd_ctl_skip_validation(&info))
    fill_remaining_elem_value(control, &info, pattern);
  ret = snd_power_ref_and_wait(card);
  if (!ret) ret = kctl->get(kctl, control);
  snd_power_unref(card);
  if (ret < 0) return ret;
  if (!snd_ctl_skip_validation(&info) &&
      sanity_check_elem_value(card, control, &info, pattern) < 0) {
    dev_err(card->dev, "control %i:%i:%i:%s:%i: access overflow\n",
            control->id.iface, control->id.device, control->id.subdevice,
            control->id.name, control->id.index);
    return -EINVAL;
  }
  return ret;
}

pam_converse(int num_msg, PAM_CONVERSE_ARG2_TYPE** msg,
             struct pam_response** resp, void* appdata_ptr) {
  int sep = 0;
  struct pam_response* reply;
  if (pam_arg_ended || !(reply = malloc(sizeof(struct pam_response) * num_msg)))
    return PAM_CONV_ERR;
  for (int i = 0; i < num_msg; i++) {
    uschar* arg;
    switch (msg[i]->msg_style) {
      case PAM_PROMPT_ECHO_ON:
      case PAM_PROMPT_ECHO_OFF:
        if (!(arg = string_nextinlist(&pam_args, &sep, NULL, 0))) {
          arg = US "";
          pam_arg_ended = TRUE;
        }
        reply[i].resp = CS string_copy_malloc(arg);
        reply[i].resp_retcode = PAM_SUCCESS;
        break;
      case PAM_TEXT_INFO:
      case PAM_ERROR_MSG:
        reply[i].resp_retcode = PAM_SUCCESS;
        reply[i].resp = NULL;
        break;
      default:
        free(reply);
        pam_conv_had_error = TRUE;
        return PAM_CONV_ERR;
    }
  }
  *resp = reply;
  return PAM_SUCCESS;
}

ip_printroute(netdissect_options* ndo, register const u_char* cp,
              u_int length) {
