void DCR_CLASS dcr_parse_riff(DCRAW* p) {
  unsigned i, size, end;
  char tag[4], date[64], month[64];
  static const char mon[12][4] = {"Jan", "Feb", "Mar", "Apr", "May", "Jun",
                                  "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"};
  struct tm t;
  p->order = 0x4949;
  dcr_fread(p->obj_, tag, 4, 1);
  size = dcr_get4(p);
  end = dcr_ftell(p->obj_) + size;
  if (!memcmp(tag, "RIFF", 4) || !memcmp(tag, "LIST", 4)) {
    dcr_get4(p);
    while (dcr_ftell(p->obj_) + 7 < (long)end) dcr_parse_riff(p);
  } else if (!memcmp(tag, "nctg", 4)) {
    while (dcr_ftell(p->obj_) + 7 < (long)end) {
      i = dcr_get2(p);
      size = dcr_get2(p);
      if ((i + 1) >> 1 == 10 && size == 20)
        dcr_get_timestamp(p, 0);
      else
        dcr_fseek(p->obj_, size, SEEK_CUR);
    }
  } else if (!memcmp(tag, "IDIT", 4) && size < 64) {
    dcr_fread(p->obj_, date, 64, 1);
    date[size] = 0;
    memset(&t, 0, sizeof t);
    if (sscanf(date, "%*s %s %d %d:%d:%d %d", month, &t.tm_mday, &t.tm_hour,
               &t.tm_min, &t.tm_sec, &t.tm_year) == 6) {
      for (i = 0; i < 12 && strcasecmp(mon[i], month); i++);
      t.tm_mon = i;
      t.tm_year -= 1900;
      if (mktime(&t) > 0) p->timestamp = mktime(&t);
    }
  } else
    dcr_fseek(p->obj_, size, SEEK_CUR);
}

