h2_vfp_body(struct vfp_ctx* vc, struct vfp_entry* vfe, void* ptr, ssize_t* lp) {
  struct h2_req* r2;
  struct h2_sess* h2;
  unsigned l;
  enum vfp_status retval = VFP_OK;
  CHECK_OBJ_NOTNULL(vc, VFP_CTX_MAGIC);
  CHECK_OBJ_NOTNULL(vfe, VFP_ENTRY_MAGIC);
  CAST_OBJ_NOTNULL(r2, vfe->priv1, H2_REQ_MAGIC);
  h2 = r2->h2sess;
  AN(ptr);
  AN(lp);
  l = *lp;
  *lp = 0;
  Lck_Lock(&h2->sess->mtx);
  assert(r2->state == H2_S_OPEN);
  r2->cond = &vc->wrk->cond;
  while (h2->mailcall != r2 && h2->error == 0 && r2->error == 0)
    AZ(Lck_CondWait(r2->cond, &h2->sess->mtx, 0));
  r2->cond = NULL;
  if (h2->error || r2->error) {
    retval = VFP_ERROR;
  } else {
    assert(h2->mailcall == r2);
    if (l > h2->rxf_len) l = h2->rxf_len;
    if (l > 0) {
      memcpy(ptr, h2->rxf_data, l);
      h2->rxf_data += l;
      h2->rxf_len -= l;
    }
    *lp = l;
    if (h2->rxf_len > 0) {
      Lck_Unlock(&h2->sess->mtx);
      return (VFP_OK);
    }
    if (h2->rxf_len == 0) {
      if (h2->rxf_flags & H2FF_DATA_END_STREAM) {
        retval = VFP_END;
        r2->state = H2_S_CLOS_REM;
      }
    }
    h2->mailcall = NULL;
    AZ(pthread_cond_signal(h2->cond));
  }
  Lck_Unlock(&h2->sess->mtx);
  return (retval);
}

fst_get_iface(struct fst_card_info* card, struct fst_port_info* port,
              struct ifreq* ifr) {
  sync_serial_settings sync;
  int i;
  switch (port->hwif) {
    case E1:
      ifr->ifr_settings.type = IF_IFACE_E1;
      break;
    case T1:
      ifr->ifr_settings.type = IF_IFACE_T1;
      break;
    case V35:
      ifr->ifr_settings.type = IF_IFACE_V35;
      break;
    case V24:
      ifr->ifr_settings.type = IF_IFACE_V24;
      break;
    case X21D:
      ifr->ifr_settings.type = IF_IFACE_X21D;
      break;
    case X21:
    default:
      ifr->ifr_settings.type = IF_IFACE_X21;
      break;
  }
  if (ifr->ifr_settings.size == 0) {
    return 0;
  }
  if (ifr->ifr_settings.size < sizeof(sync)) {
    return -ENOMEM;
  }
  i = port->index;
  sync.clock_rate = FST_RDL(card, portConfig[i].lineSpeed);
  sync.clock_type = FST_RDB(card, portConfig[i].internalClock) == INTCLK
                        ? CLOCK_INT
                        : CLOCK_EXT;
  sync.loopback = 0;
  if (copy_to_user(ifr->ifr_settings.ifs_ifsu.sync, &sync, sizeof(sync))) {
    return -EFAULT;
  }
  ifr->ifr_settings.size = sizeof(sync);
  return 0;
}

static void update_blocked_averages(int cpu) {
  struct rq* rq = cpu_rq(cpu);
  struct cfs_rq *cfs_rq, *pos;
  const struct sched_class* curr_class;
  struct rq_flags rf;
  bool done = true;
  rq_lock_irqsave(rq, &rf);
  update_rq_clock(rq);
  for_each_leaf_cfs_rq_safe(rq, cfs_rq, pos) {
    struct sched_entity* se;
    if (throttled_hierarchy(cfs_rq)) continue;
    if (update_cfs_rq_load_avg(cfs_rq_clock_task(cfs_rq), cfs_rq))
      update_tg_load_avg(cfs_rq, 0);
    se = cfs_rq->tg->se[cpu];
    if (se && !skip_blocked_update(se)) update_load_avg(cfs_rq_of(se), se, 0);
    if (cfs_rq_is_decayed(cfs_rq)) list_del_leaf_cfs_rq(cfs_rq);
    if (cfs_rq_has_blocked(cfs_rq)) done = false;
  }
  curr_class = rq->curr->sched_class;
  update_rt_rq_load_avg(rq_clock_task(rq), rq, curr_class == &rt_sched_class);
  update_dl_rq_load_avg(rq_clock_task(rq), rq, curr_class == &dl_sched_class);
  update_irq_load_avg(rq, 0);
  if (others_have_blocked(rq)) done = false;
#ifdef CONFIG_NO_HZ_COMMON
  rq->last_blocked_load_update_tick = jiffies;
  if (done) rq->has_blocked_load = 0;
#endif
  rq_unlock_irqrestore(rq, &rf);
}

status_t SampleTable::setSampleToChunkParams(off64_t data_offset,
                                             size_t data_size) {
  if (mSampleToChunkOffset >= 0) {
    return ERROR_MALFORMED;
  }
  mSampleToChunkOffset = data_offset;
  if (data_size < 8) {
    return ERROR_MALFORMED;
  }
  uint8_t header[8];
  if (mDataSource->readAt(data_offset, header, sizeof(header)) <
      (ssize_t)sizeof(header)) {
    return ERROR_IO;
  }
  if (U32_AT(header) != 0) {
    return ERROR_MALFORMED;
  }
  mNumSampleToChunkOffsets = U32_AT(&header[4]);
  if (data_size < 8 + mNumSampleToChunkOffsets * 12) {
    return ERROR_MALFORMED;
  }
  mSampleToChunkEntries = new SampleToChunkEntry[mNumSampleToChunkOffsets];
  for (uint32_t i = 0; i < mNumSampleToChunkOffsets; ++i) {
    uint8_t buffer[12];
    if (mDataSource->readAt(mSampleToChunkOffset + 8 + i * 12, buffer,
                            sizeof(buffer)) != (ssize_t)sizeof(buffer)) {
      return ERROR_IO;
    }
    CHECK(U32_AT(buffer) >= 1);
    mSampleToChunkEntries[i].startChunk = U32_AT(buffer) - 1;
    mSampleToChunkEntries[i].samplesPerChunk = U32_AT(&buffer[4]);
    mSampleToChunkEntries[i].chunkDesc = U32_AT(&buffer[8]);
  }
  return OK;
}

static bool disconnect_cb(struct io* io, void* user_data) {
  struct bt_att_chan* chan = user_data;
  struct bt_att* att = chan->att;
  int err;
  socklen_t len;
  len = sizeof(err);
  if (getsockopt(chan->fd, SOL_SOCKET, SO_ERROR, &err, &len) < 0) {
    util_debug(chan->att->debug_callback, chan->att->debug_data,
               "(chan %p) Failed to obtain disconnect"
               " error: %s",
               chan, strerror(errno));
    err = 0;
  }
  util_debug(chan->att->debug_callback, chan->att->debug_data,
             "Channel %p disconnected: %s", chan, strerror(err));
  queue_remove(att->chans, chan);
  queue_remove_all(att->req_queue, NULL, NULL, disc_att_send_op);
  queue_remove_all(att->ind_queue, NULL, NULL, disc_att_send_op);
  queue_remove_all(att->write_queue, NULL, NULL, disc_att_send_op);
  if (chan->pending_req) {
    disc_att_send_op(chan->pending_req);
    chan->pending_req = NULL;
  }
  if (chan->pending_ind) {
    disc_att_send_op(chan->pending_ind);
    chan->pending_ind = NULL;
  }
  bt_att_chan_free(chan);
  if (!queue_isempty(att->chans)) return false;
  bt_att_ref(att);
  queue_foreach(att->disconn_list, disconn_handler, INT_TO_PTR(err));
  bt_att_unregister_all(att);
  bt_att_unref(att);
  return false;
}

static int setup_ttydir_console(const struct lxc_rootfs* rootfs,
                                const struct lxc_console* console,
                                char* ttydir) {
  char path[MAXPATHLEN], lxcpath[MAXPATHLEN];
  int ret;
  ret = snprintf(path, sizeof(path), "%s/dev/%s", rootfs->mount, ttydir);
  if (ret >= sizeof(path)) return -1;
  ret = mkdir(path, 0755);
  if (ret && errno != EEXIST) {
    SYSERROR("failed with errno %d to create %s", errno, path);
    return -1;
  }
  INFO("created %s", path);
  ret = snprintf(lxcpath, sizeof(lxcpath), "%s/dev/%s/console", rootfs->mount,
                 ttydir);
  if (ret >= sizeof(lxcpath)) {
    ERROR("console path too long");
    return -1;
  }
  snprintf(path, sizeof(path), "%s/dev/console", rootfs->mount);
  ret = unlink(path);
  if (ret && errno != ENOENT) {
    SYSERROR("error unlinking %s", path);
    return -1;
  }
  ret = creat(lxcpath, 0660);
  if (ret == -1 && errno != EEXIST) {
    SYSERROR("error %d creating %s", errno, lxcpath);
    return -1;
  }
  if (ret >= 0) close(ret);
  if (console->master < 0) {
    INFO("no console");
    return 0;
  }
  if (mount(console->name, lxcpath, "none", MS_BIND, 0)) {
    ERROR("failed to mount '%s' on '%s'", console->name, lxcpath);
    return -1;
  }
  ret = snprintf(lxcpath, sizeof(lxcpath), "%s/console", ttydir);
  if (ret >= sizeof(lxcpath)) {
    ERROR("lxc/console path too long");
    return -1;
  }
  ret = symlink(lxcpath, path);
  if (ret) {
    SYSERROR("failed to create symlink for console");
    return -1;
  }
  INFO("console has been setup on %s", lxcpath);
  return 0;
}

static int semctl_down(struct ipc_namespace* ns, int semid, int cmd,
                       int version, void __user* p) {
  struct sem_array* sma;
  int err;
  struct semid64_ds semid64;
  struct kern_ipc_perm* ipcp;
  if (cmd == IPC_SET) {
    if (copy_semid_from_user(&semid64, p, version)) return -EFAULT;
  }
  ipcp = ipcctl_pre_down_nolock(ns, &sem_ids(ns), semid, cmd, &semid64.sem_perm,
                                0);
  if (IS_ERR(ipcp)) return PTR_ERR(ipcp);
  sma = container_of(ipcp, struct sem_array, sem_perm);
  err = security_sem_semctl(sma, cmd);
  if (err) {
    rcu_read_unlock();
    goto out_unlock;
  }
  switch (cmd) {
    case IPC_RMID:
      ipc_lock_object(&sma->sem_perm);
      freeary(ns, ipcp);
      goto out_up;
    case IPC_SET:
      ipc_lock_object(&sma->sem_perm);
      err = ipc_update_perm(&semid64.sem_perm, ipcp);
      if (err) goto out_unlock;
      sma->sem_ctime = get_seconds();
      break;
    default:
      rcu_read_unlock();
      err = -EINVAL;
      goto out_up;
  }
out_unlock:
  sem_unlock(sma);
out_up:
  up_write(&sem_ids(ns).rw_mutex);
  return err;
}

