static inline char* parse_ip_address_ex(const char* str, size_t str_len,
                                        int* portno, int get_err,
                                        zend_string** err) {
  char* colon;
  char* host = NULL;
#ifdef HAVE_IPV6
  char* p;
  if (*(str) == '[' && str_len > 1) {
    p = memchr(str + 1, ']', str_len - 2);
    if (!p || *(p + 1) != ':') {
      if (get_err) {
        *err = strpprintf(0, "Failed to parse IPv6 address \"%s\"", str);
      }
      return NULL;
    }
    *portno = atoi(p + 2);
    return estrndup(str + 1, p - str - 1);
  }
#endif
  if (str_len) {
    colon = memchr(str, ':', str_len - 1);
  } else {
    colon = NULL;
  }
  if (colon) {
    *portno = atoi(colon + 1);
    host = estrndup(str, colon - str);
  } else {
    if (get_err) {
      *err = strpprintf(0, "Failed to parse address \"%s\"", str);
    }
    return NULL;
  }
  return host;
}

static int link_pipe(struct pipe_inode_info* ipipe,
                     struct pipe_inode_info* opipe, size_t len,
                     unsigned int flags) {
  struct pipe_buffer *ibuf, *obuf;
  int ret = 0, i = 0, nbuf;
  pipe_double_lock(ipipe, opipe);
  do {
    if (!opipe->readers) {
      send_sig(SIGPIPE, current, 0);
      if (!ret) ret = -EPIPE;
      break;
    }
    if (i >= ipipe->nrbufs || opipe->nrbufs >= opipe->buffers) break;
    ibuf = ipipe->bufs + ((ipipe->curbuf + i) & (ipipe->buffers - 1));
    nbuf = (opipe->curbuf + opipe->nrbufs) & (opipe->buffers - 1);
    pipe_buf_get(ipipe, ibuf);
    obuf = opipe->bufs + nbuf;
    *obuf = *ibuf;
    obuf->flags &= ~PIPE_BUF_FLAG_GIFT;
    if (obuf->len > len) obuf->len = len;
    opipe->nrbufs++;
    ret += obuf->len;
    len -= obuf->len;
    i++;
  } while (len);
  if (!ret && ipipe->waiting_writers && (flags & SPLICE_F_NONBLOCK))
    ret = -EAGAIN;
  pipe_unlock(ipipe);
  pipe_unlock(opipe);
  if (ret > 0) wakeup_pipe_readers(opipe);
  return ret;
}

create_surface_from_thumbnail_data(guchar* data, gint width, gint height,
                                   gint rowstride) {
  guchar* cairo_pixels;
  cairo_surface_t* surface;
  static cairo_user_data_key_t key;
  int j;
  cairo_pixels = (guchar*)g_malloc(4 * width * height);
  surface = cairo_image_surface_create_for_data((unsigned char*)cairo_pixels,
                                                CAIRO_FORMAT_RGB24, width,
                                                height, 4 * width);
  cairo_surface_set_user_data(surface, &key, cairo_pixels,
                              (cairo_destroy_func_t)g_free);
  for (j = height; j; j--) {
    guchar* p = data;
    guchar* q = cairo_pixels;
    guchar* end = p + 3 * width;
    while (p < end) {
#if G_BYTE_ORDER == G_LITTLE_ENDIAN
      q[0] = p[2];
      q[1] = p[1];
      q[2] = p[0];
#else
      q[1] = p[0];
      q[2] = p[1];
      q[3] = p[2];
#endif
      p += 3;
      q += 4;
    }
    data += rowstride;
    cairo_pixels += 4 * width;
  }
  return surface;
}

static struct port_buffer* get_inbuf(struct port* port) {
  struct port_buffer* buf;
  unsigned int len;
  if (port->inbuf) return port->inbuf;
  buf = virtqueue_get_buf(port->in_vq, &len);
  if (buf) {
    buf->len = len;
    buf->offset = 0;
    port->stats.bytes_received += len;
  }
  return buf;
}

static int update_header(void* obj) {
  struct header_data* data = obj;
  pjsip_hdr* hdr = NULL;
  RAII_VAR(struct ast_datastore*, datastore,
           ast_sip_session_get_datastore(data->channel->session,
                                         data->header_datastore->type),
           ao2_cleanup);
  if (!datastore || !datastore->data) {
    ast_log(AST_LOG_ERROR,
            "No headers had been previously added to this session.\n");
    return -1;
  }
  hdr = find_header((struct hdr_list*)datastore->data, data->header_name,
                    data->header_number);
  if (!hdr) {
    ast_log(AST_LOG_ERROR, "There was no header named %s.\n",
            data->header_name);
    return -1;
  }
  pj_strcpy2(&((pjsip_generic_string_hdr*)hdr)->hvalue, data->header_value);
  return 0;
}

wb_id(netdissect_options* ndo, const struct pkt_id* id, u_int len) {
  int i;
  const char* cp;
  const struct id_off* io;
  char c;
  int nid;
  ND_PRINT((ndo, " wb-id:"));
  if (len < sizeof(*id) || !ND_TTEST(*id)) return (-1);
  len -= sizeof(*id);
  ND_PRINT((ndo, " %u/%s:%u (max %u/%s:%u) ", EXTRACT_32BITS(&id->pi_ps.slot),
            ipaddr_string(ndo, &id->pi_ps.page.p_sid),
            EXTRACT_32BITS(&id->pi_ps.page.p_uid),
            EXTRACT_32BITS(&id->pi_mslot),
            ipaddr_string(ndo, &id->pi_mpage.p_sid),
            EXTRACT_32BITS(&id->pi_mpage.p_uid)));
  nid = EXTRACT_16BITS(&id->pi_ps.nid);
  len -= sizeof(*io) * nid;
  io = (struct id_off*)(id + 1);
  cp = (char*)(io + nid);
  if (!ND_TTEST2(cp, len)) {
    ND_PRINT((ndo, "\""));
    fn_print(ndo, (u_char*)cp, (u_char*)cp + len);
    ND_PRINT((ndo, "\""));
  }
  c = '<';
  for (i = 0; i < nid && ND_TTEST(*io); ++io, ++i) {
    ND_PRINT((ndo, "%c%s:%u", c, ipaddr_string(ndo, &io->id),
              EXTRACT_32BITS(&io->off)));
    c = ',';
  }
  if (i >= nid) {
    ND_PRINT((ndo, ">"));
    return (0);
  }
  return (-1);
}

