int button_open(Button* b) {
  char *p, name[256];
  int r;
  assert(b);
  b->fd = safe_close(b->fd);
  p = strjoina("/dev/input/", b->name);
  b->fd = open(p, O_RDWR | O_CLOEXEC | O_NOCTTY | O_NONBLOCK);
  if (b->fd < 0) return log_warning_errno(errno, "Failed to open %s: %m", p);
  r = button_suitable(b);
  if (r < 0)
    return log_warning_errno(
        r, "Failed to determine whether input device is relevant to us: %m");
  if (r == 0)
    return log_debug_errno(
        SYNTHETIC_ERRNO(EADDRNOTAVAIL),
        "Device %s does not expose keys or switches relevant to us, ignoring.",
        p);
  if (ioctl(b->fd, EVIOCGNAME(sizeof(name)), name) < 0) {
    r = log_error_errno(errno, "Failed to get input name: %m");
    goto fail;
  }
  (void)button_set_mask(b);
  r = sd_event_add_io(b->manager->event, &b->io_event_source, b->fd, EPOLLIN,
                      button_dispatch, b);
  if (r < 0) {
    log_error_errno(r, "Failed to add button event: %m");
    goto fail;
  }
  log_info("Watching system buttons on /dev/input/%s (%s)", b->name, name);
  return 0;
fail:
  b->fd = safe_close(b->fd);
  return r;
}

void imap_quote_string(char* dest, size_t dlen, const char* src) {
  static const char quote[] = "\"\\";
  char* pt = dest;
  const char* s = src;
  *pt++ = '"';
  dlen -= 2;
  for (; *s && dlen; s++) {
    if (strchr(quote, *s)) {
      dlen -= 2;
      if (dlen == 0) break;
      *pt++ = '\\';
      *pt++ = *s;
    } else {
      *pt++ = *s;
      dlen--;
    }
  }
  *pt++ = '"';
  *pt = '\0';
}

header_put_marker(SF_PRIVATE* psf, int x) {
  if (psf->headindex < SIGNED_SIZEOF(psf->header) - 4) {
    psf->header[psf->headindex++] = (x >> 24);
    psf->header[psf->headindex++] = (x >> 16);
    psf->header[psf->headindex++] = (x >> 8);
    psf->header[psf->headindex++] = x;
  };
}

void HeaderTable::setCapacity(uint32_t capacity) {
  auto oldCapacity = capacity_;
  capacity_ = capacity;
  if (capacity_ <= oldCapacity) {
    evict(0);
  } else {
    auto oldTail = tail();
    auto oldLength = table_.size();
    uint32_t newLength = (capacity_ >> 5) + 1;
    table_.resize(newLength);
    if (size_ > 0 && oldTail > head_) {
      std::copy(table_.begin() + oldTail, table_.begin() + oldLength,
                table_.begin() + newLength - (oldLength - oldTail));
      for (auto& names_it : names_) {
        for (auto& idx : names_it.second) {
          if (idx >= oldTail) {
            DCHECK_LT(idx + (table_.size() - oldLength), table_.size());
            idx += (table_.size() - oldLength);
          } else {
            break;
          }
        }
      }
    }
  }
}

