entityValueInitProcessor(XML_Parser parser, const char* s, const char* end,
                         const char** nextPtr) {
  int tok;
  const char* start = s;
  const char* next = start;
  parser->m_eventPtr = start;
  for (;;) {
    tok = XmlPrologTok(parser->m_encoding, start, end, &next);
    parser->m_eventEndPtr = next;
    if (tok <= 0) {
      if (!parser->m_parsingStatus.finalBuffer && tok != XML_TOK_INVALID) {
        *nextPtr = s;
        return XML_ERROR_NONE;
      }
      switch (tok) {
        case XML_TOK_INVALID:
          return XML_ERROR_INVALID_TOKEN;
        case XML_TOK_PARTIAL:
          return XML_ERROR_UNCLOSED_TOKEN;
        case XML_TOK_PARTIAL_CHAR:
          return XML_ERROR_PARTIAL_CHAR;
        case XML_TOK_NONE:
        default:
          break;
      }
      return storeEntityValue(parser, parser->m_encoding, s, end,
                              XML_ACCOUNT_DIRECT);
    } else if (tok == XML_TOK_XML_DECL) {
      enum XML_Error result;
      result = processXmlDecl(parser, 0, start, next);
      if (result != XML_ERROR_NONE) return result;
      if (parser->m_parsingStatus.parsing == XML_FINISHED)
        return XML_ERROR_ABORTED;
      *nextPtr = next;
      parser->m_processor = entityValueProcessor;
      return entityValueProcessor(parser, next, end, nextPtr);
    } else if (tok == XML_TOK_BOM) {
#ifdef XML_DTD
      if (!accountingDiffTolerated(parser, tok, s, next, __LINE__,
                                   XML_ACCOUNT_DIRECT)) {
        accountingOnAbort(parser);
        return XML_ERROR_AMPLIFICATION_LIMIT_BREACH;
      }
#endif
      *nextPtr = next;
      s = next;
    } else if (tok == XML_TOK_INSTANCE_START) {
      *nextPtr = next;
      return XML_ERROR_SYNTAX;
    }
    start = next;
    parser->m_eventPtr = start;
  }
}

static struct inet_frag_queue* inet_frag_intern(struct netns_frags* nf,
                                                struct inet_frag_queue* qp_in,
                                                struct inet_frags* f,
                                                void* arg) {
  struct inet_frag_bucket* hb;
  struct inet_frag_queue* qp;
  unsigned int hash;
  read_lock(&f->lock);
  hash = f->hashfn(qp_in);
  hb = &f->hash[hash];
  spin_lock(&hb->chain_lock);
#ifdef CONFIG_SMP
  hlist_for_each_entry(qp, &hb->chain, list) {
    if (qp->net == nf && f->match(qp, arg)) {
      atomic_inc(&qp->refcnt);
      spin_unlock(&hb->chain_lock);
      read_unlock(&f->lock);
      qp_in->last_in |= INET_FRAG_COMPLETE;
      inet_frag_put(qp_in, f);
      return qp;
    }
  }
#endif
  qp = qp_in;
  if (!mod_timer(&qp->timer, jiffies + nf->timeout)) atomic_inc(&qp->refcnt);
  atomic_inc(&qp->refcnt);
  hlist_add_head(&qp->list, &hb->chain);
  spin_unlock(&hb->chain_lock);
  read_unlock(&f->lock);
  inet_frag_lru_add(nf, qp);
  return qp;
}

static char** split(const char* arg, const char* delim) {
  char* copy = dupstr(arg);
  char** result = NULL;
  int i = 0;
  for (char* cptr = strtok(copy, delim); cptr; cptr = strtok(NULL, delim)) {
    char** tmp = realloc(result, sizeof *result * (i + 1));
    if (!tmp && result) {
      while (i > 0) {
        free(result[--i]);
      }
      free(result);
      free(copy);
      return NULL;
    }
    result = tmp;
    result[i++] = dupstr(cptr);
  }
  free(copy);
  if (i) {
    char** tmp = realloc(result, sizeof *result * (i + 1));
    if (!tmp) {
      while (i > 0) {
        free(result[--i]);
      }
      free(result);
      free(copy);
      return NULL;
    }
    result = tmp;
    result[i++] = NULL;
  }
  return result;
}

