int nf_ct_frag6_gather(struct net* net, struct sk_buff* skb, u32 user) {
  struct net_device* dev = skb->dev;
  int fhoff, nhoff, ret;
  struct frag_hdr* fhdr;
  struct frag_queue* fq;
  struct ipv6hdr* hdr;
  u8 prevhdr;
  if (ipv6_hdr(skb)->payload_len == 0) {
    pr_debug("payload len = 0\n");
    return -EINVAL;
  }
  if (find_prev_fhdr(skb, &prevhdr, &nhoff, &fhoff) < 0) return -EINVAL;
  if (!pskb_may_pull(skb, fhoff + sizeof(*fhdr))) return -ENOMEM;
  skb_set_transport_header(skb, fhoff);
  hdr = ipv6_hdr(skb);
  fhdr = (struct frag_hdr*)skb_transport_header(skb);
  fq = fq_find(net, fhdr->identification, user, &hdr->saddr, &hdr->daddr,
               skb->dev ? skb->dev->ifindex : 0, ip6_frag_ecn(hdr));
  if (fq == NULL) {
    pr_debug("Can't find and can't create new queue\n");
    return -ENOMEM;
  }
  spin_lock_bh(&fq->q.lock);
  if (nf_ct_frag6_queue(fq, skb, fhdr, nhoff) < 0) {
    ret = -EINVAL;
    goto out_unlock;
  }
  ret = -EINPROGRESS;
  if (fq->q.flags == (INET_FRAG_FIRST_IN | INET_FRAG_LAST_IN) &&
      fq->q.meat == fq->q.len && nf_ct_frag6_reasm(fq, skb, dev))
    ret = 0;
out_unlock:
  spin_unlock_bh(&fq->q.lock);
  inet_frag_put(&fq->q, &nf_frags);
  return ret;
}

void common_timer_get(struct k_itimer* timr, struct itimerspec64* cur_setting) {
  const struct k_clock* kc = timr->kclock;
  ktime_t now, remaining, iv;
  struct timespec64 ts64;
  bool sig_none;
  sig_none = (timr->it_sigev_notify & ~SIGEV_THREAD_ID) == SIGEV_NONE;
  iv = timr->it_interval;
  if (iv) {
    cur_setting->it_interval = ktime_to_timespec64(iv);
  } else if (!timr->it_active) {
    if (!sig_none) return;
  }
  kc->clock_get(timr->it_clock, &ts64);
  now = timespec64_to_ktime(ts64);
  if (iv && (timr->it_requeue_pending & REQUEUE_PENDING || sig_none))
    timr->it_overrun += kc->timer_forward(timr, now);
  remaining = kc->timer_remaining(timr, now);
  if (remaining <= 0) {
    if (!sig_none) cur_setting->it_value.tv_nsec = 1;
  } else {
    cur_setting->it_value = ktime_to_timespec64(remaining);
  }
}

mp_join_print(netdissect_options* ndo, const u_char* opt, u_int opt_len,
              u_char flags) {
  const struct mp_join* mpj = (const struct mp_join*)opt;
  if (!(opt_len == 12 && flags & TH_SYN) &&
      !(opt_len == 16 && (flags & (TH_SYN | TH_ACK)) == (TH_SYN | TH_ACK)) &&
      !(opt_len == 24 && flags & TH_ACK))
    return 0;
  if (opt_len != 24) {
    if (mpj->sub_b & MP_JOIN_B) ND_PRINT((ndo, " backup"));
    ND_PRINT((ndo, " id %u", mpj->addr_id));
  }
  switch (opt_len) {
    case 12:
      ND_PRINT((ndo,
                " token 0x%x"
                " nonce 0x%x",
                EXTRACT_32BITS(mpj->u.syn.token),
                EXTRACT_32BITS(mpj->u.syn.nonce)));
      break;
    case 16:
      ND_PRINT((ndo, " hmac 0x%" PRIx64 " nonce 0x%x",
                EXTRACT_64BITS(mpj->u.synack.mac),
                EXTRACT_32BITS(mpj->u.synack.nonce)));
      break;
    case 24: {
      size_t i;
      ND_PRINT((ndo, " hmac 0x"));
      for (i = 0; i < sizeof(mpj->u.ack.mac); ++i)
        ND_PRINT((ndo, "%02x", mpj->u.ack.mac[i]));
    }
    default:
      break;
  }
  return 1;
}

