delete_policy_2_svc(dpol_arg* arg, struct svc_req* rqstp) {
  static generic_ret ret;
  char* prime_arg;
  gss_buffer_desc client_name, service_name;
  OM_uint32 minor_stat;
  kadm5_server_handle_t handle;
  const char* errmsg = NULL;
  xdr_free(xdr_generic_ret, &ret);
  if ((ret.code = new_server_handle(arg->api_version, rqstp, &handle)))
    goto exit_func;
  if ((ret.code = check_handle((void*)handle))) goto exit_func;
  ret.api_version = handle->api_version;
  if (setup_gss_names(rqstp, &client_name, &service_name) < 0) {
    ret.code = KADM5_FAILURE;
    goto exit_func;
  }
  prime_arg = arg->name;
  if (CHANGEPW_SERVICE(rqstp) ||
      !kadm5int_acl_check(handle->context, rqst2name(rqstp), ACL_DELETE, NULL,
                          NULL)) {
    log_unauth("kadm5_delete_policy", prime_arg, &client_name, &service_name,
               rqstp);
    ret.code = KADM5_AUTH_DELETE;
  } else {
    ret.code = kadm5_delete_policy((void*)handle, arg->name);
    if (ret.code != 0)
      errmsg = krb5_get_error_message(handle->context, ret.code);
    log_done("kadm5_delete_policy",
             ((prime_arg == NULL) ? "(null)" : prime_arg), errmsg, &client_name,
             &service_name, rqstp);
    if (errmsg != NULL) krb5_free_error_message(handle->context, errmsg);
  }
  gss_release_buffer(&minor_stat, &client_name);
  gss_release_buffer(&minor_stat, &service_name);
exit_func:
  free_server_handle(handle);
  return &ret;
}

int usbip_recv_xbuff(struct usbip_device* ud, struct urb* urb) {
  int ret;
  int size;
  if (ud->side == USBIP_STUB) {
    if (usb_pipein(urb->pipe)) return 0;
    size = urb->transfer_buffer_length;
  } else {
    if (usb_pipeout(urb->pipe)) return 0;
    size = urb->actual_length;
  }
  if (!(size > 0)) return 0;
  ret = usbip_recv(ud->tcp_socket, urb->transfer_buffer, size);
  if (ret != size) {
    dev_err(&urb->dev->dev, "recv xbuf, %d\n", ret);
    if (ud->side == USBIP_STUB) {
      usbip_event_add(ud, SDEV_EVENT_ERROR_TCP);
    } else {
      usbip_event_add(ud, VDEV_EVENT_ERROR_TCP);
      return -EPIPE;
    }
  }
  return ret;
}

static inline struct htx_blk* htx_add_trailer(struct htx* htx,
                                              const struct ist name,
                                              const struct ist value) {
  struct htx_blk* blk;
  blk = htx_add_blk(htx, HTX_BLK_TLR, name.len + value.len);
  if (!blk) return NULL;
  blk->info += (value.len << 8) + name.len;
  ist2bin_lc(htx_get_blk_ptr(htx, blk), name);
  memcpy(htx_get_blk_ptr(htx, blk) + name.len, value.ptr, value.len);
  return blk;
}

int do_remount_sb(struct super_block* sb, int flags, void* data, int force) {
  int retval;
  int remount_ro;
  if (sb->s_writers.frozen != SB_UNFROZEN) return -EBUSY;
#ifdef CONFIG_BLOCK
  if (!(flags & MS_RDONLY) && bdev_read_only(sb->s_bdev)) return -EACCES;
#endif
  if (flags & MS_RDONLY) acct_auto_close(sb);
  shrink_dcache_sb(sb);
  sync_filesystem(sb);
  remount_ro = (flags & MS_RDONLY) && !(sb->s_flags & MS_RDONLY);
  if (remount_ro) {
    if (force) {
      mark_files_ro(sb);
    } else {
      retval = sb_prepare_remount_readonly(sb);
      if (retval) return retval;
    }
  }
  if (sb->s_op->remount_fs) {
    retval = sb->s_op->remount_fs(sb, &flags, data);
    if (retval) {
      if (!force) goto cancel_readonly;
      WARN(1, "forced remount of a %s fs returned %i\n", sb->s_type->name,
           retval);
    }
  }
  sb->s_flags = (sb->s_flags & ~MS_RMT_MASK) | (flags & MS_RMT_MASK);
  smp_wmb();
  sb->s_readonly_remount = 0;
  if (remount_ro && sb->s_bdev) invalidate_bdev(sb->s_bdev);
  return 0;
cancel_readonly:
  sb->s_readonly_remount = 0;
  return retval;
}

irc_server_set_prefix_modes_chars(struct t_irc_server* server,
                                  const char* prefix) {
  char* pos;
  int i, length_modes, length_chars;
  if (!server || !prefix) return;
  if (server->prefix_modes) {
    free(server->prefix_modes);
    server->prefix_modes = NULL;
  }
  if (server->prefix_chars) {
    free(server->prefix_chars);
    server->prefix_chars = NULL;
  }
  pos = strchr(prefix, ')');
  if (pos) {
    server->prefix_modes = weechat_strndup(prefix + 1, pos - prefix - 1);
    if (server->prefix_modes) {
      pos++;
      length_modes = strlen(server->prefix_modes);
      length_chars = strlen(pos);
      server->prefix_chars = malloc(length_modes + 1);
      if (server->prefix_chars) {
        for (i = 0; i < length_modes; i++) {
          server->prefix_chars[i] = (i < length_chars) ? pos[i] : ' ';
        }
        server->prefix_chars[length_modes] = '\0';
      } else {
        free(server->prefix_modes);
        server->prefix_modes = NULL;
      }
    }
  }
}

set_range(bitstr_t* bits, int low, int high, int start, int stop, int step) {
  Debug(DPARS | DEXT, ("set_range(?,%d,%d,%d,%d,%d)\n", low, high, start, stop,
                       step)) if (start < low || stop > high) return (EOF);
  start -= low;
  stop -= low;
  if (step == 1) {
    bit_nset(bits, start, stop);
  } else {
    for (int i = start; i <= stop; i += step) bit_set(bits, i);
  }
  return (OK);
}

CopyKeyAliasesToKeymap(struct xkb_keymap* keymap, KeyNamesInfo* info) {
  AliasInfo* alias;
  unsigned i, num_key_aliases;
  struct xkb_key_alias* key_aliases;
  num_key_aliases = 0;
  darray_foreach(alias, info->aliases) {
    if (!XkbKeyByName(keymap, alias->real, false)) {
      log_vrb(info->ctx, 5,
              "Attempt to alias %s to non-existent key %s; Ignored\n",
              KeyNameText(info->ctx, alias->alias),
              KeyNameText(info->ctx, alias->real));
      alias->real = XKB_ATOM_NONE;
      continue;
    }
    if (XkbKeyByName(keymap, alias->alias, false)) {
      log_vrb(info->ctx, 5,
              "Attempt to create alias with the name of a real key; "
              "Alias \"%s = %s\" ignored\n",
              KeyNameText(info->ctx, alias->alias),
              KeyNameText(info->ctx, alias->real));
      alias->real = XKB_ATOM_NONE;
      continue;
    }
    num_key_aliases++;
  }
  key_aliases = NULL;
  if (num_key_aliases > 0) {
    key_aliases = calloc(num_key_aliases, sizeof(*key_aliases));
    if (!key_aliases) return false;
  }
  i = 0;
  darray_foreach(alias, info->aliases) {
    if (alias->real != XKB_ATOM_NONE) {
      key_aliases[i].alias = alias->alias;
      key_aliases[i].real = alias->real;
      i++;
    }
  }
  keymap->num_key_aliases = num_key_aliases;
  keymap->key_aliases = key_aliases;
  return true;
}

