void PaintLayerScrollableArea::UpdateCompositingLayersAfterScroll() {
  PaintLayerCompositor* compositor = GetLayoutBox()->View()->Compositor();
  if (!compositor->InCompositingMode()) return;
  if (UsesCompositedScrolling()) {
    DCHECK(Layer()->HasCompositedLayerMapping());
    ScrollingCoordinator* scrolling_coordinator = GetScrollingCoordinator();
    bool handled_scroll =
        Layer()->IsRootLayer() && scrolling_coordinator &&
        scrolling_coordinator->UpdateCompositedScrollOffset(this);
    if (!handled_scroll) {
      if (!RuntimeEnabledFeatures::BlinkGenPropertyTreesEnabled()) {
        Layer()->GetCompositedLayerMapping()->SetNeedsGraphicsLayerUpdate(
            kGraphicsLayerUpdateSubtree);
      }
      compositor->SetNeedsCompositingUpdate(
          kCompositingUpdateAfterGeometryChange);
    }
    if (Layer()->IsRootLayer()) {
      LocalFrame* frame = GetLayoutBox()->GetFrame();
      if (frame && frame->View() &&
          frame->View()->HasViewportConstrainedObjects()) {
        Layer()->SetNeedsCompositingInputsUpdate();
      }
    }
  } else {
    Layer()->SetNeedsCompositingInputsUpdate();
  }
}

int64_t OpLevelCostEstimator::CalculateOutputSize(const OpInfo& op_info,
                                                  bool* found_unknown_shapes) {
  int64_t total_output_size = 0;
  for (const auto& output : op_info.outputs()) {
    DataType dt = output.dtype();
    const auto& original_output_shape = output.shape();
    int64_t output_size = DataTypeSize(BaseType(dt));
    int num_dims = std::max(1, original_output_shape.dim_size());
    auto output_shape = MaybeGetMinimumShape(original_output_shape, num_dims,
                                             found_unknown_shapes);
    for (const auto& dim : output_shape.dim()) {
      output_size *= dim.size();
    }
    total_output_size += output_size;
    VLOG(1) << "Output Size: " << output_size
            << " Total Output Size:" << total_output_size;
  }
  return total_output_size;
}

static struct ucma_multicast* ucma_alloc_multicast(struct ucma_context* ctx) {
  struct ucma_multicast* mc;
  mc = kzalloc(sizeof(*mc), GFP_KERNEL);
  if (!mc) return NULL;
  mutex_lock(&mut);
  mc->id = idr_alloc(&multicast_idr, mc, 0, 0, GFP_KERNEL);
  mutex_unlock(&mut);
  if (mc->id < 0) goto error;
  mc->ctx = ctx;
  list_add_tail(&mc->list, &ctx->mc_list);
  return mc;
error:
  kfree(mc);
  return NULL;
}

static int tcp_v6_send_synack(const struct sock* sk, struct dst_entry* dst,
                              struct flowi* fl, struct request_sock* req,
                              struct tcp_fastopen_cookie* foc,
                              bool attach_req) {
  struct inet_request_sock* ireq = inet_rsk(req);
  struct ipv6_pinfo* np = inet6_sk(sk);
  struct flowi6* fl6 = &fl->u.ip6;
  struct sk_buff* skb;
  int err = -ENOMEM;
  if (!dst && (dst = inet6_csk_route_req(sk, fl6, req, IPPROTO_TCP)) == NULL)
    goto done;
  skb = tcp_make_synack(sk, dst, req, foc, attach_req);
  if (skb) {
    __tcp_v6_send_check(skb, &ireq->ir_v6_loc_addr, &ireq->ir_v6_rmt_addr);
    fl6->daddr = ireq->ir_v6_rmt_addr;
    if (np->repflow && ireq->pktopts)
      fl6->flowlabel = ip6_flowlabel(ipv6_hdr(ireq->pktopts));
    err = ip6_xmit(sk, skb, fl6, np->opt, np->tclass);
    err = net_xmit_eval(err);
  }
done:
  return err;
}

static void cli_session_setup_gensec_remote_done(struct tevent_req* subreq) {
  struct tevent_req* req = tevent_req_callback_data(subreq, struct tevent_req);
  struct cli_session_setup_gensec_state* state =
      tevent_req_data(req, struct cli_session_setup_gensec_state);
  NTSTATUS status;
  TALLOC_FREE(state->inbuf);
  TALLOC_FREE(state->recv_iov);
  status = cli_sesssetup_blob_recv(subreq, state, &state->blob_in,
                                   &state->inbuf, &state->recv_iov);
  TALLOC_FREE(subreq);
  data_blob_free(&state->blob_out);
  if (!NT_STATUS_IS_OK(status) &&
      !NT_STATUS_EQUAL(status, NT_STATUS_MORE_PROCESSING_REQUIRED)) {
    tevent_req_nterror(req, status);
    return;
  }
  if (NT_STATUS_IS_OK(status)) {
    struct smbXcli_session* session = NULL;
    bool is_guest = false;
    if (smbXcli_conn_protocol(state->cli->conn) >= PROTOCOL_SMB2_02) {
      session = state->cli->smb2.session;
    } else {
      session = state->cli->smb1.session;
    }
    is_guest = smbXcli_session_is_guest(session);
    if (is_guest) {
      state->blob_in = data_blob_null;
      state->local_ready = true;
    }
    state->remote_ready = true;
  }
  if (state->local_ready && state->remote_ready) {
    cli_session_setup_gensec_ready(req);
    return;
  }
  cli_session_setup_gensec_local_next(req);
}

Bool gf_sg_proto_field_is_sftime_offset(GF_Node* node, GF_FieldInfo* field) {
  u32 i;
  GF_Route* r;
  GF_ProtoInstance* inst;
  GF_FieldInfo inf;
  if (node->sgprivate->tag != TAG_ProtoNode) return 0;
  if (field->fieldType != GF_SG_VRML_SFTIME) return 0;
  inst = (GF_ProtoInstance*)node;
  i = 0;
  while ((r = (GF_Route*)gf_list_enum(inst->proto_interface->sub_graph->Routes,
                                      &i))) {
    if (!r->IS_route) continue;
    if (r->FromNode || (r->FromField.fieldIndex != field->fieldIndex)) continue;
    gf_node_get_field(r->ToNode, r->ToField.fieldIndex, &inf);
    if (r->ToNode->sgprivate->tag == TAG_ProtoNode)
      return gf_sg_proto_field_is_sftime_offset(r->ToNode, &inf);
    if (!stricmp(inf.name, "startTime") || !stricmp(inf.name, "stopTime"))
      return 1;
  }
  return 0;
}

