static int pfkey_register(struct sock* sk, struct sk_buff* skb,
                          const struct sadb_msg* hdr, void* const* ext_hdrs) {
  struct pfkey_sock* pfk = pfkey_sk(sk);
  struct sk_buff* supp_skb;
  if (hdr->sadb_msg_satype > SADB_SATYPE_MAX) return -EINVAL;
  if (hdr->sadb_msg_satype != SADB_SATYPE_UNSPEC) {
    if (pfk->registered & (1 << hdr->sadb_msg_satype)) return -EEXIST;
    pfk->registered |= (1 << hdr->sadb_msg_satype);
  }
  xfrm_probe_algs();
  supp_skb = compose_sadb_supported(hdr, GFP_KERNEL);
  if (!supp_skb) {
    if (hdr->sadb_msg_satype != SADB_SATYPE_UNSPEC)
      pfk->registered &= ~(1 << hdr->sadb_msg_satype);
    return -ENOBUFS;
  }
  pfkey_broadcast(supp_skb, GFP_KERNEL, BROADCAST_REGISTERED, sk, sock_net(sk));
  return 0;
}

static bool dump_fd_info(const char* dest_filename, char* source_filename,
                         int source_base_ofs, uid_t uid, gid_t gid) {
  FILE* fp = fopen(dest_filename, "w");
  if (!fp) return false;
  unsigned fd = 0;
  while (fd <= 99999) {
    sprintf(source_filename + source_base_ofs, "fd/%u", fd);
    char* name = malloc_readlink(source_filename);
    if (!name) break;
    fprintf(fp, "%u:%s\n", fd, name);
    free(name);
    sprintf(source_filename + source_base_ofs, "fdinfo/%u", fd);
    fd++;
    FILE* in = fopen(source_filename, "r");
    if (!in) continue;
    char buf[128];
    while (fgets(buf, sizeof(buf) - 1, in)) {
      char* eol = strchrnul(buf, '\n');
      eol[0] = '\n';
      eol[1] = '\0';
      fputs(buf, fp);
    }
    fclose(in);
  }
  const int dest_fd = fileno(fp);
  if (fchown(dest_fd, uid, gid) < 0) {
    perror_msg("Can't change '%s' ownership to %lu:%lu", dest_filename,
               (long)uid, (long)gid);
    fclose(fp);
    unlink(dest_filename);
    return false;
  }
  fclose(fp);
  return true;
}

static void ext4_end_io_dio(struct kiocb* iocb, loff_t offset, ssize_t size,
                            void* private) {
  ext4_io_end_t* io_end = iocb->private;
  struct workqueue_struct* wq;
  if (!io_end || !size) return;
  ext_debug(
      "ext4_end_io_dio(): io_end 0x%p"
      "for inode %lu, iocb 0x%p, offset %llu, size %llu\n",
      iocb->private, io_end->inode->i_ino, iocb, offset, size);
  if (io_end->flag != EXT4_IO_UNWRITTEN) {
    ext4_free_io_end(io_end);
    iocb->private = NULL;
    return;
  }
  io_end->offset = offset;
  io_end->size = size;
  wq = EXT4_SB(io_end->inode->i_sb)->dio_unwritten_wq;
  queue_work(wq, &io_end->work);
  list_add_tail(&io_end->list, &EXT4_I(io_end->inode)->i_completed_io_list);
  iocb->private = NULL;
}

int credential_from_url_gently(struct credential* c, const char* url,
                               int quiet) {
  const char *at, *colon, *cp, *slash, *host, *proto_end;
  credential_clear(c);
        proto_end = strstr(url, ":
	if (!proto_end)
		return 0;
	cp = proto_end + 3;
	at = strchr(cp, '@');
	colon = strchr(cp, ':');
	slash = strchrnul(cp, '/');
	if (!at || slash <= at) {
    host = cp;
	}
	else if (!colon || at <= colon) {
    c->username = url_decode_mem(cp, at - cp);
    host = at + 1;
	} else {
    c->username = url_decode_mem(cp, colon - cp);
    c->password = url_decode_mem(colon + 1, at - (colon + 1));
    host = at + 1;
	}
	if (proto_end - url > 0)
		c->protocol = xmemdupz(url, proto_end - url);
	c->host = url_decode_mem(host, slash - host);
	while (*slash == '/')
		slash++;
	if (*slash) {
    char* p;
    c->path = url_decode(slash);
    p = c->path + strlen(c->path) - 1;
    while (p > c->path && *p == '/') *p-- = '\0';
	}
	if (check_url_component(url, quiet, "username", c->username) < 0 ||
	    check_url_component(url, quiet, "password", c->password) < 0 ||
	    check_url_component(url, quiet, "protocol", c->protocol) < 0 ||
	    check_url_component(url, quiet, "host", c->host) < 0 ||
	    check_url_component(url, quiet, "path", c->path) < 0)
		return -1;
	return 0;
}

static void ext4_end_io_work(struct work_struct* work) {
  ext4_io_end_t* io = container_of(work, ext4_io_end_t, work);
  struct inode* inode = io->inode;
  int ret = 0;
  mutex_lock(&inode->i_mutex);
  ret = ext4_end_io_nolock(io);
  if (ret >= 0) {
    if (!list_empty(&io->list)) list_del_init(&io->list);
    ext4_free_io_end(io);
  }
  mutex_unlock(&inode->i_mutex);
}

stf_status ikev2parent_inI2outR2(struct msg_digest* md) {
  struct state* st = md->st;
  DBG(DBG_CONTROLMORE,
      DBG_log(
          "ikev2 parent inI2outR2: calculating g^{xy} in order to decrypt I2"));
  if (!md->chain[ISAKMP_NEXT_v2E]) {
    libreswan_log("R2 state should receive an encrypted payload");
    reset_globals();
    return STF_FATAL;
  }
  {
    struct dh_continuation* dh =
        alloc_thing(struct dh_continuation, "ikev2_inI2outR2 KE");
    stf_status e;
    dh->md = md;
    set_suspended(st, dh->md);
    pcrc_init(&dh->dh_pcrc);
    dh->dh_pcrc.pcrc_func = ikev2_parent_inI2outR2_continue;
    e = start_dh_v2(&dh->dh_pcrc, st, st->st_import, RESPONDER,
                    st->st_oakley.groupnum);
    if (e != STF_SUSPEND && e != STF_INLINE) {
      loglog(RC_CRYPTOFAILED, "system too busy");
      delete_state(st);
    }
    reset_globals();
    return e;
  }
}

