static int ext4_dax_fault(struct vm_area_struct* vma, struct vm_fault* vmf) {
  int result;
  handle_t* handle = NULL;
  struct super_block* sb = file_inode(vma->vm_file)->i_sb;
  bool write = vmf->flags & FAULT_FLAG_WRITE;
  if (write) {
    sb_start_pagefault(sb);
    file_update_time(vma->vm_file);
    handle = ext4_journal_start_sb(sb, EXT4_HT_WRITE_PAGE,
                                   EXT4_DATA_TRANS_BLOCKS(sb));
  }
  if (IS_ERR(handle))
    result = VM_FAULT_SIGBUS;
  else
    result = __dax_fault(vma, vmf, ext4_get_block_dax, ext4_end_io_unwritten);
  if (write) {
    if (!IS_ERR(handle)) ext4_journal_stop(handle);
    sb_end_pagefault(sb);
  }
  return result;
}

PJ_DEF(pj_status_t)
pjmedia_rtp_decode_rtp2(pjmedia_rtp_session* ses, const void* pkt, int pkt_len,
                        const pjmedia_rtp_hdr** hdr,
                        pjmedia_rtp_dec_hdr* dec_hdr, const void** payload,
                        unsigned* payloadlen) {
  int offset;
  PJ_UNUSED_ARG(ses);
  *hdr = (pjmedia_rtp_hdr*)pkt;
  if ((*hdr)->v != RTP_VERSION) {
    return PJMEDIA_RTP_EINVER;
  }
  offset = sizeof(pjmedia_rtp_hdr) + ((*hdr)->cc * sizeof(pj_uint32_t));
  if ((*hdr)->x) {
    if (offset + sizeof(pjmedia_rtp_ext_hdr) > (unsigned)pkt_len)
      return PJMEDIA_RTP_EINLEN;
    dec_hdr->ext_hdr = (pjmedia_rtp_ext_hdr*)(((pj_uint8_t*)pkt) + offset);
    dec_hdr->ext = (pj_uint32_t*)(dec_hdr->ext_hdr + 1);
    dec_hdr->ext_len = pj_ntohs((dec_hdr->ext_hdr)->length);
    offset += ((dec_hdr->ext_len + 1) * sizeof(pj_uint32_t));
  } else {
    dec_hdr->ext_hdr = NULL;
    dec_hdr->ext = NULL;
    dec_hdr->ext_len = 0;
  }
  if (offset > pkt_len) return PJMEDIA_RTP_EINLEN;
  *payload = ((pj_uint8_t*)pkt) + offset;
  *payloadlen = pkt_len - offset;
  if ((*hdr)->p && *payloadlen > 0) {
    pj_uint8_t pad_len;
    pad_len = ((pj_uint8_t*)(*payload))[*payloadlen - 1];
    if (pad_len <= *payloadlen) *payloadlen -= pad_len;
  }
  return PJ_SUCCESS;
}

static int get_filter(struct sss_certmap_ctx* ctx,
                      struct ldap_mapping_rule* parsed_mapping_rule,
                      struct sss_cert_content* cert_content, char** filter) {
  struct ldap_mapping_rule_comp* comp;
  char* result = NULL;
  char* expanded = NULL;
  int ret;
  result = talloc_strdup(ctx, "");
  if (result == NULL) {
    return ENOMEM;
  }
  for (comp = parsed_mapping_rule->list; comp != NULL; comp = comp->next) {
    if (comp->type == comp_string) {
      result = talloc_strdup_append(result, comp->val);
    } else if (comp->type == comp_template) {
      ret =
          expand_template(ctx, comp->parsed_template, cert_content, &expanded);
      if (ret != 0) {
        CM_DEBUG(ctx, "Failed to expanded template.");
        goto done;
      }
      result = talloc_strdup_append(result, expanded);
      talloc_free(expanded);
      expanded = NULL;
      if (result == NULL) {
        ret = ENOMEM;
        goto done;
      }
    } else {
      ret = EINVAL;
      CM_DEBUG(ctx, "Unsupported component type.");
      goto done;
    }
  }
  ret = 0;
done:
  talloc_free(expanded);
  if (ret == 0) {
    *filter = result;
  } else {
    talloc_free(result);
  }
  return ret;
}

bool ContainerNode::replaceChild(PassRefPtr<Node> newChild, Node* oldChild,
                                 ExceptionCode& ec, bool shouldLazyAttach) {
  ASSERT(refCount() || parentOrHostNode());
  RefPtr<Node> protect(this);
  ec = 0;
  if (oldChild == newChild) return true;
  checkReplaceChild(newChild.get(), oldChild, ec);
  if (ec) return false;
  if (!oldChild || oldChild->parentNode() != this) {
    ec = NOT_FOUND_ERR;
    return false;
  }
#if ENABLE(MUTATION_OBSERVERS)
  ChildListMutationScope mutation(this);
#endif
  RefPtr<Node> next = oldChild->nextSibling();
  RefPtr<Node> removedChild = oldChild;
  removeChild(oldChild, ec);
  if (ec) return false;
  if (next && (next->previousSibling() == newChild || next == newChild))
    return true;
  checkReplaceChild(newChild.get(), oldChild, ec);
  if (ec) return false;
  NodeVector targets;
  collectChildrenAndRemoveFromOldParent(newChild.get(), targets, ec);
  if (ec) return false;
  InspectorInstrumentation::willInsertDOMNode(document(), this);
  for (NodeVector::const_iterator it = targets.begin(); it != targets.end();
       ++it) {
    Node* child = it->get();
    if (next && next->parentNode() != this) break;
    if (child->parentNode()) break;
    treeScope()->adoptIfNeeded(child);
    forbidEventDispatch();
    if (next)
      insertBeforeCommon(next.get(), child);
    else
      appendChildToContainer(child, this);
    allowEventDispatch();
    updateTreeAfterInsertion(this, child, shouldLazyAttach);
  }
  dispatchSubtreeModifiedEvent();
  return true;
}

void CConfig::Write(CFile& File, unsigned int iIndentation) {
  CString sIndentation = CString(iIndentation, '\t');
  for (const auto& it : m_ConfigEntries) {
    for (const CString& sValue : it.second) {
      File.Write(sIndentation + it.first + " = " + sValue + "\n");
    }
  }
  for (const auto& it : m_SubConfigs) {
    for (const auto& it2 : it.second) {
      File.Write("\n");
      File.Write(sIndentation + "<" + it.first + " " + it2.first + ">\n");
      it2.second.m_pSubConfig->Write(File, iIndentation + 1);
      File.Write(sIndentation + "</" + it.first + ">\n");
    }
  }
}

MagickExport Image* ReadStream(const ImageInfo* image_info,
                               StreamHandler stream, ExceptionInfo* exception) {
  CacheMethods cache_methods;
  Image* image;
  ImageInfo* read_info;
  assert(image_info != (ImageInfo*)NULL);
  assert(image_info->signature == MagickCoreSignature);
  if (image_info->debug != MagickFalse)
    (void)LogMagickEvent(TraceEvent, GetMagickModule(), "%s",
                         image_info->filename);
  assert(exception != (ExceptionInfo*)NULL);
  assert(exception->signature == MagickCoreSignature);
  read_info = CloneImageInfo(image_info);
  read_info->cache = AcquirePixelCache(0);
  GetPixelCacheMethods(&cache_methods);
  cache_methods.get_virtual_pixel_handler = GetVirtualPixelStream;
  cache_methods.get_virtual_pixels_handler = GetVirtualPixelsStream;
  cache_methods.get_virtual_metacontent_from_handler =
      GetVirtualMetacontentFromStream;
  cache_methods.get_authentic_pixels_handler = GetAuthenticPixelsStream;
  cache_methods.queue_authentic_pixels_handler = QueueAuthenticPixelsStream;
  cache_methods.sync_authentic_pixels_handler = SyncAuthenticPixelsStream;
  cache_methods.get_authentic_pixels_from_handler =
      GetAuthenticPixelsFromStream;
  cache_methods.get_authentic_metacontent_from_handler =
      GetAuthenticMetacontentFromStream;
  cache_methods.get_one_virtual_pixel_from_handler =
      GetOneVirtualPixelFromStream;
  cache_methods.get_one_authentic_pixel_from_handler =
      GetOneAuthenticPixelFromStream;
  cache_methods.destroy_pixel_handler = DestroyPixelStream;
  SetPixelCacheMethods(read_info->cache, &cache_methods);
  read_info->stream = stream;
  image = ReadImage(read_info, exception);
