static long mem_seek(jas_stream_obj_t* obj, long offset, int origin) {
  jas_stream_memobj_t* m = (jas_stream_memobj_t*)obj;
  long newpos;
  JAS_DBGLOG(100, ("mem_seek(%p, %ld, %d)\n", obj, offset, origin));
  switch (origin) {
    case SEEK_SET:
      newpos = offset;
      break;
    case SEEK_END:
      newpos = m->len_ - offset;
      break;
    case SEEK_CUR:
      newpos = m->pos_ + offset;
      break;
    default:
      abort();
      break;
  }
  if (newpos < 0) {
    return -1;
  }
  m->pos_ = newpos;
  return m->pos_;
}

void CtcpParser::query(CoreNetwork* net, const QString& bufname,
                       const QString& ctcpTag, const QString& message) {
  QList<QByteArray> params;
  params << net->serverEncode(bufname)
         << lowLevelQuote(pack(net->serverEncode(ctcpTag),
                               net->userEncode(bufname, message)));
  static const char* splitter = " .,-!?";
  int maxSplitPos = message.count();
  int splitPos = maxSplitPos;
  int overrun = net->userInputHandler()->lastParamOverrun("PRIVMSG", params);
  if (overrun) {
    maxSplitPos = message.count() - overrun - 2;
    splitPos = -1;
    for (const char* splitChar = splitter; *splitChar != 0; splitChar++) {
      splitPos =
          qMax(splitPos, message.lastIndexOf(*splitChar, maxSplitPos) + 1);
    }
    if (splitPos <= 0 || splitPos > maxSplitPos) splitPos = maxSplitPos;
    params = params.mid(0, 1) << lowLevelQuote(
                 pack(net->serverEncode(ctcpTag),
                      net->userEncode(bufname, message.left(splitPos))));
  }
  net->putCmd("PRIVMSG", params);
  if (splitPos < message.count())
    query(net, bufname, ctcpTag, message.mid(splitPos));
}

static int __ptrace_may_access(struct task_struct* task, unsigned int mode) {
  const struct cred *cred = current_cred(), *tcred;
  int dumpable = 0;
  if (same_thread_group(task, current)) return 0;
  rcu_read_lock();
  tcred = __task_cred(task);
  if (uid_eq(cred->uid, tcred->euid) && uid_eq(cred->uid, tcred->suid) &&
      uid_eq(cred->uid, tcred->uid) && gid_eq(cred->gid, tcred->egid) &&
      gid_eq(cred->gid, tcred->sgid) && gid_eq(cred->gid, tcred->gid))
    goto ok;
  if (ptrace_has_cap(tcred->user_ns, mode)) goto ok;
  rcu_read_unlock();
  return -EPERM;
ok:
  rcu_read_unlock();
  smp_rmb();
  if (task->mm) dumpable = get_dumpable(task->mm);
  rcu_read_lock();
  if (!dumpable && !ptrace_has_cap(__task_cred(task)->user_ns, mode)) {
    rcu_read_unlock();
    return -EPERM;
  }
  rcu_read_unlock();
  return security_ptrace_access_check(task, mode);
}

TfLiteStatus ComputeDepthMultiplier(TfLiteContext* context,
                                    const TfLiteTensor* input,
                                    const TfLiteTensor* filter,
                                    int16* depth_multiplier) {
  int num_filter_channels = SizeOfDimension(filter, 3);
  int num_input_channels = SizeOfDimension(input, 3);
  TF_LITE_ENSURE_EQ(context, num_filter_channels % num_input_channels, 0);
  *depth_multiplier = num_filter_channels / num_input_channels;
  return kTfLiteOk;
}

void* pvPortMalloc(size_t xWantedSize) {
  void* pvReturn = NULL;
  static uint8_t* pucAlignedHeap = NULL;
#if (portBYTE_ALIGNMENT != 1)
  {
    if (xWantedSize & portBYTE_ALIGNMENT_MASK) {
      xWantedSize +=
          (portBYTE_ALIGNMENT - (xWantedSize & portBYTE_ALIGNMENT_MASK));
    }
  }
#endif
  vTaskSuspendAll();
  {
    if (pucAlignedHeap == NULL) {
      pucAlignedHeap =
          (uint8_t*)(((portPOINTER_SIZE_TYPE)&ucHeap[portBYTE_ALIGNMENT]) &
                     (~((portPOINTER_SIZE_TYPE)portBYTE_ALIGNMENT_MASK)));
    }
    if (((xNextFreeByte + xWantedSize) < configADJUSTED_HEAP_SIZE) &&
        ((xNextFreeByte + xWantedSize) > xNextFreeByte)) {
      pvReturn = pucAlignedHeap + xNextFreeByte;
      xNextFreeByte += xWantedSize;
    }
    traceMALLOC(pvReturn, xWantedSize);
  }
  (void)xTaskResumeAll();
#if (configUSE_MALLOC_FAILED_HOOK == 1)
  {
    if (pvReturn == NULL) {
      extern void vApplicationMallocFailedHook(void);
      vApplicationMallocFailedHook();
    }
  }
#endif
  return pvReturn;
}

