static int dynamicGetbuf(gdIOCtxPtr ctx, void* buf, int len) {
  int rlen, remain;
  dpIOCtxPtr dctx;
  dynamicPtr* dp;
  dctx = (dpIOCtxPtr)ctx;
  dp = dctx->dp;
  remain = dp->logicalSize - dp->pos;
  if (remain >= len) {
    rlen = len;
  } else {
    if (remain == 0) {
      return EOF;
    }
    rlen = remain;
  }
  memcpy(buf, (void*)((char*)dp->data + dp->pos), rlen);
  dp->pos += rlen;
  return rlen;
}

void SecurityManager::cancel_init() {
  SecurityException exception;
  if (local_participant_crypto_handle_) {
    crypto_plugin_->cryptokeyfactory()->unregister_participant(
        local_participant_crypto_handle_, exception);
  }
  if (crypto_plugin_ != nullptr) {
    delete crypto_plugin_;
    crypto_plugin_ = nullptr;
  }
  if (access_plugin_ != nullptr) {
    delete access_plugin_;
    access_plugin_ = nullptr;
  }
  delete authentication_plugin_;
  authentication_plugin_ = nullptr;
  disable_security_manager();
}

pci_emul_alloc_resource(uint64_t* baseptr, uint64_t limit, uint64_t size,
                        uint64_t* addr) {
  uint64_t base;
  assert((size & (size - 1)) == 0);
  base = roundup2(*baseptr, size);
  if (base + size <= limit) {
    *addr = base;
    *baseptr = base + size;
    return 0;
  } else
    return -1;
}

lys_getnext_data(const struct lys_module* mod, const struct lys_node* parent,
                 const char* name, int nam_len, LYS_NODE type,
                 const struct lys_node** ret) {
  const struct lys_node* node;
  assert((mod || parent) && name);
  assert(!(type & (LYS_AUGMENT | LYS_USES | LYS_GROUPING | LYS_CHOICE |
                   LYS_CASE | LYS_INPUT | LYS_OUTPUT)));
  if (!mod) {
    mod = lys_node_module(parent);
  }
  node = NULL;
  while ((node = lys_getnext(node, parent, mod, 0))) {
    if (!type || (node->nodetype & type)) {
      if (lys_node_module(node) != lys_main_module(mod)) {
        continue;
      }
      if (!strncmp(node->name, name, nam_len) && !node->name[nam_len]) {
        if (ret) {
          *ret = node;
        }
        return EXIT_SUCCESS;
      }
    }
  }
  return EXIT_FAILURE;
}

static int crypto_aead_report(struct sk_buff* skb, struct crypto_alg* alg) {
  struct crypto_report_aead raead;
  struct aead_alg* aead = &alg->cra_aead;
  snprintf(raead.type, CRYPTO_MAX_ALG_NAME, "%s", "aead");
  snprintf(raead.geniv, CRYPTO_MAX_ALG_NAME, "%s", aead->geniv ?: "<built-in>");
  raead.blocksize = alg->cra_blocksize;
  raead.maxauthsize = aead->maxauthsize;
  raead.ivsize = aead->ivsize;
  if (nla_put(skb, CRYPTOCFGA_REPORT_AEAD, sizeof(struct crypto_report_aead),
              &raead))
    goto nla_put_failure;
  return 0;
nla_put_failure:
  return -EMSGSIZE;
}

static void tcp_cwnd_reduction(struct sock* sk, const int prior_unsacked,
                               int fast_rexmit, int flag) {
  struct tcp_sock* tp = tcp_sk(sk);
  int sndcnt = 0;
  int delta = tp->snd_ssthresh - tcp_packets_in_flight(tp);
  int newly_acked_sacked = prior_unsacked - (tp->packets_out - tp->sacked_out);
  tp->prr_delivered += newly_acked_sacked;
  if (delta < 0) {
    u64 dividend =
        (u64)tp->snd_ssthresh * tp->prr_delivered + tp->prior_cwnd - 1;
    sndcnt = div_u64(dividend, tp->prior_cwnd) - tp->prr_out;
  } else if ((flag & FLAG_RETRANS_DATA_ACKED) && !(flag & FLAG_LOST_RETRANS)) {
    sndcnt = min_t(
        int, delta,
        max_t(int, tp->prr_delivered - tp->prr_out, newly_acked_sacked) + 1);
  } else {
    sndcnt = min(delta, newly_acked_sacked);
  }
  sndcnt = max(sndcnt, (fast_rexmit ? 1 : 0));
  tp->snd_cwnd = tcp_packets_in_flight(tp) + sndcnt;
}

struct lib_t* MACH0_(get_libs)(struct MACH0_(obj_t) * bin) {
