}

static int decode_attr_security_label(struct xdr_stream* xdr, uint32_t* bitmap,
                                      struct nfs4_label* label) {
  uint32_t pi = 0;
  uint32_t lfs = 0;
  __u32 len;
  __be32* p;
  int status = 0;
  if (unlikely(bitmap[2] & (FATTR4_WORD2_SECURITY_LABEL - 1U))) return -EIO;
  if (likely(bitmap[2] & FATTR4_WORD2_SECURITY_LABEL)) {
    p = xdr_inline_decode(xdr, 4);
    if (unlikely(!p)) return -EIO;
    lfs = be32_to_cpup(p++);
    p = xdr_inline_decode(xdr, 4);
    if (unlikely(!p)) return -EIO;
    pi = be32_to_cpup(p++);
    p = xdr_inline_decode(xdr, 4);
    if (unlikely(!p)) return -EIO;
    len = be32_to_cpup(p++);
    p = xdr_inline_decode(xdr, len);
    if (unlikely(!p)) return -EIO;
    if (len < NFS4_MAXLABELLEN) {
      if (label) {
        memcpy(label->label, p, len);
        label->len = len;
        label->pi = pi;
        label->lfs = lfs;
        status = NFS_ATTR_FATTR_V4_SECURITY_LABEL;
      }
      bitmap[2] &= ~FATTR4_WORD2_SECURITY_LABEL;
    } else
      printk(KERN_WARNING "%s: label too long (%u)!\n", __func__, len);
  }
  if (label && label->label)
    dprintk("%s: label=%s, len=%d, PI=%d, LFS=%d\n", __func__,
            (char*)label->label, label->len, label->pi, label->lfs);
  return status;
}

create_worker_threads(uint n) {
  comp_thread_ctxt_t* threads;
  uint i;
  threads = (comp_thread_ctxt_t*)my_malloc(sizeof(comp_thread_ctxt_t) * n,
                                           MYF(MY_FAE));
  for (i = 0; i < n; i++) {
    comp_thread_ctxt_t* thd = threads + i;
    thd->num = i + 1;
    thd->started = FALSE;
    thd->cancelled = FALSE;
    thd->data_avail = FALSE;
    thd->to = (char*)my_malloc(COMPRESS_CHUNK_SIZE + MY_QLZ_COMPRESS_OVERHEAD,
                               MYF(MY_FAE));
    if (pthread_mutex_init(&thd->ctrl_mutex, NULL) ||
        pthread_cond_init(&thd->ctrl_cond, NULL)) {
      goto err;
    }
    if (pthread_mutex_init(&thd->data_mutex, NULL) ||
        pthread_cond_init(&thd->data_cond, NULL)) {
      goto err;
    }
    pthread_mutex_lock(&thd->ctrl_mutex);
    if (pthread_create(&thd->id, NULL, compress_worker_thread_func, thd)) {
      msg("compress: pthread_create() failed: "
          "errno = %d",
          errno);
      pthread_mutex_unlock(&thd->ctrl_mutex);
      goto err;
    }
  }
  for (i = 0; i < n; i++) {
    comp_thread_ctxt_t* thd = threads + i;
    while (thd->started == FALSE)
      pthread_cond_wait(&thd->ctrl_cond, &thd->ctrl_mutex);
    pthread_mutex_unlock(&thd->ctrl_mutex);
  }
  return threads;
err:
  my_free(threads);
  return NULL;
}

R_API int r_core_bin_set_env(RCore* r, RBinFile* binfile) {
  RBinObject* binobj = binfile ? binfile->o : NULL;
  RBinInfo* info = binobj ? binobj->info : NULL;
  if (info) {
    int va = info->has_va;
    const char* arch = info->arch;
    ut16 bits = info->bits;
    ut64 baseaddr = r_bin_get_baddr(r->bin);
    r_config_set_i(r->config, "io.va",
                   (binobj->info) ? binobj->info->has_va : 0);
    r_config_set_i(r->config, "bin.baddr", baseaddr);
    r_config_set(r->config, "asm.arch", arch);
    r_config_set_i(r->config, "asm.bits", bits);
    r_config_set(r->config, "anal.arch", arch);
    if (info->cpu && *info->cpu) {
      r_config_set(r->config, "anal.cpu", info->cpu);
    } else {
      r_config_set(r->config, "anal.cpu", arch);
    }
    r_asm_use(r->assembler, arch);
    r_core_bin_info(r, R_CORE_BIN_ACC_ALL, R_CORE_BIN_SET, va, NULL, NULL);
    r_core_bin_set_cur(r, binfile);
    return true;
  }
  return false;
}

void M_LoadDefaults(void) {
  int i;
  int len;
  FILE* f;
  char def[80];
  char strparm[100];
  char* newstring;
  int parm;
  boolean isstring;
  numdefaults = sizeof(defaults) / sizeof(defaults[0]);
  for (i = 0; i < numdefaults; i++)
    *defaults[i].location = defaults[i].defaultvalue;
  i = M_CheckParm("-config");
  if (i && i < myargc - 1) {
    defaultfile = myargv[i + 1];
    printf("	default file: %s\n", defaultfile);
  } else
    defaultfile = basedefault;
  f = fopen(defaultfile, "r");
  if (f) {
    while (!feof(f)) {
      isstring = false;
      if (fscanf(f, "%79s %[^\n]\n", def, strparm) == 2) {
        if (strparm[0] == '"') {
          isstring = true;
          len = strlen(strparm);
          newstring = (char*)malloc(len);
          strparm[len - 1] = 0;
          strcpy(newstring, strparm + 1);
        } else if (strparm[0] == '0' && strparm[1] == 'x')
          sscanf(strparm + 2, "%x", &parm);
        else
          sscanf(strparm, "%i", &parm);
        for (i = 0; i < numdefaults; i++)
          if (!strcmp(def, defaults[i].name)) {
            if (!isstring)
              *defaults[i].location = parm;
            else
              *defaults[i].location = (int)newstring;
            break;
          }
      }
    }
    fclose(f);
  }
  for (i = 0; i < numdefaults; i++) {
    if (defaults[i].scantranslate) {
      parm = *defaults[i].location;
      defaults[i].untranslated = parm;
      *defaults[i].location = scantokey[parm];
    }
  }
}

bool Scanner::fill(size_t need) {
  if (eof) return false;
  pop_finished_files();
  DASSERT(bot <= tok && tok <= lim);
  size_t free = static_cast<size_t>(tok - bot);
  size_t copy = static_cast<size_t>(lim - tok);
  if (free >= need) {
    memmove(bot, tok, copy);
    shift_ptrs_and_fpos(-static_cast<ptrdiff_t>(free));
  } else {
    BSIZE += std::max(BSIZE, need);
    char* buf = new char[BSIZE + YYMAXFILL];
    if (!buf) fatal("out of memory");
    memmove(buf, tok, copy);
    shift_ptrs_and_fpos(buf - bot);
    delete[] bot;
    bot = buf;
    free = BSIZE - copy;
  }
  if (!read(free)) {
    eof = lim;
    memset(lim, 0, YYMAXFILL);
    lim += YYMAXFILL;
  }
  return true;
}

