static bool getCoverageFormat12(vector<uint32_t>& coverage, const uint8_t* data,
                                size_t size) {
  const size_t kNGroupsOffset = 12;
  const size_t kFirstGroupOffset = 16;
  const size_t kGroupSize = 12;
  const size_t kStartCharCodeOffset = 0;
  const size_t kEndCharCodeOffset = 4;
  if (kFirstGroupOffset > size) {
    return false;
  }
  uint32_t nGroups = readU32(data, kNGroupsOffset);
  if (kFirstGroupOffset + nGroups * kGroupSize > size) {
    return false;
  }
  for (uint32_t i = 0; i < nGroups; i++) {
    uint32_t groupOffset = kFirstGroupOffset + i * kGroupSize;
    uint32_t start = readU32(data, groupOffset + kStartCharCodeOffset);
    uint32_t end = readU32(data, groupOffset + kEndCharCodeOffset);
    addRange(coverage, start, end + 1);
  }
  return true;
}

static const gchar* fcwwn_name_res_str(const address* addr) {
  const guint8* addrp = (const guint8*)addr->data;
  int fmt;
  guint8 oui[6];
  fmt = (addrp[0] & 0xF0) >> 4;
  switch (fmt) {
    case FC_NH_NAA_IEEE:
    case FC_NH_NAA_IEEE_E:
      memcpy(oui, &addrp[2], 6);
      return get_manuf_name(oui);
    case FC_NH_NAA_IEEE_R:
      oui[0] = ((addrp[0] & 0x0F) << 4) | ((addrp[1] & 0xF0) >> 4);
      oui[1] = ((addrp[1] & 0x0F) << 4) | ((addrp[2] & 0xF0) >> 4);
      oui[2] = ((addrp[2] & 0x0F) << 4) | ((addrp[3] & 0xF0) >> 4);
      oui[3] = ((addrp[3] & 0x0F) << 4) | ((addrp[4] & 0xF0) >> 4);
      oui[4] = ((addrp[4] & 0x0F) << 4) | ((addrp[5] & 0xF0) >> 4);
      oui[5] = ((addrp[5] & 0x0F) << 4) | ((addrp[6] & 0xF0) >> 4);
      return get_manuf_name(oui);
  }
  return "";
}

