bool SecureSocket::verify_cert_fingerprint(
    const barrier::fs::path& fingerprint_db_path) {
  barrier::FingerprintData fingerprint_sha1, fingerprint_sha256;
  try {
    auto* cert = SSL_get_peer_certificate(m_ssl->m_ssl);
    fingerprint_sha1 =
        barrier::get_ssl_cert_fingerprint(cert, barrier::FingerprintType::SHA1);
    fingerprint_sha256 = barrier::get_ssl_cert_fingerprint(
        cert, barrier::FingerprintType::SHA256);
  } catch (const std::exception& e) {
    LOG((CLOG_ERR "%s", e.what()));
    return false;
  }
  LOG((CLOG_NOTE "server fingerprint (SHA1): %s (SHA256): %s",
       barrier::format_ssl_fingerprint(fingerprint_sha1.data).c_str(),
       barrier::format_ssl_fingerprint(fingerprint_sha256.data).c_str()));
  LOG((CLOG_NOTE "fingerprint_db_path: %s",
       fingerprint_db_path.u8string().c_str()));
  barrier::FingerprintDatabase db;
  db.read(fingerprint_db_path);
  if (!db.fingerprints().empty()) {
    LOG((CLOG_NOTE "Read %d fingerprints from: %s", db.fingerprints().size(),
         fingerprint_db_path.u8string().c_str()));
  } else {
    LOG((CLOG_NOTE "Could not read fingerprints from: %s",
         fingerprint_db_path.u8string().c_str()));
  }
  if (db.is_trusted(fingerprint_sha256)) {
    LOG((CLOG_NOTE "Fingerprint matches trusted fingerprint"));
    return true;
  } else {
    LOG((CLOG_NOTE "Fingerprint does not match trusted fingerprint"));
    return false;
  }
}

static void Process_ipfix_template_withdraw(exporter_ipfix_domain_t* exporter,
                                            void* DataPtr, uint32_t size_left,
                                            FlowSource_t* fs) {
  ipfix_template_record_t* ipfix_template_record;
  while (size_left) {
    uint32_t id;
    ipfix_template_record = (ipfix_template_record_t*)DataPtr;
    size_left -= 4;
    id = ntohs(ipfix_template_record->TemplateID);
    if (id == IPFIX_TEMPLATE_FLOWSET_ID) {
      remove_all_translation_tables(exporter);
      ReInitExtensionMapList(fs);
    } else {
      remove_translation_table(fs, exporter, id);
    }
    DataPtr = DataPtr + 4;
    if (size_left < 4) {
      dbg_printf("Skip %u bytes padding\n", size_left);
      size_left = 0;
    }
  }
}

static void ip_expire(unsigned long arg) {
  struct ipq* qp;
  struct net* net;
  qp = container_of((struct inet_frag_queue*)arg, struct ipq, q);
  net = container_of(qp->q.net, struct net, ipv4.frags);
  spin_lock(&qp->q.lock);
  if (qp->q.last_in & INET_FRAG_COMPLETE) goto out;
  ipq_kill(qp);
  IP_INC_STATS_BH(net, IPSTATS_MIB_REASMTIMEOUT);
  IP_INC_STATS_BH(net, IPSTATS_MIB_REASMFAILS);
  if ((qp->q.last_in & INET_FRAG_FIRST_IN) && qp->q.fragments != NULL) {
    struct sk_buff* head = qp->q.fragments;
    rcu_read_lock();
    head->dev = dev_get_by_index_rcu(net, qp->iif);
    if (!head->dev) goto out_rcu_unlock;
    if (qp->user == IP_DEFRAG_CONNTRACK_IN && !skb_dst(head)) {
      const struct iphdr* iph = ip_hdr(head);
      int err =
          ip_route_input(head, iph->daddr, iph->saddr, iph->tos, head->dev);
      if (unlikely(err)) goto out_rcu_unlock;
      if (skb_rtable(head)->rt_type != RTN_LOCAL) goto out_rcu_unlock;
    }
    icmp_send(head, ICMP_TIME_EXCEEDED, ICMP_EXC_FRAGTIME, 0);
  out_rcu_unlock:
    rcu_read_unlock();
  }
out:
  spin_unlock(&qp->q.lock);
  ipq_put(qp);
}

bool AuthNoneAuthorizeHandler::verify_authorizer(
    CephContext* cct, KeyStore* keys, bufferlist& authorizer_data,
    bufferlist& authorizer_reply, EntityName& entity_name, uint64_t& global_id,
    AuthCapsInfo& caps_info, CryptoKey& session_key, uint64_t* auid) {
  bufferlist::iterator iter = authorizer_data.begin();
  try {
    __u8 struct_v = 1;
    ::decode(struct_v, iter);
    ::decode(entity_name, iter);
    ::decode(global_id, iter);
  } catch (const buffer::error& err) {
    ldout(cct, 0)
        << "AuthNoneAuthorizeHandle::verify_authorizer() failed to decode"
        << dendl;
    return false;
  }
  caps_info.allow_all = true;
  return true;
}

