static const ut8* parse_die(const ut8* buf, const ut8* buf_end,
                            RzBinDwarfDebugInfo* info,
                            RzBinDwarfAbbrevDecl* abbrev,
                            RzBinDwarfCompUnitHdr* hdr, RzBinDwarfDie* die,
                            const ut8* debug_str, size_t debug_str_len,
                            bool big_endian) {
  size_t i;
  const char* comp_dir = NULL;
  ut64 line_info_offset = UT64_MAX;
  for (i = 0; i < abbrev->count - 1; i++) {
    memset(&die->attr_values[i], 0, sizeof(die->attr_values[i]));
    buf = parse_attr_value(buf, buf_end - buf, &abbrev->defs[i],
                           &die->attr_values[i], hdr, debug_str, debug_str_len,
                           big_endian);
    RzBinDwarfAttrValue* attribute = &die->attr_values[i];
    if (attribute->attr_name == DW_AT_comp_dir &&
        (attribute->attr_form == DW_FORM_strp ||
         attribute->attr_form == DW_FORM_string) &&
        attribute->string.content) {
      comp_dir = attribute->string.content;
    }
    if (attribute->attr_name == DW_AT_stmt_list) {
      if (attribute->kind == DW_AT_KIND_CONSTANT) {
        line_info_offset = attribute->uconstant;
      } else if (attribute->kind == DW_AT_KIND_REFERENCE) {
        line_info_offset = attribute->reference;
      }
    }
    die->count++;
  }
  if (comp_dir && line_info_offset != UT64_MAX) {
    char* name = strdup(comp_dir);
    if (name) {
      if (!ht_up_insert(info->line_info_offset_comp_dir, line_info_offset,
                        name)) {
        free(name);
      }
    }
  }
  return buf;
}

pf_remove_state(struct pf_state* st) {
  PF_ASSERT_LOCKED();
  if (st->timeout == PFTM_UNLINKED) return;
  st->timeout = PFTM_UNLINKED;
  pf_postprocess_addr(st);
  if (st->src.state == PF_TCPS_PROXY_DST) {
    pf_send_tcp(st->rule.ptr, st->key[PF_SK_WIRE]->af,
                &st->key[PF_SK_WIRE]->addr[1], &st->key[PF_SK_WIRE]->addr[0],
                st->key[PF_SK_WIRE]->port[1], st->key[PF_SK_WIRE]->port[0],
                st->src.seqhi, st->src.seqlo + 1, TH_RST | TH_ACK, 0, 0, 0, 1,
                st->tag, st->key[PF_SK_WIRE]->rdomain);
  }
  if (st->key[PF_SK_STACK]->proto == IPPROTO_TCP)
    pf_set_protostate(st, PF_PEER_BOTH, TCPS_CLOSED);
  RBT_REMOVE(pf_state_tree_id, &tree_id, st);
#if NPFLOW > 0
  if (st->state_flags & PFSTATE_PFLOW) export_pflow(st);
#endif
#if NPFSYNC > 0
  pfsync_delete_state(st);
#endif
  pf_src_tree_remove_state(st);
  pf_detach_state(st);
}

void DoCanonicalizeRef(const CHAR* spec, const Component& ref,
                       CanonOutput* output, Component* out_ref) {
  if (ref.len < 0) {
    *out_ref = Component();
    return;
  }
  output->push_back('#');
  out_ref->begin = output->length();
  int end = ref.end();
  for (int i = ref.begin; i < end; i++) {
    if (spec[i] == 0) {
      continue;
    } else if (static_cast<UCHAR>(spec[i]) < 0x20) {
      AppendEscapedChar(static_cast<unsigned char>(spec[i]), output);
    } else if (static_cast<UCHAR>(spec[i]) < 0x80) {
      output->push_back(static_cast<char>(spec[i]));
    } else {
      unsigned code_point;
      ReadUTFChar(spec, &i, end, &code_point);
      AppendUTF8Value(code_point, output);
    }
  }
  out_ref->len = output->length() - out_ref->begin;
}

static inline unsigned char unimap_bsearch(const uni_to_enc* table,
                                           unsigned code_key_a, size_t num) {
  const uni_to_enc *l = table, *h = &table[num - 1], *m;
  unsigned short code_key;
  if (code_key_a > 0xFFFFU) return 0;
  code_key = (unsigned short)code_key_a;
  while (l <= h) {
    m = l + (h - l) / 2;
    if (code_key < m->un_code_point)
      h = m - 1;
    else if (code_key > m->un_code_point)
      l = m + 1;
    else
      return m->cs_code;
  }
  return 0;
}

void yajl_string_decode(yajl_buf buf, const unsigned char* str,
                        unsigned int len) {
  unsigned int beg = 0;
  unsigned int end = 0;
  while (end < len) {
    if (str[end] == '\\') {
      char utf8Buf[5];
      const char* unescaped = "?";
      yajl_buf_append(buf, str + beg, end - beg);
      switch (str[++end]) {
        case 'r':
          unescaped = "\r";
          break;
        case 'n':
          unescaped = "\n";
          break;
        case '\\':
          unescaped = "\\";
          break;
        case '/':
          unescaped = "/";
          break;
        case '"':
          unescaped = "\"";
          break;
        case 'f':
          unescaped = "\f";
          break;
        case 'b':
          unescaped = "\b";
          break;
        case 't':
          unescaped = "\t";
          break;
        case 'u': {
          unsigned int codepoint = 0;
          hexToDigit(&codepoint, str + ++end);
          end += 3;
          if ((codepoint & 0xFC00) == 0xD800) {
            end++;
            if (str[end] == '\\' && str[end + 1] == 'u') {
              unsigned int surrogate = 0;
              hexToDigit(&surrogate, str + end + 2);
              codepoint = (((codepoint & 0x3F) << 10) |
                           ((((codepoint >> 6) & 0xF) + 1) << 16) |
                           (surrogate & 0x3FF));
              end += 5;
            } else {
              unescaped = "?";
              break;
            }
          }
          Utf32toUtf8(codepoint, utf8Buf);
          unescaped = utf8Buf;
          if (codepoint == 0) {
            yajl_buf_append(buf, unescaped, 1);
            beg = ++end;
            continue;
          }
          break;
        }
        default:
          assert("this should never happen" == NULL);
      }
      yajl_buf_append(buf, unescaped, (unsigned int)strlen(unescaped));
      beg = ++end;
    } else {
      end++;
    }
  }
  yajl_buf_append(buf, str + beg, end - beg);
}

bool kvm_irq_delivery_to_apic_fast(struct kvm* kvm, struct kvm_lapic* src,
                                   struct kvm_lapic_irq* irq, int* r,
                                   struct dest_map* dest_map) {
  struct kvm_apic_map* map;
  unsigned long bitmap;
  struct kvm_lapic** dst = NULL;
  int i;
  bool ret;
  *r = -1;
  if (irq->shorthand == APIC_DEST_SELF) {
    *r = kvm_apic_set_irq(src->vcpu, irq, dest_map);
    return true;
  }
  rcu_read_lock();
  map = rcu_dereference(kvm->arch.apic_map);
  ret = kvm_apic_map_get_dest_lapic(kvm, &src, irq, map, &dst, &bitmap);
  if (ret) {
    *r = 0;
    for_each_set_bit(i, &bitmap, 16) {
      if (!dst[i]) continue;
      *r += kvm_apic_set_irq(dst[i]->vcpu, irq, dest_map);
    }
  }
  rcu_read_unlock();
  return ret;
}

snmp_mib_add(snmp_mib_resource_t* new_resource) {
  snmp_mib_resource_t* resource;
  for (resource = list_head(snmp_mib); resource; resource = resource->next) {
    if (snmp_oid_cmp_oid(resource->oid, new_resource->oid) > 0) {
      break;
    }
  }
  if (resource == NULL) {
    list_add(snmp_mib, new_resource);
  } else {
    list_insert(snmp_mib, new_resource, resource);
  }
#if LOG_LEVEL == LOG_LEVEL_DBG
  LOG_DBG("Table after insert.\n");
  for (resource = list_head(snmp_mib); resource; resource = resource->next) {
    snmp_oid_print(resource->oid);
  }
#endif
}

file_continue(i_ctx_t* i_ctx_p) {
  os_ptr op = osp;
  es_ptr pscratch = esp - 2;
  file_enum* pfen = r_ptr(esp - 1, file_enum);
  int devlen = esp[-3].value.intval;
  gx_io_device* iodev = r_ptr(esp - 4, gx_io_device);
  uint len = r_size(pscratch);
  uint code;
  if (len < devlen) return_error(gs_error_rangecheck);
  memcpy((char*)pscratch->value.bytes, iodev->dname, devlen);
  code = iodev->procs.enumerate_next(
      pfen, (char*)pscratch->value.bytes + devlen, len - devlen);
  if (code == ~(uint)0) {
    esp -= 5;
    return o_pop_estack;
  } else if (code > len)
    return_error(gs_error_rangecheck);
  else {
    push(1);
    ref_assign(op, pscratch);
    r_set_size(op, code + devlen);
    push_op_estack(file_continue);
    *++esp = pscratch[2];
    return o_push_estack;
  }
}

