static struct ucounts* get_ucounts(struct user_namespace* ns, kuid_t uid) {
  struct hlist_head* hashent = ucounts_hashentry(ns, uid);
  struct ucounts *ucounts, *new;
  spin_lock_irq(&ucounts_lock);
  ucounts = find_ucounts(ns, uid, hashent);
  if (!ucounts) {
    spin_unlock_irq(&ucounts_lock);
    new = kzalloc(sizeof(*new), GFP_KERNEL);
    if (!new) return NULL;
    new->ns = ns;
    new->uid = uid;
    atomic_set(&new->count, 0);
    spin_lock_irq(&ucounts_lock);
    ucounts = find_ucounts(ns, uid, hashent);
    if (ucounts) {
      kfree(new);
    } else {
      hlist_add_head(&new->node, hashent);
      ucounts = new;
    }
  }
  if (!atomic_add_unless(&ucounts->count, 1, INT_MAX)) ucounts = NULL;
  spin_unlock_irq(&ucounts_lock);
  return ucounts;
}

void Compute(OpKernelContext* ctx) override {
  const Tensor& shape_t = ctx->input(0);
  const Tensor& rate_t = ctx->input(1);
  TensorShape samples_shape;
  OP_REQUIRES_OK(ctx, tensor::MakeShape(shape_t, &samples_shape));
  const int64_t num_samples = samples_shape.num_elements();
  samples_shape.AppendShape(rate_t.shape());
  Tensor* samples_t = nullptr;
  OP_REQUIRES_OK(ctx, ctx->allocate_output(0, samples_shape, &samples_t));
  if (num_samples == 0) return;
  const auto rate_flat = rate_t.flat<T>().data();
  const int64_t num_rate = rate_t.NumElements();
  auto samples_flat = samples_t->flat<U>().data();
  random::PhiloxRandom rng = generator_.ReserveRandomOutputs(
      num_samples * num_rate, kReservedSamplesPerOutput);
  functor::PoissonFunctor<CPUDevice, T, U>()(
      ctx, ctx->eigen_device<CPUDevice>(), rate_flat, num_rate, num_samples,
      rng, samples_flat);
}

decode_rt_routing_info(netdissect_options* ndo, const u_char* pptr, char* buf,
                       u_int buflen) {
  uint8_t route_target[8];
  u_int plen;
  ND_TCHECK(pptr[0]);
  plen = pptr[0];
  if (0 == plen) {
    snprintf(buf, buflen, "default route target");
    return 1;
  }
  if (32 > plen) return -1;
  plen -= 32;
  if (64 < plen) return -1;
  memset(&route_target, 0, sizeof(route_target));
  ND_TCHECK2(pptr[1], (plen + 7) / 8);
  memcpy(&route_target, &pptr[1], (plen + 7) / 8);
  if (plen % 8) {
    ((u_char*)&route_target)[(plen + 7) / 8 - 1] &=
        ((0xff00 >> (plen % 8)) & 0xff);
  }
  snprintf(buf, buflen, "origin AS: %s, route target %s",
           as_printf(ndo, astostr, sizeof(astostr), EXTRACT_32BITS(pptr + 1)),
           bgp_vpn_rd_print(ndo, (u_char*)&route_target));
  return 5 + (plen + 7) / 8;
trunc:
  return -2;
}

