append_utf8_value(const unsigned char* value, size_t length,
                  struct stringbuf* sb) {
  unsigned char tmp[6];
  const unsigned char* s;
  size_t n;
  int i, nmore;
  if (length && (*value == ' ' || *value == '#')) {
    tmp[0] = '\\';
    tmp[1] = *value;
    put_stringbuf_mem(sb, tmp, 2);
    value++;
    length--;
  }
  if (length && value[length - 1] == ' ') {
    tmp[0] = '\\';
    tmp[1] = ' ';
    put_stringbuf_mem(sb, tmp, 2);
    length--;
  }
  for (s = value, n = 0;;) {
    for (value = s; n < length && !(*s & 0x80); n++, s++)
      for (value = s; n < length && !(*s & 0x80); n++, s++);
    append_quoted(sb, value, s - value, 0);
    if (n == length) return;
    assert((*s & 0x80));
    if ((*s & 0xe0) == 0xc0)
      nmore = 1;
    else if ((*s & 0xf0) == 0xe0)
      nmore = 2;
    else if ((*s & 0xf8) == 0xf0)
      nmore = 3;
    else if ((*s & 0xfc) == 0xf8)
      nmore = 4;
    else if ((*s & 0xfe) == 0xfc)
      nmore = 5;
    else
      nmore = 5;
    if (n + nmore > length) nmore = length - n;
    tmp[0] = *s++;
    n++;
    for (i = 1; i <= nmore; i++) {
      if ((*s & 0xc0) != 0x80) break;
      tmp[i] = *s++;
      n++;
    }
    put_stringbuf_mem(sb, tmp, i);
  }
}

static void wdm_in_callback(struct urb* urb) {
  struct wdm_device* desc = urb->context;
  int status = urb->status;
  spin_lock(&desc->iuspin);
  clear_bit(WDM_RESPONDING, &desc->flags);
  if (status) {
    switch (status) {
      case -ENOENT:
        dev_dbg(&desc->intf->dev, "nonzero urb status received: -ENOENT");
        goto skip_error;
      case -ECONNRESET:
        dev_dbg(&desc->intf->dev, "nonzero urb status received: -ECONNRESET");
        goto skip_error;
      case -ESHUTDOWN:
        dev_dbg(&desc->intf->dev, "nonzero urb status received: -ESHUTDOWN");
        goto skip_error;
      case -EPIPE:
        dev_err(&desc->intf->dev, "nonzero urb status received: -EPIPE\n");
        break;
      default:
        dev_err(&desc->intf->dev, "Unexpected error %d\n", status);
        break;
    }
  }
  desc->rerr = status;
  desc->reslength = urb->actual_length;
  memmove(desc->ubuf + desc->length, desc->inbuf, desc->reslength);
  desc->length += desc->reslength;
skip_error:
  wake_up(&desc->wait);
  set_bit(WDM_READ, &desc->flags);
  spin_unlock(&desc->iuspin);
}

