__ext4_set_acl(handle_t* handle, struct inode* inode, int type,
               struct posix_acl* acl) {
  int name_index;
  void* value = NULL;
  size_t size = 0;
  int error;
  switch (type) {
    case ACL_TYPE_ACCESS:
      name_index = EXT4_XATTR_INDEX_POSIX_ACL_ACCESS;
      if (acl) {
        error = posix_acl_equiv_mode(acl, &inode->i_mode);
        if (error < 0)
          return error;
        else {
          inode->i_ctime = ext4_current_time(inode);
          ext4_mark_inode_dirty(handle, inode);
          if (error == 0) acl = NULL;
        }
      }
      break;
    case ACL_TYPE_DEFAULT:
      name_index = EXT4_XATTR_INDEX_POSIX_ACL_DEFAULT;
      if (!S_ISDIR(inode->i_mode)) return acl ? -EACCES : 0;
      break;
    default:
      return -EINVAL;
  }
  if (acl) {
    value = ext4_acl_to_disk(acl, &size);
    if (IS_ERR(value)) return (int)PTR_ERR(value);
  }
  error = ext4_xattr_set_handle(handle, inode, name_index, "", value, size, 0);
  kfree(value);
  if (!error) set_cached_acl(inode, type, acl);
  return error;
}

static void dtls1_clear_queues(SSL* s) {
  pitem* item = NULL;
  hm_fragment* frag = NULL;
  DTLS1_RECORD_DATA* rdata;
  while ((item = pqueue_pop(s->d1->unprocessed_rcds.q)) != NULL) {
    rdata = (DTLS1_RECORD_DATA*)item->data;
    if (rdata->rbuf.buf) {
      OPENSSL_free(rdata->rbuf.buf);
    }
    OPENSSL_free(item->data);
    pitem_free(item);
  }
  while ((item = pqueue_pop(s->d1->processed_rcds.q)) != NULL) {
    rdata = (DTLS1_RECORD_DATA*)item->data;
    if (rdata->rbuf.buf) {
      OPENSSL_free(rdata->rbuf.buf);
    }
    OPENSSL_free(item->data);
    pitem_free(item);
  }
  while ((item = pqueue_pop(s->d1->buffered_messages)) != NULL) {
    frag = (hm_fragment*)item->data;
    OPENSSL_free(frag->fragment);
    OPENSSL_free(frag);
    pitem_free(item);
  }
  while ((item = pqueue_pop(s->d1->sent_messages)) != NULL) {
    frag = (hm_fragment*)item->data;
    OPENSSL_free(frag->fragment);
    OPENSSL_free(frag);
    pitem_free(item);
  }
  while ((item = pqueue_pop(s->d1->buffered_app_data.q)) != NULL) {
    frag = (hm_fragment*)item->data;
    OPENSSL_free(frag->fragment);
    OPENSSL_free(frag);
    pitem_free(item);
  }
}

int input_set_keycode(struct input_dev* dev,
                      const struct input_keymap_entry* ke) {
  unsigned long flags;
  unsigned int old_keycode;
  int retval;
  if (ke->keycode > KEY_MAX) return -EINVAL;
  spin_lock_irqsave(&dev->event_lock, flags);
  retval = dev->setkeycode(dev, ke, &old_keycode);
  if (retval) goto out;
  __clear_bit(KEY_RESERVED, dev->keybit);
  if (test_bit(EV_KEY, dev->evbit) &&
      !is_event_supported(old_keycode, dev->keybit, KEY_MAX) &&
      __test_and_clear_bit(old_keycode, dev->key)) {
    struct input_value vals[] = {{EV_KEY, old_keycode, 0}, input_value_sync};
    input_pass_values(dev, vals, ARRAY_SIZE(vals));
  }
out:
  spin_unlock_irqrestore(&dev->event_lock, flags);
  return retval;
}

gdImageFillToBorder(gdImagePtr im, int x, int y, int border, int color) {
  int lastBorder;
  int leftLimit, rightLimit;
  int i;
  leftLimit = (-1);
  if (border < 0) {
    return;
  }
  for (i = x; (i >= 0); i--) {
    if (gdImageGetPixel(im, i, y) == border) {
      break;
    }
    gdImageSetPixel(im, i, y, color);
    leftLimit = i;
  }
  if (leftLimit == (-1)) {
    return;
  }
  rightLimit = x;
  for (i = (x + 1); (i < im->sx); i++) {
    if (gdImageGetPixel(im, i, y) == border) {
      break;
    }
    gdImageSetPixel(im, i, y, color);
    rightLimit = i;
  }
  if (y > 0) {
    lastBorder = 1;
    for (i = leftLimit; (i <= rightLimit); i++) {
      int c;
      c = gdImageGetPixel(im, i, y - 1);
      if (lastBorder) {
        if ((c != border) && (c != color)) {
          gdImageFillToBorder(im, i, y - 1, border, color);
          lastBorder = 0;
        }
      } else if ((c == border) || (c == color)) {
        lastBorder = 1;
      }
    }
  }
  if (y < ((im->sy) - 1)) {
    lastBorder = 1;
    for (i = leftLimit; (i <= rightLimit); i++) {
      int c;
      c = gdImageGetPixel(im, i, y + 1);
      if (lastBorder) {
        if ((c != border) && (c != color)) {
          gdImageFillToBorder(im, i, y + 1, border, color);
          lastBorder = 0;
        }
      } else if ((c == border) || (c == color)) {
        lastBorder = 1;
      }
    }
  }
}

renderCoTable(struct table* tbl, int maxlimit) {
  struct readbuffer obuf;
  struct html_feed_environ h_env;
  struct environment envs[MAX_ENV_LEVEL];
  struct table* t;
  int i, col, row;
  int indent, maxwidth;
  for (i = 0; i < tbl->ntable; i++) {
    t = tbl->tables[i].ptr;
    col = tbl->tables[i].col;
    row = tbl->tables[i].row;
    indent = tbl->tables[i].indent;
    init_henv(&h_env, &obuf, envs, MAX_ENV_LEVEL, tbl->tables[i].buf,
              get_spec_cell_width(tbl, row, col), indent);
    check_row(tbl, row);
    if (h_env.limit > maxlimit) h_env.limit = maxlimit;
    if (t->total_width == 0)
      maxwidth = h_env.limit - indent;
    else if (t->total_width > 0)
      maxwidth = t->total_width;
    else
      maxwidth = t->total_width = -t->total_width * h_env.limit / 100;
    renderTable(t, maxwidth, &h_env);
  }
}

static inline int hpel_motion(MpegEncContext* s, uint8_t* dest, uint8_t* src,
                              int src_x, int src_y, op_pixels_func* pix_op,
                              int motion_x, int motion_y) {
  int dxy = 0;
  int emu = 0;
  src_x += motion_x >> 1;
  src_y += motion_y >> 1;
  src_x = av_clip(src_x, -16, s->width);
  if (src_x != s->width) dxy |= motion_x & 1;
  src_y = av_clip(src_y, -16, s->height);
  if (src_y != s->height) dxy |= (motion_y & 1) << 1;
  src += src_y * s->linesize + src_x;
  if (s->unrestricted_mv) {
    if ((unsigned)src_x > FFMAX(s->h_edge_pos - (motion_x & 1) - 8, 0) ||
        (unsigned)src_y > FFMAX(s->v_edge_pos - (motion_y & 1) - 8, 0)) {
      s->vdsp.emulated_edge_mc(s->sc.edge_emu_buffer, src, s->linesize,
                               s->linesize, 9, 9, src_x, src_y, s->h_edge_pos,
                               s->v_edge_pos);
      src = s->sc.edge_emu_buffer;
      emu = 1;
    }
  }
  pix_op[dxy](dest, src, s->linesize, 8);
  return emu;
}

static int amdgpu_cs_wait_all_fences(struct amdgpu_device* adev,
                                     struct drm_file* filp,
                                     union drm_amdgpu_wait_fences* wait,
                                     struct drm_amdgpu_fence* fences) {
  uint32_t fence_count = wait->in.fence_count;
  unsigned int i;
  long r = 1;
  for (i = 0; i < fence_count; i++) {
    struct dma_fence* fence;
    unsigned long timeout = amdgpu_gem_timeout(wait->in.timeout_ns);
    fence = amdgpu_cs_get_fence(adev, filp, &fences[i]);
    if (IS_ERR(fence))
      return PTR_ERR(fence);
    else if (!fence)
      continue;
    r = dma_fence_wait_timeout(fence, true, timeout);
    dma_fence_put(fence);
    if (r < 0) return r;
    if (r == 0) break;
    if (fence->error) return fence->error;
  }
  memset(wait, 0, sizeof(*wait));
  wait->out.status = (r > 0);
  return 0;
}

