B44Compressor::B44Compressor(const Header& hdr, size_t maxScanLineSize,
                             size_t numScanLines, bool optFlatFields)
    : Compressor(hdr),
      _maxScanLineSize(maxScanLineSize),
      _optFlatFields(optFlatFields),
      _format(XDR),
      _numScanLines(numScanLines),
      _tmpBuffer(0),
      _outBuffer(0),
      _numChans(0),
      _channels(hdr.channels()),
      _channelData(0) {
  (void)_maxScanLineSize;
  _tmpBuffer = new unsigned short[checkArraySize(
      uiMult(maxScanLineSize, numScanLines), sizeof(unsigned short))];
  const ChannelList& channels = header().channels();
  int numHalfChans = 0;
  for (ChannelList::ConstIterator c = channels.begin(); c != channels.end();
       ++c) {
    assert(pixelTypeSize(c.channel().type) % pixelTypeSize(HALF) == 0);
    ++_numChans;
    if (c.channel().type == HALF) ++numHalfChans;
  }
  size_t padding = 12 * numHalfChans * (numScanLines + 3) / 4;
  _outBuffer = new char[uiAdd(uiMult(maxScanLineSize, numScanLines), padding)];
  _channelData = new ChannelData[_numChans];
  int i = 0;
  for (ChannelList::ConstIterator c = channels.begin(); c != channels.end();
       ++c, ++i) {
    _channelData[i].ys = c.channel().ySampling;
    _channelData[i].type = c.channel().type;
    _channelData[i].pLinear = c.channel().pLinear;
    _channelData[i].size =
        pixelTypeSize(c.channel().type) / pixelTypeSize(HALF);
  }
  const Box2i& dataWindow = hdr.dataWindow();
  _minX = dataWindow.min.x;
  _maxX = dataWindow.max.x;
  _maxY = dataWindow.max.y;
  assert(sizeof(unsigned short) == pixelTypeSize(HALF));
  if (_numChans == numHalfChans) _format = NATIVE;
}

void Compute(OpKernelContext* context) override {
  OpInputList ragged_nested_splits_in;
  OP_REQUIRES_OK(context, context->input_list("rt_nested_splits",
                                              &ragged_nested_splits_in));
  const int ragged_nested_splits_len = ragged_nested_splits_in.size();
  RaggedTensorVariant batched_ragged_input;
  batched_ragged_input.set_values(context->input(ragged_nested_splits_len));
  batched_ragged_input.mutable_nested_splits()->reserve(
      ragged_nested_splits_len);
  for (int i = 0; i < ragged_nested_splits_len; i++) {
    batched_ragged_input.append_splits(ragged_nested_splits_in[i]);
  }
  if (!batched_input_) {
    Tensor* encoded_scalar;
    OP_REQUIRES_OK(
        context, context->allocate_output(0, TensorShape({}), &encoded_scalar));
    encoded_scalar->scalar<Variant>()() = std::move(batched_ragged_input);
    return;
  }
  std::vector<RaggedTensorVariant> unbatched_ragged_input;
  OP_REQUIRES_OK(context, UnbatchRaggedZerothDim<VALUE_TYPE, SPLIT_TYPE>(
                              batched_ragged_input, &unbatched_ragged_input));
  Tensor* encoded_vector;
  int output_size = unbatched_ragged_input.size();
  OP_REQUIRES_OK(context, context->allocate_output(
                              0, TensorShape({output_size}), &encoded_vector));
  auto encoded_vector_t = encoded_vector->vec<Variant>();
  for (int i = 0; i < output_size; i++) {
    encoded_vector_t(i) = unbatched_ragged_input[i];
  }
}

resolve_list_keys(struct lys_node_list* list, const char* keys_str) {
  int i, len, rc;
  const char* value;
  char* s = NULL;
  struct ly_ctx* ctx = list->module->ctx;
  for (i = 0; i < list->keys_size; ++i) {
    assert(keys_str);
    if (!list->child) {
      LOGVAL(ctx, LYE_INRESOLV, LY_VLOG_LYS, list, "list keys", keys_str);
      return EXIT_FAILURE;
    }
    if ((value = strpbrk(keys_str, " \t\n"))) {
      len = value - keys_str;
      while (isspace(value[0])) {
        value++;
      }
    } else {
      len = strlen(keys_str);
    }
    rc = lys_getnext_data(lys_node_module((struct lys_node*)list),
                          (struct lys_node*)list, keys_str, len, LYS_LEAF,
                          (const struct lys_node**)&list->keys[i]);
    if (rc) {
      LOGVAL(ctx, LYE_INRESOLV, LY_VLOG_LYS, list, "list key", keys_str);
      return EXIT_FAILURE;
    }
    if (check_key(list, i, keys_str, len)) {
      return -1;
    }
    if (lyp_check_status(list->flags, list->module, list->name,
                         list->keys[i]->flags, list->keys[i]->module,
                         list->keys[i]->name,
                         (struct lys_node*)list->keys[i])) {
      return -1;
    }
    if (list->keys[i]->dflt) {
      assert(log_opt == ILO_STORE);
      log_opt = ILO_LOG;
      LOGWRN(ctx,
             "Default value \"%s\" in the list key \"%s\" is ignored. (%s)",
             list->keys[i]->dflt, list->keys[i]->name,
             s = lys_path((struct lys_node*)list, LYS_PATH_FIRST_PREFIX));
      log_opt = ILO_STORE;
      free(s);
    }
    while (value && isspace(value[0])) {
      value++;
    }
    keys_str = value;
  }
  return EXIT_SUCCESS;
}

