static int parse_video_info(AVIOContext* pb, AVStream* st) {
  uint16_t size_asf;
  uint32_t size_bmp;
  unsigned int tag;
  st->codecpar->width = avio_rl32(pb);
  st->codecpar->height = avio_rl32(pb);
  avio_skip(pb, 1);
  size_asf = avio_rl16(pb);
  tag = ff_get_bmp_header(pb, st, &size_bmp);
  st->codecpar->codec_tag = tag;
  st->codecpar->codec_id = ff_codec_get_id(ff_codec_bmp_tags, tag);
  size_bmp = FFMAX(size_asf, size_bmp);
  if (size_bmp > BMP_HEADER_SIZE) {
    int ret;
    st->codecpar->extradata_size = size_bmp - BMP_HEADER_SIZE;
    if (!(st->codecpar->extradata = av_malloc(st->codecpar->extradata_size +
                                              AV_INPUT_BUFFER_PADDING_SIZE))) {
      st->codecpar->extradata_size = 0;
      return AVERROR(ENOMEM);
    }
    memset(st->codecpar->extradata + st->codecpar->extradata_size, 0,
           AV_INPUT_BUFFER_PADDING_SIZE);
    if ((ret = avio_read(pb, st->codecpar->extradata,
                         st->codecpar->extradata_size)) < 0)
      return ret;
  }
  return 0;
}

int sub__add(struct mosquitto* context, const char* sub, uint8_t qos,
             uint32_t identifier, int options) {
  int rc = 0;
  struct mosquitto__subhier* subhier;
  const char* sharename = NULL;
  char* local_sub;
  char** topics;
  size_t topiclen;
  assert(sub);
  rc = sub__topic_tokenise(sub, &local_sub, &topics, &sharename);
  if (rc) return rc;
  topiclen = strlen(topics[0]);
  if (topiclen > UINT16_MAX) {
    mosquitto__free(local_sub);
    mosquitto__free(topics);
    return MOSQ_ERR_INVAL;
  }
  HASH_FIND(hh, db.subs, topics[0], topiclen, subhier);
  if (!subhier) {
    subhier =
        sub__add_hier_entry(NULL, &db.subs, topics[0], (uint16_t)topiclen);
    if (!subhier) {
      mosquitto__free(local_sub);
      mosquitto__free(topics);
      log__printf(NULL, MOSQ_LOG_ERR, "Error: Out of memory.");
      return MOSQ_ERR_NOMEM;
    }
  }
  rc = sub__add_context(context, sub, qos, identifier, options, subhier, topics,
                        sharename);
  mosquitto__free(local_sub);
  mosquitto__free(topics);
  return rc;
}

static void get_sem_elements(struct sem_data* p) {
  size_t i;
  if (!p || !p->sem_nsems || p->sem_perm.id < 0) return;
  p->elements = xcalloc(p->sem_nsems, sizeof(struct sem_elem));
  for (i = 0; i < p->sem_nsems; i++) {
    struct sem_elem* e = &p->elements[i];
    union semun arg = {.val = 0};
    e->semval = semctl(p->sem_perm.id, i, GETVAL, arg);
    if (e->semval < 0) err(EXIT_FAILURE, _("%s failed"), "semctl(GETVAL)");
    e->ncount = semctl(p->sem_perm.id, i, GETNCNT, arg);
    if (e->ncount < 0) err(EXIT_FAILURE, _("%s failed"), "semctl(GETNCNT)");
    e->zcount = semctl(p->sem_perm.id, i, GETZCNT, arg);
    if (e->zcount < 0) err(EXIT_FAILURE, _("%s failed"), "semctl(GETZCNT)");
    e->pid = semctl(p->sem_perm.id, i, GETPID, arg);
    if (e->pid < 0) err(EXIT_FAILURE, _("%s failed"), "semctl(GETPID)");
  }
}

