resp_get_length(netdissect_options* ndo, register const u_char* bp, int len,
                const u_char** endp) {
  int result;
  u_char c;
  int saw_digit;
  int neg;
  int too_large;
  if (len == 0) goto trunc;
  ND_TCHECK(*bp);
  too_large = 0;
  neg = 0;
  if (*bp == '-') {
    neg = 1;
    bp++;
    len--;
  }
  result = 0;
  saw_digit = 0;
  for (;;) {
    if (len == 0) goto trunc;
    ND_TCHECK(*bp);
    c = *bp;
    if (!(c >= '0' && c <= '9')) {
      if (!saw_digit) goto invalid;
      break;
    }
    c -= '0';
    if (result > (INT_MAX / 10)) {
      too_large = 1;
    } else {
      result *= 10;
      if (result == INT_MAX && c > (INT_MAX % 10)) {
        too_large = 1;
      } else
        result += c;
    }
    bp++;
    len--;
    saw_digit = 1;
  }
  if (!saw_digit) goto invalid;
  if (len == 0) goto trunc;
  ND_TCHECK(*bp);
  if (*bp != '\r') goto invalid;
  bp++;
  len--;
  if (len == 0) goto trunc;
  ND_TCHECK(*bp);
  if (*bp != '\n') goto invalid;
  bp++;
  len--;
  *endp = bp;
  if (neg) {
    if (too_large || result != 1) return (-4);
    result = -1;
  }
  return (too_large ? -3 : result);
trunc:
  return (-2);
invalid:
  return (-5);
}

static int fr_add_pvc(struct net_device* frad, unsigned int dlci, int type) {
  hdlc_device* hdlc = dev_to_hdlc(frad);
  pvc_device* pvc;
  struct net_device* dev;
  int used;
  if ((pvc = add_pvc(frad, dlci)) == NULL) {
    netdev_warn(frad, "Memory squeeze on fr_add_pvc()\n");
    return -ENOBUFS;
  }
  if (*get_dev_p(pvc, type)) return -EEXIST;
  used = pvc_is_used(pvc);
  if (type == ARPHRD_ETHER)
    dev = alloc_netdev(0, "pvceth%d", ether_setup);
  else
    dev = alloc_netdev(0, "pvc%d", pvc_setup);
  if (!dev) {
    netdev_warn(frad, "Memory squeeze on fr_pvc()\n");
    delete_unused_pvcs(hdlc);
    return -ENOBUFS;
  }
  if (type == ARPHRD_ETHER)
    random_ether_addr(dev->dev_addr);
  else {
    *(__be16*)dev->dev_addr = htons(dlci);
    dlci_to_q922(dev->broadcast, dlci);
  }
  dev->netdev_ops = &pvc_ops;
  dev->mtu = HDLC_MAX_MTU;
  dev->tx_queue_len = 0;
  dev->ml_priv = pvc;
  if (register_netdevice(dev) != 0) {
    free_netdev(dev);
    delete_unused_pvcs(hdlc);
    return -EIO;
  }
  dev->destructor = free_netdev;
  *get_dev_p(pvc, type) = dev;
  if (!used) {
    state(hdlc)->dce_changed = 1;
    state(hdlc)->dce_pvc_count++;
  }
  return 0;
}

long uv__idna_toascii(const char* s, const char* se, char* d, char* de) {
  const char* si;
  const char* st;
  unsigned c;
  char* ds;
  int rc;
  ds = d;
  for (si = s; si < se;) {
    st = si;
    c = uv__utf8_decode1(&si, se);
    if (c != '.')
      if (c != 0x3002)
        if (c != 0xFF0E)
          if (c != 0xFF61) continue;
    rc = uv__idna_toascii_label(s, st, &d, de);
    if (rc < 0) return rc;
    if (d < de) *d++ = '.';
    s = si;
  }
  if (s < se) {
    rc = uv__idna_toascii_label(s, se, &d, de);
    if (rc < 0) return rc;
  }
  if (d < de) *d++ = '\0';
  return d - ds;
}

void RendererSchedulerImpl::OnShutdownTaskQueue(
    const scoped_refptr<MainThreadTaskQueue>& task_queue) {
  if (main_thread_only().was_shutdown) return;
  if (task_queue_throttler_)
    task_queue_throttler_->ShutdownTaskQueue(task_queue.get());
  if (task_runners_.erase(task_queue)) {
    switch (task_queue->queue_class()) {
      case MainThreadTaskQueue::QueueClass::kTimer:
        task_queue->RemoveTaskObserver(
            &main_thread_only().timer_task_cost_estimator);
      case MainThreadTaskQueue::QueueClass::kLoading:
        task_queue->RemoveTaskObserver(
            &main_thread_only().loading_task_cost_estimator);
      default:
        break;
    }
  }
}

static int br_parse_ip_options(struct sk_buff* skb) {
  struct ip_options* opt;
  struct iphdr* iph;
  struct net_device* dev = skb->dev;
  u32 len;
  iph = ip_hdr(skb);
  opt = &(IPCB(skb)->opt);
  if (iph->ihl < 5 || iph->version != 4) goto inhdr_error;
  if (!pskb_may_pull(skb, iph->ihl * 4)) goto inhdr_error;
  iph = ip_hdr(skb);
  if (unlikely(ip_fast_csum((u8*)iph, iph->ihl))) goto inhdr_error;
  len = ntohs(iph->tot_len);
  if (skb->len < len) {
    IP_INC_STATS_BH(dev_net(dev), IPSTATS_MIB_INTRUNCATEDPKTS);
    goto drop;
  } else if (len < (iph->ihl * 4))
    goto inhdr_error;
  if (pskb_trim_rcsum(skb, len)) {
    IP_INC_STATS_BH(dev_net(dev), IPSTATS_MIB_INDISCARDS);
    goto drop;
  }
  if (iph->ihl == 5) {
    memset(IPCB(skb), 0, sizeof(struct inet_skb_parm));
    return 0;
  }
  opt->optlen = iph->ihl * 4 - sizeof(struct iphdr);
  if (ip_options_compile(dev_net(dev), opt, skb)) goto inhdr_error;
  if (unlikely(opt->srr)) {
    struct in_device* in_dev = __in_dev_get_rcu(dev);
    if (in_dev && !IN_DEV_SOURCE_ROUTE(in_dev)) goto drop;
    if (ip_options_rcv_srr(skb)) goto drop;
  }
  return 0;
inhdr_error:
  IP_INC_STATS_BH(dev_net(dev), IPSTATS_MIB_INHDRERRORS);
drop:
  return -1;
}

mark_context_stack(mrb_state* mrb, struct mrb_context* c) {
  size_t i;
  size_t e;
  if (c->stack == NULL) return;
  e = c->stack - c->stbase;
  if (c->ci) e += c->ci->nregs;
  if (c->stbase + e > c->stend) e = c->stend - c->stbase;
  for (i = 0; i < e; i++) {
    mrb_value v = c->stbase[i];
    if (!mrb_immediate_p(v)) {
      if (mrb_basic_ptr(v)->tt == MRB_TT_FREE) {
        c->stbase[i] = mrb_nil_value();
      } else {
        mrb_gc_mark(mrb, mrb_basic_ptr(v));
      }
    }
  }
}

static TEE_Result do_allocate_keypair(struct dh_keypair* key,
                                      size_t size_bits) {
  DH_TRACE("Allocate Keypair of %zu bits", size_bits);
  memset(key, 0, sizeof(*key));
  key->g = crypto_bignum_allocate(size_bits);
  if (!key->g) goto err;
  key->p = crypto_bignum_allocate(size_bits);
  if (!key->p) goto err;
  key->x = crypto_bignum_allocate(size_bits);
  if (!key->x) goto err;
  key->y = crypto_bignum_allocate(size_bits);
  if (!key->y) goto err;
  key->q = crypto_bignum_allocate(size_bits);
  if (!key->q) goto err;
  return TEE_SUCCESS;
err:
  DH_TRACE("Allocation error");
  crypto_bignum_free(key->g);
  crypto_bignum_free(key->p);
  crypto_bignum_free(key->x);
  crypto_bignum_free(key->y);
  return TEE_ERROR_OUT_OF_MEMORY;
}

uint32_t mt_random(mtrand* mt) {
  uint32_t y;
  unsigned long mag01[2];
  mag01[0] = 0;
  mag01[1] = MATRIX_A;
  if (mt->mt_index_ >= MT_LEN) {
    int kk;
    for (kk = 0; kk < MT_LEN - MT_IA; kk++) {
      y = (mt->mt_buffer_[kk] & UPPER_MASK) |
          (mt->mt_buffer_[kk + 1] & LOWER_MASK);
      mt->mt_buffer_[kk] =
          mt->mt_buffer_[kk + MT_IA] ^ (y >> 1) ^ mag01[y & 0x1UL];
    }
    for (; kk < MT_LEN - 1; kk++) {
      y = (mt->mt_buffer_[kk] & UPPER_MASK) |
          (mt->mt_buffer_[kk + 1] & LOWER_MASK);
      mt->mt_buffer_[kk] =
          mt->mt_buffer_[kk + (MT_IA - MT_LEN)] ^ (y >> 1) ^ mag01[y & 0x1UL];
    }
    y = (mt->mt_buffer_[MT_LEN - 1] & UPPER_MASK) |
        (mt->mt_buffer_[0] & LOWER_MASK);
    mt->mt_buffer_[MT_LEN - 1] =
        mt->mt_buffer_[MT_IA - 1] ^ (y >> 1) ^ mag01[y & 0x1UL];
    mt->mt_index_ = 0;
  }
  y = mt->mt_buffer_[mt->mt_index_++];
  y ^= (y >> 11);
  y ^= (y << 7) & 0x9d2c5680UL;
  y ^= (y << 15) & 0xefc60000UL;
  y ^= (y >> 18);
  return y;
}

