static size_t send_control_msg(VirtIOSerial* vser, void* buf, size_t len) {
  VirtQueueElement elem;
  VirtQueue* vq;
  vq = vser->c_ivq;
  if (!virtio_queue_ready(vq)) {
    return 0;
  }
  if (!virtqueue_pop(vq, &elem)) {
    return 0;
  }
  memcpy(elem.in_sg[0].iov_base, buf, len);
  virtqueue_push(vq, &elem, len);
  virtio_notify(VIRTIO_DEVICE(vser), vq);
  return len;
}

static UINT drive_process_irp_write(DRIVE_DEVICE* drive, IRP* irp) {
  DRIVE_FILE* file;
  UINT32 Length;
  UINT64 Offset;
  if (!drive || !irp || !irp->input || !irp->output || !irp->Complete)
    return ERROR_INVALID_PARAMETER;
  if (Stream_GetRemainingLength(irp->input) < 32) return ERROR_INVALID_DATA;
  Stream_Read_UINT32(irp->input, Length);
  Stream_Read_UINT64(irp->input, Offset);
  Stream_Seek(irp->input, 20);
  file = drive_get_file_by_id(drive, irp->FileId);
  if (!file) {
    irp->IoStatus = STATUS_UNSUCCESSFUL;
    Length = 0;
  } else if (!drive_file_seek(file, Offset)) {
    irp->IoStatus = drive_map_windows_err(GetLastError());
    Length = 0;
  } else if (!drive_file_write(file, Stream_Pointer(irp->input), Length)) {
    irp->IoStatus = drive_map_windows_err(GetLastError());
    Length = 0;
  }
  Stream_Write_UINT32(irp->output, Length);
  Stream_Write_UINT8(irp->output, 0);
  return irp->Complete(irp);
}

int mlx4_register_mac(struct mlx4_dev* dev, u8 port, u64 mac, int* index) {
  struct mlx4_mac_table* table = &mlx4_priv(dev)->port[port].mac_table;
  int i, err = 0;
  int free = -1;
  mlx4_dbg(dev, "Registering MAC: 0x%llx\n", (unsigned long long)mac);
  mutex_lock(&table->mutex);
  for (i = 0; i < MLX4_MAX_MAC_NUM - 1; i++) {
    if (free < 0 && !table->refs[i]) {
      free = i;
      continue;
    }
    if (mac == (MLX4_MAC_MASK & be64_to_cpu(table->entries[i]))) {
      *index = i;
      ++table->refs[i];
      goto out;
    }
  }
  mlx4_dbg(dev, "Free MAC index is %d\n", free);
  if (table->total == table->max) {
    err = -ENOSPC;
    goto out;
  }
  table->refs[free] = 1;
  table->entries[free] = cpu_to_be64(mac | MLX4_MAC_VALID);
  err = mlx4_set_port_mac_table(dev, port, table->entries);
  if (unlikely(err)) {
    mlx4_err(dev, "Failed adding MAC: 0x%llx\n", (unsigned long long)mac);
    table->refs[free] = 0;
    table->entries[free] = 0;
    goto out;
  }
  *index = free;
  ++table->total;
out:
  mutex_unlock(&table->mutex);
  return err;
}

static int fsck_gitmodules_fn(const char* var, const char* value, void* vdata) {
  struct fsck_gitmodules_data* data = vdata;
  const char *subsection, *key;
  int subsection_len;
  char* name;
  if (parse_config_key(var, "submodule", &subsection, &subsection_len, &key) <
          0 ||
      !subsection)
    return 0;
  name = xmemdupz(subsection, subsection_len);
  if (check_submodule_name(name) < 0)
    data->ret |= report(data->options, data->obj, FSCK_MSG_GITMODULES_NAME,
                        "disallowed submodule name: %s", name);
  if (!strcmp(key, "url") && value && looks_like_command_line_option(value))
    data->ret |= report(data->options, data->obj, FSCK_MSG_GITMODULES_URL,
                        "disallowed submodule url: %s", value);
  free(name);
  return 0;
}

gray_render_span(int y, int count, const FT_Span* spans, PWorker worker) {
  unsigned char* p;
  FT_Bitmap* map = &worker->target;
  p = (unsigned char*)map->buffer - y * map->pitch;
  if (map->pitch >= 0) p += (map->rows - 1) * map->pitch;
  for (; count > 0; count--, spans++) {
    unsigned char coverage = spans->coverage;
    if (coverage) {
      if (spans->len >= 8)
        FT_MEM_SET(p + spans->x, (unsigned char)coverage, spans->len);
      else {
        unsigned char* q = p + spans->x;
        switch (spans->len) {
          case 7:
            *q++ = (unsigned char)coverage;
          case 6:
            *q++ = (unsigned char)coverage;
          case 5:
            *q++ = (unsigned char)coverage;
          case 4:
            *q++ = (unsigned char)coverage;
          case 3:
            *q++ = (unsigned char)coverage;
          case 2:
            *q++ = (unsigned char)coverage;
          case 1:
            *q = (unsigned char)coverage;
          default:;
        }
      }
    }
  }
}

SYSCALL_DEFINE6(move_pages, pid_t, pid, unsigned long, nr_pages,
                const void __user * __user*, pages, const int __user*, nodes,
                int __user*, status, int, flags) {
  const struct cred *cred = current_cred(), *tcred;
  struct task_struct* task;
  struct mm_struct* mm;
  int err;
  nodemask_t task_nodes;
  if (flags & ~(MPOL_MF_MOVE | MPOL_MF_MOVE_ALL)) return -EINVAL;
  if ((flags & MPOL_MF_MOVE_ALL) && !capable(CAP_SYS_NICE)) return -EPERM;
  rcu_read_lock();
  task = pid ? find_task_by_vpid(pid) : current;
  if (!task) {
    rcu_read_unlock();
    return -ESRCH;
  }
  get_task_struct(task);
  tcred = __task_cred(task);
  if (!uid_eq(cred->euid, tcred->suid) && !uid_eq(cred->euid, tcred->uid) &&
      !uid_eq(cred->uid, tcred->suid) && !uid_eq(cred->uid, tcred->uid) &&
      !capable(CAP_SYS_NICE)) {
    rcu_read_unlock();
    err = -EPERM;
    goto out;
  }
  rcu_read_unlock();
  err = security_task_movememory(task);
  if (err) goto out;
  task_nodes = cpuset_mems_allowed(task);
  mm = get_task_mm(task);
  put_task_struct(task);
  if (!mm) return -EINVAL;
  if (nodes)
    err = do_pages_move(mm, task_nodes, nr_pages, pages, nodes, status, flags);
  else
    err = do_pages_stat(mm, nr_pages, pages, status);
  mmput(mm);
  return err;
out:
  put_task_struct(task);
  return err;
}

int __usb_get_extra_descriptor(char* buffer, unsigned size, unsigned char type,
                               void** ptr) {
  struct usb_descriptor_header* header;
  while (size >= sizeof(struct usb_descriptor_header)) {
    header = (struct usb_descriptor_header*)buffer;
    if (header->bLength < 2) {
      printk(KERN_ERR "%s: bogus descriptor, type %d length %d\n", usbcore_name,
             header->bDescriptorType, header->bLength);
      return -1;
    }
    if (header->bDescriptorType == type) {
      *ptr = header;
      return 0;
    }
    buffer += header->bLength;
    size -= header->bLength;
  }
  return -1;
}

