void WebUIExtension::Send(gin::Arguments* args) {
  blink::WebLocalFrame* frame;
  RenderFrame* render_frame;
  if (!ShouldRespondToRequest(&frame, &render_frame)) return;
  std::string message;
  if (!args->GetNext(&message)) {
    args->ThrowError();
    return;
  }
  if (base::EndsWith(message, "RequiringGesture",
                     base::CompareCase::SENSITIVE) &&
      !blink::WebUserGestureIndicator::IsProcessingUserGesture(frame)) {
    NOTREACHED();
    return;
  }
  std::unique_ptr<base::ListValue> content;
  if (args->PeekNext().IsEmpty() || args->PeekNext()->IsUndefined()) {
    content.reset(new base::ListValue());
  } else {
    v8::Local<v8::Object> obj;
    if (!args->GetNext(&obj)) {
      args->ThrowError();
      return;
    }
    content = base::ListValue::From(V8ValueConverter::Create()->FromV8Value(
        obj, frame->MainWorldScriptContext()));
    DCHECK(content);
  }
  render_frame->Send(new FrameHostMsg_WebUISend(render_frame->GetRoutingID(),
                                                frame->GetDocument().Url(),
                                                message, *content));
}

CotpConnection_readToTpktBuffer(CotpConnection* self) {
  uint8_t* buffer = self->readBuffer->buffer;
  int bufferSize = self->readBuffer->maxSize;
  int bufPos = self->readBuffer->size;
  assert(bufferSize > 4);
  int readBytes;
  if (bufPos < 4) {
    readBytes = readFromSocket(self, buffer + bufPos, 4 - bufPos);
    if (readBytes < 0) goto exit_closed;
    if (DEBUG_COTP) {
      if (readBytes > 0) printf("TPKT: read %i bytes from socket\n", readBytes);
    }
    bufPos += readBytes;
    if (bufPos == 4) {
      if ((buffer[0] == 3) && (buffer[1] == 0)) {
        self->packetSize = (buffer[2] * 0x100) + buffer[3];
        if (DEBUG_COTP)
          printf("TPKT: header complete (msg size = %i)\n", self->packetSize);
        if (self->packetSize > bufferSize) {
          if (DEBUG_COTP) printf("TPKT: packet too large\n");
          goto exit_error;
        }
      } else {
        if (DEBUG_COTP) printf("TPKT: failed to decode TPKT header.\n");
        goto exit_error;
      }
    } else
      goto exit_waiting;
  }
  readBytes = readFromSocket(self, buffer + bufPos, self->packetSize - bufPos);
  if (readBytes < 0) goto exit_closed;
  bufPos += readBytes;
  if (bufPos < self->packetSize) goto exit_waiting;
  if (DEBUG_COTP)
    printf("TPKT: message complete (size = %i)\n", self->packetSize);
  self->readBuffer->size = bufPos;
  return TPKT_PACKET_COMPLETE;
exit_closed:
  if (DEBUG_COTP) printf("TPKT: socket closed or socket error\n");
  return TPKT_ERROR;
exit_error:
  if (DEBUG_COTP) printf("TPKT: Error parsing message\n");
  return TPKT_ERROR;
exit_waiting:
  if (DEBUG_COTP)
    if (bufPos != 0)
      printf("TPKT: waiting (read %i of %i)\n", bufPos, self->packetSize);
  self->readBuffer->size = bufPos;
  return TPKT_WAITING;
}

static int em_ret_near_imm(struct x86_emulate_ctxt* ctxt) {
  int rc;
  ctxt->dst.type = OP_REG;
  ctxt->dst.addr.reg = &ctxt->_eip;
  ctxt->dst.bytes = ctxt->op_bytes;
  rc = emulate_pop(ctxt, &ctxt->dst.val, ctxt->op_bytes);
  if (rc != X86EMUL_CONTINUE) return rc;
  rsp_increment(ctxt, ctxt->src.val);
  return X86EMUL_CONTINUE;
}

static int tipc_crypto_key_revoke(struct net* net, u8 tx_key) {
  struct tipc_crypto* tx = tipc_net(net)->crypto_tx;
  struct tipc_key key;
  spin_lock(&tx->lock);
  key = tx->key;
  WARN_ON(!key.active || tx_key != key.active);
  tipc_crypto_key_set_state(tx, key.passive, 0, key.pending);
  tipc_crypto_key_detach(tx->aead[key.active], &tx->lock);
  spin_unlock(&tx->lock);
  pr_warn("%s: key is revoked\n", tx->name);
  return -EKEYREVOKED;
}

