pxa3xx_gcu_write(struct file* file, const char* buff, size_t count,
                 loff_t* offp) {
  int ret;
  unsigned long flags;
  struct pxa3xx_gcu_batch* buffer;
  struct pxa3xx_gcu_priv* priv = to_pxa3xx_gcu_priv(file);
  int words = count / 4;
  priv->shared->num_writes++;
  priv->shared->num_words += words;
  if (words >= PXA3XX_GCU_BATCH_WORDS) return -E2BIG;
  if (!priv->free) {
    ret = pxa3xx_gcu_wait_free(priv);
    if (ret < 0) return ret;
  }
  spin_lock_irqsave(&priv->spinlock, flags);
  buffer = priv->free;
  priv->free = buffer->next;
  spin_unlock_irqrestore(&priv->spinlock, flags);
  ret = copy_from_user(buffer->ptr, buff, words * 4);
  if (ret) {
    spin_lock_irqsave(&priv->spinlock, flags);
    buffer->next = priv->free;
    priv->free = buffer;
    spin_unlock_irqrestore(&priv->spinlock, flags);
    return -EFAULT;
  }
  buffer->length = words;
  buffer->ptr[words] = 0x01000000;
  spin_lock_irqsave(&priv->spinlock, flags);
  buffer->next = NULL;
  if (priv->ready) {
    BUG_ON(priv->ready_last == NULL);
    priv->ready_last->next = buffer;
  } else
    priv->ready = buffer;
  priv->ready_last = buffer;
  if (!priv->shared->hw_running) run_ready(priv);
  spin_unlock_irqrestore(&priv->spinlock, flags);
  return words * 4;
}

void Filter::onUpstreamEvent(Network::ConnectionEvent event) {
  bool connecting = connecting_;
  connecting_ = false;
  if (event == Network::ConnectionEvent::RemoteClose ||
      event == Network::ConnectionEvent::LocalClose) {
    upstream_.reset();
    disableIdleTimer();
    if (connecting) {
      if (event == Network::ConnectionEvent::RemoteClose) {
        getStreamInfo().setResponseFlag(
            StreamInfo::ResponseFlag::UpstreamConnectionFailure);
        read_callbacks_->upstreamHost()->outlierDetector().putResult(
            Upstream::Outlier::Result::LocalOriginConnectFailed);
      }
      initializeUpstreamConnection();
    } else {
      if (read_callbacks_->connection().state() ==
          Network::Connection::State::Open) {
        read_callbacks_->connection().close(
            Network::ConnectionCloseType::FlushWrite);
      }
    }
  }
}

ossl_cipher_initialize(VALUE self, VALUE str) {
  EVP_CIPHER_CTX* ctx;
  const EVP_CIPHER* cipher;
  char* name;
  unsigned char dummy_key[EVP_MAX_KEY_LENGTH] = {0};
  name = StringValueCStr(str);
  GetCipherInit(self, ctx);
  if (ctx) {
    ossl_raise(rb_eRuntimeError, "Cipher already inititalized!");
  }
  AllocCipher(self, ctx);
  if (!(cipher = EVP_get_cipherbyname(name))) {
    ossl_raise(rb_eRuntimeError,
               "unsupported cipher algorithm (%" PRIsVALUE ")", str);
  }
  if (EVP_CipherInit_ex(ctx, cipher, NULL, dummy_key, NULL, -1) != 1)
    ossl_raise(eCipherError, NULL);
  return self;
}

static int nr_recvmsg(struct kiocb* iocb, struct socket* sock,
                      struct msghdr* msg, size_t size, int flags) {
  struct sock* sk = sock->sk;
  struct sockaddr_ax25* sax = (struct sockaddr_ax25*)msg->msg_name;
  size_t copied;
  struct sk_buff* skb;
  int er;
  lock_sock(sk);
  if (sk->sk_state != TCP_ESTABLISHED) {
    release_sock(sk);
    return -ENOTCONN;
  }
  if ((skb = skb_recv_datagram(sk, flags & ~MSG_DONTWAIT, flags & MSG_DONTWAIT,
                               &er)) == NULL) {
    release_sock(sk);
    return er;
  }
  skb_reset_transport_header(skb);
  copied = skb->len;
  if (copied > size) {
    copied = size;
    msg->msg_flags |= MSG_TRUNC;
  }
  er = skb_copy_datagram_iovec(skb, 0, msg->msg_iov, copied);
  if (er < 0) {
    skb_free_datagram(sk, skb);
    release_sock(sk);
    return er;
  }
  if (sax != NULL) {
    memset(sax, 0, sizeof(*sax));
    sax->sax25_family = AF_NETROM;
    skb_copy_from_linear_data_offset(skb, 7, sax->sax25_call.ax25_call,
                                     AX25_ADDR_LEN);
  }
  msg->msg_namelen = sizeof(*sax);
  skb_free_datagram(sk, skb);
  release_sock(sk);
  return copied;
}

static int klsi_105_get_line_state(struct usb_serial_port* port,
                                   unsigned long* line_state_p) {
  int rc;
  u8* status_buf;
  __u16 status;
  dev_info(&port->serial->dev->dev, "sending SIO Poll request\n");
  status_buf = kmalloc(KLSI_STATUSBUF_LEN, GFP_KERNEL);
  if (!status_buf) return -ENOMEM;
  status_buf[0] = 0xff;
  status_buf[1] = 0xff;
  rc = usb_control_msg(port->serial->dev, usb_rcvctrlpipe(port->serial->dev, 0),
                       KL5KUSB105A_SIO_POLL, USB_TYPE_VENDOR | USB_DIR_IN, 0, 0,
                       status_buf, KLSI_STATUSBUF_LEN, 10000);
  if (rc < 0)
    dev_err(&port->dev, "Reading line status failed (error = %d)\n", rc);
  else {
    status = get_unaligned_le16(status_buf);
    dev_info(&port->serial->dev->dev, "read status %x %x\n", status_buf[0],
             status_buf[1]);
    *line_state_p = klsi_105_status2linestate(status);
  }
  kfree(status_buf);
  return rc;
}

static int jpc_siz_getparms(jpc_ms_t* ms, jpc_cstate_t* cstate,
                            jas_stream_t* in) {
  jpc_siz_t* siz = &ms->parms.siz;
  unsigned int i;
  uint_fast8_t tmp;
  cstate = 0;
  if (jpc_getuint16(in, &siz->caps) || jpc_getuint32(in, &siz->width) ||
      jpc_getuint32(in, &siz->height) || jpc_getuint32(in, &siz->xoff) ||
      jpc_getuint32(in, &siz->yoff) || jpc_getuint32(in, &siz->tilewidth) ||
      jpc_getuint32(in, &siz->tileheight) ||
      jpc_getuint32(in, &siz->tilexoff) || jpc_getuint32(in, &siz->tileyoff) ||
      jpc_getuint16(in, &siz->numcomps)) {
    return -1;
  }
  if (!siz->width || !siz->height || !siz->tilewidth || !siz->tileheight ||
      !siz->numcomps) {
    return -1;
  }
  if (!(siz->comps = jas_alloc2(siz->numcomps, sizeof(jpc_sizcomp_t)))) {
    return -1;
  }
  for (i = 0; i < siz->numcomps; ++i) {
    if (jpc_getuint8(in, &tmp) || jpc_getuint8(in, &siz->comps[i].hsamp) ||
        jpc_getuint8(in, &siz->comps[i].vsamp)) {
      jas_free(siz->comps);
      return -1;
    }
    siz->comps[i].sgnd = (tmp >> 7) & 1;
    siz->comps[i].prec = (tmp & 0x7f) + 1;
  }
  if (jas_stream_eof(in)) {
    jas_free(siz->comps);
    return -1;
  }
  return 0;
}

