static int propagateConstantExprRewrite(Walker* pWalker, Expr* pExpr) {
  int i;
  WhereConst* pConst;
  if (pExpr->op != TK_COLUMN) return WRC_Continue;
  if (ExprHasProperty(pExpr, EP_FixedCol)) return WRC_Continue;
  pConst = pWalker->u.pConst;
  for (i = 0; i < pConst->nConst; i++) {
    Expr* pColumn = pConst->apExpr[i * 2];
    if (pColumn == pExpr) continue;
    if (pColumn->iTable != pExpr->iTable) continue;
    if (pColumn->iColumn != pExpr->iColumn) continue;
    pConst->nChng++;
    ExprClearProperty(pExpr, EP_Leaf);
    ExprSetProperty(pExpr, EP_FixedCol);
    assert(pExpr->pLeft == 0);
    pExpr->pLeft =
        sqlite3ExprDup(pConst->pParse->db, pConst->apExpr[i * 2 + 1], 0);
    break;
  }
  return WRC_Prune;
}

local unsigned long crc32_big(crc, buf, len)
unsigned long crc;
const unsigned char FAR* buf;
unsigned len;
{
  register z_crc_t c;
  register const z_crc_t FAR* buf4;
  c = ZSWAP32((z_crc_t)crc);
  c = ~c;
  while (len && ((ptrdiff_t)buf & 3)) {
    c = crc_table[4][(c >> 24) ^ *buf++] ^ (c << 8);
    len--;
  }
  buf4 = (const z_crc_t FAR*)(const void FAR*)buf;
  buf4--;
  while (len >= 32) {
    DOBIG32;
    len -= 32;
  }
  while (len >= 4) {
    DOBIG4;
    len -= 4;
  }
  buf4++;
  buf = (const unsigned char FAR*)buf4;
  if (len) do {
      c = crc_table[4][(c >> 24) ^ *buf++] ^ (c << 8);
    } while (--len);
  c = ~c;
  return (unsigned long)(ZSWAP32(c));
}

char* Hub::inflate(char* data, size_t& length) {
  dynamicInflationBuffer.clear();
  inflationStream.next_in = (Bytef*)data;
  inflationStream.avail_in = length;
  int err;
  do {
    inflationStream.next_out = (Bytef*)inflationBuffer;
    inflationStream.avail_out = LARGE_BUFFER_SIZE;
    err = ::inflate(&inflationStream, Z_FINISH);
    if (!inflationStream.avail_in) {
      break;
    }
    dynamicInflationBuffer.append(
        inflationBuffer, LARGE_BUFFER_SIZE - inflationStream.avail_out);
  } while (err == Z_BUF_ERROR);
  inflateReset(&inflationStream);
  if (err != Z_BUF_ERROR && err != Z_OK) {
    length = 0;
    return nullptr;
  }
  if (dynamicInflationBuffer.length()) {
    dynamicInflationBuffer.append(
        inflationBuffer, LARGE_BUFFER_SIZE - inflationStream.avail_out);
    length = dynamicInflationBuffer.length();
    return (char*)dynamicInflationBuffer.data();
  }
  length = LARGE_BUFFER_SIZE - inflationStream.avail_out;
  return inflationBuffer;
}

static int sctp_setsockopt_auth_key(struct sock* sk, char __user* optval,
                                    int optlen) {
  struct sctp_authkey* authkey;
  struct sctp_association* asoc;
  int ret;
  if (!sctp_auth_enable) return -EACCES;
  if (optlen <= sizeof(struct sctp_authkey)) return -EINVAL;
  authkey = kmalloc(optlen, GFP_KERNEL);
  if (!authkey) return -ENOMEM;
  if (copy_from_user(authkey, optval, optlen)) {
    ret = -EFAULT;
    goto out;
  }
  if (authkey->sca_keylength > optlen) {
    ret = -EINVAL;
    goto out;
  }
  asoc = sctp_id2assoc(sk, authkey->sca_assoc_id);
  if (!asoc && authkey->sca_assoc_id && sctp_style(sk, UDP)) {
    ret = -EINVAL;
    goto out;
  }
  ret = sctp_auth_set_key(sctp_sk(sk)->ep, asoc, authkey);
out:
  kfree(authkey);
  return ret;
}

static void adu_disconnect(struct usb_interface* interface) {
