PHP_FUNCTION(move_uploaded_file) {
  char *path, *new_path;
  int path_len, new_path_len;
  zend_bool successful = 0;
#ifndef PHP_WIN32
  int oldmask;
  int ret;
#endif
  if (!SG(rfc1867_uploaded_files)) {
    RETURN_FALSE;
  }
  if (zend_parse_parameters(ZEND_NUM_ARGS() TSRMLS_CC, "ss", &path, &path_len,
                            &new_path, &new_path_len) == FAILURE) {
    return;
  }
  if (!zend_hash_exists(SG(rfc1867_uploaded_files), path, path_len + 1)) {
    RETURN_FALSE;
  }
  if (php_check_open_basedir(new_path TSRMLS_CC)) {
    RETURN_FALSE;
  }
  if (VCWD_RENAME(path, new_path) == 0) {
    successful = 1;
#ifndef PHP_WIN32
    oldmask = umask(077);
    umask(oldmask);
    ret = VCWD_CHMOD(new_path, 0666 & ~oldmask);
    if (ret == -1) {
      php_error_docref(NULL TSRMLS_CC, E_WARNING, "%s", strerror(errno));
    }
#endif
  } else if (php_copy_file_ex(path, new_path,
                              STREAM_DISABLE_OPEN_BASEDIR TSRMLS_CC) ==
             SUCCESS) {
    VCWD_UNLINK(path);
    successful = 1;
  }
  if (successful) {
    zend_hash_del(SG(rfc1867_uploaded_files), path, path_len + 1);
  } else {
    php_error_docref(NULL TSRMLS_CC, E_WARNING, "Unable to move '%s' to '%s'",
                     path, new_path);
  }
  RETURN_BOOL(successful);
}

static void wait_for_child_to_die(void* ctx) {
  REQUEST* request = ctx;
  rad_assert(request->magic == REQUEST_MAGIC);
  if ((request->child_state == REQUEST_QUEUED) ||
      ((request->child_state == REQUEST_RUNNING) &&
       (pthread_equal(request->child_pid, NO_SUCH_CHILD_PID) == 0))) {
    if (request->delay < (USEC * 60 * 5)) {
      request->delay += (request->delay >> 1);
      radlog(L_INFO,
             "WARNING: Child is hung for request %u in component %s module %s.",
             request->number, request->component, request->module);
    } else {
      RDEBUG2("Child is still stuck for request %u", request->number);
    }
    tv_add(&request->when, request->delay);
    INSERT_EVENT(wait_for_child_to_die, request);
    return;
  }
  RDEBUG2("Child is finally responsive for request %u", request->number);
  remove_from_request_hash(request);
#ifdef WITH_PROXY
  if (request->proxy) {
    wait_for_proxy_id_to_expire(request);
    return;
  }
#endif
  ev_request_free(&request);
}

merged_2v_upsample(j_decompress_ptr cinfo, JSAMPIMAGE input_buf,
                   JDIMENSION* in_row_group_ctr, JDIMENSION in_row_groups_avail,
                   JSAMPARRAY output_buf, JDIMENSION* out_row_ctr,
                   JDIMENSION out_rows_avail) {
  my_upsample_ptr upsample = (my_upsample_ptr)cinfo->upsample;
  JSAMPROW work_ptrs[2];
  JDIMENSION num_rows;
  if (upsample->spare_full) {
    JDIMENSION size = upsample->out_row_width;
    if (cinfo->out_color_space == JCS_RGB565) size = cinfo->output_width * 2;
    jcopy_sample_rows(&upsample->spare_row, 0, output_buf + *out_row_ctr, 0, 1,
                      size);
    num_rows = 1;
    upsample->spare_full = FALSE;
  } else {
    num_rows = 2;
    if (num_rows > upsample->rows_to_go) num_rows = upsample->rows_to_go;
    out_rows_avail -= *out_row_ctr;
    if (num_rows > out_rows_avail) num_rows = out_rows_avail;
    work_ptrs[0] = output_buf[*out_row_ctr];
    if (num_rows > 1) {
      work_ptrs[1] = output_buf[*out_row_ctr + 1];
    } else {
      work_ptrs[1] = upsample->spare_row;
      upsample->spare_full = TRUE;
    }
    (*upsample->upmethod)(cinfo, input_buf, *in_row_group_ctr, work_ptrs);
  }
  *out_row_ctr += num_rows;
  upsample->rows_to_go -= num_rows;
  if (!upsample->spare_full) (*in_row_group_ctr)++;
}

const char* enc_untrusted_inet_ntop(int af, const void* src, char* dst,
                                    socklen_t size) {
  if (!src || !dst) {
    errno = EFAULT;
    return nullptr;
  }
  size_t src_size = 0;
  if (af == AF_INET) {
    src_size = sizeof(struct in_addr);
  } else if (af == AF_INET6) {
    src_size = sizeof(struct in6_addr);
  } else {
    errno = EAFNOSUPPORT;
    return nullptr;
  }
  MessageWriter input;
  input.Push<int>(TokLinuxAfFamily(af));
  input.PushByReference(Extent{reinterpret_cast<const char*>(src), src_size});
  input.Push(size);
  MessageReader output;
  const auto status = NonSystemCallDispatcher(
      ::asylo::host_call::kInetNtopHandler, &input, &output);
  CheckStatusAndParamCount(status, output, "enc_untrusted_inet_ntop", 2);
  auto result = output.next();
  int klinux_errno = output.next<int>();
  if (result.empty()) {
    errno = FromkLinuxErrorNumber(klinux_errno);
    return nullptr;
  }
  memcpy(dst, result.data(),
         std::min(static_cast<size_t>(size),
                  static_cast<size_t>(INET6_ADDRSTRLEN)));
  return dst;
}

void CLASS kodak_65000_load_raw() {
  short buf[256];
  int row, col, len, pred[2], ret, i;
  for (row = 0; row < height; row++) {
#ifdef LIBRAW_LIBRARY_BUILD
    checkCancel();
#endif
    for (col = 0; col < width; col += 256) {
      pred[0] = pred[1] = 0;
      len = MIN(256, width - col);
      ret = kodak_65000_decode(buf, len);
      for (i = 0; i < len; i++)
        if ((RAW(row, col + i) =
                 curve[ret ? buf[i] : (pred[i & 1] += buf[i])]) >>
            12)
          derror();
    }
  }
}

static int f_midi_set_alt(struct usb_function* f, unsigned intf, unsigned alt) {
  struct f_midi* midi = func_to_midi(f);
  unsigned i;
  int err;
  if (intf != midi->ms_id) return 0;
  err = f_midi_start_ep(midi, f, midi->in_ep);
  if (err) return err;
  err = f_midi_start_ep(midi, f, midi->out_ep);
  if (err) return err;
  while (kfifo_avail(&midi->in_req_fifo)) {
    struct usb_request* req = midi_alloc_ep_req(midi->in_ep, midi->buflen);
    if (req == NULL) return -ENOMEM;
    req->length = 0;
    req->complete = f_midi_complete;
    kfifo_put(&midi->in_req_fifo, req);
  }
  for (i = 0; i < midi->qlen && err == 0; i++) {
    struct usb_request* req = midi_alloc_ep_req(midi->out_ep, midi->buflen);
    if (req == NULL) return -ENOMEM;
    req->complete = f_midi_complete;
    err = usb_ep_queue(midi->out_ep, req, GFP_ATOMIC);
    if (err) {
      ERROR(midi, "%s: couldn't enqueue request: %d\n", midi->out_ep->name,
            err);
      free_ep_req(midi->out_ep, req);
      return err;
    }
  }
  return 0;
}

int jpc_ppxstab_insert(jpc_ppxstab_t* tab, jpc_ppxstabent_t* ent) {
  int inspt;
  int i;
  for (i = 0; i < tab->numents; ++i) {
    if (tab->ents[i]->ind > ent->ind) {
      break;
    }
  }
  inspt = i;
  if (tab->numents >= tab->maxents) {
    if (jpc_ppxstab_grow(tab, tab->maxents + 128)) {
      return -1;
    }
  }
  for (i = tab->numents; i > inspt; --i) {
    tab->ents[i] = tab->ents[i - 1];
  }
  tab->ents[i] = ent;
  ++tab->numents;
  return 0;
}

