int ldb_handler_fold(struct ldb_context* ldb, void* mem_ctx,
                     const struct ldb_val* in, struct ldb_val* out) {
  char *s, *t;
  size_t l;
  if (!in || !out || !(in->data)) {
    return -1;
  }
  out->data =
      (uint8_t*)ldb_casefold(ldb, mem_ctx, (const char*)(in->data), in->length);
  if (out->data == NULL) {
    ldb_debug(ldb, LDB_DEBUG_ERROR,
              "ldb_handler_fold: unable to casefold string [%.*s]",
              (int)in->length, (const char*)in->data);
    return -1;
  }
  s = (char*)(out->data);
  l = strlen(s);
  while (l > 0 && s[l - 1] == ' ') l--;
  s[l] = '\0';
  if (*s == ' ') {
    for (t = s; *s == ' '; s++);
    memmove(t, s, l);
    s = t;
  }
  while ((t = strchr(s, ' ')) != NULL) {
    for (s = t; *s == ' '; s++);
    if ((s - t) > 1) {
      l = strlen(s);
      memmove(t + 1, s, l);
    }
  }
  out->length = strlen((char*)out->data);
  return 0;
}

sp<ABuffer> decodeBase64(const AString& s) {
  size_t n = s.size();
  if ((n % 4) != 0) {
    return NULL;
  }
  size_t padding = 0;
  if (n >= 1 && s.c_str()[n - 1] == '=') {
    padding = 1;
    if (n >= 2 && s.c_str()[n - 2] == '=') {
      padding = 2;
      if (n >= 3 && s.c_str()[n - 3] == '=') {
        padding = 3;
      }
    }
  }
  size_t outLen = (n / 4) * 3 - padding;
  sp<ABuffer> buffer = new ABuffer(outLen);
  uint8_t* out = buffer->data();
  if (out == NULL || buffer->size() < outLen) {
    return NULL;
  }
  size_t j = 0;
  uint32_t accum = 0;
  for (size_t i = 0; i < n; ++i) {
    char c = s.c_str()[i];
    unsigned value;
    if (c >= 'A' && c <= 'Z') {
      value = c - 'A';
    } else if (c >= 'a' && c <= 'z') {
      value = 26 + c - 'a';
    } else if (c >= '0' && c <= '9') {
      value = 52 + c - '0';
    } else if (c == '+') {
      value = 62;
    } else if (c == '/') {
      value = 63;
    } else if (c != '=') {
      return NULL;
    } else {
      if (i < n - padding) {
        return NULL;
      }
      value = 0;
    }
    accum = (accum << 6) | value;
    if (((i + 1) % 4) == 0) {
      out[j++] = (accum >> 16);
      if (j < outLen) {
        out[j++] = (accum >> 8) & 0xff;
      }
      if (j < outLen) {
        out[j++] = accum & 0xff;
      }
      accum = 0;
    }
  }
  return buffer;
}

int decomp_get_rddata(js_string* compressed, js_string* out,
                      unsigned int compressed_offset, int type, int rdlength) {
  char* desc;
  int subtype, total, len;
  desc = decomp_get_rrdesc(type);
  if (desc == 0) {
    if (rdlength == 0) {
      return JS_SUCCESS;
    }
    if (decomp_append_bytes(compressed, out, compressed_offset, rdlength) !=
        JS_SUCCESS) {
      return JS_ERROR;
    } else {
      return JS_SUCCESS;
    }
  } else {
    subtype = *desc;
    total = 0;
    while (subtype != 0) {
      if (subtype > 0 && subtype < 64) {
        if (decomp_append_bytes(compressed, out, compressed_offset, subtype) !=
            JS_SUCCESS) {
          return JS_ERROR;
        }
        total += subtype;
        compressed_offset += subtype;
      } else if (subtype == RRSUB_DLABEL) {
        len = decomp_append_dlabel(compressed, out, compressed_offset);
        if (len == JS_ERROR) {
          return JS_ERROR;
        }
        total += len;
        compressed_offset += len;
      } else if (subtype == RRSUB_TEXT) {
        len = *(compressed->string + compressed_offset);
        len += 1;
        if (len < 0 || len > 256) {
          return JS_ERROR;
        }
        if (decomp_append_bytes(compressed, out, compressed_offset, len) !=
            JS_SUCCESS) {
          return JS_ERROR;
        }
        total += len;
        compressed_offset += len;
      } else if (subtype == RRSUB_VARIABLE) {
        len = rdlength - total;
        if (len == 0) {
          break;
        }
        if (decomp_append_bytes(compressed, out, compressed_offset, len) !=
            JS_SUCCESS) {
          return JS_ERROR;
        }
        total += len;
        compressed_offset += len;
      } else {
        return JS_ERROR;
      }
      desc++;
      if (subtype != RRSUB_VARIABLE)
        subtype = *desc;
      else
        subtype = 0;
    }
    if (rdlength != total) {
      return JS_ERROR;
    }
  }
  return JS_SUCCESS;
}

