static __be32 nfsd3_proc_setacl(struct svc_rqst* rqstp,
                                struct nfsd3_setaclargs* argp,
                                struct nfsd3_attrstat* resp) {
  struct inode* inode;
  svc_fh* fh;
  __be32 nfserr = 0;
  int error;
  fh = fh_copy(&resp->fh, &argp->fh);
  nfserr = fh_verify(rqstp, &resp->fh, 0, NFSD_MAY_SATTR);
  if (nfserr) goto out;
  inode = d_inode(fh->fh_dentry);
  if (!IS_POSIXACL(inode) || !inode->i_op->set_acl) {
    error = -EOPNOTSUPP;
    goto out_errno;
  }
  error = fh_want_write(fh);
  if (error) goto out_errno;
  error = inode->i_op->set_acl(inode, argp->acl_access, ACL_TYPE_ACCESS);
  if (error) goto out_drop_write;
  error = inode->i_op->set_acl(inode, argp->acl_default, ACL_TYPE_DEFAULT);
out_drop_write:
  fh_drop_write(fh);
out_errno:
  nfserr = nfserrno(error);
out:
  posix_acl_release(argp->acl_access);
  posix_acl_release(argp->acl_default);
  RETURN_STATUS(nfserr);
}

Status DoCompute(OpKernelContext* ctx) {
  tensorflow::ResourceTagger tag(kTFDataResourceTag,
                                 ctx->op_kernel().type_string());
  tstring filename;
  TF_RETURN_IF_ERROR(ParseScalarArgument<tstring>(ctx, "filename", &filename));
  tstring compression_type;
  TF_RETURN_IF_ERROR(
      ParseScalarArgument<tstring>(ctx, "compression_type", &compression_type));
  std::unique_ptr<WritableFile> file;
  TF_RETURN_IF_ERROR(ctx->env()->NewWritableFile(filename, &file));
  auto writer = absl::make_unique<io::RecordWriter>(
      file.get(),
      io::RecordWriterOptions::CreateRecordWriterOptions(compression_type));
  DatasetBase* dataset;
  TF_RETURN_IF_ERROR(GetDatasetFromVariantTensor(ctx->input(0), &dataset));
  IteratorContext::Params params(ctx);
  FunctionHandleCache function_handle_cache(params.flr);
  params.function_handle_cache = &function_handle_cache;
  ResourceMgr resource_mgr;
  params.resource_mgr = &resource_mgr;
  CancellationManager cancellation_manager(ctx->cancellation_manager());
  params.cancellation_manager = &cancellation_manager;
  IteratorContext iter_ctx(std::move(params));
  DatasetBase* finalized_dataset;
  TF_RETURN_IF_ERROR(FinalizeDataset(ctx, dataset, &finalized_dataset));
  std::unique_ptr<IteratorBase> iterator;
  TF_RETURN_IF_ERROR(finalized_dataset->MakeIterator(
      &iter_ctx, nullptr, "ToTFRecordOpIterator", &iterator));
  std::vector<Tensor> components;
  components.reserve(finalized_dataset->output_dtypes().size());
  bool end_of_sequence;
  do {
    TF_RETURN_IF_ERROR(
        iterator->GetNext(&iter_ctx, &components, &end_of_sequence));
    if (!end_of_sequence) {
      TF_RETURN_IF_ERROR(
          writer->WriteRecord(components[0].scalar<tstring>()()));
    }
    components.clear();
  } while (!end_of_sequence);
  return Status::OK();
}

static int nfc_genl_deactivate_target(struct sk_buff* skb,
                                      struct genl_info* info) {
  struct nfc_dev* dev;
  u32 device_idx, target_idx;
  int rc;
  if (!info->attrs[NFC_ATTR_DEVICE_INDEX]) return -EINVAL;
  device_idx = nla_get_u32(info->attrs[NFC_ATTR_DEVICE_INDEX]);
  dev = nfc_get_device(device_idx);
  if (!dev) return -ENODEV;
  target_idx = nla_get_u32(info->attrs[NFC_ATTR_TARGET_INDEX]);
  rc = nfc_deactivate_target(dev, target_idx, NFC_TARGET_MODE_SLEEP);
  nfc_put_device(dev);
  return rc;
}

int pgpPrtParams(const uint8_t* pkts, size_t pktlen, unsigned int pkttype,
                 pgpDigParams* ret) {
  const uint8_t* p = pkts;
  const uint8_t* pend = pkts + pktlen;
  pgpDigParams digp = NULL;
  struct pgpPkt pkt;
  int rc = -1;
  while (p < pend) {
    if (decodePkt(p, (pend - p), &pkt)) break;
    if (digp == NULL) {
      if (pkttype && pkt.tag != pkttype) {
        break;
      } else {
        digp = pgpDigParamsNew(pkt.tag);
      }
    }
    if (pgpPrtPkt(&pkt, digp)) break;
    p += (pkt.body - pkt.head) + pkt.blen;
    if (pkttype == PGPTAG_SIGNATURE) break;
  }
  rc = (digp && (p == pend)) ? 0 : -1;
  if (ret && rc == 0) {
    *ret = digp;
  } else {
    pgpDigParamsFree(digp);
  }
  return rc;
}

int yr_object_array_set_item(YR_OBJECT* object, YR_OBJECT* item, int index) {
  YR_OBJECT_ARRAY* array;
  int i;
  int count;
  assert(index >= 0);
  assert(object->type == OBJECT_TYPE_ARRAY);
  array = object_as_array(object);
  if (array->items == NULL) {
    count = yr_max(64, (index + 1) * 2);
    array->items = (YR_ARRAY_ITEMS*)yr_malloc(sizeof(YR_ARRAY_ITEMS) +
                                              count * sizeof(YR_OBJECT*));
    if (array->items == NULL) return ERROR_INSUFFICIENT_MEMORY;
    memset(array->items->objects, 0, count * sizeof(YR_OBJECT*));
    array->items->count = count;
  } else if (index >= array->items->count) {
    count = array->items->count * 2;
    array->items = (YR_ARRAY_ITEMS*)yr_realloc(
        array->items, sizeof(YR_ARRAY_ITEMS) + count * sizeof(YR_OBJECT*));
    if (array->items == NULL) return ERROR_INSUFFICIENT_MEMORY;
    for (i = array->items->count; i < count; i++)
      array->items->objects[i] = NULL;
    array->items->count = count;
  }
  item->parent = object;
  array->items->objects[index] = item;
  return ERROR_SUCCESS;
}

