folly::Optional<TLSMessage> PlaintextReadRecordLayer::read(
    folly::IOBufQueue& buf) {
  while (true) {
    folly::io::Cursor cursor(buf.front());
    if (buf.empty() || !cursor.canAdvance(kPlaintextHeaderSize)) {
      return folly::none;
    }
    TLSMessage msg;
    msg.type = static_cast<ContentType>(cursor.readBE<ContentTypeType>());
    if (skipEncryptedRecords_) {
      if (msg.type == ContentType::application_data) {
        cursor.skip(sizeof(ProtocolVersion));
        auto length = cursor.readBE<uint16_t>();
        if (buf.chainLength() < (cursor - buf.front()) + length) {
          return folly::none;
        }
        length +=
            sizeof(ContentType) + sizeof(ProtocolVersion) + sizeof(uint16_t);
        buf.trimStart(length);
        continue;
      } else if (msg.type != ContentType::change_cipher_spec) {
        skipEncryptedRecords_ = false;
      }
    }
    switch (msg.type) {
      case ContentType::handshake:
      case ContentType::alert:
        break;
      case ContentType::change_cipher_spec:
        break;
      default:
        throw std::runtime_error(folly::to<std::string>(
            "received plaintext content type ",
            static_cast<ContentTypeType>(msg.type),
            ", header: ", folly::hexlify(buf.splitAtMost(10)->coalesce())));
    }
    receivedRecordVersion_ =
        static_cast<ProtocolVersion>(cursor.readBE<ProtocolVersionType>());
    auto length = cursor.readBE<uint16_t>();
    if (length > kMaxPlaintextRecordSize) {
      throw std::runtime_error("received too long plaintext record");
    }
    if (length == 0) {
      throw std::runtime_error("received empty plaintext record");
    }
    if (buf.chainLength() < (cursor - buf.front()) + length) {
      return folly::none;
    }
    cursor.clone(msg.fragment, length);
    buf.trimStart(cursor - buf.front());
    if (msg.type == ContentType::change_cipher_spec) {
      msg.fragment->coalesce();
      if (msg.fragment->length() == 1 && *msg.fragment->data() == 0x01) {
        continue;
      } else {
        throw FizzException("received ccs",
                            AlertDescription::illegal_parameter);
      }
    }
    return std::move(msg);
  }
}

vhost_user_check_and_alloc_queue_pair(struct virtio_net* dev,
                                      struct vhu_msg_context* ctx) {
  uint32_t vring_idx;
  switch (ctx->msg.request.master) {
    case VHOST_USER_SET_VRING_KICK:
    case VHOST_USER_SET_VRING_CALL:
    case VHOST_USER_SET_VRING_ERR:
      vring_idx = ctx->msg.payload.u64 & VHOST_USER_VRING_IDX_MASK;
      break;
    case VHOST_USER_SET_VRING_NUM:
    case VHOST_USER_SET_VRING_BASE:
    case VHOST_USER_GET_VRING_BASE:
    case VHOST_USER_SET_VRING_ENABLE:
      vring_idx = ctx->msg.payload.state.index;
      break;
    case VHOST_USER_SET_VRING_ADDR:
      vring_idx = ctx->msg.payload.addr.index;
      break;
    default:
      return 0;
  }
  if (vring_idx >= VHOST_MAX_VRING) {
    VHOST_LOG_CONFIG(ERR, "(%s) invalid vring index: %u\n", dev->ifname,
                     vring_idx);
    return -1;
  }
  if (dev->virtqueue[vring_idx]) return 0;
  return alloc_vring_queue(dev, vring_idx);
}

vrrp_tfile_end_handler(void) {
  vrrp_tracked_file_t* tfile = LIST_TAIL_DATA(vrrp_data->vrrp_track_files);
  struct stat statb;
  FILE* tf;
  int ret;
  if (!tfile->file_path) {
    report_config_error(CONFIG_GENERAL_ERROR,
                        "No file set for track_file %s - removing",
                        tfile->fname);
    free_list_element(vrrp_data->vrrp_track_files,
                      vrrp_data->vrrp_track_files->tail);
    return;
  }
  if (track_file_init == TRACK_FILE_NO_INIT) return;
  ret = stat(tfile->file_path, &statb);
  if (!ret) {
    if (track_file_init == TRACK_FILE_CREATE) {
      return;
    }
    if ((statb.st_mode & S_IFMT) != S_IFREG) {
      report_config_error(
          CONFIG_GENERAL_ERROR,
          "Cannot initialise track file %s - it is not a regular file",
          tfile->fname);
      return;
    }
    if (reload) return;
  }
  if (!__test_bit(CONFIG_TEST_BIT, &debug)) {
    if ((tf = fopen(tfile->file_path, "w"))) {
      fprintf(tf, "%d\n", track_file_init_value);
      fclose(tf);
    } else
      report_config_error(CONFIG_GENERAL_ERROR,
                          "Unable to initialise track file %s", tfile->fname);
  }
}

static int command_read(struct pci_dev* dev, int offset, u16* value,
                        void* data) {
  int i;
  int ret;
  ret = xen_pcibk_read_config_word(dev, offset, value, data);
  if (!pci_is_enabled(dev)) return ret;
  for (i = 0; i < PCI_ROM_RESOURCE; i++) {
    if (dev->resource[i].flags & IORESOURCE_IO) *value |= PCI_COMMAND_IO;
    if (dev->resource[i].flags & IORESOURCE_MEM) *value |= PCI_COMMAND_MEMORY;
  }
  return ret;
}

bool load_face(Face& face, unsigned int options) {
#ifdef GRAPHITE2_TELEMETRY
  telemetry::category _misc_cat(face.tele.misc);
#endif
  Face::Table silf(face, Tag::Silf, 0x00050000);
  if (silf)
    options &= ~gr_face_dumbRendering;
  else if (!(options & gr_face_dumbRendering))
    return false;
  if (!face.readGlyphs(options)) return false;
  if (silf) {
    if (!face.readFeatures() || !face.readGraphite(silf)) {
