}

int secure_check(void* data) {
  const at91_secure_header_t* header;
  void* file;
  if (secure_decrypt(data, sizeof(*header), 0)) return -1;
  header = (const at91_secure_header_t*)data;
  if (header->magic != AT91_SECURE_MAGIC) return -1;
  file = (unsigned char*)data + sizeof(*header);
  return secure_decrypt(file, header->file_size, 1);
}

Status CompressElement(const std::vector<Tensor>& element,
                       CompressedElement* out) {
  std::vector<TensorProto> non_memcpy_components;
  int64 total_size = 0;
  for (auto& component : element) {
    if (DataTypeCanUseMemcpy(component.dtype())) {
      total_size += DMAHelper::buffer(&component)->size();
    } else {
      non_memcpy_components.emplace_back();
      component.AsProtoTensorContent(&non_memcpy_components.back());
      total_size += non_memcpy_components.back().ByteSizeLong();
    }
  }
  tstring uncompressed;
  uncompressed.resize_uninitialized(total_size);
  char* position = uncompressed.mdata();
  int non_memcpy_component_index = 0;
  for (auto& component : element) {
    CompressedComponentMetadata* metadata =
        out->mutable_component_metadata()->Add();
    metadata->set_dtype(component.dtype());
    component.shape().AsProto(metadata->mutable_tensor_shape());
    if (DataTypeCanUseMemcpy(component.dtype())) {
      const TensorBuffer* buffer = DMAHelper::buffer(&component);
      memcpy(position, buffer->data(), buffer->size());
      metadata->set_tensor_size_bytes(buffer->size());
    } else {
      TensorProto& proto = non_memcpy_components[non_memcpy_component_index++];
      proto.SerializeToArray(position, proto.ByteSizeLong());
      metadata->set_tensor_size_bytes(proto.ByteSizeLong());
    }
    position += metadata->tensor_size_bytes();
  }
  DCHECK_EQ(position, uncompressed.mdata() + total_size);
  if (!port::Snappy_Compress(uncompressed.mdata(), total_size,
                             out->mutable_data())) {
    return errors::Internal("Failed to compress using snappy.");
  }
  VLOG(3) << "Compressed element from " << total_size << " bytes to "
          << out->data().size() << " bytes";
  return Status::OK();
}

int wmi_set_ie(struct wil6210_priv* wil, u8 type, u16 ie_len, const void* ie) {
  static const char* const names[] = {
      [WMI_FRAME_BEACON] = "BEACON",
      [WMI_FRAME_PROBE_REQ] = "PROBE_REQ",
      [WMI_FRAME_PROBE_RESP] = "WMI_FRAME_PROBE_RESP",
      [WMI_FRAME_ASSOC_REQ] = "WMI_FRAME_ASSOC_REQ",
      [WMI_FRAME_ASSOC_RESP] = "WMI_FRAME_ASSOC_RESP",
  };
  int rc;
  u16 len = sizeof(struct wmi_set_appie_cmd) + ie_len;
  struct wmi_set_appie_cmd* cmd = kzalloc(len, GFP_KERNEL);
  if (!cmd) {
    rc = -ENOMEM;
    goto out;
  }
  if (!ie) ie_len = 0;
  cmd->mgmt_frm_type = type;
  cmd->ie_len = cpu_to_le16(ie_len);
  memcpy(cmd->ie_info, ie, ie_len);
  rc = wmi_send(wil, WMI_SET_APPIE_CMDID, cmd, len);
  kfree(cmd);
out:
  if (rc) {
    const char* name = type < ARRAY_SIZE(names) ? names[type] : "??";
    wil_err(wil, "set_ie(%d %s) failed : %d\n", type, name, rc);
  }
  return rc;
}

RestStatus RestAuthHandler::execute() {
  auto const type = _request->requestType();
  if (type != rest::RequestType::POST) {
    generateError(rest::ResponseCode::METHOD_NOT_ALLOWED,
                  TRI_ERROR_HTTP_METHOD_NOT_ALLOWED);
    return RestStatus::DONE;
  }
  bool parseSuccess = false;
  VPackSlice slice = this->parseVPackBody(parseSuccess);
  if (!parseSuccess) {
    return RestStatus::DONE;
  }
  if (!slice.isObject()) {
    return badRequest();
  }
  VPackSlice usernameSlice = slice.get("username");
  VPackSlice passwordSlice = slice.get("password");
  if (!usernameSlice.isString() || !passwordSlice.isString()) {
    return badRequest();
  }
  _username = usernameSlice.copyString();
  std::string const password = passwordSlice.copyString();
  auth::UserManager* um = AuthenticationFeature::instance()->userManager();
  if (um == nullptr) {
    std::string msg = "This server does not support users";
    LOG_TOPIC("2e7d4", ERR, Logger::AUTHENTICATION) << msg;
    generateError(rest::ResponseCode::UNAUTHORIZED, TRI_ERROR_HTTP_UNAUTHORIZED,
                  msg);
  } else if (um->checkPassword(_username, password)) {
    VPackBuilder resultBuilder;
    {
      VPackObjectBuilder b(&resultBuilder);
      std::string jwt = generateJwt(_username, password);
      resultBuilder.add("jwt", VPackValue(jwt));
    }
    _isValid = true;
    generateDocument(resultBuilder.slice(), true, &VPackOptions::Defaults);
  } else {
    generateError(rest::ResponseCode::UNAUTHORIZED, TRI_ERROR_HTTP_UNAUTHORIZED,
                  "Wrong credentials");
  }
  return RestStatus::DONE;
}

static struct dump_dir* open_directory_for_modification_of_element(
    GDBusMethodInvocation* invocation, uid_t caller_uid, const char* problem_id,
    const char* element) {
  static const char* const protected_elements[] = {
      FILENAME_TIME,
      FILENAME_UID,
      NULL,
  };
  for (const char* const* protected = protected_elements; *protected;
       ++protected) {
    if (strcmp(*protected, element) == 0) {
      log_notice("'%s' element of '%s' can't be modified", element, problem_id);
      char* error = xasprintf(_("'%s' element can't be modified"), element);
      g_dbus_method_invocation_return_dbus_error(
          invocation, "org.freedesktop.problems.ProtectedElement", error);
      free(error);
      return NULL;
    }
  }
  if (!dump_dir_accessible_by_uid(problem_id, caller_uid)) {
    if (errno == ENOTDIR) {
      log_notice("'%s' is not a valid problem directory", problem_id);
      return_InvalidProblemDir_error(invocation, problem_id);
    } else {
      log_notice("UID(%d) is not Authorized to access '%s'", caller_uid,
                 problem_id);
      g_dbus_method_invocation_return_dbus_error(
          invocation, "org.freedesktop.problems.AuthFailure",
          _("Not Authorized"));
    }
    return NULL;
  }
  struct dump_dir* dd = dd_opendir(problem_id, 0);
  if (!dd) {
    log_notice("Can't access the problem '%s' for modification", problem_id);
    g_dbus_method_invocation_return_dbus_error(
        invocation, "org.freedesktop.problems.Failure",
        _("Can't access the problem for modification"));
    return NULL;
  }
  return dd;
}

static inline void native_set_ldt(const void* addr, unsigned int entries) {
  if (likely(entries == 0))
    asm volatile("lldt %w0" ::"q"(0));
  else {
    unsigned cpu = smp_processor_id();
    ldt_desc ldt;
    set_tssldt_descriptor(&ldt, (unsigned long)addr, DESC_LDT,
                          entries * sizeof(ldt) - 1);
    write_gdt_entry(get_cpu_gdt_table(cpu), GDT_ENTRY_LDT, &ldt, DESC_LDT);
    asm volatile("lldt %w0" ::"q"(GDT_ENTRY_LDT * 8));
  }
}

