void Compute(OpKernelContext* c) override {
  const Tensor& tag = c->input(0);
  OP_REQUIRES(c, TensorShapeUtils::IsScalar(tag.shape()),
              errors::InvalidArgument("tag must be scalar"));
  const Tensor& tensor = c->input(1);
  const Tensor& serialized_summary_metadata_tensor = c->input(2);
  Summary s;
  Summary::Value* v = s.add_value();
  v->set_tag(string(tag.scalar<tstring>()()));
  if (tensor.dtype() == DT_STRING) {
    tensor.AsProtoField(v->mutable_tensor());
  } else {
    tensor.AsProtoTensorContent(v->mutable_tensor());
  }
  ParseFromTString(serialized_summary_metadata_tensor.scalar<tstring>()(),
                   v->mutable_metadata());
  Tensor* summary_tensor = nullptr;
  OP_REQUIRES_OK(c, c->allocate_output(0, TensorShape({}), &summary_tensor));
  CHECK(SerializeToTString(s, &summary_tensor->scalar<tstring>()()));
}

sudo_auth_init(const struct sudoers_context* ctx, struct passwd* pw,
               unsigned int mode) {
  sudo_auth* auth;
  int status = AUTH_SUCCESS;
  debug_decl(sudo_auth_init, SUDOERS_DEBUG_AUTH);
  if (auth_switch[0].name == NULL) debug_return_int(0);
  for (auth = auth_switch; auth->name; auth++) {
    if (ISSET(mode, MODE_NONINTERACTIVE)) SET(auth->flags, FLAG_NONINTERACTIVE);
    if (auth->init && !IS_DISABLED(auth)) {
      status = (auth->init)(ctx, pw, auth);
      if (status == AUTH_FAILURE)
        SET(auth->flags, FLAG_DISABLED);
      else if (status == AUTH_ERROR)
        break;
    }
  }
  if ((standalone = IS_STANDALONE(&auth_switch[0]))) {
    bool found = false;
    for (auth = auth_switch; auth->name; auth++) {
      if (IS_DISABLED(auth)) continue;
      if (!IS_STANDALONE(auth)) {
        audit_failure(ctx, ctx->runas.argv,
                      N_("invalid authentication methods"));
        log_warningx(ctx, SLOG_SEND_MAIL,
                     N_("Invalid authentication methods compiled into sudo!  "
                        "You may not mix standalone and non-standalone "
                        "authentication."));
        debug_return_int(-1);
      }
      if (!found) {
        found = true;
        continue;
      }
      SET(auth->flags, FLAG_DISABLED);
    }
  }
  for (auth = auth_switch; auth->name; auth++) {
    if (!IS_DISABLED(auth)) {
      sudo_auth* first = auth;
      for (; auth->name; auth++) {
        if (!IS_DISABLED(auth)) break;
      }
      if (auth->name == NULL) SET(first->flags, FLAG_ONEANDONLY);
      break;
    }
  }
  debug_return_int(status == AUTH_ERROR ? -1 : 0);
}

Statement_Ptr Expand::operator()(Declaration_Ptr d) {
  Block_Obj ab = d->block();
  String_Obj old_p = d->property();
  Expression_Obj prop = old_p->perform(&eval);
  String_Obj new_p = Cast<String>(prop);
  if (!new_p) {
    std::string str(prop->to_string(ctx.c_options));
    new_p = SASS_MEMORY_NEW(String_Constant, old_p->pstate(), str);
  }
  Expression_Obj value = d->value()->perform(&eval);
  Block_Obj bb = ab ? operator()(ab) : NULL;
  if (!bb) {
    if (!value || (value->is_invisible() && !d->is_important())) return 0;
  }
  Declaration_Ptr decl =
      SASS_MEMORY_NEW(Declaration, d->pstate(), new_p, value, d->is_important(),
                      d->is_custom_property(), bb);
  decl->tabs(d->tabs());
  return decl;
}

