void faad_resetbits(bitfile* ld, int bits) {
  uint32_t tmp;
  int words = bits >> 5;
  int remainder = bits & 0x1F;
  ld->bytes_left = ld->buffer_size - words * 4;
  if (ld->bytes_left >= 4) {
    tmp = getdword(&ld->start[words]);
    ld->bytes_left -= 4;
  } else {
    tmp = getdword_n(&ld->start[words], ld->bytes_left);
    ld->bytes_left = 0;
  }
  ld->bufa = tmp;
  if (ld->bytes_left >= 4) {
    tmp = getdword(&ld->start[words + 1]);
    ld->bytes_left -= 4;
  } else {
    tmp = getdword_n(&ld->start[words + 1], ld->bytes_left);
    ld->bytes_left = 0;
  }
  ld->bufb = tmp;
  ld->bits_left = 32 - remainder;
  ld->tail = &ld->start[words + 2];
  ld->error = 0;
}

static size_t exif_convert_any_to_int(void* value, int format,
                                      int motorola_intel TSRMLS_DC) {
  int s_den;
  unsigned u_den;
  switch (format) {
    case TAG_FMT_SBYTE:
      return *(signed char*)value;
    case TAG_FMT_BYTE:
      return *(uchar*)value;
    case TAG_FMT_USHORT:
      return php_ifd_get16u(value, motorola_intel);
    case TAG_FMT_ULONG:
      return php_ifd_get32u(value, motorola_intel);
    case TAG_FMT_URATIONAL:
      u_den = php_ifd_get32u(4 + (char*)value, motorola_intel);
      if (u_den == 0) {
        return 0;
      } else {
        return php_ifd_get32u(value, motorola_intel) / u_den;
      }
    case TAG_FMT_SRATIONAL:
      s_den = php_ifd_get32s(4 + (char*)value, motorola_intel);
      if (s_den == 0) {
        return 0;
      } else {
        return php_ifd_get32s(value, motorola_intel) / s_den;
      }
    case TAG_FMT_SSHORT:
      return php_ifd_get16u(value, motorola_intel);
    case TAG_FMT_SLONG:
      return php_ifd_get32s(value, motorola_intel);
    case TAG_FMT_SINGLE:
#ifdef EXIF_DEBUG
      php_error_docref(NULL TSRMLS_CC, E_NOTICE, "Found value of type single");
#endif
      return (size_t)*(float*)value;
    case TAG_FMT_DOUBLE:
#ifdef EXIF_DEBUG
      php_error_docref(NULL TSRMLS_CC, E_NOTICE, "Found value of type double");
#endif
      return (size_t)*(double*)value;
  }
  return 0;
}

PJ_DEF(void)
pj_scan_get(pj_scanner* scanner, const pj_cis_t* spec, pj_str_t* out) {
  register char* s = scanner->curptr;
  pj_assert(pj_cis_match(spec, 0) == 0);
  if (!pj_cis_match(spec, *s)) {
    pj_scan_syntax_err(scanner);
    return;
  }
  do {
    ++s;
  } while (pj_cis_match(spec, *s));
  pj_strset3(out, scanner->curptr, s);
  scanner->curptr = s;
  if (PJ_SCAN_IS_PROBABLY_SPACE(*s) && scanner->skip_ws) {
    pj_scan_skip_whitespace(scanner);
  }
}

