static int xfrm_expand_policies(const struct flowi* fl, u16 family,
                                struct xfrm_policy** pols, int* num_pols,
                                int* num_xfrms) {
  int i;
  if (*num_pols == 0 || !pols[0]) {
    *num_pols = 0;
    *num_xfrms = 0;
    return 0;
  }
  if (IS_ERR(pols[0])) return PTR_ERR(pols[0]);
  *num_xfrms = pols[0]->xfrm_nr;
#ifdef CONFIG_XFRM_SUB_POLICY
  if (pols[0]->action == XFRM_POLICY_ALLOW &&
      pols[0]->type != XFRM_POLICY_TYPE_MAIN) {
    pols[1] =
        xfrm_policy_lookup_bytype(xp_net(pols[0]), XFRM_POLICY_TYPE_MAIN, fl,
                                  family, XFRM_POLICY_OUT, pols[0]->if_id);
    if (pols[1]) {
      if (IS_ERR(pols[1])) {
        xfrm_pols_put(pols, *num_pols);
        return PTR_ERR(pols[1]);
      }
      (*num_pols)++;
      (*num_xfrms) += pols[1]->xfrm_nr;
    }
  }
#endif
  for (i = 0; i < *num_pols; i++) {
    if (pols[i]->action != XFRM_POLICY_ALLOW) {
      *num_xfrms = -1;
      break;
    }
  }
  return 0;
}

bittok2str_internal(register const struct tok* lp, register const char* fmt,
                    register u_int v, const char* sep) {
  static char buf[256];
  int buflen = 0;
  register u_int rotbit;
  register u_int tokval;
  const char* sepstr = "";
  while (lp != NULL && lp->s != NULL) {
    tokval = lp->v;
    rotbit = 1;
    while (rotbit != 0) {
      if (tokval == (v & rotbit)) {
        buflen +=
            snprintf(buf + buflen, sizeof(buf) - buflen, "%s%s", sepstr, lp->s);
        sepstr = sep;
        break;
      }
      rotbit = rotbit << 1;
    }
    lp++;
  }
  if (buflen == 0)
    (void)snprintf(buf, sizeof(buf), fmt == NULL ? "#%08x" : fmt, v);
  return (buf);
}

static int get_rx_bufs(struct vhost_virtqueue* vq,
                       struct vring_used_elem* heads, int datalen,
                       unsigned* iovcount, struct vhost_log* log,
                       unsigned* log_num, unsigned int quota) {
  unsigned int out, in;
  int seg = 0;
  int headcount = 0;
  unsigned d;
  int r, nlogs = 0;
  while (datalen > 0 && headcount < quota) {
    if (unlikely(seg >= UIO_MAXIOV)) {
      r = -ENOBUFS;
      goto err;
    }
    d = vhost_get_vq_desc(vq->dev, vq, vq->iov + seg, ARRAY_SIZE(vq->iov) - seg,
                          &out, &in, log, log_num);
    if (d == vq->num) {
      r = 0;
      goto err;
    }
    if (unlikely(out || in <= 0)) {
      vq_err(vq,
             "unexpected descriptor format for RX: "
             "out %d, in %d\n",
             out, in);
      r = -EINVAL;
      goto err;
    }
    if (unlikely(log)) {
      nlogs += *log_num;
      log += *log_num;
    }
    heads[headcount].id = d;
    heads[headcount].len = iov_length(vq->iov + seg, in);
    datalen -= heads[headcount].len;
    ++headcount;
    seg += in;
  }
  heads[headcount - 1].len += datalen;
  *iovcount = seg;
  if (unlikely(log)) *log_num = nlogs;
  return headcount;
err:
  vhost_discard_vq_desc(vq, headcount);
  return r;
}

optional<ARN> ARN::parse(const string& s, bool wildcards) {
  static const char str_wild[] = "arn:([^:]*):([^:]*):([^:]*):([^:]*):([^:]*)";
  static const regex rx_wild(str_wild, sizeof(str_wild) - 1,
                             ECMAScript | optimize);
  static const char str_no_wild[] =
      "arn:([^:*]*):([^:*]*):([^:*]*):([^:*]*):([^:*]*)";
  static const regex rx_no_wild(str_no_wild, sizeof(str_no_wild) - 1,
                                ECMAScript | optimize);
  smatch match;
  if ((s == "*") && wildcards) {
    return ARN(Partition::wildcard, Service::wildcard, "*", "*", "*");
  } else if (regex_match(s, match, wildcards ? rx_wild : rx_no_wild)) {
    ceph_assert(match.size() == 6);
    ARN a;
    {
      auto p = to_partition(match[1], wildcards);
      if (!p) return none;
      a.partition = *p;
    }
    {
      auto s = to_service(match[2], wildcards);
      if (!s) {
        return none;
      }
      a.service = *s;
    }
    a.region = match[3];
    a.account = match[4];
    a.resource = match[5];
    return a;
  }
  return none;
}

struct vfsmount* clone_private_mount(const struct path* path) {
  struct mount* old_mnt = real_mount(path->mnt);
  struct mount* new_mnt;
  if (IS_MNT_UNBINDABLE(old_mnt)) return ERR_PTR(-EINVAL);
  new_mnt = clone_mnt(old_mnt, path->dentry, CL_PRIVATE);
  if (IS_ERR(new_mnt)) return ERR_CAST(new_mnt);
  new_mnt->mnt_ns = MNT_NS_INTERNAL;
  return &new_mnt->mnt;
}

header_put_be_8byte(SF_PRIVATE* psf, sf_count_t x) {
  if (psf->headindex < SIGNED_SIZEOF(psf->header) - 8) {
    psf->header[psf->headindex++] = 0;
    psf->header[psf->headindex++] = 0;
    psf->header[psf->headindex++] = 0;
    psf->header[psf->headindex++] = 0;
    psf->header[psf->headindex++] = (x >> 24);
    psf->header[psf->headindex++] = (x >> 16);
    psf->header[psf->headindex++] = (x >> 8);
    psf->header[psf->headindex++] = x;
  };
}

