static int skcipher_accept_parent(void* private, struct sock* sk) {
  struct skcipher_ctx* ctx;
  struct alg_sock* ask = alg_sk(sk);
  unsigned int len = sizeof(*ctx) + crypto_skcipher_reqsize(private);
  ctx = sock_kmalloc(sk, len, GFP_KERNEL);
  if (!ctx) return -ENOMEM;
  ctx->iv = sock_kmalloc(sk, crypto_skcipher_ivsize(private), GFP_KERNEL);
  if (!ctx->iv) {
    sock_kfree_s(sk, ctx, len);
    return -ENOMEM;
  }
  memset(ctx->iv, 0, crypto_skcipher_ivsize(private));
  INIT_LIST_HEAD(&ctx->tsgl);
  ctx->len = len;
  ctx->used = 0;
  ctx->more = 0;
  ctx->merge = 0;
  ctx->enc = 0;
  atomic_set(&ctx->inflight, 0);
  af_alg_init_completion(&ctx->completion);
  ask->private = ctx;
  skcipher_request_set_tfm(&ctx->req, private);
  skcipher_request_set_callback(&ctx->req, CRYPTO_TFM_REQ_MAY_BACKLOG,
                                af_alg_complete, &ctx->completion);
  sk->sk_destruct = skcipher_sock_destruct;
  return 0;
}

static gboolean irssi_ssl_verify(SSL* ssl, SSL_CTX* ctx, X509* cert) {
  if (SSL_get_verify_result(ssl) != X509_V_OK) {
    unsigned char md[EVP_MAX_MD_SIZE];
    unsigned int n;
    char* str;
    g_warning("Could not verify SSL servers certificate:");
    if ((str = X509_NAME_oneline(X509_get_subject_name(cert), 0, 0)) == NULL)
      g_warning("  Could not get subject-name from peer certificate");
    else {
      g_warning("  Subject : %s", str);
      free(str);
    }
    if ((str = X509_NAME_oneline(X509_get_issuer_name(cert), 0, 0)) == NULL)
      g_warning("  Could not get issuer-name from peer certificate");
    else {
      g_warning("  Issuer  : %s", str);
      free(str);
    }
    if (!X509_digest(cert, EVP_md5(), md, &n))
      g_warning("  Could not get fingerprint from peer certificate");
    else {
      char hex[] = "0123456789ABCDEF";
      char fp[EVP_MAX_MD_SIZE * 3];
      if (n < sizeof(fp)) {
        unsigned int i;
        for (i = 0; i < n; i++) {
          fp[i * 3 + 0] = hex[(md[i] >> 4) & 0xF];
          fp[i * 3 + 1] = hex[(md[i] >> 0) & 0xF];
          fp[i * 3 + 2] = i == n - 1 ? '\0' : ':';
        }
        g_warning("  MD5 Fingerprint : %s", fp);
      }
    }
    return FALSE;
  }
  return TRUE;
}

int nft_expr_inner_parse(const struct nft_ctx* ctx, const struct nlattr* nla,
                         struct nft_expr_info* info) {
  struct nlattr* tb[NFTA_EXPR_MAX + 1];
  const struct nft_expr_type* type;
  int err;
  err = nla_parse_nested_deprecated(tb, NFTA_EXPR_MAX, nla, nft_expr_policy,
                                    NULL);
  if (err < 0) return err;
  if (!tb[NFTA_EXPR_DATA]) return -EINVAL;
  type = __nft_expr_type_get(ctx->family, tb[NFTA_EXPR_NAME]);
  if (!type) return -ENOENT;
  if (!type->inner_ops) return -EOPNOTSUPP;
  err = nla_parse_nested_deprecated(info->tb, type->maxattr, tb[NFTA_EXPR_DATA],
                                    type->policy, NULL);
  if (err < 0) goto err_nla_parse;
  info->attr = nla;
  info->ops = type->inner_ops;
  return 0;
err_nla_parse:
  return err;
}

void processInputBuffer(client* c) {
  server.current_client = c;
  while (sdslen(c->querybuf)) {
    if (!(c->flags & CLIENT_SLAVE) && clientsArePaused()) break;
    if (c->flags & CLIENT_BLOCKED) break;
    if (c->flags & CLIENT_CLOSE_AFTER_REPLY) break;
    if (!c->reqtype) {
      if (c->querybuf[0] == '*') {
        c->reqtype = PROTO_REQ_MULTIBULK;
      } else {
        c->reqtype = PROTO_REQ_INLINE;
      }
    }
    if (c->reqtype == PROTO_REQ_INLINE) {
      if (processInlineBuffer(c) != C_OK) break;
    } else if (c->reqtype == PROTO_REQ_MULTIBULK) {
      if (processMultibulkBuffer(c) != C_OK) break;
    } else {
      serverPanic("Unknown request type");
    }
    if (c->argc == 0) {
      resetClient(c);
    } else {
      if (processCommand(c) == C_OK) resetClient(c);
      if (server.current_client == NULL) break;
    }
  }
  server.current_client = NULL;
}

