gs_font_map_glyph_to_unicode(gs_font* font, gs_glyph glyph, int ch, ushort* u,
                             unsigned int length) {
  font_data* pdata = pfont_data(font);
  const ref* UnicodeDecoding;
  uchar* unicode_return = (uchar*)u;
  if (r_type(&pdata->GlyphNames2Unicode) == t_dictionary) {
    int c = gs_font_map_glyph_by_dict(font->memory, &pdata->GlyphNames2Unicode,
                                      glyph, u, length);
    if (c != 0) return c;
    if (ch != -1) {
      ref *v, n;
      make_int(&n, ch);
      if (dict_find(&pdata->GlyphNames2Unicode, &n, &v) > 0) {
        if (r_has_type(v, t_string)) {
          int l = r_size(v);
          if (l > length) return l;
          memcpy(unicode_return, v->value.const_bytes, l * sizeof(short));
          return l;
        }
        if (r_type(v) == t_integer) {
          if (v->value.intval > 65535) {
            if (length < 4) return 4;
            unicode_return[0] = v->value.intval >> 24;
            unicode_return[1] = (v->value.intval & 0x00FF0000) >> 16;
            unicode_return[2] = (v->value.intval & 0x0000FF00) >> 8;
            unicode_return[3] = v->value.intval & 0xFF;
            return 4;
          } else {
            if (length < 2) return 2;
            unicode_return[0] = v->value.intval >> 8;
            unicode_return[1] = v->value.intval & 0xFF;
            return 2;
          }
        }
      }
    }
  }
  if (glyph <= GS_MIN_CID_GLYPH) {
    UnicodeDecoding = zfont_get_to_unicode_map(font->dir);
    if (UnicodeDecoding != NULL && r_type(UnicodeDecoding) == t_dictionary)
      return gs_font_map_glyph_by_dict(font->memory, UnicodeDecoding, glyph, u,
                                       length);
  }
  return 0;
}

static int __nla_validate_parse(const struct nlattr* head, int len, int maxtype,
                                const struct nla_policy* policy,
                                unsigned int validate,
                                struct netlink_ext_ack* extack,
                                struct nlattr** tb) {
  const struct nlattr* nla;
  int rem;
  if (tb) memset(tb, 0, sizeof(struct nlattr*) * (maxtype + 1));
  nla_for_each_attr(nla, head, len, rem) {
    u16 type = nla_type(nla);
    if (type == 0 || type > maxtype) {
      if (validate & NL_VALIDATE_MAXTYPE) {
        NL_SET_ERR_MSG_ATTR(extack, nla, "Unknown attribute type");
        return -EINVAL;
      }
      continue;
    }
    if (policy) {
      int err = validate_nla(nla, maxtype, policy, validate, extack);
      if (err < 0) return err;
    }
    if (tb) tb[type] = (struct nlattr*)nla;
  }
  if (unlikely(rem > 0)) {
    pr_warn_ratelimited(
        "netlink: %d bytes leftover after parsing attributes in process "
        "`%s'.\n",
        rem, current->comm);
    NL_SET_ERR_MSG(extack, "bytes leftover after parsing attributes");
    if (validate & NL_VALIDATE_TRAILING) return -EINVAL;
  }
  return 0;
}

AcpiPsCompleteFinalOp(ACPI_WALK_STATE* WalkState, ACPI_PARSE_OBJECT* Op,
                      ACPI_STATUS Status) {
  ACPI_STATUS Status2;
  ACPI_FUNCTION_TRACE_PTR(PsCompleteFinalOp, WalkState);
  ACPI_DEBUG_PRINT((ACPI_DB_PARSE, "AML package complete at Op %p\n", Op));
  do {
    if (Op) {
      if (WalkState->AscendingCallback != NULL) {
        WalkState->Op = Op;
        WalkState->OpInfo = AcpiPsGetOpcodeInfo(Op->Common.AmlOpcode);
        WalkState->Opcode = Op->Common.AmlOpcode;
        Status = WalkState->AscendingCallback(WalkState);
        Status = AcpiPsNextParseState(WalkState, Op, Status);
        if (Status == AE_CTRL_PENDING) {
          Status = AcpiPsCompleteOp(WalkState, &Op, AE_OK);
          if (ACPI_FAILURE(Status)) {
            return_ACPI_STATUS(Status);
          }
        }
        if (Status == AE_CTRL_TERMINATE) {
          Status = AE_OK;
          do {
            if (Op) {
              Status2 = AcpiPsCompleteThisOp(WalkState, Op);
              if (ACPI_FAILURE(Status2)) {
                return_ACPI_STATUS(Status2);
              }
            }
            AcpiPsPopScope(&(WalkState->ParserState), &Op, &WalkState->ArgTypes,
                           &WalkState->ArgCount);
          } while (Op);
          return_ACPI_STATUS(Status);
        } else if (ACPI_FAILURE(Status)) {
          (void)AcpiPsCompleteThisOp(WalkState, Op);
          return_ACPI_STATUS(Status);
        }
      }
      Status2 = AcpiPsCompleteThisOp(WalkState, Op);
      if (ACPI_FAILURE(Status2)) {
        return_ACPI_STATUS(Status2);
      }
    }
    AcpiPsPopScope(&(WalkState->ParserState), &Op, &WalkState->ArgTypes,
                   &WalkState->ArgCount);
  } while (Op);
  return_ACPI_STATUS(Status);
}

static struct nfs4_state* nfs4_try_open_cached(struct nfs4_opendata* opendata) {
  struct nfs4_state* state = opendata->state;
  struct nfs_inode* nfsi = NFS_I(state->inode);
  struct nfs_delegation* delegation;
  int open_mode =
      opendata->o_arg.open_flags & (FMODE_READ | FMODE_WRITE | O_EXCL);
  nfs4_stateid stateid;
  int ret = -EAGAIN;
  for (;;) {
    if (can_open_cached(state, open_mode)) {
      spin_lock(&state->owner->so_lock);
      if (can_open_cached(state, open_mode)) {
        update_open_stateflags(state, open_mode);
        spin_unlock(&state->owner->so_lock);
        goto out_return_state;
      }
      spin_unlock(&state->owner->so_lock);
    }
    rcu_read_lock();
    delegation = rcu_dereference(nfsi->delegation);
    if (delegation == NULL || !can_open_delegated(delegation, open_mode)) {
      rcu_read_unlock();
      break;
    }
    memcpy(stateid.data, delegation->stateid.data, sizeof(stateid.data));
    rcu_read_unlock();
    ret = nfs_may_open(state->inode, state->owner->so_cred, open_mode);
    if (ret != 0) goto out;
    ret = -EAGAIN;
    if (update_open_stateid(state, NULL, &stateid, open_mode))
      goto out_return_state;
  }
out:
  return ERR_PTR(ret);
out_return_state:
  atomic_inc(&state->count);
  return state;
}

static int huft_build(const unsigned* b, const unsigned n, const unsigned s,
                      const unsigned short* d, const unsigned char* e,
                      huft_t** t, unsigned* m) {
  unsigned a;
  unsigned c[BMAX + 1];
  unsigned eob_len;
  unsigned f;
  int g;
  int htl;
  unsigned i;
  unsigned j;
  int k;
  unsigned* p;
  huft_t* q;
  huft_t r;
  huft_t* u[BMAX];
  unsigned v[N_MAX];
  int ws[BMAX + 1];
  int w;
  unsigned x[BMAX + 1];
  int y;
  unsigned z;
  eob_len = n > 256 ? b[256] : BMAX;
  *t = NULL;
  memset(c, 0, sizeof(c));
  p = (unsigned*)b;
  i = n;
  do {
    c[*p]++;
  } while (--i);
  if (c[0] == n) {
    *m = 0;
    return 2;
  }
  for (j = 1; (j <= BMAX) && (c[j] == 0); j++) continue;
  k = j;
  for (i = BMAX; (c[i] == 0) && i; i--) continue;
  g = i;
  *m = (*m < j) ? j : ((*m > i) ? i : *m);
  for (y = 1 << j; j < i; j++, y <<= 1) {
    y -= c[j];
    if (y < 0) return 2;
  }
  y -= c[i];
  if (y < 0) return 2;
  c[i] += y;
  x[1] = j = 0;
  p = c + 1;
  xp = x + 2;
  while (--i) {
    j += *p++;
    *xp++ = j;
  }
}

file_extension(const char* s) {
  const char* extension;
  static char buf[1024];
  if (s == NULL)
    return (NULL);
  else if (!strncmp(s, "data:image/bmp;", 15))
    return ("bmp");
  else if (!strncmp(s, "data:image/gif;", 15))
    return ("gif");
  else if (!strncmp(s, "data:image/jpeg;", 16))
    return ("jpg");
  else if (!strncmp(s, "data:image/png;", 15))
    return ("png");
  else if ((extension = strrchr(s, '/')) != NULL)
    extension++;
  else if ((extension = strrchr(s, '\\')) != NULL)
    extension++;
  else
    extension = s;
  if ((extension = strrchr(extension, '.')) == NULL)
    return ("");
  else
    extension++;
  if (strchr(extension, '#') == NULL) return (extension);
  strlcpy(buf, extension, sizeof(buf));
  *(char*)strchr(buf, '#') = '\0';
  return (buf);
}

