_gnutls_server_name_recv_params(gnutls_session_t session, const opaque* data,
                                size_t _data_size) {
  int i;
  const unsigned char* p;
  uint16_t len, type;
  ssize_t data_size = _data_size;
  int server_names = 0;
  if (session->security_parameters.entity == GNUTLS_SERVER) {
    DECR_LENGTH_RET(data_size, 2, 0);
    len = _gnutls_read_uint16(data);
    if (len != data_size) {
      gnutls_assert();
      return 0;
    }
    p = data + 2;
    while (data_size > 0) {
      DECR_LENGTH_RET(data_size, 1, 0);
      p++;
      DECR_LEN(data_size, 2);
      len = _gnutls_read_uint16(p);
      p += 2;
      DECR_LENGTH_RET(data_size, len, 0);
      server_names++;
      p += len;
    }
    session->security_parameters.extensions.server_names_size = server_names;
    if (server_names == 0) return 0;
    if (server_names > MAX_SERVER_NAME_EXTENSIONS)
      server_names = MAX_SERVER_NAME_EXTENSIONS;
    p = data + 2;
    for (i = 0; i < server_names; i++) {
      type = *p;
      p++;
      len = _gnutls_read_uint16(p);
      p += 2;
      switch (type) {
        case 0:
          if (len <= MAX_SERVER_NAME_SIZE) {
            memcpy(session->security_parameters.extensions.server_names[i].name,
                   p, len);
            session->security_parameters.extensions.server_names[i]
                .name_length = len;
            session->security_parameters.extensions.server_names[i].type =
                GNUTLS_NAME_DNS;
            break;
          }
      }
      p += len;
    }
  }
  return 0;
}

void xmlrpc_char_encode(char* outbuffer, const char* s1) {
  long unsigned int i;
  unsigned char c;
  char buf2[15];
  mowgli_string_t* s = mowgli_string_create();
  *buf2 = '\0';
  *outbuffer = '\0';
  if ((!(s1) || (*(s1) == '\0'))) {
    return;
  }
  for (i = 0; s1[i] != '\0'; i++) {
    c = s1[i];
    if (c > 127) {
      snprintf(buf2, sizeof buf2, "&#%d;", c);
      s->append(s, buf2, strlen(buf2));
    } else if (c == '&') {
      s->append(s, "&amp;", 5);
    } else if (c == '<') {
      s->append(s, "&lt;", 4);
    } else if (c == '>') {
      s->append(s, "&gt;", 4);
    } else if (c == '"') {
      s->append(s, "&quot;", 6);
    } else {
      s->append_char(s, c);
    }
  }
  memcpy(outbuffer, s->str, XMLRPC_BUFSIZE);
}

