bool ReturnsValidPath(int dir_type) {
  base::FilePath path;
  bool result = PathService::Get(dir_type, &path);
  bool check_path_exists = true;
#if defined(OS_POSIX)
  if (dir_type == base::DIR_CACHE) check_path_exists = false;
#endif
#if defined(OS_LINUX)
  if (dir_type == base::DIR_USER_DESKTOP) check_path_exists = false;
#endif
#if defined(OS_WIN)
  if (dir_type == base::DIR_DEFAULT_USER_QUICK_LAUNCH) {
    if (base::win::GetVersion() < base::win::VERSION_VISTA) {
      wchar_t default_profile_path[MAX_PATH];
      DWORD size = arraysize(default_profile_path);
      return (result &&
              ::GetDefaultUserProfileDirectory(default_profile_path, &size) &&
              StartsWith(path.value(), default_profile_path, false));
    }
  } else if (dir_type == base::DIR_TASKBAR_PINS) {
    if (base::win::GetVersion() < base::win::VERSION_WIN7)
      check_path_exists = false;
  }
#endif
#if defined(OS_MAC)
  if (dir_type != base::DIR_EXE && dir_type != base::DIR_MODULE &&
      dir_type != base::FILE_EXE && dir_type != base::FILE_MODULE) {
    if (path.ReferencesParent()) return false;
  }
#else
  if (path.ReferencesParent()) return false;
#endif
  return result && !path.empty() &&
         (!check_path_exists || file_util::PathExists(path));
}

static void nfs4_return_incompatible_delegation(struct inode* inode,
                                                mode_t open_flags) {
  struct nfs_delegation* delegation;
  rcu_read_lock();
  delegation = rcu_dereference(NFS_I(inode)->delegation);
  if (delegation == NULL || (delegation->type & open_flags) == open_flags) {
    rcu_read_unlock();
    return;
  }
  rcu_read_unlock();
  nfs_inode_return_delegation(inode);
}

string handleGet(map<string, string>* reqHeaders) {
  long long sessionId = -1;
  long uid = -1;
  string uri = (*reqHeaders)["uri"];
  string body;
  if (reqHeaders->count("Cookie") != 0) {
    string cookies = (*reqHeaders)["Cookie"];
    string sessionIdString = cookies.substr(cookies.find("=") + 1);
    sessionId = stoll(sessionIdString, nullptr);
    auto usersessionIt = sessionMap.find(sessionId);
    if (usersessionIt == sessionMap.end()) {
      cout << "Bad session ID, redirecting to login." << endl;
      body = getLogin();
    } else
      uid = sessionMap[sessionId];
  }
  map<string, string> resHeaders;
  resHeaders["Server"] = "CSE461";
  resHeaders["Content-Type"] = "text/html; charset=UTF-8";
  if (uri.compare("/cal") == 0 && uid == -1) {
    cout << "login page" << endl;
    body = getLogin();
  } else if (uri.compare("/cal") == 0 && uid != -1) {
    cout << "cal page" << endl;
    string username = userNameById(uid);
    body = getHeader(username);
    body += getEmptyCalendar();
    body += getFooter();
  } else if (uri.compare("/getEvents") == 0 && uid != -1) {
    body = getEventsJson(uid);
    resHeaders["Content-Type"] = "application/json; charset=UTF-8";
  } else {
    cout << "error page" << endl;
    string message = "404 Page Not Found";
    return getResponseHeader("HTTP/1.1 404 Not Found", &resHeaders,
                             body.size()) +
           "\r\n" + message;
  }
  return getResponseHeader("HTTP/1.1 200 OK", &resHeaders, body.size()) +
         "\r\n" + body;
}

String string_chunk_split(const char* src, int srclen, const char* end,
                          int endlen, int chunklen) {
  int chunks = srclen / chunklen;
  int restlen = srclen - chunks * chunklen;
  int out_len = (chunks + 1) * endlen + srclen;
  String ret(out_len, ReserveString);
  char* dest = ret.bufferSlice().ptr;
  const char* p;
  char* q;
  const char* pMax = src + srclen - chunklen + 1;
  for (p = src, q = dest; p < pMax;) {
    memcpy(q, p, chunklen);
    q += chunklen;
    memcpy(q, end, endlen);
    q += endlen;
    p += chunklen;
  }
  if (restlen) {
    memcpy(q, p, restlen);
    q += restlen;
    memcpy(q, end, endlen);
    q += endlen;
  }
  ret.setSize(q - dest);
  return ret;
}

static Jsi_RC jsi_ArrayFillCmd(Jsi_Interp* interp, Jsi_Value* args,
                               Jsi_Value* _this, Jsi_Value** ret,
                               Jsi_Func* funcPtr) {
  if (_this->vt != JSI_VT_OBJECT || !Jsi_ObjIsArray(interp, _this->d.obj))
    return Jsi_LogError("expected array object");
  Jsi_RC rc = JSI_OK;
  int istart = 0, iend, n, nsiz;
  Jsi_Number nstart = 0, nend = 0;
  Jsi_Value *value = Jsi_ValueArrayIndex(interp, args, 0),
            *start = Jsi_ValueArrayIndex(interp, args, 1),
            *end = Jsi_ValueArrayIndex(interp, args, 2);
  Jsi_Obj* obj = _this->d.obj;
  n = Jsi_ObjGetLength(interp, obj);
  if (start && Jsi_GetNumberFromValue(interp, start, &nstart) == JSI_OK) {
    istart = (int)nstart;
    if (istart > n) goto bail;
    if (istart < 0) istart = (n + istart);
    if (istart < 0) goto bail;
  }
  if (n == 0) {
    goto bail;
  }
  iend = n - 1;
  if (end && Jsi_GetNumberFromValue(interp, end, &nend) == JSI_OK) {
    iend = (int)nend;
    if (iend >= n) iend = n;
    if (iend < 0) iend = (n + iend);
    if (iend < 0) goto bail;
  }
  nsiz = iend - istart + 1;
  if (nsiz <= 0) goto bail;
  int i;
  for (i = istart; i <= iend; i++) {
    if (obj->arr[i])
      Jsi_ValueCopy(interp, obj->arr[i], value);
    else
      obj->arr[i] = Jsi_ValueDup(interp, value);
  }
bail:
  if (_this != *ret) {
    Jsi_ValueMove(interp, *ret, _this);
  }
  return rc;
}

