static int __ptrace_may_access(struct task_struct* task, unsigned int mode) {
  const struct cred *cred = current_cred(), *tcred;
  int dumpable = 0;
  if (same_thread_group(task, current)) return 0;
  rcu_read_lock();
  tcred = __task_cred(task);
  if (uid_eq(cred->uid, tcred->euid) && uid_eq(cred->uid, tcred->suid) &&
      uid_eq(cred->uid, tcred->uid) && gid_eq(cred->gid, tcred->egid) &&
      gid_eq(cred->gid, tcred->sgid) && gid_eq(cred->gid, tcred->gid))
    goto ok;
  if (ptrace_has_cap(tcred->user_ns, mode)) goto ok;
  rcu_read_unlock();
  return -EPERM;
ok:
  rcu_read_unlock();
  smp_rmb();
  if (task->mm) dumpable = get_dumpable(task->mm);
  rcu_read_lock();
  if (!dumpable && !ptrace_has_cap(__task_cred(task)->user_ns, mode)) {
    rcu_read_unlock();
    return -EPERM;
  }
  rcu_read_unlock();
  return security_ptrace_access_check(task, mode);
}

srs_timestamp_check(srs_t* srs, const char* stamp) {
  const char* sp;
  char* bp;
  int off;
  time_t now;
  time_t then;
  then = 0;
  for (sp = stamp; *sp; sp++) {
    bp = strchr(SRS_TIME_BASECHARS, toupper(*sp));
    if (bp == NULL) return SRS_EBADTIMESTAMPCHAR;
    off = bp - SRS_TIME_BASECHARS;
    then = (then << SRS_TIME_BASEBITS) | off;
  }
  time(&now);
  now = (now / SRS_TIME_PRECISION) % SRS_TIME_SLOTS;
  while (now < then) now = now + SRS_TIME_SLOTS;
  if (now <= then + srs->maxage) return SRS_SUCCESS;
  return SRS_ETIMESTAMPOUTOFDATE;
}

rx_cache_insert(netdissect_options* ndo, const u_char* bp, const struct ip* ip,
                int dport) {
  struct rx_cache_entry* rxent;
  const struct rx_header* rxh = (const struct rx_header*)bp;
  if (ndo->ndo_snapend - bp + 1 <=
      (int)(sizeof(struct rx_header) + sizeof(int32_t)))
    return;
  rxent = &rx_cache[rx_cache_next];
  if (++rx_cache_next >= RX_CACHE_SIZE) rx_cache_next = 0;
  rxent->callnum = EXTRACT_32BITS(&rxh->callNumber);
  UNALIGNED_MEMCPY(&rxent->client, &ip->ip_src, sizeof(uint32_t));
  UNALIGNED_MEMCPY(&rxent->server, &ip->ip_dst, sizeof(uint32_t));
  rxent->dport = dport;
  rxent->serviceId = EXTRACT_32BITS(&rxh->serviceId);
  rxent->opcode = EXTRACT_32BITS(bp + sizeof(struct rx_header));
}

path_in(PG_FUNCTION_ARGS) {
  char* str = PG_GETARG_CSTRING(0);
  PATH* path;
  int isopen;
  char* s;
  int npts;
  int size;
  int depth = 0;
  if ((npts = pair_count(str, ',')) <= 0)
    ereport(ERROR, (errcode(ERRCODE_INVALID_TEXT_REPRESENTATION),
                    errmsg("invalid input syntax for type path: \"%s\"", str)));
  s = str;
  while (isspace((unsigned char)*s)) s++;
  if ((*s == LDELIM) && (strrchr(s, LDELIM) == s)) {
    s++;
    depth++;
  }
  size = offsetof(PATH, p[0]) + sizeof(path->p[0]) * npts;
  path = (PATH*)palloc(size);
  SET_VARSIZE(path, size);
  path->npts = npts;
  if ((!path_decode(TRUE, npts, s, &isopen, &s, &(path->p[0]))) &&
      (!((depth == 0) && (*s == '\0'))) && !((depth >= 1) && (*s == RDELIM)))
    ereport(ERROR, (errcode(ERRCODE_INVALID_TEXT_REPRESENTATION),
                    errmsg("invalid input syntax for type path: \"%s\"", str)));
  path->closed = (!isopen);
  path->dummy = 0;
  PG_RETURN_PATH_P(path);
}

static unsigned long ioapic_read_indirect(struct kvm_ioapic* ioapic,
                                          unsigned long addr,
                                          unsigned long length) {
  unsigned long result = 0;
  switch (ioapic->ioregsel) {
    case IOAPIC_REG_VERSION:
      result =
          ((((IOAPIC_NUM_PINS - 1) & 0xff) << 16) | (IOAPIC_VERSION_ID & 0xff));
      break;
    case IOAPIC_REG_APIC_ID:
    case IOAPIC_REG_ARB_ID:
      result = ((ioapic->id & 0xf) << 24);
      break;
    default: {
      u32 redir_index = (ioapic->ioregsel - 0x10) >> 1;
      u64 redir_content;
      ASSERT(redir_index < IOAPIC_NUM_PINS);
      redir_content = ioapic->redirtbl[redir_index].bits;
      result = (ioapic->ioregsel & 0x1) ? (redir_content >> 32) & 0xffffffff
                                        : redir_content & 0xffffffff;
      break;
    }
  }
  return result;
}

