static void nfs_set_open_stateid_locked(struct nfs4_state* state,
                                        nfs4_stateid* stateid, int open_flags) {
  if (test_bit(NFS_DELEGATED_STATE, &state->flags) == 0)
    memcpy(state->stateid.data, stateid->data, sizeof(state->stateid.data));
  memcpy(state->open_stateid.data, stateid->data,
         sizeof(state->open_stateid.data));
  switch (open_flags) {
    case FMODE_READ:
      set_bit(NFS_O_RDONLY_STATE, &state->flags);
      break;
    case FMODE_WRITE:
      set_bit(NFS_O_WRONLY_STATE, &state->flags);
      break;
    case FMODE_READ | FMODE_WRITE:
      set_bit(NFS_O_RDWR_STATE, &state->flags);
  }
}

static void read_version(struct pbap_data* pbap, GObexApparam* apparam) {
  const guint8* data;
  uint8_t value[16];
  gsize len;
  if (!(pbap->supported_features & FOLDER_VERSION_FEATURE)) return;
  if (!g_obex_apparam_get_bytes(apparam, PRIMARY_COUNTER_TAG, &data, &len)) {
    len = sizeof(value);
    memset(value, 0, len);
    data = value;
  }
  if (memcmp(pbap->primary, data, len)) {
    memcpy(pbap->primary, data, len);
    g_dbus_emit_property_changed(conn, obc_session_get_path(pbap->session),
                                 PBAP_INTERFACE, "PrimaryCounter");
  }
  if (!g_obex_apparam_get_bytes(apparam, SECONDARY_COUNTER_TAG, &data, &len)) {
    len = sizeof(value);
    memset(value, 0, len);
    data = value;
  }
  if (memcmp(pbap->secondary, data, len)) {
    memcpy(pbap->secondary, data, len);
    g_dbus_emit_property_changed(conn, obc_session_get_path(pbap->session),
                                 PBAP_INTERFACE, "SecondaryCounter");
  }
}

static MagickBooleanType SkipDXTMipmaps(Image* image, DDSInfo* dds_info,
                                        int texel_size,
                                        ExceptionInfo* exception) {
  register ssize_t i;
  MagickOffsetType offset;
  size_t h, w;
  if (EOFBlob(image) != MagickFalse) {
    ThrowFileException(exception, CorruptImageError, "UnexpectedEndOfFile",
                       image->filename);
    return (MagickFalse);
  }
  if (dds_info->ddscaps1 & DDSCAPS_MIPMAP &&
      (dds_info->ddscaps1 & DDSCAPS_TEXTURE ||
       dds_info->ddscaps2 & DDSCAPS2_CUBEMAP)) {
    w = DIV2(dds_info->width);
    h = DIV2(dds_info->height);
    for (i = 1; (i < (ssize_t)dds_info->mipmapcount) && w && h; i++) {
      offset = (MagickOffsetType)((w + 3) / 4) * ((h + 3) / 4) * texel_size;
      (void)SeekBlob(image, offset, SEEK_CUR);
      w = DIV2(w);
      h = DIV2(h);
    }
  }
  return (MagickTrue);
}

ldbm_txn_ruv_modify_context(Slapi_PBlock* pb, modify_context* mc) {
  char* uniqueid = NULL;
  backend* be;
  Slapi_Mods* smods = NULL;
  struct backentry* bentry;
  entry_address bentry_addr;
  IFP fn = NULL;
  int rc = 0;
  back_txn txn = {NULL};
  slapi_pblock_get(pb, SLAPI_TXN_RUV_MODS_FN, (void*)&fn);
  slapi_pblock_get(pb, SLAPI_TXN, &txn.back_txn_txn);
  if (NULL == fn) {
    return (0);
  }
  rc = (*fn)(pb, &uniqueid, &smods);
  if (1 != rc || NULL == smods || NULL == uniqueid) {
    return (rc);
  }
  slapi_pblock_get(pb, SLAPI_BACKEND, &be);
  bentry_addr.sdn = NULL;
  bentry_addr.udn = NULL;
  bentry_addr.uniqueid = uniqueid;
  bentry = find_entry2modify_only(pb, be, &bentry_addr, &txn);
  if (NULL == bentry) {
    LDAPDebug(LDAP_DEBUG_ANY,
              "Error: ldbm_txn_ruv_modify_context failed to retrieve and lock "
              "RUV entry\n",
              0, 0, 0);
    rc = -1;
    goto done;
  }
  modify_init(mc, bentry);
  if (modify_apply_mods_ignore_error(mc, smods, LDAP_TYPE_OR_VALUE_EXISTS)) {
    LDAPDebug(LDAP_DEBUG_ANY,
              "Error: ldbm_txn_ruv_modify_context failed to apply updates to "
              "RUV entry\n",
              0, 0, 0);
    rc = -1;
    modify_term(mc, be);
  }
done:
  slapi_ch_free_string(&uniqueid);
  return (rc);
}

static int32_t check_load_area(uintptr_t dst, uintptr_t len) {
  uint32_t legacy = dst + len <= UINT32_MAX - 1 ? 1 : 0;
  uintptr_t dram_start, dram_end;
  uintptr_t prot_start, prot_end;
  int32_t result = IO_SUCCESS;
  dram_start = legacy ? DRAM1_BASE : DRAM_40BIT_BASE;
  dram_end =
      legacy ? DRAM1_BASE + DRAM1_SIZE : DRAM_40BIT_BASE + DRAM_40BIT_SIZE;
  prot_start = legacy ? DRAM_PROTECTED_BASE : DRAM_40BIT_PROTECTED_BASE;
  prot_end = prot_start + DRAM_PROTECTED_SIZE;
  if (dst < dram_start || dst > dram_end - len) {
    ERROR("BL2: dst address is on the protected area.\n");
    result = IO_FAIL;
    goto done;
  }
  if (dst >= prot_start && dst < prot_end) {
    ERROR("BL2: dst address is on the protected area.\n");
    result = IO_FAIL;
  }
  if (dst < prot_start && dst > prot_start - len) {
    ERROR("BL2: loaded data is on the protected area.\n");
    result = IO_FAIL;
  }
done:
  if (result == IO_FAIL) {
    ERROR("BL2: Out of range : dst=0x%lx len=0x%lx\n", dst, len);
  }
  return result;
}

