_parse_pat(GstMpegtsSection* section) {
  GPtrArray* pat;
  guint16 i = 0, nb_programs;
  GstMpegtsPatProgram* program;
  guint8 *data, *end;
  data = section->data + 8;
  end = section->data + section->section_length;
  nb_programs = (end - 4 - data) / 4;
  pat = g_ptr_array_new_full(nb_programs,
                             (GDestroyNotify)_mpegts_pat_program_free);
  while (data < end - 4) {
    program = g_slice_new0(GstMpegtsPatProgram);
    program->program_number = GST_READ_UINT16_BE(data);
    data += 2;
    program->network_or_program_map_PID = GST_READ_UINT16_BE(data) & 0x1FFF;
    data += 2;
    g_ptr_array_index(pat, i) = program;
    i++;
  }
  pat->len = nb_programs;
  if (data != end - 4) {
    GST_ERROR("at the end of PAT data != end - 4");
    g_ptr_array_unref(pat);
    return NULL;
  }
  return (gpointer)pat;
}

static int snd_seq_ioctl_create_port(struct snd_seq_client* client, void* arg) {
  struct snd_seq_port_info* info = arg;
  struct snd_seq_client_port* port;
  struct snd_seq_port_callback* callback;
  if (info->addr.client != client->number) return -EPERM;
  port = snd_seq_create_port(
      client,
      (info->flags & SNDRV_SEQ_PORT_FLG_GIVEN_PORT) ? info->addr.port : -1);
  if (port == NULL) return -ENOMEM;
  if (client->type == USER_CLIENT && info->kernel) {
    snd_seq_delete_port(client, port->addr.port);
    return -EINVAL;
  }
  if (client->type == KERNEL_CLIENT) {
    if ((callback = info->kernel) != NULL) {
      if (callback->owner) port->owner = callback->owner;
      port->private_data = callback->private_data;
      port->private_free = callback->private_free;
      port->event_input = callback->event_input;
      port->c_src.open = callback->subscribe;
      port->c_src.close = callback->unsubscribe;
      port->c_dest.open = callback->use;
      port->c_dest.close = callback->unuse;
    }
  }
  info->addr = port->addr;
  snd_seq_set_port_info(port, info);
  snd_seq_system_client_ev_port_start(port->addr.client, port->addr.port);
  return 0;
}

int ipmi_si_port_setup(struct si_sm_io* io) {
  unsigned int addr = io->addr_data;
  int idx;
  if (!addr) return -ENODEV;
  io->io_cleanup = port_cleanup;
  switch (io->regsize) {
    case 1:
      io->inputb = port_inb;
      io->outputb = port_outb;
      break;
    case 2:
      io->inputb = port_inw;
      io->outputb = port_outw;
      break;
    case 4:
      io->inputb = port_inl;
      io->outputb = port_outl;
      break;
    default:
      dev_warn(io->dev, "Invalid register size: %d\n", io->regsize);
      return -EINVAL;
  }
  for (idx = 0; idx < io->io_size; idx++) {
    if (request_region(addr + idx * io->regspacing, io->regsize, DEVICE_NAME) ==
        NULL) {
      while (idx--) release_region(addr + idx * io->regspacing, io->regsize);
      return -EIO;
    }
  }
  return 0;
}

FileSpec::FileSpec(const Object* fileSpecA) {
  ok = true;
  fileName = nullptr;
  platformFileName = nullptr;
  embFile = nullptr;
  desc = nullptr;
  fileSpec = fileSpecA->copy();
  Object obj1 = getFileSpecName(fileSpecA);
  if (!obj1.isString()) {
    ok = false;
    error(errSyntaxError, -1, "Invalid FileSpec");
    return;
  }
  fileName = obj1.getString()->copy();
  if (fileSpec.isDict()) {
    obj1 = fileSpec.dictLookup("EF");
    if (obj1.isDict()) {
      fileStream = obj1.dictLookupNF("F");
      if (!fileStream.isRef()) {
        ok = false;
        fileStream.setToNull();
        error(errSyntaxError, -1,
              "Invalid FileSpec: Embedded file stream is not an indirect "
              "reference");
        return;
      }
    }
  }
  obj1 = fileSpec.dictLookup("Desc");
  if (obj1.isString()) desc = obj1.getString()->copy();
}

static int do_hidp_sock_ioctl(struct socket* sock, unsigned int cmd,
                              void __user* argp) {
  struct hidp_connadd_req ca;
  struct hidp_conndel_req cd;
  struct hidp_connlist_req cl;
  struct hidp_conninfo ci;
  struct socket* csock;
  struct socket* isock;
  int err;
  BT_DBG("cmd %x arg %p", cmd, argp);
  switch (cmd) {
    case HIDPCONNADD:
      if (!capable(CAP_NET_ADMIN)) return -EPERM;
      if (copy_from_user(&ca, argp, sizeof(ca))) return -EFAULT;
      csock = sockfd_lookup(ca.ctrl_sock, &err);
      if (!csock) return err;
      isock = sockfd_lookup(ca.intr_sock, &err);
      if (!isock) {
        sockfd_put(csock);
        return err;
      }
      err = hidp_connection_add(&ca, csock, isock);
      if (!err && copy_to_user(argp, &ca, sizeof(ca))) err = -EFAULT;
      sockfd_put(csock);
      sockfd_put(isock);
      return err;
    case HIDPCONNDEL:
      if (!capable(CAP_NET_ADMIN)) return -EPERM;
      if (copy_from_user(&cd, argp, sizeof(cd))) return -EFAULT;
      return hidp_connection_del(&cd);
    case HIDPGETCONNLIST:
      if (copy_from_user(&cl, argp, sizeof(cl))) return -EFAULT;
      if (cl.cnum <= 0) return -EINVAL;
      err = hidp_get_connlist(&cl);
      if (!err && copy_to_user(argp, &cl, sizeof(cl))) return -EFAULT;
      return err;
    case HIDPGETCONNINFO:
      if (copy_from_user(&ci, argp, sizeof(ci))) return -EFAULT;
      err = hidp_get_conninfo(&ci);
      if (!err && copy_to_user(argp, &ci, sizeof(ci))) return -EFAULT;
      return err;
  }
  return -EINVAL;
}

int jvp_number_cmp(jv a, jv b) {
  assert(JVP_HAS_KIND(a, JV_KIND_NUMBER));
  assert(JVP_HAS_KIND(b, JV_KIND_NUMBER));
#ifdef USE_DECNUM
  if (JVP_HAS_FLAGS(a, JVP_FLAGS_NUMBER_LITERAL) &&
      JVP_HAS_FLAGS(b, JVP_FLAGS_NUMBER_LITERAL)) {
    decNumber res;
    decNumberCompare(&res, jvp_dec_number_ptr(a), jvp_dec_number_ptr(b),
                     DEC_CONTEXT());
    if (decNumberIsZero(&res)) {
      return 0;
    } else if (decNumberIsNegative(&res)) {
      return -1;
    } else {
      return 1;
    }
  }
#endif
  double da = jv_number_value(a), db = jv_number_value(b);
  if (da < db) {
    return -1;
  } else if (da == db) {
    return 0;
  } else {
    return 1;
  }
}

RawTile KakaduImage::getRegion(int seq, int ang, unsigned int res, int layers,
                               int x, int y, unsigned int w, unsigned int h) {
  unsigned int obpc = bpc;
  if (bpc <= 16 && bpc > 8)
    obpc = 16;
  else if (bpc <= 8)
    obpc = 8;
#ifdef DEBUG
  Timer timer;
  timer.start();
#endif
  RawTile rawtile(0, res, seq, ang, w, h, channels, obpc);
  if (obpc == 16)
    rawtile.data = new unsigned short[w * h * channels];
  else if (obpc == 8)
    rawtile.data = new unsigned char[w * h * channels];
  else
    throw file_error("Kakadu :: Unsupported number of bits");
  rawtile.dataLength = w * h * channels * (obpc / 8);
  rawtile.filename = getImagePath();
  rawtile.timestamp = timestamp;
  process(res, layers, x, y, w, h, rawtile.data);
#ifdef DEBUG
  logfile << "Kakadu :: getRegion() :: " << timer.getTime() << " microseconds"
          << endl;
#endif
  return rawtile;
}

bool Server::MatchViewOrStatic(const std::string& method,
                               const std::string& url, bool* stream) {
  if (Router::MatchView(method, url, stream)) {
    return true;
  }
  if (method == methods::kGet && !doc_root_.empty()) {
    fs::path path = doc_root_ / url;
    fs::error_code ec;
    if (!fs::is_directory(path, ec) && fs::exists(path, ec)) {
      return true;
    }
  }
  return false;
}

int luaG_traceexec(lua_State* L, const Instruction* pc) {
  CallInfo* ci = L->ci;
  lu_byte mask = L->hookmask;
  int counthook;
  if (!(mask & (LUA_MASKLINE | LUA_MASKCOUNT))) {
    ci->u.l.trap = 0;
    return 0;
  }
  pc++;
  ci->u.l.savedpc = pc;
  counthook = (--L->hookcount == 0 && (mask & LUA_MASKCOUNT));
  if (counthook)
    resethookcount(L);
  else if (!(mask & LUA_MASKLINE))
    return 1;
  if (ci->callstatus & CIST_HOOKYIELD) {
    ci->callstatus &= ~CIST_HOOKYIELD;
    return 1;
  }
  if (!isIT(*(ci->u.l.savedpc - 1))) L->top = ci->top;
  if (counthook) luaD_hook(L, LUA_HOOKCOUNT, -1, 0, 0);
  if (mask & LUA_MASKLINE) {
    const Proto* p = ci_func(ci)->p;
    int npci = pcRel(pc, p);
    if (npci == 0 || pc <= L->oldpc ||
        changedline(p, pcRel(L->oldpc, p), npci)) {
      int newline = luaG_getfuncline(p, npci);
      luaD_hook(L, LUA_HOOKLINE, newline, 0, 0);
    }
    L->oldpc = pc;
  }
  if (L->status == LUA_YIELD) {
    if (counthook) L->hookcount = 1;
    ci->u.l.savedpc--;
    ci->callstatus |= CIST_HOOKYIELD;
    luaD_throw(L, LUA_YIELD);
  }
  return 1;
}

header_gets(SF_PRIVATE* psf, char* ptr, int bufsize) {
  int k;
  for (k = 0; k < bufsize - 1; k++) {
    if (psf->headindex < psf->headend) {
      ptr[k] = psf->header[psf->headindex];
      psf->headindex++;
    } else {
      psf->headend += psf_fread(psf->header + psf->headend, 1, 1, psf);
      ptr[k] = psf->header[psf->headindex];
      psf->headindex = psf->headend;
    };
    if (ptr[k] == '\n') break;
  };
  ptr[k] = 0;
  return k;
}

void mk_request_free(struct session_request* sr) {
  if (sr->fd_file > 0) {
    mk_vhost_close(sr);
  }
  if (sr->headers.location) {
    mk_mem_free(sr->headers.location);
  }
  if (sr->uri_processed.data != sr->uri.data) {
    mk_ptr_free(&sr->uri_processed);
  }
  if (sr->real_path.data != sr->real_path_static) {
    mk_ptr_free(&sr->real_path);
  }
}

NOEXPORT int parse_socket_error(CLI* c, const char* text) {
  switch (get_last_socket_error()) {
    case 0:
#ifndef USE_WIN32
    case EPIPE:
#endif
    case S_ECONNABORTED:
      s_log(LOG_INFO, "%s: Socket is closed", text);
      return 0;
    case S_EINTR:
      s_log(LOG_DEBUG, "%s: Interrupted by a signal: retrying", text);
      return 1;
    case S_EWOULDBLOCK:
      s_log(LOG_NOTICE, "%s: Would block: retrying", text);
      s_poll_sleep(1, 0);
      return 1;
#if S_EAGAIN != S_EWOULDBLOCK
    case S_EAGAIN:
      s_log(LOG_DEBUG, "%s: Temporary lack of resources: retrying", text);
      return 1;
#endif
#ifdef USE_WIN32
    case S_ECONNRESET:
      if (c->opt->exec_name) {
        s_log(LOG_INFO, "%s: Socket is closed (exec)", text);
        return 0;
      }
#endif
    default:
      sockerror(text);
      throw_exception(c, 1);
      return -1;
  }
}

static void nfs4_open_release(void* calldata) {
  struct nfs4_opendata* data = calldata;
  struct nfs4_state* state = NULL;
  if (data->cancelled == 0) goto out_free;
  if (data->rpc_status != 0 || !data->rpc_done) goto out_free;
  if (data->o_res.rflags & NFS4_OPEN_RESULT_CONFIRM) goto out_free;
  state = nfs4_opendata_to_nfs4_state(data);
  if (!IS_ERR(state))
    nfs4_close_state(&data->path, state, data->o_arg.open_flags);
out_free:
  nfs4_opendata_put(data);
}

int shadow_server_start(rdpShadowServer* server) {
  BOOL ipc;
  BOOL status;
  WSADATA wsaData;
  if (!server) return -1;
  if (WSAStartup(MAKEWORD(2, 2), &wsaData) != 0) return -1;
#ifndef _WIN32
  signal(SIGPIPE, SIG_IGN);
#endif
  server->screen = shadow_screen_new(server);
  if (!server->screen) {
    WLog_ERR(TAG, "screen_new failed");
    return -1;
  }
  server->capture = shadow_capture_new(server);
  if (!server->capture) {
    WLog_ERR(TAG, "capture_new failed");
    return -1;
  }
  ipc = server->ipcSocket &&
        (strncmp(bind_address, server->ipcSocket,
                 strnlen(bind_address, sizeof(bind_address))) != 0);
  if (!ipc) {
    size_t x, count;
    char** list =
        CommandLineParseCommaSeparatedValuesEx(NULL, server->ipcSocket, &count);
    if (!list || (count <= 1)) {
      free(list);
      if (server->ipcSocket == NULL) {
        if (!open_port(server, NULL)) return -1;
      } else
        return -1;
    }
    for (x = 1; x < count; x++) {
      BOOL success = open_port(server, list[x]);
      if (!success) {
        free(list);
        return -1;
      }
    }
    free(list);
  } else {
    status = server->listener->OpenLocal(server->listener, server->ipcSocket);
    if (!status) {
      WLog_ERR(TAG,
               "Problem creating local socket listener. (Port already used or "
               "insufficient permissions?)");
      return -1;
    }
  }
  if (!(server->thread = CreateThread(NULL, 0, shadow_server_thread,
                                      (void*)server, 0, NULL))) {
    return -1;
  }
  return 0;
}

PyImaging_LibTiffDecoderNew(PyObject* self, PyObject* args) {
  ImagingDecoderObject* decoder;
  char* mode;
  char* rawmode;
  char* compname;
  int compression;
  int fp;
  if (!PyArg_ParseTuple(args, "sssi", &mode, &rawmode, &compname, &fp))
    return NULL;
  TRACE(("new tiff decoder %s\n", compname));
  if (strcasecmp(compname, "tiff_ccitt") == 0) {
    compression = COMPRESSION_CCITTRLE;
  } else if (strcasecmp(compname, "group3") == 0) {
    compression = COMPRESSION_CCITTFAX3;
  } else if (strcasecmp(compname, "group4") == 0) {
    compression = COMPRESSION_CCITTFAX4;
  } else if (strcasecmp(compname, "tiff_raw_16") == 0) {
    compression = COMPRESSION_CCITTRLEW;
  } else {
    PyErr_SetString(PyExc_ValueError, "unknown compession");
    return NULL;
  }
  decoder = PyImaging_DecoderNew(sizeof(TIFFSTATE));
  if (decoder == NULL) return NULL;
  if (get_unpacker(decoder, mode, rawmode) < 0) return NULL;
  if (!ImagingLibTiffInit(&decoder->state, compression, fp)) {
    Py_DECREF(decoder);
    PyErr_SetString(PyExc_RuntimeError, "tiff codec initialization failed");
    return NULL;
  }
  decoder->decode = ImagingLibTiffDecode;
  return (PyObject*)decoder;
}

