static bool caller_is_in_ancestor(pid_t pid, const char* contrl, const char* cg,
                                  char** nextcg) {
  char fnam[PROCLEN];
  FILE* f;
  bool answer = false;
  char* line = NULL;
  size_t len = 0;
  int ret;
  ret = snprintf(fnam, PROCLEN, "/proc/%d/cgroup", pid);
  if (ret < 0 || ret >= PROCLEN) return false;
  if (!(f = fopen(fnam, "r"))) return false;
  while (getline(&line, &len, f) != -1) {
    char *c1, *c2, *linecmp;
    if (!line[0]) continue;
    c1 = strchr(line, ':');
    if (!c1) goto out;
    c1++;
    c2 = strchr(c1, ':');
    if (!c2) goto out;
    *c2 = '\0';
    if (strcmp(c1, contrl) != 0) continue;
    c2++;
    stripnewline(c2);
    prune_init_slice(c2);
    linecmp = *cg == '/' ? c2 : c2 + 1;
    if (strncmp(linecmp, cg, strlen(linecmp)) != 0) {
      if (nextcg) *nextcg = get_next_cgroup_dir(linecmp, cg);
      goto out;
    }
    answer = true;
    goto out;
  }
out:
  fclose(f);
  free(line);
  return answer;
}

static void bpf_adj_branches(struct bpf_prog* prog, u32 pos, u32 delta) {
  struct bpf_insn* insn = prog->insnsi;
  u32 i, insn_cnt = prog->len;
  bool pseudo_call;
  u8 code;
  int off;
  for (i = 0; i < insn_cnt; i++, insn++) {
    code = insn->code;
    if (BPF_CLASS(code) != BPF_JMP) continue;
    if (BPF_OP(code) == BPF_EXIT) continue;
    if (BPF_OP(code) == BPF_CALL) {
      if (insn->src_reg == BPF_PSEUDO_CALL)
        pseudo_call = true;
      else
        continue;
    } else {
      pseudo_call = false;
    }
    off = pseudo_call ? insn->imm : insn->off;
    if (i < pos && i + off + 1 > pos)
      off += delta;
    else if (i > pos + delta && i + off + 1 <= pos + delta)
      off -= delta;
    if (pseudo_call)
      insn->imm = off;
    else
      insn->off = off;
  }
}

static ssize_t eth_rx(NetClientState* nc, const uint8_t* buf, size_t size) {
  struct xlx_ethlite* s = qemu_get_nic_opaque(nc);
  unsigned int rxbase = s->rxbuf * (0x800 / 4);
  if (!(buf[0] & 0x80) && memcmp(&s->conf.macaddr.a[0], buf, 6)) return size;
  if (s->regs[rxbase + R_RX_CTRL0] & CTRL_S) {
    D(qemu_log("ethlite lost packet %x\n", s->regs[R_RX_CTRL0]));
    return -1;
  }
  D(qemu_log("%s %zd rxbase=%x\n", __func__, size, rxbase));
  memcpy(&s->regs[rxbase + R_RX_BUF0], buf, size);
  s->regs[rxbase + R_RX_CTRL0] |= CTRL_S;
  s->rxbuf ^= s->c_rx_pingpong;
  return size;
}

header_cache_t* imap_hcache_open(struct ImapData* idata, const char* path) {
  struct ImapMbox mx;
  struct Url url;
  char cachepath[PATH_MAX];
  char mbox[PATH_MAX];
  if (path)
    imap_cachepath(idata, path, mbox, sizeof(mbox));
  else {
    if (!idata->ctx || imap_parse_path(idata->ctx->path, &mx) < 0) return NULL;
    imap_cachepath(idata, mx.mbox, mbox, sizeof(mbox));
    FREE(&mx.mbox);
  }
  mutt_account_tourl(&idata->conn->account, &url);
  url.path = mbox;
  url_tostring(&url, cachepath, sizeof(cachepath), U_PATH);
  return mutt_hcache_open(HeaderCache, cachepath, imap_hcache_namer);
}

int RGWPostObj_ObjStore_S3::get_tags() {
  string tags_str;
  if (part_str(parts, "tagging", &tags_str)) {
    RGWObjTagsXMLParser parser;
    if (!parser.init()) {
      ldout(s->cct, 0) << "Couldn't init RGWObjTags XML parser" << dendl;
      err_msg = "Server couldn't process the request";
      return -EINVAL;
    }
    if (!parser.parse(tags_str.c_str(), tags_str.size(), 1)) {
      ldout(s->cct, 0) << "Invalid Tagging XML" << dendl;
      err_msg = "Invalid Tagging XML";
      return -EINVAL;
    }
    RGWObjTagSet_S3* obj_tags_s3;
    RGWObjTagging_S3* tagging;
    tagging = static_cast<RGWObjTagging_S3*>(parser.find_first("Tagging"));
    obj_tags_s3 = static_cast<RGWObjTagSet_S3*>(tagging->find_first("TagSet"));
    if (!obj_tags_s3) {
      return -ERR_MALFORMED_XML;
    }
    RGWObjTags obj_tags;
    int r = obj_tags_s3->rebuild(obj_tags);
    if (r < 0) return r;
    bufferlist tags_bl;
    obj_tags.encode(tags_bl);
    ldout(s->cct, 20) << "Read " << obj_tags.count() << "tags" << dendl;
    attrs[RGW_ATTR_TAGS] = tags_bl;
  }
  return 0;
}

int evm_update_evmxattr(struct dentry* dentry, const char* xattr_name,
                        const char* xattr_value, size_t xattr_value_len) {
  struct inode* inode = dentry->d_inode;
  struct evm_ima_xattr_data xattr_data;
  int rc = 0;
  rc = evm_calc_hmac(dentry, xattr_name, xattr_value, xattr_value_len,
                     xattr_data.digest);
  if (rc == 0) {
    xattr_data.type = EVM_XATTR_HMAC;
    rc = __vfs_setxattr_noperm(dentry, XATTR_NAME_EVM, &xattr_data,
                               sizeof(xattr_data), 0);
  } else if (rc == -ENODATA)
    rc = inode->i_op->removexattr(dentry, XATTR_NAME_EVM);
  return rc;
}

char* engrave_tombstone(pid_t pid, pid_t tid, int signal, int original_si_code,
                        uintptr_t abort_msg_address, bool dump_sibling_threads,
                        bool* detach_failed, int* total_sleep_time_usec) {
  log_t log;
  log.current_tid = tid;
  log.crashed_tid = tid;
  if ((mkdir(TOMBSTONE_DIR, 0755) == -1) && (errno != EEXIST)) {
    _LOG(&log, logtype::ERROR, "failed to create %s: %s\n", TOMBSTONE_DIR,
         strerror(errno));
  }
  if (chown(TOMBSTONE_DIR, AID_SYSTEM, AID_SYSTEM) == -1) {
    _LOG(&log, logtype::ERROR, "failed to change ownership of %s: %s\n",
         TOMBSTONE_DIR, strerror(errno));
  }
  int fd = -1;
  char* path = NULL;
  if (selinux_android_restorecon(TOMBSTONE_DIR, 0) == 0) {
    path = find_and_open_tombstone(&fd);
  } else {
    _LOG(&log, logtype::ERROR,
         "Failed to restore security context, not writing tombstone.\n");
  }
  if (fd < 0) {
    _LOG(&log, logtype::ERROR, "Skipping tombstone write, nothing to do.\n");
    *detach_failed = false;
    return NULL;
  }
  log.tfd = fd;
  int amfd = activity_manager_connect();
  log.amfd = amfd;
  *detach_failed =
      dump_crash(&log, pid, tid, signal, original_si_code, abort_msg_address,
                 dump_sibling_threads, total_sleep_time_usec);
  ALOGI("\nTombstone written to: %s\n", path);
  close(amfd);
  close(fd);
  return path;
}

static u32 swf_get_32(SWFReader* read) {
  u32 val, res;
  val = swf_read_int(read, 32);
  res = (val & 0xFF);
  res <<= 8;
  res |= ((val >> 8) & 0xFF);
  res <<= 8;
  res |= ((val >> 16) & 0xFF);
  res <<= 8;
  res |= ((val >> 24) & 0xFF);
  return res;
}

int nfc_dep_link_up(struct nfc_dev* dev, int target_index, u8 comm_mode) {
  int rc = 0;
  u8* gb;
  size_t gb_len;
  struct nfc_target* target;
  pr_debug("dev_name=%s comm %d\n", dev_name(&dev->dev), comm_mode);
  if (!dev->ops->dep_link_up) return -EOPNOTSUPP;
  device_lock(&dev->dev);
  if (!device_is_registered(&dev->dev)) {
    rc = -ENODEV;
    goto error;
  }
  if (dev->dep_link_up == true) {
    rc = -EALREADY;
    goto error;
  }
  gb = nfc_llcp_general_bytes(dev, &gb_len);
  if (gb_len > NFC_MAX_GT_LEN) {
    rc = -EINVAL;
    goto error;
  }
  target = nfc_find_target(dev, target_index);
  if (target == NULL) {
    rc = -ENOTCONN;
    goto error;
  }
  rc = dev->ops->dep_link_up(dev, target, comm_mode, gb, gb_len);
  if (!rc) {
    dev->active_target = target;
    dev->rf_mode = NFC_RF_INITIATOR;
  }
error:
  device_unlock(&dev->dev);
  return rc;
}

p11_rpc_buffer_get_attribute(p11_buffer* buffer, size_t* offset,
                             CK_ATTRIBUTE* attr) {
  uint32_t type, length;
  unsigned char validity;
  p11_rpc_attribute_serializer* serializer;
  p11_rpc_value_type value_type;
  if (!p11_rpc_buffer_get_uint32(buffer, offset, &type)) return false;
  if (!p11_rpc_buffer_get_byte(buffer, offset, &validity)) return false;
  if (!validity) {
    attr->ulValueLen = ((CK_ULONG)-1);
    attr->type = type;
    return true;
  }
  if (!p11_rpc_buffer_get_uint32(buffer, offset, &length)) return false;
  value_type = map_attribute_to_value_type(type);
  assert(value_type < ELEMS(p11_rpc_attribute_serializers));
  serializer = &p11_rpc_attribute_serializers[value_type];
  assert(serializer != NULL);
  if (!serializer->decode(buffer, offset, attr->pValue, &attr->ulValueLen))
    return false;
  if (!attr->pValue) attr->ulValueLen = length;
  attr->type = type;
  return true;
}

bool Performance::PassesTimingAllowCheck(
    const ResourceResponse& response,
    const SecurityOrigin& initiator_security_origin,
    const AtomicString& original_timing_allow_origin,
    ExecutionContext* context) {
  scoped_refptr<const SecurityOrigin> resource_origin =
      SecurityOrigin::Create(response.Url());
  if (resource_origin->IsSameSchemeHostPort(&initiator_security_origin))
    return true;
  const AtomicString& timing_allow_origin_string =
      original_timing_allow_origin.IsEmpty()
          ? response.HttpHeaderField(HTTPNames::Timing_Allow_Origin)
          : original_timing_allow_origin;
  if (timing_allow_origin_string.IsEmpty() ||
      EqualIgnoringASCIICase(timing_allow_origin_string, "null"))
    return false;
  if (timing_allow_origin_string == "*") {
    UseCounter::Count(context, WebFeature::kStarInTimingAllowOrigin);
    return true;
  }
  const String& security_origin = initiator_security_origin.ToString();
  Vector<String> timing_allow_origins;
  timing_allow_origin_string.GetString().Split(',', timing_allow_origins);
  if (timing_allow_origins.size() > 1) {
    UseCounter::Count(context, WebFeature::kMultipleOriginsInTimingAllowOrigin);
  } else if (timing_allow_origins.size() == 1 &&
             timing_allow_origin_string != "*") {
    UseCounter::Count(context, WebFeature::kSingleOriginInTimingAllowOrigin);
  }
  for (const String& allow_origin : timing_allow_origins) {
    const String allow_origin_stripped = allow_origin.StripWhiteSpace();
    if (allow_origin_stripped == security_origin ||
        allow_origin_stripped == "*") {
      return true;
    }
  }
  return false;
}

static void sixpack_close(struct tty_struct* tty) {
  struct sixpack* sp;
  write_lock_irq(&disc_data_lock);
  sp = tty->disc_data;
  tty->disc_data = NULL;
  write_unlock_irq(&disc_data_lock);
  if (!sp) return;
  if (!refcount_dec_and_test(&sp->refcnt)) wait_for_completion(&sp->dead);
  netif_stop_queue(sp->dev);
  del_timer_sync(&sp->tx_t);
  del_timer_sync(&sp->resync_t);
  unregister_netdev(sp->dev);
  kfree(sp->rbuff);
  kfree(sp->xbuff);
  free_netdev(sp->dev);
}

create_policy_2_svc(cpol_arg* arg, struct svc_req* rqstp) {
  static generic_ret ret;
  char* prime_arg;
  gss_buffer_desc client_name, service_name;
  OM_uint32 minor_stat;
  kadm5_server_handle_t handle;
  const char* errmsg = NULL;
  xdr_free(xdr_generic_ret, &ret);
  if ((ret.code = new_server_handle(arg->api_version, rqstp, &handle)))
    goto exit_func;
  if ((ret.code = check_handle((void*)handle))) goto exit_func;
  ret.api_version = handle->api_version;
  if (setup_gss_names(rqstp, &client_name, &service_name) < 0) {
    ret.code = KADM5_FAILURE;
    goto exit_func;
  }
  prime_arg = arg->rec.policy;
  if (CHANGEPW_SERVICE(rqstp) ||
      !kadm5int_acl_check(handle->context, rqst2name(rqstp), ACL_ADD, NULL,
                          NULL)) {
    ret.code = KADM5_AUTH_ADD;
    log_unauth("kadm5_create_policy", prime_arg, &client_name, &service_name,
               rqstp);
  } else {
    ret.code = kadm5_create_policy((void*)handle, &arg->rec, arg->mask);
    if (ret.code != 0)
      errmsg = krb5_get_error_message(handle->context, ret.code);
    log_done("kadm5_create_policy",
             ((prime_arg == NULL) ? "(null)" : prime_arg), errmsg, &client_name,
             &service_name, rqstp);
    if (errmsg != NULL) krb5_free_error_message(handle->context, errmsg);
  }
  gss_release_buffer(&minor_stat, &client_name);
  gss_release_buffer(&minor_stat, &service_name);
exit_func:
  free_server_handle(handle);
  return &ret;
}

hermesBuiltinApply(void*, Runtime* runtime, NativeArgs args) {
  GCScopeMarkerRAII marker{runtime};
  Handle<Callable> fn = args.dyncastArg<Callable>(0);
  if (LLVM_UNLIKELY(!fn)) {
    return runtime->raiseTypeErrorForValue(args.getArgHandle(0),
                                           " is not a function");
  }
  Handle<JSArray> argArray = args.dyncastArg<JSArray>(1);
  if (LLVM_UNLIKELY(!argArray)) {
    return runtime->raiseTypeError("args must be an array");
  }
  uint32_t len = JSArray::getLength(*argArray);
  bool isConstructor = args.getArgCount() == 2;
  MutableHandle<> thisVal{runtime};
  if (isConstructor) {
    auto thisValRes = Callable::createThisForConstruct(fn, runtime);
    if (LLVM_UNLIKELY(thisValRes == ExecutionStatus::EXCEPTION)) {
      return ExecutionStatus::EXCEPTION;
    }
    thisVal = *thisValRes;
  } else {
    thisVal = args.getArg(2);
  }
  ScopedNativeCallFrame newFrame{runtime, len, *fn, isConstructor,
                                 thisVal.getHermesValue()};
  for (uint32_t i = 0; i < len; ++i) {
    newFrame->getArgRef(i) = argArray->at(runtime, i);
  }
  return isConstructor ? Callable::construct(fn, runtime, thisVal)
                       : Callable::call(fn, runtime);
}

inline typename V::MapType FBUnserializer<V>::unserializeMap() {
  p_ += CODE_SIZE;
  typename V::MapType ret = V::createMap();
  size_t code = nextCode();
  while (code != FB_SERIALIZE_STOP) {
    switch (code) {
      case FB_SERIALIZE_VARCHAR:
      case FB_SERIALIZE_STRING: {
        auto key = unserializeString();
        auto value = unserializeThing();
        V::mapSet(ret, std::move(key), std::move(value));
      } break;
      default: {
        auto key = unserializeInt64();
        auto value = unserializeThing();
        V::mapSet(ret, std::move(key), std::move(value));
      }
    }
    code = nextCode();
  }
  p_ += CODE_SIZE;
  return ret;
}

PHYSICALPATH_FUNC(mod_alias_physical_handler) {
  plugin_data* p = p_d;
  int uri_len, basedir_len;
  char* uri_ptr;
  size_t k;
  if (buffer_is_empty(con->physical.path)) return HANDLER_GO_ON;
  mod_alias_patch_connection(srv, con, p);
  basedir_len = buffer_string_length(con->physical.basedir);
  if ('/' == con->physical.basedir->ptr[basedir_len - 1]) --basedir_len;
  uri_len = buffer_string_length(con->physical.path) - basedir_len;
  uri_ptr = con->physical.path->ptr + basedir_len;
  for (k = 0; k < p->conf.alias->used; k++) {
    data_string* ds = (data_string*)p->conf.alias->data[k];
    int alias_len = buffer_string_length(ds->key);
    if (alias_len > uri_len) continue;
    if (buffer_is_empty(ds->key)) continue;
    if (0 == (con->conf.force_lowercase_filenames
                  ? strncasecmp(uri_ptr, ds->key->ptr, alias_len)
                  : strncmp(uri_ptr, ds->key->ptr, alias_len))) {
      buffer_copy_buffer(con->physical.basedir, ds->value);
      buffer_copy_buffer(srv->tmp_buf, ds->value);
      buffer_append_string(srv->tmp_buf, uri_ptr + alias_len);
      buffer_copy_buffer(con->physical.path, srv->tmp_buf);
      return HANDLER_GO_ON;
    }
  }
  return HANDLER_GO_ON;
}

nvkm_vmm_unmap_region(struct nvkm_vmm* vmm, struct nvkm_vma* vma) {
  struct nvkm_vma* next;
  nvkm_memory_tags_put(vma->memory, vmm->mmu->subdev.device, &vma->tags);
  nvkm_memory_unref(&vma->memory);
  if (vma->part) {
    struct nvkm_vma* prev = node(vma, prev);
    if (!prev->memory) {
      prev->size += vma->size;
      rb_erase(&vma->tree, &vmm->root);
      list_del(&vma->head);
      kfree(vma);
      vma = prev;
    }
  }
  next = node(vma, next);
  if (next && next->part) {
    if (!next->memory) {
      vma->size += next->size;
      rb_erase(&next->tree, &vmm->root);
      list_del(&next->head);
      kfree(next);
    }
  }
}

int digest_generic_verify(struct digest* d, const unsigned char* md) {
  int ret;
  int len = digest_length(d);
  unsigned char* tmp;
  tmp = xmalloc(len);
  ret = digest_final(d, tmp);
  if (ret) goto end;
  ret = memcmp(md, tmp, len);
  ret = ret ? -EINVAL : 0;
end:
  free(tmp);
  return ret;
}

