static void coroutine_fn v9fs_link(void* opaque) {
  V9fsPDU* pdu = opaque;
  int32_t dfid, oldfid;
  V9fsFidState *dfidp, *oldfidp;
  V9fsString name;
  size_t offset = 7;
  int err = 0;
  v9fs_string_init(&name);
  err = pdu_unmarshal(pdu, offset, "dds", &dfid, &oldfid, &name);
  if (err < 0) {
    goto out_nofid;
  }
  trace_v9fs_link(pdu->tag, pdu->id, dfid, oldfid, name.data);
  if (name_is_illegal(name.data)) {
    err = -ENOENT;
    goto out_nofid;
  }
  if (!strcmp(".", name.data) || !strcmp("..", name.data)) {
    err = -EEXIST;
    goto out_nofid;
  }
  dfidp = get_fid(pdu, dfid);
  if (dfidp == NULL) {
    err = -ENOENT;
    goto out_nofid;
  }
  oldfidp = get_fid(pdu, oldfid);
  if (oldfidp == NULL) {
    err = -ENOENT;
    goto out;
  }
  err = v9fs_co_link(pdu, oldfidp, dfidp, &name);
  if (!err) {
    err = offset;
  }
out:
  put_fid(pdu, dfidp);
out_nofid:
  pdu_complete(pdu, err);
}

status_t Parcel::readUtf8FromUtf16(std::string* str) const {
  size_t utf16Size = 0;
  const char16_t* src = readString16Inplace(&utf16Size);
  if (!src) {
    return UNEXPECTED_NULL;
  }
  if (utf16Size == 0u) {
    str->clear();
    return NO_ERROR;
  }
  ssize_t utf8Size = utf16_to_utf8_length(src, utf16Size);
  if (utf8Size < 0) {
    return BAD_VALUE;
  }
  str->resize(utf8Size + 1);
  utf16_to_utf8(src, utf16Size, &((*str)[0]));
  str->resize(utf8Size);
  return NO_ERROR;
}

int dccp_send_reset(struct sock* sk, enum dccp_reset_codes code) {
  struct sk_buff* skb;
  int err = inet_sk_rebuild_header(sk);
  if (err != 0) return err;
  skb = sock_wmalloc(sk, sk->sk_prot->max_header, 1, GFP_ATOMIC);
  if (skb == NULL) return -ENOBUFS;
  skb_reserve(skb, sk->sk_prot->max_header);
  DCCP_SKB_CB(skb)->dccpd_type = DCCP_PKT_RESET;
  DCCP_SKB_CB(skb)->dccpd_reset_code = code;
  return dccp_transmit_skb(sk, skb);
}

