SYSCALL_DEFINE6(move_pages, pid_t, pid, unsigned long, nr_pages,
                const void __user * __user*, pages, const int __user*, nodes,
                int __user*, status, int, flags) {
  const struct cred *cred = current_cred(), *tcred;
  struct task_struct* task;
  struct mm_struct* mm;
  int err;
  nodemask_t task_nodes;
  if (flags & ~(MPOL_MF_MOVE | MPOL_MF_MOVE_ALL)) return -EINVAL;
  if ((flags & MPOL_MF_MOVE_ALL) && !capable(CAP_SYS_NICE)) return -EPERM;
  rcu_read_lock();
  task = pid ? find_task_by_vpid(pid) : current;
  if (!task) {
    rcu_read_unlock();
    return -ESRCH;
  }
  get_task_struct(task);
  tcred = __task_cred(task);
  if (!uid_eq(cred->euid, tcred->suid) && !uid_eq(cred->euid, tcred->uid) &&
      !uid_eq(cred->uid, tcred->suid) && !uid_eq(cred->uid, tcred->uid) &&
      !capable(CAP_SYS_NICE)) {
    rcu_read_unlock();
    err = -EPERM;
    goto out;
  }
  rcu_read_unlock();
  err = security_task_movememory(task);
  if (err) goto out;
  task_nodes = cpuset_mems_allowed(task);
  mm = get_task_mm(task);
  put_task_struct(task);
  if (!mm) return -EINVAL;
  if (nodes)
    err = do_pages_move(mm, task_nodes, nr_pages, pages, nodes, status, flags);
  else
    err = do_pages_stat(mm, nr_pages, pages, status);
  mmput(mm);
  return err;
out:
  put_task_struct(task);
  return err;
}

void CtcpParser::packedReply(CoreNetwork* net, const QString& bufname,
                             const QList<QByteArray>& replies) {
  QList<QByteArray> params;
  int answerSize = 0;
  for (int i = 0; i < replies.count(); i++) {
    answerSize += replies.at(i).size();
  }
  QByteArray quotedReply(answerSize, 0);
  int nextPos = 0;
  QByteArray& reply = quotedReply;
  for (int i = 0; i < replies.count(); i++) {
    reply = replies.at(i);
    quotedReply.replace(nextPos, reply.size(), reply);
    nextPos += reply.size();
  }
  params << net->serverEncode(bufname) << quotedReply;
  net->putCmd("NOTICE", params);
}

