    }
    efree(stack->elements);
  }
  return SUCCESS;
}

GC_API GC_ATTR_MALLOC void* GC_CALL GC_calloc_explicitly_typed(size_t n,
                                                               size_t lb,
                                                               GC_descr d) {
  word* op;
  size_t lg;
  GC_descr simple_descr;
  complex_descriptor* complex_descr;
  int descr_type;
  struct LeafDescriptor leaf;
  GC_ASSERT(GC_explicit_typing_initialized);
  descr_type = GC_make_array_descriptor((word)n, (word)lb, d, &simple_descr,
                                        &complex_descr, &leaf);
  switch (descr_type) {
    case NO_MEM:
      return (0);
    case SIMPLE:
      return (GC_malloc_explicitly_typed(n * lb, simple_descr));
    case LEAF:
      lb *= n;
      lb += sizeof(struct LeafDescriptor) + TYPD_EXTRA_BYTES;
      break;
    case COMPLEX:
      lb *= n;
      lb += TYPD_EXTRA_BYTES;
      break;
  }
  op = GC_malloc_kind(lb, GC_array_kind);
  if (EXPECT(NULL == op, FALSE)) return NULL;
  lg = SMALL_OBJ(lb) ? GC_size_map[lb] : BYTES_TO_GRANULES(GC_size(op));
  if (descr_type == LEAF) {
    volatile struct LeafDescriptor* lp =
        (struct LeafDescriptor*)(op + GRANULES_TO_WORDS(lg) -
                                 (BYTES_TO_WORDS(
                                      sizeof(struct LeafDescriptor)) +
                                  1));
    lp->ld_tag = LEAF_TAG;
    lp->ld_size = leaf.ld_size;
    lp->ld_nelements = leaf.ld_nelements;
    lp->ld_descriptor = leaf.ld_descriptor;
    ((volatile word*)op)[GRANULES_TO_WORDS(lg) - 1] = (word)lp;
  } else {
#ifndef GC_NO_FINALIZATION
    size_t lw = GRANULES_TO_WORDS(lg);
    op[lw - 1] = (word)complex_descr;
    if (EXPECT(GC_general_register_disappearing_link((void**)(op + lw - 1),
                                                     op) == GC_NO_MEMORY,
               FALSE))
#endif
    {
      return GC_malloc(lb);
    }
  }
  return op;
}

static int nfs_can_extend_write(struct file* file, struct page* page,
                                struct inode* inode) {
  if (file->f_flags & O_DSYNC) return 0;
  if (NFS_PROTO(inode)->have_delegation(inode, FMODE_WRITE)) return 1;
  if (nfs_write_pageuptodate(page, inode) &&
      (inode->i_flock == NULL ||
       (inode->i_flock->fl_start == 0 && inode->i_flock->fl_end == OFFSET_MAX &&
        inode->i_flock->fl_type != F_RDLCK)))
    return 1;
  return 0;
}

char* parse_content_length(char* buffer, char* end, int* length) {
  int number;
  char* p;
  int size;
  p = buffer;
  while (p < end &&
         (*p == ' ' || *p == '\t' || (*p == '\r' && *(p + 1) == '\n') ||
          (*p == '\n' && (*(p + 1) == ' ' || *(p + 1) == '\t'))))
    p++;
  if (p == end) goto error;
  size = 0;
  number = 0;
  while (p < end && *p >= '0' && *p <= '9') {
    number = number * 10 + (*p) - '0';
    if (number < 0) {
      LM_ERR("number overflow at pos %d in len number [%.*s]\n",
             (int)(p - buffer), (int)(end - buffer), buffer);
      return 0;
    }
    size++;
    p++;
  }
  if (p == end || size == 0) goto error;
  while (p < end && (*p == ' ' || *p == '\t' ||
                     (*p == '\n' && (*(p + 1) == ' ' || *(p + 1) == '\t'))))
    p++;
  if (p == end) goto error;
  if ((*(p++) != '\n') && (*(p - 1) != '\r' || *(p++) != '\n')) goto error;
  *length = number;
  return p;
error:
  LM_ERR("parse error near char [%d][%c]\n", *p, *p);
  return 0;
}

static void f2fs_put_super(struct super_block* sb) {
  struct f2fs_sb_info* sbi = F2FS_SB(sb);
  int i;
  f2fs_quota_off_umount(sb);
  mutex_lock(&sbi->umount_mutex);
  if (is_sbi_flag_set(sbi, SBI_IS_DIRTY) ||
      !is_set_ckpt_flags(sbi, CP_UMOUNT_FLAG)) {
    struct cp_control cpc = {
        .reason = CP_UMOUNT,
    };
    write_checkpoint(sbi, &cpc);
  }
  f2fs_wait_discard_bios(sbi);
  if (f2fs_discard_en(sbi) && !sbi->discard_blks) {
    struct cp_control cpc = {
        .reason = CP_UMOUNT | CP_TRIMMED,
    };
    write_checkpoint(sbi, &cpc);
  }
  f2fs_destroy_stats(sbi);
  release_ino_entry(sbi, true);
  f2fs_leave_shrinker(sbi);
  mutex_unlock(&sbi->umount_mutex);
  f2fs_flush_merged_writes(sbi);
  iput(sbi->node_inode);
  iput(sbi->meta_inode);
  destroy_node_manager(sbi);
  destroy_segment_manager(sbi);
  kfree(sbi->ckpt);
  f2fs_unregister_sysfs(sbi);
  sb->s_fs_info = NULL;
  if (sbi->s_chksum_driver) crypto_free_shash(sbi->s_chksum_driver);
  kfree(sbi->raw_super);
  destroy_device_list(sbi);
  mempool_destroy(sbi->write_io_dummy);
#ifdef CONFIG_QUOTA
  for (i = 0; i < MAXQUOTAS; i++) kfree(sbi->s_qf_names[i]);
#endif
  destroy_percpu_info(sbi);
  for (i = 0; i < NR_PAGE_TYPE; i++) kfree(sbi->write_io[i]);
  kfree(sbi);
}

