  char* aString;
  ec = obj->search(t, stack);
  elem = (DcmByteString*)stack.top();
  if (ec == EC_Normal && elem != NULL) {
    if (elem->getLength() == 0) {
      s[0] = '\0';
    } else {
      ec = elem->getString(aString);
      OFStandard::strlcpy(s, aString, bufsize);
    }
  }
  return (ec == EC_Normal);
}

int __anon_vma_prepare(struct vm_area_struct* vma) {
  struct mm_struct* mm = vma->vm_mm;
  struct anon_vma *anon_vma, *allocated;
  struct anon_vma_chain* avc;
  might_sleep();
  avc = anon_vma_chain_alloc(GFP_KERNEL);
  if (!avc) goto out_enomem;
  anon_vma = find_mergeable_anon_vma(vma);
  allocated = NULL;
  if (!anon_vma) {
    anon_vma = anon_vma_alloc();
    if (unlikely(!anon_vma)) goto out_enomem_free_avc;
    allocated = anon_vma;
  }
  anon_vma_lock_write(anon_vma);
  spin_lock(&mm->page_table_lock);
  if (likely(!vma->anon_vma)) {
    vma->anon_vma = anon_vma;
    anon_vma_chain_link(vma, avc, anon_vma);
    anon_vma->degree++;
    allocated = NULL;
    avc = NULL;
  }
  spin_unlock(&mm->page_table_lock);
  anon_vma_unlock_write(anon_vma);
  if (unlikely(allocated)) put_anon_vma(allocated);
  if (unlikely(avc)) anon_vma_chain_free(avc);
  return 0;
out_enomem_free_avc:
  anon_vma_chain_free(avc);
out_enomem:
  return -ENOMEM;
}

CallResult<bool> isConstructor(Runtime& runtime, Callable* callable) {
  if (!callable) {
    return false;
  }
  while (BoundFunction* b = dyn_vmcast<BoundFunction>(callable)) {
    callable = b->getTarget(runtime);
  }
  if (auto* func = dyn_vmcast<JSFunction>(callable)) {
    auto* cb = func->getCodeBlock(runtime);
    cb->lazyCompile(runtime);
    return !func->getCodeBlock(runtime)->getHeaderFlags().isCallProhibited(
        true);
  }
  if (!vmisa<NativeFunction>(callable) || vmisa<NativeConstructor>(callable)) {
    return true;
  }
  if (auto* cproxy = dyn_vmcast<JSCallableProxy>(callable)) {
    return cproxy->isConstructor(runtime);
  }
  return false;
}

static int snd_seq_ioctl_create_port(struct snd_seq_client* client, void* arg) {
  struct snd_seq_port_info* info = arg;
  struct snd_seq_client_port* port;
  struct snd_seq_port_callback* callback;
  if (info->addr.client != client->number) return -EPERM;
  port = snd_seq_create_port(
      client,
      (info->flags & SNDRV_SEQ_PORT_FLG_GIVEN_PORT) ? info->addr.port : -1);
  if (port == NULL) return -ENOMEM;
  if (client->type == USER_CLIENT && info->kernel) {
    snd_seq_delete_port(client, port->addr.port);
    return -EINVAL;
  }
  if (client->type == KERNEL_CLIENT) {
    if ((callback = info->kernel) != NULL) {
      if (callback->owner) port->owner = callback->owner;
      port->private_data = callback->private_data;
      port->private_free = callback->private_free;
      port->event_input = callback->event_input;
      port->c_src.open = callback->subscribe;
      port->c_src.close = callback->unsubscribe;
      port->c_dest.open = callback->use;
      port->c_dest.close = callback->unuse;
    }
  }
  info->addr = port->addr;
  snd_seq_set_port_info(port, info);
  snd_seq_system_client_ev_port_start(port->addr.client, port->addr.port);
  return 0;
}

void flash_option_bytes_init(int boot_from_dfu) {
  uint32_t val = 0xfffff8aa;
  if (boot_from_dfu) {
    val &= ~(1 << 27);
  } else {
    if (solo_is_locked()) {
      val = 0xfffff8cc;
    }
  }
  val &= ~(1 << 26);
  val &= ~(1 << 25);
  val &= ~(1 << 24);
  if (FLASH->OPTR == val) {
    return;
  }
  __disable_irq();
  while (FLASH->SR & (1 << 16));
  flash_unlock();
  if (FLASH->CR & (1 << 30)) {
    FLASH->OPTKEYR = 0x08192A3B;
    FLASH->OPTKEYR = 0x4C5D6E7F;
  }
  FLASH->OPTR = val;
  FLASH->CR |= (1 << 17);
  while (FLASH->SR & (1 << 16));
  flash_lock();
  __enable_irq();
}

static void update_open_stateflags(struct nfs4_state* state,
