}

void snd_msndmidi_input_read(void* mpuv) {
  unsigned long flags;
  struct snd_msndmidi* mpu = mpuv;
  void* pwMIDQData = mpu->dev->mappedbase + MIDQ_DATA_BUFF;
  spin_lock_irqsave(&mpu->input_lock, flags);
  while (readw(mpu->dev->MIDQ + JQS_wTail) !=
         readw(mpu->dev->MIDQ + JQS_wHead)) {
    u16 wTmp, val;
    val = readw(pwMIDQData + 2 * readw(mpu->dev->MIDQ + JQS_wHead));
    if (test_bit(MSNDMIDI_MODE_BIT_INPUT_TRIGGER, &mpu->mode))
      snd_rawmidi_receive(mpu->substream_input, (unsigned char*)&val, 1);
    wTmp = readw(mpu->dev->MIDQ + JQS_wHead) + 1;
    if (wTmp > readw(mpu->dev->MIDQ + JQS_wSize))
      writew(0, mpu->dev->MIDQ + JQS_wHead);
    else
      writew(wTmp, mpu->dev->MIDQ + JQS_wHead);
  }
  spin_unlock_irqrestore(&mpu->input_lock, flags);
}

HandleFileDownloadCancelRequest(rfbClientPtr cl, rfbTightClientPtr rtcp) {
  int n = 0;
  char* reason = NULL;
  rfbClientToServerTightMsg msg;
  memset(&msg, 0, sizeof(rfbClientToServerTightMsg));
  if ((n = rfbReadExact(cl, ((char*)&msg) + 1,
                        sz_rfbFileDownloadCancelMsg - 1)) <= 0) {
    if (n < 0)
      rfbLog(
          "File [%s]: Method [%s]: Error while reading "
          "FileDownloadCancelMsg\n",
          __FILE__, __FUNCTION__);
    rfbCloseClient(cl);
    return;
  }
  msg.fdc.reasonLen = Swap16IfLE(msg.fdc.reasonLen);
  if (msg.fdc.reasonLen == 0) {
    rfbLog("File [%s]: Method [%s]: reason length received is Zero\n", __FILE__,
           __FUNCTION__);
    return;
  }
  reason = (char*)calloc(msg.fdc.reasonLen + 1, sizeof(char));
  if (reason == NULL) {
    rfbLog("File [%s]: Method [%s]: Fatal Error: Memory alloc failed\n",
           __FILE__, __FUNCTION__);
    return;
  }
  if ((n = rfbReadExact(cl, reason, msg.fdc.reasonLen)) <= 0) {
    if (n < 0)
      rfbLog(
          "File [%s]: Method [%s]: Error while reading "
          "FileDownloadCancelMsg\n",
          __FILE__, __FUNCTION__);
    rfbCloseClient(cl);
  }
  rfbLog(
      "File [%s]: Method [%s]: File Download Cancel Request received:"
      " reason <%s>\n",
      __FILE__, __FUNCTION__, reason);
  pthread_mutex_lock(&fileDownloadMutex);
  CloseUndoneFileTransfer(cl, rtcp);
  pthread_mutex_unlock(&fileDownloadMutex);
  if (reason != NULL) {
    free(reason);
    reason = NULL;
  }
}

lyd_new(struct lyd_node* parent, const struct lys_module* module,
        const char* name) {
  const struct lys_node *snode = NULL, *siblings;
  if ((!parent && !module) || !name) {
    LOGARG;
