  }
  return _lyd_new(parent, snode, 0);
}

static int ext4_xattr_make_inode_space(handle_t* handle, struct inode* inode,
                                       struct ext4_inode* raw_inode,
                                       int isize_diff, size_t ifree,
                                       size_t bfree, int* total_ino) {
  struct ext4_xattr_ibody_header* header = IHDR(inode, raw_inode);
  struct ext4_xattr_entry* small_entry;
  struct ext4_xattr_entry* entry;
  struct ext4_xattr_entry* last;
  unsigned int entry_size;
  unsigned int total_size;
  unsigned int min_total_size;
  int error;
  while (isize_diff > ifree) {
    entry = NULL;
    small_entry = NULL;
    min_total_size = ~0U;
    last = IFIRST(header);
    for (; !IS_LAST_ENTRY(last); last = EXT4_XATTR_NEXT(last)) {
      total_size = EXT4_XATTR_LEN(last->e_name_len);
      if (!last->e_value_inum)
        total_size += EXT4_XATTR_SIZE(le32_to_cpu(last->e_value_size));
      if (total_size <= bfree && total_size < min_total_size) {
        if (total_size + ifree < isize_diff) {
          small_entry = last;
        } else {
          entry = last;
          min_total_size = total_size;
        }
      }
    }
    if (entry == NULL) {
      if (small_entry == NULL) return -ENOSPC;
      entry = small_entry;
    }
    entry_size = EXT4_XATTR_LEN(entry->e_name_len);
    total_size = entry_size;
    if (!entry->e_value_inum)
      total_size += EXT4_XATTR_SIZE(le32_to_cpu(entry->e_value_size));
    error = ext4_xattr_move_to_block(handle, inode, raw_inode, entry);
    if (error) return error;
    *total_ino -= entry_size;
    ifree += total_size;
    bfree -= total_size;
  }
  return 0;
}

static OPJ_BOOL opj_tcd_code_block_enc_allocate_data(
    opj_tcd_cblk_enc_t* p_code_block) {
  OPJ_UINT32 l_data_size;
  l_data_size = 1 + (OPJ_UINT32)((p_code_block->x1 - p_code_block->x0) *
                                 (p_code_block->y1 - p_code_block->y0) *
                                 (OPJ_INT32)sizeof(OPJ_UINT32));
  if (l_data_size > p_code_block->data_size) {
    if (p_code_block->data) {
      opj_free(p_code_block->data - 1);
    }
    p_code_block->data = (OPJ_BYTE*)opj_malloc(l_data_size + 1);
    if (!p_code_block->data) {
      p_code_block->data_size = 0U;
      return OPJ_FALSE;
    }
    p_code_block->data_size = l_data_size;
    p_code_block->data[0] = 0;
    p_code_block->data += 1;
  }
  return OPJ_TRUE;
}

bool Router::MatchView(const std::string& method, const std::string& url,
                       bool* stream) {
  assert(stream != nullptr);
  *stream = false;
  for (auto& route : routes_) {
    if (std::find(route.methods.begin(), route.methods.end(), method) ==
        route.methods.end()) {
      continue;
    }
    if (route.url.empty()) {
      std::smatch match;
      if (std::regex_match(url, match, route.url_regex)) {
        *stream = route.view->Stream(method);
        return true;
      }
    } else {
      if (boost::iequals(route.url, url)) {
        *stream = route.view->Stream(method);
        return true;
      }
    }
  }
  return false;
}

static Jsi_RC jsi_BitfieldToValue(Jsi_Interp* interp, Jsi_OptionSpec* spec,
                                  Jsi_Value** outValue, Jsi_DString* outStr,
                                  void* record, Jsi_Wide flags) {
  Jsi_csgset* bsget = spec->init.OPT_BITS;
  Jsi_Interp* d = interp;
  int idx = spec->idx;
  uchar* data = (uchar*)record;
  int64_t inum;
  Jsi_OptionSpec* enumSpec = (typeof(enumSpec))spec->data;
  if (!d || !bsget || idx < 0) return Jsi_LogBug("invalid bitfield");
  Jsi_RC rc = (*bsget)(interp, data, &inum, spec, idx, 0);
  if (rc != JSI_OK) return JSI_ERROR;
  if (enumSpec) {
    struct numStruct {
      int64_t numVal;
    } nval = {inum};
    Jsi_OptionSpec eSpec[] = {
        JSI_OPT(CUSTOM, struct numStruct, numVal, .help = spec->help,
                .flags = JSI_OPT_ENUM_SPEC, .custom = Jsi_Opt_SwitchEnum,
                .data = (void*)enumSpec, .info = 0, .tname = spec->tname,
                .value = 0, .bits = 0, .boffset = 8 * sizeof(int64_t)),
        JSI_OPT_END(struct numStruct)};
    if (JSI_OK !=
        jsi_EnumToValue(interp, eSpec, outValue, outStr, (void*)&nval, flags))
      return JSI_ERROR;
  } else if (outStr) {
    char obuf[100];
    snprintf(obuf, sizeof(obuf), "%" PRId64, inum);
    Jsi_DSAppend(outStr, obuf, NULL);
  } else {
    Jsi_Number num = (Jsi_Number)inum;
    Jsi_ValueMakeNumber(interp, outValue, num);
  }
  return JSI_OK;
}

ctnetlink_parse_tuple_filter(const struct nlattr* const cda[],
                             struct nf_conntrack_tuple* tuple, u32 type,
                             u_int8_t l3num, struct nf_conntrack_zone* zone,
                             u_int32_t flags) {
  struct nlattr* tb[CTA_TUPLE_MAX + 1];
  int err;
  memset(tuple, 0, sizeof(*tuple));
  err = nla_parse_nested_deprecated(tb, CTA_TUPLE_MAX, cda[type],
                                    tuple_nla_policy, NULL);
  if (err < 0) return err;
  tuple->src.l3num = l3num;
  if (flags & CTA_FILTER_FLAG(CTA_IP_DST) ||
      flags & CTA_FILTER_FLAG(CTA_IP_SRC)) {
    if (!tb[CTA_TUPLE_IP]) return -EINVAL;
    err = ctnetlink_parse_tuple_ip(tb[CTA_TUPLE_IP], tuple, flags);
    if (err < 0) return err;
  }
  if (flags & CTA_FILTER_FLAG(CTA_PROTO_NUM)) {
    if (!tb[CTA_TUPLE_PROTO]) return -EINVAL;
    err = ctnetlink_parse_tuple_proto(tb[CTA_TUPLE_PROTO], tuple, flags);
    if (err < 0) return err;
  } else if (flags & CTA_FILTER_FLAG(ALL_CTA_PROTO)) {
    return -EINVAL;
  }
  if ((flags & CTA_FILTER_FLAG(CTA_TUPLE_ZONE)) && tb[CTA_TUPLE_ZONE]) {
    if (!zone) return -EINVAL;
    err = ctnetlink_parse_tuple_zone(tb[CTA_TUPLE_ZONE], type, zone);
    if (err < 0) return err;
  }
  if (type == CTA_TUPLE_REPLY)
    tuple->dst.dir = IP_CT_DIR_REPLY;
  else
    tuple->dst.dir = IP_CT_DIR_ORIGINAL;
  return 0;
}

bool PackLinuxElf64::calls_crt1(Elf64_Rela const* rela, int sz) {
  if (!dynsym || !dynstr) {
    return false;
  }
  for (unsigned relnum = 0; 0 < sz;
       (sz -= sizeof(Elf64_Rela)), ++rela, ++relnum) {
    unsigned const symnum = get_te64(&rela->r_info) >> 32;
    char const* const symnam = get_dynsym_name(symnum, relnum);
    if (0 == strcmp(symnam, "__libc_start_main") ||
        0 == strcmp(symnam, "__libc_init") ||
        0 == strcmp(symnam, "__uClibc_main") ||
        0 == strcmp(symnam, "__uClibc_start_main"))
      return true;
  }
  return false;
}

static unsigned int help(struct sk_buff* skb, enum ip_conntrack_info ctinfo,
                         unsigned int protoff, unsigned int matchoff,
                         unsigned int matchlen,
                         struct nf_conntrack_expect* exp) {
  char buffer[sizeof("4294967296 65635")];
  u_int16_t port;
  unsigned int ret;
  exp->saved_proto.tcp.port = exp->tuple.dst.u.tcp.port;
  exp->dir = IP_CT_DIR_REPLY;
  exp->expectfn = nf_nat_follow_master;
  for (port = ntohs(exp->saved_proto.tcp.port); port != 0; port++) {
    int ret;
    exp->tuple.dst.u.tcp.port = htons(port);
    ret = nf_ct_expect_related(exp);
    if (ret == 0)
      break;
    else if (ret != -EBUSY) {
      port = 0;
      break;
    }
  }
  if (port == 0) {
    nf_ct_helper_log(skb, exp->master, "all ports in use");
    return NF_DROP;
  }
  ret = nf_nat_mangle_tcp_packet(skb, exp->master, ctinfo, protoff, matchoff,
                                 matchlen, buffer, strlen(buffer));
  if (ret != NF_ACCEPT) {
    nf_ct_helper_log(skb, exp->master, "cannot mangle packet");
    nf_ct_unexpect_related(exp);
  }
  return ret;
}

int kvm_read_guest_page(struct kvm* kvm, gfn_t gfn, void* data, int offset,
                        int len) {
