  if (kvm_is_error_hva(addr)) return -EFAULT;
  r = copy_from_user(data, (void __user*)addr + offset, len);
  if (r) return -EFAULT;
  return 0;
}

static PresentationContext* PresentationContext_new(VideoClientContext* video,
                                                    BYTE PresentationId,
                                                    UINT32 x, UINT32 y,
                                                    UINT32 width,
                                                    UINT32 height) {
  VideoClientContextPriv* priv = video->priv;
  PresentationContext* ret = calloc(1, sizeof(*ret));
  if (!ret) return NULL;
  ret->video = video;
  ret->PresentationId = PresentationId;
  ret->h264 = h264_context_new(FALSE);
  if (!ret->h264) {
    WLog_ERR(TAG, "unable to create a h264 context");
    goto error_h264;
  }
  h264_context_reset(ret->h264, width, height);
  ret->currentSample = Stream_New(NULL, 4096);
  if (!ret->currentSample) {
    WLog_ERR(TAG, "unable to create current packet stream");
    goto error_currentSample;
  }
  ret->surfaceData = BufferPool_Take(priv->surfacePool, width * height * 4);
  if (!ret->surfaceData) {
    WLog_ERR(TAG, "unable to allocate surfaceData");
    goto error_surfaceData;
  }
  ret->surface =
      video->createSurface(video, ret->surfaceData, x, y, width, height);
  if (!ret->surface) {
    WLog_ERR(TAG, "unable to create surface");
    goto error_surface;
  }
  ret->yuv = yuv_context_new(FALSE);
  if (!ret->yuv) {
    WLog_ERR(TAG, "unable to create YUV decoder");
    goto error_yuv;
  }
  yuv_context_reset(ret->yuv, width, height);
  ret->refCounter = 1;
  return ret;
error_yuv:
  video->deleteSurface(video, ret->surface);
error_surface:
  BufferPool_Return(priv->surfacePool, ret->surfaceData);
error_surfaceData:
  Stream_Free(ret->currentSample, TRUE);
error_currentSample:
  h264_context_free(ret->h264);
error_h264:
  free(ret);
  return NULL;
}

static void update_exception_bitmap(struct kvm_vcpu* vcpu) {
  u32 eb;
  eb = (1u << PF_VECTOR) | (1u << UD_VECTOR) | (1u << MC_VECTOR) |
       (1u << NM_VECTOR) | (1u << DB_VECTOR);
  if ((vcpu->guest_debug & (KVM_GUESTDBG_ENABLE | KVM_GUESTDBG_USE_SW_BP)) ==
      (KVM_GUESTDBG_ENABLE | KVM_GUESTDBG_USE_SW_BP))
    eb |= 1u << BP_VECTOR;
  if (to_vmx(vcpu)->rmode.vm86_active) eb = ~0;
  if (enable_ept) eb &= ~(1u << PF_VECTOR);
  if (vcpu->fpu_active) eb &= ~(1u << NM_VECTOR);
  if (is_guest_mode(vcpu)) eb |= get_vmcs12(vcpu)->exception_bitmap;
  vmcs_write32(EXCEPTION_BITMAP, eb);
}

static unsigned int tun_chr_poll(struct file* file, poll_table* wait) {
  struct tun_file* tfile = file->private_data;
  struct tun_struct* tun = __tun_get(tfile);
  struct sock* sk = tun->sk;
  unsigned int mask = 0;
  if (!tun) return POLLERR;
  DBG(KERN_INFO "%s: tun_chr_poll\n", tun->dev->name);
  poll_wait(file, &tun->socket.wait, wait);
  if (!skb_queue_empty(&tun->readq)) mask |= POLLIN | POLLRDNORM;
  if (sock_writeable(sk) ||
      (!test_and_set_bit(SOCK_ASYNC_NOSPACE, &sk->sk_socket->flags) &&
       sock_writeable(sk)))
    mask |= POLLOUT | POLLWRNORM;
  if (tun->dev->reg_state != NETREG_REGISTERED) mask = POLLERR;
  tun_put(tun);
  return mask;
}

concat_opt_exact_str(OptStr* to, UChar* s, UChar* end, OnigEncoding enc) {
  int i, j, len;
  UChar* p;
  for (i = to->len, p = s; p < end && i < OPT_EXACT_MAXLEN;) {
    len = enclen(enc, p);
    if (i + len > OPT_EXACT_MAXLEN) break;
    for (j = 0; j < len && p < end; j++) to->s[i++] = *p++;
  }
  to->len = i;
  if (p >= end) to->reach_end = 1;
}

int inode_change_ok(const struct inode* inode, struct iattr* attr) {
  unsigned int ia_valid = attr->ia_valid;
  if (ia_valid & ATTR_SIZE) {
    int error = inode_newsize_ok(inode, attr->ia_size);
    if (error) return error;
  }
  if (ia_valid & ATTR_FORCE) return 0;
  if ((ia_valid & ATTR_UID) &&
      (!uid_eq(current_fsuid(), inode->i_uid) ||
       !uid_eq(attr->ia_uid, inode->i_uid)) &&
      !inode_capable(inode, CAP_CHOWN))
    return -EPERM;
  if ((ia_valid & ATTR_GID) &&
      (!uid_eq(current_fsuid(), inode->i_uid) ||
       (!in_group_p(attr->ia_gid) && !gid_eq(attr->ia_gid, inode->i_gid))) &&
      !inode_capable(inode, CAP_CHOWN))
    return -EPERM;
  if (ia_valid & ATTR_MODE) {
    if (!inode_owner_or_capable(inode)) return -EPERM;
    if (!in_group_p((ia_valid & ATTR_GID) ? attr->ia_gid : inode->i_gid) &&
        !inode_capable(inode, CAP_FSETID))
      attr->ia_mode &= ~S_ISGID;
  }
  if (ia_valid & (ATTR_MTIME_SET | ATTR_ATIME_SET | ATTR_TIMES_SET)) {
    if (!inode_owner_or_capable(inode)) return -EPERM;
  }
  return 0;
}

