bool CFontFileType1::RemovePfbMarkers() {
  bool bSuccess = true;
  int nBlockType = 0;
  int nBlockLen = 0;
  int nChar = 0;
  unsigned char* sBuffer = NULL;
  int nBufLen = 0;
  while (nBlockType != PFB_DONE) {
    while (0 == nBlockLen) {
      nChar = ReadU8(&bSuccess);
      if (!bSuccess) return false;
      nBlockType = ReadU8(&bSuccess);
      if (!bSuccess || PFB_MARKER != nChar ||
          (PFB_ASCII != nBlockType && PFB_BINARY != nBlockType &&
           PFB_DONE != nBlockType))
        return false;
      if (PFB_DONE == nBlockType) break;
      nBlockLen = ReadU32LE(&bSuccess);
      if (!bSuccess) return false;
    }
    if (nBlockLen > 0) {
      if (!sBuffer) {
        sBuffer = (unsigned char*)MemUtilsMalloc(nBlockLen);
        if (!sBuffer) return false;
      } else
        sBuffer = (unsigned char*)MemUtilsRealloc(sBuffer, nBufLen + nBlockLen);
      Read(sBuffer + nBufLen, nBlockLen);
      nBufLen += nBlockLen;
    }
    nBlockLen = 0;
  }
  if (m_bFreeFileData) MemUtilsFree(m_sFile);
  m_bFreeFileData = true;
  m_sFile = (unsigned char*)sBuffer;
  m_sFileData = m_sFile;
  m_nLen = nBufLen;
  m_nPos = 0;
  return true;
}

int ASN1_TYPE_cmp(const ASN1_TYPE* a, const ASN1_TYPE* b) {
  int result = -1;
  if (!a || !b || a->type != b->type) return -1;
  switch (a->type) {
    case V_ASN1_OBJECT:
      result = OBJ_cmp(a->value.object, b->value.object);
      break;
    case V_ASN1_NULL:
      result = 0;
      break;
    case V_ASN1_NEG_ENUMERATED:
    case V_ASN1_BIT_STRING:
    case V_ASN1_OCTET_STRING:
    case V_ASN1_SEQUENCE:
    case V_ASN1_SET:
    case V_ASN1_NUMERICSTRING:
    case V_ASN1_PRINTABLESTRING:
    case V_ASN1_T61STRING:
    case V_ASN1_VIDEOTEXSTRING:
    case V_ASN1_IA5STRING:
    case V_ASN1_UTCTIME:
    case V_ASN1_GENERALIZEDTIME:
    case V_ASN1_GRAPHICSTRING:
    case V_ASN1_VISIBLESTRING:
    case V_ASN1_GENERALSTRING:
    case V_ASN1_UNIVERSALSTRING:
    case V_ASN1_BMPSTRING:
    case V_ASN1_UTF8STRING:
    case V_ASN1_OTHER:
    default:
      result = ASN1_STRING_cmp((ASN1_STRING*)a->value.ptr,
                               (ASN1_STRING*)b->value.ptr);
      break;
  }
  return result;
}

void SkiaOutputSurfaceImpl::Reshape(const gfx::Size& size,
                                    float device_scale_factor,
                                    const gfx::ColorSpace& color_space,
                                    bool has_alpha, bool use_stencil) {
  DCHECK_CALLED_ON_VALID_THREAD(thread_checker_);
