      base::Unretained(impl_on_gpu_.get()), size, device_scale_factor,
      std::move(color_space), has_alpha, use_stencil, pre_transform_,
      characterization, initialize_waitable_event_.get());
  ScheduleGpuTask(std::move(callback), std::vector<gpu::SyncToken>());
}

static inline int xsave_state_booting(struct xsave_struct* fx, u64 mask) {
  u32 lmask = mask;
  u32 hmask = mask >> 32;
  int err = 0;
  WARN_ON(system_state != SYSTEM_BOOTING);
  if (boot_cpu_has(X86_FEATURE_XSAVES))
    asm volatile("1:" XSAVES
                 "\n\t"
                 "2:\n\t"
                 :
                 : "D"(fx), "m"(*fx), "a"(lmask), "d"(hmask)
                 : "memory");
  else
    asm volatile("1:" XSAVE
                 "\n\t"
                 "2:\n\t"
                 :
                 : "D"(fx), "m"(*fx), "a"(lmask), "d"(hmask)
                 : "memory");
  asm volatile(xstate_fault : "0"(0) : "memory");
  return err;
}

void dmar_free_irte(const struct intr_source* intr_src, uint16_t index) {
  struct dmar_drhd_rt* dmar_unit;
  union dmar_ir_entry *ir_table, *ir_entry;
  union pci_bdf sid;
  if (intr_src->is_msi) {
    dmar_unit = device_to_dmaru((uint8_t)intr_src->src.msi.bits.b,
                                intr_src->src.msi.fields.devfun);
  } else {
    dmar_unit = ioapic_to_dmaru(intr_src->src.ioapic_id, &sid);
  }
  if (is_dmar_unit_valid(dmar_unit, sid)) {
    ir_table = (union dmar_ir_entry*)hpa2hva(dmar_unit->ir_table_addr);
    ir_entry = ir_table + index;
    ir_entry->bits.remap.present = 0x0UL;
    iommu_flush_cache(ir_entry, sizeof(union dmar_ir_entry));
    dmar_invalid_iec(dmar_unit, index, 0U, false);
    if (!is_irte_reserved(dmar_unit, index)) {
      spinlock_obtain(&dmar_unit->lock);
      bitmap_clear_nolock(index & 0x3FU,
                          &dmar_unit->irte_alloc_bitmap[index >> 6U]);
      spinlock_release(&dmar_unit->lock);
    }
  }
}

int inet_sk_rebuild_header(struct sock* sk) {
  struct inet_sock* inet = inet_sk(sk);
  struct rtable* rt = (struct rtable*)__sk_dst_check(sk, 0);
  __be32 daddr;
  int err;
  if (rt) return 0;
  daddr = inet->inet_daddr;
  if (inet->opt && inet->opt->srr) daddr = inet->opt->faddr;
  rt =
      ip_route_output_ports(sock_net(sk), sk, daddr, inet->inet_saddr,
                            inet->inet_dport, inet->inet_sport, sk->sk_protocol,
                            RT_CONN_FLAGS(sk), sk->sk_bound_dev_if);
  if (!IS_ERR(rt)) {
    err = 0;
    sk_setup_caps(sk, &rt->dst);
  } else {
    err = PTR_ERR(rt);
    sk->sk_route_caps = 0;
    if (!sysctl_ip_dynaddr || sk->sk_state != TCP_SYN_SENT ||
        (sk->sk_userlocks & SOCK_BINDADDR_LOCK) ||
        (err = inet_sk_reselect_saddr(sk)) != 0)
      sk->sk_err_soft = -err;
  }
  return err;
}

int setup_conds(THD* thd, TABLE_LIST* tables, List<TABLE_LIST>& leaves,
                COND** conds) {
  SELECT_LEX* select_lex = thd->lex->current_select;
  TABLE_LIST* table = NULL;
  bool it_is_update = (select_lex == thd->lex->first_select_lex()) &&
                      thd->lex->which_check_option_applicable();
  bool save_is_item_list_lookup = select_lex->is_item_list_lookup;
  TABLE_LIST* derived = select_lex->master_unit()->derived;
  DBUG_ENTER("setup_conds");
  select_lex->is_item_list_lookup = 0;
  thd->column_usage = MARK_COLUMNS_READ;
  DBUG_PRINT("info", ("thd->column_usage: %d", thd->column_usage));
  select_lex->cond_count = 0;
  select_lex->between_count = 0;
  select_lex->max_equal_elems = 0;
  for (table = tables; table; table = table->next_local) {
    if (select_lex == thd->lex->first_select_lex() &&
        select_lex->first_cond_optimization && table->merged_for_insert &&
        table->prepare_where(thd, conds, FALSE))
      goto err_no_arena;
  }
  if (*conds) {
    thd->where = "where clause";
    DBUG_EXECUTE("where",
                 print_where(*conds, "WHERE in setup_conds", QT_ORDINARY););
    if ((*conds)->type() == Item::FIELD_ITEM && !derived)
      wrap_ident(thd, conds);
    (*conds)->mark_as_condition_AND_part(NO_JOIN_NEST);
    if ((*conds)->fix_fields_if_needed_for_bool(thd, conds)) goto err_no_arena;
  }
  if (setup_on_expr(thd, tables, it_is_update)) goto err_no_arena;
  if (!thd->stmt_arena->is_conventional()) {
    select_lex->where = *conds;
  }
  thd->lex->current_select->is_item_list_lookup = save_is_item_list_lookup;
  DBUG_RETURN(thd->is_error());
err_no_arena:
  select_lex->is_item_list_lookup = save_is_item_list_lookup;
  DBUG_RETURN(1);
}

static int rfcomm_sock_bind(struct socket* sock, struct sockaddr* addr,
                            int addr_len) {
  struct sockaddr_rc* sa = (struct sockaddr_rc*)addr;
  struct sock* sk = sock->sk;
  int chan = sa->rc_channel;
  int err = 0;
  BT_DBG("sk %p %pMR", sk, &sa->rc_bdaddr);
  if (!addr || addr->sa_family != AF_BLUETOOTH) return -EINVAL;
  lock_sock(sk);
  if (sk->sk_state != BT_OPEN) {
    err = -EBADFD;
    goto done;
  }
  if (sk->sk_type != SOCK_STREAM) {
    err = -EINVAL;
    goto done;
  }
  write_lock(&rfcomm_sk_list.lock);
  if (chan && __rfcomm_get_listen_sock_by_addr(chan, &sa->rc_bdaddr)) {
    err = -EADDRINUSE;
  } else {
    bacpy(&rfcomm_pi(sk)->src, &sa->rc_bdaddr);
    rfcomm_pi(sk)->channel = chan;
    sk->sk_state = BT_BOUND;
  }
  write_unlock(&rfcomm_sk_list.lock);
done:
  release_sock(sk);
  return err;
}

int cfg80211_mgd_wext_giwessid(struct net_device* dev,
                               struct iw_request_info* info,
                               struct iw_point* data, char* ssid) {
  struct wireless_dev* wdev = dev->ieee80211_ptr;
  if (WARN_ON(wdev->iftype != NL80211_IFTYPE_STATION)) return -EINVAL;
  data->flags = 0;
  wdev_lock(wdev);
  if (wdev->current_bss) {
    const u8* ie;
    rcu_read_lock();
    ie = ieee80211_bss_get_ie(&wdev->current_bss->pub, WLAN_EID_SSID);
    if (ie) {
      data->flags = 1;
      data->length = ie[1];
      memcpy(ssid, ie + 2, data->length);
    }
    rcu_read_unlock();
  } else if (wdev->wext.connect.ssid && wdev->wext.connect.ssid_len) {
    data->flags = 1;
    data->length = wdev->wext.connect.ssid_len;
    memcpy(ssid, wdev->wext.connect.ssid, data->length);
  }
  wdev_unlock(wdev);
  return 0;
}

void diff_addremove(struct diff_options* options, int addremove, unsigned mode,
                    const unsigned char* sha1, const char* base,
                    const char* path) {
  char concatpath[PATH_MAX];
  struct diff_filespec *one, *two;
  if (DIFF_OPT_TST(options, IGNORE_SUBMODULES) && S_ISGITLINK(mode)) return;
  if (DIFF_OPT_TST(options, REVERSE_DIFF))
    addremove = (addremove == '+' ? '-' : addremove == '-' ? '+' : addremove);
  if (!path) path = "";
  sprintf(concatpath, "%s%s", base, path);
  if (options->prefix &&
      strncmp(concatpath, options->prefix, options->prefix_length))
    return;
  one = alloc_filespec(concatpath);
  two = alloc_filespec(concatpath);
  if (addremove != '+') fill_filespec(one, sha1, mode);
  if (addremove != '-') fill_filespec(two, sha1, mode);
  diff_queue(&diff_queued_diff, one, two);
  DIFF_OPT_SET(options, HAS_CHANGES);
}

static int java_switch_op(RAnal* anal, RAnalOp* op, ut64 addr, const ut8* data,
                          int len) {
  ut8 op_byte = data[0];
  ut64 offset = addr - java_get_method_start();
  ut8 pos = (offset + 1) % 4 ? 1 + 4 - (offset + 1) % 4 : 1;
  if (op_byte == 0xaa) {
    if (pos + 8 > len) {
      return op->size;
    }
    int min_val = (ut32)(UINT(data, pos + 4)),
        max_val = (ut32)(UINT(data, pos + 8));
    ut32 default_loc = (ut32)(UINT(data, pos)), cur_case = 0;
    op->switch_op = r_anal_switch_op_new(addr, min_val, default_loc);
    RAnalCaseOp* caseop = NULL;
    pos += 12;
    if (max_val > min_val && ((max_val - min_val) < (UT16_MAX / 4))) {
      for (cur_case = 0; cur_case <= max_val - min_val; pos += 4, cur_case++) {
        if (pos + 4 >= len) {
          break;
        }
        int offset = (int)(ut32)(R_BIN_JAVA_UINT(data, pos));
        caseop = r_anal_switch_op_add_case(op->switch_op, addr + pos,
                                           cur_case + min_val, addr + offset);
        if (caseop) {
          caseop->bb_ref_to = addr + offset;
          caseop->bb_ref_from = addr;
        }
      }
    } else {
      eprintf("Invalid switch boundaries at 0x%" PFMT64x "\n", addr);
    }
  }
  op->size = pos;
  return op->size;
}

static int klsi_105_get_line_state(struct usb_serial_port* port,
                                   unsigned long* line_state_p) {
  int rc;
  u8* status_buf;
  __u16 status;
  dev_info(&port->serial->dev->dev, "sending SIO Poll request\n");
  status_buf = kmalloc(KLSI_STATUSBUF_LEN, GFP_KERNEL);
  if (!status_buf) return -ENOMEM;
  status_buf[0] = 0xff;
  status_buf[1] = 0xff;
  rc = usb_control_msg(port->serial->dev, usb_rcvctrlpipe(port->serial->dev, 0),
                       KL5KUSB105A_SIO_POLL, USB_TYPE_VENDOR | USB_DIR_IN, 0, 0,
                       status_buf, KLSI_STATUSBUF_LEN, 10000);
  if (rc < 0)
    dev_err(&port->dev, "Reading line status failed (error = %d)\n", rc);
  else {
    status = get_unaligned_le16(status_buf);
    dev_info(&port->serial->dev->dev, "read status %x %x\n", status_buf[0],
             status_buf[1]);
    *line_state_p = klsi_105_status2linestate(status);
  }
  kfree(status_buf);
  return rc;
}

static ssize_t ucma_migrate_id(struct ucma_file* new_file,
                               const char __user* inbuf, int in_len,
                               int out_len) {
  struct rdma_ucm_migrate_id cmd;
  struct rdma_ucm_migrate_resp resp;
  struct ucma_context* ctx;
  struct fd f;
  struct ucma_file* cur_file;
  int ret = 0;
  if (copy_from_user(&cmd, inbuf, sizeof(cmd))) return -EFAULT;
  f = fdget(cmd.fd);
  if (!f.file) return -ENOENT;
  if (f.file->f_op != &ucma_fops) {
    ret = -EINVAL;
    goto file_put;
  }
  ctx = ucma_get_ctx(f.file->private_data, cmd.id);
  if (IS_ERR(ctx)) {
    ret = PTR_ERR(ctx);
    goto file_put;
  }
  rdma_lock_handler(ctx->cm_id);
  cur_file = ctx->file;
  if (cur_file == new_file) {
    mutex_lock(&cur_file->mut);
    resp.events_reported = ctx->events_reported;
    mutex_unlock(&cur_file->mut);
    goto response;
  }
  ucma_lock_files(cur_file, new_file);
  xa_lock(&ctx_table);
  list_move_tail(&ctx->list, &new_file->ctx_list);
  ucma_move_events(ctx, new_file);
  ctx->file = new_file;
  resp.events_reported = ctx->events_reported;
  xa_unlock(&ctx_table);
  ucma_unlock_files(cur_file, new_file);
response:
  if (copy_to_user(u64_to_user_ptr(cmd.response), &resp, sizeof(resp)))
    ret = -EFAULT;
  rdma_unlock_handler(ctx->cm_id);
  ucma_put_ctx(ctx);
file_put:
  fdput(f);
  return ret;
}

void ZydisFormatterBufferInitTokenized(ZydisFormatterBuffer* buffer,
                                       ZydisFormatterToken** first_token,
                                       void* user_buffer, ZyanUSize length) {
  ZYAN_ASSERT(buffer);
  ZYAN_ASSERT(first_token);
  ZYAN_ASSERT(user_buffer);
  ZYAN_ASSERT(length);
  *first_token = user_buffer;
  (*first_token)->type = ZYDIS_TOKEN_INVALID;
  (*first_token)->next = 0;
  user_buffer = (ZyanU8*)user_buffer + sizeof(ZydisFormatterToken);
  length -= sizeof(ZydisFormatterToken);
  buffer->is_token_list = ZYAN_TRUE;
  buffer->capacity = length;
  buffer->string.flags = ZYAN_STRING_HAS_FIXED_CAPACITY;
  buffer->string.vector.allocator = ZYAN_NULL;
  buffer->string.vector.element_size = sizeof(char);
  buffer->string.vector.size = 1;
  buffer->string.vector.capacity = length;
  buffer->string.vector.data = user_buffer;
  *(char*)user_buffer = '\0';
}

