gdImagePtr gdImageScaleTwoPass(const gdImagePtr src,
                               const unsigned int src_width,
                               const unsigned int src_height,
                               const unsigned int new_width,
                               const unsigned int new_height) {
  gdImagePtr tmp_im;
  gdImagePtr dst;
  if (!src->trueColor) {
    gdImagePaletteToTrueColor(src);
  }
  tmp_im = gdImageCreateTrueColor(new_width, src_height);
  if (tmp_im == NULL) {
    return NULL;
  }
  gdImageSetInterpolationMethod(tmp_im, src->interpolation_id);
  _gdScaleHoriz(src, src_width, src_height, tmp_im, new_width, src_height);
  dst = gdImageCreateTrueColor(new_width, new_height);
  if (dst == NULL) {
    gdFree(tmp_im);
    return NULL;
  }
  gdImageSetInterpolationMethod(dst, src->interpolation_id);
  _gdScaleVert(tmp_im, new_width, src_height, dst, new_width, new_height);
  gdFree(tmp_im);
  return dst;
}

static ssize_t fuse_fill_write_pages(struct fuse_req* req,
                                     struct address_space* mapping,
                                     struct iov_iter* ii, loff_t pos) {
  struct fuse_conn* fc = get_fuse_conn(mapping->host);
  unsigned offset = pos & (PAGE_CACHE_SIZE - 1);
  size_t count = 0;
  int err;
  req->in.argpages = 1;
  req->page_descs[0].offset = offset;
  do {
    size_t tmp;
    struct page* page;
    pgoff_t index = pos >> PAGE_CACHE_SHIFT;
    size_t bytes = min_t(size_t, PAGE_CACHE_SIZE - offset, iov_iter_count(ii));
    bytes = min_t(size_t, bytes, fc->max_write - count);
  again:
    err = -EFAULT;
    if (iov_iter_fault_in_readable(ii, bytes)) break;
    err = -ENOMEM;
    page = grab_cache_page_write_begin(mapping, index, 0);
    if (!page) break;
    if (mapping_writably_mapped(mapping)) flush_dcache_page(page);
    tmp = iov_iter_copy_from_user_atomic(page, ii, offset, bytes);
    flush_dcache_page(page);
    if (!tmp) {
      unlock_page(page);
      page_cache_release(page);
      bytes = min(bytes, iov_iter_single_seg_count(ii));
      goto again;
    }
    err = 0;
    req->pages[req->num_pages] = page;
    req->page_descs[req->num_pages].length = tmp;
    req->num_pages++;
    iov_iter_advance(ii, tmp);
    count += tmp;
    pos += tmp;
    offset += tmp;
    if (offset == PAGE_CACHE_SIZE) offset = 0;
    if (!fc->big_writes) break;
  } while (iov_iter_count(ii) && count < fc->max_write &&
           req->num_pages < req->max_pages && offset == 0);
  return count > 0 ? count : err;
}

