static char* get_private_subtags(const char* loc_name) {
  char* result = NULL;
  int singletonPos = 0;
  int len = 0;
  const char* mod_loc_name = NULL;
  if (loc_name && (len = strlen(loc_name) > 0)) {
    mod_loc_name = loc_name;
    len = strlen(mod_loc_name);
    while ((singletonPos = getSingletonPos(mod_loc_name)) != -1) {
      if (singletonPos != -1) {
        if ((*(mod_loc_name + singletonPos) == 'x') ||
            (*(mod_loc_name + singletonPos) == 'X')) {
          if (singletonPos + 2 == len) {
          } else {
            result = estrndup(mod_loc_name + singletonPos + 2,
                              (len - (singletonPos + 2)));
          }
          break;
        } else {
          if (singletonPos + 1 >= len) {
            break;
          } else {
            mod_loc_name = mod_loc_name + singletonPos + 1;
            len = strlen(mod_loc_name);
          }
        }
      }
    }
  }
  return result;
}

idn2_to_ascii_4i(const uint32_t* input, size_t inlen, char* output, int flags) {
  uint32_t* input_u32;
  uint8_t *input_u8, *output_u8;
  size_t length;
  int rc;
  if (!input) {
    if (output) *output = 0;
    return IDN2_OK;
  }
  input_u32 = (uint32_t*)malloc((inlen + 1) * sizeof(uint32_t));
  if (!input_u32) return IDN2_MALLOC;
  u32_cpy(input_u32, input, inlen);
  input_u32[inlen] = 0;
  input_u8 = u32_to_u8(input_u32, inlen + 1, NULL, &length);
  free(input_u32);
  if (!input_u8) {
    if (errno == ENOMEM) return IDN2_MALLOC;
    return IDN2_ENCODING_ERROR;
  }
  rc = idn2_lookup_u8(input_u8, &output_u8, flags);
  free(input_u8);
  if (rc == IDN2_OK) {
    if (output) strcpy(output, (const char*)output_u8);
    free(output_u8);
  }
  return rc;
}

int cx23888_ir_probe(struct cx23885_dev* dev) {
  struct cx23888_ir_state* state;
  struct v4l2_subdev* sd;
  struct v4l2_subdev_ir_parameters default_params;
  int ret;
  state = kzalloc(sizeof(struct cx23888_ir_state), GFP_KERNEL);
  if (state == NULL) return -ENOMEM;
  spin_lock_init(&state->rx_kfifo_lock);
  if (kfifo_alloc(&state->rx_kfifo, CX23888_IR_RX_KFIFO_SIZE, GFP_KERNEL))
    return -ENOMEM;
  state->dev = dev;
  sd = &state->sd;
  v4l2_subdev_init(sd, &cx23888_ir_controller_ops);
  v4l2_set_subdevdata(sd, state);
  snprintf(sd->name, sizeof(sd->name), "%s/888-ir", dev->name);
  sd->grp_id = CX23885_HW_888_IR;
  ret = v4l2_device_register_subdev(&dev->v4l2_dev, sd);
  if (ret == 0) {
    cx23888_ir_write4(dev, CX23888_IR_IRQEN_REG, 0);
    mutex_init(&state->rx_params_lock);
    default_params = default_rx_params;
    v4l2_subdev_call(sd, ir, rx_s_parameters, &default_params);
    mutex_init(&state->tx_params_lock);
    default_params = default_tx_params;
    v4l2_subdev_call(sd, ir, tx_s_parameters, &default_params);
  } else {
    kfifo_free(&state->rx_kfifo);
  }
  return ret;
}

static int add_array_entry(const char* loc_name, zval* hash_arr,
                           char* key_name TSRMLS_DC) {
  char* key_value = NULL;
  char* cur_key_name = NULL;
  char* token = NULL;
  char* last_ptr = NULL;
  int result = 0;
  int cur_result = 0;
  int cnt = 0;
  if (strcmp(key_name, LOC_PRIVATE_TAG) == 0) {
    key_value = get_private_subtags(loc_name);
    result = 1;
  } else {
    key_value = get_icu_value_internal(loc_name, key_name, &result, 1);
  }
  if ((strcmp(key_name, LOC_PRIVATE_TAG) == 0) ||
      (strcmp(key_name, LOC_VARIANT_TAG) == 0)) {
    if (result > 0 && key_value) {
      token = php_strtok_r(key_value, DELIMITER, &last_ptr);
      if (cur_key_name) {
        efree(cur_key_name);
      }
      cur_key_name = (char*)ecalloc(25, 25);
      sprintf(cur_key_name, "%s%d", key_name, cnt++);
      add_assoc_string(hash_arr, cur_key_name, token, TRUE);
      while ((token = php_strtok_r(NULL, DELIMITER, &last_ptr)) &&
             (strlen(token) > 1)) {
        sprintf(cur_key_name, "%s%d", key_name, cnt++);
        add_assoc_string(hash_arr, cur_key_name, token, TRUE);
      }
    }
  } else {
    if (result == 1) {
      add_assoc_string(hash_arr, key_name, key_value, TRUE);
      cur_result = 1;
    }
  }
  if (cur_key_name) {
    efree(cur_key_name);
  }
  if (key_value) {
    efree(key_value);
  }
  return cur_result;
}

