nvkm_vmm_put_region(struct nvkm_vmm* vmm, struct nvkm_vma* vma) {
  struct nvkm_vma *prev, *next;
  if ((prev = node(vma, prev)) && !prev->used) {
    rb_erase(&prev->tree, &vmm->free);
    list_del(&prev->head);
    vma->addr = prev->addr;
    vma->size += prev->size;
    kfree(prev);
  }
  if ((next = node(vma, next)) && !next->used) {
    rb_erase(&next->tree, &vmm->free);
    list_del(&next->head);
    vma->size += next->size;
    kfree(next);
  }
  nvkm_vmm_free_insert(vmm, vma);
}

xsltCompileLocationPathPattern(xsltParserContextPtr ctxt, int novar) {
  SKIP_BLANKS;
  if ((CUR == '/') && (NXT(1) == '/')) {
    NEXT;
    NEXT;
    ctxt->comp->priority = 0.5;
    xsltCompileRelativePathPattern(ctxt, NULL, novar);
  } else if (CUR == '/') {
    NEXT;
    SKIP_BLANKS;
    PUSH(XSLT_OP_ROOT, NULL, NULL, novar);
    if ((CUR != 0) && (CUR != '|')) {
      PUSH(XSLT_OP_PARENT, NULL, NULL, novar);
      xsltCompileRelativePathPattern(ctxt, NULL, novar);
    }
  } else if (CUR == '*') {
    xsltCompileRelativePathPattern(ctxt, NULL, novar);
  } else if (CUR == '@') {
    xsltCompileRelativePathPattern(ctxt, NULL, novar);
  } else {
    xmlChar* name;
    name = xsltScanNCName(ctxt);
    if (name == NULL) {
      xsltTransformError(NULL, NULL, NULL,
                         "xsltCompileLocationPathPattern : Name expected\n");
      ctxt->error = 1;
      return;
    }
    SKIP_BLANKS;
    if ((CUR == '(') && !xmlXPathIsNodeType(name)) {
      xsltCompileIdKeyPattern(ctxt, name, 1, novar, 0);
      if ((CUR == '/') && (NXT(1) == '/')) {
        PUSH(XSLT_OP_ANCESTOR, NULL, NULL, novar);
        NEXT;
        NEXT;
        SKIP_BLANKS;
        xsltCompileRelativePathPattern(ctxt, NULL, novar);
      } else if (CUR == '/') {
        PUSH(XSLT_OP_PARENT, NULL, NULL, novar);
        NEXT;
        SKIP_BLANKS;
        xsltCompileRelativePathPattern(ctxt, NULL, novar);
      }
      return;
    }
    xsltCompileRelativePathPattern(ctxt, name, novar);
  }
error:
  return;
}

ActionReply Smb4KMountHelper::mount(const QVariantMap& args) {
  ActionReply reply;
  QMapIterator<QString, QVariant> it(args);
  proc.setOutputChannelMode(KProcess::SeparateChannels);
  proc.setProcessEnvironment(QProcessEnvironment::systemEnvironment());
#if defined(Q_OS_LINUX)
  proc.setEnv("PASSWD", entry["mh_url"].toUrl().password(), true);
#endif
  QVariantMap entry = it.value().toMap();
  KProcess proc(this);
  command << entry["mh_mountpoint"].toString();
  command << entry["mh_options"].toStringList();
#elif defined(Q_OS_FREEBSD) || defined(Q_OS_NETBSD)
  command << entry["mh_command"].toString();
  command << entry["mh_options"].toStringList();
  command << entry["mh_unc"].toString();
  command << entry["mh_mountpoint"].toString();
#else
#endif
  proc.setProgram(command);
  proc.start();
  if (proc.waitForStarted(-1)) {
    bool userKill = false;
    QStringList command;
#if defined(Q_OS_LINUX)
    command << entry["mh_command"].toString();
    command << entry["mh_unc"].toString();
    command << entry["mh_mountpoint"].toString();
    command << entry["mh_options"].toStringList();
#elif defined(Q_OS_FREEBSD) || defined(Q_OS_NETBSD)
    command << entry["mh_command"].toString();
    command << entry["mh_options"].toStringList();
    command << entry["mh_unc"].toString();
    command << entry["mh_mountpoint"].toString();
    else {
    }
    if (HelperSupport::isStopped()) {
      proc.kill();
      userKill = true;
      break;
    } else {
    }
  }
  if (proc.exitStatus() == KProcess::CrashExit) {
    if (!userKill) {
      reply.setType(ActionReply::HelperErrorType);
      reply.setErrorDescription(i18n("The mount process crashed."));
      break;
    } else {
    }
  } else {
    QString stdErr = QString::fromUtf8(proc.readAllStandardError());
    reply.addData(QString("mh_error_message_%1").arg(index), stdErr.trimmed());
  }
}

static irqreturn_t snd_msnd_interrupt(int irq, void* dev_id) {
  struct snd_msnd* chip = dev_id;
  void* pwDSPQData = chip->mappedbase + DSPQ_DATA_BUFF;
  while (readw(chip->DSPQ + JQS_wTail) != readw(chip->DSPQ + JQS_wHead)) {
    u16 wTmp;
    snd_msnd_eval_dsp_msg(
        chip, readw(pwDSPQData + 2 * readw(chip->DSPQ + JQS_wHead)));
    wTmp = readw(chip->DSPQ + JQS_wHead) + 1;
    if (wTmp > readw(chip->DSPQ + JQS_wSize))
      writew(0, chip->DSPQ + JQS_wHead);
    else
      writew(wTmp, chip->DSPQ + JQS_wHead);
  }
  inb(chip->io + HP_RXL);
  return IRQ_HANDLED;
}

static int crypto_report(struct sk_buff* in_skb, struct nlmsghdr* in_nlh,
                         struct nlattr** attrs) {
  struct net* net = sock_net(in_skb->sk);
  struct crypto_user_alg* p = nlmsg_data(in_nlh);
  struct crypto_alg* alg;
  struct sk_buff* skb;
  struct crypto_dump_info info;
  int err;
  if (!null_terminated(p->cru_name) || !null_terminated(p->cru_driver_name))
    return -EINVAL;
  alg = crypto_alg_match(p, 0);
  if (!alg) return -ENOENT;
  err = -ENOMEM;
  skb = nlmsg_new(NLMSG_DEFAULT_SIZE, GFP_KERNEL);
  if (!skb) goto drop_alg;
  info.in_skb = in_skb;
  info.out_skb = skb;
  info.nlmsg_seq = in_nlh->nlmsg_seq;
  info.nlmsg_flags = 0;
  err = crypto_report_alg(alg, &info);
drop_alg:
  crypto_mod_put(alg);
  if (err) return err;
  return nlmsg_unicast(net->crypto_nlsk, skb, NETLINK_CB(in_skb).portid);
}

choose_filters(struct archive_read* a) {
  int number_bidders, i, bid, best_bid;
  struct archive_read_filter_bidder *bidder, *best_bidder;
  struct archive_read_filter* filter;
  ssize_t avail;
  int r;
  for (;;) {
    number_bidders = sizeof(a->bidders) / sizeof(a->bidders[0]);
    best_bid = 0;
    best_bidder = NULL;
    bidder = a->bidders;
    for (i = 0; i < number_bidders; i++, bidder++) {
      if (bidder->bid != NULL) {
        bid = (bidder->bid)(bidder, a->filter);
        if (bid > best_bid) {
          best_bid = bid;
          best_bidder = bidder;
        }
      }
    }
    if (best_bidder == NULL) {
      __archive_read_filter_ahead(a->filter, 1, &avail);
      if (avail < 0) {
        __archive_read_close_filters(a);
        __archive_read_free_filters(a);
        return (ARCHIVE_FATAL);
      }
      a->archive.compression_name = a->filter->name;
      a->archive.compression_code = a->filter->code;
      return (ARCHIVE_OK);
    }
    filter = (struct archive_read_filter*)calloc(1, sizeof(*filter));
    if (filter == NULL) return (ARCHIVE_FATAL);
    filter->bidder = best_bidder;
    filter->archive = a;
    filter->upstream = a->filter;
    a->filter = filter;
    r = (best_bidder->init)(a->filter);
    if (r != ARCHIVE_OK) {
      __archive_read_close_filters(a);
      __archive_read_free_filters(a);
      return (ARCHIVE_FATAL);
    }
  }
}

static x86newTokenType getToken(const char* str, size_t* begin, size_t* end) {
  while (begin && isspace((ut8)str[*begin])) {
    ++(*begin);
  }
  if (!str[*begin]) {
    *end = *begin;
    return TT_EOF;
  } else if (isalpha((ut8)str[*begin])) {
    *end = *begin;
    while (end && isalnum((ut8)str[*end])) {
      ++(*end);
    }
    return TT_WORD;
  } else if (isdigit((ut8)str[*begin])) {
    *end = *begin;
    while (end && isalnum((ut8)str[*end])) {
      ++(*end);
    }
    return TT_NUMBER;
  } else {
    *end = *begin + 1;
    return TT_SPECIAL;
  }
}

static int rds_loop_xmit(struct rds_connection* conn, struct rds_message* rm,
                         unsigned int hdr_off, unsigned int sg,
                         unsigned int off) {
  if (rm->m_inc.i_hdr.h_flags & RDS_FLAG_CONG_BITMAP) {
    rds_cong_map_updated(conn->c_fcong, ~(u64)0);
    return sizeof(struct rds_header) + RDS_CONG_MAP_BYTES;
  }
  BUG_ON(hdr_off || sg || off);
  rds_inc_init(&rm->m_inc, conn, conn->c_laddr);
  rds_message_addref(rm);
  rds_recv_incoming(conn, conn->c_laddr, conn->c_faddr, &rm->m_inc, GFP_KERNEL,
                    KM_USER0);
  rds_send_drop_acked(conn, be64_to_cpu(rm->m_inc.i_hdr.h_sequence), NULL);
  rds_inc_put(&rm->m_inc);
  return sizeof(struct rds_header) + be32_to_cpu(rm->m_inc.i_hdr.h_len);
}

void uverbs_user_mmap_disassociate(struct ib_uverbs_file* ufile) {
  struct rdma_umap_priv *priv, *next_priv;
  lockdep_assert_held(&ufile->hw_destroy_rwsem);
  while (1) {
    struct mm_struct* mm = NULL;
    mutex_lock(&ufile->umap_lock);
    while (!list_empty(&ufile->umaps)) {
      int ret;
      priv = list_first_entry(&ufile->umaps, struct rdma_umap_priv, list);
      mm = priv->vma->vm_mm;
      ret = mmget_not_zero(mm);
      if (!ret) {
        list_del_init(&priv->list);
        mm = NULL;
        continue;
      }
      break;
    }
    mutex_unlock(&ufile->umap_lock);
    if (!mm) return;
    down_write(&mm->mmap_sem);
    mutex_lock(&ufile->umap_lock);
    list_for_each_entry_safe(priv, next_priv, &ufile->umaps, list) {
      struct vm_area_struct* vma = priv->vma;
      if (vma->vm_mm != mm) continue;
      list_del_init(&priv->list);
      zap_vma_ptes(vma, vma->vm_start, vma->vm_end - vma->vm_start);
      vma->vm_flags &= ~(VM_SHARED | VM_MAYSHARE);
    }
    mutex_unlock(&ufile->umap_lock);
    up_write(&mm->mmap_sem);
    mmput(mm);
  }
}

