static blink::WebScreenOrientations stringToOrientations(
    const AtomicString& orientationString) {
  DEFINE_STATIC_LOCAL(const AtomicString, portrait,
                      ("portrait", AtomicString::ConstructFromLiteral));
  DEFINE_STATIC_LOCAL(const AtomicString, landscape,
                      ("landscape", AtomicString::ConstructFromLiteral));
  if (orientationString == portrait)
    return blink::WebScreenOrientationPortraitPrimary |
           blink::WebScreenOrientationPortraitSecondary;
  if (orientationString == landscape)
    return blink::WebScreenOrientationLandscapePrimary |
           blink::WebScreenOrientationLandscapeSecondary;
  unsigned length = 0;
  ScreenOrientationInfo* orientationMap = orientationsMap(length);
  for (unsigned i = 0; i < length; ++i) {
    if (orientationMap[i].name == orientationString)
      return orientationMap[i].orientation;
  }
  return 0;
}

R_API int r_io_bank_read_from_submap_at(RIO* io, const ut32 bankid, ut64 addr,
                                        ut8* buf, int len) {
  r_return_val_if_fail(io, -1);
  RIOBank* bank = r_io_bank_get(io, bankid);
  if (!bank) {
    return 0;
  }
  if (!len) {
    return 0;
  }
  RRBNode* node;
  if (bank->last_used &&
      r_io_submap_contain(((RIOSubMap*)bank->last_used->data), addr)) {
    node = bank->last_used;
  } else {
    node =
        r_crbtree_find_node(bank->submaps, &addr, _find_sm_by_vaddr_cb, NULL);
    if (!node) {
      return 0;
    }
    bank->last_used = node;
  }
  RIOSubMap* sm = (RIOSubMap*)node->data;
  if (!r_io_submap_contain(sm, addr)) {
    return 0;
  }
  RIOMap* map = r_io_map_get_by_ref(io, &sm->mapref);
  if (!map || !(map->perm & R_PERM_R)) {
    return -1;
  }
  const int read_len = R_MIN(len, r_io_submap_to(sm) - addr + 1);
  if (map->perm & R_PERM_RELOC) {
    return map->reloc_map->read(io, map, addr, buf, read_len);
  }
  const ut64 paddr = addr - r_io_map_from(map) + map->delta;
  return r_io_fd_read_at(io, map->fd, paddr, buf, read_len);
}

bool DependencyOptimizer::SafeToRemoveIdentity(const NodeDef& node) const {
  if (!IsIdentity(node) && !IsIdentityN(node)) {
    return true;
  }
  if (nodes_to_preserve_.find(node.name()) != nodes_to_preserve_.end()) {
    return false;
  }
  if (!fetch_nodes_known_) {
    return false;
  }
  if (node.input_size() < 1) {
    return false;
  }
  const NodeDef* input = node_map_->GetNode(NodeName(node.input(0)));
  CHECK(input != nullptr) << "node = " << node.name()
                          << " input = " << node.input(0);
  if (IsVariable(*input) || IsRecv(*input)) {
    return false;
  }
  for (const auto& consumer : node_map_->GetOutputs(node.name())) {
    if (node.input_size() > 1 && (IsRetval(*consumer) || IsMerge(*consumer))) {
      return false;
    }
    if (IsSwitch(*input)) {
      for (const string& consumer_input : consumer->input()) {
        if (consumer_input == AsControlDependency(node.name())) {
          return false;
        }
      }
    }
  }
  return true;
}

static void sas_unregister_devs_sas_addr(struct domain_device* parent,
                                         int phy_id, bool last) {
  struct expander_device* ex_dev = &parent->ex_dev;
  struct ex_phy* phy = &ex_dev->ex_phy[phy_id];
  struct domain_device *child, *n, *found = NULL;
  if (last) {
    list_for_each_entry_safe(child, n, &ex_dev->children, siblings) {
      if (SAS_ADDR(child->sas_addr) == SAS_ADDR(phy->attached_sas_addr)) {
        set_bit(SAS_DEV_GONE, &child->state);
        if (child->dev_type == SAS_EDGE_EXPANDER_DEVICE ||
            child->dev_type == SAS_FANOUT_EXPANDER_DEVICE)
          sas_unregister_ex_tree(parent->port, child);
        else
          sas_unregister_dev(parent->port, child);
        found = child;
        break;
      }
    }
    sas_disable_routing(parent, phy->attached_sas_addr);
  }
  memset(phy->attached_sas_addr, 0, SAS_ADDR_SIZE);
  if (phy->port) {
    sas_port_delete_phy(phy->port, phy->phy);
    sas_device_set_phy(found, phy->port);
    if (phy->port->num_phys == 0) sas_port_delete(phy->port);
    phy->port = NULL;
  }
}

static int dispatch_discard_io(struct xen_blkif* blkif,
                               struct blkif_request* req) {
  int err = 0;
  int status = BLKIF_RSP_OKAY;
  struct block_device* bdev = blkif->vbd.bdev;
  unsigned long secure;
  blkif->st_ds_req++;
  xen_blkif_get(blkif);
  secure = (blkif->vbd.discard_secure &&
            (req->u.discard.flag & BLKIF_DISCARD_SECURE))
               ? BLKDEV_DISCARD_SECURE
               : 0;
  err = blkdev_issue_discard(bdev, req->u.discard.sector_number,
                             req->u.discard.nr_sectors, GFP_KERNEL, secure);
  if (err == -EOPNOTSUPP) {
    pr_debug(DRV_PFX "discard op failed, not supported\n");
    status = BLKIF_RSP_EOPNOTSUPP;
  } else if (err)
    status = BLKIF_RSP_ERROR;
  make_response(blkif, req->u.discard.id, req->operation, status);
  xen_blkif_put(blkif);
  return err;
}

static int rndis_set_response(USBNetState* s, rndis_set_msg_type* buf,
                              unsigned int length) {
  rndis_set_cmplt_type* resp =
      rndis_queue_response(s, sizeof(rndis_set_cmplt_type));
  uint32_t bufoffs, buflen;
  int ret;
  if (!resp) return USB_RET_STALL;
  bufoffs = le32_to_cpu(buf->InformationBufferOffset) + 8;
  buflen = le32_to_cpu(buf->InformationBufferLength);
  if (bufoffs + buflen > length) return USB_RET_STALL;
  ret = ndis_set(s, le32_to_cpu(buf->OID), bufoffs + (uint8_t*)buf, buflen);
  resp->MessageLength = cpu_to_le32(sizeof(rndis_set_cmplt_type));
  if (ret < 0) {
    resp->Status = cpu_to_le32(RNDIS_STATUS_NOT_SUPPORTED);
    return 0;
  }
  resp->Status = cpu_to_le32(RNDIS_STATUS_SUCCESS);
  return 0;
}

UrlQuery::UrlQuery(const std::string& encoded_str) {
  if (!encoded_str.empty()) {
    for (std::size_t i = 0; i != std::string::npos;) {
      std::size_t j = encoded_str.find_first_of('&', i);
      std::string kv;
      if (j == std::string::npos) {
        kv = encoded_str.substr(i);
        i = std::string::npos;
      } else {
        kv = encoded_str.substr(i, j - i);
        i = j + 1;
      }
      string_view key;
      string_view value;
      if (SplitKV(kv, '=', false, &key, &value)) {
        parameters_.push_back({DecodeUnsafe(key), DecodeUnsafe(value)});
      }
    }
  }
}

Result ZipFile::uncompressEntry(int index, const File& targetDirectory,
                                bool shouldOverwriteFiles) {
  auto* zei = entries.getUnchecked(index);
#if JUCE_WINDOWS
  auto entryPath = zei->entry.filename;
#else
  auto entryPath = zei->entry.filename.replaceCharacter('\\', '/');
#endif
  if (entryPath.isEmpty()) return Result::ok();
  auto targetFile = targetDirectory.getChildFile(entryPath);
  if (entryPath.endsWithChar('/') || entryPath.endsWithChar('\\'))
    return targetFile.createDirectory();
  std::unique_ptr<InputStream> in(createStreamForEntry(index));
  if (in == nullptr)
    return Result::fail("Failed to open the zip file for reading");
  if (targetFile.exists()) {
    if (!shouldOverwriteFiles) return Result::ok();
    if (!targetFile.deleteFile())
      return Result::fail("Failed to write to target file: " +
                          targetFile.getFullPathName());
  }
  if (!targetFile.getParentDirectory().createDirectory())
    return Result::fail("Failed to create target folder: " +
                        targetFile.getParentDirectory().getFullPathName());
  if (zei->entry.isSymbolicLink) {
    String originalFilePath(in->readEntireStreamAsString().replaceCharacter(
        L'/', File::getSeparatorChar()));
    if (!File::createSymbolicLink(targetFile, originalFilePath, true))
      return Result::fail("Failed to create symbolic link: " +
                          originalFilePath);
  } else {
    FileOutputStream out(targetFile);
    if (out.failedToOpen())
      return Result::fail("Failed to write to target file: " +
                          targetFile.getFullPathName());
    out << *in;
  }
  targetFile.setCreationTime(zei->entry.fileTime);
  targetFile.setLastModificationTime(zei->entry.fileTime);
  targetFile.setLastAccessTime(zei->entry.fileTime);
  return Result::ok();
}

void cipso_v4_sock_delattr(struct sock* sk) {
  int hdr_delta;
  struct ip_options* opt;
  struct inet_sock* sk_inet;
  sk_inet = inet_sk(sk);
  opt = sk_inet->opt;
  if (opt == NULL || opt->cipso == 0) return;
  hdr_delta = cipso_v4_delopt(&sk_inet->opt);
  if (sk_inet->is_icsk && hdr_delta > 0) {
    struct inet_connection_sock* sk_conn = inet_csk(sk);
    sk_conn->icsk_ext_hdr_len -= hdr_delta;
    sk_conn->icsk_sync_mss(sk, sk_conn->icsk_pmtu_cookie);
  }
}

decodeJsonStructure(void* dst, const UA_DataType* type, CtxJson* ctx,
                    ParseCtx* parseCtx, UA_Boolean moveToken) {
  (void)moveToken;
  if (ctx->depth > UA_JSON_ENCODING_MAX_RECURSION)
    return UA_STATUSCODE_BADENCODINGERROR;
  ctx->depth++;
  uintptr_t ptr = (uintptr_t)dst;
  status ret = UA_STATUSCODE_GOOD;
  u8 membersSize = type->membersSize;
  const UA_DataType* typelists[2] = {UA_TYPES, &type[-type->typeIndex]};
  UA_STACKARRAY(DecodeEntry, entries, membersSize);
  for (size_t i = 0; i < membersSize && ret == UA_STATUSCODE_GOOD; ++i) {
    const UA_DataTypeMember* m = &type->members[i];
    const UA_DataType* mt = &typelists[!m->namespaceZero][m->memberTypeIndex];
    entries[i].type = mt;
    if (!m->isArray) {
      ptr += m->padding;
      entries[i].fieldName = m->memberName;
      entries[i].fieldPointer = (void*)ptr;
      entries[i].function = decodeJsonJumpTable[mt->typeKind];
      entries[i].found = false;
      ptr += mt->memSize;
    } else {
      ptr += m->padding;
      ptr += sizeof(size_t);
      entries[i].fieldName = m->memberName;
      entries[i].fieldPointer = (void*)ptr;
      entries[i].function = (decodeJsonSignature)Array_decodeJson;
      entries[i].found = false;
      ptr += sizeof(void*);
    }
  }
  ret = decodeFields(ctx, parseCtx, entries, membersSize, type);
  ctx->depth--;
  return ret;
}

