static void check_pointer_type_change(Notifier* notifier, void* data) {
  VncState* vs = container_of(notifier, VncState, mouse_mode_notifier);
  int absolute = qemu_input_is_absolute();
  if (vnc_has_feature(vs, VNC_FEATURE_POINTER_TYPE_CHANGE) &&
      vs->absolute != absolute) {
    vnc_write_u8(vs, 0);
    vnc_write_u16(vs, 1);
    vnc_framebuffer_update(vs, absolute, 0, surface_width(vs->vd->ds),
                           surface_height(vs->vd->ds),
                           VNC_ENCODING_POINTER_TYPE_CHANGE);
    vnc_unlock_output(vs);
    vnc_flush(vs);
    vnc_unlock_output(vs);
    vnc_flush(vs);
  }
  vs->absolute = absolute;
}

static int spawn_https_helper_openssl(const char* host, unsigned port) {
  char* allocated = NULL;
  char* servername;
  int sp[2];
  int pid;
  IF_FEATURE_WGET_HTTPS(volatile int child_failed = 0;)
  if (socketpair(AF_UNIX, SOCK_STREAM, 0, sp) != 0)
    bb_simple_perror_msg_and_die("socketpair");
  if (!strchr(host, ':')) host = allocated = xasprintf("%s:%u", host, port);
  servername = xstrdup(host);
  strrchr(servername, ':')[0] = '\0';
  fflush_all();
  pid = xvfork();
  if (pid == 0) {
    char* argv[8];
    close(sp[0]);
    xmove_fd(sp[1], 0);
    xdup2(0, 1);
    xmove_fd(2, 3);
    xopen("/dev/null", O_RDWR);
    memset(&argv, 0, sizeof(argv));
    argv[0] = (char*)"openssl";
    argv[1] = (char*)"s_client";
    argv[2] = (char*)"-quiet";
    argv[3] = (char*)"-connect";
    argv[4] = (char*)host;
    if (!is_ip_address(servername)) {
      argv[5] = (char*)"-servername";
      argv[6] = (char*)servername;
    }
    BB_EXECVP(argv[0], argv);
    xmove_fd(3, 2);
#if ENABLE_FEATURE_WGET_HTTPS
    child_failed = 1;
    xfunc_die();
#else
    bb_perror_msg_and_die("can't execute '%s'", argv[0]);
#endif
  }
  free(servername);
  free(allocated);
  close(sp[1]);
#if ENABLE_FEATURE_WGET_HTTPS
  if (child_failed) {
    close(sp[0]);
    return -1;
  }
#endif
  return sp[0];
}

static int __feat_register_sp(struct list_head* fn, u8 feat, u8 is_local,
                              u8 mandatory, u8 const* sp_val, u8 sp_len) {
  dccp_feat_val fval;
  if (dccp_feat_type(feat) != FEAT_SP ||
      !dccp_feat_sp_list_ok(feat, sp_val, sp_len))
    return -EINVAL;
  if (feat == DCCPF_CCID && !ccid_support_check(sp_val, sp_len))
    return -EOPNOTSUPP;
  if (dccp_feat_clone_sp_val(&fval, sp_val, sp_len)) return -ENOMEM;
  return dccp_feat_push_change(fn, feat, is_local, mandatory, &fval);
}

static __net_init int setup_net(struct net* net,
                                struct user_namespace* user_ns) {
  const struct pernet_operations *ops, *saved_ops;
  int error = 0;
  LIST_HEAD(net_exit_list);
  refcount_set(&net->count, 1);
  refcount_set(&net->passive, 1);
  net->dev_base_seq = 1;
  net->user_ns = user_ns;
  idr_init(&net->netns_ids);
  spin_lock_init(&net->nsid_lock);
  mutex_init(&net->ipv4.ra_mutex);
  list_for_each_entry(ops, &pernet_list, list) {
    error = ops_init(ops, net);
    if (error < 0) goto out_undo;
  }
  down_write(&net_rwsem);
  list_add_tail_rcu(&net->list, &net_namespace_list);
  up_write(&net_rwsem);
out:
  return error;
out_undo:
  list_add(&net->exit_list, &net_exit_list);
  saved_ops = ops;
  list_for_each_entry_continue_reverse(ops, &pernet_list, list)
      ops_exit_list(ops, &net_exit_list);
  ops = saved_ops;
  list_for_each_entry_continue_reverse(ops, &pernet_list, list)
      ops_free_list(ops, &net_exit_list);
  rcu_barrier();
  goto out;
}

int _mkp_stage_30(struct plugin* p, struct client_session* cs,
                  struct session_request* sr) {
  mk_ptr_t referer;
  (void)p;
  (void)cs;
  PLUGIN_TRACE("[FD %i] Mandril validating URL", cs->socket);
  if (mk_security_check_url(sr->uri) < 0) {
    PLUGIN_TRACE("[FD %i] Close connection, blocked URL", cs->socket);
    mk_api->header_set_http_status(sr, MK_CLIENT_FORBIDDEN);
    return MK_PLUGIN_RET_CLOSE_CONX;
  }
  PLUGIN_TRACE("[FD %d] Mandril validating hotlinking", cs->socket);
  referer = mk_api->header_get(&sr->headers_toc, "Referer", strlen("Referer"));
  if (mk_security_check_hotlink(sr->uri_processed, sr->host, referer) < 0) {
    PLUGIN_TRACE("[FD %i] Close connection, deny hotlinking.", cs->socket);
    mk_api->header_set_http_status(sr, MK_CLIENT_FORBIDDEN);
    return MK_PLUGIN_RET_CLOSE_CONX;
  }
  return MK_PLUGIN_RET_NOT_ME;
}

static int rtl8xxxu_submit_int_urb(struct ieee80211_hw* hw) {
  struct rtl8xxxu_priv* priv = hw->priv;
  struct urb* urb;
  u32 val32;
  int ret;
  urb = usb_alloc_urb(0, GFP_KERNEL);
  if (!urb) return -ENOMEM;
  usb_fill_int_urb(urb, priv->udev, priv->pipe_interrupt, priv->int_buf,
                   USB_INTR_CONTENT_LENGTH, rtl8xxxu_int_complete, priv, 1);
  usb_anchor_urb(urb, &priv->int_anchor);
  ret = usb_submit_urb(urb, GFP_KERNEL);
  if (ret) {
    usb_unanchor_urb(urb);
    goto error;
  }
  val32 = rtl8xxxu_read32(priv, REG_USB_HIMR);
  val32 |= USB_HIMR_CPWM;
  rtl8xxxu_write32(priv, REG_USB_HIMR, val32);
error:
  return ret;
}

void RenderWidgetHostImpl::DidNavigate(uint32_t next_source_id) {
  current_content_source_id_ = next_source_id;
  did_receive_first_frame_after_navigation_ = false;
  if (enable_surface_synchronization_) {
    visual_properties_ack_pending_ = false;
    viz::LocalSurfaceId old_surface_id = view_->GetLocalSurfaceId();
    if (view_) view_->DidNavigate();
    viz::LocalSurfaceId new_surface_id = view_->GetLocalSurfaceId();
    if (old_surface_id == new_surface_id) return;
  } else {
    if (last_received_content_source_id_ >= current_content_source_id_) return;
  }
  if (!new_content_rendering_timeout_) return;
  new_content_rendering_timeout_->Start(new_content_rendering_delay_);
}

static void run(int argc, const char* const argv[], const char* name,
                void (*init)(const char* const argv[])) {
  int rv;
  bool user_config;
  const char *argv_out[argc + 4], *new_argv[argc + 4];
  int argc_out;
  char conf_file[OGS_MAX_FILEPATH_LEN];
  user_config = false;
  for (argc_out = 0; argc_out < argc; argc_out++) {
    if (strcmp("-c", argv[argc_out]) == 0) {
      user_config = true;
    }
    argv_out[argc_out] = argv[argc_out];
  }
  argv_out[argc_out] = NULL;
  if (!user_config) {
    ogs_snprintf(conf_file, sizeof conf_file, "%s%s",
                 MESON_BUILD_ROOT OGS_DIR_SEPARATOR_S
                 "configs" OGS_DIR_SEPARATOR_S,
                 name);
    argv_out[argc_out++] = "-c";
    argv_out[argc_out++] = conf_file;
    argv_out[argc_out] = NULL;
  }
  argv_out[0] = MESON_BUILD_ROOT OGS_DIR_SEPARATOR_S "src" OGS_DIR_SEPARATOR_S
                                                     "open5gs-main";
  rv = abts_main(argc_out, argv_out, new_argv);
  ogs_assert(rv == OGS_OK);
  (*init)(new_argv);
}

void CLASS kodak_65000_load_raw() {
  short buf[256];
  int row, col, len, pred[2], ret, i;
  for (row = 0; row < height; row++) {
#ifdef LIBRAW_LIBRARY_BUILD
    checkCancel();
#endif
    for (col = 0; col < width; col += 256) {
      pred[0] = pred[1] = 0;
      len = MIN(256, width - col);
      ret = kodak_65000_decode(buf, len);
      for (i = 0; i < len; i++)
        if ((RAW(row, col + i) =
                 curve[ret ? buf[i] : (pred[i & 1] += buf[i])]) >>
            12)
          derror();
    }
  }
}

