bool extractPages(const char* srcFileName, const char* destFileName) {
  char pathName[1024];
  GooString* gfileName = new GooString(srcFileName);
  PDFDoc* doc = new PDFDoc(gfileName, NULL, NULL, NULL);
  if (!doc->isOk()) {
    error(errSyntaxError, -1,
          "Could not extract page(s) from damaged file ('{0:s}')", srcFileName);
    return false;
  }
  if (firstPage == 0 && lastPage == 0) {
    firstPage = 1;
    lastPage = doc->getNumPages();
  }
  if (lastPage == 0) lastPage = doc->getNumPages();
  if (firstPage == 0) firstPage = 1;
  if (firstPage != lastPage && strstr(destFileName, "%d") == NULL) {
    error(
        errSyntaxError, -1,
        "'{0:s}' must contain '%%d' if more than one page should be extracted",
        destFileName);
    return false;
  }
  for (int pageNo = firstPage; pageNo <= lastPage; pageNo++) {
    sprintf(pathName, destFileName, pageNo);
    GooString* gpageName = new GooString(pathName);
    int errCode = doc->savePageAs(gpageName, pageNo);
    if (errCode != errNone) {
      delete gpageName;
      delete gfileName;
      return false;
    }
    delete gpageName;
  }
  delete gfileName;
  return true;
}

static Jsi_RC NumberToPrecisionCmd(Jsi_Interp* interp, Jsi_Value* args,
                                   Jsi_Value* _this, Jsi_Value** ret,
                                   Jsi_Func* funcPtr) {
  char buf[100];
  int prec = 0, skip = 0;
  Jsi_Number num;
  Jsi_Value* v;
  ChkStringN(_this, funcPtr, v);
  if (Jsi_GetIntFromValue(interp, Jsi_ValueArrayIndex(interp, args, skip),
                          &prec) != JSI_OK)
    return JSI_ERROR;
  if (prec <= 0) return JSI_ERROR;
  Jsi_GetDoubleFromValue(interp, v, &num);
  snprintf(buf, sizeof(buf), "%.*" JSI_NUMFFMT, prec, num);
  if (num < 0) prec++;
  buf[prec + 1] = 0;
  if (buf[prec] == '.') buf[prec] = 0;
  Jsi_ValueMakeStringDup(interp, ret, buf);
  return JSI_OK;
}

