static int crypto_skcipher_init_tfm(struct crypto_tfm* tfm) {
  struct crypto_skcipher* skcipher = __crypto_skcipher_cast(tfm);
  struct skcipher_alg* alg = crypto_skcipher_alg(skcipher);
  if (tfm->__crt_alg->cra_type == &crypto_blkcipher_type)
    return crypto_init_skcipher_ops_blkcipher(tfm);
  if (tfm->__crt_alg->cra_type == &crypto_ablkcipher_type ||
      tfm->__crt_alg->cra_type == &crypto_givcipher_type)
    return crypto_init_skcipher_ops_ablkcipher(tfm);
  skcipher->setkey = alg->setkey;
  skcipher->encrypt = alg->encrypt;
  skcipher->decrypt = alg->decrypt;
  skcipher->ivsize = alg->ivsize;
  skcipher->keysize = alg->max_keysize;
  if (alg->exit) skcipher->base.exit = crypto_skcipher_exit_tfm;
  if (alg->init) return alg->init(skcipher);
  return 0;
}

static int br_multicast_add_group(struct net_bridge* br,
                                  struct net_bridge_port* port,
                                  struct br_ip* group) {
  struct net_bridge_mdb_entry* mp;
  struct net_bridge_port_group* p;
  struct net_bridge_port_group __rcu** pp;
  unsigned long now = jiffies;
  int err;
  spin_lock(&br->multicast_lock);
  if (!netif_running(br->dev) || (port && port->state == BR_STATE_DISABLED))
    goto out;
  mp = br_multicast_new_group(br, port, group);
  err = PTR_ERR(mp);
  if (IS_ERR(mp)) goto err;
  if (!port) {
    hlist_add_head(&mp->mglist, &br->mglist);
    mod_timer(&mp->timer, now + br->multicast_membership_interval);
    goto out;
  }
  for (pp = &mp->ports; (p = mlock_dereference(*pp, br)) != NULL;
       pp = &p->next) {
    if (p->port == port) goto found;
    if ((unsigned long)p->port < (unsigned long)port) break;
  }
  p = kzalloc(sizeof(*p), GFP_ATOMIC);
  err = -ENOMEM;
  if (unlikely(!p)) goto err;
  p->addr = *group;
  p->port = port;
  p->next = *pp;
  hlist_add_head(&p->mglist, &port->mglist);
  setup_timer(&p->timer, br_multicast_port_group_expired, (unsigned long)p);
  setup_timer(&p->query_timer, br_multicast_port_group_query_expired,
              (unsigned long)p);
  rcu_assign_pointer(*pp, p);
found:
  mod_timer(&p->timer, now + br->multicast_membership_interval);
out:
  err = 0;
err:
  spin_unlock(&br->multicast_lock);
  return err;
}

FileInformation ImageReadJPEG(Image& out, String const& filename) {
  JpegInput jpeg(filename);
  FileInformation info = GetJPEGInfo(jpeg);
  int nchan = jpeg.cinfo().num_components;
  jpeg.cinfo().out_color_space = nchan > 1 ? JCS_RGB : JCS_GRAYSCALE;
  out.ReForge(info.sizes, info.tensorElements, DT_UINT8,
              Option::AcceptDataTypeChange::DONT_ALLOW);
  out.SetPixelSize(info.pixelSize);
  out.SetColorSpace(info.colorSpace);
  jpeg_start_decompress(jpeg.cinfoptr());
  std::vector<JSAMPLE> buffer(info.sizes[0] * static_cast<unsigned>(nchan));
  dip::uint8* imagedata = static_cast<dip::uint8*>(out.Origin());
  auto stride = out.Strides();
  auto tStride = out.TensorStride();
  for (dip::uint ii = 0; ii < info.sizes[1]; ++ii) {
    JSAMPLE* indata = buffer.data();
    jpeg_read_scanlines(jpeg.cinfoptr(), &indata, 1);
    dip::uint8* outdata = imagedata;
    if (nchan > 1) {
      for (dip::uint jj = 0; jj < info.sizes[0]; ++jj) {
        for (int kk = 0; kk < nchan; ++kk) {
          *(outdata + kk * tStride) = *indata;
          ++indata;
        }
        outdata += stride[0];
      }
    } else {
      for (dip::uint jj = 0; jj < info.sizes[0]; ++jj) {
        *outdata = *indata;
        ++indata;
        outdata += stride[0];
      }
    }
    imagedata += stride[1];
  }
  jpeg_finish_decompress(jpeg.cinfoptr());
  return info;
}

ahcp_time_print(netdissect_options* ndo, const u_char* cp, uint8_t len) {
