  ND_TCHECK_LEN(cp, len);
}

int ssh_scp_init(ssh_scp scp) {
  int rc;
  char execbuffer[1024] = {0};
  if (scp == NULL) {
    return SSH_ERROR;
  }
  if (scp->state != SSH_SCP_NEW) {
    ssh_set_error(scp->session, SSH_FATAL,
                  "ssh_scp_init called under invalid state");
    return SSH_ERROR;
  }
  SSH_LOG(SSH_LOG_PROTOCOL, "Initializing scp session %s %son location '%s'",
          scp->mode == SSH_SCP_WRITE ? "write" : "read",
          scp->recursive ? "recursive " : "", scp->location);
  scp->channel = ssh_channel_new(scp->session);
  if (scp->channel == NULL) {
    scp->state = SSH_SCP_ERROR;
    return SSH_ERROR;
  }
  rc = ssh_channel_open_session(scp->channel);
  if (rc == SSH_ERROR) {
    scp->state = SSH_SCP_ERROR;
    return SSH_ERROR;
  }
  if (scp->mode == SSH_SCP_WRITE) {
    snprintf(execbuffer, sizeof(execbuffer), "scp -t %s %s",
             scp->recursive ? "-r" : "", scp->location);
  } else {
    snprintf(execbuffer, sizeof(execbuffer), "scp -f %s %s",
             scp->recursive ? "-r" : "", scp->location);
  }
  if (ssh_channel_request_exec(scp->channel, execbuffer) == SSH_ERROR) {
    scp->state = SSH_SCP_ERROR;
    return SSH_ERROR;
  }
  if (scp->mode == SSH_SCP_WRITE) {
    rc = ssh_scp_response(scp, NULL);
    if (rc != 0) {
      return SSH_ERROR;
    }
  } else {
    ssh_channel_write(scp->channel, "", 1);
  }
  if (scp->mode == SSH_SCP_WRITE) {
    scp->state = SSH_SCP_WRITE_INITED;
  } else {
    scp->state = SSH_SCP_READ_INITED;
  }
  return SSH_OK;
}

static int rtsx_usb_ms_drv_remove(struct platform_device* pdev) {
  struct rtsx_usb_ms* host = platform_get_drvdata(pdev);
  struct memstick_host* msh = host->msh;
  int err;
  host->eject = true;
  cancel_work_sync(&host->handle_req);
  mutex_lock(&host->host_mutex);
  if (host->req) {
    dev_dbg(ms_dev(host), "%s: Controller removed during transfer\n",
            dev_name(&msh->dev));
    host->req->error = -ENOMEDIUM;
    do {
      err = memstick_next_req(msh, &host->req);
      if (!err) host->req->error = -ENOMEDIUM;
    } while (!err);
  }
  mutex_unlock(&host->host_mutex);
  memstick_remove_host(msh);
  memstick_free_host(msh);
  if (pm_runtime_active(ms_dev(host))) pm_runtime_put(ms_dev(host));
  pm_runtime_disable(ms_dev(host));
  platform_set_drvdata(pdev, NULL);
  dev_dbg(ms_dev(host), ": Realtek USB Memstick controller has been removed\n");
  return 0;
}

cr_input_read_byte(CRInput* a_this, guchar* a_byte) {
  g_return_val_if_fail(a_this && PRIVATE(a_this) && a_byte, CR_BAD_PARAM_ERROR);
  g_return_val_if_fail(
      PRIVATE(a_this)->next_byte_index <= PRIVATE(a_this)->nb_bytes,
      CR_BAD_PARAM_ERROR);
  if (PRIVATE(a_this)->end_of_input == TRUE) return CR_END_OF_INPUT_ERROR;
  *a_byte = PRIVATE(a_this)->in_buf[PRIVATE(a_this)->next_byte_index];
  if (PRIVATE(a_this)->nb_bytes - PRIVATE(a_this)->next_byte_index < 2) {
    PRIVATE(a_this)->end_of_input = TRUE;
  } else {
    PRIVATE(a_this)->next_byte_index++;
  }
  return CR_OK;
}

TfLiteStatus EvalGatherNd(TfLiteContext* context, const TfLiteTensor* params,
                          const TfLiteTensor* indices, TfLiteTensor* output) {
  bool indices_has_only_positive_elements = true;
  const auto* indices_values = GetTensorData<IndicesT>(indices);
  const size_t num_indices = indices->bytes / sizeof(IndicesT);
  for (size_t i = 0; i < num_indices; i++) {
    if (indices_values[i] < 0) {
      indices_has_only_positive_elements = false;
      break;
    }
  }
  TF_LITE_ENSURE(context, indices_has_only_positive_elements);
  switch (params->type) {
    case kTfLiteFloat32:
      return GatherNd<float, IndicesT>(params, indices, output);
    case kTfLiteUInt8:
      return GatherNd<uint8_t, IndicesT>(params, indices, output);
    case kTfLiteInt8:
      return GatherNd<int8_t, IndicesT>(params, indices, output);
    case kTfLiteInt16:
      return GatherNd<int16_t, IndicesT>(params, indices, output);
    case kTfLiteInt32:
      return GatherNd<int32_t, IndicesT>(params, indices, output);
    case kTfLiteInt64:
      return GatherNd<int64_t, IndicesT>(params, indices, output);
    case kTfLiteString:
      return GatherNdString<IndicesT>(params, indices, output);
    default:
      TF_LITE_KERNEL_LOG(context,
                         "Params type '%s' are not supported by gather_nd.",
                         TfLiteTypeGetName(params->type));
      return kTfLiteError;
  }
}

