ldbm_config_search_entry_callback(Slapi_PBlock* pb __attribute__((unused)),
                                  Slapi_Entry* e,
                                  Slapi_Entry* entryAfter
                                  __attribute__((unused)),
                                  int* returncode, char* returntext,
                                  void* arg) {
  char buf[BUFSIZ];
  struct berval* vals[2];
  struct berval val;
  struct ldbminfo* li = (struct ldbminfo*)arg;
  config_info* config;
  int scope;
  vals[0] = &val;
  vals[1] = NULL;
  returntext[0] = '\0';
  PR_Lock(li->li_config_mutex);
  if (pb) {
    slapi_pblock_get(pb, SLAPI_SEARCH_SCOPE, &scope);
    if (scope == LDAP_SCOPE_BASE) {
      char** attrs = NULL;
      slapi_pblock_get(pb, SLAPI_SEARCH_ATTRS, &attrs);
      if (attrs) {
        for (size_t i = 0; attrs[i]; i++) {
          if (ldbm_config_moved_attr(attrs[i])) {
            slapi_pblock_set(pb, SLAPI_PB_RESULT_TEXT,
                             "at least one required attribute has been moved "
                             "to the BDB scecific configuration entry");
            break;
          }
        }
      }
    }
  }
  for (config = ldbm_config; config->config_name != NULL; config++) {
    if (!(config->config_flags &
          (CONFIG_FLAG_ALWAYS_SHOW | CONFIG_FLAG_PREVIOUSLY_SET))) {
      continue;
    }
    ldbm_config_get((void*)li, config, buf);
    val.bv_val = buf;
    val.bv_len = strlen(buf);
    slapi_entry_attr_replace(e, config->config_name, vals);
  }
  PR_Unlock(li->li_config_mutex);
  *returncode = LDAP_SUCCESS;
  return SLAPI_DSE_CALLBACK_OK;
}

static int cxusb_ctrl_msg(struct dvb_usb_device* d, u8 cmd, u8* wbuf, int wlen,
                          u8* rbuf, int rlen) {
  struct cxusb_state* st = d->priv;
  int ret, wo;
  if (1 + wlen > MAX_XFER_SIZE) {
    warn("i2c wr: len=%d is too big!\n", wlen);
    return -EOPNOTSUPP;
  }
  wo = (rbuf == NULL || rlen == 0);
  mutex_lock(&d->data_mutex);
  st->data[0] = cmd;
  memcpy(&st->data[1], wbuf, wlen);
  if (wo)
    ret = dvb_usb_generic_write(d, st->data, 1 + wlen);
  else
    ret = dvb_usb_generic_rw(d, st->data, 1 + wlen, rbuf, rlen, 0);
  mutex_unlock(&d->data_mutex);
  return ret;
}

jbig2_decode_gray_scale_image(Jbig2Ctx* ctx, Jbig2Segment* segment,
                              const byte* data, const size_t size, bool GSMMR,
                              uint32_t GSW, uint32_t GSH, uint32_t GSBPP,
                              bool GSUSESKIP, Jbig2Image* GSKIP, int GSTEMPLATE,
                              Jbig2ArithCx* GB_stats) {
  uint8_t** GSVALS = NULL;
  size_t consumed_bytes = 0;
  int i, j, code, stride;
  int x, y;
  Jbig2Image** GSPLANES;
  Jbig2GenericRegionParams rparams;
  Jbig2WordStream* ws = NULL;
  Jbig2ArithState* as = NULL;
  GSPLANES = jbig2_new(ctx, Jbig2Image*, GSBPP);
  if (GSPLANES == NULL) {
    jbig2_error(ctx, JBIG2_SEVERITY_FATAL, segment->number,
                "failed to allocate %d bytes for GSPLANES", GSBPP);
    return NULL;
  }
  for (i = 0; i < GSBPP; ++i) {
    GSPLANES[i] = jbig2_image_new(ctx, GSW, GSH);
    if (GSPLANES[i] == NULL) {
      jbig2_error(ctx, JBIG2_SEVERITY_FATAL, segment->number,
                  "failed to allocate %dx%d image for GSPLANES", GSW, GSH);
      for (j = i - 1; j >= 0; --j) {
        jbig2_image_release(ctx, GSPLANES[j]);
      }
      jbig2_free(ctx->allocator, GSPLANES);
      return NULL;
    }
  }
}

