linkaddr_string(netdissect_options* ndo, const u_char* ep,
                const unsigned int type, const unsigned int len) {
  register u_int i;
  register char* cp;
  register struct enamemem* tp;
  if (len == 0) return ("<empty>");
  if (type == LINKADDR_ETHER && len == ETHER_ADDR_LEN)
    return (etheraddr_string(ndo, ep));
  if (type == LINKADDR_FRELAY) return (q922_string(ndo, ep, len));
  tp = lookup_bytestring(ndo, ep, len);
  if (tp->e_name) return (tp->e_name);
  tp->e_name = cp = (char*)malloc(len * 3);
  if (tp->e_name == NULL) (*ndo->ndo_error)(ndo, "linkaddr_string: malloc");
  *cp++ = hex[*ep >> 4];
  *cp++ = hex[*ep++ & 0xf];
  for (i = len - 1; i > 0; --i) {
    *cp++ = ':';
    *cp++ = hex[*ep >> 4];
    *cp++ = hex[*ep++ & 0xf];
  }
  *cp = '\0';
  return (tp->e_name);
}

static int getStrrtokenPos(char* str, int savedPos) {
  int result = -1;
  int i;
  for (i = savedPos - 1; i >= 0; i--) {
    if (isIDSeparator(*(str + i))) {
      if (i >= 2 && isIDSeparator(*(str + i - 2))) {
        result = i - 2;
      } else {
        result = i;
      }
      break;
    }
  }
  if (result < 1) {
    result = -1;
  }
  return result;
}

static UINT printer_process_irp_write(PRINTER_DEVICE* printer_dev, IRP* irp) {
  UINT32 Length;
  UINT64 Offset;
  rdpPrintJob* printjob = NULL;
  UINT error = CHANNEL_RC_OK;
  Stream_Read_UINT32(irp->input, Length);
  Stream_Read_UINT64(irp->input, Offset);
  Stream_Seek(irp->input, 20);
  if (printer_dev->printer)
    printjob =
        printer_dev->printer->FindPrintJob(printer_dev->printer, irp->FileId);
  if (!printjob) {
    irp->IoStatus = STATUS_UNSUCCESSFUL;
    Length = 0;
  } else {
    error = printjob->Write(printjob, Stream_Pointer(irp->input), Length);
  }
  if (error) {
    WLog_ERR(TAG, "printjob->Write failed with error %" PRIu32 "!", error);
    return error;
  }
  Stream_Write_UINT32(irp->output, Length);
  Stream_Write_UINT8(irp->output, 0);
  return irp->Complete(irp);
}

smb2_flush(smb_request_t* sr) {
  smb_ofile_t* of = NULL;
  uint16_t StructSize;
  uint16_t reserved1;
  uint32_t reserved2;
  smb2fid_t smb2fid;
  uint32_t status;
  int rc = 0;
  rc = smb_mbc_decodef(&sr->smb_data, "wwlqq", &StructSize, &reserved1,
                       &reserved2, &smb2fid.persistent, &smb2fid.temporal);
  if (rc) return (SDRC_ERROR);
  if (StructSize != 24) return (SDRC_ERROR);
  status = smb2sr_lookup_fid(sr, &smb2fid);
  if (status) {
    smb2sr_put_error(sr, status);
    return (SDRC_SUCCESS);
  }
  of = sr->fid_ofile;
  if ((of->f_node->flags & NODE_FLAGS_WRITE_THROUGH) == 0)
    (void)smb_fsop_commit(sr, of->f_cr, of->f_node);
  (void)smb_mbc_encodef(&sr->reply, "wwl", 4, 0);
  return (SDRC_SUCCESS);
}

size_t olm_pk_decrypt(OlmPkDecryption* decryption, void const* ephemeral_key,
                      size_t ephemeral_key_length, void const* mac,
                      size_t mac_length, void* ciphertext,
                      size_t ciphertext_length, void* plaintext,
                      size_t max_plaintext_length) {
  if (max_plaintext_length <
      olm_pk_max_plaintext_length(decryption, ciphertext_length)) {
    decryption->last_error = OlmErrorCode::OLM_OUTPUT_BUFFER_TOO_SMALL;
    return std::size_t(-1);
  }
  struct _olm_curve25519_public_key ephemeral;
  olm::decode_base64((const uint8_t*)ephemeral_key, ephemeral_key_length,
                     (uint8_t*)ephemeral.public_key);
  olm::SharedKey secret;
  _olm_crypto_curve25519_shared_secret(&decryption->key_pair, &ephemeral,
                                       secret);
  uint8_t raw_mac[MAC_LENGTH];
  olm::decode_base64((const uint8_t*)mac, olm::encode_base64_length(MAC_LENGTH),
                     raw_mac);
  size_t raw_ciphertext_length = olm::decode_base64_length(ciphertext_length);
  olm::decode_base64((const uint8_t*)ciphertext, ciphertext_length,
                     (uint8_t*)ciphertext);
  size_t result = _olm_cipher_aes_sha_256_ops.decrypt(
      olm_pk_cipher, secret, sizeof(secret), (uint8_t*)raw_mac, MAC_LENGTH,
      (const uint8_t*)ciphertext, raw_ciphertext_length, (uint8_t*)plaintext,
      max_plaintext_length);
  if (result == std::size_t(-1)) {
    decryption->last_error = OlmErrorCode::OLM_BAD_MESSAGE_MAC;
    return std::size_t(-1);
  } else {
    return result;
  }
}

static int pfkey_register(struct sock* sk, struct sk_buff* skb,
                          const struct sadb_msg* hdr, void* const* ext_hdrs) {
  struct pfkey_sock* pfk = pfkey_sk(sk);
  struct sk_buff* supp_skb;
  if (hdr->sadb_msg_satype > SADB_SATYPE_MAX) return -EINVAL;
  if (hdr->sadb_msg_satype != SADB_SATYPE_UNSPEC) {
    if (pfk->registered & (1 << hdr->sadb_msg_satype)) return -EEXIST;
    pfk->registered |= (1 << hdr->sadb_msg_satype);
  }
  xfrm_probe_algs();
  supp_skb = compose_sadb_supported(hdr, GFP_KERNEL | __GFP_ZERO);
  if (!supp_skb) {
    if (hdr->sadb_msg_satype != SADB_SATYPE_UNSPEC)
      pfk->registered &= ~(1 << hdr->sadb_msg_satype);
    return -ENOBUFS;
  }
  pfkey_broadcast(supp_skb, GFP_KERNEL, BROADCAST_REGISTERED, sk, sock_net(sk));
  return 0;
}

handle_keywordonly_args(struct compiling* c, const node* n, int start,
                        asdl_seq* kwonlyargs, asdl_seq* kwdefaults) {
  PyObject* argname;
  node* ch;
  expr_ty expression, annotation;
  arg_ty arg;
  int i = start;
  int j = 0;
  if (kwonlyargs == NULL) {
    ast_error(c, CHILD(n, start), "named arguments must follow bare *");
    return -1;
  }
  assert(kwdefaults != NULL);
  while (i < NCH(n)) {
    ch = CHILD(n, i);
    switch (TYPE(ch)) {
      case vfpdef:
      case tfpdef:
        if (i + 1 < NCH(n) && TYPE(CHILD(n, i + 1)) == EQUAL) {
          expression = ast_for_expr(c, CHILD(n, i + 2));
          if (!expression) goto error;
          asdl_seq_SET(kwdefaults, j, expression);
          i += 2;
        } else {
          asdl_seq_SET(kwdefaults, j, NULL);
        }
        if (NCH(ch) == 3) {
          annotation = ast_for_expr(c, CHILD(ch, 2));
          if (!annotation) goto error;
        } else {
          annotation = NULL;
        }
        ch = CHILD(ch, 0);
        argname = NEW_IDENTIFIER(ch);
        if (!argname) goto error;
        if (forbidden_name(c, argname, ch, 0)) goto error;
        arg = arg(argname, annotation, NULL, LINENO(ch), ch->n_col_offset,
                  c->c_arena);
        if (!arg) goto error;
        asdl_seq_SET(kwonlyargs, j++, arg);
        i += 1;
        if (i < NCH(n) && TYPE(CHILD(n, i)) == COMMA) i += 1;
        break;
      case TYPE_COMMENT:
        arg->type_comment = NEW_TYPE_COMMENT(ch);
        i += 1;
        break;
      case DOUBLESTAR:
        return i;
      default:
        ast_error(c, ch, "unexpected node");
        goto error;
    }
  }
  return i;
error:
  return -1;
}

void iwjson_ftoa(long double val, char buf[static IWNUMBUF_SIZE],
                 size_t* out_len) {
  int len = snprintf(buf, 64, "%.8Lf", val);
  if (len <= 0) {
    buf[0] = '\0';
    *out_len = 0;
    return;
  }
  while (len > 0 && buf[len - 1] == '0') {
    buf[len - 1] = '\0';
    len--;
  }
  if ((len > 0) && (buf[len - 1] == '.')) {
    buf[len - 1] = '\0';
    len--;
  }
  *out_len = (size_t)len;
}

static int snd_timer_user_open(struct inode* inode, struct file* file) {
  struct snd_timer_user* tu;
  int err;
  err = nonseekable_open(inode, file);
  if (err < 0) return err;
  tu = kzalloc(sizeof(*tu), GFP_KERNEL);
  if (tu == NULL) return -ENOMEM;
  spin_lock_init(&tu->qlock);
  init_waitqueue_head(&tu->qchange_sleep);
  mutex_init(&tu->tread_sem);
  tu->ticks = 1;
  tu->queue_size = 128;
  tu->queue =
      kmalloc(tu->queue_size * sizeof(struct snd_timer_read), GFP_KERNEL);
  if (tu->queue == NULL) {
    kfree(tu);
    return -ENOMEM;
  }
  file->private_data = tu;
  return 0;
}

