                     dev->bid_type ? dev->bid_type : "(null)"));
  fprintf(file, "<device DEVNO=\"0x%04lx\" TIME=\"%ld.%ld\"",
          (unsigned long)dev->bid_devno, (long)dev->bid_time,
          (long)dev->bid_utime);
