void TileManager::crop(RawTile* ttt) {
  int tw = image->getTileWidth();
  int th = image->getTileHeight();
  if (loglevel >= 5) {
    *logfile << "TileManager :: Edge tile: Base size: " << tw << "x" << th
             << ": This tile: " << ttt->width << "x" << ttt->height << endl;
  }
  int len = tw * th * ttt->channels * (ttt->bpc / 8);
  unsigned char* buffer = (unsigned char*)malloc(len);
  unsigned char* src_ptr = (unsigned char*)memcpy(buffer, ttt->data, len);
  unsigned char* dst_ptr = (unsigned char*)ttt->data;
  len = ttt->width * ttt->channels * (ttt->bpc / 8);
  for (unsigned int i = 0; i < ttt->height; i++) {
    memcpy(dst_ptr, src_ptr, len);
    dst_ptr += len;
    src_ptr += tw * ttt->channels * (ttt->bpc / 8);
  }
  free(buffer);
  len = ttt->width * ttt->height * ttt->channels * (ttt->bpc / 8);
  ttt->dataLength = len;
  ttt->padded = false;
}

void jas_matrix_clip(jas_matrix_t* matrix, jas_seqent_t minval,
                     jas_seqent_t maxval) {
  int i;
  int j;
  jas_seqent_t v;
  jas_seqent_t* rowstart;
  jas_seqent_t* data;
  int rowstep;
  rowstep = jas_matrix_rowstep(matrix);
  for (i = matrix->numrows_, rowstart = matrix->rows_[0]; i > 0;
       --i, rowstart += rowstep) {
    data = rowstart;
    for (j = matrix->numcols_, data = rowstart; j > 0; --j, ++data) {
      v = *data;
      if (v < minval) {
        *data = minval;
      } else if (v > maxval) {
        *data = maxval;
      }
    }
  }
}

int flush_completed_IO(struct inode* inode) {
  ext4_io_end_t* io;
