}

static int gup_pte_range(pmd_t pmd, unsigned long addr, unsigned long end,
                         int write, struct page** pages, int* nr) {
  struct dev_pagemap* pgmap = NULL;
  int nr_start = *nr, ret = 0;
  pte_t *ptep, *ptem;
  ptem = ptep = pte_offset_map(&pmd, addr);
  do {
    pte_t pte = gup_get_pte(ptep);
    struct page *head, *page;
    if (pte_protnone(pte)) goto pte_unmap;
    if (!pte_access_permitted(pte, write)) goto pte_unmap;
    if (pte_devmap(pte)) {
      pgmap = get_dev_pagemap(pte_pfn(pte), pgmap);
      if (unlikely(!pgmap)) {
        undo_dev_pagemap(nr, nr_start, pages);
        goto pte_unmap;
      }
    } else if (pte_special(pte))
      goto pte_unmap;
    VM_BUG_ON(!pfn_valid(pte_pfn(pte)));
    page = pte_page(pte);
    head = compound_head(page);
    if (!page_cache_get_speculative(head)) goto pte_unmap;
    if (unlikely(pte_val(pte) != pte_val(*ptep))) {
      put_page(head);
      goto pte_unmap;
    }
    VM_BUG_ON_PAGE(compound_head(page) != head, page);
    SetPageReferenced(page);
    pages[*nr] = page;
    (*nr)++;
  } while (ptep++, addr += PAGE_SIZE, addr != end);
  ret = 1;
pte_unmap:
  if (pgmap) put_dev_pagemap(pgmap);
  pte_unmap(ptem);
  return ret;
}

add_header_value(VALUE hh, const char* key, int klen, const char* val,
                 int vlen) {
  if (sizeof(content_type) - 1 == klen &&
      0 == strncasecmp(key, content_type, sizeof(content_type) - 1)) {
    rb_hash_aset(hh, content_type_val, rb_str_new(val, vlen));
  } else if (sizeof(content_length) - 1 == klen &&
             0 ==
                 strncasecmp(key, content_length, sizeof(content_length) - 1)) {
    rb_hash_aset(hh, content_length_val, rb_str_new(val, vlen));
  } else {
    char hkey[1024];
    char* k = hkey;
    volatile VALUE sval = rb_str_new(val, vlen);
    strcpy(hkey, "HTTP_");
    k = hkey + 5;
    if ((int)(sizeof(hkey) - 5) <= klen) {
      klen = sizeof(hkey) - 6;
    }
    strncpy(k, key, klen);
    hkey[klen + 5] = '\0';
    for (k = hkey + 5; '\0' != *k; k++) {
      if ('-' == *k) {
        *k = '_';
      } else {
        *k = toupper(*k);
      }
    }
    rb_hash_aset(hh, rb_str_new(hkey, klen + 5), sval);
  }
}

TRIO_PUBLIC trio_pointer_t trio_register TRIO_ARGS2((callback, name),
                                                    trio_callback_t callback,
                                                    TRIO_CONST char* name) {
  trio_userdef_t* def;
  trio_userdef_t* prev = NULL;
  if (callback == NULL) return NULL;
  if (name) {
    if (name[0] == ':') {
      if (trio_equal(name, ":enter")) {
        internalEnterCriticalRegion = callback;
      } else if (trio_equal(name, ":leave")) {
        internalLeaveCriticalRegion = callback;
      }
      return NULL;
    }
    if (trio_length(name) >= MAX_USER_NAME) return NULL;
    def = TrioFindNamespace(name, &prev);
    if (def) return NULL;
  }
  def = (trio_userdef_t*)TRIO_MALLOC(sizeof(trio_userdef_t));
  if (def) {
    if (internalEnterCriticalRegion) (void)internalEnterCriticalRegion(NULL);
    if (name) {
      if (prev == NULL)
        internalUserDef = def;
      else
        prev->next = def;
    }
    def->callback = callback;
    def->name = (name == NULL) ? NULL : trio_duplicate(name);
    def->next = NULL;
    if (internalLeaveCriticalRegion) (void)internalLeaveCriticalRegion(NULL);
  }
  return (trio_pointer_t)def;
}

static inline int ip_ufo_append_data(struct sock* sk,
                                     struct sk_buff_head* queue,
                                     int getfrag(void* from, char* to,
                                                 int offset, int len, int odd,
                                                 struct sk_buff* skb),
                                     void* from, int length, int hh_len,
                                     int fragheaderlen, int transhdrlen,
                                     int maxfraglen, unsigned int flags) {
  struct sk_buff* skb;
  int err;
  if ((skb = skb_peek_tail(queue)) == NULL) {
    skb = sock_alloc_send_skb(sk, hh_len + fragheaderlen + transhdrlen + 20,
                              (flags & MSG_DONTWAIT), &err);
    if (skb == NULL) return err;
    skb_reserve(skb, hh_len);
    skb_put(skb, fragheaderlen + transhdrlen);
    skb_reset_network_header(skb);
    skb->transport_header = skb->network_header + fragheaderlen;
    skb->ip_summed = CHECKSUM_PARTIAL;
    skb->csum = 0;
    skb_shinfo(skb)->gso_size = maxfraglen - fragheaderlen;
    skb_shinfo(skb)->gso_type = SKB_GSO_UDP;
    __skb_queue_tail(queue, skb);
  }
  return skb_append_datato_frags(sk, skb, getfrag, from,
                                 (length - transhdrlen));
}

evbuffer_add(struct evbuffer* buf, const void* data, size_t datlen) {
  size_t need = buf->misalign + buf->off + datlen;
  size_t oldoff = buf->off;
  if (buf->totallen < need) {
    if (evbuffer_expand(buf, datlen) == -1) return (-1);
  }
  memcpy(buf->buffer + buf->off, data, datlen);
  buf->off += datlen;
  if (datlen && buf->cb != NULL) (*buf->cb)(buf, oldoff, buf->off, buf->cbarg);
  return (0);
}

static int hexagon_v6_op(RAnal* anal, RAnalOp* op, ut64 addr, const ut8* buf,
                         int len, RAnalOpMask mask) {
  HexInsn hi = {0};
  ;
  ut32 data = 0;
  data = r_read_le32(buf);
  int size = hexagon_disasm_instruction(data, &hi, (ut32)addr);
  op->size = size;
  if (size <= 0) {
    return size;
  }
  op->addr = addr;
  return hexagon_anal_instruction(&hi, op);
}

static int gup_huge_pud(pud_t orig, pud_t* pudp, unsigned long addr,
                        unsigned long end, int write, struct page** pages,
                        int* nr) {
  struct page *head, *page;
  int refs;
  if (!pud_access_permitted(orig, write)) return 0;
  if (pud_devmap(orig))
    return __gup_device_huge_pud(orig, pudp, addr, end, pages, nr);
  refs = 0;
  page = pud_page(orig) + ((addr & ~PUD_MASK) >> PAGE_SHIFT);
  do {
    pages[*nr] = page;
    (*nr)++;
    page++;
    refs++;
  } while (addr += PAGE_SIZE, addr != end);
  head = compound_head(pud_page(orig));
  if (!page_cache_add_speculative(head, refs)) {
    *nr -= refs;
    return 0;
  }
  if (unlikely(pud_val(orig) != pud_val(*pudp))) {
    *nr -= refs;
    while (refs--) put_page(head);
    return 0;
  }
  SetPageReferenced(head);
  return 1;
}

