int blkcg_init_queue(struct request_queue* q) {
  struct blkcg_gq *new_blkg, *blkg;
  bool preloaded;
  int ret;
  new_blkg = blkg_alloc(&blkcg_root, q, GFP_KERNEL);
  if (!new_blkg) return -ENOMEM;
  preloaded = !radix_tree_preload(GFP_KERNEL);
  rcu_read_lock();
  spin_lock_irq(q->queue_lock);
  blkg = blkg_create(&blkcg_root, q, new_blkg);
  spin_unlock_irq(q->queue_lock);
  rcu_read_unlock();
  if (preloaded) radix_tree_preload_end();
  if (IS_ERR(blkg)) {
    blkg_free(new_blkg);
    return PTR_ERR(blkg);
  }
  q->root_blkg = blkg;
  q->root_rl.blkg = blkg;
  ret = blk_throtl_init(q);
  if (ret) {
    spin_lock_irq(q->queue_lock);
    blkg_destroy_all(q);
    spin_unlock_irq(q->queue_lock);
  }
  return ret;
}

int fcntl_dirnotify(int fd, struct file* filp, unsigned long arg) {
  struct dnotify_struct* dn;
  struct dnotify_struct* odn;
  struct dnotify_struct** prev;
  struct inode* inode;
  fl_owner_t id = current->files;
  int error = 0;
  if ((arg & ~DN_MULTISHOT) == 0) {
    dnotify_flush(filp, id);
    return 0;
  }
  if (!dir_notify_enable) return -EINVAL;
  inode = filp->f_path.dentry->d_inode;
  if (!S_ISDIR(inode->i_mode)) return -ENOTDIR;
  dn = kmem_cache_alloc(dn_cache, GFP_KERNEL);
  if (dn == NULL) return -ENOMEM;
  spin_lock(&inode->i_lock);
  prev = &inode->i_dnotify;
  while ((odn = *prev) != NULL) {
    if ((odn->dn_owner == id) && (odn->dn_filp == filp)) {
      odn->dn_fd = fd;
      odn->dn_mask |= arg;
      inode->i_dnotify_mask |= arg & ~DN_MULTISHOT;
      goto out_free;
    }
    prev = &odn->dn_next;
  }
  error = __f_setown(filp, task_pid(current), PIDTYPE_PID, 0);
  if (error) goto out_free;
  dn->dn_mask = arg;
  dn->dn_fd = fd;
  dn->dn_filp = filp;
  dn->dn_owner = id;
  inode->i_dnotify_mask |= arg & ~DN_MULTISHOT;
  dn->dn_next = inode->i_dnotify;
  inode->i_dnotify = dn;
  spin_unlock(&inode->i_lock);
  if (filp->f_op && filp->f_op->dir_notify)
    return filp->f_op->dir_notify(filp, arg);
  return 0;
out_free:
  spin_unlock(&inode->i_lock);
  kmem_cache_free(dn_cache, dn);
  return error;
}

size_t mobi_get_attribute_value(char* value, const unsigned char* data,
                                const size_t size, const char* attribute,
                                bool only_quoted) {
  if (!data) {
    debug_print("Data is null%s", "\n");
    return SIZE_MAX;
  }
  size_t length = size;
  size_t attr_length = strlen(attribute);
  if (attr_length > MOBI_ATTRNAME_MAXSIZE) {
    debug_print("Attribute too long: %zu\n", attr_length);
    return SIZE_MAX;
  }
  char attr[MOBI_ATTRNAME_MAXSIZE + 2];
  strcpy(attr, attribute);
  strcat(attr, "=");
  attr_length++;
  if (size < attr_length) {
    return SIZE_MAX;
  }
  unsigned char last_border = '\0';
  do {
    if (*data == '<' || *data == '>') {
      last_border = *data;
    }
    if (length > attr_length + 1 && memcmp(data, attr, attr_length) == 0) {
      size_t offset = size - length;
      if (last_border == '>') {
        data += attr_length;
        length -= attr_length - 1;
        continue;
      }
      if (offset > 0) {
        if (data[-1] != '<' && !isspace(data[-1])) {
          data += attr_length;
          length -= attr_length - 1;
          continue;
        }
      }
      data += attr_length;
      length -= attr_length;
      unsigned char separator;
      if (*data != '\'' && *data != '"') {
        if (only_quoted) {
          continue;
        }
        separator = ' ';
      } else {
        separator = *data;
        data++;
        length--;
      }
      size_t j;
      for (j = 0; j < MOBI_ATTRVALUE_MAXSIZE && length && *data != separator &&
                  *data != '>';
           j++) {
        *value++ = (char)*data++;
        length--;
      }
      if (*(data - 1) == '/' && *data == '>') {
        value--;
      }
      *value = '\0';
      return size - length - j;
    }
    data++;
  } while (--length);
  value[0] = '\0';
  return SIZE_MAX;
}

bool QODBCResult::prepare(const QString& query) {
  Q_D(QODBCResult);
  setActive(false);
  setAt(QSql::BeforeFirstRow);
  SQLRETURN r;
  d->rInf.clear();
  if (d->hStmt && d->isStmtHandleValid()) {
    r = SQLFreeHandle(SQL_HANDLE_STMT, d->hStmt);
    if (r != SQL_SUCCESS) {
      qSqlWarning("QODBCResult::prepare: Unable to close statement"_L1, d);
      return false;
    }
  }
  r = SQLAllocHandle(SQL_HANDLE_STMT, d->dpDbc(), &d->hStmt);
  if (r != SQL_SUCCESS) {
    qSqlWarning("QODBCResult::prepare: Unable to allocate statement handle"_L1,
                d);
    return false;
  }
  d->updateStmtHandleState();
  if (isForwardOnly()) {
    r = SQLSetStmtAttr(d->hStmt, SQL_ATTR_CURSOR_TYPE,
                       (SQLPOINTER)SQL_CURSOR_FORWARD_ONLY, SQL_IS_UINTEGER);
  } else {
    r = SQLSetStmtAttr(d->hStmt, SQL_ATTR_CURSOR_TYPE,
                       (SQLPOINTER)SQL_CURSOR_STATIC, SQL_IS_UINTEGER);
  }
  if (r != SQL_SUCCESS && r != SQL_SUCCESS_WITH_INFO) {
    setLastError(qMakeError(QCoreApplication::translate(
                                "QODBCResult",
                                "QODBCResult::reset: Unable to set "
                                "'SQL_CURSOR_STATIC' as statement attribute. "
                                "Please check your ODBC driver configuration"),
                            QSqlError::StatementError, d));
    return false;
  }
  r = SQLPrepare(d->hStmt, toSQLTCHAR(query).data(),
                 (SQLINTEGER)query.length());
  if (r != SQL_SUCCESS) {
    setLastError(qMakeError(QCoreApplication::translate(
                                "QODBCResult", "Unable to prepare statement"),
                            QSqlError::StatementError, d));
    return false;
  }
  return true;
}

struct se_portal_group* tcm_loop_make_naa_tpg(struct se_wwn* wwn,
                                              struct config_group* group,
                                              const char* name) {
  struct tcm_loop_hba* tl_hba =
      container_of(wwn, struct tcm_loop_hba, tl_hba_wwn);
  struct tcm_loop_tpg* tl_tpg;
  char *tpgt_str, *end_ptr;
  int ret;
  unsigned short int tpgt;
  tpgt_str = strstr(name, "tpgt_");
  if (!tpgt_str) {
    printk(KERN_ERR
           "Unable to locate \"tpgt_#\" directory"
           " group\n");
    return ERR_PTR(-EINVAL);
  }
  tpgt_str += 5;
  tpgt = (unsigned short int)simple_strtoul(tpgt_str, &end_ptr, 0);
  if (tpgt > TL_TPGS_PER_HBA) {
    printk(KERN_ERR
           "Passed tpgt: %hu exceeds TL_TPGS_PER_HBA:"
           " %u\n",
           tpgt, TL_TPGS_PER_HBA);
