  }
  tl_tpg = &tl_hba->tl_hba_tpgs[tpgt];
  tl_tpg->tl_hba = tl_hba;
  tl_tpg->tl_tpgt = tpgt;
  ret =
      core_tpg_register(&tcm_loop_fabric_configfs->tf_ops, wwn,
                        &tl_tpg->tl_se_tpg, tl_tpg, TRANSPORT_TPG_TYPE_NORMAL);
