static int skip_boxes(JXLParseContext* ctx, const uint8_t* buf, int buf_size) {
  GetByteContext gb;
  if (ctx->skip > buf_size) return AVERROR_BUFFER_TOO_SMALL;
  buf += ctx->skip;
  buf_size -= ctx->skip;
  bytestream2_init(&gb, buf, buf_size);
  while (1) {
    uint64_t size;
    int head_size = 4;
    if (bytestream2_peek_le16(&gb) == FF_JPEGXL_CODESTREAM_SIGNATURE_LE) break;
    if (bytestream2_peek_le64(&gb) == FF_JPEGXL_CONTAINER_SIGNATURE_LE) break;
    if (bytestream2_get_bytes_left(&gb) < 8) return AVERROR_BUFFER_TOO_SMALL;
    size = bytestream2_get_be32(&gb);
    if (size == 1) {
      if (bytestream2_get_bytes_left(&gb) < 12) return AVERROR_BUFFER_TOO_SMALL;
      size = bytestream2_get_be64(&gb);
      head_size = 12;
    }
    if (!size) return AVERROR_INVALIDDATA;
    if (size <= head_size + 4) return AVERROR_INVALIDDATA;
    ctx->skip += size;
    bytestream2_skip(&gb, size - head_size);
    if (bytestream2_get_bytes_left(&gb) <= 0) return AVERROR_BUFFER_TOO_SMALL;
  }
  return 0;
}

static void sycc444_to_rgb(opj_image_t* img) {
  int *d0, *d1, *d2, *r, *g, *b;
  const int *y, *cb, *cr;
  unsigned int maxw, maxh, max, i;
  int offset, upb;
  upb = (int)img->comps[0].prec;
  offset = 1 << (upb - 1);
  upb = (1 << upb) - 1;
  maxw = (unsigned int)img->comps[0].w;
  maxh = (unsigned int)img->comps[0].h;
  max = maxw * maxh;
  y = img->comps[0].data;
  cb = img->comps[1].data;
  cr = img->comps[2].data;
  d0 = r = (int*)malloc(sizeof(int) * (size_t)max);
  d1 = g = (int*)malloc(sizeof(int) * (size_t)max);
  d2 = b = (int*)malloc(sizeof(int) * (size_t)max);
  if (r == NULL || g == NULL || b == NULL) goto fails;
  for (i = 0U; i < max; ++i) {
    sycc_to_rgb(offset, upb, *y, *cb, *cr, r, g, b);
    ++y;
    ++cb;
    ++cr;
    ++r;
    ++g;
    ++b;
  }
  free(img->comps[0].data);
  img->comps[0].data = d0;
  free(img->comps[1].data);
  img->comps[1].data = d1;
  free(img->comps[2].data);
  img->comps[2].data = d2;
  return;
fails:
  if (r) free(r);
  if (g) free(g);
  if (b) free(b);
}

int mutt_b64_decode(char* out, const char* in) {
  int len = 0;
  unsigned char digit4;
  do {
    const unsigned char digit1 = in[0];
    if ((digit1 > 127) || (base64val(digit1) == BAD)) return -1;
    const unsigned char digit2 = in[1];
    if ((digit2 > 127) || (base64val(digit2) == BAD)) return -1;
    const unsigned char digit3 = in[2];
    if ((digit3 > 127) || ((digit3 != '=') && (base64val(digit3) == BAD)))
      return -1;
    digit4 = in[3];
    if ((digit4 > 127) || ((digit4 != '=') && (base64val(digit4) == BAD)))
      return -1;
    in += 4;
    *out++ = (base64val(digit1) << 2) | (base64val(digit2) >> 4);
    len++;
    if (digit3 != '=') {
      *out++ = ((base64val(digit2) << 4) & 0xf0) | (base64val(digit3) >> 2);
      len++;
      if (digit4 != '=') {
        *out++ = ((base64val(digit3) << 6) & 0xc0) | base64val(digit4);
        len++;
      }
    }
  } while (*in && digit4 != '=');
  return len;
}

static void parse_relocation_info(struct MACH0_(obj_t) * bin, RSkipList* relocs,
                                  ut32 offset, ut32 num) {
  if (!num || !offset || (st32)num < 0) {
    return;
  }
  ut64 total_size = num * sizeof(struct relocation_info);
  if (offset > bin->size) {
    return;
  }
  if (total_size > bin->size) {
    total_size = bin->size - offset;
    num = total_size /= sizeof(struct relocation_info);
  }
  struct relocation_info* info = calloc(num, sizeof(struct relocation_info));
  if (!info) {
    return;
  }
  if (r_buf_read_at(bin->b, offset, (ut8*)info, total_size) < total_size) {
    free(info);
    return;
  }
  size_t i;
  for (i = 0; i < num; i++) {
    struct relocation_info a_info = info[i];
    ut32 sym_num = a_info.r_symbolnum;
    if (sym_num > bin->nsymtab) {
      continue;
    }
    ut32 stridx = bin->symtab[sym_num].n_strx;
    char* sym_name = get_name(bin, stridx, false);
    if (!sym_name) {
      continue;
    }
    struct reloc_t* reloc = R_NEW0(struct reloc_t);
    if (!reloc) {
      free(info);
      free(sym_name);
      return;
    }
    reloc->addr = offset_to_vaddr(bin, a_info.r_address);
    reloc->offset = a_info.r_address;
    reloc->ord = sym_num;
    reloc->type = a_info.r_type;
    reloc->external = a_info.r_extern;
    reloc->pc_relative = a_info.r_pcrel;
    reloc->size = a_info.r_length;
    r_str_ncpy(reloc->name, sym_name, sizeof(reloc->name) - 1);
    r_skiplist_insert(relocs, reloc);
    free(sym_name);
  }
  free(info);
}

void CharCodeToUnicode::addMapping(CharCode code, char* uStr, int n,
                                   int offset) {
  CharCode oldLen, i;
  Unicode u;
  char uHex[5];
  int j;
  if (code >= mapLen) {
    oldLen = mapLen;
    mapLen = (code + 256) & ~255;
    map = (Unicode*)greallocn(map, mapLen, sizeof(Unicode));
    for (i = oldLen; i < mapLen; ++i) {
      map[i] = 0;
    }
  }
  if (n <= 4) {
    if (sscanf(uStr, "%x", &u) != 1) {
      error(-1, "Illegal entry in ToUnicode CMap");
      return;
    }
    map[code] = u + offset;
  } else {
    if (sMapLen >= sMapSize) {
      sMapSize = sMapSize + 16;
      sMap = (CharCodeToUnicodeString*)greallocn(
          sMap, sMapSize, sizeof(CharCodeToUnicodeString));
    }
    map[code] = 0;
    sMap[sMapLen].c = code;
    sMap[sMapLen].len = n / 4;
    for (j = 0; j < sMap[sMapLen].len && j < maxUnicodeString; ++j) {
      strncpy(uHex, uStr + j * 4, 4);
      uHex[4] = '\0';
      if (sscanf(uHex, "%x", &sMap[sMapLen].u[j]) != 1) {
        error(-1, "Illegal entry in ToUnicode CMap");
      }
    }
    sMap[sMapLen].u[sMap[sMapLen].len - 1] += offset;
    ++sMapLen;
  }
}

processInternalEntity(XML_Parser parser, ENTITY* entity, XML_Bool betweenDecl) {
  const char *textStart, *textEnd;
  const char* next;
  enum XML_Error result;
  OPEN_INTERNAL_ENTITY* openEntity;
  if (parser->m_freeInternalEntities) {
    openEntity = parser->m_freeInternalEntities;
    parser->m_freeInternalEntities = openEntity->next;
  } else {
    openEntity =
        (OPEN_INTERNAL_ENTITY*)MALLOC(parser, sizeof(OPEN_INTERNAL_ENTITY));
    if (!openEntity) return XML_ERROR_NO_MEMORY;
  }
  entity->open = XML_TRUE;
#ifdef XML_DTD
  entityTrackingOnOpen(parser, entity, __LINE__);
#endif
  entity->processed = 0;
  openEntity->next = parser->m_openInternalEntities;
  parser->m_openInternalEntities = openEntity;
  openEntity->entity = entity;
  openEntity->startTagLevel = parser->m_tagLevel;
  openEntity->betweenDecl = betweenDecl;
  openEntity->internalEventPtr = NULL;
  openEntity->internalEventEndPtr = NULL;
  textStart = (const char*)entity->textPtr;
  textEnd = (const char*)(entity->textPtr + entity->textLen);
  next = textStart;
#ifdef XML_DTD
  if (entity->is_param) {
    int tok =
        XmlPrologTok(parser->m_internalEncoding, textStart, textEnd, &next);
    result = doProlog(parser, parser->m_internalEncoding, textStart, textEnd,
                      tok, next, &next, XML_FALSE, XML_FALSE,
                      XML_ACCOUNT_ENTITY_EXPANSION);
  } else
#endif
    result = doContent(parser, parser->m_tagLevel, parser->m_internalEncoding,
                       textStart, textEnd, &next, XML_FALSE,
                       XML_ACCOUNT_ENTITY_EXPANSION);
  if (result == XML_ERROR_NONE) {
    if (textEnd != next && parser->m_parsingStatus.parsing == XML_SUSPENDED) {
      entity->processed = (int)(next - textStart);
      parser->m_processor = internalEntityProcessor;
    } else {
#ifdef XML_DTD
      entityTrackingOnClose(parser, entity, __LINE__);
#endif
      entity->open = XML_FALSE;
      parser->m_openInternalEntities = openEntity->next;
      openEntity->next = parser->m_freeInternalEntities;
      parser->m_freeInternalEntities = openEntity;
    }
  }
  return result;
}

pango_glyph_string_set_size(PangoGlyphString* string, gint new_len) {
  g_return_if_fail(new_len >= 0);
  while (new_len > string->space) {
    if (string->space == 0)
      string->space = 1;
    else
      string->space *= 2;
    if (string->space < 0) {
      g_warning(
          "glyph string length overflows maximum integer size, truncated");
      new_len = string->space = G_MAXINT - 8;
    }
  }
  string->glyphs =
      g_realloc(string->glyphs, string->space * sizeof(PangoGlyphInfo));
  string->log_clusters =
      g_realloc(string->log_clusters, string->space * sizeof(gint));
  string->num_glyphs = new_len;
}

void unbind_ports(void) {
  SERVICE_OPTIONS* opt;
  s_poll_init(fds, 1);
  CRYPTO_THREAD_write_lock(stunnel_locks[LOCK_SECTIONS]);
  opt = service_options.next;
  service_options.next = NULL;
  service_free(&service_options);
  while (opt) {
    unsigned i;
    s_log(LOG_DEBUG, "Unbinding service [%s]", opt->servname);
    for (i = 0; i < opt->local_addr.num; ++i) unbind_port(opt, i);
    if (opt->exec_name && opt->connect_addr.names) {
      opt->option.retry = 0;
    }
    if (opt->ctx)
      SSL_CTX_flush_sessions(opt->ctx,
                             (long)time(NULL) + opt->session_timeout + 1);
    s_log(LOG_DEBUG, "Service [%s] closed", opt->servname);
    {
      SERVICE_OPTIONS* garbage = opt;
      opt = opt->next;
      garbage->next = NULL;
      service_free(garbage);
    }
  }
  CRYPTO_THREAD_unlock(stunnel_locks[LOCK_SECTIONS]);
}

static inline FILE* xfmkstemp(char** tmpname, char* dir) {
  int fd;
  FILE* ret;
  fd = xmkstemp(tmpname, dir);
  if (fd == -1) return NULL;
  if (!(ret = fdopen(fd, "w+" UL_CLOEXECSTR))) {
    close(fd);
    return NULL;
  }
  return ret;
}

