void sctp_generate_heartbeat_event(unsigned long data) {
  int error = 0;
  struct sctp_transport* transport = (struct sctp_transport*)data;
  struct sctp_association* asoc = transport->asoc;
  struct net* net = sock_net(asoc->base.sk);
  bh_lock_sock(asoc->base.sk);
  if (sock_owned_by_user(asoc->base.sk)) {
    pr_debug("%s: sock is busy\n", __func__);
    if (!mod_timer(&transport->hb_timer, jiffies + (HZ / 20)))
      sctp_transport_hold(transport);
    goto out_unlock;
  }
  if (transport->dead) goto out_unlock;
  error = sctp_do_sm(net, SCTP_EVENT_T_TIMEOUT,
                     SCTP_ST_TIMEOUT(SCTP_EVENT_TIMEOUT_HEARTBEAT), asoc->state,
                     asoc->ep, asoc, transport, GFP_ATOMIC);
  if (error) asoc->base.sk->sk_err = -error;
out_unlock:
  bh_unlock_sock(asoc->base.sk);
  sctp_transport_put(transport);
}

static int holtekff_init(struct hid_device* hid) {
  struct holtekff_device* holtekff;
  struct hid_report* report;
  struct hid_input* hidinput =
      list_entry(hid->inputs.next, struct hid_input, list);
  struct list_head* report_list =
      &hid->report_enum[HID_OUTPUT_REPORT].report_list;
  struct input_dev* dev = hidinput->input;
  int error;
  if (list_empty(report_list)) {
    hid_err(hid, "no output report found\n");
    return -ENODEV;
  }
  report = list_entry(report_list->next, struct hid_report, list);
  if (report->maxfield < 1 || report->field[0]->report_count != 7) {
    hid_err(hid, "unexpected output report layout\n");
    return -ENODEV;
  }
  holtekff = kzalloc(sizeof(*holtekff), GFP_KERNEL);
  if (!holtekff) return -ENOMEM;
  set_bit(FF_RUMBLE, dev->ffbit);
  holtekff->field = report->field[0];
  holtekff_send(holtekff, hid, stop_all4);
  holtekff_send(holtekff, hid, stop_all6);
  error = input_ff_create_memless(dev, holtekff, holtekff_play);
  if (error) {
    kfree(holtekff);
    return error;
  }
  hid_info(hid,
           "Force feedback for Holtek On Line Grip based devices by Anssi "
           "Hannula <anssi.hannula@iki.fi>\n");
  return 0;
}

static int db_dict_iter_lookup_key_values(struct db_dict_value_iter* iter) {
  struct db_dict_iter_key* key;
  string_t* path;
  const char* error;
  int ret;
  array_sort(&iter->keys, db_dict_iter_key_cmp);
  path = t_str_new(128);
  str_append(path, DICT_PATH_SHARED);
  array_foreach_modifiable(&iter->keys, key) {
    if (!key->used) continue;
    str_truncate(path, strlen(DICT_PATH_SHARED));
    ret = var_expand(path, key->key->key, iter->var_expand_table, &error);
    if (ret <= 0) {
      auth_request_log_error(iter->auth_request, AUTH_SUBSYS_DB,
                             "Failed to expand key %s: %s", key->key->key,
                             error);
      return -1;
    }
    ret = dict_lookup(iter->conn->dict, iter->pool, str_c(path), &key->value,
                      &error);
    if (ret > 0) {
      auth_request_log_debug(iter->auth_request, AUTH_SUBSYS_DB,
                             "Lookup: %s = %s", str_c(path), key->value);
    } else if (ret < 0) {
      auth_request_log_error(iter->auth_request, AUTH_SUBSYS_DB,
                             "Failed to lookup key %s: %s", str_c(path), error);
      return -1;
    } else if (key->key->default_value != NULL) {
      auth_request_log_debug(iter->auth_request, AUTH_SUBSYS_DB,
                             "Lookup: %s not found, using default value %s",
                             str_c(path), key->key->default_value);
      key->value = key->key->default_value;
    } else {
      return 0;
    }
  }
  return 1;
}

static void* gp_worker_main(void* pvt) {
  struct gp_thread* t = (struct gp_thread*)pvt;
  struct gp_query* q = NULL;
  char dummy = 0;
  int ret;
  while (!t->pool->shutdown) {
    gp_debug_set_conn_id(0);
    pthread_mutex_lock(&t->cond_mutex);
    while (t->query == NULL) {
      pthread_cond_wait(&t->cond_wakeup, &t->cond_mutex);
      if (t->pool->shutdown) {
        pthread_exit(NULL);
      }
    }
    q = t->query;
    t->query = NULL;
    pthread_mutex_unlock(&t->cond_mutex);
    gp_debug_set_conn_id(gp_conn_get_cid(q->conn));
    GPDEBUGN(3, "[status] Handling query input: %p (%zu)\n", q->buffer,
             q->buflen);
    gp_handle_query(t->pool, q);
    GPDEBUGN(3, "[status] Handling query output: %p (%zu)\n", q->buffer,
             q->buflen);
    pthread_mutex_lock(&t->pool->lock);
    q->next = t->pool->reply_list;
    t->pool->reply_list = q;
    if (!t->pool->shutdown) {
      LIST_DEL(t->pool->busy_list, t);
      LIST_ADD(t->pool->free_list, t);
    }
    pthread_mutex_unlock(&t->pool->lock);
    ret = write(t->pool->sig_pipe[1], &dummy, 1);
    if (ret == -1) {
      GPERROR("Failed to signal dispatcher!");
    }
  }
  pthread_exit(NULL);
}

static void add_password(AUTH_HDR* request, unsigned char type,
                         CONST char* password, char* secret) {
  MD5_CTX md5_secret, my_md5;
  unsigned char misc[AUTH_VECTOR_LEN];
  int i;
  int length = strlen(password);
  unsigned char hashed[256 + AUTH_PASS_LEN];
  unsigned char* vector;
  attribute_t* attr;
  if (length > MAXPASS) {
    length = MAXPASS;
  }
  if (length == 0) {
    length = AUTH_PASS_LEN;
  }
  if ((length & (AUTH_PASS_LEN - 1)) != 0) {
    length += (AUTH_PASS_LEN - 1);
    length &= ~(AUTH_PASS_LEN - 1);
  }
  memset(hashed, 0, length);
  memcpy(hashed, password, strlen(password));
  attr = find_attribute(request, PW_PASSWORD);
  if (type == PW_PASSWORD) {
    vector = request->vector;
  } else {
    vector = attr->data;
  }
  MD5Init(&md5_secret);
  MD5Update(&md5_secret, (unsigned char*)secret, strlen(secret));
  my_md5 = md5_secret;
  MD5Update(&my_md5, vector, AUTH_VECTOR_LEN);
  MD5Final(misc, &my_md5);
  xor(hashed, misc, AUTH_PASS_LEN);
  for (i = 1; i < (length >> 4); i++) {
    my_md5 = md5_secret;
    MD5Update(&my_md5, &hashed[(i - 1) * AUTH_PASS_LEN], AUTH_PASS_LEN);
    MD5Final(misc, &my_md5);
    xor(&hashed[i * AUTH_PASS_LEN], misc, AUTH_PASS_LEN);
  }
  if (type == PW_OLD_PASSWORD) {
    attr = find_attribute(request, PW_OLD_PASSWORD);
  }
  if (!attr) {
    add_attribute(request, type, hashed, length);
  } else {
    memcpy(attr->data, hashed, length);
  }
}

TEE_Result tee_mmu_check_access_rights(const struct user_ta_ctx* utc,
                                       uint32_t flags, uaddr_t uaddr,
                                       size_t len) {
  uaddr_t a;
  size_t addr_incr = MIN(CORE_MMU_USER_CODE_SIZE, CORE_MMU_USER_PARAM_SIZE);
  if (ADD_OVERFLOW(uaddr, len, &a)) return TEE_ERROR_ACCESS_DENIED;
  if ((flags & TEE_MEMORY_ACCESS_NONSECURE) &&
      (flags & TEE_MEMORY_ACCESS_SECURE))
    return TEE_ERROR_ACCESS_DENIED;
  if (!(flags & TEE_MEMORY_ACCESS_ANY_OWNER) &&
      !tee_mmu_is_vbuf_inside_ta_private(utc, (void*)uaddr, len))
    return TEE_ERROR_ACCESS_DENIED;
  for (a = uaddr; a < (uaddr + len); a += addr_incr) {
    uint32_t attr;
    TEE_Result res;
    res = tee_mmu_user_va2pa_attr(utc, (void*)a, NULL, &attr);
    if (res != TEE_SUCCESS) return res;
    if ((flags & TEE_MEMORY_ACCESS_NONSECURE) && (attr & TEE_MATTR_SECURE))
      return TEE_ERROR_ACCESS_DENIED;
    if ((flags & TEE_MEMORY_ACCESS_SECURE) && !(attr & TEE_MATTR_SECURE))
      return TEE_ERROR_ACCESS_DENIED;
    if ((flags & TEE_MEMORY_ACCESS_WRITE) && !(attr & TEE_MATTR_UW))
      return TEE_ERROR_ACCESS_DENIED;
    if ((flags & TEE_MEMORY_ACCESS_READ) && !(attr & TEE_MATTR_UR))
      return TEE_ERROR_ACCESS_DENIED;
  }
  return TEE_SUCCESS;
}

void M_LoadDefaults(void) {
  int i;
  int len;
  FILE* f;
  char def[80];
  char strparm[100];
  char* newstring;
  int parm;
  boolean isstring;
  numdefaults = sizeof(defaults) / sizeof(defaults[0]);
  for (i = 0; i < numdefaults; i++)
    *defaults[i].location = defaults[i].defaultvalue;
  i = M_CheckParm("-config");
  if (i && i < myargc - 1) {
    defaultfile = myargv[i + 1];
    printf("	default file: %s\n", defaultfile);
  } else
    defaultfile = basedefault;
  f = fopen(defaultfile, "r");
  if (f) {
    while (!feof(f)) {
      isstring = false;
      if (fscanf(f, "%79s %[^\n]\n", def, strparm) == 2) {
        if (strparm[0] == '"') {
          isstring = true;
          len = strlen(strparm);
          newstring = (char*)malloc(len);
          strparm[len - 1] = 0;
          strcpy(newstring, strparm + 1);
        } else if (strparm[0] == '0' && strparm[1] == 'x')
          sscanf(strparm + 2, "%x", &parm);
        else
          sscanf(strparm, "%i", &parm);
        for (i = 0; i < numdefaults; i++)
          if (!strcmp(def, defaults[i].name)) {
            if (!isstring)
              *defaults[i].location = parm;
            else
              *defaults[i].location = (int)newstring;
            break;
          }
      }
    }
    fclose(f);
  }
  for (i = 0; i < numdefaults; i++) {
    if (defaults[i].scantranslate) {
      parm = *defaults[i].location;
      defaults[i].untranslated = parm;
      *defaults[i].location = scantokey[parm];
    }
  }
}

hb_ot_layout_build_glyph_classes(hb_face_t* face, uint16_t num_total_glyphs,
                                 hb_codepoint_t* glyphs, unsigned char* klasses,
                                 uint16_t count) {
  if (HB_OBJECT_IS_INERT(face)) return;
  hb_ot_layout_t* layout = &face->ot_layout;
  if (HB_UNLIKELY(!count || !glyphs || !klasses)) return;
  if (layout->new_gdef.len == 0) {
    layout->new_gdef.klasses =
        (unsigned char*)calloc(num_total_glyphs, sizeof(unsigned char));
    layout->new_gdef.len = count;
  }
  for (unsigned int i = 0; i < count; i++)
    _hb_ot_layout_set_glyph_class(face, glyphs[i],
                                  (hb_ot_layout_glyph_class_t)klasses[i]);
}

compat_mptfwxfer_ioctl(struct file* filp, unsigned int cmd, unsigned long arg) {
