static void ToPropertyDescriptor(js_State* J, js_Object* obj, const char* name,
                                 js_Object* desc) {
  int haswritable = 0;
  int hasvalue = 0;
  int enumerable = 0;
  int configurable = 0;
  int writable = 0;
  int atts = 0;
  js_pushobject(J, obj);
  js_pushobject(J, desc);
  if (js_hasproperty(J, -1, "writable")) {
    haswritable = 1;
    writable = js_toboolean(J, -1);
    js_pop(J, 1);
  }
  if (js_hasproperty(J, -1, "enumerable")) {
    enumerable = js_toboolean(J, -1);
    js_pop(J, 1);
  }
  if (js_hasproperty(J, -1, "configurable")) {
    configurable = js_toboolean(J, -1);
    js_pop(J, 1);
  }
  if (js_hasproperty(J, -1, "value")) {
    hasvalue = 1;
    js_setproperty(J, -3, name);
  }
  if (!writable) atts |= JS_READONLY;
  if (!enumerable) atts |= JS_DONTENUM;
  if (!configurable) atts |= JS_DONTCONF;
  if (js_hasproperty(J, -1, "get")) {
    if (haswritable || hasvalue)
      js_typeerror(J, "value/writable and get/set attributes are exclusive");
  } else {
    js_pushundefined(J);
  }
  if (js_hasproperty(J, -2, "set")) {
    if (haswritable || hasvalue)
      js_typeerror(J, "value/writable and get/set attributes are exclusive");
  } else {
    js_pushundefined(J);
  }
  js_defaccessor(J, -4, name, atts);
  js_pop(J, 2);
}

static VALUE read_memory(VALUE klass, VALUE content) {
  xmlSchemaPtr schema;
  xmlSchemaParserCtxtPtr ctx = xmlSchemaNewMemParserCtxt(
      (const char*)StringValuePtr(content), (int)RSTRING_LEN(content));
  VALUE rb_schema;
  VALUE errors = rb_ary_new();
  xmlSetStructuredErrorFunc((void*)errors, Nokogiri_error_array_pusher);
#ifdef HAVE_XMLSCHEMASETPARSERSTRUCTUREDERRORS
  xmlSchemaSetParserStructuredErrors(ctx, Nokogiri_error_array_pusher,
                                     (void*)errors);
#endif
  schema = xmlSchemaParse(ctx);
  xmlSetStructuredErrorFunc(NULL, NULL);
  xmlSchemaFreeParserCtxt(ctx);
  if (NULL == schema) {
    xmlErrorPtr error = xmlGetLastError();
    if (error)
      Nokogiri_error_raise(NULL, error);
    else
      rb_raise(rb_eRuntimeError, "Could not parse document");
    return Qnil;
  }
  rb_schema = Data_Wrap_Struct(klass, 0, dealloc, schema);
  rb_iv_set(rb_schema, "@errors", errors);
  return rb_schema;
}

static void iwjpeg_scan_exif(struct iwjpegrcontext* rctx, const iw_byte* d,
                             size_t d_len) {
  struct iw_exif_state e;
  iw_uint32 ifd;
  if (d_len < 8) return;
  iw_zeromem(&e, sizeof(struct iw_exif_state));
  e.d = d;
  e.d_len = d_len;
  e.endian = d[0] == 'I' ? IW_ENDIAN_LITTLE : IW_ENDIAN_BIG;
  ifd = iw_get_ui32_e(&d[4], e.endian);
  iwjpeg_scan_exif_ifd(rctx, &e, ifd);
}

ext4_xattr_cache_find(struct inode* inode, struct ext4_xattr_header* header,
                      struct mb_cache_entry** pce) {
  __u32 hash = le32_to_cpu(header->h_hash);
  struct mb_cache_entry* ce;
  struct mb_cache* ext4_mb_cache = EXT4_GET_MB_CACHE(inode);
  if (!header->h_hash) return NULL;
  ea_idebug(inode, "looking for cached blocks [%x]", (int)hash);
again:
  ce = mb_cache_entry_find_first(ext4_mb_cache, inode->i_sb->s_bdev, hash);
  while (ce) {
    struct buffer_head* bh;
    if (IS_ERR(ce)) {
      if (PTR_ERR(ce) == -EAGAIN) goto again;
      break;
    }
    bh = sb_bread(inode->i_sb, ce->e_block);
    if (!bh) {
      EXT4_ERROR_INODE(inode, "block %lu read error",
                       (unsigned long)ce->e_block);
    } else if (le32_to_cpu(BHDR(bh)->h_refcount) >= EXT4_XATTR_REFCOUNT_MAX) {
      ea_idebug(inode, "block %lu refcount %d>=%d", (unsigned long)ce->e_block,
                le32_to_cpu(BHDR(bh)->h_refcount), EXT4_XATTR_REFCOUNT_MAX);
    } else if (ext4_xattr_cmp(header, BHDR(bh)) == 0) {
      *pce = ce;
      return bh;
    }
    brelse(bh);
    ce = mb_cache_entry_find_next(ce, inode->i_sb->s_bdev, hash);
  }
  return NULL;
}

static int inet_sk_reselect_saddr(struct sock* sk) {
  struct inet_sock* inet = inet_sk(sk);
  __be32 old_saddr = inet->inet_saddr;
  __be32 daddr = inet->inet_daddr;
  struct flowi4 fl4;
  struct rtable* rt;
  __be32 new_saddr;
  if (inet->opt && inet->opt->srr) daddr = inet->opt->faddr;
  rt = ip_route_connect(&fl4, daddr, 0, RT_CONN_FLAGS(sk), sk->sk_bound_dev_if,
                        sk->sk_protocol, inet->inet_sport, inet->inet_dport, sk,
                        false);
  if (IS_ERR(rt)) return PTR_ERR(rt);
  sk_setup_caps(sk, &rt->dst);
  new_saddr = rt->rt_src;
  if (new_saddr == old_saddr) return 0;
  if (sysctl_ip_dynaddr > 1) {
    printk(KERN_INFO "%s(): shifting inet->saddr from %pI4 to %pI4\n", __func__,
           &old_saddr, &new_saddr);
  }
  inet->inet_saddr = inet->inet_rcv_saddr = new_saddr;
  __sk_prot_rehash(sk);
  return 0;
}

int ipc_addid(struct ipc_ids* ids, struct kern_ipc_perm* new, int size) {
  kuid_t euid;
  kgid_t egid;
  int id;
  int next_id = ids->next_id;
  if (size > IPCMNI) size = IPCMNI;
  if (ids->in_use >= size) return -ENOSPC;
  idr_preload(GFP_KERNEL);
  spin_lock_init(&new->lock);
  new->deleted = false;
  rcu_read_lock();
  spin_lock(&new->lock);
  id = idr_alloc(&ids->ipcs_idr, new, (next_id < 0) ? 0 : ipcid_to_idx(next_id),
                 0, GFP_NOWAIT);
  idr_preload_end();
  if (id < 0) {
    spin_unlock(&new->lock);
    rcu_read_unlock();
    return id;
  }
  ids->in_use++;
  current_euid_egid(&euid, &egid);
  new->cuid = new->uid = euid;
  new->gid = new->cgid = egid;
  if (next_id < 0) {
    new->seq = ids->seq++;
    if (ids->seq > IPCID_SEQ_MAX) ids->seq = 0;
  } else {
    new->seq = ipcid_to_seqx(next_id);
    ids->next_id = -1;
  }
  new->id = ipc_buildid(id, new->seq);
  return id;
}

tcf_fill_node(struct sk_buff* skb, struct tcf_proto* tp, unsigned long fh,
              u32 pid, u32 seq, u16 flags, int event) {
  struct tcmsg* tcm;
  struct nlmsghdr* nlh;
  unsigned char* b = skb->tail;
  nlh = NLMSG_NEW(skb, pid, seq, event, sizeof(*tcm), flags);
  tcm = NLMSG_DATA(nlh);
  tcm->tcm_family = AF_UNSPEC;
  tcm->tcm_ifindex = tp->q->dev->ifindex;
  tcm->tcm_parent = tp->classid;
  tcm->tcm_info = TC_H_MAKE(tp->prio, tp->protocol);
  RTA_PUT(skb, TCA_KIND, IFNAMSIZ, tp->ops->kind);
  tcm->tcm_handle = fh;
  if (RTM_DELTFILTER != event) {
    tcm->tcm_handle = 0;
    if (tp->ops->dump && tp->ops->dump(tp, fh, skb, tcm) < 0)
      goto rtattr_failure;
  }
  nlh->nlmsg_len = skb->tail - b;
  return skb->len;
nlmsg_failure:
rtattr_failure:
  skb_trim(skb, b - skb->data);
  return -1;
}

void __init proc_root_init(void) {
  struct vfsmount* mnt;
  int err;
  proc_init_inodecache();
  err = register_filesystem(&proc_fs_type);
  if (err) return;
  mnt = kern_mount_data(&proc_fs_type, &init_pid_ns);
  if (IS_ERR(mnt)) {
    unregister_filesystem(&proc_fs_type);
    return;
  }
  init_pid_ns.proc_mnt = mnt;
  proc_symlink("mounts", NULL, "self/mounts");
  proc_net_init();
#ifdef CONFIG_SYSVIPC
  proc_mkdir("sysvipc", NULL);
#endif
  proc_mkdir("fs", NULL);
  proc_mkdir("driver", NULL);
  proc_mkdir("fs/nfsd", NULL);
#if defined(CONFIG_SUN_OPENPROMFS) || defined(CONFIG_SUN_OPENPROMFS_MODULE)
  proc_mkdir("openprom", NULL);
#endif
  proc_tty_init();
#ifdef CONFIG_PROC_DEVICETREE
  proc_device_tree_init();
#endif
  proc_mkdir("bus", NULL);
  proc_sys_init();
}

Status GetInitOp(const string& export_dir, const MetaGraphDef& meta_graph_def,
                 string* init_op_name) {
  const auto& sig_def_map = meta_graph_def.signature_def();
  const auto& init_op_sig_it =
      meta_graph_def.signature_def().find(kSavedModelInitOpSignatureKey);
  if (init_op_sig_it != sig_def_map.end()) {
    *init_op_name = init_op_sig_it->second.outputs()
                        .find(kSavedModelInitOpSignatureKey)
                        ->second.name();
    return Status::OK();
  }
  const auto& collection_def_map = meta_graph_def.collection_def();
  string init_op_collection_key;
  if (collection_def_map.find(kSavedModelMainOpKey) !=
      collection_def_map.end()) {
    init_op_collection_key = kSavedModelMainOpKey;
  } else {
    init_op_collection_key = kSavedModelLegacyInitOpKey;
  }
  const auto init_op_it = collection_def_map.find(init_op_collection_key);
  if (init_op_it != collection_def_map.end()) {
    if (init_op_it->second.node_list().value_size() != 1) {
      return errors::FailedPrecondition(
          strings::StrCat("Expected exactly one main op in : ", export_dir));
    }
    *init_op_name = init_op_it->second.node_list().value(0);
  }
  return Status::OK();
}

inline bool SegmentReader::containsInterval(const void* from, const void* to) {
  return from >= this->ptr.begin() && to <= this->ptr.end() && from <= to &&
         readLimiter->canRead(
             intervalLength(reinterpret_cast<const byte*>(from),
                            reinterpret_cast<const byte*>(to),
                            MAX_SEGMENT_WORDS * BYTES_PER_WORD) /
                 BYTES_PER_WORD,
             arena);
}

std::wstring GetSwitchValueFromCommandLine(const std::wstring& command_line,
                                           const std::wstring& switch_name) {
  assert(!command_line.empty());
  assert(!switch_name.empty());
  std::vector<std::wstring> as_array = TokenizeCommandLineToArray(command_line);
  std::wstring switch_with_equal = L"--" + switch_name + L"=";
  for (size_t i = 1; i < as_array.size(); ++i) {
    const std::wstring& arg = as_array[i];
    if (arg.compare(0, switch_with_equal.size(), switch_with_equal) == 0)
      return arg.substr(switch_with_equal.size());
  }
  return std::wstring();
}

void Compute(OpKernelContext* ctx) override {
  auto x = ctx->input(0);
  auto i = ctx->input(1);
  auto v = ctx->input(2);
  OP_REQUIRES(
      ctx, TensorShapeUtils::IsVector(i.shape()),
      errors::InvalidArgument("i must be a vector. ", i.shape().DebugString()));
  OP_REQUIRES(ctx, x.dims() == v.dims(),
              errors::InvalidArgument(
                  "x and v shape doesn't match (ranks differ): ",
                  x.shape().DebugString(), " vs. ", v.shape().DebugString()));
  for (int i = 1; i < x.dims(); ++i) {
    OP_REQUIRES(ctx, x.dim_size(i) == v.dim_size(i),
                errors::InvalidArgument("x and v shape doesn't match at index ",
                                        i, " : ", x.shape().DebugString(),
                                        " vs. ", v.shape().DebugString()));
  }
  OP_REQUIRES(ctx, i.dim_size(0) == v.dim_size(0),
              errors::InvalidArgument(
                  "i and x shape doesn't match at index 0: ",
                  i.shape().DebugString(), " vs. ", v.shape().DebugString()));
  Tensor y = x;
  if (x.NumElements() > 0 || v.NumElements() > 0) {
    OP_REQUIRES_OK(ctx, DoCompute(ctx, i, v, &y));
  }
  ctx->set_output(0, y);
}

static UINT serial_process_irp_write(SERIAL_DEVICE* serial, IRP* irp) {
  UINT32 Length;
  UINT64 Offset;
  DWORD nbWritten = 0;
  if (Stream_GetRemainingLength(irp->input) < 32) return ERROR_INVALID_DATA;
  Stream_Read_UINT32(irp->input, Length);
  Stream_Read_UINT64(irp->input, Offset);
  Stream_Seek(irp->input, 20);
  WLog_Print(serial->log, WLOG_DEBUG, "writing %" PRIu32 " bytes to %s", Length,
             serial->device.name);
  if (CommWriteFile(serial->hComm, Stream_Pointer(irp->input), Length,
                    &nbWritten, NULL)) {
    irp->IoStatus = STATUS_SUCCESS;
  } else {
    WLog_Print(serial->log, WLOG_DEBUG,
               "write failure to %s, nbWritten=%" PRIu32
               ", last-error: 0x%08" PRIX32 "",
               serial->device.name, nbWritten, GetLastError());
    irp->IoStatus = _GetLastErrorToIoStatus(serial);
  }
  WLog_Print(serial->log, WLOG_DEBUG, "%" PRIu32 " bytes written to %s",
             nbWritten, serial->device.name);
  Stream_Write_UINT32(irp->output, nbWritten);
  Stream_Write_UINT8(irp->output, 0);
  return CHANNEL_RC_OK;
}

