BufCompressedFill(BufFilePtr f) {
  CompressedFile* file;
  register char_type *stackp, *de_stack;
  register char_type finchar;
  register code_int code, oldcode, incode;
  BufChar *buf, *bufend;
  file = (CompressedFile*)f->private;
  buf = f->buffer;
  bufend = buf + BUFFILESIZE;
  stackp = file->stackp;
  de_stack = file->de_stack;
  finchar = file->finchar;
  oldcode = file->oldcode;
  while (buf < bufend) {
    while (stackp > de_stack && buf < bufend) *buf++ = *--stackp;
    if (buf == bufend) break;
    if (oldcode == -1) break;
    code = getcode(file);
    if (code == -1) break;
    if ((code == CLEAR) && file->block_compress) {
      for (code = 255; code >= 0; code--) file->tab_prefix[code] = 0;
      file->clear_flg = 1;
      file->free_ent = FIRST - 1;
      if ((code = getcode(file)) == -1) break;
    }
    incode = code;
    if (code >= file->free_ent) {
      *stackp++ = finchar;
      code = oldcode;
    }
    while (code >= 256) {
      *stackp++ = file->tab_suffix[code];
      code = file->tab_prefix[code];
    }
    if ((code = file->free_ent) < file->maxmaxcode) {
      file->tab_prefix[code] = (unsigned short)oldcode;
      file->tab_suffix[code] = finchar;
      file->free_ent = code + 1;
    }
    oldcode = incode;
  }
  file->oldcode = oldcode;
  file->stackp = stackp;
  file->finchar = finchar;
  if (buf == f->buffer) {
    f->left = 0;
    return BUFFILEEOF;
  }
  f->bufp = f->buffer + 1;
  f->left = (buf - f->buffer) - 1;
  return f->buffer[0];
}

static int rds_ib_laddr_check(__be32 addr) {
  int ret;
  struct rdma_cm_id* cm_id;
  struct sockaddr_in sin;
  cm_id = rdma_create_id(NULL, NULL, RDMA_PS_TCP, IB_QPT_RC);
  if (IS_ERR(cm_id)) return PTR_ERR(cm_id);
  memset(&sin, 0, sizeof(sin));
  sin.sin_family = AF_INET;
  sin.sin_addr.s_addr = addr;
  ret = rdma_bind_addr(cm_id, (struct sockaddr*)&sin);
  if (ret || cm_id->device->node_type != RDMA_NODE_IB_CA) ret = -EADDRNOTAVAIL;
  rdsdebug("addr %pI4 ret %d node type %d\n", &addr, ret,
           cm_id->device ? cm_id->device->node_type : -1);
  rdma_destroy_id(cm_id);
  return ret;
}

