onig_new_deluxe(regex_t** reg, const UChar* pattern, const UChar* pattern_end,
                OnigCompileInfo* ci, OnigErrorInfo* einfo) {
  int r;
  UChar *cpat, *cpat_end;
  if (IS_NOT_NULL(einfo)) einfo->par = (UChar*)NULL;
  if (ci->pattern_enc != ci->target_enc) {
    r = conv_encoding(ci->pattern_enc, ci->target_enc, pattern, pattern_end,
                      &cpat, &cpat_end);
    if (r != 0) return r;
  } else {
    cpat = (UChar*)pattern;
    cpat_end = (UChar*)pattern_end;
  }
  *reg = (regex_t*)xmalloc(sizeof(regex_t));
  if (IS_NULL(*reg)) {
    r = ONIGERR_MEMORY;
    goto err2;
  }
  r = onig_reg_init(*reg, ci->option, ci->case_fold_flag, ci->target_enc,
                    ci->syntax);
  if (r != 0) goto err;
  r = onig_compile(*reg, cpat, cpat_end, einfo);
  if (r != 0) {
  err:
    onig_free(*reg);
    *reg = NULL;
  }
err2:
  if (cpat != pattern) xfree(cpat);
  return r;
}

static Jsi_RC DebugRemoveCmd_(Jsi_Interp* interp, Jsi_Value* args,
                              Jsi_Value* _this, Jsi_Value** ret,
                              Jsi_Func* funcPtr, int op) {
  Jsi_Value* val = Jsi_ValueArrayIndex(interp, args, 0);
  if (interp->breakpointHash) {
    int num;
    char nbuf[100];
    if (Jsi_GetIntFromValue(interp, val, &num) != JSI_OK)
      return Jsi_LogError("bad number");
    snprintf(nbuf, sizeof(nbuf), "%d", num);
    Jsi_HashEntry* hPtr = Jsi_HashEntryFind(interp->breakpointHash, nbuf);
    jsi_BreakPoint* bptr;
    if (hPtr && (bptr = (jsi_BreakPoint*)Jsi_HashValueGet(hPtr))) {
      switch (op) {
        case 1:
          bptr->enabled = 0;
          break;
        case 2:
          bptr->enabled = 1;
          break;
        default:
          Jsi_HashEntryDelete(hPtr);
      }
      return JSI_OK;
    }
  }
  return Jsi_LogError("unknown breakpoint");
}

dwarf_elf_object_access_load_section(void* obj_in, Dwarf_Half section_index,
                                     Dwarf_Small** section_data, int* error) {
  dwarf_elf_object_access_internals_t* obj =
      (dwarf_elf_object_access_internals_t*)obj_in;
  if (section_index == 0) {
    return DW_DLV_NO_ENTRY;
  }
  {
    Elf_Scn* scn = 0;
    Elf_Data* data = 0;
    scn = elf_getscn(obj->elf, section_index);
    if (scn == NULL) {
      *error = DW_DLE_MDE;
      return DW_DLV_ERROR;
    }
    data = elf_getdata(scn, NULL);
    if (data == NULL) {
      *error = DW_DLE_MDE;
      return DW_DLV_ERROR;
    }
    *section_data = data->d_buf;
  }
  return DW_DLV_OK;
}

udisks_log(UDisksLogLevel level, const gchar* function, const gchar* location,
           const gchar* format, ...) {
  va_list var_args;
  gchar* message;
  va_start(var_args, format);
  message = g_strdup_vprintf(format, var_args);
  va_end(var_args);
#if GLIB_CHECK_VERSION(2, 50, 0)
  g_log_structured("udisks", (GLogLevelFlags)level, "MESSAGE", message,
                   "THREAD_ID", "%d", (gint)syscall(SYS_gettid), "CODE_FUNC",
                   function, "CODE_FILE", location);
#else
