static int do_insn_fetch(struct x86_emulate_ctxt* ctxt,
                         struct x86_emulate_ops* ops, unsigned long eip,
                         void* dest, unsigned size) {
  int rc = 0;
  eip += ctxt->cs_base;
  while (size--) {
    rc = do_fetch_insn_byte(ctxt, ops, eip++, dest++);
    if (rc) return rc;
  }
  return 0;
}

struct key* request_key_and_link(struct key_type* type, const char* description,
                                 const void* callout_info, size_t callout_len,
                                 void* aux, struct key* dest_keyring,
                                 unsigned long flags) {
  struct keyring_search_context ctx = {
      .index_key.type = type,
      .index_key.description = description,
      .cred = current_cred(),
      .match_data.cmp = type->match,
      .match_data.raw_data = description,
      .match_data.lookup_type = KEYRING_SEARCH_LOOKUP_DIRECT,
  };
  struct key* key;
  key_ref_t key_ref;
  int ret;
  kenter("%s,%s,%p,%zu,%p,%p,%lx", ctx.index_key.type->name,
         ctx.index_key.description, callout_info, callout_len, aux,
         dest_keyring, flags);
  if (type->match_preparse) {
    ret = type->match_preparse(&ctx.match_data);
    if (ret < 0) {
      key = ERR_PTR(ret);
      goto error;
    }
  }
  key_ref = search_process_keyrings(&ctx);
  if (!IS_ERR(key_ref)) {
    key = key_ref_to_ptr(key_ref);
    if (dest_keyring) {
      construct_get_dest_keyring(&dest_keyring);
      ret = key_link(dest_keyring, key);
      key_put(dest_keyring);
      if (ret < 0) {
        key_put(key);
        key = ERR_PTR(ret);
        goto error_free;
      }
    }
  } else if (PTR_ERR(key_ref) != -EAGAIN) {
    key = ERR_CAST(key_ref);
  } else {
    key = ERR_PTR(-ENOKEY);
    if (!callout_info) goto error_free;
    key = construct_key_and_link(&ctx, callout_info, callout_len, aux,
                                 dest_keyring, flags);
  }
error_free:
  if (type->match_free) type->match_free(&ctx.match_data);
error:
  kleave(" = %p", key);
  return key;
}

static ssize_t rpmsg_eptdev_write_iter(struct kiocb* iocb,
                                       struct iov_iter* from) {
  struct file* filp = iocb->ki_filp;
  struct rpmsg_eptdev* eptdev = filp->private_data;
  size_t len = iov_iter_count(from);
  void* kbuf;
  int ret;
  kbuf = kzalloc(len, GFP_KERNEL);
  if (!kbuf) return -ENOMEM;
  if (!copy_from_iter_full(kbuf, len, from)) return -EFAULT;
  if (mutex_lock_interruptible(&eptdev->ept_lock)) {
    ret = -ERESTARTSYS;
    goto free_kbuf;
  }
  if (!eptdev->ept) {
    ret = -EPIPE;
    goto unlock_eptdev;
  }
  if (filp->f_flags & O_NONBLOCK)
    ret = rpmsg_trysend(eptdev->ept, kbuf, len);
  else
    ret = rpmsg_send(eptdev->ept, kbuf, len);
unlock_eptdev:
  mutex_unlock(&eptdev->ept_lock);
free_kbuf:
  kfree(kbuf);
  return ret < 0 ? ret : len;
}

void deletesuccessor(file_t** existing, file_t* duplicate, int matchconfirmed,
                     int (*comparef)(file_t* f1, file_t* f2),
                     struct log_info* loginfo) {
  file_t* to_keep;
  file_t* to_delete;
  if (comparef(duplicate, *existing) >= 0) {
    to_keep = *existing;
    to_delete = duplicate;
  } else {
    to_keep = duplicate;
    to_delete = *existing;
    *existing = duplicate;
  }
  if (!ISFLAG(flags, F_HIDEPROGRESS)) fprintf(stderr, "\r%40s\r", " ");
  if (loginfo) log_begin_set(loginfo);
  printf("   [+] %s\n", to_keep->d_name);
  if (loginfo) log_file_remaining(loginfo, to_keep->d_name);
  if (matchconfirmed) {
    if (remove(to_delete->d_name) == 0) {
      printf("   [-] %s\n", to_delete->d_name);
      if (loginfo) log_file_deleted(loginfo, to_delete->d_name);
    } else {
      printf("   [!] %s ", to_delete->d_name);
      printf("-- unable to delete file!\n");
      if (loginfo) log_file_remaining(loginfo, to_delete->d_name);
    }
  } else {
    printf("   [!] %s\n", to_delete->d_name);
    printf(" -- unable to confirm match; file not deleted!\n");
    if (loginfo) log_file_remaining(loginfo, to_delete->d_name);
  }
  if (loginfo) log_end_set(loginfo);
  printf("\n");
}

void AppCacheGroup::RemoveCache(AppCache* cache) {
  DCHECK(cache->associated_hosts().empty());
  if (cache == newest_complete_cache_) {
    CancelUpdate();
    AppCache* tmp_cache = newest_complete_cache_;
    newest_complete_cache_ = nullptr;
    tmp_cache->set_owning_group(nullptr);
  } else {
    scoped_refptr<AppCacheGroup> protect(this);
    Caches::iterator it =
        std::find(old_caches_.begin(), old_caches_.end(), cache);
    if (it != old_caches_.end()) {
      AppCache* tmp_cache = *it;
      old_caches_.erase(it);
      tmp_cache->set_owning_group(nullptr);
    }
    if (!is_obsolete() && old_caches_.empty() &&
        !newly_deletable_response_ids_.empty()) {
      storage_->DeleteResponses(manifest_url_, newly_deletable_response_ids_);
      newly_deletable_response_ids_.clear();
    }
  }
}

rt6_print(netdissect_options* ndo, register const u_char* bp,
          const u_char* bp2 _U_) {
  register const struct ip6_rthdr* dp;
  register const struct ip6_rthdr0* dp0;
  register const u_char* ep;
  int i, len;
  register const struct in6_addr* addr;
  dp = (const struct ip6_rthdr*)bp;
  len = dp->ip6r_len;
  ep = ndo->ndo_snapend;
  ND_TCHECK(dp->ip6r_segleft);
  ND_PRINT((ndo, "srcrt (len=%d", dp->ip6r_len));
  ND_PRINT((ndo, ", type=%d", dp->ip6r_type));
  ND_PRINT((ndo, ", segleft=%d", dp->ip6r_segleft));
  switch (dp->ip6r_type) {
    case IPV6_RTHDR_TYPE_0:
    case IPV6_RTHDR_TYPE_2:
      dp0 = (const struct ip6_rthdr0*)dp;
      ND_TCHECK(dp0->ip6r0_reserved);
      if (dp0->ip6r0_reserved || ndo->ndo_vflag) {
        ND_PRINT((ndo, ", rsv=0x%0x", EXTRACT_32BITS(&dp0->ip6r0_reserved)));
      }
      if (len % 2 == 1) goto trunc;
      len >>= 1;
      addr = &dp0->ip6r0_addr[0];
      for (i = 0; i < len; i++) {
        if ((const u_char*)(addr + 1) > ep) goto trunc;
        ND_PRINT((ndo, ", [%d]%s", i, ip6addr_string(ndo, addr)));
        addr++;
      }
      ND_PRINT((ndo, ") "));
      return ((dp0->ip6r0_len + 1) << 3);
      break;
    default:
      goto trunc;
      break;
  }
trunc:
  ND_PRINT((ndo, "[|srcrt]"));
  return -1;
}

static gboolean key_value_ok(gchar* key, gchar* value) {
  char* i;
  for (i = key; *i != 0; i++) {
    if (!isalpha(*i) && (*i != '-') && (*i != '_') && (*i != ' ')) return FALSE;
  }
  if (strcmp(key, "basename") == 0 || strcmp(key, FILENAME_TYPE) == 0) {
    if (!is_correct_filename(value)) {
      error_msg("Value of '%s' ('%s') is not a valid directory name", key,
                value);
      return FALSE;
    }
  }
  return TRUE;
}

wsemul_sun_output_control(struct wsemul_sun_emuldata* edp,
                          struct wsemul_inputstate* instate) {
  int oargs;
  int rc;
  switch (instate->inchar) {
    case '0':
    case '1':
    case '2':
    case '3':
    case '4':
    case '5':
    case '6':
    case '7':
    case '8':
    case '9':
      if (edp->nargs > SUN_EMUL_NARGS - 1) {
        bcopy(edp->args + 1, edp->args,
              (SUN_EMUL_NARGS - 1) * sizeof(edp->args[0]));
        edp->args[edp->nargs = SUN_EMUL_NARGS - 1] = 0;
      }
      edp->args[edp->nargs] =
          (edp->args[edp->nargs] * 10) + (instate->inchar - '0');
      break;
    case ';':
      edp->nargs++;
      break;
    default:
      oargs = edp->nargs++;
      if (edp->nargs > SUN_EMUL_NARGS) edp->nargs = SUN_EMUL_NARGS;
      rc = wsemul_sun_control(edp, instate);
      if (rc != 0) {
        edp->nargs = oargs;
        return rc;
      }
      edp->state = SUN_EMUL_STATE_NORMAL;
      break;
  }
  return 0;
}

void ax25_disconnect(ax25_cb* ax25, int reason) {
  ax25_clear_queues(ax25);
  if (!ax25->sk || !sock_flag(ax25->sk, SOCK_DESTROY))
    ax25_stop_heartbeat(ax25);
  ax25_stop_t1timer(ax25);
  ax25_stop_t2timer(ax25);
  ax25_stop_t3timer(ax25);
  ax25_stop_idletimer(ax25);
  ax25->state = AX25_STATE_0;
  ax25_link_failed(ax25, reason);
  if (ax25->sk != NULL) {
    local_bh_disable();
    bh_lock_sock(ax25->sk);
    ax25->sk->sk_state = TCP_CLOSE;
    ax25->sk->sk_err = reason;
    ax25->sk->sk_shutdown |= SEND_SHUTDOWN;
    if (!sock_flag(ax25->sk, SOCK_DEAD)) {
      ax25->sk->sk_state_change(ax25->sk);
      sock_set_flag(ax25->sk, SOCK_DEAD);
    }
    bh_unlock_sock(ax25->sk);
    local_bh_enable();
  }
}

int jp2_box_put(jp2_box_t* box, jas_stream_t* out) {
  jas_stream_t* tmpstream;
  bool extlen;
  bool dataflag;
  tmpstream = 0;
  dataflag = !(box->info->flags & (JP2_BOX_SUPER | JP2_BOX_NODATA));
  if (dataflag) {
    if (!(tmpstream = jas_stream_memopen(0, 0))) {
      goto error;
    }
    if (box->ops->putdata) {
      if ((*box->ops->putdata)(box, tmpstream)) {
        goto error;
      }
    }
    box->len = jas_stream_tell(tmpstream) + JP2_BOX_HDRLEN(false);
    jas_stream_rewind(tmpstream);
  }
  extlen = (box->len >= (((uint_fast64_t)1) << 32)) != 0;
  if (jp2_putuint32(out, extlen ? 1 : box->len)) {
    goto error;
  }
  if (jp2_putuint32(out, box->type)) {
    goto error;
  }
  if (extlen) {
    if (jp2_putuint64(out, box->len)) {
      goto error;
    }
  }
  if (dataflag) {
    if (jas_stream_copy(out, tmpstream, box->len - JP2_BOX_HDRLEN(false))) {
      goto error;
    }
    jas_stream_close(tmpstream);
  }
  return 0;
error:
  if (tmpstream) {
    jas_stream_close(tmpstream);
  }
  return -1;
}

TfLiteStatus EvalSimple(TfLiteContext* context, TfLiteNode* node,
                        const TfLiteTensor* lookup, const TfLiteTensor* value,
                        TfLiteTensor* output) {
  const int row_size = SizeOfDimension(value, 0);
  const int row_bytes = value->bytes / row_size;
  char* output_raw = GetTensorData<char>(output);
  const char* value_raw = GetTensorData<char>(value);
  const int32_t* lookup_data = GetTensorData<int32_t>(lookup);
  for (int i = 0; i < SizeOfDimension(lookup, 0); i++) {
    int idx = lookup_data[i];
    if (idx >= row_size || idx < 0) {
      context->ReportError(context,
                           "Embedding Lookup: index out of bounds. "
                           "Got %d, and bounds are [0, %d]",
                           idx, row_size - 1);
      return kTfLiteError;
    } else {
      std::memcpy(output_raw + i * row_bytes, value_raw + idx * row_bytes,
                  row_bytes);
    }
  }
  return kTfLiteOk;
}

int digest_generic_verify(struct digest* d, const unsigned char* md) {
  int ret;
  int len = digest_length(d);
  unsigned char* tmp;
  tmp = xmalloc(len);
  ret = digest_final(d, tmp);
  if (ret) goto end;
  ret = memcmp(md, tmp, len);
  ret = ret ? -EINVAL : 0;
end:
  free(tmp);
  return ret;
}

static int xfrm_dump_sa(struct sk_buff* skb, struct netlink_callback* cb) {
  struct net* net = sock_net(skb->sk);
  struct xfrm_state_walk* walk = (struct xfrm_state_walk*)&cb->args[1];
  struct xfrm_dump_info info;
  BUILD_BUG_ON(sizeof(struct xfrm_state_walk) >
               sizeof(cb->args) - sizeof(cb->args[0]));
  info.in_skb = cb->skb;
  info.out_skb = skb;
  info.nlmsg_seq = cb->nlh->nlmsg_seq;
  info.nlmsg_flags = NLM_F_MULTI;
  if (!cb->args[0]) {
    struct nlattr* attrs[XFRMA_MAX + 1];
    struct xfrm_address_filter* filter = NULL;
    u8 proto = 0;
    int err;
    cb->args[0] = 1;
    err = nlmsg_parse(cb->nlh, 0, attrs, XFRMA_MAX, xfrma_policy);
    if (err < 0) return err;
    if (attrs[XFRMA_ADDRESS_FILTER]) {
      filter = kmemdup(nla_data(attrs[XFRMA_ADDRESS_FILTER]), sizeof(*filter),
                       GFP_KERNEL);
      if (filter == NULL) return -ENOMEM;
    }
    if (attrs[XFRMA_PROTO]) proto = nla_get_u8(attrs[XFRMA_PROTO]);
    xfrm_state_walk_init(walk, proto, filter);
  }
  (void)xfrm_state_walk(net, walk, dump_one_state, &info);
  return skb->len;
}

static bool load_buffer(RBinFile* bf, void** bin_obj, RBuffer* buf,
                        ut64 loadaddr, Sdb* sdb) {
  RDyldCache* cache = R_NEW0(RDyldCache);
  memcpy(cache->magic, "dyldcac", 7);
  cache->buf = r_buf_ref(buf);
  populate_cache_headers(cache);
  if (!cache->hdr) {
    r_dyldcache_free(cache);
    return false;
  }
  populate_cache_maps(cache);
  if (!cache->maps) {
    r_dyldcache_free(cache);
    return false;
  }
  cache->accel = read_cache_accel(cache->buf, cache->hdr, cache->maps);
  cache->bins = create_cache_bins(bf, cache);
  if (!cache->bins) {
    r_dyldcache_free(cache);
    return false;
  }
  cache->locsym = r_dyld_locsym_new(cache);
  cache->rebase_infos = get_rebase_infos(bf, cache);
