          return false;
        }
      }
      r_list_push(pending_bin_files, bf);
      swizzle_io_read(cache, bf->rbin->iob.io);
    }
  }
  *bin_obj = cache;
  return true;
}

static int dccp_v6_send_response(const struct sock* sk,
                                 struct request_sock* req) {
  struct inet_request_sock* ireq = inet_rsk(req);
  struct ipv6_pinfo* np = inet6_sk(sk);
  struct sk_buff* skb;
  struct in6_addr *final_p, final;
  struct flowi6 fl6;
  int err = -1;
  struct dst_entry* dst;
  memset(&fl6, 0, sizeof(fl6));
  fl6.flowi6_proto = IPPROTO_DCCP;
  fl6.daddr = ireq->ir_v6_rmt_addr;
  fl6.saddr = ireq->ir_v6_loc_addr;
  fl6.flowlabel = 0;
  fl6.flowi6_oif = ireq->ir_iif;
  fl6.fl6_dport = ireq->ir_rmt_port;
  fl6.fl6_sport = htons(ireq->ir_num);
  security_req_classify_flow(req, flowi6_to_flowi(&fl6));
  final_p = fl6_update_dst(&fl6, np->opt, &final);
  dst = ip6_dst_lookup_flow(sk, &fl6, final_p);
  if (IS_ERR(dst)) {
    err = PTR_ERR(dst);
    dst = NULL;
    goto done;
  }
  skb = dccp_make_response(sk, dst, req);
  if (skb != NULL) {
    struct dccp_hdr* dh = dccp_hdr(skb);
    dh->dccph_checksum =
        dccp_v6_csum_finish(skb, &ireq->ir_v6_loc_addr, &ireq->ir_v6_rmt_addr);
    fl6.daddr = ireq->ir_v6_rmt_addr;
    err = ip6_xmit(sk, skb, &fl6, np->opt, np->tclass);
    err = net_xmit_eval(err);
  }
done:
  dst_release(dst);
  return err;
}

int imap_subscribe(char* path, bool subscribe) {
  struct ImapData* idata = NULL;
  char buf[LONG_STRING];
  char mbox[LONG_STRING];
  char errstr[STRING];
  struct Buffer err, token;
  struct ImapMbox mx;
  if (!mx_is_imap(path) || imap_parse_path(path, &mx) || !mx.mbox) {
    mutt_error(_("Bad mailbox name"));
    return -1;
  }
  idata = imap_conn_find(&(mx.account), 0);
  if (!idata) goto fail;
  imap_fix_path(idata, mx.mbox, buf, sizeof(buf));
  if (!*buf) mutt_str_strfcpy(buf, "INBOX", sizeof(buf));
  if (ImapCheckSubscribed) {
    mutt_buffer_init(&token);
    mutt_buffer_init(&err);
    err.data = errstr;
    err.dsize = sizeof(errstr);
    snprintf(mbox, sizeof(mbox), "%smailboxes \"%s\"", subscribe ? "" : "un",
             path);
    if (mutt_parse_rc_line(mbox, &token, &err))
      mutt_debug(1, "Error adding subscribed mailbox: %s\n", errstr);
    FREE(&token.data);
  }
  if (subscribe)
    mutt_message(_("Subscribing to %s..."), buf);
  else
    mutt_message(_("Unsubscribing from %s..."), buf);
  imap_munge_mbox_name(idata, mbox, sizeof(mbox), buf);
  snprintf(buf, sizeof(buf), "%sSUBSCRIBE %s", subscribe ? "" : "UN", mbox);
  if (imap_exec(idata, buf, 0) < 0) goto fail;
  imap_unmunge_mbox_name(idata, mx.mbox);
  if (subscribe)
    mutt_message(_("Subscribed to %s"), mx.mbox);
  else
    mutt_message(_("Unsubscribed from %s"), mx.mbox);
  FREE(&mx.mbox);
  return 0;
fail:
  FREE(&mx.mbox);
  return -1;
}

Value sendrawtransaction(const Array& params, bool fHelp) {
  if (fHelp || params.size() < 1 || params.size() > 1)
    throw runtime_error(
        "sendrawtransaction <hex string>\n"
        "Submits raw transaction (serialized, hex-encoded) to local node and "
        "network.");
  RPCTypeCheck(params, list_of(str_type));
  vector<unsigned char> txData(ParseHex(params[0].get_str()));
  CDataStream ssData(txData, SER_NETWORK, PROTOCOL_VERSION);
  CTransaction tx;
  try {
    ssData >> tx;
  } catch (std::exception& e) {
    throw JSONRPCError(-22, "TX decode failed");
  }
  uint256 hashTx = tx.GetHash();
  CTransaction existingTx;
  uint256 hashBlock = 0;
  if (GetTransaction(hashTx, existingTx, hashBlock)) {
    if (hashBlock != 0)
      throw JSONRPCError(
          -5, string("transaction already in block ") + hashBlock.GetHex());
  } else {
    CTxDB txdb("r");
    if (!tx.AcceptToMemoryPool(txdb)) throw JSONRPCError(-22, "TX rejected");
    SyncWithWallets(tx, NULL, true);
  }
  RelayMessage(CInv(MSG_TX, hashTx), tx);
  return hashTx.GetHex();
}

static int complete_emulated_mmio(struct kvm_vcpu* vcpu) {
  struct kvm_run* run = vcpu->run;
  struct kvm_mmio_fragment* frag;
  unsigned len;
  BUG_ON(!vcpu->mmio_needed);
  frag = &vcpu->mmio_fragments[vcpu->mmio_cur_fragment];
  len = min(8u, frag->len);
  if (!vcpu->mmio_is_write) memcpy(frag->data, run->mmio.data, len);
  if (frag->len <= 8) {
    frag++;
    vcpu->mmio_cur_fragment++;
  } else {
    frag->data += len;
    frag->gpa += len;
    frag->len -= len;
  }
  if (vcpu->mmio_cur_fragment == vcpu->mmio_nr_fragments) {
    vcpu->mmio_needed = 0;
    if (vcpu->mmio_is_write) return 1;
    vcpu->mmio_read_completed = 1;
    return complete_emulated_io(vcpu);
  }
  run->exit_reason = KVM_EXIT_MMIO;
  run->mmio.phys_addr = frag->gpa;
  if (vcpu->mmio_is_write)
    memcpy(run->mmio.data, frag->data, min(8u, frag->len));
  run->mmio.len = min(8u, frag->len);
  run->mmio.is_write = vcpu->mmio_is_write;
  vcpu->arch.complete_userspace_io = complete_emulated_mmio;
  return 0;
}

getln(int fd, char* buf, size_t bufsiz, int feedback,
      enum tgetpass_errval* errval) {
  size_t left = bufsiz;
  ssize_t nr = -1;
  char* cp = buf;
  char c = '\0';
  debug_decl(getln, SUDO_DEBUG_CONV);
  *errval = TGP_ERRVAL_NOERROR;
  if (left == 0) {
    *errval = TGP_ERRVAL_READERROR;
    errno = EINVAL;
    debug_return_str(NULL);
  }
  while (--left) {
    nr = read(fd, &c, 1);
    if (nr != 1 || c == '\n' || c == '\r') break;
    if (feedback) {
      if (c == sudo_term_eof) {
        nr = 0;
        break;
      } else if (c == sudo_term_kill) {
        while (cp > buf) {
          if (write(fd, "\b \b", 3) == -1) break;
          --cp;
        }
        left = bufsiz;
        continue;
      } else if (c == sudo_term_erase) {
        if (cp > buf) {
          if (write(fd, "\b \b", 3) == -1) break;
          --cp;
          left++;
        }
        continue;
      }
      ignore_result(write(fd, "*", 1));
    }
    *cp++ = c;
  }
  *cp = '\0';
  if (feedback) {
    while (cp > buf) {
      if (write(fd, "\b \b", 3) == -1) break;
      --cp;
    }
  }
  switch (nr) {
    case -1:
      if (errno == EINTR) {
        if (signo[SIGALRM] == 1) *errval = TGP_ERRVAL_TIMEOUT;
      } else {
        *errval = TGP_ERRVAL_READERROR;
      }
      debug_return_str(NULL);
    case 0:
      if (left == bufsiz - 1) {
        *errval = TGP_ERRVAL_NOPASSWORD;
        debug_return_str(NULL);
      }
    default:
      debug_return_str_masked(buf);
  }
}

