  size_t ntypes = 0;
  size_t i;
  for (i = 0; i < *nmdev_types; i++) virMediatedDeviceTypeFree(*mdev_types[i]);
  VIR_FREE(*mdev_types);
  *nmdev_types = 0;
  if (virMediatedDeviceGetMdevTypes(sysfspath, &types, &ntypes) < 0) return -1;
  *mdev_types = g_steal_pointer(&types);
  *nmdev_types = ntypes;
  return 0;
}

static int bad_format_imginfo(char* fmt) {
  char* ptr;
  int n = 0;
  ptr = fmt;
  while (*ptr != '\0')
    if (*ptr++ == '%') {
      if (*ptr == '\0') return 1;
      if (*ptr == '%')
        ptr++;
      else if (*ptr == 's' || *ptr == 'S') {
        n = 1;
        ptr++;
      } else {
        if (*ptr == ' ') ptr++;
        while (*ptr >= '0' && *ptr <= '9') ptr++;
        if (*ptr++ != 'l') return 1;
        if (*ptr == 'u')
          ptr++;
        else
          return 1;
        n++;
      }
    }
  return (n != 3);
}

asmlinkage long sys_oabi_semtimedop(int semid, struct oabi_sembuf __user* tsops,
                                    unsigned nsops,
                                    const struct timespec __user* timeout) {
  struct sembuf* sops;
  struct timespec local_timeout;
  long err;
  int i;
  if (nsops < 1) return -EINVAL;
  sops = kmalloc(sizeof(*sops) * nsops, GFP_KERNEL);
  if (!sops) return -ENOMEM;
  err = 0;
  for (i = 0; i < nsops; i++) {
    __get_user_error(sops[i].sem_num, &tsops->sem_num, err);
    __get_user_error(sops[i].sem_op, &tsops->sem_op, err);
    __get_user_error(sops[i].sem_flg, &tsops->sem_flg, err);
    tsops++;
  }
  if (timeout) {
    err |= copy_from_user(&local_timeout, timeout, sizeof(*timeout));
    timeout = &local_timeout;
  }
  if (err) {
    err = -EFAULT;
  } else {
    mm_segment_t fs = get_fs();
    set_fs(KERNEL_DS);
    err = sys_semtimedop(semid, sops, nsops, timeout);
    set_fs(fs);
  }
  kfree(sops);
  return err;
}

