static GCObject** correctgraylist(GCObject** p) {
  GCObject* curr;
  while ((curr = *p) != NULL) {
    switch (curr->tt) {
      case LUA_VTABLE:
      case LUA_VUSERDATA: {
        GCObject** next = getgclist(curr);
        if (getage(curr) == G_TOUCHED1) {
          lua_assert(isgray(curr));
          gray2black(curr);
          changeage(curr, G_TOUCHED1, G_TOUCHED2);
          p = next;
        } else {
          if (!iswhite(curr)) {
            lua_assert(isold(curr));
            if (getage(curr) == G_TOUCHED2) changeage(curr, G_TOUCHED2, G_OLD);
            gray2black(curr);
          }
          *p = *next;
        }
        break;
      }
      case LUA_VTHREAD: {
        lua_State* th = gco2th(curr);
        lua_assert(!isblack(th));
        if (iswhite(th))
          *p = th->gclist;
        else
          p = &th->gclist;
        break;
      }
      default:
        lua_assert(0);
    }
  }
  return p;
}

skip_short_body(int fd, wgint contlen, bool chunked) {
  enum { SKIP_SIZE = 512, SKIP_THRESHOLD = 4096 };
  wgint remaining_chunk_size = 0;
  char dlbuf[SKIP_SIZE + 1];
  dlbuf[SKIP_SIZE] = '\0';
  if (contlen > SKIP_THRESHOLD) return false;
  while (contlen > 0 || chunked) {
    int ret;
    if (chunked) {
      if (remaining_chunk_size == 0) {
        char* line = fd_read_line(fd);
        char* endl;
        if (line == NULL) break;
        remaining_chunk_size = strtol(line, &endl, 16);
        xfree(line);
        if (remaining_chunk_size == 0) {
          line = fd_read_line(fd);
          xfree(line);
          break;
        }
      }
      contlen = MIN(remaining_chunk_size, SKIP_SIZE);
    }
    DEBUGP(("Skipping %s bytes of body: [", number_to_static_string(contlen)));
    ret = fd_read(fd, dlbuf, MIN(contlen, SKIP_SIZE), -1);
    if (ret <= 0) {
      DEBUGP(("] aborting (%s).\n", ret < 0 ? fd_errstr(fd) : "EOF received"));
      return false;
    }
    contlen -= ret;
    if (chunked) {
      remaining_chunk_size -= ret;
      if (remaining_chunk_size == 0) {
        char* line = fd_read_line(fd);
        if (line == NULL)
          return false;
        else
          xfree(line);
      }
    }
    DEBUGP(("%.*s", ret, dlbuf));
  }
  DEBUGP(("] done.\n"));
  return true;
}

krb5_gss_process_context_token(minor_status, context_handle,
                               token_buffer) OM_uint32* minor_status;
gss_ctx_id_t context_handle;
gss_buffer_t token_buffer;
{
  krb5_gss_ctx_id_rec* ctx;
  OM_uint32 majerr;
  ctx = (krb5_gss_ctx_id_t)context_handle;
  if (!ctx->established) {
    *minor_status = KG_CTX_INCOMPLETE;
    return (GSS_S_NO_CONTEXT);
