                                      GSS_C_NO_BUFFER));
}

static int cbs_av1_read_uvlc(CodedBitstreamContext* ctx, GetBitContext* gbc,
                             const char* name, uint32_t* write_to,
                             uint32_t range_min, uint32_t range_max) {
  uint32_t value;
  int position, zeroes, i, j;
  char bits[65];
  if (ctx->trace_enable) position = get_bits_count(gbc);
  zeroes = i = 0;
  while (1) {
    if (get_bits_left(gbc) < zeroes + 1) {
      av_log(ctx->log_ctx, AV_LOG_ERROR,
             "Invalid uvlc code at "
             "%s: bitstream ended.\n",
             name);
      return AVERROR_INVALIDDATA;
    }
    if (get_bits1(gbc)) {
      bits[i++] = '1';
      break;
    } else {
      bits[i++] = '0';
      ++zeroes;
    }
  }
  if (zeroes >= 32) {
    value = MAX_UINT_BITS(32);
  } else {
    value = get_bits_long(gbc, zeroes);
    for (j = 0; j < zeroes; j++)
      bits[i++] = (value >> (zeroes - j - 1) & 1) ? '1' : '0';
    value += (1 << zeroes) - 1;
  }
  if (ctx->trace_enable) {
    bits[i] = 0;
    ff_cbs_trace_syntax_element(ctx, position, name, NULL, bits, value);
  }
  if (value < range_min || value > range_max) {
    av_log(ctx->log_ctx, AV_LOG_ERROR,
           "%s out of range: "
           "%" PRIu32 ", but must be in [%" PRIu32 ",%" PRIu32 "].\n",
           name, value, range_min, range_max);
    return AVERROR_INVALIDDATA;
  }
  *write_to = value;
  return 0;
}

static struct vm_area_struct* vma_to_resize(unsigned long addr,
                                            unsigned long old_len,
                                            unsigned long new_len,
                                            unsigned long* p) {
  struct mm_struct* mm = current->mm;
  struct vm_area_struct* vma = find_vma(mm, addr);
  if (!vma || vma->vm_start > addr) goto Efault;
  if (is_vm_hugetlb_page(vma)) goto Einval;
  if (old_len > vma->vm_end - addr) goto Efault;
  if (vma->vm_flags & (VM_DONTEXPAND | VM_PFNMAP)) {
    if (new_len > old_len) goto Efault;
  }
  if (vma->vm_flags & VM_LOCKED) {
    unsigned long locked, lock_limit;
    locked = mm->locked_vm << PAGE_SHIFT;
    lock_limit = rlimit(RLIMIT_MEMLOCK);
    locked += new_len - old_len;
    if (locked > lock_limit && !capable(CAP_IPC_LOCK)) goto Eagain;
  }
  if (!may_expand_vm(mm, (new_len - old_len) >> PAGE_SHIFT)) goto Enomem;
  if (vma->vm_flags & VM_ACCOUNT) {
    unsigned long charged = (new_len - old_len) >> PAGE_SHIFT;
    if (security_vm_enough_memory(charged)) goto Efault;
    *p = charged;
  }
  return vma;
Efault:
  return ERR_PTR(-EFAULT);
Einval:
  return ERR_PTR(-EINVAL);
Enomem:
  return ERR_PTR(-ENOMEM);
Eagain:
  return ERR_PTR(-EAGAIN);
}

static int rawsock_create(struct net* net, struct socket* sock,
                          const struct nfc_protocol* nfc_proto, int kern) {
  struct sock* sk;
  pr_debug("sock=%p\n", sock);
  if ((sock->type != SOCK_SEQPACKET) && (sock->type != SOCK_RAW))
    return -ESOCKTNOSUPPORT;
  if (sock->type == SOCK_RAW)
    sock->ops = &rawsock_raw_ops;
  else
    sock->ops = &rawsock_ops;
  sk = sk_alloc(net, PF_NFC, GFP_ATOMIC, nfc_proto->proto, kern);
  if (!sk) return -ENOMEM;
  sock_init_data(sock, sk);
  sk->sk_protocol = nfc_proto->id;
  sk->sk_destruct = rawsock_destruct;
  sock->state = SS_UNCONNECTED;
  if (sock->type == SOCK_RAW)
    nfc_sock_link(&raw_sk_list, sk);
  else {
    INIT_WORK(&nfc_rawsock(sk)->tx_work, rawsock_tx_work);
    nfc_rawsock(sk)->tx_work_scheduled = false;
  }
  return 0;
}

static int nfs_readlink_req(struct nfs_priv* npriv, struct nfs_fh* fh,
                            char** target) {
  uint32_t data[1024];
  uint32_t* p;
  uint32_t len;
  struct packet* nfs_packet;
  p = &(data[0]);
  p = rpc_add_credentials(p);
  p = nfs_add_fh3(p, fh);
  len = p - &(data[0]);
  nfs_packet = rpc_req(npriv, PROG_NFS, NFSPROC3_READLINK, data, len);
  if (IS_ERR(nfs_packet)) return PTR_ERR(nfs_packet);
  p = (void*)nfs_packet->data + sizeof(struct rpc_reply) + 4;
  p = nfs_read_post_op_attr(p, NULL);
  len = ntoh32(net_read_uint32(p));
  p++;
  *target = xzalloc(len + 1);
  return 0;
}

handle_keywordonly_args(struct compiling* c, const node* n, int start,
                        asdl_seq* kwonlyargs, asdl_seq* kwdefaults) {
  PyObject* argname;
  node* ch;
  expr_ty expression, annotation;
  arg_ty arg = NULL;
  int i = start;
  int j = 0;
  if (kwonlyargs == NULL) {
    ast_error(c, CHILD(n, start), "named arguments must follow bare *");
    return -1;
  }
  assert(kwdefaults != NULL);
  while (i < NCH(n)) {
    ch = CHILD(n, i);
    switch (TYPE(ch)) {
      case vfpdef:
      case tfpdef:
        if (i + 1 < NCH(n) && TYPE(CHILD(n, i + 1)) == EQUAL) {
          expression = ast_for_expr(c, CHILD(n, i + 2));
          if (!expression) goto error;
          asdl_seq_SET(kwdefaults, j, expression);
          i += 2;
        } else {
          asdl_seq_SET(kwdefaults, j, NULL);
        }
        if (NCH(ch) == 3) {
          annotation = ast_for_expr(c, CHILD(ch, 2));
          if (!annotation) goto error;
        } else {
          annotation = NULL;
        }
        ch = CHILD(ch, 0);
        argname = NEW_IDENTIFIER(ch);
        if (!argname) goto error;
        if (forbidden_name(c, argname, ch, 0)) goto error;
        arg = arg(argname, annotation, NULL, LINENO(ch), ch->n_col_offset,
                  ch->n_end_lineno, ch->n_end_col_offset, c->c_arena);
        if (!arg) goto error;
        asdl_seq_SET(kwonlyargs, j++, arg);
        i += 1;
        if (TYPE(CHILD(n, i)) == COMMA) i += 1;
        break;
      case TYPE_COMMENT:
        arg->type_comment = NEW_TYPE_COMMENT(ch);
        if (!arg->type_comment) goto error;
        i += 1;
        break;
      case DOUBLESTAR:
        return i;
      default:
        ast_error(c, ch, "unexpected node");
        goto error;
    }
  }
  return i;
error:
  return -1;
}

daemon_AuthUserPwd(char* username, char* password, char* errbuf) {
#ifdef _WIN32
  HANDLE Token;
  if (LogonUser(username, ".", password, LOGON32_LOGON_NETWORK,
                LOGON32_PROVIDER_DEFAULT, &Token) == 0) {
    pcap_fmt_errmsg_for_win32_err(errbuf, PCAP_ERRBUF_SIZE, GetLastError(),
                                  "LogonUser() failed");
    return -1;
  }
  if (ImpersonateLoggedOnUser(Token) == 0) {
    pcap_fmt_errmsg_for_win32_err(errbuf, PCAP_ERRBUF_SIZE, GetLastError(),
                                  "ImpersonateLoggedOnUser() failed");
    CloseHandle(Token);
    return -1;
  }
  CloseHandle(Token);
  return 0;
#else
  struct passwd* user;
  char* user_password;
#ifdef HAVE_GETSPNAM
  struct spwd* usersp;
#endif
  if ((user = getpwnam(username)) == NULL) {
    pcap_snprintf(errbuf, PCAP_ERRBUF_SIZE,
                  "Authentication failed: user name or password incorrect");
    return -1;
  }
#ifdef HAVE_GETSPNAM
  if ((usersp = getspnam(username)) == NULL) {
    pcap_snprintf(errbuf, PCAP_ERRBUF_SIZE,
                  "Authentication failed: user name or password incorrect");
    return -1;
  }
  user_password = usersp->sp_pwdp;
#else
  user_password = user->pw_passwd;
#endif
  if (strcmp(user_password, (char*)crypt(password, user_password)) != 0) {
    pcap_snprintf(errbuf, PCAP_ERRBUF_SIZE,
                  "Authentication failed: user name or password incorrect");
    return -1;
  }
  if (setuid(user->pw_uid)) {
    pcap_fmt_errmsg_for_errno(errbuf, PCAP_ERRBUF_SIZE, errno, "setuid");
    return -1;
  }
  return 0;
#endif
}

