asmlinkage long compat_sys_recvmmsg(int fd, struct compat_mmsghdr __user* mmsg,
                                    unsigned int vlen, unsigned int flags,
                                    struct compat_timespec __user* timeout) {
  int datagrams;
  struct timespec ktspec;
  if (flags & MSG_CMSG_COMPAT) return -EINVAL;
  if (COMPAT_USE_64BIT_TIME)
    return __sys_recvmmsg(fd, (struct mmsghdr __user*)mmsg, vlen,
                          flags | MSG_CMSG_COMPAT, (struct timespec*)timeout);
  if (timeout == NULL)
    return __sys_recvmmsg(fd, (struct mmsghdr __user*)mmsg, vlen,
                          flags | MSG_CMSG_COMPAT, NULL);
  if (get_compat_timespec(&ktspec, timeout)) return -EFAULT;
  datagrams = __sys_recvmmsg(fd, (struct mmsghdr __user*)mmsg, vlen,
                             flags | MSG_CMSG_COMPAT, &ktspec);
  if (datagrams > 0 && put_compat_timespec(&ktspec, timeout))
    datagrams = -EFAULT;
  return datagrams;
}

Function* ESTreeIRGen::genGeneratorFunction(
    Identifier originalName, Variable* lazyClosureAlias,
    ESTree::FunctionLikeNode* functionNode) {
  assert(functionNode && "Function AST cannot be null");
  auto* outerFn = Builder.createGeneratorFunction(
      originalName, Function::DefinitionKind::ES5Function,
      ESTree::isStrict(functionNode->strictness), nullptr);
  auto* innerFn = genES5Function(
      genAnonymousLabelName(originalName.isValid() ? originalName.str() : ""),
      lazyClosureAlias, functionNode, true);
  {
    FunctionContext outerFnContext{this, outerFn, functionNode->getSemInfo()};
    emitFunctionPrologue(functionNode, Builder.createBasicBlock(outerFn),
                         InitES5CaptureState::Yes, DoEmitParameters::No);
    auto* gen = Builder.createCreateGeneratorInst(innerFn);
    if (!hasSimpleParams(functionNode)) {
      Value* next = Builder.createLoadPropertyInst(gen, "next");
      Builder.createCallInst(next, gen, {});
    }
    emitFunctionEpilogue(gen);
  }
  return outerFn;
}

void TabSpecificContentSettings::OnContentBlocked(
    ContentSettingsType type, const std::string& resource_identifier) {
  DCHECK(type != CONTENT_SETTINGS_TYPE_GEOLOCATION)
      << "Geolocation settings handled by OnGeolocationPermissionSet";
  content_accessed_[type] = true;
  std::string identifier;
  if (CommandLine::ForCurrentProcess()->HasSwitch(
          switches::kEnableResourceContentSettings)) {
    identifier = resource_identifier;
  }
  if (!identifier.empty()) AddBlockedResource(type, identifier);
#if defined(OS_ANDROID)
  if (type == CONTENT_SETTINGS_TYPE_POPUPS) {
    content_blocked_[type] = false;
    content_blockage_indicated_to_user_[type] = false;
  }
#endif
  if (!content_blocked_[type]) {
    content_blocked_[type] = true;
    content::NotificationService::current()->Notify(
        chrome::NOTIFICATION_WEB_CONTENT_SETTINGS_CHANGED,
        content::Source<WebContents>(web_contents()),
        content::NotificationService::NoDetails());
  }
}

