ChooserContextBase::GetGrantedObjects(const GURL& requesting_origin,
                                      const GURL& embedding_origin) {
  DCHECK_EQ(requesting_origin, requesting_origin.GetOrigin());
  DCHECK_EQ(embedding_origin, embedding_origin.GetOrigin());
  if (!CanRequestObjectPermission(requesting_origin, embedding_origin))
    return {};
  std::vector<std::unique_ptr<Object>> results;
  auto* info = new content_settings::SettingInfo();
  std::unique_ptr<base::DictionaryValue> setting =
      GetWebsiteSetting(requesting_origin, embedding_origin, info);
  std::unique_ptr<base::Value> objects;
  if (!setting->Remove(kObjectListKey, &objects)) return results;
  std::unique_ptr<base::ListValue> object_list =
      base::ListValue::From(std::move(objects));
  if (!object_list) return results;
  for (auto& object : *object_list) {
    base::DictionaryValue* object_dict;
    if (object.GetAsDictionary(&object_dict) && IsValidObject(*object_dict)) {
      results.push_back(std::make_unique<Object>(
          requesting_origin, embedding_origin, object_dict, info->source,
          host_content_settings_map_->is_incognito()));
    }
  }
  return results;
}

print_attr_string(netdissect_options* ndo, register const u_char* data,
                  u_int length, u_short attr_code) {
  register u_int i;
  ND_TCHECK2(data[0], length);
  switch (attr_code) {
    case TUNNEL_PASS:
      if (length < 3) {
        ND_PRINT((ndo, "%s", tstr));
        return;
      }
      if (*data && (*data <= 0x1F))
        ND_PRINT((ndo, "Tag[%u] ", *data));
      else
        ND_PRINT((ndo, "Tag[Unused] "));
      data++;
      length--;
      ND_PRINT((ndo, "Salt %u ", EXTRACT_16BITS(data)));
      data += 2;
      length -= 2;
      break;
    case TUNNEL_CLIENT_END:
    case TUNNEL_SERVER_END:
    case TUNNEL_PRIV_GROUP:
    case TUNNEL_ASSIGN_ID:
    case TUNNEL_CLIENT_AUTH:
    case TUNNEL_SERVER_AUTH:
      if (*data <= 0x1F) {
        if (length < 1) {
          ND_PRINT((ndo, "%s", tstr));
          return;
        }
        if (*data)
          ND_PRINT((ndo, "Tag[%u] ", *data));
        else
          ND_PRINT((ndo, "Tag[Unused] "));
        data++;
        length--;
      }
      break;
    case EGRESS_VLAN_NAME:
      ND_PRINT((ndo, "%s (0x%02x) ",
                tok2str(rfc4675_tagged, "Unknown tag", *data), *data));
      data++;
      length--;
      break;
  }
  for (i = 0; *data && i < length; i++, data++)
    ND_PRINT((ndo, "%c", (*data < 32 || *data > 126) ? '.' : *data));
  return;
trunc:
  ND_PRINT((ndo, "%s", tstr));
}

void UncompressElementOp::Compute(OpKernelContext* ctx) {
  Tensor tensor = ctx->input(0);
  const Variant& variant = tensor.scalar<Variant>()();
  const CompressedElement* compressed = variant.get<CompressedElement>();
  std::vector<Tensor> components;
  OP_REQUIRES_OK(ctx, UncompressElement(*compressed, &components));
  OP_REQUIRES(ctx, components.size() == output_types_.size(),
              errors::FailedPrecondition("Expected ", output_types_.size(),
                                         " outputs from uncompress, but got ",
                                         components.size()));
  for (int i = 0; i < components.size(); ++i) {
    OP_REQUIRES(
        ctx, components[i].dtype() == output_types_[i],
        errors::FailedPrecondition("Expected a tensor of type ",
                                   DataTypeString(output_types_[i]),
                                   " but got a tensor of type ",
                                   DataTypeString(components[i].dtype())));
    ctx->set_output(i, components[i]);
  }
}

static int cp2112_gpio_direction_input(struct gpio_chip* chip,
                                       unsigned offset) {
  struct cp2112_device* dev = gpiochip_get_data(chip);
  struct hid_device* hdev = dev->hdev;
  u8* buf = dev->in_out_buffer;
  int ret;
  mutex_lock(&dev->lock);
  ret = hid_hw_raw_request(hdev, CP2112_GPIO_CONFIG, buf,
                           CP2112_GPIO_CONFIG_LENGTH, HID_FEATURE_REPORT,
                           HID_REQ_GET_REPORT);
  if (ret != CP2112_GPIO_CONFIG_LENGTH) {
    hid_err(hdev, "error requesting GPIO config: %d\n", ret);
    goto exit;
  }
  buf[1] &= ~(1 << offset);
  buf[2] = gpio_push_pull;
  ret = hid_hw_raw_request(hdev, CP2112_GPIO_CONFIG, buf,
                           CP2112_GPIO_CONFIG_LENGTH, HID_FEATURE_REPORT,
                           HID_REQ_SET_REPORT);
  if (ret < 0) {
    hid_err(hdev, "error setting GPIO config: %d\n", ret);
    goto exit;
  }
  ret = 0;
exit:
  mutex_unlock(&dev->lock);
  return ret <= 0 ? ret : -EIO;
}

static struct dst_entry* ip6_sk_dst_check(struct sock* sk,
                                          struct dst_entry* dst,
                                          const struct flowi6* fl6) {
  struct ipv6_pinfo* np = inet6_sk(sk);
  struct rt6_info* rt = (struct rt6_info*)dst;
  if (!dst) goto out;
  if (ip6_rt_check(&rt->rt6i_dst, &fl6->daddr, np->daddr_cache) ||
#ifdef CONFIG_IPV6_SUBTREES
      ip6_rt_check(&rt->rt6i_src, &fl6->saddr, np->saddr_cache) ||
#endif
      (fl6->flowi6_oif && fl6->flowi6_oif != dst->dev->ifindex)) {
    dst_release(dst);
    dst = NULL;
  }
out:
  return dst;
}

pvscsi_ring_pop_req_descr(PVSCSIRingInfo* mgr) {
