filter_session_io(struct io* io, int evt, void* arg) {
  struct filter_session* fs = arg;
  char* line = NULL;
  ssize_t len;
  log_trace(TRACE_IO, "filter session: %p: %s %s", fs, io_strevent(evt),
            io_strio(io));
  switch (evt) {
    case IO_DATAIN:
    nextline:
      line = io_getline(fs->io, &len);
      if (line == NULL) return;
      filter_data(fs->id, line);
      goto nextline;
    case IO_DISCONNECTED:
      io_free(fs->io);
      fs->io = NULL;
      break;
  }
}

static void ram_block_add(struct uc_struct* uc, RAMBlock* new_block) {
  RAMBlock* block;
  RAMBlock* last_block = NULL;
  new_block->offset = find_ram_offset(uc, new_block->max_length);
  if (!new_block->host) {
    new_block->host =
        phys_mem_alloc(uc, new_block->max_length, &new_block->mr->align);
    if (!new_block->host) {
      return;
    }
  }
  RAMBLOCK_FOREACH(block) {
    last_block = block;
    if (block->max_length < new_block->max_length) {
      break;
    }
  }
  if (block) {
    QLIST_INSERT_BEFORE(block, new_block, next);
  } else if (last_block) {
    QLIST_INSERT_AFTER(last_block, new_block, next);
  } else {
    QLIST_INSERT_HEAD(&uc->ram_list.blocks, new_block, next);
  }
  uc->ram_list.mru_block = NULL;
  cpu_physical_memory_set_dirty_range(new_block->offset, new_block->used_length,
                                      DIRTY_CLIENTS_ALL);
}

static Jsi_RC DebugInfoCmd(Jsi_Interp* interp, Jsi_Value* args,
                           Jsi_Value* _this, Jsi_Value** ret,
                           Jsi_Func* funcPtr) {
  if (!interp->breakpointHash) {
    Jsi_ValueMakeArrayObject(interp, ret, NULL);
    return JSI_OK;
  }
  int argc = Jsi_ValueGetLength(interp, args);
  if (argc == 0)
    return Jsi_HashKeysDump(interp, interp->breakpointHash, ret, 0);
  Jsi_Value* val = Jsi_ValueArrayIndex(interp, args, 0);
  int num;
  char nbuf[100];
  if (Jsi_GetIntFromValue(interp, val, &num) != JSI_OK)
    return Jsi_LogError("bad number");
  snprintf(nbuf, sizeof(nbuf), "%d", num);
  Jsi_HashEntry* hPtr = Jsi_HashEntryFind(interp->breakpointHash, nbuf);
  if (!hPtr) return Jsi_LogError("unknown breakpoint");
  jsi_BreakPoint* bp = (jsi_BreakPoint*)Jsi_HashValueGet(hPtr);
  if (!bp) return JSI_ERROR;
  Jsi_DString dStr = {};
  if (bp->func)
    Jsi_DSPrintf(&dStr,
                 "{id:%d, type:\"func\", func:\"%s\", hits:%d, enabled:%s, "
                 "temporary:%s}",
                 bp->id, bp->func, bp->hits, bp->enabled ? "true" : "false",
                 bp->temp ? "true" : "false");
  else
    Jsi_DSPrintf(
        &dStr,
        "{id:%d, type:\"line\", file:\"%s\", line:%d, hits:%d, enabled:%s}",
        bp->id, bp->file ? bp->file : "", bp->line, bp->hits,
        bp->enabled ? "true" : "false");
  Jsi_RC rc = Jsi_JSONParse(interp, Jsi_DSValue(&dStr), ret, 0);
  Jsi_DSFree(&dStr);
  return rc;
}

void rfbClientCleanup(rfbClient* client) {
#ifdef LIBVNCSERVER_HAVE_LIBZ
  int i;
  for (i = 0; i < 4; i++) {
    if (client->zlibStreamActive[i] == TRUE) {
      if (inflateEnd(&client->zlibStream[i]) != Z_OK &&
          client->zlibStream[i].msg != NULL)
        rfbClientLog("inflateEnd: %s\n", client->zlibStream[i].msg);
    }
  }
  if (client->decompStreamInited == TRUE) {
    if (inflateEnd(&client->decompStream) != Z_OK &&
        client->decompStream.msg != NULL)
      rfbClientLog("inflateEnd: %s\n", client->decompStream.msg);
  }
#endif
  if (client->ultra_buffer) free(client->ultra_buffer);
  if (client->raw_buffer) free(client->raw_buffer);
  FreeTLS(client);
  while (client->clientData) {
    rfbClientData* next = client->clientData->next;
    free(client->clientData);
    client->clientData = next;
  }
  if (client->sock != RFB_INVALID_SOCKET) rfbCloseSocket(client->sock);
  if (client->listenSock != RFB_INVALID_SOCKET)
    rfbCloseSocket(client->listenSock);
  free(client->desktopName);
  free(client->serverHost);
  if (client->destHost) free(client->destHost);
  if (client->clientAuthSchemes) free(client->clientAuthSchemes);
#ifdef LIBVNCSERVER_HAVE_SASL
  if (client->saslSecret) free(client->saslSecret);
#endif
#ifdef WIN32
  if (WSACleanup() != 0) {
    errno = WSAGetLastError();
    rfbClientErr("Could not terminate Windows Sockets: %s\n", strerror(errno));
  }
#endif
  free(client);
}

static void write_version(FILE* fp, const char* fname, const char* dirname,
                          xref_t* xref) {
  long start;
  char *c, *new_fname, data;
  FILE* new_fp;
  start = ftell(fp);
  if ((c = strstr(fname, ".pdf"))) *c = '\0';
  new_fname = malloc(strlen(fname) + strlen(dirname) + 16);
  snprintf(new_fname, strlen(fname) + strlen(dirname) + 16,
           "%s/%s-version-%d.pdf", dirname, fname, xref->version);
  if (!(new_fp = fopen(new_fname, "w"))) {
    ERR("Could not create file '%s'\n", new_fname);
    fseek(fp, start, SEEK_SET);
    free(new_fname);
    return;
  }
  fseek(fp, 0, SEEK_SET);
  while (fread(&data, 1, 1, fp)) fwrite(&data, 1, 1, new_fp);
  fprintf(new_fp, "\r\nstartxref\r\n%ld\r\n%%%%EOF", xref->start);
  fclose(new_fp);
  free(new_fname);
  fseek(fp, start, SEEK_SET);
}

static int crypto_ahash_report(struct sk_buff* skb, struct crypto_alg* alg) {
  struct crypto_report_hash rhash;
  snprintf(rhash.type, CRYPTO_MAX_ALG_NAME, "%s", "ahash");
  rhash.blocksize = alg->cra_blocksize;
  rhash.digestsize = __crypto_hash_alg_common(alg)->digestsize;
  if (nla_put(skb, CRYPTOCFGA_REPORT_HASH, sizeof(struct crypto_report_hash),
              &rhash))
    goto nla_put_failure;
  return 0;
nla_put_failure:
  return -EMSGSIZE;
}

static long aio_read_events_ring(struct kioctx* ctx,
                                 struct io_event __user* event, long nr) {
  struct aio_ring* ring;
  unsigned head, tail, pos;
  long ret = 0;
  int copy_ret;
  mutex_lock(&ctx->ring_lock);
  ring = kmap_atomic(ctx->ring_pages[0]);
  head = ring->head;
  tail = ring->tail;
  kunmap_atomic(ring);
  pr_debug("h%u t%u m%u\n", head, tail, ctx->nr_events);
  if (head == tail) goto out;
  while (ret < nr) {
    long avail;
    struct io_event* ev;
    struct page* page;
    avail = (head <= tail ? tail : ctx->nr_events) - head;
    if (head == tail) break;
    avail = min(avail, nr - ret);
    avail = min_t(long, avail,
                  AIO_EVENTS_PER_PAGE -
                      ((head + AIO_EVENTS_OFFSET) % AIO_EVENTS_PER_PAGE));
    pos = head + AIO_EVENTS_OFFSET;
    page = ctx->ring_pages[pos / AIO_EVENTS_PER_PAGE];
    pos %= AIO_EVENTS_PER_PAGE;
    ev = kmap(page);
    copy_ret = copy_to_user(event + ret, ev + pos, sizeof(*ev) * avail);
    kunmap(page);
    if (unlikely(copy_ret)) {
      ret = -EFAULT;
      goto out;
    }
    ret += avail;
    head += avail;
    head %= ctx->nr_events;
  }
  ring = kmap_atomic(ctx->ring_pages[0]);
  ring->head = head;
  kunmap_atomic(ring);
  flush_dcache_page(ctx->ring_pages[0]);
  pr_debug("%li  h%u t%u\n", ret, head, tail);
out:
  mutex_unlock(&ctx->ring_lock);
  return ret;
}

Status InferenceContext::Multiply(DimensionHandle first,
                                  DimensionOrConstant second,
                                  DimensionHandle* out) {
  const int64_t first_value = Value(first);
  const int64_t second_value = Value(second);
  if (first_value == 0) {
    *out = first;
  } else if (second_value == 0) {
    *out = MakeDim(second);
  } else if (first_value == 1) {
    *out = MakeDim(second);
  } else if (second_value == 1) {
    *out = first;
  } else if (first_value == kUnknownDim || second_value == kUnknownDim) {
    *out = UnknownDim();
  } else {
    const int64_t product = first_value * second_value;
    if (product < 0) {
      return errors::InvalidArgument(
          "Negative dimension size caused by overflow when multiplying ",
          first_value, " and ", second_value);
    }
    *out = MakeDim(product);
  }
  return Status::OK();
}

mysqlnd_switch_to_ssl_if_needed(MYSQLND_CONN_DATA* conn,
                                const MYSQLND_PACKET_GREET* const greet_packet,
                                const MYSQLND_OPTIONS* const options,
                                unsigned long mysql_flags TSRMLS_DC) {
  enum_func_status ret = FAIL;
  const MYSQLND_CHARSET* charset;
  MYSQLND_PACKET_AUTH* auth_packet;
  DBG_ENTER("mysqlnd_switch_to_ssl_if_needed");
  auth_packet =
      conn->protocol->m.get_auth_packet(conn->protocol, FALSE TSRMLS_CC);
  if (!auth_packet) {
    SET_OOM_ERROR(*conn->error_info);
    goto end;
  }
  auth_packet->client_flags = mysql_flags;
  auth_packet->max_packet_size = MYSQLND_ASSEMBLED_PACKET_MAX_SIZE;
  if (options->charset_name &&
      (charset = mysqlnd_find_charset_name(options->charset_name))) {
    auth_packet->charset_no = charset->nr;
  } else {
#if MYSQLND_UNICODE
    auth_packet->charset_no = 200;
#else
    auth_packet->charset_no = greet_packet->charset_no;
#endif
  }
#ifdef MYSQLND_SSL_SUPPORTED
  if ((greet_packet->server_capabilities & CLIENT_SSL) &&
      (mysql_flags & CLIENT_SSL)) {
    zend_bool verify =
        mysql_flags & CLIENT_SSL_VERIFY_SERVER_CERT ? TRUE : FALSE;
    DBG_INF("Switching to SSL");
    if (!PACKET_WRITE(auth_packet, conn)) {
      CONN_SET_STATE(conn, CONN_QUIT_SENT);
      SET_CLIENT_ERROR(*conn->error_info, CR_SERVER_GONE_ERROR,
                       UNKNOWN_SQLSTATE, mysqlnd_server_gone);
      goto end;
    }
    conn->net->m.set_client_option(conn->net, MYSQL_OPT_SSL_VERIFY_SERVER_CERT,
                                   (const char*)&verify TSRMLS_CC);
    if (FAIL == conn->net->m.enable_ssl(conn->net TSRMLS_CC)) {
      goto end;
    }
  }
#endif
  ret = PASS;
end:
  PACKET_FREE(auth_packet);
  DBG_RETURN(ret);
}

inline void GatherNd(const RuntimeShape& params_shape,
                     const ParamsT* params_data,
                     const RuntimeShape& indices_shape,
                     const IndicesT* indices_data,
                     const RuntimeShape& output_shape, ParamsT* output_data) {
  ruy::profiler::ScopeLabel label("GatherNd");
  const GatherNdHelperResult res = GatherNdHelper(params_shape, indices_shape);
  for (int i = 0; i < res.n_slices; ++i) {
    int from_pos = 0;
    for (int j = 0; j < res.indices_nd; ++j) {
      from_pos += indices_data[i * res.indices_nd + j] * res.dims_to_count[j];
    }
    std::memcpy(output_data + i * res.slice_size, params_data + from_pos,
                sizeof(ParamsT) * res.slice_size);
  }
}

int cipso_v4_req_setattr(struct request_sock* req,
                         const struct cipso_v4_doi* doi_def,
                         const struct netlbl_lsm_secattr* secattr) {
  int ret_val = -EPERM;
  unsigned char* buf = NULL;
  u32 buf_len;
  u32 opt_len;
  struct ip_options* opt = NULL;
  struct inet_request_sock* req_inet;
  buf_len = CIPSO_V4_OPT_LEN_MAX;
  buf = kmalloc(buf_len, GFP_ATOMIC);
  if (buf == NULL) {
    ret_val = -ENOMEM;
    goto req_setattr_failure;
  }
  ret_val = cipso_v4_genopt(buf, buf_len, doi_def, secattr);
  if (ret_val < 0) goto req_setattr_failure;
  buf_len = ret_val;
  opt_len = (buf_len + 3) & ~3;
  opt = kzalloc(sizeof(*opt) + opt_len, GFP_ATOMIC);
  if (opt == NULL) {
    ret_val = -ENOMEM;
    goto req_setattr_failure;
  }
  memcpy(opt->__data, buf, buf_len);
  opt->optlen = opt_len;
  opt->cipso = sizeof(struct iphdr);
  kfree(buf);
  buf = NULL;
  req_inet = inet_rsk(req);
  opt = xchg(&req_inet->opt, opt);
  kfree(opt);
  return 0;
req_setattr_failure:
  kfree(buf);
  kfree(opt);
  return ret_val;
}

void TableLookUp::setTable(int ntable, const std::vector<ushort16>& table) {
  assert(!table.empty());
  const int nfilled = table.size();
  if (ntable > ntables) {
    ThrowRDE("Table lookup with number greater than number of tables.");
  }
  ushort16* t = &tables[ntable * TABLE_SIZE];
  if (!dither) {
    for (int i = 0; i < 65536; i++) {
      t[i] = (i < nfilled) ? table[i] : table[nfilled - 1];
    }
    return;
  }
  for (int i = 0; i < nfilled; i++) {
    int center = table[i];
    int lower = i > 0 ? table[i - 1] : center;
    int upper = i < (nfilled - 1) ? table[i + 1] : center;
    int delta = upper - lower;
    t[i * 2] = center - ((upper - lower + 2) / 4);
    t[i * 2 + 1] = delta;
  }
  for (int i = nfilled; i < 65536; i++) {
    t[i * 2] = table[nfilled - 1];
    t[i * 2 + 1] = 0;
  }
  t[0] = t[1];
  t[TABLE_SIZE - 1] = t[TABLE_SIZE - 2];
}

QString Helper::temporaryMountDevice(const QString& device, const QString& name,
                                     bool readonly) {
  QString mount_point = mountPoint(device);
  if (!mount_point.isEmpty()) return mount_point;
  mount_point = "%1/.%2/mount/%3";
  const QStringList& tmp_paths =
      QStandardPaths::standardLocations(QStandardPaths::TempLocation);
  mount_point =
      mount_point.arg(tmp_paths.isEmpty() ? "/tmp" : tmp_paths.first())
          .arg(qApp->applicationName())
          .arg(name);
  if (!QDir::current().mkpath(mount_point)) {
    dCError("mkpath \"%s\" failed", qPrintable(mount_point));
    return QString();
  }
  if (!mountDevice(device, mount_point, readonly)) {
    dCError("Mount the device \"%s\" to \"%s\" failed", qPrintable(device),
            qPrintable(mount_point));
    return QString();
  }
  return mount_point;
}

SWTPM_NVRAM_CheckHeader(unsigned char* data, uint32_t length,
                        uint32_t* dataoffset, uint16_t* hdrflags,
                        uint8_t* hdrversion, bool quiet) {
  blobheader* bh = (blobheader*)data;
  if (length < sizeof(bh)) {
    if (!quiet)
      logprintf(STDERR_FILENO, "not enough bytes for header: %u\n", length);
    return TPM_BAD_PARAMETER;
  }
  if (ntohl(bh->totlen) != length) {
    if (!quiet)
      logprintf(STDERR_FILENO, "broken header: bh->totlen %u != %u\n",
                htonl(bh->totlen), length);
    return TPM_BAD_PARAMETER;
  }
  if (bh->min_version > BLOB_HEADER_VERSION) {
    if (!quiet)
      logprintf(STDERR_FILENO,
                "Minimum required version for the blob is %d, we "
                "only support version %d\n",
                bh->min_version, BLOB_HEADER_VERSION);
    return TPM_BAD_VERSION;
  }
  *hdrversion = bh->version;
  *dataoffset = ntohs(bh->hdrsize);
  *hdrflags = ntohs(bh->flags);
  return TPM_SUCCESS;
}

int expand_downwards(struct vm_area_struct* vma, unsigned long address) {
  struct mm_struct* mm = vma->vm_mm;
  struct vm_area_struct* prev;
  int error;
  address &= PAGE_MASK;
  error = security_mmap_addr(address);
  if (error) return error;
  prev = vma->vm_prev;
  if (prev && !(prev->vm_flags & VM_GROWSDOWN) &&
      (prev->vm_flags & (VM_WRITE | VM_READ | VM_EXEC))) {
    if (address - prev->vm_end < stack_guard_gap) return -ENOMEM;
  }
  if (unlikely(anon_vma_prepare(vma))) return -ENOMEM;
  anon_vma_lock_write(vma->anon_vma);
  if (address < vma->vm_start) {
    unsigned long size, grow;
    size = vma->vm_end - address;
    grow = (vma->vm_start - address) >> PAGE_SHIFT;
    error = -ENOMEM;
    if (grow <= vma->vm_pgoff) {
      error = acct_stack_growth(vma, size, grow);
      if (!error) {
        spin_lock(&mm->page_table_lock);
        if (vma->vm_flags & VM_LOCKED) mm->locked_vm += grow;
        vm_stat_account(mm, vma->vm_flags, grow);
        anon_vma_interval_tree_pre_update_vma(vma);
        vma->vm_start = address;
        vma->vm_pgoff -= grow;
        anon_vma_interval_tree_post_update_vma(vma);
        vma_gap_update(vma);
        spin_unlock(&mm->page_table_lock);
        perf_event_mmap(vma);
      }
    }
  }
  anon_vma_unlock_write(vma->anon_vma);
  khugepaged_enter_vma_merge(vma, vma->vm_flags);
  validate_mm(mm);
  return error;
}

static void mrled(u8* RESTRICT in, u8* RESTRICT out, s32 outlen) {
  s32 op = 0, ip = 0;
  s32 c, pc = -1;
  s32 t[256] = {0};
  s32 run = 0;
  for (s32 i = 0; i < 32; ++i) {
    c = in[ip++];
    for (s32 j = 0; j < 8; ++j) t[i * 8 + j] = (c >> j) & 1;
  }
  while (op < outlen) {
    c = in[ip++];
    if (t[c]) {
      for (run = 0; (pc = in[ip++]) == 255; run += 255);
      run += pc + 1;
      for (; run > 0 && op < outlen; --run) out[op++] = c;
    } else
      out[op++] = c;
  }
}

DECLAREwriteFunc(writeBufferToContigTiles) {
  uint32 imagew = TIFFScanlineSize(out);
  uint32 tilew = TIFFTileRowSize(out);
  int iskew = imagew - tilew;
  tsize_t tilesize = TIFFTileSize(out);
  tdata_t obuf;
  uint8* bufp = (uint8*)buf;
  uint32 tl, tw;
  uint32 row;
  (void)spp;
  obuf = _TIFFmalloc(TIFFTileSize(out));
  if (obuf == NULL) return 0;
  _TIFFmemset(obuf, 0, tilesize);
  (void)TIFFGetField(out, TIFFTAG_TILELENGTH, &tl);
  (void)TIFFGetField(out, TIFFTAG_TILEWIDTH, &tw);
  for (row = 0; row < imagelength; row += tilelength) {
    uint32 nrow = (row + tl > imagelength) ? imagelength - row : tl;
    uint32 colb = 0;
    uint32 col;
    for (col = 0; col < imagewidth; col += tw) {
      if (colb + tilew > imagew) {
        uint32 width = imagew - colb;
        int oskew = tilew - width;
        cpStripToTile(obuf, bufp + colb, nrow, width, oskew, oskew + iskew);
      } else
        cpStripToTile(obuf, bufp + colb, nrow, tilew, 0, iskew);
      if (TIFFWriteTile(out, obuf, col, row, 0, 0) < 0) {
        TIFFError(TIFFFileName(out), "Error, can't write tile at %lu %lu",
                  (unsigned long)col, (unsigned long)row);
        _TIFFfree(obuf);
        return 0;
      }
      colb += tilew;
    }
    bufp += nrow * imagew;
  }
  _TIFFfree(obuf);
  return 1;
}

int nfc_data_exchange(struct nfc_dev* dev, u32 target_idx, struct sk_buff* skb,
                      data_exchange_cb_t cb, void* cb_context) {
  int rc;
  pr_debug("dev_name=%s target_idx=%u skb->len=%u\n", dev_name(&dev->dev),
           target_idx, skb->len);
  device_lock(&dev->dev);
  if (!device_is_registered(&dev->dev)) {
    rc = -ENODEV;
    kfree_skb(skb);
    goto error;
  }
  if (dev->rf_mode == NFC_RF_INITIATOR && dev->active_target != NULL) {
    if (dev->active_target->idx != target_idx) {
      rc = -EADDRNOTAVAIL;
      kfree_skb(skb);
      goto error;
    }
    if (dev->ops->check_presence) del_timer_sync(&dev->check_pres_timer);
    rc = dev->ops->im_transceive(dev, dev->active_target, skb, cb, cb_context);
    if (!rc && dev->ops->check_presence && !dev->shutting_down)
      mod_timer(&dev->check_pres_timer,
                jiffies + msecs_to_jiffies(NFC_CHECK_PRES_FREQ_MS));
  } else if (dev->rf_mode == NFC_RF_TARGET && dev->ops->tm_send != NULL) {
    rc = dev->ops->tm_send(dev, skb);
  } else {
    rc = -ENOTCONN;
    kfree_skb(skb);
    goto error;
  }
error:
  device_unlock(&dev->dev);
  return rc;
}

static int set_core_reg(struct kvm_vcpu* vcpu, const struct kvm_one_reg* reg) {
  __u32 __user* uaddr = (__u32 __user*)(unsigned long)reg->addr;
  struct kvm_regs* regs = vcpu_gp_regs(vcpu);
  int nr_regs = sizeof(*regs) / sizeof(__u32);
  __uint128_t tmp;
  void* valp = &tmp;
  u64 off;
  int err = 0;
  off = core_reg_offset_from_id(reg->id);
  if (off >= nr_regs ||
      (off + (KVM_REG_SIZE(reg->id) / sizeof(__u32))) >= nr_regs)
    return -ENOENT;
  if (validate_core_offset(reg)) return -EINVAL;
  if (KVM_REG_SIZE(reg->id) > sizeof(tmp)) return -EINVAL;
  if (copy_from_user(valp, uaddr, KVM_REG_SIZE(reg->id))) {
    err = -EFAULT;
    goto out;
  }
  if (off == KVM_REG_ARM_CORE_REG(regs.pstate)) {
    u32 mode = (*(u32*)valp) & PSR_AA32_MODE_MASK;
    switch (mode) {
      case PSR_AA32_MODE_USR:
      case PSR_AA32_MODE_FIQ:
      case PSR_AA32_MODE_IRQ:
      case PSR_AA32_MODE_SVC:
      case PSR_AA32_MODE_ABT:
      case PSR_AA32_MODE_UND:
      case PSR_MODE_EL0t:
      case PSR_MODE_EL1t:
      case PSR_MODE_EL1h:
        break;
      default:
        err = -EINVAL;
        goto out;
    }
  }
  memcpy((u32*)regs + off, valp, KVM_REG_SIZE(reg->id));
out:
  return err;
}

static struct rpmsg_device* rpmsg_virtio_add_ctrl_dev(
    struct virtio_device* vdev) {
  struct virtproc_info* vrp = vdev->priv;
  struct virtio_rpmsg_channel* vch;
  struct rpmsg_device* rpdev_ctrl;
  int err = 0;
  vch = kzalloc(sizeof(*vch), GFP_KERNEL);
  if (!vch) return ERR_PTR(-ENOMEM);
  vch->vrp = vrp;
  rpdev_ctrl = &vch->rpdev;
  rpdev_ctrl->ops = &virtio_rpmsg_ops;
  rpdev_ctrl->dev.parent = &vrp->vdev->dev;
  rpdev_ctrl->dev.release = virtio_rpmsg_release_device;
  rpdev_ctrl->little_endian = virtio_is_little_endian(vrp->vdev);
  err = rpmsg_ctrldev_register_device(rpdev_ctrl);
  if (err) {
    kfree(vch);
    return ERR_PTR(err);
  }
  return rpdev_ctrl;
}

static int oidc_cache_crypto_decrypt(request_rec* r, const char* cache_value,
                                     unsigned char* key,
                                     unsigned char** plaintext) {
  int len = -1;
  char* encoded_tag = strstr(cache_value, ".");
  if (encoded_tag == NULL) {
    oidc_error(
        r, "corrupted cache value: no tag separator found in encrypted value");
    return FALSE;
  }
  cache_value = apr_pstrmemdup(r->pool, cache_value,
                               strlen(cache_value) - strlen(encoded_tag));
  encoded_tag++;
  char* d_bytes = NULL;
  int d_len = oidc_base64url_decode(r->pool, &d_bytes, cache_value);
  char* t_bytes = NULL;
  int t_len = oidc_base64url_decode(r->pool, &t_bytes, encoded_tag);
  if ((d_len > 0) && (t_len > 0)) {
    *plaintext = apr_pcalloc(
        r->pool, (d_len + EVP_CIPHER_block_size(OIDC_CACHE_CIPHER) - 1));
    len = oidc_cache_crypto_decrypt_impl(
        r, (unsigned char*)d_bytes, d_len, OIDC_CACHE_CRYPTO_GCM_AAD,
        sizeof(OIDC_CACHE_CRYPTO_GCM_AAD), (unsigned char*)t_bytes, t_len, key,
        OIDC_CACHE_CRYPTO_GCM_IV, sizeof(OIDC_CACHE_CRYPTO_GCM_IV), *plaintext);
    if (len > -1) {
      (*plaintext)[len] = '\0';
    } else {
      *plaintext = NULL;
    }
  }
  return len;
}

