static int mxf_read_primer_pack(void* arg, AVIOContext* pb, int tag, int size,
                                UID uid, int64_t klv_offset) {
  MXFContext* mxf = arg;
  int item_num = avio_rb32(pb);
  int item_len = avio_rb32(pb);
  if (item_len != 18) {
    avpriv_request_sample(pb, "Primer pack item length %d", item_len);
    return AVERROR_PATCHWELCOME;
  }
  if (item_num > 65536) {
    av_log(mxf->fc, AV_LOG_ERROR, "item_num %d is too large\n", item_num);
    return AVERROR_INVALIDDATA;
  }
  mxf->local_tags = av_calloc(item_num, item_len);
  if (!mxf->local_tags) return AVERROR(ENOMEM);
  mxf->local_tags_count = item_num;
  avio_read(pb, mxf->local_tags, item_num * item_len);
  return 0;
}

void UTFstring::UpdateFromUTF8() {
  delete[] _Data;
  size_t i;
  for (_Length = 0, i = 0; i < UTF8string.length(); _Length++) {
    uint8 lead = static_cast<uint8>(UTF8string[i]);
    if (lead < 0x80)
      i++;
    else if ((lead >> 5) == 0x6)
      i += 2;
    else if ((lead >> 4) == 0xe)
      i += 3;
    else if ((lead >> 3) == 0x1e)
      i += 4;
    else
      break;
  }
  _Data = new wchar_t[_Length + 1];
  size_t j;
  for (j = 0, i = 0; i < UTF8string.length(); j++) {
    uint8 lead = static_cast<uint8>(UTF8string[i]);
    if (lead < 0x80) {
      _Data[j] = lead;
      i++;
    } else if ((lead >> 5) == 0x6) {
      _Data[j] = ((lead & 0x1F) << 6) + (UTF8string[i + 1] & 0x3F);
      i += 2;
    } else if ((lead >> 4) == 0xe) {
      _Data[j] = ((lead & 0x0F) << 12) + ((UTF8string[i + 1] & 0x3F) << 6) +
                 (UTF8string[i + 2] & 0x3F);
      i += 3;
    } else if ((lead >> 3) == 0x1e) {
      _Data[j] = ((lead & 0x07) << 18) + ((UTF8string[i + 1] & 0x3F) << 12) +
                 ((UTF8string[i + 2] & 0x3F) << 6) + (UTF8string[i + 3] & 0x3F);
      i += 4;
    } else
      break;
  }
  _Data[j] = 0;
}

static char* ConcatHttpHeaders(HTTP_HEADERS_HANDLE httpHeadersHandle,
                               size_t toAlloc, size_t headersCount) {
  char* result = (char*)malloc(toAlloc * sizeof(char) + 1);
  size_t i;
  if (result == NULL) {
    LogError("unable to malloc");
  } else {
    result[0] = '\0';
    for (i = 0; i < headersCount; i++) {
      char* temp;
      if (HTTPHeaders_GetHeader(httpHeadersHandle, i, &temp) !=
          HTTP_HEADERS_OK) {
        LogError("unable to HTTPHeaders_GetHeader");
        break;
      } else {
        (void)strcat(result, temp);
        (void)strcat(result, "\r\n");
        free(temp);
      }
    }
    if (i < headersCount) {
      free(result);
      result = NULL;
    } else {
    }
  }
  return result;
}

static SQInteger thread_call(HSQUIRRELVM v) {
  SQObjectPtr o = stack_get(v, 1);
  if (sq_type(o) == OT_THREAD) {
    SQInteger nparams = sq_gettop(v);
    _thread(o)->Push(_thread(o)->_roottable);
    for (SQInteger i = 2; i < (nparams + 1); i++) sq_move(_thread(o), v, i);
    if (SQ_SUCCEEDED(sq_call(_thread(o), nparams, SQTrue, SQTrue))) {
      sq_move(v, _thread(o), -1);
      sq_pop(_thread(o), 1);
      return 1;
    }
    v->_lasterror = _thread(o)->_lasterror;
    return SQ_ERROR;
  }
  return sq_throwerror(v, _SC("wrong parameter"));
}

