void operator()(OpKernelContext* ctx, const Index num_segments,
                const TensorShape& segment_ids_shape,
                typename TTypes<Index>::ConstFlat segment_ids,
                const Index data_size, const T* data,
                typename TTypes<T, 2>::Tensor output) {
  output.setConstant(InitialValueF()());
  if (data_size == 0) {
    return;
  }
  const int64 N = segment_ids.dimension(0);
  ReductionF reduction;
  auto data_flat = typename TTypes<T, 2>::ConstTensor(data, N, data_size / N);
  for (int64 i = 0; i < N; ++i) {
    Index j = internal::SubtleMustCopy(segment_ids(i));
    if (j < 0) {
      continue;
    }
    OP_REQUIRES(ctx, FastBoundsCheck(j, num_segments),
                errors::InvalidArgument(
                    "segment_ids", SliceDebugString(segment_ids_shape, i),
                    " = ", j, " is out of range [0, ", num_segments, ")"));
    reduction(data_flat.template chip<0>(i), output.template chip<0>(j));
  }
}

void ValidateInputs(OpKernelContext* ctx, const CSRSparseMatrix& sparse_matrix,
                    const Tensor& permutation_indices, int* batch_size,
                    int64* num_rows) {
  OP_REQUIRES(ctx, sparse_matrix.dtype() == DataTypeToEnum<T>::value,
              errors::InvalidArgument(
                  "Asked for a CSRSparseMatrix of type ",
                  DataTypeString(DataTypeToEnum<T>::value),
                  " but saw dtype: ", DataTypeString(sparse_matrix.dtype())));
  const Tensor& dense_shape = sparse_matrix.dense_shape();
  const int rank = dense_shape.dim_size(0);
  OP_REQUIRES(ctx, rank == 2 || rank == 3,
              errors::InvalidArgument("sparse matrix must have rank 2 or 3; ",
                                      "but dense_shape has size ", rank));
  const int row_dim = (rank == 2) ? 0 : 1;
  auto dense_shape_vec = dense_shape.vec<int64>();
  *num_rows = dense_shape_vec(row_dim);
  const int64 num_cols = dense_shape_vec(row_dim + 1);
  OP_REQUIRES(ctx, *num_rows == num_cols,
              errors::InvalidArgument("sparse matrix must be square; got: ",
                                      *num_rows, " != ", num_cols));
  const TensorShape& perm_shape = permutation_indices.shape();
  OP_REQUIRES(ctx, perm_shape.dims() + 1 == rank,
              errors::InvalidArgument(
                  "sparse matrix must have the same rank as permutation; got: ",
                  rank, " != ", perm_shape.dims(), " + 1."));
  OP_REQUIRES(
      ctx, perm_shape.dim_size(rank - 2) == *num_rows,
      errors::InvalidArgument(
          "permutation must have the same number of elements in each batch "
          "as the number of rows in sparse matrix; got: ",
          perm_shape.dim_size(rank - 2), " != ", *num_rows));
  *batch_size = sparse_matrix.batch_size();
  if (*batch_size > 1) {
    OP_REQUIRES(
        ctx, perm_shape.dim_size(0) == *batch_size,
        errors::InvalidArgument("permutation must have the same batch size "
                                "as sparse matrix; got: ",
                                perm_shape.dim_size(0), " != ", *batch_size));
  }
}

ECDSA_Signature_Operation::raw_sign(const uint8_t msg[], size_t msg_len,
                                    RandomNumberGenerator& rng) {
  BigInt m(msg, msg_len, m_group.get_order_bits());
#if defined(BOTAN_HAS_RFC6979_GENERATOR)
  const BigInt k =
      generate_rfc6979_nonce(m_x, m_group.get_order(), m, m_rfc6979_hash);
#else
  const BigInt k = m_group.random_scalar(rng);
#endif
  const BigInt k_inv = m_group.inverse_mod_order(k);
  const BigInt r =
      m_group.mod_order(m_group.blinded_base_point_multiply_x(k, rng, m_ws));
  const BigInt xrm = m_group.mod_order(m_group.multiply_mod_order(m_x, r) + m);
  const BigInt s = m_group.multiply_mod_order(k_inv, xrm);
  if (r.is_zero() || s.is_zero())
    throw Internal_Error("During ECDSA signature generated zero r/s");
  return BigInt::encode_fixed_length_int_pair(r, s, m_group.get_order_bytes());
}

void FontInfoScanner::scanFonts(XRef* xrefA, Dict* resDict,
                                std::vector<FontInfo*>* fontsList) {
  GfxFontDict* gfxFontDict;
  GfxFont* font;
  gfxFontDict = nullptr;
  const Object& fontObj = resDict->lookupNF("Font");
  if (fontObj.isRef()) {
    Object obj2 = fontObj.fetch(xrefA);
    if (obj2.isDict()) {
      Ref r = fontObj.getRef();
      gfxFontDict = new GfxFontDict(xrefA, &r, obj2.getDict());
    }
  } else if (fontObj.isDict()) {
    gfxFontDict = new GfxFontDict(xrefA, nullptr, fontObj.getDict());
  }
  if (gfxFontDict) {
    for (int i = 0; i < gfxFontDict->getNumFonts(); ++i) {
      if ((font = gfxFontDict->getFont(i))) {
        Ref fontRef = *font->getID();
        if (fonts.find(fontRef.num) == fonts.end()) {
          fontsList->push_back(new FontInfo(font, xrefA));
          fonts.insert(fontRef.num);
        }
      }
    }
    delete gfxFontDict;
  }
  const char* resTypes[] = {"XObject", "Pattern"};
  for (unsigned int resType = 0;
       resType < sizeof(resTypes) / sizeof(resTypes[0]); ++resType) {
    Object objDict = resDict->lookup(resTypes[resType]);
    if (objDict.isDict()) {
      for (int i = 0; i < objDict.dictGetLength(); ++i) {
        const Object& dictObjI = objDict.dictGetValNF(i);
        if (dictObjI.isRef()) {
          const Ref r = dictObjI.getRef();
          if (visitedObjects.find(r.num) != visitedObjects.end()) {
            continue;
          }
          visitedObjects.insert(r.num);
        }
        Object obj2 = dictObjI.fetch(xrefA);
        if (obj2.isStream()) {
          Object resObj = obj2.streamGetDict()->lookup("Resources");
          if (resObj.isDict() && resObj.getDict() != resDict) {
            scanFonts(xrefA, resObj.getDict(), fontsList);
          }
        }
      }
    }
  }
}

