UNCURL_EXPORT int32_t uncurl_ws_accept(struct uncurl_conn* ucc, char** origins,
                                       int32_t n_origins) {
  int32_t e;
  e = uncurl_read_header(ucc);
  if (e != UNCURL_OK) return e;
  uncurl_set_header_str(ucc, "Upgrade", "websocket");
  uncurl_set_header_str(ucc, "Connection", "Upgrade");
  char* origin = NULL;
  e = uncurl_get_header_str(ucc, "Origin", &origin);
  if (e != UNCURL_OK) return e;
  bool origin_ok = false;
  for (int32_t x = 0; x < n_origins; x++)
    if (strstr(origin, origins[x])) {
      origin_ok = true;
      break;
    }
  if (!origin_ok) return UNCURL_WS_ERR_ORIGIN;
  char* sec_key = NULL;
  e = uncurl_get_header_str(ucc, "Sec-WebSocket-Key", &sec_key);
  if (e != UNCURL_OK) return e;
  char* accept_key = ws_create_accept_key(sec_key);
  uncurl_set_header_str(ucc, "Sec-WebSocket-Accept", accept_key);
  free(accept_key);
  e = uncurl_write_header(ucc, "101", "Switching Protocols", UNCURL_RESPONSE);
  if (e != UNCURL_OK) return e;
  ucc->ws_mask = 0;
  return UNCURL_OK;
}

static void process_constructors(RBinFile* bf, RList* ret, int bits) {
  RList* secs = sections(bf);
  RListIter* iter;
  RBinSection* sec;
  int i, type;
  r_list_foreach(secs, iter, sec) {
    type = -1;
    if (!strcmp(sec->name, ".fini_array")) {
      type = R_BIN_ENTRY_TYPE_FINI;
    } else if (!strcmp(sec->name, ".init_array")) {
      type = R_BIN_ENTRY_TYPE_INIT;
    } else if (!strcmp(sec->name, ".preinit_array")) {
      type = R_BIN_ENTRY_TYPE_PREINIT;
    }
    if (type != -1) {
      ut8* buf = calloc(sec->size, 1);
      if (!buf) {
        continue;
      }
      (void)r_buf_read_at(bf->buf, sec->paddr, buf, sec->size);
      if (bits == 32) {
        for (i = 0; i < sec->size; i += 4) {
          ut32 addr32 = r_read_le32(buf + i);
          if (addr32) {
            RBinAddr* ba = newEntry(sec->paddr + i, (ut64)addr32, type, bits);
            r_list_append(ret, ba);
          }
        }
      } else {
        for (i = 0; i < sec->size; i += 8) {
          ut64 addr64 = r_read_le64(buf + i);
          if (addr64) {
            RBinAddr* ba = newEntry(sec->paddr + i, addr64, type, bits);
            r_list_append(ret, ba);
          }
        }
      }
      free(buf);
    }
  }
  r_list_free(secs);
}

gss_delete_sec_context(minor_status, context_handle,
                       output_token) OM_uint32* minor_status;
gss_ctx_id_t* context_handle;
gss_buffer_t output_token;
{
  OM_uint32 status;
  gss_union_ctx_id_t ctx;
  status = val_del_sec_ctx_args(minor_status, context_handle, output_token);
  if (status != GSS_S_COMPLETE) return (status);
  ctx = (gss_union_ctx_id_t)*context_handle;
  if (GSSINT_CHK_LOOP(ctx))
    return (GSS_S_CALL_INACCESSIBLE_READ | GSS_S_NO_CONTEXT);
  status = gssint_delete_internal_sec_context(
      minor_status, ctx->mech_type, &ctx->internal_ctx_id, output_token);
  if (status) return status;
  free(ctx->mech_type->elements);
  free(ctx->mech_type);
  free(*context_handle);
  *context_handle = GSS_C_NO_CONTEXT;
  return (GSS_S_COMPLETE);
}

