static long btrfs_ioctl_dev_info(struct btrfs_fs_info* fs_info,
                                 void __user* arg) {
  struct btrfs_ioctl_dev_info_args* di_args;
  struct btrfs_device* dev;
  int ret = 0;
  char* s_uuid = NULL;
  di_args = memdup_user(arg, sizeof(*di_args));
  if (IS_ERR(di_args)) return PTR_ERR(di_args);
  if (!btrfs_is_empty_uuid(di_args->uuid)) s_uuid = di_args->uuid;
  rcu_read_lock();
  dev = btrfs_find_device(fs_info->fs_devices, di_args->devid, s_uuid, NULL);
  if (!dev) {
    ret = -ENODEV;
    goto out;
  }
  di_args->devid = dev->devid;
  di_args->bytes_used = btrfs_device_get_bytes_used(dev);
  di_args->total_bytes = btrfs_device_get_total_bytes(dev);
  memcpy(di_args->uuid, dev->uuid, sizeof(di_args->uuid));
  if (dev->name) {
    strncpy(di_args->path, rcu_str_deref(dev->name), sizeof(di_args->path) - 1);
    di_args->path[sizeof(di_args->path) - 1] = 0;
  } else {
    di_args->path[0] = '\0';
  }
out:
  rcu_read_unlock();
  if (ret == 0 && copy_to_user(arg, di_args, sizeof(*di_args))) ret = -EFAULT;
  kfree(di_args);
  return ret;
}

inline StreamWriteResult StreamBase::Write(uv_buf_t* bufs, size_t count,
                                           uv_stream_t* send_handle,
                                           v8::Local<v8::Object> req_wrap_obj) {
  Environment* env = stream_env();
  int err;
  size_t total_bytes = 0;
  for (size_t i = 0; i < count; ++i) total_bytes += bufs[i].len;
  bytes_written_ += total_bytes;
  if (send_handle == nullptr) {
    err = DoTryWrite(&bufs, &count);
    if (err != 0 || count == 0) {
      return StreamWriteResult{false, err, nullptr, total_bytes};
    }
  }
  HandleScope handle_scope(env->isolate());
  if (req_wrap_obj.IsEmpty()) {
    req_wrap_obj = env->write_wrap_template()
                       ->NewInstance(env->context())
                       .ToLocalChecked();
    StreamReq::ResetObject(req_wrap_obj);
  }
  AsyncHooks::DefaultTriggerAsyncIdScope trigger_scope(GetAsyncWrap());
  WriteWrap* req_wrap = CreateWriteWrap(req_wrap_obj);
  err = DoWrite(req_wrap, bufs, count, send_handle);
  bool async = err == 0;
  if (!async) {
    req_wrap->Dispose();
    req_wrap = nullptr;
  }
  const char* msg = Error();
  if (msg != nullptr) {
    req_wrap_obj->Set(env->error_string(), OneByteString(env->isolate(), msg));
    ClearError();
  }
  return StreamWriteResult{async, err, req_wrap, total_bytes};
}

