static void virtqueue_map_desc(unsigned int* p_num_sg, hwaddr* addr,
                               struct iovec* iov, unsigned int max_num_sg,
                               bool is_write, hwaddr pa, size_t sz) {
  unsigned num_sg = *p_num_sg;
  assert(num_sg <= max_num_sg);
  while (sz) {
    hwaddr len = sz;
    if (num_sg == max_num_sg) {
      error_report("virtio: too many write descriptors in indirect table");
      exit(1);
    }
    iov[num_sg].iov_base = cpu_physical_memory_map(pa, &len, is_write);
    iov[num_sg].iov_len = len;
    addr[num_sg] = pa;
    sz -= len;
    pa += len;
    num_sg++;
  }
  *p_num_sg = num_sg;
}

static mp_obj_t int_to_bytes(size_t n_args, const mp_obj_t* args) {
  (void)n_args;
  mp_int_t len = mp_obj_get_int(args[1]);
  if (len < 0) {
    mp_raise_ValueError(NULL);
  }
  bool big_endian = args[2] != MP_OBJ_NEW_QSTR(MP_QSTR_little);
  vstr_t vstr;
  vstr_init_len(&vstr, len);
  byte* data = (byte*)vstr.buf;
  memset(data, 0, len);
#if MICROPY_LONGINT_IMPL != MICROPY_LONGINT_IMPL_NONE
  if (!mp_obj_is_small_int(args[0])) {
    mp_obj_int_to_bytes_impl(args[0], big_endian, len, data);
  } else
#endif
  {
    mp_int_t val = MP_OBJ_SMALL_INT_VALUE(args[0]);
    size_t l = MIN((size_t)len, sizeof(val));
    mp_binary_set_int(l, big_endian, data + (big_endian ? (len - l) : 0), val);
  }
  return mp_obj_new_bytes_from_vstr(&vstr);
}

int MDC2_Update(MDC2_CTX* c, const unsigned char* in, size_t len) {
  size_t i, j;
  i = c->num;
  if (i != 0) {
    if (i + len < MDC2_BLOCK) {
      memcpy(&(c->data[i]), in, len);
      c->num += (int)len;
      return 1;
    } else {
      j = MDC2_BLOCK - i;
      memcpy(&(c->data[i]), in, j);
      len -= j;
      in += j;
      c->num = 0;
      mdc2_body(c, &(c->data[0]), MDC2_BLOCK);
    }
  }
  i = len & ~((size_t)MDC2_BLOCK - 1);
  if (i > 0) mdc2_body(c, in, i);
  j = len - i;
  if (j > 0) {
    memcpy(&(c->data[0]), &(in[i]), j);
    c->num = (int)j;
  }
  return 1;
}

static void ip_cmsg_recv_checksum(struct msghdr* msg, struct sk_buff* skb,
                                  int tlen, int offset) {
  __wsum csum = skb->csum;
  if (skb->ip_summed != CHECKSUM_COMPLETE) return;
  if (offset != 0)
    csum = csum_sub(csum,
                    csum_partial(skb_transport_header(skb) + tlen, offset, 0));
  put_cmsg(msg, SOL_IP, IP_CHECKSUM, sizeof(__wsum), &csum);
}

windows_icon_typefind(GstTypeFind* find, gpointer user_data) {
  const guint8* data;
  gint64 datalen;
  guint16 type, nimages;
  gint32 size, offset;
  datalen = gst_type_find_get_length(find);
  if ((data = gst_type_find_peek(find, 0, 6)) == NULL) return;
  if (GST_READ_UINT16_LE(data) != 0) return;
  type = GST_READ_UINT16_LE(data + 2);
  if (type != 1 && type != 2) return;
  nimages = GST_READ_UINT16_LE(data + 4);
  if (nimages == 0) return;
  if (data[6 + 3] != 0) return;
  if (type == 1) {
    guint16 planes = GST_READ_UINT16_LE(data + 6 + 4);
    if (planes > 1) return;
  }
  size = GST_READ_UINT32_LE(data + 6 + 8);
  offset = GST_READ_UINT32_LE(data + 6 + 12);
  if (offset < 0 || size <= 0 || size >= datalen || offset >= datalen ||
      size + offset > datalen)
    return;
  gst_type_find_suggest_simple(find, GST_TYPE_FIND_NEARLY_CERTAIN,
                               "image/x-icon", NULL);
}

