ExprResolveLhs(struct xkb_context* ctx, const ExprDef* expr,
               const char** elem_rtrn, const char** field_rtrn,
               ExprDef** index_rtrn) {
  switch (expr->expr.op) {
    case EXPR_IDENT:
      *elem_rtrn = NULL;
      *field_rtrn = xkb_atom_text(ctx, expr->ident.ident);
      *index_rtrn = NULL;
      return (*field_rtrn != NULL);
    case EXPR_FIELD_REF:
      *elem_rtrn = xkb_atom_text(ctx, expr->field_ref.element);
      *field_rtrn = xkb_atom_text(ctx, expr->field_ref.field);
      *index_rtrn = NULL;
      return true;
    case EXPR_ARRAY_REF:
      *elem_rtrn = xkb_atom_text(ctx, expr->array_ref.element);
      *field_rtrn = xkb_atom_text(ctx, expr->array_ref.field);
      *index_rtrn = expr->array_ref.entry;
      return true;
    default:
      break;
  }
  log_wsgo(ctx, "Unexpected operator %d in ResolveLhs\n", expr->expr.op);
  return false;
}

static MagickPixelPacket** AcquirePixelThreadSet(const Image* image) {
  MagickPixelPacket** pixels;
  register ssize_t i, j;
  size_t number_threads;
  number_threads = (size_t)GetMagickResourceLimit(ThreadResource);
  pixels = (MagickPixelPacket**)AcquireQuantumMemory(number_threads,
                                                     sizeof(*pixels));
  if (pixels == (MagickPixelPacket**)NULL) return ((MagickPixelPacket**)NULL);
  (void)memset(pixels, 0, number_threads * sizeof(*pixels));
  for (i = 0; i < (ssize_t)number_threads; i++) {
    pixels[i] = (MagickPixelPacket*)AcquireQuantumMemory(image->columns,
                                                         sizeof(**pixels));
    if (pixels[i] == (MagickPixelPacket*)NULL)
      return (DestroyPixelThreadSet(pixels));
    for (j = 0; j < (ssize_t)image->columns; j++)
      GetMagickPixelPacket(image, &pixels[i][j]);
  }
  return (pixels);
}

int anetUnixServer(char* err, char* path, mode_t perm, int backlog) {
  int s;
  struct sockaddr_un sa;
  if (strlen(path) > sizeof(sa.sun_path) - 1) {
    anetSetError(err, "unix socket path too long (%zu), must be under %zu",
                 strlen(path), sizeof(sa.sun_path));
    return ANET_ERR;
  }
  if ((s = anetCreateSocket(err, AF_LOCAL)) == ANET_ERR) return ANET_ERR;
  memset(&sa, 0, sizeof(sa));
  sa.sun_family = AF_LOCAL;
  redis_strlcpy(sa.sun_path, path, sizeof(sa.sun_path));
  if (anetListen(err, s, (struct sockaddr*)&sa, sizeof(sa), backlog) ==
      ANET_ERR)
    return ANET_ERR;
  if (perm) chmod(sa.sun_path, perm);
  return s;
}

quant::UniformQuantizedPerAxisType ResetAxisAndBroadcast(
    ArrayRef<int64_t> shape, quant::UniformQuantizedPerAxisType qtype,
    Type target, int quant_dim) {
  auto shaped = target.dyn_cast<RankedTensorType>();
  if (!shaped) return {};
  ArrayRef<int64_t> new_shape = shaped.getShape();
  SmallVector<double, 4> scales(qtype.getScales().begin(),
                                qtype.getScales().end());
  SmallVector<int64_t, 4> zero_points(qtype.getZeroPoints().begin(),
                                      qtype.getZeroPoints().end());
  if (new_shape.size() == shape.size()) {
    if (BroadcastVector<double>(shaped.getDimSize(quant_dim), scales) ||
        BroadcastVector<int64_t>(shaped.getDimSize(quant_dim), zero_points)) {
      return {};
    }
  } else if ((new_shape.size() == shape.size() + 1) && new_shape.back() == 1) {
    if (std::equal(shape.begin(), shape.end(), new_shape.begin()) &&
        quant_dim == -1) {
      quant_dim = shape.size() + quant_dim;
    } else {
      return {};
    }
  } else {
    return {};
  }
  return quant::UniformQuantizedPerAxisType::get(
      qtype.getFlags(), qtype.getStorageType(), qtype.getExpressedType(),
      scales, zero_points, quant_dim, qtype.getStorageTypeMin(),
      qtype.getStorageTypeMax());
}

static int websocket_send(lua_State* L) {
  lastCFunction = __func__;
  std::string str = checkstring(L, 1);
  if (config.http_max_websocket_message > 0 &&
      str.size() > (unsigned)config.http_max_websocket_message)
    luaL_error(L, "Message is too large");
  ws_handle* ws = *(ws_handle**)lua_touserdata(L, lua_upvalueindex(1));
  if (ws == NULL) luaL_error(L, "attempt to use a closed file");
  std::lock_guard<std::mutex> lock(ws->lock);
  if (ws->ws == NULL) return luaL_error(L, "attempt to use a closed file");
  if (ws->ws->sendFrame(
          str.c_str(), str.size(),
          (int)WebSocket::FRAME_FLAG_FIN |
              (int)(lua_toboolean(L, 2) ? WebSocket::FRAME_BINARY
                                        : WebSocket::FRAME_TEXT)) < 1)
    websocket_close(L);
  return 0;
}

