static inline int check_entry_size_and_hooks(struct arpt_entry* e,
                                             struct xt_table_info* newinfo,
                                             const unsigned char* base,
                                             const unsigned char* limit,
                                             const unsigned int* hook_entries,
                                             const unsigned int* underflows,
                                             unsigned int valid_hooks) {
  unsigned int h;
  int err;
  if ((unsigned long)e % __alignof__(struct arpt_entry) != 0 ||
      (unsigned char*)e + sizeof(struct arpt_entry) >= limit) {
    duprintf("Bad offset %p\n", e);
    return -EINVAL;
  }
  if (e->next_offset <
      sizeof(struct arpt_entry) + sizeof(struct xt_entry_target)) {
    duprintf("checking: element %p size %u\n", e, e->next_offset);
    return -EINVAL;
  }
  err = check_entry(e);
  if (err) return err;
  for (h = 0; h < NF_ARP_NUMHOOKS; h++) {
    if (!(valid_hooks & (1 << h))) continue;
    if ((unsigned char*)e - base == hook_entries[h])
      newinfo->hook_entry[h] = hook_entries[h];
    if ((unsigned char*)e - base == underflows[h]) {
      if (!check_underflow(e)) {
        pr_err(
            "Underflows must be unconditional and "
            "use the STANDARD target with "
            "ACCEPT/DROP\n");
        return -EINVAL;
      }
      newinfo->underflow[h] = underflows[h];
    }
  }
  e->counters = ((struct xt_counters){0, 0});
  e->comefrom = 0;
  return 0;
}

Jsi_RC jsi_evalcode(jsi_Pstate* ps, Jsi_Func* func, Jsi_OpCodes* opcodes,
                    jsi_ScopeChain* scope, Jsi_Value* fargs, Jsi_Value* _this,
                    Jsi_Value** vret) {
  Jsi_Interp* interp = ps->interp;
  if (interp->exited) return JSI_ERROR;
  Jsi_RC rc;
  jsi_Frame frame = *interp->framePtr;
  frame.parent = interp->framePtr;
  interp->framePtr = &frame;
  frame.parent->child = interp->framePtr = &frame;
  frame.ps = ps;
  frame.ingsc = scope;
  frame.incsc = fargs;
  frame.inthis = _this;
  frame.opcodes = opcodes;
  frame.fileName = ((func && func->script) ? func->script : interp->curFile);
  frame.funcName = interp->curFunction;
  frame.dirName = interp->curDir;
  if (frame.fileName && frame.fileName == frame.parent->fileName)
    frame.logflag = frame.parent->logflag;
  else
    frame.logflag = 0;
  frame.level = frame.parent->level + 1;
  frame.evalFuncPtr = func;
  frame.arguments = NULL;
  if (interp->curIp) frame.parent->line = interp->curIp->Line;
  frame.ip = interp->curIp;
  interp->refCount++;
  interp->level++;
  Jsi_IncrRefCount(interp, fargs);
  rc = jsi_evalcode_sub(ps, opcodes, scope, fargs, _this, *vret);
  Jsi_DecrRefCount(interp, fargs);
  if (interp->didReturn == 0 && !interp->exited) {
    if ((interp->evalFlags & JSI_EVAL_RETURN) == 0)
      Jsi_ValueMakeUndef(interp, vret);
  }
  if (frame.arguments) Jsi_DecrRefCount(interp, frame.arguments);
  interp->didReturn = 0;
  interp->refCount--;
  interp->level--;
  interp->framePtr = frame.parent;
  interp->framePtr->child = NULL;
  interp->curIp = frame.ip;
  if (interp->exited) rc = JSI_ERROR;
  return rc;
}

videobuf_vm_close(struct vm_area_struct* vma) {
  struct videobuf_mapping* map = vma->vm_private_data;
  struct videobuf_queue* q = map->q;
  int i;
  dprintk(2, "vm_close %p [count=%d,vma=%08lx-%08lx]\n", map, map->count,
          vma->vm_start, vma->vm_end);
  map->count--;
  if (0 == map->count) {
    dprintk(1, "munmap %p q=%p\n", map, q);
    mutex_lock(&q->lock);
    for (i = 0; i < VIDEO_MAX_FRAME; i++) {
      if (NULL == q->bufs[i]) continue;
      if (q->bufs[i]->map != map) continue;
      q->ops->buf_release(q, q->bufs[i]);
      q->bufs[i]->map = NULL;
      q->bufs[i]->baddr = 0;
    }
    mutex_unlock(&q->lock);
    kfree(map);
  }
  return;
}

static bool malidp_check_pages_threshold(struct malidp_plane_state* ms,
                                         u32 pgsize) {
  int i;
  for (i = 0; i < ms->n_planes; i++) {
    struct drm_gem_object* obj;
    struct drm_gem_cma_object* cma_obj;
    struct sg_table* sgt;
    struct scatterlist* sgl;
    obj = drm_gem_fb_get_obj(ms->base.fb, i);
    cma_obj = to_drm_gem_cma_obj(obj);
    if (cma_obj->sgt)
      sgt = cma_obj->sgt;
    else
      sgt = obj->funcs->get_sg_table(obj);
    if (!sgt) return false;
    sgl = sgt->sgl;
    while (sgl) {
      if (sgl->length < pgsize) {
        if (!cma_obj->sgt) kfree(sgt);
        return false;
      }
      sgl = sg_next(sgl);
    }
    if (!cma_obj->sgt) kfree(sgt);
  }
  return true;
}

void log_flush(LOG_MODE new_mode) {
  CRYPTO_THREAD_write_lock(stunnel_locks[LOCK_LOG_MODE]);
  if (log_mode != LOG_MODE_CONFIGURED || new_mode != LOG_MODE_ERROR)
    log_mode = new_mode;
  if (new_mode != LOG_MODE_BUFFER) {
    CRYPTO_THREAD_write_lock(stunnel_locks[LOCK_LOG_BUFFER]);
    while (head) {
      struct LIST* tmp = head;
      head = head->next;
      log_raw(tmp->opt, tmp->level, tmp->stamp, tmp->id, tmp->text);
      str_free(tmp);
    }
    head = tail = NULL;
    CRYPTO_THREAD_unlock(stunnel_locks[LOCK_LOG_BUFFER]);
  }
  CRYPTO_THREAD_unlock(stunnel_locks[LOCK_LOG_MODE]);
}

__u32 secure_tcpv6_sequence_number(__be32* saddr, __be32* daddr, __be16 sport,
                                   __be16 dport) {
  __u32 seq;
  __u32 hash[12];
  struct keydata* keyptr = get_keyptr();
  memcpy(hash, saddr, 16);
  hash[4] = ((__force u16)sport << 16) + (__force u16)dport;
  memcpy(&hash[5], keyptr->secret, sizeof(__u32) * 7);
  seq = twothirdsMD4Transform((const __u32*)daddr, hash) & HASH_MASK;
  seq += keyptr->count;
  seq += ktime_to_ns(ktime_get_real());
  return seq;
}

