int sock_initaddress(const char* host, const char* port, struct addrinfo* hints,
                     struct addrinfo** addrinfo, char* errbuf, int errbuflen) {
  int retval;
  retval = getaddrinfo(host, port == NULL ? "0" : port, hints, addrinfo);
  if (retval != 0) {
    if (errbuf) {
      if (host != NULL && port != NULL) {
        int try_retval;
        try_retval = getaddrinfo(host, NULL, hints, addrinfo);
        if (try_retval == 0) {
          freeaddrinfo(*addrinfo);
          get_gai_errstring(errbuf, errbuflen, "", retval, NULL, port);
        } else {
          get_gai_errstring(errbuf, errbuflen, "", retval, host, NULL);
        }
      } else {
        get_gai_errstring(errbuf, errbuflen, "", retval, host, port);
      }
    }
    return -1;
  }
  if (((*addrinfo)->ai_family != PF_INET) &&
      ((*addrinfo)->ai_family != PF_INET6)) {
    if (errbuf)
      snprintf(errbuf, errbuflen, "getaddrinfo(): socket type not supported");
    freeaddrinfo(*addrinfo);
    *addrinfo = NULL;
    return -1;
  }
  if (((*addrinfo)->ai_socktype == SOCK_STREAM) &&
      (sock_ismcastaddr((*addrinfo)->ai_addr) == 0)) {
    if (errbuf)
      snprintf(errbuf, errbuflen,
               "getaddrinfo(): multicast addresses are not valid when using "
               "TCP streams");
    freeaddrinfo(*addrinfo);
    *addrinfo = NULL;
    return -1;
  }
  return 0;
}

int mesg_make_query(u_char* qname, uint16_t qtype, uint16_t qclass, uint32_t id,
                    int rd, u_char* buf, int buflen) {
  char* fn = "mesg_make_query()";
  u_char* ucp;
  int i, written_len;
  Mesg_Hdr* hdr;
  if (T.debug > 4)
    syslog(LOG_DEBUG, "%s: (qtype: %s, id: %d): start", fn, string_rtype(qtype),
           id);
  hdr = (Mesg_Hdr*)buf;
  hdr->id = id;
  hdr->opcode = OP_QUERY;
  hdr->rcode = RC_OK;
  hdr->rd = rd;
  hdr->qr = hdr->aa = hdr->tc = hdr->ra = hdr->zero = 0;
  hdr->qdcnt = ntohs(1);
  hdr->ancnt = hdr->nscnt = hdr->arcnt = ntohs(0);
  written_len = sizeof(Mesg_Hdr);
  ucp = (u_char*)(hdr + 1);
  if (T.debug > 4) syslog(LOG_DEBUG, "%s: qname offset = %zd", fn, ucp - buf);
  i = dname_copy(qname, ucp, buflen - written_len);
  if (i < 0) return -1;
  written_len += i;
  ucp += i;
  if (T.debug > 4)
    syslog(LOG_DEBUG, "%s: qtype/qclass offset = %zd", fn, ucp - buf);
  written_len += sizeof(uint16_t) * 2;
  if (written_len > buflen) return -1;
  PUTSHORT(qtype, ucp);
  PUTSHORT(qclass, ucp);
  return written_len;
}

netdutils::Status XfrmController::ipSecSetEncapSocketOwner(
    const android::base::unique_fd& socket, int newUid, uid_t callerUid) {
  ALOGD("XfrmController:%s, line=%d", __FUNCTION__, __LINE__);
  const int fd = socket.get();
  struct stat info;
  if (fstat(fd, &info)) {
    return netdutils::statusFromErrno(errno,
                                      "Failed to stat socket file descriptor");
  }
  if (info.st_uid != callerUid) {
    return netdutils::statusFromErrno(EPERM,
                                      "fchown disabled for non-owner calls");
  }
  if (S_ISSOCK(info.st_mode) == 0) {
    return netdutils::statusFromErrno(EINVAL,
                                      "File descriptor was not a socket");
  }
  int optval;
  socklen_t optlen;
  netdutils::Status status = getSyscallInstance().getsockopt(
      Fd(socket), IPPROTO_UDP, UDP_ENCAP, &optval, &optlen);
  if (status != netdutils::status::ok) {
    return status;
  }
  if (optval != UDP_ENCAP_ESPINUDP && optval != UDP_ENCAP_ESPINUDP_NON_IKE) {
    return netdutils::statusFromErrno(
        EINVAL, "Socket did not have UDP-encap sockopt set");
  }
  if (fchown(fd, newUid, -1)) {
    return netdutils::statusFromErrno(
        errno, "Failed to fchown socket file descriptor");
  }
  return netdutils::status::ok;
}

print_bacp_config_options(netdissect_options* ndo, const u_char* p,
                          int length) {
  int len, opt;
  if (length < 2) return 0;
  ND_TCHECK2(*p, 2);
  len = p[1];
  opt = p[0];
  if (length < len) return 0;
  if (len < 2) {
    ND_PRINT(
        (ndo,
         "\n\t  %s Option (0x%02x), length %u (length bogus, should be >= 2)",
         tok2str(bacconfopts_values, "Unknown", opt), opt, len));
    return 0;
  }
  ND_PRINT((ndo, "\n\t  %s Option (0x%02x), length %u",
            tok2str(bacconfopts_values, "Unknown", opt), opt, len));
  switch (opt) {
    case BACPOPT_FPEER:
      if (len != 6) {
        ND_PRINT((ndo, " (length bogus, should be = 6)"));
        return len;
      }
      ND_TCHECK2(*(p + 2), 4);
      ND_PRINT((ndo, ": Magic-Num 0x%08x", EXTRACT_32BITS(p + 2)));
      break;
    default:
      if (ndo->ndo_vflag < 2)
        print_unknown_data(ndo, &p[2], "\n\t    ", len - 2);
      break;
  }
  if (ndo->ndo_vflag > 1) print_unknown_data(ndo, &p[2], "\n\t    ", len - 2);
  return len;
trunc:
  ND_PRINT((ndo, "[|bacp]"));
  return 0;
}

