do_macro(uschar* p) {
  int length;
  int nest = 0;
  argstr** pp;
  macrodef* md = misc_malloc(sizeof(macrodef));
  md->name = misc_readitem(p, NULL, &length, NULL, 0);
  md->namelength = Ustrlen(md->name);
  p += length;
  if (length == 0) {
    error(14);
    return;
  }
  md->lines = md->args = NULL;
  md->next = macrolist;
  macrolist = md;
  pp = &(md->args);
  while (*p != 0) {
    argstr* as = misc_malloc(sizeof(argstr));
    as->next = NULL;
    *pp = as;
    pp = &(as->next);
    as->string = misc_readitem(p, NULL, &length, NULL, 0);
    p += length;
  }
  pp = &(md->lines);
  for (;;) {
    argstr* as;
    uschar* line = read_nextline();
    if (line == NULL) {
      error(13, ".endmacro");
      return;
    }
    if (Ustrncmp(line, ".macro ", 7) == 0)
      nest++;
    else if (Ustrncmp(line, ".endmacro", 9) == 0) {
      if (isspace(line[9]) || line[9] == '\n')
        if (--nest < 0) break;
    }
    as = misc_malloc(sizeof(argstr));
    as->next = NULL;
    *pp = as;
    pp = &(as->next);
    as->string = misc_copystring(line, Ustrlen(line));
  }
  if (md->lines == NULL) {
    md->lines = misc_malloc(sizeof(argstr));
    md->lines->next = NULL;
    md->lines->string = misc_copystring(US ". Dummy line\n", 13);
  }
}

OFCondition operator()(ImagePixel& pixel) {
  (void)pixel;
  Uint16 rows = 0;
  Uint16 cols = 0;
  m_CT.getRows(rows);
  m_CT.getColumns(cols);
  const size_t numFrames = m_CT.m_Frames.size();
  const size_t numBytesFrame = m_CT.m_Frames[0]->length;
  const size_t numPixelsFrame = rows * cols;
  DcmPixelData* pixData = new DcmPixelData(DCM_PixelData);
  OFCondition result;
  if (pixData) {
    pixData->setVR(EVR_OW);
    Uint16* ptr = NULL;
    size_t numBytesTotal = numBytesFrame * numFrames / 2;
    if (numBytesTotal <= 4294967294UL) {
      result =
          pixData->createUint16Array(OFstatic_cast(Uint32, numBytesTotal), ptr);
      if (ptr) {
        for (size_t f = 0; f < numFrames; ++f) {
          memcpy(ptr, m_CT.m_Frames[f]->pixData, numBytesFrame);
          ptr += numPixelsFrame;
        }
        return m_Item.insert(pixData);
      }
    } else {
      result = FG_EC_PixelDataTooLarge;
      delete pixData;
    }
  }
  return result;
}

static void warnf(struct Configurable* config, const char* fmt, ...) {
  if (!(config->conf & CONF_MUTE)) {
    va_list ap;
    int len;
    char* ptr;
    char print_buffer[256];
    va_start(ap, fmt);
    va_start(ap, fmt);
    len = vsnprintf(print_buffer, sizeof(print_buffer), fmt, ap);
    va_end(ap);
    ptr = print_buffer;
    while (len > 0) {
      fputs(WARN_PREFIX, config->errors);
      if (len > (int)WARN_TEXTWIDTH) {
        int cut = WARN_TEXTWIDTH - 1;
        while (!ISSPACE(ptr[cut]) && cut) {
          cut--;
        }
        fwrite(ptr, cut + 1, 1, config->errors);
        fputs("\n", config->errors);
        ptr += cut + 1;
        len -= cut;
      } else {
        fputs(ptr, config->errors);
        len = 0;
      }
    }
  }
}

int nfc_dev_up(struct nfc_dev* dev) {
  int rc = 0;
  pr_debug("dev_name=%s\n", dev_name(&dev->dev));
  device_lock(&dev->dev);
  if (!device_is_registered(&dev->dev)) {
    rc = -ENODEV;
    goto error;
  }
  if (dev->rfkill && rfkill_blocked(dev->rfkill)) {
    rc = -ERFKILL;
    goto error;
  }
  if (dev->fw_download_in_progress) {
    rc = -EBUSY;
    goto error;
  }
  if (dev->dev_up) {
    rc = -EALREADY;
    goto error;
  }
  if (dev->ops->dev_up) rc = dev->ops->dev_up(dev);
  if (!rc) dev->dev_up = true;
  if (dev->ops->discover_se && dev->ops->discover_se(dev))
    pr_err("SE discovery failed\n");
error:
  device_unlock(&dev->dev);
  return rc;
}

dtls1_buffer_record(SSL* s, record_pqueue* queue, unsigned char* priority) {
  DTLS1_RECORD_DATA* rdata;
  pitem* item;
  if (pqueue_size(queue->q) >= 100) return 0;
  rdata = OPENSSL_malloc(sizeof(DTLS1_RECORD_DATA));
  item = pitem_new(priority, rdata);
  if (rdata == NULL || item == NULL) {
    if (rdata != NULL) OPENSSL_free(rdata);
    if (item != NULL) pitem_free(item);
    SSLerr(SSL_F_DTLS1_BUFFER_RECORD, ERR_R_INTERNAL_ERROR);
    return (0);
  }
  rdata->packet = s->packet;
  rdata->packet_length = s->packet_length;
  memcpy(&(rdata->rbuf), &(s->s3->rbuf), sizeof(SSL3_BUFFER));
  memcpy(&(rdata->rrec), &(s->s3->rrec), sizeof(SSL3_RECORD));
  item->data = rdata;
#ifndef OPENSSL_NO_SCTP
  if (BIO_dgram_is_sctp(SSL_get_rbio(s)) &&
      (s->state == SSL3_ST_SR_FINISHED_A ||
       s->state == SSL3_ST_CR_FINISHED_A)) {
    BIO_ctrl(SSL_get_rbio(s), BIO_CTRL_DGRAM_SCTP_GET_RCVINFO,
             sizeof(rdata->recordinfo), &rdata->recordinfo);
  }
#endif
  s->packet = NULL;
  s->packet_length = 0;
  memset(&(s->s3->rbuf), 0, sizeof(SSL3_BUFFER));
  memset(&(s->s3->rrec), 0, sizeof(SSL3_RECORD));
  if (!ssl3_setup_buffers(s)) {
    SSLerr(SSL_F_DTLS1_BUFFER_RECORD, ERR_R_INTERNAL_ERROR);
    OPENSSL_free(rdata);
    pitem_free(item);
    return (0);
  }
  if (pqueue_insert(queue->q, item) == NULL) {
    SSLerr(SSL_F_DTLS1_BUFFER_RECORD, ERR_R_INTERNAL_ERROR);
    OPENSSL_free(rdata);
    pitem_free(item);
    return (0);
  }
  return (1);
}

GIT_INLINE(bool)
verify_dotgit_ntfs(git_repository* repo, const char* path, size_t len) {
  git_buf* reserved = git_repository__reserved_names_win32;
  size_t reserved_len = git_repository__reserved_names_win32_len;
  size_t start = 0, i;
  if (repo)
    git_repository__reserved_names(&reserved, &reserved_len, repo, true);
  for (i = 0; i < reserved_len; i++) {
    git_buf* r = &reserved[i];
    if (len >= r->size && strncasecmp(path, r->ptr, r->size) == 0) {
      start = r->size;
      break;
    }
  }
  if (!start) return true;
  if (path[start] == '\\') return false;
  for (i = start; i < len; i++) {
    if (path[i] != ' ' && path[i] != '.') return true;
  }
  return false;
}

static int hash_accept(struct socket* sock, struct socket* newsock, int flags) {
  struct sock* sk = sock->sk;
  struct alg_sock* ask = alg_sk(sk);
  struct hash_ctx* ctx = ask->private;
  struct ahash_request* req = &ctx->req;
  char state[crypto_ahash_statesize(crypto_ahash_reqtfm(req))];
  struct sock* sk2;
  struct alg_sock* ask2;
  struct hash_ctx* ctx2;
  int err;
  err = crypto_ahash_export(req, state);
  if (err) return err;
  err = af_alg_accept(ask->parent, newsock);
  if (err) return err;
  sk2 = newsock->sk;
  ask2 = alg_sk(sk2);
  ctx2 = ask2->private;
  ctx2->more = 1;
  err = crypto_ahash_import(&ctx2->req, state);
  if (err) {
    sock_orphan(sk2);
    sock_put(sk2);
  }
  return err;
}

static ssize_t gadget_dev_desc_UDC_store(struct config_item* item,
                                         const char* page, size_t len) {
  struct gadget_info* gi = to_gadget_info(item);
  char* name;
  int ret;
  name = kstrdup(page, GFP_KERNEL);
  if (!name) return -ENOMEM;
  if (name[len - 1] == '\n') name[len - 1] = '\0';
  mutex_lock(&gi->lock);
  if (!strlen(name)) {
    ret = unregister_gadget(gi);
    if (ret) goto err;
    kfree(name);
  } else {
    if (gi->composite.gadget_driver.udc_name) {
      ret = -EBUSY;
      goto err;
    }
    gi->composite.gadget_driver.udc_name = name;
    ret = usb_gadget_probe_driver(&gi->composite.gadget_driver);
    if (ret) {
      gi->composite.gadget_driver.udc_name = NULL;
      goto err;
    }
  }
  mutex_unlock(&gi->lock);
  return len;
err:
  kfree(name);
  mutex_unlock(&gi->lock);
  return ret;
}

static bool php_mb_parse_encoding(const Variant& encoding,
                                  mbfl_encoding*** return_list,
                                  int* return_size, bool persistent) {
  bool ret;
  if (encoding.isArray()) {
    ret = php_mb_parse_encoding_array(encoding.toArray(), return_list,
                                      return_size, persistent ? 1 : 0);
  } else {
    String enc = encoding.toString();
    ret = php_mb_parse_encoding_list(enc.data(), enc.size(), return_list,
                                     return_size, persistent ? 1 : 0);
  }
  if (!ret) {
    if (return_list && *return_list) {
      free(*return_list);
      *return_list = nullptr;
    }
    return_size = 0;
  }
  return ret;
}

Status CompressElement(const std::vector<Tensor>& element,
                       CompressedElement* out) {
  std::vector<TensorProto> non_memcpy_components;
  int64 total_size = 0;
  for (auto& component : element) {
    if (DataTypeCanUseMemcpy(component.dtype())) {
      total_size += DMAHelper::buffer(&component)->size();
    } else {
      non_memcpy_components.emplace_back();
      component.AsProtoTensorContent(&non_memcpy_components.back());
      total_size += non_memcpy_components.back().ByteSizeLong();
    }
  }
  tstring uncompressed;
  uncompressed.resize_uninitialized(total_size);
  char* position = uncompressed.mdata();
  int non_memcpy_component_index = 0;
  for (auto& component : element) {
    CompressedComponentMetadata* metadata =
        out->mutable_component_metadata()->Add();
    metadata->set_dtype(component.dtype());
    component.shape().AsProto(metadata->mutable_tensor_shape());
    if (DataTypeCanUseMemcpy(component.dtype())) {
      const TensorBuffer* buffer = DMAHelper::buffer(&component);
      memcpy(position, buffer->data(), buffer->size());
      metadata->set_tensor_size_bytes(buffer->size());
    } else {
      TensorProto& proto = non_memcpy_components[non_memcpy_component_index++];
      proto.SerializeToArray(position, proto.ByteSizeLong());
      metadata->set_tensor_size_bytes(proto.ByteSizeLong());
    }
    position += metadata->tensor_size_bytes();
  }
  DCHECK_EQ(position, uncompressed.mdata() + total_size);
  if (!port::Snappy_Compress(uncompressed.mdata(), total_size,
                             out->mutable_data())) {
    return errors::Internal("Failed to compress using snappy.");
  }
  VLOG(3) << "Compressed element from " << total_size << " bytes to "
          << out->data().size() << " bytes";
  return Status::OK();
}

static int cms_copy_content(BIO* out, BIO* in, unsigned int flags) {
  unsigned char buf[4096];
  int r = 0, i;
  BIO* tmpout = NULL;
  if (out == NULL)
    tmpout = BIO_new(BIO_s_null());
  else if (flags & CMS_TEXT) {
    tmpout = BIO_new(BIO_s_mem());
    BIO_set_mem_eof_return(tmpout, 0);
  } else
    tmpout = out;
  if (!tmpout) {
    CMSerr(CMS_F_CMS_COPY_CONTENT, ERR_R_MALLOC_FAILURE);
    goto err;
  }
  for (;;) {
    i = BIO_read(in, buf, sizeof(buf));
    if (i <= 0) {
      if (BIO_method_type(in) == BIO_TYPE_CIPHER) {
        if (!BIO_get_cipher_status(in)) goto err;
      }
      if (i < 0) goto err;
      break;
    }
    if (tmpout && (BIO_write(tmpout, buf, i) != i)) goto err;
  }
  if (flags & CMS_TEXT) {
    if (!SMIME_text(tmpout, out)) {
      CMSerr(CMS_F_CMS_COPY_CONTENT, CMS_R_SMIME_TEXT_ERROR);
      goto err;
    }
  }
  r = 1;
err:
  if (tmpout && (tmpout != out)) BIO_free(tmpout);
  return r;
}

static __u8* cp_report_fixup(struct hid_device* hdev, __u8* rdesc,
                             unsigned int* rsize) {
  unsigned long quirks = (unsigned long)hid_get_drvdata(hdev);
  unsigned int i;
  if (!(quirks & CP_RDESC_SWAPPED_MIN_MAX)) return rdesc;
  for (i = 0; i < *rsize - 4; i++)
    if (rdesc[i] == 0x29 && rdesc[i + 2] == 0x19) {
      rdesc[i] = 0x19;
      rdesc[i + 2] = 0x29;
      swap(rdesc[i + 3], rdesc[i + 1]);
    }
  return rdesc;
}

selaGetCombName(SELA* sela, l_int32 size, l_int32 direction) {
  char* selname;
  char combname[L_BUF_SIZE];
  l_int32 i, nsels, sx, sy, found;
  SEL* sel;
  PROCNAME("selaGetCombName");
  if (!sela) return (char*)ERROR_PTR("sela not defined", procName, NULL);
  if (direction != L_HORIZ && direction != L_VERT)
    return (char*)ERROR_PTR("invalid direction", procName, NULL);
  if (direction == L_HORIZ)
    snprintf(combname, L_BUF_SIZE, "sel_comb_%dh", size);
  else
    snprintf(combname, L_BUF_SIZE, "sel_comb_%dv", size);
  found = FALSE;
  nsels = selaGetCount(sela);
  for (i = 0; i < nsels; i++) {
    sel = selaGetSel(sela, i);
    selGetParameters(sel, &sy, &sx, NULL, NULL);
    if (sy != 1 && sx != 1) continue;
    selname = selGetName(sel);
    if (!strcmp(selname, combname)) {
      found = TRUE;
      break;
    }
  }
  if (found)
    return stringNew(selname);
  else
    return (char*)ERROR_PTR("sel not found", procName, NULL);
}

