int32_t cli_bcapi_extract_new(struct cli_bc_ctx* ctx, int32_t id) {
  cli_ctx* cctx;
  int res = -1;
  cli_event_count(EV, BCEV_EXTRACTED);
  cli_dbgmsg("previous tempfile had %u bytes\n", ctx->written);
  if (!ctx->written) return 0;
  if (ctx->ctx && cli_updatelimits(ctx->ctx, ctx->written)) return -1;
  ctx->written = 0;
  lseek(ctx->outfd, 0, SEEK_SET);
  cli_dbgmsg("bytecode: scanning extracted file %s\n", ctx->tempfile);
  cctx = (cli_ctx*)ctx->ctx;
  if (cctx) {
    cli_file_t current = cctx->container_type;
    if (ctx->containertype != CL_TYPE_ANY)
      cctx->container_type = ctx->containertype;
    res = cli_magic_scandesc(ctx->outfd, cctx);
    cctx->container_type = current;
    if (res == CL_VIRUS) {
      if (cctx->virname) ctx->virname = *cctx->virname;
      ctx->found = 1;
    }
  }
  if ((cctx && cctx->engine->keeptmp) || (ftruncate(ctx->outfd, 0) == -1)) {
    close(ctx->outfd);
    if (!(cctx && cctx->engine->keeptmp) && ctx->tempfile)
      cli_unlink(ctx->tempfile);
    free(ctx->tempfile);
    ctx->tempfile = NULL;
    ctx->outfd = 0;
  }
  cli_dbgmsg("bytecode: extracting new file with id %u\n", id);
  return res;
}

Status GraphConstructor::MakeEdge(Node* src, int output_index, Node* dst,
                                  int input_index) {
  DataType src_out = src->output_type(output_index);
  DataType dst_in = dst->input_type(input_index);
  if (!TypesCompatible(dst_in, src_out)) {
    return errors::InvalidArgument(
        "Input ", input_index, " of node ", dst->name(), " was passed ",
        DataTypeString(src_out), " from ", src->name(), ":", output_index,
        " incompatible with expected ", DataTypeString(dst_in), ".");
  }
  g_->AddEdge(src, output_index, dst, input_index);
  return Status::OK();
}

get_matching_model_microcode(int cpu, unsigned long start, void* data,
                             size_t size, struct mc_saved_data* mc_saved_data,
                             unsigned long* mc_saved_in_initrd,
                             struct ucode_cpu_info* uci) {
  u8* ucode_ptr = data;
  unsigned int leftover = size;
  enum ucode_state state = UCODE_OK;
  unsigned int mc_size;
  struct microcode_header_intel* mc_header;
  struct microcode_intel* mc_saved_tmp[MAX_UCODE_COUNT];
  unsigned int mc_saved_count = mc_saved_data->mc_saved_count;
  int i;
  while (leftover) {
    mc_header = (struct microcode_header_intel*)ucode_ptr;
    mc_size = get_totalsize(mc_header);
    if (!mc_size || mc_size > leftover ||
        microcode_sanity_check(ucode_ptr, 0) < 0)
      break;
    leftover -= mc_size;
    if (matching_model_microcode(mc_header, uci->cpu_sig.sig) != UCODE_OK) {
      ucode_ptr += mc_size;
      continue;
    }
    _save_mc(mc_saved_tmp, ucode_ptr, &mc_saved_count);
    ucode_ptr += mc_size;
  }
  if (leftover) {
    state = UCODE_ERROR;
    goto out;
  }
  if (mc_saved_count == 0) {
    state = UCODE_NFOUND;
    goto out;
  }
  for (i = 0; i < mc_saved_count; i++)
    mc_saved_in_initrd[i] = (unsigned long)mc_saved_tmp[i] - start;
  mc_saved_data->mc_saved_count = mc_saved_count;
out:
  return state;
}

cmndlist_matches(const struct sudoers_parse_tree* parse_tree,
