  sock->state = SS_UNCONNECTED;
  if (sock->type != SOCK_SEQPACKET) return -ESOCKTNOSUPPORT;
  sock->ops = &sco_sock_ops;
  sk = sco_sock_alloc(net, sock, protocol, GFP_ATOMIC, kern);
