put_gray_rows(j_decompress_ptr cinfo, djpeg_dest_ptr dinfo,
              JDIMENSION rows_supplied) {
  bmp_dest_ptr dest = (bmp_dest_ptr)dinfo;
  JSAMPARRAY image_ptr;
  register JSAMPROW inptr, outptr;
  int pad;
  if (dest->use_inversion_array) {
    image_ptr = (*cinfo->mem->access_virt_sarray)(
        (j_common_ptr)cinfo, dest->whole_image, dest->cur_output_row,
        (JDIMENSION)1, TRUE);
    dest->cur_output_row++;
    outptr = image_ptr[0];
  } else {
    outptr = dest->iobuffer;
  }
  inptr = dest->pub.buffer[0];
  MEMCOPY(outptr, inptr, cinfo->output_width);
  outptr += cinfo->output_width;
  pad = dest->pad_bytes;
  while (--pad >= 0) *outptr++ = 0;
  if (!dest->use_inversion_array)
    (void)JFWRITE(dest->pub.output_file, dest->iobuffer, dest->row_width);
}

static int llc_ui_release(struct socket* sock) {
  struct sock* sk = sock->sk;
  struct llc_sock* llc;
  if (unlikely(sk == NULL)) goto out;
  sock_hold(sk);
  lock_sock(sk);
  llc = llc_sk(sk);
  dprintk("%s: closing local(%02X) remote(%02X)\n", __func__, llc->laddr.lsap,
          llc->daddr.lsap);
  if (!llc_send_disc(sk)) llc_ui_wait_for_disc(sk, sk->sk_rcvtimeo);
  if (!sock_flag(sk, SOCK_ZAPPED)) {
    llc_sap_put(llc->sap);
    llc_sap_remove_socket(llc->sap, sk);
  }
  release_sock(sk);
  if (llc->dev) dev_put(llc->dev);
  sock_put(sk);
  llc_sk_free(sk);
out:
  return 0;
}

void PrintWebViewHelper::OnPrintForPrintPreview(
    const base::DictionaryValue& job_settings) {
  CHECK_LE(ipc_nesting_level_, 1);
  if (prep_frame_view_) return;
  if (!render_view()->GetWebView()) return;
  blink::WebFrame* main_frame = render_view()->GetWebView()->mainFrame();
  if (!main_frame) return;
  blink::WebDocument document = main_frame->document();
  blink::WebElement pdf_element = document.getElementById("pdf-viewer");
  if (pdf_element.isNull()) {
    NOTREACHED();
    return;
  }
  blink::WebLocalFrame* plugin_frame = pdf_element.document().frame();
  blink::WebElement plugin_element = pdf_element;
  if (pdf_element.hasHTMLTagName("iframe")) {
    plugin_frame = blink::WebLocalFrame::fromFrameOwnerElement(pdf_element);
    plugin_element = delegate_->GetPdfElement(plugin_frame);
    if (plugin_element.isNull()) {
      NOTREACHED();
      return;
    }
  }
  base::AutoReset<bool> set_printing_flag(&print_for_preview_, true);
  if (!UpdatePrintSettings(plugin_frame, plugin_element, job_settings)) {
    LOG(ERROR) << "UpdatePrintSettings failed";
    DidFinishPrinting(FAIL_PRINT);
    return;
  }
  PrintMsg_Print_Params& print_params = print_pages_params_->params;
  print_params.printable_area = gfx::Rect(print_params.page_size);
  if (!RenderPagesForPrint(plugin_frame, plugin_element)) {
    LOG(ERROR) << "RenderPagesForPrint failed";
    DidFinishPrinting(FAIL_PRINT);
  }
}

static int manager_setup_time_change(Manager* m) {
  int r;
  struct itimerspec its = {
      .it_value.tv_sec = TIME_T_MAX,
  };
  assert(m);
  assert_cc(sizeof(time_t) == sizeof(TIME_T_MAX));
  if (m->test_run) return 0;
  m->time_change_fd =
      timerfd_create(CLOCK_REALTIME, TFD_NONBLOCK | TFD_CLOEXEC);
  if (m->time_change_fd < 0)
    return log_error_errno(errno, "Failed to create timerfd: %m");
  if (timerfd_settime(m->time_change_fd,
                      TFD_TIMER_ABSTIME | TFD_TIMER_CANCEL_ON_SET, &its,
                      NULL) < 0) {
    log_debug_errno(errno,
                    "Failed to set up TFD_TIMER_CANCEL_ON_SET, ignoring: %m");
    m->time_change_fd = safe_close(m->time_change_fd);
    return 0;
  }
  r = sd_event_add_io(m->event, &m->time_change_event_source, m->time_change_fd,
                      EPOLLIN, manager_dispatch_time_change_fd, m);
  if (r < 0)
    return log_error_errno(r, "Failed to create time change event source: %m");
  log_debug("Set up TFD_TIMER_CANCEL_ON_SET timerfd.");
  return 0;
}

