static int vhost_vdpa_mmap(struct file* file, struct vm_area_struct* vma) {
  struct vhost_vdpa* v = vma->vm_file->private_data;
  struct vdpa_device* vdpa = v->vdpa;
  const struct vdpa_config_ops* ops = vdpa->config;
  struct vdpa_notification_area notify;
  unsigned long index = vma->vm_pgoff;
  if (vma->vm_end - vma->vm_start != PAGE_SIZE) return -EINVAL;
  if ((vma->vm_flags & VM_SHARED) == 0) return -EINVAL;
  if (vma->vm_flags & VM_READ) return -EINVAL;
  if (index > 65535) return -EINVAL;
  if (!ops->get_vq_notification) return -ENOTSUPP;
  notify = ops->get_vq_notification(vdpa, index);
  if (notify.addr & (PAGE_SIZE - 1)) return -EINVAL;
  if (vma->vm_end - vma->vm_start != notify.size) return -ENOTSUPP;
  vma->vm_flags |= VM_IO | VM_PFNMAP | VM_DONTEXPAND | VM_DONTDUMP;
  vma->vm_ops = &vhost_vdpa_vm_ops;
  return 0;
}

static int tcp_check_dsack(struct sock* sk, const struct sk_buff* ack_skb,
                           struct tcp_sack_block_wire* sp, int num_sacks,
                           u32 prior_snd_una) {
  struct tcp_sock* tp = tcp_sk(sk);
  u32 start_seq_0 = get_unaligned_be32(&sp[0].start_seq);
  u32 end_seq_0 = get_unaligned_be32(&sp[0].end_seq);
  int dup_sack = 0;
  if (before(start_seq_0, TCP_SKB_CB(ack_skb)->ack_seq)) {
    dup_sack = 1;
    tcp_dsack_seen(tp);
    NET_INC_STATS_BH(sock_net(sk), LINUX_MIB_TCPDSACKRECV);
  } else if (num_sacks > 1) {
    u32 end_seq_1 = get_unaligned_be32(&sp[1].end_seq);
    u32 start_seq_1 = get_unaligned_be32(&sp[1].start_seq);
    if (!after(end_seq_0, end_seq_1) && !before(start_seq_0, start_seq_1)) {
      dup_sack = 1;
      tcp_dsack_seen(tp);
      NET_INC_STATS_BH(sock_net(sk), LINUX_MIB_TCPDSACKOFORECV);
    }
  }
  if (dup_sack && tp->undo_marker && tp->undo_retrans &&
      !after(end_seq_0, prior_snd_una) && after(end_seq_0, tp->undo_marker))
    tp->undo_retrans--;
  return dup_sack;
}

is_headerline(uint8_t* data, size_t size) {
  size_t i = 0;
  if (data[i] == '=') {
    for (i = 1; i < size && data[i] == '='; i++);
    while (i < size && data[i] == ' ') i++;
    return (i >= size || data[i] == '\n') ? 1 : 0;
  }
  if (data[i] == '-') {
    for (i = 1; i < size && data[i] == '-'; i++);
    while (i < size && data[i] == ' ') i++;
    return (i >= size || data[i] == '\n') ? 2 : 0;
  }
  return 0;
}

