  ASSERT(lt.matchesBSON(BSON("a" << BSON_ARRAY(BSON_ARRAY(4))), NULL));
  ASSERT(!lt.matchesBSON(BSON("a" << BSON_ARRAY(BSON_ARRAY(5))), NULL));
  ASSERT(!lt.matchesBSON(BSON("a" << BSON_ARRAY(BSON_ARRAY(6))), NULL));
}

static void update_branch_counts(struct bpf_verifier_env* env,
                                 struct bpf_verifier_state* st) {
  while (st) {
    u32 br = --st->branches;
    WARN_ONCE((int)br < 0, "BUG update_branch_counts:branches_to_explore=%d\n",
              br);
    if (br) break;
    st = st->parent;
  }
}

static void perform_renew(void) {
  bb_info_msg("Performing a DHCP renew");
  switch (state) {
    case BOUND:
      change_listen_mode(LISTEN_KERNEL);
    case RENEWING:
    case REBINDING:
      state = RENEW_REQUESTED;
      break;
    case RENEW_REQUESTED:
      udhcp_run_script(NULL, "deconfig");
    case REQUESTING:
    case RELEASED:
      change_listen_mode(LISTEN_RAW);
      state = INIT_SELECTING;
      break;
    case INIT_SELECTING:
      break;
  }
}

GF_Err senc_box_write(GF_Box* s, GF_BitStream* bs) {
  GF_Err e;
  u32 i;
  u32 sample_count, nb_crypt_samples;
  GF_SampleEncryptionBox* ptr = (GF_SampleEncryptionBox*)s;
  sample_count = gf_list_count(ptr->samp_aux_info);
  nb_crypt_samples = 0;
  for (i = 0; i < sample_count; i++) {
    GF_CENCSampleAuxInfo* sai =
        (GF_CENCSampleAuxInfo*)gf_list_get(ptr->samp_aux_info, i);
    if (!sai->isNotProtected) nb_crypt_samples++;
  }
  if (!nb_crypt_samples) {
    ptr->size = 0;
    return GF_OK;
  }
  e = gf_isom_box_write_header(s, bs);
  if (e) return e;
  gf_bs_write_u8(bs, ptr->version);
  gf_bs_write_u24(bs, ptr->flags);
  gf_bs_write_u32(bs, nb_crypt_samples);
  e = store_senc_info(ptr, bs);
  if (e) return e;
  for (i = 0; i < sample_count; i++) {
    GF_CENCSampleAuxInfo* sai =
        (GF_CENCSampleAuxInfo*)gf_list_get(ptr->samp_aux_info, i);
    if (sai->isNotProtected || !sai->cenc_data_size) continue;
    gf_bs_write_data(bs, sai->cenc_data, sai->cenc_data_size);
  }
  return GF_OK;
}

static NTSTATUS smb_set_info_standard(connection_struct* conn,
                                      const char* pdata, int total_data,
                                      files_struct* fsp,
                                      struct smb_filename* smb_fname) {
  NTSTATUS status;
  struct smb_file_time ft;
  init_smb_file_time(&ft);
  if (total_data < 12) {
    return NT_STATUS_INVALID_PARAMETER;
  }
  if (fsp == NULL) {
    return NT_STATUS_INVALID_HANDLE;
  }
  ft.create_time = time_t_to_full_timespec(srv_make_unix_date2(pdata));
  ft.atime = time_t_to_full_timespec(srv_make_unix_date2(pdata + 4));
  ft.mtime = time_t_to_full_timespec(srv_make_unix_date2(pdata + 8));
  DEBUG(10, ("smb_set_info_standard: file %s\n", smb_fname_str_dbg(smb_fname)));
  status = check_access_fsp(fsp, FILE_WRITE_ATTRIBUTES);
  if (!NT_STATUS_IS_OK(status)) {
    return status;
  }
  status = smb_set_file_time(conn, fsp, smb_fname, &ft, true);
  if (!NT_STATUS_IS_OK(status)) {
    return status;
  }
  if (fsp->fsp_flags.modified) {
    trigger_write_time_update_immediate(fsp);
  }
  return NT_STATUS_OK;
}

GF_Err gf_isom_read_null_terminated_string(GF_Box* s, GF_BitStream* bs,
                                           u64 size, char** out_str) {
  u32 len = 10;
  u32 i = 0;
  *out_str = gf_malloc(sizeof(char) * len);
  if (!*out_str) return GF_OUT_OF_MEM;
  if (!s->size) {
    *out_str[0] = 0;
    return GF_OK;
  }
  while (1) {
    ISOM_DECREASE_SIZE(s, 1);
    (*out_str)[i] = gf_bs_read_u8(bs);
    if (!(*out_str)[i]) break;
    i++;
    if (i == len) {
      len += 10;
      *out_str = gf_realloc(*out_str, sizeof(char) * len);
    }
    if (gf_bs_available(bs) == 0) {
      GF_LOG(GF_LOG_WARNING, GF_LOG_CONTAINER,
             ("[iso file] missing null character in null terminated string\n"));
      (*out_str)[i] = 0;
      return GF_OK;
    }
    if (i >= size) {
      GF_LOG(GF_LOG_WARNING, GF_LOG_CONTAINER,
             ("[iso file] string bigger than container, probably missing null "
              "character\n"));
      (*out_str)[i] = 0;
      return GF_OK;
    }
  }
  return GF_OK;
}

check_cell_width(short* tabwidth, short* cellwidth, short* col, short* colspan,
                 short maxcell, short* indexarray, int space, int dir) {
  int i, j, k, bcol, ecol;
  int swidth, width;
  for (k = 0; k <= maxcell; k++) {
    j = indexarray[k];
    if (cellwidth[j] <= 0) continue;
    bcol = col[j];
    ecol = bcol + colspan[j];
    swidth = 0;
    for (i = bcol; i < ecol; i++) swidth += tabwidth[i];
    width = cellwidth[j] - (colspan[j] - 1) * space;
    if (width > swidth) {
      int w = (width - swidth) / colspan[j];
      int r = (width - swidth) % colspan[j];
      for (i = bcol; i < ecol; i++) tabwidth[i] += w;
      if (dir == 1 && r > 0) r = colspan[j];
      for (i = 1; i <= r; i++) tabwidth[ecol - i]++;
    }
  }
}

ProcEstablishConnection(ClientPtr client) {
  const char* reason;
  char *auth_proto, *auth_string;
  xConnClientPrefix* prefix;
  REQUEST(xReq);
  prefix = (xConnClientPrefix*)((char*)stuff + sz_xReq);
  auth_proto = (char*)prefix + sz_xConnClientPrefix;
  auth_string = auth_proto + pad_to_int32(prefix->nbytesAuthProto);
  if ((prefix->majorVersion != X_PROTOCOL) ||
      (prefix->minorVersion != X_PROTOCOL_REVISION))
    reason = "Protocol version mismatch";
  else
    reason = ClientAuthorized(
        client, (unsigned short)prefix->nbytesAuthProto, auth_proto,
        (unsigned short)prefix->nbytesAuthString, auth_string);
  return (SendConnSetup(client, reason));
}

cmd_writekey(assuan_context_t ctx, char* line) {
  ctrl_t ctrl = assuan_get_pointer(ctx);
  int rc;
  char* keyid;
  int force = has_option(line, "--force");
  unsigned char* keydata;
  size_t keydatalen;
  if (IS_LOCKED(ctrl)) return gpg_error(GPG_ERR_LOCKED);
  line = skip_options(line);
  if (!*line) return set_error(GPG_ERR_ASS_PARAMETER, "no keyid given");
  keyid = line;
  while (*line && !spacep(line)) line++;
  *line = 0;
  if ((rc = open_card(ctrl, NULL))) return rc;
  if (!ctrl->app_ctx) return gpg_error(GPG_ERR_UNSUPPORTED_OPERATION);
  keyid = xtrystrdup(keyid);
  if (!keyid) return out_of_core();
  assuan_begin_confidential(ctx);
  rc = assuan_inquire(ctx, "KEYDATA", &keydata, &keydatalen, MAXLEN_KEYDATA);
  assuan_end_confidential(ctx);
  if (rc) {
    xfree(keyid);
    return rc;
  }
  rc = app_writekey(ctrl->app_ctx, ctrl, keyid, force ? 1 : 0, pin_cb, ctx,
                    keydata, keydatalen);
  xfree(keyid);
  xfree(keydata);
  TEST_CARD_REMOVAL(ctrl, rc);
  return rc;
}

static void write_cachehdr(const char* name, const char* contents,
                           const char* raw __attribute__((unused)),
                           void* rock) {
  struct transaction_t* txn = (struct transaction_t*)rock;
  const char **hdr, *hop_by_hop[] = {"connection",
                                     "content-length",
                                     "content-type",
                                     "date",
                                     "forwarded",
                                     "keep-alive",
                                     "location",
                                     "status",
                                     "strict-transport-security",
                                     "upgrade",
                                     "via",
                                     NULL};
  if (name[0] == ':') return;
  for (hdr = hop_by_hop; *hdr; hdr++) {
    if (!strcasecmp(name, *hdr)) return;
  }
  simple_hdr(txn, name, contents);
}

struct key* key_get_instantiation_authkey(key_serial_t target_id) {
  char description[16];
  struct keyring_search_context ctx = {
      .index_key.type = &key_type_request_key_auth,
      .index_key.description = description,
      .cred = current_cred(),
      .match_data.cmp = key_default_cmp,
      .match_data.raw_data = description,
      .match_data.lookup_type = KEYRING_SEARCH_LOOKUP_DIRECT,
  };
  struct key* authkey;
  key_ref_t authkey_ref;
  sprintf(description, "%x", target_id);
  authkey_ref = search_process_keyrings(&ctx);
  if (IS_ERR(authkey_ref)) {
    authkey = ERR_CAST(authkey_ref);
    if (authkey == ERR_PTR(-EAGAIN)) authkey = ERR_PTR(-ENOKEY);
    goto error;
  }
  authkey = key_ref_to_ptr(authkey_ref);
  if (test_bit(KEY_FLAG_REVOKED, &authkey->flags)) {
    key_put(authkey);
    authkey = ERR_PTR(-EKEYREVOKED);
  }
error:
  return authkey;
}

static void pdf14_cleanup_parent_color_profiles(pdf14_device* pdev) {
  if (pdev->ctx) {
    pdf14_buf *buf, *next;
    for (buf = pdev->ctx->stack; buf != NULL; buf = next) {
      pdf14_parent_color_t* old_parent_color_info =
          buf->parent_color_info_procs;
      next = buf->saved;
      while (old_parent_color_info) {
        if (old_parent_color_info->icc_profile != NULL) {
          cmm_profile_t* group_profile;
          gsicc_rendering_param_t render_cond;
          cmm_dev_profile_t* dev_profile;
          int code = dev_proc((gx_device*)pdev, get_profile)((gx_device*)pdev,
                                                             &dev_profile);
          if (code >= 0) {
            gsicc_extract_profile(GS_UNKNOWN_TAG, dev_profile, &group_profile,
                                  &render_cond);
            rc_decrement(group_profile, "pdf14_end_transparency_group");
            pdev->icc_struct->device_profile[0] =
                old_parent_color_info->icc_profile;
            rc_decrement(old_parent_color_info->icc_profile,
                         "pdf14_end_transparency_group");
            old_parent_color_info->icc_profile = NULL;
          }
        }
        old_parent_color_info = old_parent_color_info->previous;
      }
    }
  }
}

int hfs_cat_create(u32 cnid, struct inode* dir, struct qstr* str,
                   struct inode* inode) {
  struct hfs_find_data fd;
  struct super_block* sb;
  union hfs_cat_rec entry;
  int entry_size;
  int err;
  dprint(DBG_CAT_MOD, "create_cat: %s,%u(%d)\n", str->name, cnid,
         inode->i_nlink);
  if (dir->i_size >= HFS_MAX_VALENCE) return -ENOSPC;
  sb = dir->i_sb;
  hfs_find_init(HFS_SB(sb)->cat_tree, &fd);
  hfs_cat_build_key(sb, fd.search_key, cnid, NULL);
  entry_size = hfs_cat_build_thread(
      sb, &entry, S_ISDIR(inode->i_mode) ? HFS_CDR_THD : HFS_CDR_FTH,
      dir->i_ino, str);
  err = hfs_brec_find(&fd);
  if (err != -ENOENT) {
    if (!err) err = -EEXIST;
    goto err2;
  }
  err = hfs_brec_insert(&fd, &entry, entry_size);
  if (err) goto err2;
  hfs_cat_build_key(sb, fd.search_key, dir->i_ino, str);
  entry_size = hfs_cat_build_record(&entry, cnid, inode);
  err = hfs_brec_find(&fd);
  if (err != -ENOENT) {
    if (!err) err = -EEXIST;
    goto err1;
  }
  err = hfs_brec_insert(&fd, &entry, entry_size);
  if (err) goto err1;
  dir->i_size++;
  dir->i_mtime = dir->i_ctime = CURRENT_TIME_SEC;
  mark_inode_dirty(dir);
  hfs_find_exit(&fd);
  return 0;
err1:
  hfs_cat_build_key(sb, fd.search_key, cnid, NULL);
  if (!hfs_brec_find(&fd)) hfs_brec_remove(&fd);
err2:
  hfs_find_exit(&fd);
  return err;
}

