imapx_unset_folder_flagged_flag(CamelFolderSummary* summary,
                                GPtrArray* changed_uids,
                                gboolean except_deleted_messages) {
  CamelMessageInfo* info;
  gboolean changed = FALSE;
  gint ii;
  g_return_if_fail(CAMEL_IS_FOLDER_SUMMARY(summary));
  g_return_if_fail(changed_uids != NULL);
  for (ii = 0; ii < changed_uids->len; ii++) {
    info = camel_folder_summary_get(summary, changed_uids->pdata[ii]);
    if (info) {
      CamelMessageInfoBase* mi = (CamelMessageInfoBase*)info;
      if ((mi->flags & CAMEL_MESSAGE_FOLDER_FLAGGED) != 0 &&
          (!except_deleted_messages ||
           (mi->flags & CAMEL_MESSAGE_DELETED) == 0)) {
        mi->flags &= ~CAMEL_MESSAGE_FOLDER_FLAGGED;
        mi->dirty = TRUE;
        changed = TRUE;
      }
      camel_message_info_unref(info);
    }
  }
  if (changed) {
    camel_folder_summary_touch(summary);
    camel_folder_summary_save_to_db(summary, NULL);
  }
}

static int show_stat(struct kmem_cache* s, char* buf, enum stat_item si) {
  unsigned long sum = 0;
  int cpu;
  int len;
  int* data = kmalloc(nr_cpu_ids * sizeof(int), GFP_KERNEL);
  if (!data) return -ENOMEM;
  for_each_online_cpu(cpu) {
    unsigned x = get_cpu_slab(s, cpu)->stat[si];
    data[cpu] = x;
    sum += x;
  }
  len = sprintf(buf, "%lu", sum);
#ifdef CONFIG_SMP
  for_each_online_cpu(cpu) {
    if (data[cpu] && len < PAGE_SIZE - 20)
      len += sprintf(buf + len, " C%d=%u", cpu, data[cpu]);
  }
#endif
  kfree(data);
  return len + sprintf(buf + len, "\n");
}

static bool mtrr_valid(struct kvm_vcpu* vcpu, u32 msr, u64 data) {
  int i;
  if (!msr_mtrr_valid(msr)) return false;
  if (msr == MSR_IA32_CR_PAT) {
    for (i = 0; i < 8; i++)
      if (!valid_pat_type((data >> (i * 8)) & 0xff)) return false;
    return true;
  } else if (msr == MSR_MTRRdefType) {
    if (data & ~0xcff) return false;
    return valid_mtrr_type(data & 0xff);
  } else if (msr >= MSR_MTRRfix64K_00000 && msr <= MSR_MTRRfix4K_F8000) {
    for (i = 0; i < 8; i++)
      if (!valid_mtrr_type((data >> (i * 8)) & 0xff)) return false;
    return true;
  }
  return valid_mtrr_type(data & 0xff);
}

void bnx2x_read_dmae(struct bnx2x* bp, u32 src_addr, u32 len32) {
  int rc;
  struct dmae_command dmae;
  if (!bp->dmae_ready) {
    u32* data = bnx2x_sp(bp, wb_data[0]);
    int i;
    if (CHIP_IS_E1(bp))
      for (i = 0; i < len32; i++)
        data[i] = bnx2x_reg_rd_ind(bp, src_addr + i * 4);
    else
      for (i = 0; i < len32; i++) data[i] = REG_RD(bp, src_addr + i * 4);
    return;
  }
  bnx2x_prep_dmae_with_comp(bp, &dmae, DMAE_SRC_GRC, DMAE_DST_PCI);
  dmae.src_addr_lo = src_addr >> 2;
  dmae.src_addr_hi = 0;
  dmae.dst_addr_lo = U64_LO(bnx2x_sp_mapping(bp, wb_data));
  dmae.dst_addr_hi = U64_HI(bnx2x_sp_mapping(bp, wb_data));
  dmae.len = len32;
  rc = bnx2x_issue_dmae_with_comp(bp, &dmae, bnx2x_sp(bp, wb_comp));
  if (rc) {
    BNX2X_ERR("DMAE returned failure %d\n", rc);
#ifdef BNX2X_STOP_ON_ERROR
    bnx2x_panic();
#endif
  }
}

static void _ipmi_destroy_user(struct ipmi_user* user) {
  struct ipmi_smi* intf = user->intf;
  int i;
  unsigned long flags;
  struct cmd_rcvr* rcvr;
  struct cmd_rcvr* rcvrs = NULL;
  if (!acquire_ipmi_user(user, &i)) {
    synchronize_srcu(&user->release_barrier);
    return;
  }
  rcu_assign_pointer(user->self, NULL);
  release_ipmi_user(user, i);
  synchronize_srcu(&user->release_barrier);
  if (user->handler->shutdown) user->handler->shutdown(user->handler_data);
  if (user->handler->ipmi_watchdog_pretimeout)
    smi_remove_watch(intf, IPMI_WATCH_MASK_CHECK_WATCHDOG);
  if (user->gets_events) atomic_dec(&intf->event_waiters);
  spin_lock_irqsave(&intf->seq_lock, flags);
  list_del_rcu(&user->link);
  for (i = 0; i < IPMI_IPMB_NUM_SEQ; i++) {
    if (intf->seq_table[i].inuse &&
        (intf->seq_table[i].recv_msg->user == user)) {
      intf->seq_table[i].inuse = 0;
      smi_remove_watch(intf, IPMI_WATCH_MASK_CHECK_MESSAGES);
      ipmi_free_recv_msg(intf->seq_table[i].recv_msg);
    }
  }
  spin_unlock_irqrestore(&intf->seq_lock, flags);
  mutex_lock(&intf->cmd_rcvrs_mutex);
  list_for_each_entry_rcu(rcvr, &intf->cmd_rcvrs, link) {
    if (rcvr->user == user) {
      list_del_rcu(&rcvr->link);
      rcvr->next = rcvrs;
      rcvrs = rcvr;
    }
  }
  mutex_unlock(&intf->cmd_rcvrs_mutex);
  synchronize_rcu();
  while (rcvrs) {
    rcvr = rcvrs;
    rcvrs = rcvr->next;
    kfree(rcvr);
  }
  kref_put(&intf->refcount, intf_free);
  module_put(intf->owner);
}

