  return 0;
}

buf_add_chunk_with_capacity(buf_t* buf, size_t capacity, int capped) {
  chunk_t* chunk;
  struct timeval now;
  if (CHUNK_ALLOC_SIZE(capacity) < buf->default_chunk_size) {
    chunk = chunk_new_with_alloc_size(buf->default_chunk_size);
  } else if (capped && CHUNK_ALLOC_SIZE(capacity) > MAX_CHUNK_ALLOC) {
    chunk = chunk_new_with_alloc_size(MAX_CHUNK_ALLOC);
  } else {
    chunk = chunk_new_with_alloc_size(preferred_chunk_size(capacity));
  }
  tor_gettimeofday_cached_monotonic(&now);
  chunk->inserted_time = (uint32_t)tv_to_msec(&now);
  if (buf->tail) {
    tor_assert(buf->head);
    buf->tail->next = chunk;
    buf->tail = chunk;
  } else {
    tor_assert(!buf->head);
    buf->head = buf->tail = chunk;
  }
  check();
  return chunk;
}

static unsigned addChunk_iTXt(ucvector* out, unsigned compressed,
                              const char* keyword, const char* langtag,
                              const char* transkey, const char* textstring,
                              LodePNGCompressSettings* zlibsettings) {
  unsigned error = 0;
  ucvector data;
  size_t i, textsize = strlen(textstring);
  ucvector_init(&data);
  for (i = 0; keyword[i] != 0; i++)
    ucvector_push_back(&data, (unsigned char)keyword[i]);
  if (i < 1 || i > 79) return 89;
  ucvector_push_back(&data, 0);
  ucvector_push_back(&data, compressed ? 1 : 0);
  ucvector_push_back(&data, 0);
  for (i = 0; langtag[i] != 0; i++)
    ucvector_push_back(&data, (unsigned char)langtag[i]);
  ucvector_push_back(&data, 0);
  for (i = 0; transkey[i] != 0; i++)
    ucvector_push_back(&data, (unsigned char)transkey[i]);
  ucvector_push_back(&data, 0);
  if (compressed) {
    ucvector compressed_data;
    ucvector_init(&compressed_data);
    error = zlib_compress(&compressed_data.data, &compressed_data.size,
                          (unsigned char*)textstring, textsize, zlibsettings);
    if (!error) {
      for (i = 0; i < compressed_data.size; i++)
        ucvector_push_back(&data, compressed_data.data[i]);
    }
    ucvector_cleanup(&compressed_data);
  } else {
    for (i = 0; textstring[i] != 0; i++)
      ucvector_push_back(&data, (unsigned char)textstring[i]);
  }
  if (!error) error = addChunk(out, "iTXt", data.data, data.size);
  ucvector_cleanup(&data);
  return error;
}

