    case XFRM_MSG_NEWAE:
      break;
    default:
      pr_err("pfkey: Unknown SA event %d\n", c->event);
      break;
  }
  return 0;
}

PHPAPI zend_string* php_escape_shell_arg(char* str) {
  int x, y = 0, l = strlen(str);
  zend_string* cmd;
  size_t estimate = (4 * l) + 3;
  TSRMLS_FETCH();
  cmd = STR_ALLOC(4 * l + 2, 0);
#ifdef PHP_WIN32
  cmd->val[y++] = '"';
#else
  cmd->val[y++] = '\'';
#endif
  for (x = 0; x < l; x++) {
    int mb_len = php_mblen(str + x, (l - x));
    if (mb_len < 0) {
      continue;
    } else if (mb_len > 1) {
      memcpy(cmd->val + y, str + x, mb_len);
      y += mb_len;
      x += mb_len - 1;
      continue;
    }
    switch (str[x]) {
#ifdef PHP_WIN32
      case '"':
      case '%':
        cmd->val[y++] = ' ';
        break;
#else
      case '\'':
        cmd->val[y++] = '\'';
        cmd->val[y++] = '\\';
        cmd->val[y++] = '\'';
#endif
      default:
        cmd->val[y++] = str[x];
    }
  }
#ifdef PHP_WIN32
  cmd->val[y++] = '"';
#else
  cmd->val[y++] = '\'';
#endif
  cmd->val[y] = '\0';
  if ((estimate - y) > 4096) {
    cmd = STR_REALLOC(cmd, y, 0);
  }
  cmd->len = y;
  return cmd;
}

static void __vmx_load_host_state(struct vcpu_vmx* vmx) {
  if (!vmx->host_state.loaded) return;
  ++vmx->vcpu.stat.host_state_reload;
  vmx->host_state.loaded = 0;
#ifdef CONFIG_X86_64
  if (is_long_mode(&vmx->vcpu))
    rdmsrl(MSR_KERNEL_GS_BASE, vmx->msr_guest_kernel_gs_base);
#endif
  if (vmx->host_state.gs_ldt_reload_needed) {
    kvm_load_ldt(vmx->host_state.ldt_sel);
#ifdef CONFIG_X86_64
    load_gs_index(vmx->host_state.gs_sel);
#else
    loadsegment(gs, vmx->host_state.gs_sel);
#endif
  }
  if (vmx->host_state.fs_reload_needed) loadsegment(fs, vmx->host_state.fs_sel);
#ifdef CONFIG_X86_64
  if (unlikely(vmx->host_state.ds_sel | vmx->host_state.es_sel)) {
    loadsegment(ds, vmx->host_state.ds_sel);
    loadsegment(es, vmx->host_state.es_sel);
  }
#endif
  reload_tss();
#ifdef CONFIG_X86_64
  wrmsrl(MSR_KERNEL_GS_BASE, vmx->msr_host_kernel_gs_base);
#endif
  if (vmx->host_state.msr_host_bndcfgs)
    wrmsrl(MSR_IA32_BNDCFGS, vmx->host_state.msr_host_bndcfgs);
  if (!user_has_fpu() && !vmx->vcpu.guest_fpu_loaded) stts();
  load_gdt(this_cpu_ptr(&host_gdt));
}

static void mark_curve(fixed sx, fixed sy, fixed c1x, fixed c1y, fixed c2x,
                       fixed c2y, fixed ex, fixed ey, fixed base_y,
                       fixed height, int* table, int* index, int depth) {
  fixed ax = (sx + c1x) >> 1;
  fixed ay = (sy + c1y) >> 1;
  fixed bx = (c1x + c2x) >> 1;
  fixed by = (c1y + c2y) >> 1;
  fixed cx = (c2x + ex) >> 1;
  fixed cy = (c2y + ey) >> 1;
  fixed dx = (ax + bx) >> 1;
  fixed dy = (ay + by) >> 1;
  fixed fx = (bx + cx) >> 1;
  fixed fy = (by + cy) >> 1;
  fixed gx = (dx + fx) >> 1;
  fixed gy = (dy + fy) >> 1;
  assert(depth >= 0);
  if (depth == 0)
    mark_line(sx, sy, ex, ey, base_y, height, table, index);
  else {
    depth--;
    mark_curve(sx, sy, ax, ay, dx, dy, gx, gy, base_y, height, table, index,
               depth);
    mark_curve(gx, gy, fx, fy, cx, cy, ex, ey, base_y, height, table, index,
               depth);
  }
}

