SMB311_posix_qfs_info(const unsigned int xid, struct cifs_tcon* tcon,
                      u64 persistent_fid, u64 volatile_fid,
                      struct kstatfs* fsdata) {
  struct smb_rqst rqst;
  struct smb2_query_info_rsp* rsp = NULL;
  struct kvec iov;
  struct kvec rsp_iov;
  int rc = 0;
  int resp_buftype;
  struct cifs_ses* ses = tcon->ses;
  FILE_SYSTEM_POSIX_INFO* info = NULL;
  int flags = 0;
  rc = build_qfs_info_req(&iov, tcon, FS_POSIX_INFORMATION,
                          sizeof(FILE_SYSTEM_POSIX_INFO), persistent_fid,
                          volatile_fid);
  if (rc) return rc;
  if (smb3_encryption_required(tcon)) flags |= CIFS_TRANSFORM_REQ;
  memset(&rqst, 0, sizeof(struct smb_rqst));
  rqst.rq_iov = &iov;
  rqst.rq_nvec = 1;
  rc = cifs_send_recv(xid, ses, &rqst, &resp_buftype, flags, &rsp_iov);
  cifs_small_buf_release(iov.iov_base);
  if (rc) {
    cifs_stats_fail_inc(tcon, SMB2_QUERY_INFO_HE);
    goto posix_qfsinf_exit;
  }
  rsp = (struct smb2_query_info_rsp*)rsp_iov.iov_base;
  info = (FILE_SYSTEM_POSIX_INFO*)(le16_to_cpu(rsp->OutputBufferOffset) +
                                   (char*)rsp);
  rc = smb2_validate_iov(le16_to_cpu(rsp->OutputBufferOffset),
                         le32_to_cpu(rsp->OutputBufferLength), &rsp_iov,
                         sizeof(FILE_SYSTEM_POSIX_INFO));
  if (!rc) copy_posix_fs_info_to_kstatfs(info, fsdata);
posix_qfsinf_exit:
  free_rsp_buf(resp_buftype, rsp_iov.iov_base);
  return rc;
}

vte_sequence_handler_sr(VteTerminal* terminal, GValueArray* params) {
  long start, end;
  VteScreen* screen;
  screen = terminal->pvt->screen;
  if (screen->scrolling_restricted) {
    start = screen->scrolling_region.start + screen->insert_delta;
    end = screen->scrolling_region.end + screen->insert_delta;
  } else {
    start = terminal->pvt->screen->insert_delta;
    end = start + terminal->row_count - 1;
  }
  if (screen->cursor_current.row == start) {
    _vte_terminal_ring_remove(terminal, end);
    _vte_terminal_ring_insert(terminal, start, TRUE);
    _vte_terminal_scroll_region(terminal, start, end - start + 1, 1);
    _vte_invalidate_cells(terminal, 0, terminal->column_count, start, 2);
  } else {
    screen->cursor_current.row--;
  }
  _vte_terminal_adjust_adjustments(terminal);
  terminal->pvt->text_modified_flag = TRUE;
}

void isdn_net_write_super(isdn_net_local* lp, struct sk_buff* skb) {
  if (in_irq()) {
    skb_queue_tail(&lp->super_tx_queue, skb);
    schedule_work(&lp->tqueue);
    return;
  }
  spin_lock_bh(&lp->xmit_lock);
  if (!isdn_net_lp_busy(lp)) {
    isdn_net_writebuf_skb(lp, skb);
  } else {
    skb_queue_tail(&lp->super_tx_queue, skb);
  }
  spin_unlock_bh(&lp->xmit_lock);
}

generate_auth_info(cms_context* cms, SECItem* der, char* url) {
  AuthInfo ai;
  SECOidData* oid = SECOID_FindOIDByTag(SEC_OID_PKIX_CA_ISSUERS);
  if (!oid) cnreterr(-1, cms, "could not get CA issuers OID");
  memcpy(&ai.oid, &oid->oid, sizeof(ai.oid));
  SECItem urlitem = {
      .data = (unsigned char*)url, .len = strlen(url), .type = siBuffer};
  int rc = make_context_specific(cms, 6, &ai.url, &urlitem);
  if (rc < 0) return rc;
  void* ret;
  SECItem unwrapped;
  ret = SEC_ASN1EncodeItem(cms->arena, &unwrapped, &ai, AuthInfoTemplate);
  if (ret == NULL) cnreterr(-1, cms, "could not encode CA Issuers");
  rc = wrap_in_seq(cms, der, &unwrapped, 1);
  if (rc < 0) return rc;
  return 0;
  if (unwrapped.len < 12)
    cnreterr(-1, cms, "generated CA Issuers Info cannot possibly be valid");
  unwrapped.data[12] = 0x86;
  unwrapped.type = siBuffer;
  AuthInfo wrapper;
  oid = SECOID_FindOIDByTag(SEC_OID_X509_AUTH_INFO_ACCESS);
  if (!oid) cnreterr(-1, cms, "could not find Auth Info Access OID");
  memcpy(&wrapper.oid, &oid->oid, sizeof(ai.oid));
  wrap_in_seq(cms, &wrapper.url, &unwrapped, 1);
  ret = SEC_ASN1EncodeItem(cms->arena, der, &wrapper, AuthInfoWrapperTemplate);
  if (ret == NULL) cnreterr(-1, cms, "could not encode CA Issuers OID");
  return 0;
}

static int sr9700_rx_fixup(struct usbnet* dev, struct sk_buff* skb) {
  struct sk_buff* sr_skb;
  int len;
  if (unlikely(skb->len < SR_RX_OVERHEAD)) {
    netdev_err(dev->net, "unexpected tiny rx frame\n");
    return 0;
  }
  while (skb->len > SR_RX_OVERHEAD) {
    if (skb->data[0] != 0x40) return 0;
    len = (skb->data[1] | (skb->data[2] << 8)) - 4;
    if (len > ETH_FRAME_LEN || len > skb->len) return 0;
    if (skb->len == (len + SR_RX_OVERHEAD)) {
      skb_pull(skb, 3);
      skb->len = len;
      skb_set_tail_pointer(skb, len);
      skb->truesize = len + sizeof(struct sk_buff);
      return 2;
    }
    sr_skb = skb_clone(skb, GFP_ATOMIC);
    if (!sr_skb) return 0;
    sr_skb->len = len;
    sr_skb->data = skb->data + 3;
    skb_set_tail_pointer(sr_skb, len);
    sr_skb->truesize = len + sizeof(struct sk_buff);
    usbnet_skb_return(dev, sr_skb);
    skb_pull(skb, len + SR_RX_OVERHEAD);
  }
  return 0;
}

xfs_bmap_add_attrfork_extents(xfs_trans_t* tp, xfs_inode_t* ip,
                              xfs_fsblock_t* firstblock,
                              struct xfs_defer_ops* dfops, int* flags) {
  xfs_btree_cur_t* cur;
  int error;
  if (ip->i_d.di_nextents * sizeof(xfs_bmbt_rec_t) <= XFS_IFORK_DSIZE(ip))
    return 0;
  cur = NULL;
  error = xfs_bmap_extents_to_btree(tp, ip, firstblock, dfops, &cur, 0, flags,
                                    XFS_DATA_FORK);
