  }
  return error;
}

int buffer_migrate_page(struct address_space* mapping, struct page* newpage,
                        struct page* page) {
  struct buffer_head *bh, *head;
  int rc;
  if (!page_has_buffers(page)) return migrate_page(mapping, newpage, page);
  head = page_buffers(page);
  rc = migrate_page_move_mapping(mapping, newpage, page);
  if (rc) return rc;
  bh = head;
  do {
    get_bh(bh);
    lock_buffer(bh);
    bh = bh->b_this_page;
  } while (bh != head);
  ClearPagePrivate(page);
  set_page_private(newpage, page_private(page));
  set_page_private(page, 0);
  put_page(page);
  get_page(newpage);
  bh = head;
  do {
    set_bh_page(bh, newpage, bh_offset(bh));
    bh = bh->b_this_page;
  } while (bh != head);
  SetPagePrivate(newpage);
  migrate_page_copy(newpage, page);
  bh = head;
  do {
    unlock_buffer(bh);
    put_bh(bh);
    bh = bh->b_this_page;
  } while (bh != head);
  return 0;
}

static const char* find_host_sep(const char* url) {
  const char* sep;
  const char* query;
  sep = strstr(url, "
  if(!sep)
    sep = url;
  else
    sep += 2;
  query = strchr(sep, '?');
  sep = strchr(sep, '/');
  if(!sep)
    sep = url + strlen(url);
  if(!query)
    query = url + strlen(url);
  return sep < query ? sep : query;
}

