void HTMLMediaElement::SourceWasRemoved(HTMLSourceElement* source) {
  BLINK_MEDIA_LOG << "sourceWasRemoved(" << (void*)this << ", " << source
                  << ")";
  KURL url = source->GetNonEmptyURLAttribute(kSrcAttr);
  BLINK_MEDIA_LOG << "sourceWasRemoved(" << (void*)this << ") - 'src' is "
                  << UrlForLoggingMedia(url);
  if (source != current_source_node_ && source != next_child_node_to_consider_)
    return;
  if (source == next_child_node_to_consider_) {
    if (current_source_node_)
      next_child_node_to_consider_ = current_source_node_->nextSibling();
    BLINK_MEDIA_LOG << "sourceWasRemoved(" << (void*)this
                    << ") - next_child_node_to_consider_ set to "
                    << next_child_node_to_consider_.Get();
  } else if (source == current_source_node_) {
    current_source_node_ = nullptr;
    BLINK_MEDIA_LOG << "SourceWasRemoved(" << (void*)this
                    << ") - current_source_node_ set to 0";
  }
}

bool PluginInfoMessageFilter::Context::FindEnabledPlugin(
    int render_view_id, const GURL& url, const GURL& top_origin_url,
    const std::string& mime_type,
    ChromeViewHostMsg_GetPluginInfo_Status* status, WebPluginInfo* plugin,
    std::string* actual_mime_type) const {
  bool allow_wildcard = true;
  std::vector<WebPluginInfo> matching_plugins;
  std::vector<std::string> mime_types;
  PluginService::GetInstance()->GetPluginInfoArray(
      url, mime_type, allow_wildcard, &matching_plugins, &mime_types);
  content::PluginServiceFilter* filter =
      PluginService::GetInstance()->GetFilter();
  bool found = false;
  for (size_t i = 0; i < matching_plugins.size(); ++i) {
    bool enabled =
        !filter || filter->ShouldUsePlugin(
                       render_process_id_, render_view_id, resource_context_,
                       url, top_origin_url, &matching_plugins[i]);
    if (!found || enabled) {
      *plugin = matching_plugins[i];
      *actual_mime_type = mime_types[i];
      if (enabled) {
        return true;
      }
      found = true;
    }
  }
  if (found)
    status->value = ChromeViewHostMsg_GetPluginInfo_Status::kDisabled;
  else
    status->value = ChromeViewHostMsg_GetPluginInfo_Status::kNotFound;
  return false;
}

onig_regset_new(OnigRegSet** rset, int n, regex_t* regs[]) {
#define REGSET_INITIAL_ALLOC_SIZE 10
  int i;
  int r;
  int alloc;
  OnigRegSet* set;
  RR* rs;
  *rset = 0;
  set = (OnigRegSet*)xmalloc(sizeof(*set));
  CHECK_NULL_RETURN_MEMERR(set);
  alloc = n > REGSET_INITIAL_ALLOC_SIZE ? n : REGSET_INITIAL_ALLOC_SIZE;
  rs = (RR*)xmalloc(sizeof(set->rs[0]) * alloc);
  if (IS_NULL(rs)) {
    xfree(set);
    return ONIGERR_MEMORY;
  }
  set->rs = rs;
  set->n = 0;
  set->alloc = alloc;
  for (i = 0; i < n; i++) {
    regex_t* reg = regs[i];
    r = onig_regset_add(set, reg);
    if (r != 0) {
      for (i = 0; i < set->n; i++) {
        OnigRegion* region = set->rs[i].region;
        if (IS_NOT_NULL(region)) onig_region_free(region, 1);
      }
      xfree(set->rs);
      xfree(set);
      return r;
    }
  }
  *rset = set;
  return 0;
}

XcursorLibraryShape(const char* library) {
  int low, high;
  int mid;
  int c;
  low = 0;
  high = NUM_STANDARD_NAMES - 1;
  while (low < high - 1) {
    mid = (low + high) >> 1;
    c = strcmp(library, STANDARD_NAME(mid));
    if (c == 0) return (mid << 1);
    if (c > 0)
      low = mid;
    else
      high = mid;
  }
  while (low <= high) {
    if (!strcmp(library, STANDARD_NAME(low))) return (low << 1);
    low++;
  }
  return -1;
}

fetch_ext_or_command_from_evbuffer(struct evbuffer* buf, ext_or_cmd_t** out) {
  char hdr[EXT_OR_CMD_HEADER_SIZE];
  uint16_t len;
  size_t buf_len = evbuffer_get_length(buf);
  if (buf_len < EXT_OR_CMD_HEADER_SIZE) return 0;
  evbuffer_copyout(buf, hdr, EXT_OR_CMD_HEADER_SIZE);
  len = ntohs(get_uint16(hdr + 2));
  if (buf_len < (unsigned)len + EXT_OR_CMD_HEADER_SIZE) return 0;
  *out = ext_or_cmd_new(len);
  (*out)->cmd = ntohs(get_uint16(hdr));
  (*out)->len = len;
  evbuffer_drain(buf, EXT_OR_CMD_HEADER_SIZE);
  evbuffer_remove(buf, (*out)->body, len);
  return 1;
}

fbStore_a1r1g1b1(FbBits* bits, const CARD32* values, int x, int width,
                 miIndexedPtr indexed) {
  int i;
  for (i = 0; i < width; ++i) {
    CARD32 pixel;
    Splita(READ(values + i));
    pixel =
        (((a >> 4) & 0x8) | ((r >> 5) & 0x4) | ((g >> 6) & 0x2) | ((b >> 7)));
    Store4(bits, i + x, pixel);
  }
}

