LookupModMask(struct xkb_context* ctx, const void* priv, xkb_atom_t field,
              enum expr_value_type type, xkb_mod_mask_t* val_rtrn) {
  const char* str;
  xkb_mod_index_t ndx;
  const LookupModMaskPriv* arg = priv;
  const struct xkb_mod_set* mods = arg->mods;
  enum mod_type mod_type = arg->mod_type;
  if (type != EXPR_TYPE_INT) return false;
  str = xkb_atom_text(ctx, field);
  if (!str) return false;
  if (istreq(str, "all")) {
    *val_rtrn = MOD_REAL_MASK_ALL;
    return true;
  }
  if (istreq(str, "none")) {
    *val_rtrn = 0;
    return true;
  }
  ndx = XkbModNameToIndex(mods, field, mod_type);
  if (ndx == XKB_MOD_INVALID) return false;
  *val_rtrn = (1u << ndx);
  return true;
}

isofs_export_encode_fh(struct inode* inode, __u32* fh32, int* max_len,
                       struct inode* parent) {
  struct iso_inode_info* ei = ISOFS_I(inode);
  int len = *max_len;
  int type = 1;
  __u16* fh16 = (__u16*)fh32;
  if (parent && (len < 5)) {
    *max_len = 5;
    return 255;
  } else if (len < 3) {
    *max_len = 3;
    return 255;
  }
  len = 3;
  fh32[0] = ei->i_iget5_block;
  fh16[2] = (__u16)ei->i_iget5_offset;
  fh16[3] = 0;
  fh32[2] = inode->i_generation;
  if (parent) {
    struct iso_inode_info* eparent;
    eparent = ISOFS_I(parent);
    fh32[3] = eparent->i_iget5_block;
    fh16[3] = (__u16)eparent->i_iget5_offset;
    fh32[4] = parent->i_generation;
    len = 5;
    type = 2;
  }
  *max_len = len;
  return type;
}

static int key_notify_sa_flush(const struct km_event* c) {
