onig_builtin_total_count(OnigCalloutArgs* args, void* user_data ARG_UNUSED) {
  int r;
  int slot;
  OnigType type;
  OnigValue val;
  OnigValue aval;
  OnigCodePoint count_type;
  r = onig_get_arg_by_callout_args(args, 0, &type, &aval);
  if (r != ONIG_NORMAL) return r;
  count_type = aval.c;
  if (count_type != '>' && count_type != 'X' && count_type != '<')
    return ONIGERR_INVALID_CALLOUT_ARG;
  r = onig_get_callout_data_by_callout_args_self_dont_clear_old(args, 0, &type,
                                                                &val);
  if (r < ONIG_NORMAL)
    return r;
  else if (r > ONIG_NORMAL) {
    val.l = 0;
  }
  if (args->in == ONIG_CALLOUT_IN_RETRACTION) {
    slot = 2;
    if (count_type == '<')
      val.l++;
    else if (count_type == 'X')
      val.l--;
  } else {
    slot = 1;
    if (count_type != '<') val.l++;
  }
  r = onig_set_callout_data_by_callout_args_self(args, 0, ONIG_TYPE_LONG, &val);
  if (r != ONIG_NORMAL) return r;
  r = onig_get_callout_data_by_callout_args_self_dont_clear_old(args, slot,
                                                                &type, &val);
  if (r < ONIG_NORMAL)
    return r;
  else if (r > ONIG_NORMAL) {
    val.l = 0;
  }
  val.l++;
  r = onig_set_callout_data_by_callout_args_self(args, slot, ONIG_TYPE_LONG,
                                                 &val);
  if (r != ONIG_NORMAL) return r;
  return ONIG_CALLOUT_SUCCESS;
}

static int mpage_process_page_bufs(struct mpage_da_data* mpd,
                                   struct buffer_head* head,
                                   struct buffer_head* bh, ext4_lblk_t lblk) {
  struct inode* inode = mpd->inode;
  int err;
  ext4_lblk_t blocks =
      (i_size_read(inode) + i_blocksize(inode) - 1) >> inode->i_blkbits;
  do {
    BUG_ON(buffer_locked(bh));
    if (lblk >= blocks || !mpage_add_bh_to_extent(mpd, lblk, bh)) {
      if (mpd->map.m_len) return 0;
      if (!mpd->do_map) return 0;
      break;
    }
  } while (lblk++, (bh = bh->b_this_page) != head);
  if (mpd->map.m_len == 0) {
    err = mpage_submit_page(mpd, head->b_page);
    if (err < 0) return err;
  }
  return lblk < blocks;
}

static int blk_mq_alloc_rq_maps(struct blk_mq_tag_set* set) {
  unsigned int depth;
  int err;
  depth = set->queue_depth;
  do {
    err = __blk_mq_alloc_rq_maps(set);
    if (!err) break;
    set->queue_depth >>= 1;
    if (set->queue_depth < set->reserved_tags + BLK_MQ_TAG_MIN) {
      err = -ENOMEM;
      break;
    }
  } while (set->queue_depth);
  if (!set->queue_depth || err) {
    pr_err("blk-mq: failed to allocate request map\n");
    return -ENOMEM;
  }
  if (depth != set->queue_depth)
    pr_info("blk-mq: reduced tag depth (%u -> %u)\n", depth, set->queue_depth);
  return 0;
}

devirtualization_time_bonus(struct cgraph_node* node, vec<tree> known_csts,
                            vec<ipa_polymorphic_call_context> known_contexts,
                            vec<ipa_agg_value_set> known_aggs) {
  struct cgraph_edge* ie;
  int res = 0;
  for (ie = node->indirect_calls; ie; ie = ie->next_callee) {
    struct cgraph_node* callee;
    class ipa_fn_summary* isummary;
    enum availability avail;
    tree target;
    bool speculative;
    target = ipa_get_indirect_edge_target(ie, known_csts, known_contexts,
                                          known_aggs, &speculative);
    if (!target) continue;
    res += 1;
    callee = cgraph_node::get(target);
    if (!callee || !callee->definition) continue;
    callee = callee->function_symbol(&avail);
    if (avail < AVAIL_AVAILABLE) continue;
    isummary = ipa_fn_summaries->get(callee);
    if (!isummary->inlinable) continue;
    int size = ipa_size_summaries->get(callee)->size;
    int max_inline_insns_auto =
        opt_for_fn(callee->decl, param_max_inline_insns_auto);
    if (size <= max_inline_insns_auto / 4)
      res += 31 / ((int)speculative + 1);
    else if (size <= max_inline_insns_auto / 2)
      res += 15 / ((int)speculative + 1);
    else if (size <= max_inline_insns_auto ||
             DECL_DECLARED_INLINE_P(callee->decl))
      res += 7 / ((int)speculative + 1);
  }
  return res;
}

