TfLiteStatus ExpandTensorDim(TfLiteContext* context, const TfLiteTensor& input,
                             int axis, TfLiteTensor* output) {
  const TfLiteIntArray& input_dims = *input.dims;
  if (axis < 0) {
    axis = input_dims.size + 1 + axis;
  }
  TF_LITE_ENSURE(context, axis <= input_dims.size);
  TF_LITE_ENSURE(context, axis >= 0);
  TfLiteIntArray* output_dims = TfLiteIntArrayCreate(input_dims.size + 1);
  for (int i = 0; i < output_dims->size; ++i) {
    if (i < axis) {
      output_dims->data[i] = input_dims.data[i];
    } else if (i == axis) {
      output_dims->data[i] = 1;
    } else {
      output_dims->data[i] = input_dims.data[i - 1];
    }
  }
  return context->ResizeTensor(context, output, output_dims);
}

static void sdhci_write_block_to_card(SDHCIState* s) {
  if (s->prnsts & SDHC_SPACE_AVAILABLE) {
    if (s->norintstsen & SDHC_NISEN_WBUFRDY) {
      s->norintsts |= SDHC_NIS_WBUFRDY;
    }
    sdhci_update_irq(s);
    return;
  }
  if (s->trnmod & SDHC_TRNS_BLK_CNT_EN) {
    if (s->blkcnt == 0) {
      return;
    } else {
      s->blkcnt--;
    }
  }
  sdbus_write_data(&s->sdbus, s->fifo_buffer, s->blksize & BLOCK_SIZE_MASK);
  s->prnsts |= SDHC_SPACE_AVAILABLE;
  if ((s->trnmod & SDHC_TRNS_MULTI) == 0 ||
      ((s->trnmod & SDHC_TRNS_MULTI) && (s->trnmod & SDHC_TRNS_BLK_CNT_EN) &&
       (s->blkcnt == 0))) {
    sdhci_end_transfer(s);
  } else if (s->norintstsen & SDHC_NISEN_WBUFRDY) {
    s->norintsts |= SDHC_NIS_WBUFRDY;
  }
  if (s->stopped_state == sdhc_gap_write && (s->trnmod & SDHC_TRNS_MULTI) &&
      s->blkcnt > 0) {
    s->prnsts &= ~SDHC_DOING_WRITE;
    if (s->norintstsen & SDHC_EISEN_BLKGAP) {
      s->norintsts |= SDHC_EIS_BLKGAP;
    }
    sdhci_end_transfer(s);
  }
  sdhci_update_irq(s);
}

static int nl80211_dump_interface(struct sk_buff* skb,
                                  struct netlink_callback* cb) {
  int wp_idx = 0;
  int if_idx = 0;
  int wp_start = cb->args[0];
  int if_start = cb->args[1];
  struct cfg80211_registered_device* rdev;
  struct wireless_dev* wdev;
  mutex_lock(&cfg80211_mutex);
  list_for_each_entry(rdev, &cfg80211_rdev_list, list) {
    if (!net_eq(wiphy_net(&rdev->wiphy), sock_net(skb->sk))) continue;
    if (wp_idx < wp_start) {
      wp_idx++;
      continue;
    }
    if_idx = 0;
    mutex_lock(&rdev->devlist_mtx);
    list_for_each_entry(wdev, &rdev->wdev_list, list) {
      if (if_idx < if_start) {
        if_idx++;
        continue;
      }
      if (nl80211_send_iface(skb, NETLINK_CB(cb->skb).portid,
                             cb->nlh->nlmsg_seq, NLM_F_MULTI, rdev, wdev) < 0) {
        mutex_unlock(&rdev->devlist_mtx);
        goto out;
      }
      if_idx++;
    }
    mutex_unlock(&rdev->devlist_mtx);
    wp_idx++;
  }
out:
  mutex_unlock(&cfg80211_mutex);
  cb->args[0] = wp_idx;
  cb->args[1] = if_idx;
  return skb->len;
}

