void shut_down(int code) {
  int i;
  int bytes_in = 0;
  int bytes_out = 0;
  in_shutdown = 1;
  if (allow_cors) free_wildmats(allow_cors);
  for (i = 0; http_namespaces[i]; i++) {
    if (http_namespaces[i]->enabled && http_namespaces[i]->shutdown)
      http_namespaces[i]->shutdown();
  }
  xmlCleanupParser();
  proc_cleanup();
  i = 0;
  while (backend_cached && backend_cached[i]) {
    proxy_downserver(backend_cached[i]);
    free(backend_cached[i]->context);
    free(backend_cached[i]);
    i++;
  }
  if (backend_cached) free(backend_cached);
  index_text_extractor_destroy();
  annotatemore_close();
  if (httpd_in) {
    prot_NONBLOCK(httpd_in);
    prot_fill(httpd_in);
    bytes_in = prot_bytes_in(httpd_in);
    prot_free(httpd_in);
  }
  if (httpd_out) {
    prot_flush(httpd_out);
    bytes_out = prot_bytes_out(httpd_out);
    prot_free(httpd_out);
    prometheus_decrement(CYRUS_HTTP_ACTIVE_CONNECTIONS);
  } else {
    prometheus_decrement(CYRUS_HTTP_READY_LISTENERS);
  }
  prometheus_increment(code ? CYRUS_HTTP_SHUTDOWN_TOTAL_STATUS_ERROR
                            : CYRUS_HTTP_SHUTDOWN_TOTAL_STATUS_OK);
  if (protin) protgroup_free(protin);
  if (config_auditlog)
    syslog(LOG_NOTICE,
           "auditlog: traffic sessionid=<%s> bytes_in=<%d> bytes_out=<%d>",
           session_id(), bytes_in, bytes_out);
#ifdef HAVE_SSL
  tls_shutdown_serverengine();
#endif
  saslprops_free(&saslprops);
  http2_done();
  cyrus_done();
  exit(code);
}

transport_rcpt_address(address_item* addr, BOOL include_affixes) {
  uschar* at;
  int plen, slen;
  if (include_affixes) {
    setflag(addr, af_include_affixes);
    return addr->address;
  }
  if (addr->suffix == NULL) {
    if (addr->prefix == NULL) return addr->address;
    return addr->address + Ustrlen(addr->prefix);
  }
  at = Ustrrchr(addr->address, '@');
  plen = (addr->prefix == NULL) ? 0 : Ustrlen(addr->prefix);
  slen = Ustrlen(addr->suffix);
  return string_sprintf("%.*s@%s", (int)(at - addr->address - plen - slen),
                        addr->address + plen, at + 1);
}

WebString WebGraphicsContext3DDefaultImpl::getShaderSource(WebGLId shader) {
  makeContextCurrent();
  ShaderSourceMap::iterator result = m_shaderSourceMap.find(shader);
  if (result != m_shaderSourceMap.end()) {
    ShaderSourceEntry* entry = result->second;
    ASSERT(entry);
    if (!entry->source) return WebString();
    WebString res = WebString::fromUTF8(entry->source, strlen(entry->source));
    return res;
  }
  GLint logLength = 0;
  glGetShaderiv(shader, GL_SHADER_SOURCE_LENGTH, &logLength);
  if (logLength <= 1) return WebString();
  GLchar* log = 0;
  if (!tryFastMalloc(logLength * sizeof(GLchar)).getValue(log))
    return WebString();
  GLsizei returnedLogLength;
  glGetShaderSource(shader, logLength, &returnedLogLength, log);
  ASSERT(logLength == returnedLogLength + 1);
  WebString res = WebString::fromUTF8(log, returnedLogLength);
  fastFree(log);
  return res;
}

ftp_quit(ftpbuf_t* ftp) {
  if (ftp == NULL) {
    return 0;
  }
  if (!ftp_putcmd(ftp, "QUIT", NULL)) {
    return 0;
  }
  if (!ftp_getresp(ftp) || ftp->resp != 221) {
    return 0;
  }
  if (ftp->pwd) {
    efree(ftp->pwd);
    ftp->pwd = NULL;
  }
  return 1;
}

isdn_timer_ctrl(int tf, int onoff) {
  unsigned long flags;
  int old_tflags;
  spin_lock_irqsave(&dev->timerlock, flags);
  if ((tf & ISDN_TIMER_SLOW) && (!(dev->tflags & ISDN_TIMER_SLOW))) {
    isdn_timer_cnt1 = 0;
    isdn_timer_cnt2 = 0;
  }
  old_tflags = dev->tflags;
  if (onoff)
    dev->tflags |= tf;
  else
    dev->tflags &= ~tf;
  if (dev->tflags && !old_tflags)
    mod_timer(&dev->timer, jiffies + ISDN_TIMER_RES);
  spin_unlock_irqrestore(&dev->timerlock, flags);
}

