dissect_header_lens_v2_large(tvbuff_t* tvb, wtap_syscall_header* syscall_header,
                             int offset, proto_tree* tree, int encoding) {
  guint32 param_count;
  proto_item* ti;
  proto_tree* len_tree;
  ti = proto_tree_add_item(tree, hf_se_param_lens, tvb, offset,
                           syscall_header->nparams * SYSDIG_PARAM_SIZE_V2_LARGE,
                           ENC_NA);
  len_tree = proto_item_add_subtree(ti, ett_sysdig_parm_lens);
  for (param_count = 0; param_count < syscall_header->nparams; param_count++) {
    proto_tree_add_item(len_tree, hf_se_param_len, tvb,
                        offset + (param_count * SYSDIG_PARAM_SIZE_V2_LARGE),
                        SYSDIG_PARAM_SIZE_V2_LARGE, encoding);
  }
  proto_item_set_len(ti, syscall_header->nparams * SYSDIG_PARAM_SIZE_V2_LARGE);
  return syscall_header->nparams * SYSDIG_PARAM_SIZE_V2_LARGE;
}

next_state_class(CClassNode* cc, OnigCodePoint* vs, enum CCVALTYPE* type,
                 enum CCSTATE* state, ScanEnv* env) {
  int r;
  if (*state == CCS_RANGE) return ONIGERR_CHAR_CLASS_VALUE_AT_END_OF_RANGE;
  if (*state == CCS_VALUE && *type != CCV_CLASS) {
    if (*type == CCV_SB)
      BITSET_SET_BIT_CHKDUP(cc->bs, (int)(*vs));
    else if (*type == CCV_CODE_POINT) {
      r = add_code_range(&(cc->mbuf), env, *vs, *vs);
      if (r < 0) return r;
    }
  }
  *state = CCS_VALUE;
  *type = CCV_CLASS;
  return 0;
}

static time_t phar_zip_d2u_time(char* cdtime, char* cddate) {
  int dtime = PHAR_GET_16(cdtime), ddate = PHAR_GET_16(cddate);
  struct tm *tm, tmbuf;
  time_t now;
  now = time(NULL);
  tm = php_localtime_r(&now, &tmbuf);
  tm->tm_year = ((ddate >> 9) & 127) + 1980 - 1900;
  tm->tm_mon = ((ddate >> 5) & 15) - 1;
  tm->tm_mday = ddate & 31;
  tm->tm_hour = (dtime >> 11) & 31;
  tm->tm_min = (dtime >> 5) & 63;
  tm->tm_sec = (dtime << 1) & 62;
  return mktime(tm);
}

