  if (!Exiv2::fileExists(path_, true)) {
    std::cerr << path_ << ": " << _("Failed to open the file\n");
    return -1;
  }
  Exiv2::Image::UniquePtr image = Exiv2::ImageFactory::open(path_);
  image->readMetadata();
  Exiv2::PreviewManager pvMgr(*image);
  Exiv2::PreviewPropertiesList pvList = pvMgr.getPreviewProperties();
  const Params::PreviewNumbers& numbers = Params::instance().previewNumbers_;
  for (auto n = numbers.cbegin(); n != numbers.cend(); ++n) {
    if (*n == 0) {
      for (int num = 0; num < static_cast<int>(pvList.size()); ++num) {
        writePreviewFile(pvMgr.getPreviewImage(pvList[num]), num + 1);
      }
      break;
    }
    if (*n > static_cast<int>(pvList.size())) {
      std::cerr << path_ << ": " << _("Image does not have preview") << " "
                << *n << "\n";
      continue;
    }
    writePreviewFile(pvMgr.getPreviewImage(pvList[*n - 1]), *n);
  }
  return 0;
}

static int rndis_set_response(USBNetState* s, rndis_set_msg_type* buf,
                              unsigned int length) {
  rndis_set_cmplt_type* resp =
      rndis_queue_response(s, sizeof(rndis_set_cmplt_type));
  uint32_t bufoffs, buflen;
  int ret;
  if (!resp) return USB_RET_STALL;
  bufoffs = le32_to_cpu(buf->InformationBufferOffset) + 8;
  buflen = le32_to_cpu(buf->InformationBufferLength);
  if (bufoffs + buflen > length) return USB_RET_STALL;
  ret = ndis_set(s, le32_to_cpu(buf->OID), bufoffs + (uint8_t*)buf, buflen);
  resp->MessageType = cpu_to_le32(RNDIS_SET_CMPLT);
  resp->RequestID = buf->RequestID;
  resp->MessageLength = cpu_to_le32(sizeof(rndis_set_cmplt_type));
  if (ret < 0) {
    resp->Status = cpu_to_le32(RNDIS_STATUS_NOT_SUPPORTED);
    return 0;
  }
  resp->Status = cpu_to_le32(RNDIS_STATUS_SUCCESS);
  return 0;
}

_XimEncodeIMATTRIBUTE(Xim im, XIMResourceList res_list, unsigned int res_num,
                      XIMArg* arg, XIMArg** arg_ret, char* buf, int size,
                      int* ret_len, XPointer top, unsigned long mode) {
  register XIMArg* p;
  XIMResourceList res;
  int check;
  CARD16* buf_s;
  int len;
  int min_len = sizeof(CARD16) + sizeof(INT16);
  *ret_len = 0;
  for (p = arg; p->name; p++) {
    if (!(res = _XimGetResourceListRec(res_list, res_num, p->name))) {
      if (_XimSetInnerIMAttributes(im, top, p, mode)) continue;
      return p->name;
    }
    check = _XimCheckIMMode(res, mode);
    if (check == XIM_CHECK_INVALID)
      continue;
    else if (check == XIM_CHECK_ERROR)
      return p->name;
    if (!(_XimEncodeLocalIMAttr(res, top, p->value))) return p->name;
    buf_s = (CARD16*)buf;
    if (!(_XimValueToAttribute(res, (XPointer)&buf_s[2], (size - min_len),
                               p->value, &len, mode, (XPointer)NULL)))
      return p->name;
    if (len == 0) {
      continue;
    } else if (len < 0) {
      *arg_ret = p;
      return (char*)NULL;
    }
    buf_s[0] = res->id;
    buf_s[1] = len;
    XIM_SET_PAD(&buf_s[2], len);
    len += min_len;
    buf += len;
    *ret_len += len;
    size -= len;
  }
  *arg_ret = (XIMArg*)NULL;
  return (char*)NULL;
}

