void GfxICCBasedColorSpace::getCMYKLine(unsigned char* in, unsigned char* out,
                                        int length) {
#ifdef USE_CMS
  if (lineTransform != nullptr &&
      lineTransform->getTransformPixelType() == PT_CMYK) {
    transform->doTransform(in, out, length);
  } else if (lineTransform != nullptr && nComps != 4) {
    GfxColorComp c, m, y, k;
    unsigned char* tmp =
        (unsigned char*)gmallocn(3 * length, sizeof(unsigned char));
    getRGBLine(in, tmp, length);
    unsigned char* p = tmp;
    for (int i = 0; i < length; i++) {
      c = byteToCol(255 - *p++);
      m = byteToCol(255 - *p++);
      y = byteToCol(255 - *p++);
      k = c;
      if (m < k) {
        k = m;
      }
      if (y < k) {
        k = y;
      }
      *out++ = colToByte(c - k);
      *out++ = colToByte(m - k);
      *out++ = colToByte(y - k);
      *out++ = colToByte(k);
    }
    gfree(tmp);
  } else {
    alt->getCMYKLine(in, out, length);
  }
#else
  alt->getCMYKLine(in, out, length);
#endif
}

int hfs_cat_find_brec(struct super_block* sb, u32 cnid,
                      struct hfs_find_data* fd) {
  hfs_cat_rec rec;
  int res, len, type;
  hfs_cat_build_key(sb, fd->search_key, cnid, NULL);
  res = hfs_brec_read(fd, &rec, sizeof(rec));
  if (res) return res;
  type = rec.type;
  if (type != HFS_CDR_THD && type != HFS_CDR_FTH) {
    printk(KERN_ERR "hfs: found bad thread record in catalog\n");
    return -EIO;
  }
  fd->search_key->cat.ParID = rec.thread.ParID;
  len = fd->search_key->cat.CName.len = rec.thread.CName.len;
  if (len > HFS_NAMELEN) {
    printk(KERN_ERR "hfs: bad catalog namelength\n");
    return -EIO;
  }
  memcpy(fd->search_key->cat.CName.name, rec.thread.CName.name, len);
  return hfs_brec_find(fd);
}

static void addrconf_dad_run(struct inet6_dev* idev) {
  struct inet6_ifaddr* ifp;
  read_lock_bh(&idev->lock);
  list_for_each_entry(ifp, &idev->addr_list, if_list) {
    spin_lock(&ifp->lock);
    if (ifp->flags & IFA_F_TENTATIVE && ifp->state == INET6_IFADDR_STATE_DAD)
      addrconf_dad_kick(ifp);
    spin_unlock(&ifp->lock);
  }
  read_unlock_bh(&idev->lock);
}

get_pubkey_byfprint_fast(PKT_public_key* pk, const byte* fprint,
                         size_t fprint_len) {
  int rc = 0;
  KEYDB_HANDLE hd;
  KBNODE keyblock;
  byte fprbuf[MAX_FINGERPRINT_LEN];
  int i;
  for (i = 0; i < MAX_FINGERPRINT_LEN && i < fprint_len; i++)
    fprbuf[i] = fprint[i];
  while (i < MAX_FINGERPRINT_LEN) fprbuf[i++] = 0;
  hd = keydb_new();
  rc = keydb_search_fpr(hd, fprbuf);
  if (gpg_err_code(rc) == GPG_ERR_NOT_FOUND) {
    keydb_release(hd);
    return G10ERR_NO_PUBKEY;
  }
  rc = keydb_get_keyblock(hd, &keyblock);
  keydb_release(hd);
  if (rc) {
    log_error("keydb_get_keyblock failed: %s\n", g10_errstr(rc));
    return G10ERR_NO_PUBKEY;
  }
  assert(keyblock->pkt->pkttype == PKT_PUBLIC_KEY ||
         keyblock->pkt->pkttype == PKT_PUBLIC_SUBKEY);
  if (pk) copy_public_key(pk, keyblock->pkt->pkt.public_key);
  release_kbnode(keyblock);
  return 0;
}

static int htc_config_pipe_credits(struct htc_target* target) {
  struct sk_buff* skb;
  struct htc_config_pipe_msg* cp_msg;
  int ret;
  unsigned long time_left;
  skb = alloc_skb(50 + sizeof(struct htc_frame_hdr), GFP_ATOMIC);
  if (!skb) {
    dev_err(target->dev, "failed to allocate send buffer\n");
    return -ENOMEM;
  }
  skb_reserve(skb, sizeof(struct htc_frame_hdr));
  cp_msg = skb_put(skb, sizeof(struct htc_config_pipe_msg));
  cp_msg->message_id = cpu_to_be16(HTC_MSG_CONFIG_PIPE_ID);
  cp_msg->pipe_id = USB_WLAN_TX_PIPE;
  cp_msg->credits = target->credits;
  target->htc_flags |= HTC_OP_CONFIG_PIPE_CREDITS;
  ret = htc_issue_send(target, skb, skb->len, 0, ENDPOINT0);
  if (ret) goto err;
  time_left = wait_for_completion_timeout(&target->cmd_wait, HZ);
  if (!time_left) {
    dev_err(target->dev, "HTC credit config timeout\n");
    kfree_skb(skb);
    return -ETIMEDOUT;
  }
  return 0;
err:
  kfree_skb(skb);
  return -EINVAL;
}

static bool not_null_fields_have_null_values(TABLE* table) {
  Field** orig_field = table->field;
  Field** filled_field = table->field_to_fill();
  if (filled_field != orig_field) {
    THD* thd = table->in_use;
    for (uint i = 0; i < table->s->fields; i++) {
      Field* of = orig_field[i];
      Field* ff = filled_field[i];
      if (ff != of) {
        swap_variables(uint32, of->flags, ff->flags);
        if (ff->is_real_null()) {
          ff->set_notnull();
          if (convert_null_to_field_value_or_error(of) || thd->is_error())
            return true;
        }
      }
    }
  }
  return false;
}

DLLEXPORT unsigned long DLLCALL tjBufSizeYUV2(int width, int pad, int height,
                                              int subsamp) {
  int retval = 0, nc, i;
  if (subsamp < 0 || subsamp >= NUMSUBOPT)
    _throwg("tjBufSizeYUV2(): Invalid argument");
  nc = (subsamp == TJSAMP_GRAY ? 1 : 3);
  for (i = 0; i < nc; i++) {
    int pw = tjPlaneWidth(i, width, subsamp);
    int stride = PAD(pw, pad);
    int ph = tjPlaneHeight(i, height, subsamp);
    if (pw < 0 || ph < 0)
      return -1;
    else
      retval += stride * ph;
  }
bailout:
  return retval;
}

or_code_range_buf(OnigEncoding enc, BBuf* bbuf1, int not1, BBuf* bbuf2,
                  int not2, BBuf** pbuf, ScanEnv* env) {
  int r;
  OnigCodePoint i, n1, *data1;
  OnigCodePoint from, to;
  *pbuf = (BBuf*)NULL;
  if (IS_NULL(bbuf1) && IS_NULL(bbuf2)) {
    if (not1 != 0 || not2 != 0) return SET_ALL_MULTI_BYTE_RANGE(enc, pbuf);
    return 0;
  }
  r = 0;
  if (IS_NULL(bbuf2)) SWAP_BBUF_NOT(bbuf1, not1, bbuf2, not2);
  if (IS_NULL(bbuf1)) {
    if (not1 != 0) {
      return SET_ALL_MULTI_BYTE_RANGE(enc, pbuf);
    } else {
      if (not2 == 0) {
        return bbuf_clone(pbuf, bbuf2);
      } else {
        return not_code_range_buf(enc, bbuf2, pbuf, env);
      }
    }
  }
  if (not1 != 0) SWAP_BBUF_NOT(bbuf1, not1, bbuf2, not2);
  data1 = (OnigCodePoint*)(bbuf1->p);
  GET_CODE_POINT(n1, data1);
  data1++;
  if (not2 == 0 && not1 == 0) {
    r = bbuf_clone(pbuf, bbuf2);
  } else if (not1 == 0) {
    r = not_code_range_buf(enc, bbuf2, pbuf, env);
  }
  if (r != 0) return r;
  for (i = 0; i < n1; i++) {
    from = data1[i * 2];
    to = data1[i * 2 + 1];
    r = add_code_range_to_buf(pbuf, env, from, to);
    if (r != 0) return r;
  }
  return 0;
}

