static void bnx2x_pbf_pN_cmd_flushed(struct bnx2x* bp,
                                     struct pbf_pN_cmd_regs* regs,
                                     u32 poll_count) {
  u32 occup, to_free, freed, freed_start;
  u32 cur_cnt = poll_count;
  occup = to_free = REG_RD(bp, regs->lines_occup);
  freed = freed_start = REG_RD(bp, regs->lines_freed);
  DP(BNX2X_MSG_SP, "OCCUPANCY[%d]   : s:%x\n", regs->pN, occup);
  DP(BNX2X_MSG_SP, "LINES_FREED[%d] : s:%x\n", regs->pN, freed);
  while (occup && ((u32)SUB_S32(freed, freed_start) < to_free)) {
    if (cur_cnt--) {
      udelay(FLR_WAIT_INTERVAL);
      occup = REG_RD(bp, regs->lines_occup);
      freed = REG_RD(bp, regs->lines_freed);
    } else {
      DP(BNX2X_MSG_SP, "PBF cmd queue[%d] timed out\n", regs->pN);
      DP(BNX2X_MSG_SP, "OCCUPANCY[%d]   : s:%x\n", regs->pN, occup);
      DP(BNX2X_MSG_SP, "LINES_FREED[%d] : s:%x\n", regs->pN, freed);
      break;
    }
  }
  DP(BNX2X_MSG_SP, "Waited %d*%d usec for PBF cmd queue[%d]\n",
     poll_count - cur_cnt, FLR_WAIT_INTERVAL, regs->pN);
}

setup_new_fields(THD* thd, List<Item>& fields, List<Item>& all_fields,
                 ORDER* new_field) {
  Item** item;
  uint counter;
  enum_resolution_type not_used;
  DBUG_ENTER("setup_new_fields");
  thd->column_usage = MARK_COLUMNS_READ;
  for (; new_field; new_field = new_field->next) {
    if ((item = find_item_in_list(*new_field->item, fields, &counter,
                                  IGNORE_ERRORS, &not_used)))
      new_field->item = item;
    else {
      thd->where = "procedure list";
      if ((*new_field->item)->fix_fields(thd, new_field->item)) DBUG_RETURN(1);
      all_fields.push_front(*new_field->item, thd->mem_root);
      new_field->item = all_fields.head_ref();
    }
  }
  DBUG_RETURN(0);
}

