cmp_node(const struct archive_rb_node* n1, const struct archive_rb_node* n2) {
  const struct zip_entry* e1 = (const struct zip_entry*)n1;
  const struct zip_entry* e2 = (const struct zip_entry*)n2;
  if (e1->local_header_offset > e2->local_header_offset) return -1;
  if (e1->local_header_offset < e2->local_header_offset) return 1;
  return 0;
}

static int check_func_call(struct bpf_verifier_env* env, struct bpf_insn* insn,
                           int* insn_idx) {
  struct bpf_verifier_state* state = env->cur_state;
  struct bpf_func_state *caller, *callee;
  int i, subprog, target_insn;
  if (state->curframe + 1 >= MAX_CALL_FRAMES) {
    verbose(env, "the call stack of %d frames is too deep\n",
            state->curframe + 2);
    return -E2BIG;
  }
  target_insn = *insn_idx + insn->imm;
  subprog = find_subprog(env, target_insn + 1);
  if (subprog < 0) {
    verbose(env, "verifier bug. No program starts at insn %d\n",
            target_insn + 1);
    return -EFAULT;
  }
  caller = state->frame[state->curframe];
  if (state->frame[state->curframe + 1]) {
    verbose(env, "verifier bug. Frame %d already allocated\n",
            state->curframe + 1);
    return -EFAULT;
  }
  callee = kzalloc(sizeof(*callee), GFP_KERNEL);
  if (!callee) return -ENOMEM;
  state->frame[state->curframe + 1] = callee;
  init_func_state(env, callee, *insn_idx, state->curframe + 1, subprog);
  for (i = BPF_REG_1; i <= BPF_REG_5; i++) callee->regs[i] = caller->regs[i];
  for (i = 0; i < CALLER_SAVED_REGS; i++) {
    mark_reg_not_init(env, caller->regs, caller_saved[i]);
    check_reg_arg(env, caller_saved[i], DST_OP_NO_MARK);
  }
  state->curframe++;
  *insn_idx = target_insn;
  if (env->log.level) {
    verbose(env, "caller:\n");
    print_verifier_state(env, caller);
    verbose(env, "callee:\n");
    print_verifier_state(env, callee);
  }
  return 0;
}

static unsigned update_adler32(unsigned adler, const unsigned char* data,
                               unsigned len) {
  unsigned s1 = adler & 0xffff;
  unsigned s2 = (adler >> 16) & 0xffff;
  while (len > 0) {
    unsigned amount = len > 5550 ? 5550 : len;
    len -= amount;
    while (amount > 0) {
      s1 += (*data++);
      s2 += s1;
      amount--;
    }
    s1 %= 65521;
    s2 %= 65521;
  }
  return (s2 << 16) | s1;
}

