static void put_pi_state(struct futex_pi_state* pi_state) {
  if (!pi_state) return;
  if (!atomic_dec_and_test(&pi_state->refcount)) return;
  if (pi_state->owner) {
    raw_spin_lock_irq(&pi_state->owner->pi_lock);
    list_del_init(&pi_state->list);
    raw_spin_unlock_irq(&pi_state->owner->pi_lock);
    rt_mutex_proxy_unlock(&pi_state->pi_mutex, pi_state->owner);
  }
  if (current->pi_state_cache)
    kfree(pi_state);
  else {
    pi_state->owner = NULL;
    atomic_set(&pi_state->refcount, 1);
    current->pi_state_cache = pi_state;
  }
}

save_to_file_cb(const gchar* buf, gsize count, GError** error, gpointer data) {
  gint bytes;
  while (count > 0) {
    bytes = fwrite(buf, sizeof(gchar), count, (FILE*)data);
    if (bytes <= 0) break;
    count -= bytes;
    buf += bytes;
  }
  if (count) {
    g_set_error_literal(error, GDK_PIXBUF_ERROR, GDK_PIXBUF_ERROR_FAILED,
                        _("Couldn't write to TIFF file"));
    return FALSE;
  }
  return TRUE;
}

