    GF_LOG(GF_LOG_INFO, GF_LOG_APP, (",resolved SID:%s", f->source_ids));
  GF_LOG(GF_LOG_INFO, GF_LOG_APP, (")"));
}

ssize_t tcp_splice_read(struct socket* sock, loff_t* ppos,
                        struct pipe_inode_info* pipe, size_t len,
                        unsigned int flags) {
  struct sock* sk = sock->sk;
  struct tcp_splice_state tss = {
      .pipe = pipe,
      .len = len,
      .flags = flags,
  };
  long timeo;
  ssize_t spliced;
  int ret;
  sock_rps_record_flow(sk);
  if (unlikely(*ppos)) return -ESPIPE;
  ret = spliced = 0;
  lock_sock(sk);
  timeo = sock_rcvtimeo(sk, sock->file->f_flags & O_NONBLOCK);
  while (tss.len) {
    ret = __tcp_splice_read(sk, &tss);
    if (ret < 0)
      break;
    else if (!ret) {
      if (spliced) break;
      if (sock_flag(sk, SOCK_DONE)) break;
      if (sk->sk_err) {
        ret = sock_error(sk);
        break;
      }
      if (sk->sk_shutdown & RCV_SHUTDOWN) break;
      if (sk->sk_state == TCP_CLOSE) {
        if (!sock_flag(sk, SOCK_DONE)) ret = -ENOTCONN;
        break;
      }
      if (!timeo) {
        ret = -EAGAIN;
        break;
      }
      if (!skb_queue_empty(&sk->sk_receive_queue)) break;
      sk_wait_data(sk, &timeo, NULL);
      if (signal_pending(current)) {
        ret = sock_intr_errno(timeo);
        break;
      }
      continue;
    }
    tss.len -= ret;
    spliced += ret;
    if (!timeo) break;
    release_sock(sk);
    lock_sock(sk);
    if (sk->sk_err || sk->sk_state == TCP_CLOSE ||
        (sk->sk_shutdown & RCV_SHUTDOWN) || signal_pending(current))
      break;
  }
  release_sock(sk);
  if (spliced) return spliced;
  return ret;
}

static int php_read_APP(const req::ptr<File>& stream, unsigned int marker,
                        Array& info) {
  unsigned short length;
  unsigned char markername[16];
  length = php_read2(stream);
  if (length < 2) {
    return 0;
  }
  length -= 2;
  String buffer = stream->read(length);
  if (buffer.empty()) {
    return 0;
  }
  snprintf((char*)markername, sizeof(markername), "APP%d", marker - M_APP0);
  if (!info.exists(String((const char*)markername))) {
    info.set(String((char*)markername, CopyString), buffer);
  }
  return 1;
}

emacs_tags_parse_line(char_u* lbuf, tagptrs_T* tagp) {
  char_u* p_7f;
  char_u* p;
  p_7f = vim_strchr(lbuf, 0x7f);
  if (p_7f == NULL) {
  etag_fail:
    if (vim_strchr(lbuf, '\n') != NULL) return FAIL;
    if (p_verbose >= 5) {
      verbose_enter();
      msg(_("Ignoring long line in tags file"));
      verbose_leave();
    }
    tagp->command = lbuf;
    tagp->tagname = lbuf;
    tagp->tagname_end = lbuf;
    return OK;
  }
  p = vim_strchr(p_7f, Ctrl_A);
  if (p == NULL)
    p = p_7f + 1;
  else
    ++p;
  if (!VIM_ISDIGIT(*p)) goto etag_fail;
  tagp->command = p;
  if (p[-1] == Ctrl_A) {
    tagp->tagname = p_7f + 1;
    tagp->tagname_end = p - 1;
  } else {
    for (p = p_7f - 1; !vim_iswordc(*p); --p)
      if (p == lbuf) goto etag_fail;
    tagp->tagname_end = p + 1;
    while (p >= lbuf && vim_iswordc(*p)) --p;
    tagp->tagname = p + 1;
  }
  return OK;
}

static int vhost_vdpa_release(struct inode* inode, struct file* filep) {
  struct vhost_vdpa* v = filep->private_data;
  struct vhost_dev* d = &v->vdev;
  mutex_lock(&d->mutex);
  filep->private_data = NULL;
  vhost_vdpa_reset(v);
  vhost_dev_stop(&v->vdev);
  vhost_vdpa_iotlb_free(v);
  vhost_vdpa_free_domain(v);
  vhost_vdpa_config_put(v);
  vhost_vdpa_clean_irq(v);
  vhost_dev_cleanup(&v->vdev);
  kfree(v->vdev.vqs);
  mutex_unlock(&d->mutex);
  atomic_dec(&v->opened);
  complete(&v->completion);
  return 0;
}

static void vhost_net_flush(struct vhost_net* n) {
  vhost_net_flush_vq(n, VHOST_NET_VQ_TX);
  vhost_net_flush_vq(n, VHOST_NET_VQ_RX);
  if (n->dev.vqs[VHOST_NET_VQ_TX].ubufs) {
    mutex_lock(&n->dev.vqs[VHOST_NET_VQ_TX].mutex);
    n->tx_flush = true;
    mutex_unlock(&n->dev.vqs[VHOST_NET_VQ_TX].mutex);
    vhost_ubuf_put_and_wait(n->dev.vqs[VHOST_NET_VQ_TX].ubufs);
    mutex_lock(&n->dev.vqs[VHOST_NET_VQ_TX].mutex);
    n->tx_flush = false;
    kref_init(&n->dev.vqs[VHOST_NET_VQ_TX].ubufs->kref);
    mutex_unlock(&n->dev.vqs[VHOST_NET_VQ_TX].mutex);
  }
}

CImg<T>& RGBtoHSI() {
  if (_spectrum != 3)
    throw CImgInstanceException(_cimg_instance
                                "RGBtoHSI(): Instance is not a RGB image.",
                                cimg_instance);
  T *p1 = data(0, 0, 0, 0), *p2 = data(0, 0, 0, 1), *p3 = data(0, 0, 0, 2);
  const ulongT whd = (ulongT)_width * _height * _depth;
      cimg_pragma_openmp(parallel for cimg_openmp_if(whd>=256))
      for (ulongT N = 0; N<whd; ++N) {
        const Tfloat R = (Tfloat)p1[N], G = (Tfloat)p2[N], B = (Tfloat)p3[N],
                     theta = (Tfloat)(std::acos(0.5f * ((R - G) + (R - B)) /
                                                std::sqrt(cimg::sqr(R - G) +
                                                          (R - B) * (G - B))) *
                                      180 / cimg::PI),
                     m = cimg::min(R, G, B), sum = R + G + B;
        Tfloat H = 0, S = 0, I = 0;
        if (theta > 0) H = B <= G ? theta : 360 - theta;
        if (sum > 0) S = 1 - 3 * m / sum;
        I = sum / (3 * 255);
        p1[N] = (T)cimg::cut(H, 0, 360);
        p2[N] = (T)cimg::cut(S, 0, 1);
        p3[N] = (T)cimg::cut(I, 0, 1);
      }
      return *this;

static int phar_zip_process_extra(php_stream* fp, phar_entry_info* entry,
                                  php_uint16 len TSRMLS_DC) {
  union {
    phar_zip_extra_field_header header;
    phar_zip_unix3 unix3;
  } h;
  int read;
  do {
    if (sizeof(h.header) !=
        php_stream_read(fp, (char*)&h.header, sizeof(h.header))) {
      return FAILURE;
    }
    if (h.header.tag[0] != 'n' || h.header.tag[1] != 'u') {
      php_stream_seek(fp, PHAR_GET_16(h.header.size), SEEK_CUR);
      len -= PHAR_GET_16(h.header.size) + 4;
      continue;
    }
    read = php_stream_read(fp, (char*)&(h.unix3.crc32),
                           sizeof(h.unix3) - sizeof(h.header));
    len -= read + 4;
    if (sizeof(h.unix3) - sizeof(h.header) != read) {
      return FAILURE;
    }
    if (PHAR_GET_16(h.unix3.size) > sizeof(h.unix3) - 4) {
      php_stream_seek(fp, PHAR_GET_16(h.unix3.size) - sizeof(h.unix3.size),
                      SEEK_CUR);
    }
    entry->flags &= PHAR_ENT_COMPRESSION_MASK;
    if (entry->is_dir) {
      entry->flags |= PHAR_GET_16(h.unix3.perms) & PHAR_ENT_PERM_MASK;
    } else {
      entry->flags |= PHAR_GET_16(h.unix3.perms) & PHAR_ENT_PERM_MASK;
    }
  } while (len);
  return SUCCESS;
}

