AP_DECLARE(int) ap_get_basic_auth_pw(request_rec* r, const char** pw) {
  const char* auth_line = apr_table_get(
      r->headers_in, (PROXYREQ_PROXY == r->proxyreq) ? "Proxy-Authorization"
                                                     : "Authorization");
  const char* t;
  if (!(t = ap_auth_type(r)) || strcasecmp(t, "Basic")) return DECLINED;
  if (!ap_auth_name(r)) {
    ap_log_rerror(APLOG_MARK, APLOG_ERR, 0, r,
                  APLOGNO(00572) "need AuthName: %s", r->uri);
    return HTTP_INTERNAL_SERVER_ERROR;
  }
  if (!auth_line) {
    ap_note_auth_failure(r);
    return HTTP_UNAUTHORIZED;
  }
  if (strcasecmp(ap_getword(r->pool, &auth_line, ' '), "Basic")) {
    ap_log_rerror(APLOG_MARK, APLOG_INFO, 0, r,
                  APLOGNO(00573) "client used wrong authentication scheme: %s",
                  r->uri);
    ap_note_auth_failure(r);
    return HTTP_UNAUTHORIZED;
  }
  while (*auth_line == ' ' || *auth_line == '\t') {
    auth_line++;
  }
  t = ap_pbase64decode(r->pool, auth_line);
  r->user = ap_getword_nulls(r->pool, &t, ':');
  r->ap_auth_type = "Basic";
  *pw = t;
  return OK;
}

static int meth_propfind_root(struct transaction_t* txn,
                              void* params __attribute__((unused))) {
  assert(txn);
#ifdef WITH_DAV
  if (!strcmp(txn->req_uri->path, "/") ||
      !strcmp(txn->req_uri->path, "/dav/")) {
    const struct prop_entry root_props[] = {
        {"principal-collection-set", NS_DAV, PROP_COLLECTION,
         propfind_princolset, NULL, NULL},
        {"current-user-principal", NS_DAV, PROP_COLLECTION, propfind_curprin,
         NULL, NULL},
        {NULL, 0, 0, NULL, NULL, NULL}};
    struct meth_params root_params = {
        .propfind = {DAV_FINITE_DEPTH, root_props}};
    strlcpy(txn->req_tgt.path, txn->req_uri->path, sizeof(txn->req_tgt.path));
    txn->req_tgt.tail = txn->req_tgt.path + strlen(txn->req_tgt.path);
    txn->req_tgt.allow |= ALLOW_DAV;
    return meth_propfind(txn, &root_params);
  }
#endif
  return HTTP_NOT_ALLOWED;
}

static unsigned long get_min_memlimit(const char* cgroup) {
  char* copy = strdupa(cgroup);
  unsigned long memlimit = 0, retlimit;
  retlimit = get_memlimit(copy);
  while (strcmp(copy, "/") != 0) {
    copy = dirname(copy);
    memlimit = get_memlimit(copy);
    if (memlimit != -1 && memlimit < retlimit) retlimit = memlimit;
  };
  return retlimit;
}

static int ep_poll_callback(wait_queue_t* wait, unsigned mode, int sync,
                            void* key) {
  int pwake = 0;
  unsigned long flags;
  struct epitem* epi = ep_item_from_wait(wait);
  struct eventpoll* ep = epi->ep;
  if ((unsigned long)key & POLLFREE) {
    ep_pwq_from_wait(wait)->whead = NULL;
    list_del_init(&wait->task_list);
  }
  spin_lock_irqsave(&ep->lock, flags);
  if (!(epi->event.events & ~EP_PRIVATE_BITS)) goto out_unlock;
  if (key && !((unsigned long)key & epi->event.events)) goto out_unlock;
  if (unlikely(ep->ovflist != EP_UNACTIVE_PTR)) {
    if (epi->next == EP_UNACTIVE_PTR) {
      epi->next = ep->ovflist;
      ep->ovflist = epi;
    }
    goto out_unlock;
  }
  if (!ep_is_linked(&epi->rdllink)) list_add_tail(&epi->rdllink, &ep->rdllist);
  if (waitqueue_active(&ep->wq)) wake_up_locked(&ep->wq);
  if (waitqueue_active(&ep->poll_wait)) pwake++;
out_unlock:
  spin_unlock_irqrestore(&ep->lock, flags);
  if (pwake) ep_poll_safewake(&ep->poll_wait);
  return 1;
}

xps_true_callback_build_char(gs_show_enum* penum, gs_gstate* pgs,
                             gs_font* pfont, gs_char chr, gs_glyph glyph) {
  gs_font_type42* p42 = (gs_font_type42*)pfont;
  const gs_rect* pbbox;
  float sbw[4], w2[6];
  gs_fixed_point saved_adjust;
  int code;
  code = gs_type42_get_metrics(p42, glyph, sbw);
  if (code < 0) return code;
  w2[0] = sbw[2];
  w2[1] = sbw[3];
  pbbox = &p42->FontBBox;
  w2[2] = pbbox->p.x;
  w2[3] = pbbox->p.y;
  w2[4] = pbbox->q.x;
  w2[5] = pbbox->q.y;
  if (pfont->PaintType) {
    float expand =
        max(1.415, gs_currentmiterlimit(pgs)) * gs_currentlinewidth(pgs) / 2;
    w2[2] -= expand, w2[3] -= expand;
    w2[4] += expand, w2[5] += expand;
  }
  if ((code = gs_moveto(pgs, 0.0, 0.0)) < 0) return code;
  if ((code = gs_setcachedevice(penum, pgs, w2)) < 0) return code;
  code =
      gs_type42_append(glyph, pgs, gx_current_path(pgs), (gs_text_enum_t*)penum,
                       (gs_font*)p42, gs_show_in_charpath(penum) != cpm_show);
  if (code < 0) return code;
  saved_adjust = pgs->fill_adjust;
  pgs->fill_adjust.x = -1;
  pgs->fill_adjust.y = -1;
  code = (pfont->PaintType ? gs_stroke(pgs) : gs_fill(pgs));
  if (code < 0) return code;
  pgs->fill_adjust = saved_adjust;
  return 0;
}

