match_init_copy(VALUE obj, VALUE orig) {
  struct rmatch* rm;
  if (!OBJ_INIT_COPY(obj, orig)) return obj;
  RMATCH(obj)->str = RMATCH(orig)->str;
  RMATCH(obj)->regexp = RMATCH(orig)->regexp;
  rm = RMATCH(obj)->rmatch;
  if (rb_reg_region_copy(&rm->regs, RMATCH_REGS(orig))) rb_memerror();
  if (!RMATCH(orig)->rmatch->char_offset_updated) {
    rm->char_offset_updated = 0;
  } else {
    if (rm->char_offset_num_allocated < rm->regs.num_regs) {
      REALLOC_N(rm->char_offset, struct rmatch_offset, rm->regs.num_regs);
      rm->char_offset_num_allocated = rm->regs.num_regs;
    }
    MEMCPY(rm->char_offset, RMATCH(orig)->rmatch->char_offset,
           struct rmatch_offset, rm->regs.num_regs);
    rm->char_offset_updated = 1;
    RB_GC_GUARD(orig);
  }
  return obj;
}

void CompactProtocolReader::readStringBody(StrType& str, int32_t size) {
  if (static_cast<int32_t>(in_.length()) < size) {
    if (!in_.canAdvance(size)) {
      protocol::TProtocolException::throwTruncatedData();
    }
    str.reserve(size);
  }
  str.clear();
  size_t size_left = size;
  while (size_left > 0) {
    auto data = in_.peekBytes();
    auto data_avail = std::min(data.size(), size_left);
    if (data.empty()) {
      TProtocolException::throwExceededSizeLimit();
    }
    str.append((const char*)data.data(), data_avail);
    size_left -= data_avail;
    in_.skipNoAdvance(data_avail);
  }
}

static int rfcomm_sock_getsockopt_old(struct socket* sock, int optname,
                                      char __user* optval, int __user* optlen) {
  struct sock* sk = sock->sk;
  struct rfcomm_conninfo cinfo;
  struct l2cap_conn* conn = l2cap_pi(sk)->chan->conn;
  int len, err = 0;
  u32 opt;
  BT_DBG("sk %p", sk);
  if (get_user(len, optlen)) return -EFAULT;
  lock_sock(sk);
  switch (optname) {
    case RFCOMM_LM:
      switch (rfcomm_pi(sk)->sec_level) {
        case BT_SECURITY_LOW:
          opt = RFCOMM_LM_AUTH;
          break;
        case BT_SECURITY_MEDIUM:
          opt = RFCOMM_LM_AUTH | RFCOMM_LM_ENCRYPT;
          break;
        case BT_SECURITY_HIGH:
          opt = RFCOMM_LM_AUTH | RFCOMM_LM_ENCRYPT | RFCOMM_LM_SECURE;
          break;
        default:
          opt = 0;
          break;
      }
      if (rfcomm_pi(sk)->role_switch) opt |= RFCOMM_LM_MASTER;
      if (put_user(opt, (u32 __user*)optval)) err = -EFAULT;
      break;
    case RFCOMM_CONNINFO:
      if (sk->sk_state != BT_CONNECTED && !rfcomm_pi(sk)->dlc->defer_setup) {
        err = -ENOTCONN;
        break;
      }
      memset(&cinfo, 0, sizeof(cinfo));
      cinfo.hci_handle = conn->hcon->handle;
      memcpy(cinfo.dev_class, conn->hcon->dev_class, 3);
      len = min_t(unsigned int, len, sizeof(cinfo));
      if (copy_to_user(optval, (char*)&cinfo, len)) err = -EFAULT;
      break;
    default:
      err = -ENOPROTOOPT;
      break;
  }
  release_sock(sk);
  return err;
}

