void CiffComponent::doRead(const byte* pData, uint32_t size, uint32_t start,
                           ByteOrder byteOrder) {
  if (size < 10) throw Error(kerNotACrwImage);
  tag_ = getUShort(pData + start, byteOrder);
  DataLocId dl = dataLocation();
  assert(dl == directoryData || dl == valueData);
  if (dl == valueData) {
    size_ = getULong(pData + start + 2, byteOrder);
    offset_ = getULong(pData + start + 6, byteOrder);
  }
  if (size_ > size || offset_ > size) throw Error(kerOffsetOutOfRange);
  if (dl == directoryData) {
    size_ = 8;
    offset_ = start + 2;
  }
  pData_ = pData + offset_;
#ifdef DEBUG
  std::cout << "  Entry for tag 0x" << std::hex << tagId() << " (0x" << tag()
            << "), " << std::dec << size_ << " Bytes, Offset is " << offset_
            << "\n";
#endif
}

utf16le_mbc_case_fold(OnigCaseFoldType flag, const UChar** pp, const UChar* end,
                      UChar* fold) {
  const UChar* p = *pp;
  if (ONIGENC_IS_ASCII_CODE(*p) && *(p + 1) == 0) {
#ifdef USE_UNICODE_CASE_FOLD_TURKISH_AZERI
    if ((flag & ONIGENC_CASE_FOLD_TURKISH_AZERI) != 0) {
      if (*p == 0x49) {
        *fold++ = 0x31;
        *fold = 0x01;
        (*pp) += 2;
        return 2;
      }
    }
#endif
    *fold++ = ONIGENC_ASCII_CODE_TO_LOWER_CASE(*p);
    *fold = 0;
    *pp += 2;
    return 2;
  } else
    return onigenc_unicode_mbc_case_fold(ONIG_ENCODING_UTF16_LE, flag, pp, end,
                                         fold);
}

void write(OutputStream& stream) const {
  stream.write_or_error(
      {local_file_header_signature, sizeof(local_file_header_signature)});
  stream << minimum_version;
  stream << general_purpose_flags;
  stream << compression_method;
  stream << modification_time;
  stream << modification_date;
  stream << crc32;
  stream << compressed_size;
  stream << uncompressed_size;
  stream << name_length;
  stream << extra_data_length;
  if (name_length > 0) stream.write_or_error({name, name_length});
  if (extra_data_length > 0)
    stream.write_or_error({extra_data, extra_data_length});
  if (compressed_size > 0)
    stream.write_or_error({compressed_data, compressed_size});
}

GC_INNER void* GC_generic_malloc_ignore_off_page(size_t lb, int k) {
  void* result;
  size_t lg;
  size_t lb_rounded;
  word n_blocks;
  GC_bool init;
  DCL_LOCK_STATE;
  if (SMALL_OBJ(lb)) return (GC_generic_malloc((word)lb, k));
  lg = ROUNDED_UP_GRANULES(lb);
  lb_rounded = GRANULES_TO_BYTES(lg);
  if (lb_rounded < lb) return ((*GC_get_oom_fn())(lb));
  n_blocks = OBJ_SZ_TO_BLOCKS(lb_rounded);
  init = GC_obj_kinds[k].ok_init;
  if (EXPECT(GC_have_errors, FALSE)) GC_print_all_errors();
  GC_INVOKE_FINALIZERS();
  LOCK();
  result = (ptr_t)GC_alloc_large(ADD_SLOP(lb), k, IGNORE_OFF_PAGE);
  if (0 != result) {
    if (GC_debugging_started) {
      BZERO(result, n_blocks * HBLKSIZE);
    } else {
#ifdef THREADS
      ((word*)result)[0] = 0;
      ((word*)result)[1] = 0;
      ((word*)result)[GRANULES_TO_WORDS(lg) - 1] = 0;
      ((word*)result)[GRANULES_TO_WORDS(lg) - 2] = 0;
#endif
    }
  }
  GC_bytes_allocd += lb_rounded;
  if (0 == result) {
    GC_oom_func oom_fn = GC_oom_fn;
    UNLOCK();
    return ((*oom_fn)(lb));
  } else {
    UNLOCK();
    if (init && !GC_debugging_started) {
      BZERO(result, n_blocks * HBLKSIZE);
    }
    return (result);
  }
}

static unsigned long emulator_get_cr(int cr, struct kvm_vcpu* vcpu) {
  unsigned long value;
  switch (cr) {
    case 0:
      value = kvm_read_cr0(vcpu);
      break;
    case 2:
      value = vcpu->arch.cr2;
      break;
    case 3:
      value = vcpu->arch.cr3;
      break;
    case 4:
      value = kvm_read_cr4(vcpu);
      break;
    case 8:
      value = kvm_get_cr8(vcpu);
      break;
    default:
      vcpu_printf(vcpu, "%s: unexpected cr %u\n", __func__, cr);
      return 0;
  }
  return value;
}

