rb_buffer_peek(struct ring_buffer_per_cpu* cpu_buffer, u64* ts,
               unsigned long* lost_events) {
  struct ring_buffer_event* event;
  struct buffer_page* reader;
  int nr_loops = 0;
  if (ts) *ts = 0;
again:
  if (RB_WARN_ON(cpu_buffer, ++nr_loops > 2)) return NULL;
  reader = rb_get_reader_page(cpu_buffer);
  if (!reader) return NULL;
  event = rb_reader_event(cpu_buffer);
  switch (event->type_len) {
    case RINGBUF_TYPE_PADDING:
      if (rb_null_event(event)) RB_WARN_ON(cpu_buffer, 1);
      return event;
    case RINGBUF_TYPE_TIME_EXTEND:
      rb_advance_reader(cpu_buffer);
      goto again;
    case RINGBUF_TYPE_TIME_STAMP:
      if (ts) {
        *ts = rb_event_time_stamp(event);
        ring_buffer_normalize_time_stamp(cpu_buffer->buffer, cpu_buffer->cpu,
                                         ts);
      }
      rb_advance_reader(cpu_buffer);
      goto again;
    case RINGBUF_TYPE_DATA:
      if (ts && !(*ts)) {
        *ts = cpu_buffer->read_stamp + event->time_delta;
        ring_buffer_normalize_time_stamp(cpu_buffer->buffer, cpu_buffer->cpu,
                                         ts);
      }
      if (lost_events) *lost_events = rb_lost_events(cpu_buffer);
      return event;
    default:
      RB_WARN_ON(cpu_buffer, 1);
  }
  return NULL;
}

