std::string get_wml_location(const std::string& filename,
                             const std::string& current_dir) {
  DBG_FS << "Looking for '" << filename << "'." << std::endl;
  assert(game_config::path.empty() == false);
  std::string result;
  if (filename.empty()) {
    LOG_FS << "  invalid filename" << std::endl;
    return result;
  }
  if (filename.find("..") != std::string::npos) {
    ERR_FS << "Illegal path '" << filename << "' (\"..\" not allowed)."
           << std::endl;
    return result;
  }
  if (looks_like_pbl(filename)) {
    ERR_FS << "Illegal path '" << filename << "' (.pbl files are not allowed)."
           << std::endl;
    return result;
  }
  bool already_found = false;
  if (filename[0] == '~') {
    result = get_user_data_dir() + "/data/" + filename.substr(1);
    DBG_FS << "  trying '" << result << "'" << std::endl;
    already_found = file_exists(result) || is_directory(result);
  } else if (filename.size() >= 2 && filename[0] == '.' && filename[1] == '/') {
    if (!current_dir.empty()) {
      result = current_dir;
    } else {
      result = game_config::path;
    }
    result += filename.substr(2);
  } else if (!game_config::path.empty())
    result = game_config::path + "/data/" + filename;
  DBG_FS << "  trying '" << result << "'" << std::endl;
  if (result.empty() ||
      (!already_found && !file_exists(result) && !is_directory(result))) {
    DBG_FS << "  not found" << std::endl;
    result.clear();
  } else
    DBG_FS << "  found: '" << result << "'" << std::endl;
  return result;
}

process_preamble(proto_tree* tree, tvbuff_t* tvb, multipart_info_t* m_info,
                 gboolean* last_boundary) {
  gint boundary_start, boundary_line_len;
  const guint8* boundary = (guint8*)m_info->boundary;
  gint boundary_len = m_info->boundary_length;
  boundary_start = find_first_boundary(tvb, 0, boundary, boundary_len,
                                       &boundary_line_len, last_boundary);
  if (boundary_start == 0) {
    proto_tree_add_item(tree, hf_multipart_first_boundary, tvb, boundary_start,
                        boundary_line_len, ENC_NA | ENC_ASCII);
    return boundary_start + boundary_line_len;
  } else if (boundary_start > 0) {
    if (boundary_line_len > 0) {
      gint body_part_start = boundary_start + boundary_line_len;
      if (boundary_start > 0) {
        proto_tree_add_item(tree, hf_multipart_preamble, tvb, 0, boundary_start,
                            ENC_NA);
      }
      proto_tree_add_item(tree, hf_multipart_first_boundary, tvb,
                          boundary_start, boundary_line_len,
                          ENC_NA | ENC_ASCII);
      return body_part_start;
    }
  }
  return -1;
}

sc_oberthur_get_friends(unsigned int id, struct crypto_container* ccont) {
  struct container* cont;
  for (cont = Containers; cont; cont = cont->next) {
    if (cont->exchange.id_pub == id || cont->exchange.id_prv == id ||
        cont->exchange.id_cert == id) {
      if (ccont)
        memcpy(ccont, &cont->exchange, sizeof(struct crypto_container));
      break;
    }
    if (cont->sign.id_pub == id || cont->sign.id_prv == id ||
        cont->sign.id_cert == id) {
      if (ccont) memcpy(ccont, &cont->sign, sizeof(struct crypto_container));
      break;
    }
  }
  return cont ? 0 : SC_ERROR_TEMPLATE_NOT_FOUND;
}

BOOL license_send(rdpLicense* license, wStream* s, BYTE type) {
  int length;
  BYTE flags;
  UINT16 wMsgSize;
  UINT16 sec_flags;
  DEBUG_LICENSE("Sending %s Packet", LICENSE_MESSAGE_STRINGS[type & 0x1F]);
  length = Stream_GetPosition(s);
  Stream_SetPosition(s, 0);
  sec_flags = SEC_LICENSE_PKT;
  wMsgSize = length - LICENSE_PACKET_HEADER_MAX_LENGTH + 4;
  flags = PREAMBLE_VERSION_3_0;
  if (!license->rdp->settings->ServerMode)
    flags |= EXTENDED_ERROR_MSG_SUPPORTED;
  rdp_write_header(license->rdp, s, length, MCS_GLOBAL_CHANNEL_ID);
  rdp_write_security_header(s, sec_flags);
  license_write_preamble(s, type, flags, wMsgSize);
#ifdef WITH_DEBUG_LICENSE
  fprintf(stderr, "Sending %s Packet, length %d\n",
          LICENSE_MESSAGE_STRINGS[type & 0x1F], wMsgSize);
  winpr_HexDump(Stream_Pointer(s) - 4, wMsgSize);
#endif
  Stream_SetPosition(s, length);
  Stream_SealLength(s);
  if (transport_write(license->rdp->transport, s) < 0) return FALSE;
  Stream_Free(s, TRUE);
  return TRUE;
}

static int mxf_read_strong_ref_array(AVIOContext* pb, UID** refs, int* count) {
  *count = avio_rb32(pb);
  *refs = av_calloc(*count, sizeof(UID));
  if (!*refs) {
    *count = 0;
    return AVERROR(ENOMEM);
  }
  avio_skip(pb, 4);
  avio_read(pb, (uint8_t*)*refs, *count * sizeof(UID));
  return 0;
}

void FrameLoader::urlSelected(const ResourceRequest& request,
                              const String& passedTarget,
                              PassRefPtr<Event> triggeringEvent,
                              bool lockHistory, bool lockBackForwardList,
                              bool userGesture, ReferrerPolicy referrerPolicy) {
  ASSERT(!m_suppressOpenerInNewFrame);
  if (m_frame->script()->executeIfJavaScriptURL(request.url(), userGesture,
                                                false))
    return;
  String target = passedTarget;
  if (target.isEmpty()) target = m_frame->document()->baseTarget();
  FrameLoadRequest frameRequest(request, target);
  if (referrerPolicy == NoReferrer) {
    m_suppressOpenerInNewFrame = true;
    setOpener(0);
  } else if (frameRequest.resourceRequest().httpReferrer().isEmpty())
    frameRequest.resourceRequest().setHTTPReferrer(m_outgoingReferrer);
  addHTTPOriginIfNeeded(frameRequest.resourceRequest(), outgoingOrigin());
  loadFrameRequest(frameRequest, lockHistory, lockBackForwardList,
                   triggeringEvent, 0, referrerPolicy);
  m_suppressOpenerInNewFrame = false;
}

