  if (hstate_is_gigantic(h) && !gigantic_page_runtime_supported())
    return -EINVAL;
  if (nid == NUMA_NO_NODE) {
    if (!(obey_mempolicy && init_nodemask_of_mempolicy(&nodes_allowed)))
      n_mask = &node_states[N_MEMORY];
    else
      n_mask = &nodes_allowed;
