int Curl_single_getsock(struct Curl_easy* data, struct connectdata* conn,
                        curl_socket_t* sock) {
  int bitmap = GETSOCK_BLANK;
  unsigned sockindex = 0;
  if (conn->handler->perform_getsock)
    return conn->handler->perform_getsock(data, conn, sock);
  if ((data->req.keepon & KEEP_RECVBITS) == KEEP_RECV) {
    DEBUGASSERT(conn->sockfd != CURL_SOCKET_BAD);
    bitmap |= GETSOCK_READSOCK(sockindex);
    sock[sockindex] = conn->sockfd;
  }
  if ((data->req.keepon & KEEP_SENDBITS) == KEEP_SEND) {
    if ((conn->sockfd != conn->writesockfd) || bitmap == GETSOCK_BLANK) {
      if (bitmap != GETSOCK_BLANK) sockindex++;
      DEBUGASSERT(conn->writesockfd != CURL_SOCKET_BAD);
      sock[sockindex] = conn->writesockfd;
    }
    bitmap |= GETSOCK_WRITESOCK(sockindex);
  }
  return bitmap;
}

static void tcp_ofo_queue(struct sock* sk) {
  struct tcp_sock* tp = tcp_sk(sk);
  __u32 dsack_high = tp->rcv_nxt;
  struct sk_buff *skb, *tail;
  bool fragstolen, eaten;
  while ((skb = skb_peek(&tp->out_of_order_queue)) != NULL) {
    if (after(TCP_SKB_CB(skb)->seq, tp->rcv_nxt)) break;
    if (before(TCP_SKB_CB(skb)->seq, dsack_high)) {
      __u32 dsack = dsack_high;
      if (before(TCP_SKB_CB(skb)->end_seq, dsack_high))
        dsack_high = TCP_SKB_CB(skb)->end_seq;
      tcp_dsack_extend(sk, TCP_SKB_CB(skb)->seq, dsack);
    }
    __skb_unlink(skb, &tp->out_of_order_queue);
    if (!after(TCP_SKB_CB(skb)->end_seq, tp->rcv_nxt)) {
      SOCK_DEBUG(sk, "ofo packet was already received\n");
      tcp_drop(sk, skb);
      continue;
    }
    SOCK_DEBUG(sk, "ofo requeuing : rcv_next %X seq %X - %X\n", tp->rcv_nxt,
               TCP_SKB_CB(skb)->seq, TCP_SKB_CB(skb)->end_seq);
    tail = skb_peek_tail(&sk->sk_receive_queue);
    eaten = tail && tcp_try_coalesce(sk, tail, skb, &fragstolen);
    tcp_rcv_nxt_update(tp, TCP_SKB_CB(skb)->end_seq);
    if (!eaten) __skb_queue_tail(&sk->sk_receive_queue, skb);
    if (TCP_SKB_CB(skb)->tcp_flags & TCPHDR_FIN) tcp_fin(sk);
    if (eaten) kfree_skb_partial(skb, fragstolen);
  }
}

static int fastrpc_dma_buf_attach(struct dma_buf* dmabuf,
                                  struct dma_buf_attachment* attachment) {
  struct fastrpc_dma_buf_attachment* a;
  struct fastrpc_buf* buffer = dmabuf->priv;
  int ret;
  a = kzalloc(sizeof(*a), GFP_KERNEL);
  if (!a) return -ENOMEM;
  ret = dma_get_sgtable(buffer->dev, &a->sgt, buffer->virt,
                        FASTRPC_PHYS(buffer->phys), buffer->size);
  if (ret < 0) {
    dev_err(buffer->dev, "failed to get scatterlist from DMA API\n");
    kfree(a);
    return -EINVAL;
  }
  a->dev = attachment->dev;
  INIT_LIST_HEAD(&a->node);
  attachment->priv = a;
  mutex_lock(&buffer->lock);
  list_add(&a->node, &buffer->attachments);
  mutex_unlock(&buffer->lock);
  return 0;
}

sg_get_dev(int dev) {
  struct sg_device* sdp;
  unsigned long flags;
  read_lock_irqsave(&sg_index_lock, flags);
  sdp = sg_lookup_dev(dev);
  if (!sdp)
    sdp = ERR_PTR(-ENXIO);
  else if (atomic_read(&sdp->detaching)) {
    sdp = ERR_PTR(-ENODEV);
  } else
    kref_get(&sdp->d_ref);
  read_unlock_irqrestore(&sg_index_lock, flags);
  return sdp;
}

static int nr_recvmsg(struct kiocb* iocb, struct socket* sock,
                      struct msghdr* msg, size_t size, int flags) {
  struct sock* sk = sock->sk;
  struct sockaddr_ax25* sax = (struct sockaddr_ax25*)msg->msg_name;
  size_t copied;
  struct sk_buff* skb;
  int er;
  lock_sock(sk);
  if (sk->sk_state != TCP_ESTABLISHED) {
    release_sock(sk);
    return -ENOTCONN;
  }
  if ((skb = skb_recv_datagram(sk, flags & ~MSG_DONTWAIT, flags & MSG_DONTWAIT,
                               &er)) == NULL) {
    release_sock(sk);
    return er;
  }
  skb_reset_transport_header(skb);
  copied = skb->len;
  if (copied > size) {
    copied = size;
    msg->msg_flags |= MSG_TRUNC;
  }
  er = skb_copy_datagram_iovec(skb, 0, msg->msg_iov, copied);
  if (er < 0) {
    skb_free_datagram(sk, skb);
    release_sock(sk);
    return er;
  }
  if (sax != NULL) {
    memset(sax, 0, sizeof(*sax));
    sax->sax25_family = AF_NETROM;
    skb_copy_from_linear_data_offset(skb, 7, sax->sax25_call.ax25_call,
                                     AX25_ADDR_LEN);
  }
  msg->msg_namelen = sizeof(*sax);
  skb_free_datagram(sk, skb);
  release_sock(sk);
  return copied;
}

void ide_exec_cmd(IDEBus* bus, uint32_t val) {
  IDEState* s;
  bool complete;
#if defined(DEBUG_IDE)
  printf("ide: CMD=%02x\n", val);
#endif
  s = idebus_active_if(bus);
  if (s != bus->ifs && !s->bs) return;
  if ((s->status & (BUSY_STAT | DRQ_STAT)) && val != WIN_DEVICE_RESET) return;
  if (!ide_cmd_permitted(s, val)) {
    ide_abort_command(s);
    ide_set_irq(s->bus);
    return;
  }
  s->status = READY_STAT | BUSY_STAT;
  s->error = 0;
  complete = ide_cmd_table[val].handler(s, val);
  if (complete) {
    s->status &= ~BUSY_STAT;
    assert(!!s->error == !!(s->status & ERR_STAT));
    if ((ide_cmd_table[val].flags & SET_DSC) && !s->error) {
      s->status |= SEEK_STAT;
    }
    ide_set_irq(s->bus);
  }
}

add_durable_context(struct kvec* iov, unsigned int* num_iovec,
                    struct cifs_open_parms* oparms, bool use_persistent) {
  struct smb2_create_req* req = iov[0].iov_base;
  unsigned int num = *num_iovec;
  if (use_persistent) {
    if (oparms->reconnect)
      return add_durable_reconnect_v2_context(iov, num_iovec, oparms);
    else
      return add_durable_v2_context(iov, num_iovec, oparms);
  }
  if (oparms->reconnect) {
    iov[num].iov_base = create_reconnect_durable_buf(oparms->fid);
    oparms->reconnect = false;
  } else
    iov[num].iov_base = create_durable_buf();
  if (iov[num].iov_base == NULL) return -ENOMEM;
  iov[num].iov_len = sizeof(struct create_durable);
  if (!req->CreateContextsOffset)
    req->CreateContextsOffset =
        cpu_to_le32(sizeof(struct smb2_create_req) + iov[1].iov_len);
  le32_add_cpu(&req->CreateContextsLength, sizeof(struct create_durable));
  *num_iovec = num + 1;
  return 0;
}

static void perf_event_comm_event(struct perf_comm_event* comm_event) {
  struct perf_cpu_context* cpuctx;
  struct perf_event_context* ctx;
  char comm[TASK_COMM_LEN];
  unsigned int size;
  struct pmu* pmu;
  int ctxn;
  memset(comm, 0, sizeof(comm));
  strlcpy(comm, comm_event->task->comm, sizeof(comm));
  size = ALIGN(strlen(comm) + 1, sizeof(u64));
  comm_event->comm = comm;
  comm_event->comm_size = size;
  comm_event->event_id.header.size = sizeof(comm_event->event_id) + size;
  rcu_read_lock();
  list_for_each_entry_rcu(pmu, &pmus, entry) {
    cpuctx = get_cpu_ptr(pmu->pmu_cpu_context);
    if (cpuctx->unique_pmu != pmu) goto next;
    perf_event_comm_ctx(&cpuctx->ctx, comm_event);
    ctxn = pmu->task_ctx_nr;
    if (ctxn < 0) goto next;
    ctx = rcu_dereference(current->perf_event_ctxp[ctxn]);
    if (ctx) perf_event_comm_ctx(ctx, comm_event);
  next:
    put_cpu_ptr(pmu->pmu_cpu_context);
  }
  rcu_read_unlock();
}

mbc_to_code(const UChar* p, const UChar* end, OnigEncoding enc) {
  int c, i, len;
  OnigCodePoint n;
  len = enclen(enc, p, end);
  c = *p++;
  n = c;
  if (len == 1) return n;
  for (i = 1; i < len; i++) {
    if (p >= end) break;
    c = *p++;
    n <<= 8;
    n += c;
  }
  return n;
}

int dane_verify_crt_raw(dane_state_t s, const gnutls_datum_t* chain,
                        unsigned chain_size,
                        gnutls_certificate_type_t chain_type, dane_query_t r,
                        unsigned int sflags, unsigned int vflags,
                        unsigned int* verify) {
  dane_state_t _s = NULL;
  int ret;
  unsigned checked = 0;
  unsigned int usage, type, match, idx;
  gnutls_datum_t data;
  if (chain_type != GNUTLS_CRT_X509)
    return gnutls_assert_val(DANE_E_INVALID_REQUEST);
  *verify = 0;
  idx = 0;
  do {
    ret = dane_query_data(r, idx++, &usage, &type, &match, &data);
    if (ret == DANE_E_REQUESTED_DATA_NOT_AVAILABLE) break;
    if (ret < 0) {
      gnutls_assert();
      goto cleanup;
    }
    if (!(vflags & DANE_VFLAG_ONLY_CHECK_EE_USAGE) &&
        (usage == DANE_CERT_USAGE_LOCAL_CA || usage == DANE_CERT_USAGE_CA)) {
      ret =
          verify_ca(chain, chain_size, chain_type, type, match, &data, verify);
      if (ret < 0) {
        gnutls_assert();
        goto cleanup;
      }
      checked = 1;
    } else if (!(vflags & DANE_VFLAG_ONLY_CHECK_CA_USAGE) &&
               (usage == DANE_CERT_USAGE_LOCAL_EE ||
                usage == DANE_CERT_USAGE_EE)) {
      ret = verify_ee(&chain[0], chain_type, type, match, &data, verify);
      if (ret < 0) {
        gnutls_assert();
        goto cleanup;
      }
      checked = 1;
    }
  } while (1);
  if ((vflags & DANE_VFLAG_FAIL_IF_NOT_CHECKED) && checked == 0)
    ret = gnutls_assert_val(DANE_E_REQUESTED_DATA_NOT_AVAILABLE);
  else
    ret = 0;
cleanup:
  if (s == NULL) dane_state_deinit(_s);
  return ret;
}

connection_dirserv_add_dir_bytes_to_outbuf(dir_connection_t* conn) {
  ssize_t bytes;
  int64_t remaining;
  bytes = DIRSERV_BUFFER_MIN - connection_get_outbuf_len(TO_CONN(conn));
  tor_assert(bytes > 0);
  tor_assert(conn->cached_dir);
  if (bytes < 8192) bytes = 8192;
  remaining = conn->cached_dir->dir_z_len - conn->cached_dir_offset;
  if (bytes > remaining) bytes = (ssize_t)remaining;
  if (conn->zlib_state) {
    connection_write_to_buf_zlib(
        conn->cached_dir->dir_z + conn->cached_dir_offset, bytes, conn,
        bytes == remaining);
  } else {
    connection_write_to_buf(conn->cached_dir->dir_z + conn->cached_dir_offset,
                            bytes, TO_CONN(conn));
  }
  conn->cached_dir_offset += bytes;
  if (conn->cached_dir_offset == (int)conn->cached_dir->dir_z_len) {
    connection_dirserv_finish_spooling(conn);
    cached_dir_decref(conn->cached_dir);
    conn->cached_dir = NULL;
  }
  return 0;
}

strstric(uschar* s, uschar* t, BOOL space_follows) {
  uschar* p = t;
  uschar* yield = NULL;
  int cl = tolower(*p);
  int cu = toupper(*p);
  while (*s) {
    if (*s == cl || *s == cu) {
      if (yield == NULL) yield = s;
      if (*(++p) == 0) {
        if (!space_follows || s[1] == ' ' || s[1] == '\n') return yield;
        yield = NULL;
        p = t;
      }
      cl = tolower(*p);
      cu = toupper(*p);
      s++;
    } else if (yield != NULL) {
      yield = NULL;
      p = t;
      cl = tolower(*p);
      cu = toupper(*p);
    } else
      s++;
  }
  return NULL;
}

static int32_t virtio_net_rsc_coalesce4(VirtioNetRscChain* chain,
                                        VirtioNetRscSeg* seg,
                                        const uint8_t* buf, size_t size,
                                        VirtioNetRscUnit* unit) {
  struct ip_header *ip1, *ip2;
  ip1 = (struct ip_header*)(unit->ip);
  ip2 = (struct ip_header*)(seg->unit.ip);
  if ((ip1->ip_src ^ ip2->ip_src) || (ip1->ip_dst ^ ip2->ip_dst) ||
      (unit->tcp->th_sport ^ seg->unit.tcp->th_sport) ||
      (unit->tcp->th_dport ^ seg->unit.tcp->th_dport)) {
    chain->stat.no_match++;
    return RSC_NO_MATCH;
  }
  return virtio_net_rsc_coalesce_data(chain, seg, buf, unit);
}

