}

static inline void init_ref(MotionEstContext* c, uint8_t* src[3],
                            uint8_t* ref[3], uint8_t* ref2[3], int x, int y,
                            int ref_index) {
  SnowContext* s = c->avctx->priv_data;
  const int offset[3] = {
      y * c->stride + x,
      ((y * c->uvstride + x) >> s->chroma_h_shift),
      ((y * c->uvstride + x) >> s->chroma_h_shift),
  };
  int i;
  for (i = 0; i < 3; i++) {
    c->src[0][i] = src[i];
    c->ref[0][i] = ref[i] + offset[i];
  }
  av_assert2(!ref_index);
}

bool PasswordAutofillAgent::ShowSuggestionPopup(
    const PasswordInfo& password_info, const blink::WebInputElement& user_input,
    bool show_all, bool show_on_password_field) {
  DCHECK(!user_input.isNull());
  blink::WebFrame* frame = user_input.document().frame();
  if (!frame) return false;
  blink::WebView* webview = frame->view();
  if (!webview) return false;
  if (user_input.isPasswordField() && !user_input.isAutofilled() &&
      !user_input.value().isEmpty()) {
    Send(new AutofillHostMsg_HidePopup(routing_id()));
    return false;
  }
  FormData form;
  FormFieldData field;
  form_util::FindFormAndFieldForFormControlElement(user_input, &form, &field);
  int options = 0;
  if (show_all) options |= SHOW_ALL;
  if (show_on_password_field) options |= IS_PASSWORD_FIELD;
  base::string16 username_string(
      user_input.isPasswordField()
          ? base::string16()
          : static_cast<base::string16>(user_input.value()));
  Send(new AutofillHostMsg_ShowPasswordSuggestions(
      routing_id(), password_info.key, field.text_direction, username_string,
      options,
      render_frame()->GetRenderView()->ElementBoundsInWindow(user_input)));
  username_query_prefix_ = username_string;
  return CanShowSuggestion(password_info.fill_data, username_string, show_all);
}

void sctp_assoc_control_transport(struct sctp_association* asoc,
                                  struct sctp_transport* transport,
                                  sctp_transport_cmd_t command,
                                  sctp_sn_error_t error) {
  struct sctp_ulpevent* event;
  struct sockaddr_storage addr;
  int spc_state = 0;
  bool ulp_notify = true;
  switch (command) {
    case SCTP_TRANSPORT_UP:
      if (SCTP_UNCONFIRMED == transport->state &&
          SCTP_HEARTBEAT_SUCCESS == error)
        spc_state = SCTP_ADDR_CONFIRMED;
      else
        spc_state = SCTP_ADDR_AVAILABLE;
      if (transport->state == SCTP_PF) {
        ulp_notify = false;
        transport->cwnd = asoc->pathmtu;
      }
      transport->state = SCTP_ACTIVE;
      break;
    case SCTP_TRANSPORT_DOWN:
      if (transport->state != SCTP_UNCONFIRMED)
        transport->state = SCTP_INACTIVE;
      else {
        dst_release(transport->dst);
        transport->dst = NULL;
        ulp_notify = false;
      }
      spc_state = SCTP_ADDR_UNREACHABLE;
      break;
    case SCTP_TRANSPORT_PF:
      transport->state = SCTP_PF;
      ulp_notify = false;
      break;
    default:
      return;
  }
  if (ulp_notify) {
    memset(&addr, 0, sizeof(struct sockaddr_storage));
    memcpy(&addr, &transport->ipaddr, transport->af_specific->sockaddr_len);
    event = sctp_ulpevent_make_peer_addr_change(asoc, &addr, 0, spc_state,
                                                error, GFP_ATOMIC);
    if (event) sctp_ulpq_tail_event(&asoc->ulpq, event);
  }
  sctp_select_active_and_retran_path(asoc);
}

libxlDomainObjBeginJob(libxlDriverPrivate* driver G_GNUC_UNUSED,
                       virDomainObj* obj, enum libxlDomainJob job) {
  libxlDomainObjPrivate* priv = obj->privateData;
  unsigned long long now;
  unsigned long long then;
  if (virTimeMillisNow(&now) < 0) return -1;
  then = now + LIBXL_JOB_WAIT_TIME;
  while (priv->job.active) {
    VIR_DEBUG("Wait normal job condition for starting job: %s",
              libxlDomainJobTypeToString(job));
    if (virCondWaitUntil(&priv->job.cond, &obj->parent.lock, then) < 0)
      goto error;
  }
  libxlDomainObjResetJob(priv);
  VIR_DEBUG("Starting job: %s", libxlDomainJobTypeToString(job));
  priv->job.active = job;
  priv->job.owner = virThreadSelfID();
  priv->job.started = now;
  priv->job.current->type = VIR_DOMAIN_JOB_UNBOUNDED;
  return 0;
error:
  VIR_WARN(
      "Cannot start job (%s) for domain %s;"
      " current job is (%s) owned by (%d)",
      libxlDomainJobTypeToString(job), obj->def->name,
      libxlDomainJobTypeToString(priv->job.active), priv->job.owner);
  if (errno == ETIMEDOUT)
    virReportError(VIR_ERR_OPERATION_TIMEOUT, "%s",
                   _("cannot acquire state change lock"));
  else
    virReportSystemError(errno, "%s", _("cannot acquire job mutex"));
  return -1;
}

static int stmt_fetch_row(MYSQL_STMT* stmt, uchar* row) {
  MYSQL_BIND *my_bind, *end;
  MYSQL_FIELD* field;
  uchar *null_ptr, bit;
  int truncation_count = 0;
  DBUG_ASSERT(stmt->field_count);
  DBUG_ASSERT(row);
  if (!stmt->bind_result_done) {
    return 0;
  }
  null_ptr = row;
  row += (stmt->field_count + 9) / 8;
  bit = 4;
  for (my_bind = stmt->bind, end = my_bind + stmt->field_count,
      field = stmt->fields;
       my_bind < end; my_bind++, field++) {
    *my_bind->error = 0;
    if (*null_ptr & bit) {
      my_bind->row_ptr = NULL;
      *my_bind->is_null = 1;
    } else {
      *my_bind->is_null = 0;
      my_bind->row_ptr = row;
      (*my_bind->fetch_result)(my_bind, field, &row);
      truncation_count += *my_bind->error;
    }
    if (!((bit <<= 1) & 255)) {
      bit = 1;
      null_ptr++;
    }
  }
  if (truncation_count && (stmt->bind_result_done & REPORT_DATA_TRUNCATION))
    return MYSQL_DATA_TRUNCATED;
  return 0;
}

static MirrorOp* coroutine_fn active_write_prepare(MirrorBlockJob* s,
                                                   uint64_t offset,
                                                   uint64_t bytes) {
  MirrorOp* op;
  uint64_t start_chunk = offset / s->granularity;
  uint64_t end_chunk = DIV_ROUND_UP(offset + bytes, s->granularity);
  op = g_new(MirrorOp, 1);
  *op = (MirrorOp){
      .s = s,
      .offset = offset,
      .bytes = bytes,
      .is_active_write = true,
      .is_in_flight = true,
      .co = qemu_coroutine_self(),
  };
  qemu_co_queue_init(&op->waiting_requests);
  QTAILQ_INSERT_TAIL(&s->ops_in_flight, op, next);
  s->in_active_write_counter++;
  mirror_wait_on_conflicts(op, s, offset, bytes);
  bitmap_set(s->in_flight_bitmap, start_chunk, end_chunk - start_chunk);
  return op;
}

