static int grow_stack_state(struct bpf_func_state* state, int size) {
  size_t old_n = state->allocated_stack / BPF_REG_SIZE, n = size / BPF_REG_SIZE;
  if (old_n >= n) return 0;
  state->stack =
      realloc_array(state->stack, old_n, n, sizeof(struct bpf_stack_state));
  if (!state->stack) return -ENOMEM;
  state->allocated_stack = size;
  return 0;
}

static int nfs4_xdr_dec_fs_locations(struct rpc_rqst* req,
                                     struct xdr_stream* xdr,
                                     struct nfs4_fs_locations_res* res) {
  struct compound_hdr hdr;
  int status;
  status = decode_compound_hdr(xdr, &hdr);
  if (status) goto out;
  status = decode_sequence(xdr, &res->seq_res, req);
  if (status) goto out;
  status = decode_putfh(xdr);
  if (status) goto out;
  status = decode_lookup(xdr);
  if (status) goto out;
  xdr_enter_page(xdr, PAGE_SIZE);
  status =
      decode_getfattr_generic(xdr, &res->fs_locations->fattr, NULL,
                              res->fs_locations, res->fs_locations->server);
out:
  return status;
}

virtual void run(Chunk& inChunk, Chunk& outChunk) {
