static void tcp_cwnd_reduction(struct sock* sk, int newly_acked_sacked,
                               int flag) {
  struct tcp_sock* tp = tcp_sk(sk);
  int sndcnt = 0;
  int delta = tp->snd_ssthresh - tcp_packets_in_flight(tp);
  if (newly_acked_sacked <= 0 || WARN_ON_ONCE(!tp->prior_cwnd)) return;
  tp->prr_delivered += newly_acked_sacked;
  if (delta < 0) {
    u64 dividend =
        (u64)tp->snd_ssthresh * tp->prr_delivered + tp->prior_cwnd - 1;
    sndcnt = div_u64(dividend, tp->prior_cwnd) - tp->prr_out;
  } else if ((flag & FLAG_RETRANS_DATA_ACKED) && !(flag & FLAG_LOST_RETRANS)) {
    sndcnt = min_t(
        int, delta,
        max_t(int, tp->prr_delivered - tp->prr_out, newly_acked_sacked) + 1);
  } else {
    sndcnt = min(delta, newly_acked_sacked);
  }
  sndcnt = max(sndcnt, (tp->prr_out ? 0 : 1));
  tp->snd_cwnd = tcp_packets_in_flight(tp) + sndcnt;
}

int CSoundFile::FrequencyToTranspose(DWORD freq) {
  return int(1536 * (log(freq / 8363.0) / log(2.0)));
#ifdef MSC_VER
  const float _f1_8363 = 1.0f / 8363.0f;
  const float _factor = 128 * 12;
  LONG result;
  if (!freq) return 0;
  _asm {
	fld _factor
	fild freq
	fld _f1_8363
	fmulp st(1), st(0)
	fyl2x
	fistp result
  }
  return result;
#endif
}

bool TranslateManager::IsAcceptLanguage(TabContents* tab,
                                        const std::string& language) {
  PrefService* pref_service = tab->profile()->GetPrefs();
  PrefServiceLanguagesMap::const_iterator iter =
      accept_languages_.find(pref_service);
  if (iter == accept_languages_.end()) {
    InitAcceptLanguages(pref_service);
    notification_registrar_.Add(this, NotificationType::PROFILE_DESTROYED,
                                Source<Profile>(tab->profile()));
