  }
  return iter->second.count(language) != 0;
}

void CLASS parseSonyLensType2(uchar a, uchar b) {
  ushort lid2;
  lid2 = (((ushort)a) << 8) | ((ushort)b);
  if (!lid2) return;
  if (lid2 < 0x100) {
    imgdata.lens.makernotes.AdapterID = lid2;
    switch (lid2) {
      case 1:
      case 2:
      case 3:
      case 6:
        imgdata.lens.makernotes.LensMount = Minolta_A;
        break;
      case 44:
      case 78:
      case 239:
        imgdata.lens.makernotes.LensMount = Canon_EF;
        break;
    }
  } else
    imgdata.lens.makernotes.LensID = lid2;
  return;
}

void ApplyChannelMatrix::initDefaultMatrix() {
  const double* matrix = NULL;
  if (m_inChannels == 1 && m_outChannels == 2) {
    static const double m[] = {1, 1};
    matrix = m;
  } else if (m_inChannels == 1 && m_outChannels == 4) {
    static const double m[] = {1, 1, 0, 0};
    matrix = m;
  } else if (m_inChannels == 2 && m_outChannels == 1) {
    static const double m[] = {.5, .5};
    matrix = m;
  } else if (m_inChannels == 2 && m_outChannels == 4) {
    static const double m[] = {1, 0, 0, 1, 0, 0, 0, 0};
    matrix = m;
  } else if (m_inChannels == 4 && m_outChannels == 1) {
    static const double m[] = {.5, .5, .5, .5};
    matrix = m;
  } else if (m_inChannels == 4 && m_outChannels == 2) {
    static const double m[] = {1, 0, 1, 0, 0, 1, 0, 1};
    matrix = m;
  }
  if (matrix) {
    std::copy(matrix, matrix + m_inChannels * m_outChannels, m_matrix);
  } else {
    for (int i = 0; i < m_inChannels; i++)
      for (int j = 0; j < m_outChannels; j++)
        m_matrix[j * m_inChannels + i] = (i == j) ? 1 : 0;
  }
}

irc_server_switch_address(struct t_irc_server* server, int connection) {
  if (server->addresses_count > 1) {
    irc_server_set_index_current_address(
        server, (server->index_current_address + 1) % server->addresses_count);
    weechat_printf(server->buffer, _("%s%s: switching address to %s/%d"),
                   weechat_prefix("network"), IRC_PLUGIN_NAME,
                   server->current_address, server->current_port);
    if (connection) {
      if (server->index_current_address == 0)
        irc_server_reconnect_schedule(server);
      else
        irc_server_connect(server);
    }
  } else {
    if (connection) irc_server_reconnect_schedule(server);
  }
}

history_tree_clear(OnigCaptureTreeNode* node) {
  int i;
  if (IS_NULL(node)) return;
  for (i = 0; i < node->num_childs; i++) {
    if (IS_NOT_NULL(node->childs[i])) {
      history_tree_free(node->childs[i]);
    }
  }
  for (i = 0; i < node->allocated; i++) {
    node->childs[i] = (OnigCaptureTreeNode*)0;
  }
  node->num_childs = 0;
  node->beg = ONIG_REGION_NOTPOS;
  node->end = ONIG_REGION_NOTPOS;
  node->group = -1;
}

static int do_add_mount(struct mount* newmnt, struct path* path,
                        int mnt_flags) {
  struct mountpoint* mp;
  struct mount* parent;
  int err;
  mnt_flags &= ~MNT_INTERNAL_FLAGS;
  mp = lock_mount(path);
  if (IS_ERR(mp)) return PTR_ERR(mp);
  parent = real_mount(path->mnt);
  err = -EINVAL;
  if (unlikely(!check_mnt(parent))) {
    if (!(mnt_flags & MNT_SHRINKABLE)) goto unlock;
    if (!parent->mnt_ns) goto unlock;
  }
  err = -EBUSY;
  if (path->mnt->mnt_sb == newmnt->mnt.mnt_sb &&
      path->mnt->mnt_root == path->dentry)
    goto unlock;
  err = -EINVAL;
  if (S_ISLNK(newmnt->mnt.mnt_root->d_inode->i_mode)) goto unlock;
  newmnt->mnt.mnt_flags = mnt_flags;
  err = graft_tree(newmnt, parent, mp);
unlock:
  unlock_mount(mp);
  return err;
}

JSValue JSArray::pop() {
  checkConsistency();
  ArrayStorage* storage = m_storage;
  unsigned length = storage->m_length;
  if (!length) return jsUndefined();
  --length;
  JSValue result;
  if (length < m_vectorLength) {
    WriteBarrier<Unknown>& valueSlot = storage->m_vector[length];
    if (valueSlot) {
      --storage->m_numValuesInVector;
      result = valueSlot.get();
      valueSlot.clear();
    } else
      result = jsUndefined();
  } else {
    result = jsUndefined();
    if (SparseArrayValueMap* map = storage->m_sparseValueMap) {
      SparseArrayValueMap::iterator it = map->find(length);
      if (it != map->end()) {
        result = it->second.get();
        map->remove(it);
        if (map->isEmpty()) {
          delete map;
          storage->m_sparseValueMap = 0;
        }
      }
    }
  }
  storage->m_length = length;
  checkConsistency();
  return result;
}

