static int coroutine_fn bdrv_mirror_top_do_write(
    BlockDriverState* bs, MirrorMethod method, uint64_t offset, uint64_t bytes,
    QEMUIOVector* qiov, int flags) {
  MirrorOp* op = NULL;
  MirrorBDSOpaque* s = bs->opaque;
  int ret = 0;
  bool copy_to_target;
  copy_to_target =
      s->job->ret >= 0 && s->job->copy_mode == MIRROR_COPY_MODE_WRITE_BLOCKING;
  if (copy_to_target) {
    op = active_write_prepare(s->job, offset, bytes);
  }
  switch (method) {
    case MIRROR_METHOD_COPY:
      ret = bdrv_co_pwritev(bs->backing, offset, bytes, qiov, flags);
      break;
    case MIRROR_METHOD_ZERO:
      ret = bdrv_co_pwrite_zeroes(bs->backing, offset, bytes, flags);
      break;
    case MIRROR_METHOD_DISCARD:
      ret = bdrv_co_pdiscard(bs->backing, offset, bytes);
      break;
    default:
      abort();
  }
  if (ret < 0) {
    goto out;
  }
  if (copy_to_target) {
    do_sync_target_write(s->job, method, offset, bytes, qiov, flags);
  }
out:
  if (copy_to_target) {
    active_write_settle(op);
  }
  return ret;
}

static http_meth_t find_http_meth(const char* str, const int len) {
  unsigned char m;
  const struct http_method_desc* h;
  m = ((unsigned)*str - 'A');
  if (m < 26) {
    for (h = http_methods[m]; h->len > 0; h++) {
      if (unlikely(h->len != len)) continue;
      if (likely(memcmp(str, h->text, h->len) == 0)) return h->meth;
    };
    return HTTP_METH_OTHER;
  }
  return HTTP_METH_NONE;
}

skip_to(file_offset file_pos, lin file_line) {
  FILE* i = pfp;
  FILE* o = stdout;
  int c;
  assert(p_base <= file_pos);
  if ((verbosity == VERBOSE || !inname) && p_base < file_pos) {
    Fseek(i, p_base, SEEK_SET);
    say("The text leading up to this was:\n--------------------------\n");
    while (file_tell(i) < file_pos) {
      putc('|', o);
      do {
        if ((c = getc(i)) == EOF) read_fatal();
        putc(c, o);
      } while (c != '\n');
    }
    say("--------------------------\n");
  } else
    Fseek(i, file_pos, SEEK_SET);
  p_input_line = file_line - 1;
}

static int futex_proxy_trylock_atomic(
    u32 __user* pifutex, struct futex_hash_bucket* hb1,
    struct futex_hash_bucket* hb2, union futex_key* key1, union futex_key* key2,
    struct futex_pi_state** ps, int set_waiters) {
  struct futex_q* top_waiter = NULL;
  u32 curval;
  int ret, vpid;
  if (get_futex_value_locked(&curval, pifutex)) return -EFAULT;
  if (unlikely(should_fail_futex(true))) return -EFAULT;
  top_waiter = futex_top_waiter(hb1, key1);
  if (!top_waiter) return 0;
  if (!match_futex(top_waiter->requeue_pi_key, key2)) return -EINVAL;
  vpid = task_pid_vnr(top_waiter->task);
  ret = futex_lock_pi_atomic(pifutex, hb2, key2, ps, top_waiter->task,
                             set_waiters);
  if (ret == 1) {
    requeue_pi_wake_futex(top_waiter, key2, hb2);
    return vpid;
  }
  return ret;
}

