int seccomp_restrict_realtime(void) {
  static const int permitted_policies[] = {
      SCHED_OTHER,
      SCHED_BATCH,
      SCHED_IDLE,
  };
  int r, max_policy = 0;
  uint32_t arch;
  unsigned i;
  for (i = 0; i < ELEMENTSOF(permitted_policies); i++)
    if (permitted_policies[i] > max_policy) max_policy = permitted_policies[i];
  SECCOMP_FOREACH_LOCAL_ARCH(arch) {
    _cleanup_(seccomp_releasep) scmp_filter_ctx seccomp = NULL;
    int p;
    log_debug("Operating on architecture: %s", seccomp_arch_to_string(arch));
    r = seccomp_init_for_arch(&seccomp, arch, SCMP_ACT_ALLOW);
    if (r < 0) return r;
    for (p = 0; p < max_policy; p++) {
      bool good = false;
      for (i = 0; i < ELEMENTSOF(permitted_policies); i++)
        if (permitted_policies[i] == p) {
          good = true;
          break;
        }
      if (good) continue;
      r = seccomp_rule_add_exact(seccomp, SCMP_ACT_ERRNO(EPERM),
                                 SCMP_SYS(sched_setscheduler), 1,
                                 SCMP_A1(SCMP_CMP_EQ, p));
      if (r < 0) {
        log_debug_errno(
            r, "Failed to add scheduler rule for architecture %s, skipping: %m",
            seccomp_arch_to_string(arch));
        continue;
      }
    }
    r = seccomp_rule_add_exact(seccomp, SCMP_ACT_ERRNO(EPERM),
                               SCMP_SYS(sched_setscheduler), 1,
                               SCMP_A1(SCMP_CMP_GT, max_policy));
    if (r < 0) {
      log_debug_errno(
          r, "Failed to add scheduler rule for architecture %s, skipping: %m",
          seccomp_arch_to_string(arch));
      continue;
    }
    r = seccomp_load(seccomp);
    if (IN_SET(r, -EPERM, -EACCES)) return r;
    if (r < 0)
      log_debug_errno(r,
                      "Failed to install realtime protection rules for "
                      "architecture %s, skipping: %m",
                      seccomp_arch_to_string(arch));
  }
  return 0;
}

double matching_candidates_in_table(JOIN_TAB* s, bool with_found_constraint,
                                    uint use_cond_selectivity) {
  ha_rows records;
  double dbl_records;
  if (use_cond_selectivity > 1) {
    TABLE* table = s->table;
    double sel = table->cond_selectivity;
    double table_records = (double)table->stat_records();
    dbl_records = table_records * sel;
    return dbl_records;
  }
  records = s->found_records;
  if (with_found_constraint) records -= records / 4;
  if (s->table->quick_condition_rows != s->found_records)
    records = s->table->quick_condition_rows;
  dbl_records = (double)records;
  return dbl_records;
}

