template <typename tf>
static CImg<floatT> cone3d(CImgList<tf>& primitives, const float radius = 50,
                           const float size_z = 100,
                           const unsigned int subdivisions = 24) {
  primitives.assign();
  if (!subdivisions) return CImg<floatT>();
  CImgList<floatT> vertices(2, 1, 3, 1, 1, 0., 0., size_z, 0., 0., 0.);
  for (float delta = 360.0f / subdivisions, angle = 0; angle < 360;
       angle += delta) {
    const float a = (float)(angle * cimg::PI / 180);
    CImg<floatT>::vector((float)(radius * std::cos(a)),
                         (float)(radius * std::sin(a)), 0)
        .move_to(vertices);
  }
  const unsigned int nbr = vertices._width - 2;
  for (unsigned int p = 0; p < nbr; ++p) {
    const unsigned int curr = 2 + p, next = 2 + ((p + 1) % nbr);
    CImg<tf>::vector(1, next, curr).move_to(primitives);
    CImg<tf>::vector(0, curr, next).move_to(primitives);
  }
  return vertices > 'x';

static CURLcode file_connect(struct connectdata* conn, bool* done) {
  struct Curl_easy* data = conn->data;
  char* real_path;
  struct FILEPROTO* file = data->req.protop;
  int fd = -1;
#ifdef DOS_FILESYSTEM
  size_t i;
  char* actual_path;
#endif
  size_t real_path_len;
  CURLcode result = Curl_urldecode(data, data->state.up.path, 0, &real_path,
                                   &real_path_len, FALSE);
  if (result) return result;
#ifdef DOS_FILESYSTEM
  actual_path = real_path;
  if ((actual_path[0] == '/') && actual_path[1] &&
      (actual_path[2] == ':' || actual_path[2] == '|')) {
    actual_path[2] = ':';
    actual_path++;
    real_path_len--;
  }
  for (i = 0; i < real_path_len; ++i)
    if (actual_path[i] == '/')
      actual_path[i] = '\\';
    else if (!actual_path[i]) {
      Curl_safefree(real_path);
      return CURLE_URL_MALFORMAT;
    }
  if (strncmp("\\\\", actual_path, 2))
    fd = open_readonly(actual_path, O_RDONLY | O_BINARY);
  file->path = actual_path;
#else
  if (memchr(real_path, 0, real_path_len)) {
    Curl_safefree(real_path);
    return CURLE_URL_MALFORMAT;
  }
  fd = open_readonly(real_path, O_RDONLY);
  file->path = real_path;
#endif
  file->freepath = real_path;
  file->fd = fd;
  if (!data->set.upload && (fd == -1)) {
    failf(data, "Couldn't open file %s", data->state.up.path);
    file_done(conn, CURLE_FILE_COULDNT_READ_FILE, FALSE);
    return CURLE_FILE_COULDNT_READ_FILE;
  }
  *done = TRUE;
  return CURLE_OK;
}

static void string_addr_inc(struct x86_emulate_ctxt* ctxt, unsigned seg,
                            int reg, struct operand* op) {
  int df = (ctxt->eflags & EFLG_DF) ? -1 : 1;
  register_address_increment(ctxt, &ctxt->regs[reg], df * op->bytes);
  op->addr.mem.ea = register_address(ctxt, ctxt->regs[reg]);
  op->addr.mem.seg = seg;
}

void HTMLMediaElement::StartPlayerLoad() {
  DCHECK(!web_media_player_);
  WebMediaPlayerSource source;
  if (src_object_) {
    source = WebMediaPlayerSource(WebMediaStream(src_object_));
  } else {
    KURL request_url = current_src_;
    if (!request_url.User().IsEmpty()) request_url.SetUser(String());
    if (!request_url.Pass().IsEmpty()) request_url.SetPass(String());
    KURL kurl(request_url);
    source = WebMediaPlayerSource(WebURL(kurl));
  }
  LocalFrame* frame = GetDocument().GetFrame();
  if (!frame) {
    MediaLoadingFailed(
        WebMediaPlayer::kNetworkStateFormatError,
        BuildElementErrorMessage("Player load failure: document has no frame"));
    return;
  }
  web_media_player_ = frame->Client()->CreateWebMediaPlayer(
      *this, source, this,
      frame->GetPage()->GetChromeClient().GetWebLayerTreeView(frame));
  if (!web_media_player_) {
    MediaLoadingFailed(WebMediaPlayer::kNetworkStateFormatError,
                       BuildElementErrorMessage(
                           "Player load failure: error creating media player"));
    return;
  }
  if (GetLayoutObject()) GetLayoutObject()->SetShouldDoFullPaintInvalidation();
  audio_source_provider_.Wrap(web_media_player_->GetAudioSourceProvider());
  web_media_player_->SetVolume(EffectiveMediaVolume());
  web_media_player_->SetPoster(PosterImageURL());
  const auto preload = EffectivePreloadType();
  web_media_player_->SetPreload(preload);
  web_media_player_->RequestRemotePlaybackDisabled(
      FastHasAttribute(kDisableremoteplaybackAttr));
  auto load_timing = web_media_player_->Load(GetLoadType(), source, CorsMode());
  if (load_timing == WebMediaPlayer::LoadTiming::kDeferred) {
    SetShouldDelayLoadEvent(false);
  }
  if (IsFullscreen()) web_media_player_->EnteredFullscreen();
  web_media_player_->BecameDominantVisibleContent(mostly_filling_viewport_);
}

methodHandle LinkResolver::linktime_resolve_virtual_method(
    const LinkInfo& link_info, TRAPS) {
  methodHandle resolved_method =
      resolve_method(link_info, Bytecodes::_invokevirtual, CHECK_NULL);
  assert(resolved_method->name() != vmSymbols::object_initializer_name(),
         "should have been checked in verifier");
  assert(resolved_method->name() != vmSymbols::class_initializer_name(),
         "should have been checked in verifier");
  Klass* resolved_klass = link_info.resolved_klass();
  Klass* current_klass = link_info.current_klass();
  if (resolved_klass->is_interface() && resolved_method->is_private()) {
    ResourceMark rm(THREAD);
    stringStream ss;
    ss.print(
        "private interface method requires invokespecial, not invokevirtual: "
        "method '");
    resolved_method->print_external_name(&ss);
    ss.print(
        "', caller-class: %s",
        (current_klass == NULL ? "<null>" : current_klass->internal_name()));
    THROW_MSG_NULL(vmSymbols::java_lang_IncompatibleClassChangeError(),
                   ss.as_string());
  }
  if (resolved_method->is_static()) {
    ResourceMark rm(THREAD);
    stringStream ss;
    ss.print("Expecting non-static method '");
    resolved_method->print_external_name(&ss);
    ss.print("'");
    THROW_MSG_NULL(vmSymbols::java_lang_IncompatibleClassChangeError(),
                   ss.as_string());
  }
  if (log_develop_is_enabled(Trace, vtables)) {
    trace_method_resolution(
        "invokevirtual resolved method: caller-class:", current_klass,
        resolved_klass, resolved_method, false);
  }
  return resolved_method;
}

int mbedtls_ssl_check_record(mbedtls_ssl_context const* ssl, unsigned char* buf,
                             size_t buflen) {
  int ret = 0;
  MBEDTLS_SSL_DEBUG_MSG(1, ("=> mbedtls_ssl_check_record"));
  MBEDTLS_SSL_DEBUG_BUF(3, "record buffer", buf, buflen);
  if (ssl->conf->transport == MBEDTLS_SSL_TRANSPORT_STREAM) {
    ret = MBEDTLS_ERR_SSL_FEATURE_UNAVAILABLE;
    goto exit;
  }
#if defined(MBEDTLS_SSL_PROTO_DTLS)
  else {
    mbedtls_record rec;
    ret = ssl_parse_record_header(ssl, buf, buflen, &rec);
    if (ret != 0) {
      MBEDTLS_SSL_DEBUG_RET(3, "ssl_parse_record_header", ret);
      goto exit;
    }
    if (ssl->transform_in != NULL) {
      ret = mbedtls_ssl_decrypt_buf(ssl, ssl->transform_in, &rec);
      if (ret != 0) {
        MBEDTLS_SSL_DEBUG_RET(3, "mbedtls_ssl_decrypt_buf", ret);
        goto exit;
      }
    }
  }
#endif
exit:
  mbedtls_platform_zeroize(buf, buflen);
  if (ret == MBEDTLS_ERR_SSL_UNEXPECTED_CID ||
      ret == MBEDTLS_ERR_SSL_EARLY_MESSAGE) {
    ret = MBEDTLS_ERR_SSL_UNEXPECTED_RECORD;
  }
  MBEDTLS_SSL_DEBUG_MSG(1, ("<= mbedtls_ssl_check_record"));
  return (ret);
}

Method* InstanceKlass::uncached_lookup_method(
    const Symbol* name, const Symbol* signature,
    OverpassLookupMode overpass_mode, PrivateLookupMode private_mode) const {
  OverpassLookupMode overpass_local_mode = overpass_mode;
  const Klass* klass = this;
  while (klass != NULL) {
    Method* const method = InstanceKlass::cast(klass)->find_method_impl(
        name, signature, overpass_local_mode, find_static, private_mode);
    if (method != NULL) {
      return method;
    }
    klass = klass->super();
    overpass_local_mode = skip_overpass;
  }
  return NULL;
}

static zval** php_zip_get_property_ptr_ptr(zval* object, zval* member,
                                           const zend_literal* key TSRMLS_DC) {
  ze_zip_object* obj;
  zval tmp_member;
  zval** retval = NULL;
  zip_prop_handler* hnd;
  zend_object_handlers* std_hnd;
  int ret;
  if (member->type != IS_STRING) {
    tmp_member = *member;
    zval_copy_ctor(&tmp_member);
    convert_to_string(&tmp_member);
    member = &tmp_member;
    key = NULL;
  }
  ret = FAILURE;
  obj = (ze_zip_object*)zend_objects_get_address(object TSRMLS_CC);
  if (obj->prop_handler != NULL) {
    if (key) {
      ret = zend_hash_quick_find(obj->prop_handler, Z_STRVAL_P(member),
                                 Z_STRLEN_P(member) + 1, key->hash_value,
                                 (void**)&hnd);
    } else {
      ret = zend_hash_find(obj->prop_handler, Z_STRVAL_P(member),
                           Z_STRLEN_P(member) + 1, (void**)&hnd);
    }
  }
  if (ret == FAILURE) {
    std_hnd = zend_get_std_object_handlers();
    retval = std_hnd->get_property_ptr_ptr(object, member, key TSRMLS_CC);
  }
  if (member == &tmp_member) {
    zval_dtor(member);
  }
  return retval;
}

int __audit_ipc_obj(struct kern_ipc_perm* ipcp) {
  struct audit_aux_data_ipcctl* ax;
  struct audit_context* context = current->audit_context;
  ax = kmalloc(sizeof(*ax), GFP_ATOMIC);
  if (!ax) return -ENOMEM;
  ax->uid = ipcp->uid;
  ax->gid = ipcp->gid;
  ax->mode = ipcp->mode;
  selinux_get_ipc_sid(ipcp, &ax->osid);
  ax->d.type = AUDIT_IPC;
  ax->d.next = context->aux;
  context->aux = (void*)ax;
  return 0;
}

generate_keys(cms_context* cms, PK11SlotInfo* slot, SECKEYPrivateKey** privkey,
              SECKEYPublicKey** pubkey) {
  PK11RSAGenParams rsaparams = {
      .keySizeInBits = 2048,
      .pe = 0x010001,
  };
  SECStatus rv;
  rv = PK11_Authenticate(slot, PR_TRUE, cms);
  if (rv != SECSuccess)
    cnreterr(-1, cms, "could not authenticate with pk11 service");
  void* params = &rsaparams;
  *privkey = PK11_GenerateKeyPair(slot, CKM_RSA_PKCS_KEY_PAIR_GEN, params,
                                  pubkey, PR_TRUE, PR_TRUE, cms);
  if (!*privkey) cnreterr(-1, cms, "could not generate RSA keypair");
  return 0;
}

static int php_snmp_write_valueretrieval(php_snmp_object* snmp_object,
                                         zval* newval) {
  zval ztmp;
  int ret = SUCCESS;
  if (Z_TYPE_P(newval) != IS_LONG) {
    ztmp = *newval;
    zval_copy_ctor(&ztmp);
    convert_to_long(&ztmp);
    newval = &ztmp;
  }
  if (Z_LVAL_P(newval) >= 0 &&
      Z_LVAL_P(newval) <=
          (SNMP_VALUE_LIBRARY | SNMP_VALUE_PLAIN | SNMP_VALUE_OBJECT)) {
    snmp_object->valueretrieval = Z_LVAL_P(newval);
  } else {
    php_error_docref(NULL, E_WARNING,
                     "Unknown SNMP value retrieval method '%pd'",
                     Z_LVAL_P(newval));
    ret = FAILURE;
  }
  if (newval == &ztmp) {
    zval_dtor(newval);
  }
  return ret;
}

