static int parse_options(char* options, struct super_block* sb,
                         unsigned long* journal_devnum,
                         unsigned int* journal_ioprio, int is_remount) {
#ifdef CONFIG_QUOTA
  struct ext4_sb_info* sbi = EXT4_SB(sb);
#endif
  char* p;
  substring_t args[MAX_OPT_ARGS];
  int token;
  if (!options) return 1;
  while ((p = strsep(&options, ",")) != NULL) {
    if (!*p) continue;
    args[0].to = args[0].from = 0;
    token = match_token(p, tokens, args);
    if (handle_mount_opt(sb, p, token, args, journal_devnum, journal_ioprio,
                         is_remount) < 0)
      return 0;
  }
#ifdef CONFIG_QUOTA
  if (sbi->s_qf_names[USRQUOTA] || sbi->s_qf_names[GRPQUOTA]) {
    if (test_opt(sb, USRQUOTA) && sbi->s_qf_names[USRQUOTA])
      clear_opt(sb, USRQUOTA);
    if (test_opt(sb, GRPQUOTA) && sbi->s_qf_names[GRPQUOTA])
      clear_opt(sb, GRPQUOTA);
    if (test_opt(sb, GRPQUOTA) || test_opt(sb, USRQUOTA)) {
      ext4_msg(sb, KERN_ERR,
               "old and new quota "
               "format mixing");
      return 0;
    }
    if (!sbi->s_jquota_fmt) {
      ext4_msg(sb, KERN_ERR,
               "journaled quota format "
               "not specified");
      return 0;
    }
  } else {
    if (sbi->s_jquota_fmt) {
      ext4_msg(sb, KERN_ERR,
               "journaled quota format "
               "specified with no journaling "
               "enabled");
      return 0;
    }
  }
#endif
  return 1;
}

static int stat_to_qid(V9fsPDU* pdu, const struct stat* stbuf, V9fsQID* qidp) {
  int err;
  size_t size;
  if (pdu->s->ctx.export_flags & V9FS_REMAP_INODES) {
    err = qid_path_suffixmap(pdu, stbuf, &qidp->path);
    if (err == -ENFILE) {
      err = qid_path_fullmap(pdu, stbuf, &qidp->path);
    }
    if (err) {
      return err;
    }
  } else {
    if (pdu->s->dev_id != stbuf->st_dev) {
      if (pdu->s->ctx.export_flags & V9FS_FORBID_MULTIDEVS) {
        error_report_once(
            "9p: Multiple devices detected in same VirtFS export. "
            "Access of guest to additional devices is (partly) "
            "denied due to virtfs option 'multidevs=forbid' being "
            "effective.");
        return -ENODEV;
      } else {
        warn_report_once(
            "9p: Multiple devices detected in same VirtFS export, "
            "which might lead to file ID collisions and severe "
            "misbehaviours on guest! You should either use a "
            "separate export for each device shared from host or "
            "use virtfs option 'multidevs=remap'!");
      }
    }
    memset(&qidp->path, 0, sizeof(qidp->path));
    size = MIN(sizeof(stbuf->st_ino), sizeof(qidp->path));
    memcpy(&qidp->path, &stbuf->st_ino, size);
  }
  qidp->version = stbuf->st_mtime ^ (stbuf->st_size << 8);
  qidp->type = 0;
  if (S_ISDIR(stbuf->st_mode)) {
    qidp->type |= P9_QID_TYPE_DIR;
  }
  if (S_ISLNK(stbuf->st_mode)) {
    qidp->type |= P9_QID_TYPE_SYMLINK;
  }
  return 0;
}

host_nmtoa(int count, int* binary, int mask, uschar* buffer, int sep) {
  int i, j;
  uschar* tt = buffer;
  if (count == 1) {
    j = binary[0];
    for (i = 24; i >= 0; i -= 8) tt += sprintf(CS tt, "%d.", (j >> i) & 255);
  } else
    for (i = 0; i < 4; i++) {
      j = binary[i];
      tt += sprintf(CS tt, "%04x%c%04x%c", (j >> 16) & 0xffff, sep, j & 0xffff,
                    sep);
    }
  tt--;
  if (mask < 0)
    *tt = 0;
  else
    tt += sprintf(CS tt, "/%d", mask);
  return tt - buffer;
}

static bool __udp_v6_is_mcast_sock(struct net* net, struct sock* sk,
                                   __be16 loc_port,
                                   const struct in6_addr* loc_addr,
                                   __be16 rmt_port,
                                   const struct in6_addr* rmt_addr, int dif,
                                   unsigned short hnum) {
  struct inet_sock* inet = inet_sk(sk);
  if (!net_eq(sock_net(sk), net)) return false;
  if (udp_sk(sk)->udp_port_hash != hnum || sk->sk_family != PF_INET6 ||
      (inet->inet_dport && inet->inet_dport != rmt_port) ||
      (!ipv6_addr_any(&sk->sk_v6_daddr) &&
       !ipv6_addr_equal(&sk->sk_v6_daddr, rmt_addr)) ||
      (sk->sk_bound_dev_if && sk->sk_bound_dev_if != dif) ||
      (!ipv6_addr_any(&sk->sk_v6_rcv_saddr) &&
       !ipv6_addr_equal(&sk->sk_v6_rcv_saddr, loc_addr)))
    return false;
  if (!inet6_mc_check(sk, loc_addr, rmt_addr)) return false;
  return true;
}

gen_setxv(codegen_scope* s, uint8_t op, uint16_t dst, mrb_sym sym, int val) {
  int idx = new_sym(s, sym);
  if (!val && !no_peephole(s)) {
    struct mrb_insn_data data = mrb_last_insn(s);
    if (data.insn == OP_MOVE && data.a == dst) {
      dst = data.b;
      rewind_pc(s);
    }
  }
  genop_2(s, op, dst, idx);
}

smb_send_rqst(struct TCP_Server_Info* server, struct smb_rqst* rqst) {
  int rc;
  struct kvec* iov = rqst->rq_iov;
  int n_vec = rqst->rq_nvec;
  unsigned int smb_buf_length = get_rfc1002_length(iov[0].iov_base);
  unsigned int i;
  size_t total_len = 0, sent;
  struct socket* ssocket = server->ssocket;
  int val = 1;
  if (ssocket == NULL) return -ENOTSOCK;
  cFYI(1, "Sending smb: smb_len=%u", smb_buf_length);
  dump_smb(iov[0].iov_base, iov[0].iov_len);
  kernel_setsockopt(ssocket, SOL_TCP, TCP_CORK, (char*)&val, sizeof(val));
  rc = smb_send_kvec(server, iov, n_vec, &sent);
  if (rc < 0) goto uncork;
  total_len += sent;
  for (i = 0; i < rqst->rq_npages; i++) {
    struct kvec p_iov;
    cifs_rqst_page_to_kvec(rqst, i, &p_iov);
    rc = smb_send_kvec(server, &p_iov, 1, &sent);
    kunmap(rqst->rq_pages[i]);
    if (rc < 0) break;
    total_len += sent;
  }
uncork:
  val = 0;
  kernel_setsockopt(ssocket, SOL_TCP, TCP_CORK, (char*)&val, sizeof(val));
  if ((total_len > 0) && (total_len != smb_buf_length + 4)) {
    cFYI(1,
         "partial send (wanted=%u sent=%zu): terminating "
         "session",
         smb_buf_length + 4, total_len);
    server->tcpStatus = CifsNeedReconnect;
  }
  if (rc < 0 && rc != -EINTR)
    cERROR(1, "Error %d sending data on socket to server", rc);
  else
    rc = 0;
  return rc;
}

void TiffEncoder::encodeOffsetEntry(TiffEntryBase* object,
                                    const Exifdatum* datum) {
  assert(object != 0);
  assert(datum != 0);
  size_t newSize = datum->size();
  if (newSize > object->size_) {
    setDirty();
    object->updateValue(datum->getValue(), byteOrder());
#ifdef DEBUG
    ExifKey key(object->tag(), groupName(object->group()));
    std::cerr << "UPDATING DATA     " << key;
    std::cerr << "\t\t\t ALLOCATED " << object->size() << " BYTES";
