TEE_Result syscall_authenc_update_aad(unsigned long state, const void* aad_data,
                                      size_t aad_data_len) {
  TEE_Result res;
  struct tee_cryp_state* cs;
  struct tee_ta_session* sess;
  res = tee_ta_get_current_session(&sess);
  if (res != TEE_SUCCESS) return res;
  res = tee_mmu_check_access_rights(
      to_user_ta_ctx(sess->ctx),
      TEE_MEMORY_ACCESS_READ | TEE_MEMORY_ACCESS_ANY_OWNER, (uaddr_t)aad_data,
      aad_data_len);
  if (res != TEE_SUCCESS) return res;
  res = tee_svc_cryp_get_state(sess, tee_svc_uref_to_vaddr(state), &cs);
  if (res != TEE_SUCCESS) return res;
  if (cs->state != CRYP_STATE_INITIALIZED) return TEE_ERROR_BAD_STATE;
  if (TEE_ALG_GET_CLASS(cs->algo) != TEE_OPERATION_AE)
    return TEE_ERROR_BAD_STATE;
  res = crypto_authenc_update_aad(cs->ctx, cs->algo, cs->mode, aad_data,
                                  aad_data_len);
  if (res != TEE_SUCCESS) return res;
  return TEE_SUCCESS;
}

Bool gf_fs_solve_js_script(char* szPath, const char* file_name,
                           const char* file_ext) {
  const char* js_dirs;
  if (gf_opts_default_shared_directory(szPath)) {
    strcat(szPath, "/scripts/jsf/");
    GF_LOG(GF_LOG_DEBUG, GF_LOG_FILTER, ("Trying JS filter %s\n", szPath));
    if (locate_js_script(szPath, file_name, file_ext)) {
      return GF_TRUE;
    }
  } else {
    GF_LOG(GF_LOG_INFO, GF_LOG_FILTER, ("Failed to get default shared dir\n"));
  }
  js_dirs = gf_opts_get_key("core", "js-dirs");
  while (js_dirs && js_dirs[0]) {
    char* sep = strchr(js_dirs, ',');
    if (sep) {
      u32 cplen = (u32)(sep - js_dirs);
      if (cplen >= GF_MAX_PATH) cplen = GF_MAX_PATH - 1;
      strncpy(szPath, js_dirs, cplen);
      szPath[cplen] = 0;
      js_dirs = sep + 1;
    } else {
      strcpy(szPath, js_dirs);
    }
    if (strcmp(szPath, "$GJS")) {
      u32 len = (u32)strlen(szPath);
      if (len && (szPath[len - 1] != '/') && (szPath[len - 1] != '\\'))
        strcat(szPath, "/");
      GF_LOG(GF_LOG_DEBUG, GF_LOG_FILTER, ("Trying JS filter in %s\n", szPath));
      if (locate_js_script(szPath, file_name, file_ext)) return GF_TRUE;
    }
    if (!sep) break;
  }
  return GF_FALSE;
}

static void call_trans2getdfsreferral(connection_struct* conn,
                                      struct smb_request* req, char** pparams,
                                      int total_params, char** ppdata,
                                      int total_data,
                                      unsigned int max_data_bytes) {
  char* params = *pparams;
  char* pathname = NULL;
  int reply_size = 0;
  int max_referral_level;
  NTSTATUS status = NT_STATUS_OK;
  TALLOC_CTX* ctx = talloc_tos();
  DEBUG(10, ("call_trans2getdfsreferral\n"));
  if (total_params < 3) {
    reply_nterror(req, NT_STATUS_INVALID_PARAMETER);
    return;
  }
  max_referral_level = SVAL(params, 0);
  if (!lp_host_msdfs()) {
    reply_nterror(req, NT_STATUS_NOT_IMPLEMENTED);
    return;
  }
  srvstr_pull_talloc(ctx, params, req->flags2, &pathname, &params[2],
                     total_params - 2, STR_TERMINATE);
  if (!pathname) {
    reply_nterror(req, NT_STATUS_NOT_FOUND);
    return;
  }
  if ((reply_size = setup_dfs_referral(conn, pathname, max_referral_level,
                                       ppdata, &status)) < 0) {
    reply_nterror(req, status);
    return;
  }
  SSVAL((discard_const_p(uint8_t, req->inbuf)), smb_flg2,
        SVAL(req->inbuf, smb_flg2) | FLAGS2_DFS_PATHNAMES);
  send_trans2_replies(conn, req, NT_STATUS_OK, 0, 0, *ppdata, reply_size,
                      max_data_bytes);
  return;
}

static void create_worker_cont(struct callback_head* cb) {
  struct io_worker* worker;
  struct task_struct* tsk;
  struct io_wqe* wqe;
  worker = container_of(cb, struct io_worker, create_work);
  clear_bit_unlock(0, &worker->create_state);
  wqe = worker->wqe;
  tsk = create_io_thread(io_wqe_worker, worker, wqe->node);
  if (!IS_ERR(tsk)) {
    io_init_new_worker(wqe, worker, tsk);
    io_worker_release(worker);
    return;
  } else if (!io_should_retry_thread(PTR_ERR(tsk))) {
    struct io_wqe_acct* acct = io_wqe_get_acct(worker);
    atomic_dec(&acct->nr_running);
    raw_spin_lock(&wqe->lock);
    acct->nr_workers--;
    if (!acct->nr_workers) {
      struct io_cb_cancel_data match = {
          .fn = io_wq_work_match_all,
          .cancel_all = true,
      };
      while (io_acct_cancel_pending_work(wqe, acct, &match))
        raw_spin_lock(&wqe->lock);
    }
    raw_spin_unlock(&wqe->lock);
    io_worker_ref_put(wqe->wq);
    return;
  }
  io_worker_release(worker);
  schedule_work(&worker->work);
}

static void conncache_remove_bundle(struct conncache* connc,
                                    struct connectbundle* bundle) {
  struct Curl_hash_iterator iter;
  struct Curl_hash_element* he;
  if (!connc) return;
  Curl_hash_start_iterate(&connc->hash, &iter);
  he = Curl_hash_next_element(&iter);
  while (he) {
    if (he->ptr == bundle) {
      Curl_hash_delete(&connc->hash, he->key, he->key_len);
      return;
    }
    he = Curl_hash_next_element(&iter);
  }
}

void GLES2DecoderImpl::DoRenderbufferStorageMultisample(GLenum target,
                                                        GLsizei samples,
                                                        GLenum internalformat,
                                                        GLsizei width,
                                                        GLsizei height) {
  if (!feature_info_->feature_flags().chromium_framebuffer_multisample) {
    SetGLError(GL_INVALID_OPERATION,
               "glRenderbufferStorageMultisampleEXT: function not available");
    return;
  }
  RenderbufferManager::RenderbufferInfo* renderbuffer =
      GetRenderbufferInfoForTarget(GL_RENDERBUFFER);
  if (!renderbuffer) {
    SetGLError(GL_INVALID_OPERATION,
               "glGetRenderbufferStorageMultisample: no renderbuffer bound");
    return;
  }
  if (samples > renderbuffer_manager()->max_samples()) {
    SetGLError(GL_INVALID_VALUE,
               "glGetRenderbufferStorageMultisample: samples too large");
    return;
  }
  if (width > renderbuffer_manager()->max_renderbuffer_size() ||
      height > renderbuffer_manager()->max_renderbuffer_size()) {
    SetGLError(GL_INVALID_VALUE,
               "glGetRenderbufferStorageMultisample: size too large");
    return;
  }
  GLenum impl_format = internalformat;
  if (gfx::GetGLImplementation() != gfx::kGLImplementationEGLGLES2) {
    switch (impl_format) {
      case GL_DEPTH_COMPONENT16:
        impl_format = GL_DEPTH_COMPONENT;
        break;
      case GL_RGBA4:
      case GL_RGB5_A1:
        impl_format = GL_RGBA;
        break;
      case GL_RGB565:
        impl_format = GL_RGB;
        break;
    }
  }
  CopyRealGLErrorsToWrapper();
  if (IsAngle()) {
    glRenderbufferStorageMultisampleANGLE(target, samples, impl_format, width,
                                          height);
  } else {
    glRenderbufferStorageMultisampleEXT(target, samples, impl_format, width,
                                        height);
  }
  GLenum error = PeekGLError();
  if (error == GL_NO_ERROR) {
    framebuffer_manager()->IncFramebufferStateChangeCount();
    renderbuffer_manager()->SetInfo(renderbuffer, samples, internalformat,
                                    width, height);
  }
}

static gps_mask_t rtcm104v2_analyze(struct gps_device_t* session) {
  rtcm2_unpack(&session->gpsdata.rtcm2, (char*)session->packet.isgps.buf);
  if (session->context->debug >= LOG_RAW)
    gpsd_report(
        LOG_RAW,
        "RTCM 2.x packet type 0x%02x length %d words from %zd bytes: %s\n",
        session->gpsdata.rtcm2.type, session->gpsdata.rtcm2.length + 2,
        session->packet.isgps.buflen,
        gpsd_hexdump(
            (char*)session->packet.isgps.buf,
            (session->gpsdata.rtcm2.length + 2) * sizeof(isgps30bits_t)));
  session->cycle_end_reliable = true;
  return RTCM2_SET;
}

