static void Ins_DELTAC(INS_ARG) {
  Long nump, k;
  Long A, B, C;
  nump = args[0];
  for (k = 1; k <= nump; k++) {
    if (CUR.args < 2) {
      CUR.error = TT_Err_Too_Few_Arguments;
      return;
    }
    CUR.args -= 2;
    A = CUR.stack[CUR.args + 1];
    B = CUR.stack[CUR.args];
    if (A >= CUR.cvtSize) {
      CUR.error = TT_Err_Invalid_Reference;
      return;
    }
    C = ((unsigned long)(B & 0xF0)) >> 4;
    switch (CUR.opcode) {
      case 0x73:
        break;
      case 0x74:
        C += 16;
        break;
      case 0x75:
        C += 32;
        break;
    }
    C += CUR.GS.delta_base;
    if (CURRENT_Ppem() == C) {
      B = (B & 0xF) - 8;
      if (B >= 0) B++;
      B = B * 64 / (1L << CUR.GS.delta_shift);
      CUR_Func_move_cvt(A, B);
    }
  }
  CUR.new_top = CUR.args;
}

int gnutls_x509_aia_get(gnutls_x509_aia_t aia, unsigned int seq,
                        gnutls_datum_t* oid, unsigned* san_type,
                        gnutls_datum_t* san) {
  if (seq >= aia->size)
    return gnutls_assert_val(GNUTLS_E_REQUESTED_DATA_NOT_AVAILABLE);
  if (san_type) *san_type = aia->aia[seq].san_type;
  if (san) {
    san->data = aia->aia[seq].san.data;
    san->size = aia->aia[seq].san.size;
  }
  if (oid) {
    oid->data = aia->aia[seq].oid.data;
    oid->size = aia->aia[seq].oid.size;
  }
  return 0;
}

