static int packet_create(struct net* net, struct socket* sock, int protocol,
                         int kern) {
  struct sock* sk;
  struct packet_sock* po;
  __be16 proto = (__force __be16)protocol;
  int err;
  if (!capable(CAP_NET_RAW)) return -EPERM;
  if (sock->type != SOCK_DGRAM && sock->type != SOCK_RAW &&
      sock->type != SOCK_PACKET)
    return -ESOCKTNOSUPPORT;
  sock->state = SS_UNCONNECTED;
  err = -ENOBUFS;
  sk = sk_alloc(net, PF_PACKET, GFP_KERNEL, &packet_proto);
  if (sk == NULL) goto out;
  sock->ops = &packet_ops;
  if (sock->type == SOCK_PACKET) sock->ops = &packet_ops_spkt;
  sock_init_data(sock, sk);
  po = pkt_sk(sk);
  sk->sk_family = PF_PACKET;
  po->num = proto;
  sk->sk_destruct = packet_sock_destruct;
  sk_refcnt_debug_inc(sk);
  spin_lock_init(&po->bind_lock);
  mutex_init(&po->pg_vec_lock);
  po->prot_hook.func = packet_rcv;
  if (sock->type == SOCK_PACKET) po->prot_hook.func = packet_rcv_spkt;
  po->prot_hook.af_packet_priv = sk;
  if (proto) {
    po->prot_hook.type = proto;
    register_prot_hook(sk);
  }
  spin_lock_bh(&net->packet.sklist_lock);
  sk_add_node_rcu(sk, &net->packet.sklist);
  sock_prot_inuse_add(net, &packet_proto, 1);
  spin_unlock_bh(&net->packet.sklist_lock);
  return 0;
out:
  return err;
}

static NTSTATUS receive_smb_raw_talloc(TALLOC_CTX* mem_ctx, int fd,
                                       char** buffer, unsigned int timeout,
                                       size_t* p_unread, size_t* plen) {
  char lenbuf[4];
  size_t len;
  int min_recv_size = lp_min_receive_file_size();
  NTSTATUS status;
  *p_unread = 0;
  status = read_smb_length_return_keepalive(fd, lenbuf, timeout, &len);
  if (!NT_STATUS_IS_OK(status)) {
    DEBUG(10, ("receive_smb_raw: %s\n", nt_errstr(status)));
    return status;
  }
  if (CVAL(lenbuf, 0) == 0 && min_recv_size &&
      (smb_len_large(lenbuf) >
       (min_recv_size + STANDARD_WRITE_AND_X_HEADER_SIZE)) &&
      !srv_is_signing_active(smbd_server_conn)) {
    return receive_smb_raw_talloc_partial_read(mem_ctx, lenbuf, fd, buffer,
                                               timeout, p_unread, plen);
  }
  if (!valid_packet_size(len)) {
    return NT_STATUS_INVALID_PARAMETER;
  }
  *buffer = TALLOC_ARRAY(mem_ctx, char, len + 4);
  if (*buffer == NULL) {
    DEBUG(0, ("Could not allocate inbuf of length %d\n", (int)len + 4));
    return NT_STATUS_NO_MEMORY;
  }
  memcpy(*buffer, lenbuf, sizeof(lenbuf));
  status = read_packet_remainder(fd, (*buffer) + 4, timeout, len);
  if (!NT_STATUS_IS_OK(status)) {
    return status;
  }
  *plen = len + 4;
  return NT_STATUS_OK;
}

static void raw_cmd_done(int flag) {
  int i;
  if (!flag) {
    raw_cmd->flags |= FD_RAW_FAILURE;
    raw_cmd->flags |= FD_RAW_HARDFAILURE;
  } else {
    raw_cmd->reply_count = inr;
    if (raw_cmd->reply_count > MAX_REPLIES) raw_cmd->reply_count = 0;
    for (i = 0; i < raw_cmd->reply_count; i++)
      raw_cmd->reply[i] = reply_buffer[i];
    if (raw_cmd->flags & (FD_RAW_READ | FD_RAW_WRITE)) {
      unsigned long flags;
      flags = claim_dma_lock();
      raw_cmd->length = fd_get_dma_residue();
      release_dma_lock(flags);
    }
    if ((raw_cmd->flags & FD_RAW_SOFTFAILURE) &&
        (!raw_cmd->reply_count || (raw_cmd->reply[0] & 0xc0)))
      raw_cmd->flags |= FD_RAW_FAILURE;
    if (disk_change(current_drive))
      raw_cmd->flags |= FD_RAW_DISK_CHANGE;
    else
      raw_cmd->flags &= ~FD_RAW_DISK_CHANGE;
    if (raw_cmd->flags & FD_RAW_NO_MOTOR_AFTER)
      motor_off_callback(&motor_off_timer[current_drive]);
    if (raw_cmd->next &&
        (!(raw_cmd->flags & FD_RAW_FAILURE) ||
         !(raw_cmd->flags & FD_RAW_STOP_IF_FAILURE)) &&
        ((raw_cmd->flags & FD_RAW_FAILURE) ||
         !(raw_cmd->flags & FD_RAW_STOP_IF_SUCCESS))) {
      raw_cmd = raw_cmd->next;
      return;
    }
  }
  generic_done(flag);
}

lazy_entry* lazy_entry::dict_append(char const* name) {
  TORRENT_ASSERT(m_type == dict_t);
  TORRENT_ASSERT(m_size <= m_capacity);
  if (m_capacity == 0) {
    int capacity = lazy_entry_dict_init;
    m_data.dict = new (std::nothrow) lazy_dict_entry[capacity];
    if (m_data.dict == 0) return 0;
    m_capacity = capacity;
  } else if (m_size == m_capacity) {
    int capacity = m_capacity * lazy_entry_grow_factor / 100;
    lazy_dict_entry* tmp = new (std::nothrow) lazy_dict_entry[capacity];
    if (tmp == 0) return 0;
    std::memcpy(tmp, m_data.dict, sizeof(lazy_dict_entry) * m_size);
    for (int i = 0; i < int(m_size); ++i) m_data.dict[i].val.release();
    delete[] m_data.dict;
    m_data.dict = tmp;
    m_capacity = capacity;
  }
  TORRENT_ASSERT(m_size < m_capacity);
  lazy_dict_entry& ret = m_data.dict[m_size++];
  ret.name = name;
  return &ret.val;
}

static int decode_attr_time_access(struct xdr_stream* xdr, uint32_t* bitmap,
                                   struct timespec* time) {
  int status = 0;
  time->tv_sec = 0;
  time->tv_nsec = 0;
  if (unlikely(bitmap[1] & (FATTR4_WORD1_TIME_ACCESS - 1U))) return -EIO;
  if (likely(bitmap[1] & FATTR4_WORD1_TIME_ACCESS)) {
    status = decode_attr_time(xdr, time);
    if (status == 0) status = NFS_ATTR_FATTR_ATIME;
    bitmap[1] &= ~FATTR4_WORD1_TIME_ACCESS;
  }
  dprintk("%s: atime=%ld\n", __func__, (long)time->tv_sec);
  return status;
}

