Rule::Rule(const ProtoRule& rule) : rule_(rule) {
  if (!rule.cookie().empty() && !rule.header().empty()) {
    throw EnvoyException("Cannot specify both header and cookie");
  }
  if (!rule.header().empty()) {
    selector_ = std::make_shared<HeaderValueSelector>(
        Http::LowerCaseString(rule.header()), rule.remove());
  } else if (!rule.cookie().empty()) {
    selector_ = std::make_shared<CookieValueSelector>(rule.cookie());
  } else {
    throw EnvoyException(
        "One of Cookie or Header option needs to be specified");
  }
  if (!rule.has_on_header_present() && !rule.has_on_header_missing()) {
    const auto& error = fmt::format(
        "header to metadata filter: rule for {} has neither "
        "`on_header_present` nor `on_header_missing` set",
        selector_->toString());
    throw EnvoyException(error);
  }
  if (!rule.on_header_present().value().empty() &&
      rule.on_header_present().has_regex_value_rewrite()) {
    throw EnvoyException("Cannot specify both value and regex_value_rewrite");
  }
  if (!rule.cookie().empty() && rule.remove()) {
    throw EnvoyException("Cannot specify remove for cookie");
  }
  if (rule.has_on_header_missing() &&
      rule.on_header_missing().value().empty()) {
    throw EnvoyException(
        "Cannot specify on_header_missing rule with an empty value");
  }
  if (rule.on_header_present().has_regex_value_rewrite()) {
    const auto& rewrite_spec = rule.on_header_present().regex_value_rewrite();
    regex_rewrite_ = Regex::Utility::parseRegex(rewrite_spec.pattern());
    regex_rewrite_substitution_ = rewrite_spec.substitution();
  }
}

static void* kmalloc_large_node(size_t size, gfp_t flags, int node) {
  struct page* page;
  void* ptr = NULL;
  unsigned int order = get_order(size);
  flags |= __GFP_COMP;
  page = alloc_pages_node(node, flags, order);
  if (page) {
    ptr = page_address(page);
    mod_node_page_state(page_pgdat(page), NR_SLAB_UNRECLAIMABLE, 1 << order);
  }
  return kmalloc_large_node_hook(ptr, size, flags);
}

static inline void ok_jpg_convert_YCbCr_to_RGB(uint8_t Y, uint8_t Cb,
                                               uint8_t Cr, uint8_t* r,
                                               uint8_t* g, uint8_t* b) {
  static const int fx1 = 91881;
  static const int fx2 = -22553;
  static const int fx3 = -46802;
  static const int fx4 = 116130;
  const int fy = (Y << 16) + (1 << 15);
  const int fr = fy + fx1 * (Cr - 128);
  const int fg = fy + fx2 * (Cb - 128) + fx3 * (Cr - 128);
  const int fb = fy + fx4 * (Cb - 128);
  *r = ok_jpg_clip_fp_uint8(fr);
  *g = ok_jpg_clip_fp_uint8(fg);
  *b = ok_jpg_clip_fp_uint8(fb);
}

zval* php_snmp_read_property(zval* object, zval* member, int type,
                             void** cache_slot, zval* rv) {
  zval tmp_member;
  zval* retval;
  php_snmp_object* obj;
  php_snmp_prop_handler* hnd;
  int ret;
  obj = Z_SNMP_P(object);
  if (Z_TYPE_P(member) != IS_STRING) {
    ZVAL_COPY(&tmp_member, member);
    convert_to_string(&tmp_member);
    member = &tmp_member;
  }
  hnd = zend_hash_find_ptr(&php_snmp_properties, Z_STR_P(member));
  if (hnd && hnd->read_func) {
    ret = hnd->read_func(obj, rv);
    if (ret == SUCCESS) {
      retval = rv;
    } else {
      retval = &EG(uninitialized_zval);
    }
  } else {
    zend_object_handlers* std_hnd = zend_get_std_object_handlers();
    retval = std_hnd->read_property(object, member, type, cache_slot, rv);
  }
  if (member == &tmp_member) {
    zval_ptr_dtor(member);
  }
  return retval;
}

PHP_FUNCTION(pg_flush) {
  zval* pgsql_link;
  int id = -1;
  PGconn* pgsql;
  int ret;
  int is_non_blocking;
  if (zend_parse_parameters(ZEND_NUM_ARGS(), "r", &pgsql_link) == FAILURE) {
    return;
  }
  ZEND_FETCH_RESOURCE2(pgsql, PGconn*, pgsql_link, id, "PostgreSQL link",
                       le_link, le_plink);
  is_non_blocking = PQisnonblocking(pgsql);
  if (is_non_blocking == 0 && PQ_SETNONBLOCKING(pgsql, 1) == -1) {
    php_error_docref(NULL, E_NOTICE,
                     "Cannot set connection to nonblocking mode");
    RETURN_FALSE;
  }
  ret = PQflush(pgsql);
  if (is_non_blocking == 0 && PQ_SETNONBLOCKING(pgsql, 0) == -1) {
    php_error_docref(NULL, E_NOTICE,
                     "Failed resetting connection to blocking mode");
  }
  switch (ret) {
    case 0:
      RETURN_TRUE;
      break;
    case 1:
      RETURN_LONG(0);
      break;
    default:
      RETURN_FALSE;
  }
}

const FilePath::CharType* SavePackage::ExtensionForMimeType(
    const std::string& contents_mime_type) {
  static const struct {
    const FilePath::CharType* mime_type;
    const FilePath::CharType* suggested_extension;
  } extensions[] = {
      {FILE_PATH_LITERAL("text/html"), kDefaultHtmlExtension},
      {FILE_PATH_LITERAL("text/xml"), FILE_PATH_LITERAL("xml")},
      {FILE_PATH_LITERAL("application/xhtml+xml"), FILE_PATH_LITERAL("xhtml")},
      {FILE_PATH_LITERAL("text/plain"), FILE_PATH_LITERAL("txt")},
      {FILE_PATH_LITERAL("text/css"), FILE_PATH_LITERAL("css")},
