static int pfkey_sendmsg(struct kiocb* kiocb, struct socket* sock,
                         struct msghdr* msg, size_t len) {
  struct sock* sk = sock->sk;
  struct sk_buff* skb = NULL;
  struct sadb_msg* hdr = NULL;
  int err;
  err = -EOPNOTSUPP;
  if (msg->msg_flags & MSG_OOB) goto out;
  err = -EMSGSIZE;
  if ((unsigned int)len > sk->sk_sndbuf - 32) goto out;
  err = -ENOBUFS;
  skb = alloc_skb(len, GFP_KERNEL);
  if (skb == NULL) goto out;
  err = -EFAULT;
  if (memcpy_fromiovec(skb_put(skb, len), msg->msg_iov, len)) goto out;
  hdr = pfkey_get_base_msg(skb, &err);
  if (!hdr) goto out;
  mutex_lock(&xfrm_cfg_mutex);
  err = pfkey_process(sk, skb, hdr);
  mutex_unlock(&xfrm_cfg_mutex);
out:
  if (err && hdr && pfkey_error(hdr, err, sk) == 0) err = 0;
  kfree_skb(skb);
  return err ?: len;
}

static void ResetPixelList(PixelList* pixel_list) {
  int level;
  register SkipNode* root;
  register SkipList* p;
  p = (&pixel_list->skip_list);
  root = p->nodes + 65536UL;
  p->level = 0;
  for (level = 0; level < 9; level++) root->next[level] = 65536UL;
  pixel_list->seed = pixel_list->signature++;
}

parse_ed_props(const uint16_t prop_class, char** arg, int* n_props,
               struct ofpbuf* out) {
  char *key, *value, *err;
  uint8_t prop_type;
  while (ofputil_parse_key_value(arg, &key, &value)) {
    if (!parse_ed_prop_type(prop_class, key, &prop_type)) {
      return xasprintf("Invalid property: %s", key);
    }
    if (value == NULL) {
      return xasprintf("Missing the value for property: %s", key);
    }
    err = parse_ed_prop_value(prop_class, prop_type, value, out);
    if (err != NULL) {
      return err;
    }
    (*n_props)++;
  }
  return NULL;
}

mm_key_allowed(enum mm_keytype type, char* user, char* host, Key* key) {
  Buffer m;
  u_char* blob;
  u_int len;
  int allowed = 0, have_forced = 0;
  debug3("%s entering", __func__);
  if (!key_to_blob(key, &blob, &len)) return (0);
  buffer_init(&m);
  buffer_put_int(&m, type);
  buffer_put_cstring(&m, user ? user : "");
  buffer_put_cstring(&m, host ? host : "");
  buffer_put_string(&m, blob, len);
  xfree(blob);
  mm_request_send(pmonitor->m_recvfd, MONITOR_REQ_KEYALLOWED, &m);
  debug3("%s: waiting for MONITOR_ANS_KEYALLOWED", __func__);
  mm_request_receive_expect(pmonitor->m_recvfd, MONITOR_ANS_KEYALLOWED, &m);
  allowed = buffer_get_int(&m);
  auth_clear_options();
  have_forced = buffer_get_int(&m);
  forced_command = have_forced ? xstrdup("true") : NULL;
  mm_send_debug(&m);
  buffer_free(&m);
  return (allowed);
}

_PUBLIC_ void file_lines_slashcont(char** lines) {
  int i, j;
  for (i = 0; lines[i];) {
    int len = strlen(lines[i]);
    if (lines[i][len - 1] == '\\') {
      lines[i][len - 1] = ' ';
      if (lines[i + 1]) {
        char* p = &lines[i][len];
        while (p < lines[i + 1]) *p++ = ' ';
        for (j = i + 1; lines[j]; j++) lines[j] = lines[j + 1];
      }
    } else {
      i++;
    }
