static int fsmSetFCaps(int fd, int dirfd, const char* path,
                       const char* captxt) {
  int rc = 0;
#if WITH_CAP
  if (captxt && *captxt != '\0') {
    cap_t fcaps = cap_from_text(captxt);
    if (fd >= 0) {
      if (fcaps == NULL || cap_set_fd(fd, fcaps)) rc = RPMERR_SETCAP_FAILED;
    } else {
      if (fcaps == NULL || cap_set_fileat(dirfd, path, fcaps))
        rc = RPMERR_SETCAP_FAILED;
    }
    if (_fsm_debug) {
      rpmlog(RPMLOG_DEBUG, " %8s (%d - %d %s, %s) %s\n", __func__, fd, dirfd,
             path, captxt, (rc < 0 ? strerror(errno) : ""));
    }
    cap_free(fcaps);
  }
#endif
  return rc;
}

nfs4_proc_setattr(struct dentry* dentry, struct nfs_fattr* fattr,
                  struct iattr* sattr) {
  struct inode* inode = dentry->d_inode;
  struct rpc_cred* cred = NULL;
  struct nfs4_state* state = NULL;
  int status;
  if (pnfs_ld_layoutret_on_setattr(inode)) pnfs_return_layout(inode);
  nfs_fattr_init(fattr);
  if (sattr->ia_valid & ATTR_OPEN)
    sattr->ia_valid &= ~(ATTR_MTIME | ATTR_CTIME | ATTR_OPEN);
  if ((sattr->ia_valid & ~(ATTR_FILE)) == 0) return 0;
  if (sattr->ia_valid & ATTR_FILE) {
    struct nfs_open_context* ctx;
    ctx = nfs_file_open_context(sattr->ia_file);
    if (ctx) {
      cred = ctx->cred;
      state = ctx->state;
    }
  }
  status = nfs4_do_setattr(inode, cred, fattr, sattr, state);
  if (status == 0) nfs_setattr_update_inode(inode, sattr);
  return status;
}

