    msr->data = efer & ~EFER_LME;
  }
  setup_msrs(vmx);
}

bool PasswordAutofillAgent::FindPasswordInfoForElement(
    const blink::WebInputElement& element,
    blink::WebInputElement* username_element,
    blink::WebInputElement* password_element, PasswordInfo** password_info) {
  DCHECK(username_element && password_element && password_info);
  username_element->reset();
  password_element->reset();
  if (!element.isPasswordField()) {
    *username_element = element;
  } else {
    WebInputToPasswordInfoMap::iterator iter =
        web_input_to_password_info_.find(element);
    if (iter != web_input_to_password_info_.end()) {
      *password_element = element;
      *password_info = &iter->second;
      return true;
    }
    PasswordToLoginMap::const_iterator password_iter =
        password_to_username_.find(element);
    if (password_iter == password_to_username_.end()) {
      if (web_input_to_password_info_.empty()) return false;
      *password_element = element;
      *password_info = &web_input_to_password_info_.begin()->second;
      return true;
    }
    *username_element = password_iter->second;
    *password_element = element;
  }
  WebInputToPasswordInfoMap::iterator iter =
      web_input_to_password_info_.find(*username_element);
  if (iter == web_input_to_password_info_.end()) return false;
  *password_info = &iter->second;
  if (password_element->isNull())
    *password_element = (*password_info)->password_field;
  return true;
}

Bool gf_isom_get_edit_list_type(GF_ISOFile* the_file, u32 trackNumber,
                                s64* mediaOffset) {
  GF_EdtsEntry* ent;
  GF_TrackBox* trak;
  u32 count;
  trak = gf_isom_get_track_from_file(the_file, trackNumber);
  if (!trak) return GF_FALSE;
  *mediaOffset = 0;
  if (!trak->editBox || !trak->editBox->editList) return GF_FALSE;
  count = gf_list_count(trak->editBox->editList->entryList);
  ent = (GF_EdtsEntry*)gf_list_get(trak->editBox->editList->entryList, 0);
  if (!ent) return GF_TRUE;
  if ((count == 1) && (ent->mediaRate == 0x10000)) {
    *mediaOffset = -ent->mediaTime;
    return GF_FALSE;
  } else if (count == 2) {
    if ((ent->mediaRate == -0x10000) || (ent->mediaTime == -1)) {
      Double time = (Double)ent->segmentDuration;
      time /= trak->moov->mvhd->timeScale;
      time *= trak->Media->mediaHeader->timeScale;
      *mediaOffset = (s64)time;
      ent = (GF_EdtsEntry*)gf_list_get(trak->editBox->editList->entryList, 1);
      if (ent->mediaRate != 0x10000) return GF_TRUE;
      if (ent->mediaTime > 0) {
        *mediaOffset -= ent->mediaTime;
      }
      return GF_FALSE;
    }
  }
  return GF_TRUE;
}

