ipa_value_from_jfunc(class ipa_node_params* info, struct ipa_jump_func* jfunc,
                     tree parm_type) {
  if (jfunc->type == IPA_JF_CONST)
    return ipa_get_jf_constant(jfunc);
  else if (jfunc->type == IPA_JF_PASS_THROUGH ||
           jfunc->type == IPA_JF_ANCESTOR) {
    tree input;
    int idx;
    if (jfunc->type == IPA_JF_PASS_THROUGH)
      idx = ipa_get_jf_pass_through_formal_id(jfunc);
    else
      idx = ipa_get_jf_ancestor_formal_id(jfunc);
    if (info->ipcp_orig_node)
      input = info->known_csts[idx];
    else {
      ipcp_lattice<tree>* lat;
      if (!info->lattices || idx >= ipa_get_param_count(info)) return NULL_TREE;
      lat = ipa_get_scalar_lat(info, idx);
      if (!lat->is_single_const()) return NULL_TREE;
      input = lat->values->value;
    }
    if (!input) return NULL_TREE;
    if (jfunc->type == IPA_JF_PASS_THROUGH)
      return ipa_get_jf_pass_through_result(jfunc, input, parm_type);
    else
      return ipa_get_jf_ancestor_result(jfunc, input);
  } else
    return NULL_TREE;
}

template <typename tc>
CImg<T>& _draw_triangle(const int x0, const int y0, const int x1, const int y1,
                        const int x2, const int y2, const tc* const color,
                        const float opacity, const float brightness) {
  cimg_init_scanline(color, opacity);
  const float nbrightness = cimg::cut(brightness, 0, 2);
  int nx0 = x0, ny0 = y0, nx1 = x1, ny1 = y1, nx2 = x2, ny2 = y2;
  if (ny0 > ny1) cimg::swap(nx0, nx1, ny0, ny1);
  if (ny0 > ny2) cimg::swap(nx0, nx2, ny0, ny2);
  if (ny1 > ny2) cimg::swap(nx1, nx2, ny1, ny2);
  if (ny0 < height() && ny2 >= 0) {
    if ((nx1 - nx0) * (ny2 - ny0) - (nx2 - nx0) * (ny1 - ny0) < 0)
      _cimg_for_triangle1(*this, xl, xr, y, nx0, ny0, nx1, ny1, nx2, ny2)
          cimg_draw_scanline(xl, xr, y, color, opacity, nbrightness);
    else
      _cimg_for_triangle1(*this, xl, xr, y, nx0, ny0, nx1, ny1, nx2, ny2)
          cimg_draw_scanline(xr, xl, y, color, opacity, nbrightness);
  }
  return *this;

get_loop_line(int c, void* cookie, int indent, getline_opt_T options) {
  struct loop_cookie* cp = (struct loop_cookie*)cookie;
  wcmd_T* wp;
  char_u* line;
  if (cp->current_line + 1 >= cp->lines_gap->ga_len) {
    if (cp->repeating) return NULL;
    if (cp->getline == NULL)
      line = getcmdline(c, 0L, indent, options);
    else
      line = cp->getline(c, cp->cookie, indent, options);
    if (line != NULL && store_loop_line(cp->lines_gap, line) == OK)
      ++cp->current_line;
    return line;
  }
  KeyTyped = FALSE;
  ++cp->current_line;
  wp = (wcmd_T*)(cp->lines_gap->ga_data) + cp->current_line;
  SOURCING_LNUM = wp->lnum;
  return vim_strsave(wp->line);
}

