_asn1_change_integer_value(asn1_node node) {
  asn1_node p;
  unsigned char val[SIZEOF_UNSIGNED_LONG_INT];
  unsigned char val2[SIZEOF_UNSIGNED_LONG_INT + 1];
  int len;
  if (node == NULL) return ASN1_ELEMENT_NOT_FOUND;
  p = node;
  while (p) {
    if ((type_field(p->type) == ASN1_ETYPE_INTEGER) &&
        (p->type & CONST_ASSIGN)) {
      if (p->value) {
        _asn1_convert_integer(p->value, val, sizeof(val), &len);
        asn1_octet_der(val, len, val2, &len);
        _asn1_set_value(p, val2, len);
      }
    }
    if (p->down) {
      p = p->down;
    } else {
      if (p == node)
        p = NULL;
      else if (p->right)
        p = p->right;
      else {
        while (1) {
          p = _asn1_find_up(p);
          if (p == node) {
            p = NULL;
            break;
          }
          if (p && p->right) {
            p = p->right;
            break;
          }
        }
      }
    }
  }
  return ASN1_SUCCESS;
}

event_sched_out(struct perf_event* event, struct perf_cpu_context* cpuctx,
                struct perf_event_context* ctx) {
  u64 tstamp = perf_event_time(event);
  u64 delta;
  if (event->state == PERF_EVENT_STATE_INACTIVE && !event_filter_match(event)) {
    delta = tstamp - event->tstamp_stopped;
    event->tstamp_running += delta;
    event->tstamp_stopped = tstamp;
  }
  if (event->state != PERF_EVENT_STATE_ACTIVE) return;
  perf_pmu_disable(event->pmu);
  event->state = PERF_EVENT_STATE_INACTIVE;
  if (event->pending_disable) {
    event->pending_disable = 0;
    event->state = PERF_EVENT_STATE_OFF;
  }
  event->tstamp_stopped = tstamp;
  event->pmu->del(event, 0);
  event->oncpu = -1;
  if (!is_software_event(event)) cpuctx->active_oncpu--;
  ctx->nr_active--;
  if (event->attr.freq && event->attr.sample_freq) ctx->nr_freq--;
  if (event->attr.exclusive || !cpuctx->active_oncpu) cpuctx->exclusive = 0;
  if (is_orphaned_child(event)) schedule_orphans_remove(ctx);
  perf_pmu_enable(event->pmu);
}

int64_t qmp_guest_file_open(const char* path, bool has_mode, const char* mode,
                            Error** errp) {
  int64_t fd;
  HANDLE fh;
  HANDLE templ_file = NULL;
  DWORD share_mode = FILE_SHARE_READ;
  DWORD flags_and_attr = FILE_ATTRIBUTE_NORMAL;
  LPSECURITY_ATTRIBUTES sa_attr = NULL;
  OpenFlags* guest_flags;
  if (!has_mode) {
    mode = "r";
  }
  slog("guest-file-open called, filepath: %s, mode: %s", path, mode);
  guest_flags = find_open_flag(mode);
  if (guest_flags == NULL) {
    error_setg(errp, "invalid file open mode");
    return -1;
  }
  fh =
      CreateFile(path, guest_flags->desired_access, share_mode, sa_attr,
                 guest_flags->creation_disposition, flags_and_attr, templ_file);
  if (fh == INVALID_HANDLE_VALUE) {
    error_setg_win32(errp, GetLastError(), "failed to open file '%s'", path);
    return -1;
  }
  handle_set_nonblocking(fh);
  fd = guest_file_handle_add(fh, errp);
  if (fd < 0) {
    CloseHandle(fh);
    error_setg(errp, "failed to add handle to qmp handle table");
    return -1;
  }
  slog("guest-file-open, handle: % " PRId64, fd);
  return fd;
}

static void nfs4_xdr_enc_release_lockowner(
    struct rpc_rqst* req, struct xdr_stream* xdr,
    struct nfs_release_lockowner_args* args) {
  struct compound_hdr hdr = {
      .minorversion = 0,
  };
  encode_compound_hdr(xdr, req, &hdr);
  encode_release_lockowner(xdr, &args->lock_owner, &hdr);
  encode_nops(&hdr);
}

crm_client_new(qb_ipcs_connection_t* c, uid_t uid_client, gid_t gid_client) {
  static uid_t uid_server = 0;
  static gid_t gid_cluster = 0;
  crm_client_t* client = NULL;
  CRM_LOG_ASSERT(c);
  if (c == NULL) {
    return NULL;
  }
  if (gid_cluster == 0) {
    uid_server = getuid();
    if (crm_user_lookup(CRM_DAEMON_USER, NULL, &gid_cluster) < 0) {
      static bool have_error = FALSE;
      if (have_error == FALSE) {
        crm_warn("Could not find group for user %s", CRM_DAEMON_USER);
        have_error = TRUE;
      }
    }
  }
  if (gid_cluster != 0 && gid_client != 0) {
    uid_t best_uid = -1;
    if (uid_client == 0 || uid_server == 0) {
      best_uid = QB_MAX(uid_client, uid_server);
      crm_trace("Allowing user %u to clean up after disconnect", best_uid);
    }
    crm_trace("Giving access to group %u", gid_cluster);
    qb_ipcs_connection_auth_set(c, best_uid, gid_cluster,
                                S_IRUSR | S_IWUSR | S_IRGRP | S_IWGRP);
  }
  crm_client_init();
  client = calloc(1, sizeof(crm_client_t));
  client->ipcs = c;
  client->kind = CRM_CLIENT_IPC;
  client->pid = crm_ipcs_client_pid(c);
  client->id = crm_generate_uuid();
  crm_info("Connecting %p for uid=%d gid=%d pid=%u id=%s", c, uid_client,
           gid_client, client->pid, client->id);
#if ENABLE_ACL
  client->user = uid2username(uid);
#endif
  g_hash_table_insert(client_connections, c, client);
  return client;
}

void btrfs_assign_next_active_device(struct btrfs_device* device,
                                     struct btrfs_device* this_dev) {
  struct btrfs_fs_info* fs_info = device->fs_info;
  struct btrfs_device* next_device;
  if (this_dev)
    next_device = this_dev;
  else
    next_device = btrfs_find_next_active_device(fs_info->fs_devices, device);
  ASSERT(next_device);
  if (fs_info->sb->s_bdev && (fs_info->sb->s_bdev == device->bdev))
    fs_info->sb->s_bdev = next_device->bdev;
  if (fs_info->fs_devices->latest_bdev == device->bdev)
    fs_info->fs_devices->latest_bdev = next_device->bdev;
}

static void S_AL_FreeStreamChannel(int stream) {
  if ((stream < 0) || (stream >= MAX_RAW_STREAMS)) return;
  qalSourcei(streamSources[stream], AL_BUFFER, 0);
  if (streamNumBuffers[stream] > 0) {
    qalDeleteBuffers(streamNumBuffers[stream], streamBuffers[stream]);
    streamNumBuffers[stream] = 0;
  }
  S_AL_SrcUnlock(streamSourceHandles[stream]);
  S_AL_SrcKill(streamSourceHandles[stream]);
  streamSources[stream] = 0;
  streamSourceHandles[stream] = -1;
}

njs_string_prototype_repeat(njs_vm_t* vm, njs_value_t* args, njs_uint_t nargs,
                            njs_index_t unused) {
  u_char* p;
  int64_t n, max;
  uint64_t size, length;
  njs_int_t ret;
  njs_value_t* this;
  njs_string_prop_t string;
  this = njs_argument(args, 0);
  if (njs_slow_path(njs_is_null_or_undefined(this))) {
    njs_type_error(vm, "cannot convert \"%s\"to object",
                   njs_type_string(this->type));
    return NJS_ERROR;
  }
  ret = njs_value_to_string(vm, this, this);
  if (njs_slow_path(ret != NJS_OK)) {
    return ret;
  }
  ret = njs_value_to_integer(vm, njs_arg(args, nargs, 1), &n);
  if (njs_slow_path(ret != NJS_OK)) {
    return ret;
  }
  if (njs_slow_path(n < 0 || n == INT64_MAX)) {
    njs_range_error(vm, NULL);
    return NJS_ERROR;
  }
  (void)njs_string_prop(&string, this);
  if (njs_slow_path(n == 0 || string.size == 0)) {
    vm->retval = njs_string_empty;
    return NJS_OK;
  }
  max = NJS_STRING_MAX_LENGTH / string.size;
  if (njs_slow_path(n >= max)) {
    njs_range_error(vm, NULL);
    return NJS_ERROR;
  }
  size = string.size * n;
  length = string.length * n;
  p = njs_string_alloc(vm, &vm->retval, size, length);
  if (njs_slow_path(p == NULL)) {
    return NJS_ERROR;
  }
  while (n != 0) {
    p = memcpy(p, string.start, string.size);
    p += string.size;
    n--;
  }
  return NJS_OK;
}

