void* page_frag_alloc(struct page_frag_cache* nc, unsigned int fragsz,
                      gfp_t gfp_mask) {
  unsigned int size = PAGE_SIZE;
  struct page* page;
  int offset;
  if (unlikely(!nc->va)) {
  refill:
    page = __page_frag_cache_refill(nc, gfp_mask);
    if (!page) return NULL;
#if (PAGE_SIZE < PAGE_FRAG_CACHE_MAX_SIZE)
    size = nc->size;
#endif
    page_ref_add(page, size - 1);
    nc->pfmemalloc = page_is_pfmemalloc(page);
    nc->pagecnt_bias = size;
    nc->offset = size;
  }
  offset = nc->offset - fragsz;
  if (unlikely(offset < 0)) {
    page = virt_to_page(nc->va);
    if (!page_ref_sub_and_test(page, nc->pagecnt_bias)) goto refill;
#if (PAGE_SIZE < PAGE_FRAG_CACHE_MAX_SIZE)
    size = nc->size;
#endif
    set_page_count(page, size);
    nc->pagecnt_bias = size;
    offset = size - fragsz;
  }
  nc->pagecnt_bias--;
  nc->offset = offset;
  return nc->va + offset;
}

vpnc_cleanup(NMVPNCPlugin* self, gboolean killit) {
  NMVPNCPluginPrivate* priv = NM_VPNC_PLUGIN_GET_PRIVATE(self);
  if (priv->infd >= 0) {
    close(priv->infd);
    priv->infd = -1;
  }
  pipe_cleanup(&priv->out);
  pipe_cleanup(&priv->err);
  g_string_truncate(priv->server_message, 0);
  priv->server_message_done = FALSE;
  if (priv->watch_id) {
    g_source_remove(priv->watch_id);
    priv->watch_id = 0;
  }
  if (priv->pid) {
    if (killit) {
      if (kill(priv->pid, SIGTERM) == 0)
        g_timeout_add(2000, ensure_killed, GINT_TO_POINTER(priv->pid));
      _LOGI("Terminated vpnc daemon with PID %d.", priv->pid);
    } else {
      waitpid(priv->pid, NULL, WNOHANG);
    }
    priv->pid = 0;
  }
}

