_gnutls_x509_encode_and_copy_PKI_params(ASN1_TYPE dst, const char* dst_name,
                                        gnutls_pk_algorithm_t pk_algorithm,
                                        gnutls_pk_params_st* params) {
  const char* pk;
  gnutls_datum_t der = {NULL, 0};
  int result;
  char name[128];
  pk = _gnutls_x509_pk_to_oid(pk_algorithm);
  if (pk == NULL) {
    gnutls_assert();
    return GNUTLS_E_UNKNOWN_PK_ALGORITHM;
  }
  _asnstr_append_name(name, sizeof(name), dst_name, ".algorithm.algorithm");
  result = asn1_write_value(dst, name, pk, 1);
  if (result != ASN1_SUCCESS) {
    gnutls_assert();
    return _gnutls_asn2err(result);
  }
  result = _gnutls_x509_write_pubkey_params(pk_algorithm, params, &der);
  if (result < 0) {
    gnutls_assert();
    return result;
  }
  _asnstr_append_name(name, sizeof(name), dst_name, ".algorithm.parameters");
  result = asn1_write_value(dst, name, der.data, der.size);
  _gnutls_free_datum(&der);
  if (result != ASN1_SUCCESS) {
    gnutls_assert();
    return _gnutls_asn2err(result);
  }
  result = _gnutls_x509_write_pubkey(pk_algorithm, params, &der);
  if (result < 0) {
    gnutls_assert();
    return result;
  }
  _asnstr_append_name(name, sizeof(name), dst_name, ".subjectPublicKey");
  result = asn1_write_value(dst, name, der.data, der.size * 8);
  _gnutls_free_datum(&der);
  if (result != ASN1_SUCCESS) {
    gnutls_assert();
    return _gnutls_asn2err(result);
  }
  return 0;
}

static int llc_ui_autobind(struct socket* sock, struct sockaddr_llc* addr) {
  struct sock* sk = sock->sk;
  struct llc_sock* llc = llc_sk(sk);
  struct llc_sap* sap;
  int rc = -EINVAL;
  if (!sock_flag(sk, SOCK_ZAPPED)) goto out;
  if (!addr->sllc_arphrd) addr->sllc_arphrd = ARPHRD_ETHER;
  if (addr->sllc_arphrd != ARPHRD_ETHER) goto out;
  rc = -ENODEV;
  if (sk->sk_bound_dev_if) {
    llc->dev = dev_get_by_index(&init_net, sk->sk_bound_dev_if);
    if (llc->dev && addr->sllc_arphrd != llc->dev->type) {
      dev_put(llc->dev);
      llc->dev = NULL;
    }
  } else
    llc->dev = dev_getfirstbyhwtype(&init_net, addr->sllc_arphrd);
  if (!llc->dev) goto out;
  netdev_tracker_alloc(llc->dev, &llc->dev_tracker, GFP_KERNEL);
  rc = -EUSERS;
  llc->laddr.lsap = llc_ui_autoport();
  if (!llc->laddr.lsap) goto out;
  rc = -EBUSY;
  sap = llc_sap_open(llc->laddr.lsap, NULL);
  if (!sap) goto out;
  memcpy(llc->laddr.mac, llc->dev->dev_addr, IFHWADDRLEN);
  memcpy(&llc->addr, addr, sizeof(llc->addr));
  llc_sap_add_socket(sap, sk);
  sock_reset_flag(sk, SOCK_ZAPPED);
  rc = 0;
out:
  if (rc) {
    dev_put_track(llc->dev, &llc->dev_tracker);
    llc->dev = NULL;
  }
  return rc;
}

ExtractorImpl::extract(const Http::RequestHeaderMap& headers) const {
  std::vector<JwtLocationConstPtr> tokens;
  for (const auto& location_it : header_locations_) {
    const auto& location_spec = location_it.second;
    ENVOY_LOG(debug, "extract {}", location_it.first);
    const auto result = Http::HeaderUtility::getAllOfHeaderAsString(
        headers, location_spec->header_);
    if (result.result().has_value()) {
      auto value_str = result.result().value();
      if (!location_spec->value_prefix_.empty()) {
        const auto pos = value_str.find(location_spec->value_prefix_);
        if (pos == absl::string_view::npos) {
          continue;
        }
        value_str =
            extractJWT(value_str, pos + location_spec->value_prefix_.length());
      }
      tokens.push_back(std::make_unique<const JwtHeaderLocation>(
          std::string(value_str), location_spec->specified_issuers_,
          location_spec->header_));
    }
  }
  if (param_locations_.empty() || headers.Path() == nullptr) {
    return tokens;
  }
  const auto& params =
      Http::Utility::parseAndDecodeQueryString(headers.getPathValue());
  for (const auto& location_it : param_locations_) {
    const auto& param_key = location_it.first;
    const auto& location_spec = location_it.second;
    const auto& it = params.find(param_key);
    if (it != params.end()) {
      tokens.push_back(std::make_unique<const JwtParamLocation>(
          it->second, location_spec.specified_issuers_, param_key));
    }
  }
  return tokens;
}

int rxrpc_get_server_data_key(struct rxrpc_connection* conn,
                              const void* session_key, time_t expiry,
                              u32 kvno) {
  const struct cred* cred = current_cred();
  struct key* key;
  int ret;
  struct {
    u32 kver;
    struct rxrpc_key_data_v1 v1;
  } data;
  _enter("");
  key = key_alloc(&key_type_rxrpc, "x", GLOBAL_ROOT_UID, GLOBAL_ROOT_GID, cred,
                  0, KEY_ALLOC_NOT_IN_QUOTA);
  if (IS_ERR(key)) {
    _leave(" = -ENOMEM [alloc %ld]", PTR_ERR(key));
    return -ENOMEM;
  }
  _debug("key %d", key_serial(key));
  data.kver = 1;
  data.v1.security_index = RXRPC_SECURITY_RXKAD;
  data.v1.ticket_length = 0;
  data.v1.expiry = expiry;
  data.v1.kvno = 0;
  memcpy(&data.v1.session_key, session_key, sizeof(data.v1.session_key));
  ret = key_instantiate_and_link(key, &data, sizeof(data), NULL, NULL);
  if (ret < 0) goto error;
  conn->key = key;
  _leave(" = 0 [%d]", key_serial(key));
  return 0;
error:
  key_revoke(key);
  key_put(key);
  _leave(" = -ENOMEM [ins %d]", ret);
  return -ENOMEM;
}

void SVGFEColorMatrixElement::svgAttributeChanged(
    const QualifiedName& attrName) {
  if (!isSupportedAttribute(attrName)) {
    SVGFilterPrimitiveStandardAttributes::svgAttributeChanged(attrName);
