static int _nfs41_test_stateid(struct nfs_server* server,
                               nfs4_stateid* stateid) {
  int status;
  struct nfs41_test_stateid_args args = {
      .stateid = stateid,
  };
  struct nfs41_test_stateid_res res;
  struct rpc_message msg = {
      .rpc_proc = &nfs4_procedures[NFSPROC4_CLNT_TEST_STATEID],
      .rpc_argp = &args,
      .rpc_resp = &res,
  };
  dprintk("NFS call  test_stateid %p\n", stateid);
  nfs41_init_sequence(&args.seq_args, &res.seq_res, 0);
  status = nfs4_call_sync_sequence(server->client, server, &msg, &args.seq_args,
                                   &res.seq_res, 1);
  if (status != NFS_OK) {
    dprintk("NFS reply test_stateid: failed, %d\n", status);
    return status;
  }
  dprintk("NFS reply test_stateid: succeeded, %d\n", -res.status);
  return -res.status;
}

iasecc_select_aid(struct sc_card* card, struct sc_aid* aid, unsigned char* out,
                  size_t* out_len) {
  struct sc_apdu apdu;
  unsigned char apdu_resp[SC_MAX_APDU_BUFFER_SIZE];
  int rv;
  LOG_FUNC_CALLED(card->ctx);
  sc_format_apdu(card, &apdu, SC_APDU_CASE_4_SHORT, 0xA4, 0x04, 0x00);
  apdu.lc = aid->len;
  apdu.data = aid->value;
  apdu.datalen = aid->len;
  apdu.resplen = sizeof(apdu_resp);
  apdu.resp = apdu_resp;
  rv = sc_transmit_apdu(card, &apdu);
  LOG_TEST_RET(card->ctx, rv, "APDU transmit failed");
  rv = sc_check_sw(card, apdu.sw1, apdu.sw2);
  LOG_TEST_RET(card->ctx, rv, "Cannot select AID");
  if (*out_len < apdu.resplen)
    LOG_TEST_RET(card->ctx, SC_ERROR_BUFFER_TOO_SMALL, "Cannot select AID");
  memcpy(out, apdu.resp, apdu.resplen);
  LOG_FUNC_RETURN(card->ctx, SC_SUCCESS);
}

PHP_FUNCTION(pg_send_query) {
  zval* pgsql_link;
  char* query;
  int len;
  int id = -1;
  PGconn* pgsql;
  PGresult* res;
  int leftover = 0;
  int ret;
  if (zend_parse_parameters(ZEND_NUM_ARGS() TSRMLS_CC, "rs", &pgsql_link,
                            &query, &len) == FAILURE) {
    return;
  }
  ZEND_FETCH_RESOURCE2(pgsql, PGconn*, &pgsql_link, id, "PostgreSQL link",
                       le_link, le_plink);
  if (PQ_SETNONBLOCKING(pgsql, 1)) {
    php_error_docref(NULL TSRMLS_CC, E_NOTICE,
                     "Cannot set connection to nonblocking mode");
    RETURN_FALSE;
  }
  while ((res = PQgetResult(pgsql))) {
    PQclear(res);
    leftover = 1;
  }
  if (leftover) {
    php_error_docref(NULL TSRMLS_CC, E_NOTICE,
                     "There are results on this connection. Call "
                     "pg_get_result() until it returns FALSE");
  }
  if (!PQsendQuery(pgsql, query)) {
    if ((PGG(auto_reset_persistent) & 2) && PQstatus(pgsql) != CONNECTION_OK) {
      PQreset(pgsql);
    }
    if (!PQsendQuery(pgsql, query)) {
      RETURN_FALSE;
    }
  }
  while ((ret = PQflush(pgsql))) {
    if (ret == -1) {
      php_error_docref(NULL TSRMLS_CC, E_NOTICE,
                       "Could not empty PostgreSQL send buffer");
      break;
    }
    usleep(10000);
  }
  if (PQ_SETNONBLOCKING(pgsql, 0)) {
    php_error_docref(NULL TSRMLS_CC, E_NOTICE,
                     "Cannot set connection to blocking mode");
  }
  RETURN_TRUE;
}

fbFetch_r8g8b8(const FbBits* bits, int x, int width, CARD32* buffer,
               miIndexedPtr indexed) {
  const CARD8* pixel = (const CARD8*)bits + 3 * x;
  const CARD8* end = pixel + 3 * width;
  while (pixel < end) {
    CARD32 b = Fetch24(pixel) | 0xff000000;
    pixel += 3;
    WRITE(buffer++, b);
  }
}

