eb_create(struct drm_i915_gem_execbuffer2* args) {
  struct eb_objects* eb = NULL;
  if (args->flags & I915_EXEC_HANDLE_LUT) {
    int size = args->buffer_count;
    size *= sizeof(struct drm_i915_gem_object*);
    size += sizeof(struct eb_objects);
    eb = kmalloc(size, GFP_TEMPORARY | __GFP_NOWARN | __GFP_NORETRY);
  }
  if (eb == NULL) {
    int size = args->buffer_count;
    int count = PAGE_SIZE / sizeof(struct hlist_head) / 2;
    BUILD_BUG_ON(!is_power_of_2(PAGE_SIZE / sizeof(struct hlist_head)));
    while (count > 2 * size) count >>= 1;
    eb = kzalloc(count * sizeof(struct hlist_head) + sizeof(struct eb_objects),
                 GFP_TEMPORARY);
    if (eb == NULL) return eb;
    eb->and = count - 1;
  } else
    eb->and = -args->buffer_count;
  INIT_LIST_HEAD(&eb->objects);
  return eb;
}

int sched_rt_handler(struct ctl_table* table, int write, void __user* buffer,
                     size_t* lenp, loff_t* ppos) {
  int old_period, old_runtime;
  static DEFINE_MUTEX(mutex);
  int ret;
  mutex_lock(&mutex);
  old_period = sysctl_sched_rt_period;
  old_runtime = sysctl_sched_rt_runtime;
  ret = proc_dointvec(table, write, buffer, lenp, ppos);
  if (!ret && write) {
    ret = sched_rt_global_validate();
    if (ret) goto undo;
    ret = sched_dl_global_validate();
    if (ret) goto undo;
    ret = sched_rt_global_constraints();
    if (ret) goto undo;
    sched_rt_do_global();
    sched_dl_do_global();
  }
  if (0) {
  undo:
    sysctl_sched_rt_period = old_period;
    sysctl_sched_rt_runtime = old_runtime;
  }
  mutex_unlock(&mutex);
  return ret;
}

bool AreAttrValuesEqual(const AttrValue& a, const AttrValue& b,
                        TensorProtosEquality tensor_equality) {
  if (a.type() != b.type()) {
    return false;
  } else if (a.type() != DT_INVALID && b.type() != DT_INVALID) {
    return a.type() == b.type();
  }
  if (a.has_tensor() != b.has_tensor()) {
    return false;
  } else if (a.has_tensor() && b.has_tensor()) {
    return tensor_equality(a.tensor(), b.tensor());
  }
  if (a.has_func() != b.has_func()) {
    return false;
  } else if (a.has_func() && b.has_func()) {
    const NameAttrList& af = a.func();
    const NameAttrList& bf = b.func();
    if (af.name() != bf.name()) return false;
    std::unordered_map<string, AttrValue> am(af.attr().begin(),
                                             af.attr().end());
    for (const auto& bm_pair : bf.attr()) {
      const auto& iter = am.find(bm_pair.first);
      if (iter == am.end()) return false;
      if (!AreAttrValuesEqual(iter->second, bm_pair.second, tensor_equality))
        return false;
      am.erase(iter);
    }
    if (!am.empty()) return false;
    return true;
  }
  return AreSerializedProtosEqual(a, b);
}

void WasmBinaryBuilder::processExpressions() {
  BYN_TRACE("== processExpressions\n");
  unreachableInTheWasmSense = false;
  while (1) {
    Expression* curr;
    auto ret = readExpression(curr);
    if (!curr) {
      lastSeparator = ret;
      BYN_TRACE("== processExpressions finished\n");
      return;
    }
    pushExpression(curr);
    if (curr->type == Type::unreachable) {
      if (pos == endOfFunction) {
        throwError("Reached function end without seeing End opcode");
      }
      if (!more()) {
        throwError("unexpected end of input");
      }
      auto peek = input[pos];
      if (peek == BinaryConsts::End || peek == BinaryConsts::Else ||
          peek == BinaryConsts::Catch || peek == BinaryConsts::CatchAll ||
          peek == BinaryConsts::Delegate) {
        BYN_TRACE("== processExpressions finished with unreachable"
                  << std::endl);
        lastSeparator = BinaryConsts::ASTNodes(peek);
        Expression* dummy = nullptr;
        readExpression(dummy);
        assert(!dummy);
        return;
      } else {
        skipUnreachableCode();
        return;
      }
    }
  }
}

static void pit_load_count(struct kvm* kvm, int channel, u32 val) {
  struct kvm_kpit_state* ps = &kvm->arch.vpit->pit_state;
  WARN_ON(!mutex_is_locked(&ps->lock));
  pr_debug("load_count val is %d, channel is %d\n", val, channel);
  if (val == 0) val = 0x10000;
  ps->channels[channel].count = val;
  if (channel != 0) {
    ps->channels[channel].count_load_time = ktime_get();
    return;
  }
  switch (ps->channels[0].mode) {
    case 0:
    case 1:
    case 4:
      if (!(ps->flags & KVM_PIT_FLAGS_HPET_LEGACY)) {
        create_pit_timer(ps, val, 0);
      }
      break;
    case 2:
    case 3:
      if (!(ps->flags & KVM_PIT_FLAGS_HPET_LEGACY)) {
        create_pit_timer(ps, val, 1);
      }
      break;
    default:
      destroy_pit_timer(&ps->pit_timer);
  }
}

static int xennet_connect(struct net_device* dev) {
  struct netfront_info* np = netdev_priv(dev);
  unsigned int num_queues = 0;
  int err;
  unsigned int j = 0;
  struct netfront_queue* queue = NULL;
  if (!xenbus_read_unsigned(np->xbdev->otherend, "feature-rx-copy", 0)) {
    dev_info(&dev->dev, "backend does not support copying receive path\n");
    return -ENODEV;
  }
  err = talk_to_netback(np->xbdev, np);
  if (err) return err;
  if (np->netback_has_xdp_headroom) pr_info("backend supports XDP headroom\n");
  if (np->bounce)
    dev_info(&np->xbdev->dev, "bouncing transmitted data to zeroed pages\n");
  num_queues = dev->real_num_tx_queues;
  if (dev->reg_state == NETREG_UNINITIALIZED) {
    err = register_netdev(dev);
    if (err) {
      pr_warn("%s: register_netdev err=%d\n", __func__, err);
      device_unregister(&np->xbdev->dev);
      return err;
    }
  }
  rtnl_lock();
  netdev_update_features(dev);
  rtnl_unlock();
  netif_tx_lock_bh(np->netdev);
  netif_device_attach(np->netdev);
  netif_tx_unlock_bh(np->netdev);
  netif_carrier_on(np->netdev);
  for (j = 0; j < num_queues; ++j) {
    queue = &np->queues[j];
    notify_remote_via_irq(queue->tx_irq);
    if (queue->tx_irq != queue->rx_irq) notify_remote_via_irq(queue->rx_irq);
    spin_lock_irq(&queue->tx_lock);
    xennet_tx_buf_gc(queue);
    spin_unlock_irq(&queue->tx_lock);
    spin_lock_bh(&queue->rx_lock);
    xennet_alloc_rx_buffers(queue);
    spin_unlock_bh(&queue->rx_lock);
  }
  return 0;
}

device_drive_benchmark_authorized_cb(Daemon* daemon, Device* device,
                                     DBusGMethodInvocation* context,
                                     const gchar* action_id,
                                     guint num_user_data,
                                     gpointer* user_data_elements) {
  gboolean do_write_benchmark = GPOINTER_TO_INT(user_data_elements[0]);
  gchar** options = user_data_elements[1];
  gchar* argv[16];
  guint n;
  if (!device->priv->device_is_drive) {
    throw_error(context, ERROR_FAILED, "Device is not a drive");
    goto out;
  }
  if (do_write_benchmark) {
    if (device->priv->device_is_partition_table) {
      throw_error(
          context, ERROR_FAILED,
          "A partition table was detected - write benchmarking requires "
          "the disk to be completely empty");
      goto out;
    }
    if (device->priv->id_usage != NULL) {
      throw_error(
          context, ERROR_FAILED,
          "The disk seems to have usage `%s' - write benchmarking requires "
          "the disk to be completely empty",
          device->priv->id_usage);
      goto out;
    }
  }
  for (n = 0; options[n] != NULL; n++) {
    const char* option = options[n];
    throw_error(context, ERROR_INVALID_OPTION, "Unknown option %s", option);
    goto out;
  }
  n = 0;
  argv[n++] = "udisks-helper-drive-benchmark";
  argv[n++] = device->priv->device_file;
  argv[n++] = do_write_benchmark ? "1" : "0";
  argv[n++] = NULL;
  if (!job_new(context, "DriveBenchmark", TRUE, device, argv, NULL,
               drive_benchmark_completed_cb, FALSE, NULL, NULL)) {
    goto out;
  }
out:;
}

