Curl_conncache_extract_bundle(struct Curl_easy* data,
                              struct connectbundle* bundle) {
  struct Curl_llist_element* curr;
  timediff_t highscore = -1;
  timediff_t score;
  struct curltime now;
  struct connectdata* conn_candidate = NULL;
  struct connectdata* conn;
  (void)data;
  now = Curl_now();
  curr = bundle->conn_list.head;
  while (curr) {
    conn = curr->ptr;
    if (!CONN_INUSE(conn)) {
      score = Curl_timediff(now, conn->lastused);
      if (score > highscore) {
        highscore = score;
        conn_candidate = conn;
      }
    }
    curr = curr->next;
  }
  if (conn_candidate) {
    bundle_remove_conn(bundle, conn_candidate);
    data->state.conn_cache->num_conn--;
    DEBUGF(infof(data, "The cache now contains %zu members",
                 data->state.conn_cache->num_conn));
  }
  return conn_candidate;
}

vhost_user_set_vring_num(struct virtio_net* dev, VhostUserMsg* msg) {
  struct vhost_virtqueue* vq = dev->virtqueue[msg->payload.state.index];
  vq->size = msg->payload.state.num;
  if ((vq->size & (vq->size - 1)) || vq->size > 32768) {
    RTE_LOG(ERR, VHOST_CONFIG, "invalid virtqueue size %u\n", vq->size);
    return -1;
  }
  if (dev->dequeue_zero_copy) {
    vq->nr_zmbuf = 0;
    vq->last_zmbuf_idx = 0;
    vq->zmbuf_size = vq->size;
    vq->zmbufs =
        rte_zmalloc(NULL, vq->zmbuf_size * sizeof(struct zcopy_mbuf), 0);
    if (vq->zmbufs == NULL) {
      RTE_LOG(WARNING, VHOST_CONFIG,
              "failed to allocate mem for zero copy; "
              "zero copy is force disabled\n");
      dev->dequeue_zero_copy = 0;
    }
    TAILQ_INIT(&vq->zmbuf_list);
  }
  vq->shadow_used_ring = rte_malloc(
      NULL, vq->size * sizeof(struct vring_used_elem), RTE_CACHE_LINE_SIZE);
  if (!vq->shadow_used_ring) {
    RTE_LOG(ERR, VHOST_CONFIG,
            "failed to allocate memory for shadow used ring.\n");
    return -1;
  }
  vq->batch_copy_elems = rte_malloc(
      NULL, vq->size * sizeof(struct batch_copy_elem), RTE_CACHE_LINE_SIZE);
  if (!vq->batch_copy_elems) {
    RTE_LOG(ERR, VHOST_CONFIG,
            "failed to allocate memory for batching copy.\n");
    return -1;
  }
  return 0;
}

util_curl_unsetopt(CurlObject* self, int option) {
  int res;
#define SETOPT2(o, x) \
  if ((res = curl_easy_setopt(self->handle, (o), (x))) != CURLE_OK) goto error
#define SETOPT(x) SETOPT2((CURLoption)option, (x))
  switch (option) {
    case CURLOPT_SHARE:
      SETOPT((CURLSH*)NULL);
      Py_XDECREF(self->share);
      self->share = NULL;
      break;
    case CURLOPT_HTTPPOST:
      SETOPT((void*)0);
      curl_formfree(self->httppost);
      util_curl_xdecref(self, PYCURL_MEMGROUP_HTTPPOST, self->handle);
      self->httppost = NULL;
      break;
    case CURLOPT_INFILESIZE:
      SETOPT((long)-1);
      break;
    case CURLOPT_WRITEHEADER:
      SETOPT((void*)0);
      Py_CLEAR(self->writeheader_fp);
      break;
    case CURLOPT_CAINFO:
    case CURLOPT_CAPATH:
    case CURLOPT_COOKIE:
    case CURLOPT_COOKIEJAR:
    case CURLOPT_CUSTOMREQUEST:
    case CURLOPT_EGDSOCKET:
    case CURLOPT_FTPPORT:
    case CURLOPT_PROXYUSERPWD:
#ifdef HAVE_CURLOPT_PROXYUSERNAME
    case CURLOPT_PROXYUSERNAME:
    case CURLOPT_PROXYPASSWORD:
#endif
    case CURLOPT_RANDOM_FILE:
    case CURLOPT_SSL_CIPHER_LIST:
    case CURLOPT_USERPWD:
#ifdef HAVE_CURLOPT_USERNAME
    case CURLOPT_USERNAME:
    case CURLOPT_PASSWORD:
#endif
    case CURLOPT_RANGE:
#if LIBCURL_VERSION_NUM >= 0x072b00
    case CURLOPT_SERVICE_NAME:
    case CURLOPT_PROXY_SERVICE_NAME:
#endif
      SETOPT((char*)0);
      break;
#ifdef HAVE_CURLOPT_CERTINFO
    case CURLOPT_CERTINFO:
      SETOPT((long)0);
      break;
#endif
    case CURLOPT_COOKIEFILE:
    default:
      PyErr_SetString(PyExc_TypeError,
                      "unsetopt() is not supported for this option");
      return NULL;
  }
  Py_RETURN_NONE;
error:
  CURLERROR_RETVAL();
#undef SETOPT
#undef SETOPT2
}

do_unimap_ioctl(int cmd, struct unimapdesc __user* user_ud, int perm,
                struct vc_data* vc) {
  struct unimapdesc tmp;
  if (copy_from_user(&tmp, user_ud, sizeof tmp)) return -EFAULT;
  switch (cmd) {
    case PIO_UNIMAP:
      if (!perm) return -EPERM;
      return con_set_unimap(vc, tmp.entry_ct, tmp.entries);
    case GIO_UNIMAP:
      if (!perm && fg_console != vc->vc_num) return -EPERM;
      return con_get_unimap(vc, tmp.entry_ct, &(user_ud->entry_ct),
                            tmp.entries);
  }
  return 0;
}

static const char* typeString(ut32 n, int* bits) {
  *bits = 32;
  if (n == 12) {
    return "arm";
  }
  if (n == 0x0100000c) {
    *bits = 64;
    return "arm";
  }
  if (n == 0x0200000c) {
    *bits = 64;
    return "arm";
  }
  return "x86";
}

static void hash_sock_destruct(struct sock* sk) {
  struct alg_sock* ask = alg_sk(sk);
  struct hash_ctx* ctx = ask->private;
  sock_kfree_s(sk, ctx->result,
               crypto_ahash_digestsize(crypto_ahash_reqtfm(&ctx->req)));
  sock_kfree_s(sk, ctx, ctx->len);
  af_alg_release_parent(sk);
}

static int tipc_add_tlv(struct sk_buff* skb, u16 type, void* data, u16 len) {
  struct tlv_desc* tlv = (struct tlv_desc*)skb_tail_pointer(skb);
  if (tipc_skb_tailroom(skb) < TLV_SPACE(len)) return -EMSGSIZE;
  skb_put(skb, TLV_SPACE(len));
  tlv->tlv_type = htons(type);
  tlv->tlv_len = htons(TLV_LENGTH(len));
  if (len && data) memcpy(TLV_DATA(tlv), data, len);
  return 0;
}

static uint64_t nvme_mmio_read(void* opaque, hwaddr addr, unsigned size) {
  NvmeCtrl* n = (NvmeCtrl*)opaque;
  uint8_t* ptr = (uint8_t*)&n->bar;
  trace_pci_nvme_mmio_read(addr, size);
  if (unlikely(addr & (sizeof(uint32_t) - 1))) {
    NVME_GUEST_ERR(pci_nvme_ub_mmiord_misaligned32,
                   "MMIO read not 32-bit aligned,"
                   " offset=0x%" PRIx64 "",
                   addr);
  } else if (unlikely(size < sizeof(uint32_t))) {
    NVME_GUEST_ERR(pci_nvme_ub_mmiord_toosmall,
                   "MMIO read smaller than 32-bits,"
                   " offset=0x%" PRIx64 "",
                   addr);
  }
  if (addr > sizeof(n->bar) - size) {
    NVME_GUEST_ERR(pci_nvme_ub_mmiord_invalid_ofs,
                   "MMIO read beyond last register,"
                   " offset=0x%" PRIx64 ", returning 0",
                   addr);
    return 0;
  }
  if (addr == NVME_REG_PMRSTS &&
      (NVME_PMRCAP_PMRWBM(ldl_le_p(&n->bar.pmrcap)) & 0x02)) {
    memory_region_msync(&n->pmr.dev->mr, 0, n->pmr.dev->size);
  }
  return ldn_le_p(ptr + addr, size);
}

write_via_header(int fd, orderedmap hashofheaders, unsigned int major,
                 unsigned int minor) {
  char hostname[512];
  char* data;
  int ret;
  if (config->disable_viaheader) {
    ret = 0;
    goto done;
  }
  if (config->via_proxy_name) {
    strlcpy(hostname, config->via_proxy_name, sizeof(hostname));
  } else if (gethostname(hostname, sizeof(hostname)) < 0) {
    strlcpy(hostname, "unknown", 512);
  }
  data = orderedmap_find(hashofheaders, "via");
  if (data) {
    ret = write_message(fd, "Via: %s, %hu.%hu %s (%s/%s)\r\n", data, major,
                        minor, hostname, PACKAGE, VERSION);
    orderedmap_remove(hashofheaders, "via");
  } else {
    ret = write_message(fd, "Via: %hu.%hu %s (%s/%s)\r\n", major, minor,
                        hostname, PACKAGE, VERSION);
  }
done:
  return ret;
}

static inline void decode_eatbits(Encoder* encoder, int len) {
  int delta;
  spice_extra_assert(len > 0 && len < 32);
  encoder->io_word <<= len;
  if ((delta = ((int)encoder->io_available_bits - len)) >= 0) {
    encoder->io_available_bits = delta;
    encoder->io_word |= encoder->io_next_word >> encoder->io_available_bits;
    return;
  }
  delta = -delta;
  encoder->io_word |= encoder->io_next_word << delta;
  read_io_word(encoder);
  encoder->io_available_bits = 32 - delta;
  encoder->io_word |= (encoder->io_next_word >> encoder->io_available_bits);
}

