static CURLcode add_parallel_transfers(struct GlobalConfig* global,
                                       CURLM* multi, CURLSH* share, bool* morep,
                                       bool* addedp) {
  struct per_transfer* per;
  CURLcode result = CURLE_OK;
  CURLMcode mcode;
  bool sleeping = FALSE;
  *addedp = FALSE;
  *morep = FALSE;
  result = create_transfer(global, share, addedp);
  if (result) return result;
  for (per = transfers; per && (all_added < global->parallel_max);
       per = per->next) {
    bool getadded = FALSE;
    if (per->added) continue;
    if (per->startat && (time(NULL) < per->startat)) {
      sleeping = TRUE;
      continue;
    }
    result = pre_transfer(global, per);
    if (result) return result;
    (void)curl_easy_setopt(per->curl, CURLOPT_PIPEWAIT,
                           global->parallel_connect ? 0L : 1L);
    (void)curl_easy_setopt(per->curl, CURLOPT_PRIVATE, per);
    (void)curl_easy_setopt(per->curl, CURLOPT_XFERINFOFUNCTION, xferinfo_cb);
    (void)curl_easy_setopt(per->curl, CURLOPT_XFERINFODATA, per);
    (void)curl_easy_setopt(per->curl, CURLOPT_NOPROGRESS, 0L);
    mcode = curl_multi_add_handle(multi, per->curl);
    if (mcode) return CURLE_OUT_OF_MEMORY;
    result = create_transfer(global, share, &getadded);
    if (result) return result;
    per->added = TRUE;
    all_added++;
    *addedp = TRUE;
  }
  *morep = (per || sleeping) ? TRUE : FALSE;
  return CURLE_OK;
}

jpc_pchglist_t* jpc_pchglist_copy(jpc_pchglist_t* pchglist) {
  jpc_pchglist_t* newpchglist;
  jpc_pchg_t* newpchg;
  int pchgno;
  if (!(newpchglist = jpc_pchglist_create())) {
    return 0;
  }
  for (pchgno = 0; pchgno < pchglist->numpchgs; ++pchgno) {
    if (!(newpchg = jpc_pchg_copy(pchglist->pchgs[pchgno])) ||
        jpc_pchglist_insert(newpchglist, -1, newpchg)) {
      jpc_pchglist_destroy(newpchglist);
      return 0;
    }
  }
  return newpchglist;
}

copy_creds_except(krb5_context context, krb5_ccache incc, krb5_ccache outcc,
                  krb5_principal princ) {
  krb5_error_code ret, ret2;
  krb5_cc_cursor cur;
  krb5_creds creds;
  ret = krb5_cc_set_flags(context, incc, 0);
  if (ret) return ret;
  ret = krb5_cc_start_seq_get(context, incc, &cur);
  if (ret) goto cleanup;
  while (!(ret = krb5_cc_next_cred(context, incc, &cur, &creds))) {
    if (krb5_principal_compare(context, princ, creds.server)) continue;
    ret = krb5_cc_store_cred(context, outcc, &creds);
    krb5_free_cred_contents(context, &creds);
    if (ret) goto cleanup;
  }
  if (ret != KRB5_CC_END) goto cleanup;
  ret = 0;
cleanup:
  ret2 = krb5_cc_set_flags(context, incc, KRB5_TC_OPENCLOSE);
  return (ret == 0) ? ret2 : ret;
}

SMB2_set_info_init(struct cifs_tcon* tcon, struct smb_rqst* rqst,
                   u64 persistent_fid, u64 volatile_fid, u32 pid, u8 info_class,
                   u8 info_type, u32 additional_info, void** data,
                   unsigned int* size) {
  struct smb2_set_info_req* req;
  struct kvec* iov = rqst->rq_iov;
  unsigned int i, total_len;
  int rc;
  rc = smb2_plain_req_init(SMB2_SET_INFO, tcon, (void**)&req, &total_len);
  if (rc) return rc;
  req->sync_hdr.ProcessId = cpu_to_le32(pid);
  req->InfoType = info_type;
  req->FileInfoClass = info_class;
  req->PersistentFileId = persistent_fid;
  req->VolatileFileId = volatile_fid;
  req->AdditionalInformation = cpu_to_le32(additional_info);
  req->BufferOffset = cpu_to_le16(sizeof(struct smb2_set_info_req) - 1);
  req->BufferLength = cpu_to_le32(*size);
  memcpy(req->Buffer, *data, *size);
  total_len += *size;
  iov[0].iov_base = (char*)req;
  iov[0].iov_len = total_len - 1;
  for (i = 1; i < rqst->rq_nvec; i++) {
    le32_add_cpu(&req->BufferLength, size[i]);
    iov[i].iov_base = (char*)data[i];
    iov[i].iov_len = size[i];
  }
  return 0;
}

krb5_decode_krbsecretkey(krb5_context context, krb5_db_entry* entries,
                         struct berval** bvalues,
                         krb5_tl_data* userinfo_tl_data, krb5_kvno* mkvno) {
  char* user = NULL;
  int i = 0, j = 0, noofkeys = 0;
  krb5_key_data *key_data = NULL, *tmp;
  krb5_error_code st = 0;
  if ((st = krb5_unparse_name(context, entries->princ, &user)) != 0)
    goto cleanup;
  for (i = 0; bvalues[i] != NULL; ++i) {
    krb5_int16 n_kd;
    krb5_key_data* kd;
    krb5_data in;
    if (bvalues[i]->bv_len == 0) continue;
    in.length = bvalues[i]->bv_len;
    in.data = bvalues[i]->bv_val;
    st = asn1_decode_sequence_of_keys(&in, &kd, &n_kd, mkvno);
    if (st != 0) {
      const char* msg = error_message(st);
      st = -1;
      krb5_set_error_message(context, st,
                             _("unable to decode stored "
                               "principal key data (%s)"),
                             msg);
      goto cleanup;
    }
    noofkeys += n_kd;
    tmp = key_data;
    key_data = realloc(key_data, (noofkeys + 1) * sizeof(krb5_key_data));
    if (key_data == NULL) {
      key_data = tmp;
      st = ENOMEM;
      goto cleanup;
    }
    for (j = 0; j < n_kd; j++) key_data[noofkeys - n_kd + j] = kd[j];
    free(kd);
  }
  entries->n_key_data = noofkeys;
  entries->key_data = key_data;
cleanup:
  ldap_value_free_len(bvalues);
  free(user);
  return st;
}

