  *read_time_arg = read_time;
  *record_count_arg = record_count;
}

static void ok_inflater_make_huffman_tree_from_array(
    ok_inflater_huffman_tree* tree, const uint8_t* code_length, int length) {
  tree->bits = 1;
  unsigned int code_length_count[MAX_CODE_LENGTH];
  int i;
  for (i = 0; i < MAX_CODE_LENGTH; i++) {
    code_length_count[i] = 0;
  }
  for (i = 0; i < length; i++) {
    code_length_count[code_length[i]]++;
  }
  unsigned int next_code[MAX_CODE_LENGTH];
  unsigned int code = 0;
  for (i = 1; i < MAX_CODE_LENGTH; i++) {
    code = (code + code_length_count[i - 1]) << 1;
    next_code[i] = code;
    if (code_length_count[i] != 0) {
      tree->bits = (unsigned int)i;
    }
  }
  const unsigned int max = 1 << tree->bits;
  memset(tree->lookup_table, 0, sizeof(tree->lookup_table[0]) * max);
  for (i = 0; i < length; i++) {
    unsigned int len = code_length[i];
    if (len != 0) {
      code = next_code[len];
      next_code[len]++;
      unsigned int value = (unsigned int)i | (len << VALUE_BITS);
      tree->lookup_table[ok_inflater_reverse_bits(code, len)] = (uint16_t)value;
    }
  }
  int next_limit = 1;
  int num_bits = 0;
  int mask = 0;
  for (i = 1; i < (int)max; i++) {
    if (i == next_limit) {
      mask = (1 << num_bits) - 1;
      num_bits++;
      next_limit <<= 1;
    }
    if (tree->lookup_table[i] == 0) {
      tree->lookup_table[i] = tree->lookup_table[i & mask];
    }
  }
}

static ssize_t trace_store(struct kmem_cache* s, const char* buf,
                           size_t length) {
  if (s->refcount > 1) return -EINVAL;
  s->flags &= ~SLAB_TRACE;
  if (buf[0] == '1') {
    s->flags &= ~__CMPXCHG_DOUBLE;
    s->flags |= SLAB_TRACE;
  }
  return length;
}

u64 gf_isom_segment_get_fragment_size(GF_ISOFile* file, u32 moof_index,
                                      u32* moof_size) {
#ifndef GPAC_DISABLE_ISOM_FRAGMENTS
  if (!file) return 0;
  u32 moof_sn = 0;
  Bool moof_after_mdat = GF_FALSE;
  u64 size = 0;
  u32 i, count = gf_list_count(file->TopBoxes);
  if (moof_size) *moof_size = 0;
  for (i = 0; i < count; i++) {
    GF_Box* b = gf_list_get(file->TopBoxes, i);
    size += b->size;
    if (b->type == GF_ISOM_BOX_TYPE_MOOF) {
      if (!moof_after_mdat && (moof_sn == moof_index)) return size - b->size;
      if (moof_size) *moof_size = (u32)b->size;
      moof_sn++;
      if (moof_after_mdat && (moof_sn == moof_index)) return size;
      if (moof_after_mdat) size = 0;
      if ((moof_sn > 1) && !moof_after_mdat) size = b->size;
    }
    if (b->type == GF_ISOM_BOX_TYPE_MDAT) {
      if (!moof_sn) moof_after_mdat = GF_TRUE;
    }
  }
  return size;
#endif
  return 0;
}

static NTSTATUS smb_set_file_dosmode(connection_struct* conn,
                                     struct files_struct* fsp,
                                     uint32_t dosmode) {
  struct files_struct* dos_fsp = NULL;
  uint32_t current_dosmode;
  int ret;
  if (!VALID_STAT(fsp->fsp_name->st)) {
    return NT_STATUS_OBJECT_NAME_NOT_FOUND;
  }
  dos_fsp = fsp->base_fsp != NULL ? fsp->base_fsp : fsp;
  if (dosmode != 0) {
    if (S_ISDIR(fsp->fsp_name->st.st_ex_mode)) {
      dosmode |= FILE_ATTRIBUTE_DIRECTORY;
    } else {
      dosmode &= ~FILE_ATTRIBUTE_DIRECTORY;
    }
  }
  DBG_DEBUG("dosmode: 0x%" PRIx32 "\n", dosmode);
  if (dosmode == 0) {
    return NT_STATUS_OK;
  }
  current_dosmode = fdos_mode(dos_fsp);
  if (dosmode == current_dosmode) {
    return NT_STATUS_OK;
  }
  DBG_DEBUG("file %s : setting dos mode 0x%" PRIx32 "\n", fsp_str_dbg(dos_fsp),
            dosmode);
  ret = file_set_dosmode(conn, dos_fsp->fsp_name, dosmode, NULL, false);
  if (ret != 0) {
    DBG_WARNING("file_set_dosmode of %s failed: %s\n", fsp_str_dbg(dos_fsp),
                strerror(errno));
    return map_nt_error_from_unix(errno);
  }
  return NT_STATUS_OK;
}

void zmq::stream_engine_t::plug(io_thread_t* io_thread_,
                                session_base_t* session_) {
  zmq_assert(!plugged);
  plugged = true;
  zmq_assert(!session);
  zmq_assert(session_);
  session = session_;
  socket = session->get_socket();
  io_object_t::plug(io_thread_);
  handle = add_fd(s);
  io_error = false;
  if (options.raw_sock) {
    encoder = new (std::nothrow) raw_encoder_t(out_batch_size);
    alloc_assert(encoder);
    decoder = new (std::nothrow) raw_decoder_t(in_batch_size);
    alloc_assert(decoder);
    handshaking = false;
    next_msg = &stream_engine_t::pull_msg_from_session;
    process_msg = &stream_engine_t::push_msg_to_session;
    msg_t connector;
    connector.init();
    push_msg_to_session(&connector);
    connector.close();
    session->flush();
  } else {
    set_handshake_timer();
    outpos = greeting_send;
    outpos[outsize++] = 0xff;
    put_uint64(&outpos[outsize], options.identity_size + 1);
    outsize += 8;
    outpos[outsize++] = 0x7f;
  }
  set_pollin(handle);
  set_pollout(handle);
  in_event();
}

