      kzalloc(sizeof(struct dce110_resource_pool), GFP_KERNEL);
  if (!pool) return NULL;
  if (construct(num_virtual_links, dc, pool)) return &pool->base;
  kfree(pool);
  BREAK_TO_DEBUGGER();
  return NULL;
}

