static void ieee80211_parse_qos(struct ieee80211_rx_data* rx) {
  struct ieee80211_hdr* hdr = (struct ieee80211_hdr*)rx->skb->data;
  struct ieee80211_rx_status* status = IEEE80211_SKB_RXCB(rx->skb);
  int tid, seqno_idx, security_idx;
  if (ieee80211_is_data_qos(hdr->frame_control)) {
    u8* qc = ieee80211_get_qos_ctl(hdr);
    tid = *qc & IEEE80211_QOS_CTL_TID_MASK;
    if (*qc & IEEE80211_QOS_CTL_A_MSDU_PRESENT)
      status->rx_flags |= IEEE80211_RX_AMSDU;
    seqno_idx = tid;
    security_idx = tid;
  } else {
    seqno_idx = IEEE80211_NUM_TIDS;
    security_idx = 0;
    if (ieee80211_is_mgmt(hdr->frame_control))
      security_idx = IEEE80211_NUM_TIDS;
    tid = 0;
  }
  rx->seqno_idx = seqno_idx;
  rx->security_idx = security_idx;
  rx->skb->priority = (tid > 7) ? 0 : tid;
}

static int recheck_discard_flags(AVFormatContext* s, int first) {
  HLSContext* c = s->priv_data;
  int i, changed = 0;
  for (i = 0; i < c->n_playlists; i++) c->playlists[i]->cur_needed = 0;
  for (i = 0; i < s->nb_streams; i++) {
    AVStream* st = s->streams[i];
    struct playlist* pls = c->playlists[s->streams[i]->id];
    if (st->discard < AVDISCARD_ALL) pls->cur_needed = 1;
  }
  for (i = 0; i < c->n_playlists; i++) {
    struct playlist* pls = c->playlists[i];
    if (pls->cur_needed && !pls->needed) {
      pls->needed = 1;
      changed = 1;
      pls->cur_seq_no = select_cur_seq_no(c, pls);
      pls->pb.eof_reached = 0;
      if (c->cur_timestamp != AV_NOPTS_VALUE) {
        pls->seek_timestamp = c->cur_timestamp;
        pls->seek_flags = AVSEEK_FLAG_ANY;
        pls->seek_stream_index = -1;
      }
      av_log(s, AV_LOG_INFO, "Now receiving playlist %d, segment %d\n", i,
             pls->cur_seq_no);
    } else if (first && !pls->cur_needed && pls->needed) {
      if (pls->input) ffurl_close(pls->input);
      pls->input = NULL;
      pls->needed = 0;
      changed = 1;
      av_log(s, AV_LOG_INFO, "No longer receiving playlist %d\n", i);
    }
  }
  return changed;
}

switchGroup(uid_t uid, const struct passwd* userInfo, gid_t gid) {
  if (userInfo != NULL) {
    bool setgroupsCalled = false;
#if defined(__linux__) || defined(__APPLE__) || defined(__FreeBSD__)
#ifdef __APPLE__
    int groups[1024];
    int ngroups = sizeof(groups) / sizeof(int);
#else
    gid_t groups[1024];
    int ngroups = sizeof(groups) / sizeof(gid_t);
#endif
    boost::scoped_array<gid_t> gidset;
    int ret = getgrouplist(userInfo->pw_name, gid, groups, &ngroups);
    if (ret == -1) {
      int e = errno;
      fprintf(stderr, "ERROR: getgrouplist(%s, %d) failed: %s (errno=%d)\n",
              userInfo->pw_name, (int)gid, strerror(e), e);
      exit(1);
    }
    if (ngroups <= NGROUPS_MAX) {
      setgroupsCalled = true;
      gidset.reset(new gid_t[ngroups]);
      for (int i = 0; i < ngroups; i++) {
        gidset[i] = groups[i];
      }
      if (setgroups(ngroups, gidset.get()) == -1) {
        int e = errno;
        fprintf(stderr, "ERROR: setgroups(%d, ...) failed: %s (errno=%d)\n",
                ngroups, strerror(e), e);
        exit(1);
      }
    }
#endif
    if (!setgroupsCalled && initgroups(userInfo->pw_name, gid) == -1) {
      int e = errno;
      fprintf(stderr, "ERROR: initgroups(%s, %d) failed: %s (errno=%d)\n",
              userInfo->pw_name, (int)gid, strerror(e), e);
      exit(1);
    }
  }
  if (setgid(gid) == -1) {
    int e = errno;
    fprintf(stderr, "ERROR: setgid(%d) failed: %s (errno=%d)\n", (int)gid,
            strerror(e), e);
    exit(1);
  }
}

runlist_element* ntfs_attr_find_vcn(ntfs_attr* na, const VCN vcn) {
  runlist_element* rl;
  BOOL is_retry = FALSE;
  if (!na || !NAttrNonResident(na) || vcn < 0) {
    errno = EINVAL;
    return NULL;
  }
  ntfs_log_trace("Entering for inode 0x%llx, attr 0x%x, vcn %llx\n",
                 (unsigned long long)na->ni->mft_no, le32_to_cpu(na->type),
                 (long long)vcn);
retry:
  rl = na->rl;
  if (!rl) goto map_rl;
  if (vcn < rl[0].vcn) goto map_rl;
  while (rl->length) {
    if (vcn < rl[1].vcn) {
      if (rl->lcn >= (LCN)LCN_HOLE) return rl;
      break;
    }
    rl++;
  }
  switch (rl->lcn) {
    case (LCN)LCN_RL_NOT_MAPPED:
      goto map_rl;
    case (LCN)LCN_ENOENT:
      errno = ENOENT;
      break;
    case (LCN)LCN_EINVAL:
      errno = EINVAL;
      break;
    default:
      errno = EIO;
      break;
  }
  return NULL;
map_rl:
  if (!is_retry && !ntfs_attr_map_runlist(na, vcn)) {
    is_retry = TRUE;
    goto retry;
  }
  if (is_retry || errno == EINVAL || errno == ENOENT) errno = EIO;
  return NULL;
}

smtp_read_response(void* sx0, uschar* buffer, int size, int okdigit,
                   int timeout) {
  smtp_context* sx = sx0;
  uschar* ptr = buffer;
  int count = 0;
  errno = 0;
#ifdef EXPERIMENTAL_PIPE_CONNECT
  if (sx->pending_BANNER || sx->pending_EHLO)
    if (smtp_reap_early_pipe(sx, &count) != OK) {
      DEBUG(D_transport)
      debug_printf("failed reaping pipelined cmd responsess\n");
      return FALSE;
    }
#endif
  for (;;) {
    if ((count = read_response_line(&sx->inblock, ptr, size, timeout)) < 0)
      return FALSE;
    HDEBUG(D_transport | D_acl | D_v)
    debug_printf_indent("  %s %s\n", ptr == buffer ? "SMTP<<" : "      ", ptr);
    if (count < 3 || !isdigit(ptr[0]) || !isdigit(ptr[1]) || !isdigit(ptr[2]) ||
        (ptr[3] != '-' && ptr[3] != ' ' && ptr[3] != 0)) {
      errno = ERRNO_SMTPFORMAT;
      return FALSE;
    }
    if (ptr[3] != '-') break;
    ptr += count;
    *ptr++ = '\n';
    size -= count + 1;
  }
#ifdef TCP_FASTOPEN
  tfo_out_check(sx->cctx.sock);
#endif
  errno = 0;
  return buffer[0] == okdigit;
}

