        av_packet_pack_dictionary(st->metadata, &os->new_metadata_size);
  } else {
    os->new_metadata = av_malloc(1);
    os->new_metadata_size = 0;
  }
  return ret;
}

static inline unsigned short ReadPropertyUnsignedShort(
    const EndianType endian, const unsigned char* buffer) {
  unsigned short value;
  if (endian == LSBEndian) {
    value = (unsigned short)buffer[1] << 8;
    value |= (unsigned short)buffer[0];
    return (value & 0xffff);
  }
  value = (unsigned short)buffer[0] << 8;
  value |= (unsigned short)buffer[1];
  return (value & 0xffff);
}

