static void parse_cmdline(int argc, char** argv, int pass) {
  FILE* rfile;
  char *envreal, *envcopy = NULL, *p;
  int i;
  for (i = 0; i < ERR_WARN_ALL; i++) {
    warning_state_init[i] = warning_state[i] =
        warnings[i].enabled ? WARN_ST_ENABLED : 0;
  }
  envreal = getenv("NASMENV");
  if (envreal) {
    envcopy = nasm_strdup(envreal);
    process_args(envcopy, pass);
    nasm_free(envcopy);
  }
  while (--argc) {
    bool advance;
    argv++;
    if (argv[0][0] == '@') {
      process_response_file(argv[0] + 1, pass);
      argc--;
      argv++;
    }
    if (!stopoptions && argv[0][0] == '-' && argv[0][1] == '@') {
      p = get_param(argv[0], argc > 1 ? argv[1] : NULL, &advance);
      if (p) {
        rfile = nasm_open_read(p, NF_TEXT);
        if (rfile) {
          process_respfile(rfile, pass);
          fclose(rfile);
        } else
          nasm_error(ERR_NONFATAL | ERR_NOFILE | ERR_USAGE,
                     "unable to open response file `%s'", p);
      }
    } else
      advance = process_arg(argv[0], argc > 1 ? argv[1] : NULL, pass);
    argv += advance, argc -= advance;
  }
  if (pass != 2) return;
  if (!inname)
    nasm_fatal(ERR_NOFILE | ERR_USAGE, "no input file specified");
  else if ((errname && !strcmp(inname, errname)) ||
           (outname && !strcmp(inname, outname)) ||
           (listname && !strcmp(inname, listname)) ||
           (depend_file && !strcmp(inname, depend_file)))
    nasm_fatal(ERR_USAGE, "will not overwrite input file");
  if (errname) {
    error_file = nasm_open_write(errname, NF_TEXT);
    if (!error_file) {
      error_file = stderr;
      nasm_fatal(ERR_NOFILE | ERR_USAGE,
                 "cannot open file `%s' for error messages", errname);
    }
  }
}

double Matrix::norm() const {
  double f, g, h, i, j;
  i = m[0] * m[0] + m[1] * m[1];
  j = m[2] * m[2] + m[3] * m[3];
  f = 0.5 * (i + j);
  g = 0.5 * (i - j);
  h = m[0] * m[2] + m[1] * m[3];
  return sqrt(f + hypot(g, h));
}

newVar_N2(char* var, char* var2, char* var3, char* var4, int pop_counter,
          char* final) {
  struct SWF_ACTIONPUSHPARAM* v;
  int psize = PARAM_STRSIZE;
  int i;
  int slen =
      strlen(var) + strlen(var2) + strlen(var3) + strlen(var4) + strlen(final);
  v = malloc(sizeof(struct SWF_ACTIONPUSHPARAM));
  v->p.String = malloc(psize + slen);
  v->Type = PUSH_VARIABLE;
  strcpy(v->p.String, var);
  strcat(v->p.String, var2);
  strcat(v->p.String, var3);
  strcat(v->p.String, var4);
  for (i = 0; i < pop_counter; i++) {
    char* pops1 = getString(pop());
    char* pops2 = getName(pop());
    while (strlen(v->p.String) + 3 + strlen(pops1) + strlen(pops2) + slen >=
           psize) {
      psize += PARAM_STRSIZE;
      v->p.String = realloc(v->p.String, psize);
    }
    strcat(v->p.String, pops2);
    strcat(v->p.String, ":");
    strcat(v->p.String, pops1);
    if (i < pop_counter - 1) strcat(v->p.String, ",");
  }
  strcat(v->p.String, final);
  return v;
}

