cdf_read_short_sector(const cdf_stream_t* sst, void* buf, size_t offs,
                      size_t len, const cdf_header_t* h, cdf_secid_t id) {
  size_t ss = CDF_SHORT_SEC_SIZE(h);
  size_t pos = CDF_SHORT_SEC_POS(h, id);
  assert(ss == len);
  if (pos + len > CDF_SEC_SIZE(h) * sst->sst_len) {
    DPRINTF(("Out of bounds read %" SIZE_T_FORMAT "u > %" SIZE_T_FORMAT "u\n",
             pos + len, CDF_SEC_SIZE(h) * sst->sst_len));
    goto out;
  }
  (void)memcpy(((char*)buf) + offs, ((const char*)sst->sst_tab) + pos, len);
  return len;
out:
  errno = EFTYPE;
  return -1;
}

int bnx2x_acquire_hw_lock(struct bnx2x* bp, u32 resource) {
  u32 lock_status;
  u32 resource_bit = (1 << resource);
  int func = BP_FUNC(bp);
  u32 hw_lock_control_reg;
  int cnt;
  if (resource > HW_LOCK_MAX_RESOURCE_VALUE) {
    BNX2X_ERR("resource(0x%x) > HW_LOCK_MAX_RESOURCE_VALUE(0x%x)\n", resource,
              HW_LOCK_MAX_RESOURCE_VALUE);
    return -EINVAL;
  }
  if (func <= 5) {
    hw_lock_control_reg = (MISC_REG_DRIVER_CONTROL_1 + func * 8);
  } else {
    hw_lock_control_reg = (MISC_REG_DRIVER_CONTROL_7 + (func - 6) * 8);
  }
  lock_status = REG_RD(bp, hw_lock_control_reg);
  if (lock_status & resource_bit) {
    BNX2X_ERR("lock_status 0x%x  resource_bit 0x%x\n", lock_status,
              resource_bit);
    return -EEXIST;
  }
  for (cnt = 0; cnt < 1000; cnt++) {
    REG_WR(bp, hw_lock_control_reg + 4, resource_bit);
    lock_status = REG_RD(bp, hw_lock_control_reg);
    if (lock_status & resource_bit) return 0;
    usleep_range(5000, 10000);
  }
  BNX2X_ERR("Timeout\n");
  return -EAGAIN;
}

static bool lru_maintainer_bumps(void) {
  lru_bump_buf* b;
  lru_bump_entry* be;
  unsigned int size;
  unsigned int todo;
  bool bumped = false;
  pthread_mutex_lock(&bump_buf_lock);
  for (b = bump_buf_head; b != NULL; b = b->next) {
    pthread_mutex_lock(&b->mutex);
    be = (lru_bump_entry*)bipbuf_peek_all(b->buf, &size);
    pthread_mutex_unlock(&b->mutex);
    if (be == NULL) {
      continue;
    }
    todo = size;
    bumped = true;
    while (todo) {
      item_lock(be->hv);
      do_item_update(be->it);
      do_item_remove(be->it);
      item_unlock(be->hv);
      be++;
      todo -= sizeof(lru_bump_entry);
    }
    pthread_mutex_lock(&b->mutex);
    be = (lru_bump_entry*)bipbuf_poll(b->buf, size);
    pthread_mutex_unlock(&b->mutex);
  }
  pthread_mutex_unlock(&bump_buf_lock);
  return bumped;
}

static bool rb_per_cpu_empty(struct ring_buffer_per_cpu* cpu_buffer) {
  struct buffer_page* reader = cpu_buffer->reader_page;
  struct buffer_page* head = rb_set_head_page(cpu_buffer);
  struct buffer_page* commit = cpu_buffer->commit_page;
  if (unlikely(!head)) return true;
  return reader->read == rb_page_commit(reader) &&
         (commit == reader ||
          (commit == head && head->read == rb_page_commit(commit)));
}

