static void tcp_process_loss(struct sock* sk, int flag, bool is_dupack,
                             int* rexmit) {
  struct tcp_sock* tp = tcp_sk(sk);
  bool recovered = !before(tp->snd_una, tp->high_seq);
  if ((flag & FLAG_SND_UNA_ADVANCED) && tcp_try_undo_loss(sk, false)) return;
  if (tp->frto) {
    if ((flag & FLAG_ORIG_SACK_ACKED) && tcp_try_undo_loss(sk, true)) return;
    if (after(tp->snd_nxt, tp->high_seq)) {
      if (flag & FLAG_DATA_SACKED || is_dupack) tp->frto = 0;
    } else if (flag & FLAG_SND_UNA_ADVANCED && !recovered) {
      tp->high_seq = tp->snd_nxt;
      if (tcp_send_head(sk) && after(tcp_wnd_end(tp), tp->snd_nxt)) {
        *rexmit = REXMIT_NEW;
        return;
      }
      tp->frto = 0;
    }
  }
  if (recovered) {
    tcp_try_undo_recovery(sk);
    return;
  }
  if (tcp_is_reno(tp)) {
    if (after(tp->snd_nxt, tp->high_seq) && is_dupack)
      tcp_add_reno_sack(sk);
    else if (flag & FLAG_SND_UNA_ADVANCED)
      tcp_reset_reno_sack(tp);
  }
  *rexmit = REXMIT_LOST;
}

static int ppp_unattached_ioctl(struct net* net, struct ppp_file* pf,
                                struct file* file, unsigned int cmd,
                                unsigned long arg) {
  int unit, err = -EFAULT;
  struct ppp* ppp;
  struct channel* chan;
  struct ppp_net* pn;
  int __user* p = (int __user*)arg;
  mutex_lock(&ppp_mutex);
  switch (cmd) {
    case PPPIOCNEWUNIT:
      if (get_user(unit, p)) break;
      ppp = ppp_create_interface(net, unit, file, &err);
      if (!ppp) break;
      file->private_data = &ppp->file;
      err = -EFAULT;
      if (put_user(ppp->file.index, p)) break;
      err = 0;
      break;
    case PPPIOCATTACH:
      if (get_user(unit, p)) break;
      err = -ENXIO;
      pn = ppp_pernet(net);
      mutex_lock(&pn->all_ppp_mutex);
      ppp = ppp_find_unit(pn, unit);
      if (ppp) {
        atomic_inc(&ppp->file.refcnt);
        file->private_data = &ppp->file;
        err = 0;
      }
      mutex_unlock(&pn->all_ppp_mutex);
      break;
    case PPPIOCATTCHAN:
      if (get_user(unit, p)) break;
      err = -ENXIO;
      pn = ppp_pernet(net);
      spin_lock_bh(&pn->all_channels_lock);
      chan = ppp_find_channel(pn, unit);
      if (chan) {
        atomic_inc(&chan->file.refcnt);
        file->private_data = &chan->file;
        err = 0;
      }
      spin_unlock_bh(&pn->all_channels_lock);
      break;
    default:
      err = -ENOTTY;
  }
  mutex_unlock(&ppp_mutex);
  return err;
}

xmlParsePITarget(xmlParserCtxtPtr ctxt) {
  const xmlChar* name;
  name = xmlParseName(ctxt);
  if ((name != NULL) && ((name[0] == 'x') || (name[0] == 'X')) &&
      ((name[1] == 'm') || (name[1] == 'M')) &&
      ((name[2] == 'l') || (name[2] == 'L'))) {
    int i;
    if ((name[0] == 'x') && (name[1] == 'm') && (name[2] == 'l') &&
        (name[3] == 0)) {
      xmlFatalErrMsg(
          ctxt, XML_ERR_RESERVED_XML_NAME,
          "XML declaration allowed only at the start of the document\n");
      return (name);
    } else if (name[3] == 0) {
      xmlFatalErr(ctxt, XML_ERR_RESERVED_XML_NAME, NULL);
      return (name);
    }
    for (i = 0;; i++) {
      if (xmlW3CPIs[i] == NULL) break;
      if (xmlStrEqual(name, (const xmlChar*)xmlW3CPIs[i])) return (name);
    }
    xmlWarningMsg(ctxt, XML_ERR_RESERVED_XML_NAME,
                  "xmlParsePITarget: invalid name prefix 'xml'\n", NULL, NULL);
  }
  if ((name != NULL) && (xmlStrchr(name, ':') != NULL)) {
    xmlNsErr(ctxt, XML_NS_ERR_COLON,
             "colons are forbidden from PI names '%s'\n", name, NULL, NULL);
  }
  return (name);
}

void WasmBinaryBuilder::visitLoop(Loop* curr) {
  BYN_TRACE("zz node: Loop\n");
  startControlFlow(curr);
  curr->type = getType();
  curr->name = getNextLabel();
  breakStack.push_back({curr->name, Type::none});
  auto start = expressionStack.size();
  processExpressions();
  size_t end = expressionStack.size();
  if (start > end) {
    throwError("block cannot pop from outside");
  }
  if (end - start == 1) {
    curr->body = popExpression();
  } else {
    auto* block = allocator.alloc<Block>();
    pushBlockElements(block, curr->type, start);
    block->finalize(curr->type);
    curr->body = block;
  }
  breakStack.pop_back();
  breakTargetNames.erase(curr->name);
  curr->finalize(curr->type);
}

static sctp_disposition_t sctp_sf_violation_paramlen(
    struct net* net, const struct sctp_endpoint* ep,
    const struct sctp_association* asoc, const sctp_subtype_t type, void* arg,
    void* ext, sctp_cmd_seq_t* commands) {
  struct sctp_chunk* chunk = arg;
  struct sctp_paramhdr* param = ext;
  struct sctp_chunk* abort = NULL;
  if (sctp_auth_recv_cid(SCTP_CID_ABORT, asoc)) goto discard;
  abort = sctp_make_violation_paramlen(asoc, chunk, param);
  if (!abort) goto nomem;
  sctp_add_cmd_sf(commands, SCTP_CMD_REPLY, SCTP_CHUNK(abort));
  SCTP_INC_STATS(net, SCTP_MIB_OUTCTRLCHUNKS);
  sctp_add_cmd_sf(commands, SCTP_CMD_SET_SK_ERR, SCTP_ERROR(ECONNABORTED));
  sctp_add_cmd_sf(commands, SCTP_CMD_ASSOC_FAILED,
                  SCTP_PERR(SCTP_ERROR_PROTO_VIOLATION));
  SCTP_DEC_STATS(net, SCTP_MIB_CURRESTAB);
  SCTP_INC_STATS(net, SCTP_MIB_ABORTEDS);
discard:
  sctp_sf_pdiscard(net, ep, asoc, SCTP_ST_CHUNK(0), arg, commands);
  return SCTP_DISPOSITION_ABORT;
nomem:
  return SCTP_DISPOSITION_NOMEM;
}

