void module_destructor(zend_module_entry* module) {
  TSRMLS_FETCH();
  if (module->type == MODULE_TEMPORARY) {
    zend_clean_module_rsrc_dtors(module->module_number TSRMLS_CC);
    clean_module_constants(module->module_number TSRMLS_CC);
    clean_module_classes(module->module_number TSRMLS_CC);
  }
  if (module->module_started && module->module_shutdown_func) {
#if 0
		zend_printf("%s: Module shutdown\n", module->name);
#endif
    module->module_shutdown_func(module->type, module->module_number TSRMLS_CC);
  }
  if (module->globals_size) {
#ifdef ZTS
    if (*module->globals_id_ptr) {
      ts_free_id(*module->globals_id_ptr);
    }
#else
    if (module->globals_dtor) {
      module->globals_dtor(module->globals_ptr TSRMLS_CC);
    }
#endif
  }
  module->module_started = 0;
  if (module->functions) {
    zend_unregister_functions(module->functions, -1, NULL TSRMLS_CC);
  }
#if HAVE_LIBDL
#if !(defined(NETWARE) && defined(APACHE_1_BUILD))
  if (module->handle && !getenv("ZEND_DONT_UNLOAD_MODULES")) {
    DL_UNLOAD(module->handle);
  }
#endif
#endif
}

TfLiteStatus Eval(TfLiteContext* context, TfLiteNode* node) {
  auto* params = reinterpret_cast<TfLiteDivParams*>(node->builtin_data);
  OpData* data = reinterpret_cast<OpData*>(node->user_data);
  const TfLiteTensor* input1;
  TF_LITE_ENSURE_OK(context,
                    GetInputSafe(context, node, kInputTensor1, &input1));
  const TfLiteTensor* input2;
  TF_LITE_ENSURE_OK(context,
                    GetInputSafe(context, node, kInputTensor2, &input2));
  TfLiteTensor* output;
  TF_LITE_ENSURE_OK(context,
                    GetOutputSafe(context, node, kOutputTensor, &output));
#define TF_LITE_CHECK_DIV_NON_ZERO(data_type)                       \
  const auto* input2_data = GetTensorData<data_type>(input2);       \
  const size_t input2_elements = input2->bytes / sizeof(data_type); \
  for (size_t i = 0; i < input2_elements; i++) {                    \
    TF_LITE_ENSURE(context, input2_data[i] != 0);                   \
  }
  if (output->type == kTfLiteFloat32) {
    EvalDiv<kernel_type>(context, node, params, data, input1, input2, output);
  } else if (output->type == kTfLiteInt32) {
    TF_LITE_CHECK_DIV_NON_ZERO(int32_t);
    EvalDiv<kernel_type>(context, node, params, data, input1, input2, output);
  } else if (output->type == kTfLiteUInt8) {
    TF_LITE_CHECK_DIV_NON_ZERO(uint8_t);
    TF_LITE_ENSURE_OK(
        context, EvalQuantized<kernel_type>(context, node, params, data, input1,
                                            input2, output));
  } else {
    context->ReportError(
        context,
        "Div only supports FLOAT32, INT32 and quantized UINT8 now, got %d.",
        output->type);
    return kTfLiteError;
  }
#undef TF_LITE_CHECK_DIV_NON_ZERO
  return kTfLiteOk;
}

static struct nfs4_state* nfs4_do_open(struct inode* dir, struct dentry* dentry,
                                       fmode_t fmode, int flags,
                                       struct iattr* sattr,
                                       struct rpc_cred* cred,
                                       struct nfs4_threshold** ctx_th) {
  struct nfs4_exception exception = {};
  struct nfs4_state* res;
  int status;
  fmode &= FMODE_READ | FMODE_WRITE | FMODE_EXEC;
  do {
    status =
        _nfs4_do_open(dir, dentry, fmode, flags, sattr, cred, &res, ctx_th);
    if (status == 0) break;
    if (status == -NFS4ERR_BAD_SEQID) {
      pr_warn_ratelimited(
          "NFS: v4 server %s "
          " returned a bad sequence-id error!\n",
          NFS_SERVER(dir)->nfs_client->cl_hostname);
      exception.retry = 1;
      continue;
    }
    if (status == -NFS4ERR_BAD_STATEID) {
      exception.retry = 1;
      continue;
    }
    if (status == -EAGAIN) {
      exception.retry = 1;
      continue;
    }
    res = ERR_PTR(nfs4_handle_exception(NFS_SERVER(dir), status, &exception));
  } while (exception.retry);
  return res;
}

void S_AL_StartBackgroundTrack(const char* intro, const char* loop) {
  int i;
  qboolean issame;
  S_AL_StopBackgroundTrack();
  if ((!intro || !*intro) && (!loop || !*loop)) return;
  S_AL_MusicSourceGet();
  if (musicSourceHandle == -1) return;
  if (!loop || !*loop) {
    loop = intro;
    issame = qtrue;
  } else if (intro && *intro && !strcmp(intro, loop))
    issame = qtrue;
  else
    issame = qfalse;
  Q_strncpyz(s_backgroundLoop, loop, sizeof(s_backgroundLoop));
  if (!issame) {
    intro_stream = S_CodecOpenStream(intro);
  } else
    intro_stream = NULL;
  mus_stream = S_CodecOpenStream(s_backgroundLoop);
  if (!mus_stream) {
    S_AL_CloseMusicFiles();
    S_AL_MusicSourceFree();
    return;
  }
  if (!S_AL_GenBuffers(NUM_MUSIC_BUFFERS, musicBuffers, "music")) return;
  for (i = 0; i < NUM_MUSIC_BUFFERS; i++) {
    S_AL_MusicProcess(musicBuffers[i]);
  }
  qalSourceQueueBuffers(musicSource, NUM_MUSIC_BUFFERS, musicBuffers);
  S_AL_Gain(musicSource, s_alGain->value * s_musicVolume->value);
  qalSourcePlay(musicSource);
  musicPlaying = qtrue;
}

void CLASS lossless_dng_load_raw() {
  unsigned save, trow = 0, tcol = 0, jwide, jrow, jcol, row, col;
  struct jhead jh;
  ushort* rp;
  while (trow < raw_height) {
#ifdef LIBRAW_LIBRARY_BUILD
    checkCancel();
#endif
    save = ftell(ifp);
    if (tile_length < INT_MAX) fseek(ifp, get4(), SEEK_SET);
    if (!ljpeg_start(&jh, 0)) break;
    jwide = jh.wide;
    if (filters) jwide *= jh.clrs;
    jwide /= is_raw;
#ifdef LIBRAW_LIBRARY_BUILD
    try {
#endif
      for (row = col = jrow = 0; jrow < jh.high; jrow++) {
#ifdef LIBRAW_LIBRARY_BUILD
        checkCancel();
#endif
        rp = ljpeg_row(jrow, &jh);
        for (jcol = 0; jcol < jwide; jcol++) {
          adobe_copy_pixel(trow + row, tcol + col, &rp);
          if (++col >= tile_width || col >= raw_width) row += 1 + (col = 0);
        }
      }
#ifdef LIBRAW_LIBRARY_BUILD
    } catch (...) {
      ljpeg_end(&jh);
      throw;
    }
#endif
    fseek(ifp, save + 4, SEEK_SET);
    if ((tcol += tile_width) >= raw_width) trow += tile_length + (tcol = 0);
    ljpeg_end(&jh);
  }
}

static void vmx_vcpu_load(struct kvm_vcpu* vcpu, int cpu) {
  struct vcpu_vmx* vmx = to_vmx(vcpu);
  bool already_loaded = vmx->loaded_vmcs->cpu == cpu;
  if (!already_loaded) {
    loaded_vmcs_clear(vmx->loaded_vmcs);
    local_irq_disable();
    crash_disable_local_vmclear(cpu);
    smp_rmb();
    list_add(&vmx->loaded_vmcs->loaded_vmcss_on_cpu_link,
             &per_cpu(loaded_vmcss_on_cpu, cpu));
    crash_enable_local_vmclear(cpu);
    local_irq_enable();
  }
  if (per_cpu(current_vmcs, cpu) != vmx->loaded_vmcs->vmcs) {
    per_cpu(current_vmcs, cpu) = vmx->loaded_vmcs->vmcs;
    vmcs_load(vmx->loaded_vmcs->vmcs);
  }
  if (!already_loaded) {
    void* gdt = get_current_gdt_ro();
    unsigned long sysenter_esp;
    kvm_make_request(KVM_REQ_TLB_FLUSH, vcpu);
    vmcs_writel(HOST_TR_BASE, (unsigned long)this_cpu_ptr(&cpu_tss));
    vmcs_writel(HOST_GDTR_BASE, (unsigned long)gdt);
    BUILD_BUG_ON(IO_BITMAP_OFFSET - 1 != 0x67);
    rdmsrl(MSR_IA32_SYSENTER_ESP, sysenter_esp);
    vmcs_writel(HOST_IA32_SYSENTER_ESP, sysenter_esp);
    vmx->loaded_vmcs->cpu = cpu;
  }
  if (kvm_has_tsc_control &&
      vmx->current_tsc_ratio != vcpu->arch.tsc_scaling_ratio)
    decache_tsc_multiplier(vmx);
  vmx_vcpu_pi_load(vcpu, cpu);
  vmx->host_pkru = read_pkru();
}

int ntfs_attr_map_runlist(ntfs_attr* na, VCN vcn) {
  LCN lcn;
  ntfs_attr_search_ctx* ctx;
  ntfs_log_trace("Entering for inode 0x%llx, attr 0x%x, vcn 0x%llx.\n",
                 (unsigned long long)na->ni->mft_no, le32_to_cpu(na->type),
                 (long long)vcn);
  lcn = ntfs_rl_vcn_to_lcn(na->rl, vcn);
  if (lcn >= 0 || lcn == LCN_HOLE || lcn == LCN_ENOENT) return 0;
  ctx = ntfs_attr_get_search_ctx(na->ni, NULL);
  if (!ctx) return -1;
  if (!ntfs_attr_lookup(na->type, na->name, na->name_len, CASE_SENSITIVE, vcn,
                        NULL, 0, ctx)) {
    runlist_element* rl;
    rl = ntfs_mapping_pairs_decompress(na->ni->vol, ctx->attr, na->rl);
    if (rl) {
      na->rl = rl;
      ntfs_attr_put_search_ctx(ctx);
      return 0;
    }
  }
  ntfs_attr_put_search_ctx(ctx);
  return -1;
}

