static void update_cr0_intercept(struct vcpu_svm* svm) {
  ulong gcr0 = svm->vcpu.arch.cr0;
  u64* hcr0 = &svm->vmcb->save.cr0;
  if (!svm->vcpu.fpu_active)
    *hcr0 |= SVM_CR0_SELECTIVE_MASK;
  else
    *hcr0 = (*hcr0 & ~SVM_CR0_SELECTIVE_MASK) | (gcr0 & SVM_CR0_SELECTIVE_MASK);
  mark_dirty(svm->vmcb, VMCB_CR);
  if (gcr0 == *hcr0 && svm->vcpu.fpu_active) {
    clr_cr_intercept(svm, INTERCEPT_CR0_READ);
    clr_cr_intercept(svm, INTERCEPT_CR0_WRITE);
  } else {
    set_cr_intercept(svm, INTERCEPT_CR0_READ);
    set_cr_intercept(svm, INTERCEPT_CR0_WRITE);
  }
}

static WERROR dcesrv_DnssrvOperation(struct dcesrv_call_state* dce_call,
                                     TALLOC_CTX* mem_ctx,
                                     struct DnssrvOperation* r) {
  struct dnsserver_state* dsstate;
  struct dnsserver_zone* z = NULL;
  uint32_t request_filter = 0;
  WERROR ret;
  if ((dsstate = dnsserver_connect(dce_call)) == NULL) {
    return WERR_DNS_ERROR_DS_UNAVAILABLE;
  }
  if (r->in.dwContext == 0) {
    if (r->in.pszZone != NULL) {
      request_filter = dnsserver_zone_to_request_filter(r->in.pszZone);
    }
  } else {
    request_filter = r->in.dwContext;
  }
  if (r->in.pszZone == NULL) {
    ret = dnsserver_operate_server(dsstate, mem_ctx, r->in.pszOperation,
                                   DNS_CLIENT_VERSION_W2K, r->in.dwTypeId,
                                   &r->in.pData);
  } else {
    z = dnsserver_find_zone(dsstate->zones, r->in.pszZone);
    if (z == NULL) {
      return WERR_DNS_ERROR_ZONE_DOES_NOT_EXIST;
    }
    ret = dnsserver_operate_zone(dsstate, mem_ctx, z, request_filter,
                                 r->in.pszOperation, DNS_CLIENT_VERSION_W2K,
                                 r->in.dwTypeId, &r->in.pData);
  }
  if (W_ERROR_EQUAL(ret, WERR_CALL_NOT_IMPLEMENTED)) {
    NDR_PRINT_FUNCTION_DEBUG(DnssrvOperation, NDR_IN, r);
  }
  return ret;
}

static int sco_conn_del(struct hci_conn* hcon, int err) {
  struct sco_conn* conn = hcon->sco_data;
  struct sock* sk;
  if (!conn) return 0;
  BT_DBG("hcon %p conn %p, err %d", hcon, conn, err);
  sk = sco_chan_get(conn);
  if (sk) {
    bh_lock_sock(sk);
    sco_sock_clear_timer(sk);
    sco_chan_del(sk, err);
    bh_unlock_sock(sk);
    sco_sock_kill(sk);
  }
  hcon->sco_data = NULL;
  kfree(conn);
  return 0;
}

