static int ehci_qh_do_overlay(EHCIQueue* q) {
  EHCIPacket* p = QTAILQ_FIRST(&q->packets);
  int i;
  int dtoggle;
  int ping;
  int eps;
  int reload;
  assert(p != NULL);
  assert(p->qtdaddr == q->qtdaddr);
  dtoggle = q->qh.token & QTD_TOKEN_DTOGGLE;
  ping = q->qh.token & QTD_TOKEN_PING;
  q->qh.current_qtd = p->qtdaddr;
  q->qh.next_qtd = p->qtd.next;
  q->qh.altnext_qtd = p->qtd.altnext;
  q->qh.token = p->qtd.token;
  eps = get_field(q->qh.epchar, QH_EPCHAR_EPS);
  if (eps == EHCI_QH_EPS_HIGH) {
    q->qh.token &= ~QTD_TOKEN_PING;
    q->qh.token |= ping;
  }
  reload = get_field(q->qh.epchar, QH_EPCHAR_RL);
  set_field(&q->qh.altnext_qtd, reload, QH_ALTNEXT_NAKCNT);
  for (i = 0; i < 5; i++) {
    q->qh.bufptr[i] = p->qtd.bufptr[i];
  }
  if (!(q->qh.epchar & QH_EPCHAR_DTC)) {
    q->qh.token &= ~QTD_TOKEN_DTOGGLE;
    q->qh.token |= dtoggle;
  }
  q->qh.bufptr[1] &= ~BUFPTR_CPROGMASK_MASK;
  q->qh.bufptr[2] &= ~BUFPTR_FRAMETAG_MASK;
  ehci_flush_qh(q);
  return 0;
}

static void log_backtrace(const request_rec* r) {
  const request_rec* top = r;
  ap_log_rerror(APLOG_MARK, APLOG_DEBUG, 0, r, APLOGNO(00121) "r->uri = %s",
                r->uri ? r->uri : "(unexpectedly NULL)");
  while (top && (top->prev || top->main)) {
    if (top->prev) {
      top = top->prev;
      ap_log_rerror(APLOG_MARK, APLOG_DEBUG, 0, r,
                    APLOGNO(00122) "redirected from r->uri = %s",
                    top->uri ? top->uri : "(unexpectedly NULL)");
    }
    if (!top->prev && top->main) {
      top = top->main;
      ap_log_rerror(APLOG_MARK, APLOG_DEBUG, 0, r,
                    APLOGNO(00123) "subrequested from r->uri = %s",
                    top->uri ? top->uri : "(unexpectedly NULL)");
    }
  }
}

int btrfs_run_dev_stats(struct btrfs_trans_handle* trans,
                        struct btrfs_fs_info* fs_info) {
  struct btrfs_fs_devices* fs_devices = fs_info->fs_devices;
  struct btrfs_device* device;
  int stats_cnt;
  int ret = 0;
  mutex_lock(&fs_devices->device_list_mutex);
  list_for_each_entry(device, &fs_devices->devices, dev_list) {
    stats_cnt = atomic_read(&device->dev_stats_ccnt);
    if (!device->dev_stats_valid || stats_cnt == 0) continue;
    smp_rmb();
    ret = update_dev_stat_item(trans, device);
    if (!ret) atomic_sub(stats_cnt, &device->dev_stats_ccnt);
  }
  mutex_unlock(&fs_devices->device_list_mutex);
  return ret;
}

void optimize_keyuse(JOIN* join, DYNAMIC_ARRAY* keyuse_array) {
  KEYUSE *end, *keyuse = dynamic_element(keyuse_array, 0, KEYUSE*);
  for (end = keyuse + keyuse_array->elements; keyuse < end; keyuse++) {
    table_map map;
    keyuse->ref_table_rows = ~(ha_rows)0;
    if (keyuse->used_tables &
        (map = (keyuse->used_tables & ~join->const_table_map &
                ~OUTER_REF_TABLE_BIT))) {
      uint n_tables = my_count_bits(map);
      if (n_tables == 1) {
        DBUG_ASSERT(!(map & PSEUDO_TABLE_BITS));
        Table_map_iterator it(map);
        int tablenr = it.next_bit();
        DBUG_ASSERT(tablenr != Table_map_iterator::BITMAP_END);
        TABLE* tmp_table = join->table[tablenr];
        if (tmp_table)
          keyuse->ref_table_rows = MY_MAX(tmp_table->file->stats.records, 100);
      }
    }
    if (keyuse->used_tables == OUTER_REF_TABLE_BIT) keyuse->ref_table_rows = 1;
  }
}

