write_xauth(char* number, FILE* output) {
  Xauth *xa, local_xa;
  char* filename;
  FILE* f;
  struct utsname unames;
  if (uname(&unames)) {
    g_warning("uname failed");
    return;
  }
  filename = XauFileName();
  f = fopen(filename, "rb");
  if (f == NULL) return;
  while (TRUE) {
    xa = XauReadAuth(f);
    if (xa == NULL) break;
    if (xauth_entry_should_propagate(xa, unames.nodename, number)) {
      local_xa = *xa;
      if (local_xa.number) {
        local_xa.number = "99";
        local_xa.number_length = 2;
      }
      if (local_xa.family == FamilyLocal &&
          !auth_streq(unames.nodename, local_xa.address,
                      local_xa.address_length)) {
        local_xa.address = unames.nodename;
        local_xa.address_length = strlen(local_xa.address);
      }
      if (!XauWriteAuth(output, &local_xa)) g_warning("xauth write error");
    }
    XauDisposeAuth(xa);
  }
  fclose(f);
}

__releases(&files->file_lock) {
  struct file* tofree;
  struct fdtable* fdt;
  fdt = files_fdtable(files);
  tofree = fdt->fd[fd];
  if (!tofree && fd_is_open(fd, fdt)) goto Ebusy;
  get_file(file);
  rcu_assign_pointer(fdt->fd[fd], file);
  __set_open_fd(fd, fdt);
  if (flags & O_CLOEXEC)
    __set_close_on_exec(fd, fdt);
  else
    __clear_close_on_exec(fd, fdt);
  spin_unlock(&files->file_lock);
  if (tofree) filp_close(tofree, files);
  return fd;
Ebusy:
  spin_unlock(&files->file_lock);
  return -EBUSY;
}

