static void scalar32_min_max_add(struct bpf_reg_state* dst_reg,
                                 struct bpf_reg_state* src_reg) {
  s32 smin_val = src_reg->s32_min_value;
  s32 smax_val = src_reg->s32_max_value;
  u32 umin_val = src_reg->u32_min_value;
  u32 umax_val = src_reg->u32_max_value;
  if (signed_add32_overflows(dst_reg->s32_min_value, smin_val) ||
      signed_add32_overflows(dst_reg->s32_max_value, smax_val)) {
    dst_reg->s32_min_value = S32_MIN;
    dst_reg->s32_max_value = S32_MAX;
  } else {
    dst_reg->s32_min_value += smin_val;
    dst_reg->s32_max_value += smax_val;
  }
  if (dst_reg->u32_min_value + umin_val < umin_val ||
      dst_reg->u32_max_value + umax_val < umax_val) {
    dst_reg->u32_min_value = 0;
    dst_reg->u32_max_value = U32_MAX;
  } else {
    dst_reg->u32_min_value += umin_val;
    dst_reg->u32_max_value += umax_val;
  }
}

_asn1_change_integer_value(asn1_node node) {
  asn1_node p;
  unsigned char val[SIZEOF_UNSIGNED_LONG_INT];
  unsigned char val2[SIZEOF_UNSIGNED_LONG_INT + 1];
  int len;
  if (node == NULL) return ASN1_ELEMENT_NOT_FOUND;
  p = node;
  while (p) {
    if ((type_field(p->type) == ASN1_ETYPE_INTEGER) &&
        (p->type & CONST_ASSIGN)) {
      if (p->value) {
        _asn1_convert_integer(p->value, val, sizeof(val), &len);
        asn1_octet_der(val, len, val2, &len);
        _asn1_set_value(p, val2, len);
      }
    }
    if (p->down) {
      p = p->down;
    } else {
      if (p == node)
        p = NULL;
      else if (p->right)
        p = p->right;
      else {
        while (1) {
          p = _asn1_get_up(p);
          if (p == node) {
            p = NULL;
            break;
          }
          if (p->right) {
            p = p->right;
            break;
          }
        }
      }
    }
  }
  return ASN1_SUCCESS;
}

sign_pe(context* ctx, int infd, int outfd, int attached) {
  Pe* inpe = NULL;
  int rc = set_up_inpe(ctx, infd, &inpe);
  if (rc < 0) goto finish;
  if (attached) {
    Pe* outpe = NULL;
    rc = set_up_outpe(ctx, outfd, inpe, &outpe);
    if (rc < 0) goto finish;
    rc = generate_digest(ctx->cms, outpe, 1);
    if (rc < 0) {
    err_attached:
      pe_end(outpe);
      ftruncate(outfd, 0);
      goto finish;
    }
    ssize_t sigspace = calculate_signature_space(ctx->cms, outpe);
    if (sigspace < 0) goto err_attached;
    allocate_signature_space(outpe, sigspace);
    rc = generate_digest(ctx->cms, outpe, 1);
    if (rc < 0) goto err_attached;
    rc = generate_signature(ctx->cms);
    if (rc < 0) goto err_attached;
    insert_signature(ctx->cms, ctx->cms->num_signatures);
    finalize_signatures(ctx->cms->signatures, ctx->cms->num_signatures, outpe);
    pe_end(outpe);
  } else {
    ftruncate(outfd, 0);
    rc = generate_digest(ctx->cms, inpe, 1);
    if (rc < 0) {
    err_detached:
      ftruncate(outfd, 0);
      goto finish;
    }
    rc = generate_signature(ctx->cms);
    if (rc < 0) goto err_detached;
    rc = export_signature(ctx->cms, outfd, 0);
    if (rc >= 0)
      ftruncate(outfd, rc);
    else if (rc < 0)
      goto err_detached;
  }
finish:
  if (inpe) pe_end(inpe);
  return rc;
}

void DesktopNativeWidgetHelperAura::PreInitialize(
    aura::Window* window, const Widget::InitParams& params) {
#if !defined(OS_WIN)
  if (params.type == Widget::InitParams::TYPE_POPUP) {
    is_embedded_window_ = true;
    position_client_.reset(new EmbeddedWindowScreenPositionClient(widget_));
    aura::client::SetScreenPositionClient(window, position_client_.get());
    return;
  } else if (params.type == Widget::InitParams::TYPE_CONTROL) {
    return;
  }
#endif
  gfx::Rect bounds = params.bounds;
  if (bounds.IsEmpty()) {
    bounds.set_size(gfx::Size(100, 100));
  }
  root_window_.reset(new aura::RootWindow(bounds));
  root_window_->Init();
  root_window_->set_focus_manager(new aura::FocusManager);
  root_window_event_filter_ =
      new aura::shared::RootWindowEventFilter(root_window_.get());
  root_window_->SetEventFilter(root_window_event_filter_);
  input_method_filter_.reset(new aura::shared::InputMethodEventFilter());
  input_method_filter_->SetInputMethodPropertyInRootWindow(root_window_.get());
  root_window_event_filter_->AddFilter(input_method_filter_.get());
  aura::DesktopActivationClient* activation_client =
      new aura::DesktopActivationClient(root_window_.get());
#if defined(USE_X11)
  x11_window_event_filter_.reset(
      new X11WindowEventFilter(root_window_.get(), activation_client, widget_));
  x11_window_event_filter_->SetUseHostWindowBorders(false);
  root_window_event_filter_->AddFilter(x11_window_event_filter_.get());
#endif
  root_window_->AddRootWindowObserver(this);
  aura::client::SetActivationClient(root_window_.get(), activation_client);
  aura::client::SetDispatcherClient(root_window_.get(),
                                    new aura::DesktopDispatcherClient);
  position_client_.reset(
      new RootWindowScreenPositionClient(root_window_.get()));
  aura::client::SetScreenPositionClient(window, position_client_.get());
}

void FrameLoader::completed() {
