static void fuse_put_module(struct fuse_module* m) {
  pthread_mutex_lock(&fuse_context_lock);
  assert(m->ctr > 0);
  m->ctr--;
  if (!m->ctr && m->so) {
    struct fusemod_so* so = m->so;
    assert(so->ctr > 0);
    so->ctr--;
    if (!so->ctr) {
      struct fuse_module** mp;
      for (mp = &fuse_modules; *mp;) {
        if ((*mp)->so == so)
          *mp = (*mp)->next;
        else
          mp = &(*mp)->next;
      }
      dlclose(so->handle);
      free(so);
    }
  }
  pthread_mutex_unlock(&fuse_context_lock);
}

static int packet_ioctl(struct socket* sock, unsigned int cmd,
                        unsigned long arg) {
  struct sock* sk = sock->sk;
  switch (cmd) {
    case SIOCOUTQ: {
      int amount = sk_wmem_alloc_get(sk);
      return put_user(amount, (int __user*)arg);
    }
    case SIOCINQ: {
      struct sk_buff* skb;
      int amount = 0;
      spin_lock_bh(&sk->sk_receive_queue.lock);
      skb = skb_peek(&sk->sk_receive_queue);
      if (skb) amount = skb->len;
      spin_unlock_bh(&sk->sk_receive_queue.lock);
      return put_user(amount, (int __user*)arg);
    }
    case SIOCGSTAMP:
      return sock_get_timestamp(sk, (struct timeval __user*)arg);
    case SIOCGSTAMPNS:
      return sock_get_timestampns(sk, (struct timespec __user*)arg);
#ifdef CONFIG_INET
    case SIOCADDRT:
    case SIOCDELRT:
    case SIOCDARP:
    case SIOCGARP:
    case SIOCSARP:
    case SIOCGIFADDR:
    case SIOCSIFADDR:
    case SIOCGIFBRDADDR:
    case SIOCSIFBRDADDR:
    case SIOCGIFNETMASK:
    case SIOCSIFNETMASK:
    case SIOCGIFDSTADDR:
    case SIOCSIFDSTADDR:
    case SIOCSIFFLAGS:
      return inet_dgram_ops.ioctl(sock, cmd, arg);
#endif
    default:
      return -ENOIOCTLCMD;
  }
  return 0;
}

generate_common_name(cms_context* cms, SECItem* der, char* cn_str) {
  CommonName cn;
  SECItem cn_item;
  int rc;
  rc = generate_object_id(cms, &cn.oid, SEC_OID_AVA_COMMON_NAME);
  if (rc < 0) return rc;
  rc = generate_string(cms, &cn.string, cn_str);
  if (rc < 0) return rc;
  void* ret;
  ret = SEC_ASN1EncodeItem(cms->arena, &cn_item, &cn, CommonNameTemplate);
  if (ret == NULL) cnreterr(-1, cms, "could not encode common name");
  SECItem cn_set;
  SECItem* items[2] = {&cn_item, NULL};
  rc = wrap_in_set(cms, &cn_set, items);
  if (rc < 0) return rc;
  rc = wrap_in_seq(cms, der, &cn_set, 1);
  if (rc < 0) return rc;
  return 0;
}

