WasmBinaryBuilder::getBreakTarget(int32_t offset) {
  BYN_TRACE("getBreakTarget " << offset << std::endl);
  if (breakStack.size() < 1 + size_t(offset)) {
    throwError("bad breakindex (low)");
  }
  size_t index = breakStack.size() - 1 - offset;
  if (index >= breakStack.size()) {
    throwError("bad breakindex (high)");
  }
  BYN_TRACE("breaktarget " << breakStack[index].name << " type "
                           << breakStack[index].type << std::endl);
  auto& ret = breakStack[index];
  if (!willBeIgnored) {
    breakTargetNames.insert(ret.name);
  }
  return ret;
}

fbStore_a1b5g5r5(FbBits* bits, const CARD32* values, int x, int width,
                 miIndexedPtr indexed) {
  int i;
  CARD16* pixel = ((CARD16*)bits) + x;
  for (i = 0; i < width; ++i) {
    Splita(READ(values + i));
    WRITE(pixel++, ((a << 8) & 0x8000) | ((b << 7) & 0x7c00) |
                       ((g << 2) & 0x03e0) | ((r >> 3)));
  }
}

static int __ftrace_function_set_filter(int filter, char* buf, int len,
                                        struct function_filter_data* data) {
  int i, re_cnt, ret = -EINVAL;
  int* reset;
  char** re;
  reset = filter ? &data->first_filter : &data->first_notrace;
  re = ftrace_function_filter_re(buf, len, &re_cnt);
  if (!re) return -EINVAL;
  for (i = 0; i < re_cnt; i++) {
    ret = ftrace_function_set_regexp(data->ops, filter, *reset, re[i],
                                     strlen(re[i]));
    if (ret) break;
    if (*reset) *reset = 0;
  }
  argv_free(re);
  return ret;
}

