void HTMLMediaElement::SourceWasAdded(HTMLSourceElement* source) {
  BLINK_MEDIA_LOG << "sourceWasAdded(" << (void*)this << ", " << source << ")";
  KURL url = source->GetNonEmptyURLAttribute(kSrcAttr);
  BLINK_MEDIA_LOG << "sourceWasAdded(" << (void*)this << ") - 'src' is "
                  << UrlForLoggingMedia(url);
  if (FastHasAttribute(kSrcAttr)) return;
  if (getNetworkState() == HTMLMediaElement::kNetworkEmpty) {
    InvokeResourceSelectionAlgorithm();
    next_child_node_to_consider_ = source;
    return;
  }
  if (current_source_node_ && source == current_source_node_->nextSibling()) {
    BLINK_MEDIA_LOG << "sourceWasAdded(" << (void*)this
                    << ") - <source> inserted immediately after current source";
    next_child_node_to_consider_ = source;
    return;
  }
  if (next_child_node_to_consider_) return;
  if (load_state_ != kWaitingForSource) return;
  SetShouldDelayLoadEvent(true);
  SetNetworkState(kNetworkLoading);
  next_child_node_to_consider_ = source;
  ScheduleNextSourceChild();
}

static void print_section(char* text, u8* addr, unsigned int length) {
  int i, offset;
  int newline = 1;
  char ascii[17];
  ascii[16] = 0;
  for (i = 0; i < length; i++) {
    if (newline) {
      printk(KERN_ERR "%8s 0x%p: ", text, addr + i);
      newline = 0;
    }
    printk(KERN_CONT " %02x", addr[i]);
    offset = i % 16;
    ascii[offset] = isgraph(addr[i]) ? addr[i] : '.';
    if (offset == 15) {
      printk(KERN_CONT " %s\n", ascii);
      newline = 1;
    }
  }
  if (!newline) {
    i %= 16;
    while (i < 16) {
      printk(KERN_CONT "   ");
      ascii[i] = ' ';
      i++;
    }
    printk(KERN_CONT " %s\n", ascii);
  }
}

static krb5_error_code hdb_samba4_fetch_kvno(krb5_context context, HDB* db,
                                             krb5_const_principal principal,
                                             unsigned flags, krb5_kvno kvno,
                                             hdb_entry* entry) {
  struct samba_kdc_db_context* kdc_db_ctx;
  struct sdb_entry sentry = {};
  krb5_error_code code, ret;
  uint32_t sflags;
  kdc_db_ctx = talloc_get_type_abort(db->hdb_db, struct samba_kdc_db_context);
  if (flags & HDB_F_GET_FAST_COOKIE) {
    return hdb_samba4_fetch_fast_cookie(context, kdc_db_ctx, entry);
  }
  sflags = (flags & SDB_F_HDB_MASK);
  ret = samba_kdc_fetch(context, kdc_db_ctx, principal, sflags, kvno, &sentry);
  switch (ret) {
    case 0:
      code = 0;
      break;
    case SDB_ERR_WRONG_REALM:
      code = HDB_ERR_WRONG_REALM;
      break;
    case SDB_ERR_NOENTRY:
      return HDB_ERR_NOENTRY;
    case SDB_ERR_NOT_FOUND_HERE:
      return HDB_ERR_NOT_FOUND_HERE;
    default:
      return ret;
  }
  ret = sdb_entry_to_hdb_entry(context, &sentry, entry);
  sdb_entry_free(&sentry);
  if (code != 0 && ret != 0) {
    code = ret;
  }
  return code;
}

static struct xol_area* __create_xol_area(unsigned long vaddr) {
  struct mm_struct* mm = current->mm;
  uprobe_opcode_t insn = UPROBE_SWBP_INSN;
  struct xol_area* area;
  area = kmalloc(sizeof(*area), GFP_KERNEL);
  if (unlikely(!area)) goto out;
  area->bitmap =
      kzalloc(BITS_TO_LONGS(UINSNS_PER_PAGE) * sizeof(long), GFP_KERNEL);
  if (!area->bitmap) goto free_area;
  area->xol_mapping.name = "[uprobes]";
  area->xol_mapping.fault = NULL;
  area->xol_mapping.pages = area->pages;
  area->pages[0] = alloc_page(GFP_HIGHUSER);
  if (!area->pages[0]) goto free_bitmap;
  area->pages[1] = NULL;
  area->vaddr = vaddr;
  init_waitqueue_head(&area->wq);
  set_bit(0, area->bitmap);
  atomic_set(&area->slot_count, 1);
  arch_uprobe_copy_ixol(area->pages[0], 0, &insn, UPROBE_SWBP_INSN_SIZE);
  if (!xol_add_vma(mm, area)) return area;
  __free_page(area->pages[0]);
free_bitmap:
  kfree(area->bitmap);
free_area:
  kfree(area);
out:
  return NULL;
}

sctp_disposition_t sctp_sf_shutdown_pending_abort(
    struct net* net, const struct sctp_endpoint* ep,
    const struct sctp_association* asoc, const sctp_subtype_t type, void* arg,
    sctp_cmd_seq_t* commands) {
  struct sctp_chunk* chunk = arg;
  if (!sctp_vtag_verify_either(chunk, asoc))
    return sctp_sf_pdiscard(net, ep, asoc, type, arg, commands);
  if (!sctp_chunk_length_valid(chunk, sizeof(sctp_abort_chunk_t)))
    return sctp_sf_pdiscard(net, ep, asoc, type, arg, commands);
  if (SCTP_ADDR_DEL ==
      sctp_bind_addr_state(&asoc->base.bind_addr, &chunk->dest))
    return sctp_sf_discard_chunk(net, ep, asoc, type, arg, commands);
  return __sctp_sf_do_9_1_abort(net, ep, asoc, type, arg, commands);
}

xmlParseQNameAndCompare(xmlParserCtxtPtr ctxt, xmlChar const* name,
                        xmlChar const* prefix) {
  const xmlChar* cmp;
  const xmlChar* in;
  const xmlChar* ret;
  const xmlChar* prefix2;
  if (prefix == NULL) return (xmlParseNameAndCompare(ctxt, name));
  GROW;
  in = ctxt->input->cur;
  cmp = prefix;
  while (*in != 0 && *in == *cmp) {
    ++in;
    ++cmp;
  }
  if ((*cmp == 0) && (*in == ':')) {
    in++;
    cmp = name;
    while (*in != 0 && *in == *cmp) {
      ++in;
      ++cmp;
    }
    if (*cmp == 0 && (*in == '>' || IS_BLANK_CH(*in))) {
      ctxt->input->cur = in;
      return ((const xmlChar*)1);
    }
  }
  ret = xmlParseQName(ctxt, &prefix2);
  if ((ret == name) && (prefix == prefix2)) return ((const xmlChar*)1);
  return ret;
}

void blk_mq_start_request(struct request* rq) {
  struct request_queue* q = rq->q;
  trace_block_rq_issue(q, rq);
  rq->resid_len = blk_rq_bytes(rq);
  if (unlikely(blk_bidi_rq(rq)))
    rq->next_rq->resid_len = blk_rq_bytes(rq->next_rq);
  blk_add_timer(rq);
  smp_mb__before_atomic();
  if (!test_bit(REQ_ATOM_STARTED, &rq->atomic_flags))
    set_bit(REQ_ATOM_STARTED, &rq->atomic_flags);
  if (test_bit(REQ_ATOM_COMPLETE, &rq->atomic_flags))
    clear_bit(REQ_ATOM_COMPLETE, &rq->atomic_flags);
  if (q->dma_drain_size && blk_rq_bytes(rq)) {
    rq->nr_phys_segments++;
  }
}

