u64 sched_clock_cpu(int cpu) {
  struct sched_clock_data* scd;
  u64 clock;
  if (sched_clock_stable()) return sched_clock();
  if (unlikely(!sched_clock_running)) return 0ull;
  preempt_disable_notrace();
  scd = cpu_sdc(cpu);
  if (cpu != smp_processor_id())
    clock = sched_clock_remote(scd);
  else
    clock = sched_clock_local(scd);
  preempt_enable_notrace();
  return clock;
}

join_read_last_key(JOIN_TAB* tab) {
  int error;
  TABLE* table = tab->table;
  if (!table->file->inited &&
      (error = table->file->ha_index_init(tab->ref.key, tab->sorted))) {
    (void)report_error(table, error);
    return 1;
  }
  if (cp_buffer_from_ref(tab->join->thd, table, &tab->ref)) return -1;
  if ((error = table->file->prepare_index_key_scan_map(
           tab->ref.key_buff, make_prev_keypart_map(tab->ref.key_parts)))) {
    report_error(table, error);
    return -1;
  }
  if ((error = table->file->ha_index_read_map(
           table->record[0], tab->ref.key_buff,
           make_prev_keypart_map(tab->ref.key_parts), HA_READ_PREFIX_LAST))) {
    if (error != HA_ERR_KEY_NOT_FOUND && error != HA_ERR_END_OF_FILE)
      return report_error(table, error);
    return -1;
  }
  return 0;
}

static WERROR dcesrv_DnssrvEnumRecords(struct dcesrv_call_state* dce_call,
                                       TALLOC_CTX* mem_ctx,
                                       struct DnssrvEnumRecords* r) {
  struct dnsserver_state* dsstate;
  struct dnsserver_zone* z;
  WERROR ret;
  ZERO_STRUCTP(r->out.pdwBufferLength);
  ZERO_STRUCTP(r->out.pBuffer);
  if ((dsstate = dnsserver_connect(dce_call)) == NULL) {
    return WERR_DNS_ERROR_DS_UNAVAILABLE;
  }
  if (r->in.pszZone == NULL) {
    return WERR_DNS_ERROR_NAME_DOES_NOT_EXIST;
  }
  if (strcasecmp(r->in.pszZone, "..RootHints") == 0) {
    ret = dnsserver_enumerate_root_records(
        dsstate, mem_ctx, DNS_CLIENT_VERSION_W2K, r->in.pszNodeName,
        r->in.wRecordType, r->in.fSelectFlag, r->out.pdwBufferLength,
        r->out.pBuffer);
  } else {
    z = dnsserver_find_zone(dsstate->zones, r->in.pszZone);
    if (z == NULL) {
      return WERR_DNS_ERROR_NAME_DOES_NOT_EXIST;
    }
    ret = dnsserver_enumerate_records(
        dsstate, mem_ctx, z, DNS_CLIENT_VERSION_W2K, r->in.pszNodeName,
        r->in.pszStartChild, r->in.wRecordType, r->in.fSelectFlag,
        r->in.pszFilterStart, r->in.pszFilterStop, r->out.pdwBufferLength,
        r->out.pBuffer);
  }
  if (W_ERROR_EQUAL(ret, WERR_CALL_NOT_IMPLEMENTED)) {
    NDR_PRINT_FUNCTION_DEBUG(DnssrvEnumRecords, NDR_IN, r);
  }
  return ret;
}

void mwifiex_set_vht_width(struct mwifiex_private* priv,
                           enum nl80211_chan_width width, bool ap_11ac_enable) {
