valid_ruser(const char* s) {
  size_t i;
  if (*s == '-') return 0;
  for (i = 0; s[i] != 0; i++) {
    if (strchr("'`\";&<>|(){}", s[i]) != NULL) return 0;
    if (isspace((u_char)s[i]) && s[i + 1] == '-') return 0;
    if (s[i] == '\\' && s[i + 1] == '\0') return 0;
  }
  return 1;
}

int RemoveUnknownSections(void) {
  int a;
  int Modified = FALSE;
  for (a = 0; a < SectionsRead - 1;) {
    switch (Sections[a].Type) {
      case M_SOF0:
      case M_SOF1:
      case M_SOF2:
      case M_SOF3:
      case M_SOF5:
      case M_SOF6:
      case M_SOF7:
      case M_SOF9:
      case M_SOF10:
      case M_SOF11:
      case M_SOF13:
      case M_SOF14:
      case M_SOF15:
      case M_SOI:
      case M_EOI:
      case M_SOS:
      case M_JFIF:
      case M_EXIF:
      case M_XMP:
      case M_COM:
      case M_DQT:
      case M_DHT:
      case M_DRI:
      case M_IPTC:
        a++;
        break;
      default:
        free(Sections[a].Data);
        memmove(Sections + a, Sections + a + 1,
                sizeof(Section_t) * (SectionsRead - a - 1));
        SectionsRead -= 1;
        Modified = TRUE;
    }
  }
  return Modified;
}

date_s_rfc2822(int argc, VALUE* argv, VALUE klass) {
  VALUE str, sg, opt;
  rb_scan_args(argc, argv, "02:", &str, &sg, &opt);
  switch (argc) {
    case 0:
      str = rb_str_new2("Mon, 1 Jan -4712 00:00:00 +0000");
    case 1:
      sg = INT2FIX(DEFAULT_SG);
  }
  {
    int argc2 = 1;
    VALUE argv2[2];
    argv2[0] = str;
    if (!NIL_P(opt)) argv2[argc2++] = opt;
    VALUE hash = date_s__rfc2822(argc2, argv2, klass);
    return d_new_by_frags(klass, hash, sg);
  }
}

void LibRaw::hat_transform(float* temp, float* base, int st, int size, int sc) {
  int i;
  for (i = 0; i < sc; i++)
    temp[i] = 2 * base[st * i] + base[st * (sc - i)] + base[st * (i + sc)];
  for (; i + sc < size; i++)
    temp[i] = 2 * base[st * i] + base[st * (i - sc)] + base[st * (i + sc)];
  for (; i < size; i++)
    temp[i] = 2 * base[st * i] + base[st * (i - sc)] +
              base[st * (2 * size - 2 - (i + sc))];
}

