static void print_enc_string(FILE* fp, OnigEncoding enc, const UChar* s,
                             const UChar* end) {
  fprintf(fp, "\nPATTERN: /");
  if (ONIGENC_MBC_MINLEN(enc) > 1) {
    const UChar* p;
    OnigCodePoint code;
    p = s;
    while (p < end) {
      code = ONIGENC_MBC_TO_CODE(enc, p, end);
      if (code >= 0x80) {
        fprintf(fp, " 0x%04x ", (int)code);
      } else {
        fputc((int)code, fp);
      }
      p += enclen(enc, p, end);
    }
  } else {
    while (s < end) {
      fputc((int)*s, fp);
      s++;
    }
  }
  fprintf(fp, "/ (%s)\n", enc->name);
}

int rds_notify_queue_get(struct rds_sock* rs, struct msghdr* msghdr) {
  struct rds_notifier* notifier;
  struct rds_rdma_notify cmsg = {0};
  unsigned int count = 0, max_messages = ~0U;
  unsigned long flags;
  LIST_HEAD(copy);
  int err = 0;
  if (msghdr) {
    max_messages = msghdr->msg_controllen / CMSG_SPACE(sizeof(cmsg));
    if (!max_messages) max_messages = 1;
  }
  spin_lock_irqsave(&rs->rs_lock, flags);
  while (!list_empty(&rs->rs_notify_queue) && count < max_messages) {
    notifier =
        list_entry(rs->rs_notify_queue.next, struct rds_notifier, n_list);
    list_move(&notifier->n_list, &copy);
    count++;
  }
  spin_unlock_irqrestore(&rs->rs_lock, flags);
  if (!count) return 0;
  while (!list_empty(&copy)) {
    notifier = list_entry(copy.next, struct rds_notifier, n_list);
    if (msghdr) {
      cmsg.user_token = notifier->n_user_token;
      cmsg.status = notifier->n_status;
      err =
          put_cmsg(msghdr, SOL_RDS, RDS_CMSG_RDMA_STATUS, sizeof(cmsg), &cmsg);
      if (err) break;
    }
    list_del_init(&notifier->n_list);
    kfree(notifier);
  }
  if (!list_empty(&copy)) {
    spin_lock_irqsave(&rs->rs_lock, flags);
    list_splice(&copy, &rs->rs_notify_queue);
    spin_unlock_irqrestore(&rs->rs_lock, flags);
  }
  return err;
}

