int git_tree__prefix_position(const git_tree* tree, const char* path) {
  const git_vector* entries = &tree->entries;
  struct tree_key_search ksearch;
  size_t at_pos;
  if (!path) return 0;
  ksearch.filename = path;
  ksearch.filename_len = strlen(path);
  assert(git_vector_is_sorted(&tree->entries));
  git_vector_bsearch2(&at_pos, (git_vector*)entries, &homing_search_cmp,
                      &ksearch);
  for (; at_pos < entries->length; ++at_pos) {
    const git_tree_entry* entry = entries->contents[at_pos];
    if (homing_search_cmp(&ksearch, entry) < 0) break;
  }
  for (; at_pos > 0; --at_pos) {
    const git_tree_entry* entry = entries->contents[at_pos - 1];
    if (homing_search_cmp(&ksearch, entry) > 0) break;
  }
  return (int)at_pos;
}

_tiffMapProc(thandle_t fd, void** pbase, toff_t* psize) {
  uint64 size64 = _tiffSizeProc(fd);
  tmsize_t sizem = (tmsize_t)size64;
  if ((uint64)sizem == size64) {
    fd_as_handle_union_t fdh;
    fdh.h = fd;
    *pbase = (void*)mmap(0, (size_t)sizem, PROT_READ, MAP_SHARED, fdh.fd, 0);
    if (*pbase != (void*)-1) {
      *psize = (tmsize_t)sizem;
      return (1);
    }
  }
  return (0);
}

