static bool guest_state_valid(struct kvm_vcpu* vcpu) {
  if (enable_unrestricted_guest) return true;
  if (!is_protmode(vcpu) || (vmx_get_rflags(vcpu) & X86_EFLAGS_VM)) {
    if (!rmode_segment_valid(vcpu, VCPU_SREG_CS)) return false;
    if (!rmode_segment_valid(vcpu, VCPU_SREG_SS)) return false;
    if (!rmode_segment_valid(vcpu, VCPU_SREG_DS)) return false;
    if (!rmode_segment_valid(vcpu, VCPU_SREG_ES)) return false;
    if (!rmode_segment_valid(vcpu, VCPU_SREG_FS)) return false;
    if (!rmode_segment_valid(vcpu, VCPU_SREG_GS)) return false;
  } else {
    if (!cs_ss_rpl_check(vcpu)) return false;
    if (!code_segment_valid(vcpu)) return false;
    if (!stack_segment_valid(vcpu)) return false;
    if (!data_segment_valid(vcpu, VCPU_SREG_DS)) return false;
    if (!data_segment_valid(vcpu, VCPU_SREG_ES)) return false;
    if (!data_segment_valid(vcpu, VCPU_SREG_FS)) return false;
    if (!data_segment_valid(vcpu, VCPU_SREG_GS)) return false;
    if (!tr_valid(vcpu)) return false;
    if (!ldtr_valid(vcpu)) return false;
  }
  return true;
}

int STDCALL mysql_server_init(int argc __attribute__((unused)),
                              char** argv __attribute__((unused)),
                              char** groups __attribute__((unused))) {
  int result = 0;
  if (!mysql_client_init) {
    mysql_client_init = 1;
    org_my_init_done = my_init_done;
    if (my_init()) return 1;
    init_client_errs();
    if (mysql_client_plugin_init()) return 1;
    if (!mysql_port) {
      char* env;
      struct servent* serv_ptr __attribute__((unused));
      mysql_port = MYSQL_PORT;
#if MYSQL_PORT_DEFAULT == 0
      if ((serv_ptr = getservbyname("mysql", "tcp")))
        mysql_port = (uint)ntohs((ushort)serv_ptr->s_port);
#endif
      if ((env = getenv("MYSQL_TCP_PORT"))) mysql_port = (uint)atoi(env);
    }
    if (!mysql_unix_port) {
      char* env;
#ifdef __WIN__
      mysql_unix_port = (char*)MYSQL_NAMEDPIPE;
#else
      mysql_unix_port = (char*)MYSQL_UNIX_ADDR;
#endif
      if ((env = getenv("MYSQL_UNIX_PORT"))) mysql_unix_port = env;
    }
    mysql_debug(NullS);
#if defined(SIGPIPE) && !defined(__WIN__)
    (void)signal(SIGPIPE, SIG_IGN);
#endif
#ifdef EMBEDDED_LIBRARY
    if (argc > -1) result = init_embedded_server(argc, argv, groups);
#endif
  } else
    result = (int)my_thread_init();
  return result;
}

