static int do_check_subprogs(struct bpf_verifier_env* env) {
  struct bpf_prog_aux* aux = env->prog->aux;
  int i, ret;
  if (!aux->func_info) return 0;
  for (i = 1; i < env->subprog_cnt; i++) {
    if (aux->func_info_aux[i].linkage != BTF_FUNC_GLOBAL) continue;
    env->insn_idx = env->subprog_info[i].start;
    WARN_ON_ONCE(env->insn_idx == 0);
    ret = do_check_common(env, i);
    if (ret) {
      return ret;
    } else if (env->log.level & BPF_LOG_LEVEL) {
      verbose(env, "Func#%d is safe for any args that match its prototype\n",
              i);
    }
  }
  return 0;
}

void InstanceKlass::add_implementor(Klass* k) {
  assert_lock_strong(Compile_lock);
  assert(is_interface(), "not interface");
  if (InstanceKlass::cast(k)->is_interface()) return;
  Klass* sk = k->super();
  if (sk != NULL && InstanceKlass::cast(sk)->implements_interface(this)) return;
  Klass* ik = implementor();
  if (ik == NULL) {
    set_implementor(k);
  } else if (ik != this && ik != k) {
    set_implementor(this);
  }
  for (int index = 0; index < local_interfaces()->length(); index++) {
    InstanceKlass::cast(local_interfaces()->at(index))->add_implementor(k);
  }
}

