      static_cast<int>(ConvertUnitDouble(page_layout_in_points.content_width,
                                         printing::kPointsPerInch, dpi)),
      static_cast<int>(ConvertUnitDouble(page_layout_in_points.content_height,
                                         printing::kPointsPerInch, dpi)));
  double page_width_in_points = page_layout_in_points.content_width +
                                page_layout_in_points.margin_left +
                                page_layout_in_points.margin_right;
  double page_height_in_points = page_layout_in_points.content_height +
                                 page_layout_in_points.margin_top +
                                 page_layout_in_points.margin_bottom;
  params->page_size =
