codegen_error(codegen_scope* s, const char* message) {
  if (!s) return;
#ifndef MRB_NO_STDIO
  if (s->filename_sym && s->lineno) {
    const char* filename = mrb_sym_name_len(s->mrb, s->filename_sym, NULL);
    fprintf(stderr, "%s:%d: %s\n", filename, s->lineno, message);
  } else {
    fprintf(stderr, "%s\n", message);
  }
#endif
  while (s->prev) {
    codegen_scope* tmp = s->prev;
    if (s->irep) {
      mrb_free(s->mrb, s->iseq);
      for (int i = 0; i < s->irep->plen; i++) {
        mrb_pool_value* pv = &s->pool[i];
        if ((pv->tt & 0x3) == IREP_TT_STR || pv->tt == IREP_TT_BIGINT) {
          mrb_free(s->mrb, (void*)pv->u.str);
        }
      }
      mrb_free(s->mrb, s->pool);
      mrb_free(s->mrb, s->syms);
      mrb_free(s->mrb, s->catch_table);
      if (s->reps) {
        for (int i = 0; i < s->irep->rlen; i++) {
          if (s->reps[i]) mrb_irep_decref(s->mrb, (mrb_irep*)s->reps[i]);
        }
        mrb_free(s->mrb, s->reps);
      }
      mrb_free(s->mrb, s->lines);
    }
    mrb_pool_close(s->mpool);
    s = tmp;
  }
  MRB_THROW(s->mrb->jmp);
}

int uprobe_write_opcode(struct mm_struct* mm, unsigned long vaddr,
                        uprobe_opcode_t opcode) {
  struct page *old_page, *new_page;
  struct vm_area_struct* vma;
  int ret;
retry:
  ret = get_user_pages_remote(NULL, mm, vaddr, 1, FOLL_FORCE | FOLL_SPLIT,
                              &old_page, &vma, NULL);
  if (ret <= 0) return ret;
  ret = verify_opcode(old_page, vaddr, &opcode);
  if (ret <= 0) goto put_old;
  ret = anon_vma_prepare(vma);
  if (ret) goto put_old;
  ret = -ENOMEM;
  new_page = alloc_page_vma(GFP_HIGHUSER_MOVABLE, vma, vaddr);
  if (!new_page) goto put_old;
  __SetPageUptodate(new_page);
  copy_highpage(new_page, old_page);
  copy_to_page(new_page, vaddr, &opcode, UPROBE_SWBP_INSN_SIZE);
  ret = __replace_page(vma, vaddr, old_page, new_page);
  put_page(new_page);
put_old:
  put_page(old_page);
  if (unlikely(ret == -EAGAIN)) goto retry;
  return ret;
}

