static int caif_create(struct net* net, struct socket* sock, int protocol,
                       int kern) {
  struct sock* sk = NULL;
  struct caifsock* cf_sk = NULL;
  static struct proto prot = {
      .name = "PF_CAIF",
      .owner = THIS_MODULE,
      .obj_size = sizeof(struct caifsock),
  };
  if (!capable(CAP_SYS_ADMIN) && !capable(CAP_NET_ADMIN)) return -EPERM;
  if (sock->type == SOCK_SEQPACKET)
    sock->ops = &caif_seqpacket_ops;
  else if (sock->type == SOCK_STREAM)
    sock->ops = &caif_stream_ops;
  else
    return -ESOCKTNOSUPPORT;
  if (protocol < 0 || protocol >= CAIFPROTO_MAX) return -EPROTONOSUPPORT;
  sk = sk_alloc(net, PF_CAIF, GFP_KERNEL, &prot);
  if (!sk) return -ENOMEM;
  cf_sk = container_of(sk, struct caifsock, sk);
  sk->sk_protocol = (unsigned char)protocol;
  switch (protocol) {
    case CAIFPROTO_AT:
      sk->sk_priority = TC_PRIO_CONTROL;
      break;
    case CAIFPROTO_RFM:
      sk->sk_priority = TC_PRIO_INTERACTIVE_BULK;
      break;
    default:
      sk->sk_priority = TC_PRIO_BESTEFFORT;
  }
  lock_sock(&(cf_sk->sk));
  sock_init_data(sock, sk);
  sk->sk_destruct = caif_sock_destructor;
  mutex_init(&cf_sk->readlock);
  cf_sk->layer.ctrlcmd = caif_ctrl_cb;
  cf_sk->sk.sk_socket->state = SS_UNCONNECTED;
  cf_sk->sk.sk_state = CAIF_DISCONNECTED;
  set_tx_flow_off(cf_sk);
  set_rx_flow_on(cf_sk);
  cf_sk->conn_req.link_selector = CAIF_LINK_LOW_LATENCY;
  cf_sk->conn_req.protocol = protocol;
  release_sock(&cf_sk->sk);
  return 0;
}

slow_name_validate(GMarkupParseContext* context, const gchar* name,
                   GError** error) {
  const gchar* p = name;
  if (!g_utf8_validate(name, strlen(name), NULL)) {
    set_error(context, error, G_MARKUP_ERROR_BAD_UTF8,
              _("Invalid UTF-8 encoded text in name — not valid “%s”"), name);
    return FALSE;
  }
  if (!(g_ascii_isalpha(*p) ||
        (!IS_COMMON_NAME_END_CHAR(*p) &&
         (*p == '_' || *p == ':' || g_unichar_isalpha(g_utf8_get_char(p)))))) {
    set_error(context, error, G_MARKUP_ERROR_PARSE,
              _("“%s” is not a valid name"), name);
    return FALSE;
  }
  for (p = g_utf8_next_char(name); *p != '\0'; p = g_utf8_next_char(p)) {
    if (!(g_ascii_isalnum(*p) ||
          (!IS_COMMON_NAME_END_CHAR(*p) &&
           (*p == '.' || *p == '-' || *p == '_' || *p == ':' ||
            g_unichar_isalpha(g_utf8_get_char(p)))))) {
      set_error(context, error, G_MARKUP_ERROR_PARSE,
                _("“%s” is not a valid name: “%c”"), name, *p);
      return FALSE;
    }
  }
  return TRUE;
}

static void mce_panic(const char* msg, struct mce* final, char* exp) {
  int apei_err = 0;
  struct llist_node* pending;
  struct mce_evt_llist* l;
  if (!fake_panic) {
    if (atomic_inc_return(&mce_panicked) > 1) wait_for_panic();
    barrier();
    bust_spinlocks(1);
    console_verbose();
  } else {
    if (atomic_inc_return(&mce_fake_panicked) > 1) return;
  }
  pending = mce_gen_pool_prepare_records();
  llist_for_each_entry(l, pending, llnode) {
    struct mce* m = &l->mce;
    if (!(m->status & MCI_STATUS_UC)) {
      print_mce(m);
      if (!apei_err) apei_err = apei_write_mce(m);
    }
  }
  llist_for_each_entry(l, pending, llnode) {
    struct mce* m = &l->mce;
    if (!(m->status & MCI_STATUS_UC)) continue;
    if (!final || mce_cmp(m, final)) {
      print_mce(m);
      if (!apei_err) apei_err = apei_write_mce(m);
    }
  }
  if (final) {
    print_mce(final);
    if (!apei_err) apei_err = apei_write_mce(final);
  }
  if (cpu_missing)
    pr_emerg(HW_ERR "Some CPUs didn't answer in synchronization\n");
  if (exp) pr_emerg(HW_ERR "Machine check: %s\n", exp);
  if (!fake_panic) {
    if (panic_timeout == 0) panic_timeout = mca_cfg.panic_timeout;
    panic(msg);
  } else
    pr_emerg(HW_ERR "Fake kernel panic: %s\n", msg);
}

static int tcmu_glfs_open(struct tcmu_device* dev) {
  struct glfs_state* gfsp;
  int ret = 0;
  char* config;
  struct stat st;
  gfsp = calloc(1, sizeof(*gfsp));
  if (!gfsp) return -ENOMEM;
  tcmu_set_dev_private(dev, gfsp);
  config = tcmu_get_path(dev);
  if (!config) {
    goto fail;
  }
  gfsp->fs = tcmu_create_glfs_object(config, &gfsp->hosts);
  if (!gfsp->fs) {
    tcmu_err("tcmu_create_glfs_object failed\n");
    goto fail;
  }
  gfsp->gfd = glfs_open(gfsp->fs, gfsp->hosts->path, ALLOWED_BSOFLAGS);
  if (!gfsp->gfd) {
    tcmu_err("glfs_open failed: %m\n");
    goto unref;
  }
  ret = glfs_lstat(gfsp->fs, gfsp->hosts->path, &st);
  if (ret) {
    tcmu_err("glfs_lstat failed: %m\n");
    goto unref;
  }
  if (st.st_size != tcmu_get_device_size(dev)) {
    tcmu_err(
        "device size and backing size disagree: "
        "device %lld backing %lld\n",
        tcmu_get_device_size(dev), (long long)st.st_size);
    goto unref;
  }
  return 0;
unref:
  gluster_cache_refresh(gfsp->fs, tcmu_get_path(dev));
fail:
  if (gfsp->gfd) glfs_close(gfsp->gfd);
  gluster_free_server(&gfsp->hosts);
  free(gfsp);
  return -EIO;
}

static int skcipher_wait_for_wmem(struct sock* sk, unsigned flags) {
  long timeout;
  DEFINE_WAIT(wait);
  int err = -ERESTARTSYS;
  if (flags & MSG_DONTWAIT) return -EAGAIN;
  set_bit(SOCK_ASYNC_NOSPACE, &sk->sk_socket->flags);
  for (;;) {
    if (signal_pending(current)) break;
    prepare_to_wait(sk_sleep(sk), &wait, TASK_INTERRUPTIBLE);
    timeout = MAX_SCHEDULE_TIMEOUT;
    if (sk_wait_event(sk, &timeout, skcipher_writable(sk))) {
      err = 0;
      break;
    }
  }
  finish_wait(sk_sleep(sk), &wait);
  return err;
}

