static int handle_invept(struct kvm_vcpu* vcpu) {
  u32 vmx_instruction_info, types;
  unsigned long type;
  gva_t gva;
  struct x86_exception e;
  struct {
    u64 eptp, gpa;
  } operand;
  if (!(nested_vmx_secondary_ctls_high & SECONDARY_EXEC_ENABLE_EPT) ||
      !(nested_vmx_ept_caps & VMX_EPT_INVEPT_BIT)) {
    kvm_queue_exception(vcpu, UD_VECTOR);
    return 1;
  }
  if (!nested_vmx_check_permission(vcpu)) return 1;
  if (!kvm_read_cr0_bits(vcpu, X86_CR0_PE)) {
    kvm_queue_exception(vcpu, UD_VECTOR);
    return 1;
  }
  vmx_instruction_info = vmcs_read32(VMX_INSTRUCTION_INFO);
  type = kvm_register_readl(vcpu, (vmx_instruction_info >> 28) & 0xf);
  types = (nested_vmx_ept_caps >> VMX_EPT_EXTENT_SHIFT) & 6;
  if (!(types & (1UL << type))) {
    nested_vmx_failValid(vcpu, VMXERR_INVALID_OPERAND_TO_INVEPT_INVVPID);
    return 1;
  }
  if (get_vmx_mem_address(vcpu, vmcs_readl(EXIT_QUALIFICATION),
                          vmx_instruction_info, &gva))
    return 1;
  if (kvm_read_guest_virt(&vcpu->arch.emulate_ctxt, gva, &operand,
                          sizeof(operand), &e)) {
    kvm_inject_page_fault(vcpu, &e);
    return 1;
  }
  switch (type) {
    case VMX_EPT_EXTENT_GLOBAL:
      kvm_mmu_sync_roots(vcpu);
      kvm_make_request(KVM_REQ_TLB_FLUSH, vcpu);
      nested_vmx_succeed(vcpu);
      break;
    default:
      BUG_ON(1);
      break;
  }
  skip_emulated_instruction(vcpu);
  return 1;
}

void sctp_assoc_rwnd_increase(struct sctp_association* asoc, unsigned int len) {
  struct sctp_chunk* sack;
  struct timer_list* timer;
  if (asoc->rwnd_over) {
    if (asoc->rwnd_over >= len) {
      asoc->rwnd_over -= len;
    } else {
      asoc->rwnd += (len - asoc->rwnd_over);
      asoc->rwnd_over = 0;
    }
  } else {
    asoc->rwnd += len;
  }
  if (asoc->rwnd_press && asoc->rwnd >= asoc->rwnd_press) {
    int change = min(asoc->pathmtu, asoc->rwnd_press);
    asoc->rwnd += change;
    asoc->rwnd_press -= change;
  }
  pr_debug("%s: asoc:%p rwnd increased by %d to (%u, %u) - %u\n", __func__,
           asoc, len, asoc->rwnd, asoc->rwnd_over, asoc->a_rwnd);
  if (sctp_peer_needs_update(asoc)) {
    asoc->a_rwnd = asoc->rwnd;
    pr_debug(
        "%s: sending window update SACK- asoc:%p rwnd:%u "
        "a_rwnd:%u\n",
        __func__, asoc, asoc->rwnd, asoc->a_rwnd);
    sack = sctp_make_sack(asoc);
    if (!sack) return;
    asoc->peer.sack_needed = 0;
    sctp_outq_tail(&asoc->outqueue, sack);
    timer = &asoc->timers[SCTP_EVENT_TIMEOUT_SACK];
    if (del_timer(timer)) sctp_association_put(asoc);
  }
}

static int mce_device_create(unsigned int cpu) {
  struct device* dev;
  int err;
  int i, j;
  if (!mce_available(&boot_cpu_data)) return -EIO;
  dev = per_cpu(mce_device, cpu);
  if (dev) return 0;
  dev = kzalloc(sizeof *dev, GFP_KERNEL);
  if (!dev) return -ENOMEM;
  dev->id = cpu;
  dev->bus = &mce_subsys;
  dev->release = &mce_device_release;
  err = device_register(dev);
  if (err) {
    put_device(dev);
    return err;
  }
  for (i = 0; mce_device_attrs[i]; i++) {
    err = device_create_file(dev, mce_device_attrs[i]);
    if (err) goto error;
  }
  for (j = 0; j < mca_cfg.banks; j++) {
    err = device_create_file(dev, &mce_banks[j].attr);
    if (err) goto error2;
  }
  cpumask_set_cpu(cpu, mce_device_initialized);
  per_cpu(mce_device, cpu) = dev;
  return 0;
error2:
  while (--j >= 0) device_remove_file(dev, &mce_banks[j].attr);
error:
  while (--i >= 0) device_remove_file(dev, mce_device_attrs[i]);
  device_unregister(dev);
  return err;
}

