static void ldapsrv_process_call_trigger(struct tevent_req* req,
                                         void* private_data) {
  struct ldapsrv_process_call_state* state =
      tevent_req_data(req, struct ldapsrv_process_call_state);
  struct ldapsrv_connection* conn = state->call->conn;
  NTSTATUS status;
  if (conn->deferred_expire_disconnect != NULL) {
    tevent_req_done(req);
    return;
  }
  status = ldapsrv_do_call(state->call);
  if (NT_STATUS_EQUAL(status, NT_STATUS_NETWORK_SESSION_EXPIRED)) {
    int defer_msec = lpcfg_parm_int(conn->lp_ctx, NULL, "ldap_server",
                                    "delay_expire_disconnect", 0);
    conn->deferred_expire_disconnect =
        tevent_wakeup_send(conn, conn->connection->event.ctx,
                           timeval_current_ofs_msec(defer_msec));
    if (tevent_req_nomem(conn->deferred_expire_disconnect, req)) {
      return;
    }
    tevent_req_set_callback(conn->deferred_expire_disconnect,
                            ldapsrv_disconnect_ticket_expired, conn);
    tevent_req_done(req);
    return;
  }
  if (!NT_STATUS_IS_OK(status)) {
    tevent_req_nterror(req, status);
    return;
  }
  tevent_req_done(req);
}

static char* kvp_if_name_to_mac(char* if_name) {
  FILE* file;
  char *p, *x;
  char buf[256];
  char addr_file[256];
  int i;
  char* mac_addr = NULL;
  snprintf(addr_file, sizeof(addr_file), "%s%s%s", "/sys/class/net/", if_name,
           "/address");
  file = fopen(addr_file, "r");
  if (file == NULL) return NULL;
  p = fgets(buf, sizeof(buf), file);
  if (p) {
    x = strchr(p, '\n');
    if (x) *x = '\0';
    for (i = 0; i < strlen(p); i++) p[i] = toupper(p[i]);
    mac_addr = strdup(p);
  }
  fclose(file);
  return mac_addr;
}

