posix_acl_permission(struct inode* inode, const struct posix_acl* acl,
                     int want) {
  const struct posix_acl_entry *pa, *pe, *mask_obj;
  int found = 0;
  want &= MAY_READ | MAY_WRITE | MAY_EXEC | MAY_NOT_BLOCK;
  FOREACH_ACL_ENTRY(pa, acl, pe) {
    switch (pa->e_tag) {
      case ACL_USER_OBJ:
        if (uid_eq(inode->i_uid, current_fsuid())) goto check_perm;
        break;
      case ACL_USER:
        if (uid_eq(pa->e_uid, current_fsuid())) goto mask;
        break;
      case ACL_GROUP_OBJ:
        if (in_group_p(inode->i_gid)) {
          found = 1;
          if ((pa->e_perm & want) == want) goto mask;
        }
        break;
      case ACL_GROUP:
        if (in_group_p(pa->e_gid)) {
          found = 1;
          if ((pa->e_perm & want) == want) goto mask;
        }
        break;
      case ACL_MASK:
        break;
      case ACL_OTHER:
        if (found)
          return -EACCES;
        else
          goto check_perm;
      default:
        return -EIO;
    }
  }
  return -EIO;
mask:
  for (mask_obj = pa + 1; mask_obj != pe; mask_obj++) {
    if (mask_obj->e_tag == ACL_MASK) {
      if ((pa->e_perm & mask_obj->e_perm & want) == want) return 0;
      return -EACCES;
    }
  }
check_perm:
  if ((pa->e_perm & want) == want) return 0;
  return -EACCES;
}

static TT_F26Dot6 Round_None(EXEC_OPS TT_F26Dot6 distance,
                             TT_F26Dot6 compensation) {
  TT_F26Dot6 val;
  (void)exc;
  if (distance >= 0) {
    val = distance + compensation;
    if (val < 0) val = 0;
  } else {
    val = distance - compensation;
    if (val > 0) val = 0;
  }
  return val;
}

archive_read_format_rar_read_data(struct archive_read* a, const void** buff,
                                  size_t* size, int64_t* offset) {
  struct rar* rar = (struct rar*)(a->format->data);
  int ret;
  if (rar->has_encrypted_entries == ARCHIVE_READ_FORMAT_ENCRYPTION_DONT_KNOW) {
    rar->has_encrypted_entries = 0;
  }
  if (rar->bytes_unconsumed > 0) {
    __archive_read_consume(a, rar->bytes_unconsumed);
    rar->bytes_unconsumed = 0;
  }
  *buff = NULL;
  if (rar->entry_eof || rar->offset_seek >= rar->unp_size) {
    *size = 0;
    *offset = rar->offset;
    if (*offset < rar->unp_size) *offset = rar->unp_size;
    return (ARCHIVE_EOF);
  }
  switch (rar->compression_method) {
    case COMPRESS_METHOD_STORE:
      ret = read_data_stored(a, buff, size, offset);
      break;
    case COMPRESS_METHOD_FASTEST:
    case COMPRESS_METHOD_FAST:
    case COMPRESS_METHOD_NORMAL:
    case COMPRESS_METHOD_GOOD:
    case COMPRESS_METHOD_BEST:
      ret = read_data_compressed(a, buff, size, offset);
      if (ret != ARCHIVE_OK && ret != ARCHIVE_WARN)
        __archive_ppmd7_functions.Ppmd7_Free(&rar->ppmd7_context, &g_szalloc);
      break;
    default:
      archive_set_error(&a->archive, ARCHIVE_ERRNO_FILE_FORMAT,
                        "Unsupported compression method for RAR file.");
      ret = ARCHIVE_FATAL;
      break;
  }
  return (ret);
}

