static double mp_date(_cimg_math_parser& mp) {
  const unsigned int _arg = (unsigned int)mp.opcode[3],
                     _siz = (unsigned int)mp.opcode[4], siz = _siz ? _siz : 1;
  const double* const arg_in = _arg == ~0U ? 0 : &_mp_arg(3) + (_siz ? 1 : 0);
  double* const arg_out = &_mp_arg(1) + (_siz ? 1 : 0);
  if (arg_in)
    std::memcpy(arg_out, arg_in, siz * sizeof(double));
  else
    for (unsigned int i = 0; i < siz; ++i) arg_out[i] = i;
  CImg<charT> filename(mp.opcode[2] - 5);
  if (filename) {
    const ulongT* ptrs = mp.opcode._data + 5;
    cimg_for(filename, ptrd, char)* ptrd = (char)*(ptrs++);
    cimg::fdate(filename, arg_out, siz);
  } else
    cimg::date(arg_out, siz);
  return _siz ? cimg::type<double>::nan() : *arg_out;

static int mxf_read_source_package(void* arg, AVIOContext* pb, int tag,
                                   int size, UID uid, int64_t klv_offset) {
  MXFPackage* package = arg;
  switch (tag) {
    case 0x4403:
      package->tracks_count = avio_rb32(pb);
      package->tracks_refs = av_calloc(package->tracks_count, sizeof(UID));
      if (!package->tracks_refs) return AVERROR(ENOMEM);
      avio_skip(pb, 4);
      avio_read(pb, (uint8_t*)package->tracks_refs,
                package->tracks_count * sizeof(UID));
      break;
    case 0x4401:
      avio_skip(pb, 16);
      avio_read(pb, package->package_uid, 16);
      break;
    case 0x4701:
      avio_read(pb, package->descriptor_ref, 16);
      break;
  }
  return 0;
}

