static int ip6_route_del(struct fib6_config* cfg) {
  struct fib6_table* table;
  struct fib6_node* fn;
  struct rt6_info* rt;
  int err = -ESRCH;
  table = fib6_get_table(cfg->fc_nlinfo.nl_net, cfg->fc_table);
  if (!table) return err;
  read_lock_bh(&table->tb6_lock);
  fn = fib6_locate(&table->tb6_root, &cfg->fc_dst, cfg->fc_dst_len,
                   &cfg->fc_src, cfg->fc_src_len);
  if (fn) {
    for (rt = fn->leaf; rt; rt = rt->dst.rt6_next) {
      if (cfg->fc_ifindex &&
          (!rt->dst.dev || rt->dst.dev->ifindex != cfg->fc_ifindex))
        continue;
      if (cfg->fc_flags & RTF_GATEWAY &&
          !ipv6_addr_equal(&cfg->fc_gateway, &rt->rt6i_gateway))
        continue;
      if (cfg->fc_metric && cfg->fc_metric != rt->rt6i_metric) continue;
      dst_hold(&rt->dst);
      read_unlock_bh(&table->tb6_lock);
      return __ip6_del_rt(rt, &cfg->fc_nlinfo);
    }
  }
  read_unlock_bh(&table->tb6_lock);
  return err;
}

void WebProcessProxy::disconnect() {
  clearConnection();
  if (m_webConnection) {
    m_webConnection->invalidate();
    m_webConnection = nullptr;
  }
  m_responsivenessTimer.stop();
  Vector<RefPtr<WebFrameProxy> > frames;
  copyValuesToVector(m_frameMap, frames);
  for (size_t i = 0, size = frames.size(); i < size; ++i)
    frames[i]->disconnect();
  m_frameMap.clear();
  if (m_downloadProxyMap) m_downloadProxyMap->processDidClose();
  m_context->disconnectProcess(this);
}

static int spl_array_skip_protected(spl_array_object* intern,
                                    HashTable* aht TSRMLS_DC) {
  char* string_key;
  uint string_length;
  ulong num_key;
  if (Z_TYPE_P(intern->array) == IS_OBJECT) {
    do {
      if (zend_hash_get_current_key_ex(aht, &string_key, &string_length,
                                       &num_key, 0,
                                       &intern->pos) == HASH_KEY_IS_STRING) {
        if (!string_length || string_key[0] || string_length == 1) {
          return SUCCESS;
        }
      } else {
        return SUCCESS;
      }
      if (zend_hash_has_more_elements_ex(aht, &intern->pos) != SUCCESS) {
        return FAILURE;
      }
      zend_hash_move_forward_ex(aht, &intern->pos);
      spl_array_update_pos(intern);
    } while (1);
  }
  return FAILURE;
}

static void reply_entry(fuse_req_t req, const struct fuse_entry_param* e,
                        int err) {
  if (!err) {
    struct fuse* f = req_fuse(req);
#ifdef __SOLARIS__
    if ((fuse_reply_entry(req, e) == -ENOENT) && (e->ino != 0))
      forget_node(f, e->ino, 1);
#else
    if (fuse_reply_entry(req, e) == -ENOENT) forget_node(f, e->ino, 1);
#endif
  } else
    reply_err(req, err);
}

