callbacks_update_ruler_scales(void) {
  double xStart, xEnd, yStart, yEnd;
  xStart = screenRenderInfo.lowerLeftX;
  yStart = screenRenderInfo.lowerLeftY;
  xEnd = screenRenderInfo.lowerLeftX +
         (screenRenderInfo.displayWidth / screenRenderInfo.scaleFactorX);
  yEnd = screenRenderInfo.lowerLeftY +
         (screenRenderInfo.displayHeight / screenRenderInfo.scaleFactorY);
  if (!((screen.unit == GERBV_MILS) &&
        ((screenRenderInfo.scaleFactorX < 80) ||
         (screenRenderInfo.scaleFactorY < 80)))) {
    xStart = callbacks_calculate_actual_distance(xStart);
    xEnd = callbacks_calculate_actual_distance(xEnd);
    yStart = callbacks_calculate_actual_distance(yStart);
    yEnd = callbacks_calculate_actual_distance(yEnd);
  }
  if (screen.win.hRuler)
    gtk_ruler_set_range(GTK_RULER(screen.win.hRuler), xStart, xEnd, 0,
                        xEnd - xStart);
  if (screen.win.vRuler)
    gtk_ruler_set_range(GTK_RULER(screen.win.vRuler), yEnd, yStart, 0,
                        yEnd - yStart);
}

GF_Err tenc_box_read(GF_Box* s, GF_BitStream* bs) {
  u8 iv_size;
  GF_TrackEncryptionBox* ptr = (GF_TrackEncryptionBox*)s;
  ISOM_DECREASE_SIZE(ptr, 3);
  gf_bs_read_u8(bs);
  if (!ptr->version) {
    gf_bs_read_u8(bs);
  } else {
    ptr->crypt_byte_block = gf_bs_read_int(bs, 4);
    ptr->skip_byte_block = gf_bs_read_int(bs, 4);
  }
  ptr->isProtected = gf_bs_read_u8(bs);
  ISOM_DECREASE_SIZE(ptr, 17);
  ptr->key_info[0] = 0;
  ptr->key_info[1] = 0;
  ptr->key_info[2] = 0;
  ptr->key_info[3] = iv_size = gf_bs_read_u8(bs);
  gf_bs_read_data(bs, ptr->key_info + 4, 16);
  if (!iv_size && ptr->isProtected) {
    ISOM_DECREASE_SIZE(ptr, 1);
    iv_size = ptr->key_info[20] = gf_bs_read_u8(bs);
    ISOM_DECREASE_SIZE(ptr, ptr->key_info[20]);
    if ((iv_size != 8) && (iv_size != 16)) {
      GF_LOG(GF_LOG_ERROR, GF_LOG_CONTAINER,
             ("[iso file] Invalid constant IV size %d, must be 8 or 16\n",
              (u32)iv_size));
      ptr->key_info[20] = 16;
      return GF_NON_COMPLIANT_BITSTREAM;
    }
    gf_bs_read_data(bs, ptr->key_info + 21, iv_size);
  } else if ((iv_size != 0) && (iv_size != 8) && (iv_size != 16)) {
    GF_LOG(
        GF_LOG_ERROR, GF_LOG_CONTAINER,
        ("[iso file] Invalid IV size %d, must be 0, 8 or 16\n", (u32)iv_size));
    return GF_NON_COMPLIANT_BITSTREAM;
  }
  return GF_OK;
}

static void pp_pre_command(const char* what, char* string) {
  char* cmd;
  Token *def, *space;
  Line* l;
  def = tokenize(string);
  if (what) {
    space = new_White(def);
    cmd = nasm_strcat(what[0] == '%' ? "" : "%", what);
    def = new_Token(space, TOK_PREPROC_ID, cmd, nasm_last_string_len());
    nasm_free(cmd);
  }
  l = nasm_malloc(sizeof(Line));
  l->next = predef;
  l->first = def;
  l->finishes = NULL;
  predef = l;
}

void ThreadWatcherList::ParseCommandLine(
    const base::CommandLine& command_line, uint32* unresponsive_threshold,
    CrashOnHangThreadMap* crash_on_hang_threads) {
  *unresponsive_threshold = kUnresponsiveCount;
  version_info::Channel channel = chrome::GetChannel();
  if (channel == version_info::Channel::STABLE) {
    *unresponsive_threshold *= 4;
  } else if (channel == version_info::Channel::BETA) {
    *unresponsive_threshold *= 2;
  }
#if defined(OS_WIN)
  if (base::win::GetVersion() <= base::win::VERSION_XP)
    *unresponsive_threshold *= 2;
#endif
  uint32 crash_seconds = *unresponsive_threshold * kUnresponsiveSeconds;
  std::string crash_on_hang_thread_names;
  if (command_line.HasSwitch(switches::kCrashOnHangThreads)) {
    crash_on_hang_thread_names =
        command_line.GetSwitchValueASCII(switches::kCrashOnHangThreads);
  } else if (channel != version_info::Channel::STABLE) {
    crash_on_hang_thread_names = base::StringPrintf(
        "UI:%d:%d,IO:%d:%d,FILE:%d:%d", kLiveThreadsThreshold, crash_seconds,
        kLiveThreadsThreshold, crash_seconds, kLiveThreadsThreshold,
        crash_seconds * 5);
  }
  ParseCommandLineCrashOnHangThreads(crash_on_hang_thread_names,
                                     kLiveThreadsThreshold, crash_seconds,
                                     crash_on_hang_threads);
}

void RenderView::didFailProvisionalLoad(WebFrame* frame,
                                        const WebURLError& error) {
  WebDataSource* ds = frame->provisionalDataSource();
  DCHECK(ds);
  const WebURLRequest& failed_request = ds->request();
  bool show_repost_interstitial =
      (error.reason == net::ERR_CACHE_MISS &&
       EqualsASCII(failed_request.httpMethod(), "POST"));
  Send(new ViewHostMsg_DidFailProvisionalLoadWithError(
      routing_id_, !frame->parent(), error.reason, error.unreachableURL,
      show_repost_interstitial));
  if (error.reason == net::ERR_ABORTED) return;
  frame->enableViewSourceMode(false);
  NavigationState* navigation_state = NavigationState::FromDataSource(ds);
  bool replace =
      navigation_state->pending_page_id() != -1 ||
      navigation_state->transition_type() == PageTransition::AUTO_SUBFRAME;
  if (!navigation_state->is_content_initiated()) {
    pending_navigation_state_.reset(NavigationState::CreateBrowserInitiated(
        navigation_state->pending_page_id(),
        navigation_state->pending_history_list_offset(),
        navigation_state->transition_type(), navigation_state->request_time()));
  }
  if (MaybeLoadAlternateErrorPage(frame, error, replace)) return;
  LoadNavigationErrorPage(frame, failed_request, error, std::string(), replace);
}

static void perf_event_exit_task_context(struct task_struct* child, int ctxn) {
  struct perf_event *child_event, *tmp;
  struct perf_event_context* child_ctx;
  unsigned long flags;
  if (likely(!child->perf_event_ctxp[ctxn])) {
    perf_event_task(child, NULL, 0);
    return;
  }
  local_irq_save(flags);
  child_ctx = rcu_dereference_raw(child->perf_event_ctxp[ctxn]);
  raw_spin_lock(&child_ctx->lock);
  task_ctx_sched_out(child_ctx);
  child->perf_event_ctxp[ctxn] = NULL;
  unclone_ctx(child_ctx);
  update_context_time(child_ctx);
  raw_spin_unlock_irqrestore(&child_ctx->lock, flags);
  perf_event_task(child, child_ctx, 0);
  mutex_lock(&child_ctx->mutex);
again:
  list_for_each_entry_safe(child_event, tmp, &child_ctx->pinned_groups,
                           group_entry)
      __perf_event_exit_task(child_event, child_ctx, child);
  list_for_each_entry_safe(child_event, tmp, &child_ctx->flexible_groups,
                           group_entry)
      __perf_event_exit_task(child_event, child_ctx, child);
  if (!list_empty(&child_ctx->pinned_groups) ||
      !list_empty(&child_ctx->flexible_groups))
    goto again;
  mutex_unlock(&child_ctx->mutex);
  put_ctx(child_ctx);
}

v8::Handle<v8::Value> V8DOMWrapper::convertCSSValueToV8Object(CSSValue* value) {
  if (!value) return v8::Null();
  v8::Handle<v8::Object> wrapper = getDOMObjectMap().get(value);
  if (!wrapper.IsEmpty()) return wrapper;
  V8ClassIndex::V8WrapperType type;
  if (value->isWebKitCSSTransformValue())
    type = V8ClassIndex::WEBKITCSSTRANSFORMVALUE;
  else if (value->isValueList())
    type = V8ClassIndex::CSSVALUELIST;
  else if (value->isPrimitiveValue())
    type = V8ClassIndex::CSSPRIMITIVEVALUE;
#if ENABLE(SVG)
  else if (value->isSVGPaint())
    type = V8ClassIndex::SVGPAINT;
  else if (value->isSVGColor())
    type = V8ClassIndex::SVGCOLOR;
#endif
  else
    type = V8ClassIndex::CSSVALUE;
  v8::Handle<v8::Object> result =
      instantiateV8Object(type, V8ClassIndex::CSSVALUE, value);
  if (!result.IsEmpty()) {
    value->ref();
    setJSWrapperForDOMObject(value, v8::Persistent<v8::Object>::New(result));
  }
  return result;
}

static STACK_OF(X509) * load_all_certs_from_file(char* certfile) {
  STACK_OF(X509_INFO)* sk = NULL;
  STACK_OF(X509)* stack = NULL, *ret = NULL;
  BIO* in = NULL;
  X509_INFO* xi;
  TSRMLS_FETCH();
  if (!(stack = sk_X509_new_null())) {
    php_error_docref(NULL TSRMLS_CC, E_ERROR, "memory allocation failure");
    goto end;
  }
  if (php_openssl_safe_mode_chk(certfile TSRMLS_CC)) {
    sk_X509_free(stack);
    goto end;
  }
  if (!(in = BIO_new_file(certfile, "r"))) {
    php_error_docref(NULL TSRMLS_CC, E_WARNING, "error opening the file, %s",
                     certfile);
    sk_X509_free(stack);
    goto end;
  }
  if (!(sk = PEM_X509_INFO_read_bio(in, NULL, NULL, NULL))) {
    php_error_docref(NULL TSRMLS_CC, E_WARNING, "error reading the file, %s",
                     certfile);
    sk_X509_free(stack);
    goto end;
  }
  while (sk_X509_INFO_num(sk)) {
    xi = sk_X509_INFO_shift(sk);
    if (xi->x509 != NULL) {
      sk_X509_push(stack, xi->x509);
      xi->x509 = NULL;
    }
    X509_INFO_free(xi);
  }
  if (!sk_X509_num(stack)) {
    php_error_docref(NULL TSRMLS_CC, E_WARNING, "no certificates in file, %s",
                     certfile);
    sk_X509_free(stack);
    goto end;
  }
  ret = stack;
end:
  BIO_free(in);
  sk_X509_INFO_free(sk);
  return ret;
}

