struct kobject* get_disk(struct gendisk* disk) {
  struct module* owner;
  struct kobject* kobj;
  if (!disk->fops) return NULL;
  owner = disk->fops->owner;
  if (owner && !try_module_get(owner)) return NULL;
  kobj = kobject_get(&disk_to_dev(disk)->kobj);
  if (kobj == NULL) {
    module_put(owner);
    return NULL;
  }
  return kobj;
}

static void process_slab(struct loc_track* t, struct kmem_cache* s,
                         struct page* page, enum track_item alloc) {
  void* addr = page_address(page);
  void* p;
  unsigned long* map;
  map = get_map(s, page);
  for_each_object(p, s, addr,
                  page->objects) if (!test_bit(slab_index(p, s, addr), map))
      add_location(t, s, get_track(s, p, alloc));
  put_map(map);
}

mbc_enc_len(const UChar* p, const UChar* e, OnigEncoding enc ARG_UNUSED) {
  int firstbyte = *p++;
  state_t s;
  s = trans[0][firstbyte];
  if (s < 0)
    return s == ACCEPT ? ONIGENC_CONSTRUCT_MBCLEN_CHARFOUND(1)
                       : ONIGENC_CONSTRUCT_MBCLEN_INVALID();
  if (p == e)
    return ONIGENC_CONSTRUCT_MBCLEN_NEEDMORE(EncLen_EUCJP[firstbyte] - 1);
  s = trans[s][*p++];
  if (s < 0)
    return s == ACCEPT ? ONIGENC_CONSTRUCT_MBCLEN_CHARFOUND(2)
                       : ONIGENC_CONSTRUCT_MBCLEN_INVALID();
  if (p == e)
    return ONIGENC_CONSTRUCT_MBCLEN_NEEDMORE(EncLen_EUCJP[firstbyte] - 2);
  s = trans[s][*p++];
  return s == ACCEPT ? ONIGENC_CONSTRUCT_MBCLEN_CHARFOUND(3)
                     : ONIGENC_CONSTRUCT_MBCLEN_INVALID();
}

reportDefault(XML_Parser parser, const ENCODING* enc, const char* s,
              const char* end) {
  if (MUST_CONVERT(enc, s)) {
    enum XML_Convert_Result convert_res;
    const char** eventPP;
    const char** eventEndPP;
    if (enc == parser->m_encoding) {
      eventPP = &parser->m_eventPtr;
      eventEndPP = &parser->m_eventEndPtr;
    } else {
      eventPP = &(parser->m_openInternalEntities->internalEventPtr);
      eventEndPP = &(parser->m_openInternalEntities->internalEventEndPtr);
    }
    do {
      ICHAR* dataPtr = (ICHAR*)parser->m_dataBuf;
      convert_res =
          XmlConvert(enc, &s, end, &dataPtr, (ICHAR*)parser->m_dataBufEnd);
      *eventEndPP = s;
      parser->m_defaultHandler(parser->m_handlerArg, parser->m_dataBuf,
                               (int)(dataPtr - (ICHAR*)parser->m_dataBuf));
      *eventPP = s;
    } while ((convert_res != XML_CONVERT_COMPLETED) &&
             (convert_res != XML_CONVERT_INPUT_INCOMPLETE));
  } else
    parser->m_defaultHandler(parser->m_handlerArg, (XML_Char*)s,
                             (int)((XML_Char*)end - (XML_Char*)s));
}

static void mmf_recalc_uprobes(struct mm_struct* mm) {
  struct vm_area_struct* vma;
