}

static int futex_wait(u32 __user* uaddr, unsigned int flags, u32 val,
                      ktime_t* abs_time, u32 bitset) {
  struct hrtimer_sleeper timeout, *to = NULL;
  struct restart_block* restart;
  struct futex_hash_bucket* hb;
  struct futex_q q = futex_q_init;
  int ret;
  if (!bitset) return -EINVAL;
  q.bitset = bitset;
  if (abs_time) {
    to = &timeout;
    hrtimer_init_on_stack(
        &to->timer, (flags & FLAGS_CLOCKRT) ? CLOCK_REALTIME : CLOCK_MONOTONIC,
        HRTIMER_MODE_ABS);
    hrtimer_init_sleeper(to, current);
    hrtimer_set_expires_range_ns(&to->timer, *abs_time,
                                 current->timer_slack_ns);
  }
retry:
  ret = futex_wait_setup(uaddr, val, flags, &q, &hb);
  if (ret) goto out;
  futex_wait_queue_me(hb, &q, to);
  ret = 0;
  if (!unqueue_me(&q)) goto out;
  ret = -ETIMEDOUT;
  if (to && !to->task) goto out;
  if (!signal_pending(current)) goto retry;
  ret = -ERESTARTSYS;
  if (!abs_time) goto out;
  restart = &current->restart_block;
  restart->fn = futex_wait_restart;
  restart->futex.uaddr = uaddr;
  restart->futex.val = val;
  restart->futex.time = *abs_time;
  restart->futex.bitset = bitset;
  restart->futex.flags = flags | FLAGS_HAS_TIMEOUT;
  ret = -ERESTART_RESTARTBLOCK;
out:
  if (to) {
    hrtimer_cancel(&to->timer);
    destroy_hrtimer_on_stack(&to->timer);
  }
  return ret;
}

void LIRGenerator::do_NewTypeArray(NewTypeArray* x) {
  CodeEmitInfo* info = state_for(x, x->state());
  LIRItem length(x->length(), this);
  length.load_item_force(FrameMap::rbx_opr);
  LIR_Opr reg = result_register_for(x->type());
  LIR_Opr tmp1 = FrameMap::rcx_oop_opr;
  LIR_Opr tmp2 = FrameMap::rsi_oop_opr;
  LIR_Opr tmp3 = FrameMap::rdi_oop_opr;
  LIR_Opr tmp4 = reg;
  LIR_Opr klass_reg = FrameMap::rdx_metadata_opr;
  LIR_Opr len = length.result();
  BasicType elem_type = x->elt_type();
  __ metadata2reg(ciTypeArrayKlass::make(elem_type)->constant_encoding(),
                  klass_reg);
