v8::Handle<v8::Value> V8DOMWrapper::convertEventToV8Object(Event* event) {
  if (!event) return v8::Null();
  v8::Handle<v8::Object> wrapper = getDOMObjectMap().get(event);
  if (!wrapper.IsEmpty()) return wrapper;
  V8ClassIndex::V8WrapperType type = V8ClassIndex::EVENT;
  if (event->isUIEvent()) {
    if (event->isKeyboardEvent())
      type = V8ClassIndex::KEYBOARDEVENT;
    else if (event->isTextEvent())
      type = V8ClassIndex::TEXTEVENT;
    else if (event->isMouseEvent())
      type = V8ClassIndex::MOUSEEVENT;
    else if (event->isWheelEvent())
      type = V8ClassIndex::WHEELEVENT;
#if ENABLE(SVG)
    else if (event->isSVGZoomEvent())
      type = V8ClassIndex::SVGZOOMEVENT;
#endif
    else
      type = V8ClassIndex::UIEVENT;
  } else if (event->isMutationEvent())
    type = V8ClassIndex::MUTATIONEVENT;
  else if (event->isOverflowEvent())
    type = V8ClassIndex::OVERFLOWEVENT;
  else if (event->isMessageEvent())
    type = V8ClassIndex::MESSAGEEVENT;
  else if (event->isProgressEvent()) {
    if (event->isXMLHttpRequestProgressEvent())
      type = V8ClassIndex::XMLHTTPREQUESTPROGRESSEVENT;
    else
      type = V8ClassIndex::PROGRESSEVENT;
  } else if (event->isWebKitAnimationEvent())
    type = V8ClassIndex::WEBKITANIMATIONEVENT;
  else if (event->isWebKitTransitionEvent())
    type = V8ClassIndex::WEBKITTRANSITIONEVENT;
#if ENABLE(WORKERS)
  else if (event->isErrorEvent())
    type = V8ClassIndex::ERROREVENT;
#endif
  v8::Handle<v8::Object> result =
      instantiateV8Object(type, V8ClassIndex::EVENT, event);
  if (result.IsEmpty()) {
    return v8::Null();
  }
  event->ref();
  setJSWrapperForDOMObject(event, v8::Persistent<v8::Object>::New(result));
  return result;
}

static int lua_ap_strcmp_match(lua_State* L) {
  int returnValue;
  const char* str;
  const char* expected;
  int ignoreCase = 0;
  luaL_checktype(L, 1, LUA_TSTRING);
  str = lua_tostring(L, 1);
  luaL_checktype(L, 2, LUA_TSTRING);
  expected = lua_tostring(L, 2);
  if (lua_isboolean(L, 3)) ignoreCase = lua_toboolean(L, 3);
  if (!ignoreCase)
    returnValue = ap_strcmp_match(str, expected);
  else
    returnValue = ap_strcasecmp_match(str, expected);
  lua_pushboolean(L, (!returnValue));
  return 1;
}

static int wcd9335_bring_up(struct wcd9335_codec* wcd) {
  struct regmap* rm = wcd->regmap;
  int val, byte0;
  regmap_read(rm, WCD9335_CHIP_TIER_CTRL_EFUSE_VAL_OUT0, &val);
  regmap_read(rm, WCD9335_CHIP_TIER_CTRL_CHIP_ID_BYTE0, &byte0);
  if ((val < 0) || (byte0 < 0)) {
    dev_err(wcd->dev, "WCD9335 CODEC version detection fail!\n");
    return -EINVAL;
  }
  if (byte0 == 0x1) {
    dev_info(wcd->dev, "WCD9335 CODEC version is v2.0\n");
    wcd->version = WCD9335_VERSION_2_0;
    regmap_write(rm, WCD9335_CODEC_RPM_RST_CTL, 0x01);
    regmap_write(rm, WCD9335_SIDO_SIDO_TEST_2, 0x00);
    regmap_write(rm, WCD9335_SIDO_SIDO_CCL_8, 0x6F);
    regmap_write(rm, WCD9335_BIAS_VBG_FINE_ADJ, 0x65);
    regmap_write(rm, WCD9335_CODEC_RPM_PWR_CDC_DIG_HM_CTL, 0x5);
    regmap_write(rm, WCD9335_CODEC_RPM_PWR_CDC_DIG_HM_CTL, 0x7);
    regmap_write(rm, WCD9335_CODEC_RPM_PWR_CDC_DIG_HM_CTL, 0x3);
    regmap_write(rm, WCD9335_CODEC_RPM_RST_CTL, 0x3);
  } else {
    dev_err(wcd->dev, "WCD9335 CODEC version not supported\n");
    return -EINVAL;
  }
  return 0;
}

static int snd_ctl_dev_disconnect(struct snd_device* device) {
  struct snd_card* card = device->device_data;
  struct snd_ctl_file* ctl;
  int err, cardnum;
  if (snd_BUG_ON(!card)) return -ENXIO;
  cardnum = card->number;
  if (snd_BUG_ON(cardnum < 0 || cardnum >= SNDRV_CARDS)) return -ENXIO;
  read_lock(&card->ctl_files_rwlock);
  list_for_each_entry(ctl, &card->ctl_files, list) {
    wake_up(&ctl->change_sleep);
    kill_fasync(&ctl->fasync, SIGIO, POLL_ERR);
  }
  read_unlock(&card->ctl_files_rwlock);
  if ((err = snd_unregister_device(SNDRV_DEVICE_TYPE_CONTROL, card, -1)) < 0)
    return err;
  return 0;
}

int sctp_do_peeloff(struct sock* sk, sctp_assoc_t id, struct socket** sockp) {
  struct sctp_association* asoc = sctp_id2assoc(sk, id);
  struct sctp_sock* sp = sctp_sk(sk);
  struct socket* sock;
  int err = 0;
  if (!asoc) return -EINVAL;
  if (waitqueue_active(&asoc->wait)) return -EBUSY;
  if (!sctp_style(sk, UDP)) return -EINVAL;
  err = sock_create(sk->sk_family, SOCK_SEQPACKET, IPPROTO_SCTP, &sock);
  if (err < 0) return err;
  sctp_copy_sock(sock->sk, sk, asoc);
  sp->pf->to_sk_daddr(&asoc->peer.primary_addr, sk);
  sctp_sock_migrate(sk, sock->sk, asoc, SCTP_SOCKET_UDP_HIGH_BANDWIDTH);
  *sockp = sock;
  return err;
}

