OPJ_BOOL opj_j2k_set_decoded_resolution_factor(opj_j2k_t* p_j2k,
                                               OPJ_UINT32 res_factor,
                                               opj_event_mgr_t* p_manager) {
  OPJ_UINT32 it_comp;
  p_j2k->m_cp.m_specific_param.m_dec.m_reduce = res_factor;
  if (p_j2k->m_private_image) {
    if (p_j2k->m_private_image->comps) {
      if (p_j2k->m_specific_param.m_decoder.m_default_tcp) {
        if (p_j2k->m_specific_param.m_decoder.m_default_tcp->tccps) {
          for (it_comp = 0; it_comp < p_j2k->m_private_image->numcomps;
               it_comp++) {
            OPJ_UINT32 max_res =
                p_j2k->m_specific_param.m_decoder.m_default_tcp->tccps[it_comp]
                    .numresolutions;
            if (res_factor >= max_res) {
              opj_event_msg(p_manager, EVT_ERROR,
                            "Resolution factor is greater than the maximum "
                            "resolution in the component.\n");
              return OPJ_FALSE;
            }
            p_j2k->m_private_image->comps[it_comp].factor = res_factor;
          }
          return OPJ_TRUE;
        }
      }
    }
  }
  return OPJ_FALSE;
}

sc_pkcs15emu_get_df(sc_pkcs15_card_t* p15card, unsigned int type) {
  sc_pkcs15_df_t* df;
  sc_file_t* file;
  int created = 0;
  while (1) {
    for (df = p15card->df_list; df; df = df->next) {
      if (df->type == type) {
        if (created) df->enumerated = 1;
        return df;
      }
    }
    assert(created == 0);
    file = sc_file_new();
    if (!file) return NULL;
    sc_format_path("11001101", &file->path);
    sc_pkcs15_add_df(p15card, type, &file->path);
    sc_file_free(file);
    created++;
  }
}

static int decode_delegation(struct xdr_stream* xdr, struct nfs_openres* res) {
  __be32* p;
  uint32_t delegation_type;
  int status;
  p = xdr_inline_decode(xdr, 4);
  if (unlikely(!p)) goto out_overflow;
  delegation_type = be32_to_cpup(p);
  if (delegation_type == NFS4_OPEN_DELEGATE_NONE) {
    res->delegation_type = 0;
    return 0;
  }
  status = decode_stateid(xdr, &res->delegation);
  if (unlikely(status)) return status;
  p = xdr_inline_decode(xdr, 4);
  if (unlikely(!p)) goto out_overflow;
  res->do_recall = be32_to_cpup(p);
  switch (delegation_type) {
    case NFS4_OPEN_DELEGATE_READ:
      res->delegation_type = FMODE_READ;
      break;
    case NFS4_OPEN_DELEGATE_WRITE:
      res->delegation_type = FMODE_WRITE | FMODE_READ;
      if (decode_space_limit(xdr, &res->maxsize) < 0) return -EIO;
  }
  return decode_ace(xdr, NULL, res->server->nfs_client);
out_overflow:
  print_overflow_msg(__func__, xdr);
  return -EIO;
}

static void cswitch(JF, js_Ast* ref, js_Ast* head) {
  js_Ast *node, *clause, *def = NULL;
  int end;
  cexp(J, F, ref);
  for (node = head; node; node = node->b) {
    clause = node->a;
    if (clause->type == STM_DEFAULT) {
      if (def) jsC_error(J, clause, "more than one default label in switch");
      def = clause;
    } else {
      cexp(J, F, clause->a);
      clause->casejump = emitjump(J, F, OP_JCASE);
    }
  }
  emit(J, F, OP_POP);
  if (def) {
    def->casejump = emitjump(J, F, OP_JUMP);
    end = 0;
  } else {
    end = emitjump(J, F, OP_JUMP);
  }
  for (node = head; node; node = node->b) {
    clause = node->a;
    label(J, F, clause->casejump);
    if (clause->type == STM_DEFAULT)
      cstmlist(J, F, clause->a);
    else
      cstmlist(J, F, clause->b);
  }
  if (end) label(J, F, end);
}

event_filter(GdkXEvent* xevent, GdkEvent* event, gpointer data) {
  GsdXrandrManager* manager = data;
  XEvent* xev = (XEvent*)xevent;
  if (!manager->priv->running) return GDK_FILTER_CONTINUE;
  if (xev->xany.type != KeyPress && xev->xany.type != KeyRelease)
    return GDK_FILTER_CONTINUE;
  if (xev->xany.type == KeyPress &&
      xev->xkey.keycode == manager->priv->keycode) {
    handle_fn_f7(manager, xev->xkey.time);
    return GDK_FILTER_CONTINUE;
  }
  return GDK_FILTER_CONTINUE;
}

