TypedValue HHVM_FUNCTION(array_column, ArrayArg input, const Variant& val_key,
                         const Variant& idx_key) {
  ArrNR arr_input(input.get());
  Variant val = val_key, idx = idx_key;
  if (!array_column_coerce_key(val, "column") ||
      !array_column_coerce_key(idx, "index")) {
    return make_tv<KindOfBoolean>(false);
  }
  ArrayInit ret(input->size(), ArrayInit::Map{});
  for (auto it = arr_input.asArray().begin(); !it.end(); it.next()) {
    if (!it.second().isArray()) {
      continue;
    }
    Array sub = it.second().toArray();
    Variant elem;
    if (val.isNull()) {
      elem = sub;
    } else if (sub.exists(val)) {
      elem = sub[val];
    } else {
      continue;
    }
    if (idx.isNull() || !sub.exists(idx)) {
      ret.append(elem);
    } else if (sub[idx].isObject()) {
      ret.setUnknownKey(sub[idx].toString(), elem);
    } else {
      ret.setUnknownKey(sub[idx], elem);
    }
  }
  return tvReturn(ret.toVariant());
}

void CiffComponent::doRead(const byte* pData, uint32_t size, uint32_t start,
                           ByteOrder byteOrder) {
  enforce(size >= 10 && start <= size - 10, kerNotACrwImage);
  tag_ = getUShort(pData + start, byteOrder);
  DataLocId dl = dataLocation();
  assert(dl == directoryData || dl == valueData);
  if (dl == valueData) {
    size_ = getULong(pData + start + 2, byteOrder);
    offset_ = getULong(pData + start + 6, byteOrder);
    if (offset_ < start) {
      enforce(size_ <= start - offset_, kerOffsetOutOfRange);
    } else {
      enforce(offset_ >= start + 10, kerOffsetOutOfRange);
      enforce(offset_ <= size, kerOffsetOutOfRange);
      enforce(size_ <= size - offset_, kerOffsetOutOfRange);
    }
  }
  if (dl == directoryData) {
    size_ = 8;
    offset_ = start + 2;
  }
  pData_ = pData + offset_;
#ifdef EXIV2_DEBUG_MESSAGES
  std::cout << "  Entry for tag 0x" << std::hex << tagId() << " (0x" << tag()
            << "), " << std::dec << size_ << " Bytes, Offset is " << offset_
            << "\n";
#endif
}

static void avrcp_register_notification(struct avrcp* session, uint8_t event) {
  uint8_t buf[AVRCP_HEADER_LENGTH + AVRCP_REGISTER_NOTIFICATION_PARAM_LENGTH];
  struct avrcp_header* pdu = (void*)buf;
  uint8_t length;
  memset(buf, 0, sizeof(buf));
  set_company_id(pdu->company_id, IEEEID_BTSIG);
  pdu->pdu_id = AVRCP_REGISTER_NOTIFICATION;
  pdu->packet_type = AVRCP_PACKET_TYPE_SINGLE;
  pdu->params[0] = event;
  if (event == AVRCP_EVENT_PLAYBACK_POS_CHANGED)
    bt_put_be32(UINT32_MAX / 1000, &pdu->params[1]);
  pdu->params_len = htons(AVRCP_REGISTER_NOTIFICATION_PARAM_LENGTH);
  length = AVRCP_HEADER_LENGTH + ntohs(pdu->params_len);
  avctp_send_vendordep_req(session->conn, AVC_CTYPE_NOTIFY, AVC_SUBUNIT_PANEL,
                           buf, length, avrcp_handle_event, session);
}

pam_sm_acct_mgmt(pam_handle_t* pamh, int flags UNUSED, int argc,
                 const char** argv) {
  const char* username;
  const char* database = NULL;
  const char* cryptmode = NULL;
  int retval = PAM_AUTH_ERR, ctrl;
  ctrl = _pam_parse(pamh, argc, argv, &database, &cryptmode);
  retval = pam_get_user(pamh, &username, NULL);
  if ((retval != PAM_SUCCESS) || (!username)) {
    pam_syslog(pamh, LOG_ERR, "can not get the username");
    return PAM_SERVICE_ERR;
  }
  retval = user_lookup(pamh, database, cryptmode, username, "", ctrl);
  switch (retval) {
    case -2:
      return PAM_SERVICE_ERR;
    case -1:
    case 0:
      return PAM_SUCCESS;
    case 1:
      return PAM_USER_UNKNOWN;
    default:
      pam_syslog(pamh, LOG_ERR,
                 "internal module error (retval = %d, user = `%s'", retval,
                 username);
      return PAM_SERVICE_ERR;
  }
  return PAM_SUCCESS;
}

bool XSSAuditor::filterStartToken(const FilterTokenRequest& request) {
  m_state = FilteringTokens;
  bool didBlockScript = eraseDangerousAttributesIfInjected(request);
  if (hasName(request.token, scriptTag)) {
    didBlockScript |= filterScriptToken(request);
    ASSERT(request.shouldAllowCDATA || !m_scriptTagNestingLevel);
    m_scriptTagNestingLevel++;
  } else if (hasName(request.token, objectTag))
    didBlockScript |= filterObjectToken(request);
  else if (hasName(request.token, paramTag))
    didBlockScript |= filterParamToken(request);
  else if (hasName(request.token, embedTag))
    didBlockScript |= filterEmbedToken(request);
  else if (hasName(request.token, appletTag))
    didBlockScript |= filterAppletToken(request);
  else if (hasName(request.token, iframeTag) ||
           hasName(request.token, frameTag))
    didBlockScript |= filterFrameToken(request);
  else if (hasName(request.token, metaTag))
    didBlockScript |= filterMetaToken(request);
  else if (hasName(request.token, baseTag))
    didBlockScript |= filterBaseToken(request);
  else if (hasName(request.token, formTag))
    didBlockScript |= filterFormToken(request);
  else if (hasName(request.token, inputTag))
    didBlockScript |= filterInputToken(request);
  else if (hasName(request.token, buttonTag))
    didBlockScript |= filterButtonToken(request);
  return didBlockScript;
}

add_key_part(DYNAMIC_ARRAY* keyuse_array, KEY_FIELD* key_field) {
  Field* field = key_field->field;
  TABLE* form = field->table;
  if (key_field->eq_func && !(key_field->optimize & KEY_OPTIMIZE_EXISTS)) {
    for (uint key = 0; key < form->s->keys; key++) {
      if (!(form->keys_in_use_for_query.is_set(key))) continue;
      if (form->key_info[key].flags & (HA_FULLTEXT | HA_SPATIAL)) continue;
      KEY* keyinfo = form->key_info + key;
      uint key_parts = form->actual_n_key_parts(keyinfo);
      for (uint part = 0; part < key_parts; part++) {
        if (field->eq(form->key_info[key].key_part[part].field) &&
            field->can_optimize_keypart_ref(key_field->cond, key_field->val)) {
          if (add_keyuse(keyuse_array, key_field, key, part)) return TRUE;
        }
      }
    }
    if (field->hash_join_is_possible() &&
        (key_field->optimize & KEY_OPTIMIZE_EQ) &&
        key_field->val->used_tables()) {
      if (!field->can_optimize_hash_join(key_field->cond, key_field->val))
        return false;
      if (form->is_splittable())
        form->add_splitting_info_for_key_field(key_field);
      if (add_keyuse(keyuse_array, key_field, get_hash_join_key_no(), 0))
        return TRUE;
    }
  }
  return FALSE;
}

intrusive_ptr<Expression> Expression::parseOperand(
    ExpressionContext* const expCtx, BSONElement exprElement,
    const VariablesParseState& vps) {
  BSONType type = exprElement.type();
  if (type == String && exprElement.valuestr()[0] == '$') {
    return ExpressionFieldPath::parse(expCtx, exprElement.str(), vps);
  } else if (type == Object) {
    return Expression::parseObject(expCtx, exprElement.Obj(), vps);
  } else if (type == Array) {
    return ExpressionArray::parse(expCtx, exprElement, vps);
  } else {
    return ExpressionConstant::parse(expCtx, exprElement, vps);
  }
}

static int mov_read_dvcc_dvvc(MOVContext* c, AVIOContext* pb, MOVAtom atom) {
  AVStream* st;
  uint8_t buf[ISOM_DVCC_DVVC_SIZE];
  int ret;
  int64_t read_size = atom.size;
  if (c->fc->nb_streams < 1) return 0;
  st = c->fc->streams[c->fc->nb_streams - 1];
  read_size = FFMIN(read_size, ISOM_DVCC_DVVC_SIZE);
  if ((ret = ffio_read_size(pb, buf, read_size)) < 0) return ret;
  return ff_isom_parse_dvcc_dvvc(c->fc, st, buf, read_size);
}

void Document::WillChangeFrameOwnerProperties(int margin_width,
                                              int margin_height,
                                              ScrollbarMode scrolling_mode,
                                              bool is_display_none) {
  DCHECK(GetFrame() && GetFrame()->Owner());
  FrameOwner* owner = GetFrame()->Owner();
  if (RuntimeEnabledFeatures::DisplayNoneIFrameCreatesNoLayoutObjectEnabled()) {
    if (documentElement()) {
      if (is_display_none != owner->IsDisplayNone())
        documentElement()->LazyReattachIfAttached();
    }
  }
  if (!body()) return;
  if (margin_width != owner->MarginWidth())
    body()->SetIntegralAttribute(marginwidthAttr, margin_width);
  if (margin_height != owner->MarginHeight())
    body()->SetIntegralAttribute(marginheightAttr, margin_height);
  if (scrolling_mode != owner->ScrollingMode() && View())
    View()->SetNeedsLayout();
}

read_symlink_stored(struct archive_read* a, struct archive_entry* entry,
                    struct archive_string_conv* sconv) {
  const void* h;
  const char* p;
  struct rar* rar;
  int ret = (ARCHIVE_OK);
  rar = (struct rar*)(a->format->data);
  if ((h = rar_read_ahead(a, (size_t)rar->packed_size, NULL)) == NULL)
    return (ARCHIVE_FATAL);
  p = h;
  if (archive_entry_copy_symlink_l(entry, p, (size_t)rar->packed_size, sconv)) {
    if (errno == ENOMEM) {
      archive_set_error(&a->archive, ENOMEM, "Can't allocate memory for link");
      return (ARCHIVE_FATAL);
    }
    archive_set_error(&a->archive, ARCHIVE_ERRNO_FILE_FORMAT,
                      "link cannot be converted from %s to current locale.",
                      archive_string_conversion_charset_name(sconv));
    ret = (ARCHIVE_WARN);
  }
  __archive_read_consume(a, rar->packed_size);
  return ret;
}

static void Ins_SZP0(INS_ARG) {
