static int power_pmu_add(struct perf_event* event, int ef_flags) {
  struct cpu_hw_events* cpuhw;
  unsigned long flags;
  int n0;
  int ret = -EAGAIN;
  local_irq_save(flags);
  perf_pmu_disable(event->pmu);
  cpuhw = &__get_cpu_var(cpu_hw_events);
  n0 = cpuhw->n_events;
  if (n0 >= ppmu->n_counter) goto out;
  cpuhw->event[n0] = event;
  cpuhw->events[n0] = event->hw.config;
  cpuhw->flags[n0] = event->hw.event_base;
  if (!(ef_flags & PERF_EF_START))
    event->hw.state = PERF_HES_STOPPED | PERF_HES_UPTODATE;
  if (cpuhw->group_flag & PERF_EVENT_TXN) goto nocheck;
  if (check_excludes(cpuhw->event, cpuhw->flags, n0, 1)) goto out;
  if (power_check_constraints(cpuhw, cpuhw->events, cpuhw->flags, n0 + 1))
    goto out;
  event->hw.config = cpuhw->events[n0];
nocheck:
  ++cpuhw->n_events;
  ++cpuhw->n_added;
  ret = 0;
out:
  perf_pmu_enable(event->pmu);
  local_irq_restore(flags);
  return ret;
}

rb_reset_tail(struct ring_buffer_per_cpu* cpu_buffer, unsigned long tail,
              struct rb_event_info* info) {
  struct buffer_page* tail_page = info->tail_page;
  struct ring_buffer_event* event;
  unsigned long length = info->length;
  if (tail >= BUF_PAGE_SIZE) {
    if (tail == BUF_PAGE_SIZE) tail_page->real_end = 0;
    local_sub(length, &tail_page->write);
    return;
  }
  event = __rb_page_index(tail_page, tail);
  kmemcheck_annotate_bitfield(event, bitfield);
  local_add(BUF_PAGE_SIZE - tail, &cpu_buffer->entries_bytes);
  tail_page->real_end = tail;
  if (tail > (BUF_PAGE_SIZE - RB_EVNT_MIN_SIZE)) {
    rb_event_set_padding(event);
    local_sub(length, &tail_page->write);
    return;
  }
  event->array[0] = (BUF_PAGE_SIZE - tail) - RB_EVNT_HDR_SIZE;
  event->type_len = RINGBUF_TYPE_PADDING;
  event->time_delta = 1;
  length = (tail + length) - BUF_PAGE_SIZE;
  local_sub(length, &tail_page->write);
}

static unsigned int ppp_poll(struct file* file, poll_table* wait) {
  struct ppp_file* pf = file->private_data;
  unsigned int mask;
  if (!pf) return 0;
  poll_wait(file, &pf->rwait, wait);
  mask = POLLOUT | POLLWRNORM;
  if (skb_peek(&pf->rq)) mask |= POLLIN | POLLRDNORM;
  if (pf->dead)
    mask |= POLLHUP;
  else if (pf->kind == INTERFACE) {
    struct ppp* ppp = PF_TO_PPP(pf);
    if (ppp->n_channels == 0 && (ppp->flags & SC_LOOP_TRAFFIC) == 0)
      mask |= POLLIN | POLLRDNORM;
  }
  return mask;
}

