lock_tables_maybe(MYSQL* connection, int timeout, int retry_count) {
  if (tables_locked || opt_lock_ddl_per_table) {
    return (true);
  }
  if (have_backup_locks) {
    return lock_tables_for_backup(connection, timeout, retry_count);
  }
  if (have_lock_wait_timeout) {
    char query[200];
    ut_snprintf(query, sizeof(query), "SET SESSION lock_wait_timeout=%d",
                timeout);
    xb_mysql_query(connection, query, false);
  }
  if (!opt_lock_wait_timeout && !opt_kill_long_queries_timeout) {
    msg_ts("Executing FLUSH NO_WRITE_TO_BINLOG TABLES...\n");
    xb_mysql_query(connection, "FLUSH NO_WRITE_TO_BINLOG TABLES", false);
  }
  if (opt_lock_wait_timeout) {
    if (!wait_for_no_updates(connection, opt_lock_wait_timeout,
                             opt_lock_wait_threshold)) {
      return (false);
    }
  }
  msg_ts("Executing FLUSH TABLES WITH READ LOCK...\n");
  if (opt_kill_long_queries_timeout) {
    start_query_killer();
  }
  if (have_galera_enabled) {
    xb_mysql_query(connection, "SET SESSION wsrep_causal_reads=0", false);
  }
  xb_mysql_query(connection, "FLUSH TABLES WITH READ LOCK", false);
  if (opt_kill_long_queries_timeout) {
    stop_query_killer();
  }
  tables_locked = true;
  return (true);
}

struct dentry* kern_path_create(int dfd, const char* pathname,
                                struct path* path, unsigned int lookup_flags) {
  struct dentry* dentry = ERR_PTR(-EEXIST);
  struct nameidata nd;
  int err2;
  int error;
  bool is_dir = (lookup_flags & LOOKUP_DIRECTORY);
  lookup_flags &= LOOKUP_REVAL;
  error = do_path_lookup(dfd, pathname, LOOKUP_PARENT | lookup_flags, &nd);
  if (error) return ERR_PTR(error);
  if (nd.last_type != LAST_NORM) goto out;
  nd.flags &= ~LOOKUP_PARENT;
  nd.flags |= LOOKUP_CREATE | LOOKUP_EXCL;
  err2 = mnt_want_write(nd.path.mnt);
  mutex_lock_nested(&nd.path.dentry->d_inode->i_mutex, I_MUTEX_PARENT);
  dentry = lookup_hash(&nd);
  if (IS_ERR(dentry)) goto unlock;
  error = -EEXIST;
  if (dentry->d_inode) goto fail;
  if (unlikely(!is_dir && nd.last.name[nd.last.len])) {
    error = -ENOENT;
    goto fail;
  }
  if (unlikely(err2)) {
    error = err2;
    goto fail;
  }
  *path = nd.path;
  return dentry;
fail:
  dput(dentry);
  dentry = ERR_PTR(error);
unlock:
  mutex_unlock(&nd.path.dentry->d_inode->i_mutex);
  if (!err2) mnt_drop_write(nd.path.mnt);
out:
  path_put(&nd.path);
  return dentry;
}

static int rr_cmp(uchar* a, uchar* b) {
  if (a[0] != b[0]) return (int)a[0] - (int)b[0];
  if (a[1] != b[1]) return (int)a[1] - (int)b[1];
  if (a[2] != b[2]) return (int)a[2] - (int)b[2];
#if MAX_REFLENGTH == 4
  return (int)a[3] - (int)b[3];
#else
  if (a[3] != b[3]) return (int)a[3] - (int)b[3];
  if (a[4] != b[4]) return (int)a[4] - (int)b[4];
  if (a[5] != b[5]) return (int)a[5] - (int)b[5];
  if (a[6] != b[6]) return (int)a[6] - (int)b[6];
  return (int)a[7] - (int)b[7];
#endif
}

static int wddx_stack_push(wddx_stack* stack, void* element, int size) {
  if (stack->top >= stack->max) {
    stack->elements = (void**)erealloc(
        stack->elements, (sizeof(void**) * (stack->max += STACK_BLOCK_SIZE)));
  }
  stack->elements[stack->top] = (void*)emalloc(size);
  memcpy(stack->elements[stack->top], element, size);
  return stack->top++;
}

