static void get_block_sizes(ALSDecContext* ctx, unsigned int* div_blocks,
                            uint32_t* bs_info) {
  ALSSpecificConfig* sconf = &ctx->sconf;
  GetBitContext* gb = &ctx->gb;
  unsigned int* ptr_div_blocks = div_blocks;
  unsigned int b;
  if (sconf->block_switching) {
    unsigned int bs_info_len = 1 << (sconf->block_switching + 2);
    *bs_info = get_bits_long(gb, bs_info_len);
    *bs_info <<= (32 - bs_info_len);
  }
  ctx->num_blocks = 0;
  parse_bs_info(*bs_info, 0, 0, &ptr_div_blocks, &ctx->num_blocks);
  for (b = 0; b < ctx->num_blocks; b++)
    div_blocks[b] = ctx->sconf.frame_length >> div_blocks[b];
  if (ctx->cur_frame_length != ctx->sconf.frame_length) {
    unsigned int remaining = ctx->cur_frame_length;
    for (b = 0; b < ctx->num_blocks; b++) {
      if (remaining <= div_blocks[b]) {
        div_blocks[b] = remaining;
        ctx->num_blocks = b + 1;
        break;
      }
      remaining -= div_blocks[b];
    }
  }
}

void Curl_flush_cookies(struct Curl_easy* data, bool cleanup) {
  CURLcode res;
  if (data->set.str[STRING_COOKIEJAR]) {
    if (data->state.cookielist) {
      Curl_cookie_loadfiles(data);
    }
    Curl_share_lock(data, CURL_LOCK_DATA_COOKIE, CURL_LOCK_ACCESS_SINGLE);
    res = cookie_output(data, data->cookies, data->set.str[STRING_COOKIEJAR]);
    if (res)
      infof(data, "WARNING: failed to save cookies in %s: %s",
            data->set.str[STRING_COOKIEJAR], curl_easy_strerror(res));
  } else {
    if (cleanup && data->state.cookielist) {
      curl_slist_free_all(data->state.cookielist);
      data->state.cookielist = NULL;
    }
    Curl_share_lock(data, CURL_LOCK_DATA_COOKIE, CURL_LOCK_ACCESS_SINGLE);
  }
  if (cleanup && (!data->share || (data->cookies != data->share->cookies))) {
    Curl_cookie_cleanup(data->cookies);
    data->cookies = NULL;
  }
  Curl_share_unlock(data, CURL_LOCK_DATA_COOKIE);
}

inline int qs_strncmp(const char* s, const char* qs, size_t n) {
  int i = 0;
  unsigned char u1, u2, unyb, lnyb;
  while (n-- > 0) {
    u1 = static_cast<unsigned char>(*s++);
    u2 = static_cast<unsigned char>(*qs++);
    if (!CROW_QS_ISQSCHR(u1)) {
      u1 = '\0';
    }
    if (!CROW_QS_ISQSCHR(u2)) {
      u2 = '\0';
    }
    if (u1 == '+') {
      u1 = ' ';
    }
    if (u1 == '%') {
      unyb = static_cast<unsigned char>(*s++);
      lnyb = static_cast<unsigned char>(*s++);
      if (CROW_QS_ISHEX(unyb) && CROW_QS_ISHEX(lnyb))
        u1 = (CROW_QS_HEX2DEC(unyb) * 16) + CROW_QS_HEX2DEC(lnyb);
      else
        u1 = '\0';
    }
    if (u2 == '+') {
      u2 = ' ';
    }
    if (u2 == '%') {
      unyb = static_cast<unsigned char>(*qs++);
      lnyb = static_cast<unsigned char>(*qs++);
      if (CROW_QS_ISHEX(unyb) && CROW_QS_ISHEX(lnyb))
        u2 = (CROW_QS_HEX2DEC(unyb) * 16) + CROW_QS_HEX2DEC(lnyb);
      else
        u2 = '\0';
    }
    if (u1 != u2) return u1 - u2;
    if (u1 == '\0') return 0;
    i++;
  }
  if (CROW_QS_ISQSCHR(*qs))
    return -1;
  else
    return 0;
}

static void evdev_events(struct input_handle* handle,
                         const struct input_value* vals, unsigned int count) {
  struct evdev* evdev = handle->private;
  struct evdev_client* client;
  ktime_t time_mono, time_real;
  time_mono = ktime_get();
  time_real = ktime_sub(time_mono, ktime_get_monotonic_offset());
  rcu_read_lock();
  client = rcu_dereference(evdev->grab);
  if (client)
    evdev_pass_values(client, vals, count, time_mono, time_real);
  else
    list_for_each_entry_rcu(client, &evdev->client_list, node)
        evdev_pass_values(client, vals, count, time_mono, time_real);
  rcu_read_unlock();
}

smtp_notquit_exit(uschar* reason, uschar* code, uschar* defaultrespond, ...) {
  int rc;
  uschar* user_msg = NULL;
  uschar* log_msg = NULL;
  if (fl.smtp_exit_function_called) {
    log_write(0, LOG_PANIC, "smtp_notquit_exit() called more than once (%s)",
              reason);
    return;
  }
  fl.smtp_exit_function_called = TRUE;
  if (acl_smtp_notquit && reason) {
    smtp_notquit_reason = reason;
    if ((rc = acl_check(ACL_WHERE_NOTQUIT, NULL, acl_smtp_notquit, &user_msg,
                        &log_msg)) == ERROR)
      log_write(0, LOG_MAIN | LOG_PANIC, "ACL for not-QUIT returned ERROR: %s",
                log_msg);
  }
  tls_in.active.sock = -1;
  if (code && defaultrespond) {
    if (user_msg)
      smtp_respond(code, 3, TRUE, user_msg);
    else {
      gstring* g;
      va_list ap;
      va_start(ap, defaultrespond);
      g = string_vformat(NULL, TRUE, CS defaultrespond, ap);
      va_end(ap);
      smtp_printf("%s %s\r\n", FALSE, code, string_from_gstring(g));
    }
    mac_smtp_fflush();
  }
}

static bool caller_may_see_dir(pid_t pid, const char* contrl, const char* cg) {
  bool answer = false;
  char *c2, *task_cg;
  size_t target_len, task_len;
  if (strcmp(cg, "/") == 0) return true;
  c2 = get_pid_cgroup(pid, contrl);
  if (!c2) return false;
  task_cg = c2 + 1;
  target_len = strlen(cg);
  task_len = strlen(task_cg);
  if (strcmp(cg, task_cg) == 0) {
    answer = true;
    goto out;
  }
  if (target_len < task_len) {
    if (strncmp(task_cg, cg, target_len) == 0 && task_cg[target_len] == '/')
      answer = true;
    goto out;
  }
  if (target_len > task_len) {
    if (strncmp(task_cg, cg, task_len) == 0 && cg[task_len] == '/')
      answer = true;
    goto out;
  }
out:
  free(c2);
  return answer;
}

int http_process_tarpit(struct session* s, struct channel* req, int an_bit) {
  struct http_txn* txn = &s->txn;
  channel_dont_connect(req);
  if ((req->flags & (CF_SHUTR | CF_READ_ERROR)) == 0 &&
      !tick_is_expired(req->analyse_exp, now_ms))
    return 0;
  s->logs.t_queue = tv_ms_elapsed(&s->logs.tv_accept, &now);
  txn->status = 500;
  if (!(req->flags & CF_READ_ERROR))
    stream_int_retnclose(req->prod, http_error_message(s, HTTP_ERR_500));
  req->analysers = 0;
  req->analyse_exp = TICK_ETERNITY;
  s->fe->fe_counters.failed_req++;
  if (s->listener->counters) s->listener->counters->failed_req++;
  if (!(s->flags & SN_ERR_MASK)) s->flags |= SN_ERR_PRXCOND;
  if (!(s->flags & SN_FINST_MASK)) s->flags |= SN_FINST_T;
  return 0;
}

