  }
}

static Bool Calc_Length(EXEC_OP) {
  CUR.opcode = CUR.code[CUR.IP];
  switch (CUR.opcode) {
    case 0x40:
      if (CUR.IP + 1 >= CUR.codeSize) return FAILURE;
      CUR.length = CUR.code[CUR.IP + 1] + 2;
      break;
    case 0x41:
      if (CUR.IP + 1 >= CUR.codeSize) return FAILURE;
      CUR.length = CUR.code[CUR.IP + 1] * 2 + 2;
      break;
    case 0xB0:
    case 0xB1:
    case 0xB2:
    case 0xB3:
    case 0xB4:
    case 0xB5:
    case 0xB6:
    case 0xB7:
      CUR.length = CUR.opcode - 0xB0 + 2;
      break;
    case 0xB8:
    case 0xB9:
    case 0xBA:
    case 0xBB:
    case 0xBC:
    case 0xBD:
    case 0xBE:
    case 0xBF:
      CUR.length = (CUR.opcode - 0xB8) * 2 + 3;
      break;
    default:
      CUR.length = 1;
      break;
  }
  if (CUR.IP + CUR.length > CUR.codeSize) return FAILURE;
  return SUCCESS;
}

