static int inet6_dump_ifinfo(struct sk_buff* skb, struct netlink_callback* cb) {
  struct net* net = sock_net(skb->sk);
  int h, s_h;
  int idx = 0, s_idx;
  struct net_device* dev;
  struct inet6_dev* idev;
  struct hlist_head* head;
  s_h = cb->args[0];
  s_idx = cb->args[1];
  rcu_read_lock();
  for (h = s_h; h < NETDEV_HASHENTRIES; h++, s_idx = 0) {
    idx = 0;
    head = &net->dev_index_head[h];
    hlist_for_each_entry_rcu(dev, head, index_hlist) {
      if (idx < s_idx) goto cont;
      idev = __in6_dev_get(dev);
      if (!idev) goto cont;
      if (inet6_fill_ifinfo(skb, idev, NETLINK_CB(cb->skb).portid,
                            cb->nlh->nlmsg_seq, RTM_NEWLINK, NLM_F_MULTI) <= 0)
        goto out;
    cont:
      idx++;
    }
  }
out:
  rcu_read_unlock();
  cb->args[1] = idx;
  cb->args[0] = h;
  return skb->len;
}

static int memory_access_size(MemoryRegion* mr, unsigned l, hwaddr addr) {
  unsigned access_size_max = mr->ops->valid.max_access_size;
  if (access_size_max == 0) {
    access_size_max = 4;
  }
  if (!mr->ops->impl.unaligned) {
    unsigned align_size_max = addr & -addr;
    if (align_size_max != 0 && align_size_max < access_size_max) {
      access_size_max = align_size_max;
    }
  }
  if (l > access_size_max) {
    l = access_size_max;
  }
  if (l & (l - 1)) {
    l = 1 << (qemu_fls(l) - 1);
  }
  return l;
}

MatchExpression::ExpressionOptimizerFunc ExprMatchExpression::getOptimizer()
    const {
  return [](std::unique_ptr<MatchExpression> expression) {
    auto& exprMatchExpr = static_cast<ExprMatchExpression&>(*expression);
    if (exprMatchExpr._rewriteResult) {
      return expression;
    }
    exprMatchExpr._expression = exprMatchExpr._expression->optimize();
    exprMatchExpr._rewriteResult = RewriteExpr::rewrite(
        exprMatchExpr._expression, exprMatchExpr._expCtx->getCollator());
    if (exprMatchExpr._rewriteResult->matchExpression()) {
      auto andMatch = stdx::make_unique<AndMatchExpression>();
      andMatch->add(
          exprMatchExpr._rewriteResult->releaseMatchExpression().release());
      andMatch->add(expression.release());
      expression = MatchExpression::optimize(std::move(andMatch));
    }
    return expression;
  };
}

