njs_string_alloc(njs_vm_t* vm, njs_value_t* value, uint64_t size,
                 uint64_t length) {
  uint32_t total, map_offset, *map;
  njs_string_t* string;
  if (njs_slow_path(size > NJS_STRING_MAX_LENGTH)) {
    njs_range_error(vm, "invalid string length");
    return NULL;
  }
  value->type = NJS_STRING;
  njs_string_truth(value, size);
  if (size <= NJS_STRING_SHORT) {
    value->short_string.size = size;
    value->short_string.length = length;
    return value->short_string.start;
  }
  value->short_string.size = NJS_STRING_LONG;
  value->short_string.length = 0;
  value->long_string.external = 0;
  value->long_string.size = size;
  if (size != length && length > NJS_STRING_MAP_STRIDE) {
    map_offset = njs_string_map_offset(size);
    total = map_offset + njs_string_map_size(length);
  } else {
    map_offset = 0;
    total = size;
  }
  string = njs_mp_alloc(vm->mem_pool, sizeof(njs_string_t) + total);
  if (njs_fast_path(string != NULL)) {
    value->long_string.data = string;
    string->start = (u_char*)string + sizeof(njs_string_t);
    string->length = length;
    string->retain = 1;
    if (map_offset != 0) {
      map = (uint32_t*)(string->start + map_offset);
      map[0] = 0;
    }
    return string->start;
  }
  njs_memory_error(vm);
  return NULL;
}

void RootWindowHostWin::ToggleFullScreen() {
  gfx::Rect target_rect;
  if (!fullscreen_) {
    fullscreen_ = true;
    saved_window_style_ = GetWindowLong(hwnd(), GWL_STYLE);
    saved_window_ex_style_ = GetWindowLong(hwnd(), GWL_EXSTYLE);
    GetWindowRect(hwnd(), &saved_window_rect_);
    SetWindowLong(hwnd(), GWL_STYLE,
                  saved_window_style_ & ~(WS_CAPTION | WS_THICKFRAME));
    SetWindowLong(
        hwnd(), GWL_EXSTYLE,
        saved_window_ex_style_ & ~(WS_EX_DLGMODALFRAME | WS_EX_WINDOWEDGE |
                                   WS_EX_CLIENTEDGE | WS_EX_STATICEDGE));
    MONITORINFO mi;
    mi.cbSize = sizeof(mi);
    GetMonitorInfo(MonitorFromWindow(hwnd(), MONITOR_DEFAULTTONEAREST), &mi);
    target_rect = mi.rcMonitor;
  } else {
    fullscreen_ = false;
    SetWindowLong(hwnd(), GWL_STYLE, saved_window_style_);
    SetWindowLong(hwnd(), GWL_EXSTYLE, saved_window_ex_style_);
    target_rect = saved_window_rect_;
  }
  SetWindowPos(hwnd(), NULL, target_rect.x(), target_rect.y(),
               target_rect.width(), target_rect.height(),
               SWP_NOZORDER | SWP_NOACTIVATE | SWP_FRAMECHANGED);
}

