    if ((chip->setup & MAUDIO_SET_DTS) && altno != 6) return 1;
    if ((chip->setup & MAUDIO_SET_96K) && altno != 1) return 1;
    mask = chip->setup & MAUDIO_SET_MASK;
    if (mask == MAUDIO_SET_24B_48K_DI && altno != 2) return 1;
    if (mask == MAUDIO_SET_24B_48K_NOTDI && altno != 3) return 1;
    if (mask == MAUDIO_SET_16B_48K_DI && altno != 4) return 1;
    if (mask == MAUDIO_SET_16B_48K_NOTDI && altno != 5) return 1;
  }
  return 0;
}

