int hugetlb_overcommit_handler(struct ctl_table* table, int write, void* buffer,
                               size_t* length, loff_t* ppos) {
  struct hstate* h = &default_hstate;
  unsigned long tmp;
  int ret;
  if (!hugepages_supported()) return -EOPNOTSUPP;
  tmp = h->nr_overcommit_huge_pages;
  if (write && hstate_is_gigantic(h)) return -EINVAL;
  ret =
      proc_hugetlb_doulongvec_minmax(table, write, buffer, length, ppos, &tmp);
