char** lxc_va_arg_list_to_argv(va_list ap, size_t skip, int do_strdup) {
  va_list ap2;
  size_t count = 1 + skip;
  char** result;
  va_copy(ap2, ap);
  while (1) {
    char* arg = va_arg(ap2, char*);
    if (!arg) break;
    count++;
  }
  va_end(ap2);
  result = calloc(count, sizeof(char*));
  if (!result) return NULL;
  count = skip;
  while (1) {
    char* arg = va_arg(ap, char*);
    if (!arg) break;
    arg = do_strdup ? strdup(arg) : arg;
    if (!arg) goto oom;
    result[count++] = arg;
  }
  return result;
oom:
  free(result);
  return NULL;
}

static void blk_mq_rq_timer(unsigned long priv) {
  struct request_queue* q = (struct request_queue*)priv;
  struct blk_mq_timeout_data data = {
      .next = 0,
      .next_set = 0,
  };
  struct blk_mq_hw_ctx* hctx;
  int i;
  queue_for_each_hw_ctx(q, hctx, i) {
    if (!blk_mq_hw_queue_mapped(hctx)) continue;
    blk_mq_tag_busy_iter(hctx, blk_mq_check_expired, &data);
  }
  if (data.next_set) {
    data.next = blk_rq_timeout(round_jiffies_up(data.next));
    mod_timer(&q->timeout, data.next);
  } else {
    queue_for_each_hw_ctx(q, hctx, i) {
      if (blk_mq_hw_queue_mapped(hctx)) blk_mq_tag_idle(hctx);
    }
  }
}

