MemoryRegion* qemu_ram_addr_from_host(void* ptr, ram_addr_t* ram_addr) {
  RAMBlock* block;
  uint8_t* host = ptr;
  MemoryRegion* mr;
  if (xen_enabled()) {
    rcu_read_lock();
    *ram_addr = xen_ram_addr_from_mapcache(ptr);
    mr = qemu_get_ram_block(*ram_addr)->mr;
    rcu_read_unlock();
    return mr;
  }
  rcu_read_lock();
  block = atomic_rcu_read(&ram_list.mru_block);
  if (block && block->host && host - block->host < block->max_length) {
    goto found;
  }
  QLIST_FOREACH_RCU(block, &ram_list.blocks, next) {
    if (block->host == NULL) {
      continue;
    }
    if (host - block->host < block->max_length) {
      goto found;
    }
  }
  rcu_read_unlock();
  return NULL;
found:
  *ram_addr = block->offset + (host - block->host);
  mr = block->mr;
  rcu_read_unlock();
  return mr;
}

int rtnl_dump_request_n(struct rtnl_handle* rth, struct nlmsghdr* n) {
  struct sockaddr_nl nladdr = {.nl_family = AF_NETLINK};
  struct iovec iov = {.iov_base = n, .iov_len = n->nlmsg_len};
  struct msghdr msg = {
      .msg_name = &nladdr,
      .msg_namelen = sizeof(nladdr),
      .msg_iov = &iov,
      .msg_iovlen = 1,
  };
  n->nlmsg_flags = NLM_F_DUMP | NLM_F_REQUEST;
  n->nlmsg_pid = 0;
  n->nlmsg_seq = rth->dump = ++rth->seq;
  return sendmsg(rth->fd, &msg, 0);
}

connection_write_throttled(const connection* const con, off_t max_bytes) {
  const request_config* const restrict rconf = &con->request.conf;
  if (0 == rconf->global_bytes_per_second && 0 == rconf->bytes_per_second)
    return max_bytes;
  if (rconf->global_bytes_per_second) {
    off_t limit = (off_t)rconf->global_bytes_per_second -
                  *(rconf->global_bytes_per_second_cnt_ptr);
    if (max_bytes > limit) max_bytes = limit;
  }
  if (rconf->bytes_per_second) {
    off_t limit =
        (off_t)rconf->bytes_per_second - con->bytes_written_cur_second;
    if (max_bytes > limit) max_bytes = limit;
  }
  return max_bytes > 0 ? max_bytes : 0;
}

callbacks_screen2board(gdouble* X, gdouble* Y, gint x, gint y) {
  if ((screenRenderInfo.scaleFactorX > 0.001) ||
      (screenRenderInfo.scaleFactorY > 0.001)) {
    *X = screenRenderInfo.lowerLeftX + (x / screenRenderInfo.scaleFactorX);
    *Y = screenRenderInfo.lowerLeftY +
         ((screenRenderInfo.displayHeight - y) / screenRenderInfo.scaleFactorY);
  } else {
    *X = *Y = 0.0;
  }
}

void UpstreamRequest::onPerTryTimeout() {
  if (per_try_idle_timeout_) {
    per_try_idle_timeout_.reset();
  }
  if (!parent_.downstreamResponseStarted()) {
    ENVOY_STREAM_LOG(debug, "upstream per try timeout", *parent_.callbacks());
    stream_info_.setResponseFlag(
        StreamInfo::CoreResponseFlag::UpstreamRequestTimeout);
    parent_.onPerTryTimeout(*this);
  } else {
    ENVOY_STREAM_LOG(debug,
                     "ignored upstream per try timeout due to already started "
                     "downstream response",
                     *parent_.callbacks());
  }
}

int64 ClientUsageTracker::GetCachedGlobalUnlimitedUsage() {
  if (!global_unlimited_usage_is_valid_) {
    global_unlimited_usage_ = 0;
    for (HostUsageMap::const_iterator host_iter = cached_usage_.begin();
         host_iter != cached_usage_.end(); host_iter++) {
      const UsageMap& origin_map = host_iter->second;
      for (UsageMap::const_iterator origin_iter = origin_map.begin();
           origin_iter != origin_map.end(); origin_iter++) {
        if (IsStorageUnlimited(origin_iter->first))
          global_unlimited_usage_ += origin_iter->second;
      }
    }
    global_unlimited_usage_is_valid_ = true;
  }
  return global_unlimited_usage_;
}

mm_skey_query(void* ctx, char** name, char** infotxt, u_int* numprompts,
              char*** prompts, u_int** echo_on) {
  Buffer m;
  int len;
  u_int success;
  char *p, *challenge;
  debug3("%s: entering", __func__);
  buffer_init(&m);
  mm_request_send(pmonitor->m_recvfd, MONITOR_REQ_SKEYQUERY, &m);
  mm_request_receive_expect(pmonitor->m_recvfd, MONITOR_ANS_SKEYQUERY, &m);
  success = buffer_get_int(&m);
  if (success == 0) {
    debug3("%s: no challenge", __func__);
    buffer_free(&m);
    return (-1);
  }
  challenge = buffer_get_string(&m, NULL);
  buffer_free(&m);
  debug3("%s: received challenge: %s", __func__, challenge);
  mm_chall_setup(name, infotxt, numprompts, prompts, echo_on);
  len = strlen(challenge) + strlen(SKEY_PROMPT) + 1;
  p = xmalloc(len);
  strlcpy(p, challenge, len);
  strlcat(p, SKEY_PROMPT, len);
  (*prompts)[0] = p;
  xfree(challenge);
  return (0);
}

GF_Err senc_box_size(GF_Box* s) {
  u32 sample_count;
  u32 i, nb_crypt_samples;
  GF_SampleEncryptionBox* ptr = (GF_SampleEncryptionBox*)s;
  sample_count = gf_list_count(ptr->samp_aux_info);
  nb_crypt_samples = 0;
  for (i = 0; i < sample_count; i++) {
    GF_CENCSampleAuxInfo* sai =
        (GF_CENCSampleAuxInfo*)gf_list_get(ptr->samp_aux_info, i);
    if (!sai->isNotProtected) nb_crypt_samples++;
  }
  if (!nb_crypt_samples) {
    ptr->size = 0;
    return GF_OK;
  }
  ptr->size += 4;
  ptr->size += 4;
  for (i = 0; i < sample_count; i++) {
    GF_CENCSampleAuxInfo* sai =
        (GF_CENCSampleAuxInfo*)gf_list_get(ptr->samp_aux_info, i);
    if (sai->isNotProtected) continue;
    ptr->size += sai->cenc_data_size;
  }
  return GF_OK;
}

static bool tailmatch(const char* cooke_domain, const char* hostname) {
  size_t cookie_domain_len = strlen(cooke_domain);
  size_t hostname_len = strlen(hostname);
  if (hostname_len < cookie_domain_len) return FALSE;
  if (!strcasecompare(cooke_domain,
                      hostname + hostname_len - cookie_domain_len))
    return FALSE;
  if (hostname_len == cookie_domain_len) return TRUE;
  if ('.' == *(hostname + hostname_len - cookie_domain_len - 1)) return TRUE;
  return FALSE;
}

void audit_syscall_exit(int valid, long return_code) {
  struct task_struct* tsk = current;
  struct audit_context* context;
  context = audit_get_context(tsk, valid, return_code);
  if (likely(!context)) return;
  if (context->in_syscall && context->auditable) audit_log_exit(context, tsk);
  context->in_syscall = 0;
  context->auditable = 0;
  if (context->previous) {
    struct audit_context* new_context = context->previous;
    context->previous = NULL;
    audit_free_context(context);
    tsk->audit_context = new_context;
  } else {
    audit_free_names(context);
    audit_free_aux(context);
    context->aux = NULL;
    context->aux_pids = NULL;
    context->target_pid = 0;
    context->target_sid = 0;
    kfree(context->filterkey);
    context->filterkey = NULL;
    tsk->audit_context = context;
  }
}

static inline void address_space_stl_internal(AddressSpace* as, hwaddr addr,
                                              uint32_t val, MemTxAttrs attrs,
                                              MemTxResult* result,
                                              enum device_endian endian) {
  uint8_t* ptr;
  MemoryRegion* mr;
  hwaddr l = 4;
  hwaddr addr1;
  MemTxResult r;
  rcu_read_lock();
  mr = address_space_translate(as, addr, &addr1, &l, true);
  if (l < 4 || !memory_access_is_direct(mr, true)) {
#if defined(TARGET_WORDS_BIGENDIAN)
    if (endian == DEVICE_LITTLE_ENDIAN) {
      val = bswap32(val);
    }
#else
    if (endian == DEVICE_BIG_ENDIAN) {
      val = bswap32(val);
    }
#endif
    r = memory_region_dispatch_write(mr, addr1, val, 4, attrs);
  } else {
    addr1 += memory_region_get_ram_addr(mr) & TARGET_PAGE_MASK;
    ptr = qemu_get_ram_ptr(addr1);
    switch (endian) {
      case DEVICE_LITTLE_ENDIAN:
        stl_le_p(ptr, val);
        break;
      case DEVICE_BIG_ENDIAN:
        stl_be_p(ptr, val);
        break;
      default:
        stl_p(ptr, val);
        break;
    }
    invalidate_and_set_dirty(mr, addr1, 4);
    r = MEMTX_OK;
  }
  if (result) {
    *result = r;
  }
  rcu_read_unlock();
}

OPJ_BOOL opj_j2k_write_regions(opj_j2k_t* p_j2k,
                               struct opj_stream_private* p_stream,
                               struct opj_event_mgr* p_manager) {
  OPJ_UINT32 compno;
  const opj_tccp_t* l_tccp = 00;
  assert(p_j2k != 00);
  assert(p_manager != 00);
  assert(p_stream != 00);
  l_tccp = p_j2k->m_cp.tcps->tccps;
  for (compno = 0; compno < p_j2k->m_private_image->numcomps; ++compno) {
    if (l_tccp->roishift) {
