static int handle_en_event(struct hns_roce_dev* hr_dev, u8 port,
                           unsigned long event) {
  struct device* dev = hr_dev->dev;
  struct net_device* netdev;
  int ret = 0;
  netdev = hr_dev->iboe.netdevs[port];
  if (!netdev) {
    dev_err(dev, "port(%d) can't find netdev\n", port);
    return -ENODEV;
  }
  switch (event) {
    case NETDEV_UP:
    case NETDEV_CHANGE:
    case NETDEV_REGISTER:
    case NETDEV_CHANGEADDR:
      ret = hns_roce_set_mac(hr_dev, port, netdev->dev_addr);
      break;
    case NETDEV_DOWN:
      break;
    default:
      dev_dbg(dev, "NETDEV event = 0x%x!\n", (u32)(event));
      break;
  }
  return ret;
}

void CiffComponent::writeDirEntry(Blob& blob, ByteOrder byteOrder) const {
#ifdef EXIV2_DEBUG_MESSAGES
  std::cout << "  Directory entry for tag 0x" << std::hex << tagId() << " (0x"
            << tag() << "), " << std::dec << size_ << " Bytes, Offset is "
            << offset_ << "\n";
#endif
  byte buf[4];
  DataLocId dl = dataLocation();
  assert(dl == directoryData || dl == valueData);
  if (dl == valueData) {
    us2Data(buf, tag_, byteOrder);
    append(blob, buf, 2);
    ul2Data(buf, size_, byteOrder);
    append(blob, buf, 4);
    ul2Data(buf, offset_, byteOrder);
    append(blob, buf, 4);
  }
  if (dl == directoryData) {
    assert(size_ <= 8);
    us2Data(buf, tag_, byteOrder);
    append(blob, buf, 2);
    append(blob, pData_, size_);
    for (uint32_t i = size_; i < 8; ++i) {
      blob.push_back(0);
    }
  }
}

static int ieee80211_get_mmie_keyidx(struct sk_buff* skb) {
  struct ieee80211_mgmt* hdr = (struct ieee80211_mgmt*)skb->data;
  struct ieee80211_mmie* mmie;
  struct ieee80211_mmie_16* mmie16;
  if (skb->len < 24 + sizeof(*mmie) || !is_multicast_ether_addr(hdr->da))
    return -1;
  if (!ieee80211_is_robust_mgmt_frame(skb)) return -1;
  mmie = (struct ieee80211_mmie*)(skb->data + skb->len - sizeof(*mmie));
  if (mmie->element_id == WLAN_EID_MMIE && mmie->length == sizeof(*mmie) - 2)
    return le16_to_cpu(mmie->key_id);
  mmie16 = (struct ieee80211_mmie_16*)(skb->data + skb->len - sizeof(*mmie16));
  if (skb->len >= 24 + sizeof(*mmie16) && mmie16->element_id == WLAN_EID_MMIE &&
      mmie16->length == sizeof(*mmie16) - 2)
    return le16_to_cpu(mmie16->key_id);
  return -1;
}

