static bool rootdir_empty(struct super_block* sb, unsigned long block) {
  int offset = 0, files = 0, de_len;
  struct iso_directory_record* de;
  struct buffer_head* bh;
  bh = sb_bread(sb, block);
  if (!bh) return true;
  while (files < 3) {
    de = (struct iso_directory_record*)(bh->b_data + offset);
    de_len = *(unsigned char*)de;
    if (de_len == 0) break;
    files++;
    offset += de_len;
  }
  brelse(bh);
  return files < 3;
}

static __poll_t proc_sys_poll(struct file* filp, poll_table* wait) {
  struct inode* inode = file_inode(filp);
  struct ctl_table_header* head = grab_header(inode);
  struct ctl_table* table = PROC_I(inode)->sysctl_entry;
  __poll_t ret = DEFAULT_POLLMASK;
  unsigned long event;
  if (IS_ERR(head)) return EPOLLERR | EPOLLHUP;
  if (!table->proc_handler) goto out;
  if (!table->poll) goto out;
  event = (unsigned long)filp->private_data;
  poll_wait(filp, &table->poll->wait, wait);
  if (event != atomic_read(&table->poll->event)) {
    filp->private_data = proc_sys_poll_event(table->poll);
    ret = EPOLLIN | EPOLLRDNORM | EPOLLERR | EPOLLPRI;
  }
out:
  sysctl_head_finish(head);
  return ret;
}

static void nvme_copy_out_completed_cb(void* opaque, int ret) {
  NvmeCopyAIOCB* iocb = opaque;
  NvmeRequest* req = iocb->req;
  NvmeNamespace* ns = req->ns;
  NvmeCopySourceRange* range = &iocb->ranges[iocb->idx];
  uint32_t nlb = le32_to_cpu(range->nlb) + 1;
  if (ret < 0) {
    iocb->ret = ret;
    goto out;
  } else if (iocb->ret < 0) {
    goto out;
  }
  if (ns->params.zoned) {
    nvme_advance_zone_wp(ns, iocb->zone, nlb);
  }
  iocb->idx++;
  iocb->slba += nlb;
out:
  nvme_copy_cb(iocb, iocb->ret);
}

void LibRaw::border_interpolate(int border) {
  unsigned row, col, y, x, f, c, sum[8];
  for (row = 0; row < height; row++)
    for (col = 0; col < width; col++) {
      if (col == border && row >= border && row < height - border)
        col = width - border;
      memset(sum, 0, sizeof sum);
      for (y = row - 1; y != row + 2; y++)
        for (x = col - 1; x != col + 2; x++)
          if (y < height && x < width) {
            f = fcol(y, x);
            sum[f] += image[y * width + x][f];
            sum[f + 4]++;
          }
      f = fcol(row, col);
      FORCC if (c != f && sum[c + 4]) image[row * width + col][c] =
          sum[c] / sum[c + 4];
    }
}

