numbered_ref_check(Node* node) {
  int r = 0;
  switch (NTYPE(node)) {
    case NT_LIST:
    case NT_ALT:
      do {
        r = numbered_ref_check(NCAR(node));
      } while (r == 0 && IS_NOT_NULL(node = NCDR(node)));
      break;
    case NT_QTFR:
      r = numbered_ref_check(NQTFR(node)->target);
      break;
    case NT_ENCLOSE:
      r = numbered_ref_check(NENCLOSE(node)->target);
      break;
    case NT_BREF:
      if (!IS_BACKREF_NAME_REF(NBREF(node)))
        return ONIGERR_NUMBERED_BACKREF_OR_CALL_NOT_ALLOWED;
      break;
    case NT_ANCHOR:
      if (NANCHOR(node)->target) r = numbered_ref_check(NANCHOR(node)->target);
      break;
    default:
      break;
  }
  return r;
}

static int snd_timer_start_slave(struct snd_timer_instance* timeri,
                                 bool start) {
  unsigned long flags;
  spin_lock_irqsave(&slave_active_lock, flags);
  if (timeri->flags & SNDRV_TIMER_IFLG_RUNNING) {
    spin_unlock_irqrestore(&slave_active_lock, flags);
    return -EBUSY;
  }
  timeri->flags |= SNDRV_TIMER_IFLG_RUNNING;
  if (timeri->master && timeri->timer) {
    spin_lock(&timeri->timer->lock);
    list_add_tail(&timeri->active_list, &timeri->master->slave_active_head);
    snd_timer_notify1(
        timeri, start ? SNDRV_TIMER_EVENT_START : SNDRV_TIMER_EVENT_CONTINUE);
    spin_unlock(&timeri->timer->lock);
  }
  spin_unlock_irqrestore(&slave_active_lock, flags);
  return 1;
}

