static int nr_setsockopt(struct socket* sock, int level, int optname,
                         char __user* optval, int optlen) {
  struct sock* sk = sock->sk;
  struct nr_sock* nr = nr_sk(sk);
  int opt;
  if (level != SOL_NETROM) return -ENOPROTOOPT;
  if (optlen < sizeof(int)) return -EINVAL;
  if (get_user(opt, (int __user*)optval)) return -EFAULT;
  switch (optname) {
    case NETROM_T1:
      if (opt < 1) return -EINVAL;
      nr->t1 = opt * HZ;
      return 0;
    case NETROM_T2:
      if (opt < 1) return -EINVAL;
      nr->t2 = opt * HZ;
      return 0;
    case NETROM_N2:
      if (opt < 1 || opt > 31) return -EINVAL;
      nr->n2 = opt;
      return 0;
    case NETROM_T4:
      if (opt < 1) return -EINVAL;
      nr->t4 = opt * HZ;
      return 0;
    case NETROM_IDLE:
      if (opt < 0) return -EINVAL;
      nr->idle = opt * 60 * HZ;
      return 0;
    default:
      return -ENOPROTOOPT;
  }
}

static int mxf_get_d10_aes3_packet(AVIOContext* pb, AVStream* st, AVPacket* pkt,
                                   int64_t length) {
  const uint8_t *buf_ptr, *end_ptr;
  uint8_t* data_ptr;
  int i;
  if (length > 61444) return AVERROR_INVALIDDATA;
  length = av_get_packet(pb, pkt, length);
  if (length < 0) return length;
  data_ptr = pkt->data;
  end_ptr = pkt->data + length;
  buf_ptr = pkt->data + 4;
  for (; end_ptr - buf_ptr >= st->codec->channels * 4;) {
    for (i = 0; i < st->codec->channels; i++) {
      uint32_t sample = bytestream_get_le32(&buf_ptr);
      if (st->codec->bits_per_coded_sample == 24)
        bytestream_put_le24(&data_ptr, (sample >> 4) & 0xffffff);
      else
        bytestream_put_le16(&data_ptr, (sample >> 12) & 0xffff);
    }
    buf_ptr += 32 - st->codec->channels * 4;
  }
  av_shrink_packet(pkt, data_ptr - pkt->data);
  return 0;
}

