static void ldapsrv_terminate_connection(struct ldapsrv_connection* conn,
                                         const char* reason) {
  struct tevent_req* subreq;
  if (conn->limits.reason) {
    return;
  }
  DLIST_REMOVE(conn->service->connections, conn);
  conn->limits.endtime = timeval_current_ofs(0, 500);
  tevent_queue_stop(conn->sockets.send_queue);
  TALLOC_FREE(conn->sockets.read_req);
  TALLOC_FREE(conn->deferred_expire_disconnect);
  if (conn->active_call) {
    tevent_req_cancel(conn->active_call);
    conn->active_call = NULL;
  }
  conn->limits.reason = talloc_strdup(conn, reason);
  if (conn->limits.reason == NULL) {
    TALLOC_FREE(conn->sockets.tls);
    TALLOC_FREE(conn->sockets.sasl);
    TALLOC_FREE(conn->sockets.raw);
    stream_terminate_connection(conn->connection, reason);
    return;
  }
  subreq = tstream_disconnect_send(conn, conn->connection->event.ctx,
                                   conn->sockets.active);
  if (subreq == NULL) {
    TALLOC_FREE(conn->sockets.tls);
    TALLOC_FREE(conn->sockets.sasl);
    TALLOC_FREE(conn->sockets.raw);
    stream_terminate_connection(conn->connection, reason);
    return;
  }
  tevent_req_set_endtime(subreq, conn->connection->event.ctx,
                         conn->limits.endtime);
  tevent_req_set_callback(subreq, ldapsrv_terminate_connection_done, conn);
}

utf32be_mbc_case_fold(OnigCaseFoldType flag, const UChar** pp, const UChar* end,
                      UChar* fold, OnigEncoding enc) {
  const UChar* p = *pp;
  if (ONIGENC_IS_ASCII_CODE(*(p + 3)) && *(p + 2) == 0 && *(p + 1) == 0 &&
      *p == 0) {
    *fold++ = 0;
    *fold++ = 0;
#ifdef USE_UNICODE_CASE_FOLD_TURKISH_AZERI
    if ((flag & ONIGENC_CASE_FOLD_TURKISH_AZERI) != 0) {
      if (*(p + 3) == 0x49) {
        *fold++ = 0x01;
        *fold = 0x31;
        (*pp) += 4;
        return 4;
      }
    }
#endif
    *fold++ = 0;
    *fold = ONIGENC_ASCII_CODE_TO_LOWER_CASE(*(p + 3));
    *pp += 4;
    return 4;
  } else
    return onigenc_unicode_mbc_case_fold(enc, flag, pp, end, fold);
}

static int _btrfs_ioctl_send(struct file* file, void __user* argp,
                             bool compat) {
  struct btrfs_ioctl_send_args* arg;
  int ret;
  if (compat) {
#if defined(CONFIG_64BIT) && defined(CONFIG_COMPAT)
    struct btrfs_ioctl_send_args_32 args32;
    ret = copy_from_user(&args32, argp, sizeof(args32));
    if (ret) return -EFAULT;
    arg = kzalloc(sizeof(*arg), GFP_KERNEL);
    if (!arg) return -ENOMEM;
    arg->send_fd = args32.send_fd;
    arg->clone_sources_count = args32.clone_sources_count;
    arg->clone_sources = compat_ptr(args32.clone_sources);
    arg->parent_root = args32.parent_root;
    arg->flags = args32.flags;
    memcpy(arg->reserved, args32.reserved, sizeof(args32.reserved));
#else
    return -ENOTTY;
#endif
  } else {
    arg = memdup_user(argp, sizeof(*arg));
    if (IS_ERR(arg)) return PTR_ERR(arg);
  }
  ret = btrfs_ioctl_send(file, arg);
  kfree(arg);
  return ret;
}

