int iterate_fd(struct files_struct* files, unsigned n,
               int (*f)(const void*, struct file*, unsigned), const void* p) {
  struct fdtable* fdt;
  int res = 0;
  if (!files) return 0;
  spin_lock(&files->file_lock);
  for (fdt = files_fdtable(files); n < fdt->max_fds; n++) {
    struct file* file;
    file = rcu_dereference_check_fdtable(files, fdt->fd[n]);
    if (!file) continue;
    res = f(p, file, n);
    if (res) break;
  }
  spin_unlock(&files->file_lock);
  return res;
}

GF_Err av1c_box_read(GF_Box* s, GF_BitStream* bs) {
  u64 pos, read;
  GF_AV1ConfigurationBox* ptr = (GF_AV1ConfigurationBox*)s;
  if (ptr->config) gf_odf_av1_cfg_del(ptr->config);
  pos = gf_bs_get_position(bs);
  ptr->config = gf_odf_av1_cfg_read_bs_size(bs, (u32)ptr->size);
  read = gf_bs_get_position(bs) - pos;
  if (read < ptr->size)
    GF_LOG(GF_LOG_WARNING, GF_LOG_CONTAINER,
           ("[ISOBMFF] AV1ConfigurationBox: read only " LLU
            " bytes (expected " LLU ").\n",
            read, ptr->size));
  if (read > ptr->size)
    GF_LOG(GF_LOG_ERROR, GF_LOG_CONTAINER,
           ("[ISOBMFF] AV1ConfigurationBox overflow read " LLU
            " bytes, of box size " LLU ".\n",
            read, ptr->size));
  return GF_OK;
}

inherit_event(struct perf_event* parent_event, struct task_struct* parent,
              struct perf_event_context* parent_ctx, struct task_struct* child,
              struct perf_event* group_leader,
              struct perf_event_context* child_ctx) {
  struct perf_event* child_event;
  unsigned long flags;
  if (parent_event->parent) parent_event = parent_event->parent;
  child_event = perf_event_alloc(&parent_event->attr, parent_event->cpu, child,
                                 group_leader, parent_event, NULL, NULL);
  if (IS_ERR(child_event)) return child_event;
  if (!atomic_long_inc_not_zero(&parent_event->refcount)) {
    free_event(child_event);
    return NULL;
  }
  get_ctx(child_ctx);
  if (parent_event->state >= PERF_EVENT_STATE_INACTIVE)
    child_event->state = PERF_EVENT_STATE_INACTIVE;
  else
    child_event->state = PERF_EVENT_STATE_OFF;
  if (parent_event->attr.freq) {
    u64 sample_period = parent_event->hw.sample_period;
    struct hw_perf_event* hwc = &child_event->hw;
    hwc->sample_period = sample_period;
    hwc->last_period = sample_period;
    local64_set(&hwc->period_left, sample_period);
  }
  child_event->ctx = child_ctx;
  child_event->overflow_handler = parent_event->overflow_handler;
  child_event->overflow_handler_context =
      parent_event->overflow_handler_context;
  perf_event__header_size(child_event);
  perf_event__id_header_size(child_event);
  raw_spin_lock_irqsave(&child_ctx->lock, flags);
  add_event_to_ctx(child_event, child_ctx);
  raw_spin_unlock_irqrestore(&child_ctx->lock, flags);
  WARN_ON_ONCE(parent_event->ctx->parent_ctx);
  mutex_lock(&parent_event->child_mutex);
  list_add_tail(&child_event->child_list, &parent_event->child_list);
  mutex_unlock(&parent_event->child_mutex);
  return child_event;
}

void LIRGenerator::do_LogicOp(LogicOp* x) {
  if (x->is_commutative() && x->y()->as_Constant() == NULL &&
      x->x()->use_count() > x->y()->use_count()) {
    x->swap_operands();
  }
  LIRItem left(x->x(), this);
  LIRItem right(x->y(), this);
  left.load_item();
  right.load_nonconstant();
  LIR_Opr reg = rlock_result(x);
  logic_op(x->op(), reg, left.result(), right.result());
}

bool sctp_verify_asconf(const struct sctp_association* asoc,
                        struct sctp_chunk* chunk, bool addr_param_needed,
                        struct sctp_paramhdr** errp) {
  sctp_addip_chunk_t* addip = (sctp_addip_chunk_t*)chunk->chunk_hdr;
  union sctp_params param;
  bool addr_param_seen = false;
  sctp_walk_params(param, addip, addip_hdr.params) {
    size_t length = ntohs(param.p->length);
    *errp = param.p;
    switch (param.p->type) {
      case SCTP_PARAM_ERR_CAUSE:
        break;
      case SCTP_PARAM_IPV4_ADDRESS:
        if (length != sizeof(sctp_ipv4addr_param_t)) return false;
        addr_param_seen = true;
        break;
      case SCTP_PARAM_IPV6_ADDRESS:
        if (length != sizeof(sctp_ipv6addr_param_t)) return false;
        addr_param_seen = true;
        break;
      case SCTP_PARAM_ADD_IP:
      case SCTP_PARAM_DEL_IP:
      case SCTP_PARAM_SET_PRIMARY:
        if (addr_param_needed && !addr_param_seen) return false;
        length = ntohs(param.addip->param_hdr.length);
        if (length < sizeof(sctp_addip_param_t) + sizeof(sctp_paramhdr_t))
          return false;
        break;
      case SCTP_PARAM_SUCCESS_REPORT:
      case SCTP_PARAM_ADAPTATION_LAYER_IND:
        if (length != sizeof(sctp_addip_param_t)) return false;
        break;
      default:
        return false;
    }
  }
  if (addr_param_needed && !addr_param_seen) return false;
  if (!addr_param_needed && addr_param_seen) return false;
  if (param.v != chunk->chunk_end) return false;
  return true;
}

coolkey_find_object_by_template(sc_card_t* card,
                                sc_cardctl_coolkey_attribute_t* template,
                                int count) {
  list_t* list;
  sc_cardctl_coolkey_object_t *current, *rv = NULL;
  coolkey_private_data_t* priv = COOLKEY_DATA(card);
  int i, r;
  unsigned int tmp_pos = (unsigned int)-1;
  list = &priv->objects_list;
  if (list->iter_active) {
    tmp_pos = list->iter_pos;
    list_iterator_stop(list);
  }
  list_iterator_start(list);
  while (list_iterator_hasnext(list)) {
    sc_cardctl_coolkey_attribute_t attribute;
    current = list_iterator_next(list);
    attribute.object = current;
    for (i = 0; i < count; i++) {
      attribute.attribute_type = template[i].attribute_type;
      r = coolkey_find_attribute(card, &attribute);
      if (r < 0) {
        break;
      }
      if (template[i].attribute_data_type != attribute.attribute_data_type) {
        break;
      }
      if (template[i].attribute_length != attribute.attribute_length) {
        break;
      }
      if (memcmp(attribute.attribute_value, template[i].attribute_value,
                 attribute.attribute_length) != 0) {
        break;
      }
    }
    if (i == count) {
      rv = current;
      break;
    }
  }
  list_iterator_stop(list);
  if (tmp_pos != (unsigned int)-1) {
    list_iterator_start(list);
    while (list_iterator_hasnext(list) && list->iter_pos < tmp_pos)
      (void)list_iterator_next(list);
  }
  return rv;
}

xfs_iunlink(struct xfs_trans* tp, struct xfs_inode* ip) {
  struct xfs_mount* mp = tp->t_mountp;
  struct xfs_agi* agi;
  struct xfs_buf* agibp;
  xfs_agino_t next_agino;
  xfs_agnumber_t agno = XFS_INO_TO_AGNO(mp, ip->i_ino);
  xfs_agino_t agino = XFS_INO_TO_AGINO(mp, ip->i_ino);
  short bucket_index = agino % XFS_AGI_UNLINKED_BUCKETS;
  int error;
  ASSERT(VFS_I(ip)->i_nlink == 0);
  ASSERT(VFS_I(ip)->i_mode != 0);
  trace_xfs_iunlink(ip);
  error = xfs_read_agi(mp, tp, agno, &agibp);
  if (error) return error;
  agi = agibp->b_addr;
  next_agino = be32_to_cpu(agi->agi_unlinked[bucket_index]);
  if (next_agino == agino || !xfs_verify_agino_or_null(mp, agno, next_agino)) {
    xfs_buf_mark_corrupt(agibp);
    return -EFSCORRUPTED;
  }
  if (next_agino != NULLAGINO) {
    xfs_agino_t old_agino;
    error = xfs_iunlink_update_inode(tp, ip, agno, next_agino, &old_agino);
    if (error) return error;
    ASSERT(old_agino == NULLAGINO);
    error = xfs_iunlink_add_backref(agibp->b_pag, agino, next_agino);
    if (error) return error;
  }
  return xfs_iunlink_update_bucket(tp, agno, agibp, bucket_index, agino);
}

