static void extend_solid_area(VncState* vs, int x, int y, int w, int h,
                              uint32_t color, int* x_ptr, int* y_ptr,
                              int* w_ptr, int* h_ptr) {
  int cx, cy;
  for (cy = *y_ptr - 1;
       cy >= y && check_solid_tile(vs, *x_ptr, cy, *w_ptr, 1, &color, true);
       cy--);
  *h_ptr += *y_ptr - (cy + 1);
  *y_ptr = cy + 1;
  for (cy = *y_ptr + *h_ptr;
       cy < y + h && check_solid_tile(vs, *x_ptr, cy, *w_ptr, 1, &color, true);
       cy++);
  *h_ptr += cy - (*y_ptr + *h_ptr);
  for (cx = *x_ptr - 1;
       cx >= x && check_solid_tile(vs, cx, *y_ptr, 1, *h_ptr, &color, true);
       cx--);
  *w_ptr += *x_ptr - (cx + 1);
  *x_ptr = cx + 1;
  for (cx = *x_ptr + *w_ptr;
       cx < x + w && check_solid_tile(vs, cx, *y_ptr, 1, *h_ptr, &color, true);
       cx++);
  *w_ptr += cx - (*x_ptr + *w_ptr);
}

void AutoFillManager::FillPhoneNumberField(const AutoFillProfile* profile,
