static void intel_unmap(struct device* dev, dma_addr_t dev_addr, size_t size) {
  struct dmar_domain* domain;
  unsigned long start_pfn, last_pfn;
  unsigned long nrpages;
  unsigned long iova_pfn;
  struct intel_iommu* iommu;
  struct page* freelist;
  if (iommu_no_mapping(dev)) return;
  domain = find_domain(dev);
  BUG_ON(!domain);
  iommu = domain_get_iommu(domain);
  iova_pfn = IOVA_PFN(dev_addr);
  nrpages = aligned_nrpages(dev_addr, size);
  start_pfn = mm_to_dma_pfn(iova_pfn);
  last_pfn = start_pfn + nrpages - 1;
  pr_debug("Device %s unmapping: pfn %lx-%lx\n", dev_name(dev), start_pfn,
           last_pfn);
  freelist = domain_unmap(domain, start_pfn, last_pfn);
  if (intel_iommu_strict) {
    iommu_flush_iotlb_psi(iommu, domain, start_pfn, nrpages, !freelist, 0);
    free_iova_fast(&domain->iovad, iova_pfn, dma_to_mm_pfn(nrpages));
    dma_free_pagelist(freelist);
  } else {
    queue_iova(&domain->iovad, iova_pfn, nrpages, (unsigned long)freelist);
  }
}

bool WasmBinaryBuilder::maybeVisitSIMDLoadStoreLane(Expression*& out,
                                                    uint32_t code) {
  SIMDLoadStoreLaneOp op;
  size_t lanes;
  switch (code) {
    case BinaryConsts::V128Load8Lane:
      op = Load8LaneVec128;
      lanes = 16;
      break;
    case BinaryConsts::V128Load16Lane:
      op = Load16LaneVec128;
      lanes = 8;
      break;
    case BinaryConsts::V128Load32Lane:
      op = Load32LaneVec128;
      lanes = 4;
      break;
    case BinaryConsts::V128Load64Lane:
      op = Load64LaneVec128;
      lanes = 2;
      break;
    case BinaryConsts::V128Store8Lane:
      op = Store8LaneVec128;
      lanes = 16;
      break;
    case BinaryConsts::V128Store16Lane:
      op = Store16LaneVec128;
      lanes = 8;
      break;
    case BinaryConsts::V128Store32Lane:
      op = Store32LaneVec128;
      lanes = 4;
      break;
    case BinaryConsts::V128Store64Lane:
      op = Store64LaneVec128;
      lanes = 2;
      break;
    default:
      return false;
  }
  auto* curr = allocator.alloc<SIMDLoadStoreLane>();
  curr->op = op;
  readMemoryAccess(curr->align, curr->offset);
  curr->index = getLaneIndex(lanes);
  curr->vec = popNonVoidExpression();
  curr->ptr = popNonVoidExpression();
  curr->finalize();
  out = curr;
  return true;
}

