rb_reg_match_last(VALUE match) {
  int i;
  struct re_registers* regs;
  if (NIL_P(match)) return Qnil;
  match_check(match);
  regs = RMATCH_REGS(match);
  if (BEG(0) == -1) return Qnil;
  for (i = regs->num_regs - 1; BEG(i) == -1 && i > 0; i--);
  if (i == 0) return Qnil;
  return rb_reg_nth_match(i, match);
}

static bool repeatedPtrFieldEqual(
    const Protobuf::RepeatedPtrField<ProtoType>& lhs,
    const Protobuf::RepeatedPtrField<ProtoType>& rhs,
    bool ignore_ordering = false) {
  if (lhs.size() != rhs.size()) {
    return false;
  }
  if (!ignore_ordering) {
    for (int i = 0; i < lhs.size(); ++i) {
      if (!TestUtility::protoEqual(lhs[i], rhs[i], false)) {
        return false;
      }
    }
    return true;
  }
  using ProtoList = std::list<std::unique_ptr<const Protobuf::Message>>;
  ProtoList lhs_list =
      RepeatedPtrUtil::convertToConstMessagePtrContainer<ProtoType, ProtoList>(
          lhs);
  ProtoList rhs_list =
      RepeatedPtrUtil::convertToConstMessagePtrContainer<ProtoType, ProtoList>(
          rhs);
  while (!lhs_list.empty()) {
    bool found = false;
    for (auto it = rhs_list.begin(); it != rhs_list.end(); ++it) {
      if (TestUtility::protoEqual(*lhs_list.front(), **it, true)) {
        lhs_list.pop_front();
        rhs_list.erase(it);
        found = true;
        break;
      }
    }
    if (!found) {
      return false;
    }
  }
  return true;
}

void FileSystemOperation::Move(const GURL& src_path_url,
                               const GURL& dest_path_url,
                               const StatusCallback& callback) {
  DCHECK(SetPendingOperationType(kOperationMove));
  base::PlatformFileError result =
      SetUpFileSystemPath(src_path_url, &src_path_, &src_util_, PATH_FOR_WRITE);
  if (result == base::PLATFORM_FILE_OK)
    result = SetUpFileSystemPath(dest_path_url, &dest_path_, &dest_util_,
                                 PATH_FOR_CREATE);
  if (result != base::PLATFORM_FILE_OK) {
    callback.Run(result);
    delete this;
    return;
  }
  GetUsageAndQuotaThenRunTask(
      dest_path_.origin(), dest_path_.type(),
      base::Bind(&FileSystemOperation::DoMove, base::Unretained(this),
                 callback),
      base::Bind(callback, base::PLATFORM_FILE_ERROR_FAILED));
}

