static int lstats_show_proc(struct seq_file* m, void* v) {
  int i;
  struct task_struct* task = m->private;
  seq_puts(m, "Latency Top version : v0.1\n");
  for (i = 0; i < 32; i++) {
    if (task->latency_record[i].backtrace[0]) {
      int q;
      seq_printf(m, "%i %li %li ", task->latency_record[i].count,
                 task->latency_record[i].time, task->latency_record[i].max);
      for (q = 0; q < LT_BACKTRACEDEPTH; q++) {
        char sym[KSYM_NAME_LEN];
        char* c;
        if (!task->latency_record[i].backtrace[q]) break;
        if (task->latency_record[i].backtrace[q] == ULONG_MAX) break;
        sprint_symbol(sym, task->latency_record[i].backtrace[q]);
        c = strchr(sym, '+');
        if (c) *c = 0;
        seq_printf(m, "%s ", sym);
      }
      seq_printf(m, "\n");
    }
  }
  return 0;
}

static int inet6_netconf_fill_devconf(struct sk_buff* skb, int ifindex,
                                      struct ipv6_devconf* devconf, u32 portid,
                                      u32 seq, int event, unsigned int flags,
                                      int type) {
  struct nlmsghdr* nlh;
  struct netconfmsg* ncm;
  nlh = nlmsg_put(skb, portid, seq, event, sizeof(struct netconfmsg), flags);
  if (nlh == NULL) return -EMSGSIZE;
  ncm = nlmsg_data(nlh);
  ncm->ncm_family = AF_INET6;
  if (nla_put_s32(skb, NETCONFA_IFINDEX, ifindex) < 0) goto nla_put_failure;
  if ((type == -1 || type == NETCONFA_FORWARDING) &&
      nla_put_s32(skb, NETCONFA_FORWARDING, devconf->forwarding) < 0)
    goto nla_put_failure;
#ifdef CONFIG_IPV6_MROUTE
  if ((type == -1 || type == NETCONFA_MC_FORWARDING) &&
      nla_put_s32(skb, NETCONFA_MC_FORWARDING, devconf->mc_forwarding) < 0)
    goto nla_put_failure;
#endif
  return nlmsg_end(skb, nlh);
nla_put_failure:
  nlmsg_cancel(skb, nlh);
  return -EMSGSIZE;
}

bool DelChan(CWebSock& WebSock, CIRCNetwork* pNetwork) {
  CString sChan = WebSock.GetParam("name", false);
  if (sChan.empty()) {
    WebSock.PrintErrorPage("That channel doesn't exist for this user");
    return true;
  }
  pNetwork->DelChan(sChan);
  pNetwork->PutIRC("PART " + sChan);
  if (!CZNC::Get().WriteConfig()) {
    WebSock.PrintErrorPage("Channel deleted, but config was not written");
    return true;
  }
  WebSock.Redirect(GetWebPath() + "editnetwork?user=" +
                   pNetwork->GetUser()->GetUserName().Escape_n(CString::EURL) +
                   "&network=" + pNetwork->GetName().Escape_n(CString::EURL));
  return false;
}

void nl80211_ch_switch_notify(struct cfg80211_registered_device* rdev,
                              struct net_device* netdev,
                              struct cfg80211_chan_def* chandef, gfp_t gfp) {
  struct sk_buff* msg;
  void* hdr;
  msg = nlmsg_new(NLMSG_DEFAULT_SIZE, gfp);
  if (!msg) return;
  hdr = nl80211hdr_put(msg, 0, 0, 0, NL80211_CMD_CH_SWITCH_NOTIFY);
  if (!hdr) {
    nlmsg_free(msg);
    return;
  }
  if (nla_put_u32(msg, NL80211_ATTR_IFINDEX, netdev->ifindex))
    goto nla_put_failure;
  if (nl80211_send_chandef(msg, chandef)) goto nla_put_failure;
  genlmsg_end(msg, hdr);
  genlmsg_multicast_netns(wiphy_net(&rdev->wiphy), msg, 0,
                          nl80211_mlme_mcgrp.id, gfp);
  return;
nla_put_failure:
  genlmsg_cancel(msg, hdr);
  nlmsg_free(msg);
}

static struct key* request_master_key(struct encrypted_key_payload* epayload,
                                      u8** master_key, size_t* master_keylen) {
  struct key* mkey = NULL;
  if (!strncmp(epayload->master_desc, KEY_TRUSTED_PREFIX,
               KEY_TRUSTED_PREFIX_LEN)) {
    mkey = request_trusted_key(epayload->master_desc + KEY_TRUSTED_PREFIX_LEN,
                               master_key, master_keylen);
  } else if (!strncmp(epayload->master_desc, KEY_USER_PREFIX,
                      KEY_USER_PREFIX_LEN)) {
    mkey = request_user_key(epayload->master_desc + KEY_USER_PREFIX_LEN,
                            master_key, master_keylen);
  } else
    goto out;
  if (IS_ERR(mkey)) {
    int ret = PTR_ERR(mkey);
    if (ret == -ENOTSUPP)
      pr_info("encrypted_key: key %s not supported", epayload->master_desc);
    else
      pr_info("encrypted_key: key %s not found", epayload->master_desc);
    goto out;
  }
  dump_master_key(*master_key, *master_keylen);
out:
  return mkey;
}

int sock_queue_rcv_skb(struct sock* sk, struct sk_buff* skb) {
  int err = 0;
  int skb_len;
  if (atomic_read(&sk->sk_rmem_alloc) + skb->truesize >=
      (unsigned)sk->sk_rcvbuf) {
    err = -ENOMEM;
    goto out;
  }
  err = sk_filter(sk, skb);
  if (err) goto out;
  if (!sk_rmem_schedule(sk, skb->truesize)) {
    err = -ENOBUFS;
    goto out;
  }
  skb->dev = NULL;
  skb_set_owner_r(skb, sk);
  skb_len = skb->len;
  skb_queue_tail(&sk->sk_receive_queue, skb);
  if (!sock_flag(sk, SOCK_DEAD)) sk->sk_data_ready(sk, skb_len);
out:
  return err;
}

