and_code_range_buf(BBuf* bbuf1, int not1, BBuf* bbuf2, int not2, BBuf** pbuf) {
  int r;
  OnigCodePoint i, j, n1, n2, *data1, *data2;
  OnigCodePoint from, to, from1, to1, from2, to2;
  *pbuf = (BBuf*)NULL;
  if (IS_NULL(bbuf1)) {
    if (not1 != 0 && IS_NOT_NULL(bbuf2)) return bbuf_clone(pbuf, bbuf2);
    return 0;
  } else if (IS_NULL(bbuf2)) {
    if (not2 != 0) return bbuf_clone(pbuf, bbuf1);
    return 0;
  }
  if (not1 != 0) SWAP_BB_NOT(bbuf1, not1, bbuf2, not2);
  data1 = (OnigCodePoint*)(bbuf1->p);
  data2 = (OnigCodePoint*)(bbuf2->p);
  GET_CODE_POINT(n1, data1);
  GET_CODE_POINT(n2, data2);
  data1++;
  data2++;
  if (not2 == 0 && not1 == 0) {
    for (i = 0; i < n1; i++) {
      from1 = data1[i * 2];
      to1 = data1[i * 2 + 1];
      for (j = 0; j < n2; j++) {
        from2 = data2[j * 2];
        to2 = data2[j * 2 + 1];
        if (from2 > to1) break;
        if (to2 < from1) continue;
        from = MAX(from1, from2);
        to = MIN(to1, to2);
        r = add_code_range_to_buf(pbuf, from, to);
        if (r != 0) return r;
      }
    }
  } else if (not1 == 0) {
    for (i = 0; i < n1; i++) {
      from1 = data1[i * 2];
      to1 = data1[i * 2 + 1];
      r = and_code_range1(pbuf, from1, to1, data2, n2);
      if (r != 0) return r;
    }
  }
  return 0;
}

GF_Err udta_on_child_box(GF_Box* s, GF_Box* a, Bool is_rem) {
  GF_Err e;
  u32 box_type;
  GF_UserDataMap* map;
  GF_UserDataBox* ptr = (GF_UserDataBox*)s;
  if (!ptr) return GF_BAD_PARAM;
  if (!a) return GF_OK;
  gf_list_del_item(ptr->child_boxes, a);
  box_type = a->type;
  if (box_type == GF_ISOM_BOX_TYPE_UNKNOWN) {
    GF_UnknownBox* unkn = (GF_UnknownBox*)a;
    box_type = unkn->original_4cc;
  }
  map = udta_getEntry(
      ptr, box_type,
      (a->type == GF_ISOM_BOX_TYPE_UUID) ? &((GF_UUIDBox*)a)->uuid : NULL);
  if (map == NULL) {
    if (is_rem) return GF_OK;
    map = (GF_UserDataMap*)gf_malloc(sizeof(GF_UserDataMap));
    if (map == NULL) return GF_OUT_OF_MEM;
    memset(map, 0, sizeof(GF_UserDataMap));
    map->boxType = box_type;
    if (a->type == GF_ISOM_BOX_TYPE_UUID)
      memcpy(map->uuid, ((GF_UUIDBox*)a)->uuid, 16);
    map->boxes = gf_list_new();
    if (!map->boxes) {
      gf_free(map);
      return GF_OUT_OF_MEM;
    }
    e = gf_list_add(ptr->recordList, map);
    if (e) return e;
  }
  if (is_rem) {
    gf_list_del_item(map->boxes, a);
    return GF_OK;
  }
  return gf_list_add(map->boxes, a);
}

static void addrconf_dad_start(struct inet6_ifaddr* ifp) {
  struct inet6_dev* idev = ifp->idev;
  struct net_device* dev = idev->dev;
  addrconf_join_solict(dev, &ifp->addr);
  net_srandom(ifp->addr.s6_addr32[3]);
  read_lock_bh(&idev->lock);
  spin_lock(&ifp->lock);
  if (ifp->state == INET6_IFADDR_STATE_DEAD) goto out;
  if (dev->flags & (IFF_NOARP | IFF_LOOPBACK) || idev->cnf.accept_dad < 1 ||
      !(ifp->flags & IFA_F_TENTATIVE) || ifp->flags & IFA_F_NODAD) {
    ifp->flags &= ~(IFA_F_TENTATIVE | IFA_F_OPTIMISTIC | IFA_F_DADFAILED);
    spin_unlock(&ifp->lock);
    read_unlock_bh(&idev->lock);
    addrconf_dad_completed(ifp);
    return;
  }
  if (!(idev->if_flags & IF_READY)) {
    spin_unlock(&ifp->lock);
    read_unlock_bh(&idev->lock);
    in6_ifa_hold(ifp);
    addrconf_dad_stop(ifp, 0);
    return;
  }
  if (ifp->flags & IFA_F_OPTIMISTIC) ip6_ins_rt(ifp->rt);
  addrconf_dad_kick(ifp);
out:
  spin_unlock(&ifp->lock);
  read_unlock_bh(&idev->lock);
}

