static void virtio_net_handle_tx_timer(VirtIODevice* vdev, VirtQueue* vq) {
  VirtIONet* n = VIRTIO_NET(vdev);
  VirtIONetQueue* q = &n->vqs[vq2q(virtio_get_queue_index(vq))];
  if (unlikely((n->status & VIRTIO_NET_S_LINK_UP) == 0)) {
    virtio_net_drop_tx_queue_data(vdev, vq);
    return;
  }
  if (!vdev->vm_running) {
    q->tx_waiting = 1;
    return;
  }
  if (q->tx_waiting) {
    virtio_queue_set_notification(vq, 1);
    timer_del(q->tx_timer);
    q->tx_waiting = 0;
    if (virtio_net_flush_tx(q) == -EINVAL) {
      return;
    }
  } else {
    timer_mod(q->tx_timer,
              qemu_clock_get_ns(QEMU_CLOCK_VIRTUAL) + n->tx_timeout);
    q->tx_waiting = 1;
    virtio_queue_set_notification(vq, 0);
  }
}

static int send_creds(int sock, struct ucred* cred, char v, bool pingfirst) {
  struct msghdr msg = {0};
  struct iovec iov;
  struct cmsghdr* cmsg;
  char cmsgbuf[CMSG_SPACE(sizeof(*cred))];
  char buf[1];
  buf[0] = 'p';
  if (pingfirst) {
    if (msgrecv(sock, buf, 1) != 1) {
      fprintf(stderr, "%s: Error getting reply from server over socketpair\n",
              __func__);
      return SEND_CREDS_FAIL;
    }
  }
  msg.msg_control = cmsgbuf;
  msg.msg_controllen = sizeof(cmsgbuf);
  cmsg = CMSG_FIRSTHDR(&msg);
  cmsg->cmsg_len = CMSG_LEN(sizeof(struct ucred));
  cmsg->cmsg_level = SOL_SOCKET;
  cmsg->cmsg_type = SCM_CREDENTIALS;
  memcpy(CMSG_DATA(cmsg), cred, sizeof(*cred));
  msg.msg_name = NULL;
  msg.msg_namelen = 0;
  buf[0] = v;
  iov.iov_base = buf;
  iov.iov_len = sizeof(buf);
  msg.msg_iov = &iov;
  msg.msg_iovlen = 1;
  if (sendmsg(sock, &msg, 0) < 0) {
    fprintf(stderr, "%s: failed at sendmsg: %s\n", __func__, strerror(errno));
    if (errno == 3) return SEND_CREDS_NOTSK;
    return SEND_CREDS_FAIL;
  }
  return SEND_CREDS_OK;
}

