bool InstanceKlass::is_same_class_package(
    oop other_class_loader, const Symbol* other_class_name) const {
  if (class_loader() != other_class_loader) {
    return false;
  }
  if (name()->fast_compare(other_class_name) == 0) {
    return true;
  }
  {
    ResourceMark rm;
    bool bad_class_name = false;
    TempNewSymbol other_pkg =
        ClassLoader::package_from_class_name(other_class_name, &bad_class_name);
    if (bad_class_name) {
      return false;
    }
    assert(other_pkg == NULL || other_pkg->utf8_length() > 0,
           "package name is empty string");
    const Symbol* const this_package_name =
        this->package() != NULL ? this->package()->name() : NULL;
    if (this_package_name == NULL || other_pkg == NULL) {
      return this_package_name == other_pkg;
    }
    return this_package_name->fast_compare(other_pkg) == 0;
  }
}

static int nested_svm_exit_special(struct vcpu_svm* svm) {
  u32 exit_code = svm->vmcb->control.exit_code;
  switch (exit_code) {
    case SVM_EXIT_INTR:
    case SVM_EXIT_NMI:
    case SVM_EXIT_EXCP_BASE + MC_VECTOR:
      return NESTED_EXIT_HOST;
    case SVM_EXIT_NPF:
      if (npt_enabled) return NESTED_EXIT_HOST;
      break;
    case SVM_EXIT_EXCP_BASE + PF_VECTOR:
      if (!npt_enabled && svm->apf_reason == 0) return NESTED_EXIT_HOST;
      break;
    case SVM_EXIT_EXCP_BASE + NM_VECTOR:
      nm_interception(svm);
      break;
    default:
      break;
  }
  return NESTED_EXIT_CONTINUE;
}

