                            void* private) {
  struct pagemapread* pm = private;
  unsigned long addr;
  int err = 0;
  for (addr = start; addr < end; addr += PAGE_SIZE) {
    err = add_to_pagemap(addr, PM_NOT_PRESENT, pm);
    if (err) break;
  }
  return err;
}

int LibRaw::open_file(const char* fname, INT64 max_buf_size) {
#ifndef WIN32
  struct stat st;
  if (stat(fname, &st)) return LIBRAW_IO_ERROR;
  int big = (st.st_size > max_buf_size) ? 1 : 0;
#else
  struct _stati64 st;
  if (_stati64(fname, &st)) return LIBRAW_IO_ERROR;
  int big = (st.st_size > max_buf_size) ? 1 : 0;
#endif
  LibRaw_abstract_datastream* stream;
  try {
    if (big)
      stream = new LibRaw_bigfile_datastream(fname);
    else
      stream = new LibRaw_file_datastream(fname);
  } catch (std::bad_alloc) {
    recycle();
    return LIBRAW_UNSUFFICIENT_MEMORY;
  }
  if (!stream->valid()) {
    delete stream;
    return LIBRAW_IO_ERROR;
  }
  ID.input_internal = 0;
  int ret = open_datastream(stream);
  if (ret == LIBRAW_SUCCESS) {
    ID.input_internal = 1;
  } else {
    delete stream;
    ID.input_internal = 0;
  }
  return ret;
}

void MrwImage::readMetadata() {
#ifdef DEBUG
  std::cerr << "Reading MRW file " << io_->path() << "\n";
#endif
  if (io_->open() != 0) {
    throw Error(kerDataSourceOpenFailed, io_->path(), strError());
  }
  IoCloser closer(*io_);
  if (!isMrwType(*io_, false)) {
    if (io_->error() || io_->eof()) throw Error(kerFailedToReadImageData);
    throw Error(kerNotAnImage, "MRW");
  }
  clearMetadata();
  uint32_t const len = 8;
  byte tmp[len];
  io_->read(tmp, len);
  uint32_t pos = len;
  uint32_t const end = getULong(tmp + 4, bigEndian);
  pos += len;
  if (pos > end) throw Error(kerFailedToReadImageData);
  io_->read(tmp, len);
  if (io_->error() || io_->eof()) throw Error(kerFailedToReadImageData);
  while (memcmp(tmp + 1, "TTW", 3) != 0) {
    uint32_t const siz = getULong(tmp + 4, bigEndian);
    pos += siz;
    if (pos > end) throw Error(kerFailedToReadImageData);
    io_->seek(siz, BasicIo::cur);
    if (io_->error() || io_->eof()) throw Error(kerFailedToReadImageData);
    pos += len;
    if (pos > end) throw Error(kerFailedToReadImageData);
    io_->read(tmp, len);
    if (io_->error() || io_->eof()) throw Error(kerFailedToReadImageData);
  }
  DataBuf buf(getULong(tmp + 4, bigEndian));
  io_->read(buf.pData_, buf.size_);
  if (io_->error() || io_->eof()) throw Error(kerFailedToReadImageData);
  ByteOrder bo = TiffParser::decode(exifData_, iptcData_, xmpData_, buf.pData_,
                                    (uint32_t)buf.size_);
  setByteOrder(bo);
}

