static int test_expmodone(void) {
  int ret = 0, i;
  BIGNUM* r = BN_new();
  BIGNUM* a = BN_new();
  BIGNUM* p = BN_new();
  BIGNUM* m = BN_new();
  if (!TEST_ptr(r) || !TEST_ptr(a) || !TEST_ptr(p) || !TEST_ptr(p) ||
      !TEST_ptr(m) || !TEST_true(BN_set_word(a, 1)) ||
      !TEST_true(BN_set_word(p, 0)) || !TEST_true(BN_set_word(m, 1)))
    goto err;
  for (i = 0; i < 2; i++) {
    if (!TEST_true(BN_mod_exp(r, a, p, m, NULL)) || !TEST_BN_eq_zero(r) ||
        !TEST_true(BN_mod_exp_mont(r, a, p, m, NULL, NULL)) ||
        !TEST_BN_eq_zero(r) ||
        !TEST_true(BN_mod_exp_mont_consttime(r, a, p, m, NULL, NULL)) ||
        !TEST_BN_eq_zero(r) ||
        !TEST_true(BN_mod_exp_mont_word(r, 1, p, m, NULL, NULL)) ||
        !TEST_BN_eq_zero(r) ||
        !TEST_true(BN_mod_exp_simple(r, a, p, m, NULL)) ||
        !TEST_BN_eq_zero(r) || !TEST_true(BN_mod_exp_recp(r, a, p, m, NULL)) ||
        !TEST_BN_eq_zero(r))
      goto err;
    if (i == 0) BN_set_negative(m, 1);
  }
  ret = 1;
err:
  BN_free(r);
  BN_free(a);
  BN_free(p);
  BN_free(m);
  return ret;
}

static TIFFMethodType GetJPEGMethod(Image* image, TIFF* tiff,
                                    uint16 photometric, uint16 bits_per_sample,
                                    uint16 samples_per_pixel) {
#define BUFFER_SIZE 2048
  MagickOffsetType position, offset;
  size_t i;
  TIFFMethodType method;
#if defined(TIFF_VERSION_BIG)
  uint64* value = (uint64*)NULL;
#else
  uint32* value = (uint32*)NULL;
#endif
  unsigned char buffer[BUFFER_SIZE + 32];
  unsigned short length;
  if ((photometric != PHOTOMETRIC_SEPARATED) || (bits_per_sample != 8) ||
      (samples_per_pixel != 4))
    return (ReadGenericMethod);
  if (!TIFFGetField(tiff, TIFFTAG_STRIPOFFSETS, &value) || (value == NULL))
    return (ReadStripMethod);
  position = TellBlob(image);
  offset = (MagickOffsetType)(value[0]);
  if (SeekBlob(image, offset, SEEK_SET) != offset) return (ReadStripMethod);
  method = ReadStripMethod;
  if (ReadBlob(image, BUFFER_SIZE, buffer) == BUFFER_SIZE) {
    for (i = 0; i < BUFFER_SIZE; i++) {
      while (i < BUFFER_SIZE) {
        if (buffer[i++] == 255) break;
      }
      while (i < BUFFER_SIZE) {
        if (buffer[++i] != 255) break;
      }
      if (buffer[i++] == 216) continue;
      length = (unsigned short)(((unsigned int)(buffer[i] << 8) |
                                 (unsigned int)buffer[i + 1]) &
                                0xffff);
      if (i + (size_t)length >= BUFFER_SIZE) break;
      if (buffer[i - 1] == 238) {
        if (length != 14) break;
        if (buffer[i + 13] == 2) method = ReadYCCKMethod;
        break;
      }
      i += (size_t)length;
    }
  }
  (void)SeekBlob(image, position, SEEK_SET);
  return (method);
}

void FAST_FUNC udhcp_add_binary_option(struct dhcp_packet* packet,
                                       uint8_t* addopt) {
  unsigned len;
  uint8_t* optionptr = packet->options;
  unsigned end = udhcp_end_option(optionptr);
  len = OPT_DATA + addopt[OPT_LEN];
  if (end + len + 1 >= DHCP_OPTIONS_BUFSIZE) {
    bb_error_msg("option 0x%02x did not fit into the packet", addopt[OPT_CODE]);
    return;
  }
  log_option("Adding option", addopt);
  memcpy(optionptr + end, addopt, len);
  optionptr[end + len] = DHCP_END;
}

int kill_pid_info_as_uid(int sig, struct siginfo* info, struct pid* pid,
                         uid_t uid, uid_t euid, u32 secid) {
  int ret = -EINVAL;
  struct task_struct* p;
  const struct cred* pcred;
  if (!valid_signal(sig)) return ret;
  read_lock(&tasklist_lock);
  p = pid_task(pid, PIDTYPE_PID);
  if (!p) {
    ret = -ESRCH;
    goto out_unlock;
  }
  pcred = __task_cred(p);
  if ((info == SEND_SIG_NOINFO ||
       (!is_si_special(info) && SI_FROMUSER(info))) &&
      euid != pcred->suid && euid != pcred->uid && uid != pcred->suid &&
      uid != pcred->uid) {
    ret = -EPERM;
    goto out_unlock;
  }
  ret = security_task_kill(p, info, sig, secid);
  if (ret) goto out_unlock;
  if (sig && p->sighand) {
    unsigned long flags;
    spin_lock_irqsave(&p->sighand->siglock, flags);
    ret = __send_signal(sig, info, p, 1, 0);
    spin_unlock_irqrestore(&p->sighand->siglock, flags);
  }
out_unlock:
  read_unlock(&tasklist_lock);
  return ret;
}

static int ldb_comparator_bitmask(const char* oid, const struct ldb_val* v1,
                                  const struct ldb_val* v2, bool* matched) {
  uint64_t i1, i2;
  char ibuf[100];
  char* endptr = NULL;
  if (v1->length >= sizeof(ibuf) - 1) {
    return LDB_ERR_INVALID_ATTRIBUTE_SYNTAX;
  }
  memcpy(ibuf, (char*)v1->data, v1->length);
  ibuf[v1->length] = 0;
  i1 = strtoull(ibuf, &endptr, 0);
  if (endptr != NULL) {
    if (endptr == ibuf || *endptr != 0) {
      return LDB_ERR_INVALID_ATTRIBUTE_SYNTAX;
    }
  }
  if (v2->length >= sizeof(ibuf) - 1) {
    return LDB_ERR_INVALID_ATTRIBUTE_SYNTAX;
  }
  endptr = NULL;
  memcpy(ibuf, (char*)v2->data, v2->length);
  ibuf[v2->length] = 0;
  i2 = strtoull(ibuf, &endptr, 0);
  if (endptr != NULL) {
    if (endptr == ibuf || *endptr != 0) {
      return LDB_ERR_INVALID_ATTRIBUTE_SYNTAX;
    }
  }
  if (strcmp(LDB_OID_COMPARATOR_AND, oid) == 0) {
    *matched = ((i1 & i2) == i2);
  } else if (strcmp(LDB_OID_COMPARATOR_OR, oid) == 0) {
    *matched = ((i1 & i2) != 0);
  } else {
    return LDB_ERR_INAPPROPRIATE_MATCHING;
  }
  return LDB_SUCCESS;
}

should_compact_retry(struct alloc_context* ac, unsigned int order,
                     int alloc_flags, enum compact_result compact_result,
                     enum compact_priority* compact_priority,
                     int* compaction_retries) {
  struct zone* zone;
  struct zoneref* z;
  if (!order || order > PAGE_ALLOC_COSTLY_ORDER) return false;
  for_each_zone_zonelist_nodemask(zone, z, ac->zonelist, ac->high_zoneidx,
                                  ac->nodemask) {
    if (zone_watermark_ok(zone, 0, min_wmark_pages(zone), ac_classzone_idx(ac),
                          alloc_flags))
