  }
  return false;
}

static int setup_netfront_single(struct netfront_queue* queue) {
  int err;
  err = xenbus_alloc_evtchn(queue->info->xbdev, &queue->tx_evtchn);
  if (err < 0) goto fail;
  err = bind_evtchn_to_irqhandler_lateeoi(queue->tx_evtchn, xennet_interrupt, 0,
                                          queue->info->netdev->name, queue);
  if (err < 0) goto bind_fail;
  queue->rx_evtchn = queue->tx_evtchn;
  queue->rx_irq = queue->tx_irq = err;
  return 0;
bind_fail:
  xenbus_free_evtchn(queue->info->xbdev, queue->tx_evtchn);
  queue->tx_evtchn = 0;
fail:
  return err;
}

