smb3_set_oplock_level(struct cifsInodeInfo* cinode, __u32 oplock,
                      unsigned int epoch, bool* purge_cache) {
  unsigned int old_oplock = cinode->oplock;
  smb21_set_oplock_level(cinode, oplock, epoch, purge_cache);
  if (purge_cache) {
    *purge_cache = false;
    if (old_oplock == CIFS_CACHE_READ_FLG) {
      if (cinode->oplock == CIFS_CACHE_READ_FLG && (epoch - cinode->epoch > 0))
        *purge_cache = true;
      else if (cinode->oplock == CIFS_CACHE_RH_FLG &&
               (epoch - cinode->epoch > 1))
        *purge_cache = true;
      else if (cinode->oplock == CIFS_CACHE_RHW_FLG &&
               (epoch - cinode->epoch > 1))
        *purge_cache = true;
      else if (cinode->oplock == 0 && (epoch - cinode->epoch > 0))
        *purge_cache = true;
    } else if (old_oplock == CIFS_CACHE_RH_FLG) {
      if (cinode->oplock == CIFS_CACHE_RH_FLG && (epoch - cinode->epoch > 0))
        *purge_cache = true;
      else if (cinode->oplock == CIFS_CACHE_RHW_FLG &&
               (epoch - cinode->epoch > 1))
        *purge_cache = true;
    }
    cinode->epoch = epoch;
  }
}

CURLcode Curl_disconnect(struct connectdata* conn, bool dead_connection) {
  struct SessionHandle* data;
  if (!conn) return CURLE_OK;
  data = conn->data;
  if (!data) {
    DEBUGF(fprintf(stderr, "DISCONNECT without easy handle, ignoring\n"));
    return CURLE_OK;
  }
  if (conn->dns_entry != NULL) {
    Curl_resolv_unlock(data, conn->dns_entry);
    conn->dns_entry = NULL;
  }
  Curl_hostcache_prune(data);
#if !defined(CURL_DISABLE_HTTP) && defined(USE_NTLM)
  Curl_http_ntlm_cleanup(conn);
#endif
  if (conn->handler->disconnect)
    conn->handler->disconnect(conn, dead_connection);
  infof(data, "Closing connection %ld\n", conn->connection_id);
  Curl_conncache_remove_conn(data->state.conn_cache, conn);
#if defined(USE_LIBIDN)
  if (conn->host.encalloc) idn_free(conn->host.encalloc);
  if (conn->proxy.encalloc) idn_free(conn->proxy.encalloc);
#elif defined(USE_WIN32_IDN)
  free(conn->host.encalloc);
  if (conn->proxy.encalloc) free(conn->proxy.encalloc);
#endif
  Curl_ssl_close(conn, FIRSTSOCKET);
  if (Curl_multi_pipeline_enabled(data->multi)) {
    signalPipeClose(conn->send_pipe, TRUE);
    signalPipeClose(conn->recv_pipe, TRUE);
  }
  conn_free(conn);
  return CURLE_OK;
}

