static int on_freelist(struct kmem_cache* s, struct page* page, void* search) {
  int nr = 0;
  void* fp;
  void* object = NULL;
  int max_objects;
  fp = page->freelist;
  while (fp && nr <= page->objects) {
    if (fp == search) return 1;
    if (!check_valid_pointer(s, page, fp)) {
      if (object) {
        object_err(s, page, object, "Freechain corrupt");
        set_freepointer(s, object, NULL);
      } else {
        slab_err(s, page, "Freepointer corrupt");
        page->freelist = NULL;
        page->inuse = page->objects;
        slab_fix(s, "Freelist cleared");
        return 0;
      }
      break;
    }
    object = fp;
    fp = get_freepointer(s, object);
    nr++;
  }
  max_objects = order_objects(compound_order(page), s->size);
  if (max_objects > MAX_OBJS_PER_PAGE) max_objects = MAX_OBJS_PER_PAGE;
  if (page->objects != max_objects) {
    slab_err(s, page, "Wrong number of objects. Found %d but should be %d",
             page->objects, max_objects);
    page->objects = max_objects;
    slab_fix(s, "Number of objects adjusted.");
  }
  if (page->inuse != page->objects - nr) {
    slab_err(s, page, "Wrong object count. Counter is %d but counted were %d",
             page->inuse, page->objects - nr);
    page->inuse = page->objects - nr;
    slab_fix(s, "Object count adjusted.");
  }
  return search == NULL;
}

static int sr_share_write_word(struct usbnet* dev, int phy, u8 reg,
                               __le16 value) {
  int ret;
  mutex_lock(&dev->phy_mutex);
  ret = sr_write(dev, SR_EPDR, 2, &value);
  if (ret < 0) goto out_unlock;
  sr_write_reg(dev, SR_EPAR, phy ? (reg | EPAR_PHY_ADR) : reg);
  sr_write_reg(
      dev, SR_EPCR,
      phy ? (EPCR_WEP | EPCR_EPOS | EPCR_ERPRW) : (EPCR_WEP | EPCR_ERPRW));
  ret = wait_phy_eeprom_ready(dev, phy);
  if (ret < 0) goto out_unlock;
  sr_write_reg(dev, SR_EPCR, 0x0);
out_unlock:
  mutex_unlock(&dev->phy_mutex);
  return ret;
}

