static int fetch_setup_walk(git_revwalk** out, git_repository* repo) {
  git_revwalk* walk = NULL;
  git_strarray refs;
  unsigned int i;
  git_reference* ref;
  int error;
  if ((error = git_reference_list(&refs, repo)) < 0) return error;
  if ((error = git_revwalk_new(&walk, repo)) < 0) return error;
  git_revwalk_sorting(walk, GIT_SORT_TIME);
  for (i = 0; i < refs.count; ++i) {
    if (!git__prefixcmp(refs.strings[i], GIT_REFS_TAGS_DIR)) continue;
    if ((error = git_reference_lookup(&ref, repo, refs.strings[i])) < 0)
      goto on_error;
    if (git_reference_type(ref) == GIT_REF_SYMBOLIC) continue;
    if ((error = git_revwalk_push(walk, git_reference_target(ref))) < 0)
      goto on_error;
    git_reference_free(ref);
  }
  git_strarray_free(&refs);
  *out = walk;
  return 0;
on_error:
  git_revwalk_free(walk);
  git_reference_free(ref);
  git_strarray_free(&refs);
  return error;
}

static void tcp_init_buffer_space(struct sock* sk) {
  struct tcp_sock* tp = tcp_sk(sk);
  int maxwin;
  if (!(sk->sk_userlocks & SOCK_RCVBUF_LOCK)) tcp_fixup_rcvbuf(sk);
  if (!(sk->sk_userlocks & SOCK_SNDBUF_LOCK)) tcp_fixup_sndbuf(sk);
  tp->rcvq_space.space = tp->rcv_wnd;
  maxwin = tcp_full_space(sk);
  if (tp->window_clamp >= maxwin) {
    tp->window_clamp = maxwin;
    if (sysctl_tcp_app_win && maxwin > 4 * tp->advmss)
      tp->window_clamp =
          max(maxwin - (maxwin >> sysctl_tcp_app_win), 4 * tp->advmss);
  }
  if (sysctl_tcp_app_win && tp->window_clamp > 2 * tp->advmss &&
      tp->window_clamp + tp->advmss > maxwin)
    tp->window_clamp = max(2 * tp->advmss, maxwin - tp->advmss);
  tp->rcv_ssthresh = min(tp->rcv_ssthresh, tp->window_clamp);
  tp->snd_cwnd_stamp = tcp_time_stamp;
}

