int _gnutls_encrypt(gnutls_session_t session, const opaque* headers,
                    size_t headers_size, const opaque* data, size_t data_size,
                    opaque* ciphertext, size_t ciphertext_size,
                    content_type_t type, int random_pad) {
  gnutls_datum_t plain;
  gnutls_datum_t comp;
  int ret;
  int free_comp = 1;
  plain.data = (opaque*)data;
  plain.size = data_size;
  if (plain.size == 0 || is_write_comp_null(session) == 0) {
    comp = plain;
    free_comp = 0;
  } else {
    ret = _gnutls_m_plaintext2compressed(session, &comp, plain);
    if (ret < 0) {
      gnutls_assert();
      return ret;
    }
  }
  ret = _gnutls_compressed2ciphertext(session, &ciphertext[headers_size],
                                      ciphertext_size - headers_size, comp,
                                      type, random_pad);
  if (free_comp) _gnutls_free_datum(&comp);
  if (ret < 0) {
    gnutls_assert();
    return ret;
  }
  memcpy(ciphertext, headers, headers_size);
  _gnutls_write_uint16(ret, &ciphertext[3]);
  return ret + headers_size;
}

void PackLinuxElf64::pack4(OutputFile* fo, Filter& ft) {
  overlay_offset = sz_elf_hdrs + sizeof(linfo);
  if (opt->o_unix.preserve_build_id) {
    unsigned const len = fpad4(fo);
    set_te64(&elfout.ehdr.e_shoff, len);
    int const ssize = sizeof(shdrout);
    shdrout.shdr[2].sh_offset = len + ssize;
    shdrout.shdr[1].sh_offset =
        shdrout.shdr[2].sh_offset + shdrout.shdr[2].sh_size;
    fo->write(&shdrout, ssize);
    fo->write(o_shstrtab, shdrout.shdr[2].sh_size);
    fo->write(buildid_data, shdrout.shdr[1].sh_size);
  }
  set_te64(&elfout.phdr[0].p_filesz, sz_pack2 + lsize);
  elfout.phdr[0].p_memsz = elfout.phdr[0].p_filesz;
  super::pack4(fo, ft);
  fo->seek(0, SEEK_SET);
  if (0 != xct_off) {
    fo->rewrite(&lowmem[0], sizeof(ehdri) + e_phnum * sizeof(Elf64_Phdr));
    fo->seek(sz_elf_hdrs, SEEK_SET);
    fo->rewrite(&linfo, sizeof(linfo));
  } else {
    if (PT_NOTE64 == get_te64(&elfout.phdr[2].p_type)) {
      upx_uint64_t const reloc = get_te64(&elfout.phdr[0].p_vaddr);
      set_te64(&elfout.phdr[2].p_vaddr,
               reloc + get_te64(&elfout.phdr[2].p_vaddr));
      set_te64(&elfout.phdr[2].p_paddr,
               reloc + get_te64(&elfout.phdr[2].p_paddr));
      fo->rewrite(&elfout, sz_elf_hdrs);
    } else {
      fo->rewrite(&elfout, sz_elf_hdrs);
    }
    fo->rewrite(&linfo, sizeof(linfo));
  }
}

asmlinkage long compat_sys_epoll_pwait(int epfd,
                                       struct compat_epoll_event __user* events,
                                       int maxevents, int timeout,
                                       const compat_sigset_t __user* sigmask,
                                       compat_size_t sigsetsize) {
  long err;
  compat_sigset_t csigmask;
  sigset_t ksigmask, sigsaved;
  if (sigmask) {
    if (sigsetsize != sizeof(compat_sigset_t)) return -EINVAL;
    if (copy_from_user(&csigmask, sigmask, sizeof(csigmask))) return -EFAULT;
    sigset_from_compat(&ksigmask, &csigmask);
    sigdelsetmask(&ksigmask, sigmask(SIGKILL) | sigmask(SIGSTOP));
    sigprocmask(SIG_SETMASK, &ksigmask, &sigsaved);
  }
#ifdef CONFIG_HAS_COMPAT_EPOLL_EVENT
  err = compat_sys_epoll_wait(epfd, events, maxevents, timeout);
#else
  err = sys_epoll_wait(epfd, events, maxevents, timeout);
#endif
  if (sigmask) {
    if (err == -EINTR) {
      memcpy(&current->saved_sigmask, &sigsaved, sizeof(sigsaved));
      set_thread_flag(TIF_RESTORE_SIGMASK);
    } else
      sigprocmask(SIG_SETMASK, &sigsaved, NULL);
  }
  return err;
}

