void FrameLoader::checkNavigationPolicyAndContinueFragmentScroll(
    const NavigationAction& action, bool isNewNavigation) {
  m_documentLoader->setTriggeringAction(action);
  const ResourceRequest& request = action.resourceRequest();
  if (!m_documentLoader->shouldContinueForNavigationPolicy(
          request, DocumentLoader::PolicyCheckFragment))
    return;
  if (m_provisionalDocumentLoader &&
      !equalIgnoringFragmentIdentifier(
          m_provisionalDocumentLoader->request().url(), request.url())) {
    m_provisionalDocumentLoader->stopLoading();
    if (m_provisionalDocumentLoader)
      m_provisionalDocumentLoader->detachFromFrame();
    m_provisionalDocumentLoader = 0;
  }
  loadInSameDocument(request.url(), 0, isNewNavigation);
}

void LibRaw::process_Hassy_Lens(int LensMount) {
  char* ps;
  int c = atoi(strchr(imgdata.lens.Lens, ' ') + 1);
  if (!c) return;
  if (LensMount == LIBRAW_MOUNT_Hasselblad_H) {
    if (imgdata.lens.Lens[2] == ' ')
      ilm.LensID = LensMount * 100000000ULL + 10000000ULL;
    else
      ilm.LensID = LensMount * 100000000ULL + 20000000ULL;
    ilm.LensFormat = LIBRAW_FORMAT_645;
  } else if (LensMount == LIBRAW_MOUNT_Hasselblad_XCD) {
    ilm.LensFormat = LIBRAW_FORMAT_CROP645;
    ilm.LensID = LensMount * 100000000ULL;
  } else
    return;
  ilm.LensMount = LensMount;
  ilm.LensID += c * 10000ULL;
  if ((ps = strchr(imgdata.lens.Lens, '-'))) {
    ilm.FocalType = LIBRAW_FT_ZOOM_LENS;
    ilm.LensID += atoi(ps + 1) * 10ULL;
  } else {
    ilm.FocalType = LIBRAW_FT_PRIME_LENS;
    ilm.LensID += c * 10ULL;
  }
  if (strstr(imgdata.lens.Lens, "III"))
    ilm.LensID += 3ULL;
  else if (strstr(imgdata.lens.Lens, "II"))
    ilm.LensID += 2ULL;
}

stack_double(int is_alloca, char** arg_alloc_base, StackType** arg_stk_base,
             StackType** arg_stk_end, StackType** arg_stk, MatchArg* msa) {
  unsigned int n;
  int used;
  size_t size;
  size_t new_size;
  char* alloc_base;
  char* new_alloc_base;
  StackType *stk_base, *stk_end, *stk;
  alloc_base = *arg_alloc_base;
  stk_base = *arg_stk_base;
  stk_end = *arg_stk_end;
  stk = *arg_stk;
  n = (unsigned int)(stk_end - stk_base);
  size = sizeof(StackIndex) * msa->ptr_num + sizeof(StackType) * n;
  n *= 2;
  new_size = sizeof(StackIndex) * msa->ptr_num + sizeof(StackType) * n;
  if (is_alloca != 0) {
    new_alloc_base = (char*)xmalloc(new_size);
    if (IS_NULL(new_alloc_base)) {
      STACK_SAVE;
      return ONIGERR_MEMORY;
    }
    xmemcpy(new_alloc_base, alloc_base, size);
  } else {
    if (msa->match_stack_limit != 0 && n > msa->match_stack_limit) {
      if ((unsigned int)(stk_end - stk_base) == msa->match_stack_limit)
        return ONIGERR_MATCH_STACK_LIMIT_OVER;
      else
        n = msa->match_stack_limit;
    }
    new_alloc_base = (char*)xrealloc(alloc_base, new_size);
    if (IS_NULL(new_alloc_base)) {
      STACK_SAVE;
      return ONIGERR_MEMORY;
    }
  }
  alloc_base = new_alloc_base;
  used = (int)(stk - stk_base);
  *arg_alloc_base = alloc_base;
  *arg_stk_base =
      (StackType*)(alloc_base + (sizeof(StackIndex) * msa->ptr_num));
  *arg_stk = *arg_stk_base + used;
  *arg_stk_end = *arg_stk_base + n;
  return 0;
}

