static void fuse_lib_create(fuse_req_t req, fuse_ino_t parent, const char* name,
                            mode_t mode, struct fuse_file_info* fi) {
  struct fuse* f = req_fuse_prepare(req);
  struct fuse_intr_data d;
  struct fuse_entry_param e;
  char* path;
  int err;
  err = -ENOENT;
  pthread_rwlock_rdlock(&f->tree_lock);
  path = get_path_name(f, parent, name);
  if (path) {
    fuse_prepare_interrupt(f, req, &d);
    err = fuse_fs_create(f->fs, path, mode, fi);
    if (!err) {
      err = lookup_path(f, parent, name, path, &e, fi);
      if (err)
        fuse_fs_release(f->fs, path, fi);
      else if (!S_ISREG(e.attr.st_mode)) {
        err = -EIO;
        fuse_fs_release(f->fs, path, fi);
        forget_node(f, e.ino, 1);
      } else {
        if (f->conf.direct_io) fi->direct_io = 1;
        if (f->conf.kernel_cache) fi->keep_cache = 1;
      }
    }
    fuse_finish_interrupt(f, req, &d);
  }
  if (!err) {
    pthread_mutex_lock(&f->lock);
    get_node(f, e.ino)->open_count++;
    pthread_mutex_unlock(&f->lock);
    if (fuse_reply_create(req, &e, fi) == -ENOENT) {
      fuse_prepare_interrupt(f, req, &d);
      fuse_do_release(f, e.ino, path, fi);
      fuse_finish_interrupt(f, req, &d);
      forget_node(f, e.ino, 1);
    } else if (f->conf.debug) {
      fprintf(stderr, "  CREATE[%llu] flags: 0x%x %s\n",
              (unsigned long long)fi->fh, fi->flags, path);
    }
  } else
    reply_err(req, err);
  if (path) free(path);
  pthread_rwlock_unlock(&f->tree_lock);
}

error::Error GLES2DecoderImpl::HandleCreateStreamTextureCHROMIUM(
    uint32 immediate_data_size, const gles2::CreateStreamTextureCHROMIUM& c) {
  if (!feature_info_->feature_flags().chromium_stream_texture) {
    SetGLError(GL_INVALID_OPERATION,
               "glOpenStreamTextureCHROMIUM: "
               "not supported.");
    return error::kNoError;
  }
  uint32 client_id = c.client_id;
  typedef gles2::CreateStreamTextureCHROMIUM::Result Result;
  Result* result = GetSharedMemoryAs<Result*>(
      c.result_shm_id, c.result_shm_offset, sizeof(*result));
  if (!result) return error::kOutOfBounds;
  *result = GL_ZERO;
  TextureManager::TextureInfo* info =
      texture_manager()->GetTextureInfo(client_id);
  if (!info) {
    SetGLError(GL_INVALID_VALUE,
               "glCreateStreamTextureCHROMIUM: "
               "bad texture id.");
    return error::kNoError;
  }
  if (info->IsStreamTexture()) {
    SetGLError(GL_INVALID_OPERATION,
               "glCreateStreamTextureCHROMIUM: "
               "is already a stream texture.");
    return error::kNoError;
  }
  if (info->target() && info->target() != GL_TEXTURE_EXTERNAL_OES) {
    SetGLError(GL_INVALID_OPERATION,
               "glCreateStreamTextureCHROMIUM: "
               "is already bound to incompatible target.");
    return error::kNoError;
  }
  if (!stream_texture_manager_) return error::kInvalidArguments;
  GLuint object_id = stream_texture_manager_->CreateStreamTexture(
      info->service_id(), client_id);
  if (object_id) {
    info->SetStreamTexture(true);
  } else {
    SetGLError(GL_OUT_OF_MEMORY,
               "glCreateStreamTextureCHROMIUM: "
               "failed to create platform texture.");
  }
  *result = object_id;
  return error::kNoError;
}

_dbus_lookup_session_address_launchd(DBusString* address, DBusError* error) {
  dbus_bool_t valid_socket;
  DBusString socket_path;
  if (_dbus_check_setuid()) {
    dbus_set_error_const(error, DBUS_ERROR_NOT_SUPPORTED,
                         "Unable to find launchd socket when setuid");
    return FALSE;
  }
  if (!_dbus_string_init(&socket_path)) {
    _DBUS_SET_OOM(error);
    return FALSE;
  }
  valid_socket = _dbus_lookup_launchd_socket(
      &socket_path, "DBUS_LAUNCHD_SESSION_BUS_SOCKET", error);
  if (dbus_error_is_set(error)) {
    _dbus_string_free(&socket_path);
    return FALSE;
  }
  if (!valid_socket) {
    dbus_set_error(error, "no socket path",
                   "launchd did not provide a socket path, "
                   "verify that org.freedesktop.dbus-session.plist is loaded!");
    _dbus_string_free(&socket_path);
    return FALSE;
  }
  if (!_dbus_string_append(address, "unix:path=")) {
    _DBUS_SET_OOM(error);
    _dbus_string_free(&socket_path);
    return FALSE;
  }
  if (!_dbus_string_copy(&socket_path, 0, address,
                         _dbus_string_get_length(address))) {
    _DBUS_SET_OOM(error);
    _dbus_string_free(&socket_path);
    return FALSE;
  }
  _dbus_string_free(&socket_path);
  return TRUE;
}

void opj_j2k_write_float_to_float64(const void* p_src_data, void* p_dest_data,
                                    OPJ_UINT32 p_nb_elem) {
  OPJ_BYTE* l_dest_data = (OPJ_BYTE*)p_dest_data;
  OPJ_FLOAT32* l_src_data = (OPJ_FLOAT32*)p_src_data;
  OPJ_UINT32 i;
  OPJ_FLOAT64 l_temp;
  for (i = 0; i < p_nb_elem; ++i) {
    l_temp = (OPJ_FLOAT64) * (l_src_data++);
    opj_write_double(l_dest_data, l_temp);
    l_dest_data += sizeof(OPJ_FLOAT64);
  }
}

ServerItem* ServerView::getParent(const QString& continentcode,
                                  const QString& countrycode,
                                  const QString& countryname,
                                  const QString& usercontinent,
                                  const QString& usercountry) {
  ServerItem* continent = qmContinent.value(continentcode);
  if (!continent) {
    QString name = qmContinentNames.value(continentcode);
    if (name.isEmpty()) name = continentcode;
    continent = new ServerItem(name, ServerItem::PublicType, continentcode);
    qmContinent.insert(continentcode, continent);
    siPublic->addServerItem(continent);
    if (!continentcode.isEmpty()) {
      if (continentcode == usercontinent) {
        continent->setExpanded(true);
        scrollToItem(continent, QAbstractItemView::PositionAtTop);
      }
    } else {
      continent->setChildIndicatorPolicy(QTreeWidgetItem::ShowIndicator);
    }
  }
  if (continentcode.isEmpty()) {
    return continent;
  }
  ServerItem* country = qmCountry.value(countrycode);
  if (!country) {
    country = new ServerItem(countryname, ServerItem::PublicType, continentcode,
                             countrycode);
    qmCountry.insert(countrycode, country);
    country->setChildIndicatorPolicy(QTreeWidgetItem::ShowIndicator);
    continent->addServerItem(country);
    if (!countrycode.isEmpty() && countrycode == usercountry) {
      country->setExpanded(true);
      scrollToItem(country, QAbstractItemView::PositionAtTop);
    }
  }
  return country;
}

int cma_set_default_gid_type(struct cma_device* cma_dev, u32 port,
                             enum ib_gid_type default_gid_type) {
  unsigned long supported_gids;
  if (!rdma_is_port_valid(cma_dev->device, port)) return -EINVAL;
  if (default_gid_type == IB_GID_TYPE_IB &&
      rdma_protocol_roce_eth_encap(cma_dev->device, port))
    default_gid_type = IB_GID_TYPE_ROCE;
  supported_gids = roce_gid_type_mask_support(cma_dev->device, port);
  if (!(supported_gids & 1 << default_gid_type)) return -EINVAL;
  cma_dev->default_gid_type[port - rdma_start_port(cma_dev->device)] =
      default_gid_type;
  return 0;
}

static u64 box_unused_bytes(GF_Box* b) {
  u32 i, count;
  u64 size = 0;
  switch (b->type) {
    case GF_QT_BOX_TYPE_WIDE:
    case GF_ISOM_BOX_TYPE_FREE:
    case GF_ISOM_BOX_TYPE_SKIP:
      size += b->size;
      break;
  }
  count = gf_list_count(b->child_boxes);
  for (i = 0; i < count; i++) {
    GF_Box* child = gf_list_get(b->child_boxes, i);
    size += box_unused_bytes(child);
  }
  return size;
}

