void LinkResolver::check_field_accessability(Klass* ref_klass,
                                             Klass* resolved_klass,
                                             Klass* sel_klass,
                                             const fieldDescriptor& fd, TRAPS) {
  bool can_access =
      Reflection::verify_member_access(ref_klass, resolved_klass, sel_klass,
                                       fd.access_flags(), true, false, CHECK);
  if (!can_access) {
    bool same_module = (sel_klass->module() == ref_klass->module());
    ResourceMark rm(THREAD);
    Exceptions::fthrow(
        THREAD_AND_LOCATION, vmSymbols::java_lang_IllegalAccessError(),
        "class %s tried to access %s%sfield %s.%s (%s%s%s)",
        ref_klass->external_name(), fd.is_protected() ? "protected " : "",
        fd.is_private() ? "private " : "", sel_klass->external_name(),
        fd.name()->as_C_string(),
        (same_module) ? ref_klass->joint_in_module_of_loader(sel_klass)
                      : ref_klass->class_in_module_of_loader(),
        (same_module) ? "" : "; ",
        (same_module) ? "" : sel_klass->class_in_module_of_loader());
    return;
  }
}

