smtp_message_code(uschar** code, int* codelen, uschar** msg, uschar** log_msg,
                  BOOL check_valid) {
  int n;
  int ovector[3];
  if (!msg || !*msg) return;
  if ((n = pcre_exec(regex_smtp_code, NULL, CS * msg, Ustrlen(*msg), 0,
                     PCRE_EOPT, ovector, sizeof(ovector) / sizeof(int))) < 0)
    return;
  if (check_valid && (*msg)[0] != (*code)[0]) {
    log_write(0, LOG_MAIN | LOG_PANIC,
              "configured error code starts with "
              "incorrect digit (expected %c) in \"%s\"",
              (*code)[0], *msg);
    if (log_msg != NULL && *log_msg == *msg)
      *log_msg = string_sprintf("%s %s", *code, *log_msg + ovector[1]);
  } else {
    *code = *msg;
    *codelen = ovector[1];
  }
  *msg += ovector[1];
  return;
}

static int is_pkt_ptr_branch_taken(struct bpf_reg_state* dst_reg,
                                   struct bpf_reg_state* src_reg, u8 opcode) {
  struct bpf_reg_state* pkt;
  if (src_reg->type == PTR_TO_PACKET_END) {
    pkt = dst_reg;
  } else if (dst_reg->type == PTR_TO_PACKET_END) {
    pkt = src_reg;
    opcode = flip_opcode(opcode);
  } else {
    return -1;
  }
  if (pkt->range >= 0) return -1;
  switch (opcode) {
    case BPF_JLE:
      fallthrough;
    case BPF_JGT:
      if (pkt->range == BEYOND_PKT_END) return opcode == BPF_JGT;
      break;
    case BPF_JLT:
      fallthrough;
    case BPF_JGE:
      if (pkt->range == BEYOND_PKT_END || pkt->range == AT_PKT_END)
        return opcode == BPF_JGE;
      break;
  }
  return -1;
}

static void mxf_read_pixel_layout(AVIOContext* pb, MXFDescriptor* descriptor) {
  int code, value, ofs = 0;
