static int cmv_decode_frame(AVCodecContext* avctx, void* data, int* got_frame,
                            AVPacket* avpkt) {
  const uint8_t* buf = avpkt->data;
  int buf_size = avpkt->size;
  CmvContext* s = avctx->priv_data;
  const uint8_t* buf_end = buf + buf_size;
  AVFrame* frame = data;
  int ret;
  if (buf_end - buf < EA_PREAMBLE_SIZE) return AVERROR_INVALIDDATA;
  if (AV_RL32(buf) == MVIh_TAG || AV_RB32(buf) == MVIh_TAG) {
    ret = cmv_process_header(s, buf + EA_PREAMBLE_SIZE, buf_end);
    if (ret < 0) return ret;
    return buf_size;
  }
  if (av_image_check_size(s->width, s->height, 0, s->avctx)) return -1;
  if ((ret = ff_get_buffer(avctx, frame, AV_GET_BUFFER_FLAG_REF)) < 0) {
    av_log(avctx, AV_LOG_ERROR, "get_buffer() failed\n");
    return ret;
  }
  memcpy(frame->data[1], s->palette, AVPALETTE_SIZE);
  buf += EA_PREAMBLE_SIZE;
  if ((buf[0] & 1)) {
    cmv_decode_inter(s, frame, buf + 2, buf_end);
    frame->key_frame = 0;
    frame->pict_type = AV_PICTURE_TYPE_P;
  } else {
    frame->key_frame = 1;
    frame->pict_type = AV_PICTURE_TYPE_I;
    cmv_decode_intra(s, frame, buf + 2, buf_end);
  }
  av_frame_unref(s->last2_frame);
  av_frame_move_ref(s->last2_frame, s->last_frame);
  if ((ret = av_frame_ref(s->last_frame, frame)) < 0) return ret;
  *got_frame = 1;
  return buf_size;
}

static int __vhost_add_used_n(struct vhost_virtqueue* vq,
                              struct vring_used_elem* heads, unsigned count) {
  struct vring_used_elem __user* used;
  u16 old, new;
  int start;
  start = vq->last_used_idx % vq->num;
  used = vq->used->ring + start;
  if (__copy_to_user(used, heads, count * sizeof *used)) {
    vq_err(vq, "Failed to write used");
    return -EFAULT;
  }
  if (unlikely(vq->log_used)) {
    smp_wmb();
    log_write(vq->log_base,
              vq->log_addr + ((void __user*)used - (void __user*)vq->used),
              count * sizeof *used);
  }
  old = vq->last_used_idx;
  new = (vq->last_used_idx += count);
  if (unlikely((u16)(new - vq->signalled_used) < (u16)(new - old)))
    vq->signalled_used_valid = false;
  return 0;
}

static ssize_t read_port(struct file* file, char __user* buf, size_t count,
                         loff_t* ppos) {
  unsigned long i = *ppos;
  char __user* tmp = buf;
  if (!access_ok(VERIFY_WRITE, buf, count)) return -EFAULT;
  while (count-- > 0 && i < 65536) {
    if (__put_user(inb(i), tmp) < 0) return -EFAULT;
    i++;
    tmp++;
  }
  *ppos = i;
  return tmp - buf;
}

static void adjust_poke_descs(struct bpf_prog* prog, u32 off, u32 len) {
  struct bpf_jit_poke_descriptor* tab = prog->aux->poke_tab;
  int i, sz = prog->aux->size_poke_tab;
  struct bpf_jit_poke_descriptor* desc;
  for (i = 0; i < sz; i++) {
    desc = &tab[i];
    if (desc->insn_idx <= off) continue;
    desc->insn_idx += len - 1;
  }
}

update_info_linux_loop(Device* device) {
  gboolean ret;
  gint fd;
  struct loop_info64 loop_info_buf;
  gboolean is_loop;
  gchar* s;
  gchar* s2;
  is_loop = FALSE;
  ret = FALSE;
  fd = -1;
  if (!g_str_has_prefix(device->priv->native_path,
                        "/sys/devices/virtual/block/loop")) {
    ret = TRUE;
    goto out;
  }
  fd = open(device->priv->device_file, O_RDONLY);
  if (fd < 0) goto out;
  if (ioctl(fd, LOOP_GET_STATUS64, &loop_info_buf) != 0) goto out;
  device_set_linux_loop_filename(device,
                                 (const gchar*)loop_info_buf.lo_file_name);
  ret = TRUE;
  is_loop = TRUE;
  device_set_drive_vendor(device, "Linux");
  s2 = g_path_get_basename((gchar*)loop_info_buf.lo_file_name);
  s = g_strdup_printf("Loop: %s", s2);
  g_free(s2);
  device_set_drive_model(device, s);
  g_free(s);
out:
  if (fd > 0) close(fd);
  device_set_device_is_linux_loop(device, is_loop);
  return ret;
}

