static long __compat_sys_preadv64(unsigned long fd,
                                  const struct compat_iovec __user* vec,
                                  unsigned long vlen, loff_t pos) {
  struct fd f;
  ssize_t ret;
  if (pos < 0) return -EINVAL;
  f = fdget(fd);
  if (!f.file) return -EBADF;
  ret = -ESPIPE;
  if (f.file->f_mode & FMODE_PREAD) ret = compat_readv(f.file, vec, vlen, &pos);
  fdput(f);
  return ret;
}

date_s_iso8601(int argc, VALUE* argv, VALUE klass) {
  VALUE str, sg, opt;
  rb_scan_args(argc, argv, "02:", &str, &sg, &opt);
  if (!NIL_P(opt)) argc--;
  switch (argc) {
    case 0:
      str = rb_str_new2("-4712-01-01");
    case 1:
      sg = INT2FIX(DEFAULT_SG);
  }
  {
    int argc2 = 1;
    VALUE argv2[2];
    argv2[0] = str;
    if (!NIL_P(opt)) argv2[argc2++] = opt;
    VALUE hash = date_s__iso8601(argc2, argv2, klass);
    return d_new_by_frags(klass, hash, sg);
  }
}

oldgnu_add_sparse(struct tar_sparse_file* file, struct sparse* s) {
  struct sp_array sp;
  if (s->numbytes[0] == '\0') return add_finish;
  sp.offset = OFF_FROM_HEADER(s->offset);
  sp.numbytes = OFF_FROM_HEADER(s->numbytes);
  if (sp.offset < 0 || sp.numbytes < 0 ||
      INT_ADD_OVERFLOW(sp.offset, sp.numbytes) ||
      file->stat_info->stat.st_size < sp.offset + sp.numbytes ||
      file->stat_info->archive_file_size < 0)
    return add_fail;
  sparse_add_map(file->stat_info, &sp);
  return add_ok;
}

int sctp_assoc_set_bind_addr_from_ep(struct sctp_association* asoc,
