  state.delayed_for_oplocks = True;
  state.async_open = false;
  state.id = lck->data->id;
  if (!request_timed_out(request_time, timeout)) {
    defer_open(lck, request_time, timeout, req, &state);
  }
}

static void Ins_SHPIX(INS_ARG) {
  TT_F26Dot6 dx, dy;
  Long point;
  if (CUR.top < CUR.GS.loop) {
    CUR.error = TT_Err_Invalid_Reference;
    return;
  }
  dx = MulDiv_Round(args[0], (Long)CUR.GS.freeVector.x, 0x4000);
  dy = MulDiv_Round(args[0], (Long)CUR.GS.freeVector.y, 0x4000);
  while (CUR.GS.loop > 0) {
    CUR.args--;
    point = CUR.stack[CUR.args];
    if (BOUNDS(point, CUR.zp2.n_points)) {
      CUR.error = TT_Err_Invalid_Reference;
      return;
    }
    MOVE_Zp2_Point(point, dx, dy, TRUE);
    CUR.GS.loop--;
  }
  CUR.GS.loop = 1;
  CUR.new_top = CUR.args;
}

static int compat_target_to_user(struct ebt_entry_target* t,
                                 void __user** dstptr, unsigned int* size) {
  const struct xt_target* target = t->u.target;
  struct compat_ebt_entry_mwt __user* cm = *dstptr;
  int off = xt_compat_target_offset(target);
  compat_uint_t tsize = t->target_size - off;
  BUG_ON(off >= t->target_size);
  if (copy_to_user(cm->u.name, target->name, strlen(target->name) + 1) ||
      put_user(tsize, &cm->match_size))
    return -EFAULT;
  if (target->compat_to_user) {
    if (target->compat_to_user(cm->data, t->data)) return -EFAULT;
  } else if (copy_to_user(cm->data, t->data, tsize))
    return -EFAULT;
  *size -= ebt_compat_entry_padsize() + off;
  *dstptr = cm->data;
  *dstptr += tsize;
  return 0;
}

gfx::Size Browser::GetSizeForNewRenderView(WebContents* web_contents) const {
