const char* InstanceKlass::signature_name() const {
  int hash_len = 0;
  char hash_buf[40];
  const char* src = (const char*)(name()->as_C_string());
  const int src_length = (int)strlen(src);
  char* dest = NEW_RESOURCE_ARRAY(char, src_length + hash_len + 3);
  int dest_index = 0;
  dest[dest_index++] = JVM_SIGNATURE_CLASS;
  for (int src_index = 0; src_index < src_length;) {
    dest[dest_index++] = src[src_index++];
  }
  if (is_hidden()) {
    for (int index = (int)src_length; index > 0; index--) {
      if (dest[index] == '+') {
        dest[index] = JVM_SIGNATURE_DOT;
        break;
      }
    }
  }
  for (int hash_index = 0; hash_index < hash_len;) {
    dest[dest_index++] = hash_buf[hash_index++];
  }
  dest[dest_index++] = JVM_SIGNATURE_ENDCLASS;
  dest[dest_index] = '\0';
  return dest;
}

static int rfcomm_sock_shutdown(struct socket* sock, int how) {
  struct sock* sk = sock->sk;
  int err = 0;
  BT_DBG("sock %p, sk %p", sock, sk);
  if (!sk) return 0;
  lock_sock(sk);
  if (!sk->sk_shutdown) {
    sk->sk_shutdown = SHUTDOWN_MASK;
    __rfcomm_sock_close(sk);
    if (sock_flag(sk, SOCK_LINGER) && sk->sk_lingertime)
      err = bt_sock_wait_state(sk, BT_CLOSED, sk->sk_lingertime);
  }
  release_sock(sk);
  return err;
}

dirvote_get_intermediate_param_value(const smartlist_t* param_list,
                                     const char* keyword, int32_t default_val) {
  unsigned int n_found = 0;
  int32_t value = default_val;
  SMARTLIST_FOREACH_BEGIN(param_list, const char*, k_v_pair) {
    if (!strcmpstart(k_v_pair, keyword) && k_v_pair[strlen(keyword)] == '=') {
      const char* integer_str = &k_v_pair[strlen(keyword) + 1];
      int ok;
      value = (int32_t)tor_parse_long(integer_str, 10, INT32_MIN, INT32_MAX,
                                      &ok, NULL);
      if (BUG(!ok)) return default_val;
      ++n_found;
    }
  }
  SMARTLIST_FOREACH_END(k_v_pair);
  if (n_found == 1)
    return value;
  else if (BUG(n_found > 1))
    return default_val;
  else
    return default_val;
}

