void GfxDeviceCMYKColorSpace::getRGB(const GfxColor* color, GfxRGB* rgb) const {
  double c, m, y, k, c1, m1, y1, k1, r, g, b;
  c = colToDbl(color->c[0]);
  m = colToDbl(color->c[1]);
  y = colToDbl(color->c[2]);
  k = colToDbl(color->c[3]);
  c1 = 1 - c;
  m1 = 1 - m;
  y1 = 1 - y;
  k1 = 1 - k;
  cmykToRGBMatrixMultiplication(c, m, y, k, c1, m1, y1, k1, r, g, b);
  rgb->r = clip01(dblToCol(r));
  rgb->g = clip01(dblToCol(g));
  rgb->b = clip01(dblToCol(b));
}

int sldns_str2wire_int32_buf(const char* str, uint8_t* rd, size_t* len) {
  char* end;
  uint32_t r;
  errno = 0;
  if (*str == '-')
    r = (uint32_t)strtol((char*)str, &end, 10);
  else
    r = (uint32_t)strtoul((char*)str, &end, 10);
  if (*end != 0)
    return RET_ERR(LDNS_WIREPARSE_ERR_SYNTAX_INT, end - (char*)str);
  if (errno == ERANGE) return LDNS_WIREPARSE_ERR_SYNTAX_INTEGER_OVERFLOW;
  if (*len < 4) return LDNS_WIREPARSE_ERR_BUFFER_TOO_SMALL;
  sldns_write_uint32(rd, r);
  *len = 4;
  return LDNS_WIREPARSE_ERR_OK;
}

