static int llc_ui_getsockopt(struct socket* sock, int level, int optname,
                             char __user* optval, int __user* optlen) {
  struct sock* sk = sock->sk;
  struct llc_sock* llc = llc_sk(sk);
  int val = 0, len = 0, rc = -EINVAL;
  lock_sock(sk);
  if (unlikely(level != SOL_LLC)) goto out;
  rc = get_user(len, optlen);
  if (rc) goto out;
  rc = -EINVAL;
  if (len != sizeof(int)) goto out;
  switch (optname) {
    case LLC_OPT_RETRY:
      val = llc->n2;
      break;
    case LLC_OPT_SIZE:
      val = llc->n1;
      break;
    case LLC_OPT_ACK_TMR_EXP:
      val = llc->ack_timer.expire / HZ;
      break;
    case LLC_OPT_P_TMR_EXP:
      val = llc->pf_cycle_timer.expire / HZ;
      break;
    case LLC_OPT_REJ_TMR_EXP:
      val = llc->rej_sent_timer.expire / HZ;
      break;
    case LLC_OPT_BUSY_TMR_EXP:
      val = llc->busy_state_timer.expire / HZ;
      break;
    case LLC_OPT_TX_WIN:
      val = llc->k;
      break;
    case LLC_OPT_RX_WIN:
      val = llc->rw;
      break;
    default:
      rc = -ENOPROTOOPT;
      goto out;
  }
  rc = 0;
  if (put_user(len, optlen) || copy_to_user(optval, &val, len)) rc = -EFAULT;
out:
  release_sock(sk);
  return rc;
}

static int nl80211_dump_survey(struct sk_buff* skb,
                               struct netlink_callback* cb) {
  struct survey_info survey;
  struct cfg80211_registered_device* dev;
  struct net_device* netdev;
  int survey_idx = cb->args[1];
  int res;
  res = nl80211_prepare_netdev_dump(skb, cb, &dev, &netdev);
  if (res) return res;
  if (!dev->ops->dump_survey) {
    res = -EOPNOTSUPP;
    goto out_err;
  }
  while (1) {
    struct ieee80211_channel* chan;
    res = rdev_dump_survey(dev, netdev, survey_idx, &survey);
    if (res == -ENOENT) break;
    if (res) goto out_err;
    if (!survey.channel) {
      res = -EINVAL;
      goto out;
    }
    chan = ieee80211_get_channel(&dev->wiphy, survey.channel->center_freq);
    if (!chan || chan->flags & IEEE80211_CHAN_DISABLED) {
      survey_idx++;
      continue;
    }
    if (nl80211_send_survey(skb, NETLINK_CB(cb->skb).portid, cb->nlh->nlmsg_seq,
                            NLM_F_MULTI, netdev, &survey) < 0)
      goto out;
    survey_idx++;
  }
out:
  cb->args[1] = survey_idx;
  res = skb->len;
out_err:
  nl80211_finish_netdev_dump(dev);
  return res;
}

