      goto out;
    }
  }
out:
  g_list_free(devices);
  return ret;
}

rgb2bgr15(UINT8* out_, const UINT8* in, int xsize) {
  int x;
  for (x = 0; x < xsize; x++, in += 4, out_ += 2) {
    UINT16 v = ((((UINT16)in[0]) << 7) & 0x7c00) +
               ((((UINT16)in[1]) << 2) & 0x03e0) +
               ((((UINT16)in[2]) >> 3) & 0x001f);
    memcpy(out_, &v, sizeof(v));
  }
}

static void tcp_fixup_rcvbuf(struct sock* sk) {
  u32 mss = tcp_sk(sk)->advmss;
  int rcvmem;
  rcvmem = 2 * SKB_TRUESIZE(mss + MAX_TCP_HEADER) * tcp_default_init_rwnd(mss);
  if (sysctl_tcp_moderate_rcvbuf) rcvmem <<= 2;
  if (sk->sk_rcvbuf < rcvmem) sk->sk_rcvbuf = min(rcvmem, sysctl_tcp_rmem[2]);
}

bool InstanceKlass::has_nest_member(JavaThread* current,
                                    InstanceKlass* k) const {
  assert(!is_hidden(), "unexpected hidden class");
  if (_nest_members == NULL ||
      _nest_members == Universe::the_empty_short_array()) {
    if (log_is_enabled(Trace, class, nestmates)) {
      ResourceMark rm(current);
      log_trace(class, nestmates)(
          "Checked nest membership of %s in non-nest-host class %s",
          k->external_name(), this->external_name());
    }
    return false;
  }
  if (log_is_enabled(Trace, class, nestmates)) {
    ResourceMark rm(current);
    log_trace(class, nestmates)("Checking nest membership of %s in %s",
                                k->external_name(), this->external_name());
  }
  for (int i = 0; i < _nest_members->length(); i++) {
    int cp_index = _nest_members->at(i);
    Symbol* name = _constants->klass_name_at(cp_index);
    if (name == k->name()) {
      log_trace(class, nestmates)(
          "- named class found at nest_members[%d] => cp[%d]", i, cp_index);
      return true;
    }
  }
  log_trace(class, nestmates)("- class is NOT a nest member!");
  return false;
}

static port::StatusOr<CudnnRnnSequenceTensorDescriptor> Create(
    GpuExecutor* parent, int max_seq_length, int batch_size, int data_size,
    const absl::Span<const int>& seq_lengths, bool time_major,
    cudnnDataType_t data_type) {
  if (max_seq_length <= 0) {
    return port::Status(port::error::INVALID_ARGUMENT, "max_seq_length <= 0");
  }
  int dims[] = {batch_size, data_size, 1};
  int strides[] = {dims[1] * dims[2], dims[2], 1};
  TensorDescriptor tensor_desc = CreateTensorDescriptor();
  RETURN_IF_CUDNN_ERROR(cudnnSetTensorNdDescriptor(
      tensor_desc.get(), data_type, sizeof(dims) / sizeof(dims[0]), dims,
      strides));
  const int* seq_lengths_array = seq_lengths.data();
  RNNDataDescriptor data_desc = CreateRNNDataDescriptor();
  float padding_fill = 0.0f;
  cudnnRNNDataLayout_t layout;
  if (time_major) {
    layout = CUDNN_RNN_DATA_LAYOUT_SEQ_MAJOR_UNPACKED;
  } else {
    layout = CUDNN_RNN_DATA_LAYOUT_BATCH_MAJOR_UNPACKED;
  }
  RETURN_IF_CUDNN_ERROR(cudnnSetRNNDataDescriptor(
      data_desc.get(), data_type, layout, max_seq_length, batch_size, data_size,
      seq_lengths_array, (void*)&padding_fill));
  return CudnnRnnSequenceTensorDescriptor(
      parent, max_seq_length, batch_size, data_size, data_type,
      std::move(data_desc), std::move(tensor_desc));
}

