static const char* set_allow_opts(cmd_parms* cmd, allow_options_t* opts,
                                  const char* l) {
  allow_options_t opt;
  int first = 1;
  char *w, *p = (char*)l;
  char* tok_state;
  while ((w = apr_strtok(p, ",", &tok_state)) != NULL) {
    if (first) {
      p = NULL;
      *opts = OPT_NONE;
      first = 0;
    }
    if (!ap_cstr_casecmp(w, "Indexes")) {
      opt = OPT_INDEXES;
    } else if (!ap_cstr_casecmp(w, "Includes")) {
      opt = (OPT_INCLUDES | OPT_INC_WITH_EXEC);
    } else if (!ap_cstr_casecmp(w, "IncludesNOEXEC")) {
      opt = OPT_INCLUDES;
    } else if (!ap_cstr_casecmp(w, "FollowSymLinks")) {
      opt = OPT_SYM_LINKS;
    } else if (!ap_cstr_casecmp(w, "SymLinksIfOwnerMatch")) {
      opt = OPT_SYM_OWNER;
    } else if (!ap_cstr_casecmp(w, "ExecCGI")) {
      opt = OPT_EXECCGI;
    } else if (!ap_cstr_casecmp(w, "MultiViews")) {
      opt = OPT_MULTI;
    } else if (!ap_cstr_casecmp(w, "RunScripts")) {
      opt = OPT_MULTI | OPT_EXECCGI;
    } else if (!ap_cstr_casecmp(w, "None")) {
      opt = OPT_NONE;
    } else if (!ap_cstr_casecmp(w, "All")) {
      opt = OPT_ALL;
    } else {
      return apr_pstrcat(cmd->pool, "Illegal option ", w, NULL);
    }
    *opts |= opt;
  }
  (*opts) &= (~OPT_UNSET);
  return NULL;
}

static void virtio_net_change_num_queue_pairs(VirtIONet* n,
                                              int new_max_queue_pairs) {
  VirtIODevice* vdev = VIRTIO_DEVICE(n);
  int old_num_queues = virtio_get_num_queues(vdev);
  int new_num_queues = new_max_queue_pairs * 2 + 1;
  int i;
  assert(old_num_queues >= 3);
  assert(old_num_queues % 2 == 1);
  if (old_num_queues == new_num_queues) {
    return;
  }
  virtio_del_queue(vdev, old_num_queues - 1);
  for (i = new_num_queues - 1; i < old_num_queues - 1; i += 2) {
    virtio_net_del_queue(n, i / 2);
  }
  for (i = old_num_queues - 1; i < new_num_queues - 1; i += 2) {
    virtio_net_add_queue(n, i / 2);
  }
  n->ctrl_vq = virtio_add_queue(vdev, 64, virtio_net_handle_ctrl);
}

bool SVGDocumentExtensions::isElementPendingResources(Element* element) const {
  ASSERT(element);
  HashMap<AtomicString, OwnPtr<SVGPendingElements> >::const_iterator end =
      m_pendingResources.end();
  for (HashMap<AtomicString, OwnPtr<SVGPendingElements> >::const_iterator it =
           m_pendingResources.begin();
       it != end; ++it) {
    SVGPendingElements* elements = it->value.get();
    ASSERT(elements);
    if (elements->contains(element)) return true;
  }
  return false;
}

insert_y_line(line_list* ll, active_line* alp) {
  active_line* yp = ll->y_line;
  active_line* nyp;
  fixed y_start = alp->start.y;
  if (yp == 0) {
    alp->next = alp->prev = 0;
    ll->y_list = alp;
  } else if (y_start >= yp->start.y) {
    while (INCR_EXPR(y_up),
           ((nyp = yp->next) != NULL && y_start > nyp->start.y))
      yp = nyp;
    alp->next = nyp;
    alp->prev = yp;
    yp->next = alp;
    if (nyp) nyp->prev = alp;
  } else {
    while (INCR_EXPR(y_down),
           ((nyp = yp->prev) != NULL && y_start < nyp->start.y))
      yp = nyp;
    alp->prev = nyp;
    alp->next = yp;
    yp->prev = alp;
    if (nyp)
      nyp->next = alp;
    else
      ll->y_list = alp;
  }
  ll->y_line = alp;
  print_al(ll->memory, "add ", alp);
}

logical_ring_default_irqs(struct intel_engine_cs* engine) {
  unsigned int shift = 0;
  if (INTEL_GEN(engine->i915) < 11) {
    const u8 irq_shifts[] = {
        [RCS0] = GEN8_RCS_IRQ_SHIFT,   [BCS0] = GEN8_BCS_IRQ_SHIFT,
        [VCS0] = GEN8_VCS0_IRQ_SHIFT,  [VCS1] = GEN8_VCS1_IRQ_SHIFT,
        [VECS0] = GEN8_VECS_IRQ_SHIFT,
    };
    shift = irq_shifts[engine->id];
  }
  engine->irq_enable_mask = GT_RENDER_USER_INTERRUPT << shift;
  engine->irq_keep_mask = GT_CONTEXT_SWITCH_INTERRUPT << shift;
}

void PDFiumEngine::DrawPageShadow(const pp::Rect& page_rc,
                                  const pp::Rect& shadow_rc,
                                  const pp::Rect& clip_rc,
                                  pp::ImageData* image_data) {
  pp::Rect page_rect(page_rc);
  page_rect.Offset(page_offset_);
  pp::Rect shadow_rect(shadow_rc);
  shadow_rect.Offset(page_offset_);
  pp::Rect clip_rect(clip_rc);
  clip_rect.Offset(page_offset_);
  const double factor = 0.5;
  uint32_t depth =
      std::max(std::max(page_rect.x() - shadow_rect.x(),
                        page_rect.y() - shadow_rect.y()),
               std::max(shadow_rect.right() - page_rect.right(),
                        shadow_rect.bottom() - page_rect.bottom()));
  depth = static_cast<uint32_t>(depth * 1.5) + 1;
  if (!page_shadow_.get() || page_shadow_->depth() != depth)
    page_shadow_.reset(
        new ShadowMatrix(depth, factor, client_->GetBackgroundColor()));
  DCHECK(!image_data->is_null());
  DrawShadow(image_data, shadow_rect, page_rect, clip_rect, *page_shadow_);
}

