connection_dirserv_add_microdescs_to_outbuf(dir_connection_t* conn) {
  microdesc_cache_t* cache = get_microdesc_cache();
  while (smartlist_len(conn->fingerprint_stack) &&
         buf_datalen(conn->_base.outbuf) < DIRSERV_BUFFER_MIN) {
    char* fp256 = smartlist_pop_last(conn->fingerprint_stack);
    microdesc_t* md = microdesc_cache_lookup_by_digest256(cache, fp256);
    tor_free(fp256);
    if (!md) continue;
    if (conn->zlib_state) {
      int last = !smartlist_len(conn->fingerprint_stack);
      connection_write_to_buf_zlib(md->body, md->bodylen, conn, last);
      if (last) {
        tor_zlib_free(conn->zlib_state);
        conn->zlib_state = NULL;
      }
    } else {
      connection_write_to_buf(md->body, md->bodylen, TO_CONN(conn));
    }
  }
  if (!smartlist_len(conn->fingerprint_stack)) {
    conn->dir_spool_src = DIR_SPOOL_NONE;
    smartlist_free(conn->fingerprint_stack);
    conn->fingerprint_stack = NULL;
  }
  return 0;
}

get_host_princs_from_keytab(krb5_context context, krb5_keytab keytab,
                            krb5_principal** princ_list_out) {
  krb5_error_code ret;
  krb5_kt_cursor cursor;
  krb5_keytab_entry kte;
  krb5_principal *plist = NULL, p;
  *princ_list_out = NULL;
  ret = krb5_kt_start_seq_get(context, keytab, &cursor);
  if (ret) goto cleanup;
  while ((ret = krb5_kt_next_entry(context, keytab, &kte, &cursor)) == 0) {
    p = kte.principal;
    if (p->length == 2 && data_eq_string(p->data[0], "host"))
      ret = add_princ_list(context, p, &plist);
    krb5_kt_free_entry(context, &kte);
    if (ret) break;
  }
  (void)krb5_kt_end_seq_get(context, keytab, &cursor);
  if (ret == KRB5_KT_END) ret = 0;
  if (ret) goto cleanup;
  *princ_list_out = plist;
  plist = NULL;
cleanup:
  free_princ_list(context, plist);
  return ret;
}

