  vnc_jobs_join(vs);
  vnc_lock_output(vs);
  vnc_qmp_event(vs, QAPI_EVENT_VNC_DISCONNECTED);
  buffer_free(&vs->input);
  buffer_free(&vs->output);
  qapi_free_VncClientInfo(vs->info);
