timeval_to_jiffies(const struct timeval* value) {
  unsigned long sec = value->tv_sec;
  long usec = value->tv_usec;
  if (sec >= MAX_SEC_IN_JIFFIES) {
    sec = MAX_SEC_IN_JIFFIES;
    usec = 0;
  }
  return (((u64)sec * SEC_CONVERSION) +
          (((u64)usec * USEC_CONVERSION + USEC_ROUND) >>
           (USEC_JIFFIE_SC - SEC_JIFFIE_SC))) >>
         SEC_JIFFIE_SC;
}

void GLES2DecoderImpl::DoBindRenderbuffer(GLenum target, GLuint client_id) {
  RenderbufferManager::RenderbufferInfo* info = NULL;
  GLuint service_id = 0;
  if (client_id != 0) {
    info = GetRenderbufferInfo(client_id);
    if (!info) {
      glGenRenderbuffersEXT(1, &service_id);
      CreateRenderbufferInfo(client_id, service_id);
      info = GetRenderbufferInfo(client_id);
      IdAllocator* id_allocator =
          group_->GetIdAllocator(id_namespaces::kRenderbuffers);
      id_allocator->MarkAsUsed(client_id);
    } else {
      service_id = info->service_id();
    }
  }
  bound_renderbuffer_ = info;
  glBindRenderbufferEXT(target, service_id);
}

static ssize_t demote_size_store(struct kobject* kobj,
                                 struct kobj_attribute* attr, const char* buf,
                                 size_t count) {
  struct hstate *h, *demote_hstate;
  unsigned long demote_size;
  unsigned int demote_order;
  int nid;
  demote_size = (unsigned long)memparse(buf, NULL);
  demote_hstate = size_to_hstate(demote_size);
  if (!demote_hstate) return -EINVAL;
  demote_order = demote_hstate->order;
  if (demote_order < HUGETLB_PAGE_ORDER) return -EINVAL;
  h = kobj_to_hstate(kobj, &nid);
  if (demote_order >= h->order) return -EINVAL;
  mutex_lock(&h->resize_lock);
  h->demote_order = demote_order;
  mutex_unlock(&h->resize_lock);
  return count;
}

cmsStage* CMSEXPORT cmsStageDup(cmsStage* mpe) {
  cmsStage* NewMPE;
  if (mpe == NULL) return NULL;
  NewMPE = _cmsStageAllocPlaceholder(
      mpe->ContextID, mpe->Type, mpe->InputChannels, mpe->OutputChannels,
      mpe->EvalPtr, mpe->DupElemPtr, mpe->FreePtr, NULL);
  if (NewMPE == NULL) return NULL;
  NewMPE->Implements = mpe->Implements;
  if (mpe->DupElemPtr) {
    NewMPE->Data = mpe->DupElemPtr(mpe);
    if (NewMPE->Data == NULL) {
      cmsStageFree(NewMPE);
      return NULL;
    }
  } else {
    NewMPE->Data = NULL;
  }
  return NewMPE;
}

check_command(char* cmd, int auxbin_p) {
  static char* path = NULL;
  Str dirs;
  char *p, *np;
  Str pathname;
  struct stat st;
  if (path == NULL) path = getenv("PATH");
  if (auxbin_p)
    dirs = Strnew_charp(w3m_auxbin_dir());
  else
    dirs = Strnew_charp(path);
  for (p = dirs->ptr; p != NULL; p = np) {
    np = strchr(p, PATH_SEPARATOR);
    if (np) *np++ = '\0';
    pathname = Strnew();
    Strcat_charp(pathname, p);
    Strcat_char(pathname, '/');
    Strcat_charp(pathname, cmd);
    if (stat(pathname->ptr, &st) == 0 && S_ISREG(st.st_mode) &&
        (st.st_mode & S_IXANY) != 0)
      return 1;
  }
  return 0;
}

int kvm_arch_hardware_enable(void) {
  struct kvm* kvm;
  struct kvm_vcpu* vcpu;
  int i;
  int ret;
  u64 local_tsc;
  u64 max_tsc = 0;
  bool stable, backwards_tsc = false;
  kvm_shared_msr_cpu_online();
  ret = kvm_x86_ops->hardware_enable();
  if (ret != 0) return ret;
  local_tsc = native_read_tsc();
  stable = !check_tsc_unstable();
  list_for_each_entry(kvm, &vm_list, vm_list) {
    kvm_for_each_vcpu(i, vcpu, kvm) {
      if (!stable && vcpu->cpu == smp_processor_id())
        kvm_make_request(KVM_REQ_CLOCK_UPDATE, vcpu);
      if (stable && vcpu->arch.last_host_tsc > local_tsc) {
        backwards_tsc = true;
        if (vcpu->arch.last_host_tsc > max_tsc)
          max_tsc = vcpu->arch.last_host_tsc;
      }
    }
  }
  if (backwards_tsc) {
    u64 delta_cyc = max_tsc - local_tsc;
    backwards_tsc_observed = true;
    list_for_each_entry(kvm, &vm_list, vm_list) {
      kvm_for_each_vcpu(i, vcpu, kvm) {
        vcpu->arch.tsc_offset_adjustment += delta_cyc;
        vcpu->arch.last_host_tsc = local_tsc;
        kvm_make_request(KVM_REQ_MASTERCLOCK_UPDATE, vcpu);
      }
      kvm->arch.last_tsc_nsec = 0;
      kvm->arch.last_tsc_write = 0;
    }
  }
  return 0;
}

proc_map_files_instantiate(struct inode* dir, struct dentry* dentry,
                           struct task_struct* task, const void* ptr) {
  const struct file* file = ptr;
  struct proc_inode* ei;
  struct inode* inode;
  if (!file) return ERR_PTR(-ENOENT);
  inode = proc_pid_make_inode(dir->i_sb, task);
  if (!inode) return ERR_PTR(-ENOENT);
  ei = PROC_I(inode);
  ei->op.proc_get_link = proc_map_files_get_link;
  inode->i_op = &proc_pid_link_inode_operations;
  inode->i_size = 64;
  inode->i_mode = S_IFLNK;
  if (file->f_mode & FMODE_READ) inode->i_mode |= S_IRUSR;
  if (file->f_mode & FMODE_WRITE) inode->i_mode |= S_IWUSR;
  d_set_d_op(dentry, &tid_map_files_dentry_operations);
  d_add(dentry, inode);
  return NULL;
}

xfs_readlink_by_handle(struct file* parfilp, xfs_fsop_handlereq_t* hreq) {
  struct dentry* dentry;
  __u32 olen;
  int error;
  if (!capable(CAP_SYS_ADMIN)) return -EPERM;
  dentry = xfs_handlereq_to_dentry(parfilp, hreq);
  if (IS_ERR(dentry)) return PTR_ERR(dentry);
  if (!d_is_symlink(dentry)) {
    error = -EINVAL;
    goto out_dput;
  }
  if (copy_from_user(&olen, hreq->ohandlen, sizeof(__u32))) {
    error = -EFAULT;
    goto out_dput;
  }
  error = vfs_readlink(dentry, hreq->ohandle, olen);
out_dput:
  dput(dentry);
  return error;
}

read_PackInfo(struct archive_read* a, struct _7z_pack_info* pi) {
  const unsigned char* p;
  unsigned i;
  memset(pi, 0, sizeof(*pi));
  if (parse_7zip_uint64(a, &(pi->pos)) < 0) return (-1);
  if (parse_7zip_uint64(a, &(pi->numPackStreams)) < 0) return (-1);
  if (pi->numPackStreams == 0) return (-1);
  if (UMAX_ENTRY < pi->numPackStreams) return (-1);
  if ((p = header_bytes(a, 1)) == NULL) return (-1);
  if (*p == kEnd) return (0);
  if (*p != kSize) return (-1);
  pi->sizes = calloc((size_t)pi->numPackStreams, sizeof(uint64_t));
  pi->positions = calloc((size_t)pi->numPackStreams, sizeof(uint64_t));
  if (pi->sizes == NULL || pi->positions == NULL) return (-1);
  for (i = 0; i < pi->numPackStreams; i++) {
    if (parse_7zip_uint64(a, &(pi->sizes[i])) < 0) return (-1);
  }
  if ((p = header_bytes(a, 1)) == NULL) return (-1);
  if (*p == kEnd) {
    pi->digest.defineds =
        calloc((size_t)pi->numPackStreams, sizeof(*pi->digest.defineds));
    pi->digest.digests =
        calloc((size_t)pi->numPackStreams, sizeof(*pi->digest.digests));
    if (pi->digest.defineds == NULL || pi->digest.digests == NULL) return (-1);
    return (0);
  }
  if (*p != kSize) return (-1);
  if (read_Digests(a, &(pi->digest), (size_t)pi->numPackStreams) < 0)
    return (-1);
  if ((p = header_bytes(a, 1)) == NULL) return (-1);
  if (*p != kEnd) return (-1);
  return (0);
}

int php_request_startup(void) {
  int retval = SUCCESS;
#if PHP_SIGCHILD
  signal(SIGCHLD, sigchld_handler);
#endif
  if (php_start_sapi() == FAILURE) {
    return FAILURE;
  }
  php_output_activate();
  sapi_activate();
  php_hash_environment();
  zend_try {
    PG(during_request_startup) = 1;
    if (PG(expose_php)) {
      sapi_add_header(SAPI_PHP_VERSION_HEADER,
                      sizeof(SAPI_PHP_VERSION_HEADER) - 1, 1);
    }
  }
  zend_catch { retval = FAILURE; }
  zend_end_try();
  return retval;
}

