bool RenderView::CaptureThumbnail(WebView* view, int w, int h,
                                  SkBitmap* thumbnail, ThumbnailScore* score) {
  base::TimeTicks beginning_time = base::TimeTicks::Now();
  skia::PlatformCanvas canvas;
  if (!PaintViewIntoCanvas(view, canvas)) return false;
  skia::BitmapPlatformDevice& device =
      static_cast<skia::BitmapPlatformDevice&>(canvas.getTopPlatformDevice());
  const SkBitmap& src_bmp = device.accessBitmap(false);
  SkRect dest_rect = {0, 0, SkIntToScalar(w), SkIntToScalar(h)};
  float dest_aspect = dest_rect.width() / dest_rect.height();
  SkIRect src_rect;
  if (src_bmp.width() < dest_rect.width() ||
      src_bmp.height() < dest_rect.height()) {
    src_rect.set(0, 0, static_cast<S16CPU>(dest_rect.width()),
                 static_cast<S16CPU>(dest_rect.height()));
    score->good_clipping = false;
  } else {
    float src_aspect = static_cast<float>(src_bmp.width()) / src_bmp.height();
    if (src_aspect > dest_aspect) {
      S16CPU new_width = static_cast<S16CPU>(src_bmp.height() * dest_aspect);
      S16CPU x_offset = (src_bmp.width() - new_width) / 2;
      src_rect.set(x_offset, 0, new_width + x_offset, src_bmp.height());
      score->good_clipping = false;
    } else {
      src_rect.set(0, 0, src_bmp.width(),
                   static_cast<S16CPU>(src_bmp.width() / dest_aspect));
      score->good_clipping = true;
    }
  }
  score->at_top = (view->mainFrame()->scrollOffset().height == 0);
  SkBitmap subset;
  device.accessBitmap(false).extractSubset(&subset, src_rect);
  *thumbnail = skia::ImageOperations::Resize(
      subset, skia::ImageOperations::RESIZE_LANCZOS3, w, h);
  score->boring_score = CalculateBoringScore(thumbnail);
  HISTOGRAM_TIMES("Renderer4.Thumbnail",
                  base::TimeTicks::Now() - beginning_time);
  return true;
}

static bool torture_winbind_struct_dsgetdcname(
    struct torture_context* torture) {
  bool ok;
  bool strict = torture_setting_bool(torture, "strict mode", false);
  struct torture_trust_domain* listd = NULL;
  uint32_t i;
  uint32_t count = 0;
  torture_comment(torture, "Running WINBINDD_DSGETDCNAME (struct based)\n");
  ok = get_trusted_domains(torture, &listd);
  torture_assert(torture, ok, "failed to get trust list");
  for (i = 0; listd && listd[i].netbios_name; i++) {
    struct winbindd_request req;
    struct winbindd_response rep;
    ZERO_STRUCT(req);
    ZERO_STRUCT(rep);
    if (strlen(listd[i].dns_name) == 0) continue;
    if (strcmp(listd[i].dns_name, listd[i].netbios_name) == 0) {
      continue;
    }
    fstrcpy(req.domain_name, listd[i].dns_name);
    req.flags = DS_DIRECTORY_SERVICE_REQUIRED;
    ok = true;
    DO_STRUCT_REQ_REP_EXT(
        WINBINDD_DSGETDCNAME, &req, &rep, NSS_STATUS_SUCCESS, strict,
        ok = false, talloc_asprintf(torture, "DOMAIN '%s'", req.domain_name));
    if (!ok) continue;
    torture_comment(torture, "DOMAIN '%s' => DCNAME '%s'\n", req.domain_name,
                    rep.data.dc_name);
    count++;
  }
  if (count == 0) {
    torture_warning(torture,
                    "WINBINDD_DSGETDCNAME"
                    " was not tested with %d non-AD domains",
                    i);
  }
  if (strict) {
    torture_assert(torture, count > 0, "WiNBINDD_DSGETDCNAME was not tested");
  }
  return true;
}

