AFframecount afSeekFrame(AFfilehandle file, int trackid, AFframecount frame) {
  _Track* track;
  if (!_af_filehandle_ok(file)) return -1;
  if (!_af_filehandle_can_read(file)) return -1;
  if ((track = _af_filehandle_get_track(file, trackid)) == NULL) return -1;
  if (track->ms->isDirty() && track->ms->setup(file, track) == AF_FAIL)
    return -1;
  if (frame < 0) return track->nextvframe;
  if (frame == track->nextvframe) return track->nextvframe;
  if (track->totalvframes != -1)
    if (frame > track->totalvframes) frame = track->totalvframes - 1;
  track->nextvframe = frame;
  if (track->ms->setup(file, track) == AF_FAIL) return -1;
  return track->nextvframe;
}

join_tab_cmp_straight(const void* dummy, const void* ptr1, const void* ptr2) {
  JOIN_TAB* jt1 = *(JOIN_TAB**)ptr1;
  JOIN_TAB* jt2 = *(JOIN_TAB**)ptr2;
  DBUG_ASSERT(!jt1->emb_sj_nest);
  DBUG_ASSERT(!jt2->emb_sj_nest);
  int cmp;
  if ((cmp = compare_embedding_subqueries(jt1, jt2)) != 0) return cmp;
  if (jt1->dependent & jt2->table->map) return 1;
  if (jt2->dependent & jt1->table->map) return -1;
  return jt1 > jt2 ? 1 : (jt1 < jt2 ? -1 : 0);
}

choose_plan(JOIN* join, table_map join_tables) {
  uint search_depth = join->thd->variables.optimizer_search_depth;
  uint prune_level = join->thd->variables.optimizer_prune_level;
  uint use_cond_selectivity =
      join->thd->variables.optimizer_use_condition_selectivity;
  bool straight_join = MY_TEST(join->select_options & SELECT_STRAIGHT_JOIN);
  THD* thd = join->thd;
  DBUG_ENTER("choose_plan");
  join->cur_embedding_map = 0;
  reset_nj_counters(join, join->join_list);
  qsort2_cmp jtab_sort_func;
  if (join->emb_sjm_nest) {
    jtab_sort_func = join_tab_cmp_embedded_first;
  } else {
    jtab_sort_func = straight_join ? join_tab_cmp_straight : join_tab_cmp;
  }
  my_qsort2(join->best_ref + join->const_tables,
            join->table_count - join->const_tables, sizeof(JOIN_TAB*),
            jtab_sort_func, (void*)join->emb_sjm_nest);
  Json_writer_object wrapper(thd);
  Json_writer_array trace_plan(thd, "considered_execution_plans");
  if (!join->emb_sjm_nest) {
    choose_initial_table_order(join);
  }
  join->cur_sj_inner_tables = 0;
  if (straight_join) {
    optimize_straight_join(join, join_tables);
  } else {
    DBUG_ASSERT(search_depth <= MAX_TABLES + 1);
    if (search_depth == 0) search_depth = determine_search_depth(join);
    if (greedy_search(join, join_tables, search_depth, prune_level,
                      use_cond_selectivity))
      DBUG_RETURN(TRUE);
  }
  if (join->thd->lex->is_single_level_stmt())
    join->thd->status_var.last_query_cost = join->best_read;
  DBUG_RETURN(FALSE);
}

AP_CORE_DECLARE(void) ap_parse_uri(request_rec* r, const char* uri) {
  int status = HTTP_OK;
  r->unparsed_uri = apr_pstrdup(r->pool, uri);
  while ((uri[0] == '/') && (uri[1] == '/')) {
    ++uri;
  }
  if (r->method_number == M_CONNECT) {
    status = apr_uri_parse_hostinfo(r->pool, uri, &r->parsed_uri);
  } else {
    status = apr_uri_parse(r->pool, uri, &r->parsed_uri);
  }
  if (status == APR_SUCCESS) {
    if (r->parsed_uri.scheme &&
        !strcasecmp(r->parsed_uri.scheme, ap_http_scheme(r))) {
      r->hostname = r->parsed_uri.hostname;
    } else if (r->method_number == M_CONNECT) {
      r->hostname = r->parsed_uri.hostname;
    }
    r->args = r->parsed_uri.query;
    r->uri =
        r->parsed_uri.path ? r->parsed_uri.path : apr_pstrdup(r->pool, "/");
#if defined(OS2) || defined(WIN32)
    {
      char* x;
      for (x = r->uri; (x = strchr(x, '\\')) != NULL;) *x = '/';
    }
#endif
  } else {
    r->args = NULL;
    r->hostname = NULL;
    r->status = HTTP_BAD_REQUEST;
    r->uri = apr_pstrdup(r->pool, uri);
  }
}

static sctp_disposition_t sctp_sf_shut_8_4_5(
    struct net* net, const struct sctp_endpoint* ep,
    const struct sctp_association* asoc, const sctp_subtype_t type, void* arg,
    sctp_cmd_seq_t* commands) {
  struct sctp_packet* packet = NULL;
  struct sctp_chunk* chunk = arg;
  struct sctp_chunk* shut;
  packet = sctp_ootb_pkt_new(net, asoc, chunk);
  if (packet) {
    shut = sctp_make_shutdown_complete(asoc, chunk);
    if (!shut) {
      sctp_ootb_pkt_free(packet);
      return SCTP_DISPOSITION_NOMEM;
    }
    if (sctp_test_T_bit(shut)) packet->vtag = ntohl(chunk->sctp_hdr->vtag);
    shut->skb->sk = ep->base.sk;
    sctp_packet_append_chunk(packet, shut);
    sctp_add_cmd_sf(commands, SCTP_CMD_SEND_PKT, SCTP_PACKET(packet));
    SCTP_INC_STATS(net, SCTP_MIB_OUTCTRLCHUNKS);
    if (!sctp_chunk_length_valid(chunk, sizeof(sctp_chunkhdr_t)))
      return sctp_sf_pdiscard(net, ep, asoc, type, arg, commands);
    return sctp_sf_pdiscard(net, ep, asoc, type, arg, commands);
  }
  return SCTP_DISPOSITION_NOMEM;
}

bool JOIN::shrink_join_buffers(JOIN_TAB* jt, ulonglong curr_space,
                               ulonglong needed_space) {
  JOIN_TAB* tab;
  JOIN_CACHE* cache;
  for (tab = first_linear_tab(this, WITHOUT_BUSH_ROOTS, WITHOUT_CONST_TABLES);
       tab != jt; tab = next_linear_tab(this, tab, WITHOUT_BUSH_ROOTS)) {
    cache = tab->cache;
    if (cache) {
      size_t buff_size;
      if (needed_space < cache->get_min_join_buffer_size()) return TRUE;
      if (cache->shrink_join_buffer_in_ratio(curr_space, needed_space)) {
        revise_cache_usage(tab);
        return TRUE;
      }
      buff_size = cache->get_join_buffer_size();
      curr_space -= buff_size;
      needed_space -= buff_size;
    }
  }
  cache = jt->cache;
  DBUG_ASSERT(cache);
  if (needed_space < cache->get_min_join_buffer_size()) return TRUE;
  cache->set_join_buffer_size((size_t)needed_space);
  return FALSE;
}

