is_device_in_fstab(Device* device, char** out_mount_point) {
  GList* l;
  GList* mount_points;
  gboolean ret;
  ret = FALSE;
  mount_points = g_unix_mount_points_get(NULL);
  for (l = mount_points; l != NULL; l = l->next) {
    GUnixMountPoint* mount_point = l->data;
    char canonical_device_file[PATH_MAX];
    char* device_path;
    char* s;
    device_path = g_strdup(g_unix_mount_point_get_device_path(mount_point));
    if (g_str_has_prefix(device_path, "UUID=")) {
      s = device_path;
      device_path = g_strdup_printf("/dev/disk/by-uuid/%s", device_path + 5);
      g_free(s);
    } else if (g_str_has_prefix(device_path, "LABEL=")) {
      s = device_path;
      device_path = g_strdup_printf("/dev/disk/by-label/%s", device_path + 6);
      g_free(s);
    }
    if (realpath(device_path, canonical_device_file) == NULL) {
      g_free(device_path);
      continue;
    }
    g_free(device_path);
    if (strcmp(device->priv->device_file, canonical_device_file) == 0) {
      ret = TRUE;
      if (out_mount_point != NULL)
        *out_mount_point =
            g_strdup(g_unix_mount_point_get_mount_path(mount_point));
      break;
    }
  }
  g_list_foreach(mount_points, (GFunc)g_unix_mount_point_free, NULL);
  g_list_free(mount_points);
  return ret;
}

MagickPrivate void XProgressMonitorWidget(Display* display, XWindows* windows,
                                          const char* task,
                                          const MagickOffsetType offset,
                                          const MagickSizeType span) {
  unsigned int width;
  XEvent event;
  assert(display != (Display*)NULL);
  assert(windows != (XWindows*)NULL);
  assert(task != (const char*)NULL);
  (void)LogMagickEvent(TraceEvent, GetMagickModule(), "%s", task);
  if (span == 0) return;
  while (XCheckTypedWindowEvent(display, windows->command.id, Expose, &event))
    (void)XCommandWidget(display, windows, (const char* const*)NULL, &event);
  while (XCheckTypedWindowEvent(display, windows->image.id, Expose, &event))
    XRefreshWindow(display, &windows->image, &event);
  while (XCheckTypedWindowEvent(display, windows->info.id, Expose, &event))
    if (monitor_info.text != (char*)NULL)
      XInfoWidget(display, windows, monitor_info.text);
  if ((windows->info.mapped == MagickFalse) || (task != monitor_info.text))
    XInfoWidget(display, windows, task);
  width = (unsigned int)(((offset + 1) *
                          (windows->info.width - (2 * monitor_info.x))) /
                         span);
  if (width < monitor_info.width) {
    monitor_info.raised = MagickTrue;
    XDrawWidgetText(display, &windows->info, &monitor_info);
    monitor_info.raised = MagickFalse;
  }
  monitor_info.width = width;
  XDrawWidgetText(display, &windows->info, &monitor_info);
  (void)XFlush(display);
}

