  }
  if (option & ~(PGSQL_CONV_FORCE_NULL | PGSQL_DML_NO_CONV | PGSQL_DML_EXEC |
                 PGSQL_DML_ASYNC | PGSQL_DML_STRING | PGSQL_DML_ESCAPE)) {
    php_error_docref(NULL, E_WARNING, "Invalid option is specified");
    RETURN_FALSE;
  }
  ZEND_FETCH_RESOURCE2(pg_link, PGconn*, pgsql_link, id, "PostgreSQL link",
                       le_link, le_plink);
  if (php_pgsql_flush_query(pg_link)) {
    php_error_docref(NULL, E_NOTICE,
                     "Detected unhandled result(s) in connection");
  }
  array_init(return_value);
  if (php_pgsql_select(pg_link, table, ids, return_value, option, &sql) ==
      FAILURE) {
    zval_ptr_dtor(return_value);
    RETURN_FALSE;
  }
  if (option & PGSQL_DML_STRING) {
    zval_ptr_dtor(return_value);
    RETURN_STR(sql);
  }
  return;
}

static int openssl_push_check_result(lua_State* L, int ret, const char* name) {
  switch (ret) {
    case 1:
      lua_pushboolean(L, 1);
      if (name) {
        lua_pushstring(L, name);
        ret = 2;
      }
      break;
    case 0:
      lua_pushboolean(L, 0);
      ret = 1;
      break;
    case -1:
      lua_pushnil(L);
      lua_pushliteral(L, "internal");
      ret = 2;
    case -2:
      lua_pushnil(L);
      lua_pushliteral(L, "malformed");
      ret = 2;
    default:
      lua_pushnil(L);
      lua_pushinteger(L, ret);
      ret = 2;
  }
  return ret;
}

int ssl_prepare_serverhello_tlsext(SSL* s) {
#ifndef OPENSSL_NO_EC
  unsigned long alg_k = s->s3->tmp.new_cipher->algorithm_mkey;
  unsigned long alg_a = s->s3->tmp.new_cipher->algorithm_auth;
  int using_ecc =
      (alg_k & (SSL_kEECDH | SSL_kECDHr | SSL_kECDHe)) || (alg_a & SSL_aECDSA);
  using_ecc = using_ecc && (s->session->tlsext_ecpointformatlist != NULL);
  if (using_ecc) {
    if (s->tlsext_ecpointformatlist != NULL)
      OPENSSL_free(s->tlsext_ecpointformatlist);
    if ((s->tlsext_ecpointformatlist = OPENSSL_malloc(3)) == NULL) {
      SSLerr(SSL_F_SSL_PREPARE_SERVERHELLO_TLSEXT, ERR_R_MALLOC_FAILURE);
      return -1;
    }
    s->tlsext_ecpointformatlist_length = 3;
    s->tlsext_ecpointformatlist[0] = TLSEXT_ECPOINTFORMAT_uncompressed;
    s->tlsext_ecpointformatlist[1] =
        TLSEXT_ECPOINTFORMAT_ansiX962_compressed_prime;
    s->tlsext_ecpointformatlist[2] =
        TLSEXT_ECPOINTFORMAT_ansiX962_compressed_char2;
  }
#endif
  return 1;
}

