static int acl_match_meth(struct sample* smp, struct acl_pattern* pattern) {
  int icase;
  if (smp->type == SMP_T_UINT) {
    if (smp->data.uint == pattern->val.i) return ACL_PAT_PASS;
    return ACL_PAT_FAIL;
  }
  if (pattern->val.i != HTTP_METH_OTHER) return ACL_PAT_FAIL;
  if (pattern->len != smp->data.str.len) return ACL_PAT_FAIL;
  icase = pattern->flags & ACL_PAT_F_IGNORE_CASE;
  if ((icase && strncasecmp(pattern->ptr.str, smp->data.str.str,
                            smp->data.str.len) != 0) ||
      (!icase &&
       strncmp(pattern->ptr.str, smp->data.str.str, smp->data.str.len) != 0))
    return ACL_PAT_FAIL;
  return ACL_PAT_PASS;
}

parse_reparse_symlink(struct reparse_symlink_data_buffer* symlink_buf, u32 plen,
                      char** target_path, struct cifs_sb_info* cifs_sb) {
  unsigned int sub_len;
  unsigned int sub_offset;
  sub_offset = le16_to_cpu(symlink_buf->SubstituteNameOffset);
  sub_len = le16_to_cpu(symlink_buf->SubstituteNameLength);
  if (sub_offset + 20 > plen || sub_offset + sub_len + 20 > plen) {
    cifs_dbg(VFS, "srv returned malformed symlink buffer\n");
    return -EIO;
  }
  *target_path = cifs_strndup_from_utf16(symlink_buf->PathBuffer + sub_offset,
                                         sub_len, true, cifs_sb->local_nls);
  if (!(*target_path)) return -ENOMEM;
  convert_delimiter(*target_path, '/');
  cifs_dbg(FYI, "%s: target path: %s\n", __func__, *target_path);
  return 0;
}

