xmlValidGetPotentialChildren(xmlElementContent* ctree, const xmlChar** names,
                             int* len, int max) {
  int i;
  if ((ctree == NULL) || (names == NULL) || (len == NULL)) return (-1);
  if (*len >= max) return (*len);
  switch (ctree->type) {
    case XML_ELEMENT_CONTENT_PCDATA:
      for (i = 0; i < *len; i++)
        if (xmlStrEqual(BAD_CAST "#PCDATA", names[i])) return (*len);
      names[(*len)++] = BAD_CAST "#PCDATA";
      break;
    case XML_ELEMENT_CONTENT_ELEMENT:
      for (i = 0; i < *len; i++)
        if (xmlStrEqual(ctree->name, names[i])) return (*len);
      names[(*len)++] = ctree->name;
      break;
    case XML_ELEMENT_CONTENT_SEQ:
      xmlValidGetPotentialChildren(ctree->c1, names, len, max);
      xmlValidGetPotentialChildren(ctree->c2, names, len, max);
      break;
    case XML_ELEMENT_CONTENT_OR:
      xmlValidGetPotentialChildren(ctree->c1, names, len, max);
      xmlValidGetPotentialChildren(ctree->c2, names, len, max);
      break;
  }
  return (*len);
}

static int parse_request_line(struct transaction_t* txn) {
  struct request_line_t* req_line = &txn->req_line;
  char* p;
  tok_t tok;
  int ret = 0;
  p = req_line->buf + strlen(req_line->buf);
  if (p[-1] == '\n') *--p = '\0';
  if (p[-1] == '\r') *--p = '\0';
  tok_initm(&tok, req_line->buf, " ", 0);
  if (!(req_line->meth = tok_next(&tok))) {
    ret = HTTP_BAD_REQUEST;
    txn->error.desc = "Missing method in request-line";
  } else if (!(req_line->uri = tok_next(&tok))) {
    ret = HTTP_BAD_REQUEST;
    txn->error.desc = "Missing request-target in request-line";
  } else if ((size_t)(p - req_line->buf) > MAX_REQ_LINE - 2) {
    ret = HTTP_URI_TOO_LONG;
    buf_printf(&txn->buf, "Length of request-line MUST be less than %u octets",
               MAX_REQ_LINE);
    txn->error.desc = buf_cstring(&txn->buf);
  } else if (!(req_line->ver = tok_next(&tok))) {
    ret = HTTP_BAD_REQUEST;
    txn->error.desc = "Missing HTTP-version in request-line";
  } else if (tok_next(&tok)) {
    ret = HTTP_BAD_REQUEST;
    txn->error.desc = "Unexpected extra argument(s) in request-line";
  } else if (strlen(req_line->ver) != HTTP_VERSION_LEN ||
             strncmp(req_line->ver, HTTP_VERSION, HTTP_VERSION_LEN - 1) ||
             !isdigit(req_line->ver[HTTP_VERSION_LEN - 1])) {
    ret = HTTP_BAD_VERSION;
    buf_printf(&txn->buf, "This server only speaks %.*sx", HTTP_VERSION_LEN - 1,
               HTTP_VERSION);
    txn->error.desc = buf_cstring(&txn->buf);
  } else if (req_line->ver[HTTP_VERSION_LEN - 1] == '0') {
    txn->flags.ver = VER_1_0;
  }
  tok_fini(&tok);
  return ret;
}

is_valid_cert_without_private_key(CERTCertificate* cert, void* data) {
  struct validity_cbdata* cbd = (struct validity_cbdata*)data;
  PK11SlotInfo* slot = cbd->slot;
  SECKEYPrivateKey* privkey = NULL;
  int errnum;
  errnum = PORT_GetError();
  if (errnum == SEC_ERROR_EXTENSION_NOT_FOUND) {
    dprintf("Got SEC_ERROR_EXTENSION_NOT_FOUND; clearing");
    PORT_SetError(0);
    errnum = 0;
  }
  if (cert == NULL) {
    if (!errnum) PORT_SetError(SEC_ERROR_UNKNOWN_CERT);
    return SECFailure;
  }
  privkey = PK11_FindPrivateKeyFromCert(slot, cert, cbd->cms);
  if (privkey == NULL) {
    if (cbd->cert) CERT_DestroyCertificate(cbd->cert);
    PORT_SetError(0);
    cbd->cert = CERT_DupCertificate(cert);
    CERT_DestroyCertificate(cert);
    return SECSuccess;
  } else {
    SECKEY_DestroyPrivateKey(privkey);
    CERT_DestroyCertificate(cert);
  }
  return SECFailure;
}

