  isdn_info_update();
}

static int do_move_mount(struct path* path, const char* old_name) {
  struct path old_path, parent_path;
  struct mount* p;
  struct mount* old;
  struct mountpoint* mp;
  int err;
  if (!old_name || !*old_name) return -EINVAL;
  err = kern_path(old_name, LOOKUP_FOLLOW, &old_path);
  if (err) return err;
  mp = lock_mount(path);
  err = PTR_ERR(mp);
  if (IS_ERR(mp)) goto out;
  old = real_mount(old_path.mnt);
  p = real_mount(path->mnt);
  err = -EINVAL;
  if (!check_mnt(p) || !check_mnt(old)) goto out1;
  if (old->mnt.mnt_flags & MNT_LOCKED) goto out1;
  err = -EINVAL;
  if (old_path.dentry != old_path.mnt->mnt_root) goto out1;
  if (!mnt_has_parent(old)) goto out1;
  if (S_ISDIR(path->dentry->d_inode->i_mode) !=
      S_ISDIR(old_path.dentry->d_inode->i_mode))
    goto out1;
  if (IS_MNT_SHARED(old->mnt_parent)) goto out1;
  if (IS_MNT_SHARED(p) && tree_contains_unbindable(old)) goto out1;
  err = -ELOOP;
  for (; mnt_has_parent(p); p = p->mnt_parent)
    if (p == old) goto out1;
  err = attach_recursive_mnt(old, real_mount(path->mnt), mp, &parent_path);
  if (err) goto out1;
  list_del_init(&old->mnt_expire);
out1:
  unlock_mount(mp);
out:
  if (!err) path_put(&parent_path);
  path_put(&old_path);
  return err;
}

