Reopen an IMAP stream to a new mailbox* / PHP_FUNCTION(imap_reopen) {
  zval* streamind;
  zend_string* mailbox;
  zend_long options = 0, retries = 0;
  pils* imap_le_struct;
  long flags = NIL;
  long cl_flags = NIL;
  if (zend_parse_parameters(ZEND_NUM_ARGS(), "rS|ll", &streamind, &mailbox,
                            &options, &retries) == FAILURE) {
    return;
  }
  if ((imap_le_struct = (pils*)zend_fetch_resource(Z_RES_P(streamind), "imap",
                                                   le_imap)) == NULL) {
    RETURN_FALSE;
  }
  if (options) {
    flags = options;
    if (flags & PHP_EXPUNGE) {
      cl_flags = CL_EXPUNGE;
      flags ^= PHP_EXPUNGE;
    }
    imap_le_struct->flags = cl_flags;
  }
#ifdef SET_MAXLOGINTRIALS
  if (retries) {
    mail_parameters(NIL, SET_MAXLOGINTRIALS, (void*)retries);
  }
#endif
  if (ZSTR_VAL(mailbox)[0] != '{' &&
      php_check_open_basedir(ZSTR_VAL(mailbox))) {
    RETURN_FALSE;
  }
  imap_le_struct->imap_stream =
      mail_open(imap_le_struct->imap_stream, ZSTR_VAL(mailbox), flags);
  if (imap_le_struct->imap_stream == NIL) {
    zend_list_delete(Z_RES_P(streamind));
    php_error_docref(NULL, E_WARNING, "Couldn't re-open stream");
    RETURN_FALSE;
  }
  RETURN_TRUE;

sldns_affix_token(sldns_buffer* strbuf, char* token, size_t* token_len,
                  int* quoted, int* parens, size_t* pre_data_pos,
                  const char* delimiters, sldns_rdf_type rdftype,
                  size_t* token_strlen) {
  size_t addlen = *token_len - *token_strlen;
  size_t addstrlen = 0;
  if (addlen < 1) return 0;
  token[*token_strlen] = ' ';
  token[++(*token_strlen)] = 0;
  addlen = *token_len - *token_strlen;
  if (!sldns_parse_rdf_token(strbuf, token + *token_strlen, addlen, quoted,
                             parens, pre_data_pos, delimiters, rdftype,
                             &addstrlen))
    return 0;
  (*token_strlen) += addstrlen;
  return 1;
}

void PrintWebViewHelper::DidFinishPrinting(PrintingResult result) {
  bool store_print_pages_params = true;
  if (result == FAIL_PRINT) {
    DisplayPrintJobError();
    if (notify_browser_of_print_failure_ && print_pages_params_.get()) {
      int cookie = print_pages_params_->params.document_cookie;
      Send(new PrintHostMsg_PrintingFailed(routing_id(), cookie));
    }
  } else if (result == FAIL_PREVIEW) {
    DCHECK(is_preview_enabled_);
    store_print_pages_params = false;
    int cookie = print_pages_params_.get()
                     ? print_pages_params_->params.document_cookie
                     : 0;
    if (notify_browser_of_print_failure_)
      Send(new PrintHostMsg_PrintPreviewFailed(routing_id(), cookie));
    else
      Send(new PrintHostMsg_PrintPreviewCancelled(routing_id(), cookie));
    print_preview_context_.Failed(notify_browser_of_print_failure_);
  }
  if (print_web_view_) {
    print_web_view_->close();
    print_web_view_ = NULL;
  }
  if (store_print_pages_params) {
    old_print_pages_params_.reset(print_pages_params_.release());
  } else {
    print_pages_params_.reset();
    old_print_pages_params_.reset();
  }
  notify_browser_of_print_failure_ = true;
}

