static int chunk_usage_range_filter(struct btrfs_fs_info* fs_info,
                                    u64 chunk_offset,
                                    struct btrfs_balance_args* bargs) {
  struct btrfs_block_group_cache* cache;
  u64 chunk_used;
  u64 user_thresh_min;
  u64 user_thresh_max;
  int ret = 1;
  cache = btrfs_lookup_block_group(fs_info, chunk_offset);
  chunk_used = btrfs_block_group_used(&cache->item);
  if (bargs->usage_min == 0)
    user_thresh_min = 0;
  else
    user_thresh_min = div_factor_fine(cache->key.offset, bargs->usage_min);
  if (bargs->usage_max == 0)
    user_thresh_max = 1;
  else if (bargs->usage_max > 100)
    user_thresh_max = cache->key.offset;
  else
    user_thresh_max = div_factor_fine(cache->key.offset, bargs->usage_max);
  if (user_thresh_min <= chunk_used && chunk_used < user_thresh_max) ret = 0;
  btrfs_put_block_group(cache);
  return ret;
}

GF_Err minf_box_read(GF_Box* s, GF_BitStream* bs) {
  GF_MediaInformationBox* ptr = (GF_MediaInformationBox*)s;
  GF_Err e;
  e = gf_isom_box_array_read(s, bs, minf_on_child_box);
  if (!e && !ptr->dataInformation) {
    GF_Box* url;
    GF_LOG(GF_LOG_ERROR, GF_LOG_CONTAINER,
           ("[iso file] Missing DataInformationBox\n"));
    ptr->dataInformation = (GF_DataInformationBox*)gf_isom_box_new_parent(
        &ptr->child_boxes, GF_ISOM_BOX_TYPE_DINF);
    if (!ptr->dataInformation) return GF_OUT_OF_MEM;
    ptr->dataInformation->dref = (GF_DataReferenceBox*)gf_isom_box_new_parent(
        &ptr->dataInformation->child_boxes, GF_ISOM_BOX_TYPE_DREF);
    if (!ptr->dataInformation->dref) return GF_OUT_OF_MEM;
    url = gf_isom_box_new_parent(&ptr->dataInformation->dref->child_boxes,
                                 GF_ISOM_BOX_TYPE_URL);
    if (!url) return GF_OUT_OF_MEM;
    ((GF_FullBox*)url)->flags = 1;
  }
  return e;
}

