gpgsm_sign(void* engine, gpgme_data_t in, gpgme_data_t out,
           gpgme_sig_mode_t mode, int use_armor, int use_textmode,
           int include_certs, gpgme_ctx_t ctx) {
  engine_gpgsm_t gpgsm = engine;
  gpgme_error_t err;
  char* assuan_cmd;
  int i;
  gpgme_key_t key;
  if (!gpgsm) return gpg_error(GPG_ERR_INV_VALUE);
  if (include_certs != GPGME_INCLUDE_CERTS_DEFAULT) {
    if (asprintf(&assuan_cmd, "OPTION include-certs %i", include_certs) < 0)
      return gpg_error_from_syserror();
    err =
        gpgsm_assuan_simple_command(gpgsm->assuan_ctx, assuan_cmd, NULL, NULL);
    free(assuan_cmd);
    if (err) return err;
  }
  for (i = 0; (key = gpgme_signers_enum(ctx, i)); i++) {
    const char* s = key->subkeys ? key->subkeys->fpr : NULL;
    if (s && strlen(s) < 80) {
      char buf[100];
      strcpy(stpcpy(buf, "SIGNER "), s);
      err = gpgsm_assuan_simple_command(
          gpgsm->assuan_ctx, buf, gpgsm->status.fnc, gpgsm->status.fnc_value);
    } else
      err = gpg_error(GPG_ERR_INV_VALUE);
    gpgme_key_unref(key);
    if (err) return err;
  }
  gpgsm->input_cb.data = in;
  err = gpgsm_set_fd(gpgsm, INPUT_FD, map_data_enc(gpgsm->input_cb.data));
  if (err) return err;
  gpgsm->output_cb.data = out;
  err =
      gpgsm_set_fd(gpgsm, OUTPUT_FD,
                   use_armor ? "--armor" : map_data_enc(gpgsm->output_cb.data));
  if (err) return err;
  gpgsm_clear_fd(gpgsm, MESSAGE_FD);
  gpgsm->inline_data = NULL;
  err =
      start(gpgsm, mode == GPGME_SIG_MODE_DETACH ? "SIGN --detached" : "SIGN");
  return err;
}

int RGW_Auth_S3::authorize(const DoutPrefixProvider* dpp,
                           rgw::sal::RGWRadosStore* const store,
                           const rgw::auth::StrategyRegistry& auth_registry,
                           struct req_state* const s) {
  if (!store->ctx()->_conf->rgw_s3_auth_use_rados &&
      !store->ctx()->_conf->rgw_s3_auth_use_keystone &&
      !store->ctx()->_conf->rgw_s3_auth_use_ldap) {
    ldpp_dout(dpp, 0) << "WARNING: no authorization backend enabled! Users "
                         "will never authenticate."
                      << dendl;
    return -EPERM;
  }
  const auto ret =
      rgw::auth::Strategy::apply(dpp, auth_registry.get_s3_main(), s);
  if (ret == 0) {
