    s->owner.set_name(s->user->get_display_name());
  }
  return ret;
}

GC_INNER ptr_t GC_alloc_large(size_t lb, int k, unsigned flags) {
  struct hblk* h;
  word n_blocks;
  ptr_t result;
  GC_bool retry = FALSE;
  lb = (lb + GRANULE_BYTES - 1) & ~(GRANULE_BYTES - 1);
  n_blocks = OBJ_SZ_TO_BLOCKS(lb);
  if (!EXPECT(GC_is_initialized, TRUE)) GC_init();
  if (GC_incremental && !GC_dont_gc) GC_collect_a_little_inner((int)n_blocks);
  h = GC_allochblk(lb, k, flags);
#ifdef USE_MUNMAP
  if (0 == h) {
    GC_merge_unmapped();
    h = GC_allochblk(lb, k, flags);
  }
#endif
  while (0 == h && GC_collect_or_expand(n_blocks, flags != 0, retry)) {
    h = GC_allochblk(lb, k, flags);
    retry = TRUE;
  }
  if (h == 0) {
    result = 0;
  } else {
    size_t total_bytes = n_blocks * HBLKSIZE;
    if (n_blocks > 1) {
      GC_large_allocd_bytes += total_bytes;
      if (GC_large_allocd_bytes > GC_max_large_allocd_bytes)
        GC_max_large_allocd_bytes = GC_large_allocd_bytes;
    }
    result = h->hb_body;
  }
  return result;
}

GF_Err fdpa_box_write(GF_Box* s, GF_BitStream* bs) {
  GF_Err e;
  u32 i;
  GF_FDpacketBox* ptr = (GF_FDpacketBox*)s;
  if (!s) return GF_BAD_PARAM;
  e = gf_isom_box_write_header(s, bs);
  if (e) return e;
  gf_bs_write_int(bs, ptr->info.sender_current_time_present, 1);
  gf_bs_write_int(bs, ptr->info.expected_residual_time_present, 1);
  gf_bs_write_int(bs, ptr->info.session_close_bit, 1);
  gf_bs_write_int(bs, ptr->info.object_close_bit, 1);
  gf_bs_write_int(bs, 0, 4);
  gf_bs_write_u16(bs, ptr->info.transport_object_identifier);
  gf_bs_write_u16(bs, ptr->header_ext_count);
  for (i = 0; i < ptr->header_ext_count; i++) {
    gf_bs_write_u8(bs, ptr->headers[i].header_extension_type);
    if (ptr->headers[i].header_extension_type > 127) {
      gf_bs_write_data(bs, (const char*)ptr->headers[i].content, 3);
    } else {
      gf_bs_write_u8(bs, ptr->headers[i].data_length
                             ? (ptr->headers[i].data_length + 2) / 4
                             : 0);
      if (ptr->headers[i].data_length) {
        gf_bs_write_data(bs, ptr->headers[i].data, ptr->headers[i].data_length);
      }
    }
  }
  return GF_OK;
}

BOOL license_read_binary_blob(wStream* s, LICENSE_BLOB* blob) {
  UINT16 wBlobType;
  if (Stream_GetRemainingLength(s) < 4) return FALSE;
  Stream_Read_UINT16(s, wBlobType);
  Stream_Read_UINT16(s, blob->length);
  if (Stream_GetRemainingLength(s) < blob->length) return FALSE;
  if ((blob->type != BB_ANY_BLOB) && (blob->length == 0)) return TRUE;
  if ((blob->type != wBlobType) && (blob->type != BB_ANY_BLOB)) {
    fprintf(
        stderr,
        "license binary blob type (%x) does not match expected type (%x).\n",
        wBlobType, blob->type);
  }
  blob->type = wBlobType;
  blob->data = (BYTE*)malloc(blob->length);
  Stream_Read(s, blob->data, blob->length);
  return TRUE;
}

rfbSetClientColourMapBGR233(rfbClientPtr cl) {
  union {
    char bytes[sz_rfbSetColourMapEntriesMsg + 256 * 3 * 2];
    rfbSetColourMapEntriesMsg msg;
  } buf;
  rfbSetColourMapEntriesMsg* scme = &buf.msg;
  uint16_t* rgb = (uint16_t*)(&buf.bytes[sz_rfbSetColourMapEntriesMsg]);
  int i, len;
  int r, g, b;
  if (cl->format.bitsPerPixel != 8) {
    rfbErr("%s: client not 8 bits per pixel\n", "rfbSetClientColourMapBGR233");
    rfbCloseClient(cl);
    return FALSE;
  }
  scme->type = rfbSetColourMapEntries;
  scme->firstColour = Swap16IfLE(0);
  scme->nColours = Swap16IfLE(256);
  len = sz_rfbSetColourMapEntriesMsg;
  i = 0;
  for (b = 0; b < 4; b++) {
    for (g = 0; g < 8; g++) {
      for (r = 0; r < 8; r++) {
        rgb[i++] = Swap16IfLE(r * 65535 / 7);
        rgb[i++] = Swap16IfLE(g * 65535 / 7);
        rgb[i++] = Swap16IfLE(b * 65535 / 3);
      }
    }
  }
  len += 256 * 3 * 2;
  if (rfbWriteExact(cl, buf.bytes, len) < 0) {
    rfbLogPerror("rfbSetClientColourMapBGR233: write");
    rfbCloseClient(cl);
    return FALSE;
  }
  return TRUE;
}

