get_password(FILE* input, FILE* output, char* prompt, PRBool (*ok)(char*)) {
  int infd = fileno(input);
  char phrase[200];
  size_t size = sizeof(phrase);
  ingress();
  memset(phrase, 0, size);
  while (true) {
    int rc;
    print_prompt(input, output, prompt);
    rc = read_password(input, output, phrase, size);
    if (rc < 0) return NULL;
    if (!ok) break;
    if ((*ok)(phrase)) break;
    if (!isatty(infd)) return NULL;
    fprintf(output, "Password does not meet requirements.\n");
    fflush(output);
  }
  egress();
  return (char*)PORT_Strdup(phrase);
}

static bool zlibToDataBuf(const byte* bytes, long length, DataBuf& result) {
  uLongf uncompressedLen = length * 2;
  int zlibResult;
  do {
    result.alloc(uncompressedLen);
    zlibResult =
        uncompress((Bytef*)result.pData_, &uncompressedLen, bytes, length);
    if (zlibResult == Z_OK && (long)uncompressedLen < result.size_) {
      result.free();
      result.alloc(uncompressedLen);
      zlibResult =
          uncompress((Bytef*)result.pData_, &uncompressedLen, bytes, length);
    }
    if (zlibResult == Z_BUF_ERROR) {
      result.free();
      if (uncompressedLen > 16 * 1024 * 1024)
        zlibResult = Z_DATA_ERROR;
      else
        uncompressedLen *= 2;
    }
  } while (zlibResult == Z_BUF_ERROR);
  return zlibResult == Z_OK;
}

