int ipmi_request_supply_msgs(struct ipmi_user* user, struct ipmi_addr* addr,
                             long msgid, struct kernel_ipmi_msg* msg,
                             void* user_msg_data, void* supplied_smi,
                             struct ipmi_recv_msg* supplied_recv,
                             int priority) {
  unsigned char saddr = 0, lun = 0;
  int rv, index;
