void reds_update_client_mouse_allowed(RedsState* reds) {
  int allow_now = FALSE;
  int x_res = 0;
  int y_res = 0;
  int num_active_workers = reds->qxl_instances.size();
  if (num_active_workers > 0) {
    allow_now = TRUE;
    FOREACH_QXL_INSTANCE(reds, qxl) {
      if (red_qxl_get_allow_client_mouse(qxl, &x_res, &y_res, &allow_now)) {
        break;
      }
    }
  }
  if (allow_now || allow_now != reds->dispatcher_allows_client_mouse) {
    reds->monitor_mode.x_res = x_res;
    reds->monitor_mode.y_res = y_res;
    reds->dispatcher_allows_client_mouse = allow_now;
    reds_update_mouse_mode(reds);
    if (reds->is_client_mouse_allowed && reds->inputs_channel &&
        reds->inputs_channel->has_tablet()) {
      reds->inputs_channel->set_tablet_logical_size(reds->monitor_mode.x_res,
                                                    reds->monitor_mode.y_res);
    }
  }
}

static int __init mcheck_enable(char* str) {
  struct mca_config* cfg = &mca_cfg;
  if (*str == 0) {
    enable_p5_mce();
    return 1;
  }
  if (*str == '=') str++;
  if (!strcmp(str, "off"))
    cfg->disabled = true;
  else if (!strcmp(str, "no_cmci"))
    cfg->cmci_disabled = true;
  else if (!strcmp(str, "no_lmce"))
    cfg->lmce_disabled = true;
  else if (!strcmp(str, "dont_log_ce"))
    cfg->dont_log_ce = true;
  else if (!strcmp(str, "ignore_ce"))
    cfg->ignore_ce = true;
  else if (!strcmp(str, "bootlog") || !strcmp(str, "nobootlog"))
    cfg->bootlog = (str[0] == 'b');
  else if (!strcmp(str, "bios_cmci_threshold"))
    cfg->bios_cmci_threshold = true;
  else if (!strcmp(str, "recovery"))
    cfg->recovery = true;
  else if (isdigit(str[0])) {
    if (get_option(&str, &cfg->tolerant) == 2)
      get_option(&str, &(cfg->monarch_timeout));
  } else {
    pr_info("mce argument %s ignored. Please use /sys\n", str);
    return 0;
  }
  return 1;
}

long keyctl_keyring_link(key_serial_t id, key_serial_t ringid) {
  key_ref_t keyring_ref, key_ref;
  long ret;
  keyring_ref = lookup_user_key(ringid, KEY_LOOKUP_CREATE, KEY_NEED_WRITE);
  if (IS_ERR(keyring_ref)) {
    ret = PTR_ERR(keyring_ref);
    goto error;
  }
  key_ref = lookup_user_key(id, KEY_LOOKUP_CREATE, KEY_NEED_LINK);
  if (IS_ERR(key_ref)) {
    ret = PTR_ERR(key_ref);
    goto error2;
  }
  ret = key_link(key_ref_to_ptr(keyring_ref), key_ref_to_ptr(key_ref));
  key_ref_put(key_ref);
error2:
  key_ref_put(keyring_ref);
error:
  return ret;
}

htp_status_t htp_tx_state_request_complete(htp_tx_t* tx) {
  if (tx == NULL) return HTP_ERROR;
  if (tx->request_progress != HTP_REQUEST_COMPLETE) {
    htp_status_t rc = htp_tx_state_request_complete_partial(tx);
    if (rc != HTP_OK) return rc;
  }
  htp_connp_t* connp = tx->connp;
  if (tx->is_protocol_0_9) {
    connp->in_state = htp_connp_REQ_IGNORE_DATA_AFTER_HTTP_0_9;
  } else {
    connp->in_state = htp_connp_REQ_IDLE;
  }
  htp_tx_finalize(tx);
  connp->in_tx = NULL;
  return HTP_OK;
}

void InstanceKlass::set_enclosing_method_indices(u2 class_index,
