print_chaninfo(netdissect_options* ndo, uint16_t freq, int flags,
               int presentflags) {
  ND_PRINT((ndo, "%u MHz", freq));
  if (presentflags & (1 << IEEE80211_RADIOTAP_MCS)) {
    ND_PRINT((ndo, " 11n"));
  } else {
    if (IS_CHAN_FHSS(flags)) ND_PRINT((ndo, " FHSS"));
    if (IS_CHAN_A(flags)) {
      if (flags & IEEE80211_CHAN_HALF)
        ND_PRINT((ndo, " 11a/10Mhz"));
      else if (flags & IEEE80211_CHAN_QUARTER)
        ND_PRINT((ndo, " 11a/5Mhz"));
      else
        ND_PRINT((ndo, " 11a"));
    }
    if (IS_CHAN_ANYG(flags)) {
      if (flags & IEEE80211_CHAN_HALF)
        ND_PRINT((ndo, " 11g/10Mhz"));
      else if (flags & IEEE80211_CHAN_QUARTER)
        ND_PRINT((ndo, " 11g/5Mhz"));
      else
        ND_PRINT((ndo, " 11g"));
    } else if (IS_CHAN_B(flags))
      ND_PRINT((ndo, " 11b"));
    if (flags & IEEE80211_CHAN_TURBO) ND_PRINT((ndo, " Turbo"));
  }
  if (flags & IEEE80211_CHAN_HT20)
    ND_PRINT((ndo, " ht/20"));
  else if (flags & IEEE80211_CHAN_HT40D)
    ND_PRINT((ndo, " ht/40-"));
  else if (flags & IEEE80211_CHAN_HT40U)
    ND_PRINT((ndo, " ht/40+"));
  ND_PRINT((ndo, " "));
}

njs_array_expand(njs_vm_t* vm, njs_array_t* array, uint32_t prepend,
                 uint32_t append) {
  uint32_t free_before, free_after;
  uint64_t size;
  njs_value_t *start, *old;
  njs_assert(array->object.fast_array);
  free_before = array->start - array->data;
  free_after = array->size - array->length - free_before;
  if (njs_fast_path(free_before >= prepend && free_after >= append)) {
    return NJS_OK;
  }
  size = (uint64_t)prepend + array->length + append;
  if (size < 16) {
    size *= 2;
  } else {
    size += size / 2;
  }
  if (njs_slow_path(size > (UINT32_MAX / sizeof(njs_value_t)))) {
    goto memory_error;
  }
  start = njs_mp_align(vm->mem_pool, sizeof(njs_value_t),
                       size * sizeof(njs_value_t));
  if (njs_slow_path(start == NULL)) {
    goto memory_error;
  }
  array->size = size;
  old = array->data;
  array->data = start;
  start += prepend;
  if (array->length != 0) {
    memcpy(start, array->start, array->length * sizeof(njs_value_t));
  }
  array->start = start;
  if (old != NULL) {
    njs_mp_free(vm->mem_pool, old);
  }
  return NJS_OK;
memory_error:
  njs_memory_error(vm);
  return NJS_ERROR;
}

static void FNAME_DECL(uncompress_row0_seg)(int i, PIXEL* const cur_row,
                                            const int end,
                                            const unsigned int waitmask,
                                            const unsigned int bpc_mask) {
  DECLARE_STATE_VARIABLES;
  DECLARE_CHANNEL_VARIABLES;
  int stopidx;
  spice_assert(end - i > 0);
  if (i == 0) {
    unsigned int codewordlen;
    UNCOMPRESS_PIX_START(&cur_row[i]);
    APPLY_ALL_COMP(UNCOMPRESS_ONE_ROW0_0);
    if (state->waitcnt) {
      --state->waitcnt;
    } else {
      state->waitcnt = (tabrand(&state->tabrand_seed) & waitmask);
      UPDATE_MODEL(0);
    }
    stopidx = ++i + state->waitcnt;
  } else {
    stopidx = i + state->waitcnt;
  }
  while (stopidx < end) {
    for (; i <= stopidx; i++) {
      unsigned int codewordlen;
      UNCOMPRESS_PIX_START(&cur_row[i]);
      APPLY_ALL_COMP(UNCOMPRESS_ONE_ROW0);
    }
    UPDATE_MODEL(stopidx);
    stopidx = i + (tabrand(&state->tabrand_seed) & waitmask);
  }
  for (; i < end; i++) {
    unsigned int codewordlen;
    UNCOMPRESS_PIX_START(&cur_row[i]);
    APPLY_ALL_COMP(UNCOMPRESS_ONE_ROW0);
  }
  state->waitcnt = stopidx - end;
}

PHP_FUNCTION(openssl_pkey_export) {
  struct php_x509_request req;
  zval **zpkey, *args = NULL, *out;
  char* passphrase = NULL;
  int passphrase_len = 0;
  long key_resource = -1;
  EVP_PKEY* key;
  BIO* bio_out = NULL;
  const EVP_CIPHER* cipher;
  if (zend_parse_parameters(ZEND_NUM_ARGS() TSRMLS_CC, "Zz|s!a!", &zpkey, &out,
                            &passphrase, &passphrase_len, &args) == FAILURE) {
    return;
  }
  RETVAL_FALSE;
  key = php_openssl_evp_from_zval(zpkey, 0, passphrase, 0,
                                  &key_resource TSRMLS_CC);
  if (key == NULL) {
    php_error_docref(NULL TSRMLS_CC, E_WARNING,
                     "cannot get key from parameter 1");
    RETURN_FALSE;
  }
  PHP_SSL_REQ_INIT(&req);
  if (PHP_SSL_REQ_PARSE(&req, args) == SUCCESS) {
    bio_out = BIO_new(BIO_s_mem());
    if (passphrase && req.priv_key_encrypt) {
      if (req.priv_key_encrypt_cipher) {
        cipher = req.priv_key_encrypt_cipher;
      } else {
        cipher = (EVP_CIPHER*)EVP_des_ede3_cbc();
      }
    } else {
      cipher = NULL;
    }
    if (PEM_write_bio_PrivateKey(bio_out, key, cipher,
                                 (unsigned char*)passphrase, passphrase_len,
                                 NULL, NULL)) {
      char* bio_mem_ptr;
      long bio_mem_len;
      RETVAL_TRUE;
      bio_mem_len = BIO_get_mem_data(bio_out, &bio_mem_ptr);
      zval_dtor(out);
      ZVAL_STRINGL(out, bio_mem_ptr, bio_mem_len, 1);
    }
  }
  PHP_SSL_REQ_DISPOSE(&req);
  if (key_resource == -1 && key) {
    EVP_PKEY_free(key);
  }
  if (bio_out) {
    BIO_free(bio_out);
  }
}

_XimCountNumberOfAttr(CARD16 total, CARD16* attr, unsigned int* names_len) {
  unsigned int n;
  CARD16 len;
  CARD16 min_len = sizeof(CARD16) + sizeof(CARD16) + sizeof(INT16);
  n = 0;
  *names_len = 0;
  while (total > min_len) {
    len = attr[2];
    if (len >= (total - min_len)) {
      return 0;
    }
    *names_len += (len + 1);
    len += (min_len + XIM_PAD(len + 2));
    total -= len;
    attr = (CARD16*)((char*)attr + len);
    n++;
  }
  return n;
}

static int cenc_decrypt(MOVContext* c, MOVStreamContext* sc,
                        AVEncryptionInfo* sample, uint8_t* input, int size) {
  if (sample->scheme == MKBETAG('c', 'e', 'n', 'c') &&
      !sample->crypt_byte_block && !sample->skip_byte_block) {
    return cenc_scheme_decrypt(c, sc, sample, input, size);
  } else if (sample->scheme == MKBETAG('c', 'b', 'c', '1') &&
             !sample->crypt_byte_block && !sample->skip_byte_block) {
    return cbc1_scheme_decrypt(c, sc, sample, input, size);
  } else if (sample->scheme == MKBETAG('c', 'e', 'n', 's')) {
    return cens_scheme_decrypt(c, sc, sample, input, size);
  } else if (sample->scheme == MKBETAG('c', 'b', 'c', 's')) {
    return cbcs_scheme_decrypt(c, sc, sample, input, size);
  } else {
    av_log(c->fc, AV_LOG_ERROR, "invalid encryption scheme\n");
    return AVERROR_INVALIDDATA;
  }
}

