static long vhost_net_ioctl(struct file* f, unsigned int ioctl,
                            unsigned long arg) {
  struct vhost_net* n = f->private_data;
  void __user* argp = (void __user*)arg;
  u64 __user* featurep = argp;
  struct vhost_vring_file backend;
  u64 features;
  int r;
  switch (ioctl) {
    case VHOST_NET_SET_BACKEND:
      if (copy_from_user(&backend, argp, sizeof backend)) return -EFAULT;
      return vhost_net_set_backend(n, backend.index, backend.fd);
    case VHOST_GET_FEATURES:
      features = VHOST_NET_FEATURES;
      if (copy_to_user(featurep, &features, sizeof features)) return -EFAULT;
      return 0;
    case VHOST_SET_FEATURES:
      if (copy_from_user(&features, featurep, sizeof features)) return -EFAULT;
      if (features & ~VHOST_NET_FEATURES) return -EOPNOTSUPP;
      return vhost_net_set_features(n, features);
    case VHOST_RESET_OWNER:
      return vhost_net_reset_owner(n);
    default:
      mutex_lock(&n->dev.mutex);
      r = vhost_dev_ioctl(&n->dev, ioctl, argp);
      if (r == -ENOIOCTLCMD)
        r = vhost_vring_ioctl(&n->dev, ioctl, argp);
      else
        vhost_net_flush(n);
      mutex_unlock(&n->dev.mutex);
      return r;
  }
}

void HeaderString::append(const char* data, uint32_t data_size) {
  const uint64_t new_capacity = static_cast<uint64_t>(data_size) + size();
  validateCapacity(new_capacity);
  ASSERT(validHeaderString(absl::string_view(data, data_size)));
  switch (type()) {
    case Type::Reference: {
      const absl::string_view prev = getStrView(buffer_);
      buffer_ = InlineHeaderVector();
      getInVec(buffer_).reserve(new_capacity);
      getInVec(buffer_).assign(prev.begin(), prev.end());
      break;
    }
    case Type::Inline: {
      getInVec(buffer_).reserve(new_capacity);
      break;
    }
  }
  getInVec(buffer_).insert(getInVec(buffer_).end(), data, data + data_size);
}

static int grep_file(struct grep_opt* opt, const char* filename) {
  struct stat st;
  int i;
  char* data;
  size_t sz;
  if (lstat(filename, &st) < 0) {
  err_ret:
    if (errno != ENOENT) error("'%s': %s", filename, strerror(errno));
    return 0;
  }
  if (!st.st_size) return 0;
  if (!S_ISREG(st.st_mode)) return 0;
  sz = xsize_t(st.st_size);
  i = open(filename, O_RDONLY);
  if (i < 0) goto err_ret;
  data = xmalloc(sz + 1);
  if (st.st_size != read_in_full(i, data, sz)) {
    error("'%s': short read %s", filename, strerror(errno));
    close(i);
    free(data);
    return 0;
  }
  close(i);
  if (opt->relative && opt->prefix_length) filename += opt->prefix_length;
  i = grep_buffer(opt, filename, data, sz);
  free(data);
  return i;
}

static int tx_active(struct edgeport_port* port) {
  int status;
  struct out_endpoint_desc_block* oedb;
  __u8* lsr;
  int bytes_left = 0;
  oedb = kmalloc(sizeof(*oedb), GFP_KERNEL);
  if (!oedb) return -ENOMEM;
  lsr = kmalloc(1, GFP_KERNEL);
  if (!lsr) {
    kfree(oedb);
    return -ENOMEM;
  }
  status = read_ram(port->port->serial->dev, port->dma_address, sizeof(*oedb),
                    (void*)oedb);
  if (status) goto exit_is_tx_active;
  dev_dbg(&port->port->dev, "%s - XByteCount    0x%X\n", __func__,
          oedb->XByteCount);
  status = read_ram(port->port->serial->dev,
                    port->uart_base + UMPMEM_OFFS_UART_LSR, 1, lsr);
  if (status) goto exit_is_tx_active;
  dev_dbg(&port->port->dev, "%s - LSR = 0x%X\n", __func__, *lsr);
  if ((oedb->XByteCount & 0x80) != 0) bytes_left += 64;
  if ((*lsr & UMP_UART_LSR_TX_MASK) == 0) bytes_left += 1;
exit_is_tx_active:
  dev_dbg(&port->port->dev, "%s - return %d\n", __func__, bytes_left);
  kfree(lsr);
  kfree(oedb);
  return bytes_left;
}

static void sched_dl_do_global(void) {
  u64 new_bw = -1;
  struct dl_bw* dl_b;
  int cpu;
  unsigned long flags;
  def_dl_bandwidth.dl_period = global_rt_period();
  def_dl_bandwidth.dl_runtime = global_rt_runtime();
  if (global_rt_runtime() != RUNTIME_INF)
    new_bw = to_ratio(global_rt_period(), global_rt_runtime());
  for_each_possible_cpu(cpu) {
    rcu_read_lock_sched();
    dl_b = dl_bw_of(cpu);
    raw_spin_lock_irqsave(&dl_b->lock, flags);
    dl_b->bw = new_bw;
    raw_spin_unlock_irqrestore(&dl_b->lock, flags);
    rcu_read_unlock_sched();
  }
}

