PHP_FUNCTION(pg_fetch_all_columns) {
  zval* result;
  PGresult* pgsql_result;
  pgsql_result_handle* pg_result;
  zend_long colno = 0;
  int pg_numrows, pg_row;
  size_t num_fields;
  if (zend_parse_parameters(ZEND_NUM_ARGS(), "r|l", &result, &colno) ==
      FAILURE) {
    RETURN_FALSE;
  }
  ZEND_FETCH_RESOURCE(pg_result, pgsql_result_handle*, result, -1,
                      "PostgreSQL result", le_result);
  pgsql_result = pg_result->result;
  num_fields = PQnfields(pgsql_result);
  if (colno >= (zend_long)num_fields || colno < 0) {
    php_error_docref(NULL, E_WARNING, "Invalid column number '%pd'", colno);
    RETURN_FALSE;
  }
  array_init(return_value);
  if ((pg_numrows = PQntuples(pgsql_result)) <= 0) {
    return;
  }
  for (pg_row = 0; pg_row < pg_numrows; pg_row++) {
    if (PQgetisnull(pgsql_result, pg_row, (int)colno)) {
      add_next_index_null(return_value);
    } else {
      add_next_index_string(return_value,
                            PQgetvalue(pgsql_result, pg_row, (int)colno));
    }
  }
}

