  MMDEBUG("myanmar_shape: from %d length %d", item->item.pos,
          item->item.length);
  while (sstart < end) {
    HB_Bool invalid;
    int send =
        myanmar_nextSyllableBoundary(item->string, sstart, end, &invalid);
    MMDEBUG("syllable from %d, length %d, invalid=%s", sstart, send - sstart,
            invalid ? "TRUE" : "FALSE");
    syllable.item.pos = sstart;
    syllable.item.length = send - sstart;
    syllable.glyphs = item->glyphs + first_glyph;
    syllable.attributes = item->attributes + first_glyph;
    syllable.advances = item->advances + first_glyph;
    syllable.offsets = item->offsets + first_glyph;
    syllable.num_glyphs = item->num_glyphs - first_glyph;
    if (!myanmar_shape_syllable(openType, &syllable, invalid)) {
      MMDEBUG("syllable shaping failed, syllable requests %d glyphs",
              syllable.num_glyphs);
      item->num_glyphs += syllable.num_glyphs;
      return FALSE;
    }
    MMDEBUG("syllable:");
    for (i = first_glyph; i < first_glyph + (int)syllable.num_glyphs; ++i)
      MMDEBUG("        %d -> glyph %x", i, item->glyphs[i]);
    MMDEBUG("    logclusters:");
    for (i = sstart; i < send; ++i) {
      MMDEBUG("        %d -> glyph %d", i, first_glyph);
      logClusters[i - item->item.pos] = first_glyph;
    }
    sstart = send;
    first_glyph += syllable.num_glyphs;
  }
  item->num_glyphs = first_glyph;
  return TRUE;
}

static void ahci_mem_write(void* opaque, hwaddr addr, uint64_t val,
                           unsigned size) {
  AHCIState* s = opaque;
  DPRINTF(-1, "addr=0x%" HWADDR_PRIx " val=0x%" PRIx64 ", size=%d\n", addr, val,
          size);
  if (addr & 3) {
    fprintf(stderr, "ahci: Mis-aligned write to addr 0x" TARGET_FMT_plx "\n",
            addr);
    return;
  }
  if (addr < AHCI_GENERIC_HOST_CONTROL_REGS_MAX_ADDR) {
    DPRINTF(-1, "(addr 0x%08X), val 0x%08" PRIX64 "\n", (unsigned)addr, val);
    switch (addr) {
      case HOST_CAP:
        break;
      case HOST_CTL:
        if (val & HOST_CTL_RESET) {
          DPRINTF(-1, "HBA Reset\n");
          ahci_reset(s);
        } else {
          s->control_regs.ghc = (val & 0x3) | HOST_CTL_AHCI_EN;
          ahci_check_irq(s);
        }
        break;
      case HOST_IRQ_STAT:
        s->control_regs.irqstatus &= ~val;
        ahci_check_irq(s);
        break;
      case HOST_PORTS_IMPL:
        break;
      case HOST_VERSION:
        break;
      default:
        DPRINTF(-1, "write to unknown register 0x%x\n", (unsigned)addr);
    }
  } else if ((addr >= AHCI_PORT_REGS_START_ADDR) &&
             (addr < (AHCI_PORT_REGS_START_ADDR +
                      (s->ports * AHCI_PORT_ADDR_OFFSET_LEN)))) {
    ahci_port_write(s, (addr - AHCI_PORT_REGS_START_ADDR) >> 7,
                    addr & AHCI_PORT_ADDR_OFFSET_MASK, val);
  }
}

static int list_keys(void) {
  int r, idx = 0;
  sc_path_t path;
  u8 buf[2048], *p = buf;
  size_t keysize, i;
  int mod_lens[] = {512, 768, 1024, 2048};
  size_t sizes[] = {167, 247, 327, 647};
  r = select_app_df();
  if (r) return 1;
  sc_format_path("I1012", &path);
  r = sc_select_file(card, &path, NULL);
  if (r) {
    fprintf(stderr, "Unable to select public key file: %s\n", sc_strerror(r));
    return 2;
  }
  do {
    int mod_len = -1;
    r = sc_read_binary(card, idx, buf, 3, 0);
    if (r < 0) {
      fprintf(stderr, "Unable to read public key file: %s\n", sc_strerror(r));
      return 2;
    }
    keysize = (p[0] << 8) | p[1];
    if (keysize == 0) break;
    idx += keysize;
    for (i = 0; i < sizeof(sizes) / sizeof(sizes[0]); i++)
      if (sizes[i] == keysize) mod_len = mod_lens[i];
    if (mod_len < 0)
      printf("Key %d -- unknown modulus length\n", p[2] & 0x0F);
    else
      printf("Key %d -- Modulus length %d\n", p[2] & 0x0F, mod_len);
  } while (1);
  return 0;
}

