static void scalar_min_max_lsh(struct bpf_reg_state* dst_reg,
                               struct bpf_reg_state* src_reg) {
  u64 umax_val = src_reg->umax_value;
  u64 umin_val = src_reg->umin_value;
  dst_reg->smin_value = S64_MIN;
  dst_reg->smax_value = S64_MAX;
  if (dst_reg->umax_value > 1ULL << (63 - umax_val)) {
    dst_reg->umin_value = 0;
    dst_reg->umax_value = U64_MAX;
  } else {
    dst_reg->umin_value <<= umin_val;
    dst_reg->umax_value <<= umax_val;
  }
  dst_reg->var_off = tnum_lshift(dst_reg->var_off, umin_val);
  __update_reg_bounds(dst_reg);
}

GF_Err sbgp_box_read(GF_Box* s, GF_BitStream* bs) {
  u32 i;
  GF_SampleGroupBox* ptr = (GF_SampleGroupBox*)s;
  ISOM_DECREASE_SIZE(ptr, 8);
  ptr->grouping_type = gf_bs_read_u32(bs);
  if (ptr->version == 1) {
    ISOM_DECREASE_SIZE(ptr, 4);
    ptr->grouping_type_parameter = gf_bs_read_u32(bs);
  }
  ptr->entry_count = gf_bs_read_u32(bs);
  if (ptr->size < sizeof(GF_SampleGroupEntry) * ptr->entry_count ||
      (u64)ptr->entry_count > (u64)SIZE_MAX / sizeof(GF_SampleGroupEntry))
    return GF_ISOM_INVALID_FILE;
  ptr->sample_entries =
      gf_malloc(sizeof(GF_SampleGroupEntry) * ptr->entry_count);
  if (!ptr->sample_entries) return GF_OUT_OF_MEM;
  for (i = 0; i < ptr->entry_count; i++) {
    ISOM_DECREASE_SIZE(ptr, 8);
    ptr->sample_entries[i].sample_count = gf_bs_read_u32(bs);
    ptr->sample_entries[i].group_description_index = gf_bs_read_u32(bs);
  }
  return GF_OK;
}

void RtmpProtocol::handle_C1_simple(const char* data) {
  char handshake_head = HANDSHAKE_PLAINTEXT;
  onSendRawData(obtainBuffer(&handshake_head, 1));
  RtmpHandshake s1(0);
  onSendRawData(obtainBuffer((char*)&s1, C1_HANDSHARK_SIZE));
  onSendRawData(obtainBuffer(data + 1, C1_HANDSHARK_SIZE));
  _next_step_func = [this](const char* data, size_t len) {
    return handle_C2(data, len);
  };
}

