BGD_DECLARE(int) gdAlphaBlend(int dst, int src) {
  int src_alpha = gdTrueColorGetAlpha(src);
  int dst_alpha, alpha, red, green, blue;
  int src_weight, dst_weight, tot_weight;
  if (src_alpha == gdAlphaOpaque) return src;
  dst_alpha = gdTrueColorGetAlpha(dst);
  if (src_alpha == gdAlphaTransparent) return dst;
  if (dst_alpha == gdAlphaTransparent) return src;
  src_weight = gdAlphaTransparent - src_alpha;
  dst_weight = (gdAlphaTransparent - dst_alpha) * src_alpha / gdAlphaMax;
  tot_weight = src_weight + dst_weight;
  alpha = src_alpha * dst_alpha / gdAlphaMax;
  red = (gdTrueColorGetRed(src) * src_weight +
         gdTrueColorGetRed(dst) * dst_weight) /
        tot_weight;
  green = (gdTrueColorGetGreen(src) * src_weight +
           gdTrueColorGetGreen(dst) * dst_weight) /
          tot_weight;
  blue = (gdTrueColorGetBlue(src) * src_weight +
          gdTrueColorGetBlue(dst) * dst_weight) /
         tot_weight;
  return ((alpha << 24) + (red << 16) + (green << 8) + blue);
}

static int mxf_read_sequence(void* arg, AVIOContext* pb, int tag, int size,
                             UID uid, int64_t klv_offset) {
  MXFSequence* sequence = arg;
  switch (tag) {
    case 0x0202:
      sequence->duration = avio_rb64(pb);
      break;
    case 0x0201:
      avio_read(pb, sequence->data_definition_ul, 16);
      break;
    case 0x4b02:
      sequence->origin = avio_r8(pb);
      break;
    case 0x1001:
      return mxf_read_strong_ref_array(pb,
                                       &sequence->structural_components_refs,
                                       &sequence->structural_components_count);
  }
  return 0;
}

MagickPrivate void ConvertHCLToRGB(const double hue, const double chroma,
                                   const double luma, double* red,
                                   double* green, double* blue) {
  double b, c, g, h, m, r, x;
  assert(red != (double*)NULL);
  assert(green != (double*)NULL);
  assert(blue != (double*)NULL);
  h = 6.0 * hue;
  c = chroma;
  x = c * (1.0 - fabs(fmod(h, 2.0) - 1.0));
  r = 0.0;
  g = 0.0;
  b = 0.0;
  if ((0.0 <= h) && (h < 1.0)) {
    r = c;
    g = x;
  } else if ((1.0 <= h) && (h < 2.0)) {
    r = x;
    g = c;
  } else if ((2.0 <= h) && (h < 3.0)) {
    g = c;
    b = x;
  } else if ((3.0 <= h) && (h < 4.0)) {
    g = x;
    b = c;
  } else if ((4.0 <= h) && (h < 5.0)) {
    r = x;
    b = c;
  } else if ((5.0 <= h) && (h < 6.0)) {
    r = c;
    b = x;
  }
  m = luma - (0.298839 * r + 0.586811 * g + 0.114350 * b);
  *red = QuantumRange * (r + m);
  *green = QuantumRange * (g + m);
  *blue = QuantumRange * (b + m);
}

static int vcpu_mmio_gva_to_gpa(struct kvm_vcpu* vcpu, unsigned long gva,
                                gpa_t* gpa, struct x86_exception* exception,
                                bool write) {
  u32 access = ((kvm_x86_ops->get_cpl(vcpu) == 3) ? PFERR_USER_MASK : 0) |
               (write ? PFERR_WRITE_MASK : 0);
  if (vcpu_match_mmio_gva(vcpu, gva) &&
      !permission_fault(vcpu, vcpu->arch.walk_mmu, vcpu->arch.access, access)) {
    *gpa = vcpu->arch.mmio_gfn << PAGE_SHIFT | (gva & (PAGE_SIZE - 1));
    trace_vcpu_match_mmio(gva, *gpa, write, false);
    return 1;
  }
  *gpa = vcpu->arch.walk_mmu->gva_to_gpa(vcpu, gva, access, exception);
  if (*gpa == UNMAPPED_GVA) return -1;
  if ((*gpa & PAGE_MASK) == APIC_DEFAULT_PHYS_BASE) return 1;
  if (vcpu_match_mmio_gpa(vcpu, *gpa)) {
    trace_vcpu_match_mmio(gva, *gpa, write, true);
    return 1;
  }
  return 0;
}

