static void* lookupOpenGLFunctionAddress(const char* functionName,
                                         bool* success = 0) {
  if (success && !*success) return 0;
  void* target = getProcAddress(functionName);
  if (target) return target;
  String fullFunctionName(functionName);
  fullFunctionName.append("ARB");
  target = getProcAddress(fullFunctionName.utf8().data());
  if (target) return target;
  fullFunctionName = functionName;
  fullFunctionName.append("EXT");
  target = getProcAddress(fullFunctionName.utf8().data());
#if defined(GL_ES_VERSION_2_0)
  fullFunctionName = functionName;
  fullFunctionName.append("ANGLE");
  target = getProcAddress(fullFunctionName.utf8().data());
  if (target) return target;
  fullFunctionName = functionName;
  fullFunctionName.append("APPLE");
  target = getProcAddress(fullFunctionName.utf8().data());
#endif
  if (!target && success) *success = false;
  return target;
}

int CLua::push_args(lua_State* ls, const char* format, va_list args,
                    va_list* targ) {
  if (!format) {
    if (targ) va_copy(*targ, args);
    return 0;
  }
  const char* cs = strchr(format, ':');
  if (cs) format = cs + 1;
  int argc = 0;
  for (const char* run = format; *run; run++) {
    if (*run == '>') break;
    char argtype = *run;
    ++argc;
    switch (argtype) {
      case 'u':
        lua_pushlightuserdata(ls, va_arg(args, void*));
        break;
      case 'i':
        clua_push_item(ls, va_arg(args, item_def*));
        break;
      case 's': {
        const char* s = va_arg(args, const char*);
        if (s)
          lua_pushstring(ls, s);
        else
          lua_pushnil(ls);
        break;
      }
      case 'd':
        lua_pushnumber(ls, va_arg(args, int));
        break;
      case 'L':
        die("ambiguous long in Lua push_args");
        lua_pushnumber(ls, va_arg(args, long));
        break;
      case 'b':
        lua_pushboolean(ls, va_arg(args, int));
        break;
      case 'D':
        clua_push_dgn_event(ls, va_arg(args, const dgn_event*));
        break;
      case 'm':
        clua_push_map(ls, va_arg(args, map_def*));
        break;
      case 'M':
        push_monster(ls, va_arg(args, monster*));
        break;
      case 'I':
        lua_push_moninf(ls, va_arg(args, monster_info*));
        break;
      case 'A':
        argc +=
            push_activity_interrupt(ls, va_arg(args, activity_interrupt_data*));
        break;
      default:
        --argc;
        break;
    }
  }
  if (targ) va_copy(*targ, args);
  return argc;
}

static inline unsigned FNAME(gpte_access)(u64 gpte) {
  unsigned access;
#if PTTYPE == PTTYPE_EPT
  access = ((gpte & VMX_EPT_WRITABLE_MASK) ? ACC_WRITE_MASK : 0) |
           ((gpte & VMX_EPT_EXECUTABLE_MASK) ? ACC_EXEC_MASK : 0) |
           ((gpte & VMX_EPT_READABLE_MASK) ? ACC_USER_MASK : 0);
#else
  BUILD_BUG_ON(ACC_EXEC_MASK != PT_PRESENT_MASK);
  BUILD_BUG_ON(ACC_EXEC_MASK != 1);
  access = gpte & (PT_WRITABLE_MASK | PT_USER_MASK | PT_PRESENT_MASK);
  access ^= (gpte >> PT64_NX_SHIFT);
#endif
  return access;
}

