gpgsm_assuan_simple_command(assuan_context_t ctx, char* cmd,
                            engine_status_handler_t status_fnc,
                            void* status_fnc_value) {
  gpg_error_t err;
  char* line;
  size_t linelen;
  err = assuan_write_line(ctx, cmd);
  if (err) return err;
  do {
    err = assuan_read_line(ctx, &line, &linelen);
    if (err) return err;
    if (*line == '#' || !linelen) continue;
    if (linelen >= 2 && line[0] == 'O' && line[1] == 'K' &&
        (line[2] == '\0' || line[2] == ' '))
      return 0;
    else if (linelen >= 4 && line[0] == 'E' && line[1] == 'R' &&
             line[2] == 'R' && line[3] == ' ')
      err = atoi(&line[4]);
    else if (linelen >= 2 && line[0] == 'S' && line[1] == ' ') {
      char* rest;
      gpgme_status_code_t r;
      rest = strchr(line + 2, ' ');
      if (!rest)
        rest = line + linelen;
      else
        *(rest++) = 0;
      r = _gpgme_parse_status(line + 2);
      if (r >= 0 && status_fnc)
        err = status_fnc(status_fnc_value, r, rest);
      else
        err = gpg_error(GPG_ERR_GENERAL);
    } else
      err = gpg_error(GPG_ERR_GENERAL);
  } while (!err);
  return err;
}

static int io_files_update_with_index_alloc(struct io_kiocb* req,
                                            unsigned int issue_flags) {
  __s32 __user* fds = u64_to_user_ptr(req->rsrc_update.arg);
  unsigned int done;
  struct file* file;
  int ret, fd;
  if (!req->ctx->file_data) return -ENXIO;
  for (done = 0; done < req->rsrc_update.nr_args; done++) {
    if (copy_from_user(&fd, &fds[done], sizeof(fd))) {
      ret = -EFAULT;
      break;
    }
    file = fget(fd);
    if (!file) {
      ret = -EBADF;
      break;
    }
    ret = io_fixed_fd_install(req, issue_flags, file, IORING_FILE_INDEX_ALLOC);
    if (ret < 0) break;
    if (copy_to_user(&fds[done], &ret, sizeof(ret))) {
      __io_close_fixed(req, issue_flags, ret);
      ret = -EFAULT;
      break;
    }
  }
  if (done) return done;
  return ret;

