void btrfs_rm_dev_replace_free_srcdev(struct btrfs_fs_info* fs_info,
                                      struct btrfs_device* srcdev) {
  struct btrfs_fs_devices* fs_devices = srcdev->fs_devices;
  if (test_bit(BTRFS_DEV_STATE_WRITEABLE, &srcdev->dev_state)) {
    btrfs_scratch_superblocks(srcdev->bdev, srcdev->name->str);
  }
  btrfs_close_bdev(srcdev);
  call_rcu(&srcdev->rcu, free_device_rcu);
  if (!fs_devices->num_devices) {
    struct btrfs_fs_devices* tmp_fs_devices;
    ASSERT(fs_devices->seeding);
    tmp_fs_devices = fs_info->fs_devices;
    while (tmp_fs_devices) {
      if (tmp_fs_devices->seed == fs_devices) {
        tmp_fs_devices->seed = fs_devices->seed;
        break;
      }
      tmp_fs_devices = tmp_fs_devices->seed;
    }
    fs_devices->seed = NULL;
    close_fs_devices(fs_devices);
    free_fs_devices(fs_devices);
  }
}

v8::Handle<v8::Value> V8DOMWrapper::convertSVGObjectWithContextToV8Object(
    V8ClassIndex::V8WrapperType type, void* object) {
  if (!object) return v8::Null();
  v8::Persistent<v8::Object> result =
      getDOMSVGObjectWithContextMap().get(object);
  if (!result.IsEmpty()) return result;
  if (type == V8ClassIndex::SVGPATHSEG)
    type = V8Custom::DowncastSVGPathSeg(object);
  v8::Local<v8::Object> v8Object = instantiateV8Object(type, type, object);
  if (!v8Object.IsEmpty()) {
    result = v8::Persistent<v8::Object>::New(v8Object);
    switch (type) {
#define MAKE_CASE(TYPE, NAME)          \
  case V8ClassIndex::TYPE:             \
    static_cast<NAME*>(object)->ref(); \
    break;
      SVG_OBJECT_TYPES(MAKE_CASE)
#undef MAKE_CASE
#define MAKE_CASE(TYPE, NAME)                               \
  case V8ClassIndex::TYPE:                                  \
    static_cast<V8SVGPODTypeWrapper<NAME>*>(object)->ref(); \
    break;
      SVG_POD_NATIVE_TYPES(MAKE_CASE)
#undef MAKE_CASE
      default:
        ASSERT_NOT_REACHED();
    }
    getDOMSVGObjectWithContextMap().set(object, result);
  }
  return result;
}

int vmtruncate_range(struct inode* inode, loff_t offset, loff_t end) {
  struct address_space* mapping = inode->i_mapping;
  if (!inode->i_op || !inode->i_op->truncate_range) return -ENOSYS;
  mutex_lock(&inode->i_mutex);
  down_write(&inode->i_alloc_sem);
  unmap_mapping_range(mapping, offset, (end - offset), 1);
  truncate_inode_pages_range(mapping, offset, end);
  unmap_mapping_range(mapping, offset, (end - offset), 1);
  inode->i_op->truncate_range(inode, offset, end);
  up_write(&inode->i_alloc_sem);
  mutex_unlock(&inode->i_mutex);
  return 0;
}

static void set_fdc(int drive) {
  if (drive >= 0 && drive < N_DRIVE) {
    fdc = FDC(drive);
    current_drive = drive;
  }
  if (fdc != 1 && fdc != 0) {
    pr_info("bad fdc value\n");
    return;
  }
  set_dor(fdc, ~0, 8);
#if N_FDC > 1
  set_dor(1 - fdc, ~8, 0);
#endif
  if (FDCS->rawcmd == 2) reset_fdc_info(1);
  if (fd_inb(FD_STATUS) != STATUS_READY) FDCS->reset = 1;
}

