bool DependencyOptimizer::SafeToRemoveIdentity(const NodeDef& node) const {
  if (!IsIdentity(node) && !IsIdentityN(node)) {
    return true;
  }
  if (nodes_to_preserve_.find(node.name()) != nodes_to_preserve_.end()) {
    return false;
  }
  if (!fetch_nodes_known_) {
    return false;
  }
  if (node.input_size() < 1) {
    return false;
  }
  const NodeDef* input = node_map_->GetNode(NodeName(node.input(0)));
  CHECK(input != nullptr) << "node = " << node.name()
                          << " input = " << node.input(0);
  if (IsVariable(*input) || IsRecv(*input)) {
    return false;
  }
  for (const auto& consumer : node_map_->GetOutputs(node.name())) {
    if (node.input_size() > 1 && (IsRetval(*consumer) || IsMerge(*consumer))) {
      return false;
    }
    if (IsSwitch(*input)) {
      for (const string& consumer_input : consumer->input()) {
        if (consumer_input == AsControlDependency(node.name())) {
          return false;
        }
      }
    }
  }
  return true;
}

rar_br_preparation(struct archive_read* a, struct rar_br* br) {
  struct rar* rar = (struct rar*)(a->format->data);
  if (rar->bytes_remaining > 0) {
    br->next_in = rar_read_ahead(a, 1, &(br->avail_in));
    if (br->next_in == NULL) {
      archive_set_error(&a->archive, ARCHIVE_ERRNO_FILE_FORMAT,
                        "Truncated RAR file data");
      return (ARCHIVE_FATAL);
    }
    if (br->cache_avail == 0) (void)rar_br_fillup(a, br);
  }
  return (ARCHIVE_OK);
}

get_resource_entry(WinLibrary* fi, WinResource* wr, size_t* size) {
  if (fi->is_PE_binary) {
    Win32ImageResourceDataEntry* dataent;
    dataent = (Win32ImageResourceDataEntry*)wr->children;
    RETURN_IF_BAD_POINTER(NULL, *dataent);
    *size = dataent->size;
    RETURN_IF_BAD_OFFSET(NULL, fi->memory + dataent->offset_to_data, *size);
    return fi->memory + dataent->offset_to_data;
  } else {
    Win16NENameInfo* nameinfo;
    int sizeshift;
    nameinfo = (Win16NENameInfo*)wr->children;
    sizeshift = *((uint16_t*)fi->first_resource - 1);
    *size = nameinfo->length << sizeshift;
    RETURN_IF_BAD_OFFSET(NULL, fi->memory + (nameinfo->offset << sizeshift),
                         *size);
    return fi->memory + (nameinfo->offset << sizeshift);
  }
}

dev_t blk_lookup_devt(const char* name, int partno) {
  dev_t devt = MKDEV(0, 0);
  struct class_dev_iter iter;
  struct device* dev;
  class_dev_iter_init(&iter, &block_class, NULL, &disk_type);
  while ((dev = class_dev_iter_next(&iter))) {
    struct gendisk* disk = dev_to_disk(dev);
    struct hd_struct* part;
    if (strcmp(dev_name(dev), name)) continue;
    if (partno < disk->minors) {
      devt = MKDEV(MAJOR(dev->devt), MINOR(dev->devt) + partno);
      break;
    }
    part = disk_get_part(disk, partno);
    if (part) {
      devt = part_devt(part);
      disk_put_part(part);
      break;
    }
    disk_put_part(part);
  }
  class_dev_iter_exit(&iter);
  return devt;
}

