join_read_const(JOIN_TAB* tab) {
  int error;
  TABLE* table = tab->table;
  if (table->status & STATUS_GARBAGE) {
    table->status = 0;
    if (cp_buffer_from_ref(tab->join->thd, table, &tab->ref))
      error = HA_ERR_KEY_NOT_FOUND;
    else {
      error = table->file->ha_index_read_idx_map(
          table->record[0], tab->ref.key, (uchar*)tab->ref.key_buff,
          make_prev_keypart_map(tab->ref.key_parts), HA_READ_KEY_EXACT);
    }
    if (unlikely(error)) {
      table->status = STATUS_NOT_FOUND;
      mark_as_null_row(tab->table);
      empty_record(table);
      if (error != HA_ERR_KEY_NOT_FOUND && error != HA_ERR_END_OF_FILE)
        return report_error(table, error);
      return -1;
    }
    store_record(table, record[1]);
  } else if (!(table->status & ~STATUS_NULL_ROW)) {
    table->status = 0;
    restore_record(table, record[1]);
  }
  table->null_row = 0;
  return table->status ? -1 : 0;
}

int posix_cpu_nsleep(const clockid_t which_clock, int flags,
                     struct timespec* rqtp, struct timespec __user* rmtp) {
  struct restart_block* restart_block = &current_thread_info()->restart_block;
  struct itimerspec it;
  int error;
  if (CPUCLOCK_PERTHREAD(which_clock) &&
      (CPUCLOCK_PID(which_clock) == 0 ||
       CPUCLOCK_PID(which_clock) == current->pid))
    return -EINVAL;
  error = do_cpu_nanosleep(which_clock, flags, rqtp, &it);
  if (error == -ERESTART_RESTARTBLOCK) {
    if (flags & TIMER_ABSTIME) return -ERESTARTNOHAND;
    if (rmtp != NULL && copy_to_user(rmtp, &it.it_value, sizeof *rmtp))
      return -EFAULT;
    restart_block->fn = posix_cpu_nsleep_restart;
    restart_block->arg0 = which_clock;
    restart_block->arg1 = (unsigned long)rmtp;
    restart_block->arg2 = rqtp->tv_sec;
    restart_block->arg3 = rqtp->tv_nsec;
  }
  return error;
}

