xfs_bmap_split_indlen(xfs_filblks_t ores, xfs_filblks_t* indlen1,
                      xfs_filblks_t* indlen2, xfs_filblks_t avail) {
  xfs_filblks_t len1 = *indlen1;
  xfs_filblks_t len2 = *indlen2;
  xfs_filblks_t nres = len1 + len2;
  xfs_filblks_t stolen = 0;
  xfs_filblks_t resfactor;
  if (ores < nres && avail) stolen = XFS_FILBLKS_MIN(nres - ores, avail);
  ores += stolen;
  if (ores >= nres) return stolen;
  resfactor = (ores * 100);
  do_div(resfactor, nres);
  len1 *= resfactor;
  do_div(len1, 100);
  len2 *= resfactor;
  do_div(len2, 100);
  ASSERT(len1 + len2 <= ores);
  ASSERT(len1 < *indlen1 && len2 < *indlen2);
  ores -= (len1 + len2);
  ASSERT((*indlen1 - len1) + (*indlen2 - len2) >= ores);
  if (ores && !len2 && *indlen2) {
    len2++;
    ores--;
  }
  while (ores) {
    if (len1 < *indlen1) {
      len1++;
      ores--;
    }
    if (!ores) break;
    if (len2 < *indlen2) {
      len2++;
      ores--;
    }
  }
  *indlen1 = len1;
  *indlen2 = len2;
  return stolen;
}

int JOIN::optimize() {
  int res = 0;
  create_explain_query_if_not_exists(thd->lex, thd->mem_root);
  join_optimization_state init_state = optimization_state;
  if (select_lex->pushdown_select) {
    if (!(select_options & SELECT_DESCRIBE)) {
      res = select_lex->pushdown_select->init();
    }
    with_two_phase_optimization = false;
  } else if (optimization_state == JOIN::OPTIMIZATION_PHASE_1_DONE)
    res = optimize_stage2();
  else {
    if (optimization_state != JOIN::NOT_OPTIMIZED) return FALSE;
    optimization_state = JOIN::OPTIMIZATION_IN_PROGRESS;
    res = optimize_inner();
  }
  if (!with_two_phase_optimization ||
      init_state == JOIN::OPTIMIZATION_PHASE_1_DONE) {
    if (!res && have_query_plan != QEP_DELETED) res = build_explain();
    optimization_state = JOIN::OPTIMIZATION_DONE;
  }
  return res;
}

int snd_power_wait(struct snd_card* card, unsigned int power_state) {
  wait_queue_t wait;
  int result = 0;
  if (snd_power_get_state(card) == power_state) return 0;
  init_waitqueue_entry(&wait, current);
  add_wait_queue(&card->power_sleep, &wait);
  while (1) {
    if (card->shutdown) {
      result = -ENODEV;
      break;
    }
    if (snd_power_get_state(card) == power_state) break;
    set_current_state(TASK_UNINTERRUPTIBLE);
    snd_power_unlock(card);
    schedule_timeout(30 * HZ);
    snd_power_lock(card);
  }
  remove_wait_queue(&card->power_sleep, &wait);
  return result;
}

static int read_request_line(struct conn_s* connptr) {
  ssize_t len;
retry:
  len = readline(connptr->client_fd, &connptr->request_line);
  if (len <= 0) {
    log_message(LOG_ERR,
                "read_request_line: Client (file descriptor: %d) "
                "closed socket before read.",
                connptr->client_fd);
    return -1;
  }
  if (chomp(connptr->request_line, len) == len) {
    safefree(connptr->request_line);
    goto retry;
  }
  log_message(LOG_CONN, "Request (file descriptor %d): %s", connptr->client_fd,
              connptr->request_line);
  return 0;
}

