mbc_case_fold(OnigCaseFoldType flag, const UChar** pp,
              const UChar* end ARG_UNUSED, UChar* lower,
              OnigEncoding enc ARG_UNUSED) {
  const UChar* p = *pp;
  if (*p == 0xdf && (flag & INTERNAL_ONIGENC_CASE_FOLD_MULTI_CHAR) != 0) {
    *lower++ = 's';
    *lower = 's';
