static int protocol_version(VncState* vs, uint8_t* version, size_t len) {
  char local[13];
  memcpy(local, version, 12);
  local[12] = 0;
  if (sscanf(local, "RFB %03d.%03d\n", &vs->major, &vs->minor) != 2) {
    VNC_DEBUG("Malformed protocol version %s\n", local);
    vnc_client_error(vs);
    return 0;
  }
  VNC_DEBUG("Client request protocol version %d.%d\n", vs->major, vs->minor);
  if (vs->major != 3 || (vs->minor != 3 && vs->minor != 4 && vs->minor != 5 &&
                         vs->minor != 7 && vs->minor != 8)) {
    VNC_DEBUG("Unsupported client version\n");
    vnc_write_u32(vs, VNC_AUTH_INVALID);
    vnc_flush(vs);
    vnc_client_error(vs);
    return 0;
  }
  if (vs->minor == 4 || vs->minor == 5) vs->minor = 3;
  if (vs->minor == 3) {
    trace_vnc_auth_start(vs, vs->auth);
    if (vs->auth == VNC_AUTH_NONE) {
      vnc_write_u32(vs, vs->auth);
      vnc_flush(vs);
      trace_vnc_auth_pass(vs, vs->auth);
      start_client_init(vs);
    } else if (vs->auth == VNC_AUTH_VNC) {
      VNC_DEBUG("Tell client VNC auth\n");
      vnc_write_u32(vs, vs->auth);
      vnc_flush(vs);
      start_auth_vnc(vs);
    } else {
      trace_vnc_auth_fail(vs, vs->auth, "Unsupported auth method for v3.3", "");
      vnc_write_u32(vs, VNC_AUTH_INVALID);
      vnc_flush(vs);
      vnc_client_error(vs);
    }
  } else {
    vnc_write_u8(vs, 1);
    vnc_write_u8(vs, vs->auth);
    vnc_read_when(vs, protocol_client_auth, 1);
    vnc_flush(vs);
  }
  return 0;
}

static int serialize_data(struct usbredirparser_priv* parser, uint8_t** state,
                          uint8_t** pos, uint32_t* remain, uint8_t* data,
                          uint32_t len, const char* desc) {
  DEBUG("serializing %d bytes of %s data", len, desc);
  if (len >= 8)
    DEBUG("First 8 bytes of %s: %02x %02x %02x %02x %02x %02x %02x %02x", desc,
          data[0], data[1], data[2], data[3], data[4], data[5], data[6],
          data[7]);
  if (serialize_alloc(parser, state, pos, remain, sizeof(uint32_t) + len))
    return -1;
  memcpy(*pos, &len, sizeof(uint32_t));
  *pos += sizeof(uint32_t);
  *remain -= sizeof(uint32_t);
  memcpy(*pos, data, len);
  *pos += len;
  *remain -= len;
  return 0;
}

static int check_is_mount_child(void* p) {
  const char** a = p;
  const char* last = a[0];
  const char* mnt = a[1];
  int res;
  const char* procmounts = "/proc/mounts";
  int found;
  FILE* fp;
  struct mntent* entp;
  int count;
  res = mount("", "/", "", MS_PRIVATE | MS_REC, NULL);
  if (res == -1) {
    fprintf(stderr, "%s: failed to mark mounts private: %s\n", progname,
            strerror(errno));
    return 1;
  }
  fp = setmntent(procmounts, "r");
  if (fp == NULL) {
    fprintf(stderr, "%s: failed to open %s: %s\n", progname, procmounts,
            strerror(errno));
    return 1;
  }
  count = 0;
  while (getmntent(fp) != NULL) count++;
  endmntent(fp);
  fp = setmntent(procmounts, "r");
  if (fp == NULL) {
    fprintf(stderr, "%s: failed to open %s: %s\n", progname, procmounts,
            strerror(errno));
    return 1;
  }
  res = mount(".", "/", "", MS_BIND | MS_REC, NULL);
  if (res == -1) {
    fprintf(stderr, "%s: failed to bind parent to /: %s\n", progname,
            strerror(errno));
    return 1;
  }
  found = 0;
  while ((entp = getmntent(fp)) != NULL) {
    if (count > 0) {
      count--;
      continue;
    }
    if (entp->mnt_dir[0] == '/' && strcmp(entp->mnt_dir + 1, last) == 0) {
      found = 1;
      break;
    }
  }
  endmntent(fp);
  if (!found) {
    fprintf(stderr, "%s: %s not mounted\n", progname, mnt);
    return 1;
  }
  return 0;
}

