                              size_t dname_len, uint16_t tp, uint16_t cl,
                              uint32_t ttl, int question) {
  if (question) {
    if (dname_len + 4 > len)
      return RET_ERR(LDNS_WIREPARSE_ERR_BUFFER_TOO_SMALL,
                     sldns_buffer_position(strbuf));
    sldns_write_uint16(rr + dname_len, tp);
