  sldns_write_uint16(rr + dname_len + 2, cl);
  sldns_write_uint32(rr + dname_len + 4, ttl);
  sldns_write_uint16(rr + dname_len + 8, 0);
  return LDNS_WIREPARSE_ERR_OK;
}

