}

static int addrconf_ifid_eui48(u8* eui, struct net_device* dev) {
  if (dev->addr_len != ETH_ALEN) return -1;
  memcpy(eui, dev->dev_addr, 3);
  memcpy(eui + 5, dev->dev_addr + 3, 3);
  if (dev->dev_id) {
    eui[3] = (dev->dev_id >> 8) & 0xFF;
    eui[4] = dev->dev_id & 0xFF;
  } else {
    eui[3] = 0xFF;
    eui[4] = 0xFE;
    eui[0] ^= 2;
  }
  return 0;
}

zmakewordimagedevice(i_ctx_t* i_ctx_p) {
  os_ptr op = osp;
  os_ptr op1 = op - 1;
  gs_matrix imat;
  gx_device* new_dev;
  const byte* colors;
  int colors_size;
  int code;
  check_int_leu(op[-3], max_uint >> 1);
  check_int_leu(op[-2], max_uint >> 1);
  check_type(*op, t_boolean);
  if (r_has_type(op1, t_null)) {
    colors = 0;
    colors_size = -24;
  } else if (r_has_type(op1, t_integer)) {
    if (op1->value.intval != 16 && op1->value.intval != 24 &&
        op1->value.intval != 32)
      return_error(gs_error_rangecheck);
    colors = 0;
    colors_size = -op1->value.intval;
  } else {
    check_type(*op1, t_string);
    if (r_size(op1) > 3 * 256) return_error(gs_error_rangecheck);
    colors = op1->value.bytes;
    colors_size = r_size(op1);
  }
  if ((code = read_matrix(imemory, op - 4, &imat)) < 0) return code;
  code = gs_makewordimagedevice(&new_dev, &imat, (int)op[-3].value.intval,
                                (int)op[-2].value.intval, colors, colors_size,
                                op->value.boolval, true, imemory);
  if (code == 0) {
    new_dev->memory = imemory;
    make_tav(op - 4, t_device, imemory_space(iimemory) | a_all, pdevice,
             new_dev);
    pop(4);
  }
  return code;
}

void FrameLoader::updateForSameDocumentNavigation(
    const KURL& newURL,
    SameDocumentNavigationSource sameDocumentNavigationSource,
    PassRefPtr<SerializedScriptValue> data, const String& title,
    UpdateBackForwardListPolicy updateBackForwardList) {
  KURL oldURL = m_frame->document()->url();
  m_frame->document()->setURL(newURL);
  setOutgoingReferrer(newURL);
  documentLoader()->replaceRequestURLForSameDocumentNavigation(newURL);
  if (updateBackForwardList == UpdateBackForwardList)
    history()->updateBackForwardListForFragmentScroll();
  if (sameDocumentNavigationSource == SameDocumentNavigationDefault)
    history()->updateForSameDocumentNavigation();
  else if (sameDocumentNavigationSource == SameDocumentNavigationPushState)
    history()->pushState(data, title, newURL.string());
  else if (sameDocumentNavigationSource == SameDocumentNavigationReplaceState)
    history()->replaceState(data, title, newURL.string());
  else
    ASSERT_NOT_REACHED();
  if (m_frame->document()->loadEventFinished())
    m_client->postProgressStartedNotification();
  m_documentLoader->clearRedirectChain();
  if (m_documentLoader->isClientRedirect())
    m_documentLoader->appendRedirect(oldURL);
  m_documentLoader->appendRedirect(newURL);
  m_client->dispatchDidNavigateWithinPage();
  m_client->dispatchDidReceiveTitle(m_frame->document()->title());
  if (m_frame->document()->loadEventFinished())
    m_client->postProgressFinishedNotification();
}

static void clearSelect(sqlite3* db, Select* p, int bFree) {
  while (p) {
    Select* pPrior = p->pPrior;
    sqlite3ExprListDelete(db, p->pEList);
    sqlite3SrcListDelete(db, p->pSrc);
    sqlite3ExprDelete(db, p->pWhere);
    sqlite3ExprListDelete(db, p->pGroupBy);
    sqlite3ExprDelete(db, p->pHaving);
    sqlite3ExprListDelete(db, p->pOrderBy);
    sqlite3ExprDelete(db, p->pLimit);
#ifndef SQLITE_OMIT_WINDOWFUNC
    if (OK_IF_ALWAYS_TRUE(p->pWinDefn)) {
      sqlite3WindowListDelete(db, p->pWinDefn);
    }
#endif
    if (OK_IF_ALWAYS_TRUE(p->pWith)) sqlite3WithDelete(db, p->pWith);
    if (bFree) sqlite3DbFreeNN(db, p);
    p = pPrior;
    bFree = 1;
  }
}

