static bool nested_vmx_exit_handled_msr(struct kvm_vcpu* vcpu,
                                        struct vmcs12* vmcs12,
                                        u32 exit_reason) {
  u32 msr_index = vcpu->arch.regs[VCPU_REGS_RCX];
  gpa_t bitmap;
  if (!nested_cpu_has(vmcs12, CPU_BASED_USE_MSR_BITMAPS)) return 1;
  bitmap = vmcs12->msr_bitmap;
  if (exit_reason == EXIT_REASON_MSR_WRITE) bitmap += 2048;
  if (msr_index >= 0xc0000000) {
    msr_index -= 0xc0000000;
    bitmap += 1024;
  }
  if (msr_index < 1024 * 8) {
    unsigned char b;
    if (kvm_read_guest(vcpu->kvm, bitmap + msr_index / 8, &b, 1)) return 1;
    return 1 & (b >> (msr_index & 7));
  } else
    return 1;
}

