void RenderWidgetHostImpl::CompositorFrameDrawn(
    const std::vector<ui::LatencyInfo>& latency_info) {
  for (size_t i = 0; i < latency_info.size(); i++) {
    std::set<RenderWidgetHostImpl*> rwhi_set;
    for (const auto& lc : latency_info[i].latency_components()) {
      if (lc.first.first == ui::INPUT_EVENT_LATENCY_BEGIN_RWH_COMPONENT ||
          lc.first.first == ui::WINDOW_SNAPSHOT_FRAME_NUMBER_COMPONENT ||
          lc.first.first == ui::TAB_SHOW_COMPONENT) {
        int routing_id = lc.first.second & 0xffffffff;
        int process_id = (lc.first.second >> 32) & 0xffffffff;
        RenderWidgetHost* rwh =
            RenderWidgetHost::FromID(process_id, routing_id);
        if (!rwh) {
          continue;
        }
        RenderWidgetHostImpl* rwhi = RenderWidgetHostImpl::From(rwh);
        if (rwhi_set.insert(rwhi).second) rwhi->FrameSwapped(latency_info[i]);
      }
    }
  }
}

png_crc_finish(png_structp png_ptr, png_uint_32 skip) {
  png_size_t i;
  png_size_t istop = png_ptr->zbuf_size;
  for (i = (png_size_t)skip; i > istop; i -= istop) {
    png_crc_read(png_ptr, png_ptr->zbuf, png_ptr->zbuf_size);
  }
  if (i) {
    png_crc_read(png_ptr, png_ptr->zbuf, i);
  }
  if (png_crc_error(png_ptr)) {
    if (((png_ptr->chunk_name[0] & 0x20) &&
         !(png_ptr->flags & PNG_FLAG_CRC_ANCILLARY_NOWARN)) ||
        (!(png_ptr->chunk_name[0] & 0x20) &&
         (png_ptr->flags & PNG_FLAG_CRC_CRITICAL_USE))) {
      png_chunk_warning(png_ptr, "CRC error");
    } else {
      png_chunk_error(png_ptr, "CRC error");
    }
    return (1);
  }
  return (0);
}

static int chunk_drange_filter(struct extent_buffer* leaf,
                               struct btrfs_chunk* chunk,
                               struct btrfs_balance_args* bargs) {
  struct btrfs_stripe* stripe;
  int num_stripes = btrfs_chunk_num_stripes(leaf, chunk);
  u64 stripe_offset;
  u64 stripe_length;
  int factor;
  int i;
  if (!(bargs->flags & BTRFS_BALANCE_ARGS_DEVID)) return 0;
  if (btrfs_chunk_type(leaf, chunk) &
      (BTRFS_BLOCK_GROUP_DUP | BTRFS_BLOCK_GROUP_RAID1 |
       BTRFS_BLOCK_GROUP_RAID10)) {
    factor = num_stripes / 2;
  } else if (btrfs_chunk_type(leaf, chunk) & BTRFS_BLOCK_GROUP_RAID5) {
    factor = num_stripes - 1;
  } else if (btrfs_chunk_type(leaf, chunk) & BTRFS_BLOCK_GROUP_RAID6) {
    factor = num_stripes - 2;
  } else {
    factor = num_stripes;
  }
  for (i = 0; i < num_stripes; i++) {
    stripe = btrfs_stripe_nr(chunk, i);
    if (btrfs_stripe_devid(leaf, stripe) != bargs->devid) continue;
    stripe_offset = btrfs_stripe_offset(leaf, stripe);
    stripe_length = btrfs_chunk_length(leaf, chunk);
    stripe_length = div_u64(stripe_length, factor);
    if (stripe_offset < bargs->pend &&
        stripe_offset + stripe_length > bargs->pstart)
      return 0;
  }
  return 1;
}

COMPAT_SYSCALL_DEFINE3(sched_getaffinity, compat_pid_t, pid, unsigned int, len,
                       compat_ulong_t __user*, user_mask_ptr) {
  int ret;
  cpumask_var_t mask;
  if ((len * BITS_PER_BYTE) < nr_cpu_ids) return -EINVAL;
  if (len & (sizeof(compat_ulong_t) - 1)) return -EINVAL;
  if (!alloc_cpumask_var(&mask, GFP_KERNEL)) return -ENOMEM;
  ret = sched_getaffinity(pid, mask);
  if (ret == 0) {
    size_t retlen = min_t(size_t, len, cpumask_size());
    if (compat_put_bitmap(user_mask_ptr, cpumask_bits(mask), retlen * 8))
      ret = -EFAULT;
    else
      ret = retlen;
  }
  free_cpumask_var(mask);
  return ret;
}

