acpi_status acpi_os_read_port(acpi_io_address port, u32* value, u32 width) {
  u32 dummy;
  if (!value) value = &dummy;
  *value = 0;
  if (width <= 8) {
    *(u8*)value = inb(port);
  } else if (width <= 16) {
    *(u16*)value = inw(port);
  } else if (width <= 32) {
    *(u32*)value = inl(port);
  } else {
    BUG();
  }
  return AE_OK;
}

