get_possible_sybil_list(const smartlist_t* routers) {
  const or_options_t* options = get_options();
  digestmap_t* omit_as_sybil;
  smartlist_t* routers_by_ip = smartlist_new();
  uint32_t last_addr;
  int addr_count;
  int max_with_same_addr = options->AuthDirMaxServersPerAddr;
  int max_with_same_addr_on_authority = options->AuthDirMaxServersPerAuthAddr;
  if (max_with_same_addr <= 0) max_with_same_addr = INT_MAX;
  if (max_with_same_addr_on_authority <= 0)
    max_with_same_addr_on_authority = INT_MAX;
  smartlist_add_all(routers_by_ip, routers);
  smartlist_sort(routers_by_ip, compare_routerinfo_by_ip_and_bw_);
  omit_as_sybil = digestmap_new();
  last_addr = 0;
  addr_count = 0;
  SMARTLIST_FOREACH_BEGIN(routers_by_ip, routerinfo_t*, ri) {
    if (last_addr != ri->addr) {
      last_addr = ri->addr;
      addr_count = 1;
    } else if (++addr_count > max_with_same_addr) {
      if (!router_addr_is_trusted_dir(ri->addr) ||
          addr_count > max_with_same_addr_on_authority)
        digestmap_set(omit_as_sybil, ri->cache_info.identity_digest, ri);
    }
  }
  SMARTLIST_FOREACH_END(ri);
  smartlist_free(routers_by_ip);
  return omit_as_sybil;
}

st_lookup(st_table* table, register st_data_t key, st_data_t* value) {
  st_index_t hash_val, bin_pos;
  register st_table_entry* ptr;
  if (table->entries_packed) {
    st_index_t i;
    for (i = 0; i < table->num_entries; i++) {
      if ((st_data_t)table->bins[i * 2] == key) {
        if (value != 0) *value = (st_data_t)table->bins[i * 2 + 1];
        return 1;
      }
    }
    return 0;
  }
  hash_val = do_hash(key, table);
  FIND_ENTRY(table, ptr, hash_val, bin_pos);
  if (ptr == 0) {
    return 0;
  } else {
    if (value != 0) *value = ptr->record;
    return 1;
  }
}

bool extend_table_list(THD* thd, TABLE_LIST* tables,
                       Prelocking_strategy* prelocking_strategy,
                       bool has_prelocking_list) {
  bool error = false;
  LEX* lex = thd->lex;
  if (thd->locked_tables_mode <= LTM_LOCK_TABLES && !has_prelocking_list &&
      tables->updating && tables->lock_type >= TL_WRITE_ALLOW_WRITE) {
    bool need_prelocking = FALSE;
    TABLE_LIST** save_query_tables_last = lex->query_tables_last;
    error =
        prelocking_strategy->handle_table(thd, lex, tables, &need_prelocking);
    if (need_prelocking && !lex->requires_prelocking())
      lex->mark_as_requiring_prelocking(save_query_tables_last);
  }
  return error;
}

static void __free_slab(struct kmem_cache* s, struct page* page) {
  int order = compound_order(page);
  int pages = 1 << order;
  if (unlikely(SlabDebug(page))) {
    void* p;
    slab_pad_check(s, page);
    for_each_object(p, s, page_address(page), page->objects)
        check_object(s, page, p, 0);
    ClearSlabDebug(page);
  }
  mod_zone_page_state(page_zone(page),
                      (s->flags & SLAB_RECLAIM_ACCOUNT) ? NR_SLAB_RECLAIMABLE
                                                        : NR_SLAB_UNRECLAIMABLE,
                      -pages);
  __ClearPageSlab(page);
  reset_page_mapcount(page);
  __free_pages(page, order);
}

