void migration_entry_wait(struct mm_struct* mm, pmd_t* pmd,
                          unsigned long address) {
  pte_t *ptep, pte;
  spinlock_t* ptl;
  swp_entry_t entry;
  struct page* page;
  ptep = pte_offset_map_lock(mm, pmd, address, &ptl);
  pte = *ptep;
  if (!is_swap_pte(pte)) goto out;
  entry = pte_to_swp_entry(pte);
  if (!is_migration_entry(entry)) goto out;
  page = migration_entry_to_page(entry);
  get_page(page);
  pte_unmap_unlock(ptep, ptl);
  wait_on_page_locked(page);
  put_page(page);
  return;
out:
  pte_unmap_unlock(ptep, ptl);
}

void HTMLMediaElement::UpdatePlayState() {
  bool is_playing = GetWebMediaPlayer() && !GetWebMediaPlayer()->Paused();
  bool should_be_playing = PotentiallyPlaying();
  BLINK_MEDIA_LOG << "updatePlayState(" << (void*)this
                  << ") - shouldBePlaying = " << BoolString(should_be_playing)
                  << ", isPlaying = " << BoolString(is_playing);
  if (should_be_playing && !muted_) was_always_muted_ = false;
  if (should_be_playing) {
    SetDisplayMode(kVideo);
    if (!is_playing) {
      GetWebMediaPlayer()->SetRate(playbackRate());
      GetWebMediaPlayer()->SetVolume(EffectiveMediaVolume());
      GetWebMediaPlayer()->Play();
    }
    StartPlaybackProgressTimer();
    playing_ = true;
  } else {
    if (is_playing) {
      GetWebMediaPlayer()->Pause();
    }
    playback_progress_timer_.Stop();
    playing_ = false;
    double time = currentTime();
    if (time > last_seek_time_) AddPlayedRange(last_seek_time_, time);
  }
  if (GetLayoutObject()) GetLayoutObject()->UpdateFromElement();
}

static int vnc_refresh_lossy_rect(VncDisplay* vd, int x, int y) {
  VncState* vs;
  int sty = y / VNC_STAT_RECT;
  int stx = x / VNC_STAT_RECT;
  int has_dirty = 0;
  y = QEMU_ALIGN_DOWN(y, VNC_STAT_RECT);
  x = QEMU_ALIGN_DOWN(x, VNC_STAT_RECT);
  QTAILQ_FOREACH(vs, &vd->clients, next) {
    int j;
    if (vs->output.offset) {
      continue;
    }
    if (!vs->lossy_rect[sty][stx]) {
      continue;
    }
    vs->lossy_rect[sty][stx] = 0;
    for (j = 0; j < VNC_STAT_RECT; ++j) {
      bitmap_set(vs->dirty[y + j], x / VNC_DIRTY_PIXELS_PER_BIT,
                 VNC_STAT_RECT / VNC_DIRTY_PIXELS_PER_BIT);
    }
    has_dirty++;
  }
  return has_dirty;
}

evaluate_null_complemented_join_record(JOIN* join, JOIN_TAB* join_tab) {
  JOIN_TAB* last_inner_tab = join_tab->last_inner;
  COND* select_cond;
  for (; join_tab <= last_inner_tab; join_tab++) {
    join_tab->found = 1;
    join_tab->not_null_compl = 0;
    restore_record(join_tab->table, s->default_values);
    mark_as_null_row(join_tab->table);
    select_cond = join_tab->select_cond;
    if (select_cond && !select_cond->val_int()) return NESTED_LOOP_OK;
  }
  join_tab--;
  for (;;) {
    JOIN_TAB* first_unmatched = join_tab->first_unmatched;
    if ((first_unmatched = first_unmatched->first_upper) &&
        first_unmatched->last_inner != join_tab)
      first_unmatched = 0;
    join_tab->first_unmatched = first_unmatched;
    if (!first_unmatched) break;
    first_unmatched->found = 1;
    for (JOIN_TAB* tab = first_unmatched; tab <= join_tab; tab++) {
      if (tab->select_cond && !tab->select_cond->val_int()) {
        join->return_tab = tab;
        return NESTED_LOOP_OK;
      }
    }
  }
  if (join_tab->check_weed_out_table) {
    int res = join_tab->check_weed_out_table->sj_weedout_check_row(join->thd);
    if (res == -1)
      return NESTED_LOOP_ERROR;
    else if (res == 1)
      return NESTED_LOOP_OK;
  } else if (join_tab->do_firstmatch) {
    if (join_tab->do_firstmatch < join->return_tab)
      join->return_tab = join_tab->do_firstmatch;
  }
  return (*join_tab->next_select)(join, join_tab + 1, 0);
}

static int sg_check_file_access(struct file* filp, const char* caller) {
  if (filp->f_cred != current_real_cred()) {
    pr_err_once(
        "%s: process %d (%s) changed security contexts after opening file "
        "descriptor, this is not allowed.\n",
        caller, task_tgid_vnr(current), current->comm);
    return -EPERM;
  }
  if (uaccess_kernel()) {
    pr_err_once(
        "%s: process %d (%s) called from kernel context, this is not "
        "allowed.\n",
        caller, task_tgid_vnr(current), current->comm);
    return -EACCES;
  }
  return 0;
}

