static Token** count_mmac_params(Token* tline, int* nparamp, Token*** paramsp) {
  int paramsize;
  int nparam = 0;
  Token* t;
  Token **comma = NULL, **maybe_comma = NULL;
  Token** params;
  paramsize = PARAM_DELTA;
  nasm_newn(params, paramsize);
  t = skip_white(tline);
  if (t) {
    while (true) {
      if (unlikely(nparam + 2 >= paramsize)) {
        paramsize += PARAM_DELTA;
        params = nasm_realloc(params, sizeof(*params) * paramsize);
      }
      params[++nparam] = t;
      if (tok_is(t, '{')) {
        int brace = 1;
        comma = NULL;
        while (brace && (t = t->next)) {
          brace += tok_is(t, '{');
          brace -= tok_is(t, '}');
        }
        if (t) {
          t = skip_white(t->next);
          if (tok_isnt(t, ','))
            nasm_nonfatal("braces do not enclose all of macro parameter");
        } else {
          nasm_nonfatal("expecting closing brace in macro parameter");
        }
      }
      maybe_comma = &t->next;
      while (tok_isnt(t, ',')) {
        if (!tok_white(t)) comma = NULL;
        maybe_comma = &t->next;
        t = t->next;
      }
      if (!t) break;
      comma = maybe_comma;
      t = skip_white(t->next);
    }
  }
  params[nparam + 1] = NULL;
  *paramsp = params;
  *nparamp = nparam;
  return comma;
}

int RGWHandler_REST_S3Website::retarget(RGWOp* op, RGWOp** new_op) {
  *new_op = op;
  ldout(s->cct, 10) << __func__ << " Starting retarget" << dendl;
  if (!(s->prot_flags & RGW_REST_WEBSITE)) return 0;
  int ret =
      store->get_bucket_info(*s->sysobj_ctx, s->bucket_tenant, s->bucket_name,
                             s->bucket_info, NULL, &s->bucket_attrs);
  if (ret < 0) {
    return -ERR_NO_SUCH_BUCKET;
  }
  if (!s->bucket_info.has_website) {
    return -ERR_NO_SUCH_WEBSITE_CONFIGURATION;
  }
  rgw_obj_key new_obj;
  bool get_res = s->bucket_info.website_conf.get_effective_key(
      s->object.name, &new_obj.name, web_dir());
  if (!get_res) {
    s->err.message =
        "The IndexDocument Suffix is not configurated or not well formed!";
    ldout(s->cct, 5) << s->err.message << dendl;
    return -EINVAL;
  }
  ldout(s->cct, 10) << "retarget get_effective_key " << s->object << " -> "
                    << new_obj << dendl;
  RGWBWRoutingRule rrule;
  bool should_redirect =
      s->bucket_info.website_conf.should_redirect(new_obj.name, 0, &rrule);
  if (should_redirect) {
    const string& hostname = s->info.env->get("HTTP_HOST", "");
    const string& protocol =
        (s->info.env->get("SERVER_PORT_SECURE") ? "https" : "http");
    int redirect_code = 0;
    rrule.apply_rule(protocol, hostname, s->object.name, &s->redirect,
                     &redirect_code);
    if (redirect_code > 0) s->err.http_ret = redirect_code;
    ldout(s->cct, 10) << "retarget redirect code=" << redirect_code
                      << " proto+host:" << protocol << ":
                      << " -> " << s->redirect << dendl;
    return -ERR_WEBSITE_REDIRECT;
  }
  s->object = new_obj;
  return 0;
}

