juniper_mlppp_print(netdissect_options* ndo, const struct pcap_pkthdr* h,
                    register const u_char* p) {
  struct juniper_l2info_t l2info;
  l2info.pictype = DLT_JUNIPER_MLPPP;
  if (juniper_parse_header(ndo, p, h, &l2info) == 0) return l2info.header_len;
  if (ndo->ndo_eflag && EXTRACT_16BITS(&l2info.cookie) != PPP_OSI &&
      EXTRACT_16BITS(&l2info.cookie) != (PPP_ADDRESS << 8 | PPP_CONTROL))
    ND_PRINT((ndo, "Bundle-ID %u: ", l2info.bundle));
  p += l2info.header_len;
  switch (l2info.proto) {
    case JUNIPER_LSQ_L3_PROTO_IPV4:
      if (l2info.cookie[4] == (JUNIPER_LSQ_COOKIE_RE | JUNIPER_LSQ_COOKIE_DIR))
        ppp_print(ndo, p, l2info.length);
      else
        ip_print(ndo, p, l2info.length);
      return l2info.header_len;
    case JUNIPER_LSQ_L3_PROTO_IPV6:
      ip6_print(ndo, p, l2info.length);
      return l2info.header_len;
    case JUNIPER_LSQ_L3_PROTO_MPLS:
      mpls_print(ndo, p, l2info.length);
      return l2info.header_len;
    case JUNIPER_LSQ_L3_PROTO_ISO:
      isoclns_print(ndo, p, l2info.length);
      return l2info.header_len;
    default:
      break;
  }
  switch (EXTRACT_16BITS(&l2info.cookie)) {
    case PPP_OSI:
      ppp_print(ndo, p - 2, l2info.length + 2);
      break;
    case (PPP_ADDRESS << 8 | PPP_CONTROL):
    default:
      ppp_print(ndo, p, l2info.length);
      break;
  }
  return l2info.header_len;
}

static int32_t virtio_net_rsc_handle_ack(VirtioNetRscChain* chain,
                                         VirtioNetRscSeg* seg,
                                         const uint8_t* buf,
                                         struct tcp_header* n_tcp,
                                         struct tcp_header* o_tcp) {
  uint32_t nack, oack;
  uint16_t nwin, owin;
  nack = htonl(n_tcp->th_ack);
  nwin = htons(n_tcp->th_win);
  oack = htonl(o_tcp->th_ack);
  owin = htons(o_tcp->th_win);
  if ((nack - oack) >= VIRTIO_NET_MAX_TCP_PAYLOAD) {
    chain->stat.ack_out_of_win++;
    return RSC_FINAL;
  } else if (nack == oack) {
    if (nwin == owin) {
      chain->stat.dup_ack++;
      return RSC_FINAL;
    } else {
      o_tcp->th_win = n_tcp->th_win;
      chain->stat.win_update++;
      return RSC_COALESCE;
    }
  } else {
    chain->stat.pure_ack++;
    return RSC_FINAL;
  }
}

