static void fill_prstatus(struct elf_prstatus* prstatus, struct task_struct* p,
                          long signr) {
  prstatus->pr_info.si_signo = prstatus->pr_cursig = signr;
  prstatus->pr_sigpend = p->pending.signal.sig[0];
  prstatus->pr_sighold = p->blocked.sig[0];
  rcu_read_lock();
  prstatus->pr_ppid = task_pid_vnr(rcu_dereference(p->real_parent));
  rcu_read_unlock();
  prstatus->pr_pid = task_pid_vnr(p);
  prstatus->pr_pgrp = task_pgrp_vnr(p);
  prstatus->pr_sid = task_session_vnr(p);
  if (thread_group_leader(p)) {
    struct task_cputime cputime;
    thread_group_cputime(p, &cputime);
    prstatus->pr_utime = ns_to_timeval(cputime.utime);
    prstatus->pr_stime = ns_to_timeval(cputime.stime);
  } else {
    u64 utime, stime;
    task_cputime(p, &utime, &stime);
    prstatus->pr_utime = ns_to_timeval(utime);
    prstatus->pr_stime = ns_to_timeval(stime);
  }
  prstatus->pr_cutime = ns_to_timeval(p->signal->cutime);
  prstatus->pr_cstime = ns_to_timeval(p->signal->cstime);
}

irc_server_get_isupport_value(struct t_irc_server* server,
                              const char* feature) {
  char feature2[64], *pos_feature, *pos_equal, *pos_space;
  int length;
  static char value[256];
  if (!server || !server->isupport || !feature) return NULL;
  snprintf(feature2, sizeof(feature2), " %s=", feature);
  pos_feature = strstr(server->isupport, feature2);
  if (pos_feature) {
    pos_feature++;
    pos_equal = strchr(pos_feature, '=');
    pos_space = strchr(pos_feature, ' ');
    if (pos_space)
      length = pos_space - pos_equal - 1;
    else
      length = strlen(pos_equal) + 1;
    if (length > (int)sizeof(value) - 1) length = (int)sizeof(value) - 1;
    memcpy(value, pos_equal + 1, length);
    value[length] = '\0';
    return value;
  }
  feature2[strlen(feature2) - 1] = ' ';
  pos_feature = strstr(server->isupport, feature2);
  if (pos_feature) {
    value[0] = '\0';
    return value;
  }
  return NULL;
}

my_bool mysql_rm_tmp_tables(void) {
  uint i, idx;
  char filePath[FN_REFLEN], *tmpdir, filePathCopy[FN_REFLEN];
  MY_DIR* dirp;
  FILEINFO* file;
  TABLE_SHARE share;
  THD* thd;
  DBUG_ENTER("mysql_rm_tmp_tables");
  if (!(thd = new THD(0))) DBUG_RETURN(1);
  thd->thread_stack = (char*)&thd;
  thd->store_globals();
  for (i = 0; i <= mysql_tmpdir_list.max; i++) {
    tmpdir = mysql_tmpdir_list.list[i];
    if (!(dirp = my_dir(tmpdir, MYF(MY_WME | MY_DONT_SORT)))) continue;
    for (idx = 0; idx < (uint)dirp->number_of_files; idx++) {
      file = dirp->dir_entry + idx;
      if (!strncmp(file->name, tmp_file_prefix, tmp_file_prefix_length)) {
        char* ext = fn_ext(file->name);
        uint ext_len = strlen(ext);
        uint filePath_len = my_snprintf(filePath, sizeof(filePath), "%s%c%s",
                                        tmpdir, FN_LIBCHAR, file->name);
        if (!strcmp(reg_ext, ext)) {
          handler* handler_file = 0;
          memcpy(filePathCopy, filePath, filePath_len - ext_len);
          filePathCopy[filePath_len - ext_len] = 0;
          init_tmp_table_share(thd, &share, "", 0, "", filePathCopy);
          if (!open_table_def(thd, &share) &&
              ((handler_file =
                    get_new_handler(&share, thd->mem_root, share.db_type())))) {
            handler_file->ha_delete_table(filePathCopy);
            delete handler_file;
          }
          free_table_share(&share);
        }
        (void)mysql_file_delete(key_file_misc, filePath, MYF(0));
      }
    }
    my_dirend(dirp);
  }
  delete thd;
  DBUG_RETURN(0);
}

