  }
}

static int rfcomm_sock_getsockopt(struct socket* sock, int level, int optname,
                                  char __user* optval, int __user* optlen) {
  struct sock* sk = sock->sk;
  struct bt_security sec;
  int len, err = 0;
  BT_DBG("sk %p", sk);
  if (level == SOL_RFCOMM)
    return rfcomm_sock_getsockopt_old(sock, optname, optval, optlen);
  if (level != SOL_BLUETOOTH) return -ENOPROTOOPT;
  if (get_user(len, optlen)) return -EFAULT;
  lock_sock(sk);
  switch (optname) {
    case BT_SECURITY:
      if (sk->sk_type != SOCK_STREAM) {
        err = -EINVAL;
        break;
      }
      sec.level = rfcomm_pi(sk)->sec_level;
      sec.key_size = 0;
      len = min_t(unsigned int, len, sizeof(sec));
      if (copy_to_user(optval, (char*)&sec, len)) err = -EFAULT;
      break;
    case BT_DEFER_SETUP:
      if (sk->sk_state != BT_BOUND && sk->sk_state != BT_LISTEN) {
        err = -EINVAL;
        break;
      }
      if (put_user(test_bit(BT_SK_DEFER_SETUP, &bt_sk(sk)->flags),
                   (u32 __user*)optval))
        err = -EFAULT;
      break;
    default:
      err = -ENOPROTOOPT;
      break;
  }
  release_sock(sk);
  return err;
}

_asn1_get_objectid_der(const unsigned char* der, int der_len, int* ret_len,
                       char* str, int str_size) {
  int len_len, len, k;
  int leading;
  char temp[20];
  unsigned long val, val1;
  *ret_len = 0;
  if (str && str_size > 0) str[0] = 0;
  if (str == NULL || der_len <= 0) return ASN1_GENERIC_ERROR;
  len = asn1_get_length_der(der, der_len, &len_len);
  if (len < 0 || len > der_len || len_len > der_len) return ASN1_DER_ERROR;
  val1 = der[len_len] / 40;
  val = der[len_len] - val1 * 40;
  _asn1_str_cpy(str, str_size, _asn1_ltostr(val1, temp));
  _asn1_str_cat(str, str_size, ".");
  _asn1_str_cat(str, str_size, _asn1_ltostr(val, temp));
  val = 0;
  leading = 1;
  for (k = 1; k < len; k++) {
    if (leading != 0 && der[len_len + k] == 0x80) return ASN1_DER_ERROR;
    leading = 0;
    if (INT_LEFT_SHIFT_OVERFLOW(val, 7)) return ASN1_DER_ERROR;
    val = val << 7;
    val |= der[len_len + k] & 0x7F;
    if (!(der[len_len + k] & 0x80)) {
      _asn1_str_cat(str, str_size, ".");
      _asn1_str_cat(str, str_size, _asn1_ltostr(val, temp));
      val = 0;
      leading = 1;
    }
  }
  if (INT_ADD_OVERFLOW(len, len_len)) return ASN1_DER_ERROR;
  *ret_len = len + len_len;
  return ASN1_SUCCESS;
}

static void update_changeattr(struct inode* dir,
                              struct nfs4_change_info* cinfo) {
  struct nfs_inode* nfsi = NFS_I(dir);
  spin_lock(&dir->i_lock);
  nfsi->cache_validity |= NFS_INO_INVALID_ATTR | NFS_INO_INVALID_DATA;
  if (!cinfo->atomic || cinfo->before != dir->i_version)
    nfs_force_lookup_revalidate(dir);
  dir->i_version = cinfo->after;
  spin_unlock(&dir->i_lock);
}

