}

static int prb_calc_retire_blk_tmo(struct packet_sock* po,
                                   int blk_size_in_bytes) {
  struct net_device* dev;
  unsigned int mbits = 0, msec = 0, div = 0, tmo = 0;
  dev = dev_get_by_index(sock_net(&po->sk), po->ifindex);
  if (unlikely(dev == NULL)) return DEFAULT_PRB_RETIRE_TOV;
  if (dev->ethtool_ops && dev->ethtool_ops->get_settings) {
    struct ethtool_cmd ecmd = {
        .cmd = ETHTOOL_GSET,
    };
    if (!dev->ethtool_ops->get_settings(dev, &ecmd)) {
      switch (ecmd.speed) {
        case SPEED_10000:
          msec = 1;
          div = 10000 / 1000;
          break;
        case SPEED_1000:
          msec = 1;
          div = 1000 / 1000;
          break;
        case SPEED_100:
        case SPEED_10:
        default:
          return DEFAULT_PRB_RETIRE_TOV;
      }
    }
  }
  mbits = (blk_size_in_bytes * 8) / (1024 * 1024);
  if (div) mbits /= div;
  tmo = mbits * msec;
  if (div) return tmo + 1;
  return tmo;
}

void tcp_enter_cwr(struct sock* sk, const int set_ssthresh) {
  struct tcp_sock* tp = tcp_sk(sk);
  const struct inet_connection_sock* icsk = inet_csk(sk);
  tp->prior_ssthresh = 0;
  tp->bytes_acked = 0;
  if (icsk->icsk_ca_state < TCP_CA_CWR) {
    tp->undo_marker = 0;
    if (set_ssthresh) tp->snd_ssthresh = icsk->icsk_ca_ops->ssthresh(sk);
    tp->snd_cwnd = min(tp->snd_cwnd, tcp_packets_in_flight(tp) + 1U);
    tp->snd_cwnd_cnt = 0;
    tp->high_seq = tp->snd_nxt;
    tp->snd_cwnd_stamp = tcp_time_stamp;
    TCP_ECN_queue_cwr(tp);
    tcp_set_ca_state(sk, TCP_CA_CWR);
  }
}

static int nf_tables_delsetelem(struct sock* nlsk, struct sk_buff* skb,
                                const struct nlmsghdr* nlh,
                                const struct nlattr* const nla[]) {
  const struct nlattr* attr;
  struct nft_set* set;
  struct nft_ctx ctx;
  int rem, err = 0;
  if (nla[NFTA_SET_ELEM_LIST_ELEMENTS] == NULL) return -EINVAL;
  err = nft_ctx_init_from_elemattr(&ctx, skb, nlh, nla, false);
  if (err < 0) return err;
  set = nf_tables_set_lookup(ctx.table, nla[NFTA_SET_ELEM_LIST_SET]);
  if (IS_ERR(set)) return PTR_ERR(set);
  if (!list_empty(&set->bindings) && set->flags & NFT_SET_CONSTANT)
    return -EBUSY;
  nla_for_each_nested(attr, nla[NFTA_SET_ELEM_LIST_ELEMENTS], rem) {
    err = nft_del_setelem(&ctx, set, attr);
    if (err < 0) break;
    set->nelems--;
  }
  return err;
}

static int udp_lib_lport_inuse2(struct net* net, __u16 num,
                                struct udp_hslot* hslot2, struct sock* sk,
                                int (*saddr_comp)(const struct sock* sk1,
                                                  const struct sock* sk2)) {
  struct sock* sk2;
  struct hlist_nulls_node* node;
  kuid_t uid = sock_i_uid(sk);
  int res = 0;
  spin_lock(&hslot2->lock);
  udp_portaddr_for_each_entry(sk2, node, &hslot2->head) {
    if (net_eq(sock_net(sk2), net) && sk2 != sk &&
        (udp_sk(sk2)->udp_port_hash == num) &&
        (!sk2->sk_reuse || !sk->sk_reuse) &&
        (!sk2->sk_bound_dev_if || !sk->sk_bound_dev_if ||
         sk2->sk_bound_dev_if == sk->sk_bound_dev_if) &&
        (!sk2->sk_reuseport || !sk->sk_reuseport ||
         !uid_eq(uid, sock_i_uid(sk2))) &&
        saddr_comp(sk, sk2)) {
      res = 1;
      break;
    }
  }
  spin_unlock(&hslot2->lock);
  return res;
}

