authz_status oidc_authz_checker(request_rec* r, const char* require_args,
                                const void* parsed_require_args,
                                oidc_authz_match_claim_fn_type match_claim_fn) {
  oidc_debug(r, "enter: require_args=\"%s\"", require_args);
  if (r->user != NULL && strlen(r->user) == 0) {
    r->user = NULL;
    if (oidc_dir_cfg_unauth_action(r) == OIDC_UNAUTH_PASS) return AUTHZ_GRANTED;
  }
  json_t *claims = NULL, *id_token = NULL;
  oidc_authz_get_claims_and_idtoken(r, &claims, &id_token);
  if (claims) oidc_util_json_merge(r, id_token, claims);
  authz_status rc =
      oidc_authz_worker24(r, claims ? claims : id_token, require_args,
                          parsed_require_args, match_claim_fn);
  if (claims) json_decref(claims);
  if (id_token) json_decref(id_token);
  if ((rc == AUTHZ_DENIED) && ap_auth_type(r))
    rc = oidc_handle_unauthorized_user24(r);
  return rc;
}

static int nested_vmx_check_apicv_controls(struct kvm_vcpu* vcpu,
                                           struct vmcs12* vmcs12) {
  if (!nested_cpu_has_virt_x2apic_mode(vmcs12) &&
      !nested_cpu_has_apic_reg_virt(vmcs12) && !nested_cpu_has_vid(vmcs12) &&
      !nested_cpu_has_posted_intr(vmcs12))
    return 0;
  if (nested_cpu_has_virt_x2apic_mode(vmcs12) &&
      nested_cpu_has2(vmcs12, SECONDARY_EXEC_VIRTUALIZE_APIC_ACCESSES))
    return -EINVAL;
  if (nested_cpu_has_vid(vmcs12) && !nested_exit_on_intr(vcpu)) return -EINVAL;
  if (nested_cpu_has_posted_intr(vmcs12) &&
      (!nested_cpu_has_vid(vmcs12) || !nested_exit_intr_ack_set(vcpu) ||
       vmcs12->posted_intr_nv & 0xff00))
    return -EINVAL;
  if (!nested_cpu_has(vmcs12, CPU_BASED_TPR_SHADOW)) return -EINVAL;
  return 0;
}

