  }
  for (int i = 0; i < gfxColorMaxComps; ++i) {
    color->c[i] = dblToCol(out[i]);
  }
}

static void init_decode_cache(struct x86_emulate_ctxt* ctxt) {
  memset(&ctxt->twobyte, 0, (void*)&ctxt->_regs - (void*)&ctxt->twobyte);
  ctxt->fetch.start = 0;
  ctxt->fetch.end = 0;
  ctxt->io_read.pos = 0;
  ctxt->io_read.end = 0;
  ctxt->mem_read.pos = 0;
  ctxt->mem_read.end = 0;
}

static NTSTATUS kdc_task_init(struct task_server* task) {
  struct kdc_server* kdc;
  NTSTATUS status;
  struct interface* ifaces;
  switch (lpcfg_server_role(task->lp_ctx)) {
    case ROLE_STANDALONE:
      task_server_terminate(
          task, "kdc: no KDC required in standalone configuration", false);
      return NT_STATUS_INVALID_DOMAIN_ROLE;
    case ROLE_DOMAIN_MEMBER:
      task_server_terminate(
          task, "kdc: no KDC required in member server configuration", false);
      return NT_STATUS_INVALID_DOMAIN_ROLE;
    case ROLE_DOMAIN_PDC:
    case ROLE_DOMAIN_BDC:
    case ROLE_IPA_DC:
      task_server_terminate(task, "Cannot start KDC as a 'classic Samba' DC",
                            false);
      return NT_STATUS_INVALID_DOMAIN_ROLE;
    case ROLE_ACTIVE_DIRECTORY_DC:
      break;
  }
  load_interface_list(task, task->lp_ctx, &ifaces);
  if (iface_list_count(ifaces) == 0) {
    task_server_terminate(task, "kdc: no network interfaces configured", false);
    return NT_STATUS_UNSUCCESSFUL;
  }
  task_server_set_title(task, "task[kdc]");
  kdc = talloc_zero(task, struct kdc_server);
  if (kdc == NULL) {
    task_server_terminate(task, "kdc: out of memory", true);
    return NT_STATUS_NO_MEMORY;
  }
  kdc->task = task;
  task->private_data = kdc;
  status = kdc_startup_interfaces(kdc, task->lp_ctx, ifaces, task->model_ops);
  if (!NT_STATUS_IS_OK(status)) {
    task_server_terminate(task, "kdc failed to setup interfaces", true);
    return status;
  }
  return NT_STATUS_OK;
}

u32 gf_isom_segment_get_track_fragment_decode_time(GF_ISOFile* file,
                                                   u32 moof_index,
                                                   u32 traf_index,
                                                   u64* decode_time) {
#ifndef GPAC_DISABLE_ISOM_FRAGMENTS
  GF_MovieFragmentBox* moof;
  GF_TrackFragmentBox* traf;
  if (!file) return 0;
  gf_list_count(file->TopBoxes);
  moof = gf_isom_get_moof(file, moof_index);
  traf =
      moof ? (GF_TrackFragmentBox*)gf_list_get(moof->TrackList, traf_index - 1)
           : NULL;
  if (!traf) return 0;
  if (decode_time) {
    *decode_time = traf->tfdt ? traf->tfdt->baseMediaDecodeTime : 0;
  }
  return traf->tfhd->trackID;
#endif
  return 0;
}

static int wcd9335_irq_init(struct wcd9335_codec* wcd) {
  int ret;
  wcd->intr1 = of_irq_get_byname(wcd->dev->of_node, "intr1");
  if (wcd->intr1 < 0) {
    if (wcd->intr1 != -EPROBE_DEFER)
      dev_err(wcd->dev, "Unable to configure IRQ\n");
    return wcd->intr1;
  }
  ret = devm_regmap_add_irq_chip(wcd->dev, wcd->regmap, wcd->intr1,
                                 IRQF_TRIGGER_HIGH, 0,
                                 &wcd9335_regmap_irq1_chip, &wcd->irq_data);
  if (ret) dev_err(wcd->dev, "Failed to register IRQ chip: %d\n", ret);
  return ret;
}

uint find_shortest_key(TABLE* table, const key_map* usable_keys) {
  double min_cost = DBL_MAX;
  uint best = MAX_KEY;
  if (!usable_keys->is_clear_all()) {
    for (uint nr = 0; nr < table->s->keys; nr++) {
      if (usable_keys->is_set(nr)) {
        double cost = table->file->keyread_time(nr, 1, table->file->records());
        if (cost < min_cost) {
          min_cost = cost;
          best = nr;
        }
        DBUG_ASSERT(best < MAX_KEY);
      }
    }
  }
  return best;
}

