Loader::UniquePtr Loader::create(PreviewId id, const Image& image) {
  if (id < 0 || id >= Loader::getNumLoaders()) return UniquePtr();
  if (loaderList_[id].imageMimeType_ &&
      std::string(loaderList_[id].imageMimeType_) != image.mimeType())
    return UniquePtr();
  UniquePtr loader =
      loaderList_[id].create_(id, image, loaderList_[id].parIdx_);
  if (loader.get() && !loader->valid()) loader.reset();
  return loader;
}

int kernel_accept(struct socket* sock, struct socket** newsock, int flags) {
  struct sock* sk = sock->sk;
  int err;
  err = sock_create_lite(sk->sk_family, sk->sk_type, sk->sk_protocol, newsock);
  if (err < 0) goto done;
  err = sock->ops->accept(sock, *newsock, flags);
  if (err < 0) {
    sock_release(*newsock);
    *newsock = NULL;
    goto done;
  }
  (*newsock)->ops = sock->ops;
  __module_get((*newsock)->ops->owner);
done:
  return err;
}

static int decode_ber_digest_info(const gnutls_datum_t* info,
                                  gnutls_mac_algorithm_t* hash, opaque* digest,
                                  int* digest_size) {
  ASN1_TYPE dinfo = ASN1_TYPE_EMPTY;
  int result;
  char str[1024];
  int len;
  if ((result = asn1_create_element(_gnutls_get_gnutls_asn(),
                                    "GNUTLS.DigestInfo", &dinfo)) !=
      ASN1_SUCCESS) {
    gnutls_assert();
    return _gnutls_asn2err(result);
  }
  result = asn1_der_decoding(&dinfo, info->data, info->size, NULL);
  if (result != ASN1_SUCCESS) {
    gnutls_assert();
    asn1_delete_structure(&dinfo);
    return _gnutls_asn2err(result);
  }
  len = sizeof(str) - 1;
  result = asn1_read_value(dinfo, "digestAlgorithm.algorithm", str, &len);
  if (result != ASN1_SUCCESS) {
    gnutls_assert();
    asn1_delete_structure(&dinfo);
    return _gnutls_asn2err(result);
  }
  *hash = _gnutls_x509_oid2mac_algorithm(str);
  if (*hash == GNUTLS_MAC_UNKNOWN) {
    _gnutls_x509_log("verify.c: HASH OID: %s\n", str);
    gnutls_assert();
    asn1_delete_structure(&dinfo);
    return GNUTLS_E_UNKNOWN_HASH_ALGORITHM;
  }
  result = asn1_read_value(dinfo, "digest", digest, digest_size);
  if (result != ASN1_SUCCESS) {
    gnutls_assert();
    asn1_delete_structure(&dinfo);
    return _gnutls_asn2err(result);
  }
  asn1_delete_structure(&dinfo);
  return 0;
}

par_reduce(int max, BOOL fallback) {
  while (parcount > max) {
    address_item* doneaddr = par_wait();
    if (!doneaddr) {
      log_write(0, LOG_MAIN | LOG_PANIC,
                "remote delivery process count got out of step");
      parcount = 0;
    } else {
      transport_instance* tp = doneaddr->transport;
      if (tp->max_parallel)
        enq_end(string_sprintf("tpt-serialize-%s", tp->name));
      remote_post_process(doneaddr, LOG_MAIN, NULL, fallback);
    }
  }
}

static void smbd_deferred_open_timer(struct event_context* ev,
                                     struct timed_event* te,
                                     struct timeval _tval, void* private_data) {
  struct pending_message_list* msg =
      talloc_get_type(private_data, struct pending_message_list);
  TALLOC_CTX* mem_ctx = talloc_tos();
  uint8_t* inbuf;
  inbuf = (uint8_t*)talloc_memdup(mem_ctx, msg->buf.data, msg->buf.length);
  if (inbuf == NULL) {
    exit_server("smbd_deferred_open_timer: talloc failed\n");
    return;
  }
  DEBUG(5, ("smbd_deferred_open_timer: trigger mid %u.\n",
            (unsigned int)SVAL(msg->buf.data, smb_mid)));
  process_smb(smbd_server_conn, inbuf, msg->buf.length, 0, msg->seqnum,
              msg->encrypted, &msg->pcd);
}

COMPAT_SYSCALL_DEFINE2(timer_gettime, timer_t, timer_id,
                       struct compat_itimerspec __user*, setting) {
  long err;
  mm_segment_t oldfs;
  struct itimerspec ts;
  oldfs = get_fs();
  set_fs(KERNEL_DS);
  err = sys_timer_gettime(timer_id, (struct itimerspec __user*)&ts);
  set_fs(oldfs);
  if (!err && put_compat_itimerspec(setting, &ts)) return -EFAULT;
  return err;
}

char* on_path(const char* cmd, const char* rootfs) {
  char *entry = NULL, *path = NULL;
  char cmdpath[MAXPATHLEN];
  int ret;
  path = getenv("PATH");
  if (!path) return NULL;
  path = strdup(path);
  if (!path) return NULL;
  lxc_iterate_parts(entry, path, ":") {
    if (rootfs)
      ret = snprintf(cmdpath, MAXPATHLEN, "%s/%s/%s", rootfs, entry, cmd);
    else
      ret = snprintf(cmdpath, MAXPATHLEN, "%s/%s", entry, cmd);
    if (ret < 0 || ret >= MAXPATHLEN) continue;
    if (access(cmdpath, X_OK) == 0) {
      free(path);
      return strdup(cmdpath);
    }
  }
  free(path);
  return NULL;
}

void HTMLMediaElement::CreatePlaceholderTracksIfNecessary() {
  if (!MediaTracksEnabledInternally()) return;
  if (HasAudio() && !audioTracks().length()) {
    AddAudioTrack("audio", WebMediaPlayerClient::kAudioTrackKindMain,
                  "Audio Track", "", true);
  }
  if (HasVideo() && !videoTracks().length()) {
    AddVideoTrack("video", WebMediaPlayerClient::kVideoTrackKindMain,
                  "Video Track", "", true);
  }
}

bool HTMLInputElement::hasValidDataListOptions() const {
  HTMLDataListElement* dataList = this->dataList();
  if (!dataList) return false;
  RefPtr<HTMLCollection> options = dataList->options();
  for (unsigned i = 0;
       HTMLOptionElement* option = toHTMLOptionElement(options->item(i)); ++i) {
    if (isValidValue(option->value())) return true;
  }
  return false;
}

static void irda_selective_discovery_indication(discinfo_t* discovery,
                                                DISCOVERY_MODE mode,
                                                void* priv) {
  struct irda_sock* self;
  IRDA_DEBUG(2, "%s()\n", __func__);
  self = (struct irda_sock*)priv;
  if (!self) {
    IRDA_WARNING("%s: lost myself!\n", __func__);
    return;
  }
  self->cachedaddr = discovery->daddr;
  wake_up_interruptible(&self->query_wait);
}
